import type { Recipe } from '../types'

const externalRecipesRaw = "[{\"id\":\"k1\",\"title\":\"새우 두부 계란찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00028_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00028_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우두부계란찜\",\"연두부 75g(3/4모)\",\"칵테일새우 20g(5마리)\",\"달걀 30g(1/2개)\",\"생크림 13g(1큰술)\",\"설탕 5g(1작은술)\",\"무염버터 5g(1작은술)\",\"고명\",\"시금치 10g(3줄기)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"나트륨의 배출을 도와주는 것으로 알려진 칼륨이 풍부한 시금치와 소금, 간장 등의 양념 대신 새우에 들어있는 간으로 맛을 내요.\",\"instructions\":[\"1. 손질된 새우를 끓는 물에 데쳐 건진다.\",\"2. 연두부, 달걀, 생크림, 설탕에 녹인 무염버터를 믹서에 넣고 간 뒤 새우(1)를 함께 섞어 그릇에 담는다.\",\"3. 시금치를 잘게 다져 혼합물 그릇(2)에 뿌리고 찜기에 넣고 중간 불에서 10분 정도 찐다.\"]},{\"id\":\"k2\",\"title\":\"부추 콩가루 찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00029_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054820_1675673300714.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054834_1675673314720.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230206/20230206054908_1675673348152.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[1인분]조선부추 50g\",\"날콩가루 7g(1⅓작은술)\",\"·양념장 : 저염간장 3g(2/3작은술)\",\"다진 대파 5g(1작은술)\",\"다진 마늘 2g(1/2쪽)\",\"고춧가루 2g(1/3작은술)\",\"요리당 2g(1/3작은술)\",\"참기름 2g(1/3작은술)\",\"참깨 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"콩가루로 버무려 감칠맛과 고소한 맛으로 나트륨 사용량을 줄여보세요. 부추는 피를 맑게 하고 허약 체질을 개선하여 성인병을 예방하는데 효과가 있지만, 알레르기 체질이나 위장이 약한 사람은 부작용이 생길 수 있으니 주의하세요.\",\"instructions\":[\"1. 부추는 깨끗이 씻어 물기를 제거하고, 5cm 길이로 썰고 부추에 날콩가루를 넣고 고루 섞이도록 버무린다.\",\"2. 찜기에 면보를 깔고 부추를 넣은 후 김이 오르게 쪄서 파랗게 익힌다.\",\"3. 저염간장에 다진 대파, 다진 마늘, 고춧가루, 요리당 , 참기름, 참깨를 섞어 양념장을 만들고 찐 부추는 그릇에 담아낸다.\"]},{\"id\":\"k3\",\"title\":\"방울토마토 소박이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00031_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00031_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●방울토마토 소박이 :\",\"방울토마토 150g(5개)\",\"양파 10g(3×1cm)\",\"부추 10g(5줄기)\",\"●양념장 :\",\"고춧가루 4g(1작은술)\",\"멸치액젓 3g(2/3작은술)\",\"다진 마늘 2.5g(1/2쪽)\",\"매실액 2g(1/3작은술)\",\"설탕 2g(1/3작은술)\",\"물 2ml(1/3작은술)\",\"통깨 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금에 절이는 오이 대신 방울토마토를 사용하여 나트륨 섭취를 줄였어요. 토마토에는 과일에 대체로 없는 글루탐산이 풍부하여 감칠맛을 내주며, 겉절이 양념과 잘 어우러져 상큼함과 감칠맛을 내주어요.\",\"instructions\":[\"1. 물기를 빼고 2cm 정도의 크기로 썰은 부추와 양파를 양념장에 섞어 양념속을 만든다.\",\"2. 깨끗이 씻은 방울토마토는 꼭지를 떼고 윗부분에 칼로 십자모양으로 칼집을 낸다.\",\"3. 칼집을 낸 방울토마토에 양념속을 사이사이에 넣어 버무린다.\"]},{\"id\":\"k4\",\"title\":\"순두부 사과 소스 오이무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00032_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00032_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●오이무침 :\",\"오이 70g(1/3개)\",\"다진 땅콩 10g(1큰술)\",\"●순두부사과 소스 :\",\"순두부 40g(1/8봉지)\",\"사과 50g(1/3개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"사과에는 팩틴이 풍부하여 체내 나쁜 콜레스테롤을 감소시키고 나트륨 배출을 촉진시켜줘요. 순두부와 사과를 갈아 만든 소스는 맵고 짠 자극적인 간이 아닌 재료 그대로의 새콤달콤한 맛과 깔끔한 맛을 내요.\",\"instructions\":[\"1. 사과, 순두부를 믹서에 넣고 곱게 갈아 소스를 만든다.\",\"2. 오이는 소금으로 문질러 씻어 반을 갈라 씨를 제거하고 어슷썰기를 한다.\",\"3. 썰어 놓은 오이에 순두부사과 소스를 넣고 버무린 후 다진 땅콩을 뿌려 마무리 한다.\"]},{\"id\":\"k5\",\"title\":\"사과 새우 북엇국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00033_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00033_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"북엇국\",\"북어채 25g(15개)\",\"새우 10g(3마리)\",\"사과 30g(1/5개)\",\"양파 40g(1/4개)\",\"표고버섯 20g(2장)\",\"물 300ml(1½컵)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금과 간장 대신 북어채와 새우의 짠맛으로 간을 한 담백한 맛의 북엇국을 만들었어요. 홍합이나 바지락을 넣으면 시원한 국물을 연출 할 수 있어요.\",\"instructions\":[\"2. 북어채를 잘게 손으로 찢어 찬물에 헹구어 준비한 후 양파, 표고버섯, 사과는 채 썰고 새우는 등쪽의 두세 마디에 꼬챙이를 넣어 내장을 뺀 후 헹군다.\",\"3. 찬물에 북어채, 새우, 표고버섯, 양파를 넣고 20분 정도 끓인 후 사과를 넣어 북어의 씁쓸한 맛을 없앤다.\",\"5. 그릇에 담아낸다.\"]},{\"id\":\"k6\",\"title\":\"저염 된장으로 맛을 낸 황태해장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00036_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00036_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00036_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00036_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"황태해장국\",\"황태(채) 15g(10개)\",\"콩나물 30g(1/6봉지)\",\"무 30g(5×3×2cm)\",\"저염된장 10g(2작은술)\",\"물 300ml(1½컵)\",\"청양고추 5g(1/2개)\",\"다진 마늘 2g(1/3작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"황태해장국을 조리할 때 소금 대신 저염된장을 사용하면 덜 짜고 감칠맛 나는 황태해장국을 맛 볼 수 있어요.\\n황태는 빛이 누렇고 살이 연한 것이 좋은 상품이며, 황태는 냉동실에 보관하거나 잘 밀봉하여 건조하고 서늘한 곳에 보관하는 것이 좋아요.\",\"instructions\":[\"3. 황태는 손질하여 물에 헹궈 건져 놓고 콩나물은 다듬어 씻고 청양고추는 어슷썰기 한다.\",\"4. 냄비에 물을 붓고 황태와 무를 넣고 끓인 후 육수에서 물을 건져내고 저염 된장을 푼다.\",\"5. 콩나물, 다진 마늘, 청양고추를 넣고 뚜껑을 덮어 김이 나게 끓\\n여준다.\"]},{\"id\":\"k7\",\"title\":\"된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00037_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00037_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00037_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00037_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"된장국\",\"두부 20g(2×2×2cm)\",\"애느타리버섯 20g(4가닥)\",\"감자 10g(4×3×1cm)\",\"양파 10g(2×1cm)\",\"대파 10g(5cm)\",\"된장 5g(1작은술)\",\"물 300ml(1½컵)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장국의 된장 사용량을 줄이기 위해 두부와 감자 등의 재료를 갈아 넣으면 담백한 된장국을 맛볼 수 있어요.\\n된장의 양을 적게 사용함으로 나트륨 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 감자, 양파는 얇게 썰고 애느타리 버섯은 썰어 달궈진 팬에 굽는다.\",\"2. 냄비에 물을 붓고 된장을 푼 뒤 감자, 양파, 두부를 넣어 재료가 투명해지게 끓인 후 된장국의 재료를 건져서 믹서에 넣어 갈고 된장국에 넣어 한번 더 끓인다.\",\"3. 구운 애느타리버섯과 대파를 국에 넣어 끓인 후 그릇에 담는다.\"]},{\"id\":\"k8\",\"title\":\"표고버섯 청경채국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00038_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00038_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00038_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00038_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●멸치육수 : 국물용 멸치 5g(3마리)\",\"다시마 1장(5×1cm)\",\"양파 10g(2×1cm)\",\"표고버섯 기둥\",\"국간장 5g(1작은술)\",\"물 300ml(1½컵)\",\"●채소준비 : 청경채 20g(1개)\",\"표고버섯 20g(2장)\",\"다진 마늘 2g(1/3작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"표고버섯 밑둥을 육수에 넣어 감칠맛을 더하고, 멸치와 다시마는 다량의 소금 없이도 국물 맛을 깊게 만들어 주는 역할을 해요. 건표고버섯은 햇볕에 말리는 과정에서 만들어진 비타민 D가 풍부해 칼슘 흡수를 도와 골다공증 예방에 좋은 식품이예요. 생표고버섯에는 비타민 D가 거의 들어있지 않아\",\"instructions\":[\"1. 찬물에 표고버섯,머리와 내장을 제거한 멸치,\\n다시마, 양파를 넣어 중간 불에서 10분 정도\\n끓여 멸치육수를 만든다.\",\"2. 육수의 표고버섯 기둥, 멸치, 다시마, 양파를 건진 후 표고버섯은 편으로 썰고 청경채는 4cm 크기로 썬다.\",\"3. 끓는 육수에 준비한 표고버섯과 청경채를 넣고 국간장으로 간을 한 후 마늘을 넣어 한소끔 끓인다.\"]},{\"id\":\"k9\",\"title\":\"치커리샐러드와 올리브 마늘 소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00095_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00095_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00095_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00095_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●치커리 샐러드 : 치커리 30g(10줄기)\",\"적양배추 15g(5×3cm)\",\"양파 10g(2×1cm)\",\"당근 5g(3×1×1cm)\",\"●올리브마늘 드레싱 : 올리브유 10g(2작은술)\",\"식초 5g(1작은술)\",\"설탕 5g(1작은술)\",\"마늘 5g(1쪽)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치커리를 육류와 함께 섭취하면 치커리의 산뜻한 맛으로 입맛을 돋우고 섬유소의 섭취를 늘릴 수 있으며 동맥경화를 예방하는데 도움이 된답니다. 치커리에는 칼륨이 많아 육류나 고나트륨 식사시 함께 섭취하면 체내나트륨 배출에 효과적이에요.\",\"instructions\":[\"1. 올리브유, 식초, 설탕, 다진 마늘을 섞어 거품기로 충분히 저어주어 올리브마늘 드레싱을 만든다.\",\"2. 치커리는 싱싱하게 찬물에 담갔다가 물기를 뺀 후 한입 크기로 자르고, 적양배추, 양파, 당근은 곱게채를 썬다.\",\"3. 접시에 준비한 치커리, 적양배추, 양파, 당근을 담고 올리브마늘 드레싱을 뿌린다.\"]},{\"id\":\"k10\",\"title\":\"스트로베리 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00087_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00087_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00087_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00087_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"스트로베리 샐러드\",\"딸기 70g(7개)\",\"플레인요거트 85g(1개)\",\"양상추 70g(2장)\",\"메추리알 30g(3개)\",\"블루베리 15g(1큰술)\",\"식초 약간\",\"소금 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"딸기는 칼륨이 풍부하여 나트륨 배출에 뛰어나지만 칼슘이 부족한 과일이예요. 그렇기 때문에 칼슘이 풍부한 요거트나 기타 유제품과 함께 섭취하면 좋아요.\",\"instructions\":[\"1. 찬물이 담긴 냄비에 식초, 소금을 넣고 메추리알을 삶는다. 물이 끓어오르면 5분 정도 더 삶아 찬물에 헹군 후 껍질을 벗기고 반으로 자른다.\",\"2. 딸기를 흐르는 물에 가볍게 씻어 꼭지를 제거한 후 물기를 빼고 반으로 자른다.\",\"3. 양상추는 찬물에 담갔다가 물기를 빼고 한입 크기로 찢은 후 접시에 양상추, 딸기, 블루베리, 메추리알을 담고 플레인요거트를 끼얹는다.\"]},{\"id\":\"k11\",\"title\":\"시금치 우유 소스와 그린매쉬드포테이토\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00089_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00089_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00089_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00089_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●그린매쉬드포테이토 : 감자 80g(1/2개)\",\"시금치우유 소스 5g(1작은술)\",\"아몬드 2g(1알)\",\"설탕 2g(1/3작은술)\",\"크랜베리 3g\",\"치커리 약간\",\"●시금치우유 소스 : 시금치 10g\",\"우유 10g(2작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시금치에 풍부한 칼륨과 우유의 칼슘은 나트륨 배출을 도와줘요. 감자도 칼륨이 풍부한 채소이지만 감자에 부족한 칼슘을 유제품과 함께 섭취하면 칼슘을 보충 받을 수 있어요.\",\"instructions\":[\"1. 시금치는 끓는 소금물에 데쳐 찬물에 헹구어 물기를 짜고 우유를 넣고 블렌더에 곱게 갈아 체에 거른다.\",\"2. 껍질 벗긴 감자는 찜기에 넣어 20분 정도 삶고 꺼내서 으깨고, 아몬드는 잘게 다지며, 치커리는 곱게 다진다.\",\"3. 으깬 감자, 다진 치커리, 시금치 우유소스, 설탕을 넣고 섞어 접시에 담고 아몬드, 크랜베리를 올리고 시금치우유 소스를 곁들인다.\"]},{\"id\":\"k12\",\"title\":\"버섯구이와 두부타르타르 소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00091_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00091_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00091_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00091_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●버섯구이 : 새송이버섯 70g(7개)\",\"올리브유 10g(2작은술)\",\"●곁들임 : 치커리 10g(3줄기)\",\"●두부타르타르 소스 : 연두부 30g(1/4모)\",\"다진 양파 10g(2작은술)\",\"다진 오이피클 10g(2작은술)\",\"올리브유 2g(1/3작은술)\",\"식초 5g(1작은술)\",\"레몬즙 3g(2/3작은술)\",\"머스터드 3g(2/3작은술)\",\"꿀 2g(1/3작은술)\",\"흰 후추 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"새송이 버섯은 칼륨 함량이 높아 육류와 함께 섭취하면 혈중 콜레스테롤 수치를 낮추는데 효과가 있어요.\\n나트륨이 많은 간장이나 소금 대신 겨자, 레몬 등을 이용한 소스로 나트륨 함량을 줄여보세요.\",\"instructions\":[\"1. 곱게 다진 양파와 오이피클은 물기를 짠다.\",\"2. 연두부에 다진 양파, 다진 오이피클, 올리브유, 머스터드, 후추, 꿀, 식초, 레몬즙을 넣어 두부타르타르 소스를 만든다.\",\"3. 새송이버섯은 0.5cm 두께로 썰고 프라이팬에 노릇하게 구워준 후 접시에 새송이버섯과 치커리를 담고 소스를 곁들인다.\"]},{\"id\":\"k13\",\"title\":\"구운채소와 간장레몬 소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00093_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00093_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00093_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00093_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●구운채소 : 가지 20g(3cm)\",\"호박 50g(1/3개)\",\"새송이버섯 15g(3개)\",\"양파 15g(1/8개)\",\"발사믹크레마 15g(1큰술)\",\"빨강 파프리카 3g(3×1cm)\",\"노랑 파프리카 3g(3×1cm)\",\"청피망 3g(3×1cm)\",\"올리브유 약간\",\"●간장 레몬 소스 : 저염간장 5g(1작은술)\",\"식초 15g(1큰술)\",\"설탕 10g(1큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"채소와 버섯류에는 대부분 나트륨 배출에 효과적인 칼륨이 함유되어 있어 채소를 많이 섭취하는 것이 저나트륨 식단의 기본이에요. 레몬즙은 음식의 짠맛을 감추고 간장과 함께 사용하면 간장의 감칠맛을 상승시키는 효\\n과도 있어요.\",\"instructions\":[\"1. 저염간장, 식초, 레몬즙, 설탕을 혼합하여 간장레몬 소스를 만든다.\",\"2. 호박, 가지, 새송이버섯은 3cm 길이로 자른 후 얇은 편으로 채 썰고, 양파, 파프리카, 피망은 호박 길이로 썬다.\",\"3. 가지, 호박, 새송이버섯, 양파, 파프리카, 피망에 올리브유를 바르고 달궈진 그릴 팬에 구운 후 접시에 담고 발사믹 크레타를 뿌리고 간장레몬 소스를 곁들인다.\"]},{\"id\":\"k14\",\"title\":\"브로콜리 컬리플라워 샐러드와 두유 요거트 소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00094_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00094_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00094_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00094_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●브로콜리컬리플라워 샐러드 : 브로콜리 40g(1/5송이)\",\"컬리플라워 40g(1/3송이)\",\"적양파 10g(2×1cm)\",\"강낭콩 5g(1작은술)\",\"건포도 5알\",\"호두 1/2알\",\"소금 약간\",\"●두유요거트 소스 : 두유 50g(3⅓큰술)\",\"플레인요거트 20g(1⅓큰술)\",\"레몬즙 5g(1작은술)\",\"설탕 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"브로콜리와 컬리플라워를 데치는 과정에서만 소금을 넣어 맛과 색은 살려주고 소금 사용은 줄였어요, 또한 마요네즈 대신 두유를 사용하면 맛은 고소해지고 나트륨 배설은 증가 시킬 수 있어요.\",\"instructions\":[\"1. 두유에 플레인요거트와 레몬즙, 설탕을 넣고 잘 섞어 두유요거트 소스를 만든다.\",\"2. 강낭콩은 물에 불린 후 콩과 물을 1:2.5로 넣고 20~25분 삶아 건지고 브로콜리와 컬리플라워는 한입 크기로 썰어 끓는 소금물에 살짝 데쳐 찬물에 헹궈 물기를 뺀다.\",\"3. 접시에 데친 브로콜리와 컬리플라워, 삶은 강낭콩, 채썬 적양파, 다진 호두, 건포도를 담고 두유요거트 소스를 곁들여 낸다.\"]},{\"id\":\"k15\",\"title\":\"오렌지와 당근 만남주스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00108_1.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00108_6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오렌지 당근펀치\",\"당근 100g(1/2개)\",\"오렌지 100g(1/2개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시판되는 대부분의 주스는 가공되고 농축되는 과정에서 나트륨이 첨가되는 경우가 있어 과일, 채소를 직접 갈아 마시면 나트륨 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 오렌지는 깨끗이 씻어 껍질을 벗긴다.\",\"2. 당근은 깨끗이 씻어 작은 토막으로 썬다.\",\"3. 당근, 오렌지, 물(50ml)을 믹서에 곱게 간다.\",\"4. 믹서에 갈아낸 주스는 고운 체로 거른다.\",\"5. 주스를 살얼음이 생길 만큼 시원하게 냉동한다.\",\"6. 컵에 담아 마무리한다.\"]},{\"id\":\"k16\",\"title\":\"칠곡석류국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00111_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00111_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00111_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00111_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 소면 160g\",\"저염소금 4g(1작은술)\",\"식초 8g(1/2작은술)\",\"●소스 : 석류 200g(1/2개)\",\"●장식 : 잣 4g(1작은술)\",\"아몬드 4g(1작은술)\",\"해바라기씨 4g(1작은술)\",\"호두 4g(1작은술)\",\"호박씨 4g(1작은술)\",\"오이 20g(1/4개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"견과류에는 불포화 지방산이 풍부하게 함유되어 있어, 고지혈증 등 혈류개선에 효과가 있어 성인병 예방에 좋다. 짠맛을 대신하여 석류의 새콤달콤한 맛을 활용하고, 볶은 견과류로 고소한 맛과 풍미를 더하였다.\",\"instructions\":[\"1. 잣, 아몬드, 해바라기씨, 호두, 호박씨는 다진다.\",\"2. 끓는 물에 저염소금과 식초를 넣은 후 소면을 삶은 후 체에 건져 물기를\\n뺀다.\",\"3. 석류는 물 600g와 함께 믹서에 갈고 체에 걸러 즙을 낸다. 그릇에 면을 담고 차갑게 식힌 석류즙을 붓고 견과류, 채 썬 오이를 고명으로 올린다.\"]},{\"id\":\"k17\",\"title\":\"블랙빈 곤약국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00113_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00113_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00113_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00113_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료\",\"실곤약 440g\",\"검은콩 70g\",\"볶은 흑임자 6g(1작은술)\",\"호두 6g(1알)\",\"●장식\",\"오이 20g(1/8개)\",\"토마토 50g(1/2개)\",\"달걀 50g(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"검은콩은 안토시아닌 색소를 많이 함유하고 있어 시력회복과 항암작용에 좋다. 나트륨 함량이 높은 소면을 대신하여 실곤약으로 면을 대체함으로써 나트륨과 칼로리의 섭취량을 줄이고, 콩국물에 흑임자와 호두를 넣어 짠맛 대신 고소한 맛과 향을 강조한다.\",\"instructions\":[\"1. 검은콩을 1시간 찬물에 담가 불린 후 삶아 익힌 후 불순물을 제거하고 흑임자, 생수, 삶은 콩, 호두를 믹서에 갈아 살엄음이 생기도록 냉동실에 넣는다.\",\"2. 오이는 돌려 깎아 채 썰고, 토마토는 1/8크기로 썰고, 달걀은 삶아 반으로 자른다.\",\"3. 실곤약은 끓는 물에 데치고 찬물에 헹궈 그릇에 담은 후 콩물을 담고 오이, 토마토, 달걀을 고명으로 올려 완성한다.\"]},{\"id\":\"k18\",\"title\":\"닭가슴살 브로콜리 만두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00114_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00114_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00114_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00114_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료\",\"만두피 4g(2장)\",\"브로콜리 100g(1/4개)\",\"숙주 100g\",\"표고버섯 20g(2개)\",\"닭 가슴살 100g\",\"참기름 2g(1/2작은술)\",\"저염간장 4g(1작은술)\",\"소금 0.5g\",\"후춧가루 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨 함량이 높은 브로콜리를 사용하여 나트륨 배출을 돕는다. 만두소는 저염간장으로 양념하고 별도로 초간장을 곁들이지 않아 나트륨섭취를 줄인다.\",\"instructions\":[\"1. 브로콜리, 숙주, 표고버섯, 닭 가슴살은 다지고 다진 닭 가슴살은 소금과 후추로 밑간 한다.\",\"2. 다진 채소와 닭가슴살, 참기름, 저염간장을 섞어 만두소를 만든다.\",\"3. 준비한 만두피에 만두소를 넣은 후 만두 모양으로 빚고 만두를 찜통에 넣어 찌고 그릇에 담는다.\"]},{\"id\":\"k19\",\"title\":\"함초 냉이 국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00131_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00131_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00131_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00131_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 소면 50g\",\"●육수 : 함초 3g(1/2작은술)\",\"노루궁뎅이버섯 25g(1/2개)\",\"다시마 17g(15cm)\",\"파 140g(1/2개)\",\"양파 150g(1/2개)\",\"무 250g(1/3개)\",\"모시조개 150g(3/4컵)\",\"냉이 35g\",\"간장 30g(2큰술)\",\"●장식 : 달걀 50g(1개)\",\"청고추 20g(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"냉이에 함유된 비타민A와 비타민C는 소화작용을 용이하게 한다. 소금을 대체하여 함초를 사용하고, 멸치와 모시조개, 다시마 등을 사용하여 감칠맛을 더한다.\",\"instructions\":[\"1. 함초, 노루궁뎅이버섯, 다시마, 파, 양파, 무를 물에 넣어 10분 끓이고 향이 강한 모시조개와 냉이를 넣고 30분  끓인 후 간장으로 색을 낸다.\",\"2. 소면은 따로 삶는다.\",\"3. 그릇에 삶은 소면을 담은 후 육수를 붓고 지단, 슬라이스한 청고추, 실고추를 올려 완성한다.\"]},{\"id\":\"k20\",\"title\":\"된장 두부찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00137_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00137_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00137_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00137_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 320g(1모)\",\"쌀뜨물 300g(1½컵)\",\"돼지고기 100g\",\"김치 140g\",\"된장 20g(1½큰술)\",\"청양고추 10g(1/2개)\",\"홍고추 5g(1/4개)\",\"대파 10g(2cm)\",\"고춧가루 5g(1작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치는 물에 헹구어 염분을 제거하고 고추를 넣어 매운 맛과 향을 더한다. 두부는 콩 단백질이 풍부한 식품으로 두뇌발달에 좋다.\",\"instructions\":[\"1. 두부에 쌀뜨물을 넣고 갈아준다.\",\"2. 돼지고기는 썰고 김치는 물에 씻어 양념을 제거하고 3×3cm로 썬다.\",\"3. 냄비에 돼지고기와 김치를 함께 볶은 후, 망에 거른 된장과 1의 두부, 고춧가루, 청양고추, 홍고추를 넣어 끓이다가 대파를 넣어 완성한다.\"]},{\"id\":\"k21\",\"title\":\"부대된장찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00138_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00138_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00138_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00138_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다시마 1g\",\"두부 10g\",\"떡국 떡 10g\",\"스팸(마일드) 10g\",\"다진 마늘 5g\",\"무 20g\",\"김치 15g\",\"소시지 10g(1/2개)\",\"우민찌 5g(1작은술)\",\"양파 5g\",\"저염된장 15g(1큰술)\",\"베이컨 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염된장과 저염햄을 사용하고 김치는 물에 헹구어 염도를 낮추어 준다.\",\"instructions\":[\"1. 김치, 베이컨, 스팸, 소시지, 양파, 두부, 무는 두께 0.5cm로 썬다.\",\"2. 다시마와 물을 끓여 다시마물을 만든다.\",\"3. 냄비에 소시지, 베이컨, 두부, 스팸, 무, 우민찌, 김치, 다시마물 300g을 넣어 끓인 후 저염된장, 양파, 대파, 다진 마늘, 떡국 떡을 넣고 재료가 다 익으면 홍고추와 청양고추를 넣어 완성한다.\"]},{\"id\":\"k22\",\"title\":\"양배추감자전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00181_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00181_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00181_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00181_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 감자 100g(1개)\",\"양배추 150g(1/2개)\",\"당근 15g(1/10개)\",\"두부 20g(1/20모)\",\"돼지고기 30g\",\"청양고추 5g(1개)\",\"부침가루 45g(3큰술)\",\"달걀 60g(1개)\",\"식용유 15g(1큰술)\",\"●소스 : 오렌지즙 15g(1큰술)\",\"간장 2g(1/2작은술)\",\"식초 10g(2작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감자와 양배추에는 칼륨이 풍부하게 들어있어 나트륨 배출에 도움을 준다. 양념간장 대신 과일즙을 활용한 폰즈소스를 곁들여 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 감자는 믹서에 갈고 양배추는 채 썰고 고기, 당근, 청양고추, 두부는 다진다.\",\"2. 준비해둔 재료를 모두 섞고 부침가루와 계란을 넣어 반죽한다.\",\"3. 가열된 팬에 기름을 두르고 반죽을 부어 굽고 소스를 함께 곁들인다.\"]},{\"id\":\"k23\",\"title\":\"돌나물 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00074_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00074_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00074_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00074_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●돌나물 샐러드 : 돌나물 90g\",\"미니새송이버섯 60g(7개)\",\"참기름 약간\",\"●레몬마요네즈 소스 : 마요네즈 10g(2작은술)\",\"레몬즙 20g(1⅓큰술)\",\"청양고추 5g(1/2개)\",\"홍고추 5g(1/2개)\",\"참기름 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"샐러드드레싱에 짠맛을 줄이기 위해 마요네즈 사용량을 줄이고 레몬즙과 청양고추를 혼합하여 드레싱을 만들면 짠맛을 줄이는 효과를 낼 수 있어요. 마요네즈 사용이 지나치면 나트륨과 콜레스테롤의 섭취가 높아지므로 주의하세요.\",\"instructions\":[\"1. 청양고추와 홍고추를 다져서 참기름에 살짝 볶은 후 볶은 고추에 마요네즈와 레몬즙을 넣어 소스를 만든다.\",\"2. 돌나물은 손질하여 찬물에 담구고 새송이버섯은 달군 프라이팬에 참기름을 두르고 노릇\\n하게 굽는다.\",\"3. 돌나물은 물기를 빼고 구운 새송이버섯과 레몬마요네즈 소스를 넣고\\n버무려 접시에 담는다.\"]},{\"id\":\"k24\",\"title\":\"석류 보쌈김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00159_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00159_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00159_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00159_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 배추 70g(1/10개)\",\"석류즙 10g(2작은술)\",\"소금 5g(1/2작은술)\",\"●양념 : 무 10g(3cm)\",\"미나리 10g\",\"쪽파 10g(1개)\",\"다진 마늘 5g(1작은술)\",\"다진 생강 5g(1작은술)\",\"새우젓국 15g(1큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배추는 최소한의 소금으로 절이고 석류 즙으로 새콤한 맛과 향을 더한다. 미네랄, 칼슘, 무기질이 풍부한 석류는 여성질환에 도움을 준다.\",\"instructions\":[\"1. 배추를 소금물에 하루 동안 절인 후 물기를 빼고 석류는 즙을 낸다.\",\"2. 무는 채 썰고, 쪽파와 미나리는 4cm로 자른다.\",\"3. 무채, 미나리, 쪽파, 다진 마늘, 다진 생강, 새우젓국을 넣고 섞어 소를 만들고 절인 배추에 소를 넣고 오므려 싼다. 석류즙에 소를 채운 배추를 담가 완성한다.\"]},{\"id\":\"k25\",\"title\":\"유자 대구조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00161_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00161_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00161_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00161_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 대구살 120g\",\"홍파프리카 10g(1/10개)\",\"황파프리카 10g(1/10개)\",\"청파프리카 10g(1/10개)\",\"황금팽이버섯 10g\",\"미나리 20g\",\"밀가루 25g(2큰술)\",\"●소스 : 유자청 20g(1⅓큰술)\",\"발사믹식초 10g(2작은술)\",\"화이트와인 10g(2작은술)\",\"●장식 : 대파 30g(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 유자청으로 향을 더하고 발사믹식초로 상큼함을 더한다. 찜은 재료 본연의 맛을 느낄 수 있는 조리법이며 소스를 찍어먹을 수 있도록 곁들여 내면 나트륨 섭취량을 줄일 수 있다.\",\"instructions\":[\"1. 발사믹 식초, 화이트와인, 다진 유자청 건더기를 넣고 졸여 소스를 만들고 대구를 손질하여 포를 뜬다.\",\"2. 대파, 청파프리카, 홍파프리카, 황파프리카를 채 썬다.\",\"3. 대구포에 밀가루를 묻혀 청파프리카, 홍파프리카, 황파프리카, 황금팽이버섯을 넣고 말아 미나리로 묶어 찐 후 소스를 뿌리고 썬 대파를 올려 완성한다.\"]},{\"id\":\"k26\",\"title\":\"파프리카 물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00162_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00162_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00162_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00162_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 자색고구마 10g(3cm)\",\"무 10g(2cm)\",\"배 80g(1/4개)\",\"배추 200g(1/3개)\",\"부추 10g\",\"사과 80g(1/3개)\",\"쪽파 10g(10cm)\",\"소금 20g(1⅓큰술)\",\"●양념 : 멥쌀 10g(2작은술)\",\"물엿 50g(1/4컵)\",\"황파프리카 140g(1½개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치를 절인 후 찬물에 세 번 씻어 소금기를 빼고 기호에 따라 청고추를 넣어 매콤한 맛을 준다.\",\"instructions\":[\"1. 황파프리카를 갈아 체에 내리고 멥쌀로 쌀풀을 만들어 황파프리카 즙을 섞고 물엿을 첨가하여 양념을 만든다.\",\"2. 배추를 소금물에 절이고 절인 배추를 찬물로 씻어 소금기를 뺀다.\",\"3. 소금기를 뺀 배추에 채썬 자색고구마, 무, 쪽파, 부추, 사과, 배를 놓고 양념을 부은 후 3일 동안 숙성시켜 완성한다.\"]},{\"id\":\"k27\",\"title\":\"고추장 라따뚜이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00193_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00193_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00193_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00193_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 애호박 70g(1½개)\",\"양송이버섯 60g(3개)\",\"가지 70g(1/2개)\",\"저염살라미 25g\",\"사과 60g(1/3개)\",\"●소스 :양파 40g(1/5개)\",\"마늘 10g(2개)\",\"토마토 600g(3개)\",\"설탕 10g(2작은술)\",\"바질 50g\",\"고추장 15g(1큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 토마토를 사용하여 나트륨 배출에 도움을 주며, 살라미는 끓는 물에 데쳐 염분을 제거한 후 사용한다.\",\"instructions\":[\"1. 양파와 마늘은 다져서 볶다가 토마토 과육과 설탕, 바질을 넣고 고추장을 섞어 토마토 소스를 만든다.\",\"2. 가지, 양송이버섯, 애호박, 사과는 썰고 살라미는 데친다.\",\"3. 오븐용 팬에 토마토 소스를 넓게 펴준 뒤 애호박, 가지, 양송이버섯, 살라미를 겹치게 넣고 180℃로 예열한 오븐에 넣고 30분 구워 완성한다\"]},{\"id\":\"k28\",\"title\":\"민들레 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00201_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00201_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00201_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00201_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 민들레 잎 40g\",\"비트 5g(1작은술)\",\"오렌지(껍질) 40g(1/5개)\",\"●드레싱 : 간장 20g(1⅓큰술)\",\"다진 홍고추 10g(1개)\",\"레몬즙 60g(4큰술)\",\"설탕 6g(1작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"간장에 생수를 희석하여 염도를 낮추고 레몬의 상큼함을 강조한다.\",\"instructions\":[\"1. 간장, 레몬즙, 설탕, 다진 홍고추를 섞어 드레싱을 만든다.\",\"2. 민들레 잎은 4×4cm로 썰고, 비트는 채 썰고 물에 담가 색을 뺀다.\",\"3. 오렌지는 씻어 껍질만 발라 채 썰고 민들레 잎, 비트, 오렌지 껍질을 섞어 접시에 담고 드레싱을 곁들인다.\"]},{\"id\":\"k29\",\"title\":\"토마토 가지 카프레제\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00202_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00202_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00202_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00202_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 가지 100g(1개)\",\"토마토 200g(1½개)\",\"무순 20g\",\"마늘 10g(2개)\",\"올리브오일 5g(1작은술)\",\"●드레싱 : 올리브오일 25g(2큰술)\",\"발사믹식초 60g(4큰술)\",\"후춧가루 2g(1/2작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨 함량이 높은 토마토와 가지 사용하여 나트륨의 배출을 돕고, 가지와 토마토의 영양성분 중 베타카로틴은 시력보호와 피부노화에 효과가 있다.\",\"instructions\":[\"1. 올리브오일, 발사믹식초, 후춧가루를 섞어 차게 식혀 드레싱을 만든다.\",\"2. 가지와 토마토는 5mm두께로 썰고 120도 오븐에 20분 구운 후 구운 가지는 물기를 제거한다.\",\"3. 팬에 올리브오일을 두르고 약불에서 채 썬 마늘을 볶다가, 가지를 넣고 구운 후 접시에 토마토, 가지를 번갈아 담고 무순으로 장식하고 드레싱을 곁들인다.\"]},{\"id\":\"k30\",\"title\":\"우렁된장소스 배추롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00636_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00636_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(50g)\",\"배춧잎(5장)\",\"부추(30g)\",\"쌀(100g)\",\"당근(20g)\",\"표고버섯(2개)\",\"양파(50g)\",\"애호박(1/2개)\",\"우렁이(100g)\",\"된장(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장에 양파, 당근, 호박, 표고버섯을 많이 섞어 나트륨 함량을 감소시키고, 야채맛이 가득한 된장소스를 만들 수 있어요.\",\"instructions\":[\"1. 끓는 물에 배춧잎을 데친다.\",\"2. 당근, 호박, 표고버섯, 양파는\\n입자있게 다진다.\",\"3. 돼지고기를 썰어 불린 쌀, 다진 야채와\\n함께 밥을 짓는다.\",\"4. 데친 배춧잎에 지어놓은 밥을 올려\\n돌돌만다.\",\"5. 말아 놓은 배춧잎을 부추로 묶는다.\",\"6. 찜통에 김이 오르면 ?번을 넣고 약 5분\\n정도 찐다.\"]},{\"id\":\"k31\",\"title\":\"인삼떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00637_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00637_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(100g)\",\"돼지고기(100g)\",\"대추(3알)\",\"양파(30g)\",\"마늘(20g)\",\"배(1/4개)\",\"애호박(1/2개)\",\"단호박(1/4개)\",\"파프리카(50g)\",\"인삼(1뿌리)\",\"양송이(5개)\",\"배추잎(5장)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"대추의 단맛 때문에 간장을 적게 쓸 수 있어 나트륨을 줄일 수 있어요\",\"instructions\":[\"1. 대추는 돌려 깍아 씨를 제거 하고 곱게\\n다진다.\",\"2. 다진 소고기와 돼지고기에 대추와 소금\\n후춧가루를 넣고 치댄다.\",\"3. 애호박과 단호박, 파프리카는\\n입자있게 썰어 ?에 넣고 잘 치댄다.\",\"4. 양송이는 편으로 썰어 팬에 익히고,\\n인삼을 뇌두를 자르고 깨끗이 씻어\\n팬에 볶아 잘게 썰어 ?에 넣는다.\",\"5. 재료가 골고루 섞인 떡갈비를 갈비\\n모양으로 만든다.\",\"6. 떡갈비를 팬에 굽고, 접시에 배춧잎을\\n깔고 익힌 양송이를 올리고 떡갈비를\\n담는다.\"]},{\"id\":\"k32\",\"title\":\"초계탕과 사색곤약\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00638_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00638_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(1마리)\",\"가시오가피(10g)\",\"대파(20g)\",\"다시마(10g)\",\"건새우(20g)\",\"실곤약(100g)\",\"비트(30g)\",\"치자가루(10g)\",\"마늘(20g)\",\"소금(0.3g)\",\"후춧가루(0.01g)\",\"양파(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마와 건새우의 천연 조미료 성분이 나트륨을 대신할 수 있어요.\",\"instructions\":[\"1. 닭을 깨끗이 손질하고, 부위별로\\n자른다.\",\"2. 냄비에 가시오가피, 대파, 다시마,\\n마늘, 건새우를 넣고 은근히 끓인 후\\n닭을 넣고 약 20분 정도 삶아 건진 뒤\\n살을 찢어둔다.\",\"3. 양파, 오이는 채썰고 식초, 설탕,\\n소금을 넣고 초절임한다\",\"4. 겨자가루에 30℃ 정도의 물을 넣고\\n골고루 섞어 발효시키고, 설탕, 식초,\\n소금을 넣고 겨자소스를 만든다\",\"5. 흰곤약과 비트, 치자가루를 섞은 곤약,\\n채썬 다시마를 접시에 담는다.\",\"6. 양파, 오이 초절임과 닭살을 한쪽에\\n담아 먹기 직전에 겨자소스를 올린다.\"]},{\"id\":\"k33\",\"title\":\"호박잎 삼계탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00639_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00639_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"호박잎(5장)\",\"닭고기(가슴살\",\"120g)\",\"찹쌀(100g)\",\"대추(3알)\",\"미나리(20g)\",\"인삼(1뿌리)\",\"소금(0.2g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소화가 잘되는 찹쌀을 사용하여 쫀득한 맛을 낼 수 있으며, 별도 소스없이 고소한 맛을 즐길 수 있어요.\",\"instructions\":[\"1. 찹쌀은 깨끗이 씻어 30분 정도 불린다\",\"2. 불린 찹쌀은 냄비에 넣고 질게 밥을\\n한다.\",\"3. 닭가슴살은 넓게 펴서 소금,\\n후춧가루를 뿌린다.\",\"4. 호박잎과 미나리는 끓는 물에 살짝\\n데치고, 대추는 돌려 깎아 씨를\\n제거하고 인삼은 뇌두를 제거한 뒤\\n채를 썰어둔다.\",\"5. 데친 호박잎에 닭 가슴살을 올린다.\",\"6. 닭 가슴살위에 찹쌀밥과 준비한 야채와\\n대추를 올려 돌돌 말아 질게 된\\n찹쌀밥에 넣고 약 20분 정도 더 쪄낸다.\"]},{\"id\":\"k34\",\"title\":\"황태미역 곤약스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00640_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00640_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"황태채(100g)\",\"곤약(100g)\",\"건미역(20g)\",\"들깨가루(20g)\",\"두부(50g)\",\"된장(10g)\",\"액젓(10g)\",\"표고버섯(1개)\",\"마늘(10g)\",\"참기름(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장에 두부를 섞어서 나트륨을 감소시킬 수 있어요.\",\"instructions\":[\"1. 된장에 두부를 넣고 골고루 섞는다.\",\"2. 표고버섯과 마늘은 함께 갈아둔다.\",\"3. 미역은 충분히 불린다.\",\"4. 냄비에 황태채와 갈아둔 표고버섯,\\n마늘을 넣고 은근히 끓여 육수를\\n만든다.\",\"5. 곤약은 납작납작하게 썰어 끓는 물에\\n데친다.\",\"6. 육수에서 황태를 건져 두부된장과 함께\\n갈아 육수에 붓고, 미역, 곤약,\\n들깨가루를 넣고 약 20분 정도 끓인 후\\n액젓으로 간을 한다.\"]},{\"id\":\"k35\",\"title\":\"훈제오리가슴살 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00641_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00641_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오리고기(훈제오리 가슴살\",\"150g)\",\"발사믹소스(50g)\",\"양파(30g)\",\"파슬리(5g)\",\"블루베리(20g)\",\"레디쉬(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"훈제오리와 양파채 및 레디쉬채와 블루베리를 함께 먹으면 나트륨 섭취도 감소시켜주고 훈제오리의 맛을 한층 더 좋게 만들어요\",\"instructions\":[\"1. 훈제오리 가슴살을 슬라이스한다.\",\"2. 슬라이스한 훈제오리는 팬에 굽는다.\",\"3. 양파는 채썰고 찬물에 담근 뒤 건진다.\",\"4. 레디쉬는 채썰고 찬물에 담근 뒤\\n건진다.\",\"5. 먹기 직전에 발사믹소스를 만든다.\",\"6. 접시에 훈제오리와 양파채, 레디쉬,\\n블루베리를 담고 발사믹소스를\\n올린다.\"]},{\"id\":\"k36\",\"title\":\"훈제오리가슴살크러스트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00642_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00642_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오리고기(훈제오리 가슴살\",\"150g)\",\"로즈마리(2g)\",\"오렌지(1개)\",\"새송이버섯(1개)\",\"파슬리(5g)\",\"땅콩(50g)\",\"올리브오일(20g)\",\"유자청(20g)\",\"후춧가루(0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"로즈마리를 사용하여 오리고기의 잡내를 제거하고, 유자청을 이용한 소스는 소금을 적게 사용해도 맛을 좋게 만들어요.\",\"instructions\":[\"1. 훈제오리 가슴살은 올리브오일,\\n로즈마리, 후춧가루로\\n마리네이드한다.\",\"2. 새송이버섯은 편으로 썰고 팬에\\n굽는다.\",\"3. 오렌지는 슬라이스로 썬다.\",\"4. 땅콩과 파슬리는 입자있게 다진다.\",\"5. 마리네이드한 오리 고기를 구워 접시에\\n담는다.\",\"6. 유자청에 땅콩, 파슬리가루를 넣고\\n소스를 만들고, 구워진 오리고기\\n사이에 오렌지 슬라이스를 넣고\\n유자청소스를 올린다.\"]},{\"id\":\"k37\",\"title\":\"간장소스를 곁들인 새우전복찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00643_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00643_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"전복(2개)\",\"새우(3마리)\",\"시금치(30g)\",\"해초(20g)\",\"저염간장(20g)\",\"레몬(1/4개)\",\"설탕(20g)\",\"소금(0.1g)\",\"마늘(10g)\",\"녹말(10g)\",\"식용꽃(60g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해초류를 사용해서 소금을 대신할 수 있어요.\",\"instructions\":[\"1. 전복은 수저로 떼어내어 소금으로 비벼\\n깨끗이 씻는다.\",\"2. 시금치는 데쳐 다지고, 새우는 껍질을\\n벗겨 전복, 해초와 함께 다진다.\",\"3. ?번을 잘 섞어 전복 껍질에 넣는다.\",\"4. 찜통에 김이 오르면 속을 채운 전복\\n껍질을 넣고 약 10분 정도 찐다.\",\"5. 저염간장, 레몬, 설탕, 다진마늘을\\n넣고 살짝 끓여 소스를 만든다.\",\"6. 간장소스에 전분을 풀어 농도를\\n맞추고, 전복찜에 여러번 바르고\\n식용꽃을 올린다.\"]},{\"id\":\"k38\",\"title\":\"검은콩국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00644_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00644_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"검은콩(200g)\",\"메밀면(120g)\",\"오이(30g)\",\"방울토마토(1개)\",\"땅콩(20g)\",\"잣(10g)\",\"참깨(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"블랙푸드의 대표 주자인 검은콩으로 만들어 나트륨 함량을 줄일 수 있었어요.\",\"instructions\":[\"1. 검은콩은 깨끗이 씻어 약 12시간 정도\\n충분히 불린다.\",\"2. 불린 검은콩은 20분 정도 삶아 깨끗이\\n씻는다.\",\"3. 삶은 검은콩은 믹서기에 곱게 갈아\\n차갑게 식힌다.\",\"4. 오이는 씨를 제거하고 깨끗이 씻어\\n채썬다.\",\"5. 물을 끓여 메밀면을 삶고, 찬물에\\n여러번 헹구어 건져 물기를 뺀다.\",\"6. 메밀면을 그릇에 담고 차가운 콩 국물,\\n땅콩, 잣, 오이, 방울토마토 및 통깨를\\n올린다.\"]},{\"id\":\"k39\",\"title\":\"겨자소스로 구운 산마샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00645_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00645_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"산마(100g)\",\"참나물(20g)\",\"돈나물(20g)\",\"토마토(100g)\",\"레디쉬(1개)\",\"어린잎(10g)\",\"저염간장(20g)\",\"식초(10g)\",\"설탕(20g)\",\"겨자가루(10g).\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"참나물, 돈나물의 칼륨 성분이 체내에 쌓인 나트륨을 배출을 도와줘요.\",\"instructions\":[\"1. 어린잎은 찬물에 담근다.\",\"2. 마는 껍질을 벗겨 동글동글하게 썬다\",\"3. 썰어 놓은 마는 팬에 기름을 살짝\\n두르고 앞뒤로 굽는다.\",\"4. 참나물, 돈나물, 토마토, 레디쉬는\\n먹기 좋은 크기로 썬다.\",\"5. 겨자가루는 30℃ 물을 섞어 발효\\n시킨다.\",\"6. 저염간장에 식초, 설탕, 발효겨자를\\n넣고 골고루 섞어 소스를 만들고,\\n접시에 구운 마와 손질한 야채를 넣고\\n만들어 놓은 소스와 어린잎을 올린다.\"]},{\"id\":\"k40\",\"title\":\"닭고기김치찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00271_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00271_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 닭가슴살(60g)\",\"애호박(30g)\",\"미나리(20g)\",\"청양고추(3g)\",\"두부(60g)\",\"김치(120g)\",\"참기름(20g)\",\"느타리버섯(10g)\",\"달걀(50g)\",\"육수 다시마(5g)\",\"무(40g)\",\"대파(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치다시마육수를 이용해 깊은 맛을 내 소금간을 줄여\\n나트륨 섭취를 적게 할 수 있고, 달걀물을 부어 자극적인 맛을 줄였다.\",\"instructions\":[\"1. 육수 재료를 넣고 중간 불로 끓인 뒤\\n체에 걸러 육수를 만든다.\",\"2. 닭가슴살은 채 썬 뒤 물에 넣고\\n삶는다.\",\"3. 애호박은 반달 썰고, 미나리는 5㎝\\n길이로 썰고, 청양고추는 잘게 썬 뒤\\n찬물에 담가 씨를 빼고, 두부는 한입\\n크기로 썰어 물에 담가둔다.\",\"4. 김치를 한입 크기로 썬 뒤 참기름에\\n볶다가 육수를 붓는다.\",\"5. 두부, 애호박, 느타리버섯, 미나리,\\n닭가슴살을 넣어 끓어오르면\\n달걀물과 청양고추를 넣고 조금\\n더 끓여 마무리한다.\"]},{\"id\":\"k41\",\"title\":\"완자김치찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00272_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00272_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 콩나물(30g)\",\"김치(50g)\",\"두부(40g)\",\"붉은 고추(15g)\",\"다진 돼지고기(등심\",\"60g)\",\"새우젓(5g)\",\"육수 대파(10g)\",\"마늘(5g)\",\"쇠고기(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치는 물에 한 번 씻어 염분을 최대한 제거하고,\\n쇠고기육수로 깊은 맛을 내고 붉은 고추로 매콤한 맛을 더해\\n소금간을 하지 않아 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 대파, 마늘, 쇠고기를 물(300g)과\\n함께 끓인 뒤 면포에 걸러 육수를\\n만든다.\",\"2. 콩나물, 김치를 물에 씻어 손질한다.\",\"3. 두부는 물기를 빼고, 붉은 고추는\\n다진 뒤 돼지고기와 섞어 반죽해\\n동그랗게 빚어 완자를 만든다.\",\"4. 김 오른 찜기에 완자를 넣어 찐다.\",\"5. 육수를 끓이고 끓어오르면 김치,\\n콩나물, 새우젓을 넣는다.\",\"6. 한소끔 더 끓이다가 완자를 넣고\\n조금 더 끓여 마무리한다.\"]},{\"id\":\"k42\",\"title\":\"백김치콩비지찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00273_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00273_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 풋고추(10g)\",\"백김치(100g)\",\"콩비지(100g)\",\"양념 참기름(8g)\",\"후춧가루(0.2g)\",\"다진 마늘(10g)\",\"간장(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"콩비지찌개를 끓일 때 넣는 묵은지 대신\\n백김치를 넣어 염분을 줄이고 깔끔한 맛을 냈다.\",\"instructions\":[\"1. 풋고추는 잘게 다진다.\",\"2. 백김치는 먹기 좋은 크기로 썬다.\",\"3. 냄비에 백김치를 볶다가 김치가\\n익으면 참기름, 후춧가루,\\n다진 마늘을 넣고 볶는다.\",\"4. 물(200g)을 넣고 끓인다.\",\"5. 물이 끓으면 콩비지와 간장,\\n풋고추를 넣어 약한 불에서 15분\\n정도 끓여 마무리한다.\"]},{\"id\":\"k43\",\"title\":\"오징어김치찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00274_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00274_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 오징어(100g)\",\"두부(50g)\",\"팽이버섯(20g)\",\"붉은 고추(4g)\",\"고구마(30g)\",\"콩나물(20g)\",\"김치(140g)\",\"쑥갓(20g)\",\"육수 무(50g)\",\"다시마(5g)\",\"대파(20g)\",\"멸치(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치의 속을 덜어내 염분을 줄였고,\\n김치 자체의 간만을 이용해 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 육수 재료를 넣고 끓인 뒤 체로 걸러\\n육수를 낸다.\",\"2. 오징어 몸통은 큼지막하게 썰고\\n다리는 얇게 썬다.\",\"3. 두부와 버섯은 먹기 좋게 썰고,\\n고추는 어슷하게 썰고, 고구마는\\n먹기 좋은 크기로 썰고, 콩나물은\\n다듬는다.\",\"4. 김치는 먹기 좋은 크기로 썬 뒤\\n냄비에 참기름을 두르고 볶다가\\n고구마, 콩나물, 육수를 넣고 끓인다.\",\"5. 자작하게 끓으면 오징어를 넣고\\n끓이고, 오징어가 익으면 들깻가루를\\n넣고 끓인다.\",\"6. 두부, 팽이버섯, 쑥갓, 고구마,\\n붉은 고추를 넣고 끓여 마무리한다.\"]},{\"id\":\"k44\",\"title\":\"해물김치찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306022845_1678080525384.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306022942_1678080582607.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023039_1678080639676.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023103_1678080663820.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313110637_1678673197807.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023149_1678080709863.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023210_1678080730863.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 주꾸미(40g)\",\"김치(40g)\",\"무(10g)\",\"마늘(3g)\",\"대파(3g)\",\"양파(10g)\",\"두부(10g)\",\"참기름(3g)\",\"배즙(10g)\",\"팽이버섯(3g)\",\"•육수 재료 : 다시마(5g)\",\"멸치(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•김치는 국물을 꼭 짜서 사용해 염분을 줄였고, 해산물을 넣어 간을 맞췄어요.\\n•배즙으로 짠맛을 중화하면서 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 냄비에 육수 재료를 넣고 끓이다가 물이 끓어오르면 다시마를 건지고 조금 더 끓여 육수를 우려낸다.\",\"2. 주꾸미는 내장과 입, 눈을 제거하고 4cm 크기로 잘라 준비한다.\",\"3. 김치는 국물을 꽉 짜서 한입 크기로 썰고, 무는 편 썰고, 마늘은 다지고, 대파는 어슷 썰고, 양파는 굵게 채 썰고, 두부는 납작하게 썬다.\",\"4. 냄비에 참기름을 두르고, 김치, 무, 양파가 투명해질 때까지 볶다가 육수를 붓고 끓으면 주꾸미, 다진 마늘을 넣어 더 끓인다.\",\"5. 김칫국물과 배즙을 2:1로 섞은 뒤 찌개에 넣어 간을 맞춘다.\",\"6. 두부, 팽이버섯을 넣고 한소끔 끓여 마무리한다\"]},{\"id\":\"k45\",\"title\":\"맑은부대찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00276_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00276_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 느타리버섯(10g)\",\"두부(50g)\",\"콩나물(10g)\",\"배추(40g)\",\"미나리(20g)\",\"돼지고기(50g)\",\"쇠고기(50g)\",\"불린 당면(10g)\",\"조랭이떡(30g)\",\"다시마육수 다시마(3g)\",\"양파(30g)\",\"대파(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"보통 부대찌개에 들어가는 김치와 햄 대신\\n배추와 고기완자를 넣어 나트륨 함량을 줄였다.\",\"instructions\":[\"1. 다시마육수재료를 물에 넣고 끓여\\n육수를 낸다.\",\"2. 느타리버섯은 가닥가닥 떼고, 두부는\\n썰고, 콩나물은 머리와 꼬리를 떼\\n손질한다.\",\"3. 배추와 미나리를 데친다.\",\"4. 돼지고기, 쇠고기에 고기완자양념을\\n넣어 반죽한 뒤 빚어 완자를 만든다.\",\"5. 냄비에 모든 재료를 돌려 담은 뒤\\n육수를 부어 끓인다.\"]},{\"id\":\"k46\",\"title\":\"나가사키부대찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00277_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00277_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 통조림 햄(30g)\",\"우유(100g)\",\"실곤약(50g)\",\"양파(30g)\",\"느타리버섯(25g)\",\"표고버섯(10g)\",\"팽이버섯(30g)\",\"청양고추(5g)\",\"붉은 고추(5g)\",\"감자(30g)\",\"무(30g)\",\"두부(40g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨 함량이 높은 김치와 고추장 대신 사골육수와 청양고추를 사용해\\n염도를 낮추면서 칼칼하고 깔끔한 맛을 내 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 통조림 햄은 한 번 데친 뒤 우유에\\n담가두고, 실곤약은 식초를 넣은\\n끓는 물에 살짝 데친다.\",\"2. 양파는 굵게 채 썰고, 느타리버섯은\\n찢고, 표고버섯은 모양대로 썰고,\\n팽이버섯은 끝부분을 잘라내고,\\n청양고추와 붉은 고추는 어슷 썬다.\",\"3. 감자, 무, 두부는 0.5㎝ 두께로 썰고,\\n애호박은 반달썰기 하고 깻잎은\\n채 썰어 찬물에 담가 매운맛을\\n제거한다.\",\"4. 사골육수에 다시마를 넣어 끓인 후\\n한 김 식힌다.\",\"5. 다진 돼지고기에 다진 파, 다진 마늘,\\n후춧가루, 소금을 섞어 완자를\\n만들고 밀가루와 달걀물을 묻혀\\n식용유(5g)를 두른 팬에 부친다.\",\"6. 냄비에 재료를 보기 좋게 담고\\n사골육수를 부은 뒤 끓이다가\\n쑥갓과 들깻가루를 넣어 마무리한다.\"]},{\"id\":\"k47\",\"title\":\"삼계부대찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00278_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00278_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 닭가슴살(100g)\",\"당근(20g)\",\"붉은 고추(6g)\",\"풋고추(6g)\",\"대파(6g)\",\"쑥갓(4g)\",\"표고버섯(14g)\",\"애호박(60g)\",\"김치(40g)\",\"팽이버섯(40g)\",\"당면(21g)\",\"숙주(40g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장에 고추장 대신 겨자가루와 콩가루로 간을 하여 나트륨 사용을 줄였다\",\"instructions\":[\"1. 육수 재료를 넣고 20분간 끓여\\n육수를 낸다.\",\"2. 닭가슴살과 당근을 다져 모양을\\n잡은 뒤 김 오른 찜기에 넣고 찐다.\",\"3. 고추, 대파는 어슷 썰고, 쑥갓,\\n표고버섯, 애호박, 김치는 먹기\\n좋은 크기로 썰고, 팽이버섯은\\n밑동을 잘라 손질한다.\",\"4. 당면과 숙주는 뜨거운 물에 데쳐\\n준비한다.\",\"5. 양념장 재료를 섞은 뒤 육수(13g)를\\n넣고 양념장을 만든다.\",\"6. 준비한 재료를 담고 육수를 부은 뒤\\n양념장을 넣고 끓여 마무리한다.\"]},{\"id\":\"k48\",\"title\":\"쑥갓부대찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012547_1678249547987.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012641_1678249601913.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012702_1678249622285.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012717_1678249637881.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012732_1678249652118.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012747_1678249667092.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012805_1678249685798.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 통조림 햄(30g)\",\"애호박(20g)\",\"두부(20g)\",\"팽이버섯(20g)\",\"청양고추(5g)\",\"김치(30g)\",\"쑥갓(4g)\",\"•육수 : 다시마(5g)\",\"물(200g)\",\"•양념장 : 설탕(0.5g)\",\"고춧가루(4g)\",\"다진마늘(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•김치는 씻어서 사용하고 햄은 한 번 데쳐 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 통조림 햄을 썰어 끓는 물에 데친다.\",\"2. 애호박은 반달모양으로 썰고, 두부는 도톰하게 썰고, 팽이버섯은 3등분하고, 청양고추는 어슷 썬다.\",\"3. 김치는 씻어서 잘게 썬다.\",\"4. 양념장을 만든다.\",\"5. 냄비에 물과 다시마를 넣고 살짝 끓여 육수를 만든다.\",\"6. 육수에 손질한 재료를 담고 양념장의 1/2 분량을 넣고 중간 불에 끓이다가 쑥갓과 남은 양념장을 넣고 약한 불에 조금 더 끓여 마무리한다.\"]},{\"id\":\"k49\",\"title\":\"들깨순두부찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00280_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00280_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 굴(40g)\",\"멸치(2g)\",\"표고버섯(10g)\",\"느타리버섯(40g)\",\"무(20g)\",\"양파(10g)\",\"미나리(10g)\",\"대파(3g)\",\"붉은 고추(2g)\",\"순두부(100g)\",\"양념 다진 마늘(1g)\",\"들깻가루(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"보통 순두부찌개에 넣는 고춧가루를 넣지 않고\\n들깻가루와 들깨를 넣어 고소한 맛을 내 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 굴은 깨끗이 씻은 뒤 김 오른 찜기에\\n찐다.\",\"2. 굴을 쪄낸 물(250g)에 멸치,\\n표고버섯 밑동을 넣고 끓인 뒤\\n멸치와 표고버섯 밑동을 건져내\\n육수를 만든다.\",\"3. 느타리버섯은 밑동을 제거한 후\\n씻어 세로로 찢고, 표고버섯은\\n0.5㎝ 두께로 썬다.\",\"4. 무는 나박 썰고 양파는 채 썰고,\\n미나리는 3㎝ 길이로 썰고,\\n대파와 고추는 송송 썬다.\",\"5. 육수에 굴, 다진 마늘, 무, 양파,\\n버섯을 넣고 끓인다.\",\"6. 들깻가루와 순두부를 넣고 한소끔\\n끓인 뒤 국간장과 소금으로 간을\\n맞추고 대파, 붉은 고추, 미나리를\\n올려 마무리한다.\"]},{\"id\":\"k50\",\"title\":\"백태순두부찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00281_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00281_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 콩(백태\",\"30g)\",\"느타리버섯(10g)\",\"표고버섯(10g)\",\"애호박(20g)\",\"양파(10g)\",\"대파(5g)\",\"붉은 고추(2g)\",\"풋고추(2g)\",\"바지락(30g)\",\"저염된장(10g)\",\"새우(25g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"매콤한 보통의 순두부찌개와는 달리 백태와 청양고추로\\n맛을 내 나트륨 함량을 낮추면서 새우와 바지락으로 감칠맛을 냈다.\",\"instructions\":[\"1. 냄비에 육수 재료를 넣어 끓인다.\",\"2. 콩을 충분히 불려 믹서기에 물을\\n넣고 갈아 준비한다.\",\"3. 느타리버섯은 찢고, 표고버섯은 먹기\\n좋은 크기로 자르고, 애호박과\\n양파는 깍둑 썰고, 대파와 고추는\\n송송 썬다.\",\"4. 바지락은 해감해 준비한다.\",\"5. 육수에 콩, 느타리버섯, 표고버섯,\\n애호박, 저염된장, 새우, 바지락을\\n넣고 끊인다.\",\"6. 순두부를 넣고 끊인 후 양파, 대파,\\n붉은 고추, 풋고추를 넣고 한소끔\\n끓여 마무리한다.\"]},{\"id\":\"k51\",\"title\":\"버섯순두부찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053608_1678264568602.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053656_1678264616396.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053712_1678264632312.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053727_1678264647414.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053743_1678264663037.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053800_1678264680719.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053819_1678264699729.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 표고버섯(3g)\",\"애호박(10g)\",\"감자(10g)\",\"양파(3g)\",\"미나리(3g)\",\"부추(1g)\",\"대파(1g)\",\"청양고추(1g)\",\"순두부(100g)\",\"•육수 : 다시마(3g)\",\"표고버섯 밑동(3g)\",\"물(250g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•된장의 양을 줄이는 대신 찹쌀가루와 들깻가루로 구수한 맛을 내 나트륨 함량을 낮췄어요.\\n•감자는 체내 나트륨 배출을 돕는 칼륨이 다량 함유된 채소예요.\",\"instructions\":[\"1. 표고버섯은 머리와 밑동을 분리하고, 머리 부분은 잘게 썬다.\",\"2. 애호박, 감자, 양파는 한입 크기로 썰고, 미나리와 부추는 3cm 길이로 썰고, 대파와 청양고추는 송송 썬다.\",\"3. 물에 다시마, 표고버섯 밑동을 넣고 끓으면 건더기를 건져 육수를 만든다.\",\"4. 육수에 저염된장과 찹쌀가루를 풀어 한소끔 끓이고, 감자와 다진마늘을 넣어 끓인다.\",\"5. 애호박과 표고버섯을 넣고, 순두부, 양파, 들깻가루, 저염국간장을 넣어 한소끔 끓인다.\",\"6. 대파, 청양고추, 미나리, 부추를 듬뿍 올려 마무리한다.\"]},{\"id\":\"k52\",\"title\":\"토란순두부찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00283_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00283_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00283_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00283_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00283_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00283_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00283_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 토란(40g)\",\"표고버섯(20g)\",\"붉은 고추(1g)\",\"청양고추(2g)\",\"백합(150g)\",\"들깻가루(40g)\",\"순두부(150g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"백합으로 진한 육수를 내고 들깻가루로 구수한 맛을 더해 소금간을 줄여 나트륨 함량을 낮췄다.\\n또한 나트륨 배출에 효과적인 토란을 넣었다.\",\"instructions\":[\"1. 토란은 2×2㎝로 썬다.\",\"2. 표고버섯은 채 썰고, 고추는\\n어슷하게 썬다.\",\"3. 냄비에 물(500ml)을 넣고 물이\\n끓으면 백합을 넣고 끓여 육수를\\n낸다.\",\"4. 조개가 입을 벌리면 토란과\\n들깻가루, 표고버섯을 넣고 끓인다.\",\"5. 육수가 어느 정도 걸쭉해지면\\n순두부를 넣고 끓인다.\",\"6. 붉은 고추와 청양고추를 올려\\n마무리한다.\"]},{\"id\":\"k53\",\"title\":\"토마토스프파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00385_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00385_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00385_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00385_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00385_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00385_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00385_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홀토마토 200g\",\"토마토 100g\",\"다진양파 30g\",\"다진마늘 20g\",\"먹물파스타 25g\",\"치즈 25g\",\"파슬리가루 1g\",\"함초소금 1g\",\"올리브오일 30g\",\"곁들이 야채 : 양파 20g\",\"가지 20g\",\"2가지색 파프리카 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨 배출에 도움을 주는 토마토와 갖가지 채소들이 조화를 이루어 짠맛을 대체하였다.\",\"instructions\":[\"1. 토마토홀과 토마토는 송송 다져주고, 마늘,\\n양파를 냄비에서 볶은 후 믹서에 갈아 토마토\\n스프를 만들어준다.\",\"2. 만들어진 스프를 볶아서 신맛을 날려준다.\",\"3. 먹물파스타면은 삶은 뒤 오일에 버무려주고\\n볶아준다.\",\"4. 양파, 애호박, 가지, 2가지색 파프리카를 먹기\\n좋게 잘라 팬에 볶아준다.\",\"5. 접시에 볶아진 채소와 파스타면을 서로 다시\\n볶아준다.\",\"6. 치즈를 곱게 다져주고 접시에 파스타면을\\n올린 뒤, 토마토스프와 치즈가루를 뿌려 완성\\n한다.\"]},{\"id\":\"k54\",\"title\":\"다이어트국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00386_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00386_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00386_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00386_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00386_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00386_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00386_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"실곤약 200g\",\"물김치국물 200g\",\"오이 25g\",\"달걀 1개(60g)\",\"당근 20g\",\"양파 50g\",\"통깨 3g\",\"레몬즙 15g\",\"탄산수 50ml\",\"어간장 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"열무물김치의 시원한 맛과 청량감이 느껴지는 탄산수, 그리고 염이 낮은 어간장으로 국수국물이 조화를 이루었다.\",\"instructions\":[\"1. 양파, 당근, 오이는 채 썰어준다.\",\"2. 열무 물김치와 탄산수, 어간장을 넣어 국수\\n국물을 만들어준다.\",\"3. 달걀은 삶아준다.\",\"4. 실곤약은 삶을 때 레몬즙을 넣어서 곤약의\\n특이한 냄새를 제거한다.\",\"5. 물기를 제거한 곤약에 어간장을 넣어 밑간을\\n해준다.\",\"6. 그릇에 담고 국물을 부어주고, 채소와 달걀을\\n곁들여 완성한다.\"]},{\"id\":\"k55\",\"title\":\"오징어구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00387_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00387_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00387_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00387_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00387_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00387_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00387_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어 300g\",\"미니파프리카 40g\",\"양파 50g\",\"청고추 15g\",\"홍고추 15g\",\"양념장 : 다진마늘 15g\",\"고춧가루 15g\",\"홀토마토 50g\",\"고추장 15g\",\"설탕 15g\",\"올리고당 15g\",\"후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장 대신 홀토마토를 사용해 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 오징어는 솔방울 모양으로 잘라준다.\",\"2. 미니 파프리카, 양파, 청홍고추는 적당한\\n크기로 잘라준다.\",\"3. 다진마늘을 볶다가 오징어를 넣어 볶는다.\",\"4. 홀토마토와 양념장 재료를 넣어 볶는다.\",\"5. 팬을 약간 태우는 듯 해서 불맛과 매운맛을\\n더해준다.\",\"6. 접시에 담아주고 볶은 현미를 뿌려 완성한다.\"]},{\"id\":\"k56\",\"title\":\"배숙구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00388_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00388_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00388_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00388_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00388_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00388_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배 750g\",\"후르츠칵테일 150g\",\"생강청 50g\",\"방울토마토 60g\",\"탄산수 200g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배의 시원한 맛에 탄산수의 개운한 맛을 더하여 추가 간을 하지 않아도 맛있는 음료를 즐길 수가 있다.\",\"instructions\":[\"1. 뚜껑을 만들 배의 윗동을 자르고, 수저로\\n배 속을 판다.\",\"2. 탄산수와 생강청을 미리 30분 전에 섞어준다.\",\"3. 방울토마토를 먹기 좋게 잘라준 후 속을 파낸\\n배에 후르츠 칵테일과 방울토마토를 넣어준다.\",\"4. 과일로 채워진 배에 미리 만든 생강탄산수를\\n부어준다.\",\"5. 배를 뚜껑을 덮어 호일로 싼 후 팬에 구워준다.\"]},{\"id\":\"k57\",\"title\":\"웰빙스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00389_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00389_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00389_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00389_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00389_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00389_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00389_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기등심 240g\",\"시금치 50g\",\"마늘 15g\",\"양파 50g\",\"건바질 2g\",\"감자 60g\",\"레몬 25g\",\"파슬리가루 1g\",\"소스 : 르네디종 홀그레인머스터 15g\",\"사과 80g\",\"버터 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과의 단맛과 버터의 고소한 맛으로 소스를 만들어 추가 간을 따로 하지 않고 소고기의 풍미와 맛을 살려주었다.\",\"instructions\":[\"1. 쇠고기는 칼집을 살짝 넣어준 후 건 바질을\\n뿌려 1시간 정도 숙성시킨다.\",\"2. 감자는 껍질을 벗긴 후 먹기 좋게 잘라 뜨거운\\n물에 70% 정도 익혀준다.\",\"3. 익혀준 감자를 버터를 살짝 바른 후 팬에\\n파슬리가루를 뿌려 구워준다.\",\"4. 시금치는 데쳐내 물기를 제거하고 다진 양파와\\n함께 버터에 볶아준다.\",\"5. 사과는 사방 1cm 크기로 자른 후 레몬즙을\\n살짝 뿌려준 후 버터에 볶아 소스를 만들어\\n준다.\",\"6. 숙성된 소고기를 팬에 구워주고 곁들이 채소와\\n소스를 완성한다.\"]},{\"id\":\"k58\",\"title\":\"오징어콩순대\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00390_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00390_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00390_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00390_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00390_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00390_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00390_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어 1마리(220g)\",\"옥수수 30g\",\"귀리밥 50g\",\"강낭콩 20g\",\"당근 20g\",\"미니파프리카 20g\",\"피망 20g\",\"대파 10g\",\"양파 25g\",\"카레가루 25g\",\"흰후추 1g\",\"다진마늘 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 카레가루를 곁들여 향미를 돋우고, 귀리와 강낭콩을 이용해 식감을 높였다.\",\"instructions\":[\"1. 오징어는 내장을 빼서 흐르는 물에 깨끗이\\n씻은 후, 다리는 송송 다져주고 레몬즙을\\n살짝 뿌려준다.\",\"2. 강낭콩은 먼저 삶아준다.\",\"3. 피망, 당근, 양파, 대파, 파프리카는 송송\\n다져준다.\",\"4. 잘라준 오징어다리는 다진마늘과 살짝\\n볶아준다.\",\"5. 볼에 귀리밥을 넣고 카레가루를 넣고 모든\\n재료를 섞어 소 재료를 만든다.\",\"6. 오징어 안쪽에 밀가루를 묻혀주고 소를 채워\\n팬에 구워준다.\"]},{\"id\":\"k59\",\"title\":\"토마토소고기장조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00391_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00391_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00391_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00391_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00391_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00391_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기 우둔살 200g\",\"메추리알 100g\",\"방울토마토 100g\",\"마늘 30g\",\"꽈리고추 50g\",\"양파 45g\",\"양념장 : 맛간장 30g\",\"흰후추 1g\",\"어간장 15g\",\"설탕 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"우둔살을 한 번 데쳐내 간장이 고기 내부까지 흡수되는 것을 방지하였다.\",\"instructions\":[\"1. 소고기는 사방 2cm 정도의 크기로 잘라서\\n물에서 80% 정도까지 익혀준 후 냉수에\\n깨끗하게 세척해 준다.\",\"2. 양파는 먹기 좋게 자르고 물 400g과 함께\\n간장 물을 만들어준다.\",\"3. 간장 물에 데쳐 놓은 소고기부터 졸여주기\\n시작한다.\",\"4. 메추리알을 넣고 함께 졸여준다.\",\"5. 방울토마토, 양파, 마늘, 꽈리고추까지 넣고\\n마지막으로 졸여준다.\"]},{\"id\":\"k60\",\"title\":\"토마토소고기찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00392_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00392_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00392_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00392_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00392_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00392_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00392_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기우둔살 200g\",\"샐러리 40g\",\"당근 30g\",\"양파 50g\",\"화이트와인 25g\",\"홀토마토 100g\",\"버터 20g\",\"레몬 25g\",\"흰후추 1g\",\"파슬리가루 2g\",\"함초소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"샐러리, 파슬리가루, 흰후추 등 향신료를 사용해 향신료 특유의 맛과 향으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 당근, 양파, 샐러리는 사방 2cm 정도로\\n잘라준다.\",\"2. 레몬은 껍질을 아주 곱게 채 썰어준다.\",\"3. 소고기는 사방 3cm 정도로 자르고 흰 후추를\\n뿌려준다.\",\"4. 홀토마토는 먹기 좋게 부수어 준 후 볶아준다.\",\"5. 팬에 버터를 넣고 소고기부터 볶기 시작하다\\n채소를 넣고 볶아준다. 이 때 두꺼운 채소부터\\n볶아주는 것이 고기랑 익는 시간이 같아진다.\",\"6. 마지막에 다져 놓은 홀토마토를 넣고 함초소금\\n으로 간을 한 후 레몬껍질을 올려서 마무리\\n한다.\"]},{\"id\":\"k61\",\"title\":\"맛간장삼치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00393_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00393_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00393_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00393_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00393_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00393_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00393_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼치 200g\",\"생강 50g\",\"대파 100g\",\"통깨 1g\",\"버터 10g\",\"소스 : 맛간장 30g\",\"생강청 25g\",\"커피 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"커피를 넣어 삼치의 비린맛을 잡아주고, 야채 발효액이 첨가된 맛간장을 사용해서 염도는 낮추고 깊은 맛을 살렸다.\",\"instructions\":[\"1. 소스 재료를 이용해 맛 간장으로 만든 데리\\n야끼소스를 만들어준다.\",\"2. 참치는 손질해 수분을 빼준 후 흰 후추로\\n밑간을 해준다.\",\"3. 생강은 아주 곱게 채 썰어 냉수에 헹군다.\",\"4. 대파도 아주 가늘게 채 썰어서 냉수에 담가\\n매운맛을 빼준다.\",\"5. 버터를 올린 팬에 삼치를 약불에서 구워준다.\",\"6. 구워진 참치를 소스에 졸여주고 대파채를\\n올린다. 삼치에 소스를 뿌리고 생강채를 올려\\n완성한다.\"]},{\"id\":\"k62\",\"title\":\"삼겹살꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00394_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00394_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00394_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00394_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00394_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00394_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼겹살 200g\",\"방울토마토 100g\",\"마늘기름 15g\",\"후추 1g\",\"로즈마리 1g\",\"통후추 2g\",\"대파 20g\",\"마늘 10g\",\"꽈리고추 25g\",\"대파채 : 대파 25g\",\"고춧가루 1g\",\"레몬즙 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 후추, 로즈마리 등의 향신료와 마늘기름, 대파를 사용하여 나트륨을 줄였으며, 이 재료들 특유의 맛과 향이 삼겹살의 누린내를 잡아주고 음식을 조화롭게 해준다.\",\"instructions\":[\"1. 삼겹살은 길이로 잘라서 마늘기름, 통후추,\\n로즈마리에 마리네이드 해준다.\",\"2. 대파는 흰 부분만 잘라 구워주고, 꽈리고추도\\n함께 구워준다.\",\"3. 대파는 가늘게 채 썰어 물에 담가준다.\",\"4. 물에 담가진 대파를 물기를 빼고 양념해준다.\",\"5. 삼겹살을 꼬치에 끼워 굽고 구워진 채소,\\n대파채와 함께 완성한다.\"]},{\"id\":\"k63\",\"title\":\"새우아욱죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00395_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00395_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00395_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00395_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00395_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00395_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00395_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"귀리밥 100g\",\"아욱 30g\",\"건새우 25g\",\"칵테일새우 25g\",\"저염 된장 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"일반 된장 보다 염도를 낮춘 저염된장을 사용하고 칼륨의 함량이 높은 아욱을 넣어 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 저염 된장을 물 300cc에 풀어준 뒤 건새우를\\n담가 30분 정도 담가준 뒤 살짝 끓여준다.\",\"2. 새우를 풀어준 된장 물을 체에 걸러준다.\",\"3. 아욱은 뜨거운 물에 데쳐서 먹기 좋게 썬다.\",\"4. 냄비에 밥과 된장 물을 풀어 끓인다.\",\"5. 어느 정도 끓으면 칵테일새우와 건져 놓았던\\n새우를 다시 넣어준다.\",\"6. 불을 끄기 전에 아욱을 넣어 한 번 더 끓여준\\n후 완성한다.\"]},{\"id\":\"k64\",\"title\":\"까르보나라뇨끼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00396_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00396_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00396_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00396_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00396_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00396_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00396_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 220g\",\"깻잎 10g\",\"베이컨 25g\",\"백일송이 25g\",\"다진마늘 15g\",\"다진양파 25g\",\"다진대파 25g\",\"흰후추 3g\",\"버터15g\",\"우유 200g\",\"생크림 30g\",\"설탕 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"염분이 많은 베이컨을 한 번 데친 후 사용하여 나트륨 섭취량을 줄였고 양파와 우유, 생크림을 이용하여 구수하고 담백한 맛을 높였다.\",\"instructions\":[\"1. 감자를 슬라이스 하여 찜통에 찐 후 체에\\n으깬다. 깻잎을 잘게 채 썰어서 냉수에 담가\\n향을 빼준다.\",\"2. 베이컨을 한 번 데쳐내 송송 썰어준 후 다진\\n마늘과 볶아준다.\",\"3. 으깬 감자와 깻잎을 다져서 반죽을 만들고\\n엄지손가락 크기로 떼어 밀가루를 뿌리고,\\n둥글게 빚은 후 포크로 자국을 내 뇨끼를 만든다.\",\"4. 만들어진 뇨끼를 삶아 건져준다.\",\"5. 팬에 버터를 넣고 다진양파, 다진마늘, 다진\\n대파, 볶은 베이컨, 새송이, 흰후추를 볶다가\\n우유와 생크림, 설탕을 넣고 끓여준다.\",\"6. 뇨끼를 넣어 한 번 더 끓여준 뒤 완성한다.\"]},{\"id\":\"k65\",\"title\":\"호박죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00397_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00397_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00397_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00397_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00397_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00397_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00397_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 200g\",\"찹쌀가루 100g\",\"브로콜리 50g\",\"양파 60g\",\"볶은 현미 25g\",\"버섯마늘소금 2g\",\"흰후추 1g\",\"치즈가루 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"호박죽의 감칠맛을 높이기 위해 버섯마늘소금과 치즈가루로 간을 하였다.\\n볶은 현미를 이용해 나트륨 사용을 줄여주고 고소함을 더했다.\",\"instructions\":[\"1. 단호박은 껍질을 까고 작게 잘라주고, 양파도\\n작게 잘라준다.\",\"2. 브로콜리는 뜨거운 물에 데쳐내 준 후 송송\\n잘라준다.\",\"3. 찹쌀가루는 물 100g에 풀어준다.\",\"4. 단호박과 양파는 물 300g에 삶아준다.\",\"5. 단호박과 양파가 익으면 믹서에 갈아서 다시\\n끓여준 뒤 찹쌀가루물을 넣어 끓여준다.\",\"6. 호박죽이 끓어오르면 치즈가루를 넣어준 후\\n볶은 현미랑 완성한다.\"]},{\"id\":\"k66\",\"title\":\"라이스버거떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00398_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00398_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00398_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00398_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00398_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00398_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00398_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"라이스버거 : 밥 200g\",\"맛간장 15g\",\"전분가루 15g\",\"팽이버섯 20g\",\"흰후추 1g\",\"달걀 60g\",\"떡갈비 : 다진소고기 50g\",\"다진돼지고기 50g\",\"다진양파 30g\",\"다진쪽파 15g\",\"맛간장 10g\",\"후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라이스버거와 떡갈비를 함께 먹을 수 있는 겉절이를 절인 배추 대신 칼륨이 풍부한 토마토와 양파를 주재료로 하여 만들었다. 일반 간장 대신 염도가 낮은 맛간장으로 맛을 냈다.\",\"instructions\":[\"1. 팽이버섯을 송송 다진 후 라이스버거 재료로\\n라이스버거를 만들어준다.\",\"2. 만들어준 버거는 팬에 구워준다.\",\"3. 토마토와 미나리를 먹기 좋게 잘라서 겉절이를\\n만들어준다.\",\"4. 떡갈비 재료로 떡 갈비를 만들어준다.\",\"5. 만들어진 떡갈비를 구워준다.\",\"6. 접시에 토마토 겉절이를 담고 라이스버거와\\n떡갈비를 올려 완성한다.\"]},{\"id\":\"k67\",\"title\":\"고추김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052031_1678090831734.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052119_1678090879888.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052136_1678090896972.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052154_1678090914303.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052208_1678090928991.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052224_1678090944885.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052240_1678090960385.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 오이고추(40g)\",\"영양부추(5g)\",\"연근(5g)\",\"무(5g)\",\"•절임물 : 해물육수(8g)\",\"어간장(3g)\",\"•양념 : 고춧가루(3g)\",\"생강청(3g)\",\"통깨(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•김치를 담글 때 사용하는 젓갈 대신 연근, 부추, 생강청으로 대체하여 김치 특유의 맛과 향미를 높였어요.\",\"instructions\":[\"1. 오이고추는 배를 갈라 씨를 제거하고 세척 후 절임물에 절여준다.\",\"2. 영양부추, 연근은 송송 다지고 무는 채 썬다.\",\"3. 손질한 부추와 연근, 무에 절임물을 조금 넣고 절인다.\",\"4. 고춧가루, 생강청, 통깨를 절임채소에 섞어 소를 만든다.\",\"5. 오이고추 속에 소를 채워 넣는다.\",\"6. 오이고추를 그릇에 담고 남은 물을 부어 마무리한다.\"]},{\"id\":\"k68\",\"title\":\"누룽닭\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00500_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00500_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00500_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00500_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00500_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00500_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00500_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살(120g)\",\"생강즙(5g)\",\"정종(10g)\",\"시금치(20g)\",\"당근(20g)\",\"양파(20g)\",\"샐러리(20g)\",\"파프리카(20g)\",\"느타리(20g)\",\"주꾸미(30g)\",\"새우(20g)\",\"청경채(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"주꾸미와 새우를 넣어 만들어서, 나트륨을 적게 넣어 만들 수 있었어요.\",\"instructions\":[\"1. 닭은 포를 떠서 생강즙과 정종을 섞어\\n발라 놓는다.\",\"2. 시금치는 살짝 데쳐 썰고, 당근, 양파,\\n샐러리, 파프리카는 약 6Cm 길이로\\n채를 썰어 절반은 닭고기말이에 사용\\n하고, 절반은 곁들임채소로 사용한다.\",\"3. 느타리는 끓는 물에 소금을 넣고 데쳐\\n손으로 찢어놓고, 포를 뜬 닭가슴살에\\n느타리와 썰어 놓은 채소를 넣어 말아\\n주고, 육수를 끓여서 말아놓은 닭을\\n넣고 익혀낸다.\",\"4. 주꾸미와 새우는 끓는 물에 살짝 데치고,\\n청경채는 반으로 썰어 살짝 데쳐 준비\\n한다.\",\"5. 튀김기름 온도가 180℃ 정도 되면\\n누룽지를 넣고 튀겨 기름을 밭쳐 놓는다.\",\"6. 닭을 넣은 육수(③)에 간장과 녹말,\\n마늘, 소금, 후춧가루를 넣고 끓이다가,\\n곁들임채소로 남겨 놓은 채소(②)와\\n데쳐 놓은 해물 및 청경채를 넣고 한 번 더\\n끓인 뒤 튀겨진 누룽지를 넣어 완성한다.\"]},{\"id\":\"k69\",\"title\":\"광어스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00501_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00501_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00501_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00501_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00501_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00501_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00501_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"광어(150g)\",\"소금(0.3g)\",\"후춧가루(0.02g)\",\"밀가루(20g)\",\"달걀(50g)\",\"아몬드(20g)\",\"호두(20g)\",\"올리브오일(20g)\",\"- 소스 : 플레인요거트(50g)\",\"꿀(10g)\",\"레몬즙(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"광어를 견과류와 함께 어울려 만든 스테이크는 나트륨을 적게 사용해도 맛과 영양을 느낄 수 있어요.\",\"instructions\":[\"1. 광어는 포를 길게 떠서 소금과\\n후춧가루에 밑간을 해 놓는다.\",\"2. 아몬드와 호두는 입자있게 다져\\n준비한다.\",\"3. 밑간이 되어 있는 광어포에 밀가루와\\n달걀물을 입힌다.\",\"4. 달걀물을 입힌 광어살에 다시 다져\\n놓은 견과류를 입혀 준다.\",\"5. 팬에 올리브 오일을 넣고, 팬이 따끈해\\n지면 광어 살을 조심스럽게 앞뒤로\\n익혀 접시에 담는다.\",\"6. 플레인요거트에 꿀과 레몬즙을 넣고\\n골고루 섞어 광어스테이크소스를\\n만들어 완성한다.\"]},{\"id\":\"k70\",\"title\":\"치즈감자크로켓\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00502_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00502_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00502_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00502_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00502_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00502_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00502_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자(150g)\",\"생크림(20g)\",\"당근(20g)\",\"양파(20g)\",\"오이(20g)\",\"소금(0.5g)\",\"모짜렐라치즈(50g)\",\"밀가루(20g)\",\"달걀(50g)\",\"빵가루(50g)\",\"튀김기름(400g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감자에 들어있는 칼륨은 나트륨 배출을 도와줍니다.\",\"instructions\":[\"1. 감자는 껍질을 벗겨 삶는다.\",\"2. 오이와 당근은 어슷썰기를 하고 양파는\\n채를 썰어놓는다.\",\"3. 썰어 놓은 채소에 소금과 물을 넣고\\n살짝 절여, 물기를 짜놓는다.\",\"4. 삶아 놓은 감자를 채에 내리고\\n생크림을 넣어 섞는다.\",\"5. 생크림을 넣은 감자에 절여 놓은 채소와\\n모짜렐라치즈를 넣고 골고루 섞는다.\",\"6. 섞여진 감자를 크로켓 모양을 만들어\\n밀가루, 달걀물, 빵가루를 묻혀 튀김기름\\n170~180℃ 온도에서 바삭하게 튀겨\\n냅킨에 올려 기름을 제거하고, 접시에\\n담아 완성한다.\"]},{\"id\":\"k71\",\"title\":\"코코넛밀크카레\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00503_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00503_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00503_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00503_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00503_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00503_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00503_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(100g)\",\"소금(0.3g)\",\"코코넛밀크(20g)\",\"당근(20g)\",\"양파(20g)\",\"브로컬리(20g)\",\"돼지고기(50g)\",\"감자(20g)\",\"버터(10g)\",\"카레가루(30g)\",\"물(250g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"코코넛 밀크와 카레의 풍미가 더해져 짜지 않고 맛있는 카레를 만들 수 있어요.\",\"instructions\":[\"1. 두부는 소창에 넣고, 짜서 물기를\\n제거하고, 으깨어 놓는다.\",\"2. 으깬 두부에 소금과 코코넛 밀크를\\n넣고 골고루 섞는다.\",\"3. 섞여진 두부를 김이 오른 찜통에 넣고\\n약 5분 정도 찐다.\",\"4. 당근과 양파는 사각지게 썰고,\\n브로컬리는 데쳐 당근 크기로 썰어\\n놓는다.\",\"5. 돼지고기와 감자는 당근 크기로 썰어\\n주고, 냄비에 버터를 녹여 돼지고기를\\n먼저 볶다가 양파와 당근, 감자,\\n브로컬리를 넣고 다시 볶아 준 뒤,\\n쪄놓은 두부를 넣어 한 번 더 볶아준다.\",\"6. 볶아지는 냄비(⑤)에 카레 가루를 넣고\\n살짝 더 볶아준 뒤, 물을 넣고 자작하게\\n끓여 완성한다.\"]},{\"id\":\"k72\",\"title\":\"소고기리조또롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00504_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00504_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00504_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00504_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00504_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00504_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00504_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(50g)\",\"강황가루(20g)\",\"버터(10g)\",\"마늘(10g)\",\"양파(20g)\",\"새송이(30g)\",\"파프리카(30g)\",\"소고기(150g)\",\"소금(0.1g)\",\"후춧가루(0.02g)\",\"하얀된장(10g)\",\"생크림(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장에 생크림을 섞어 풍미는 높이고 나트륨 함량은 낮췄어요.\",\"instructions\":[\"1. 쌀은 불려 놓고, 마늘은 작게 다지고,\\n양파는 새송이와 파프리카와 함께\\n입자를 크게 다져 준비한다.\",\"2. 소고기는 포를 넓게 떠서 소금과\\n후춧가루를 뿌려 밑간을 해 놓는다.\",\"3. 냄비에 버터를 넣고, 마늘과 양파를\\n먼저 볶다가, 새송이와 파프리카를\\n넣는다.\",\"4. ③번에 다시 불린 쌀과 강화를 넣고,\\n볶다가 불을 줄여, 쌀이 익을 때까지\\n익혀 준다.\",\"5. 쌀이 익으면, 밑간이 되어 있는\\n소고기에 넣고 돌돌 말아 준비한다.\",\"6. 하얀 된장에 생크림을 넣어 골고루 섞고,\\n냄비에 육수를 넣고 생크림을 섞은 하얀\\n된장을 넣어 끓으면, 말아놓은 소고기를\\n넣고 은근히 졸여 완성한다.\"]},{\"id\":\"k73\",\"title\":\"둥지튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00556_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00556_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00556_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00556_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00556_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00556_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00556_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(살코기\",\"100g)\",\"달걀(1개)\",\"레몬(1/4개)\",\"통계피(5g)\",\"감자(150g)\",\"어린잎(20g)\",\"메추리알(3개)\",\"소금(0.2g)\",\"후춧가루(0.01g)\",\"밀가루(50g)\",\"전분(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"레몬즙의 칼륨이 나트륨 배출을 도와주고 레몬의 상큼한 맛 때문에 소금없이 소스를 만들 수 있어요.\",\"instructions\":[\"1. 닭고기는 잘게 썰어 후춧가루로 밑간을\\n한다.\",\"2. 밑간한 닭고기를 달걀과 섞은 뒤\\n전분을 넣고 골고루 묻힌다.\",\"3. 감자는 껍질을 벗기고 곱게 채 썰어\\n찬물에 담궈 전분을 뺀다.\",\"4. 감자를 건져 물기를 빼고, 전분을 묻혀\\n둥지모양을 만들어 튀긴다.\",\"5. 레몬과 설탕을 넣고 끓인다.\",\"6. 감자를 둥지모양으로 튀기고 그 위에\\n튀긴 닭고기를 올리고 어린잎으로\\n장식한 뒤 레몬소스를 올린다.\"]},{\"id\":\"k74\",\"title\":\"새우와스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00506_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00506_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00506_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00506_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00506_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00506_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00506_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(60g)\",\"버터(10g)\",\"소고기(120g)\",\"로즈마리(2g)\",\"소금(0.3g)\",\"후춧가루(2g)\",\"- 소스 : 와인(50g)\",\"설탕(20g)\",\"당근(20g)\",\"양파(20g)\",\"토마토(30g)\",\"마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"와인의 풍미와 갖가지 채소를 이용한 소스는 나트륨 사용을 줄일 수 있으며, 아스파라거스의 칼륨 성분이 체내에 나트륨을 배출시켜 주어요.\",\"instructions\":[\"1. 새우는 꼬리를 자르고 내장을 제거\\n한다.\",\"2. 스테이크 소고기는 소금과 로즈마리를\\n뿌리고 후춧가루를 살짝 뿌려 놓는다.\",\"3. 아스파라거스는 팬에 기름 없이\\n굽는다.\",\"4. 새송이와 가지는 길게 썰어 브로컬리와\\n함께 기름 없이 팬에 살짝 구워 놓는다.\",\"5. 팬에 버터를 살짝 넣고 새우를 굽고,\\n스테이크를 구워 접시에 담는다.\",\"6. 팬에 와인과 설탕을 넣고 끓이다가,\\n당근, 양파와 토마토 마늘, 대파를 다져\\n넣고 볶듯이 끓이다가 발사믹소스를\\n넣고 한 번 더 졸인 소스를 스테이크\\n위에 얹고, 브로컬리와 새송이, 가지,\\n아스파라거스를 함께 놓아 완성한다.\"]},{\"id\":\"k75\",\"title\":\"함초삼겹\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00507_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00507_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00507_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00507_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00507_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00507_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00507_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통삼겹살(150g)\",\"함초가루(10g)\",\"소금(0.5g)\",\"후춧가루(0.2g)\",\"부추(30g)\",\"버터(5g)\",\"- 소스 : 유자청(20g)\",\"쌈장(10g)\",\"설탕(20g)\",\"생크림(20g)\",\"연두부(30g)\",\"양파(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"함초가루를 이용하여 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 통 삼겹살에 함초와 소금, 후춧가루를\\n뿌려 숙성을 시킨다.\",\"2. 부추는 약 6cm 길이로 썰고, 양파는\\n채를 썰어 놓고, 당근은 납작하게\\n편으로 썰어 준비한다.\",\"3. 연두부는 잘게 다져 놓는다.\",\"4. 유자청에 쌈장과 설탕, 생크림을 넣어\\n골고루 섞는다.\",\"5. 골고루 섞은 유자청에 다져 놓은\\n연두부를 넣어 섞어 냄비에 넣고, 썰어\\n놓은 양파와 당근을 넣어 은근히 끓여\\n소스를 만들어 놓는다.\",\"6. 숙성시킨 통삼겹은 버터를 녹인 팬에\\n살짝 구워 다시 오븐에서 20분 정도\\n익힌 후 먹기 좋게 썰은 뒤, 접시에\\n부추를 깔고 그 위에 구워진 삼겹을\\n올리고 소스를 얹어 완성한다.\"]},{\"id\":\"k76\",\"title\":\"햄버거스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00508_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00508_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00508_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00508_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00508_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00508_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00508_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다진 돼지고기(60g)\",\"다진 소고기(60g)\",\"다진 마늘(10g)\",\"로즈마리(2g)\",\"빵가루(20g)\",\"후춧가루(0.2g)\",\"파프리카(20g)\",\"- 소스 : 양파(20g)\",\"플레인요거트(20g)\",\"설탕(10g)\",\"매실액(10g)\",\"식초(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"매실과 요거트의 새콤달콤한 맛이 나트륨 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 돼지고기와 소고기를 섞어, 매실액을\\n넣고 30분 정도 냉장고에서 숙성을\\n시킨다.\",\"2. 숙성된 돼지고기와 소고기에 다진마늘,\\n로즈마리, 빵가루, 후춧가루를 넣고\\n골고루 섞는다.\",\"3. 파프리카는 반으로 잘라 그 안에 씨를\\n수저를 이용해서 파낸다.\",\"4. 속을 파낸 파프리카에 양념한 고기를\\n넣고, 꼭꼭 눌러 두툼하게 잘라 구워\\n접시에 담는다.\",\"5. 양파는 입자있게 다져 팬에 기름을\\n넣고 은근히 볶아 양파 향을 낸다.\",\"6. 볶아진 팬(⑤)에 준비한 플레인요거트와\\n설탕, 매실액을 넣고 끓이다가, 식초와\\n녹말을 넣고 한 번 더 끓여 소스를\\n완성한다. 햄버거스테이트(④)에 소스를\\n얹고, 어린잎을 올려 완성한다.\"]},{\"id\":\"k77\",\"title\":\"유자삼치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00509_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00509_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00509_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00509_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00509_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00509_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00509_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼치(150g)\",\"소금(0.3g)\",\"녹말(20g)\",\"식용유(10g)\",\"- 소스 : 생강(10g)\",\"유자청(50g)\",\"레몬(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"삼치에 소금을 살짝 뿌려서 말리면 추가간을 하지 않아도 싱겁지 않으며, 간장 소스 대신 레몬 유자 소스를 이용하여 나트륨의 함량을 줄일 수\\n있어요.\",\"instructions\":[\"1. 삼치는 반으로 잘라지지 않게 편으로\\n떠서 소금을 살짝 뿌려 잠시 말려\\n놓는다.\",\"2. 손질을 한 삼치에 녹말가루를 입혀\\n팬에 기름을 두르고 구워 접시에 담아\\n놓는다.\",\"3. 생강은 잘게 썰어, 물에 섞은 후\\n거름종이에 걸러 생강즙을 만든다.\",\"4. 유자청에 만들어 놓은 생강즙을 넣고\\n섞는다.\",\"5. 냄비에 레몬을 넣고, 물을 넣고 은근히\\n끓인다.\",\"6. 레몬을 끓인 물에 ④번을 넣고 졸여\\n소스를 만든 후 접시에 담아 놓은 삼치\\n위에 소스로 올려 완성한다.\"]},{\"id\":\"k78\",\"title\":\"냉토마토파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00510_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00510_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00510_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00510_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00510_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00510_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00510_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토(50g)\",\"브로컬리(20g)\",\"펜네(100g)\",\"올리브오일(10g)\",\"후춧가루(0.1g)\",\"- 소스 : 마늘(10g)\",\"양파(20g)\",\"당근(20g)\",\"방울토마토(50g)\",\"올리브오일(10g)\",\"육수(400g)\",\"설탕(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"깔끔한 맛의 토마토소스를 차갑게 만들어, 나트륨 함량이 적어도 싱겁지 않아요.\",\"instructions\":[\"1. 마늘은 곱게 다지고 양파, 당근,\\n방울토마토는 입자있게 다진다.\",\"2. 토마토는 씨와 껍질을 제거하고 채를\\n썰어놓는다.\",\"3. 브로컬리를 끓는 물에 데쳐 찬물에\\n헹구어 작게 썰어 준비한다.\",\"4. 펜네는 끓는 물에 약 10분 정도\\n삶아 건진다.\",\"5. 건져진 펜네는 올리브오일을 넣어\\n무친 후 그릇에 담아놓는다.\",\"6. 냄비에 오일을 넣고 마늘과 양파를\\n볶다가 당근과 방울토마토를 넣어\\n볶으면서 육수를 붓고 설탕과 소금,\\n레몬즙, 월계수잎을 넣고 끓인 뒤\\n월계수잎을 건져내고, 차갑게 식힌 후\\n그릇에 담겨 있는 펜네에 토마토채(②)와\\n브로컬리(③)를 함께 넣어 담아 완성\\n한다.\"]},{\"id\":\"k79\",\"title\":\"닭고기또띠아\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00511_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00511_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00511_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00511_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00511_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00511_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00511_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"또띠아(50g)\",\"닭고기살(100g)\",\"느타리버섯(20g)\",\"사과(20g)\",\"오이(20g)\",\"파프리카(20g)\",\"애호박(20g)\",\"양파(20g)\",\"식초(10g)\",\"- 소스 : 아몬드(10g)\",\"우유(20g)\",\"머스터드(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"머스터드를 소스로 사용하기 때문에 별도의 나트륨을 넣지 않아, 나트륨 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 닭고기살은 끓는 물에 데쳐 손으로\\n찢고, 느타리버섯도 데쳐 손으로 찢어\\n준비한다.\",\"2. 사과는 씨를 제거하고 약 6cm 길이로\\n채를 썰고, 오이와 파프리카도 같은\\n길이로 채를 썰어 놓는다.\",\"3. 애호박은 반달로 썰어 식초에 살짝\\n절여서 볶고, 양파는 채를 썰어 물에\\n잠시 담가 놓는다.\",\"4. 아몬드는 우유를 넣어 갈아 준비한다.\",\"5. 머스터드에 올리고당을 넣어 잘 섞어\\n준다.\",\"6. 또띠아를 팬에 기름 없이 굽고, 그 안에\\n닭고기 살과 느타리버섯, 오이, 사과,\\n파프리카와 호박을 넣어 속이 보이도록\\n말아놓고, ④번과 ⑤번은 섞어서 소스를\\n만들어 완성한다.\"]},{\"id\":\"k80\",\"title\":\"닭고기스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00512_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00512_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00512_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00512_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00512_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00512_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00512_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기살(120g)\",\"소금(0.5g)\",\"후춧가루(0.1g)\",\"생강(5g)\",\"정종(5g)\",\"우유(50g)\",\"오이(20g)\",\"토마토(20g)\",\"두부(80g)\",\"흑임자(20g)\",\"우유(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부의 단백하고 고소한 맛을 이용하여 영양가 있고 맛있는 스테이크를 만들 수 있어요.\",\"instructions\":[\"1. 닭고기살은 소금과 후춧가루, 생강즙과\\n정종을 뿌린 후 우유를 살짝 발라 숙성을\\n시킨다.\",\"2. 오이는 길게 껍질째 썰어 놓는다.\",\"3. 토마토는 반으로 잘라 편으로 썰어\\n준비한다.\",\"4. 두부는 소창으로 물기를 꼭 짜 놓는다.\",\"5. 물기를 제거 시킨 두부에 흑임자를\\n넣고 골고루 섞은 뒤 냄비에 넣고\\n우유와 함께 은근히 끓여 속을 만든다.\",\"6. 팬에 토마토를 먼저 구워 접시에 담고,\\n숙성된 닭고기를 구워 올린 뒤, 그 위에\\n오이로 원형기둥을 만들고 구운\\n닭고기를 다시 올려 완성한다.\"]},{\"id\":\"k81\",\"title\":\"오징어순대\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00513_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00513_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00513_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00513_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00513_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00513_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00513_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통오징어(100g)\",\"양파(20g)\",\"당근(20g)\",\"부추(20g)\",\"견과류(20g)\",\"두부(50g)\",\"대파(10g)\",\"마늘(10g)\",\"소금(0.5g)\",\"녹말가루(10g)\",\"정종(10g)\",\"레몬(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갖가지 채소를 넣은 오징어 순대는 따로 양념장을 찍어먹지 않아도 맛있어요.\",\"instructions\":[\"1. 통오징어는 다리를 떼어내고 내장을\\n제거시켜 통째로 깨끗이 씻어 준비\\n한다.\",\"2. 양파와 당근, 부추, 생강은 입자있게\\n썰고, 견과류는 다져 준비한다.\",\"3. 두부는 물기를 짠 후 수저로 으깨어\\n놓는다.\",\"4. 잘게 썰은 오징어 다리와 썰어 놓은\\n채소, 견과류(②), 곱게 다진 대파와\\n마늘, 그리고 소금과 녹말가루를 두부\\n(③)와 함께 골고루 섞어 순대속을\\n만든다.\",\"5. 손질된 오징어 속 안에 준비한 속을\\n채워 넣는다.\",\"6. 오징어순대에 레몬즙과 정종, 생강즙을\\n섞어 바른 뒤 찜통에 김이 오르면\\n오징어순대를 넣어 약 10분 정도 쪄서\\n완성한다.\"]},{\"id\":\"k82\",\"title\":\"연어차우더스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00514_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00514_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00514_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00514_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00514_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00514_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00514_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"모시조개(50g)\",\"연어(100g)\",\"청피망(20g)\",\"당근(20g)\",\"양파(20g)\",\"감자(50g)\",\"밀가루(10g)\",\"버터(5g)\",\"육수(200g)\",\"월계수잎(1장)\",\"통후추(3알)\",\"생크림(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"모시조개의 맛과 향을 이용하여 추가 간을 하지 않아도 맛있어요.\",\"instructions\":[\"1. 모시조개는 물에 소금을 넣고, 담그어\\n해감을 한다.\",\"2. 연어는 사각지게 썰어 준비한다.\",\"3. 당근, 양파, 감자는 사각크기로 썰어\\n놓고, 청피망은 채를 썰어 당근과\\n비슷한 길이로 잘라둔다.\",\"4. 냄비에 버터와 밀가루를 넣고 볶다가\\n채소를 넣어 같이 볶는다.\",\"5. 볶아지는 냄비에 모시조개와 육수를\\n넣고 끓인다.\",\"6. 거품을 걷어내고, 월계수 잎과 통후추,\\n통마늘을 넣고 끓이다가 연어와\\n생크림을 넣어 한 소큼 끓으면 완성한다.\"]},{\"id\":\"k83\",\"title\":\"시금치브로컬리 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00663_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00663_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00663_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00663_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00663_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00663_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00663_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(대하\",\"3마리)\",\"스파게티(100g)\",\"시금치(30g)\",\"브로콜리(50g)\",\"바질(10g)\",\"생크림(50g)\",\"올리브오일(10g)\",\"소금 (0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생크림이 맛도 부드럽게 해주고 나트륨도 줄여 줘요.\",\"instructions\":[\"1. 시금치와 브로콜리는 끓는 물에 소금을\\n넣고 살짝 데친다.\",\"2. 데친 시금치, 브로콜리와 바질을\\n믹서에 갈아 준다.\",\"3. 새우는 껍질을 벗겨 손질한다\",\"4. 끓는 물에 스파게티를 10분 정도 삶아\\n건진다.\",\"5. 삶아진 스파게티는 팬에 올리브오일을\\n넣고 볶는다.\",\"6. 갈아 놓은 시금치소스에 생크림을 넣고\\n한소끔 끓이면서 볶은 파스타를 넣은\\n뒤 새우를 올린다\"]},{\"id\":\"k84\",\"title\":\"야채찜을 곁들인 광어스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00664_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00664_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00664_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00664_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00664_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00664_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00664_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"광어(1마리)\",\"당근(30g)\",\"단호박(30g)\",\"가지(1/2개)\",\"파프리카(50g)\",\"콜리플라워(50g)\",\"레몬(1/4개)\",\"와사비(5g)\",\"발사믹소스(50g)\",\"저염간장(30g)\",\"청주(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"야채를 찜통에 쪄서 영양소 파괴를 줄였으며, 저염간장에 레몬즙을 넣어 나트륨 함량을 줄일 수 있어요.\",\"instructions\":[\"1. 광어는 비늘을 제거하고 포를 뜬다.\",\"2. 손질된 광어에 레몬과 청주를 뿌려\\n숙성 시킨다.\",\"3. 저염간장에 레몬즙, 와사비,\\n발사믹소스를 넣고 소스를 만든다.\",\"4. 당근, 애호박은 쿠퍼로 동글동글하게\\n깎는다.\",\"5. 당근, 애호박, 콜리플라워는 김이 오른\\n찜통에 5분 정도 쪄 낸다.\",\"6. 가지와 파프리카는 팬에 굽고,\\n숙성시킨 광어도 팬에 구워 접시에\\n담고 쪄 낸 야채를 담은 뒤 소스를\\n올린다.\"]},{\"id\":\"k85\",\"title\":\"연근부각\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00665_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00665_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00665_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00665_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00665_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00665_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00665_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연근(60g)\",\"식초(10g)\",\"천일염(0.1g)\",\"계피가루(20g)\",\"식용유(200g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"미네랄이 풍부한 천일염을 볶아 사용해서 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 연근은 껍질을 벗긴다.\",\"2. 껍질벗긴 연근은 얇게 썬다.\",\"3. 물 200g에 식초 10g을 섞는다\",\"4. 식촛물에 썬 연근을 담근다.\",\"5. 연근을 체에 건져 물기를 뺀다.\",\"6. 연근을 바삭하게 튀긴 뒤 천일염을\\n살짝 뿌리고, 계피가루를 묻힌다.\"]},{\"id\":\"k86\",\"title\":\"오이냉국을 곁들인 오색쌈밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00666_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00666_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00666_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00666_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00666_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00666_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00666_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(안심\",\"100g)\",\"쌀(200g)\",\"도라지(30g)\",\"애호박(1/2개)\",\"양파(30g)\",\"홍고추(1개)\",\"미나리(20g)\",\"오이(50g)\",\"청포묵(20g)\",\"쌈무(20g)\",\"달걀(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갖은 야채와 나물을 골고루 넣은 쌈밥은 고추장을 조금 사용하게 해 나트륨 함량을 줄일 수 있어요.\",\"instructions\":[\"1. 쌀은 깨끗이 씻어 30분 정도 불려 밥을\\n짓는다.\",\"2. 달걀을 풀어 소금을 넣고 지단을\\n만들어 채썬다.\",\"3. 도라지, 애호박, 양파, 홍고추는 채를\\n썰어 소금에 살짝 절여 볶고, 청포묵은\\n채를 썰어 참기름에 버무린다.\",\"4. 돼지 안심은 소금, 후춧가루로 양념 한\\n뒤 팬에 익힌다.\",\"5. 찬물에 식초, 설탕, 소금을 넣고 채 썬\\n오이를 넣어 냉국을 만든다.\",\"6. 고추장에 고춧가루를 섞어 쌈밥장을\\n만들고, 라이스페이퍼를 물에 담궈\\n건져 밥과 준비한 야채, 달걀지단,\\n쌈무, 쌈밥장을 올려 돌돌 말고 데친\\n미나리로 묶는다.\"]},{\"id\":\"k87\",\"title\":\"카레탄두리치킨과 닭가슴살냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00667_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00667_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00667_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00667_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00667_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00667_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00667_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(1마리)\",\"오곡(50g)\",\"인삼(1뿌리)\",\"대추(3알)\",\"아스파라거스(3개)\",\"당근(20g)\",\"양파(30g)\",\"오이(50g)\",\"파프리카(50g)\",\"카레가루(20g)\",\"디종머스터드(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레가루를 묻혀 닭의 비릿한 맛도 없애고, 별도의 소금을 넣지 않아도 맛이 좋게 만들 수 있어요.\",\"instructions\":[\"1. 닭은 살을 발라 소금, 후춧가루로\\n밑간을 한다.\",\"2. 오곡을 불려 밥을 짓는다.\",\"3. 오이, 아스파라거스, 당근, 양파는\\n길이대로 채썬다.\",\"4. 닭살에 지어 놓은 오곡밥을 넣는다\",\"5. 오곡밥을 넣은 닭살에 카레가루를\\n골고루 묻힌다.\",\"6. 팬에 기름을 두르고 5번을 올려 은근히\\n익혀 접시에 담고, 썰어 놓은 야채를\\n닭살위에 담은 뒤 디종머스터드를\\n올린다.\"]},{\"id\":\"k88\",\"title\":\"컬리플라워소스 광어스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00668_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00668_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00668_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00668_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00668_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00668_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00668_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"광어(1마리)\",\"콜리플라워(50g)\",\"감자(30g)\",\"양파(20g)\",\"시금치(20g)\",\"가지(1/2개)\",\"단호박(1/4개)\",\"당근(30g)\",\"우유(200g)\",\"소금(0.2g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 칼슘이 가득한 우유을 넣어 담백하고, 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 광어는 비늘을 벗기고 포를 떠 소금,\\n후춧가루를 뿌린다.\",\"2. 콜리플라워는 팬에 볶는다.\",\"3. 감자와 양파를 썰어 콜리플라워와 함께\\n볶는다.\",\"4. ?번에 우유를 넣는다.\",\"5. ?를 믹서로 곱게 간 뒤, 끓인다.\",\"6. 가지, 당근. 단호박은 둥근 모양으로\\n만들어 팬에 시금치와 함께 익히고,\\n광어도 팬에 구워 접시에 담아\\n컬리플라워 소스를 올린다.\"]},{\"id\":\"k89\",\"title\":\"콜라비오미자 물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00669_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00669_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00669_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00669_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00669_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00669_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00669_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콜라비(1/2개)\",\"오미자(20g)\",\"무화과(20g)\",\"파프리카(50g)\",\"피망(30g)\",\"쪽파(10g)\",\"양파(30g)\",\"건새우(10g)\",\"다시마(10g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"건새우로 육수를 만들어 풍부한 맛을 내고 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 다시마와 건새우를 넣고 은근히 끓여\\n차갑게 식힌 뒤 육수를 만든다.\",\"2. 차갑게 식힌 육수는 체에 걸려내고\\n오미자를 넣고 소금으로 간을 한다.\",\"3. 콜라비, 피망, 파프리카는 납작하게\\n썬다.\",\"4. 육수는 체에 거른다\",\"5. 오미자를 넣고 소금으로 간을 한다.\",\"6. 통에 썰어놓은 야채와 무화과를 담고\\n?를 넣는다.\"]},{\"id\":\"k90\",\"title\":\"크림소스치킨롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00670_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00670_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00670_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00670_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00670_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00670_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00670_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"150g)\",\"새우(대하\",\"3마리)\",\"베이컨(20g)\",\"마늘(20g)\",\"바질(5g)\",\"아스파라거스(3개)\",\"새송이버섯(1개)\",\"치즈(1장)\",\"버터(10g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"베이컨을 데쳐 사용하면 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 닭가슴살은 포를 떠 소금과 후춧가루로\\n밑간을 한다.\",\"2. 새우는 껍질을 벗겨 손질한다.\",\"3. 베이컨은 끓는 물에 데친다.\",\"4. 마늘과 바질은 다진 뒤 버터에 섞는다.\",\"5. 닭가슴살에 베이컨과 다진 버터를\\n올린다.\",\"6. 냄비에 마늘과 바질을 섞은 버터,\\n치즈를 넣고 끓이다가 ?를 놓고\\n졸인다.\"]},{\"id\":\"k91\",\"title\":\"표고버섯 감자찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00671_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00671_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00671_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00671_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00671_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00671_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00671_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"표고버섯(3개)\",\"감자(200g)\",\"고수(10g)\",\"당근(30g)\",\"양파(30g)\",\"홍고추(1개)\",\"녹말(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"표고버섯의 향과 담백한 감자 덕분에 간을 하지 않아도 맛있게 먹을 수 있어요.\",\"instructions\":[\"1. 표고버섯은 따뜻한 물에 불린다.\",\"2. 감자는 강판에 간다.\",\"3. 고수는 잘게 다진다.\",\"4. 당근은 곱게 다지고, 양파와 홍고추도\\n다진다.\",\"5. 감자에 다진 당근과 양파, 홍고추를\\n섞는다.\",\"6. 불린 표고버섯은 기둥을 자르고 바닥에\\n녹말가루를 묻혀 ?번을 넣고 김이\\n오른 찜통에 약 10분 정도 찐다.\"]},{\"id\":\"k92\",\"title\":\"해물애호박 전병말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00672_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00672_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00672_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00672_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00672_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00672_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00672_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(3마리)\",\"오징어(50g)\",\"애호박(1/2개)\",\"당근(20g)\",\"깻잎(3장)\",\"대추(2알)\",\"밀가루(100g)\",\"찹쌀가루(50g)\",\"저염간장(20g)\",\"식초(10g)\",\"설탕(10g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우와 오징어를 다져 넣었기 때문에 소금을 안 넣어도 맛있는 전병을 만들 수 있어요.\",\"instructions\":[\"1. 새우는 껍질을 벗겨 다진다.\",\"2. 오징어는 소금으로 껍질을 벗겨\\n다진다.\",\"3. 애호박, 깻잎, 대추는 곱게 채썬다.\",\"4. 채썬 애호박과 깻잎은 소금에 살짝\\n절인 뒤 물기를 짠다.\",\"5. 밀가루에 찹쌀가루, 애호박, 깻잎,\\n대추채와 다진 새우, 오징어를 넣고\\n팬에 기름을 둘러 전병을 만든 뒤 돌돌\\n말아 썰어 접시에 담는다.\",\"6. 저염간장과 식초, 설탕을 넣고 소스를\\n만든다.\"]},{\"id\":\"k93\",\"title\":\"찬밥이용닭죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102057_1416273657171.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/673-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/673-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/673-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/673-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/673-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/673-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찬밥 60g\",\"닭다리살 80g\",\"감자 30g\",\"통마늘 15g\",\"양파 10g\",\"당근 8g\",\"부추 5g\",\"물 700g\",\"소금 0.75g\",\"후춧가루 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭은 찬물에 넣어 끓여야 고기의 맛있는 성분이 잘 우러 나온다. - 닭 육수를 만들 때 황기, 대추, 수삼을 넣으면 여름철 보양식으로 좋다. - 녹두를 섞어 끓이면 고소하고 담백한 맛이 있다.\",\"instructions\":[\"1. 닭다리는 기름기를 제거하고 냄비에 물 3컵 반을 부어 통마늘과 삶아 육수를 만든다.\",\"2. 삶은 마늘을 체에 걸러 으깬 뒤 다시 육수에 넣는다.\",\"3. 닭 육수 2컵 반에 찬밥을 넣고 밥알이 무르도록 끓인다.\",\"4. 삶은 닭다리 살을 발라 잘게 찢어 넣는다.\",\"5. 감자, 양파, 당근, 부추는 잘게 다진다.\",\"6. 4에 5를 넣고 끓인 뒤 소금, 후춧가루로 간 한다.\"]},{\"id\":\"k94\",\"title\":\"감자느타리버섯국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102104_1416273664244.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/674-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/674-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/674-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/674-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/674-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/674-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 30g\",\"느타리버섯 15g\",\"두부 8g\",\"파 5g\",\"물 300g\",\"국멸치 5g\",\"홍고추 3g\",\"건다시마 3g\",\"다진 마늘 3g\",\"소금 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치는 찬물에 넣고 끓여 국물을 내고 끓는 중간에 생기는 거품을 걷어낸다. - 느타리버섯은 갓 쪽에서 기둥 쪽을 향해 찢으면 잘 찢어진다.\",\"instructions\":[\"1. 물 1컵 반에 국멸치와 건다시마를 넣어 멸치다시마국물을 만든다.\",\"2. 국물을 우린 다시마는 채썬다.\",\"3. 느타리버섯은 끓는 물에 데친 후 찢는다.\",\"4. 감자와 두부는 3~4cm 가량으로 채를 썰고 홍고추와 대파는 어슷썬다.\",\"5. 멸치다시마국물 1컵에 감자를 넣고 끓인 뒤 느타리버섯을 넣어 한소끔 끓이고 두부, 파, 다진 마늘, 홍고추를 넣고 소금으로 간 한다.\",\"6. 채 썬 다시마를 고명으로 얹는다\"]},{\"id\":\"k95\",\"title\":\"민어매운탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102107_1416273667490.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/677-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/677-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/677-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/677-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/677-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/677-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"- 주재료 : 민어 50g\",\"쇠고기 양지15g\",\"다진 마늘 1.25g\",\"후추 0.25g\",\"참기름 0.5g\",\"무 40g\",\"애호박 20g\",\"애느타리버섯 20g\",\"풋 고추 5g\",\"홍고추 2.5g\",\"쑥갓 10g\",\"대파 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장을 미리 만들어 숙성시켜 사용하면 얼큰한 맛이 증가되고 풍미가 좋아진다.\",\"instructions\":[\"1. 양념장 재료를 모두 섞어 냉장고에서 하루 숙성시킨다.\",\"2. 민어는 비늘을 긁고 지느러미, 내장을 제거하여 흐르는 물에 씻어 5cm 길이로 토막 낸다.\",\"3. 소고기는 채 썰어 다진 마늘, 후추로 밑간한다.\",\"4. 무는 나박 썰기, 애호박은 반달 썰기, 애느타리는 한입 크기로 찢고 고추와 대파는 어슷 썬다.\",\"5. 냄비에 참기름을 두르고 소고기를 볶다가 물 1컵 반과 무를 넣고 양념장을 풀어 끓인다.\",\"6. 무가 반 정도 익으면 민어와 채소를 넣고 한소끔 끓인 뒤 어슷 썬 대파와 생강즙을 넣어 살짝 끓이고 소금 간하고 쑥갓을 넣는다.\"]},{\"id\":\"k96\",\"title\":\"아몬드치킨볼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00297_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00297_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00297_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00297_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00297_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00297_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00297_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 양송이버섯(5g)\",\"버터(10g)\",\"닭다리살(30g)\",\"닭가슴살(50g)\",\"아몬드(5g)\",\"밀가루(10g)\",\"우유(50g)\",\"들깻가루(30g)\",\"브로콜리(15g)\",\"마늘(10g)\",\"육수 닭뼈(90g)\",\"양파(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 우유와 들깨소스를 넣은 소스로 나트륨 섭취를 줄이고 고소함과 담백함을 더했다.\",\"instructions\":[\"1. 냄비에 육수 재료와 물(400g)을\\n넣고 푹 끓인다.\",\"2. 양송이버섯을 잘게 다진 뒤 버터에\\n살짝 볶아 건져 한김 식힌 뒤\\n닭다리살과 닭가슴살, 아몬드를 다져\\n볶은 양송이버섯과 섞어 동그랗게\\n빚어 밀가루옷을 입힌다.\",\"3. 식용유(15g)를 두른 팬에서 겉을\\n노릇하게 굽는다.\",\"4. 육수(150g), 우유, 들깻가루를 끓여\\n소스를 만든 뒤 아몬드 치킨볼과\\n브로콜리를 넣고 졸인다.\",\"5. 마늘은 편 썰어 낮은 온도의\\n식용유에서 바삭하게 튀긴다.\",\"6. 접시에 아몬드치킨볼을 담고\\n튀긴 마늘을 얹어 마무리한다.\"]},{\"id\":\"k97\",\"title\":\"양배추롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00536_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00536_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기살(100g)\",\"천일염(0.5g)\",\"후춧가루(0.3g)\",\"식용유(10g)\",\"정종(10g)\",\"양배추(80g)\",\"부추(30g)\",\"깻잎(10g)\",\"홍파프리카(20g)\",\"노랑파프리카(20g)\",\"당근(20g)\",\"양파(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"요구르트와 머스터드를 이용하여 소스를 만들었기 때문에 별도의 소금 없이도 맛을 느낄 수 있고, 양배추와 함께 어울려 먹기 좋아요\",\"instructions\":[\"1. 닭고기살은 천일염과 후춧가루를 뿌려\\n마리네이드를 해놓는다.\",\"2. 양배추와 부추는 김이 오른 찜통에\\n쪄서 식혀 놓는다.\",\"3. 깻잎은 채를 썰고, 파프리카는 속을 제거\\n하고 5cm 길이로 채를 썰고, 당근과\\n양파도 같은 길이로 채를 썰어 놓는다.\",\"4. 마리네이드를 해 놓은 닭고기살은 팬에\\n기름을 두르고, 팬이 따끈해지면 앞뒤를\\n돌려가며 정종을 살살 뿌려 닭고기살을\\n굽고, 닭고기살이 익으면 살을 찢어 준비\\n한다.\",\"5. 요거트와 머스터드, 꿀 ,레몬즙, 설탕을\\n넣고 고루 섞어 소스를 만들어 놓는다.\",\"6. 쪄 놓은 양배추에 준비한 채소(③)와\\n닭고기살(④)을 넣고, 돌돌 말아 쪄\\n놓은 부추로 양배추를 묶어 완성하고,\\n만들어 놓은 요거트 소스를 함께 제공\\n한다.\"]},{\"id\":\"k98\",\"title\":\"생선베이컨말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00299_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00299_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00299_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00299_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00299_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00299_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 피망(5g)\",\"파프리카(10g)\",\"시금치(15g)\",\"저염베이컨(60g)\",\"동태포(30g)\",\"저염버터(10g)\",\"생크림(10g)\",\"새싹채소(0.1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금간 대신 시금치소스로 맛을 내 나트륨을 적게 섭취하였다\",\"instructions\":[\"1. 피망, 파프리카는 5㎝ 길이로 채\\n썰고, 시금치는 갈아둔다.\",\"2. 베이컨 위에 동태포를 올리고\\n그 위에 피망과 파프리카를 올려\\n돌돌 만다.\",\"3. 저염버터에 생크림을 넣어서 농도를\\n맞춘 후 갈아놓은 시금치를 넣어\\n시금치소스를 만든다.\",\"4. 달군 팬에 흰살생선베이컨말이를\\n올려 완전히 익힌다.\",\"5. 접시에 담아 시금치소스를\\n곁들인 뒤 새싹채소로 장식하여\\n마무리한다.\"]},{\"id\":\"k99\",\"title\":\"콩고기샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00300_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00300_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00300_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00300_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00300_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00300_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 콩고기(30g)\",\"아보카도(10g)\",\"바나나(10g)\",\"가지(10g)\",\"연근(10g)\",\"방울토마토(10g)\",\"만두피(20g)\",\"저염간장양념 저염간장(2.5g)\",\"물(25g)\",\"설탕(3g)\",\"허브오일드레싱 저염소금(1g)\",\"식초(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"육류에 비해 나트륨 함량이 적은 콩고기를 사용하고, 바나나 등 과일로\\n달콤한 맛을 내 소금간을 따로 하지 않아 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 콩고기를 15분~20분 정도 물에\\n불려 물기를 완전히 제거한 뒤\\n저염간장양념으로 버무려 볶는다.\",\"2. 아보카도, 바나나, 가지, 연근은\\n깍둑 썰고, 방울토마토는 반을\\n가른다.\",\"3. 팬에 식용유(5g)를 둘러가며\\n방울토마토, 가지, 연근을 각각\\n볶아 건진다.\",\"4. 만두피를 작은 체에 넣고\\n바구니 모양으로 만들어 튀긴다.\",\"5. 콩고기와 아보카도, 바나나,\\n방울토마토, 가지, 연근을 튀긴\\n만두피에 담은 뒤 허브오일드레싱을\\n곁들여 마무리한다.\"]},{\"id\":\"k100\",\"title\":\"퀴노아닭가슴살샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00301_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00301_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00301_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00301_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00301_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00301_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00301_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 수박껍질(17g)\",\"토마토(17g)\",\"닭가슴살(80g)\",\"감자(27g)\",\"가지(17g)\",\"양파(17g)\",\"피망(34g)\",\"아스파라거스(30g)\",\"퀴노아(8g)\",\"리코타치즈(5g)\",\"양상추(9g)\",\"플레인 요구르트(25g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토와 수박은 칼륨 함량이 높아 나트륨 배출을 촉진하였고,\\n소스의 짠맛 대신 복분자와 레몬즙을 넣어 과실 특유의 맛을 살렸다\",\"instructions\":[\"1. 수박껍질은 흰 부분만 사용해\\n작게 깍둑 썰고, 토마토는 껍질을\\n벗겨 속씨를 제거해 작게 깍둑썬다.\",\"2. 닭가슴살은 수비드해 익힌 뒤\\n한입 크기로 썬다.\",\"3. 감자, 가지, 양파, 피망,\\n아스파라거스는 깍둑 썬 뒤\\n닭가슴살과 함께 볶는다.\",\"4. 팬에 복분자를 넣고 살짝 졸인 뒤\\n레몬즙을 섞어 복분자소스를 만든다.\",\"5. 접시에 퀴노아를 두른 후\\n닭가슴살과 감자, 가지, 양파, 피망,\\n아스파라거스를 올리면서 중간\\n중간에 토마토와 수박,\\n리코타치즈를 넣는다.\",\"6. 맨 위에 퀴노아를 살짝 올려주고\\n양상추, 플레인 요구르트,\\n어린잎채소를 얹어 마무리한다.\"]},{\"id\":\"k101\",\"title\":\"바나나크림파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00302_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00302_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 바나나(150g)\",\"아보카도(110g)\",\"토마토(100g)\",\"저염베이컨(46g\",\"3장)\",\"바질가루(1g)\",\"마늘(10g)\",\"양파(20g)\",\"휘핑크림(80g)\",\"저염치즈(40g)\",\"우유(200g)\",\"소금(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"아보카도와 바나나에는 칼륨이 다량 함유되어 있어 나트륨 배출을 돕는다.\\n이들을 소스로 사용해 단맛으로 맛을 냈다.\",\"instructions\":[\"1. 바나나를 반으로 잘라 반은 편 썰고\\n반은 으깨고, 아보카도는 껍질과\\n씨를 제거 한 후 ⅓은 편 썰고\\n⅔는 으깬다.\",\"2. 토마토는 끓는 물에 데쳐 껍질을\\n제거하고 얇게 썬다.\",\"3. 베이컨 2장은 채 썰고,\\n1장은 구운 뒤 비슷한 크기로\\n채 썬다.\",\"4. 베이컨을 구운 기름에 편 썬 바나나,\\n아보카도, 토마토를 넣고 바질가루를\\n뿌려 굽는다.\",\"5. 팬에 채 썬 베이컨과 다진 마늘,\\n다진 양파를 볶은 후 휘핑크림,\\n저염치즈를 넣고 볶다가 으깬\\n아보카도, 바나나, 우유를 넣어\\n농도를 맞추고 소금으로 간해\\n바나나크림을 만든다.\",\"6. 접시에 구운 바나나, 아보카도,\\n토마토를 깔고 삶은 스파게티면을\\n담은 후 바나나크림을 뿌리고\\n베이컨을 올려 장식해 마무리한다.\"]},{\"id\":\"k102\",\"title\":\"산채쌀파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00303_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00303_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 신선초(3g)\",\"참나물(3g)\",\"취나물(3g)\",\"적겨자(3g)\",\"깻잎(2g)\",\"양파(8g)\",\"오이(6g)\",\"붉은 고추(5g)\",\"풋고추(5g)\",\"쌀파스타면(160g)\",\"파스타소스 된장(4g)\",\"청국장(16g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"적겨자, 취나물 등 산채를 사용해 특별히 간을 하지 않아도\\n쌉싸름한 향과 맛을 살려 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 신선초, 참나물, 취나물, 적겨자는\\n먹기 좋은 크기로 뜯고,\\n깻잎은 한입 크기로 썬다.\",\"2. 양파(8g)는 채 썰고, 파스타소스에\\n들어갈 양파(15g)는 굵게 다지고,\\n애호박도 양파와 비슷한 크기로\\n굵게 다진다.\",\"3. 오이는 돌려 깎은 뒤 채 썰고,\\n고추도 얇게 채 썬다.\",\"4. 끓는 물에 쌀파스타면을 넣고 5분간\\n삶아 익힌 뒤 찬물에 헹궈 물기를\\n뺀다.\",\"5. 팬에 물(60g)을 붓고 물이 끓으면\\n된장, 청국장, 다진 양파, 애호박,\\n으깬 두부, 다진 마늘을 넣고\\n1분 30초 정도 졸여 파스타소스를\\n만든다.\",\"6. 쌀파스타면 위에 소스를 얹은 뒤\\n채소를 올리고 들기름을 뿌려\\n마무리한다.\"]},{\"id\":\"k103\",\"title\":\"황태포당면국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00304_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00304_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 감자(80g)\",\"양파(15g)\",\"당근(10g)\",\"대파(5g)\",\"청양고추(3g)\",\"팽이버섯(20g)\",\"달걀(30g)\",\"당면(70g)\",\"쑥갓(5g)\",\"육수 멸치(2g)\",\"황태포(10g)\",\"양념 다진 마늘(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치, 황태 등 천연조미료를 사용해 육수 특유의 구수한 맛을 살려\\n짠맛을 내는 간장과 소금의 양을 줄였다\",\"instructions\":[\"1. 감자는 한입 크기로 썰고, 양파와\\n당근, 대파는 길게 채 썰고,\\n청양고추는 다지고, 팽이버섯은\\n깨끗이 씻어 준비한다.\",\"2. 달걀은 노른자와 흰자를 분리해\\n지단을 부쳐 채 썬다.\",\"3. 당면은 찬물에 2시간 정도 불린다.\",\"4. 물(300g)에 멸치를 넣어 육수를\\n만든 후, 황태포를 넣어 다시\\n한 번 진하게 육수를 우려낸다.\",\"5. 육수에 감자, 당근, 양파, 당면을\\n순서대로 넣고 끓인 후 불을 끄고\\n팽이버섯을 얹어 잔열로 익힌다.\",\"6. 다진 마늘, 청양고추, 저염간장, 소금,\\n후춧가루를 넣어 간을 한 뒤 지단,\\n쑥갓, 대파를 얹어 마무리한다.\"]},{\"id\":\"k104\",\"title\":\"닭갈비볶음면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00305_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00305_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 마늘(20g)\",\"깻잎(2g)\",\"쪽파(1g)\",\"파프리카(60g)\",\"양파(40g)\",\"대파(10g)\",\"방울토마토(50g)\",\"닭가슴살(30g)\",\"이태리시즈닝(1g)\",\"라면(110g)\",\"양념 카레가루(2g)\",\"고춧가루(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파프리카와 토마토를 소스에 넣어 나트륨 함량을 줄이면서\\n자연스러운 단맛을 내 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 마늘 5g은 다지고, 나머지 마늘(15g)은\\n편 썰어 노릇하게 튀긴다.\",\"2. 깻잎은 채 썰고, 쪽파는 송송 썰고,\\n파프리카는 주사위 모양으로 썰고,\\n양파와 대파는 채 썰고,\\n방울토마토는 반을 갈라 준비한다.\",\"3. 닭가슴살은 어슷하게 납작 썰어\\n이태리시즈닝에 재운 뒤 팬에 구워\\n준비한다.\",\"4. 다진 마늘, 양파, 대파를 팬에 넣고\\n향을 내다 파프리카와 방울토마토,\\n양념을 넣고 볶은 뒤 한 김 식혀\\n믹서에 곱게 갈아 소스를 만든다.\",\"5. 팬에 소스와 구운 닭가슴살을 넣어\\n볶다가 삶은 라면을 넣고 재빠르게\\n볶는다.\",\"6. 튀긴 마늘과 깻잎, 쪽파를 올려\\n마무리한다.\"]},{\"id\":\"k105\",\"title\":\"오색볶음면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00306_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00306_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 양파(40g)\",\"청경채(30g)\",\"두 가지 색 파프리카(각 15g씩)\",\"쪽파(15g)\",\"라면(60g)\",\"채 썬 돼지고기(30g)\",\"양념 다진 마늘(7g)\",\"고추기름(5g)\",\"설탕(4g)\",\"두반장(8g)\",\"라면스프(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"면을 미리 한 번 삶은 뒤 헹궈내 튀긴 면의 나트륨을 제거하고,\\n파프리카와 청경채, 양파를 곁들여 나트륨 배출을 도와주는 칼륨의 함량을 높였다.\",\"instructions\":[\"1. 양파와 청경채, 파프라카는 채 썰고,\\n쪽파는 송송 썬다.\",\"2. 라면은 삶아서 체에 밭쳐 물기를\\n제거한다.\",\"3. 팬에 식용유(5g)를 두르고 다진\\n마늘을 볶아 향을 낸 뒤 돼지고기를\\n볶는다.\",\"4. 채 썬 양파와 청경채, 파프리카를\\n함께 넣고 볶다가 고추기름, 설탕,\\n두반장, 라면스프로 간을 해\\n볶는다.\",\"5. 면을 함께 볶은 후 송송 썬 쪽파를\\n뿌려 마무리한다.\"]},{\"id\":\"k106\",\"title\":\"로제소스라면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00307_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00307_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 새우(10g)\",\"조개(20g)\",\"홍합(20g)\",\"새송이버섯(15g)\",\"양파(8g)\",\"토마토(100g)\",\"라면(50g)\",\"우유(200g)\",\"생크림(100g)\",\"월계수잎(5g)\",\"정향(5g)\",\"파르메산 치즈가루(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토와 해물에서 우러나오는 감칠맛으로 따로 소금간을 하지 않아\\n나트륨을 줄이고, 라면을 한 번 데쳐 염도를 낮췄다.\",\"instructions\":[\"1. 새우, 조개, 홍합은 손질한다.\",\"2. 버섯은 먹기 좋은 크기로 썰고,\\n양파는 채 썰고, 토마토는 씨를\\n제거해 다진다.\",\"3. 라면은 끓는 물에 데친 뒤 체에 밭쳐\\n물기를 제거한다.\",\"4. 냄비에 식용유(10g)를 두른 뒤\\n새우와 조개, 홍합을 넣어 살짝 볶아\\n건진다.\",\"5. 같은 냄비에 토마토, 우유, 생크림을\\n넣은 뒤 월계수잎과 정향을 넣고\\n끓인다.\",\"6. 끓으면 데친 라면, 새송이버섯, 홍합,\\n새우, 조개, 양파를 넣고 끓여 다\\n익으면 파르메산 치즈가루를\\n뿌린 후 그 위에 파슬리가루를 뿌려\\n마무리한다.\"]},{\"id\":\"k107\",\"title\":\"라면월남쌈튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00308_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00308_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 라면(20g)\",\"배(12g)\",\"파인애플(15g)\",\"파프리카(10g)\",\"쇠고기(우둔살\",\"20g)\",\"레드와인(20g)\",\"매실청(20g)\",\"라이스페이퍼(8g)\",\"달걀(30g)\",\"빵가루(25g)\",\"어린잎채소(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장을 이용해 염분을 줄인 대신\\n매실청과 레드와인으로 맛을 더해 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 라면을 살짝 익힌다.\",\"2. 배와 파인애플을 한입 크기로\\n썰고, 파프리카는 깍둑 썬다.\",\"3. 팬에 쇠고기 양념장과 파인애플을\\n넣어 끓이다가 채 썬 쇠고기를\\n넣는다.\",\"4. 레드와인을 넣고 알코올을 날린 뒤\\n매실청을 넣고 조린다.\",\"5. 라면과 파프리카, 배를 섞은 후\\n라이스페이퍼에 올려 만다.\",\"6. 달걀물을 묻힌 후 빵가루를 입혀\\n튀긴 뒤 그릇에 어린잎채소와 함께\\n담아 조린 쇠고기를 곁들여 마무리\\n한다.\"]},{\"id\":\"k108\",\"title\":\"삼겹살라면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00309_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00309_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 라면(100g)\",\"쪽파(3g)\",\"육수 돼지고기(삼겹살\",\"60g)\",\"대파(20g)\",\"얇게 썬 생강(5g)\",\"가다랑어포(3g)\",\"조림양념 저염간장(3g)\",\"맛술(8g)\",\"흑설탕(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"가다랑어포 육수를 사용해 나트륨 섭취를 줄였다.\\n또한 라면을 끓인 뒤 찬물로 헹궈 나트륨 함량을 낮췄다\",\"instructions\":[\"1. 돼지고기를 차가운 물로 헹구고\\n냄비에 물(300g), 대파, 생강과 같이\\n넣고 끓여 돼지고기가 익으면\\n면포에 거른다.\",\"2. 냄비에 물(300g)을 넣어 끓으면\\n가다랑어포를 넣고 1분간 끓이고\\n불을 꺼 가다랑어포가 가라앉으면\\n면포에 거르고, 다시 물(300g)을\\n넣어 면포에 걸러낸 가다랑어포를\\n넣어 약한 불로 10분간 끓인 뒤\\n가다랑어포가 가라앉으면 면포에\\n거른다.\",\"3. 돼지고기 육수와 가다랑어포 육수를\\n섞은 뒤 200g을 따로 덜어\\n조림양념을 넣고 끓이다가\\n돼지고기를 넣고 조린다.\",\"4. 라면은 삶아 찬물에 헹궈 건지고,\\n쪽파는 송송 썬다.\",\"5. 육수를 뜨겁게 끓인 뒤 그릇에\\n라면사리와 함께 담고,\\n돼지고기조림, 쪽파를 올리고 팬에\\n남은 조림 소스를 끼얹어 마무리한다.\"]},{\"id\":\"k109\",\"title\":\"유자샐러드라면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00310_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00310_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 라면(55g)\",\"양상추(40g)\",\"케일(5g)\",\"파프리카(20g)\",\"비타민(5g)\",\"유자드레싱 식초(2g)\",\"레몬즙(5g)\",\"유자청(15g)\",\"올리브유(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"면을 데칠 때 많은 양의 물을 끓여 나트륨이 충분히 빠져나가게 했다.\\n또한 채소를 많이 넣고 면을 반만 사용해 나트륨의 양도 반으로 낮춰 섭취량을 줄였다.\",\"instructions\":[\"1. 끓는 물(600g)에 라면을 넣어\\n데친다.\",\"2. 면은 찬물에 헹궈 물기를 뺀다.\",\"3. 양상추, 케일, 파프리카는 얇게 채\\n썰고, 비타민은 먹기 좋은 크기로\\n자른다.\",\"4. 유자드레싱을 고루 섞은 뒤 라면,\\n채소를 버무려 마무리한다.\"]},{\"id\":\"k110\",\"title\":\"주꾸미머리순대\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00414_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00414_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미 200g\",\"미나리 20g\",\"양파 25g\",\"당근 20g\",\"계란 60g\",\"다진마늘 15g\",\"생강청 15g\",\"레몬즙 10g\",\"소스 : 고추장 15g\",\"레몬즙 10g\",\"생강청 10g\",\"통깨 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"소스에 고추장의 양을 줄이고 레몬즙을 넣어 상큼한 맛을 높여 짠맛을 대체하였다.\",\"instructions\":[\"1. 주꾸미를 몸과 다리를 분리 후 잘 씻어준다.\",\"2. 주꾸미 다리, 미나리, 양파, 당근을 다져준다.\",\"3. 다진 채소를 계란, 다진마늘, 생강청에 양념\\n한다.\",\"4. 양념한 3을 주꾸미 머리 속에 넣어주고\\n이쑤시개로 꽂아준다.\",\"5. 찜기에 찐다. 찔 때 레몬즙을 뿌리면 더욱\\n탱탱하다.\",\"6. 소스를 만든 뒤 주꾸미를 함께 완성한다.\"]},{\"id\":\"k111\",\"title\":\"매실동치미\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00415_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00415_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"무 50g\",\"연근 25g\",\"사과 25g\",\"배 30g\",\"함초소금 2g\",\"국물 : 매실청 30g\",\"생강청 15g\",\"함초소금 1g\",\"청양고추 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"동치미 국물에 매실청과 생강청을 넣어 시원함과 새콤달콤한 맛을 더해주어 소금 사용량을 줄였으며, 청양고추를 썰어 넣어 칼칼함을 높여 동치미의 염분을 낮출 수 있었다.\",\"instructions\":[\"1. 무는 모양 틀로 자른다.\",\"2. 무와 연근을 손질해 놓은 후 소금에 살짝\\n절여준다.\",\"3. 사과와 배는 먹기 좋게 잘라 레몬즙에 뿌려\\n갈변을 막아준다.\",\"4. 물에 청양고추를 넣어 끓여서 식힌다.\",\"5. 식힌 물에 국물 재료를 넣어 국물을 만든다.\",\"6. 만들어진 국물에 절여진 무, 연근, 사과, 배를\\n넣어주어 완성한다. 24시간 이후부터 시원하게\\n먹는다.\"]},{\"id\":\"k112\",\"title\":\"조기까스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00416_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00416_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"조기 1마리(250g)\",\"허브크러스트 100g\",\"흰 후추 1g\",\"화이트와인 15g\",\"마늘오일 15g\",\"전분 15g\",\"소스 : 고추장 15g\",\"저염간장 15g\",\"화이트와인 15g\",\"버터 5g\",\"다진양파 15g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생선을 조림 대신 찜을 사용하여 소금 사용량을 낮추었으며 와인과 양파, 마늘 오일을 소스에 첨가하여 고추장 사용량을 줄이면서 풍미를 높일 수 있었다.\",\"instructions\":[\"1. 다진마늘을 버터에 충분히 볶아준다.\",\"2. 화이트와인을 뿌려주고 소스재료로 소스를\\n만들어준다.\",\"3. 찜기에 살짝 져 준다. 이때 80% 정도까지만\\n익혀준다.\",\"4. 쪄준 조기는 와인과 후추로 밑간을 해준 후\\n전분을 발라준다.\",\"5. 전분를 바른 조기에 허브크러스트를 두툼하게\\n올려준다.\",\"6. 팬에 기름을 두르고 조기를 한쪽부터 구운 뒤,\\n뒤집어서 다시 구워주고 소스를 뿌려 완성한다.\"]},{\"id\":\"k113\",\"title\":\"돼지머리수육맑은전골\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00417_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00417_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지머리 200g\",\"우동면 100g\",\"미나리 20g\",\"청고추 15g\",\"소스 : 일본 된장 30g\",\"다진마늘 10g\",\"다진대파 10g\",\"청주 15g\",\"무 25g\",\"육수 : 해물육수 300g\",\"청양고추 20g\",\"맛간장 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"청양고추의 매운맛과 통후추의 매운맛을 곁들여주는 방식으로 나트륨을 줄여주면서 개운하고 시원한 국물을 만들어 주었다.\",\"instructions\":[\"1. 무, 청고추, 미나리, 대파는 먹기 좋게 썰어준다.\",\"2. 돼지머리는 냉수에 데친다. 냉수일 때부터\\n돼지머리를 넣어야 물이 끓어오르면 불순물이\\n제거된다.\",\"3. 일본 된장을 풀어 체에 걸러준다.\",\"4. 돼지머리를 살짝 졸여준다.\",\"5. 냄비에 국물을 끓여주다가 채소를 넣어 끓인다.\",\"6. 국물에 우동면을 데쳐낸 뒤 완성한다.\"]},{\"id\":\"k114\",\"title\":\"파인애플볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00418_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00418_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 150g\",\"칵테일새우 50g\",\"파인애플 통조림 100g\",\"양파 60g\",\"청고추 15g\",\"노란파프리카 20g\",\"빨간파프리카 20g\",\"마늘 15g\",\"계란 60g\",\"마늘기름 30g\",\"흰후추 1g\",\"레몬소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"파인애플에 레몬소금을 살짝 뿌려서 단맛을 향상시키고 더욱 쫀득하게 만들어준다.\\n과일을 이용해 만든 맛간장을 마지막에 살짝 첨가해주면서 풍미를 더해주는 요리법으로 나트륨을 줄였다.\",\"instructions\":[\"1. 양파, 2가지색 파프리카, 청고추는 작은 깍두기\\n모양으로 잘라준다.\",\"2. 파인애플도 먹기 좋게 썰어준 뒤 레몬소금을\\n살짝 뿌려준다.\",\"3. 계란은 풀어서 팬에 스크램블을 만들어준다.\",\"4. 마늘을 다진 후 마늘기름으로 칵테일 새우를\\n볶아준다.\",\"5. 볶아진 칵테일새우에 잘라준 채소를 넣어\\n다시 볶아준다.\",\"6. 여기에 밥을 넣어서 볶아주고 파인애플과\\n맛간장, 통깨를 넣어서 볶아준다.\"]},{\"id\":\"k115\",\"title\":\"연근초무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00419_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00419_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연근 200g\",\"양파 60g\",\"오이 40g\",\"밤 60g\",\"소스 : 유자청 25g\",\"강황가루 2g\",\"잣 2g\",\"설탕 5g\",\"식초 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"잣의 고소함과 유자청의 상큼한 맛이 소스에 상큼한 맛을 주었고, 연근과 밤을 이용해 식감을 살려주어 추가 간을 하지 않아도 자연의 맛을 느낄 수 있는 조리법이다\",\"instructions\":[\"1. 양파는 채 썰어 물에 담가주고, 오이는 돌려\\n깎기 해서 물에 담가준다.\",\"2. 연근은 껍질을 까고 얇게 썰어서 식초 2방울을\\n넣은 물에 데쳐준다.\",\"3. 밤도 아주 얇게 썰어서 물에 담가준다.\",\"4. 소스 재료를 모두 넣고 믹서에 간다.\",\"5. 물에 데쳐낸 연근은 키친타월에 올려서 물기를\\n완전히 제거한다.\",\"6. 모든 재료를 넣고 소스에 버무려준다.\"]},{\"id\":\"k116\",\"title\":\"코다리맑은찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00420_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00420_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"코다리 250g\",\"콩나물 50g\",\"미나리 20g\",\"함초 25g\",\"무 30g\",\"함초소금 1g\",\"양념 : 간편어간장 15g\",\"함초소금 1g\",\"생강청 15g\",\"흰후추 1g\",\"청주 15g\",\"레몬즙 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스를 만들 때 레몬즙을 이용해 상큼한 맛이 짠맛을 대체하여 간장을 조금만 사용해도\\n깊은 맛을 내는 효과로 나트륨을 줄였다.\",\"instructions\":[\"1. 코다리는 어간장, 청주, 흰후추, 생강청에\\n살짝 재워준다.\",\"2. 함초는 손질해 잘라준다.\",\"3. 무는 소금에 살짝 절여서 수분과 염분을\\n제거해준다.\",\"4. 무와 함초를 고루 섞어준다.\",\"5. 미나리와 콩나물은 손질해준 후 찜기에 깔고\\n코다리를 쪄준다.\",\"6. 소스를 만든 뒤 채소를 깔고 코다리를 올리고\\n미나리, 콩나물을 올려 완성한다.\"]},{\"id\":\"k117\",\"title\":\"뿌리채소두부선\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00421_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00421_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 300g\",\"전분 50g\",\"계란 60g\",\"흰후추 2g\",\"소 : 우엉 30g\",\"인삼 15g\",\"감자 30g\",\"청고추 10g\",\"홍고추 15g\",\"마늘기름 15g\",\"흰후추 1g\",\"소스 : 일본된장 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"땅콩잼과 참깨를 이용해 소스에 고소한 맛을 더해 된장의 나트륨을 줄여주었고, 나트륨 배출에 도움을 주는 뿌리채소를 이용해 각각의 향을 주어 담백한 두부의 풍미를 살렸다.\",\"instructions\":[\"1. 두부는 물기를 꼭 짠 뒤 으깨어 전분, 계란과\\n섞어준다.\",\"2. 우엉, 인삼, 감자는 아주 곱게 채 썰어서 냉수에\\n담가준다.\",\"3. 볶아진 모든 채소를 각각 볶아서 한데 섞어\\n준다.\",\"4. 땅콩잼으로 소스를 만들어준다.\",\"5. 김발을 깔고 비닐을 놓아 준 후 두부를 펴준다.\",\"6. 볶아진 채소를 두부에 넣어주고 찜기에 쪄서\\n식힌 뒤 한입 크기로 잘라준다.\"]},{\"id\":\"k118\",\"title\":\"사과장아찌\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00422_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00422_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"풋사과 200g\",\"양파 80g\",\"청고추 20g\",\"홍고추 20g\",\"소스 : 맛간장 30g\",\"식초 30g\",\"설탕 10g\",\"생강청 30g\",\"매실청 15g\",\"청주 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"장아찌를 만들 때 소스를 생강청, 매실청 등을 넣어 특유의 단맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 사과는 8조각으로 잘라 씨를 제거한다.\",\"2. 청고추, 홍고추는 어슷하게 잘라준다.\",\"3. 양파도 먹기 좋은 크기로 잘라준다.\",\"4. 사과는 식초 물에 살짝 절여준다.\",\"5. 양념장을 만든다.\",\"6. 양념장에 준비된 재료를 모두 섞어 완성한다.\"]},{\"id\":\"k119\",\"title\":\"해물들깨탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00423_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00423_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미 80g\",\"전복 100g\",\"칵테일새우 50g\",\"양파 560g\",\"청고추 17g\",\"홍고추 17g\",\"계란 60g\",\"청주 15g\",\"국물 : 거피한 들깨가루 100g\",\"저염간장 15g\",\"다진마늘 15g\",\"다진대파 7g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"들깨의 구수한 맛과 염도를 낮춘 간장으로 국물을 우려내 짠맛을 내지 않아도 깊은 맛을 냈다.\",\"instructions\":[\"1. 주꾸미, 전복, 칵테일새우는 각각 물에 데쳐서\\n준비한다.\",\"2. 이때 데치고 남은 물을 국물에 이용해주고\\n여기에 청주를 넣어준다.\",\"3. 양파, 청고추, 홍고추는 먹기좋게 썰어준다.\",\"4. 계란을 황백으로 부쳐서 먹기좋게 썰어준다.\",\"5. 만들어진 국물에 거피한 들깨가루와 국물재료를\\n넣어 끓여서 준비한다.\",\"6. 준비된 재료를 냄비에 넣고 국물을 부어 끓여\\n완성한다.\"]},{\"id\":\"k120\",\"title\":\"참외깍두기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00424_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00424_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"참외 200g\",\"양파 60g\",\"청고추 17g\",\"홍고추 17g\",\"대파 15g\",\"미나리 20g\",\"양념장 : 저염간장 15g\",\"생강청 10g\",\"고춧가루 10g\",\"통깨 5g\",\"다진마늘 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"염도를 낮춘 간장을 사용하여 참외와 양파를 절여 염도가 낮은 김치를 만들었다.\",\"instructions\":[\"1. 참외는 껍질을 벗기고 반으로 잘라 속을\\n파 준 후 먹기 좋게 잘라준다.\",\"2. 청고추, 홍고추는 송송 잘라준다.\",\"3. 양파와 미나리는 참외크기로 자르고, 대파는\\n송송 자른다.\",\"4. 참외, 양파를 저염 간장에 살짝 절여준다.\",\"5. 절여진 채소에 고춧가루로 먼저 색을 입힌다.\",\"6. 나머지 재료를 넣고 김치를 만든다.\"]},{\"id\":\"k121\",\"title\":\"새콤한연어샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00425_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00425_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어 60g\",\"어린잎 20g\",\"말린 토마토 15g\",\"양파 50g\",\"2가지색 미니파프리카 70g\",\"소스 : 유자청 30g\",\"감식초 15g\",\"정종 100ml\",\"볶은소금 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감식초와 유자청으로 상큼한 맛을 주었고, 말린 토마토를 이용해 씹는 맛이 짠맛을 대체하였다.\",\"instructions\":[\"1. 연어는 얇게 모양을 살려 슬라이스 한 후\\n정종에 소금을 섞어 분무기에 넣어 냉장고에\\n넣어둔다.\",\"2. 건조된 방울토마토는 올리브오일과 후추로\\n양념하여 사용한다.\",\"3. 양상추는 먹기 좋은 크기로 뜯어 어린잎과\\n함께 찬물에 담가 물기를 제거한 후 사용한다.\",\"4. 유자청과 감식초는 함께 섞어 믹서에 갈아\\n드레싱소스를 완성한다.\",\"5. 양파는 모양을 살려 얇게 슬라이스 하여\\n찬물에 담가 물기를 제거한 뒤 사용한다.\",\"6. 샐러드 접시에 준비된 모든 채소를 담고,\\n연어는 장미 모양으로 접어서 보기좋게 담아\\n드레싱 소스를 곁들여 완성한다.\"]},{\"id\":\"k122\",\"title\":\"논우렁순무섞박지\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00426_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00426_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콜라비 200g\",\"논우렁 100g\",\"미나리 25g\",\"양파 60g\",\"청고추 15g\",\"홍고추 15g\",\"대파 10g\",\"양념 : 고춧가루 20g\",\"생강청 15g\",\"저염간장 15g\",\"다진마늘 15g\",\"플레인요구르트 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"플레인요구르트로 고춧가루의 염도를 줄여주었고, 생강청의 톡 쏘는 맛이 짠맛을 대체하였다.\",\"instructions\":[\"1. 콜라비는 껍질을 벗긴 후 저염간장에 30분\\n정도 절여준다.\",\"2. 우렁은 뜨거운 물에 데친 후 행군 뒤 물기를\\n빼준다.\",\"3. 미나리는 먹기 좋은 크기로 잘라준다.\",\"4. 다진대파, 청홍고추, 양파는 송송 잘라준다.\",\"5. 양념장에 콜라비부터 버무린 뒤 모든 재료를\\n섞어서 완성한다.\"]},{\"id\":\"k123\",\"title\":\"코다리맑은탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00427_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00427_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"코다리 200g\",\"무 60g\",\"감자 60g\",\"양파 15g\",\"청양고추 30g\",\"미나리 25g\",\"백일송이버섯 25g\",\"참기름 15g\",\"국물 : 다진마늘 15g\",\"저염간장 15g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"맑은 국물에 소금간을 많이 하지 않고 염도를 낮춘 간장으로 감칠맛을 내주었다.\\n무와 감자를 이용해 부드럽게 씹는 맛이 짠맛을 대체하였다.\",\"instructions\":[\"1. 코다리는 먹기 좋게 잘라서 물에 헹궈 물기를\\n빼준다.\",\"2. 감자와 무, 백일송이버섯, 미나리는 먹기 좋게\\n썰어준다.\",\"3. 양파, 청양고추도 먹기 좋게 썰어준다.\",\"4. 냄비에 참기름을 넣어 코다리를 살짝 볶아준다.\",\"5. 코다리를 볶은 냄비에 무, 감자, 국물 재료를\\n넣고 충분히 끓인다.\",\"6. 끓고 있는 국에 양파, 청양고추, 백일송이\\n버섯을 올려 완성한다.\"]},{\"id\":\"k124\",\"title\":\"세가지샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00530_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00530_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연두부(100g)\",\"닭고기살(50g)\",\"통후추(1g)\",\"단호박(20g)\",\"바나나(20g)\",\"파프리카(20g)\",\"토마토(20g)\",\"어린잎(10g)\",\"- 소스 : 마(20g)\",\"생크림(20g)\",\"요거트(20g)\",\"식초(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"마, 흑임자 등을 섞어서 만든 소스는 나트륨 함량을 낮춰주어요.\",\"instructions\":[\"1. 연두부는 동글게 썰어 준비한다.\",\"2. 호박은 갈라 씨를 제거 하고 껍질을\\n벗겨 쪄서 작은 깍둑썰기로 썰어 준비\\n한다.\",\"3. 바나나와 파프리카 토마토는 호박과\\n같은 크기의 작은 깍두기로 썰어 놓는다.\",\"4. 닭고기살은 통후추를 넣고 약 20분 정도\\n삶아 건져 작은 깍두기로 썰어 준비한다.\",\"5. 마와 잣, 흑임자를 갈아 놓은 뒤 생크림,\\n요거트, 식초, 올리브오일, 설탕을\\n섞어 샐러드 소스를 만들어 놓는다.\",\"6. 썰어 놓은 연두부 위에 호박 , 닭고기,\\n토마토, 파프리카를 각각 올린 뒤 어린\\n잎을 올리고 소스를 뿌려 완성한다.\"]},{\"id\":\"k125\",\"title\":\"애호박들깨볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00531_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00531_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"애호박(150g)\",\"소금(0.5g)\",\"양파(20g)\",\"대파(10g)\",\"홍고추(10g)\",\"들기름(20g)\",\"다진 마늘(5g)\",\"건새우(20g)\",\"들깨가루(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"건새우와 들깨가루를 넣어 감칠맛과 고소한 맛을 더했어요.\",\"instructions\":[\"1. 애호박은 반달 모양으로 썰어 준다.\",\"2. 썰어 놓은 호박에 소금을 넣고 살짝\\n절여 물기를 제거하고 준비한다.\",\"3. 양파는 채를 썰고, 대파는 1/4로 자르고,\\n홍고추는 어슷썰어 자연스럽게 씨를\\n제거해 놓는다.\",\"4. 팬에 들기름을 넣고, 마늘을 먼저\\n볶는다.\",\"5. 볶아진 팬에 건새우를 넣어 볶아준다.\",\"6. 건새우가 볶아지면, 썰어 놓은 호박을\\n넣어 볶다가 양파와 대파를 넣어\\n볶으면서 들깨 가루와 넣어 살짝\\n볶으면서 마지막에 썰어 놓은 홍고추를\\n넣어 한 번만 더 볶아 완성한다.\"]},{\"id\":\"k126\",\"title\":\"고구마바나나샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00532_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00532_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마(100g)\",\"바나나(100g)\",\"요거트(30g)\",\"어린잎(20g)\",\"잣(5g)\",\"연유(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마와 바나나를 섞어 연유를 넣어 만들면 나트륨을 넣지 않아도 맛이 좋은 샐러드를 만들 수 있어요.\",\"instructions\":[\"1. 고구마는 찜통에 약 20분 정도 쪄서\\n껍질을 벗겨 준비한다.\",\"2. 뜨거운 고구마가 한김 빠지면, 곱게\\n으깨 놓는다.\",\"3. 으깨진 고구마에 바나나를 썰어\\n요거트와 함께 넣는다.\",\"4. 3번에 다시 연유를 넣어 골고루 섞는다.\",\"5. 잣은 종이를 깔고 곱게 다져 준비한다.\",\"6. 어린잎은 물에 담그어, 건져 물기를\\n제거해 놓고, 으깬 고구마에 다진 잣을\\n넣어 샐러드를 완성한다.\"]},{\"id\":\"k127\",\"title\":\"누룽지새우튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00533_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00533_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(100g)\",\"소금(0.3g)\",\"후춧가루(0.02g)\",\"튀김가루(100g)\",\"달걀(50g)\",\"누룽지(50g)\",\"튀김기름(200g)\",\"- 소스 : 오렌지주스(100g)\",\"설탕(10g)\",\"식초(10g)\",\"- 곁들임채소 : 어린잎(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일소스를 사용하여 새콤달콤한 맛을 더했어요.\",\"instructions\":[\"1. 새우는 껍질을 제거하고 소금과\\n후춧가루를 넣어 밑간을 해놓는다.\",\"2. 어린잎은 찬물에 담그어 놓는다.\",\"3. 튀김가루에 달걀을 넣어 잘 섞어\\n튀김반죽을 만들어 놓는다.\",\"4. 밑간을 해 놓은 새우를 튀김반죽에\\n넣어 옷을 입힌다.\",\"5. 누룽지는 170℃의 온도 튀김 기름에\\n튀겨내고, 튀김옷 입힌 새우도 튀겨낸다.\",\"6. 냄비에 오렌지주스와 설탕, 식초를\\n넣어 은근히 졸여 소스를 만들고,\\n어린잎은 찬물에 건져 물기를 제거하고\\n접시에 깔고 튀긴 누룽지와 튀긴 새우를\\n올려 완성한다.\"]},{\"id\":\"k128\",\"title\":\"백김치주꾸미샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00534_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00534_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"백김치(100g)\",\"주꾸미(100g)\",\"파(10g)\",\"양상추(10g)\",\"홍고추(10g)\",\"어린잎(10g)\",\"- 샐러드드레싱 : 저염간장(20g)\",\"식초(10g)\",\"설탕(10g)\",\"꿀(10g)\",\"레몬(10g)\",\"양파(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"백김치 자체에 간이 있어 소금을 넣지 않고도 맛이 좋은 샐러드를 완성할 수 있어요.\",\"instructions\":[\"1. 백김치는 살짝 씻어 물기를 제거하고\\n잘게 썰어 준비한다.\",\"2. 양파와 마늘은 다지고 파는 채를 썰어\\n놓는다.\",\"3. 어린잎은 찬 물에 담그어 놓았다가,\\n다시 소창에 건져 물기를 빼 놓는다.\",\"4. 냄비에 물을 넣고, 양파와 파를 넣어\\n끓이다가 준비한 쭈구미를 넣고\\n부드럽게 데쳐 썰어 놓는다.\",\"5. 식초와 간장, 설탕, 꿀, 레몬, 다진양파,\\n다진마늘을 넣고 잘 섞어서 샐러드\\n드레싱을 만든다.\",\"6. 준비한 백김치(①)와 주꾸미(②)를\\n섞은 후 양상추를 접시에 깔고, 그 위에\\n섞어놓은 백김치와 주꾸미를 올리고,\\n홍고추와 어린잎을 위에 장식으로 올린\\n후 샐러드 소스를 뿌려 완성한다.\"]},{\"id\":\"k129\",\"title\":\"닭고기월남쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00535_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00535_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기살(100g)\",\"로즈마리(5g)\",\"양파(20g)\",\"소금(0.5g)\",\"후춧가루(0.02g)\",\"오이(30g)\",\"파프리카(30g)\",\"당근(30g)\",\"라이스페이퍼(20g)\",\"녹말가루(30g)\",\"식용유(20g)\",\"- 소스 : 다진 마늘(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라이스 페이퍼를 이용하여 채소와 닭고기살의 맛을 함께 느낄 수 있어 소금간 없이 맛을 냈어요\",\"instructions\":[\"1. 닭고기살에 로즈마리를 뿌려 약 3시간\\n이상 숙성을 시킨다.\",\"2. 냄비에 물을 1/3쯤 넣고, 양파채를 썰어\\n넣어 끓으면, 숙성된 닭고기살을 넣고\\n약 20분 정도 삶아 건진다.\",\"3. 삶아 건진 닭고기살을 한 김 빼고, 길게\\n손으로 찢어 소금과 후춧가루에 살짝\\n무치고, 오이와 파프리카는 씨를 제거\\n하고 채를 썰고, 당근도 오이채의 길이에\\n맞게 채를 썰어 준비해 놓는다.\",\"4. 마늘을 다지고, 고춧가루와 설탕, 식초,\\n레몬즙을 넣어 소스를 만든다.\",\"5. 뜨거운 물에 라이스페이퍼를 살짝 넣어\\n바로 건진다.\",\"6. 건져 놓은 라이스페이퍼에 준비한\\n닭고기살과 파프리카, 오이, 당근 넣고\\n돌돌 말아, 녹말가루를 살짝 입혀, 팬에\\n굴리듯 익혀 완성하고, 준비해 놓은\\n소스와 함께 제공한다.\"]},{\"id\":\"k130\",\"title\":\"단호박소고기롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00537_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00537_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(70g)\",\"저염간장(10g)\",\"다진 마늘(10g)\",\"설탕(10g)\",\"파프리카(30g)\",\"오이(20g)\",\"적양배추(20g)\",\"사과(20g)\",\"설탕(10g)\",\"팽이버섯(20g)\",\"무순(5g)\",\"- 밀전병 : 단호박(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박을 이용한 전병에 사과와 버섯, 다양한 채소를 넣어 롤을 만들기 때문에 나트륨 사용이 적어도 좋은 맛을 느낄 수 있어요\",\"instructions\":[\"1. 단호박은 1/8 등분으로 갈라 속을\\n파내고 찜통에서 약 15~20분 정도\\n충분히 쪄낸다.\",\"2. 소고기는 채를 썰어 마늘, 간장, 설탕에\\n양념을 하고 팬에 볶아서 식힌다.\",\"3. 파프리카와 오이, 적양배추는 채를\\n썰고, 무순은 물에 잠시 담그어 놓고,\\n사과는 채를 썰어 설탕물에 잠시 담그어\\n놓고, 팽이버섯은 밑둥만 잘라 한 줌\\n집기 좋은 크기로 준비해 놓는다.\",\"4. 다진마늘과 다진 양파 ,올리브오일,\\n설탕, 식초, 소금을 넣고, 골고루 섞어\\n소스를 만들어 놓는다.\",\"5. 쪄 낸 단호박은 껍질을 벗기고 채에\\n곱게 내려 밀가루와 물, 소금을 조금\\n섞어 단호박 반죽을 만들어 놓는다.\",\"6. 팬에 올리브 오일을 바르고, 만들어\\n놓은 단호박 반죽을 한 국자씩 떠 넣어,\\n밀전병을 만들고, 밀전병이 익으면,\\n한 김 식혀, 그 안에 소고기 볶음과\\n채소를 넣어 돌돌 말아 소스와 함께\\n완성한다.\"]},{\"id\":\"k131\",\"title\":\"생선카레튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00538_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00538_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"생선살(150g)\",\"생강(10g)\",\"정종(10g)\",\"녹말가루(10g)\",\"깻잎(10g)\",\"- 튀김반죽 : 콩가루(20g)\",\"밀가루(10g)\",\"카레가루(10g)\",\"녹말가루(10g)\",\"달걀(50g)\",\"- 소스 : 마요네즈(20g)\",\"요구르트(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 마요네즈와 요구르트를 섞어 만들기 때문에 튀김의 느끼한 맛을 잡아주고, 튀김옷에 카레가루와 콩가루를 넣어 별도의 소금간이 없어도\\n맛있는 생선튀김을 즐길 수 있어요.\",\"instructions\":[\"1. 생선살에 생강즙과 정종을 넣고 약 30분\\n정도 숙성을 시켜 비릿한 맛 제거 및 생선\\n살의 탱탱함을 살려준다.\",\"2. 콩가루와 밀가루, 카레가루, 녹말가루,\\n달걀을 넣고 골고루 섞어 튀김 반죽을\\n만들어 놓는다.\",\"3. 깻잎은 반으로 접어 채를 썰어 물에\\n잠시 담그어 놓는다.\",\"4. 깻잎(③)은 물기를 제거하고\\n튀김반죽(②)을 골고루 입힌다.\",\"5. 숙성시킨 생선살(①)에 녹말가루를\\n살짝 입히고 튀김 반죽(②)을 골고루\\n입힌 뒤, 튀김반죽을 입힌 깻잎(④)을\\n얹어 튀김 기름 170℃ 온도에 넣어\\n약 2분 정도 튀겨 기름을 자연스럽게\\n빼 놓는다.\",\"6. 마요네즈와 요구르트, 설탕, 식초를\\n넣어 골고루 섞어 튀김소스를 만들고,\\n튀김을 접시에 담아 양상추와 함께 얹어\\n완성한다.\"]},{\"id\":\"k132\",\"title\":\"삼겹가지볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00539_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00539_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼겹살(100g)\",\"생강(5g)\",\"정종(10g)\",\"가지(50g)\",\"양파(20g)\",\"당근(20g)\",\"깻잎(10g)\",\"느타리버섯(20g)\",\"대파(10g)\",\"식용유(5g)\",\"참기름(5g)\",\"잣(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장 대신 고춧가루와 갖가지 양념을 넣고 양념장을 만들어 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 썰어 놓은 삼겹살에 생갑즙과 정종을\\n넣고 약 2시간 정도 숙성을 시켜 준비\\n한다.\",\"2. 가지는 씨가 적은 것으로 골라 반으로\\n갈라 어슷썰어 놓는다.\",\"3. 양파와 깻잎은 채를 썰고, 당근은\\n직사각형으로 썰고, 대파는 송송 썰고,\\n느타리는 손으로 찢어 준비한다.\",\"4. 고춧가루과 다진마늘, 간장, 올리고당,\\n후춧가루, 설탕을 넣고 골고루 섞어\\n양념장을 만든다.\",\"5. 숙성시켜 놓은 삼겹살에 만들어 놓은\\n양념장을 넣고 골고루 무쳐 놓는다.\",\"6. 팬에 기름을 살짝 둘러 양념한 고기(⑤)\\n를 먼저 볶은 후 고기가 중간쯤 익으면,\\n가지(②)와 썰어 놓은 채소(③)를 넣어\\n볶다가 마지막에 참기름과 잣을 넣고\\n한 번 더 볶은 후 통깨를 올려 완성한다.\"]},{\"id\":\"k133\",\"title\":\"주꾸미샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00540_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00540_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미(120g)\",\"밀가루(10g)\",\"식초(10g)\",\"양상추(30g)\",\"미나리(30g)\",\"홍고추(10g)\",\"피망(20g)\",\"- 소스 : 배(40g)\",\"무(20g)\",\"와사비(5g)\",\"설탕(20g)\",\"다진 마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배즙과 무즙을 이용한 샐러드 소스는 시원한 맛을 내어 짠 맛을 대체하였어요.\",\"instructions\":[\"1. 끓는 물에 식초 한 방울을 떨어 뜨려\\n주꾸미를 데쳐 한김 식혀 먹기 좋게\\n썰어놓는다.\",\"2. 끓는 물에 식초 한 방울을 떨어 뜨려\\n주꾸미를 데쳐 한김 식혀먹기 좋게\\n썰어놓는다.\",\"3. 양상추는 손으로 뜯어, 찬물에 담그어\\n놓는다.\",\"4. 미나리는 약 4cm 길이로 썰고, 홍고추는\\n어슷 썰어 씨를 살짝 제거하고 피망은\\n씨를 제거하고 미나리와 비슷한 길이로\\n썰어놓는다.\",\"5. 강판에 곱게 간 배즙과 무즙에 와사비,\\n설탕, 다진마늘, 식초, 소금을 넣어\\n샐러드소스를 만든다.\",\"6. 만들어 놓은 샐러드소스와 함께 썰어\\n놓은 주꾸미(②)와 채소(③, ④)를 넣어\\n먹기 직전에 버무려 완성한다.\"]},{\"id\":\"k134\",\"title\":\"닭가슴살현미스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00541_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00541_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살(150g)\",\"정종(10g)\",\"카레가루(20g)\",\"현미쌀(50g)\",\"튀김기름(200g)\",\"- 소스 : 토마토소스(50g)\",\"생크림(20g)\",\"- 곁들임채소 : 적양배추(20g)\",\"양배추(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭가슴살을 카레가루로 숙성을 시키면 별도의 양념이 없어도 간이 잘 스며들어 나트륨 함량을 줄 일 수 있어요.\",\"instructions\":[\"1. 닭가슴살에 칼을 1/3 쯤 넣고 양쪽으로\\n포를 뜨고, 정종을 살짝 발라놓는다.\",\"2. 포뜬 닭가슴살 위에 카레가루를 솔솔\\n뿌려 숙성을 시킨다.\",\"3. 현미쌀은 물에 충분히 불려, 물기를\\n빼 놓고, 양배추와 적 양배추는 곱게\\n채를 썰어 각각 찬물에 담그어 싱싱\\n해 지면 건져 물기를 빼놓는다.\",\"4. 냄비에 토마토소스를 끓이다가\\n생크림을 넣고 살짝 한 번 더\\n끓여놓는다.\",\"5. 튀김기름에 온도가 약 170℃ 정도가\\n되면, 불려 놓은 현미쌀의 물기를\\n제거한 뒤 튀겨 기름을 제거해 놓는다.\",\"6. 숙성된 닭가슴살(①)에 튀긴 현미쌀\\n(⑤)을 앞뒤로 골고루 바르고 다시\\n170℃ 온도의 튀김 기름에 약 3~5분\\n정도 튀겨내고, 양배추와 적채를 깔고\\n그 위에 튀겨진 닭가슴살을 올리고,\\n토마토소스를 뿌려 완성한다.\"]},{\"id\":\"k135\",\"title\":\"삼겹선\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00542_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00542_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼겹살(100g)\",\"정종(20g)\",\"소금(0.5g)\",\"후춧가루(0.05g)\",\"생강즙(10g)\",\"조(20g)\",\"쌀(50g)\",\"양파(30g)\",\"파프리카(30g)\",\"당근(20g)\",\"새송이버섯(20g)\",\"표고버섯(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다양한 채소와 조밥을 삼겹살에 함께 넣어 말아 만든 삼겹선은 단백하고 먹기 편하며, 새콤달콤한 소스가 어우러져 나트륨 사용량을 줄였어요.\",\"instructions\":[\"1. 삼겹살에 소금, 후춧가루, 생강즙,\\n정종을 넣고 약 30분 정도 숙성을 시킨다.\",\"2. 조와 쌀은 물에 약 30분 정도 불려 밥을\\n짓고, 밥이 다 익으면, 뚜껑을 열어 주걱\\n으로 골고루 섞어 한 김을 빼 놓는다.\",\"3. 파는 길게 채를 썰어 물에 담그어 파채가\\n둥글게 말리도록 한다.\",\"4. 설탕과 식초, 레몬, 소금, 고춧가루,\\n매실액을 골고루 섞어 소스를 만들어\\n놓는다.\",\"5. 파프리카는 속을 제거하고 양파,\\n당근, 파프리카를 양파와 같은 길이로\\n채를 썰고, 새송이와 표고버섯은 살짝\\n데쳐 채를 썰고, 깻잎도 채를 썰어\\n놓는다.\",\"6. 파프리카는 속을 제거하고 양파, 당근,\\n파프리카를 양파와 같은 길이로 채를\\n썰고, 새송이와 표고버섯은 살짝 데쳐\\n채를 썰고, 깻잎도 채를 썰어 놓는다.\"]},{\"id\":\"k136\",\"title\":\"미니버섯탕수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00543_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00543_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"미니버섯(120g)\",\"소금(0.3g)\",\"녹말가루(50g)\",\"달걀흰자(30g)\",\"튀김기름(300g)\",\"- 소스 : 저염간장(30g)\",\"홍초(20g)\",\"설탕(20g)\",\"브로컬리(20g)\",\"오이(20g)\",\"당근(20g)\",\"홍파프리카(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기를 사용하지 않고, 버섯을 이용한 탕수육은 소화가 잘 되고, 짠맛이 적어 나트륨 함량을 줄 일 수 있어요.\",\"instructions\":[\"1. 미니버섯을 깨끗이 씻어 소금을 살짝\\n뿌려 놓는다.\",\"2. 녹말가루에 물을 반쯤 넣고, 가만히\\n가라앉혀 윗물은 따라 버리고, 딱딱한\\n된녹말을 만들어 놓는다.\",\"3. 브로컬리는 끓는 물에 데쳐 작게 썰고,\\n오이는 반달로 썰고, 당근은 은행잎\\n모양으로 썰어 준비하고, 파프리카는\\n속씨를 제거하고, 삼각지게 썰어 준비\\n한다.\",\"4. 간장과 홍초, 설탕을 넣어 골고루 섞어\\n탕수육소스를 만들어 놓는다.\",\"5. 소금을 뿌려 놓은 미니 버섯에 만들어\\n놓은 된 녹말과 달걀흰자를 넣어 골고\\n루 섞는다.\",\"6. 튀김 기름의 온도가 170~180℃가\\n되면, 녹말 입힌 미니버섯을 바삭 하게\\n튀겨 주고, 다시 팬에 만들어 놓은\\n탕수육소스를 바글바글 끓이다가,\\n썰어 놓은 채소를 넣고 살짝 익힌 후,\\n물녹말을 한 숟가락 정도 넣어 끓인 후\\n튀겨진 미니버섯 위에 올려 완성해 준다.\"]},{\"id\":\"k137\",\"title\":\"연어오븐구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00571_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00571_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(150g)\",\"양파(50g)\",\"토마토(100g)\",\"파프리카(50g)\",\"당근(30g)\",\"마늘(20g)\",\"청피망(30g)\",\"레몬(1/4개)\",\"소금(0.3g)\",\"후춧가루(0.01g)\",\"생크림(20g)\",\"화이트크림(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연어를 레몬으로 마리네이드 하면 연어의 비릿한 맛을 감소시키고 소금 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 연어는 소금, 후춧가루, 레몬으로\\n마리네이드 한다.\",\"2. 양파, 마늘은 입자있게 다진다.\",\"3. 토마토는 씨를 제거하고 입자있게\\n썰고, 파프리카, 피망은 채 썬 뒤\\n볶는다.\",\"4. 화이트크림, 생크림을 골고루 섞어\\n크림소스를 만든다.\",\"5. 팬에 버터를 넣고 양파, 마늘을 볶다가\\n만들어 놓은 크림소스를 넣고 졸인다.\",\"6. 접시에 볶은 야채를 담고, 200℃\\n오븐에서 10분 정도 구운 연어를 담은\\n뒤 크림소스를 올린다.\"]},{\"id\":\"k138\",\"title\":\"옥음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00572_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00572_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"옥수수콘(200g)\",\"애호박(1/3개)\",\"당근(20g)\",\"양파(30g)\",\"새송이버섯(1/2개)\",\"마늘(10g)\",\"라이스페이퍼(1장)\",\"저염간장(20g)\",\"쌀(150g)\",\"후춧가루(0.01g)\",\"식용유(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"식이섬유가 풍부한 옥수수에 갖은 야채를 넣어 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 쌀은 깨끗이 씻어 30분 이상 불려 밥을\\n지어 식힌다.\",\"2. 옥수수콘은 체에 걸러 물기를 뺀다.\",\"3. 양파, 애호박, 당근, 양파 및\\n새송이버섯은 옥수수콘 크기로 썰고\\n마늘은 다진다.\",\"4. 팬에 기름을 두르고 야채를 먼저\\n볶는다.\",\"5. 볶은 야채에 식혀놓은 밥을 넣고\\n볶다가 저염간장, 후춧가루로 간을\\n하고 옥수수콘을 넣고 살짝 볶는다.\",\"6. 팬에 기름을 자작하게 넣고,\\n라이스페이퍼를 둥글게 넣고 튀겨\\n그릇에 담은 뒤 볶음밥을 담는다\"]},{\"id\":\"k139\",\"title\":\"와사비 연어초밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00573_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00573_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(100g)\",\"쌀(150g)\",\"당근(20g)\",\"표고버섯(3장)\",\"겨자가루(10g)\",\"새싹(10g)\",\"파슬리(5g)\",\"식초(10g)\",\"설탕(20g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"초밥에 당근과 표고를 다져 넣어 향과 맛을 더해 소금 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 연어는 끝을 뾰족하게 살려\\n슬라이스한다.\",\"2. 쌀은 깨끗이 씻어 30분 이상 불려 밥을\\n지어 식힌다.\",\"3. 냄비에 식초, 설탕, 소금 약간과 물을\\n동량으로 넣고 끓인 뒤 식혀 촛물을\\n만들어 밥에 넣고 골고루 섞는다.\",\"4. 당근과 표고버섯은 입자있게 다져 살짝\\n볶아 식혀놓은 초밥에 넣고 잘\\n섞어준다.\",\"5. 와사비 가루에 30℃정도의 물을 넣고\\n섞은 뒤 발효 시키고, 초밥 형태를\\n만들어 그 위에 와사비를 바르고\\n연어를 올린 후 접시에 담는다\",\"6. 새싹과 파슬리는 찬물에 담았다 건져\\n물기를 빼고, 연어 초밥 옆에 올린다.\"]},{\"id\":\"k140\",\"title\":\"원소병\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00574_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00574_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀가루(200g)\",\"치자(10g)\",\"오미자(10g)\",\"대추(5알)\",\"귤병(20g)\",\"유자청(30g)\",\"꿀(50g)\",\"녹말(50g)\",\"잣(10알)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"5가지 맛을 내는 오미자가 들어가 소금 없이 요리를 할 수 있어요.\",\"instructions\":[\"1. 찹쌀가루는 체에 내려 2등분한다.\",\"2. 찹쌀가루는 오미자와 치자를 우린\\n뜨거운 물로 익반죽하여 비닐봉투에\\n담아 숙성시킨다\",\"3. 대추는 씨를 발라내 곱게 다지고 귤병,\\n유자청, 꿀을 섞어 원소병 소를 만든다.\",\"4. 굴병과 꿀을 섞어 원소병 소를\\n준비한다.\",\"5. 익반죽을 지름 3cm 크기로 동그랗게\\n만들고 안에 소를 넣어 다시 동그랗게\\n만든다\",\"6. 녹말가루를 입혀 끓는 물에 넣은 뒤\\n떠오르면 건져 찬물에 헹궈 물기를\\n빼고 그릇에 담아 꿀물을 붓고 잣을\\n올린다.\"]},{\"id\":\"k141\",\"title\":\"음메꼬꼬돌돌\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00575_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00575_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(120g)\",\"달걀(1개)\",\"닭고기(가슴살\",\"100g)\",\"미나리(50g)\",\"찹쌀가루(50g)\",\"홍고추(1개)\",\"소금(0.3g)\",\"후춧가루(0.01g)\",\"통후추(5알)\",\"저염간장(20g)\",\"설탕(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨이 적은 저염간장에 설탕과 식초를 넣어 나트륨을 더 감소시킬 수 있었어요.\",\"instructions\":[\"1. 소고기는 넓게 펴서 소금, 후춧가루로\\n밑간을 하고 굽는다.\",\"2. 닭가슴살은 소금, 후춧가루로 밑간을\\n하여 굽고 길이대로 썬다.\",\"3. 미나리는 끓는 물에 넣고 데쳐 찬물에\\n헹군다.\",\"4. 홍고추는 씨를 제거 하고 길게 썰어\\n준비한다.\",\"5. 달걀은 황백으로 나눠 지단을 부쳐\\n길게 썰어 놓는다\",\"6. 밑간한 소고기와 닭살 에 찹쌀가루를\\n뭍혀 홍고추와 달걀 황백지단을 넣어\\n돌돌 말아 미나리로 띠를 둘러 팬에\\n기름을 살짝 둘러 익힌다.\"]},{\"id\":\"k142\",\"title\":\"전복리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00576_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00576_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(100g)\",\"전복(1개)\",\"당근(20g)\",\"양파(30g)\",\"양송이버섯(3개)\",\"우유(200g)\",\"올리브오일(10g)\",\"소금(0.2g)\",\"후춧가루(0.01g)\",\"버터(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"천연 미네랄이 가득한 전복을 사용하면, 소금을 적게 넣어도 싱겁지 않아요.\",\"instructions\":[\"1. 쌀은 깨끗이 씻어 30분 정도 불린다\",\"2. 전복은 수저로 떼어 내어 소금으로\\n세척한다.\",\"3. 준비된 전복에 버터를 두르고 굽는다\",\"4. 당근. 양파 . 양송이는 입자 있게\\n다진다.\",\"5. 냄비에 올리브 오일을 넣고 불린 쌀을\\n볶는다.\",\"6. 쌀이 어느 정도 볶아지면 다져 놓은\\n야채를 넣어 볶다가 우유를 넣어\\n끓이고, 쌀이 퍼지면 구워 놓은 전복을\\n넣어 다시 끓인다.\"]},{\"id\":\"k143\",\"title\":\"참깨흑임 자연두부샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00577_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00577_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연두부(100g)\",\"참깨(20g)\",\"흑임자(20g)\",\"파프리카(50g)\",\"무순(10g)\",\"날치알(20g)\",\"설탕(20g)\",\"식초(10g)\",\"마요네즈(30g)\",\"우유(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"마요네즈에 우유를 섞으면 나트륨 함량을 줄일 수 있어요. 우유를 넣을 때에는 조금씩 저어가면서 넣어야 마요네즈가 분리되지\\n않아요.\",\"instructions\":[\"1. 참깨와 흑임자를 섞어 곱게 간다.\",\"2. 갈아 놓은 참깨와 흑임자에 설탕과\\n식초를 넣고 섞는다.\",\"3. 2번에 우유와 마요네즈를 넣고 골고루\\n섞어 참깨 흑임자 드레싱을 만든다.\",\"4. 연두부는 동그랗게 자른다.\",\"5. 파프리카는 채 썬다.\",\"6. 접시에 드레싱, 연두부, 파프리카,\\n무순, 날치알 순으로 올린다.\"]},{\"id\":\"k144\",\"title\":\"초계탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00578_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00578_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(다리\",\"2개)\",\"양파(50g)\",\"파프리카(50g)\",\"적양배추(20g)\",\"오이(50g)\",\"마늘(30g)\",\"겨자가루(20g)\",\"대파(20g)\",\"소금(0.3g)\",\"설탕(20g)\",\"식초(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭 육수에 겨자를 넣어 섞으면, 닭 비린맛을 제거하고 매콤한 맛과 향으로 소금 사용도 줄일 수 있어요.\",\"instructions\":[\"1. 냄비에 마늘과 대파를 넣고 끓이다가\\n닭다리를 넣고 삶는다\",\"2. 닭을 삶아 놓은 육수는 걸러 기름을\\n제거 하고 차갑게 식힌다.\",\"3. 삶아 놓은 닭고기는 결대로 찢는다.\",\"4. 양파, 오이와 파프리카는 채썬다\",\"5. 적채는 채를 썰어 찬물에 담궈 건져\\n물기를 빼 놓는다.\",\"6. 차갑게 걸러 놓은 닭 육수에 발효된\\n겨자와 소금 .설탕, 식초를 넣어 육수\\n간을 하고, 그릇에 닭살과 오이 적채,\\n파프리카 양파를 올려 차가운 육수를\\n넣어 완성한다.\"]},{\"id\":\"k145\",\"title\":\"콩나물부추볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00579_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00579_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콩나물(150g)\",\"부추(50g)\",\"양파(30g)\",\"당근(20g)\",\"파(10g)\",\"감자(50g)\",\"소금(0.3g)\",\"식용유(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"부추의 향 때문에 소금 간을 많이 하지 않아도 맛있어요.\",\"instructions\":[\"1. 감자는 채를 썰어 물에 담궈 전분을\\n제거하고, 양파와 당근 파는 채를 썬다.\",\"2. 콩나물은 머리와 꼬리를 손질한다\",\"3. 물이 끓으면 손질한 콩나물을 넣는다.\",\"4. 콩나물이 익으면 체에 건져 찬물에\\n헹군다.\",\"5. 부추는 약 6cm 길이로 썬다.\",\"6. 팬에 기름을 두르고 콩나물을 넣고\\n살짝 볶다가 썰어 놓은 야채를 넣고\\n볶으면서 소금 간을 하고 마지막에\\n부추를 넣고\"]},{\"id\":\"k146\",\"title\":\"콩비지포카치아 샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00580_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00580_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"포카치아빵(1개)\",\"콩비지(50g)\",\"무장아찌(20g)\",\"토마토(50g)\",\"생치즈(20g)\",\"루꼴라(20g)\",\"올리브오일(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"무장아찌를 이용하여 비지소스를 만들어서 별도의 소금 간을 하지 않고도 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 비지는 살짝 데쳐 물기를 뺀다.\",\"2. 무장아찌는 잘게 다져 비지에 골고루\\n섞어 소스를 만든다.\",\"3. 토마토는 슬라이스로 썰어 팬에 오일을\\n두르고 익힌다.\",\"4. 포카치아빵은 반으로 갈라 비지소스를\\n바른다.\",\"5. 생치즈는 동그랗게 원형으로 찍어,\\n비지를 바른 빵에 구운 토마토와 함께\\n올리고, 다시 그 위에 비지를 올려\\n접시에 담는다.\",\"6. 루꼴라는 찬물에 담궈 건져 포카치아빵\\n옆에 함께 놓는다\"]},{\"id\":\"k147\",\"title\":\"파프리카더덕소고기깻잎롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00581_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00581_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(살치살\",\"120g)\",\"파프리카(50g)\",\"더덕(100g)\",\"깻잎(3장)\",\"파인애플(50g)\",\"아스파라거스(3개)\",\"양파(50g)\",\"꿀(20g)\",\"레몬(1/4개)\",\"식초(10g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"더덕의 향과 파인애플의 단맛이 어우러져 소금을 조금만 사용해도 맛을 낼 수 있어요.\",\"instructions\":[\"1. 소고기는 후춧가루, 올리브오일로\\n밑간을 한다.\",\"2. 더덕은 칼로 껍질을 돌려 깎고,\\n파프리카, 아스파라거스와 함께\\n가늘게 채썬다.\",\"3. 파인애플, 양파, 당근, 대파는 채썬다.\",\"4. 밑간한 고기를 팬에 굽는다.\",\"5. 따로 갈아 놓은 파인애플과 레몬즙\\n꿀을 섞어 드레싱을 만는다\",\"6. 구워 놓은 고기에 더덕과 파인애플\\n아스파라거스 깻잎을 넣어 돌돌 말고,\\n팬에 발사믹 소스를 끓인 뒤 말아 놓은\\n소고기롤을 넣어 졸인다.\"]},{\"id\":\"k148\",\"title\":\"해물아란치니\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00582_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00582_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어(100g)\",\"새우(3마리)\",\"토마토(50g)\",\"양파(30g)\",\"마늘(20g)\",\"샐러리(20g)\",\"밥(100g)\",\"달걀(1개)\",\"어린잎(10g)\",\"소금(0.2g)\",\"레몬(1/4개)\",\"빵가루(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우와 오징어를 넣어 감칠맛이 좋고 소금을 사용하지 않는 볶음밥을 만들 수 있어요.\",\"instructions\":[\"1. 새우는 껍질을 벗겨 다진다.\",\"2. 오징어는 썰어서 다진다.\",\"3. 양파, 샐러리, 마늘은 다져 팬에 볶아\\n식힌다.\",\"4. 토마토는 껍질을 벗겨 다진다.\",\"5. 다진 토마토를 팬에 볶다가 다진\\n새우와 오징어, 밥을 넣어 볶고, 3번을\\n넣고 볶아 동그랗게 모양을 만든다\",\"6. 동그란 밥에 레몬을 섞은 달걀노른자를\\n묻히고 빵가루 옷을 입혀 팬에 기름을\\n둘러 굴려가며 익힌 후 접시에 담고\\n어린잎을 올린다.\"]},{\"id\":\"k149\",\"title\":\"호박잎삼계\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00583_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00583_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(120g)\",\"인삼(1뿌리)\",\"미나리(30g)\",\"대추(2알)\",\"찹쌀(50g)\",\"소금(0.2g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"천천히 익히는 조리법으로 재료의 맛이 충분히 우러나 간을 조금만 해도 맛있는 요리를 만들 수 있어요.\",\"instructions\":[\"1. 닭고기는 넓게 펴 소금, 후추로 밑간을\\n한다.\",\"2. 찹쌀은 깨끗이 씻어 밥을 짓는다\",\"3. 인삼은 뇌두를 제거 하고 깨끗이 씻어\\n길게 썬다.\",\"4. 미나리는 데쳐 찬물에 헹구고, 대추는\\n씨를 제거하고 채를 썬다.\",\"5. 호박잎은 끓는 물에 데쳐 찬물에\\n식힌다.\",\"6. 데친 호박잎에 밑간한 닭고기와\\n찹쌀밥을 올리고 그 위에 인삼, 데친\\n미나리, 대추를 올려 돌돌 말아 찜통에\\n찐 뒤 먹기 좋게 썬다.\"]},{\"id\":\"k150\",\"title\":\"노른자크림 육회샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00584_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00584_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(홍두깨살\",\"150g)\",\"두릅(100g)\",\"아보카도(1/2개)\",\"배(1/4개)\",\"마늘(20g)\",\"달걀(1개)\",\"레몬(1/8개)\",\"크림치즈(20g)\",\"설탕(20g)\",\"소금(0.3g)\",\"참기름(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크림치즈를 사용하여 나트륨 함량을 줄였어요\",\"instructions\":[\"1. 소고기는 홍두깨살로 준비해서\\n0.3mm 두께로 썰고, 배는 껍질을 벗겨\\n채 썰어 설탕을 뿌린다.\",\"2. 끓는 물에 소금을 넣고 두릅을 데친 후\\n찬물에 헹구어 건진다.\",\"3. 소금과 설탕, 다진 마늘을 넣고 소고기\\n육회 양념장을 만든다.\",\"4. 삶은 달걀노른자와 크림치즈, 레몬을\\n섞어 짤주머니에 담는다.\",\"5. 숙성이 잘된 아보카도는 강판에 갈아\\n준비한다.\",\"6. 접시에 양념한 육회와 두릅을 담고 그\\n위에 배를 올리고, 달걀크림과\\n아보카도를 짜서 올린다\"]},{\"id\":\"k151\",\"title\":\"닭고기 완자삼계죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00585_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00585_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(1마리)\",\"인삼(1뿌리)\",\"찹쌀(50g)\",\"대추(10알)\",\"마늘(30g)\",\"대파(30g)\",\"양파(30g)\",\"통후추(10알)\",\"저염간장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"완자에서 우러나오는 맛으로 짠맛을 대체하여 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 닭은 깨끗이 씻고 포를 뜬다.\",\"2. 닭고기는 15분 정도 삶아 식으면 곱게\\n다져 다진 마늘, 대파, 저염간장을 넣고\\n완자를 만든다.\",\"3. 인삼은 뇌두를 제거하고 깨끗이\\n씻는다.\",\"4. 찹쌀은 약 30분 정도 충분히 불린다\",\"5. 대추는 소금물에 깨끗이 씻고 씨를\\n제거한다.\",\"6. 믹서에 인삼과 대추, 불린 찹쌀, 물을\\n정도 넣고 곱게 간 뒤, 냄비에 담아 죽을\\n쑤다가 다 익으면 만들어 놓은 완자를\\n넣고 한소끔 더 끓인다.\"]},{\"id\":\"k152\",\"title\":\"대하마늘볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309012647_1678336007930.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309015216_1678337536871.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021346_1678338826806.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021409_1678338849298.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021426_1678338866582.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021447_1678338887494.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309021505_1678338905796.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 대하(3마리)\",\"쌀(90g)\",\"당근(20g)\",\"깻잎(2장)\",\"양파(30g)\",\"숙주(50g)\",\"대추(2알)\",\"청고추(1개)\",\"파(10g)\",\"마늘(10g)\",\"생강(5g)\",\"식용유(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•새우는 생강과 함께 쪄서 비린내를 잡고, 새우 본연의 감칠맛으로 저염간장 사용량을 줄였어요.\",\"instructions\":[\"1. 새우는 내장을 제거하고 껍질을 벗겨 깨끗이 씻는다.\",\"2. 찜기에 새우와 생강을 넣어 약 5분 정도 찐다.\",\"3. 마늘은 납작 썰고, 당근과 양파, 파, 깻잎, 청고추, 대추는 굵게 다진다.\",\"4. 숙주는 꼬리를 떼어 다듬고, 끓는 물에 살짝 데친다.\",\"5. 팬에 식용유를 두른 뒤 손질한 채소를 넣어 볶는다.\",\"6. 밥과 새우를 넣어 볶고, 저염간장을 넣어 볶아 마무리한다.\"]},{\"id\":\"k153\",\"title\":\"두부 카프리제\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00587_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00587_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(100g)\",\"돼지고기(100g)\",\"표고버섯(2개)\",\"마(100g)\",\"연근(20g)\",\"감자(60g)\",\"깻잎(3장)\",\"애호박(1/3개)\",\"마늘(20g)\",\"두유(100g)\",\"설탕(20g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"발사믹소스와 파마산치즈를 이용해서 소금 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 토마토는 깨끗이 씻어 슬라이스한다.\",\"2. 두부는 원형틀을 이용해서 토마토와\\n같은 크기로 만들고 소금을 살짝 뿌린\\n뒤 물기를 제거한다.\",\"3. 팬에 올리브오일을 두르고 두부를 살짝\\n굽는다.\",\"4. 어린잎은 찬물에 담근다.\",\"5. 발사믹소스에 설탕과 레몬즙을 넣고\\n골고루 섞어 소스를 만든다.\",\"6. 두부와 준비한 토마토를 접시에 돌려\\n담고 어린잎을 위에 올린 뒤 먹기\\n직전에 발사믹소스와 파마산치즈를\\n뿌려 완성한다.\"]},{\"id\":\"k154\",\"title\":\"미역볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00217_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00217_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 쌀(80g)\",\"완두콩(10g)\",\"닭고기(100g)\",\"대추(10g)\",\"수삼(20g)\",\"양파(20g)\",\"당근(10g)\",\"양념 강황가루(3g)\",\"맛술(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"미역과 해산물로 짭짤한 맛을 내 소금을 적게 사용하고, 들깻가루를 넣어\\n고소한 맛을 더했다.\",\"instructions\":[\"1. 쌀과 다시마를 넣고 쌀과 동량의\\n물을 부어 밥을 고슬고슬하게\\n짓는다.\",\"2. 양파는 굵게 다지고, 쪽파와 고추는\\n송송 썰고, 오징어와 주꾸미는 먹기\\n좋은 크기로 썬다.\",\"3. 달군 팬에 들기름을 두르고 다진\\n마늘을 볶아 향을 낸다.\",\"4. 미역을 넣고 볶다가 손질해둔\\n오징어, 주꾸미, 새우살, 양파를 넣어\\n볶는다.\",\"5. 밥을 넣고 소금을 넣어 볶다가\\n들깻가루를 넣어 볶는다.\",\"6. 송송 썬 쪽파와 청양고추, 붉은\\n고추를 넣어 조금 더 볶아\\n마무리한다.\"]},{\"id\":\"k155\",\"title\":\"청국장볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00218_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00218_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 쌀(100g)\",\"현미(30g)\",\"감자(30g)\",\"고구마(15g)\",\"양파(15g)\",\"연근(15g)\",\"당근(15g)\",\"애호박(15g)\",\"우엉(15g)\",\"마늘(3g)\",\"시금치(5g)\",\"참나물(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨 함량이 적은 생청국장을 사용해 간을 맞추고\\n칼륨을 다량 함유한 뿌리채소와 향미채소를 사용해\\n향과 맛을 살리면서 나트륨 배출 효과를 높였다\",\"instructions\":[\"1. 쌀과 현미는 물에 깨끗이 씻어 불린\\n후 밥을 고슬고슬하게 짓는다.\",\"2. 감자, 고구마, 우엉, 양파, 당근,\\n애호박, 연근은 작게 깍둑 썰고,\\n마늘은 편 썬다.\",\"3. 시금치와 참나물, 깻잎은 굵게 채\\n썰고, 미나리는 2.5㎝ 길이로 썬다.\",\"4. 물(50g)에 다시마를 우려내 육수를\\n내고 청국장을 넣어 잘 푼 뒤\\n들깻가루를 넣고 잘 저어주며 졸여\\n청국장소스를 만든다.\",\"5. 팬에 올리브유와 들기름을 두르고\\n양파, 마늘을 약한 불에 볶다가\\n감자, 고구마, 우엉, 연근, 당근,\\n애호박을 넣고 같이 볶는다.\",\"6. 밥과 청국장소스를 부어 80% 정도\\n볶다가 시금치, 참나물, 미나리를\\n넣고 한 번 더 볶고 채 썬 깻잎을\\n올려 마무리한다.\"]},{\"id\":\"k156\",\"title\":\"해물볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00219_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00219_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"볶음밥 쌀(100g)\",\"아스파라거스(5g)\",\"새송이버섯(10g)\",\"달걀(40g)\",\"문어(20g)\",\"새우살(20g)\",\"주꾸미(15g)\",\"미나리볶음고추장 무(20g)\",\"우엉(10g)\",\"미나리(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밥에 간을 따로 하지 않아 나트륨 함량을 줄이고 해산물 본연의 맛을 살렸다.\\n양념장을 따로 만들어 조금씩 비벼 먹으면 나트륨 섭취를 줄일 수 있다.\",\"instructions\":[\"1. 쌀은 씻어서 체에 건져 1시간 이상\\n불린 후 동량의 물을 부어 밥을\\n짓는다.\",\"2. 아스파라거스, 새송이버섯은 작게\\n깍둑 썰고, 무와 우엉, 미나리는\\n다진다.\",\"3. 식용유(10g)를 두른 팬을 중간 불로\\n달궈 달걀을 넣고 스크램블로\\n볶는다.\",\"4. 문어, 새우살, 주꾸미는 끓는 물에\\n살짝 데쳐 작게 자른다.\",\"5. 식용유(15g)를 두른 팬을 중간 불로\\n달궈 밥을 넣어 볶다가 문어, 새우살,\\n주꾸미, 스크램블 에그를 넣고 조금\\n더 볶는다.\",\"6. 무와 우엉에 고추장과 참기름,\\n물(40g)을 넣고 묽게 졸인 후 불을\\n끄고 미나리를 넣고 섞어\\n미나리볶음고추장을 만들어 밥에\\n곁들여 마무리한다.\"]},{\"id\":\"k157\",\"title\":\"토마토카레 채소볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00220_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00220_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 감자(20g)\",\"양파(10g)\",\"당근(10g)\",\"피망(5g)\",\"닭가슴살(20g)\",\"밥(200g)\",\"브로콜리(10g)\",\"방울토마토(20g)\",\"플레인 요구르트(15g)\",\"양념 후춧가루(0.1g)\",\"토마토페이스트(20g)\",\"파프리카가루(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레가루를 넣어 향미를 높이고 나트륨 함량을 낮추는 동시에\\n토마토를 넣어 상큼한 맛을 살리고 나트륨 배출을 도왔다.\",\"instructions\":[\"1. 감자, 양파, 당근, 피망은 볶음밥에\\n넣을 분량은 잘게 다지고, 카레에\\n넣을 분량은 한입 크기로 썬다.\",\"2. 닭가슴살도 한입 크기로 잘라\\n후춧가루로 밑간한다.\",\"3. 팬에 식용유(15g)를 두른 뒤 잘게\\n다진 감자, 양파, 당근, 피망을 넣고\\n볶다가 밥을 넣고 같이 볶는다.\",\"4. 식용유(15g)를 두른 팬에 닭고기를\\n먼저 볶다가 한입 크기로 썬 감자,\\n당근, 양파, 피망, 브로콜리를 넣고\\n볶은 뒤 마지막에 방울토마토를\\n넣는다.\",\"5. 토마토페이스트을 넣고 볶다가\\n파프리카가루를 넣어 향을 낸다.\",\"6. 카레가루를 푼 물(300g)을 부어\\n끓이다가 플레인 요구르트를 넣고\\n농도를 맞춘 뒤 밥 위에 얹어\\n마무리한다.\"]},{\"id\":\"k158\",\"title\":\"구운주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00221_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00221_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 현미(100g)\",\"톳(30g)\",\"생김(5g)\",\"달걀(50g)\",\"밥 밑간 참기름(4g)\",\"참깨(2g)\",\"톳 무침양념 설탕(2g)\",\"식초(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"조미김 대신 생김을 사용해 염분 섭취를 줄였다.\",\"instructions\":[\"1. 현미로 밥을 지은 뒤 밥 밑간을 넣고\\n섞는다.\",\"2. 톳에 톳 무침양념을 넣고 버무린다.\",\"3. 밥에 톳을 넣고 버무린다.\",\"4. 밥을 먹기 좋은 크기로 둥글게 뭉친\\n뒤 부순 생김을 골고루 묻힌다.\",\"5. 주먹밥에 달걀물을 입힌 뒤 팬에\\n구워 마무리한다.\"]},{\"id\":\"k159\",\"title\":\"깐풍주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00222_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00222_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 칵테일새우(10g)\",\"다진 쇠고기(15g)\",\"후춧가루(1g)\",\"참기름(7g)\",\"찹쌀현미밥(200g)\",\"밀가루(30g)\",\"파인애플(10g)\",\"부추(10g)\",\"소스 다진 마늘(4g)\",\"다진 붉은 고추(7g)\",\"다진 풋고추(7g)\",\"식초(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 새콤한 소스로 맛을 내어 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 칵테일새우는 잘게 다진다.\",\"2. 다진 쇠고기에 후춧가루와\\n참기름(3g)으로 밑간한 후 볶는다.\",\"3. 찹쌀현미밥에 참기름(4g)을 넣어\\n밑간하고 식힌 후 새우와 쇠고기를\\n넣어 뭉쳐준다.\",\"4. 마늘과 고추는 볶다가 식초와\\n함초가루, 설탕, 물(30g)을 넣고 졸여\\n소스를 만든다.\",\"5. 밀가루는 반죽한 뒤 얇게 밀어\\n삼각형으로 잘라 튀긴 후 기름을\\n뺀다.\",\"6. 위에 주먹밥을 올리고 파인애플을\\n올린 후 소스를 곁들여 마무리한다.\"]},{\"id\":\"k160\",\"title\":\"닭봉주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00223_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00223_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 닭봉(80g)\",\"우유(20g)\",\"단호박(10g)\",\"새송이버섯(5g)\",\"가지(15g)\",\"주키니호박(15g)\",\"당근(15g)\",\"양파(10g)\",\"시래기(20g)\",\"치즈(20g)\",\"밥(150g)\",\"새싹채소(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 염분이 높은 간장 대신 고소한 참깨와 상큼한 레몬즙,\\n달콤한 꿀을 넣어 상큼하고 달콤한 맛으로 짠맛을 대체했다.\",\"instructions\":[\"1. 닭봉은 손질한 뒤 후춧가루를\\n섞은 우유에 담가두었다가 구워\\n준비한다.\",\"2. 단호박, 새송이버섯은 구워서\\n준비한다.\",\"3. 소스를 만든다.\",\"4. 가지, 주키니호박, 당근, 양파,\\n시래기는 잘게 다진 뒤 볶는다.\",\"5. 볶은 채소와 치즈를 참기름, 간장과\\n함께 밥에 넣고 섞는다.\",\"6. 구운 닭봉을 밥으로 감싼 뒤 구운\\n단호박, 새송이버섯, 새싹채소와\\n함께 담아 소스를 곁들여\\n마무리한다.\"]},{\"id\":\"k161\",\"title\":\"봄주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20160318/20160318051200_1458288720482.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/774-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/774-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/774-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/774-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/774-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/774-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 1인분 봄동 10g\",\"깻잎 6g\",\"낙지다리 6g\",\"참기름 3g 두릎 8g\",\"올리브유 4g\",\"미나리 3g 주먹밥 데친꼬막살 12g\",\"올리브유 4g\",\"밥 100g\",\"참깨 3g 두부강된장 참기름 10g\",\"다진양파 14g\",\"다진당근 14g\",\"다진애호박 14g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"주먹밥에 소스를 넣지 않고 찍어 먹을 수 있도록 하여 나트륨 섭취를 줄일 수 있다. 또한 강된장에 두부를 넣어 나트륨 함량을 줄였다.\",\"instructions\":[\"1. 봄동과 깻잎은 데친 뒤 체에 밭쳐 물기를 제거한다.\",\"2. 데친 꼬막살은 물기를 제거하고 다져 올리브유로 양념한 밥에 참께와 함께 버무린 후 한입 크기로 주먹밥을 만든다.\",\"3. 낙지 다리는 데처 찬물에 담가 식힌 뒤 참기름(3g)에 양념하고, 두릅은 데쳐 물기를 제거한 뒤 올리브유로 양념한다.\",\"4. 봄동에 꼬막밥을 넣고 만 뒤 껫잎으로 싸고 데친 미나리로 묶어 봄주먹밥을 만든다.\",\"5. 냄비에 참기름을 두르고 양파, 당근, 애호박을 볶은 뒤 물, 된장, 고춧가루, 다진마늘, 붉은고추, 청양고추, 두부를 넣고 조려 두부강된장을 만든다.\",\"6. 봄주먹밥에 낙지와 두릅, 두부강된장을 곁들여 마무리한다.\"]},{\"id\":\"k162\",\"title\":\"깻잎장아찌롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20160603/20160603011759_1464927479016.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/776-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/776-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/776-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/776-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/776-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/776-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(200g)\",\"깻잎장아찌(30g)\",\"김(5g)\",\"새싹(20g)\",\"밥 밑간 참기름(5g)\",\"참깨(3g)\",\"허브타르타르드레싱 양파(20g)\",\"피클(20g)\",\"삶은달걀(60g)\",\"마요네즈(20g)\",\"머스터드소스 설탕(3g)\",\"물(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"삶은 달걀과 양파로 속을 만들어 밥과 깻잎장아찌로 롤을 만들어 나트륨을 줄인 일품요리\",\"instructions\":[\"1. 쌀을 씻어 밥을 지은 뒤 밥 밑간을 한다.\",\"2. 양파, 피클, 삶은 달걀은 다진 뒤 마요네즈에 섞어 허브타르타르드레싱을 만든다.\",\"3. 김 위에 밥을 펴고 허브타르타르드레싱을 위에 올리 후 만다.\",\"4. 깻잎장아찌를 바닥에 깔고 말아놓은 롤을 올린 후 한 번 더 만다.\",\"5. 머스트드소스를 만든다.\",\"6. 한입 크기로 롤을 썬 뒤 새싹과 소스를 곁들여 마무리한다.\"]},{\"id\":\"k163\",\"title\":\"참치비빔밥롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00226_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00226_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 멥쌀(60g)\",\"완두콩(30g)\",\"달걀(80g)\",\"주키니호박(15g)\",\"당근(15g)\",\"가지(15g)\",\"참치(25g)\",\"김밥용 김(2g)\",\"케일(3g)\",\"참치밑간 후춧가루(3g)\",\"올리브유(5g)\",\"사과드레싱 식초(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토소스와 사과드레싱으로 맛을 내 소금간을 줄이고 나트륨 함량을 낮췄다.\",\"instructions\":[\"1. 쌀을 물에 불린 뒤 완두콩을 함께\\n넣고 밥을 짓는다.\",\"2. 달걀을 풀어 체에 내린 뒤 지단을\\n부치면서 반 정도 익었을 때 그 위에\\n얇게 썬 주키니호박, 당근, 가지를\\n올려 익힌다.\",\"3. 참치를 참치밑간에 재운 뒤 겉만\\n살짝 익힌다.\",\"4. 김에 밥을 올리고, 뒤집어 참치를\\n올려 만 뒤 그 위에 지단을 올려\\n한 번 더 만다.\",\"5. 사과드레싱을 만들고,\\n토마토소스 재료를 간 뒤 체에\\n거른다.\",\"6. 참치비빔밥롤을 담은 뒤\\n토마토소스를 곁들이고, 케일에\\n사과드레싱을 뿌려 마무리한다.\"]},{\"id\":\"k164\",\"title\":\"새싹참치김밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00227_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00227_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 파프리카(15g)\",\"파인애플(15g)\",\"달걀(30g)\",\"김(2g)\",\"밥(150g)\",\"새싹채소(10g)\",\"참치(12g)\",\"소스 저염간장(5g)\",\"마요네즈(2.5g)\",\"설탕(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"보통 김밥에 들어가는 햄이나 어묵 등을 대신해\\n새싹채소와 파프리카 등 채소를 속재료로 사용해 나트륨 함량을 낮췄다.\\n또한 파인애플로 달콤한 맛을 내 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 소스를 만든다.\",\"2. 파프리카와 파인애플을 먹기 좋게\\n썬다.\",\"3. 스크램블 에그를 만든다.\",\"4. 김발 위에 ⅔크기로 자른 김을 놓고\\n밥을 고루 편 뒤 새싹채소,\\n스크램블 에그, 파프리카, 기름 뺀\\n참치, 파인애플을 올리고 소스를\\n고르게 뿌린다.\",\"5. 반으로 접어 먹기 좋게 썰어\\n마무리한다.\"]},{\"id\":\"k165\",\"title\":\"연어주먹밥튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00228_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00228_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 당근(30g)\",\"피망(30g)\",\"양파(30g)\",\"밥(100g)\",\"마요네즈(20g)\",\"통조림 연어(1캔=130g)\",\"식초(10g)\",\"데리야키소스(15g)\",\"달걀(40g)\",\"빵가루(60g)\",\"어린잎채소(50g)\",\"오리엔탈소스 식초(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연어를 식초물에 데쳐 염분을 최대한 제거해 나트륨 섭취량을 줄였다\",\"instructions\":[\"1. 당근, 피망, 양파를 잘게 다진 뒤\\n기름에 살짝 볶아 밥에\\n마요네즈(10g)와 함께 넣어 섞는다.\",\"2. 통조림 연어는 기름기를 빼고,\\n식초를 넣은 끓는 물에서 30초 정도\\n데친다.\",\"3. 데리야키소스와 마요네즈(10g)에\\n연어를 넣고 버무려 양념한다.\",\"4. 밥을 동그랗게 빚은 뒤 가운데에\\n연어를 넣고 주먹밥을 만든다.\",\"5. 달걀물과 빵가루를 입혀 160℃로\\n예열한 기름에 바삭하게 튀긴다.\",\"6. 연어주먹밥튀김을 담고\\n어린잎채소를 곁들인 뒤\\n오리엔탈소스를 곁들여 마무리한다.\"]},{\"id\":\"k166\",\"title\":\"오징어불고기김밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00229_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00229_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 오징어 몸통(130g)\",\"파프리카(30g)\",\"당근(20g)\",\"피망(30g)\",\"밥(200g)\",\"채 썬 쇠고기(우둔살\",\"60g)\",\"달걀(50g)\",\"김(2g)\",\"깻잎(20g)\",\"새송이버섯(30g)\",\"양념 참기름(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염고추장과 매실청을 사용한 소스로 달콤한 맛을 내 나트륨 함량을 줄였다\",\"instructions\":[\"1. 오징어 몸통 안쪽에 칼집을 내고\\n끓는 물에 데친다.\",\"2. 파프리카와 당근, 피망은 작게 다져\\n볶은 뒤 밥에 넣어 섞는다.\",\"3. 쇠고기는 참기름에 볶는다.\",\"4. 달걀을 풀어 약한 불로 달군 팬에\\n부은 뒤 김가루를 뿌려 지단을\\n부치고, 바닥이 익으면 깻잎과\\n밥을 올린다.\",\"5. 데친 오징어, 볶은 쇠고기 순으로\\n올려 만 뒤 랩으로 싼다.\",\"6. 고추장과 매실청을 섞은 뒤 팬에\\n넣고 약한 불에서 끓여 소스를\\n만들고 한입 크기로 썬 김밥에\\n구운 버섯을 함께 곁들여\\n마무리한다.\"]},{\"id\":\"k167\",\"title\":\"닭가슴살청포묵비빔밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00230_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00230_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 닭가슴살(40g)\",\"양배추(10g)\",\"청포묵(30g)\",\"숙주(30g)\",\"쌀(80g)\",\"달걀지단(20g)\",\"무순(5g)\",\"닭고기 삶는 재료 된장(3g)\",\"마늘(5g)\",\"후춧가루(0.1g)\",\"소금(0.1g)\",\"비빔소스 저염간장(4g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭가슴살은 삶아 염분을 제거하고, 청포묵에도 따로 간을 하지 않고\\n저염간장으로 만든 소스를 곁들여 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 닭고기 삶는 재료를 물(100g)에 넣어\\n끓이다가 닭가슴살을 넣고 삶아\\n한입 크기로 썬다.\",\"2. 양배추는 곱게 채 썰고, 청포묵은\\n먹기 좋은 크기로 썬다.\",\"3. 숙주는 끓는 물에 데쳐 물기를 뺀다\",\"4. 비빔소스를 만든다.\",\"5. 쌀에 물을 붓고 밥을 짓는다.\",\"6. 밥 위에 닭가슴살, 양배추, 청포묵,\\n숙주, 달걀지단, 무순을 담아\\n마무리한다.\"]},{\"id\":\"k168\",\"title\":\"족발수육\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00325_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00325_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00325_1.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 양념족발 200g\",\"고구마 150g\",\"가지 150g\",\"맥주 400g\",\"백김치 50g\",\"●백김치 무침양념 : 참기름 15g\",\"통깨 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"백김치를 물에 헹궈 양념을 제거하여 짠맛을 줄였다.\",\"instructions\":[\"1. 조미된 족발은 뜨거운 맥주에 데쳐내 기름기를\\n제거한다.\",\"2. 고구마는 편으로 썰어 냉수에 헹궈 기름\\n없는 팬에 구워준다.\",\"3. 가지는 편으로 썰어서 수분을 제거한다.\",\"4. 가지는 편으로 썰어 살짝 구워준다.\",\"5. 백김치는 물에 헹궈서 손으로 꼭 짠 후 송송\\n썰어서 양념을 해 무쳐준다.\",\"6. 무쳐준 김치와 함께 구워진 채소와 족발수육을\\n담아 완성한다.\"]},{\"id\":\"k169\",\"title\":\"함초떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00326_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00326_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"갈은 소고기 150g\",\"갈은 돼지고기 150g\",\"당근 25g\",\"새송이버섯 20g\",\"함초 30g\",\"양파 25g\",\"샐러리 10g\",\"대파 10g\",\"다진마늘 10g\",\"참기름 15g\",\"통깨 5g\",\"함초소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 자연식품인 함초를 사용하여 함초 특유의 맛과 향미로 짠맛을 대체하였다.\",\"instructions\":[\"1. 함초는 송송 다져준다.\",\"2. 당근, 새송이, 샐러리, 양파를 송송 다져준다.\",\"3. 볼에 소고기, 돼지고기, 다져 놓은 채소와\\n다진마늘, 다진대파, 참기름을 넣고 반죽해준다.\",\"4. 여기에 함초 다진 것을 넣고 다시 반죽해 준다.\",\"5. 떡갈비 모양으로 만들어준 후 팬에 노릇하게\\n구워준다.\",\"6. 소스를 만들어 구워진 떡갈비를 졸여준다.\"]},{\"id\":\"k170\",\"title\":\"삼색소면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00327_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00327_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"3가지색 소면(분홍\",\"초록\",\"흰색) 각 25g씩\",\"쪽파 20g\",\"청고추 20g\",\"홍고추 15g\",\"마늘 10g\",\"국물 : 다시마물 400g\",\"모시조개 200g\",\"볶은소금 1g\",\"청주 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마와 모시조개를 이용하여 천연육수를 만들어 감칠맛을 높였다.\",\"instructions\":[\"1. 모시조개는 볶은소금을 넣어서 해감시킨다.\",\"2. 준비된 다시마물에 준비된 채소의 국물재료를\\n넣고 국물을 만들어준다.\",\"3. 만들어진 국물에 모시조개를 넣고 청주를\\n부어서 국물을 만들어준다.\",\"4. 쪽파는 송송 다지고 마늘은 곱게 다져주고\\n청홍고추는 가늘게 채 썰어준다.\",\"5. 면을 각각 삶아준다.\",\"6. 삼색 면을 그릇에 담고 만들어진 국물을\\n부워서 완성한다.\"]},{\"id\":\"k171\",\"title\":\"돼지수육맑은전골\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00328_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00328_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통삼겹 250g\",\"된장 10g\",\"통후추 2g\",\"다진대파 5g\",\"팽이버섯 10g\",\"당근 20g\",\"배추 30g\",\"청경채 20g\",\"애호박 25g\",\"숙주 25g\",\"청양고추 20g\",\"육수 : 천연다시다 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"국물을 내는 육수는 천연재료를, 곁들이장은 어간장을 사용하여 일반간장, 소금을 대체하여 나트륨 함량을 줄였다.\",\"instructions\":[\"1. 당근, 청경채, 배추, 애호박, 팽이버섯은 먹기\\n좋은 크기로 잘라준다.\",\"2. 흑돼지고기, 저염된장, 후추를 넣어서 불순물을\\n제거하면서 고기를 삶아준다.\",\"3. 천연다시다로 육수를 만들어 체에 걸러준다.\",\"4. 손질한 야채들과 청양고추를 잘라 함께 육수에\\n데쳐 국물에 매운 맛을 낸다.\",\"5. 곁들이장을 만들어 준다.\",\"6. 냄비에 데쳐준 채소와 국물을 붓고 고기를\\n먹기좋게 썰어 소스랑 완성한다.\"]},{\"id\":\"k172\",\"title\":\"채소비빔밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00329_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00329_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 150g\",\"바지락 100g\",\"다진쇠고기 25g\",\"물 300g\",\"참기름 15g\",\"흰후추 1g\",\"다진마늘 15g\",\"애호박 25g\",\"양파 25g\",\"오이 25g\",\"당근 25g\",\"표고 25g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부볶음에 특유의 향과 맛을 내는 함초, 깻잎, 양파, 계란을 넣어 추가장을 하지 않고 맛있는 맛을 낸다.\",\"instructions\":[\"1. 바지락은 해감을 시켜준 후 물에 넣어 바지락\\n육수를 만들어준다.\",\"2. 바지락살은 따로 떼어내어 다진소고기와\\n다시 다져서 양념해 볶아준다.\",\"3. 두부는 물기제거를 한 후 함초, 깻잎, 다진양파,\\n를 넣어 치대어 두부볶음을 만들어준다.\",\"4. 애호박은 채 썰어주고 양파, 오이, 당근, 표고도\\n채 썰어 각각 볶아준다.\",\"5. 볶은 바지락과 쌀을 넣어 밥을 한다.\",\"6. 몰드에 밥과 각종 채소들을 올려주고 마지막에\\n두부 스크램블을 올려 밥을 완성한다.\"]},{\"id\":\"k173\",\"title\":\"열무김치파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00330_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00330_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"파스타면 50g\",\"열무김치 100g\",\"오이 20g\",\"청홍고추 각각 15g\",\"노란 파프리카 30g\",\"양파 30g\",\"당근 25g\",\"생들기름 30g\",\"통깨 2g\",\"청양고추 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"특별한 간을 하지 않고 청양고추의 매운 맛과 열무김치의 시큼하고 시원한 맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 뜨거운 물에 파스타면을 삶아낸 뒤 물기를\\n빼준다.\",\"2. 송송 썬 청양고추를 생들기름에 볶아주다\\n면을 볶는다.\",\"3. 볶아준 청양고추에 삶아진 면을 볶아준다.\",\"4. 열무김치는 송송 썰어서 들기름에 살짝\\n볶아준다.\",\"5. 오이는 돌려깎기 해서 채 썰어주고 청고추,\\n2가지색 파프리카, 당근도 채 썰어 각각 볶아\\n준다.\",\"6. 청양고추에 볶아진 파스타면을 볶은 채소와\\n한 번 더 볶아 완성한다.\"]},{\"id\":\"k174\",\"title\":\"해초갈비찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00331_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00331_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찜갈비 200g\",\"마른미역줄기 10g\",\"감자 20g\",\"양파 25g\",\"청고추 15g\",\"홍고추 15g\",\"대추 4g\",\"당근 20g\",\"메추리알 25g\",\"양념장 : 맛간장 30g\",\"다진마늘 5g\",\"다진대파 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"기존 갈비찜은 만들 때 양념장과 생고기를 같이 넣어 간을 속까지 넣어주는데, 미리 생고기와 생강청을 넣고 익혀\\n고기의 맛을 좋게 하고 양념장의 간을 적게 한다.\",\"instructions\":[\"1. 갈비는 핏물을 빼주고 뜨거운 물에 80% 이상\\n데쳐준 뒤 갈비와 감자를 물을 자작하게 넣고\\n청주, 생강청을 넣고 푹 삶아준다.\",\"2. 양파, 청고추, 홍고추는 먹기 좋게 썰어준다.\",\"3. 마른미역줄기는 냉수에 행군 뒤 물기를 빼준다.\",\"4. 양념장을 바글바글 끓여준다.\",\"5. 끓고 있는 양념장에 삶아진 갈비, 감자, 당근\\n순으로 끓이다 메추리알을 넣고 졸여준다.\",\"6. 마지막에 미역줄기를 넣고 볶아주는 형식으로\\n갈비찜을 완성한다.\"]},{\"id\":\"k175\",\"title\":\"버섯곤드레밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00332_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00332_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 100g\",\"건곤드레 10g\",\"느타리버섯 20g\",\"참기름 15g\",\"비빔장 : 두부 50g\",\"된장 15g\",\"다진청고추 5g\",\"다진홍고추 5g\",\"다진마늘 2g\",\"다진대파 2g\",\"참기름 15g\",\"통깨 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장을 만들때 된장의 양을 줄이기 위해 두부를 사용해서 고소함을 더해주었고,\\n버섯을 이용해 씹는 맛을 살려 식감과 맛을 높여주었다.\",\"instructions\":[\"1. 곤드레는 뜨거운 물에 데쳐낸 뒤 깨끗하게\\n헹구고 송송 썰어준다.\",\"2. 두부의 물기를 짜 준다.\",\"3. 양념장 재료와 물기를 짠 두부로 양념장을\\n만들어준다.\",\"4. 느타리버섯은 뜨거운 물에 데쳐낸 후 수분을\\n빼 가늘게 찢어준다.\",\"5. 냄비에 참기름을 두르고 곤드레를 볶다가 쌀을\\n넣고 밥을 해준다.\",\"6. 뜸을 들일 때 느타리버섯을 올려주어 밥을\\n완성한다.\"]},{\"id\":\"k176\",\"title\":\"바다향이 풍부한 전복죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00333_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00333_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"전복 100g\",\"당근 15g\",\"건조미역 10g\",\"찹쌀 50g\",\"흑임자 3g\",\"참기름 15g\",\"청주 15g\",\"흰후추 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"참기름을 이용해 내장을 볶아 고소한 맛을 충분히 내주었고, 미역과 당근으로 씹는 맛을 주어\\n짜지 않으면서 식감과 풍미를 높여주었다.\",\"instructions\":[\"1. 찹쌀은 불려주고 전복은 손질해 내장과 분리해\\n준 뒤 청주를 넣어서 전복 내장을 믹서에\\n갈아준다.\",\"2. 전복 몸에 칼집을 내준 후 참기름을 두른 팬에\\n구워준다.\",\"3. 당근과 미역은 송송 잘라준다.\",\"4. 전복내장을 먼저 참기름에 충분히 볶아준다.\",\"5. 내장을 볶아주다가 불린 찹쌀을 넣고 충분히\\n볶아준다.\",\"6. 죽이 완성될 때 당근, 미역을 넣고 죽을 끓여\\n주고 전복은 고명으로 올려준다.\"]},{\"id\":\"k177\",\"title\":\"주꾸미연포탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00334_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00334_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미 200g\",\"무 30g\",\"양파 50g\",\"대파 20g\",\"미나리 20g\",\"단호박 25g\",\"청고추 25g\",\"국물 : 해물육수 400g\",\"청양고추 20g\",\"마늘 10g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"주꾸미와 무, 호박을 이용해 국물의 시원함을 살리고, 청양고추의 매콤한 맛으로 나트륨을 줄여주었다.\",\"instructions\":[\"1. 주꾸미는 세척해 물기를 빼준다.\",\"2. 무와 단호박은 먹기 좋게 썰어준다.\",\"3. 청고추, 미나리, 양파를 먹기 좋게 썰어준다.\",\"4. 청양 고추를 어슷하게 썰고 마늘은 편으로 썰어\\n국물을 끓여준다.\",\"5. 국물이 만들어지면 무, 단호박을 넣고 끓여준다.\",\"6. 국물에 대파를 넣어주고 모든 재료를 넣어\\n완성한다.\"]},{\"id\":\"k178\",\"title\":\"함초소고기말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00335_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00335_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기구이용 150g\",\"알마늘 20g\",\"홍고추 15g\",\"양파 60g\",\"함초 30g\",\"무순 2g\",\"노란색파프리카 25g\",\"소스 : 마늘기름 15g\",\"맛간장 15g\",\"허브식초 15g\",\"연겨자 10g\",\"버섯마늘소금 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소고기의 잡냄새를 마늘기름으로 잡아주어 기본 간을 해주지 않아도 잡냄새를 잡을 수 있다.\\n또 함초의 씹는 맛과 짭짤한 맛이 짠맛을 대체하였다.\",\"instructions\":[\"1. 파프라카, 양파, 홍고추는 가늘게 채 썰어준다.\",\"2. 함초는 세척 후 먹기 좋게 손질해 준다.\",\"3. 무순을 물 속에 담가준다.\",\"4. 편으로 썰어준 소고기에 채 썰어준 채소와\\n함초를 꼭 싸 말아준다.\",\"5. 마늘은 편으 로 썰 어 마늘기름에 한 번\\n구워준다.\",\"6. 구운 마늘을 깔고 말아준 고기를 굽는다.\"]},{\"id\":\"k179\",\"title\":\"묵계밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00336_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00336_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"도토리묵\",\"올방개묵\",\"검정깨묵 각각 25g\",\"귀리밥 150g\",\"계란 55g\",\"콩나물 30g\",\"국물 : 닭가슴살 70g\",\"마늘 10g\",\"대파 10g\",\"양파 15g\",\"맛간장 15g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"천연 재료로 만든 버섯마늘소금으로 구수하고 맛있는 국물을 내서 나트륨을 줄일 수 있고,\\n집에서 만든 맛간장을 이용해 감칠맛을 높여서 나트륨을 줄였다.\",\"instructions\":[\"1. 닭가슴살을 이용해 국물을 만든다.\",\"2. 닭가슴살은 먹기 좋게 찢어 흰 후추, 버섯마늘\\n소금으로 밑간을 해준다.\",\"3. 콩나물은 머리를 떼어내고 데쳐준다.\",\"4. 계란은 황백지단으로 부친 후 채 썰어준다.\",\"5. 3종류의 묵은 먹기 좋은 크기로 썰어준다.\",\"6. 그릇에 밥을 담고 콩나물을 올리고 3종류의\\n묵을 올린 후 계란으로 고명해 완성한다.\"]},{\"id\":\"k180\",\"title\":\"근채류주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00337_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00337_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"우엉 20g\",\"연근 20g\",\"감자 20g\",\"청고추 10g\",\"양파 10g\",\"당근 10g\",\"쌀 100g\",\"오이 70g\",\"통깨 1g\",\"맛간장 15g\",\"참기름 5g\",\"마늘기름 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"향이 있는 우엉과 맛간장을 사용해 맛을 냈고 다양한 채소를 이용해 씹는 맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 쌀을 깨끗하게 씻은 후에 쌀뜨물은 따로\\n보관하고 불려준 쌀로 밥을 해주고 접시에\\n펼쳐 식혀준다.\",\"2. 우엉과 연근, 감자는 송송 다져준 후 아린 맛을\\n빼기위해 물에 담가준다.\",\"3. 우엉과 연근, 감자는 물기를 빼고 볶아준다.\",\"4. 청고추, 양파, 당근은 송송 다져서 함께\\n볶아준 뒤, 함초 소금을 이용해 1차 간을\\n해준다.\",\"5. 그 릇 에 모 든 재 료 를 넣 고 오 니 기 리 를\\n만들어준다.\",\"6. 그릇에 담아 완성한다.\"]},{\"id\":\"k181\",\"title\":\"단호박약식\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00338_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00338_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"미니 단호박 250g\",\"찹쌀 100g\",\"밤 40g\",\"대추 18g\",\"크린베리 10g\",\"양념장 : 맛간장 15g\",\"참기름 10g\",\"계피가루 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박을 이용해 단맛을 높이고 일반 간장 대신 맛간장과 계피가루를 넣어 짜지 않게 약식을 만들었다.\",\"instructions\":[\"1. 단 호박은 속을 파 준다.\",\"2. 찹쌀은 물에 불려준다.\",\"3. 밤은 먹기 좋게 잘라서 물에 담가준다.\",\"4. 대추는 씨를 제거하고 먹기 좋게 잘라준다.\",\"5. 양념장을 만들어 먼저 쌀과 밤을 재워준 후\\n찰밥을 만든다.\",\"6. 단호박 속에 찰밥을 넣어서 찜기에 쪄준다.\"]},{\"id\":\"k182\",\"title\":\"달콤스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00339_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00339_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소 채끝살 200g\",\"감자 70g\",\"시금치 25g\",\"당근 30g\",\"소스 : 레드와인 200cc. 망고 50g\",\"딸기잼 30g\",\"볶은소금 0.5g\",\"후추 2g\",\"무염버터 5g\",\"설탕 10g\",\"레몬즙 5g\",\"다진양파 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"레드와인과 망고를 이용해 새콤달콤한 소스를 만들어 소스의 짠맛을 대체하였다.\",\"instructions\":[\"1. 망고는 손질 후 버터로 살짝 볶고 레드와인을\\n넣고 졸이다가 믹서로 갈아주고 딸기잼으로\\n간과 농도를 맞추어 레드와인 소스를 만든다.\",\"2. 소 채끝살은 손질 후 만들어진 레드와인 소스에\\n마리네이드 해준다.\",\"3. 감자는 껍질을 제거 후 먹기 좋은 크기로 잘라서\\n뜨거운 물에 데쳐내 버터에 볶아준다. 당근은\\n먹기좋은 크기로 잘라 뜨거운 물에 데쳐 버터\\n에 볶아주고, 시금치도 데친 후 수분을 제거하\\n고 버터에 볶는다.\",\"4. 마리네이드 한 고기를 구워준다.\",\"5. 마리네이드 하고 남은 망고소스를 다시 팬에\\n졸여 소스를 만든다.\",\"6. 접시에 준비된 채소와 안심을 담고 소스를\\n뿌려 완성한다.\"]},{\"id\":\"k183\",\"title\":\"삼색샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00441_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00441_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"식빵(100g)\",\"토마토(20g)\",\"어린이치즈(20g)\",\"양상추(30g)\",\"감자(30g)\",\"올리고당(20g)\",\"달걀(60g)\",\"당근(20g)\",\"오이(20g)\",\"양파(20g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"여러 가지 채소와 감자를 곁들여 나트륨을 적게 사용해도 좋은 맛을 충분히 느낄 수 있어요.\",\"instructions\":[\"1. 식빵은 가장 자리를 잘라 밀대를 이용\\n하여 얇게 밀어 준비한다.\",\"2. 감자는 삶은 뒤 곱게 으깨어 올리고당을\\n넣고 골고루 섞는다.\",\"3. 달걀은 약 13분 정도 삶아 껍질을\\n벗기고, 반으로 갈라 썰어놓는다.\",\"4. 당근과 양파 오이도 얇게 썰어놓는다.\",\"5. 토마토는 포를 떠서 준비한다.\",\"6. 으깬 감자(②)에 준비한 달걀(③)과\\n채소(④)를 넣고 소금을 약간 넣은 뒤\\n골고루 섞어, 밀어 놓은 식빵에 토마토,\\n치즈, 양상추와 함께 넣어 돌돌 말아\\n완성한다.\"]},{\"id\":\"k184\",\"title\":\"황태탕수육\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00442_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00442_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"황태채(100g)\",\"밀가루(30g)\",\"찹쌀가루(10g)\",\"녹말가루(10g)\",\"삼색분말(각 10g)\",\"달걀(50g)\",\"튀김기름(200g)\",\"- 소스 : 파프리카(30g)\",\"양파(30g)\",\"당근(30g)\",\"오이(30g)\",\"파인애플(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기가 아닌 황태를 이용하여 탕수육을 만들기 때문에 나트륨을 감소시킬 수 있어요.\",\"instructions\":[\"1. 황태는 가위로 약 3cm 길이로 잘라\\n스프레이로 물기를 준다.\",\"2. 밀가루를 세 군데로 나눠 각각 찹쌀\\n가루와 녹말가루, 삼색 가루를 넣어\\n세 가지의 색을 만든다.\",\"3. 만들어 놓은 밀가루에 달걀을 넣어\\n골고루 섞는다.\",\"4. 튀김 반죽(③)에 황태(①)를 넣어\\n섞은 후, 튀김 기름 170℃ 의 온도에서\\n약 1분 정도 튀겨 기름을 빼 놓는다.\",\"5. 파프리카는 속씨를 제거하고, 양파와\\n당근, 오이, 파인애플과 함께 썰어 준비\\n한다.\",\"6. 저염간장에 설탕과 식초를 넣어 골고루\\n섞은 후 냄비에서 바글바글 끓이다가\\n물녹말을 넣고, 썰어놓은 채소를 넣어\\n한 번 더 끓인 후 황태 탕수육(④)에\\n곁들여 완성한다.\"]},{\"id\":\"k185\",\"title\":\"밥핫도그\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00443_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00443_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소시지(100g)\",\"나무막대기(5개)\",\"밀가루(30g)\",\"달걀(50g)\",\"빵가루(30g)\",\"튀김기름(200g)\",\"파프리카(30g)\",\"밥(50g)\",\"감자(50g)\",\"달걀흰자(10g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밀가루 반죽대신 감자, 밥, 파프리카을 이용하여 나트륨은 줄이고, 어린이들의 영양 간식으로도 좋아요.\",\"instructions\":[\"1. 소시지는 먹기 좋은 크기로 썰어 나무\\n막대기에 꽂아놓는다.\",\"2. 파프리카는 작게 다져 준비한다.\",\"3. 으깬 감자를 준비된 밥과 함께 골고루\\n섞는다.\",\"4. 으깬 감자를 다시 준비된 밥과 함께\\n소금을 조금 넣고 골고루 섞는다.\",\"5. 밥과 감자가 잘 섞어지면, 다시 다져진\\n파프리카를 넣고 섞어준다.\",\"6. 막대기에 밀가루를 살짝 바르고, 소시\\n지에 반죽(⑤)을 감싸듯 손으로 둥글게\\n말아 밀가루와, 달걀물, 빵가루 순서로\\n입혀 튀김 기름 170℃의 온도에서\\n약 2분 정도 튀긴 후 기름을 제거하여\\n완성한다.\"]},{\"id\":\"k186\",\"title\":\"스테이크카나페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00444_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00444_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소등심(100g)\",\"소금(0.3g)\",\"후춧가루(0.03g)\",\"로즈마리(0.5g)\",\"애호박(20g)\",\"양파(20g)\",\"가지(20g)\",\"파프리카(20g)\",\"토마토(20g)\",\"- 소스 : 발사믹소스(20g)\",\"설탕(10g)\",\"마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새콤달콤한 소스는 나트륨 사용을 줄이고 맛의 풍미를 높여줘요.\",\"instructions\":[\"1. 소등심은 소금과 후춧가루, 로즈마리를\\n뿌려 약 30분 이상 숙성을 시킨다.\",\"2. 애호박은 동그랗게 자르고, 양파는 형태\\n그대로 떼어내고, 가지는 직사각형으로\\n잘라 준비한다.\",\"3. 파프리카는 속을 파내고 작은 사각으로\\n자르고, 토마토는 씨를 제거하고\\n네모지게 잘라 준비해 놓는다.\",\"4. 사과는 껍질을 깨끗이 씻어 길쭉하게\\n썰어놓는다.\",\"5. 발사믹소스에 설탕과 마늘을 넣고 썰어\\n놓은 사과채를 넣어 잘 섞은 후 바글바글\\n끓여 소스를 만들어놓는다.\",\"6. 팬이 따끈해지면, 호박과 양파, 가지를\\n구워 내고, 팬에 소등심을 앞뒤로 구워\\n먹기 좋은 크기로 자른 뒤 구워 놓은\\n양파와 호박, 가지에 각각 올리고,\\n끓여놓은 소스와 파프리카, 토마토를\\n얹어 완성한다.\"]},{\"id\":\"k187\",\"title\":\"꽃밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00445_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00445_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"라이스페퍼(50g)\",\"당근(20g)\",\"달걀(30g)\",\"시금치(20g)\",\"소금(0.5g)\",\"돼지고기(50g)\",\"마늘(10g)\",\"대파(10g)\",\"맛술(10g)\",\"저염간장(20g)\",\"설탕(10g)\",\"통깨(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밥 대신 고구마와 두부를 사용하여 만든 음식으로 단백질을 높였고, 견과류를 다져 사용하여 나트륨을 감소시켰어요.\",\"instructions\":[\"1. 당근은 채를 곱게 썰어 준비한다.\",\"2. 달걀은 노란자와 흰자로 나눠 각각\\n지단을 부쳐 약 5cm 길이로 채를\\n썰어놓는다.\",\"3. 시금치는 끓는 물에 소금을 넣고 파랗게\\n데쳐 물기를 제거하고 무쳐놓는다.\",\"4. 돼지고기는 마늘, 파, 설탕, 맛술, 간장,\\n후춧가루, 통깨, 참기름을 넣고 30분간\\n숙성시킨 뒤 팬에 볶아서 준비한다.\",\"5. 고구마는 삶아 으깨고, 두부는 소창에\\n물기를 짜고, 토마토와 양파, 견과류는\\n입자있게 다져섞는다.\",\"6. 라이스 페이퍼를 따뜻한 물에 담궜\\n다가 바로 꺼내어 으깬 고구마(⑤)를\\n먼저 깔고, 그 위에 준비한 재료(②,\\n③, ④)를 올려 돌돌 말은 뒤 먹기 좋은\\n크기로 썰어 완성한다.\"]},{\"id\":\"k188\",\"title\":\"버섯만두찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00446_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00446_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀가루(100g)\",\"시금치가루(10g)\",\"호박가루(10g)\",\"백년초가루(10g)\",\"물 (40g)\",\"식용유(3g)\",\"소금(0.5g)\",\"양파(20g)\",\"양송이버섯(30g)\",\"새송이버섯(20g)\",\"표고버섯(30g)\",\"두부(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"우유와 버섯, 새우를 넣은 버섯만두찜은 칼슘과 단백질이 풍부하여, 나트륨 함량을 줄여 줄 수 있었어요.\",\"instructions\":[\"1. 밀가루를 세 개로 나눠 호박가루와\\n백년초가루, 시금치가루를 각각 넣고\\n물, 식용유, 소금을 넣어 반죽 한 후\\n비닐봉지에 담아 1~2시간 정도 숙성\\n시킨다.\",\"2. 양파, 마늘, 버섯들은 입자있게 다져\\n준비한다.\",\"3. 두부는 소창을 이용하여 물기를 짜낸다.\",\"4. 새우는 껍질과 내장을 제거하고 다져,\\n마늘을 넣고 골고루 섞어준다.\",\"5. 다진 채소(②), 으깬 두부(③), 새우\\n(④)를 넣고 섞어서 만두소를 만들어\\n준다.\",\"6. 숙성된 만두 반죽(①)을 얇게 밀어\\n꽃 모양으로 찍어 만두소(⑤)를 넣은\\n뒤, 반죽을 맞잡아 모양을 만든다.\\n우유와 생크림을 끓인 뒤 만들어 놓은\\n만두를 넣고 은근히 찜을 하듯이 익혀\\n완성한다.\"]},{\"id\":\"k189\",\"title\":\"떡갈비주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00447_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00447_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다진소고기(70g)\",\"다진돼지고기(50g)\",\"찹쌀가루(10g)\",\"밥(30g)\",\"대파(10g)\",\"후춧가루(0.02g)\",\"맛술(10g)\",\"저염간장(10g)\",\"생크림(10g)\",\"식용유(20g)\",\"새송이버섯(20g)\",\"시금치(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밥과 떡을 넣어 만든 떡갈비는 나트륨함량을 줄여주고, 씹을 때 쫄깃한 식감이 맛을 더욱 좋게 하도록 만들었어요.\",\"instructions\":[\"1. 소고기와 돼지고기에 찹쌀가루와 밥을\\n넣고 골고루 섞는다.\",\"2. 섞여진 고기(1)에 파와 후춧가루, 간장,\\n맛술, 생크림을 넣고 다시 잘 섞어 30분\\n이상 숙성을 시킨다.\",\"3. 새송이버섯은 다지고, 시금치는 뜨거운\\n물에 데쳐 물기를 제거하고 잘게 다지고,\\n당근도 다져 준비한다.\",\"4. 양파와 마늘은 다져서 볶아 준비해\\n놓는다.\",\"5. 떡볶이 떡은 뜨거운 물에 잠시 담그어\\n부드러워지면 꺼내서 잘게 다진다.\",\"6. 숙성된 고기(②)에 다진 채소(③)와 볶은\\n마늘과 양파(④), 떡볶이떡(⑤)을 넣고\\n섞이도록 치댄 후 작은 떡갈비 모양을\\n만들어 팬에 기름을 두르고, 앞뒤를 돌려\\n가며 익힌 후, 냄비에 간장과 올리고당을\\n넣고 끓이다가, 익힌 떡갈비를 넣고 자작\\n하게 졸여 완성한다.\"]},{\"id\":\"k190\",\"title\":\"홍합죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00448_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00448_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(100g)\",\"참기름(5g)\",\"홍합(50g)\",\"양파(20g)\",\"당근(20g)\",\"표고버섯(20g)\",\"건새우(15g)\",\"- 육수 : 건새우(15g)\",\"다시마(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"건 새우에 들어있는 천연 간으로 조미하여 풍미는 살리고 나트륨은 줄였어요.\",\"instructions\":[\"1. 쌀은 깨끗이 씻어 약 30분 이상 불려\\n물기를 빼고 절구에 빻아놓는다.\",\"2. 냄비에 물을 넣고, 다시마와 건새우 반을\\n넣고 끓여 간단한 육수를 만들어 놓는다.\",\"3. 건새우 반은 다져서 따로 준비하고,\\n양파와 당근은 입자있게 다지고, 버섯을\\n편으로 썰어 준비한다.\",\"4. 홍합은 끓는 물에 소금을 넣고 데쳐\\n껍질을 제거해 놓는다.\",\"5. 냄비에 참기름을 넣고 빻아 놓은 쌀을\\n넣어 은근히 볶는다.\",\"6. 볶은 쌀(⑤)에 육수(②)를 붓고\\n끓이다가 양파, 당근, 버섯(③)과\\n홍합(④)을 넣고 어우러지게 나무\\n주걱으로 저어가면 끓이다가 죽이\\n다 익을 때쯤 다져 놓은 건새우\\n(③)를 넣고 한 번 더 끓인 후 완성\\n한다.\"]},{\"id\":\"k191\",\"title\":\"샐러드돈가스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00449_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00449_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심(120g)\",\"정종(10g)\",\"소금(0.3g)\",\"후춧가루(0.02g)\",\"우유(30g)\",\"밀가루(20g)\",\"달걀(50g)\",\"빵가루(20g)\",\"튀김기름(400g)\",\"- 소스 : 삶은 달걀(50g)\",\"피클(20g)\",\"마요네즈(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양상추 샐러드와 토마토 등 채소 섭취로 인해 나트륨 배출에 도움이 되요.\",\"instructions\":[\"1. 우유에 등심을 넣어 30분간 재워 놓은\\n뒤, 후춧가루, 정종을 발라 1시간 이상\\n숙성시킨다.\",\"2. 방울토마토는 반으로 잘라 준비한다.\",\"3. 양상추는 먹기 좋은 크기로 찢어 놓는다.\",\"4. 피클은 입자 있게 다져 준비한다.\",\"5. 숙성시킨 등심(①)은 물기를 제거하고,\\n먹기 좋은 크기로 썰어 밀가루, 달걀물,\\n빵가루 순으로 입혀, 튀김 기름\\n170~180℃ 온도에 약 3분 정도 튀긴\\n후 기름을 빼 놓는다.\",\"6. 삶은 달걀은 다지고 피클(④)에\\n마요네즈를 넣어 섞어 샐러드 소스를\\n만들고, 접시에 양상추를 깔고 그 위에\\n어린잎채소, 돈가스(⑤)와 방울토마토\\n(②)를 올려 소스와 함께 완성한다.\"]},{\"id\":\"k192\",\"title\":\"조개크림파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00450_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00450_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"스파게티(100g)\",\"올리브오일(3g)\",\"소금(0.3g)\",\"양송이(20g)\",\"새우(50g)\",\"파슬리가루(0.3g)\",\"버터(20g)\",\"양파(20g)\",\"마늘(20g)\",\"밀가루(20g)\",\"육수(100g)\",\"우유(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"조개로 삶은 물을 걸러 육수로 사용하게 되면 별도의 소금간이 필요 없어요.\",\"instructions\":[\"1. 스파게티는 끓는 물에 소금을 넣고 약\\n10분 정도 삶아 건져 올리브 오일에\\n살짝 발라 준비한다.\",\"2. 양송이는 껍질을 벗겨 편으로 썰어\\n놓는다.\",\"3. 마늘과 양파는 굵게 다져놓는다.\",\"4. 조개는 끓는 물에 데쳐 해감을 씻고,\\n삶은 물을 소창에 걸러 육수를 만들어\\n놓는다.\",\"5. 냄비에 버터를 넣고, 다진 마늘과\\n양파를 넣어 볶다가 밀가루를 넣고\\n은근히 볶는다.\",\"6. 볶고 있는 채소(⑤)에 육수(④)를 부어\\n한소끔 끓인 뒤, 우유와 생크림을 넣고\\n다시 끓으면 새우와 삶은 조개를 넣고\\n살짝 끓인 후, 삶아놓은 스파게티면\\n(①)을 넣고 한 번 더 끓이고 그 위에\\n파슬리 가루를 살짝 뿌려 완성한다.\"]},{\"id\":\"k193\",\"title\":\"닭날개튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00451_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00451_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭봉(120g)\",\"오렌지(30g)\",\"레몬(20g)\",\"생강즙(10g)\",\"카레가루(30g)\",\"튀김기름(400g)\",\"- 소스 : 양파(20g)\",\"땅콩(20g)\",\"마요네즈(20g)\",\"파스리가루(0.3g)\",\"요거트(30g)\",\"- 곁들임채소 : 어린잎(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레를 입힌 닭봉은 닭의 비릿한 맛도 없애고, 닭에 별도의 소금을 넣지 않아도 맛이 좋기 때문에 나트륨 감소가 될 수 있었어요.\",\"instructions\":[\"1. 닭날개는 끝을 잘라 뒤로 뒤집어 봉을\\n만든다.\",\"2. 오렌지즙과 레몬즙을 짜서 섞어 주고,\\n생강을 갈아 소창에 걸러 즙을 낸다.\",\"3. 닭봉(①)에 생강즙, 오렌지 ․ 레몬즙\\n(②)을 발라 숙성시킨 후 다시 카레\\n가루를 입힌다.\",\"4. 땅콩은 물기 없이 입자있게 다진다.\",\"5. 양파를 입자있게 다져 다진 땅콩과\\n마요네즈, 파슬리가루, 요거트를\\n넣고 골고루 섞어 소스를 만들어\\n놓는다.\",\"6. 카레가루를 입힌 닭봉은 튀김기름\\n170~180℃ 온도에서 약 3분 정도 튀겨\\n기름을 빼고, 접시에 어린잎을 담고\\n만들어 놓은 소스와 닭봉을 함께 제공\\n하여 완성한다.\"]},{\"id\":\"k194\",\"title\":\"해산물리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00452_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00452_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"보리쌀(50g)\",\"당근(20g)\",\"양파(20g)\",\"마늘(10g)\",\"대파(10g)\",\"버터(10g)\",\"오징어(50g)\",\"새우(50g)\",\"시금치(20g)\",\"소금(0.2g)\",\"생크림(20g)\",\"우유(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해산물의 감칠맛과 보리의 고소한 맛이 어우러져 풍미를 더해줘요.\",\"instructions\":[\"1. 보리는 깨끗이 씻어 물에 약 30분 이상\\n불려 놓고, 당근, 양파, 마늘, 대파는\\n입자있게 다져 준비한다.\",\"2. 시금치는 끓는 물에 소금을 넣고 데친 후\\n생크림을 넣고 함께 갈아서 준비한다.\",\"3. 오징어는 껍질을 벗겨 안쪽에 칼집을\\n내어 새우와 함께 데치고, 조개는 해감\\n후 다시마를 넣고 삶은 뒤 소창에 걸러\\n육수를 만들어 놓는다.\",\"4. 냄비에 버터를 넣고, 다진 마늘과 양파\\n당근을 볶다가 불린 보리를 넣어 다시\\n볶는다.\",\"5. 볶아지는 냄비에 조개 삶은 육수를\\n넣어 끓인다.\",\"6. 끓여지는 냄비에 데친 조개와 해물,\\n치즈, 우유를 넣어 어우러지게 저어\\n가며 졸이듯 끓이다가 마지막에\\n시금치와 생크림 갈은 것(②)을\\n넣고 살짝 끓인 후 파슬리 가루를\\n살짝 뿌려 완성한다.\"]},{\"id\":\"k195\",\"title\":\"떡완자조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00453_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00453_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다진 쇠고기(70g)\",\"다진 돼지고기(30g)\",\"매실액(10g)\",\"맛술(10g)\",\"양파(20g)\",\"당근(20g)\",\"새송이버섯(20g)\",\"마늘(20g)\",\"대파(10g)\",\"떡볶이떡(100g)\",\"식용유(20g)\",\"저염간장(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기와 떡을 넣어 만든 완자 조림은 쫄깃한 식감을 주고, 채소를 풍성하게 먹을 수 있어 나트륨 감소를 시킬 수 있었어요.\",\"instructions\":[\"1. 소고기와 돼지고기를 섞어, 후춧가루,\\n매실액, 맛술을 넣어 재워둔다.\",\"2. 양파와 당근, 새송이, 대파는 입자있게\\n다지고 마늘은 곱게 다져 준비한다.\",\"3. 재워둔 고기(①)에 파, 마늘, 양파,\\n당근, 새송이를 넣고 골고루 섞는다.\",\"4. 떡은 잘게 썰어 뜨거운 물에 잠시\\n담그어 놓는다.\",\"5. 섞어 놓은 고기(③)에 불려 놓은 떡을\\n섞는다.\",\"6. 고기반죽(⑤)을 조금씩 떼어 둥글게\\n완자를 빚고, 팬에 기름을 둘러 굴리듯이\\n굽는다. 냄비에 간장과 올리고당을 넣고\\n끓이다가 구운 완자와 참기름을 넣어\\n은근히 졸인 뒤 통깨를 얹어 완성한다.\"]},{\"id\":\"k196\",\"title\":\"닭고기채소스파게티\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00454_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00454_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기살(100g)\",\"후춧가루(0.03g)\",\"스파게티(60g)\",\"올리브유(3g)\",\"브로컬리(20g)\",\"양송이(20g)\",\"표고버섯(20g)\",\"파프리카(20g)\",\"당근(20g)\",\"양파(20g)\",\"다진마늘(10g)\",\"토마토(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"야채와 토마토를 가득 넣어 만든 스파게티는 염분을 줄여주고 식감은 살려줘요.\",\"instructions\":[\"1. 닭살은 한 번 정도 펴서 후춧가루를\\n뿌려 사각지게 썰어 준비한다.\",\"2. 브로컬리는 살짝 데쳐 썰고, 양송이\\n버섯은 껍질을 벗겨 두툼하게 썰어\\n준비한다.\",\"3. 파프리카와 토마토는 속씨를 제거하고\\n사각으로 썰고, 당근, 양파, 표고버섯도\\n사각지게 썰어 준비한다.\",\"4. 스파게티는 끓는 물에 소금을 넣고 약\\n10분 정도 삶아 건져 올리브 오일을\\n살짝 발라 준비한다.\",\"5. 팬에 올리브 오일을 두르고, 따끈해지\\n면, 닭살을 먼저 볶는다.\",\"6. 닭고기살(⑤)에 준비한 채소(②,③)를\\n넣고 살짝 볶다가 토마토 페이스트를\\n넣어 다시 볶은 후 육수와 토마토소스,\\n케첩, 생크림을 넣고 끓인 후 삶아놓은\\n스파게티(④)를 넣고 한 번 더 끓여\\n완성한다.\"]},{\"id\":\"k197\",\"title\":\"계만두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00245_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00245_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 배추(50g)\",\"오이(50g)\",\"표고버섯(30g)\",\"피망(20g)\",\"당근(80g)\",\"녹말가루(20g)\",\"닭가슴살(150g)\",\"마늘(10g)\",\"대파(5g)\",\"삶은 메추리알(15g)\",\"양념 참기름(5g)\",\"간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨 함량이 높은 된장 대신 빠금장과 우유를 사용한 소스를 곁들여 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 배추, 오이는 얇게 채 썬 뒤 소금물에\\n담가 절인 후 물기를 꼭 짜고,\\n표고버섯은 채 썬 뒤 참기름과\\n간장을 넣어 양념하고, 피망과\\n당근은 얇게 채 썬다.\",\"2. 예열된 팬에 배추, 오이, 채 썬 피망,\\n표고버섯 순으로 센 불에서 각각\\n볶고, 당근은 물기를 제거한 뒤\\n녹말가루를 묻혀 150℃로 예열한\\n기름에 튀긴다.\",\"3. 닭가슴살은 얇게 저민 후\\n후춧가루로 밑간을 한 뒤 볶아놓은\\n채소를 올려 말아 계만두를 만든다.\",\"4. 찜기에 물과 마늘, 대파를 넣고\\n육수를 내면서 예열하다가 김이\\n오르면 말아놓은 계만두를 넣고\\n약 8분 정도 찐다.\",\"5. 빠금장에 휘핑크림과 우유, 다진\\n청양고추, 후춧가루, 참깨를 넣고\\n끓여 빠금장소스를 만든다.\",\"6. 계만두에 튀긴 당근과 삶은\\n메추리알을 곁들인 뒤 빠금장소스를\\n곁들여 마무리한다.\"]},{\"id\":\"k198\",\"title\":\"삼계선\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00246_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00246_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 닭가슴살(200g)\",\"두부(40g)\",\"수삼(10g)\",\"파프리카(20g)\",\"대추(30g)\",\"블루베리소스 블루베리잼(20g)\",\"화이트와인(20g)\",\"설탕(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"재료에 소금간을 하지 않고 블루베리잼으로 만든 소스를 곁들여 나트륨 함량을 줄였다.\\n또한 블루베리에는 칼륨이 많아 체내 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 닭가슴살을 다져서 두부와 섞어준다.\",\"2. 수삼과 파프리카를 채 썰고, 대추는\\n돌려서 깎아준다.\",\"3. 닭가슴살두부반죽을 얇게 편 후\\n파프리카, 수삼, 대추를 올린 뒤\\n풀리지 않게 종이포일로 만다.\",\"4. 김 오른 찜기에 20분간 쪄준다.\",\"5. 블루베리잼과 화이트와인을 졸인 뒤\\n설탕을 넣고 블루베리소스를 만든다.\",\"6. 쪄낸 삼계선을 2㎝두께로 잘라 담고 블루베리소스를 곁들여 마무리한다.\"]},{\"id\":\"k199\",\"title\":\"쇠고기표고찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00247_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00247_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 표고버섯(15g)\",\"밀가루(5g)\",\"달걀(30g)\",\"잣(2g)\",\"대추(1g)\",\"단호박(7g)\",\"피클(10g)\",\"소 다진 쇠고기(15g)\",\"다진 대파(1g)\",\"다진 마늘(1g)\",\"다진 양파(5g)\",\"다진 파프리카(6g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새콤달콤한 소스와 피클을 곁들여 식욕을 돋우고,\\n소금간을 따로 하지 않아 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 소를 고루 치대 반죽한다.\",\"2. 표고버섯은 밑동을 제거한 뒤\\n안쪽에 밀가루→달걀물 순서로\\n바른 뒤 반죽을 넣고 달걀물을\\n한 번 더 발라준 뒤 김 오른 찜기에\\n15분간 찐다.\",\"3. 잣과 대추를 올리고 달걀물을 한 번\\n더 바르고 3분간 더 찐다.\",\"4. 오렌지소스 재료를 팬에 넣고\\n조린다.\",\"5. 단호박은 얇게 썰어 노릇하게\\n굽는다.\",\"6. 쇠고기표고찜에 오렌지소스를\\n뿌리고 피클과 구운 단호박을\\n곁들여 마무리한다.\"]},{\"id\":\"k200\",\"title\":\"떡갈비찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00248_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00248_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00248_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00248_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00248_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00248_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00248_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 다진 돼지고기(50g)\",\"다진 쇠고기(30g)\",\"가지(10g)\",\"가래떡(60g)\",\"유자청(15g)\",\"간장(5g)\",\"연근(4g)\",\"고기 밑간 다진 파(5g)\",\"다진 마늘(5g)\",\"다진 양파(10g)\",\"소금(1g)\",\"후춧가루(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 가지를 사용해 몸속 나트륨 배출을 촉진했다.\\n또한 소금간을 적게 하면서 유자소스로 새콤한 맛을 더해 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 돼지고기와 쇠고기는 고기 밑간을\\n넣고 반죽을 만든다.\",\"2. 가지를 길고 얇게 썬다.\",\"3. 깨끗이 씻은 떡을 가지로 돌돌 말고\\n그 위에 고기를 말아 떡갈비를\\n만들고 팬에서 겉면이 노릇해질\\n때까지만 익힌 뒤 김 오른 찜기에\\n넣어 10분~15분 정도 찐다.\",\"4. 유자청과 간장을 섞고 팬에서\\n농도를 맞춰주며 살짝 졸여\\n유자소스를 만든다.\",\"5. 연근은 모양대로 얇게 썰어 기름에\\n튀겨 연근칩을 만든다.\",\"6. 떡갈비에 유자소스를 바르고\\n연근칩을 올려 마무리한다.\"]},{\"id\":\"k201\",\"title\":\"해산물두부샌드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00249_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00249_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00249_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00249_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00249_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00249_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00249_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 두부(80g)\",\"새우(20g)\",\"관자(20g)\",\"파프리카(20g)\",\"새싹채소(20g)\",\"완두콩드레싱 삶은 완두콩(30g)\",\"두유(40g)\",\"꿀(15g)\",\"검은깨(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"담백한 두부에 완두콩드레싱으로 달콤하고 부드러운 맛을 내\\n소금간을 줄여 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 두부는 두 덩어리로 잘라 넓게 편다.\",\"2. 새우, 관자, 파프리카를 함께 갈아\\n속을 만든다.\",\"3. 완두콩과 두유, 꿀, 검은깨를 섞은 뒤\\n갈아 완두콩드레싱을 만든다.\",\"4. 두부 사이에 속을 넣은 뒤 먹기 편한\\n크기로 자른다.\",\"5. 두부샌드를 김 오른 찜기에서\\n15분 정도 찐다.\",\"6. 완두콩드레싱과 새싹채소를 올려\\n마무리한다.\"]},{\"id\":\"k202\",\"title\":\"단호박제육볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00250_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00250_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00250_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00250_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00250_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00250_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00250_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 돼지고기(불고기용\",\"100g)\",\"단호박(50g)\",\"죽순(15g)\",\"양파(10g)\",\"대파(10g)\",\"마른 표고버섯(10g)\",\"양념장 저염간장(5g)\",\"고추장(10g)\",\"고춧가루(5g)\",\"된장육수 된장(5g)\",\"물(150g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"돼지고기를 한 번 데친 후 양념에 재워 나트륨 함량을 낮추고\\n육수를 넣고 소금간을 줄여 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 돼지고기는 핏물을 제거하고\\n된장육수에 살짝 데친다.\",\"2. 데친 돼지고기에 양념장을 넣고\\n재운다.\",\"3. 단호박은 도톰하게 썰고, 죽순,\\n양파는 채 썰고, 대파는 어슷 썰고,\\n마른 표고버섯은 불린 뒤 먹기\\n좋은 크기로 썬다.\",\"4. 팬에 올리브유를 두르고 재운\\n돼지고기와 된장육수(50g)를 넣고\\n볶는다.\",\"5. 반 정도 익었을 때 단호박과 죽순,\\n양파, 대파, 표고버섯, 다진 마늘을\\n넣고 볶는다.\",\"6. 부순 참깨와 참기름을 넣어\\n마무리한다.\"]},{\"id\":\"k203\",\"title\":\"버섯콩불고기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00251_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00251_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00251_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00251_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00251_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00251_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00251_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 콩고기(150g)\",\"양파(20g)\",\"당근(5g)\",\"양배추(30g)\",\"깻잎(10g)\",\"느타리버섯(15g)\",\"표고버섯(15g)\",\"새송이버섯(15g)\",\"부추(10g)\",\"미나리(10g)\",\"청양고추(3g)\",\"양념장 설탕(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"육류에 비해 나트륨 함량이 적은 콩고기를 사용하고, 저염간장과 매실액,\\n배즙으로 맛을 낸 소스로 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 콩고기는 물에 담가 20분 정도 불린\\n뒤 양념장 ½과 버무린다.\",\"2. 양파, 당근은 채 썰고, 양배추와\\n깻잎, 버섯은 한입 크기로 썬다.\",\"3. 부추와 미나리는 양파와 비슷한\\n길이로 썰고, 청양고추는 어슷 썬다.\",\"4. 들기름을 두른 팬에 다진 파와 마늘,\\n생강을 넣고 약한 불에 볶다가\\n콩고기를 넣고 나머지 양념장을\\n뿌려 볶는다.\",\"5. 어느 정도 볶아지면 양파, 당근을\\n넣고 볶다가 양배추를 넣고 볶는다.\",\"6. 양배추가 익으면 먹기 좋게 손질한\\n버섯을 넣고 살짝 볶아 마무리한다.\"]},{\"id\":\"k204\",\"title\":\"차돌박이볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00252_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00252_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00252_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00252_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00252_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00252_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00252_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 차돌박이(100g)\",\"파프리카(15g)\",\"양파(10g)\",\"부추(5g)\",\"해초(50g)\",\"소스1 발사믹식초(5g)\",\"매실청(5g)\",\"올리브유(5g)\",\"소스2 마요네즈(10g)\",\"연겨자(5g)\",\"소스3 유자청(10g)\",\"식초(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장을 사용해 나트륨 섭취를 줄이고,\\n해초를 물에 충분히 담가둬 염분이 제거되도록 한다.\",\"instructions\":[\"1. 차돌박이는 고기 밑간에 재워둔다.\",\"2. 파프리카, 양파는 깨끗이 씻어 곱게\\n채 썰고, 부추도 비슷한 길이로 썬다.\",\"3. 해초는 깨끗이 손질하여\\n해초 밑간에 재운다.\",\"4. 3가지 소스를 만든다.\",\"5. 차돌박이를 팬에 볶아 준비한다.\",\"6. 볶은 차돌박이와 해초, 부추,\\n파프리카, 양파를 접시에 담고\\n삼색소스를 곁들여 마무리한다.\"]},{\"id\":\"k205\",\"title\":\"토마토오리볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023658_1678081018817.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023803_1678081083811.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023826_1678081106815.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023847_1678081127389.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306023917_1678081157000.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306024005_1678081205516.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306024027_1678081227718.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 오리고기(90g)\",\"가지(15g)\",\"양파(15g)\",\"파프리카(15g)\",\"새송이버섯(10g)\",\"브로콜리(15g)\",\"부추(5g)\",\"방울토마토(10g)\",\"식용유(3g)\",\"•고기 밑간 : 후춧가루(1g)\",\"맛술(5g)\",\"다진마늘(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•고추장을 적게 사용하고 토마토를 사용한 소스를 곁들여 나트륨 함량을 낮췄어요.\\n•토마토, 풋고추, 양파로 맛을 내 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 오리고기에 고기 밑간을 해 재운다.\",\"2. 가지, 양파, 파프리카, 새송이버섯, 브로콜리는 깍둑 썰고, 부추는 5㎝ 길이로 썰고, 방울토마토는 꼭지만 따서 씻은 뒤 2등분한다.\",\"3. 토마토, 양파, 풋고추는 갈아둔다.\",\"4. 팬에 기름을 두르고 다진 마늘을\\n넣고 볶다가 고추장과 갈아놓은\\n토마토, 양파, 풋고추와 물엿을 넣고\\n볶으면서 농도를 맞춰\\n토마토고추장소스를 만든다.\",\"5. 오리고기와 가지, 양파, 파프리카, 새송이버섯, 브로콜리를 같이 볶다가 토마토고추장소스를 넣어준다.\",\"6. 접시에 담은 뒤 부추와 방울토마토를 곁들여 마무리한다.\"]},{\"id\":\"k206\",\"title\":\"토마토두루치기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00254_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00254_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00254_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00254_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00254_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00254_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00254_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 양배추(40g)\",\"양파(15g)\",\"표고버섯(10g)\",\"양송이버섯(30g)\",\"파프리카(10g)\",\"피망(10g)\",\"대파(5g)\",\"마늘(2g)\",\"토마토(30g)\",\"비트(0.5g)\",\"식용유(5g)\",\"돼지고기(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장의 양을 절반 이상 줄이고 토마토와 비트를 사용해 맛을 내 나트륨 섭취를 줄였다.\\n또한 파프리카와 피망은 칼륨 함량이 높아 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 양배추, 양파, 표고버섯, 양송이버섯,\\n파프리카, 피망은 먹기 좋은 크기로\\n깍둑 썰고, 대파는 어슷 썬다.\",\"2. 마늘은 편 썰어 기름 두른 팬에\\n투명해질 때까지 4~5분 정도\\n볶는다.\",\"3. 토마토는 김 오른 찜기에 찐 후\\n껍질을 벗겨 양파와 함께 으깨가며\\n볶는다.\",\"4. 비트도 곱게 갈아 넣고 함께 볶는다.\",\"5. 식용유를 두른 팬에 돼지고기를\\n넣고 토마토비트소스와 함께 볶는다.\",\"6. 양념을 넣어 간을 맞춘 후 양배추,\\n표고버섯, 양송이버섯, 파프리카,\\n피망, 대파를 넣고 살짝 볶아\\n마무리한다.\"]},{\"id\":\"k207\",\"title\":\"검은콩피시볼조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00255_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00255_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00255_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00255_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00255_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00255_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"피시볼반죽 검은콩(15g)\",\"쪽파(5g)\",\"동태포(30g)\",\"감자전분(10g)\",\"밀가루(7g)\",\"청양고추(1g)\",\"달걀흰자(7g)\",\"소스 마늘(5g)\",\"녹말가루(2g)\",\"가다랑어장국(3g)\",\"간장(3g)\",\"물(100ml)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"간장과 가다랑어포로 만든 조림장은 감칠맛이 좋아 적은 양을 사용하더라도 맛이 난다.\\n또한 검은콩은 칼륨 함량이 높아 나트륨 배출에도 좋다.\",\"instructions\":[\"1. 검은콩을 불려 삶는다.\",\"2. 마늘은 편으로 썰고, 쪽파는 송송\\n썬다.\",\"3. 동태포는 물기를 제거한다.\",\"4. 믹서에 피시볼반죽 재료를 넣어 간\\n뒤 동그랗게 빚고 콩식용유(5g)를\\n두른 팬에 굴려가며 익힌다.\",\"5. 팬에 녹말가루를 제외한 소스\\n재료를 넣고 끓이다가 피시볼을\\n넣고 조리고, 녹말가루로 농도를\\n맞춘 뒤 쪽파를 뿌려 마무리한다.\"]},{\"id\":\"k208\",\"title\":\"대하조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00256_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00256_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00256_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00256_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00256_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00256_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00256_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 대하(4마리)\",\"화이트와인(15g)\",\"시금치(50g)\",\"유자청(40g)\",\"매실액(10g)\",\"아보카도(30g)\",\"토마토(25g)\",\"닭육수 닭다리(1개)\",\"월계수잎(1g)\",\"물(300g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"손질한 대하를 물에 담가 나트륨이 빠져 나오게 해 나트륨 함량을 줄였다\",\"instructions\":[\"1. 냄비에 닭육수 재료를 넣고 20분간\\n끓여 면포에 거른다.\",\"2. 대하를 흐르는 물에 잘 헹구고\\n머리와 껍질을 제거한 뒤\\n화이트와인에 재운다.\",\"3. 시금치를 손질한 후 끓는 물에 살짝\\n데친다.\",\"4. 팬에 닭육수(100g)와 유자청과\\n매실액을 넣고 끓이다가 잘 섞이면\\n대하를 넣어 조린다.\",\"5. 대하가 익어갈 때쯤 시금치를 넣고\\n1분간 더 조린다.\",\"6. 그릇에 시금치를 올리고 그 위에\\n대하를 올린 후 아보카도와\\n토마토를 먹기 좋게 썰어 얹어\\n마무리한다.\"]},{\"id\":\"k209\",\"title\":\"묵은지가지말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00257_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00257_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00257_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00257_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00257_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00257_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00257_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 돼지고기(80g)\",\"가지(30g)\",\"김치(40g)\",\"청피망(15g)\",\"붉은피망(15g)\",\"양파(40g)\",\"생강(2g)\",\"마늘(10g)\",\"올리브유(5g)\",\"레몬(50g)\",\"레드와인(120g)\",\"올리고당(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"씻은 김치에 배어있는 간에 레몬과 레드와인을 넣어 상큼함과\\n깊은 풍미를 더해 따로 소금간을 하지 않아 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 냄비에 고기 삶는 재료를 넣고\\n끓으면 돼지고기를 넣어 익힌다.\",\"2. 가지는 길이로 납작하게 썰고,\\n김치는 씻어 5㎝ 길이로 채 썰고,\\n피망, 양파도 같은 길이로 채 썰고,\\n생강과 마늘은 편으로 썰어 준비한다.\",\"3. 팬에 올리브유를 약간 두르고\\n가지를 살짝 굽는다.\",\"4. 김치, 피망을 가지에 넣고 돌돌 만다.\",\"5. 팬에 올리브유, 마늘, 생강,\\n삶은 고기를 넣고 육즙이 나오지\\n않도록 고기 겉면을 익힌 뒤 채 썬\\n양파, 마늘, 레몬, 레드와인,\\n올리고당을 넣고 조린다.\",\"6. 고기에 간이 배면 건져내 먹기\\n좋은 크기로 썰어 마무리한다.\"]},{\"id\":\"k210\",\"title\":\"함초타락죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00355_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00355_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00355_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00355_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00355_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00355_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00355_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀 25g\",\"우유 200g\",\"함초 15g\",\"크렌베리 10g\",\"다진양파 15g\",\"파마산치즈 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"함초 자체의 짠맛으로 간을 해 소금 등 염분 제품 사용을 줄였고, 파마산치즈의 짠맛과 고소한 맛으로 풍미를 더해 주었다.\",\"instructions\":[\"1. 함초는 세척 후 송송 잘라준다. 이때 물이\\n안 나오게 잘라주는 것이 중요하다.\",\"2. 찹쌀은 미리 30분전에 불려준다.\",\"3. 불린 찹쌀의 물기를 빼고 물 50g을 넣고 죽을\\n끓이다가 함초를 넣고 더 끓인다.\",\"4. 여기에 우유를 넣고 약불에서 은근히 끓여준다.\",\"5. 죽이 어느정도 완성되면 치즈가루를 뿌려준다.\",\"6. 죽이 완성되면 그릇에 담아 완성한다.\"]},{\"id\":\"k211\",\"title\":\"황태두부무국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00356_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00356_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00356_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00356_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00356_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00356_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00356_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"황태 30g\",\"두부 50g\",\"함초 25g\",\"무 100g\",\"청고추 20g\",\"홍고추 15g\",\"쪽파 10g\",\"흰후추 1g\",\"어간장 7g\",\"대파뿌리 7g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"황태 자체의 맛이 소금을 사용하지 않아도 음식에 맛과 풍미를 준다.\\n황태 국물을 이용해 감칠맛을 높이고 국간장 보다 염도가 낮은 어간장을 사용해 나트륨 함량을 줄였다.\",\"instructions\":[\"1. 두부는 사방 1cm로 잘라주고, 무는 반은\\n나박썰기 하고 반은 국물을 낸다.\",\"2. 두부는 사방 1cm로 잘라주고, 무는 반은\\n나박썰기 하고 반은 국물을 낸다.\",\"3. 황태는 먹기 좋게 잘라준다.\",\"4. 황태, 대파뿌리, 함초, 무를 넣고 국물을 만든다.\",\"5. 만들어진 국물에 함초와 대파뿌리를 건져내고\\n어간장으로 간을 해준다. 국물을 만들고 남은\\n무는 나박썰기 해서 국에 넣어준다.\",\"6. 마지막에 두부를 넣어 끓여주고 먹기 직전에\\n청홍고추와 쪽파를 올려 완성한다.\"]},{\"id\":\"k212\",\"title\":\"삼합잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00357_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00357_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00357_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00357_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00357_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00357_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미 50g\",\"바지락살 25g\",\"소고기 20g\",\"닭가슴살 20g\",\"양파 25g\",\"청고추 15g\",\"홍고추 15g\",\"당근 20g\",\"미나리 20g\",\"양념장 : 맛간장 25g\",\"마늘기름 15g\",\"다진마늘 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시원한 맛을 내주는 미나리를 통해 맛과 향을 주어서 해산물의 비린 맛을 잡아준다.\\n마늘기름을 이용해 향과 풍미를 높이며 맛간장을 사용하여 짜지 않은 잡채를 만들었다.\",\"instructions\":[\"1. 주꾸미는 먹기 좋게 잘라주고, 바지락살은 물에\\n데쳐서 수분을 빼고 생강청으로 비린내를 제\\n거한 뒤 볶아준다.\",\"2. 소고기와 닭가슴살은 각각 양념해준다.\",\"3. 양파, 청고추, 홍고추, 당근은 채 썰어 함께\\n볶아준다.\",\"4. 볶아 놓은 채소와 고기, 해산물은 양념장에\\n버무린다.\",\"5. 미나리와 배를 곱게 채 썰어 올려서 완성한다.\"]},{\"id\":\"k213\",\"title\":\"고등어카레탕수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00358_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00358_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00358_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00358_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00358_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00358_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00358_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"냉동고등어 300g\",\"전분가루 50g\",\"식용유 200g\",\"우유 200g\",\"카레가루 20g\",\"감자 50g\",\"애호박 25g\",\"방울토마토 25g\",\"양파 20g\",\"사과 25g\",\"꿀 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"탕수 소스를 우유와 카레가루, 과일을 사용하여 구수하고 담백한 맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 냉동고등어는 먹기 좋은 크기로 잘라 전분을\\n묻혀 기름에 두 번 튀겨준다.\",\"2. 애호박, 방울토마토, 사과는 적당한 크기로\\n잘라준다.\",\"3. 감자와 양파는 적당한 크기로 자른 뒤 물 1컵\\n에 감자를 먼저 넣고 끓여주다 양파를 넣고\\n끓여 단맛을 내준다.\",\"4. 우유에 카레가루를 섞어 불려준 뒤 끓고 있는\\n감자에 넣어준다.\",\"5. 튀겨진 고등어를 키친타월을 이용해 기름을\\n빼준다.\",\"6. 카레가 완성되면 사과, 방울토마토, 꿀을\\n넣어주고 튀겨 놓은 고등어에 뿌려 완성한다.\"]},{\"id\":\"k214\",\"title\":\"효도강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00359_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00359_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00359_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00359_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00359_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00359_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00359_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"볶은현미 25g\",\"볶은율무 25g\",\"볶은수수 25g\",\"혼합견과 50g\",\"흑임자 10g\",\"소스 : 올리고당 25g\",\"설탕 25g\",\"기름 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"견과와 올리고당을 이용해 고소하고 맛있는 강정을 만들 수 있으며 설탕 사용을 줄일 수 있다.\",\"instructions\":[\"1. 모든 재료를 한데 섞어준다.\",\"2. 소스를 만들어준다.\",\"3. 준비된 틀에 비닐을 깔고 기름을 발라준다.\",\"4. 소스가 끓어오르면 모든 재료를 넣어 버무려\\n준다.\",\"5. 준비된 용기에 만들어진 재료를 쏟아 다져준다.\",\"6. 식으면 잘라서 완성한다.\"]},{\"id\":\"k215\",\"title\":\"비트양파김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00360_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00360_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00360_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00360_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00360_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00360_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파 150g\",\"절임물 : 물 200g\",\"볶은소금 2g\",\"식초 15g\",\"비트 2g\",\"국물 : 절임물 100g\",\"생강청 30g\",\"식초 15g\",\"청양고추 7g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"비트와 식초를 이용해 절임물을 만들어 짜지 않은 새콤달콤한 김치를 만들었다.\",\"instructions\":[\"1. 양파는 네 번 정도 칼집을 내어 준다.\",\"2. 절임물을 만들고 절임 물에 칼집 낸 양파를\\n하루(24시간) 정도 절여준다.\",\"3. 절임물을 버리지 말고 절임물 반에 생강청,\\n식초, 청양고추를 잘라서 섞어주고 국물을\\n만든다.\",\"4. 만들어진 국물에 절여진 양파를 담가준다.\",\"5. 24시간 후부터 먹을 수가 있다.\"]},{\"id\":\"k216\",\"title\":\"관자브로콜리스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00361_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00361_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00361_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00361_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00361_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00361_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00361_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"관자 100g\",\"양파 25g\",\"브로콜리 40g\",\"시금치 10g\",\"생크림 25g\",\"우유 200g\",\"버터 15g\",\"파마산가루 3g\",\"다진마늘 5g\",\"흰후추 1g\",\"마늘칩 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파마산가루와 마늘칩 버터 사용을 통해 소금 첨가 없이 짜지 않은 스프를 만들 수 있었다.\",\"instructions\":[\"1. 관자 50g은 편으로 썰어준다.\",\"2. 편으로 썰어준 관자를 다진마늘, 흰후추,\\n버터에 볶아준다.\",\"3. 남은 관자 50g은 국물을 만들어준다.\",\"4. 브로콜리와 시금치는 뜨거운 물에 데쳐낸 후\\n국물 낸 볶은관자와 브로콜리, 시금치는 믹서\\n에 간다.\",\"5. 팬에 넣고 끓이고 우유를 넣고 한 번 더 끓여\\n준다.\",\"6. 생크림과 파마산치즈로 농도를 맞춘 후 그릇에\\n담고 마늘칩을 올려서 완성한다.\"]},{\"id\":\"k217\",\"title\":\"곤약잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308032224_1678256544580.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308032329_1678256609176.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308033824_1678257504091.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308033847_1678257527466.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308033907_1678257547672.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308034202_1678257722146.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308034306_1678257786207.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 실곤약(50g)\",\"당근(10g)\",\"오이(10g)\",\"양파(10g)\",\"팽이버섯(5g)\",\"청고추(10g)\",\"홍고추(10g)\",\"영양부추(10g)\",\"달걀(30g)\",\"식용유(3g)\",\"•소스 : 맛간장(5g)\",\"흑설탕(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•곤약과 버섯을 이용해 식감을 높이고 소스에 맛간장과 다진마늘, 다진대파를 넣어 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 실곤약은 세척해 물기를 빼준 뒤 레몬즙을 살짝 뿌려준다.\",\"2. 당근, 양파, 홍고추, 청고추는 채 썰어 볶는다.\",\"3. 오이는 돌려깎기 해주고 팽이와 영양부추는 적당한 크기로 잘라 각각 살짝 볶아 건진다.\",\"4. 달걀은 황백지단으로 만들어 채 썰어준다.\",\"5. 소스를 팬에 만들어 준 뒤 곤약을 볶아준다.\",\"6. 볶은 곤약에 ②를 넣고 한 번 더 볶은 뒤 ③을 섞어 그릇에 담고, 지단채를 올리고 참기름, 통깨를 뿌려 마무리한다.\"]},{\"id\":\"k218\",\"title\":\"미역 닭가슴살전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00363_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00363_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00363_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00363_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00363_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00363_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00363_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 100g\",\"미역 10g\",\"두부 50g\",\"청양고추 10g\",\"대파 10g\",\"당근 10g\",\"계란 60g\",\"소스 : 저염간장 30g\",\"식초 15g\",\"레몬즙 10g\",\"고추냉이 5g\",\"통깨 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"나트륨을 줄인 간장에 고추냉이를 넣어서 만든 소스는 미역의 풍부한 맛을 살려주고, 부족한 맛을 잡아주어 나트륨 함량을 낮췄으며 두부를 섞어 고소함을 더해주었다.\",\"instructions\":[\"1. 닭가슴살은 송송 다져준 후 소금, 후추로\\n밑간을 해준다.\",\"2. 미역은 물에 불려준 후 송송 잘라준다.\",\"3. 두부는 물기를 꼭 짜준다.\",\"4. 청양고추, 대파, 당근은 송송 다져준다.\",\"5. 소스를 만들어준다.\",\"6. 준비된 재료에 계란으로 반죽해 한입 크기로\\n전을 부쳐준다.\"]},{\"id\":\"k219\",\"title\":\"두가지묵샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00364_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00364_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00364_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00364_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00364_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00364_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두가지 묵(올방개묵\",\"검정깨묵) 각 25g씩\",\"당귀잎 10g\",\"양파 40g\",\"노란 파프리카 25g\",\"알배추 20g\",\"소스 : 저염간장 15g\",\"유자청 30g\",\"다진청고추 7g\",\"다진홍고추 7g\",\"다진대파 7g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"당귀잎을 통해 밋밋한 묵의 풍미를 도와주는 효과를 주었으며 나트륨을 줄인 저염간장에\\n다량의 과일을 넣어 새콤한 맛을 높여 짠맛을 대체하였다.\",\"instructions\":[\"1. 당귀는 잎만 떼어 먹기 좋게 잘라서 물에\\n담가준다.\",\"2. 두가지묵은 먹기 좋게 길이로 잘라준다.\",\"3. 양파, 파프리카, 알배추는 가늘게 채 썰어준다.\",\"4. 소스를 만들어준다.\",\"5. 모든 재료를 담고 소스에 통깨를 섞은 뒤\\n샐러드에 뿌려 완성한다.\"]},{\"id\":\"k220\",\"title\":\"블루베리양갱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00365_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00365_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00365_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00365_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00365_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00365_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00365_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"흰앙금 100g\",\"블루베리 30g\",\"설탕 30g\",\"한천 20g\",\"물100g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"블루베리의 상큼함으로 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 블루베리는 믹서에 갈아서 체에 내려준다.\",\"2. 물에 끓여주면서 흰앙금과 설탕을 풀어준다.\",\"3. 여기에 다시 한천가루를 넣어 끓여준다.\",\"4. 여기에 블루베리를 넣어 끓인다.\",\"5. 몰드에 넣어서 시원한 곳에서 식혀준다.\",\"6. 접시에 완성한다.\"]},{\"id\":\"k221\",\"title\":\"장어찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00366_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00366_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00366_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00366_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00366_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00366_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00366_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"장어 250g\",\"우유 100g\",\"후추 1g\",\"곁들이 샐러드 : 우엉 25g\",\"인삼 20g\",\"미나리 20g\",\"팽이 15g\",\"양파 40g\",\"샐러드소스 : 청고추 17g\",\"홍고추 15g\",\"맛간장 7g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"곁들이 채소를 향이 있는 것을 선택해서 간장이 많이 들어간 장어소스 없이도 맛있게 장어를 먹을 수 있다.\",\"instructions\":[\"1. 장어 살 쪽에 칼집을 내어 우유와 후추로\\n마리네이드 해서 비린내를 제거한다.\",\"2. 우엉, 인삼, 홍고추는 채 썰어 냉수에 담가둔다\",\"3. 미나리, 팽이는 먹기 좋게 썰어준다.\",\"4. 양파, 청고추는 가늘게 채 썰어준다.\",\"5. 장어는 찜기에 쪄준다.\",\"6. 모든 채소를 한데 섞어 샐러드소스로 버무려\\n샐러드를 만들어주고 장어와 함께 완성한다.\"]},{\"id\":\"k222\",\"title\":\"두부까나페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00367_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00367_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00367_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00367_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00367_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00367_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00367_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단단한 두부 150g\",\"슬라이스햄 25g\",\"올리브오일 15g\",\"로즈마리 1g\",\"볶은소금 1g\",\"샐러드 : 마요네즈 30g\",\"당근 20g\",\"양파 50g\",\"오이 25g\",\"소스 : 맛간장 15g\",\"양파 15g\",\"다진마늘 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"마요네즈에 갖가지 야채를 버무린 소스를 사용하여 나트륨 섭취를 줄였고, 로즈마리의 향기로 느끼한 두부구이의 맛을 잡아주었다.\",\"instructions\":[\"1. 두부는 1cm 두께로 잘라 볶은소금을 뿌려\\n수분을 제거한다.\",\"2. 오이는 껍질 부분만 송송 썰어준다.\",\"3. 당근, 양파는 송송 썰어준다.\",\"4. 두부는 노릇하게 구워준다.\",\"5. 오이, 당근, 양파를 소스에 버무려 샐러드를\\n만들고 소스도 함께 만든다.\",\"6. 두부를 한입 크기로 잘라준 후 슬라이스햄과\\n샐러드를 올려 소스랑 함께 완성한다.\"]},{\"id\":\"k223\",\"title\":\"두부청국장죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00368_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00368_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00368_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00368_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00368_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00368_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00368_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"청국장가루 20g\",\"두부 60g\",\"밥 150g\",\"표고버섯 12g\",\"당근 20g\",\"애호박 25g\",\"양념장 : 다진쇠고기 30g\",\"참기름 15g\",\"맛간장 10g\",\"버섯마늘소금 1g\",\"흰후추 1g\",\"다진마늘 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"죽에 청국장가루를 사용해서 구수한 맛이 짠맛을 대체하고 두부, 소고기, 채소를 넣어 씹는 맛과 음식의 색감으로 맛을 높여주었다.\",\"instructions\":[\"1. 다진 쇠고기는 양념장에 버무려주고 두부는\\n으깨준다.\",\"2. 애호박, 당근은 송송 다져준다.\",\"3. 표고버섯은 불려준 뒤 채 썰어 참기름과\\n버섯마늘소금에 살짝 무쳐서 볶아준다.\",\"4. 양념된 소고기는 팬에 볶아준다.\",\"5. 소고기를 볶아주던 팬에 밥과 표고를 넣고\\n끓여주다 두부를 넣고 죽을 해준다.\",\"6. 다진 애호박, 당근을 넣어서 끓여주고 불을\\n끄기 전에 청국장과 흑임자를 넣어 죽을\\n완성한다.\"]},{\"id\":\"k224\",\"title\":\"망고샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00369_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00369_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00369_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00369_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00369_04.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"증편 200g\",\"망고 150g\",\"양상추 30g\",\"치커리 20g\",\"방울토마토 60g\",\"양파 60g\",\"소스 : 올리브오일 30g\",\"유자청 15g\",\"식초 15g\",\"볶은소금 2g\",\"후추 1g\",\"다진 파프리카(노랑) 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쫄깃한 증편을 사용해 식감을 높이고, 망고와 유자청 등을 이용해 짜지 않은 샐러드 소스를 사용하여 짠맛을 대체하였다.\",\"instructions\":[\"1. 증편은 팬에 구워준다.\",\"2. 망고와 방울토마토는 먹기 좋게 잘라준다.\",\"3. 모든 채소는 먹기 좋게 잘라서 물에 담근다.\",\"4. 소스 재료를 섞어 소스를 만들고, 접시에 준비된\\n채소를 담고 소스를 뿌려준 후 구운 떡과 망고\\n를 올려 완성한다.\"]},{\"id\":\"k225\",\"title\":\"토마토젤리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00470_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00470_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00470_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00470_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00470_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00470_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00470_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토(120g)\",\"판젤라틴(10g)\",\"레몬(10g)\",\"올리고당(20g)\",\"블루베리(20g)\",\"설탕(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"아이들이 좋아하는 젤리를 직접 만들어 당과 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 판젤라틴을 얼음물에 담군 후 흐물흐물\\n해질 때까지 불려 둔다.\",\"2. 토마토는 물을 넣고 갈아 준비한다.\",\"3. 갈아 놓은 토마토에 올리고당과\\n레몬즙을 넣어 골고루 섞는다.\",\"4. 레몬즙을 넣은 토마토를 은근히\\n끓인다.\",\"5. 끓고 있는 토마토에 불린 젤라틴을\\n넣고 녹여주고, 젤라틴이 녹으면\\n불을 끄고, 접시에 담아 냉장고에 약\\n20분 정도 굳힌다.\",\"6. 팬에 설탕을 넣고 설탕이 녹으면,\\n블루베리를 넣어 은근히 졸여진 후\\n굳어진 토마토젤리 위에 올려 완성한다.\"]},{\"id\":\"k226\",\"title\":\"샌드스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00471_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00471_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00471_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00471_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00471_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00471_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00471_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살(120g)\",\"소금(0.1g)\",\"후춧가루(0.02g)\",\"버터(10g)\",\"느타리버섯(20g)\",\"시금치(20g)\",\"굴소스(5g)\",\"올리브오일(10g)\",\"- 카레소스 : 베이컨(20g)\",\"양파(20g)\",\"카레가루(20g)\",\"대파(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레의 특유향과 갖가지 채소가 짠맛을 대체하면서 식욕을 자극해요.\",\"instructions\":[\"1. 닭가슴살은 가운데 1/4 정도 깊은 칼집\\n넣어 소금과 후추를 뿌려놓는다.\",\"2. 느타리버섯은 찢고, 베이컨은 네모지게\\n썰어놓는다.\",\"3. 시금치는 살짝 데쳐 썰고, 양파와 대파는\\n입자있게 썰어 준비한다.\",\"4. 팬에 버터를 두르고, 시금치와 버섯을\\n넣어 볶다가 굴소스를 넣고 다시 볶아\\n준다.\",\"5. 닭가슴살에 볶아 놓은 시금치와 버섯을\\n넣어 팬에 올리브기름으로 구워 익힌다.\",\"6. 냄비에 베이컨과 양파를 넣어 볶다가\\n카레가루를 넣어 살짝 볶고, 다시 우유와\\n생크림, 대파를 넣고 끓여 카레소스를\\n만들고, 어린잎채소와 닭스테이크\\n(⑤)를 접시에 담고 카레 소스를 올려\\n완성한다.\"]},{\"id\":\"k227\",\"title\":\"맥적구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00472_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00472_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00472_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00472_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00472_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00472_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00472_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(120g)\",\"생강(10g)\",\"소금(0.2g)\",\"후춧가루(0.02g)\",\"저염간장(20g)\",\"정종(10g)\",\"설탕(20g)\",\"대파(10g)\",\"마늘(20g)\",\"양파(20g)\",\"참기름(5g)\",\"통깨(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장에 마요네즈와 생크림을 넣어 만든 맥적 소스는 된장의 짠맛을 감소시켜 나트륨 함량을 낮출 수 있었어요.\",\"instructions\":[\"1. 돼지고기에 생강즙과 소금, 후춧가루를\\n넣어 숙성한다.\",\"2. 숙성된 돼지고기에 간장과 정종, 설탕,\\n파, 마늘, 양파, 참기름, 통깨 넣어\\n골고루 양념한다.\",\"3. 새송이, 가지, 표고, 홍피망을 편으로\\n썰어 준비한다.\",\"4. 된장에 마요네즈와 생크림, 다진\\n땅콩을 섞어놓는다.\",\"5. 새송이와 가지, 표고, 홍피망은 팬에서\\n굽는다.\",\"6. 팬이 따끈해지면 양념한 돼지고기를\\n구워 접시에 담고 그 위에 된장 소스를\\n올리고, 구워낸 채소를 다시 위에 올려\\n완성한다.\"]},{\"id\":\"k228\",\"title\":\"채소어묵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00473_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00473_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00473_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00473_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00473_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00473_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00473_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"생선살(100g)\",\"맛술(10g)\",\"생강(10g)\",\"소금(0.2g)\",\"밀가루(20g)\",\"양파(20g)\",\"당근(20g)\",\"샐러리(10g)\",\"마늘(10g)\",\"옥수수(20g)\",\"어린이치즈(20g)\",\"튀김기름(400g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"흰살 생선은 담백한 맛과 튀김의 고소한 맛이 더해져 간을 하지 않아도 풍미가 있어요\",\"instructions\":[\"1. 생선살은 가시를 발라내고 곱게 으깨어\\n놓는다.\",\"2. 으깬 생선살에 맛술 과 생강즙, 소금을\\n넣어 골고루 치댄다.\",\"3. 잘 치댄 생선살에 밀가루를 넣어 다시\\n치대어 준다.\",\"4. 양파와 당근, 샐러리, 마늘은 곱게\\n다지고, 옥수수는 알맹이를 준비한다.\",\"5. 생선살에 다진 채소와 어린이 치즈를\\n다져 섞는다.\",\"6. 채소를 다져 섞은 생선살을 동글동글\\n하게 완자를 빚어 튀김기름에 약 150℃\\n온도에서 은근히 5분 정도 튀겨 완성\\n한다.\"]},{\"id\":\"k229\",\"title\":\"주꾸미보리죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00474_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00474_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00474_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00474_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00474_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00474_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00474_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미(100g)\",\"밀가루(10g)\",\"보리(100g)\",\"미나리(10g)\",\"당근(20g)\",\"양파(20g)\",\"참기름(5g)\",\"육수(400g)\",\"저염치즈(20g)\",\"우유(100g)\",\"저염간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"주꾸미와 보리쌀을 넣어 씹히는 질감이 있으며, 갖가지 채소와 어우러져 맛이 좋고, 저염치즈를 넣으므로 별도의 소금을 넣지 않아도\\n나트륨 함량을 줄일 수 있다.\",\"instructions\":[\"1. 보리는 깨끗이 씻어 물을 충분히 붓고\\n약 30분 정도 불려 준비한다.\",\"2. 주꾸미는 밀가루를 넣고 조물조물\\n주물러 다시 깨끗이 씻어 준비한다.\",\"3. 씻어놓은 주꾸미는 살짝 데쳐 입자\\n있게 다져 놓는다.\",\"4. 미나리와 당근, 양파는 입자있게\\n다져 놓는다.\",\"5. 냄비에 참기름을 두르고, 주꾸미를\\n먼저 볶다가 불린 보리쌀을 넣고 다시\\n볶은 뒤 썰어놓은 채소(④)를 넣는다.\",\"6. 냄비에 육수를 넣고 나무주걱으로\\n은근히 저어가면 끓이다가 죽이 어우러\\n지면, 우유와 치즈, 간장을 살짝 넣고\\n한 번 더 끓여 완성한다.\"]},{\"id\":\"k230\",\"title\":\"오렌지삼겹찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00475_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00475_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00475_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00475_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00475_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00475_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00475_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼겹살(100g)\",\"로즈마리(5g)\",\"고구마(30g)\",\"생크림(10g)\",\"감자(20g)\",\"튀김기름(200g)\",\"브로컬리(30g)\",\"올리브오일(10g)\",\"- 소스 : 오렌지(50g)\",\"설탕(10g)\",\"정종(10g)\",\"저염소금(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"로즈마리와 함께 숙성시킨 삼겹살에 오렌지와 와사비를 곁들여 만든 소스가 어우러져 별도의 소금 없이도 맛을 느낄 수 있어요.\",\"instructions\":[\"1. 삼겹살은 로즈마리를 뿌려\\n숙성시킨다.\",\"2. 고구마는 삶아 준비하고, 감자는 웨지\\n감자형으로 썰어 익힌 후 기름에 튀겨\\n놓는다.\",\"3. 삶아진 고구마를 으깨어 생크림을 넣어\\n골고루 섞는다.\",\"4. 오렌지는 즙을 짜 놓는다.\",\"5. 숙성된 삼겹살은 오븐에 굽고, 브로컬리는\\n살짝 데쳐 올리브오일에 볶아놓는다.\",\"6. 팬에 오렌지즙과 설탕, 정종, 소금을\\n넣고 바글바글 졸인 후 와사비를 넣어\\n소스를 만들고, 오븐에 구어진 삼겹살을\\n잘라 접시에 담고 그 위에 소스를\\n살짝 올리고, 한쪽에는 감자튀김(②),\\n고구마무스(③), 브로컬리(⑤)를\\n곁들여 완성한다.\"]},{\"id\":\"k231\",\"title\":\"소고기볼게살타르\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00476_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00476_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00476_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00476_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00476_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00476_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00476_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다진 소고기(100g)\",\"마늘(10g)\",\"양파(20g)\",\"파프리카(20g)\",\"후춧가루(0.02g)\",\"빵가루(10g)\",\"소금(0.3g)\",\"버터(10g)\",\"식용유(5g)\",\"- 소스 : 고구마(20g)\",\"바나나(20g)\",\"마요네즈(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갖가지 채소를 넣은 소고기 볼에 고소하고 달콤한 소스를 곁들여 소금을 사용하지 않아도 맛있어요.\",\"instructions\":[\"1. 마늘과 양파를 입자있게 다져 팬에 볶아\\n식혀 준비하고 파프리카는 다져 놓는다.\",\"2. 다진 소고기에 준비한 채소(①)와\\n빵가루, 후춧가루, 소금 넣고 골고루 치\\n대어 소고기 볼을 만든 후 후라이팬에\\n버터와 식용유를 두르고 소고기볼을\\n속까지 익혀 준비한다.\",\"3. 바나나는 작게 깍뚝 모양으로 썰고,\\n게맛살은 약 3cm 길이로 찢어 준비\\n한다.\",\"4. 고구마는 껍질을 벗겨 삶아 채에 내려\\n마요네즈와 매실액을 넣어 섞은 뒤\\n바나나, 게맛살(③)을 골고루 섞어\\n소스를 만든다.\",\"5. 브로컬리는 작게 썰어 미니버섯과\\n함께 팬에 살짝 구워 준비한다.\",\"6. 익혀 놓은 소고기볼(②)을 접시에 담고\\n그 위에 소스(④)를 얹은 뒤 브로컬리와\\n미니버섯(⑤), 어린잎을 올려 완성한다.\"]},{\"id\":\"k232\",\"title\":\"수삼떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00477_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00477_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00477_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00477_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00477_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00477_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00477_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다진소고기(100g)\",\"수삼(50g)\",\"양파(20g)\",\"대파(10g)\",\"마늘(10g)\",\"저염간장(10g)\",\"후춧가루(0.05g)\",\"정종(10g)\",\"찹쌀가루(10g)\",\"새송이(50g)\",\"대추(20g)\",\"통깨(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수삼의 향으로 나트륨 섭취를 줄였어요\",\"instructions\":[\"1. 수삼은 뇌두를 제거하고 양파와\\n대파, 마늘과 함께 다진다\",\"2. 다진 소고기에 다진 재료(①)와 간장,\\n후춧가루, 정종, 찹쌀가루를 넣어\\n골고루 섞는다.\",\"3. 대추는 씨를 제거하고 채를 썰어\\n곁들임채소로 준비하고, 새송이는\\n길이로 썰어 갈비뼈 모양으로 만들어\\n놓는다.\",\"4. 양념이 된 소고기(②)를 새송이(③)에\\n감싸듯 타원형 모양으로 떡갈비를\\n만든다.\",\"5. 만들어 놓은 떡갈비를 팬에 은근히\\n익힌다.\",\"6. 간장과 올리고당, 설탕, 육수를 넣고\\n섞어가며 바글바글 끓인 뒤, 익힌 떡갈\\n비(⑤)를 넣고 살짝 졸인 후 접시에 담고,\\n그 위에 통깨를 살짝 뿌리고, 대추채(③)와\\n어린잎을 곁들임채소로 올려 완성한다.\"]},{\"id\":\"k233\",\"title\":\"삼색딤섬\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00478_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00478_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00478_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00478_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00478_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00478_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00478_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀가루(200g)\",\"백년초가루(20g)\",\"뽕잎가루(20g)\",\"치자가루(10g)\",\"미나리(20g)\",\"두부(30g)\",\"오징어(30g)\",\"다진 소고기(60g)\",\"양파(20g)\",\"부추(30g)\",\"숙주(30g)\",\"대파(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"천연색소가루로 만든 삼색 만두는 식감을 자극하며, 오징어의 짠맛을 이용하여 추가 간을 하지 않아도 맛이 있다.\",\"instructions\":[\"1. 밀가루를 세등분하여 각각 백년초,\\n뽕잎, 치자 가루를 넣고 물을 넣고\\n반죽을 한 뒤 비닐봉투에 넣어 숙성을\\n시킨다.\",\"2. 두부는 소창에 물기를 짜고, 양파, 파,\\n마늘은 다지고, 부추는 송송 썰어 준비\\n하고, 숙주는 뜨거운 물에 데쳐 곱게\\n다진다.\",\"3. 오징어는 껍질을 벗겨 입자있게 다져\\n놓는다.\",\"4. 다진고기에 준비한 두부와 양파, 파,\\n마늘, 부추, 숙주(②)와 오징어(③)를\\n넣어 섞은 후 참기름과 후춧가루, 통깨를\\n넣어 딤섬 속을 만든다.\",\"5. 숙성된 밀가루 반죽을 꺼내 밀대를\\n이용하여 넓게 밀어 준다.\",\"6. 밀어 놓은 반죽을 사각으로 자른 후\\n그 안에 딤섬 속을 넣어 미나리를 데쳐\\n끈을 만들어 딤섬 위쪽을 묶은 후\\n찜통에서 김이 오르면 약 10분 정도\\n쪄서 완성한다.\"]},{\"id\":\"k234\",\"title\":\"밥크로켓\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00479_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00479_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00479_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00479_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00479_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00479_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00479_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파(20g)\",\"대파(10g)\",\"당근(20g)\",\"마늘(10g)\",\"식용유(10g)\",\"메추리알(100g)\",\"밥(100g)\",\"소금(0.5g)\",\"밀가루(20g)\",\"녹말가루(10g)\",\"달걀(50g)\",\"빵가루(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갖가지 채소와 메추리알이 어우러져 별도의 소금간을 하지 않아도 맛이 좋아요\",\"instructions\":[\"1. 양파와 대파, 당근, 마늘은 입자있게\\n다져 준비한다.\",\"2. 팬에 기름을 두르고, 팬이 따끈해 지면\\n준비한 채소(①)를 넣어 재빠르게 볶아\\n식힌다.\",\"3. 메추리알은 찬물에 넣어 소금을 넣고\\n약 5분 정도 삶아 건져 찬물에 헹구어\\n껍질을 제거시켜 놓는다.\",\"4. 준비한 밥에 볶아 놓은 채소와 소금을\\n넣어 골고루 섞은 후 준비한 메추리알을\\n감싸 준다.\",\"5. 밥으로 감싼 메추리알을 밀가루와\\n녹말을 섞어 그 위에 굴리고, 다시\\n달걀물에 굴린 후 빵가루를 입혀준다.\",\"6. 튀김 기름이 약 170℃ 정도 되면,\\n만들어 놓은 메추리알을 넣어 골고루\\n색이 나도록 튀겨 완성하고, 칠리소소와\\n함께 제공한다.\"]},{\"id\":\"k235\",\"title\":\"가지토마토구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00480_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00480_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00480_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00480_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00480_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00480_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00480_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지(80g)\",\"올리브오일(10g)\",\"소금(0.5g)\",\"토마토(40g)\",\"모짜렐라치즈(30g)\",\"- 소스 : 토마토소스(20g)\",\"토마토(40g)\",\"- 곁들임 : 팽이버섯(20g)\",\"후춧가루(0.02g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"모짜렐라치즈를 사용하여 만든 음식은 맛이 담백하고, 나트륨 사용을 적게 할 수 있어 좋아요.\",\"instructions\":[\"1. 가지는 약 10cm 길이로 길고, 납작하게\\n썰어 준비한다.\",\"2. 팬에 올리브 오일을 살짝 둘러 썰어놓은\\n가지를 소금을 넣고 살짝 익힌다.\",\"3. 토마토는 반은 토마토 형태로 납작하게\\n썰어 놓는다.\",\"4. 토마토반은 입자있게 다져 준비한다.\",\"5. 다진 토마토를 준비한 토마토소스에\\n섞어 살짝 어우러지게 끓여 준비한다.\",\"6. 구운 가지위에 토마토와 모짜렐라치즈를\\n올려 팬에 굽고, 별도로 팽이버섯에\\n후춧가루를 뿌려 살짝 구워 접시에 담고,\\n끓여 놓은 토마토소스를 올려 완성한다.\"]},{\"id\":\"k236\",\"title\":\"함박스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102236_1678324956054.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102321_1678325001406.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102338_1678325018516.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102353_1678325033553.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102411_1678325051671.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102429_1678325069385.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102448_1678325088522.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 다진 소고기(90g)\",\"다진 돼지고기(90g)\",\"양파(15g)\",\"마늘(7g)\",\"깻잎(3g)\",\"올리브오일(5g)\",\"메추리알(35g)\",\"•숙성 : 소금(0.2g)\",\"후춧가루(0.02g)\",\"달걀(15g)\",\"녹말가루(3g)\",\"빵가루(7g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•깻잎의 향으로 고기의 누린내를 잡았어요. \\n•고추, 와인, 토마토를 활용한 저염소스를 만들어 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 마늘과 양파는 입자있게 다져 볶아서 준비한다.\",\"2. 다진 소고기와 돼지고기에 볶아놓은 마늘과 양파를 넣고, 소금과 후춧가루, 달걀물, 빵가루, 녹말가루를 넣어 골고루 치대어 숙성시킨다.\",\"3. 깻잎은 곱게 채를 썰어 찬물에 담가 싱싱해 지면 건져 숙성된 고기에 넣는다.\",\"4. 깻잎을 넣은 고기를 지름 4cm 크기의 함박스테이크 형태를 만들어 팬에 올리브오일을 넣고 익힌다\",\"5. 냄비에 마른고추와 대파, 마늘, 와인, 저염간장, 올리고당, 설탕을 넣어 끓이다가, 토마토(2/3 분량)를 다져넣고, 뭉근하게 졸여 체에 걸러 놓는다.\",\"6. 남은 토마토는 원형을 살려 슬라이스하여 접시에 깔아준 뒤 익힌 함박스테이를 얹고 메추리알은 한 개씩 반숙 지단을 부쳐 익힌 함박스테이크 위에 올린다.\"]},{\"id\":\"k237\",\"title\":\"냉파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00482_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00482_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00482_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00482_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00482_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00482_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00482_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"스파게티(100g)\",\"올리브오일(10g)\",\"소고기(50g)\",\"저염간장(10g)\",\"설탕(10g)\",\"마늘(10g)\",\"깻잎(10g)\",\"양파(20g)\",\"파프리카(20g)\",\"육수(400g)\",\"설탕(10g)\",\"식초(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새콤달콤한 육수에 양념된 소고기구이가 어우러져 나트륨 함량을 낮출 수 있어요\",\"instructions\":[\"1. 스파게티는 약 10분 정도 삶아 건져\\n찬물에 헹궈 물기를 빼고 올리브오일을\\n발라 준비한다.\",\"2. 소고기는 넓게 편으로 펴서 간장, 설탕,\\n마늘을 넣어 양념을 한다.\",\"3. 양념된 소고기를 팬에 구워 냅킨위에\\n올려 기름을 빼놓는다.\",\"4. 깻잎과 양파, 파프리카는 길게 채를\\n썰어 준비한다.\",\"5. 팬에 기름을 넣고 팬이 뜨거울 때\\n양파를 넣어 재빠르게 볶아낸다.\",\"6. 준비한 육수에 설탕과 식초, 저염간장을\\n넣어 차갑게 냉장보관하고, 그릇에\\n스파게티를 담고, 그 위에 볶은 양파와\\n깻잎, 파프리카와 구운 고기를 올린 후\\n차가운 육수를 부어 완성한다.\"]},{\"id\":\"k238\",\"title\":\"과일겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00483_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00483_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00483_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00483_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00483_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00483_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00483_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과(50g)\",\"배(30g)\",\"설탕(10g)\",\"바나나(50g)\",\"키위(30g)\",\"파인애플(30g)\",\"마(50g)\",\"- 양념장 : 마늘(10g)\",\"식용유(5g)\",\"고춧가루(20g)\",\"식초(10g)\",\"저염간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일과 절묘하게 어울리는 볶은 마늘 양념장은 나트륨 함량을 낮춰줘요\",\"instructions\":[\"1. 사과와 배는 껍질을 베이킹파우더에\\n깨끗이 씻어 납작하게 썰어 설탕물에\\n담그어 색이 변하지 않게 준비한다.\",\"2. 바나나는 동글하게 썰고, 키위는 껍질을\\n제거하고 은행잎 모양으로 썰고,\\n파인애플은 가운데 심을 제거하고\\n사각형 모양으로 썰어놓는다.\",\"3. 마는 껍질을 벗겨 동글하게 썰어 준비\\n한다.\",\"4. 마늘은 입자있게 다져, 팬에 식용유를\\n두르고 살짝 볶는다.\",\"5. 고춧가루에 볶은 마늘(④), 식초. 설탕,\\n간장, 고춧가루를 넣고, 골고루 섞어\\n양념장을 만든다.\",\"6. 설탕물에 사과와 배를 건지고, 준비한\\n과일과 마를 담은 후 먹기 직전에 만들어\\n놓은 양념장을 넣어 버무려 완성한다.\"]},{\"id\":\"k239\",\"title\":\"버섯탕수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00484_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00484_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00484_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00484_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00484_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00484_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00484_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새송이버섯(80g)\",\"느타리버섯(50g)\",\"표고버섯(50g)\",\"소금(0.5g)\",\"녹말가루(40g)\",\"달걀(50g)\",\"튀김기름(400g)\",\"키위(20g)\",\"- 소스 : 저염간장(20g)\",\"설탕(20g)\",\"식초(20g)\",\"물녹말(녹말가루 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갖가지 버섯향과 키위의 새콤달콤함이 어우러져 소스의 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 새송이와 느타리, 표고버섯은 먹기\\n좋은 형태로 썰어 준비한다.\",\"2. 썰어 놓은 버섯에 소금을 살짝 뿌려\\n놓는다.\",\"3. 소금 뿌린 버섯에 녹말가루와 달걀물을\\n넣고 골고루 섞는다.\",\"4. 오이, 당근, 양파, 키위는 작은 깍두기\\n모양으로 썰어 준비한다.\",\"5. 냄비에 저염간장에 설탕을 넣고 골고루\\n섞어 끓이다가, 물녹말을 풀어 농도를\\n맞추고 썰어놓은 오이, 당근, 양파를\\n넣어 소스를 만든다.\",\"6. 튀김기름의 온도가 약 170~180℃ 정도\\n올라오면 녹말옷을 입힌 버섯(③)을\\n재빠르게 튀겨 기름을 제거하고, 접시에\\n담아 소스(⑤)를 얹고 키위를 올려 완성\\n한다.\"]},{\"id\":\"k240\",\"title\":\"아보카도 연어샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00604_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00604_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00604_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00604_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00604_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00604_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00604_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(훈제연어\",\"120g)\",\"양파(1/2개)\",\"아보카도(1/2개)\",\"파프리카(1/2개)\",\"오렌지(1/2개)\",\"사워크림(20g)\",\"어린잎(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사워크림에 양파를 넣고 만든 소스는 훈제 연어의 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 연어는 주사위 모양으로 썬다.\",\"2. 양파, 파프리카도 주사위 모양으로\\n썬다.\",\"3. 아보카도와 오렌지도 같은 형태로\\n썬다.\",\"4. 사워크림에 다진 양파를 섞어 소스를\\n만든다.\",\"5. 어린잎은 찬물에 담궈 싱싱하게 한다.\",\"6. 원형 몰드에 연어를 넣고, 옆으로\\n야채와 과일을 담고 그 위에\\n사워크림소스와 어린잎을 올린다.\"]},{\"id\":\"k241\",\"title\":\"오렌지마리네이드 돼지고기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00605_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00605_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00605_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00605_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00605_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00605_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00605_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(150g)\",\"시금치(30g)\",\"양송이버섯(3개)\",\"파프리카(1/4개)\",\"마늘(10g)\",\"오렌지(1/2개)\",\"레몬(1/4개)\",\"머스터드(20g)\",\"꿀(10g)\",\"생크림(20g)\",\"우유(200g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"머스터드에 꿀을 섞어서 나트륨을 줄인 소스를 만들 수 있어요.\",\"instructions\":[\"1. 돼지고기는 오렌지와 레몬,\\n올리브오일로 마리네이드 한다.\",\"2. 파프리카, 양송이버섯은 썰어서 팬에\\n굽는다.\",\"3. 머스터드와 꿀을 섞어 소스를 만든다.\",\"4. 시금치는 끓는 물에 데친다.\",\"5. 마늘은 편으로 썰고 팬에 굽는다.\",\"6. 돼지고기를 팬에 구워 접시에 담고,\\n구운 마늘, 파프리카, 양송이버섯,\\n데친 시금치를 담고 그 위에\\n머스터드소스를 올린다.\"]},{\"id\":\"k242\",\"title\":\"인삼갈비탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00606_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00606_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00606_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00606_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00606_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00606_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00606_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(갈비\",\"300g)\",\"인삼(2뿌리)\",\"당면(50g)\",\"표고버섯(1개)\",\"달걀(1개)\",\"대추(3알)\",\"양파(50g)\",\"파(30g)\",\"마늘(30g)\",\"설탕(10g)\",\"저염간장(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"표고버섯, 양파, 마늘, 인삼을 넣고 끓인 육수에 갈비를 넣고 갈비탕을 만들면 천연의 맛을 느낄 수 있고, 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 갈비는 찬물에 담궈 핏물을 뺀다.\",\"2. 끓은 물에 갈비를 데친다.\",\"3. 찬물에 표고버섯, 파, 마늘, 양파 및\\n인삼을 넣고 데친 갈비를 넣고 약 2시간\\n정도 끓여 갈비탕을 만든다.\",\"4. 저염간장에 설탕을 섞어 고기소스를\\n만든다.\",\"5. 당면은 뜨거운 물에 불려 갈비탕을\\n먹기 직전에 넣는다.\",\"6. 달걀은 황백으로 나눠 지단을 부쳐\\n완성된 갈비탕 위에 대추와 함께 올려\\n완성한다.\"]},{\"id\":\"k243\",\"title\":\"체리젤리를 곁들인 고구마무스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00607_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00607_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00607_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00607_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00607_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00607_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00607_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"체리(50g)\",\"고구마(150g)\",\"화이트 초콜릿(50g)\",\"판젤라틴(1장)\",\"피스타치오(20g)\",\"헤이즐넛(20g)\",\"캐슈넛(20g)\",\"호두(20g)\",\"아몬드(20g)\",\"라즈베리(20g)\",\"건포도(20g)\",\"애플민트(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다양한 견과류와 라즈베리를 사용해서 만들기 때문에 후식으로 즐길 수 있어요\",\"instructions\":[\"1. 고구마는 깨끗이 씻어 찜통에 쪄낸다\",\"2. 뜨거운 고구마는 식기 전에 으깬다.\",\"3. 화이트 초콜릿은 중탕으로 녹여 으깬\\n고구마와 섞는다\",\"4. 체리는 믹서에 곱게 간다.\",\"5. 젤라틴은 물에 불려 중탕으로 녹이고\\n갈아 놓은 체리에 섞어 굳힌다\",\"6. 견과류와 라즈베리, 건포도는 다져서\\n굳힌 체리젤리에 뿌리고 고구마 무스를\\n젤리 주위에 두르고 애플민트를\\n올린다.\"]},{\"id\":\"k244\",\"title\":\"카레닭 룰라이드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00608_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00608_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00608_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00608_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00608_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00608_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00608_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(120g)\",\"카레가루(20g)\",\"당근(20g)\",\"양파(20g)\",\"샐러리(1/2개)\",\"아스파라거스(3개)\",\"토마토(50g)\",\"감자(50g)\",\"생크림(30g)\",\"소금(0.1g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레가루를 묻히기 때문에 닭살에는 아주 적은 소금으로 밑간을 할 수 있어요\",\"instructions\":[\"1. 닭살에 소금, 후추로 밑간을 한다.\",\"2. 밑간한 닭살에 카레가루를 골고루\\n묻힌다.\",\"3. 양파, 당근, 토마토, 샐러리는 주사위\\n모양으로 자른다\",\"4. 냄비에 양파, 당근, 토마토, 샐러리를\\n볶다가 카레가루를 넣고 끓여\\n카레소스를 만든다.\",\"5. 팬에 기름을 두르고 닭살을 익힌다.\",\"6. 그릇에 익힌 닭살을 담고 카레소스를\\n올린다.\"]},{\"id\":\"k245\",\"title\":\"세 가지곡물콩라미수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00609_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00609_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00609_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00609_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00609_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00609_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00609_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"미숫가루(50g)\",\"통조림콩(20g)\",\"검은콩(20g)\",\"바나나(1개)\",\"흑임자(5g)\",\"달걀(1개)\",\"우유(200g)\",\"애플민트(10g)\",\"버터(20g)\",\"설탕(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"버터와 콩을 함께 사용해서 나트륨 함량도 줄일 수 있고, 바나나는 몸 속의 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 미숫가루는 설탕을 넣고 체에 한 번\\n거른다.\",\"2. 달걀노른자에 설탕을 넣고 중탕으로\\n익힌다.\",\"3. 버터는 중탕으로 녹이고 검은콩은 불린\\n뒤 삶아 통조림콩, 버터와 함께 간다.\",\"4. 바나나는 곱게 으깨고 흑임자는 곱게\\n간다.\",\"5. 우유는 냄비에 넣고 따끈하게 데운다.\",\"6. 데워진 우유에 미숫가루와 모든 재료를\\n골고루 섞는다.\"]},{\"id\":\"k246\",\"title\":\"크림치즈 망고무스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00610_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00610_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00610_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00610_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00610_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00610_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00610_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"망고퓨레(50g)\",\"라즈베리(10g)\",\"피스타치오(30g)\",\"크림치즈(50g)\",\"요거트(50g)\",\"생크림(50g)\",\"판젤라틴(1장)\",\"레몬(1/4개)\",\"애플민트(10g)\",\"설탕(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"요거트를 사용해서 나트륨을 줄이고, 애플민트향이 망고무스를 더욱 돋보이게 해요.\",\"instructions\":[\"1. 냄비에 망고퓨레, 레몬, 설탕을 넣고\\n은근히 끓인다.\",\"2. 젤라틴은 찬물에 불린 뒤 중탕으로\\n녹여 망고퓨레에 넣고 틀에 굳힌다.\",\"3. 생크림은 차갑게 휘핑하여 요거트와\\n섞는다.\",\"4. 생크림을 섞은 요거트에 설탕,\\n크림치즈를 섞는다\",\"5. 냄비에 라즈베리, 설탕을 넣고 은근히\\n끓인다.\",\"6. 접시에 굳힌 망고무스에 담고 그 위에\\n라즈베리 소스와 크림치즈 소스, 다진\\n파스타치오를 올리고 애플민트로\\n장식한다.\"]},{\"id\":\"k247\",\"title\":\"토마토주스를곁들인컵토마토\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00611_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00611_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00611_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00611_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00611_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00611_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00611_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"줄기토마토(3개)\",\"토마토(100g)\",\"오이(50g)\",\"양파(30g)\",\"올리브오일(10g)\",\"설탕(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토는 나트륨을 배출을 도와주고, 고혈압 예방에도 도움을 줘요.\",\"instructions\":[\"1. 토마토는 끓는 물에 살짝 데친다.\",\"2. 데친 토마토를 믹서에 곱게 갈고\\n설탕을 넣고 섞는다.\",\"3. 줄기토마토는 윗부분을 잘라내고 속을\\n파낸다.\",\"4. 오이와 양파는 입자있게 썬다.\",\"5. 팬에 올리브오일을 두르고 썰어 놓은\\n오이와 양파를 살짝 볶는다.\",\"6. 을 파낸 줄기토마토에 볶아 놓은\\n야채와 ?번을 넣는다.\"]},{\"id\":\"k248\",\"title\":\"해산물 훈제연어롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00612_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00612_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00612_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00612_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00612_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00612_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00612_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(훈제연어\",\"120g)\",\"주꾸미(100g)\",\"소라(50g)\",\"완두콩(20g)\",\"샐러리(30g)\",\"파프리카(1/2개)\",\"오이(20g)\",\"당근(20g)\",\"양파(20g)\",\"고추장(20g)\",\"식초(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨 성분이 많은 주꾸미를 끓는 물에 데쳐 나트륨을 줄여주고, 상큼한 소스로 맛을 더했어요.\",\"instructions\":[\"1. 훈제 연어는 넓게 썬다.\",\"2. 당근, 오이, 파프리카, 양파, 샐러리는\\n길게 썬다.\",\"3. 주꾸미는 소금에 주물러 씻는다.\",\"4. 손질한 주꾸미, 소라는 끓는 물에\\n데치고 썰어준다.\",\"5. 고추장에 식초, 설탕을 넣고\\n초고추장소스를 만든다.\",\"6. 훈제 연어에 야채와 주꾸미, 소라를\\n넣고 돌돌 말아 접시에 담고\\n초고추장소스를 올리고 완두콩으로\\n장식한다.\"]},{\"id\":\"k249\",\"title\":\"인절미 무스와 수정과 아이스크림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00613_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00613_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00613_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00613_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00613_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00613_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00613_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홍시(1개)\",\"콩가루(20g)\",\"계피(10g)\",\"생강(20g)\",\"호두(10g)\",\"곶감(2개)\",\"자몽(1/6개)\",\"판젤라틴(1장)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"인절미를 만들 때 콩가루를 섞어 소금을 넣지 않아도 맛있게 만들 수 있어요.\",\"instructions\":[\"1. 곶감은 씨를 발라낸다.\",\"2. 생강과 계피를 넣고 끓여 수정과를\\n만든 뒤 냉동한다.\",\"3. 홍시는 믹서로 곱게 갈고 틀어 넣어\\n굳힌다.\",\"4. 생크림은 차갑게 휘핑한다.\",\"5. 불려 놓은 젤라틴을 굳혀 콩가루를\\n섞어 인절미를 만든다\",\"6. 자몽을 껍질을 제거 후 갈아서 젤리를\\n만들고, 접시에 굳혀놓은 홍시와\\n아이스 수정과를 담는다\"]},{\"id\":\"k250\",\"title\":\"감닭떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00614_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00614_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00614_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00614_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00614_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00614_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00614_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 : 닭고기(120g)\",\"감자(200g)\",\"양파(50g)\",\"달걀(1개)\",\"마늘(10g)\",\"찹쌀가루(50g)\",\"매실청(5g)\",\"소금(0.3g)\",\"후춧가루(0.5g)\",\"식용유(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갈아 놓은 감자와 양념된 닭살을 섞어 소금 간을 조금만 해도 맛을 낼 수 있어요.\",\"instructions\":[\"1. 닭 살을 곱게 다진다.\",\"2. 다진 닭살에 소금, 후춧가루, 매실청 및\\n다진 마늘을 넣고 골고루 양념한다.\",\"3. 믹서에 양파, 마늘, 감자, 찹쌀가루를\\n넣고 간다.\",\"4. 갈아 놓은 감자에 양념된 닭살과\\n달걀을 섞는다.\",\"5. 4번을 잘 치대 떡갈비 모양으로 만든다.\",\"6. 팬에 기름을 살짝 두르고 떡갈비를\\n앞뒤로 구워 익힌다.\"]},{\"id\":\"k251\",\"title\":\"겨자아욱쌈밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00615_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00615_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00615_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00615_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00615_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00615_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00615_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"현미(200g)\",\"두부(100g)\",\"아욱(100g)\",\"날치알(50g)\",\"단호박(1/6개)\",\"새싹(20g)\",\"된장(20g)\",\"생크림(20g)\",\"매실청(20g)\",\"참기름(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소량의 된장을 사용하여 삼삼한 맛 뿐만 아니라 쌈밥에 어울리는 된장소스를 만들 수 있어요.\",\"instructions\":[\"1. 현미는 깨끗이 씻어 30분 이상 충분히\\n불린 뒤 밥을 짓는다\",\"2. 두부는 끓는 물에 데쳐 물기를 빼고\\n곱게 다져 된장, 생크림, 매실청을 넣고\\n골고루 섞는다.\",\"3. 데친 두부에 된장, 생크림 및 매실청을\\n골고루 섞는다.\",\"4. 아욱과 단호박은 각각 찐 후 식힌다.\",\"5. 찐 아욱 위에 현미밥을 올리고\\n두부소스, 날치알, 새싹 단호박을\\n올린다.\",\"6. 아욱에 올린 밥을 동그랗게 말아\\n접시에 담는다.\"]},{\"id\":\"k252\",\"title\":\"다마고도후\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00616_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00616_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00616_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00616_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00616_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00616_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00616_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀(1개)\",\"다시마(10g)\",\"요리술(10g)\",\"저염간장(5g)\",\"날치알(20g)\",\"말린 매생이(10g)\",\"무순(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마와 매생이를 천연조미료로 사용하여 나트륨 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 물에 다시마를 넣고 약 10분 정도 끓인\\n뒤 걸러 육수를 만든다.\",\"2. 달걀과 다시마 육수를 1:1로 섞고 체에\\n거른다.\",\"3. ?를 체에 내린다.\",\"4. 달걀물에 매생이를 풀어둔다.\",\"5. 매생이를 풀어 놓은 달걀물에 요리술을\\n넣어 섞는다.\",\"6. 쪄낸 다마고도후에 날치알을 올려\\n완성한다.\"]},{\"id\":\"k253\",\"title\":\"단호박생채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00617_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00617_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00617_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00617_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00617_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00617_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00617_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(1/2개)\",\"부추(30g)\",\"양파(30g)\",\"까나리액젓(20g)\",\"건새우(20g)\",\"다시마(10g)\",\"매실액(20g)\",\"마늘(10g)\",\"배(1/4개)\",\"고춧가루(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마와 건새우 육수가 천연조미료 역할을 해요.\",\"instructions\":[\"1. 다시마, 건새우, 물을 약 20분 정도\\n끓인 뒤 체에 걸러 육수를 만든다.\",\"2. 단호박은 껍질을 벗기고, 속을 깨끗이\\n파내 슬라이스 한다\",\"3. 슬라이스한 단호박을 까나리액젓에\\n20분 정도 절인 뒤 물로 씻는다.\",\"4. 부추는 5cm 길이로 썰고, 양파는\\n채썰고, 배는 껍질을 벗겨 슬라이스로\\n썰어둔다.\",\"5. 만들어 놓은 육수에 고춧가루, 매실액,\\n다진마늘을 섞어 양념장을 만든다\",\"6. 단호박, 배, 양파, 부추를 양념장에\\n버무린다.\"]},{\"id\":\"k254\",\"title\":\"닭가슴살 스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00618_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00618_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00618_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00618_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00618_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00618_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00618_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"150g)\",\"토마토(100g)\",\"가지(1개)\",\"치즈(1장)\",\"오레가노(2g)\",\"마늘(20g)\",\"소금(0.2g)\",\"후춧가루(0.01g)\",\"올리브오일(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치즈를 사용하여 별도의 소금 사용 없이 삼삼한 맛을 낼 수 있어요.\",\"instructions\":[\"1. 닭가슴살을 소금과 후추로 밑간한다.\",\"2. 토마토와 마늘은 입자있게 다진다\",\"3. 다진 토마토와 마늘을 냄비에 담아\\n볶다가 물과 오레가노를 넣고 끓여\\n소스를 만든다.\",\"4. 팬에 올리브오일을 두르고 밑간 한\\n닭가슴살을 노릇노릇하게 굽는다.\",\"5. 가지는 길게 썬다.\",\"6. 가지에 치즈를 감싸 익히고, 구운 닭\\n스테이크를 옆에 담고 소스를 옮긴다.\"]},{\"id\":\"k255\",\"title\":\"마늘드레싱을 곁들인 키위샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00077_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00077_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00077_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00077_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●키위샐러드 : 키위 60g(1개)\",\"방울토마토 100g(10개)\",\"양상추 70g(2장)\",\"아몬드 10g(6알)\",\"땅콩 10g(10알)\",\"무순 약간\",\"●마늘 드레싱 : 사과식초 30g(2큰술)\",\"설탕 15g(1큰술)\",\"물 50ml(1/4컵)\",\"다진 마늘 5g(1작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"마늘드레싱은 기존의 나트륨 함량이 높은 샐러드 드레싱을 대신하여 사용하면 나트륨을 줄일 수 있을 뿐만 아니라 식전 애피타이저로 활용해도 좋아요.\",\"instructions\":[\"1. 그릇에 다진 마늘, 사과식초, 설탕, 물을 섞어 설탕이 녹을 때까지 저어 마늘 드레싱을 만든다.\",\"2. 양상추는 찬물에 담갔다가 물기를 빼서 한입 크기로 찢고, 무순은 손질하여 물기를 빼고, 방\\n울토마토는 꼭지를 떼고 반으로 자른다.\",\"3. 키위는 껍질을 벗기고 둥근 모양으로 썰고 그릇에 양상추, 방울토마토, 키위, 아몬드, 땅콩을 넣고 마늘 드레싱에 버무려 접시에 담아 무순을 곁들인다.\"]},{\"id\":\"k256\",\"title\":\"깻잎향을 입힌 관자 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00078_1.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00078_1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00078_2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00078_3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00078_4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00078_5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00078_6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돌나물(10g)\",\"깻잎(3장)\",\"관자(5개)\",\"식용 꽃(약간)\",\"올리브유(60g)\",\"석류 원액(3g)\",\"레시틴가루(0.5)\",\"후춧가루(약간)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 샐러드드레싱에 소금 대신 석류 원액과 깻잎을 사용해 새콤달콤한 맛과 향을 더하고 소금 사용량을 줄였어요.\",\"instructions\":[\"1. 돌나물은 손질하여 찬물에 담갔다가 물기를 빼고, 깻잎은 씻어 한 장씩 앞뒤로 물기를 닦고, 식용 꽃은 찬물에 담가 놓는다.\",\"2. 튀김 팬에 올리브유(50g)를 붓고 예열해 깻잎을 넣어 바삭하고 투명하게 튀긴 뒤 건지고 팬에 남은 깻잎 기름은 따로 둔다.\",\"3. 석류 원액에 물(100ml)과 레시틴가루를 넣어 블렌더로 섞어 석류 거품을 만든다.\",\"4. 관자는 막을 제거한 뒤 찬물에 씻고, 잘게 칼집을 내 후춧가루를 뿌린다.\",\"5. 달군 팬에 올리브유(10g)를 두르고 관자를 넣어 겉은 노릇하게 굽는다.\",\"6. 접시에 튀긴 깻잎, 돌나물, 구운 관자, 깻잎 기름을 순서대로 담고, 석류 거품을 올려 마무리한다.\"]},{\"id\":\"k257\",\"title\":\"건강그린 샐러드와 고소한 두유드레싱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00082_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00082_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00082_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00082_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●건강그린 샐러드 : 양상추 40g(1장)\",\"치커리 10g(3줄기)\",\"레드치커리 10g(3줄기)\",\"방울토마토 40g(4개)\",\"주황 파프리카 10g(5ⅹ3cm)\",\"●두유 드레싱 : 두유 40g(2⅔큰술)\",\"마요네즈 15g(1큰술)\",\"물엿 3g(2/3작은술)\",\"식초 3g(2/3작은술)\",\"물 15ml(1큰술)\",\"설탕 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"콩에 함유된 이소플라본은 여성호르몬인 에스트로겐과 유사한 역할을 하여 골다공증과 유방암을 예방하는 효과가 있어요. 콩에 풍부한 칼슘과 마그네슘은 나트륨을 효과적으로 배출하도록 도와주므로 콩이나 두유의 섭취를 늘려보세요.\",\"instructions\":[\"1. 두유, 마요네즈, 물엿, 식초, 설탕, 물을 잘 섞어서 두유 드레싱을 만든다.\",\"2. 양상추, 치커리, 레드치커리는 찬물에 담갔다가 물기를 빼서 한입 크기로 찢고 방울토마토는 꼭지를 떼고 반으로 자른다.\",\"3. 주황 파프리카는 얇게 채를 썰고 그릇에 양상추, 치커리, 레드치커리, 파프리카, 방울토마토를 담고 두유 드레싱을 곁들인다.\"]},{\"id\":\"k258\",\"title\":\"케일 오미자 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00085_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00085_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00085_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00085_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00085_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"케일 샐러드\",\"보라로즈케일 15g(3장)\",\"흰로즈케일 15g(3장)\",\"케일 15g(3장)\",\"오미자 드레싱\",\"오미자물 100g(1/2컵)\",\"요리당 15g(1큰술)\",\"식초 2g(1/2작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"일반적인 샐러드드레싱에는 마요네즈나 기타 나트륨이 다량 함유된 제품들이 많이 있지만 오미자의 새콤달콤함을 활용하여 만든 드레싱은 소금을 첨가하지 않아도 감칠맛을 낼 수 있어요. 케일에는 섬유소가 많아 혈중 콜레스테롤을 감소시키고 동맥경화 예방에 도움이 되요.\",\"instructions\":[\"1. 케일은 깨끗이 씻어 잎은한입 크기로 자르고 줄기는 잘게 다진다.\",\"2. 오미자물, 요리당, 식초를 섞는다.\",\"3. (1)의 케일의 다진 줄기를 넣어 드레싱을 만든다.\",\"4. 그릇에 케일을 담고 오미자 드레싱을 끼얹는다.\"]},{\"id\":\"k259\",\"title\":\"꼬막 달래 된장 무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00163_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00163_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00163_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00163_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 꼬막 1000g\",\"달래 100g(2단)\",\"깻잎 10g(10장)\",\"파프리카 100g(1개)\",\"●소스 : 된장 15g(1큰술)\",\"고추장 5g(1작은술)\",\"사과즙 300g(1/2컵)\",\"참기름 20g(1⅓큰술)\",\"깨 15g(1큰술)\",\"다진 마늘 10g(2작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고유의 향을 가진 깨와, 참기름, 사과즙 등을 활용하여 된장의 양을 줄이고 다양한 채소를 곁들여 비타민과 무기질 공급에 도움을 주고 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 된장, 고추장, 사과즙, 깨, 다진 마늘, 참기름을 넣어 소스를 만든다.\",\"2. 꼬막을 30분간 소금물에 해감시킨 후 끓는 물에 10분 데친다.\",\"3. 달래, 깻잎, 파프리카를 5cm로 썰고 꼬막과 달래, 깻잎, 파프리카에 소스를 넣고 버무린다.\"]},{\"id\":\"k260\",\"title\":\"베이컨 가지 말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00165_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00165_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00165_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00165_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 가지 150g(1/2개)\",\"베이컨 80g(8장)\",\"홍파프리카 50g(1/2개)\",\"황파프리카 50g(1/2개)\",\"청파프리카 50g(1/2개)\",\"미나리 30g\",\"●소스 : 고추장 5g(1작은술)\",\"와사비 1g(1/3작은술)\",\"고춧가루 2g(1/2작은술)\",\"배 10g(2cm)\",\"양파 2g(1cm)\",\"마늘 1g(1/5개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"베이컨은 끓는 물에 데쳐 염분을 제거하고 칼륨이 다량 함유된 가지와 함께 섭취하도록 하여 나트륨 배출에 도움을 준다. 소스에 와사비, 식초, 올리고당을 넣어 매운맛과 새콤달콤한 맛을 준다.\",\"instructions\":[\"1. 마늘, 양파, 배는 다지고 고추장, 와사비, 고춧가루, 올리고당, 사과식초와 함께 섞어 고추장 소스를 만든다.\",\"2. 가지는 길게 자르고, 미나리는 잎을 떼고, 파프리카는 채 썬다.\",\"3. 가지는 찌고, 미나리와 베이컨은 데친 후 베이컨, 가지, 파프리카 순으로 올려 말아준 뒤 미나리로 묶어 접시에 담고 소스를 뿌려 완성한다.\"]},{\"id\":\"k261\",\"title\":\"청국장소스 연어 스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00172_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00172_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00172_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00172_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 마늘종 60g(10개)\",\"연어 200g\",\"식용유 5g(1/2작은술)\",\"●소스 : 검정깨 5g(1작은술)\",\"청국장가루 5g(1작은술)\",\"마요네즈 20g(4작은술)\",\"●장식 : 대추 5g(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연어에 함유된 오메가3지방산은 동맥경화와 심장병을 예방하는 효과가 있다. 소스에는 청국장가루와 검정깨를 사용해 고소한 향과 풍미를 더한다.\",\"instructions\":[\"1. 검정깨, 마요네즈, 청국장 가루를 섞어 소스를 만든다.\",\"2. 팬에 식용유를 둘러 연어와 마늘종을 굽는다.\",\"3. 마늘종을 접시에 깔고 연어를 올린 뒤 소스를 뿌리고 채썬 대추채를 얹어 장식한다.\\n대추채를 얹어 장식한다.\"]},{\"id\":\"k262\",\"title\":\"두부곤약조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00258_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00258_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00258_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00258_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00258_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00258_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 곤약(100g)\",\"두부(100g)\",\"가지(20g)\",\"애호박(20g)\",\"꽈리고추(15g)\",\"조림장 감자전분(6g)\",\"저염간장(3g)\",\"물(165g)\",\"다진 마늘(2g)\",\"유자청(10g)\",\"고추기름(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장을 사용해 나트륨을 줄이면서 유자청으로 간을 맞췄다.\\n가지와 애호박은 칼륨을 많이 함유하고 있어 나트륨 배출을 돕는다.\\n또한 곤약과 달걀옷을 입힌 두부에는 양념이 적게 스며들어 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 곤약과 두부는 사방 1㎝ 크기로\\n깍둑 썰고, 가지와 애호박은 조금\\n더 작은 크기로 썰고, 꽈리고추는\\n얇게 송송 썬다.\",\"2. 곤약을 끓는 물에 식초를 한두 방울\\n떨어뜨린 후 삶아 냄새를 제거한 후\\n찬물에 식힌다.\",\"3. 올리브유(10g)를 두른 팬에 두부를\\n올려 살짝 굽는다.\",\"4. 팬에 조림장을 넣은 후 약한 불에서\\n저어가며 끓이다가 조림장이 고루\\n섞이면 곤약과 두부, 가지, 애호박을\\n모두 넣고 조린다.\",\"5. 조림장이 반 이상 졸아들면\\n꽈리고추를 넣고 조금 더 조려\\n마무리한다.\"]},{\"id\":\"k263\",\"title\":\"아귀나가사키조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00259_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00259_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00259_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00259_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00259_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00259_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 미나리(10g)\",\"숙주(10g)\",\"양파(10g)\",\"대파(10g)\",\"청양고추(5g)\",\"붉은 고추(5g)\",\"아스파라거스(5g)\",\"문어(20g)\",\"꽃게(30g)\",\"조개(30g)\",\"전복(30g)\",\"소라(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해물육수를 사용해 감칠맛을 내고,\\n해산물을 한 번 데쳐 염분을 제거한 후 조리해 염도를 낮췄다.\",\"instructions\":[\"1. 미나리, 숙주는 적당한 길이로 썰고,\\n양파는 채 썰고, 대파, 고추,\\n아스파라거스는 어슷하게 썬다.\",\"2. 해산물을 끓는 물에 데친다.\",\"3. 해산물 데친 물에 육수 재료를 넣고\\n끓인 뒤 체에 걸러 육수를 만든다.\",\"4. 냄비에 데친 해산물과 미나리, 숙주,\\n양파, 대파, 청양고추, 아스파라거스,\\n붉은 고추를 얹은 뒤 육수를 넣어\\n끓인다.\",\"5. 녹말물을 넣어 농도를 맞춘 뒤 조려\\n마무리한다.\"]},{\"id\":\"k264\",\"title\":\"카레가자미조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00260_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00260_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00260_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00260_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00260_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00260_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00260_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 고구마(10g)\",\"당근(10g)\",\"양파(10g)\",\"파프리카(30g)\",\"양송이버섯(10g)\",\"브로콜리(8g)\",\"가자미(50g)\",\"밀가루(15g)\",\"달걀(30g)\",\"버터(10g)\",\"치킨스톡(200g)\",\"코코넛 밀크(14g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레의 양을 줄여 나트륨 섭취를 줄이는 대신 코코넛 밀크와 생크림으로 부드러운 맛을 더했다\",\"instructions\":[\"1. 고구마, 당근, 양파, 파프리카는 깍둑\\n썰고, 양송이버섯은 4등분해 썰고,\\n브로콜리는 먹기 좋게 썬다.\",\"2. 가자미에 밀가루, 달걀물을 묻혀\\n버터를 두른 팬에 바삭하게 굽는다.\",\"3. 식용유를 두른 팬을 약한 불로\\n달궈 다진 마늘을 볶다가\\n토마토페이스트를 넣어 볶는다.\",\"4. 당근, 양파, 고구마를 넣어 볶다가\\n브로콜리와 치킨스톡, 카레가루,\\n강황가루을 넣어 잘 섞어 끓인다.\",\"5. 코코넛 밀크와 생크림, 파프리카,\\n양송이버섯을 넣어 살짝 더 끓인다.\",\"6. 구운 가자미와 청양고추를 넣고\\n조려 마무리한다.\"]},{\"id\":\"k265\",\"title\":\"타콤소스닭조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00261_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00261_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00261_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00261_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00261_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00261_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00261_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 양파(80g)\",\"셀러리(15g)\",\"당근(15g)\",\"사과(30g)\",\"양송이버섯(20g)\",\"새송이버섯(17.5g)\",\"가지(15g)\",\"토마토(125g)\",\"단호박(35g)\",\"브로콜리(25g)\",\"닭가슴살(150g)\",\"닭육수(200g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스를 만들 때 닭육수를 사용해 소금을 사용하지 않아도\\n깊은 맛을 내 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 양파와 셀러리, 당근, 사과, 버섯은\\n잘게 다지고, 가지, 양파는 한입\\n크기로 썰고, 토마토는 십자로\\n칼집을 내고 살짝 데쳐 껍질을\\n벗긴 뒤 씨를 제거해 다진다.\",\"2. 단호박과 브로콜리는 한입 크기로\\n썰어 데친다.\",\"3. 닭가슴살은 칼집을 내 닭밑간양념한\\n뒤 팬에 식용유(10g)를 둘러\\n80%정도 익힌다.\",\"4. 팬에 식용유를 두르고 다진 마늘을\\n먼저 볶다가 양파와 셀러리, 당근을\\n넣어 볶고, 양파가 투명하게 변하면\\n사과와 버섯을 넣어 볶는다.\",\"5. 토마토를 넣어 3분 정도 더 볶다가\\n닭육수와 월계수잎을 넣어 5분 정도\\n푹 끓인 뒤 한 김 식혀 오레가노와\\n바질을 넣고 믹서기에 곱게 갈아\\n타콤소스를 만든다.\",\"6. 단호박과 브로콜리, 양파, 가지를\\n센 불에서 빠르게 볶은 뒤 닭고기와\\n타콤소스를 넣어 조리다가 닭고기가\\n다 익으면 접시에 담고,\\n파슬리가루를 뿌려 마무리.\"]},{\"id\":\"k266\",\"title\":\"토마토콩조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00262_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00262_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00262_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00262_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00262_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00262_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 콩(대두\",\"100g)\",\"양파(50g)\",\"양송이버섯(30g)\",\"토마토(200g)\",\"양념 설탕(4g)\",\"후춧가루(2g)\",\"파슬리가루(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금이나 토마토 페이스트를 쓰지 않아 나트륨 함량을 줄였다.\\n또한 토마토와 콩, 양송이버섯은 칼륨 함량이 풍부해 나트륨 배출에 도움이 된다\",\"instructions\":[\"1. 콩을 충분히 불린 후 냄비에 물과\\n함께 넣고 삶는다.\",\"2. 양파와 버섯은 곱게 다진다.\",\"3. 토마토를 끓는 물에 데쳐 껍질을\\n벗긴 뒤 으깨 팬에서 끓인다.\",\"4. 양파와 버섯을 넣고 끓여 숨이\\n죽으면 설탕과 후춧가루로 간을\\n한다.\",\"5. 삶은 콩을 넣고 조린 뒤\\n파슬리가루를 뿌려 마무리한다.\"]},{\"id\":\"k267\",\"title\":\"관자해장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00263_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00263_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00263_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00263_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00263_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00263_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00263_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 풋고추(2g)\",\"붉은 고추(1g)\",\"무(80g)\",\"당근(30g)\",\"양파(50g)\",\"노란 파프리카(30g)\",\"두부(100g)\",\"육수 콩나물(80g)\",\"다시마(7g)\",\"관자(70g)\",\"물(300g)\",\"토마토소스 토마토(200g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨을 많이 함유한 토마토를 이용한 소스로 간을 해 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 고추는 어슷 썰고, 무, 당근, 양파,\\n노란 파프리카, 두부는 납작하게\\n썬다.\",\"2. 토마토소스 재료를 믹서에 갈아\\n토마토소스를 만든다.\",\"3. 두부를 제외한 납작 썬 재료를\\n식용유(5g)를 두른 팬에 볶다가 갈아\\n놓은 토마토소스를 함께 넣어 볶아\\n토마토채소소스를 만든다.\",\"4. 냄비에 육수 재료를 넣고\\n끓어오르면 다시마를 건진 뒤 다진\\n마늘을 넣고 다시 끓어오르면\\n콩나물과 관자를 건져내 따로 둔다.\",\"5. 육수에 토마토채소소스를 넣어 끓인\\n후, 마지막으로 두부를 넣어 약 2분\\n정도 끓인다.\",\"6. 그릇에 담고 덜어놓았던 콩나물과\\n관자, 고추를 올려 마무리한다.\"]},{\"id\":\"k268\",\"title\":\"견과류들깨해장탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00264_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00264_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00264_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00264_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00264_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 느타리버섯(20g)\",\"양송이버섯(20g)\",\"표고버섯(20g)\",\"두부(40g)\",\"애호박(40g)\",\"양파(30g)\",\"밤(30g)\",\"호두(10g)\",\"멸치다시마육수(300g)\",\"양념 들기름(10g)\",\"들깻가루(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장으로 간을 하는 기본 탕과는 달리 들깻가루를 사용해\\n나트륨 함량을 줄이면서 고소한 맛을 더했다.\",\"instructions\":[\"1. 느타리버섯, 양송이버섯, 표고버섯,\\n두부, 애호박, 양파, 껍질 벗긴 밤은\\n사방 1cm로 깍뚝 썰고, 호두는\\n반으로 가른다.\",\"2. 뚝배기에 들기름을 두르고 호두와\\n밤을 살짝 볶은 후 두부를 제외한\\n재료를 넣고 볶는다.\",\"3. 멸치다시마육수를 넣고 끓인다.\",\"4. 들깻가루와 두부를 넣고 걸쭉하게\\n끓여 마무리한다.\"]},{\"id\":\"k269\",\"title\":\"뿌리채소들깨수제비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00265_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00265_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00265_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00265_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00265_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00265_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00265_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 다시마(2g)\",\"감자(20g)\",\"연근(20g)\",\"마른 미역(2g)\",\"새알심 찹쌀가루(40g)\",\"물(25g)\",\"소금(0.1g)\",\"양념 들기름(5g)\",\"다진 마늘(15g)\",\"들깻가루(50g)\",\"국간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"미역과 감자, 연근은 칼륨을 많이 함유하고 있어 나트륨 배출을 돕는다.\\n또한 들깻가루로 고소한 맛을 내 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 냄비에 다시마와 물(250g)을 넣고\\n중간 불에서 끓여 끓어오르면\\n다시마를 건진다.\",\"2. 감자와 연근은 껍질을 벗겨 깍둑\\n썰고 물에 헹궈 전분기를\\n제거한다.\",\"3. 마른 미역은 미지근한 물에 담가\\n불린 후 손으로 바락바락 주물러\\n한입 크기로 썬다.\",\"4. 찹쌀가루에 물(25g)과 소금(0.1g)을\\n넣고 반죽해 작은 새알심을 만든다.\",\"5. 냄비에 들기름을 두르고 미역과\\n다진 마늘을 넣고 볶다가\\n다시마물과 감자, 연근을 넣고\\n끓인다.\",\"6. 감자가 익을 때쯤 새알심을 넣어\\n익힌 후 들깻가루를 넣고\\n국간장으로 간을 해 마무리한다.\"]},{\"id\":\"k270\",\"title\":\"대구지리탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00266_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00266_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00266_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00266_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00266_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00266_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00266_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 대구(150g)\",\"미나리(15g)\",\"청양고추(1g)\",\"붉은 고추(1g)\",\"콩나물(25g)\",\"쑥갓(10g)\",\"반죽 쑥가루(10g)\",\"밀가루(20g)\",\"육수 다시마(1g)\",\"북어(15g)\",\"무(30g)\",\"물(500g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 쑥을 넣어 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 대구는 비늘과 내장을 제거하고\\n흐르는 물에 씻어 비린 향을 없앤다.\",\"2. 미나리는 6cm 길이로 썰고,\\n청양고추, 붉은 고추는 어슷하게\\n썰고, 콩나물, 쑥갓을 씻어 준비한다.\",\"3. 쑥가루와 밀가루를 섞고 물(15g)을\\n조금씩 넣어가며 매끈해지도록\\n반죽한 뒤 30분~1시간 정도\\n숙성시킨다.\",\"4. 냄비에 육수 재료를 넣어 10분간\\n끓여 육수를 만든다.\",\"5. 다진 마늘과 생강을 넣고 향이\\n우러나면 대구를 넣은 뒤 대구가\\n어느 정도 익으면 콩나물을 넣고,\\n끓어오르면 수제비 반죽을 떼어\\n넣는다.\",\"6. 청양고추, 붉은 고추를 넣고 한소끔\\n더 끓이다가 미나리와 쑥갓을\\n얹은 뒤 바로 불을 꺼 마무리한다.\"]},{\"id\":\"k271\",\"title\":\"양지해장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00267_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00267_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00267_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00267_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00267_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00267_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00267_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 쇠고기육수(30g)\",\"느타리버섯(10g)\",\"애호박(20g)\",\"청양고추(1g)\",\"대파(10g)\",\"방울토마토(80g)\",\"콩나물(50g)\",\"양념 다진 마늘(8g)\",\"저염국간장(2.5g)\",\"소금(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장으로 간을 해 염분을 줄이고 콩나물로 시원한 맛을 내고, 쇠고기육수로 깊은 맛을 더했다.\\n칼륨을 많이 함유한 토마토는 체내 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 육수를 끓인 양지는 건져 얇게 썬다.\",\"2. 버섯은 잘게 찢고, 애호박은\\n반달모양으로 납작 썰고, 고추와\\n대파는 어슷하게 썬다.\",\"3. 방울토마토에 열십자로 칼집을 넣고\\n끓는 물에 데쳐 껍질을 벗긴다.\",\"4. 냄비에 식용유(10g)를 두른 뒤\\n다진 마늘을 넣고 볶아 향을 낸 뒤\\n방울토마토를 넣고 볶는다.\",\"5. 육수(300g), 콩나물, 쇠고기,\\n느타리버섯, 애호박을 넣고 국간장과\\n소금으로 간해 끓인다.\",\"6. 어슷 썬 청양고추와 대파를 넣어\\n마무리한다.\"]},{\"id\":\"k272\",\"title\":\"토마토돼지고기해장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00268_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00268_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00268_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00268_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00268_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00268_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00268_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 양파(40g)\",\"청양고추(3g)\",\"토마토(250g)\",\"돼지고기(사태\",\"60g)\",\"방울토마토(60g)\",\"육수 무(20g)\",\"다시마(3g) 대파(10g)\",\"마른 표고버섯(3g)\",\"양파(30g)\",\"물(400g)\",\"양념 다진 마늘(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토에는 100g당 270㎎의 칼륨이 들어있어 나트륨 배출을 돕는다.\\n청양고추와 다진 마늘을 넣어 칼칼한 맛을 더해 소금간을 줄일 수 있다.\",\"instructions\":[\"1. 냄비에 육수 재료를 넣고 10분 정도\\n끓여 체에 걸러 육수를 만든다.\",\"2. 양파는 채 썰고, 고추는 어슷 썰고,\\n토마토는 잘게 다진다.\",\"3. 돼지고기는 1.5cm 크기로 깍둑썰기\\n하고, 핏물을 제거한다.\",\"4. 냄비에 육수를 붓고 다진 토마토와\\n다진 마늘, 바질가루를 넣고 끓인다.\",\"5. 걸쭉해지면 설탕과 돼지고기를 넣고,\\n고기가 익으면 채 썬 양파, 어슷\\n썬 청양고추와 꼭지를 딴\\n방울토마토를 넣는다.\",\"6. 방울토마토의 껍질이 벗겨질 때까지\\n끓이고 후춧가루를 넣어 마무리한다.\"]},{\"id\":\"k273\",\"title\":\"효종갱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00269_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00269_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00269_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00269_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00269_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00269_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00269_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 배추(20g)\",\"무(10g)\",\"느타리버섯(20g)\",\"표고버섯(20g)\",\"전복(100g)\",\"육수 쇠고기(양지 50g\",\"갈비 50g)\",\"양파(40g)\",\"마늘(10g)\",\"물(300g)\",\"양념 저염간장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장으로 간을 해 염도를 낮춘 대신 쇠고기와 전복으로 깊은 맛을 더했다\",\"instructions\":[\"1. 쇠고기는 핏물을 제거한 뒤 양파,\\n마늘을 넣고 물(300g)을 부어 1시간\\n이상 끓인 뒤 면포에 걸러 육수를\\n만든다.\",\"2. 삶은 쇠고기는 건져내 결 반대\\n방향으로 썬다.\",\"3. 배추, 무, 느타리버섯, 표고버섯은\\n먹기 좋은 크기로 썬다.\",\"4. 전복은 깨끗이 손질한다.\",\"5. 육수를 끓인 뒤 끓어오르면 무를\\n넣어 반투명해지면 배추, 버섯,\\n전복을 넣는다.\",\"6. 전복이 익으면 쇠고기를 넣고\\n저염간장으로 간을 해 마무리한다.\"]},{\"id\":\"k274\",\"title\":\"해물토마토김치찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00270_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00270_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00270_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00270_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00270_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00270_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 김치(40g)\",\"토마토(30g)\",\"양파(40g)\",\"오징어(15g)\",\"홍합(20g)\",\"바지락(15g)\",\"주꾸미(25g)\",\"데친 미나리(2g)\",\"쑥갓(5g)\",\"느타리버섯(7g)\",\"팽이버섯(7g)\",\"어슷 썬 풋고추(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해산물로 시원한 맛을 내고 따로 간을 하지 않아 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 김치를 씻은 뒤 줄기부분은 한입\\n크기로 썰고, 잎은 따로 두고,\\n토마토, 양파도 비슷한 크기로 썬다.\",\"2. 오징어는 칼집을 넣고, 홍합,\\n바지락, 주꾸미와 함께 살짝 데친 뒤\\n식용유(10g) 두른 팬에 볶는다.\",\"3. 새우, 부추, 불린 당면과 무말랭이는\\n다진 뒤 녹말가루와 달걀을 넣어\\n반죽해 김치주머니 소를 만든다.\",\"4. 김치 잎에 소를 넣고 주머니\\n모양으로 감싸 데친 미나리로\\n묶는다.\",\"5. 김치와 채소를 볶아 냄비에 담은 뒤\\n해산물과 김치주머니를 넣고\\n끓이다가 끓어오르면 쑥갓,\\n느타리버섯, 팽이버섯, 고추를 올려\\n마무리한다.\"]},{\"id\":\"k275\",\"title\":\"버섯 두유 소스 볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00018_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00018_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00018_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00018_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"버섯볶음\",\"새송이버섯 100g(3개)\",\"올리브유 10g(2작은술)\",\"두유 소스\",\"두유 20g(1⅓큰술)\",\"생크림 10g(2작은술)\",\"청양고추 5g(1/2개)\",\"후추 약간\",\"곁들임\",\"새싹채소 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두유와 생크림으로 고소한 맛을 내어 짠맛을 대신해 줘요. 두유는 식사대용으로 먹을 정도로 영양이 우수하며, 두유를 소스에 사용하면 생크림 사용량을 줄일 수 있어 지방섭취를 줄일 수 있어요. 두유 200ml에 125kcal의\\n열량이 있으므로 당뇨 환자의 경우 한잔 정도가 적당해요\",\"instructions\":[\"1. 새송이버섯은 굵게 채썬 후 달군 프라이팬에 기름을 두르고 노릇하게 볶는다.\",\"2. 소스 팬에 두유, 생크림, 청양고추, 후추를 넣고 약한 불에 뭉근하게 졸인다.\",\"3. 볶은 새송이버섯을 소스에 넣고 고루 섞어 가며 조금 더 볶아 접시에 담은 후 새싹채소를 함께 곁들인다.\"]},{\"id\":\"k276\",\"title\":\"백일송이버섯 볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00019_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00019_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00019_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00019_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"백일송이버섯볶음\",\"백일송이버섯 65g(1컵)\",\"노랑 파프리카 5g(5×1cm)\",\"빨강 파프리카 5g(5×1cm)\",\"카놀라유 3g(2/3작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파프리카에 함유된 칼륨, 철분, 구리, 아연 성분은 체내 나트륨 수치를 낮추는 효과가 있으며, 백일송이버섯은 나트륨 함량이 높은 생선이나 육류 요리와 함께 섭취하면 나트륨 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 파프리카는 씨를 빼고 버섯 크기와 비슷하게 썬다.\",\"2. 달구어진 팬에 카놀라유를 두르고 백일송이 버섯을 볶는다.\",\"3. 버섯이 살짝 숨이 죽으면 파프리카를 넣어 함께 볶아 접시에 담는다.\"]},{\"id\":\"k277\",\"title\":\"땅콩소스 버섯가지나물\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030010_1678341610669.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030103_1678341663088.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030120_1678341680752.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313032425_1678688665992.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313032438_1678688678164.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030208_1678341728057.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 가지(15g)\",\"새송이버섯(15g)\",\"표고버섯(10g)\",\"•땅콩 소스 : 땅콩가루(5g)\",\"다진마늘(2g)\",\"참기름(2g)\",\"저염간장(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•땅콩과 저염간장으로 만든 소스로 나트륨 섭취를 줄이고 짠맛을 고소한 맛으로 대체했어요.\",\"instructions\":[\"1. 가지는 꼭지를 떼어 편으로 썬다.\",\"2. 새송이버섯은 길게 편으로 썰고, 표고버섯은 기둥을 떼고 납작하게 썬다.\",\"3. 가지와 버섯은 끓는 물에 각각 데친 후 찬물에 식힌다.\",\"4. 땅콩소스 재료를 섞어 땅콩소스를 만든다.\",\"5. 데친 가지와 버섯은 물기를 제거해 그릇에 담고, 땅콩소스를 곁들여 마무리한다.\"]},{\"id\":\"k278\",\"title\":\"유자향의 곤약 냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00096_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00096_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00096_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00096_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●곤약냉채 : 실곤약 50g\",\"오이 30g(3cm)\",\"사과 20g(1/8개)\",\"당근 15g(1/10개)\",\"빨강 파프리카 10g(5ⅹ3cm)\",\"●유자 드레싱 : 유자청 25g(1⅔큰술)\",\"레몬즙 10g(2작은술)\",\"카놀라유 3g(2/3작은술)\",\"흰후추 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"유자는 레몬의 3배가 넘는 비타민 C를 함유하고 있어 기관지 천식, 기침, 피부미용, 스트레스 해소에 좋아요.\\n유자소스의 새콤달콤한 맛으로 소금간을 대신하여 나트륨 함량을 줄일 수 있어요.\",\"instructions\":[\"1. 유자청, 레몬즙, 카놀라유, 흰 후추를 넣어 유자 드레싱을 만든다.\",\"2. 실곤약은 끓는 물에 데치고 찬물에 헹궈 물기를 빼준다. 오이, 사과, 당근, 빨강 파프리카는 4cm 길이로 가늘게 채 썬다.\",\"3. 실곤약, 오이, 사과, 당근, 빨강 파프리카에 유자 드레싱을 섞어 버무린다.\"]},{\"id\":\"k279\",\"title\":\"새우단배추된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00284_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00284_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00284_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00284_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00284_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00284_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00284_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 마늘(0.3g)\",\"양파(10g)\",\"애호박(20g)\",\"단배추(25g)\",\"대파(5g)\",\"두부(25g)\",\"마른 새우(10g)\",\"육수 무(15g)\",\"멸치(2.5g)\",\"다시마(2.5g)\",\"물(300g)\",\"양념 된장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장에 콩가루와 표고버섯가루를 섞어 염분을 줄이고\\n마른 새우로 감칠맛을 더해 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 냄비에 육수 재료를 넣고 10분간\\n끓여 건진다.\",\"2. 마늘은 다지고, 양파는 채 썰고,\\n애호박은 반달모양으로 납작하게\\n썬다.\",\"3. 단배추는 5cm로 썰고, 대파는\\n어슷 썰고, 두부는 0.5cm 두께로\\n썬다.\",\"4. 된장에 표고버섯가루, 날콩가루,\\n육수(50g)를 넣어 섞는다.\",\"5. 육수에 된장을 풀고 다진 마늘, 호박,\\n양파, 단배추 순으로 넣어가며\\n끓인다.\",\"6. 끓으면 마른 새우, 대파를 넣어 살짝\\n더 끓여 마무리한다.\"]},{\"id\":\"k280\",\"title\":\"검은콩보리된장찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00285_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00285_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00285_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00285_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00285_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00285_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00285_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 검은콩(30g)\",\"애호박(30g)\",\"양파(20g)\",\"검은콩두부(30g)\",\"표고버섯(5g)\",\"붉은 고추(2g)\",\"청양고추(2g)\",\"대파(5g)\",\"육수 바지락(20g)\",\"멸치(5g)\",\"다시마(1g)\",\"보리된장 보리(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쪄낸 보리쌀을 된장에 묵혀 된장 사용량을 줄여 나트륨 섭취량을 줄였다.\\n또한 검은콩을 갈아 넣어 나트륨 배출 효과를 높였다.\",\"instructions\":[\"1. 보리를 김 오른 찜기에 넣고 쪄서\\n저염된장과 섞은 뒤 재워\\n보리된장을 만든다.\",\"2. 검은콩은 삶아서 간다.\",\"3. 검은콩 삶은 물(200g)에 바지락,\\n멸치, 다시마를 넣고 끓여 육수를\\n만든다.\",\"4. 애호박, 양파, 검은콩두부,\\n표고버섯은 깍둑 썰고, 붉은 고추,\\n청양고추, 대파는 어슷하게 썬다.\",\"5. 육수에 보리된장을 풀고 호박, 양파,\\n표고버섯을 넣고 끓인다.\",\"6. 갈아놓은 검은콩을 넣어 농도를\\n맞춘 후 검은콩두부, 대파, 고추를\\n넣고 한소끔 끓여 마무리한다.\"]},{\"id\":\"k281\",\"title\":\"단호박배추된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306050313_1678089793329.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313014423_1678682663468.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313014442_1678682682771.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313014508_1678682708772.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313014540_1678682740233.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313014557_1678682757303.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313014618_1678682778547.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 단호박(20g)\",\"배추(50g)\",\"새송이버섯(10g)\",\"홍고추(1g)\",\"•육수 : 대파(50g)\",\"양파(50g)\",\"물(300g)\",\"•양념 : 된장(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•된장을 적게 사용하여 나트륨 섭취를 줄이고 으깬 단호박으로 맛을 냈어요.\\n•단호박은 칼륨 함유량이 높아 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 냄비에 육수 재료를 넣고 10분간\\n끓여 체로 건진다.\",\"2. 단호박은 전자레인지에 2분간 넣고\\n익힌 후 껍질을 벗겨 으깬다.\",\"3. 배추와 새송이버섯을 먹기 좋은\\n크기로 썰고 홍고추는 어슷 썬다.\",\"4. 육수에 단호박을 넣어 잘 풀어준다.\",\"5. 육수에 된장을 풀어 끓인다.\",\"6. 배추와 새송이버섯을 넣어 익힌 후\\n홍고추를 넣고 마무리한다.\"]},{\"id\":\"k282\",\"title\":\"된장냉국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00287_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00287_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00287_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00287_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00287_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00287_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 가다랑어포(5g)\",\"오이(5g)\",\"깻잎(1g)\",\"육수 무(50g)\",\"다시마(1g)\",\"대파(10g)\",\"물(500g)\",\"된장양념 콩가루(1g)\",\"설탕(1.5g)\",\"식초(2g)\",\"다진 대파(0.5g)\",\"다진 마늘(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염된장을 사용해 나트륨을 적게 섭취할 수 있다.\\n콩가루와 식초로 고소함과 새콤달콤한 맛을 더했다.\",\"instructions\":[\"1. 냄비에 육수 재료를 넣어 20분간\\n끓인 뒤 불을 끄고 가다랑어포를\\n넣어 10분간 우려 체에 걸러\\n차갑게 식힌다.\",\"2. 된장양념을 만든다.\",\"3. 오이와 깻잎은 채 썬다.\",\"4. 식힌 육수에 된장양념을 푼다.\",\"5. 채 썬 오이와 깻잎을 올려\\n마무리한다.\"]},{\"id\":\"k283\",\"title\":\"들깨된장육개장\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00288_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00288_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00288_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00288_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00288_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00288_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 숙주(30g)\",\"느타리버섯(25g)\",\"양파(25g)\",\"대파(10g)\",\"청양고추(2g)\",\"얼갈이배추(25g)\",\"육수 무(50g)\",\"돼지고기(사태\",\"25g)\",\"다시마(2g)\",\"청주(1g)\",\"보리새우(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"얼갈이배추에는 칼륨이 많이 들어있어 나트륨 배출을 돕는다.\\n된장과 들깨로 간을 해 육개장의 자극적인 맛을 줄이고 고소하고 담백한 맛을 냈다.\",\"instructions\":[\"1. 냄비에 무, 돼지고기, 다시마를 넣고\\n끓이다가 끓어오르면 다시마를\\n건지고 청주와 보리새우를 넣어\\n약한 불로 끓여 고기가 익으면 체에\\n거른다.\",\"2. 숙주는 끝을 다듬고, 느타리버섯은\\n결대로 찢고, 양파는 채 썰고, 대파와\\n청양고추는 어슷 썰고, 무는\\n납작하게 썬다.\",\"3. 얼갈이배추는 밑동을 잘라 3cm\\n간격으로 썰어 데친 뒤 찬물로 헹궈\\n물기를 짠다.\",\"4. 양념장을 만든 뒤 찢은 고기와\\n얼갈이배추를 넣어 버무린다.\",\"5. 육수에 무, 양념에 버무린 고기와\\n얼갈이배추, 숙주, 느타리버섯, 대파,\\n청양고추 순으로 넣어가며 푹 끓여\\n마무리한다.\"]},{\"id\":\"k284\",\"title\":\"삼색묵냉국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00289_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00289_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00289_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00289_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00289_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00289_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00289_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 도토리묵(50g)\",\"메밀묵(50g)\",\"청포묵(50g)\",\"미니양배추(11g)\",\"적양파(5g)\",\"양파(8g)\",\"오이(8g)\",\"래디시(3g)\",\"당근(5g)\",\"아스파라거스(8g)\",\"파프리카(8g)\",\"붉은 고추(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장은 쪄서 사용하면 염도가 낮아지기 때문에 미소된장을 사용하기 전에\\n김 오른 찜기에 한 번 쪄 사용해 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 찬물에 육수 재료를 넣어 육수를\\n우린다.\",\"2. 육수에 미소된장을 풀어 차갑게\\n식힌다.\",\"3. 묵은 먹기 좋은 크기로 썬다.\",\"4. 미니양배추는 반 자르고, 적양파,\\n양파, 오이, 래디시, 당근,\\n아스파라거스, 파프리카는 채 썰고,\\n고추는 어슷 썰어 준비한다.\",\"5. 달걀은 지단으로 부쳐 채 썰고,\\n목이버섯은 물에 불린다.\",\"6. 육수에 묵을 넣고 색을 맞춰 고명을\\n올린 뒤 들깻가루, 참깨, 검은깨를\\n얹어 마무리한다.\"]},{\"id\":\"k285\",\"title\":\"샤브된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00290_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00290_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00290_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00290_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00290_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00290_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 우삼겹(50g)\",\"깻잎(7.5g)\",\"느타리버섯(20g)\",\"팽이버섯(20g)\",\"쪽파(10g)\",\"송송 썬 청양고추(3g)\",\"송송 썬 붉은 고추(3g)\",\"육수 닭가슴살(50g)\",\"대파(20g)\",\"마늘(10g)\",\"양념 저염된장(5g)\",\"다진 마늘(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염된장을 사용해 나트륨 섭취량을 줄이고\\n닭육수를 사용하고 따로 간을 하지 않아 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 물(600g)에 육수 재료를 넣고 15분간\\n센 불에 끓인 후 10분간 약한 불로\\n끓여 육수를 만든다.\",\"2. 우삼겹을 펼쳐 깔고 그 위에 깻잎,\\n느타리버섯, 팽이버섯 순으로\\n올린다.\",\"3. 돌돌 말고 쪽파로 묶어 고정시킨다.\",\"4. 육수에 저염된장을 풀고 다진\\n마늘을 넣은 뒤 청양고추와 돌돌 만\\n고기를 넣고 약한 불에 살짝 익힌다.\",\"5. 그릇에 담은 뒤 붉은 고추를 올려\\n마무리한다.\"]},{\"id\":\"k286\",\"title\":\"완자된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00291_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00291_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00291_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00291_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00291_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00291_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00291_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 감자(20g)\",\"애호박(15g)\",\"쪽파(5g)\",\"양파(5g)\",\"부추(2g)\",\"두부(15g)\",\"대파(2g)\",\"고추(5g)\",\"표고버섯(5g)\",\"당면(2g)\",\"숙주(5g)\",\"브로콜리(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장을 적게 사용하는 대신 콩가루를 넣어 구수한 맛을 더해 나트륨 섭취량을 줄였다\",\"instructions\":[\"1. 감자는 깍둑 썰고, 애호박은\\n모양대로 썰고, 쪽파, 양파, 부추는\\n잘게 다진다.\",\"2. 두부는 으깨 물기를 제거하고,\\n대파는 송송 썰고, 고추는 어슷 썰고,\\n표고버섯은 먹기 좋은 크기로 썬다.\",\"3. 당면, 숙주는 끓는 물에 데친 뒤\\n다지고, 브로콜리는 끓는 물에 살짝\\n데친다.\",\"4. 볼에 돼지고기, 다진 마늘, 쪽파,\\n양파, 부추, 숙주, 당면, 두부를 넣은\\n뒤 녹말가루를 섞어 반죽해 동글\\n납작하게 빚어 완자를 만들어\\n팬에 노릇하게 굽는다.\",\"5. 물(300g)에 된장을 풀고 애호박과\\n감자, 표고버섯을 넣고 끓이다가\\n날콩가루를 넣은 뒤 청양고추,\\n완자를 넣고 조금 더 끓인다.\",\"6. 그릇에 브로콜리를 담고 국물을\\n부은 뒤 채 썬 대파와 고추를 얹어\\n마무리한다.\"]},{\"id\":\"k287\",\"title\":\"산나물된장찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00292_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00292_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00292_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00292_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00292_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00292_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00292_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 곤드레나물(25g)\",\"고구마순(10g)\",\"취나물(20g)\",\"애호박(20g)\",\"양파(10g)\",\"청양고추(3g)\",\"대파(1g)\",\"순두부(40g)\",\"저염재래된장 콩(백태\",\"5g)\",\"표고버섯(5g)\",\"저염된장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금간을 전혀 하지 않고 콩가루와 표고버섯을 섞은\\n된장을 만들어 사용해 나트륨 섭취량을 줄였다\",\"instructions\":[\"1. 콩은 삶아서 표고버섯과 함께\\n물(30g)을 넣고 간다.\",\"2. 저염된장, 날콩가루, 갈아 놓은 콩과\\n표고버섯을 섞어 저염재래된장을\\n만든다.\",\"3. 냄비에 육수 재료를 끓여낸 뒤\\n건진다.\",\"4. 산나물과 애호박, 양파는 먹기 좋게\\n썰고, 청양고추와 대파는 어슷하게\\n썬다.\",\"5. 저염재래된장을 육수에 풀고\\n곤드레나물, 고구마순, 취나물을\\n넣고 끓여 반 이상 익으면 애호박,\\n양파를 넣는다.\",\"6. 순두부, 양념, 청양고추, 대파를 넣고\\n마무리한다.\"]},{\"id\":\"k288\",\"title\":\"토마토요구르트된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00293_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00293_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00293_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00293_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00293_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00293_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00293_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 표고버섯(15g)\",\"팽이버섯(35g)\",\"양송이(30g)\",\"새송이버섯(17g)\",\"양파(25g)\",\"대파(3g)\",\"청양고추(3g)\",\"토마토(25g)\",\"된장양념 콩가루(5g)\",\"요구르트(15g)\",\"저염된장(10g)\",\"육수 멸치(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장양념에 된장 대신 콩가루와 요구르트를 넣어 콩가루의 구수한 맛과 요구르트의\\n시큼한 맛으로 짠맛을 보강하였고, 천연조미료인 들깻가루를 넣어 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 버섯은 밑동을 제거해 먹기 좋게\\n손질하고, 양파는 채 썰고, 대파와\\n청양고추는 어슷 썬다.\",\"2. 토마토는 아주 잘게 다진다.\",\"3. 된장양념을 만든다.\",\"4. 냄비에 육수 재료를 넣고 15분간\\n끓인 뒤 체로 건더기를 건지고,\\n된장양념을 체에 내리면서 푼다.\",\"5. 버섯을 넣고 끓으면 토마토, 다진\\n마늘, 고춧가루, 들깻가루, 채 썬\\n양파를 넣고 끓인다.\",\"6. 송송 썬 대파와 청양고추를 넣고\\n조금 더 끓여 마무리한다.\"]},{\"id\":\"k289\",\"title\":\"굴림만두된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00294_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00294_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00294_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00294_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00294_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00294_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00294_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 풋고추(1g)\",\"붉은 고추(1g)\",\"애호박(5g)\",\"팽이버섯(5g)\",\"두부(20g)\",\"굴림만두 새송이버섯(10g)\",\"닭가슴살(25g)\",\"양파(40g)\",\"마늘(8g)\",\"부추(4g)\",\"두부(25g)\",\"간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"재래식 된장과 간장 대신 저염된장과 저염간장을 사용해 나트륨 섭취를 줄였\",\"instructions\":[\"1. 새송이버섯, 닭가슴살, 양파, 마늘,\\n부추는 잘게 다지고, 두부도 곱게\\n다진 뒤 물기를 제거한 후 간장을\\n넣고 함께 섞어 동그랗게 빚은 뒤\\n녹말가루와 밀가루를 섞어\\n반죽을 굴린다.\",\"2. 차가운 물에 넣었다 뺀 뒤 가루에\\n굴리기를 2~3회 반복해 겉에\\n만두피가 코팅되면 끓는 물에 살짝\\n데친다.\",\"3. 고추는 어슷 썰고, 팽이버섯, 애호박,\\n두부는 먹기 좋게 썬다.\",\"4. 냄비에 저염된장을 제외한 육수\\n재료와 물을 넣고 끓어오르면\\n저염된장을 체에 내려 풀고 면포에\\n거른다.\",\"5. 육수에 굴림만두와 애호박,\\n팽이버섯을 넣고 끓인다.\",\"6. 굴림만두가 적당히 익으면 두부를\\n넣고 끓인 뒤 고추 고명을 얹어\\n마무리한다.\"]},{\"id\":\"k290\",\"title\":\"해물순두부된장찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00295_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00295_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00295_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00295_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00295_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00295_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00295_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 바지락(5g)\",\"주꾸미(60g)\",\"마른 미역(1g)\",\"마른 표고버섯(10g)\",\"순두부(80g)\",\"대파(5g)\",\"육수 멸치(2g)\",\"양념 된장(7g)\",\"콩가루(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"순두부찌개를 고추장 양념으로 끓이는 대신 저염된장을 넣어 나트륨 함량을 줄였다.\",\"instructions\":[\"1. 물(250g)에 멸치를 넣고 육수를\\n낸다.\",\"2. 바지락은 해감해 준비하고 주꾸미는\\n손질한다.\",\"3. 마른 미역과 마른 표고버섯은 물에\\n불린다.\",\"4. 육수에 된장을 풀고, 바지락과\\n주꾸미를 넣어 끓인다.\",\"5. 해물이 어느 정도 익으면 미역,\\n표고버섯을 넣고 끓인다.\",\"6. 끓어오르면 순두부를 넣고 콩가루를\\n넣어 더 끓이다가 송송 썬 대파를\\n올려 마무리한다.\"]},{\"id\":\"k291\",\"title\":\"곤약함박스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00296_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00296_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00296_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00296_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00296_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00296_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 새송이버섯(10g)\",\"가지(10g)\",\"브로콜리(15g)\",\"양파(10g)\",\"파프리카(30g)\",\"방울토마토(15g)\",\"아스파라거스(10g)\",\"올리브유(10g)\",\"어린잎채소(5g)\",\"스테이크반죽 곤약(80g)\",\"두부(80g)\",\"쇠고기(40g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"간장과 유자청으로 만든 소스를 곁들여 단맛을 더해 나트륨 섭취량을 줄였다.\",\"instructions\":[\"1. 곤약을 식촛물에 살짝 데친 뒤\\n나머지 반죽 재료와 함께 믹서에\\n넣고 갈아 치댄다.\",\"2. 스테이크 반죽을 동글납작하게 빚고\\n팬에 식용유를 살짝 둘러 구운 뒤\\n140℃로 달군 오븐에서 30분간\\n굽는다.\",\"3. 새송이버섯, 가지, 브로콜리, 양파,\\n파프리카, 방울토마토, 아스파라거스는\\n올리브유에 구워 준비한다.\",\"4. 팬에 유자청과 저염간장, 물을 넣고\\n끓여 유자청간장소스를 만든다.\",\"5. 접시에 곤약함박스테이크를 담고\\n어린잎채소를 올리고, 구운 채소와\\n유자청간장소스를 곁들여\\n마무리한다.\"]},{\"id\":\"k292\",\"title\":\"청국장 두부 검은깨 냉스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00039_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00039_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00039_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00039_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"냉스프\",\"두부 120g(1/3모)\",\"플레인요거트 70g(1개)\",\"검은깨 8g(1⅔작은술)\",\"고명\",\"청국장가루 10g(1큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"스프에 소금 대신 청국장 가루를 넣어 나트륨 함량을 줄였어요. 청국장에 풍부한 바실러스균은 다른 유해한 세균을 제거하고 혈전을 용해하는 능력이 있어 암예방과 동맥경화 예방에 효과가 있어요.\",\"instructions\":[\"1. 두부가 잠길 정도로 물을 부어\\n5~7분 정도 삶는다.\",\"2. 삶은 두부와 플레인요거트, 검은깨\\n를 믹서에 넣고 간 다음 냉장고에\\n1시간 정도 보관한다.\",\"3. 차가워진 스프를 그릇에 담고 그\\n위에 청국장가루를 얹는다.\"]},{\"id\":\"k293\",\"title\":\"호박 고구마 스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00040_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00040_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00040_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00040_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"호박고구마스프\",\"고구마 70g(1/2개)\",\"단호박 30g(4×6cm)\",\"우유 100ml(1/2컵)\",\"설탕 2g(1/3작은술)\",\"물 50ml(1/4컵)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박은 애호박에 비해 칼륨 함량이 2배 정도 많으며, 고구마 역시 칼륨 함량이 높아 나트륨 배설을 도와줘요.\\n지방의 섭취를 줄여야 하는 경우 우유 대신 저지방 우유를 사용해 보세요. 체 대신 믹서기를 이용할 때는 우유와 고구마, 단호박을 같이 넣으면 잘 갈려요.\",\"instructions\":[\"1. 고구마와 단호박을 찜기에 10~20분 동안 익힌 후 껍질을 제거하고 으깨어 체에 거른\\n다.\",\"2. 냄비에 고구마, 단호박, 우유, 설탕을 넣고 잘 저어주며 끓인다.\",\"3. 스프의 농도를 보면서 물을 조금씩 넣어가며 걸쭉하게 끓여준다.\"]},{\"id\":\"k294\",\"title\":\"시금치 리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00121_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00121_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00121_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00121_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 180g(1컵)\",\"시금치 50g(1/2개)\",\"마 10g(5cm)\",\"두유 150g(3/4컵)\",\"소금 1g\",\"버터 8g(1½작은술)\",\"후춧가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시금치에 풍부하게 함유된 식물성 섬유질은 장의 운동을 활발하게 하는 역할을 해 변비에 효과적이다. 무염버터를 사용하면 버터에 비하여 나트륨 함량을 줄일 수 있으며, 칼륨 함량이 높은 마와 시금치를 활용하여 나트륨 배출에 도움을 준다.\",\"instructions\":[\"1. 시금치는 뚜껑을 열고 데친 후, 물기를 뺀다.\",\"2. 마, 시금치, 두유를 함께 갈아 체에 거른다.\",\"3. 가열된 팬에 버터를 두르고 약불에서 2와 밥을 넣어 밥의 색을 입히고 소금, 후추가루로 간을 한다.\"]},{\"id\":\"k295\",\"title\":\"북어비빔밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00124_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00124_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00124_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00124_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료\",\"밥 210g(1컵)\",\"북어 15g\",\"당근 15g(5cm)\",\"애호박 15g(5cm)\",\"달걀 100g(2개)\",\"고사리 15g\",\"표고버섯 15g(2개)\",\"우렁 25g(2큰술)\",\"들기름 5g(1작은술) 장식\",\"베이비채소 5g\",\"식용꽃 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"북어 고유의 짠 맛을 활용하여 소금을 사용하지 않고 맛을 내 나트륨의 섭취를 줄였으며, 재료 고유의 향이 강한 표고버섯과 고사리, 들기름 등을 사용한다.\",\"instructions\":[\"1. 당근과 표고버섯, 고사리는 5cm로 채 썰고, 애호박도 돌려 깎아 5cm로\\n채 썬다.\",\"2. 우렁은 3등분으로 자른 후 1의 재료와 함께 들기름에 볶고 달걀은 황백으로 나누어 지단을 부쳐 채 썬다.\",\"3. 북어는 갈아 북어보푸라기를 만든다. 그릇에 밥을 담고 준비된 재료를 담고 베이비채소, 식용꽃, 북어보푸라기를 올려 완성한다.\"]},{\"id\":\"k296\",\"title\":\"무 현미밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00125_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00125_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00125_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00125_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 현미 140g(2/3컵)\",\"찹쌀 140g(2/3컵)\",\"무 35g(1/20개)\",\"표고버섯 30g(2개) 근대 10g\",\"올리브오일 15g(1큰술)\",\"참기름 15g(1큰술)\",\"●육수 :뒤포리(밴댕이) 50g(5개)\",\"다시마 15g(5cm)\",\"간장 15g(1큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"무에 함유된 섬유소는 체내 노폐물을 제거하는 역할을 한다. 표고버섯과 무, 참기름을 넣어 다양한 향과 맛을 부여한다.\",\"instructions\":[\"1. 현미와 찹쌀은 씻어서 물에 불리고 물에 뒤포리와 다시마, 간장 1큰술을 넣어 육수를 만든다.\",\"2. 무, 표고버섯, 근대는 채 썰고 팬에 올리브 오일을 두른 후 채 썬 무와 표고버섯을 볶다가 참기름을 넣는다.\",\"3. 불린 현미와 찹쌀에 육수를 넣고 볶은 무와 표고버섯을 올려 밥을 짓고 채 썬 근대를 올려 완성한다.\"]},{\"id\":\"k297\",\"title\":\"컵밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00127_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00127_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00127_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00127_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀밥 420g(2컵)\",\"김 4g(1장)\",\"배추김치 30g\",\"달걀 200g(4개)\",\"베이컨 30g(3장)\",\"소시지 30g(1개)\",\"시금치 70g\",\"고춧가루 20g(1큰술)\",\"참기름 6g(1작은술)\",\"마늘 6g(1작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"베이컨과 소시지는 데치고, 김치는 물에 헹구어 염분을 제거하고 칼륨이 많은 시금치를 사용하여 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 베이컨과, 소시지를 다진 후 끓는 물에 데쳐 팬에 볶고 다진 김치는 물에 행군 후 고추가루를 넣어 볶는다.\",\"2. 시금치는 데친 후 다져 참기름과 다진 마늘을 넣어 무치고 달걀은 부쳐서 다진다.\",\"3. 김은 참기름을 발라 구워 길게 자르고 밥과 준비된 재료를 층층히 쌓아 완성한다.\"]},{\"id\":\"k298\",\"title\":\"두릅 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00210_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00210_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00210_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00210_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 두릅 20g(2개)\",\"가지 20g(1/5개)\",\"레몬(껍질) 12g(1큰술)\",\"청경채 25g(2개)\",\"슬라이스연어 30g(2장)\",\"크림치즈 5g(1작은술)\",\"레몬 5g(1작은술)\",\"●드레싱 : 레몬즙15g(1큰술)\",\"레드와인 30g(2큰술)\",\"설탕 5g(1작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 치즈를 사용하여 짠 맛과 치즈 고유의 풍미를 더하고 레몬과 와인을 이용하여 새콤달콤한 소스를 곁들인다.\\n소스에 버무려 제공하기 보다는 찍어서 먹도록 하면 나트륨 섭취량을 줄일 수 있다.\",\"instructions\":[\"1. 팬에 레드와인, 레몬즙, 설탕을 넣고 졸여 드레싱을 만든다.\",\"2. 청경채와 두릅은 끓는 물에 데쳐 식히고 레몬은 부채꼴 모양으로 썰고 가지는 어슷하게 썰어 석쇠에 굽는다.\",\"3. 슬라이스연어에 크림치즈를 넣고 말아준 후 접시에 연어, 가지, 레몬, 두릅, 청경채를 담고 드레싱을 뿌려 완성한다.\"]},{\"id\":\"k299\",\"title\":\"구운 바나나\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00212_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00212_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00212_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00212_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 바나나 100g(1개)\",\"설탕 5g(1/2작은술)\",\"●장식 : 다진 호두 15g(1큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바나나에 함유된 칼륨은 나트륨 배출에 도움을 주며, 비타민 A가 풍부해 항산화작용에 탁월하다.\",\"instructions\":[\"1. 바나나는 껍질을 벗겨 2등분한다.\",\"2. 가열된 팬에 기름을 두르지 않고 바나나를 굽는다.\",\"3. 구워진 바나나의 겉면에 설탕을 뿌리고 가열된 팬에 구운 후 완성된 바나나를 접시에 담고, 다진 호두를 뿌린다.\"]},{\"id\":\"k300\",\"title\":\"과일무스 테린\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00214_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00214_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00214_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00214_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 딸기 100g(5개)\",\"키위 100g(1개)\",\"매실원액 15g(1큰술)\",\"젤라틴 20g\",\"●소스 : 망고 20g(1/5개)\",\"우유 45g(3큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"망고에는 비타민 A가 다량 함유되어 항산화작용을 돕는다. 과일의 새콤달콤한 맛을 강조하였다.\",\"instructions\":[\"1. 망고와 우유를 섞어 믹서에 갈아 팬에 넣고 끓인다.\",\"2. 딸기와 키위는 0.5×0.5×0.5cm로 썰고 젤라틴은 녹여서 매실원액과 섞는다.\",\"3. 딸기, 키위를 젤라틴과 섞어서 틀에 넣어 굳히고 위에 망고소스를 뿌려 완성한다.\"]},{\"id\":\"k301\",\"title\":\"가지볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00215_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00215_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00215_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00215_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00215_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00215_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 단호박(100g)\",\"양파(30g)\",\"석박지(35g)\",\"파프리카(40g)\",\"가지(90g)\",\"두부(50g)\",\"밥(180g)\",\"세발나물(10g)\",\"양념 다진 마늘(5g)\",\"저염된장(12g)\",\"후춧가루(0.3g)\",\"들기름(4g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염된장을 사용해 염도를 낮추고, 칼륨 함량이 높은 가지와 단호박을 사용해\\n체내 나트륨 배출을 돕는다.\",\"instructions\":[\"1. 단호박은 삶아 으깬다.\",\"2. 양파, 석박지, 파프리카, 가지는 깍둑\\n썰고, 두부는 으깬다.\",\"3. 팬에 다진 마늘, 양파, 석박지를 넣어\\n볶다가 두부를 넣고 수분이 없어질\\n때까지 볶다가 가지, 파프리카도\\n넣어 볶는다\",\"4. 밥과 저염된장, 후춧가루를 넣고\\n볶다가 들기름을 넣어 한 번 더\\n볶는다.\",\"5. 그릇에 담고 으깬 단호박과\\n세발나물을 곁들여 마무리한다.\"]},{\"id\":\"k302\",\"title\":\"닭고기볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00216_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00216_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00216_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00216_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00216_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00216_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 쌀(80g)\",\"완두콩(10g)\",\"닭고기(100g)\",\"대추(10g)\",\"수삼(20g)\",\"양파(20g)\",\"당근(10g)\",\"양념 강황가루(3g)\",\"맛술(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"강황가루 특유의 향을 통해 소금과 기름의 양을 줄여\\n나트륨 함량을 낮췄다.\",\"instructions\":[\"1. 쌀은 30분 정도 불린 뒤 동량의 물에 강황가루를 풀어 완두콩과 함께\\n넣어 밥을 짓는다.\",\"2. 닭고기를 깨끗이 씻은 후 끓는 물에\\n살짝 데쳐 기름기를 제거한 뒤 작게\\n썰어 대추, 수삼과 함께 맛술에 재워\\n잡냄새를 없앤다.\",\"3. 양파와 당근은 작게 깍둑 썬다.\",\"4. 팬에 기름을 두른 후 재워둔\\n닭고기와 당근, 양파를 볶는다\",\"5. 강황밥을 넣고 같이 볶아\\n마무리한다.\"]},{\"id\":\"k303\",\"title\":\"토마토라면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00311_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00311_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00311_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00311_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00311_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00311_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00311_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 애호박(30g)\",\"양파(20g)\",\"청양고추(5g)\",\"대파(5g)\",\"토마토(300g)\",\"라면스프(3g)\",\"라면(100g)\",\"육수 다시마(2.5g)\",\"멸치(2.5g)\",\"무(10g)\",\"물(250g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라면스프의 양을 ¼로 줄여 나트륨 섭취량을 낮추고,\\n대신 토마토와 청양고추를 넣어 상큼함과 칼칼함을 더했다.\",\"instructions\":[\"1. 냄비에 육수 재료를 넣고 10분간\\n끓여 건더기를 건진다.\",\"2. 애호박은 돌려 깎아 채 썰고, 양파도\\n채 썰고, 청양고추와 대파는\\n어슷 썬다.\",\"3. 토마토는 200g은 잘게 다지고,\\n100g은 두툼하게 썬다.\",\"4. 육수에 라면스프와 라면을 넣고\\n살짝 익힌 뒤 양파, 애호박, 다진\\n토마토를 넣고 끓인다.\",\"5. 면이 다 익으면 두툼하게 썬\\n토마토를 넣고 10초간 더 끓인다.\",\"6. 대파와 청양고추를 올려 마무리한다.\"]},{\"id\":\"k304\",\"title\":\"토마토샐러드라면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00312_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00312_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00312_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00312_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00312_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00312_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00312_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 양상추(80g)\",\"치커리(15g)\",\"굵은 면발 라면(55g)\",\"삶은 닭가슴살(50g)\",\"방울토마토(15g)\",\"파슬리가루(0.1g)\",\"소스 설탕(2g)\",\"식초(1.5g)\",\"레몬즙(1g)\",\"저염간장(3g)\",\"다진 마늘(1g)\",\"다진 토마토(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장을 사용해 나트륨 섭취를 줄이고 식초와 레몬 등 상큼한 맛을 보강하여 간을 맞췄다\",\"instructions\":[\"1. 소스를 만든다.\",\"2. 양상추와 치커리는 굵은 줄기\\n부분을 빼고 먹기 좋은 크기로 잘게\\n찢는다.\",\"3. 라면 끓는 물에서 4분간 삶고 체에\\n건져 찬물에 헹군다.\",\"4. 닭가슴살을 먹기 좋은 크기로 찢어\\n면과 함께 섞는다.\",\"5. 그릇에 채소와 면을 담고,\\n방울토마토도 먹기 좋게 잘라\\n담는다.\",\"6. 소스와 파슬리가루를 뿌려\\n마무리한다.\"]},{\"id\":\"k305\",\"title\":\"검은깨라면크로켓\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00313_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00313_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00313_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00313_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00313_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00313_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00313_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 검은깨(8g)\",\"빵가루(80g)\",\"라면(50g)\",\"달걀(45g)\",\"녹말가루(15g)\",\"다진 쇠고기(40g)\",\"다진 땅콩(5g)\",\"어린잎채소(2g)\",\"방울토마토(20g) 소스 통계피(20g)\",\"생강(10g)\",\"조청(10g)\",\"물엿(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라면을 미리 끓는 물에 한 번 데쳐 염분을 줄였다\",\"instructions\":[\"1. 검은깨를 곱게 부숴 빵가루와 섞어\\n마른 팬에서 볶는다.\",\"2. 라면을 삶아 건져 물기를 제거 한 뒤\\n달걀물→녹말가루 순서대로 묻힌다.\",\"3. 다진 쇠고기에 다진 땅콩을 넣어\\n반죽해 적당한 크기로 빚는다.\",\"4. 반죽을 라면으로 감싸 달걀물→\\n빵가루 순으로 입혀 튀긴다.\",\"5. 통계피와 생강을 물(200g)에 넣고\\n끓여 우려낸 뒤 건더기를 건지고\\n나머지 소스 재료를 넣고 살짝\\n조린다.\",\"6. 발사믹드레싱을 만들어\\n어린잎채소에 뿌리고, 방울토마토는\\n반으로 썰어 라면 크로켓과 함께\\n그릇에 담아 마무리한다.\"]},{\"id\":\"k306\",\"title\":\"김말이두부스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00314_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00314_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00314_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00314_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00314_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00314_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00314_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 100g\",\"김 2g\",\"허브소금 1g\",\"소 : 다진쇠고기 20g\",\"양파20g\",\"표고버섯10g\",\"새송이버섯 10g\",\"밀가루 10g\",\"흰후추 0.3g\",\"곁들이채소 : 고구마 50g\",\"단호박 50g\",\"양파 70g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부의 속을 레드와인과 발사믹식초를 이용해 간을 하여 나트륨을 줄여주고 두부의 냄새도 잡아주었다.\",\"instructions\":[\"1. 두부는 사방 3cm 길이와 두께로 잘라 허브\\n소금을 뿌려 수분을 완전히 빼고 속을 파서\\n밀가루를 묻힌다.\",\"2. 소 재료를 골고루 양념해 속을 파준 두부에\\n채워준다.\",\"3. 채워진 두부를 김을 두른 뒤 팬에 은근하게\\n구워준다.\",\"4. 고구마, 단호박, 아스파라거스를 편으로\\n썰어 준다.\",\"5. 마늘과 토마토를 각각 다진 후 오일에 볶다가\\n레드와인을 넣어 졸인다. 불을 끄기 직전에\\n버터를 넣어 소스를 만든다.\",\"6. 채소를 각각 구워주고 구워진 두부스테이크를\\n담고 레드와인 소스를 뿌려 완성한다.\"]},{\"id\":\"k307\",\"title\":\"연어롤샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00315_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00315_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00315_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00315_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00315_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00315_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00315_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어 60g\",\"단호박 50g\",\"방울토마토 4개\",\"시금치 50g\",\"영양부추 50g\",\"소스 : 잣 5g\",\"더덕 45g\",\"마늘 5g\",\"식초 15g\",\"올리브오일 30g\",\"다진홍고추 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시금치와 영양부추 등 다양한 채소를 이용해 소금을 사용하지 않고 맛을 유지시켜주었으며\\n잣 소스의 고소함으로 맛과 영양분을 향상시켰다.\",\"instructions\":[\"1. 영양부추, 시금치는 먹기 좋게 잘라 물에\\n담가준다.\",\"2. 단호박은 삶아서 체에 내려준다.\",\"3. 토마토는 곱게 다져주고 시금치도 데친 후\\n단호박, 연두부와 섞어준다.\",\"4. 연어를 포를 떠서 만들어진 단호박과 연두부를\\n연어에 돌돌 말아 냉동실에 살짝 얼려준다.\",\"5. 소스재료로 소스를 만든다.\",\"6. 접시에 준비된 채소를 깔고 연어를 올리고\\n소스를 올려 완성한다.\"]},{\"id\":\"k308\",\"title\":\"비타민이유식\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00316_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00316_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00316_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00316_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00316_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00316_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"멜론 300g\",\"브로콜리 30g\",\"감자 60g\",\"요거트 15g\",\"설탕 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금을 사용하지 않고 멜론과 요거트의 상큼한 맛으로 특유의 깊은 맛을 낼 수가 있다.\",\"instructions\":[\"1. 브로콜리는 데쳐낸 후 송송 다져준다.\",\"2. 감자는 삶아준 후 체에 내려준다.\",\"3. 멜론은 씨를 제거하고 껍질을 벗긴 후 믹서에\\n갈아 체에 내려준다.\",\"4. 체에 내린 감자와 브로콜리 그리고 멜론즙을\\n함께 섞어준다.\",\"5. 설탕으로 간을 해주고 볼에 담고 요거트로\\n장식을 해 완성한다.\"]},{\"id\":\"k309\",\"title\":\"한입꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00317_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00317_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00317_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00317_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00317_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00317_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00317_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통삼겹 200g\",\"고구마 100g\",\"대파 40g\",\"2가지색 미니파프리카 40g\",\"청피망 40g\",\"양송이 40g\",\"건고추 3g\",\"어간장 10g\",\"통후추 1g\",\"로즈마리 1g. 마늘기름 15g\",\"소스 : 오렌지주스 100g\",\"레몬즙 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"일반 간장과 달리 어간장은 멸치, 젓갈 등 발효 중 감칠맛 성분이 많아 염도를 낮추면서 풍미를 높여준다.\",\"instructions\":[\"1. 통삼겹살은 어간장, 마늘기름, 로즈마리,\\n통후추에 재워준다.\",\"2. 양송이, 피망, 파프리카는 먹기 좋게 썰어서\\n마늘기름에 구워준다.\",\"3. 고구마는 먹기 좋게 잘라 기름 없이 구워준다.\",\"4. 재워 놓은 통삼겹은 작은 크기로 잘라서\\n건고추를 넣어 물에 데쳐낸다.\",\"5. 모든 재료를 꼬치에 끼워서 살짝 구워준다.\",\"6. 레몬껍질을 채 썰어서 소스를 만들어주고\\n꼬치와 함께 완성한다.\"]},{\"id\":\"k310\",\"title\":\"간장곤약볶음국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00318_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00318_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00318_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00318_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00318_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00318_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00318_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"곤약국수 200g\",\"사과 60g\",\"레몬즙 15g\",\"볶음양념 : 맛간장 30g\",\"다진생강 3g\",\"다진양파 15g\",\"버터 10g\",\"소스 : 다진양파 10g\",\"흑임자 7g\",\"플레인요거트 30g\",\"그라놀라 30g\",\"꿀 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"볶음양념의 다진생강과 양파 특유의 맛으로 짠맛을 대체하였고, 구수한 맛의 흑임자와 요거트, 꿀의 단맛으로\\n풍미를 높였다.\",\"instructions\":[\"1. 곤약은 세척 후 물기를 빼준다.\",\"2. 사과는 가늘게 채 썰어 레몬에 살짝 담가 주고,\\n다진양파도 레몬즙에 살짝 담가준다.\",\"3. 팬에 다진양파를 버터에 볶다가 나머지 볶음\\n재료를 넣고 볶음양념을 만들어준다.\",\"4. 볶음양념에 곤약 을 넣 어 고들고들하게\\n볶아준다.\",\"5. 사과를 물기를 완전히 제거하고 소스재료를\\n섞어 곁들이 소스를 만들어준다.\",\"6. 볶음곤약을 그릇에 담고 그라놀라를 뿌려서\\n완성한다.\"]},{\"id\":\"k311\",\"title\":\"닭가슴살리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00319_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00319_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00319_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00319_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00319_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00319_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00319_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 100g\",\"찰보리 50g\",\"찹쌀 50g\",\"청피망 50g\",\"표고버섯 30g\",\"청양고추 10g\",\"양파 60g\",\"다진마늘 15g\",\"홍피망 50g\",\"생크림 30g\",\"우유 30g\",\"올리브오일 50g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"표고버섯 불린 물이나 자투리 채소를 이용해 채소국물을 만들어 깊은 맛을 내고\\n보리쌀의 씹는 맛이 고소함을 더해 주어 나트륨을 줄일 수가 있다.\",\"instructions\":[\"1. 찹쌀은 30분 정도, 찰보리는 1시간 이상\\n불려주고 보리쌀은 한번 쪄 준다.\",\"2. 표고버섯은 물에 데친다. 이때 표고버섯 불린\\n물은 버리지 않고 짜투리 채소와 함께 채소\\n국물을 만들어준다.\",\"3. 불린 표고버섯, 청피망, 홍피망, 양파, 오리\\n가슴살은 작은 정사각형으로 잘라주고 청양\\n고추는 다져준다.\",\"4. 다진 청양고추와 다진마늘은 볶아주고 다시\\n여기에 다진채소와 가슴살을 볶아준다.\",\"5. 찹쌀과 보리쌀을 넣어 만들어진 채소국물에\\n끓여주다 생크림과 우유를 넣어 죽 형태로\\n만든다.\",\"6. 여기에 볶아진 재료를 넣고 소금으로 간을\\n하고 말린 토마토를 올려 완성한다.\"]},{\"id\":\"k312\",\"title\":\"녹차귀리라떼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00320_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00320_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00320_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00320_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00320_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00320_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00320_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"브로콜리 60g\",\"귀리 30g\",\"닭육수 250ml\",\"우유150ml\",\"녹차가루 10g\",\"아몬드슬라이스 20g\",\"무염버터 5g\",\"흰후추 3g\",\"소금 0.5g\",\"우유 50ml\",\"생크림 50ml\",\"다진양파 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭육수를 이용해 감칠맛을 높여 소금 사용량을 줄여도 충분히 맛을 줄 수 있으며,\\n버터와 생크림우유의 고소함과 풍미가 나트륨을 줄여준다.\",\"instructions\":[\"1. 귀리는 불려준 뒤 닭육수에 삶아준다.\",\"2. 브로콜리는 잘 손질하여 잘게 썰어 놓는다.\",\"3. 양파는 채 썰어 버터로 볶다가 1의 브로콜리와\\n귀리, 아몬드슬라이스를 넣고 같이 볶아준다.\",\"4. 어느 정도 볶아지면 우유를 넣고 다시 한 번\\n볶아준다.\",\"5. 닭육수를 넣고 귀리가 익을 때 까지 푹 익힌 후\\n믹서에 갈아 체에 걸러준다.\",\"6. 마지막으로 생크림을 넣고 농도를 조절하고\\n녹차가루를 올려 완성한다.\"]},{\"id\":\"k313\",\"title\":\"계란숙샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00321_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00321_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00321_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00321_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00321_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00321_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00321_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 120g\",\"쇠고기 50g\",\"게맛살 20g\",\"감자 1개\",\"천연조미료 5g\",\"물 200g\",\"브로콜리 50g\",\"방울토마토 60g\",\"미니파프리카 25g\",\"영양부추 5g\",\"소스 : 매실청 30g\",\"발사믹식초 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치가루, 새우가루, 함초가루를 이용해 만든 천연조미료의 감칠맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 소고기에 물을 넣어 육수를 뽑아준 후 천연\\n조미료로 간을 해준다.\",\"2. 소고기는 곱게 다져준 뒤 볶아준다.\",\"3. 감자를 삶아서 체에 내려준다.\",\"4. 계란을 풀고 소고기 다진 것과 게맛살, 물을\\n넣고 섞은 뒤 찜기에 쪄준다.\",\"5. 부추와 브로콜리는 뜨거운 물에 데쳐 먹기\\n좋게 잘라주고, 방울토마토와 미니파프리카도\\n먹기 좋게 잘라준다.\",\"6. 매실청과 올리브오일, 후추로 드레싱을 만들어\\n준비된 채소를 섞어준 뒤 그릇에 담는다.\"]},{\"id\":\"k314\",\"title\":\"한식풍닭가슴살스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00322_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00322_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00322_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00322_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00322_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00322_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00322_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 280g\",\"미나리 50g\",\"쌀 50g\",\"청경채 60g\",\"무조림 : 무 150g\",\"맛간장 15g\",\"고춧가루 15g\",\"다진마늘 5g\",\"물 200g\",\"소스 : 된장 15g\",\"매실청 15g\",\"들기름 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"무조림에는 소금 대신 고춧가루를 이용해 나트륨을 줄여주었고,\\n소스를 만들 때 된장 양을 줄이고 매실청을 넣어 나트륨은 낮추고 맛은 높였다.\",\"instructions\":[\"1. 미나리는 데친 후 먹기 좋은 크기로 잘라서\\n밥을 해준다.\",\"2. 닭가슴살에 밥을 넣고 말아서 오븐에 굽는다.\",\"3. 무는 물에 익히고 고춧가루와 무조림 재료를\\n넣어 졸여준다.\",\"4. 청경채는 데친 후 팬에 살짝 볶아준다.\",\"5. 소스를 만들어준다.\",\"6. 접시에 무조림을 깔고 닭가슴살 구이를 올리고\\n청경채와 함께 소스를 뿌려 완성한다.\"]},{\"id\":\"k315\",\"title\":\"강황고구마밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00323_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00323_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00323_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00323_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00323_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00323_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 100g\",\"강황가루 15g\",\"고구마 50g\",\"닭육수 300g\",\"양념장 : 영양부추 10g\",\"다진청고추 15g\",\"다진홍고추 15g\",\"다진양파 15g\",\"간편 어간장 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"어간장에 영양부추, 다진청고추, 다진홍고추, 다진양파를 사용해 충분히 절여\\n식품 자체의 맛을 살려 짠맛을 대체하였다.\",\"instructions\":[\"1. 먼저 영양부추를 뺀 재료로 양념장을 30분\\n전에 만들어준다.\",\"2. 쌀은 30분전에 불려주고 고구마는 껍질째\\n작은 깍두기 모양으로 잘라 냉수에 담가준다.\",\"3. 닭육수에 강황가루를 풀어주고 쌀과 고구마를\\n고루 섞어 밥을 해준다.\",\"4. 만들어진 양념장에 영양부추를 한입 크기로\\n잘라 최종 양념장을 만들어준다.\",\"5. 그릇에 강황고구마밥을 담아주고 양념장과\\n함께 완성한다.\"]},{\"id\":\"k316\",\"title\":\"된장시금치옹심이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00324_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00324_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00324_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00324_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00324_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00324_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00324_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"시금치 150g\",\"감자 80g\",\"애호박 30g\",\"당근 20g\",\"양파 50g\",\"청고추 15g\",\"홍고추 15g\",\"밀가루 30g\",\"국물 : 바지락 100g\",\"저염된장 25g\",\"볶은소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 많이 들어 있는 채소들을 이용해 된장 속에 들어 있는 나트륨을 줄여주었고,\\n바지락 데친 물을 버리지 않고 사용하여 짠맛을 감칠맛으로 대체하였다.\",\"instructions\":[\"1. 바지락은 볶은 소금에 담가 해감을 시켜준다.\",\"2. 물 400g에 저염 된장과 바지락을 넣어 국물을\\n만들어준다.\",\"3. 시금치 는 데 친 후 물기를 제거해 송송\\n다져준다.\",\"4. 당근, 양파와 청홍고추는 채 썰고 애호박과\\n감자는 반달모양으로 썰어준다.\",\"5. 다진 시금치와 밀가루를 이용해 완자를\\n만들어준다.\",\"6. 만들어진 국물에 옹심이를 넣어 끓여주고\\n나머지 채소를 넣어 완성한다.\"]},{\"id\":\"k317\",\"title\":\"불고기 소스를 곁들인 두부구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00062_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00062_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00062_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00062_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●두부구이 : 두부 70g(1/5모)\",\"전분 10g(2작은술)\",\"흑임자 2g(1/3작은술)\",\"식용유 5g(1작은술)\",\"후추약간\",\"●불고기 양념 : 간장 3g(2/3작은술)\",\"올리고당 3g(2/3작은술)\",\"생강즙 3g(2/3작은술)\",\"물 30ml(2큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부는 칼슘, 칼륨과 철분 등이 풍부하여 나트륨 배출을 도와줘요. 두부에 전분을 묻혀서 구워주면 소스와의 흡착력이 강해져서 소량의 간장소스로도 요리 맛을 살리고 나트륨 섭취도 줄일 수 있어요.\",\"instructions\":[\"1. 두부를 2.5×2.5×1cm 정도로 잘라 물기를 빼고 후추를 뿌린 후 전분가루를 골고루 묻혀\\n식용유를 둘러 프라이팬에 갈색이 나도록 양면을 굽는다.\",\"2. 프라이팬에 간장, 올리고당, 생강즙, 물을 넣어 끓여 불고기 양념을 만든 후 양념을 구운 두부에 넣고 졸인다.\",\"3. 그릇에 두부를 담고 위에 흑임자를 뿌린다.\"]},{\"id\":\"k318\",\"title\":\"매생이순두부탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00140_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00140_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00140_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00140_3.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 풋고추 5g(1/3개)\",\"순두부 80g(1/3모)\",\"매생이 120g\",\"홍합 120g\",\"●육수 : 다시마 20g(10cm)\",\"멸치 60g(10개)\",\"보리된장 15g(1큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"재료 본연의 맛과 향을 풍부하게 가지고 있는 매생이와 홍합을 사용하여 소금 간을 하지 않고 재료 자체의 향과 감칠맛을 더한다. 매생이는 철분 함량은 빈혈을 예방해주고, 비타민과 무기질이 풍부하여 피부미용과 다이어트에 효과 적이다.\",\"instructions\":[\"1. 매생이는 씻어 체에 거른다.\",\"2. 물 250g에 다시마, 멸치, 보리된장을 넣어 육수를 만든다.\",\"3. 육수가 끓으면 매생이, 홍합, 순두부를 넣어 끓인 후 고추를 고명으로 올려 완성한다.\"]},{\"id\":\"k319\",\"title\":\"겨자 오이고추소박이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00144_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00144_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00144_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00144_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 오이고추 15g(1개)\",\"당근 5g(5cm)\",\"무 5g(5cm)\",\"부추 5g(6cm)\",\"양파 5g(5cm)\",\"●소스 : 겨자분말 5g(1작은술)\",\"식초 10g(2작은술)\",\"설탕 10g(2작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금으로 절이거나 양념을 하는 대신 겨자소스를 활용하여 톡 쏘는 매운 맛을 더한다. 오이고추는 비타민 A가 풍부하여 면역력을 높여 감기예방에 효과가 있다.\",\"instructions\":[\"1. 겨자분말은 물에 섞은 후, 뜨거운 물 3g에 중탕하여 발효시킨 후 설탕과 식초를 넣어 겨자 소스를 만들고 당근, 무, 양파는 0.1×5cm로 채 썬다.\",\"2. 부추는 3cm 길이로 썬다.\",\"3. 오이 고추는 길게 칼집을 넣어 씨를 제거한 다음 4cm로 썰고 당근, 무, 양파, 부추를 겨자냉채소스와 버무려 오이고추의 속을 채워 완성한다.\"]},{\"id\":\"k320\",\"title\":\"실치오이 초절임\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00145_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00145_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00145_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00145_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"매실액 10g(2작은술)\",\"실치 40g(1컵)\",\"식초 20g(1⅓큰술)\",\"오이 80g(1/2개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"실치는 고칼슘 식품으로 뼈의 건강에 도움을 준다. 실치의 염분은 데쳐서 뺀 후에 사용하고 식초를 이용하여 신맛을 더한다.\",\"instructions\":[\"1. 실치는 끓는 물에 데친다.\",\"2. 오이는 반달 모양으로 슬라이스하고 식초에 절인 후 물기를 제거하고 매실액을 넣는다.\",\"3. 데쳐낸 실치와 오이를 함께 버무려 완성한다.\"]},{\"id\":\"k321\",\"title\":\"비트무절임\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00146_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00146_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00146_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00146_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 무 200g(1/3개)\",\"비트 10g(5cm)\",\"쪽파 10g(10cm)\",\"●초절이 소스 : 소금 2g(1/2작은술)\",\"식초 20g(1⅓큰술)\",\"설탕 10g(2작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"비트는 칼륨과 철분이 풍부하여 빈혈예방에 좋고, 나트륨 배출에 용이하며 식초의 새콤한 맛을 살려 소금 사용량을 줄인다.\",\"instructions\":[\"1. 비트는 강판에 갈아 비트 물을 만든다.\",\"2. 무는 채 썰고 비트 물에 채 썬 무를 넣어 색을 들인다.\",\"3. 초절이 소스를 만든 후 색을 입힌 무를 소스에 넣어 재우고 절인 무를 건져 그릇에 담고 0.5cm로 썬 쪽파를 올린다.\"]},{\"id\":\"k322\",\"title\":\"감귤 김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00150_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00150_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00150_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00150_4.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료 : 배추 10g(1/60개)\",\"미나리 5g\",\"홍고추 5g(1/2개)\",\"소금 5g(1작은술)\",\"●김치국물 : 귤 100g(1개)\",\"고춧가루 5g(1작은술)\",\"다진 마늘 10g(2작은술)\",\"생강즙 5g(1작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"비타민C가 풍부한 귤은 신진대사를 원활하게 도와주고 피부와 점막을 튼튼하게 해주고 겨울철 감기 예방에 뛰어난 귤의 효능이 있다. 귤의 새콤달콤한 맛과 향을 이용하여 심심한 맛을 살릴 수 있다.\",\"instructions\":[\"1. 귤은 껍질을 까서 믹서에 갈아 체에 내린다.\",\"2. 배추는 3×3cm로 썰어 소금에 절인 후 체에 받치고 미나리, 홍고추는 길이 3cm로 썬다.\",\"3. 귤즙에 고춧가루, 생강즙, 다진 마늘을 넣고 김치 국물을 만들고 배추, 미나리, 홍고추에 김치 국물을 부어 실온에 2일 숙성시킨다.\"]},{\"id\":\"k323\",\"title\":\"두부달걀덮밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00231_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00231_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00231_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00231_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00231_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00231_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00231_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 두부(50g)\",\"가지(20g)\",\"표고버섯(30g)\",\"양파(10g)\",\"달걀(15g)\",\"밥(200g)\",\"가다랑어포(1g)\",\"육수 재료 물(200g)\",\"다시마(1g)\",\"가다랑어포(1g)\",\"양념 후춧가루(0.1g)\",\"녹말가루(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"담백한 두부를 주재료로, 나트륨 배출을 돕는 칼륨이 많이 함유된 가지와 버섯을 사용하고,\\n가다랑어포로 육수를 내 감칠맛을 더해 소금간을 줄여 나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 찬물에 다시마를 넣고 끓여 건져\\n내고 불을 끈 후 가다랑어포를\\n넣어 우려 육수를 만든다.\",\"2. 두부, 가지는 깍둑 썰고, 표고버섯,\\n양파는 채 썰고, 달걀은 곱게 푼다.\",\"3. 두부, 가지는 물기를 제거한 뒤\\n후춧가루로 밑간하고 녹말가루를\\n얇게 입혀 식용유를 두른 팬에서\\n구워 건진다.\",\"4. 육수(1컵)에 청주, 설탕, 간장을 넣고\\n표고버섯, 양파를 넣고 조려 덮밥\\n소스를 만든다.\",\"5. 달걀물을 붓고 익을 때까지 저은 후\\n녹말물을 넣어 되직하게 끓인다.\",\"6. 밥을 그릇에 담고 덮밥소스를\\n곁들인 후 두부, 가지, 가다랑어포를\\n얹어 마무리한다.\"]},{\"id\":\"k324\",\"title\":\"봄나물밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306041839_1678087119869.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306041929_1678087169607.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306041944_1678087184376.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306042000_1678087200758.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306042016_1678087216329.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306042032_1678087232744.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306042049_1678087249634.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 현미(30g)\",\"멥쌀(60g)\",\"쑥갓(20g)\",\"달래(10g)\",\"•두부양념장 : 고추장(5g)\",\"된장(5g)\",\"다시마 육수(60g)\",\"두부(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•두부를 함께 갈아 만든 장은 시판 비빔장보다 나트륨 함량이 훨씬 낮아요.\",\"instructions\":[\"1. 현미는 1시간 정도, 멥쌀은 30분 정도 각각 불린 뒤 섞는다.\",\"2. 쑥갓과 달래는 줄기부분과 잎으로 나누어 1㎝ 길이로 썬다.\",\"3. 쑥갓과 달래의 줄기부분은 불린 쌀과 함께 냄비에 넣고 밥물을 맞춰 센 불에서 끓어오르면 중약 불로 줄여 밥을 15분간 짓는다.\",\"4. 약한 불로 줄여 밥을 뜸 들인다.\",\"5. 다시마육수를 제외한 두부 양념장 재료를 믹서에 곱게 갈아 다시마 육수, 남겨둔 나물의 잎을 팬에 넣어 끓여 두부장을 만든다\",\"6. 나물밥에 두부장을 곁들여 마무리한다.\"]},{\"id\":\"k325\",\"title\":\"가지연어구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00233_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00233_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00233_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00233_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00233_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00233_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00233_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 가지(40g)\",\"토마토(20g)\",\"연어(200g)\",\"파슬리가루(1g)\",\"올리브유(5g)\",\"마늘(10g)\",\"소스 사과(20g)\",\"유자청(30g)\",\"레몬즙(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"가지에는 나트륨 배출을 돕는 칼륨이 많이 들어있다.\\n또한 사과와 유자, 레몬으로 만든 새콤달콤한 소스를 곁들여\\n따로 소금간을 할 필요가 없어 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 가지는 어슷 썰고, 토마토는 반\\n자른다.\",\"2. 연어는 파슬리와 올리브유에 재운다.\",\"3. 마늘은 노릇하게 굽는다.\",\"4. 재운 연어와 가지, 토마토는 180℃로\\n예열한 오븐에 10분 정도 굽는다.\",\"5. 사과는 잘게 다져 유자청과\\n레몬즙을 넣고 살짝 볶아 소스를\\n만든다.\",\"6. 연어, 가지, 토마토, 구운 마늘을\\n담고 소스를 얹어 마무리한다.\"]},{\"id\":\"k326\",\"title\":\"갈릭칩동태구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00234_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00234_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00234_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00234_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00234_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00234_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 동태포(150g)\",\"통마늘(10g)\",\"양념 맛술(10g)\",\"저염된장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"잘 부서지는 동태살을 단단하게 만들기 위해서는 소금에 재워야 하는데,\\n소금 대신 저염된장에 재우면 살이 단단해지면서 염도를 낮출 수 있다.\",\"instructions\":[\"1. 동태는 맛술과 저염된장에 담가\\n재운다.\",\"2. 마늘은 얇게 편으로 썬 후\\n식용유(15g)에 노릇하게 튀긴다.\",\"3. 재운 동태는 흐르는 물에 살짝 헹궈\\n짠맛을 제거한 뒤 물기를 최대한\\n제거한다.\",\"4. 식용유(15g)를 두른 팬에 동태살을\\n얹어 부서지지 않게 굽는다.\",\"5. 갈릭칩을 올려 마무리한다.\"]},{\"id\":\"k327\",\"title\":\"고구마두부스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00235_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00235_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00235_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00235_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00235_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00235_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00235_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"스테이크재료 두부(200g)\",\"고구마(130g)\",\"마늘(15g)\",\"대파(20g)\",\"양파(60g)\",\"다진 견과류(20g)\",\"찹쌀가루(30g)\",\"청국장소스 양송이버섯(20g)\",\"다시마육수(80g)\",\"청국장(15g)\",\"유 자청(10g)\",\"녹말가루(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"청국장은 된장보다 염분을 적게 함유하고 있어 나트륨을 적게 섭취할 수 있다.\\n유자청을 섞어 달콤새콤한 맛을 더해 소금간을 줄였다\",\"instructions\":[\"1. 두부는 물기를 없앤 뒤 체에 밭쳐\\n으깬 뒤 칼등으로 한 번 더 으깬다.\",\"2. 고구마는 삶아 껍질을 벗겨 으깬다.\",\"3. 마늘, 대파, 양파는 잘게 다진 뒤\\n식용유(5g)를 두른 팬에서 살짝 볶아\\n키친타월에 밭쳐 물기를 제거하며\\n식힌다.\",\"4. 볶은 채소, 두부, 고구마,\\n다진 견과류, 찹쌀가루를 섞은 뒤\\n반죽해 둥글 납작하게 모양을\\n빚고, 식용유(15g)를 두른 팬에서\\n앞뒤로 노릇하게 굽는다.\",\"5. 양송이버섯은 채 썬다.\",\"6. 다시마육수에 청국장, 유자청,\\n녹말가루, 양송이버섯을 넣고 조린\\n청국장소스를 곁들여 마무리한다.\"]},{\"id\":\"k328\",\"title\":\"닭가슴살카나페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00236_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00236_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00236_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00236_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00236_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00236_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00236_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 고구마(100g)\",\"우유(110g)\",\"백김치(40g)\",\"비트(40g)\",\"닭가슴살(100g)\",\"후춧가루(0.3g)\",\"새싹(1g)\",\"바나나식초(80g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"후춧가루로만 간을 해서 염도를 낮췄고, 고구마와 바나나에 들어있는\\n칼륨이 몸속 나트륨 배출을 돕는다\",\"instructions\":[\"1. 고구마를 삶아 껍질을 벗겨 으깬 뒤\\n우유와 섞어 고구마무스를 만든다.\",\"2. 백김치와 비트를 작게 썬 뒤\\n백김치에 물이 들도록 절여 놓는다.\",\"3. 닭가슴살을 한입 크기로 썬 후\\n칼등으로 두드린 뒤 후춧가루로\\n밑간한다.\",\"4. 식용유(15g)를 두른 팬에 닭가슴살을\\n올려 굽는다.\",\"5. 구운 닭가슴살 위에 고구마무스,\\n비트에 절인 백김치, 새싹을 얹는다.\",\"6. 그릇에 닭가슴살카나페를 넣은 후\\n바나나식초를 곁들여 마무리한다.\"]},{\"id\":\"k329\",\"title\":\"삼색꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00237_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00237_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00237_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00237_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00237_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00237_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00237_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 돼지고기(목살\",\"120g)\",\"파인애플(30g)\",\"브로콜리(20g)\",\"방울토마토(40g)\",\"배사과소스 배(30g)\",\"사과(50g)\",\"레몬즙(5g)\",\"꿀(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"돼지고기를 나트륨 함량이 높은 쌈장과 고추장, 소금장에 찍어먹는 대신\\n육류와 어울리는 배와 사과를 사용해 만든 새콤달콤한 소스를 곁들여 나트륨 섭취를 줄였다\",\"instructions\":[\"1. 껍질을 벗긴 배, 사과를 믹서기에\\n갈아 레몬즙과 꿀을 넣고\\n배사과소스를 만든다.\",\"2. 돼지고기와 파인애플은 깍둑 썬다.\",\"3. 브로콜리는 약 2~3cm 크기로 자른\\n후 끓는 물에 살짝 데친다.\",\"4. 식용유(5g)를 두른 팬에 돼지고기를\\n한 번 먼저 굽는다.\",\"5. 꼬치에 방울토마토, 구운 돼지고기,\\n파인애플, 브로콜리 순서로 끼운 후\\n굽는다.\",\"6. 노릇하게 구운 꼬치구이에\\n배사과소스를 얹어 마무리한다.\"]},{\"id\":\"k330\",\"title\":\"꽁치채소말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00238_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00238_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00238_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00238_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00238_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00238_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00238_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 꽁치살(200g)\",\"마늘종(30g)\",\"양파(40g)\",\"파프리카(100g)\",\"밀가루(30g)\",\"깻잎(3g)\",\"무순(8g)\",\"새싹(8g)\",\"오렌지소스 오렌지(200g)\",\"레몬즙(15g)\",\"설탕(0.3g)\",\"고운 소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"꽁치에 소금간을 최대한 줄이고, 오렌지소스를 곁들여 비린 맛을 잡으면서 상큼함을 더했다.\",\"instructions\":[\"1. 꽁치는 머리와 꼬리를 떼어 내고\\n포 뜨듯이 길게 살만 발라내 잔뼈를\\n발라 쌀뜨물에 담갔다 건져 물기를\\n제거한다.\",\"2. 오렌지를 간 뒤 레몬즙과 설탕,\\n소금을 섞어 오렌지소스를 만든다.\",\"3. 마늘종은 꽁치 폭에 맞춰 썰고,\\n양파와 파프리카도 채 썬다.\",\"4. 수분을 제거한 꽁치에 밀가루를\\n묻혀 깻잎→마늘종→양파→\\n파프리카 순으로 올려 돌돌 말아\\n꼬치로 꽂아 고정한다.\",\"5. 밀가루를 묻히고 달군 팬에\\n앞뒤가 노릇노릇하게 익힌다.\",\"6. 소스를 팬에 넣고 끓이다가 꽁치\\n꼬치를 넣고 졸인 뒤 그릇에 무순,\\n새싹과 함께 담아 마무리한다.\"]},{\"id\":\"k331\",\"title\":\"차돌박이구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00239_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00239_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00239_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00239_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00239_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00239_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00239_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 연근(30g)\",\"미나리(20g)\",\"오렌지(50g)\",\"오렌지주스(50g)\",\"차돌박이(60g)\",\"어린잎채소(10g)\",\"홍초물 설탕(5g)\",\"홍초(20g)\",\"물(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"염분이 많은 양념 대신에 오렌지와 홍초를 이용해 상큼한 맛을 살리면서 나트륨 함량을 줄였다\",\"instructions\":[\"1. 연근은 얇게 3㎜ 정도의 두께로 썰어\\n홍초물에 담가 절인다.\",\"2. 미나리는 연근과 비슷한 길이로\\n썬다.\",\"3. 오렌지는 껍질은 얇게 벗겨 채 썰고,\\n과육부분은 반달 모양으로 2조각\\n썬다.\",\"4. 과육을 오렌지주스와 섞은 뒤 갈아\\n오렌지소스를 만든다.\",\"5. 팬에 차돌박이를 펼친 뒤\\n오렌지소스를 조금씩 넣으며 익힌다.\",\"6. 그릇에 연근초절임, 미나리,\\n어린잎채소, 차돌박이 순서로\\n담은 뒤 오렌지 껍질과\\n오렌지소스를 얹어 마무리한다.\"]},{\"id\":\"k332\",\"title\":\"간장아귀찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00240_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00240_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00240_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00240_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00240_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00240_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00240_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 아귀(150g)\",\"새우(20g)\",\"미나리(15g)\",\"풋고추(5g)\",\"붉은 고추(5g)\",\"콩나물무침 콩나물(30g)\",\"참기름(3g)\",\"참깨(1g)\",\"간장소스 설탕(1g)\",\"저염간장(3g)\",\"청주(15g)\",\"다시마물(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장소스를 사용하지 않고 저염간장과 천연 조미료를 우린 물로 맛을 내\\n나트륨 섭취를 줄였다.\",\"instructions\":[\"1. 아귀는 얇게 포를 뜬다.\",\"2. 새우를 다져 아귀포 안에 채워 넣은\\n뒤 데친 미나리로 묶는다.\",\"3. 냄비에 간장소스, 아귀,\\n아귀찜양념을 넣고 약한 불에서\\n끓인다.\",\"4. 아귀가 익으면 고추를 어슷 썰어\\n올린 뒤 살짝 더 익힌다.\",\"5. 콩나물은 끓는 물에 데친 뒤 참기름,\\n참깨를 넣고 무친다.\",\"6. 아귀찜에 콩나물무침을 곁들여\\n마무리한다.\"]},{\"id\":\"k333\",\"title\":\"견과류통삼겹살찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00241_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00241_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00241_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00241_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00241_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00241_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00241_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 돼지고기(통삼겹살\",\"200g)\",\"땅콩(15g)\",\"아몬드(5g)\",\"말린 자두(15g)\",\"호두(15g)\",\"새우젓(5g)\",\"마늘(20g)\",\"파프리카(45g)\",\"부추(15g)\",\"돼지고기 밑간 간장(5g)\",\"참기름(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우젓과 마늘에 소금간을 따로 하지 않고 튀겨 함께 곁들여 맛을 내 나트륨 섭취량을 줄였다\",\"instructions\":[\"1. 통삼겹살은 속을 판 뒤 땅콩, 아몬드,\\n말린 자두, 호두로 채운 뒤\\n돼지고기 밑간에 재워 놓는다.\",\"2. 통삼겹살을 김 오른 찜기에 넣어\\n찐다.\",\"3. 물기를 뺀 새우젓과 편 썬\\n마늘을 기름에 튀긴다.\",\"4. 소스 재료를 끓인다.\",\"5. 파프리카는 채 썰고, 부추는 먹기\\n좋은 크기로 썰어 들기름과\\n고춧가루에 버무린다.\",\"6. 통삼겹살을 먹기 좋은 크기로 썰어\\n부추, 파프리카 위에 놓고 튀긴\\n새우젓과 마늘을 올린 뒤 소스를\\n곁들여 마무리한다.\"]},{\"id\":\"k334\",\"title\":\"닭가슴살말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00242_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00242_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00242_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00242_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00242_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00242_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00242_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 닭가슴살(150g)\",\"당근(10g)\",\"시금치(10g)\",\"마른 표고버섯(10g)\",\"간장(5g)\",\"참기름(3g)\",\"견과류(16g)\",\"단촛물 설탕(3g)\",\"식초(10g)\",\"겨자소스 설탕(28g)\",\"발효겨자(28g)\",\"식초(28g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"재료에 따로 간을 하지 않고\\n식초와 겨자를 사용한\\n견과류 소스를 곁들여\\n나트륨 섭취를 줄였다\",\"instructions\":[\"1. 닭가슴살은 곱게 다진다.\",\"2. 당근은 채 썰어서 단촛물에 5분 정도 절이고, 시금치는 데쳐서 물기를 제거하고, 마른 표고버섯은 불린 뒤 곱게 채를 썰어 간장과 참기름에 버무린다.\",\"3. 종이포일에 다진 가슴살을 올리고 그 위에 시금치, 당근, 표고버섯과 견과류를 올려 말아준다\",\"4. 김 오른 찜기에 넣어서 25분간 찐다.\",\"5. 겨자소스를 만든다.\",\"6. 닭가슴살말이에 겨자소스를 곁들여\\n마무리한다.\"]},{\"id\":\"k335\",\"title\":\"두부말이찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00243_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00243_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00243_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00243_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00243_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00243_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00243_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 두부(150g)\",\"불린 표고버섯(50g)\",\"닭가슴살(100g)\",\"톳(50g)\",\"깻잎(10g)\",\"참기름(5g)\",\"반죽양념 다진 파(10g)\",\"다진 마늘(10g)\",\"부순 참깨(5g)\",\"레몬소스 설탕(2g)\",\"레몬즙(3g)\",\"간장(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금간 대신 시큼한 레몬소스로 맛을 내 나트륨 함량을 줄였다.\",\"instructions\":[\"1. 두부는 으깨어 면포에 물기를 짜고,\\n불린 표고버섯도 물기를 꼭 짠 뒤\\n다지고, 닭가슴살은 곱게 다진다.\",\"2. 두부, 표고버섯, 닭가슴살에\\n반죽양념을 넣어 치댄다.\",\"3. 톳은 데쳐서 송송 썬다.\",\"4. 쿠킹포일에 참기름을 바르고 반죽을\\n펼친 뒤 깻잎을 얹고 그 위에 톳을\\n올려 김밥 말듯이 만다.\",\"5. 쿠킹 포일에 구멍을 내고 김이 오른\\n찜통에 10-15분 정도 찐다.\",\"6. 두부말이가 식으면 적당한 크기로\\n썬 뒤 레몬소스를 살짝 뿌려\\n마무리한다.\"]},{\"id\":\"k336\",\"title\":\"미나리명태찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00244_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00244_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00244_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00244_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00244_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00244_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00244_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료 미나리(20g)\",\"명태(150g)\",\"후춧가루(0.1g)\",\"레몬소스 설탕(7g)\",\"레몬(108g)\",\"식초(6g)\",\"저염간장(4g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생선에 양념을 내 익히는 것이 아니라 생선을 찐 다음 소스를 곁들여\\n생선살 속에 간이 배지 않아 나트륨 함량은 낮추고 재료 본연의 맛을 느낄 수 있다.\",\"instructions\":[\"1. 레몬소스를 만들어 약한 불에\\n졸인다.\",\"2. 미나리는 4cm 간격으로 썬 뒤\\n잎 부분을 레몬소스에 버무려\\n놓는다.\",\"3. 즙을 짜고 남은 레몬은 얇게 썰어\\n준비한다.\",\"4. 명태는 손질한 뒤 후춧가루를 뿌려\\n밑간한다.\",\"5. 김 오른 찜기에 면포를 깔고 명태를\\n올린 뒤 미나리줄기와 얇게 썬\\n레몬을 올려서 중간 불에서 10분,\\n약한 불에서 10분 정도 찐다.\",\"6. 명태가 다 익으면 레몬소스에\\n버무린 미나리 잎과 남은\\n레몬소스를 끼얹어 마무리한다.\"]},{\"id\":\"k337\",\"title\":\"불고기덮밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00340_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00340_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00340_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00340_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00340_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00340_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00340_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀밥 200g\",\"소불고기 150g\",\"양파 60g\",\"청고추 15g\",\"홍고추 18g\",\"팽이버섯 20g\",\"계란 60g\",\"쪽파 15g\",\"마늘기름 30g\",\"통깨 5g\",\"양념장 : 맛간장 15g\",\"생강청 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"일반 간장 대신 맛간장도 넣고 특유의 맛을 높이기 위해서 생강청과 다진마늘을 넣어 감칠맛을 높였다.\",\"instructions\":[\"1. 소 불고기는 양념장을 버무려 팬에 볶아준다.\",\"2. 청고추, 홍고추는 가늘게 채 썰어준다.\",\"3. 양파는 채 썰고 쪽파도 한입 크기로 잘라준다.\",\"4. 팽이도 먹기 좋은 크기로 잘라준다.\",\"5. 계란물을 풀어준다.\",\"6. 채소를 각각 볶아주다가 볶은 불고기에 섞어\\n주고 계란물을 풀어서 밥에 올려서 통깨를\\n뿌려 완성한다.\"]},{\"id\":\"k338\",\"title\":\"바비큐리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00341_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00341_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00341_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00341_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00341_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00341_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00341_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통삼겹 200g\",\"조림장 : 맛간장 30g\",\"통후추 2g\",\"발사믹식초 30g\",\"흰후추 1g\",\"청국장리조뜨 : 밥 150g\",\"청국장가루 15g\",\"야채육수 200g\",\"감자 30g\",\"올리브오일 15g\",\"영양부추 20g\",\"곁들이채소 : 적양배추 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"통후추와 맛간장, 발사믹식초를 이용해 조림장을 만들어\\n통삼겹살의 두께가 있어도 간장을 많이 사용 안 해도 깊은 맛을 낼 수가 있다.\",\"instructions\":[\"1. 사과와 적양배추는 먹기 좋은 크기로 잘라준다.\",\"2. 감자를 작은 깍두기 모양으로 자르고 영양부추는\\n송송 잘라주어 청국장 리조또를 만들어준다.\",\"3. 준비된 곁들이 채소를 올리브오일에 볶아준다.\",\"4. 준비된 통삼겹은 물에 한번 80% 이상 데쳐준 후\\n조림장 재료에 물 200g을 넣고 은근히 졸여서\\n익혀준다.\",\"5. 조림장에 졸여지는 통삼겹에 장이 한 큰술\\n남을 정도까지 졸여준다.\",\"6. 접시에 곁들이 채소와 청국장 리조또를 함께\\n올려 셋팅한다.\"]},{\"id\":\"k339\",\"title\":\"간편콩국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00342_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00342_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00342_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00342_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00342_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00342_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00342_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"메밀면 80g\",\"백일송이 25g\",\"마늘기름 15g\",\"통깨 2g\",\"볶은소금 1g\",\"고명 : 애호박 50g\",\"양파 50g\",\"청고추 15g\",\"홍고추 15g\",\"국물 : 두유 200g\",\"두부 60g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 마늘기름을 사용해 채소를 볶을 때 향을 내주어 나트륨 함량을 줄여주었고,\\n두유와 두부를 믹서에 갈아 고소함을 높여서 짜지 않은 콩국수를 만들었다.\",\"instructions\":[\"1. 두유와 두부를 믹서에 생수 100g을 넣고\\n갈아준다.\",\"2. 애호박은 돌려깎기 해서 채 썰어주고 양파,\\n홍고추, 청고추도 가늘게 채 썰어준다.\",\"3. 백일송이는 가늘게 찢어 볶아준다.\",\"4. 애호박, 당근, 청고추, 홍고추를 각각 볶아준다.\",\"5. 메밀면을 삶아서 준비한다.\",\"6. 볼에 메밀면을 담고 고명을 올려준 후 믹서\\n에 갈은 두부두유를 뿌려 완성한다.\"]},{\"id\":\"k340\",\"title\":\"모듬해물찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00343_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00343_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00343_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00343_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00343_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00343_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00343_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"전복 200g\",\"자숙새우 60g\",\"소라살 45g\",\"알마늘 20g\",\"대파 15g\",\"청고추 15g\",\"홍고추 15g\",\"홍피망 15g\",\"양파 50g\",\"양념장 : 멕시코고추 2g\",\"맛간장 30g\",\"올리고당 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해물을 데친 물을 육수로 사용하여 감칠맛을 높였다.\",\"instructions\":[\"1. 자숙새우와 소라살은 한번 데친 후 소라살은\\n먹기 좋게 잘라준다.\",\"2. 전복은 껍질을 벗기지 말고 세척해 준다.\",\"3. 양파, 홍피망, 대파는 먹기 좋게 잘라준다.\",\"4. 청고추, 홍고추도 먹기 좋게 잘라준다.\",\"5. 데친 물 200g에 양념장을 만들어 멕시코\\n고추를 담가 숙성시켜준 뒤 양념장에 알마늘을\\n넣어 끓여준다.\",\"6. 만들어진 양념장에 소라, 전복, 자숙새우,\\n준비된 채소 순으로 넣어 모듬해물찜을 완성\\n한다.\"]},{\"id\":\"k341\",\"title\":\"크렌베리귀리밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00344_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00344_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00344_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00344_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00344_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00344_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"백미 150g\",\"크렌베리 15g\",\"귀리 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크렌베리의 새콤달콤한 맛과 귀리의 고소함으로 나트륨 사용을 줄이고 맛있는 밥을 만들었다.\",\"instructions\":[\"1. 백미와 귀리는 세척해 백미는 30분, 귀리는\\n1시간 정도 불려준다.\",\"2. 귀리를 먼저 물을 넣어 볶아 충분히 익혀준다.\",\"3. 귀리가 어느 정도 익을 때 쯤 쌀을 섞어 한 번\\n더 볶아준다.\",\"4. 귀뢰와 쌀이 익어갈 때 쌀의 물 1배를 넣고\\n밥을 해 준다.\",\"5. 불을 끄고 크린베리를 바로 넣어서 뚜껑을\\n덮어 5분 후에 밥을 완성한다.\"]},{\"id\":\"k342\",\"title\":\"블루베리냉스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00345_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00345_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00345_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00345_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00345_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00345_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00345_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"검은콩두유 50g\",\"꿀 15g\",\"딸기 20g\",\"블루베리 20g\",\"저지방우유 50g\",\"볶은현미 20g\",\"바나나 50g\",\"고명 : 브로콜리 15g\",\"라이스페이퍼 1장\",\"건조체리 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"볶은 현미의 고소함과 건조 체리의 상큼한 맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 브로콜리는 먹기 좋게 잘라서 데쳐준다.\",\"2. 건조체리는 손질해 씨를 제거하고 송송 다져서\\n먹기 좋게 잘라준다.\",\"3. 라이스페이퍼를 뜨거운 물에 데쳐내 체리를\\n말아 체리 만두를 만든다.\",\"4. 만들어진 체리 만두를 팬에 살짝 구워서\\n라이스페이퍼를 고소하게 만든다.\",\"5. 블루베리, 딸기, 바나나, 검은콩두유와 우유를\\n한데 섞어 믹서에 갈아준다.\",\"6. 갈아둔 스프를 담고 브로콜리와 체리 만두를\\n올리고 먹기 전에 볶은 현미를 올려준다.\"]},{\"id\":\"k343\",\"title\":\"토마토제철나물 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00346_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00346_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00346_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00346_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00346_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00346_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"영양부추 20g\",\"치커리 20g\",\"적양배추 50g\",\"알배추 30g\",\"방울토마토 100g\",\"양파70g\",\"두부크루통 : 두부 60g\",\"식용유 20g\",\"소스 : 마늘 7g\",\"참깨 5g\",\"흑임자 5g\",\"꿀 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"식빵 대신 두부로 크루통을 만들어 고소함을 더해 주었고,\\n흑임자와 참깨를 소스로 이용해 짠맛 대신 고소한 맛과 향을 더했다.\",\"instructions\":[\"1. 마늘과 흑임자 참깨를 다져서 소스를 만든다.\",\"2. 영양부추는 5cm 길이로 잘라주고 알배추는\\n채 썰어 냉수에 담가둔다.\",\"3. 방울토마토는 먹기 좋게 자르고 적양배추,\\n양파를 채 썬다.\",\"4. 두부는 기름에 구워서 크루통을 만든다.\",\"5. 준비된 채소를 물기를 빼고 접시에 담아\\n두부크루통을 올린 뒤 소스와 함께 셋팅한다.\"]},{\"id\":\"k344\",\"title\":\"브로콜리스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00347_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00347_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00347_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00347_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00347_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00347_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00347_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭육수 200g\",\"양송이버섯 30g\",\"브로콜리 50g\",\"생크림 50g\",\"함초소금 1g\",\"고명 : 바케트 20g\",\"청양고추버터 : 청양고추 1개\",\"버터 15g\",\"방울토마토 20g\",\"설탕 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭육수를 이용해 풍미를 높였고 닭육수 자체의 맛으로 소금 사용을 줄였다.\\n버터는 일반 버터 대신 저염버터을 이용하면 더 좋다.\",\"instructions\":[\"1. 닭육수에 브로콜리, 양송이를 넣고 끓인다.\",\"2. 생크림을 넣고 갈아준 후 함초소금으로 간을\\n해준다.\",\"3. 다진 청양고추와 버터를 섞어 청양고추버터를\\n만들어준다.\",\"4. 토마토를 믹서에 갈아 설탕과 팬에 섞어서\\n토마토 시럽을 만들어준다.\",\"5. 바게트에 토마토시럽을 발라주고 청양고추\\n버터를 발라 140도 오븐에서 2분간 구워준다.\",\"6. 그릇에 브로콜리스프를 담아주고 청양고추\\n버터 바게트를 곁들여 완성한다.\"]},{\"id\":\"k345\",\"title\":\"초계샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00348_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00348_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00348_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00348_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00348_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00348_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00348_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 250g\",\"달걀 60g\",\"오이 25g\",\"피망 25g\",\"파프리카 25g\",\"시금치 50g\",\"소스 : 잣 20g\",\"식초 15g\",\"연겨자 15g\",\"설탕 15g\",\"참깨 15g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"잣으로 소스를 만들어 고소함을 높여주었고, 참깨와 연겨자 등을 활용하여 소스를 만들어\\n짜지 않고 고소한 샐러드 소스를 만들었다.\",\"instructions\":[\"1. 닭가슴살은 데친 후 가늘게 찢어준다.\",\"2. 달걀은 황백지단을 부쳐서 다이아몬드 모양\\n으로 잘라준다.\",\"3. 오이, 피망, 파프리카도 마름모로 잘라준다.\",\"4. 시금치는 살짝 데쳐서 수분을 짜서 한입\\n크기로 잘라준다.\",\"5. 소스 재료를 믹서에 갈아 소스를 만들어준다.\",\"6. 대추는 돌려깎기 해서 잘라주고 준비된 모든\\n재료를 섞어 샐러드를 만들고 대추채를 올려\\n완성한다.\"]},{\"id\":\"k346\",\"title\":\"토마토맑은장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313031720_1678688240492.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024342_1678340622515.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024356_1678340636568.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024413_1678340653407.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024450_1678340690548.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024507_1678340707224.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024524_1678340724748.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 방울토마토(100g)\",\"시금치(30g)\",\"알배추(25g)\",\"팽이버섯(5g)\",\"•육수 : 닭육수(250g)\",\"•양념 : 일식된장(25g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•닭으로 육수를 우려내고 소량의 된장을 풀어 된장의 구수한 맛과 닭육수의 감칠맛으로 짠맛을 대체했어요.\",\"instructions\":[\"1. 방울토마토를 뜨거운 물에 넣어 껍질을 벗겨주면 더욱 부드럽게 섭취할 수 있다.\",\"2. 시금치와 알배추는 한입 크기로 잘라준 뒤 뜨거운 물에 살짝 익혀준다.\",\"3. 닭육수에 미소된장을 풀어 체에 걸러준다.\",\"4. 체에 거른 된장국에 팽이버섯을 넣고 살짝 끓여준다.\",\"5. 그릇에 토마토, 시금치, 알배추를 담는다.\",\"6. 끓인 된장국을 붓고 완성한다.\"]},{\"id\":\"k347\",\"title\":\"매생이찰범벅\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00350_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00350_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00350_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00350_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00350_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00350_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00350_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"우유100g\",\"매생이 20g\",\"찹쌀 15g\",\"단호박 50g\",\"밤 30g\",\"녹차소금 1g\",\"멸치육수 150g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 녹차소금을 사용하여 염분 섭취량을 줄이고, 멸치로 육수를 우려내 시원한 맛을 높였다.\",\"instructions\":[\"1. 찹쌀은 미리 불려준다.\",\"2. 매생이는 물에 담가 짠기와 이물질을 빼준다.\",\"3. 단호박은 작은 사각형으로 잘라 멸치육수에\\n데쳐준다.\",\"4. 밤은 곱게 다져주어 고명으로 사용한다.\",\"5. 우유와 육수를 섞은 뒤 찹쌀을 끓여준다.\",\"6. 죽이 어느 정도 완성되면 데쳐낸 호박과\\n매생이를 넣어 범벅을 만들어준다.\"]},{\"id\":\"k348\",\"title\":\"통삼겹맥적구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00351_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00351_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00351_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00351_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00351_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00351_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00351_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통삼겹 250g\",\"닭육수 400g\",\"구이소스 : 저염된장 15g\",\"꿀 30g\",\"청주 15g\",\"참기름 15g\",\"다진마늘 10g\",\"다진대파 5g\",\"통깨 10g\",\"샐러드 : 수삼 1개(20g)\",\"알배추 35g\",\"당근 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 사용되는 된장을 나트륨을 낮춘 제품을 사용하였고, 닭을 우려낸 육수로 감칠맛을 높였다.\",\"instructions\":[\"1. 구이소스 재료를 이용해 소스를 만든다.\",\"2. 통삼겹은 닭육수에 삶아 냉수에 헹궈 물기를\\n빼준다.\",\"3. 통삼겹에 만들어진 소스를 발라 준 뒤 10분\\n정도 숙성시켜준다.\",\"4. 샐러드재료는 곱게 채 썰고 냉수에 담가\\n각각의 맛을 중화시켜준다.\",\"5. 샐러드소스를 만들어 샐러드를 버무려준다.\",\"6. 양념에 재워진 통삼겹을 구워주고 샐러드를\\n담아 완성한다.\"]},{\"id\":\"k349\",\"title\":\"닭가슴살샌드스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00352_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00352_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00352_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00352_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00352_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00352_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00352_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 150g\",\"시금치 30g\",\"양파 60g\",\"콜리플라워 30g\",\"브로콜리 100g\",\"양송이 30g\",\"방울토마토 100g\",\"닭육수 200g\",\"다진마늘 5g\",\"버터 15g\",\"흰후추 1g\",\"올리브오일 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭육수를 사용하여 감칠맛을 높이고, 오렌지주스의 상큼한 맛으로 짜지 않은 스테이크 소스를 만들었다.\",\"instructions\":[\"1. 닭은 손질해 주고 흰 후추와 올리브오일로\\n밑간을 해준다.\",\"2. 시금치는 데친 후 수분을 제거해 먹기 좋게\\n잘라주고, 양파는 송송 다져준다. 준비된\\n채소를 마늘과 버터에 볶아주다 생크림을 넣어\\n살짝 졸여준다.\",\"3. 콜리플라워, 브로콜리는 뜨거운 물에 데친 후\\n방울토마토와 함께 팬에 구워준다.\",\"4. 버터에 꿀을 넣고 졸이다가 카라멜 효과를\\n주고 오렌지주스와 레몬즙을 넣고 갈색소스를\\n만든다.\",\"5. 닭가슴살을 포를 떠준 후 졸여준 채소를\\n채워준다.\",\"6. 닭가슴살을 팬에 구워주고 접시에 구운 채소\\n와 소스를 뿌려준다.\"]},{\"id\":\"k350\",\"title\":\"치즈리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00353_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00353_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00353_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00353_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00353_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00353_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00353_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 50g\",\"우유 180mg\",\"유기농 아기치즈 27g\",\"멥쌀 60g\",\"생 표고버섯 15g\",\"참기름 5g\",\"볶은소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 소량의 볶음소금을 사용하여 구수한 맛을 높이고 생 표고 버섯을 채썰어 넣어 부드러운 식감을 살렸다.\",\"instructions\":[\"1. 쌀은 30분전에 불려준다.\",\"2. 단호박은 찐 후 체에 내려준다.\",\"3. 생 표고버섯은 뜨거운 물에 데친 후 아주\\n가늘게 채를 썰어준다.\",\"4. 반은 채 썰어서 참기름으로 간을 해 준다.\",\"5. 팬에 표고를 먼저 볶아주다가 불린 쌀을\\n넣어 볶고 볶은소금으로 간을 해준다.\",\"6. 볶아주던 쌀에 우유를 넣어가면서 계속 볶아\\n주고 단호박과 치즈를 넣어 완성한다.\"]},{\"id\":\"k351\",\"title\":\"가지말이샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00354_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00354_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00354_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00354_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00354_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00354_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00354_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지 250g\",\"감자 50g\",\"미니파프리카 30g\",\"양파 40g\",\"마늘튀김 15g\",\"소스 : 홀그레인머스터드 15g\",\"올리브오일 30g\",\"다진마늘 15g\",\"설탕 5g\",\"올리고당 15g\",\"레드와인 30g\",\"곁들이채소 : 어린채소 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고칼륨 식품인 가지와 다양한 채소를 사용하여 씹는 맛을 높이고, 소스에 머스터드와 레드와인으로 맛을 내\\n머스터드의 고소한 맛과 레드와인의 떫은 맛으로 조화를 이루었다.\",\"instructions\":[\"1. 가지는 길이로 포를 떠 준다. 이때 필러를\\n이용하면 간편하게 할 수가 있다.\",\"2. 감자는 채 썰어 냉수에 담가 전분기를 완전히\\n빼준다.\",\"3. 파프리카, 양파, 청고추는 감자와 같은 길이로\\n채 썰어준다.\",\"4. 소스를 만들어준다.\",\"5. 가지를 기름 없이 구워준다.\",\"6. 구운 가지를 펴 놓고 준비된 채소를 말아서\\n가지말이를 만들고, 마늘튀김을 올려 소스랑\\n완성한 뒤 파마산치즈를 다져서 먹기 직전에\\n뿌려준다.\"]},{\"id\":\"k352\",\"title\":\"유자등갈비구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00485_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00485_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00485_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00485_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00485_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00485_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00485_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"등갈비(150g)\",\"월계수잎(2g)\",\"생강(10g)\",\"통후추(3g)\",\"식용유(10g)\",\"마늘(20g)m 적양배추(20g)\",\"양파(20g)\",\"당근(20g)\",\"- 소스 : 유자청(30g)\",\"사과(20g)\",\"밤(10g)\",\"생크림(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"유자소스가 고기의 잡내를 없애주고, 고기를 연하게 합니다. 새콤달콤한 소스로 인해 나트륨을 적게 넣고도 맛있는 등갈비를 만들 수 있어요.\",\"instructions\":[\"1. 등갈비는 찬물에 약 2시간 이상 담그어\\n핏물을 빼고, 월계수잎과 생강, 통훗추를\\n넣고 약 1시간 삶아 건져 놓는다.\",\"2. 적양배추와 당근, 양파를 채를 썰어\\n찬물에 담그어 놓는다.\",\"3. 유자청에 밤을 다져넣고 사과즙,\\n생크림, 설탕, 소금, 식초를 넣어\\n골고루 섞어 소스를 만든다.\",\"4. 물에 담그어 놓은 채소는 채에 올려\\n물기를 빼 놓는다.\",\"5. 팬에 기름을 두르고 다진마늘을 볶아\\n마늘기름을 만들어 놓는다.\",\"6. 마늘기름으로 삶아 놓은 등갈비를\\n노릇노릇 하게 굽고, 접시에 담아\\n물기를 빼 놓은 채소를 담고 유자소스를\\n올려 완성한다.\"]},{\"id\":\"k353\",\"title\":\"실곤약팟타야\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00486_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00486_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00486_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00486_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00486_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00486_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00486_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"실곤약(120g)\",\"소고기(50g)\",\"숙주(50g)\",\"양파(20g)\",\"청피망(10g)\",\"홍고추(10g)\",\"- 소스 : 굴소스(20g)\",\"다진 마늘(10g)\",\"액젓(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"곤약은 칼륨이 함유 되어있어 나트륨의 배출에 효과가 있어요.\",\"instructions\":[\"1. 뜨거운 물에 실곤약을 넣고, 약 20초\\n정도 삶아 건진다.\",\"2. 양파와 청 피망, 홍고추는 약 5cm\\n길이로 채를 썰고, 홍고추 몇 개는\\n어슷썰어 놓는다.\",\"3. 굴소스에 다진 마늘과 액젓을 넣고\\n섞는다.\",\"4. 냄비에 소스(③)을 넣고 바글바글 끓여\\n팟타야소스를 만들어 놓는다.\",\"5. 소고기는 만들어 놓은 팟타야소스에\\n볶는다.\",\"6. 팬에 기름을 두르고, 채소를 먼저\\n볶다가 실곤약을 넣고 살짝 볶은 후\\n팟타야소스를 넣어 다시 볶다가 접시에\\n담고, 숙주와 고기를 올려 완성한다.\"]},{\"id\":\"k354\",\"title\":\"닭고기라이스롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00487_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00487_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00487_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00487_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00487_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00487_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00487_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(100g)\",\"우유(50g)\",\"후춧가루(0.02g)\",\"수수(20g)\",\"쌀(50g)\",\"파프리카(20g)\",\"당근(20g)\",\"양파(20g)\",\"애호박(20g)\",\"소금(0.5g)\",\"식용유(5g)\",\"- 소스 : 토마토(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"잡곡과 닭고기, 갖가지 채소가 토마토 소스랑 어우러져 간편하고 맛있게 먹을 수 있는 롤이예요\",\"instructions\":[\"1. 닭고기살은 넓게 펴서, 약 10분 정도\\n우유에 담그어 놓는다.\",\"2. 수수와 쌀은 깨끗이 씻어 찬물에 약 30분\\n정도 불려 밥을 지어 놓는다.\",\"3. 파프리카는 가운데 씨를 제거하고 채를\\n썰고, 당근과 양파도 파프리카 길이로\\n채를 썰고, 애호박은 껍질 부분만 돌려\\n깎아 채를 썰어 준비한다.\",\"4. 팬에 기름을 살짝 둘러 준비한 채소(③)에\\n소금을 넣고 볶아 놓는다.\",\"5. 우유에서 닭고기를 건져 후춧가루를\\n살짝 뿌린 후 잡곡밥(②)과 볶아 놓은\\n채소(④)를 넣어 돌돌 말아 준다.\",\"6. 토마토는 입자있게 다져 다진 마늘과\\n함께 볶다가 케첩과 육수를 넣고 끓인\\n뒤 말아놓은 닭고기를 넣고 은근히\\n졸이듯 익혀 완성한다.\"]},{\"id\":\"k355\",\"title\":\"깐풍파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00488_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00488_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00488_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00488_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00488_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00488_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00488_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀가루(200g)\",\"뽕잎가루(10g)\",\"백년초가루(10g)\",\"호박가루(10g)\",\"올리브오일(10g)\",\"닭고기(200g)\",\"생강(5g)\",\"정종(10g)\",\"소금(0.5g)\",\"후춧가루(0.02g)\",\"녹말가루(50g)\",\"달걀(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크림소스의 고소한 맛을 이용하여 나트륨 함량을 낮출 수 있었어요.\",\"instructions\":[\"1. 밀가루는 세 군데로 나눠 각각 뽕잎\\n가루와 호박가루, 백년초가루를\\n넣고 올리브오일을 넣어 반죽을\\n하고, 비닐봉투에 넣어 숙성시킨다.\",\"2. 닭은 작게 토막을 내어 생강과 정종,\\n소금, 후춧가루를 뿌려 숙성시킨다.\",\"3. 파프리카와 피망은 속을 파내고 작은\\n깍두기 모양으로 썰고, 깻잎은 잘게\\n썰어둔다.\",\"4. 숙성된 밀가루를 각각 꺼내 밀대로\\n밀어, 파스타 굵기로 썰어 면을 데쳐\\n접시에 담아 놓는다.\",\"5. 숙성한 닭(②)은 녹말가루와 달걀을\\n섞은 반죽을 입혀 170℃의 튀김기름에\\n두 번 튀겨 기름을 제거한다.\",\"6. 파스타면(④) 위에 튀긴 닭(⑤)을\\n올리고 냄비에 크림소스를 끓이다가\\n설탕을 넣고, 다시 끓으면 파프리카와\\n피망, 깻잎(③)을 넣고, 한 번 더 끓인 후\\n깐풍파스타에 올려 완성한다.\"]},{\"id\":\"k356\",\"title\":\"닭강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00489_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00489_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00489_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00489_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00489_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00489_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00489_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(200g)\",\"카레가루(20g)\",\"녹말가루(10g)\",\"튀김기름(400g)\",\"저염간장(20g)\",\"레몬즙(10g)\",\"설탕(10g)\",\"꿀(10g)\",\"다진마늘(10g)\",\"- 소스 : 요거트(20g)\",\"양파(20g)\",\"당근(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"상큼한 요거트 소스와 카레 튀김옷을 이용하여 별도의 소금을 닭에 넣지 않아도 맛있는 닭강정을 즐길 수 있어요.\",\"instructions\":[\"1. 닭은 깨끗이 씻어 여러 번 토막을 낸다.\",\"2. 토막 낸 닭을 카레가루와 녹말가루에\\n버무려 놓는다.\",\"3. 양파와 당근, 파프리카, 오이는 크기를\\n작은 깍두기 모양으로 썰어 준비한다.\",\"4. 팬에 식용유를 두르고 다진마늘를 살짝\\n볶은 뒤 저염간장에 레몬즙과 설탕, 꿀,\\n볶은 마늘을 넣어 섞는다.\",\"5. 요거트에 썰어 놓은 양파와 당근,\\n파프리카, 오이, 케첩을 넣어 섞어준다.\",\"6. 튀김기름 온도가 170℃가 되면 버무려\\n놓은 닭(②)을 넣고 두 번 튀겨, 기름을\\n제거하고, ④번 소스에 살짝 버무려\\n접시에 담아, 준비한 요거트소스(⑤)를\\n올려 완성한다.\"]},{\"id\":\"k357\",\"title\":\"소고기꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00490_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00490_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00490_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00490_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00490_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00490_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00490_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(100g)\",\"소금(0.5g)\",\"후춧가루(0.02g)\",\"인삼(20g)\",\"올리브오일(5g)\",\"파프리카(20g)\",\"파인애플(30g)\",\"표고버섯(20g)\",\"대파(30g)\",\"토마토(20g)\",\"베이컨(30g)\",\"마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"간장이나 고추장 소스 대신 유자소스를 이용하여 나트륨 함량을 줄일 수 있어요\",\"instructions\":[\"1. 소고기는 포를 두툼하게 떠서, 소금과\\n후춧가루를 뿌려 숙성을 시킨다.\",\"2. 인삼은 뇌두를 잘라 씻어 약 2cm\\n두께로 썰고, 파인애플과 파프리카도\\n두툼하게 썰고, 표고버섯과 대파,\\n토마토를 썰어 준비하고, 베이컨도\\n2cm 길이로 썰어 준비한다.\",\"3. 팬에 기름 없이 파인애플과 파프리카를\\n먼저 굽는다.\",\"4. 잘라놓은 인삼은 올리브오일을 살짝\\n넣고 굽는다.\",\"5. 마늘은 썰어 굽고, 준비한 재료를\\n꼬치에 차례로 꽂아 프라이팬 또는\\n직화로 구워 담는다.\",\"6. 유자청에 저염간장과 레몬, 설탕을\\n넣고 골고루 섞어 구워 놓은 소고기\\n꼬지에 올려 완성한다.\"]},{\"id\":\"k358\",\"title\":\"황태볶음면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00491_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00491_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00491_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00491_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00491_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00491_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00491_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"황태(100g)\",\"새우(20g)\",\"오징어(30g)\",\"굵은 소금(5g)\",\"양파(20g)\",\"마늘(10g)\",\"대파(20g)\",\"표고버섯(10g)\",\"양배추(20g)\",\"라면(70g)\",\"숙주(30g)\",\"올리브오일(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오징어, 새우, 황태 등 해산물의 감칠맛을 이용하여 나트륨 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 다시마는 깨끗이 씻어 찬물에 넣고\\n은근히 끓여 다시마 육수를 만들어\\n생강즙과 저염간장을 넣어 약한 불에서\\n졸여 볶음 간장을 만들어 놓는다.\",\"2. 황태는 강판에 갈아 곱게 가루를 만들어\\n놓는다.\",\"3. 새우는 씻어놓고, 오징어는 소금을\\n이용하여 껍질을 벗기고, 안쪽에 사선\\n으로 칼집을 넣어 모양을 만들어 살짝\\n데쳐 준비한다.\",\"4. 양파와 마늘은 입자있게 다지고, 대파는\\n5cm 길이로 썰어놓고, 표고버섯과\\n양배추도 채를 썰고, 숙주는 다듬어\\n놓는다.\",\"5. 라면은 끓는 물에 데쳐 준비한다.\",\"6. 팬에 올리브오일을 넣어 따근해지면,\\n오징어와 새우를 넣어 볶다가, 다시\\n숙주와 마요네즈, 설탕, ①번 소스와\\n채소를 넣어 센 불에서 재빠르게 볶고,\\n다시 면을 넣어 볶아 완성한다.\"]},{\"id\":\"k359\",\"title\":\"토마토덮밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00492_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00492_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00492_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00492_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00492_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00492_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00492_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(100g)\",\"가지(50g)\",\"새우(20g)\",\"- 소스 : 양파(20g)\",\"마늘(10g)\",\"올리브오일(10g)\",\"토마토소스(20g)\",\"케첩(20g)\",\"토마토(80g)\",\"설탕(5g)\",\"- 곁들임채소 : 어린잎(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토의 칼륨 성분이 나트륨 배출에 도움이 되요.\",\"instructions\":[\"1. 쌀은 물에 불려 밥을 짓고, 가지는 길게\\n썰어 팬에 구워 놓는다.\",\"2. 양파와 마늘은 잘게 다져 준비한다.\",\"3. 토마토는 입자있게 다져 놓는다.\",\"4. 새우는 정종을 넣어 데쳐 껍질을 벗겨\\n준비한다.\",\"5. 팬에 올리브 오일을 넣고 양파와 마늘을\\n먼저 볶는다.\",\"6. 볶아지는 양파와 마늘에 토마토소스와\\n케첩을 넣어 볶다가 토마토와 설탕을\\n넣어 볶다가 졸이고, 밥을 그릇에 담고,\\n구운 가지와 새우를 올린 후 졸여 놓은\\n토마토소스를 위에 올린 후 어린잎을\\n살짝 올려 완성한다.\"]},{\"id\":\"k360\",\"title\":\"표고크림파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00493_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00493_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00493_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00493_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00493_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00493_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00493_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양송이(20g)\",\"표고버섯(80g)\",\"소금(0.5g)\",\"후춧가루(0.02g)\",\"스파게티(100g)\",\"올리브오일(10g)\",\"- 크림소스 : 밀가루(10g)\",\"버터(10g)\",\"우유(200g)\",\"생크림(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"우유를 넣고 소스를 만들면, 영양도 좋고, 나트륨을 적게 넣어도 풍부한 맛을 느낄 수 있어요.\",\"instructions\":[\"1. 양송이는 껍질을 벗겨 형태 그대로\\n썰고, 표고버섯은 기둥을 제거하고\\n편으로 썰어놓는다.\",\"2. 팬에 버터를 살짝 넣고 썰어놓은\\n버섯을 소금을 살짝 뿌려 볶아 준비한다.\",\"3. 냄비에 버터와 밀가루를 넣고, 은근히\\n볶아 화이트루를 만든다.\",\"4. 화이트 루에 우유를 조금씩 넣고 뭉치지\\n않게 풀어 끓이다가 다시 생크림을 넣고\\n한 소큼 끓여 놓는다.\",\"5. 스파게티는 끓는 물에 약 10분 정도\\n삶아 건져 올리브 오일에 볶아 접시에\\n담는다.\",\"6. 끓여 놓은 크림소스에 볶아진 버섯과\\n후춧가루를 넣고 한 소큼 더 끓여\\n스파게티를 담은 접시에 넣고 완성한다.\"]},{\"id\":\"k361\",\"title\":\"떡갈비통치미국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00494_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00494_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00494_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00494_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00494_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00494_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00494_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"동치미(400g)\",\"배(30g)\",\"식초(10g)\",\"다진 소고기(30g)\",\"오이(20g)\",\"당근(20g)\",\"양파(10g)\",\"후춧가루(0.2g)\",\"정종(2g)\",\"설탕(10g)\",\"저염간장(5g)\",\"다진 마늘(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배와 동치미국물이 어우러져 나트륨 사용을 줄일 수 있어요\",\"instructions\":[\"1. 동치미에 배를 갈아 넣고, 설탕과\\n식초를 넣어 양념을 한 후 냉장고에\\n보관한다.\",\"2. 양파는 채를 썰고, 오이와 당근은 편으로\\n썰어 소금물에 살짝 절여 준비한다.\",\"3. 다진 소고기는 다진 대파와 다진 마늘,\\n매실액, 참기름, 통깨, 후춧가루, 정종,\\n설탕, 간장을 넣어 양념을 한다.\",\"4. 양념을 한 소고기를 잘 치대어 둥글게\\n떡갈비를 만들어 냉장고에서 숙성을\\n시킨다.\",\"5. 숙성된 떡갈비를 팬에 기름을 살짝\\n둘러 은근히 익혀, 냅킨에 올려 기름을\\n빼놓는다.\",\"6. 끓는 물에 국수를 삶아 찬물에 여러 번\\n헹구어 건져 그릇에 담고, 그 위에\\n떡갈비를 올리고, 차게 보관한 동치미\\n국물을 부은 뒤 곁들임채소로 오이와\\n당근, 양파를 얹어 완성한다.\"]},{\"id\":\"k362\",\"title\":\"백김치닭살샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00495_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00495_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00495_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00495_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00495_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00495_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00495_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(80g)\",\"월계수잎(1장)\",\"통후추(2g)\",\"정종(10g)\",\"백김치(100g)\",\"토마토(30g)\",\"파프리카(20g)\",\"당근(20g)\",\"브로컬리(20g)\",\"양상추(50g)\",\"- 소스 : 발사믹식초(20g)\",\"설탕(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"백김치로 간을 하여 나트륨 사용을 줄였어요\",\"instructions\":[\"1. 닭고기에 물을 자작하게 넣고\\n월계수잎과 통후추, 정종을 넣고\\n약 20분 정도 삶아 식혀 찢어놓는다.\",\"2. 브로컬리는 끓는 물에 소금을 넣고,\\n데쳐 작게 썰어놓고, 양상추는 물에\\n담그어 놓았다가 먹기 좋게 손으로\\n찢어 놓는다.\",\"3. 파프리카는 속씨를 제거하고, 작은\\n깍둑썰기를 하고, 당근은 5cm 길이로\\n납작하게 썰어놓는다.\",\"4. 브로컬리는 끓는 물에 소금을 넣고 데쳐\\n작게 썰어놓고, 양상추는 물에 담그어\\n놓았다가 먹기 좋게 손으로 찢어 놓는다.\",\"5. 발사믹 식초에 설탕과 올리브 오일을\\n넣고 골고루 섞어 소스를 만들어\\n놓는다.\",\"6. 찢어 놓은 닭고기살과 백김치를 넣고,\\n준비한 채소를 넣어 먹기 직전에 소스를\\n올려 완성한다.\"]},{\"id\":\"k363\",\"title\":\"단호박크림파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00496_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00496_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00496_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00496_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00496_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00496_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00496_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(150g)\",\"파스타(80g)\",\"소금(0.2g)\",\"다진 마늘(10g)\",\"버터(10g)\",\"베이컨(20g)\",\"양송이(20g)\",\"양파(20g)\",\"육수(100g)\",\"우유(50g)\",\"생크림(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"베이컨을 사용하면, 소금을 별도로 넣지 않아도 맛이 좋은 크림 파스타를 만들 수 있어요.\",\"instructions\":[\"1. 단호박은 잘라 씨를 제거하고 껍질을\\n벗겨 김이 오른 찜통에서 약 20분 정도\\n찐다.\",\"2. 찐 단호박이 한 김 식으면, 채에 곱게\\n내려 준비하고, 스파게티는 소금을\\n넣고 삶아 건져놓는다.\",\"3. 베이컨은 입자있게 썰고, 양송이버섯은\\n껍질을 벗겨 다지고, 양파도 입자있게\\n다진다.\",\"4. 팬에 버터를 녹인 뒤 다진 마늘을 먼저\\n넣고 은근히 볶아 향을 만든다.\",\"5. 볶은 마늘(④)에 베이컨과 양송이,\\n양파를 넣고 다시 볶는다.\",\"6. 볶은 채소(⑤)에 육수를 붓고 끓이다가\\n으깬 단호박(②), 생크림, 우유를 넣어\\n한소끔 끓인 뒤 삶아놓은 스파게티면\\n(②)을 넣고 다시 한 번 더 끓여 완성\\n한다.\"]},{\"id\":\"k364\",\"title\":\"견과편수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00497_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00497_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00497_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00497_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00497_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00497_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00497_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"흑임자(20g)\",\"밀가루(200g)\",\"우유(100g)\",\"닭가슴살(100g)\",\"후춧가루(0.01g)\",\"다진 마늘(10g)\",\"부추(20g)\",\"양파(20g)\",\"다진 대파(10g)\",\"- 육수 : 마(20g)\",\"바나나(30g)\",\"머스터드(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"견과를 사용하여 단백하여 소금을 적게 넣어도 맛이 좋아 나트륨 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 흑임자는 곱게 갈아 밀가루와 우유를\\n넣고 반죽을 해서 비닐에 넣어 숙성\\n시킨다.\",\"2. 닭가슴살은 삶아 건져 후춧가루를\\n살짝 넣고, 입자있게 다진다.\",\"3. 입자있게 다진 닭가슴살을 마늘과 함께\\n팬에서 볶아놓는다.\",\"4. 마와 바나나는 강판에 갈고, 캐슈넛과\\n잣은 입자있게 다진 뒤 냄비에 마,\\n바나나, 캐슈넛, 잣, 머스터드를 넣어\\n섞은 뒤, 우유를 넣고 살짝 끓여 편수\\n육수를 만들어 놓는다.\",\"5. 부추와 양파, 파는 입자있게 썰어, 볶아\\n놓은 닭가슴살(③)에 섞어 편수 속을\\n만들어 놓는다.\",\"6. 숙성시킨 밀가루 반죽(①)은 얇게\\n밀어 사각형으로 썰어 그 안에 속을\\n채워 넣고, 찜통에 약 5분 정도 쪄\\n접시에 담고, 그 위에 편수 육수를\\n올려 완성한다.\"]},{\"id\":\"k365\",\"title\":\"바지락실곤약파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00498_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00498_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00498_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00498_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00498_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00498_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00498_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바지락(100g)\",\"브로컬리(20g)\",\"소금(2g)\",\"마늘(10g)\",\"파프리카(20g)\",\"청양고추(10g)\",\"올리브오일(5g)\",\"실곤약(100g)\",\"후춧가루(0.1g)\",\"- 곁들임채소 : 어린싹(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바지락을 육수로 사용해 나트륨 함량을 줄일 수 있었어요.\",\"instructions\":[\"1. 끓는 물에 바지락을 넣고, 바지락이\\n입을 벌릴 때 까지 삶는다.\",\"2. 삶아진 바지락을 채에 밭쳐 바지락\\n국물을 만들어 놓는다.\",\"3. 브로컬리는 끓는 물에 소금을 조금\\n넣어 데쳐 찬물에 헹구어 잘라놓고,\\n마늘은 편으로 썰고, 파프리카는 채를\\n썰고, 청양고추는 어슷썰어 놓는다.\",\"4. 팬에 올리브 오일을 조금 넣고 마늘과\\n청양고추를 먼저 볶는다.\",\"5. 볶아지는 팬에 바지락과 브로컬리를\\n넣고 볶는다.\",\"6. 볶아지는 팬에 바지락 국물을 넣어\\n졸이다가 실곤약과 파프리카, 후춧\\n가루를 넣고, 한 번 더 졸여 완성한다.\"]},{\"id\":\"k366\",\"title\":\"황태리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00499_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00499_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00499_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00499_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00499_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00499_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00499_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(100g)\",\"소금(0.2g)\",\"홍합(50g)\",\"버터(5g)\",\"황태(100g)\",\"육수(100g)\",\"생크림(20g)\",\"달걀(10g)\",\"참기름(5g)\",\"통깨(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"홍합 육수를 사용하여 나트륨 사용은 줄이고 감칠맛은 높였어요.\",\"instructions\":[\"1. 두부는 김이 오르는 찜통에 소금을\\n넣고 약 5분 정도 쪄 놓는다.\",\"2. 황태는 강판에 갈아 보프리를 만들어\\n놓는다.\",\"3. 홍합은 끓는 육수에 데쳐 육수는 따로\\n걸러 놓고, 홍합은 살만 꺼내 따로 준비\\n한다.\",\"4. 냄비에 버터를 녹이고, 두부와 홍합을\\n으깨어 볶는다.\",\"5. 볶아지는 냄비에 만들어 놓은 육수와\\n생크림을 넣고, 골고루 섞어 가면서\\n볶는다.\",\"6. 두부가 육수에 볶아지면, 마지막에\\n황태보프라기를 넣고, 달걀과 참기름\\n통깨를 넣어 살짝 익혀 완성한다.\"]},{\"id\":\"k367\",\"title\":\"깻잎애호박찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00646_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00646_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00646_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00646_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00646_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00646_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00646_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"애호박(1개)\",\"깻잎(3장)\",\"양파(30g)\",\"피망(30g)\",\"파프리카(50g)\",\"저염간장(50g)\",\"매실액(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장에 양파를 넣어 나트륨을 줄일 수 있고, 매실액으로 맛을 한층 더 높일 수 있어요.\",\"instructions\":[\"1. 애호박은 길게 반으로 자른다.\",\"2. 자른 애호박에 칼집을 넣는다.\",\"3. 깻잎은 잘게 썰고, 양파는 곱게 다지고\\n피망, 파프리카는 입자있게 썬다.\",\"4. 저염간장에 다진 양파와 매실액을 넣고\\n잘 섞어 양념장을 만든다.\",\"5. 양념장에 피망, 파프리카, 깻잎을\\n섞는다.\",\"6. ?번을 칼집낸 호박 가운데 넣고 찜통\\n에서 5분 정도 쪄 낸 뒤 그릇에 담아 저\\n염간장소스를 한번 더 올린다.\"]},{\"id\":\"k368\",\"title\":\"녹차와 대추밀전병\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00647_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00647_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00647_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00647_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00647_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00647_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00647_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(등심\",\"120g)\",\"오이(50g)\",\"당근(30g)\",\"양파(30g)\",\"표고버섯(1개)\",\"대추(5알)\",\"계피가루(10g)\",\"밀가루(200g)\",\"녹차가루(30g)\",\"달걀(1개)\",\"잣(5알)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"녹차가 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 계피가루와 대추를 삶아 건지고, 삶은\\n물은 따로 준비한다.\",\"2. 밀가루에 대추와 계피 삶은 물을 넣고\\n전병 반죽을 한다.\",\"3. 팬에 기름을 살짝 두르고 전병반죽을\\n작은 국자로 떠넣고 전병을 만든다.\",\"4. 달걀은 황백으로 나눠 지단을 부쳐\\n채를 썬다.\",\"5. 오이, 당근, 양파 및 표고버섯은 채를\\n썰어 소금에 살짝 절여 팬에 볶아 따로\\n준비한다.\",\"6. 소고기는 채를 썰어 저염간장으로 양념\\n하고 팬에 볶은 후, 만들어 놓은 전병에\\n볶은 야채와 소고기를 올려 돌돌 말아\\n접시에 담고 그 위에 잣을 올리고\\n녹차를 만든다.\"]},{\"id\":\"k369\",\"title\":\"단호박 된장매쉬와 해물굴림만두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00648_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00648_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00648_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00648_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00648_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00648_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00648_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(우둔살\",\"50g)\",\"새우(3마리)\",\"흰살생선(100g)\",\"단호박(1/2개)\",\"고구마(50g)\",\"녹말(10g)\",\"달걀(1개)\",\"된장(30g)\",\"소금(0.1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장에 고구마와 단호박을 섞어 나트륨을 줄이고 짠맛이 줄어든 부드러운 된장소스를 만들었어요.\",\"instructions\":[\"1. 새우와 흰살생선, 우둔살은 쪄낸 후 한\\n김 식힌다.\",\"2. 쪄낸 새우와 흰살 생선, 우둔살을 곱게\\n다진다.\",\"3. ?번에 녹말과 달걀물을 넣고 소금을\\n조금 넣고 골고루 섞어 숙성시킨다.\",\"4. 고구마와 단호박은 찜통에 찐다.\",\"5. 찐 고구마와 단호박을 곱게 갈아\\n된장을 섞는다.\",\"6. 숙성된 반죽으로 해물완자를 빚고,\\n된장을 섞은 단호박, 고구마를\\n끓이면서 해물 완자를 넣어준다\"]},{\"id\":\"k370\",\"title\":\"닭순대\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00649_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00649_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00649_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00649_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00649_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00649_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00649_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"200g)\",\"당면(50g)\",\"달걀(1개)\",\"부추(20g)\",\"밀가루(10g)\",\"저염간장(10g)\",\"당근(30g)\",\"참기름(5g)\",\"후춧가루(0.01g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"담백한 닭가슴살을 갖은 야채와 함께 쪄내서 나트륨을 적게 넣어도 그 맛을 충분히 느낄 수 있어요.\",\"instructions\":[\"1. 닭가슴살은 포를 떠 넓게 편다.\",\"2. 포 뜬 닭가슴살에 소금, 후춧가루로\\n밑간을 한다.\",\"3. 당면은 따뜻한 물에 불려 건진 뒤 3cm\\n길이로 썬다.\",\"4. 부추는 송송 썰고 당근은 곱게 채썬다.\",\"5. 당면, 당근, 부추는 골고루 섞어\\n저염간장으로 간을 한다.\",\"6. 밑간이 된 닭가슴살에 ?번을 넣고\\n돌돌 말아 김이 오른 찜통에서 약 10분\\n정도 찐 뒤 한 김 식혀 썬다.\"]},{\"id\":\"k371\",\"title\":\"도라지 유자청생채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00650_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00650_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00650_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00650_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00650_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00650_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00650_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"도라지(120g)\",\"풋고추(1개)\",\"홍고추(1개)\",\"양파(30g)\",\"라임주스(20g)\",\"흑임자(20g)\",\"유자청(30g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라임과 유자로 만든 소스의 새콤달콤한 맛 때문에 소금을 적게 사용할 수 있어요.\",\"instructions\":[\"1. 통 도라지는 껍질을 벗긴다\",\"2. 껍질을 벗긴 도라지는 잘라 소금에\\n살짝 절여 쓴맛을 뺀다.\",\"3. 청·홍고추와 양파는 채썬다.\",\"4. 썰어 놓은 청. 홍고추와 양파는 차가운\\n물에 담군 뒤 체에 밭쳐 물기를 뺀다.\",\"5. 라임쥬스, 흑임자와 유자청을 골고루\\n섞어 소스를 만들고 도라지와 야채를\\n넣어 버물려 접시에 담는다\",\"6. 홍고추는 반으로 잘라 장식한다.\"]},{\"id\":\"k372\",\"title\":\"돼지고기 숙주덮밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031030_1678342230794.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031102_1678342262765.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031118_1678342278695.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031132_1678342292452.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031145_1678342305935.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031158_1678342318590.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031215_1678342335942.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 가다랑어포(10g)\",\"돼지고기(100g)\",\"양파(30g)\",\"표고버섯(1개)\",\"팽이버섯(20g)\",\"쪽파(10g)\",\"달걀(1개)\",\"쌀(90g)\",\"숙주(50g)\",\"•밑간 : 소금(1g)\",\"후춧가루(1g)\",\"•육수 :다시마(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•다시마와 가다랑어포로 만든 육수를 사용하여 소금 사용량은 줄이고 맛을 살렸어요.\",\"instructions\":[\"1. 다시마 우린 물에 가다랑어포를 넣고 10분간 담갔다가 체에 거르고, 쌀로 밥을 짓는다.\",\"2. 돼지고기는 소금과 후춧가루로 밑간을 한 뒤 굽는다.\",\"3. 양파, 표고버섯, 팽이버섯은 채 썰고, 쪽파는 버섯 길이로 썬다.\",\"4. 육수에 저염간장을 넣어 한소끔 끓이다가 양파와 버섯을 넣고 끓인다.\",\"5. 다시 한 번 끓어오르면 쪽파와 달걀을 고루 풀어 넣고 젓지 말고 그대로 끓인다.\",\"6. 그릇에 밥을 담고, 돼지고기와 숙주를 올린 뒤 뜨거운 육수를 부어 마무리한다.\"]},{\"id\":\"k373\",\"title\":\"두부스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00652_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00652_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00652_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00652_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00652_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00652_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00652_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(200g)\",\"양파(30g)\",\"새송이버섯(1개)\",\"달걀(1개)\",\"케일(1장)\",\"당근(20g)\",\"토마토(100g)\",\"칵테일새우(30g)\",\"레몬(1/4개)\",\"파인애플(50g)\",\"마늘(10g)\",\"올리브오일(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파인애플과 올리브오일을 섞어 만든 소스는 새콤달콤해서 소금을 사용하지 않아도 맛있어요.\",\"instructions\":[\"1. 새우, 양파, 당근, 새송이버섯은\\n입자있게 다진다.\",\"2. 두부는 곱게 으깬다.\",\"3. ?번과 으깬 두부, 소금, 달걀을 골고루\\n섞는다.\",\"4. 파인애플을 넣어 곱게 갈아\\n올리브오일을 섞어 소스를 만든다.\",\"5. 으깬 두부를 원형으로 만든다.\",\"6. 팬에 기름을 두르고 두부와 토마토를\\n굽고, 접시에 케일을 깔고 그 위에\\n두부와 토마토를 올린 뒤\\n파인애플소스를 올린다.\"]},{\"id\":\"k374\",\"title\":\"들깨곤약수제비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00653_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00653_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00653_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00653_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00653_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00653_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00653_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"곤약(150g)\",\"표고버섯(1개)\",\"새송이버섯(1개)\",\"들깨가루(200g)\",\"사골육수(400g)\",\"마늘(5g)\",\"식초(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"곤약은 칼륨이 함유되어 있어 나트륨을 배출을 도와주는 효과가 있어요.\",\"instructions\":[\"1. 곤약은 얇게 썬다.\",\"2. 끓는 물에 식초를 한두 방울 넣고, 썰어\\n놓은 곤약을 데친다.\",\"3. 표고는 불려서 채를 썬다.\",\"4. 마늘을 다져서 냄비에 볶는다.\",\"5. 냄비에 표고버섯과 새송이버섯을 넣고\\n함께 볶는다.\",\"6. 냄비에 들깨가루와 사골육수를 넣고\\n끓인 뒤 데친 곤약을 넣은 뒤 한소끔 더\\n끓인다.\"]},{\"id\":\"k375\",\"title\":\"먹물소스를 곁들인 토마토피클\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00654_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00654_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00654_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00654_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00654_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00654_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00654_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"마(50g)\",\"우엉(50g)\",\"토마토(200g)\",\"배(1/2개)\",\"새싹(10g)\",\"피클링스파이스(10g)\",\"와인(20g)\",\"먹물(10g)\",\"설탕(50g)\",\"식초(30g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토는 체내에 나트륨 배출을 도와주는 역할을 해요.\",\"instructions\":[\"1. 물 한 컵에 설탕, 식초, 소금,\\n피클링스파이스를 넣고 식촛물을\\n만든다.\",\"2. 배는 스쿱으로 동그랗게 판다.\",\"3. 토마토는 1/6등분으로 썬다.\",\"4. 마와 우엉은 슬라이스 한다.\",\"5. 썰어 놓은 마와 우엉을 식촛물에\\n담근다.\",\"6. 와인에 먹물, 설탕을 넣고 섞어\\n식촛물에 넣고 배, 토마토, 새싹을\\n넣는다.\"]},{\"id\":\"k376\",\"title\":\"묵은지고등어와 새우말이꼬치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00655_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00655_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00655_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00655_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00655_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00655_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00655_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고등어(1마리)\",\"새우(5마리)\",\"새송이버섯(1개)\",\"당근(30g)\",\"미나리(20g)\",\"깻잎(2장)\",\"가지(20g)\",\"오이(30g)\",\"아몬드(20g)\",\"마늘(20g)\",\"파프리카(50g)\",\"어린잎(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"묵은지를 물에 헹궈서 사용하면 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 고등어는 길게 포를 뜬다.\",\"2. 새우는 껍질을 벗겨 손질한다.\",\"3. 새송이와 당근은 채썬다\",\"4. 미나리는 끓는 물에 살짝 데친다.\",\"5. 묵은지는 흐르는 물에 헹군 뒤,\\n묵은지에 고등어를 넣고 새우, 새송이,\\n당근, 가지를 넣고 돌돌 말아 미나리로\\n묶은 뒤 찐다.\",\"6. 양상추, 오이, 깻잎, 파프리카를\\n채썰고 땅콩가루를 버무려 함께\\n담아낸다.\"]},{\"id\":\"k377\",\"title\":\"버섯배추말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00656_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00656_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00656_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00656_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00656_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00656_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00656_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추(5장)\",\"양배추(20g)\",\"표고버섯(2개)\",\"만송이버섯(50g)\",\"미나리(30g)\",\"다시마(20g)\",\"식초(20g)\",\"설탕(20g)\",\"소금(0.2g)\",\"저염간장(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장에 다시마물, 설탕, 식초를 넣어 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 버섯은 채썬다.\",\"2. 끓는 물에 채썰어 놓은 버섯을\\n데쳐낸다.\",\"3. 다시마는 물에 담궈 다시마 물을\\n만들어 식초와 설탕 저염간장을 넣고\\n골고루 섞어 소스를 만들어 놓는다.\",\"4. 미나리는 끓는 물에 소금을 넣고\\n데친다.\",\"5. 배추는 끓는 물에 양배추와 함께 데쳐\\n찬물에 헹구고 양배추는 채 썬다.\",\"6. 김발에 데친 배추를 놓고 표고버섯,\\n만송이버섯, 미나리, 양배추 채를 넣고\\n돌돌 말아 먹기 좋게 썰어 접시에 담은\\n뒤 소스를 담는다.\"]},{\"id\":\"k378\",\"title\":\"봄날의 연못\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00657_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00657_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00657_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00657_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00657_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00657_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00657_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"문어(100g)\",\"양파(30g)\",\"오이(30g)\",\"배(1/4개)\",\"토마토(50g)\",\"유자청(30g)\",\"레몬(1/4개)\",\"올리브오일(10g)\",\"라임(1/2개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라임과 유자청의 상큼한 맛 덕분에 간을 적게 해도 맛있게 만들 수 있어요.\",\"instructions\":[\"1. 끓는 물에 문어를 넣고 약 10분 정도\\n삶아 건진다.\",\"2. 라임은 얇게 썬다.\",\"3. 삶은 문어를 얇게 저미고 라임을 한 장\\n한 장 넣고 숙성 시킨다.\",\"4. 양파, 오이는 채썬다.\",\"5. 배와 토마토는 주사위 모양으로 썬다.\",\"6. 유자청, 레몬, 올리브오일, 소금으로\\n소스를 만들고, 접시에 문어와 라임을\\n담고 그 옆에 썰어 놓은 야채와 과일을\\n올려 소스를 올린다.\"]},{\"id\":\"k379\",\"title\":\"산나물 유부초밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00658_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00658_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00658_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00658_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00658_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00658_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00658_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"취나물(50g)\",\"참나물(30g)\",\"곤드레나물(30g)\",\"유부(50g)\",\"쌀(200g)\",\"식초(20g)\",\"설탕(30g)\",\"소금(0.2g)\",\"토마토(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"식이섬유가 풍부한 나물들은 장운동을 활발하게 도와주고 나트륨 배출도 도와줘요.\",\"instructions\":[\"1. 쌀은 깨끗이 씻어 30분 정도 불린 뒤\\n고슬고슬하게 밥을 짓는다.\",\"2. 취나물과 참나물은 끓는 물에 소금을\\n넣고 데쳐 헹군다.\",\"3. 곤드레나물은 충분히 불려 삶아\\n헹군다.\",\"4. 유부는 끓는 물에 살짝 데쳐 기름기를\\n제거 하고 반으로 자른다.\",\"5. 식초, 설탕, 소금을 섞어 촛물을\\n만든다.\",\"6. 촛물을 밥에 섞고 준비한 나물을 다져\\n골고루 섞고 데친 유부에 넣고 초밥을\\n만들어 접시에 담은 뒤 나물과\\n토마토를 올린다.\"]},{\"id\":\"k380\",\"title\":\"삼삼한 롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00659_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00659_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00659_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00659_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00659_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00659_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00659_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(훈제연어\",\"120g)\",\"양파(30g)\",\"아보카도(1/4개)\",\"당근(30g)\",\"감자(50g)\",\"새송이버섯(1개)\",\"레몬(1/4개)\",\"사워크림(50g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사워크림에 감자를 섞어 만든 부드러운 메쉬감자가 훈제연어의 짠맛을 줄여줘요.\",\"instructions\":[\"1. 훈제연어는 길게 손질한다\",\"2. 아보카도는 길게 채 썬다.\",\"3. 양파, 당근, 새송이버섯도 길게 채\\n썬다.\",\"4. 감자는 삶아 체에 내려 소금과\\n사워크림을 넣고 잘 섞어서 틀에\\n담는다.\",\"5. 팬에 양파, 당근, 새송이버섯을 각각\\n볶는다.\",\"6. 사워크림과 레몬즙을 섞어 소스를\\n만들고 훈제 연어에 준비된 야채를\\n넣고 돌돌 말아 먹기 좋게 썰어 접시에\\n담고, 한쪽에 감자를 담은 뒤\\n사워소스를 올린다.\"]},{\"id\":\"k381\",\"title\":\"삼색채소 냉파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00660_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00660_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00660_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00660_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00660_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00660_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00660_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"100g)\",\"파스타(100g)\",\"쥬키니호박(50g)\",\"사과(1/4개)\",\"비트(50g)\",\"레몬(1/4개)\",\"마늘(20g)\",\"시금치(30g)\",\"소금(0.2g)\",\"올리브오일(20g)\",\"꿀(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과와 비트, 레몬으로 만든 소스는 닭가슴살과 어우러져 짜지 않고 맛있게 만들 수 있어요.\",\"instructions\":[\"1. 끓는 물에 파스타를 넣고 약 10분 정도\\n삶아 건져 올리브오일을 살짝 바른다.\",\"2. 쥬키니 호박은 채썰어 소금에 절인 뒤\\n볶는다.\",\"3. 닭가슴살은 마늘을 넣고 삶은 뒤 먹기\\n좋게 찢는다.\",\"4. 사과와 비트, 레몬을 믹서에 갈아\\n소스를 만든다.\",\"5. 소스에 꿀을 넣어 맛을 내고 차갑게\\n보관한다.\",\"6. 팬에 삶아 놓은 파스타를 넣고 볶다가\\n닭살과 호박채, 시금치를 넣고 볶은 뒤\\n접시에 담고 차갑게 보관한 소스를\\n올린다.\"]},{\"id\":\"k382\",\"title\":\"새우보리죽 고등어스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00661_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00661_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00661_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00661_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00661_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00661_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00661_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고등어(1/2마리)\",\"새우(3마리)\",\"보리(100g)\",\"생강(10g)\",\"레몬(1/4개)\",\"막걸리(50g)\",\"비트(50g)\",\"설탕(20g)\",\"식초(20g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새콤달콤한 비트 피클은 고등어의 비린맛을 줄여 주고, 새우를 넣고 죽을 쑤면 소금 간을 하지 않아 나트륨을 줄일 수 있었어요.\",\"instructions\":[\"1. 새우는 껍질을 벗겨 손질한다.\",\"2. 보리는 깨끗이 씻어 불린다.\",\"3. 불린 보리와 새우에 5배 정도 물을 넣고\\n죽을 쑨다.\",\"4. 고등어는 포를 뜬다.\",\"5. 포 뜬 고등어에 생강, 레몬, 막걸리를\\n넣고 비린맛을 제거한다.\",\"6. 비트에 설탕, 식초, 소금을 넣고 피클을\\n만들고, 보리죽이 끓으면 포 뜬\\n고등어를 넣고 은근히 익힌다.\"]},{\"id\":\"k383\",\"title\":\"소금없는 초밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00662_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00662_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00662_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00662_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00662_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00662_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00662_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"참치(100g)\",\"파프리카(50g)\",\"아스파라거스(3개)\",\"표고버섯(2개)\",\"달걀(2개)\",\"밥(200g)\",\"김(10g)\",\"다시마(100g)\",\"무(30g)\",\"가쓰오부시(20g)\",\"와사비(20g)\",\"식초(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마와 가쓰오부시로 육수를 만들어 촛물을 만들면, 소금을 적게 사용할 수 있어요.\",\"instructions\":[\"1. 냄비에 다시마와 무를 넣고 끓이다가\\n가쓰오부시를 넣고 불을 꺼 진한\\n육수를 만든다.\",\"2. 육수에 식초, 설탕, 소금을 넣고 촛물을\\n만든다.\",\"3. 참치는 불에 타다끼 한 뒤 두툼하게\\n썬다.\",\"4. 파프리카는 직화로 겉만 태워 참치\\n크기로 썬다.\",\"5. 아스파라거스와 표고버섯은 살짝 데쳐\\n편으로 썬다.\",\"6. 육수에 달걀을 풀어 두툼하게 지단을\\n부쳐 썰고, 밥에 촛물을 넣고 골고루\\n섞어 초밥을 만든 뒤 와사비, 참치,\\n달걀, 표고버섯, 파프리카 순으로 올려\\n김으로 띠를 두른다.\"]},{\"id\":\"k384\",\"title\":\"잣소스새송이볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102053_1416273653440.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/725-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/725-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/725-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/725-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/725-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/725-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새송이 버섯 30g\",\"빨간 파프리카 10g\",\"노란 파프리카 10g\",\"찹쌀가루 20g\",\"물 30g\",\"소금 0.25g\",\"올리브유 4g\",\"잣 5g\",\"꿀 0.5g\",\"우유 5g\",\"소금 0.25g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"반죽에 단호박 가루를 섞어 부치면 색도 곱고 달큰한 맛의 단호박 찹쌀전병이 된다.\",\"instructions\":[\"1. 새송이버섯과 파프리카는 가늘게 채썬다.\",\"2. 채선 야채는 팬에 기름을 두르고 살짝 볶아낸다.\",\"3. 찹쌀가루, 물, 소금을 섞어 찹쌀 반죽을 만든다.\",\"4. 팬에 기름을 두르고 반죽을 한 스푼씩 떠 넣어 동그랗게 부친다.\",\"5. 소스 재료를 모두 넣어 믹서에 간다.\",\"6. 채소볶음을 잣소스에 무쳐 찹쌀전병 위에 한 스푼씩 올려낸다.\"]},{\"id\":\"k385\",\"title\":\"더덕얼갈이겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102056_1416273656078.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/727-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/727-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/727-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/727-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/727-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/727-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"얼갈이 배추 50g\",\"더덕 20g\",\"까나리액젓 3g\",\"고춧가루 1.7g\",\"깨소금 1g\",\"다진 파 2.5g\",\"다진 마늘 1.25g\",\"다진 생강 0.65g\",\"소금 0.5g\",\"국간장 3g\",\"물 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장을 미리 만들어 하루 밤 숙성시키면 맛이 더욱 좋아진다. - 양념장을 한번에 만들어 냉동해 두고 사용하면 시간을 절약할 수 있다\",\"instructions\":[\"1. 얼갈이는 깨끗이 씻어 한입 크기로 뜯는다.\",\"2. 더덕은 껍질을 벗긴다.\",\"3. 껍질 벗긴 더덕은 굵게 채 썰어 소금물에 담가둔다.\",\"4. 양념장 재료를 모두 섞어 양념장을 만든다.\",\"5. 더덕을 건져 물기를 제거한다.\",\"6. 더덕과 얼갈이 배추에 양념장을 넣고 가볍게 버무린다.\"]},{\"id\":\"k386\",\"title\":\"과일겨자채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102058_1416273658950.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/728-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/728-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/728-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/728-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/728-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/728-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과 25g\",\"배 50g\",\"밤 10g\",\"대추 6g\",\"곶감 10g\",\"호두 5g\",\"땅콩 5g\",\"양상추 15g\",\"연겨자 1.25g\",\"연유 2.5g\",\"사과식초 2.5g\",\"꿀 3.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"샐러드를 크래커 등에 올려 카나페로 먹어도 맛있고 샌드위치 속으로 사용해도 좋다.\",\"instructions\":[\"1. 사과와 배는 사방 2cm 네모로 썰고, 밤도 얇게 썰어준다.\",\"2. 1을 설탕물(물 1컵 + 설탕 2.5g)에 담근다.\",\"3. 대추, 곶감은 굵게 채 썰고 호두, 땅콩은 굵게 다진다.\",\"4. 분량의 재료를 섞어 겨자소스 만든다.\",\"5. 과일을 체에 받쳐 물기를 빼고 소스에 버무린다.\",\"6. 한입 크기로 자른 양상추에 샐러드를 올려낸다.\"]},{\"id\":\"k387\",\"title\":\"콜라비물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102100_1416273660762.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/729-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/729-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/729-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/729-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/729-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/729-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콜라비 10g\",\"당근 3g\",\"오이 6g\",\"청고추 2g\",\"홍고추 1g\",\"실파 0.5g\",\"소금 0.5g\",\"물 60g\",\"찹쌀가루 10g\",\"배 10g\",\"적양파 10g\",\"소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"남은 콜라비는 채 썰어 사과, 오이와 함께 비빔국수에 넣어 먹어도 맛있다.\",\"instructions\":[\"1. 콜라비, 당근, 오이는 나박 썬다.\",\"2. 고추는 둥글게 썰고 실파는 3cm 길이로 썬다.\",\"3. 콜라비를 소금에 살짝 절인다.\",\"4. 물에 찹쌀을 풀어 찹쌀풀을 쑤어 식힌다.\",\"5. 찹쌀풀에 배와 적양파를 갈아 넣어 국물을 만든다.\",\"6. 국물에 소금을 넣어 간을 맞추고 썰어놓은 채소에 부어 용기에 담아 익혀 먹는다.\"]},{\"id\":\"k388\",\"title\":\"고구마라떼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102102_1416273662245.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/730-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/730-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/730-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/730-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/730-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/730-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 90g\",\"우유 100g\",\"플레인 요거트 30g\",\"다진 호두 10g\",\"올리고당 7g\",\"계피가루 0.25g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마를 전자레인지에 익히면 조리시간이 단축되고 이때 우유를 함께 데우면 연료가 절감 된다.\",\"instructions\":[\"1. 고구마를 전자렌지에서 익힌다.\",\"2. 전자레인지 마지막 1분이 남았을 때 컵에 우유를 따라 함께 데운다.\",\"3. 거품기로 살짝 저어 거품을 낸다.\",\"4. 고구마의 껍질을 벗겨 작게 잘라 우유, 요거트, 호두, 올리고당을 넣고 믹서에 간다.\",\"5. 거품기로 살짝 저어 거품을 낸다.\",\"6. 잔에 따르고 계피가루를 뿌린다.\"]},{\"id\":\"k389\",\"title\":\"홍시곶감화채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102102_1416273662979.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/731-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/731-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/731-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/731-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/731-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/731-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"얼린 홍시 70g\",\"곶감 30g\",\"호두 10g\",\"꿀 20g\",\"물 70g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"홍시를 얼려두었다 음료나 샐러드 소스 등으로 사용하면 좋다.\",\"instructions\":[\"1. 홍시의 껍질을 벗긴다.\",\"2. 껍질 벗긴 홍시에 꿀과 물을 넣어 믹서에 간다.\",\"3. 곶감을 갈라 씨를 뺀다.\",\"4. 씨를 빼낸 곶감에 호두를 넣어 만다.\",\"5. 곶감말이를 0.5cm 두게로 썬다.\",\"6. 홍시 간 것에 곶감말이를 띄워 낸다.\"]},{\"id\":\"k390\",\"title\":\"오징어채소말이와 치킨양념소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102125_1416273685292.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/732-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/732-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/732-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/732-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/732-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/732-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어채소말이 : 오징어 몸통 80g\",\"오이 20g\",\"빨강파프리카 20g\",\"노랑파프리카 20g - 치킨양념소스 : 토마토케첩 8g\",\"다진 양파 8g\",\"물엿 2g\",\"고추장 2g\",\"다진 마늘 2.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오징어몸통을 한손으로 잡고 다른 손으로는 살며시 다리를 잡아당겨 내장과 함께 떼어 낸 다음 몸통에 소금을 문질러 위로부터 아래쪽으로 껍질을 벗겨낸다. - 오징어는 찐 후 오래두면 색이 누렇게 변하므로 무를 넣어 끓인 물에 오징어를데치거나 찌면 조리 후 색이 덜 변한다.\",\"instructions\":[\"1. 오징어 몸통을 가르고 껍질을 벗긴 후 씻어서 물기를 제거 한다.\",\"2. 오징어 안쪽에 대각선으로 0.3cm 간격의 칼집을 넣고 반대방향으로도 칼집을 넣는다.\",\"3. 오이와 파프리카는 0.4cm 폭으로 길게 썬다.\",\"4. 오징어의 칼집을 넣지 않은 부분에 오이와 파프리카를 얹고 김밥처럼 말아 실로 엮은 후 찜통에 넣고 찐다.\",\"5. 치킨양념소스는 다진 마늘과 다진 양파를 팬에 기름을 두르지 않고 살짝 구워 향을 낸 후 고추장, 토마토케첩, 물엿을 넣고 소스를 만든다.\",\"6. 익은 오징어 말이는 2~3cm 길이로 썰고 5의 소스를 곁들인다.\"]},{\"id\":\"k391\",\"title\":\"옥수수감자샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102126_1416273686634.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/733-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/733-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/733-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/733-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/733-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/733-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 70g\",\"달걀 60g\",\"옥수수알 10g\",\"완두콩알 5g\",\"빨강파프리카 5g\",\"마요네즈 12g\",\"호상요구르트 10g\",\"소금 0.15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감자는 뜨거울 때 포크를 사용하여 으깬다. 남은 샐러드는 드레싱과 섞어 식빵에 넣어 샌드위치를 만들어도 좋다.\",\"instructions\":[\"1. 감자는 익기 쉽도록 토막 내고 완두콩과 옥수수알과 함께 김이 오른 찜통에 10~15분간 찐다.\",\"2. 찐 감자를 으깬다.\",\"3. 달걀은 삶아 흰자는 굵게 다지고 노른자는 체에 곱게 내린다.\",\"4. 파프리카는 옥수수알 크기로 썬다.\",\"5. 2에 완두콩, 옥수수, 파프리카, 달걀 흰자를 넣어 섞는다.\",\"6. 마요네즈, 호상요구르트, 달걀노른자, 소금을 넣어 샐러드드레싱을 만들어 5와 곁들인다.\"]},{\"id\":\"k392\",\"title\":\"홍합 쌀옹심이국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101955_1416273595773.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/737-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/737-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/737-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/737-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/737-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/737-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀가루 50g\",\"감자 25g\",\"홍합살 20g\",\"애호박 20g\",\"달걀노른자 20g\",\"양파 5g\",\"다진 파 5g\",\"국멸치 3g\",\"홍고추 2.5g\",\"청고추 2.5g\",\"다진 마늘 2.5g\",\"다시마 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"옹심이 반죽 시 물을 넣지 않고 빚는다. 감자 생것을 갈아서 옹심이를 만드는 것보다 찌는 것이 모양이 잘 만들어 지고 국물이 탁하지 않다.\",\"instructions\":[\"1. 물 1컵 반에 홍합, 국멸치, 건다시마, 양파를 넣고 멸치다시마국물 1컵을 내고 다시마는 건져 채 썬다.\",\"2. 감자는 껍질을 벗겨 찜통에 찐 후 으깬다.\",\"3. 2의 재료에 쌀가루, 달걀노른자, 현미유, 소금을 넣고 반죽하여 구슬크기의 옹심이를 10개 정도 만든다.\",\"4. 호박은 돌려깍기하여 2cm 가량으로 채 썰고 파, 홍고추, 청고추는 어슷썰기 한다.\",\"5. 멸치다시마국물이 끓으면 옹심이를 넣고 익어서 떠오르면 홍합, 호박, 다진 파, 다진 마늘, 다시마를 넣고 국간장으로 간을 한다.\",\"6. 홍고추와 청고추로 장식한다.\"]},{\"id\":\"k393\",\"title\":\"찬밥김치달걀찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101957_1416273597162.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/738-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/738-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/738-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/738-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/738-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/738-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 50g\",\"밥 30g(쌀 13g)\",\"김장김치 20g\",\"당근 5g\",\"양파 5g\",\"파 5g\",\"새우젓국물 2g\",\"물 100g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"걀물을 체에 거르면 찜이 부드러워진다. 밥을 많이 넣을 경우 무거워 가라앉으므로 가끔씩 저어주어야 한다. 표고버섯, 피망 등 냉장고속 남은 재료를 활용해도 좋다.\",\"instructions\":[\"1. 배추김치는 속을 털어낸다.\",\"2. 1의 김치를 다진 다음 물기를 짠다.\",\"3. 당근, 양파, 파는 잘게 다진다.\",\"4. 달걀은 흰자와 노른자를 체에 거른다.\",\"5. 달걀에 물 반컵을 넣고 잘 저은 후 1,2의 재료와 찬밥을 섞고 새우젓으로 간을 한다.\",\"6. 5를 찜통에 넣고 찐다.\"]},{\"id\":\"k394\",\"title\":\"꼬막떡꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101958_1416273598193.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/739-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/739-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/739-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/739-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/739-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/739-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"꼬막 60g(꼬막살 20g)\",\"떡볶이떡 40g 고추장 8g\",\"양파 10g\",\"파 5g\",\"조청 3g\",\"현미유 3g\",\"다진 마늘 2.5g\",\"간장 1g\",\"고춧가루 1g\",\"참기름 1g\",\"통깨 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"꼬막은 껍질이 부딪치게 바락바락 깨끗이 비벼 씻은 뒤 소금물에 반나절 정도 담가 여러번 물을 갈아주면서 해감시킨다. 꼬막과 떡은 데쳤으므로 팬에 구울 때는 꼬막이 질겨지지 않도록 살짝 굽는다.\",\"instructions\":[\"1. 떡볶이떡은 반으로 잘라 끓는 물에 데쳐 건진다.\",\"2. 꼬막은 씻어 떡을 데친 끓는 물(잔열)에 살짝 삶아 건진 후 식으면 꼬막살을 뺀다.\",\"3. 꼬치에 데친 떡과 꼬막살을 번갈아 가며 꽂는다.\",\"4. 파와 양파는 다진다.\",\"5. 고추장, 양파, 파, 다진 마늘, 조청, 간장, 고춧가루, 참기름을 넣어 고추장양념을 만든다.\",\"6. 팬에 현미유를 조금 두르고 고추장양념을 볶다가 3의 꼬막떡꼬치에 고추장양념을 입힌 후 통깨를 뿌린다.\"]},{\"id\":\"k395\",\"title\":\"물파래콩전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101959_1416273599145.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/740-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/740-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/740-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/740-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/740-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/740-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"물파래 5g\",\"노란콩 25g(불린것 52g)\",\"우리밀가루 10g\",\"현미유 5g\",\"홍고추 2g\",\"물 120g 간장 2g\",\"파 1g\",\"식초 0.5g\",\"통깨 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"노란콩은 물에 충분히 불려야 연료소비가 적고 잘 갈아진다.\",\"instructions\":[\"1. 물파래는 씻어 체에 걸러 물기를 제거하고 잘게 썬다.\",\"2. 물에 5시간정도 불린 노란콩은 물 반컵을 넣고 약 10분가량 삶아 건져 믹서에 곱게 간다.\",\"3. 파는 다지고 홍고추는 어슷썰기 한다.\",\"4. 밀가루에 1,2와 물 20g을 넣어 반죽을 한다.\",\"5. 팬에 현미유를 두르고 반죽을 떠서 지름 8cm 가량의 크기로 동그랗게 부치면서 윗면에 홍고추로 장식한다.\",\"6. 간장, 파, 식초, 통깨를 넣고 초간장을 만들어 물파래콩전과 곁들인다.\"]},{\"id\":\"k396\",\"title\":\"카스텔라케이크와 해독주스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00400_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00400_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00400_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00400_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00400_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00400_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00400_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"카스텔라 100g\",\"꿀 15g\",\"견과류 15g\",\"요거트 30g\",\"체리 10g\",\"해독주스 : 바나나 50g\",\"브로콜리 25g\",\"사과 50g\",\"당근 25g\",\"방울토마토 25g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해독주스는 몸 안에 독소를 빼주고 나트륨 배출에 도움을 주는 채소 함유량이 많다.\\n또한 견과류와 건조과일을 사용해 씹는 맛과 고소함으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 카스텔라는 반으로 잘라준 후 꿀을 발라준다.\",\"2. 견과류는 먹기 좋게 잘라준다.\",\"3. 자른 카스텔라 위에 꿀을 발라준다.\",\"4. 바른 카스텔라 위에 자른 견과류를 뿌려준다.\",\"5. 브로콜리를 뺀 해독주스 재료를 끓이다 마지막에\\n브로콜리를 넣어 살짝 끓여준 뒤 믹서에 간다.\",\"6. 접시에 담고 요거트를 뿌리고 체리와 애플민트를\\n올려준다.\"]},{\"id\":\"k397\",\"title\":\"토마토김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00401_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00401_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00401_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00401_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00401_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00401_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00401_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"방울토마토 200g\",\"영양부추 20g\",\"양파 40g\",\"청고추 15g\",\"홍고추 15g\",\"양념 : 바나나 40g\",\"배 40g\",\"고춧가루 15g\",\"매실청 10g\",\"간편 어간장 15g\",\"통깨 2g\",\"다진마늘 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치 양념으로 나트륨 배출에 도움을 주는 바나나를 이용하였으며, 바나나를 이용해 단맛을 높여 주어 소금의 사용량을 줄일 수 있다.\",\"instructions\":[\"1. 토마토는 먹기 좋은 크기로 잘라준다.\",\"2. 청고추, 홍고추, 양파는 채 썰고 부추는 먹기\\n좋게 잘라준다.\",\"3. 바나나, 배, 젓갈을 갈아 준 뒤 고춧가루와\\n섞어준다.\",\"4. 만들어진 국물에 나머지 재료를 넣고 최종\\n김치 국물을 만들어준다.\",\"5. 국물에 영양부추만 뺀 재료를 넣고 버무려준다.\",\"6. 마지막에 영양부추를 넣어 김치를 완성한다.\"]},{\"id\":\"k398\",\"title\":\"닭가슴살스튜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00402_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00402_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00402_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00402_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00402_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00402_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00402_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 200g\",\"당근 30g\",\"양파 30g\",\"브로콜리 30g\",\"감자 40g\",\"방울토마토 100g\",\"우유 100g\",\"올리브유 15g\",\"소스 : 토마토페이스트 100g\",\"다진마늘 15g\",\"밀가루 7g\",\"흰후추 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스로 토마토케첩이 아닌 페이스트 사용으로 나트륨 함량을 낮추었고, 다진마늘과 밀가루를 넣어 감칠맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 닭가슴살은 먹기 좋은 크기로 잘라서 우유에\\n재워준 뒤 뜨거운 물에 데쳐준다.\",\"2. 방울토마토는 반으로 자르고, 양파는 먹기 좋은\\n크기로 잘라준다.\",\"3. 감자, 당근, 브로콜리는 먹기 좋은 크기로\\n잘라 뜨거운 물에 순서대로 데쳐준다.\",\"4. 모든 재료를 올리브유에 볶아준다.\",\"5. 토마토페이스트와 닭가슴살을 데쳐낸 물을\\n섞어 끓여준다.\",\"6. 끓고 있는 국물 50g에 밀가루를 섞어 농도를\\n맞추어 준다.\"]},{\"id\":\"k399\",\"title\":\"가지겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00403_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00403_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00403_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00403_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00403_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00403_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지 250g\",\"양파 60g\",\"대파 25g\",\"청고추 15g\",\"홍고추 15g\",\"간편 어간장 15g\",\"양념장 : 고추장 15g\",\"생강청 15g\",\"다진마늘 5g\",\"통깨 7g\",\"매실청 10g\",\"고춧가루 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장에 고추장, 생강청, 매실청을 넣어 감칠맛을 높여주었고 통깨 사용으로 고소함이 더해지면서 고추장 사용을 줄일 수 있었고, 고춧가루 첨가로 색감을 살렸다.\",\"instructions\":[\"1. 가지는 먹기 좋은 크기로 잘라서 간편 어간장에\\n절여준다.\",\"2. 다진 대파, 청홍고추, 양파는 송송 잘라준다.\",\"3. 절여진 가지를 꼭 짜서 수분을 제거해준다.\",\"4. 양념장에 가지와 준비된 채소를 버무려 준다.\",\"5. 완성된 가지김치는 2시간 정도 후에 숙성시켜\\n완성한다.\"]},{\"id\":\"k400\",\"title\":\"저염 동치미\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00404_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00404_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00404_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00404_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00404_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00404_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00404_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"함초 25g\",\"사과 100g\",\"양파 25g\",\"무 100g\",\"쪽파 10g\",\"청고추 20g\",\"홍고추 15g\",\"마늘 10g\",\"함초소금 2g\",\"찹쌀가루 15g\",\"매실청 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"천연 재료인 함초를 사용하여 소금 사용량을 줄여 주었으며, 매실청과 청양고추를 넣어 시원함과 칼칼한 맛을 더해 짜지 않은 동치미를 만들 수 있었다.\",\"instructions\":[\"1. 함초와 쪽파는 1cm 길이로 자른다. 청고추,\\n홍고추, 무는 한입 크기로 잘라주고 마늘은\\n편으로 썰어준다.\",\"2. 물 1컵에 찹쌀가루를 풀어서 풀을 쑨다.\",\"3. 물 2컵에 함초, 편마늘을 넣고 국물을 만든다.\",\"4. 이 물로 무를 절여준다. 이때 무를 절였던 물을\\n버리지 말고 찹쌀 풀과 섞어 국물을 만들어\\n준다.\",\"5. 만들어진 국물과 찹쌀 풀을 섞어 체에 내려\\n준다.\",\"6. 모든 재료를 한데 섞어서 저염 동치미를\\n완성한다.\"]},{\"id\":\"k401\",\"title\":\"장어수육구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00405_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00405_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00405_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00405_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00405_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00405_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"장어 250g\",\"양파 70g\",\"통생강 20g\",\"생강청 15g\",\"소스 : 씨겨자 15g\",\"통깨 5g\",\"매실청 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스로 씨겨자를 이용해 간장과 소금 사용없이 매콤하면서 장어의 고소한 맛을 높여 줄 수 있었으며, 장어를 조리지 않고 수육구이 방법을 이용해 나트륨 섭취를 줄일 수 있었다.\",\"instructions\":[\"1. 장어는 생강청에 20분 정도 재워준다.\",\"2. 생강, 양파는 아주 가늘게 채 썰어서 냉수에\\n담가 매운맛을 빼준다.\",\"3. 소스 재료로 소스를 만들어준다.\",\"4. 채 썬 양파와 생강채를 냄비에 깔고 장어를\\n수분 없이 쪄준다.\",\"5. 쪄낸 장어는 접시에 올리고 양파, 생강채를\\n올려 소스와 함께 완성한다.\"]},{\"id\":\"k402\",\"title\":\"울금해초밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00406_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00406_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00406_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00406_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00406_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00406_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00406_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"울금가루 15g\",\"쌀 50g\",\"올리브오일 5g\",\"건조미역줄기 10g\",\"맛장 : 일본된장 15g\",\"다진양파 15g\",\"두부 50g\",\"다진마늘 3g\",\"고춧가루 2g\",\"참기름 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밥에 울금가루와 건조 미역줄기를 넣어 별도 소금 사용 없이 맛있는 밥을 만들 수 있었다.\",\"instructions\":[\"1. 쌀은 세척 후 울금물에 불려준다.\",\"2. 두부를 으깨서 수분을 빼준다.\",\"3. 쌈장을 맛장으로 만들어준다.\",\"4. 건조 미역줄기는 세척해 불린다. 이때 불리고\\n나온 물을 이용해 밥을 한다.\",\"5. 올리브오일로 쌀을 볶아주다 미역줄기를\\n넣고 밥을 한다.\",\"6. 두부 맛장과 함께 곁들여 완성한다.\"]},{\"id\":\"k403\",\"title\":\"미역줄기두부무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00407_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00407_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00407_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00407_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00407_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00407_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00407_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"건조미역줄기 10g\",\"두부 70g\",\"로즈마리 1g\",\"혼합견과류 25g\",\"소스 : 맛간장 15g\",\"다진양파 15g\",\"다진마늘 5g\",\"흰후추 1g\",\"통깨 3g\",\"식초 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장에 다진양파, 마늘, 맛간장을 이용해 일반 간장 소스보다 염분을 낮추었으며, 식초를 넣어 새콤함을 더해 주었다.\\n혼합 견과류를 추가하여 고소함을 더해주어 두부무침의 풍미를 높일 수 있었다.\",\"instructions\":[\"1. 두부는 물기를 꼭 짜준 후 으깬다.\",\"2. 미역줄기는 불린 후 먹기 좋게 자른다.\",\"3. 양념장을 만들어준다.\",\"4. 준비된 견과류를 송송 다져준다.\",\"5. 불린 미역줄기에 소스를 섞어 재워준다.\",\"6. 불린 미역줄기에 두부를 넣어 섞어준다.\"]},{\"id\":\"k404\",\"title\":\"맑은육개장\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00408_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00408_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00408_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00408_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00408_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00408_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00408_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고사리 25g\",\"무 20g\",\"대파 20g\",\"양파 20g\",\"팽이버섯 10g\",\"볶은소금 1g\",\"다진마늘 10g\",\"국물 : 소고기 양지 75g\",\"물 300g\",\"마늘 20g\",\"청양고추 25g\",\"고사리양념 : 맛간장 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"청양고추의 매콤한 맛을 더해 소금 함량을 낮추어 주었으며, 국간장이 아닌 다진마늘과 대파, 후추, 맛간장 사용을 통해 염도를 낮추어주면서 감칠맛과 칼칼한 맛을 더해 주었다.\",\"instructions\":[\"1. 국물 재료로 국을 끓여준 뒤 체에 걸러주고\\n양지는 찢어준다.\",\"2. 무와 양파는 굵은 채로 썬다.\",\"3. 대파의 흰 부분은 어슷하게 썰고 파란 부분은\\n굵게 썰어준다.\",\"4. 고사리는 뜨거운 물에 데친 후 먹기 좋은\\n크기로 잘라서 고사리 양념장에 양념한다.\",\"5. 청양고추를 썰어서 볶은 후 국물을 미리\\n끓여 놓은 국물에 붓는다.\",\"6. 만들어진 국물에 모든 재료를 넣고 한 번\\n끓여 완성한다.\"]},{\"id\":\"k405\",\"title\":\"주꾸미보양샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00409_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00409_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00409_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00409_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00409_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00409_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00409_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미 50g\",\"사과 60g\",\"더덕 40g\",\"양파 60g\",\"청고추 15g\",\"홍고추 15g\",\"소스 : 마늘기름 30g\",\"식초 15g\",\"다진마늘 5g\",\"다진대파 5g\",\"레몬소금 1g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 레몬즙과 정제염이 아닌 레몬소금을 사용하여 비린맛을 잡았고, 소금 사용량을 줄여 나트륨을 줄인 메뉴로 만들 수 있었다.\",\"instructions\":[\"1. 더덕은 손질해 어슷하게 잘라 소금물에 살짝\\n담가준다.\",\"2. 사과는 먹기 좋게 썰어서 레몬즙에 살짝\\n뿌려준다.\",\"3. 주꾸미는 레몬즙을 넣어 살짝 데쳐준다.\",\"4. 청고추, 홍고추는 씨를 제거하고 사과처럼\\n잘라주고. 양파도 잘라준다.\",\"5. 소스를 만들어준다.\",\"6. 모든 채소와 주꾸미를 섞어 소스랑 한데\\n버무려 완성한다.\"]},{\"id\":\"k406\",\"title\":\"전복내장밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00410_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00410_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00410_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00410_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00410_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00410_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00410_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"전복 100g\",\"칵테일새우 25g\",\"바지락살 25g\",\"당근 15g\",\"연근 25g\",\"단호박 25g\",\"찹쌀 50g\",\"다진마늘 7g\",\"참기름 15g\",\"소주 15g\",\"흰후추 1g\",\"마늘기름 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"전복의 내장을 소주로 믹서에 갈아주어 비릿한 냄새를 잡아주었고, 나트륨 배출에 도움을 주는 연근과 단호박, 전복의 고소함과 채소의 씹는맛으로 나트륨을 줄였다.\",\"instructions\":[\"1. 전복은 손질해 잘라주고 전복내장과 소주를\\n넣어서 믹서에 간다.\",\"2. 참기름과 마늘기름을 섞어서 불린 쌀을 볶는다.\",\"3. 연근, 당근, 단호박은 작은 깍두기 모양으로\\n잘라 각각 볶아준다.\",\"4. 전복은 작은 깍두기 모양으로 잘라서 칵테일새우,\\n바지락살, 다진마늘, 청주를 넣어 살짝 볶아준다.\",\"5. 냄비에 갈아준 전복내장을 만들어준 기름에\\n볶아주다 쌀을 넣고 볶고, 나머지 채소를\\n넣어 볶는다.\",\"6. 마지막으로 새우, 바지락을 넣고 볶아 완성한다.\"]},{\"id\":\"k407\",\"title\":\"카레감자전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00411_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00411_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00411_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00411_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00411_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00411_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00411_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 150g\",\"유기농 밀가루 50g\",\"카레가루 15g\",\"양파 70g\",\"루콜라 3g\",\"마늘기름 30g\",\"소스 : 발사믹식초 30g\",\"저염간장 15g\",\"설탕 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레가루를 이용하여 맛을 내어 나트륨 양을 줄여 주었으며, 소스로 발사믹식초를 넣어 간장의 염분을 줄이면서 맛을 높일 수 있었다.\",\"instructions\":[\"1. 감자는 껍질을 벗겨서 1개를 채 썰고 물에\\n담가둔다.\",\"2. 감자 1개는 강판에 갈아서 즙과 건지를 따로\\n분리해준다.\",\"3. 양파를 곱게 채 썰어주고 볼에 강판에 간 건지와\\n채 썬 감자, 채 썬 양파를 섞어 반죽을 만들어\\n준다.\",\"4. 소스를 만들어준다.\",\"5. 팬에 한입 크기로 전을 부쳐준다.\",\"6. 루콜라를 물에 살짝 헹궈주고 전과 함께\\n접시에 셋팅한다.\"]},{\"id\":\"k408\",\"title\":\"두부채소샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00412_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00412_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00412_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00412_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00412_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00412_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00412_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 100g\",\"건 표고버섯 10g\",\"치커리 15g\",\"홍고추 17g\",\"노란색 파프리카 25g\",\"방울토마토 40g\",\"소스 : 요거트 50g\",\"겨자 2g\",\"꿀 15g\",\"레몬즙 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스로 요거트의 상큼함과 겨자의 톡 쏘는 매콤함, 레몬즙의 새콤함을 높여서 짜지 않고 맛있는 샐러드 소스를 만들어 나트륨 섭취를 낮추었다.\",\"instructions\":[\"1. 두부는 먹기 좋은 크기로 잘라서 팬에 바삭\\n하게 구워준다.\",\"2. 구워진 두부는 기름을 빼고 채 썰어준다.\",\"3. 방울토마토는 작은 사각형으로 잘라주고,\\n치커리는 먹기좋게 잘라준다.\",\"4. 표고버섯와 홍고추, 노란파프리카는 가늘게\\n채 썰어 볶아준다.\",\"5. 소스를 만들어준다. 잘라준 토마토는 먹기\\n직전에 소스와 섞어준다.\",\"6. 접시에 치커리를 깔고 볶아진 두부와 채소를\\n올려 완성한다.\"]},{\"id\":\"k409\",\"title\":\"더덕비트물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00413_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00413_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00413_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00413_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00413_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00413_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00413_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"더덕 50g\",\"양파 60g\",\"청고추 15g\",\"홍고추 15g\",\"식초 10g\",\"국물 : 비트 20g\",\"함초소금 5g\",\"생강청 30g\",\"식초 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"더덕의 쓴맛을 제거하려고 소금물에 담가 주는데, 소금물에 담그는 대신 식초에 담가 염분이 더덕에 배는 것을 방지하였고, 생강청을 이용해 매콤하면서 달콤한 맛을 주어 국물의 깊은 맛을 내주었다.\",\"instructions\":[\"1. 물과 식초가 포함된 물에 담가서 쓴맛을\\n빼준다.\",\"2. 물에 절여진 더덕은 키친타월을 이용해 물기를\\n완전히 빼준다.\",\"3. 양파, 청고추, 홍고추도 어슷하게 썰어준다.\",\"4. 비트를 편으로 썰어서 국물을 만들어준다.\",\"5. 그릇에 더덕부터 30분 정도 담가 물을 살짝\\n들여준다.\",\"6. 나머지 재료도 함께 담가 간을 배게 한 뒤 24\\n시간 후부터 먹을 수가 있다.\"]},{\"id\":\"k410\",\"title\":\"연어허브스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00515_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00515_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00515_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00515_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00515_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00515_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00515_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(150g)\",\"로즈마리(3g)\",\"레몬(10g)\",\"올리브오일(30g)\",\"- 소스 : 당근(20g)\",\"양파(20g)\",\"토마토(30g)\",\"마늘(10g)\",\"버터(5g)\",\"밀가루(10g)\",\"토마토 소스(50g)\",\"육수(150g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"로즈마리의 향기로 연어의 잡내를 잡았으며, 갖가지 채소를 넣어 만든 소스를 사용하여 나트륨 섭취를 줄였어요.\",\"instructions\":[\"1. 연어에 로즈마리를 위에 올려\\n마리네이드를 한다.\",\"2. 마리네이드를 해놓은 연어에 레몬즙을\\n뿌린다.\",\"3. 당근, 양파는 썰고 마늘과 토마토는\\n다져 준비한다.\",\"4. 냄비에 버터를 두르고, 채소(③)를\\n볶다가 밀가루를 넣고 볶으면서 다시\\n토마토소스를 넣어 볶다가 육수와\\n월계수잎을 넣어 끓인다.\",\"5. 소스가 자작 하게 끓고 있을 때, 우유를\\n넣고 한 소끔 끓여준다.\",\"6. 팬에 올리브 오일을 두르고, 연어\\n(①)를 올려 앞뒤로 구어 접시에\\n담고, 토마토소스를 올려 완성한다.\"]},{\"id\":\"k411\",\"title\":\"해물칼국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00516_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00516_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00516_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00516_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00516_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00516_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00516_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀가루(180g)\",\"소금(0.3g)\",\"녹말가루(20g)\",\"덧밀가루(50g)\",\"애호박(20g)\",\"느타리버섯(20g)\",\"양파(20g)\",\"대파(20g)\",\"홍합(20g)\",\"새우(20g)\",\"미더덕(10g)\",\"저염간장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼국수면을 직접 만들어 나트륨 함량을 낮추고 풍부한 해산물을 이용하여 간장 사용을 줄였어요.\",\"instructions\":[\"1. 밀가루에 소금과 녹말가루를 넣고\\n반죽을 한다.\",\"2. 냄비에 건새우와 머리와 내장을 제거한\\n멸치, 다시마, 무, 마늘, 양파를 넣고\\n약30분 정도 끓여 체에 걸러 육수를\\n만들어 놓는다.\",\"3. 호박은 반달모양으로 썰고, 느타리는\\n손으로 찢고, 양파와 대파는 길게 썰어\\n준비한다.\",\"4. 새우는 요지를 이용하여 새우등의\\n내장을 제거하고, 홍합은 족사를 때어\\n내고 솔을 이용하여 껍질을 깨끗이\\n씻어낸 후 흐르는 물에 깨끗하게\\n행구고, 미더덕은 깨끗이 씻어 놓는다.\",\"5. 반죽을 해 놓은 밀가루에 덧 밀가루를\\n뿌려가며 얇게 밀어준다.\",\"6. 얇게 밀어 놓은 밀가루를 칼로 썰어\\n덧밀가루를 털어내고, 만들어 놓은\\n육수에 칼국수를 넣고, 준비한 채소\\n(③)와 해물(④)을 넣고 간장으로 간을\\n맞추어 완성한다.\"]},{\"id\":\"k412\",\"title\":\"버섯리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00517_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00517_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00517_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00517_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00517_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00517_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00517_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파(20g)\",\"양송이(20g)\",\"표고버섯(20g)\",\"느타리버섯(20g)\",\"버터(5g)\",\"불린쌀(150g)\",\"생크림(20g)\",\"소금(0.05g)\",\"- 육수 : 건새우(10g)\",\"건멸치(20g)\",\"마늘(10g)\",\"다시마(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해산물을 이용하여 짠맛을 대체하였으며, 갖가지 버섯을 활용하여 풍미를 살렸어요\",\"instructions\":[\"1. 양파와 양송이, 표고버섯, 느타리버섯은\\n작게 썰어 준비해 놓는다.\",\"2. 멸치와 새우, 마늘을 냄비에 담고,\\n물을 약 500㎖ 정도 붓고 끓여 육수를\\n만든다.\",\"3. 냄비에 버터를 넣고, 양파와 버섯을\\n넣어 볶는다.\",\"4. ③번의 냄비에 불린 쌀을 넣고 은근히\\n볶는다.\",\"5. 볶아지는 냄비에 만들어 놓은 육수를\\n조금 넣는다.\",\"6. 육수를 넣고 다시 은근히 볶으면서\\n뚜껑을 덮어 충분히 익힌 후, 마지막에\\n생크림과 소금을 넣고 완성한다.\"]},{\"id\":\"k413\",\"title\":\"삼색소고기만두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00518_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00518_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00518_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00518_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00518_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00518_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00518_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"애호박(30g)\",\"소금(0.5g)\",\"부추(30g)\",\"숙주(30g)\",\"두부(30g)\",\"달걀(50g)\",\"소고기(50g)\",\"다진 파(20g)\",\"다진 마늘(10g)\",\"참기름(5g)\",\"후춧가루(0.03g)\",\"- 만두피 : 시금치(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"천연식품으로 밀가루 반죽을 하고, 해물로 만든 육수에 만두를 끓여 나트륨 함량을 줄일 수 있었어요.\",\"instructions\":[\"1. 시금치는 끓는 물에 소금을 넣고 데쳐\\n찬물에 식힌 후 곱게 갈아 준비한다.\",\"2. 당근즙, 시금치즙, 들깨가루를 각각\\n준비한 뒤, 밀가루와 녹말가루를\\n세 개로 나눠 각각의 즙을 넣어 반죽 후\\n숙성시킨다.\",\"3. 호박은 채를 썰어 소금에 살짝 절여\\n물기를 제거하고, 부추는 송송 썰고,\\n숙주는 데쳐 물기를 제거하고 다지고,\\n두부는 면포에 물기를 꼭 짜서 준비한다.\",\"4. 달걀은 노란자와 흰자를 나눠 각각\\n지단을 붙여 준비한다. 냄비에 멸치와\\n다시마, 건새우, 양파를 넣고 약30분\\n정도 끓여 체에 걸러 육수를 만들어\\n놓는다.\",\"5. 소고기는 곱게 다져, 파 , 마늘, 참기름,\\n후춧가루를 넣어 양념을 해 놓는다.\",\"6. 준비한 채소(③)와 고기(⑤)를 섞어\\n만두속을 만들고, 숙성된 밀가루\\n반죽(②)을 밀어 만든 만두피에 만두\\n속을 넣어 만두를 만든다. 준비한 육수\\n(④)에 삼색 만두를 넣어 끓여 담고 그\\n위에 달걀지단을 올려 완성한다.\"]},{\"id\":\"k414\",\"title\":\"콩가루비빔밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00519_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00519_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00519_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00519_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00519_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00519_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00519_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"청포묵(20g)\",\"참기름(5g)\",\"소금(0.5g)\",\"달걀(50g)\",\"소금(0.5g)\",\"오이(20g)\",\"당근(20g)\",\"고사리(20g)\",\"표고버섯(20g)\",\"식용유(10g)\",\"쌀밥(150g)\",\"- 소고기 곁들임채소 : 소고기(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"콩가루를 섞은 고추장소스는 고소한 맛이 더해져 나트륨 함량을 낮출 수 있어요.\",\"instructions\":[\"1. 청포묵은 4cm 길이로 썰어 참기름과\\n소금에 살짝 무쳐 준비한다.\",\"2. 달걀은 황백으로 나누어 각각 소금을\\n조금씩 넣어 섞어 지단을 부친다.\",\"3. 오이는 돌려 깎아 채 썰고 당근도 오이\\n길이로 채 썰고 고사리는 길에 맞게\\n다듬고, 표고버섯도 채를 썰어 준비한다.\",\"4. 소고기는 채를 썰어 파, 마늘, 참기름,\\n후춧가루를 넣어 양념한다.\",\"5. 팬에 기름을 두르고, 준비한 곁들임\\n채소(③)와 다진 소고기를 재료별로\\n따로 볶아 준비한다.\",\"6. 고추장에 콩가루를 섞고, 볶아진 소고기를\\n넣어 다시 볶아 고추장 소스를 준비하고,\\n쌀밥을 그릇에 담은 후 청포묵(①), 볶아\\n놓은 채소와 소고기(⑤)를 올리고,\\n마지막에 고추장소스를 올려 완성한다.\"]},{\"id\":\"k415\",\"title\":\"인삼닭살찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00520_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00520_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00520_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00520_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00520_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00520_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00520_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살(200g)\",\"소금(0.5g)\",\"후춧가루(0.03g)\",\"정종(10g)\",\"대추(20g)\",\"인삼(50g)\",\"밤(20g)\",\"표고버섯(30g)\",\"새송이버섯(30g)\",\"치킨육수(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"대추와 인삼 등의 향이 닭고기의 잡내를 없애고, 육수에 찌듯이 익혀 추가 간을 하지 않아도 되요.\",\"instructions\":[\"1. 닭가슴살을 넓게 펴서 소금과\\n후춧가루, 정종으로 밑간을 한다.\",\"2. 대추는 돌려깎아 채를 썰고, 인삼은\\n세로 방향으로 반으로 가르고, 밤은\\n껍질을 벗겨 납작하게 썰고, 표고와\\n새송이 버섯은 뜨거운 물에 담그어\\n불린 후 채를 썰어 준비한다.\",\"3. 숙성된 닭가슴살(①)에 썰어놓은\\n재료(②)를 얹어 놓는다.\",\"4. 닭 가슴살을 돌돌 말아 놓는다.\",\"5. 냄비에 육수를 붓고, 육수가 끓으면\\n말아 놓은 닭가슴살을 넣는다.\",\"6. 뚜껑을 덮고, 약 15분 정도 은근히\\n찐 뒤, 닭가슴살이 익으면 불을 끄고\\n먹기 좋은 크기로 썰어서 접시에 담는다.\"]},{\"id\":\"k416\",\"title\":\"양배추버섯말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00521_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00521_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00521_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00521_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00521_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00521_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00521_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양배추(120g)\",\"미나리(20g)\",\"느타리버섯(30g)\",\"표고버섯(20g)\",\"팽이버섯(20g)\",\"당근(30g)\",\"오이(30g)\",\"소금(1g)\",\"소고기(100g)\",\"파(10g)\",\"마늘(10g)\",\"참기름(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양배추 찜과 갖가지 채소, 양념한 소고기를 이용하여 식감과 풍미가 좋아요\",\"instructions\":[\"1. 양배추는 깨끗이 씻어 찜기에 김이\\n오르면 쪄서 식혀 준비한다.\",\"2. 느타리, 표고 ,팽이버섯, 당근, 오이는\\n약 5cm 길이로 채를 썰어 준비한다.\",\"3. 소고기도 가늘게 채를 썰어 준비하고,\\n파, 마늘, 참기름, 설탕을 넣어 양념을\\n한다.\",\"4. 팬에 준비한 채소에 소량의 소금을\\n넣어 먼저 볶다가 양념한 소고기를\\n넣고 재빠르게 볶아 식혀 준비한다.\",\"5. 쪄 놓은 양배추를 김발 위에 올려 넣고,\\n볶아놓은 채소와 소고기를 넣는다.\",\"6. 김발을 이용하여 양배추를 돌돌 말고,\\n미나리를 데쳐 끈으로 묶어 접시에\\n올리고, 간장과 맛술, 참기름을 섞은\\n간장소스를 만들어 담는다.\"]},{\"id\":\"k417\",\"title\":\"단호박떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00522_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00522_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00522_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00522_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00522_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00522_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00522_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(150g)\",\"육수(100g)\",\"다진소고기(100g)\",\"다진 파(10g)\",\"다진 마늘(10g)\",\"다진 양파(30g)\",\"참기름(5g)\",\"저염간장(10g)\",\"후춧가루(0.2g)\",\"매실액(10g)\",\"찹쌀가루(20g)\",\"설탕(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"떡갈비를 쪄서 만들어 영양소 파괴를 줄이고 육수를 이용하여 찜으로써 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 단호박은 칼로 잘라, 수저를 이용하여\\n호박씨를 제거한다.\",\"2. 손질이 된 단호박은 면보를 깔고,\\n김이 오른 찜통에서 약 15분 정도\\n쪄 준비한다.\",\"3. 다진 소고기는 파, 마늘, 양파, 참기름,\\n간장, 후춧가루, 매실액을 넣고 양념을\\n한다.\",\"4. 3번에 양념된 소고기에 찹쌀가루를\\n넣고 골고루 섞는다.\",\"5. 쪄 놓은 호박에 양념된 소고기를 넣고\\n모양을 잡아 준다.\",\"6. 육수가 한 소큼 끓으면 만들어 놓은\\n단호박떡갈비(⑤)를 넣어 약 20분 정도\\n은근히 쪄서 잣을 올려 완성한다.\"]},{\"id\":\"k418\",\"title\":\"배추만두탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00523_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00523_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00523_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00523_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00523_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00523_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00523_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추(100g)\",\"미나리(20g)\",\"두부((30g)\",\"부추(20g)\",\"표고버섯(20g)\",\"느타리(20g)\",\"소고기(30g)\",\"저염간장(10g)\",\"대파(10g)\",\"마늘(10g)\",\"참기름(10g)\",\"통깨(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부와 배추를 이용하여 고소하고 달달한 맛이 어우러져 저염간장을 사용해도 그 맛을 충분히 느낄 수 있어요.\",\"instructions\":[\"1. 냄비에 무와 양지육, 마늘을 넣고\\n은근히 끓여 육수를 만들어 놓는다.\",\"2. 배추와 미나리는 면보를 깔고 찜통에서\\n약 10분 정도 쪄서 식혀놓는다.\",\"3. 두부는 면보에 넣어 손으로 물기를\\n짜 놓는다.\",\"4. 부추는 송송 썰고, 표고, 느타리버섯은\\n잘게 다지고, 소고기도 다져 놓고, 저염\\n간장과 파, 마늘, 참기름, 후춧가루,\\n통깨를 넣고 잘 섞어서 만두속을 만들\\n어 놓는다.\",\"5. 쪄놓은 배추를 한 장 펴놓고, 그 위에\\n만들어 놓은 만두속을 넣어 양 쪽을\\n접어 말아준다.\",\"6. 말아놓은 배추만두를 쪄 놓은 미나리\\n끈으로 묶은 후, 만들어 놓은 육수가\\n끓으면 배추만두를 넣고 간장으로\\n간을 한 뒤 한 번 더 끓여서 완성한다.\"]},{\"id\":\"k419\",\"title\":\"해산물누들볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00524_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00524_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00524_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00524_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00524_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00524_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00524_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홍합(30g)\",\"조개(30g)\",\"표고버섯(20g)\",\"양파(20g)\",\"홍파프리카(20g)\",\"피망(20g)\",\"오징어(30g)\",\"칵텔새우(20g)\",\"스파게티(100g)\",\"소금(0.5g)\",\"올리브오일(20g)\",\"마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다양한 해산물을 사용하게 되면, 나트륨을 넣지 않아도 맛이 충분히 우러나오기 때문에 나트륨을 감소 시킬 수 있어요\",\"instructions\":[\"1. 홍합은 끓는 물에 살짝 데쳐 준비하고,\\n조개는 소금물에 담그어 해감을 해\\n놓는다.\",\"2. 표고는 기둥을 제거하고 편으로 썰고,\\n양파는 채를 썰고, 홍파프리카와\\n피망은 씨를 제거한 뒤 5~6cm 길이로\\n채를 썰어 놓는다.\",\"3. 새우는 요지를 이용하여 등에 있는\\n내장을 제거해 놓고 오징어는 피망과\\n비슷한 크기로 채를 썰어 놓는다.\",\"4. 스파게티면은 끓은 물에 소금을 넣고\\n약 10분 정도 삶아 건져 올리브오일을\\n살짝 발라 준비한다.\",\"5. 팬에 올리브 오일을 두르고, 편 마늘을\\n넣어 먼저 볶아 향을 만든다.\",\"6. 마늘의 향이 나오면, 스파게티면을\\n넣어 볶다가 카레가루를 넣고, 다시\\n볶으면서 준비한 해물과 채소를 넣어\\n볶아 완성한다.\"]},{\"id\":\"k420\",\"title\":\"허브닭스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00525_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00525_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00525_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00525_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00525_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00525_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00525_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살(150g)\",\"우유(100g)\",\"로즈마리(5g)\",\"후춧가루(0.02g)\",\"저염버터(10g)\",\"- 소스 : 토마토(50g)\",\"마늘(10g)\",\"저염버터(10g)\",\"양송이(20g)\",\"토마토케첩(50g)\",\"생크림(20g)\",\"- 곁들임채소 : 당근(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생토마토를 사용한 소스는 나트륨 함량을 줄이고 신선한 맛과 풍미가 있어요.\",\"instructions\":[\"1. 닭가슴살에 로즈마리, 후춧가루를\\n넣고, 15분 정도 우유에 담그어 놓는다.\",\"2. 당근과 감자는 사각으로 깎아 양 모서리를\\n칼로 다시 다듬어 주사위 모양으로\\n둥그스럼하게 만들어 준비한다.\",\"3. 냄비에 물이 끓으면, 브로컬리와 깎아\\n놓은 당근과 감자를 데쳐 준비한다.\",\"4. 양송이는 껍질을 제거하고 모양 그대로\\n편으로 썰어 준비하고, 토마토와 마늘은\\n잘게 다져 냄비에 버터를 두르고 볶다가\\n케첩을 넣어준다.\",\"5. 볶아지는 4번에 썰어 놓은 양송이와\\n생크림을 넣고, 다시 살짝 한 번 더\\n볶아준다.\",\"6. 팬에 버터를 녹이고, 재워놓은 닭가슴살\\n(①)을 속이 익도록 노릇노릇 하게 익혀\\n접시에 담고, 만들어 놓은 감자와 당근,\\n브로컬리로 장식을 하고, 소스를 함께\\n올려 완성한다.\"]},{\"id\":\"k421\",\"title\":\"새우완자찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00526_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00526_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00526_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00526_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00526_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00526_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00526_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(100g)\",\"소금(0.5g)\",\"후춧가루(0.02g)\",\"다진소고기(30g)\",\"마늘(10g)\",\"브로컬리(20g)\",\"당근(20g)\",\"양파(20g)\",\"소금(0.5g)\",\"달걀(30g)\",\"녹말(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼슘과 타우린이 풍부한 새우를 다져 넣으면 나트륨을 적게 넣어도 맛있는 요리가 되어 나트륨 함량을 줄일 수 있어요.\",\"instructions\":[\"1. 준비한 새우의 반은 껍질을 벗겨\\n내장을 제거하고 곱게 다진다.\",\"2. 나머지 새우는 내장을 제거하고 껍질을\\n벗겨, 2/3 정도 반으로 갈라 소금, 후추로\\n밑간을 해 놓는다.\",\"3. 다진 새우는 소고기와 섞어, 마늘을\\n넣고 양념이 충분히 스며들도록 준비해\\n놓는다.\",\"4. 브로컬리는 데쳐 식힌 후 다지고, 당근과\\n양파도 다져 소금에 살짝 절여 물기를\\n제거해 놓는다.\",\"5. 양념된 재료(③)에 준비해 놓은 채소\\n(④)를 넣고, 녹말가루와 달걀을 풀어\\n골고루 섞는다.\",\"6. 반으로 갈라 준비한 새우에 녹말가루를\\n살짝 뿌리고, 섞어놓은 재료(⑤)를\\n완자를 빚어 새우에 올려 주고, 찜기에서\\n약 10분 정도 쪄서 완성한다.\"]},{\"id\":\"k422\",\"title\":\"두부된장무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00527_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00527_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00527_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00527_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00527_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00527_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00527_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(100g)\",\"된장(20g)\",\"쌈채(100g)\",\"생크림(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장에 생크림을 섞어 나트륨을 감소시켰어요.\",\"instructions\":[\"1. 쌈채는 먹기 좋게 손으로 뜯어 놓는다.\",\"2. 뜯어 놓은 쌈채를 물에 담그어 싱싱하게\\n준비해 놓는다.\",\"3. 두부는 면보에 넣어 손으로 짜서 물기를\\n제거하고 준비한다.\",\"4. 된장에 생크림을 넣어 골고루 섞어\\n짠 맛을 줄여준다.\",\"5. 으깬 두부에 된장을 넣어 섞어준다.\",\"6. 물에 담그어 놓은 채소를 체에 건져,\\n물기를 털어내고, 만들어 놓은 된장\\n소스에 넣어 무친다.\"]},{\"id\":\"k423\",\"title\":\"귀리죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00528_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00528_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00528_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00528_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00528_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00528_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00528_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"귀리(100g)\",\"쌀(30g)\",\"양파(20g)\",\"부추(20g)\",\"소고기(20g)\",\"참기름(5g)\",\"달걀(50g)\",\"흑임자(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"귀리와 달걀을 넣어 고소한 맛을 더함으로써 짠맛을 대체했어요.\",\"instructions\":[\"1. 귀리는 깨끗이 씻어 물에 불린다.\",\"2. 쌀도 씻어 따로 불려 놓는다.\",\"3. 양파와 부추는 송송 썰어 준비한다.\",\"4. 냄비에 참기름을 넣고, 소고기를 먼저\\n볶는다.\",\"5. 볶아지는 냄비에 다시 불린 귀리와\\n쌀을 넣어 볶아준다.\",\"6. 충분히 귀리가 볶아지면 물을 넣고\\n끓이다가, 썰어 놓은 채소를 넣고, 죽이\\n어우러지게 끓인 뒤 달걀을 풀어 넣고\\n다시 저어가면 끓여주고, 죽 위에\\n흑임자를 올려 완성한다.\"]},{\"id\":\"k424\",\"title\":\"탕평채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00529_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00529_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00529_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00529_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00529_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00529_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00529_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"청포묵(150g)\",\"맛소금(1g)\",\"참기름(5g)\",\"소고기(30g)\",\"저염간장(20g)\",\"설탕(10g)\",\"참기름(5g)\",\"미나리(20g)\",\"숙주(20g)\",\"홍파프리카(20g)\",\"달걀(30g)\",\"김(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장을 소스로 사용해서 나트륨을 감소시켰어요.\",\"instructions\":[\"1. 청포묵을 약 6~7cm 길이로 썰어\\n맛소금과 참기름에 살짝 버무려 놓는다.\",\"2. 소고기는 채를 썰어 간장과 설탕,\\n참기름에 볶아놓고 미나리는 데쳐\\n찬물에 식혀 5~6cm 길이로 썰고,\\n숙주는 머리와 꼬리를 떼어 내고,\\n뜨거운 물에 데쳐 식혀 준비한다.\",\"3. 홍파프리카는 씨를 제거하고 약 6cm\\n길이로 썰어 놓는다.\",\"4. 달걀은 황백으로 나눠 각각 지단을\\n부쳐 채를 썰어 놓는다.\",\"5. 김은 살짝 구어 봉투에 넣고 부수어\\n김가루를 만들어 놓는다.\",\"6. 저염간장에 설탕과 식초를 넣어 골고루\\n섞어 탕평채 양념장을 만들고, 접시에\\n준비한 청포묵을 담고, 그 위에 채소와\\n고기를 올리고, 맨 위에 달걀지단과\\n김가루를 올린 후 양념장을 끼얹어 완성\\n한다.\"]},{\"id\":\"k425\",\"title\":\"겨자소스를 곁들인 새우롤과 전복샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00554_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00554_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00554_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00554_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00554_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00554_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00554_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(3마리)\",\"전복(2개)\",\"연어(100g)\",\"겨자가루(20g)\",\"어린잎(30g)\",\"요구르트(20g)\",\"고추장(30g)\",\"설탕(10g)\",\"식초(10g)\",\"소금(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장에 요구르트를 넣으면 맛도 부드럽고, 나트륨 함량도 감소시킬 수 있어요.\",\"instructions\":[\"1. 새우는 껍질을 제거하고 포를 뜬 뒤 삶아 익힌다.\",\"2. 전복은 수저로 떼어내 소금으로 씻고\\n달군 팬에 굽는다.\",\"3. 연어는 포를 뜬다.\",\"4. 겨자가루에 30℃ 정도의 물을 넣고\\n골고루 섞어 발효시키고, 설탕, 식초를\\n넣고 겨자소스를 만든다.\",\"5. 고추장에 요구르트를 넣고\\n고추장소스를 만든다\",\"6. 접시에 익힌 새우, 전복, 연어를 담은 뒤\\n겨자소스와 고추장소스를 올리고\\n어린잎으로 장식한다.\"]},{\"id\":\"k426\",\"title\":\"속채운대저토마토백김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00555_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00555_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00555_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00555_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00555_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00555_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00555_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토(100g)\",\"배춧잎(2장)\",\"오이(50g)\",\"무(50g)\",\"양파(30g)\",\"마늘(10g)\",\"생강(5g)\",\"소금(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금을 볶아서 김치 국물로 사용하면, 나트륨 함량은 줄이고 단 맛을 느낄 수 있어요.\",\"instructions\":[\"1. 토마토는 윗부분을 자르고 속을\\n파낸다.\",\"2. 오이는 소금에 깨끗이 씻는다.\",\"3. 소금을 팬에 볶은 후 배추를 절인다.\",\"4. 절인 배추에 오이와 무를 넣고\\n돌돌만다.\",\"5. ?를 속을 파낸 토마토 안에 넣는다.\",\"6. ?번을 통에 담아 소금 국물을 붓고\\n양파와 마늘 생강을 넣는다.\"]},{\"id\":\"k427\",\"title\":\"들깨죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00557_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00557_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00557_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00557_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00557_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00557_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00557_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사골육수(800g)\",\"들깨가루(200g)\",\"마늘(5g)\",\"부추(20g)\",\"홍고추(1개)\",\"양파(30g)\",\"당근(15g)\",\"찹쌀(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사골육수에 들깨가루를 넣어 따로 간을 하지 않아도 맛있게 즐길 수 있어요.\",\"instructions\":[\"1. 찹쌀은 깨끗이 씻어 물에 약 30분 간\\n충분히 불린다.\",\"2. 부추, 홍고추, 양파 및 당근을 잘게\\n다진다.\",\"3. 마늘은 곱게 다진다.\",\"4. 냄비에 기름을 두르고 마늘을 볶다가\\n불린 찹쌀을 넣고 볶는다.\",\"5. 어느 정도 볶아지면 사골육수와\\n들깨가루를 넣고 은근히 끓인다.\",\"6. 찹쌀이 어느 정도 익으면 홍고추와\\n부추를 넣고 살짝 끓인다\"]},{\"id\":\"k428\",\"title\":\"레몬크림콩다식\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00558_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00558_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00558_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00558_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00558_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00558_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00558_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콩가루(100g)\",\"꿀(30g)\",\"레몬(1/2개)\",\"생크림(30g)\",\"설탕(20g)\",\"레몬제스트(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"몸에 좋은 콩을 다식으로 만들어 먹기에도 간편하고 레몬크림으로 상큼함을 더해 다른 음식의 소금 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 콩가루에 꿀을 넣고 반죽한다.\",\"2. 섞어 놓은 콩가루 반죽은 고운 천으로\\n감싸 숙성을 시킨다.\",\"3. 레몬은 즙을 짠다.\",\"4. 생크림에 설탕과 레몬즙을 넣고 휘핑해\\n레몬크림을 만든다\",\"5. 콩다식 판에 숙성된 콩반죽을 넣고\\n모양을 만든다.\",\"6. 콩다식에 레몬크림을 올리고\\n레몬제스트로 장식한다.\"]},{\"id\":\"k429\",\"title\":\"룰룰랄라\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00559_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00559_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00559_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00559_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00559_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00559_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00559_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양상추(120g)\",\"소고기(120g)\",\"부추(100g)\",\"닭고기(120g)\",\"토마토(100g)\",\"양파(50g)\",\"전복(1개)\",\"당근(20g)\",\"양송이버섯(3개)\",\"쌀(200g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"구워 넣은 전복이 짠맛을 내서 소금을 적게 넣을 수 있어요.\",\"instructions\":[\"1. 양상추, 부추를 데친다.\",\"2. 양송이버섯은 얇게 슬라이스하고 팬에\\n기름을 살짝 두르고 굽는다.\",\"3. 전복은 수저로 떼어 소금으로 씻고\\n일정한 크기로 썰어 팬에 굽는다.\",\"4. 닭고기는 일정한 크기로 썬 뒤 삶고,\\n소고기도 일정한 크기로 썰어 양념 한\\n뒤 볶는다.\",\"5. 토마토, 양파, 당근은 잘게 썰고, 쌀은\\n깨끗이 씻어 불려 야채를 넣고 밥을\\n짓는다.\",\"6. 쪄낸 양배추에 볶은 고기, 삶은 닭고기,\\n구운 전복, 밥을 넣고 돌돌 말아 부추로\\n묶어 접시에 담고, 한쪽에 구운 버섯을\\n담는다.\"]},{\"id\":\"k430\",\"title\":\"매실소스를 곁들인 돼지고기만두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00560_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00560_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00560_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00560_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00560_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00560_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00560_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(안심\",\"120g)\",\"당면(50g)\",\"애호박(1/2개)\",\"당근(30g)\",\"표고버섯(20g)\",\"목이버섯(10g)\",\"양파(50g)\",\"마늘(20g)\",\"토마토(100g)\",\"매실액(50g)\",\"후춧가루(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해독작용과 살균작용이 있는 매실을 사용하면 돼지고기의 냄새도 감소시키고, 매실의 깊은 맛으로 나트륨이 적고 맛좋은 만두를\\n만들 수 있어요.\",\"instructions\":[\"1. 돼지고기 안심을 요리망치로 얇게\\n두드려 펴고 후춧가루로 밑간한다.\",\"2. 목이버섯은 불려 잘게 썰고 양파와\\n마늘은 입자있게 다진다\",\"3. 당면은 따뜻한 물에 충분히 불려 썰고\\n애호박, 당근, 표고버섯은 잘게 썬다.\",\"4. 팬에 기름을 두르고 다진 양파와\\n마늘을 볶는다.\",\"5. 4번에 매실액과 잘게 자른 애호박,\\n당근, 표고버섯, 목이버섯, 당면을\\n넣고 볶아 만두소를 만든다.\",\"6. 돼지고기는 넓게 펴서 만두소를 넣고\\n주머니를 만들어 실로 묶고 토마토와\\n함께 오븐에 굽는다.\"]},{\"id\":\"k431\",\"title\":\"머스터드튤립치킨\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00561_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00561_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00561_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00561_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00561_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00561_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00561_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(날개\",\"8개)\",\"어린잎(20g)\",\"파슬리(5g)\",\"머스터드(50g)\",\"양파(50g)\",\"마늘(20g)\",\"레몬(1/4개)\",\"튀김가루(100g)\",\"소금(0.1g)\",\"후추(0.01g)\",\"식용유(400g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"튀김가루에 양파즙, 마늘즙, 파슬리 가루를 넣어 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 닭날개에 칼집을 넣고 뒤집어\\n튤립모양의 봉을 만든다.\",\"2. 닭날개에 소금, 후춧가루로 밑간을\\n한다.\",\"3. 파슬리는 곱게 다져 가루를 만든다\",\"4. 양파, 마늘은 즙을 내서 튀김가루,\\n파슬리 가루와 함께 골고루 섞어\\n튀김반죽을 만든다.\",\"5. 어린잎은 찬물에 담궈 건져 놓는다.\",\"6. 튀긴 닭날개의 기름을 빼고 레몬과\\n어린잎으로 장식한다.\"]},{\"id\":\"k432\",\"title\":\"머위향 통밀푸실리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00562_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00562_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00562_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00562_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00562_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00562_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00562_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"머윗대(100g)\",\"푸실리(50g)\",\"올리브오일(20g)\",\"마늘(10g)\",\"양파(20g)\",\"생크림(100g)\",\"화이트와인(30g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"머위의 향이 푸실리와 어우러져 간을 조금만 해도 충분히 맛을 낼 수 있어요.\",\"instructions\":[\"1. 푸실리는 뜨거운 물에 약 10분 정도\\n삶아 건져 올리브오일을 살짝 바른다.\",\"2. 머윗대는 살짝 데친 후 찬물에 헹궈\\n껍질을 벗긴다.\",\"3. 껍질 벗긴 머윗대는 푸실리 크기로\\n자른다.\",\"4. 양파, 마늘은 입자있게 다진다.\",\"5. 팬에 올리브오일을 두르고 다진 마늘과\\n양파를 볶다가 화이트와인을 넣고\\n볶는다.\",\"6. 5번에 생크림, 소금을 넣고 믹서에 간\\n뒤 푸실리와 머윗대를 넣고 한소끔\\n끓인다.\"]},{\"id\":\"k433\",\"title\":\"미니함박스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00563_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00563_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00563_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00563_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00563_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00563_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00563_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(100g)\",\"돼지고기(100g)\",\"대추(2알)\",\"양파(50g)\",\"마늘(10g)\",\"새송이버섯(1개)\",\"파프리카(50g)\",\"배춧잎(1장)\",\"단호박(1/4개)\",\"당근(20g)\",\"소금(0.3g)\",\"후춧가루(0.02g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장에 배를 갈아 넣고 소스를 만들면, 고기도 부드러워지고 나트륨도 줄일 수 있어요.\",\"instructions\":[\"1. 대추는 돌려 깎아 씨를 제거하고 곱게\\n다지고 팬에 볶는다.\",\"2. 소고기, 돼지고기, 양파 및 마늘을\\n다진다.\",\"3. 배춧잎, 파프리카, 새송이버섯, 당근은\\n입자있게 다진다.\",\"4. 다진 소고기, 돼지고기, 양파, 마늘,\\n대추, 배춧잎, 파프리카, 새송이버섯,\\n당근 및 양파에 소금, 후춧가루를 섞어\\n잘 치대어 스테이크 모양으로 만든다\",\"5. 팬에 기름을 살짝 두르고, 스테이크\\n고기를 충분히 익혀 접시에 담고,\\n단호박은 껍질을 벗겨 팬에 구워\\n담는다.\",\"6. 배는 갈아 저염간장과 설탕을 넣고 잘\\n저어 소스를 만들고 익혀 놓은\\n스테이크에 올려 완성한다.\"]},{\"id\":\"k434\",\"title\":\"바다완자탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00564_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00564_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00564_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00564_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00564_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00564_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00564_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(3마리)\",\"바지락(50g)\",\"무(20g)\",\"다시마(10g)\",\"대파(20g)\",\"가쓰오부시(10g)\",\"달걀(1개)\",\"전분(10g)\",\"홍고추(1/2개)\",\"풋고추(1/2개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우와 바지락을 넣으면 시원한 육수맛과 천연조미료 성분이 나와 따로 간을 할 필요가 없어요.\",\"instructions\":[\"1. 대파, 무, 다시마를 물에 넣고 끓여\\n육수를 만든다.\",\"2. 육수에 가쓰오부시를 넣고 10분 정도\\n가라앉힌 뒤 거른다.\",\"3. 새우는 껍질을 벗겨 깨끗이 씻고\\n바지락은 주물러 씻는다.\",\"4. 손질한 새우와 바지락을 곱게 다진다.\",\"5. 다진 새우와 바지락에 달걀흰자와\\n전분을 넣고 골고루 섞어 완자를\\n만들어 후라이팬에 살짝 굴려 모양이\\n풀리지 않게 한다\",\"6. 준비된 육수에 완자를 넣고 완전히\\n익히고 그릇에 담은 뒤 어슷썬\\n홍고추와 풋고추를 위에 올린다.\"]},{\"id\":\"k435\",\"title\":\"봄옷을 입은 닭\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00565_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00565_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00565_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00565_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00565_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00565_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00565_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"100g)\",\"취나물(20g)\",\"달걀(1개)\",\"애호박(1/2개)\",\"당근(20g)\",\"표고버섯(1개)\",\"오이(50g)\",\"파프리카(50g)\",\"고구마(50g)\",\"누룽지(20g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"간을 살짝 해도 취나물의 향이 맛을 더해주어 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 닭가슴살에 소금, 후춧가루로\\n밑간하고 랩으로 말아 50℃ 정도의\\n물에서 천천히 익힌다.\",\"2. 달걀은 황백 지단을 만들어 채를 썰고,\\n표고버섯, 당근, 오이, 파프리카 및\\n고구마도 채를 썰어 팬에 볶는다.\",\"3. 미나리는 끓는 물에 소금을 넣고 살짝\\n데친 뒤 찬물에 헹군다\",\"4. 취나물은 끓는 물에 소금을 넣고 살짝\\n데친 뒤 찬물에 헹구어 넓게 펴 놓는다.\",\"5. 누룽지는 손으로 잘라 기름에 튀긴다.\",\"6. 취나물에 익힌 닭가슴살과 볶은 야채를\\n돌돌 말아 미나리를 감고 먹기 좋은\\n크기로 썰어 접시에 담은 뒤 튀긴\\n누룽지를 올린다.\"]},{\"id\":\"k436\",\"title\":\"삼계치킨\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00566_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00566_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00566_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00566_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00566_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00566_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00566_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"120g)\",\"인삼(1뿌리)\",\"양송이버섯(3개)\",\"마늘(20g)\",\"양파(30g)\",\"깻잎(2장)\",\"아스파라거스(3개)\",\"오렌지(1/2개)\",\"레몬(1/2개)\",\"생크림(30g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"인삼소스의 향이 풍미를 더해주어 소금을 적게 사용할 수 있어요.\",\"instructions\":[\"1. 닭가슴살은 포를 떠 후춧가루로 밑간을\\n한다.\",\"2. 인삼은 뇌두를 제거하고 깨끗이 씻어\\n절반은 다지고, 양파와 마늘도 다진다.\",\"3. 나머지 인삼은 채썰고, 대파, 깻잎도\\n채를 썰어 물에 담군다.\",\"4. 다진 양파, 마늘을 볶다가 생크림을\\n넣고 은근히 졸인 뒤 오렌지, 레몬즙을\\n넣고 소스를 만든다.\",\"5. 닭가슴살에 밀가루에 찬물, 달걀을\\n넣고 튀김옷을 만들어 입힌다.\",\"6. 팬에 기름을 넉넉히 넣고 지지듯이\\n닭가슴살을 튀겨 접시에 담고\\n인삼소스를 뿌린 뒤, 그 위에 깻잎과\\n대파, 인삼채를 올린다.\"]},{\"id\":\"k437\",\"title\":\"삼계치킨롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00567_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00567_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00567_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00567_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00567_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00567_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00567_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(1마리)\",\"인삼(2뿌리)\",\"대추(3알)\",\"찹쌀(100g)\",\"양파(50g)\",\"대파(20g)\",\"당근(20g)\",\"마늘(20g)\",\"생강(5g)\",\"월계수잎(2장)\",\"통후추(10알)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"찹쌀과 야채를 함께 볶아 맛을 한층 더 어우러지게 만들어 소금 사용을 줄였어요.\",\"instructions\":[\"1. 닭은 살을 발라 소금, 후춧가루로\\n밑간을 하고 닭뼈는 삶아 육수를\\n만든다.\",\"2. 인삼은 뇌두를 제거하고 깨끗이 씻어\\n채 썰고, 대추도 씨를 제거 한 후 채\\n썬다.\",\"3. 양파, 대파, 당근은 채썰고, 찹쌀은\\n깨끗이 씻어 충분히 불린 뒤 함께\\n볶는다.\",\"4. 충분히 볶아지면 육수를 자작하게 넣고\\n익힌다.\",\"5. 랩에 닭살을 놓고 찹쌀과 인삼채,\\n대추채를 올려 돌돌 만다.\",\"6. 마늘, 생강, 월계수잎 및 통후추를 넣고\\n끓인 물에 김이 올라오면 말아놓은\\n닭살을 찜통에서 20분 정도 찌고 한 김\\n식으면 썰어 접시에 담는다.\"]},{\"id\":\"k438\",\"title\":\"새우완자탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00568_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00568_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00568_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00568_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00568_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00568_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00568_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(5마리)\",\"청경채(20g)\",\"달걀(2개)\",\"치킨육수(200g)\",\"전분(30g)\",\"후춧가루(0.01g)\",\"요리술(20g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우로 완자를 만들어 소금을 적게 넣어도 싱겁지 않고 맛있게 먹을 수 있어요.\",\"instructions\":[\"1. 새우는 내장을 제거 하고 껍질을 벗겨\\n깨끗이 씻는다.\",\"2. 다진 새우에 전분, 후춧가루, 달걀흰자\\n및 요리술을 섞는다.\",\"3. 반죽새우를 잘 치대어 완자로 만든 후\\n치킨 육수에 넣고 끓인다\",\"4. 청경채는 깨끗이 씻어 반으로 길게\\n가른다.\",\"5. 달걀은 황백으로 나눠 지단을 부쳐\\n마름모꼴로 썬다.\",\"6. 완자가 익으면 물 녹말을 한 수저 넣고\\n청경채를 넣고 한소끔 끓인 뒤 그릇에\\n담고 황백지단을 올린다.\"]},{\"id\":\"k439\",\"title\":\"아삭\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00569_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00569_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00569_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00569_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00569_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00569_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00569_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"아스파라거스(5개)\",\"당근(100g)\",\"무(100g)\",\"식초(200g)\",\"설탕(200g)\",\"월계수잎(3장)\",\"통후추(20알)\",\"소금(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨을 배출을 도와주는 아스파라거스를 초절임으로 만들어 오래 두고 먹을 수 있어요.\",\"instructions\":[\"1. 아스파라거스는 깨끗이 씻어 5cm\\n길이로 썬다.\",\"2. 당근을 아스파라거스 크기로 썬다.\",\"3. 무도 아스파라거스 크기로 썬다.\",\"4. 식초, 설탕을 동량으로 섞는다.\",\"5. 식초 설탕물이 끓으면 통에 뜨거울 때\\n붓고, 떠오르지 않도록 눌러 담는다.\",\"6. 약 7일 정도 숙성한다.\"]},{\"id\":\"k440\",\"title\":\"연어비트 절임샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00570_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00570_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00570_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00570_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00570_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00570_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00570_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(150g)\",\"비트(100g)\",\"오렌지(1개)\",\"양파(50g)\",\"새싹(20g)\",\"식용꽃(20g)\",\"올리브오일(10g)\",\"설탕(10g)\",\"식초(10g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새콤달콤한 드레싱과 야채가 소금 사용을 줄여요.\",\"instructions\":[\"1. 비트는 껍질을 벗겨 채 썬다.\",\"2. 양파를 얇게 채 썬 후 물에 담근 뒤 건져\\n물기를 뺀다.\",\"3. 비트와 오렌지에 절여진 연어를 얇게\\n슬라이스한다.\",\"4. 식용꽃과 새싹은 물에 담궈 싱싱함을\\n살리고 건져 물기를 뺀다.\",\"5. 새싹과 양파를 접시에 깔고 그 위에\\n연어를 올린다.\",\"6. 올리브오일, 식초, 소금 및 설탕을 잘\\n섞어서 만든 드레싱을 올리고\\n식용꽃으로 장식한다\"]},{\"id\":\"k441\",\"title\":\"가지나물냉국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102108_1416273668286.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/678-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/678-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/678-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/678-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/678-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/678-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"- 주재료 : 가지 50g\",\"다진 청양고추 2.5g\",\"다진 홍고추 2.5g\",\"다진 실파 2.5g\",\"다진 마늘 1.25g\",\"국간장 3g - 국물 : 다시마국물 100g(건다시마 5g)\",\"사과식초 1.25g\",\"감식초 1.25g\",\"소금 0.5g\",\"통깨 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"가지나물을 무쳐 냉장 보관했다가 먹을 때 다시마국물을 부어 먹으면 나물과 냉국 두 가지로 즐길 수 있다. - 두가지 식초를 혼합하여 냉국의 간을 맞추면 감칠맛이 더 좋아진다.\",\"instructions\":[\"1. 가지는 반 갈라 4등분하여 찜통에 5분간 찐 후 한 김 식혀준다.\",\"2. 식은 가지를 새끼손가락 굵기로 찢는다.\",\"3. 다진 고추, 실파, 마늘, 국간장을 넣어 양념장을 만든다.\",\"4. 찐 가지에 양념장을 넣고 조물조물 무친다.\",\"5. 차게 한 다시마국물 반컵에 식초, 죽염을 넣어 간한다.\",\"6. 유리 그릇에 무친 가지를 담고 5를 부은 뒤 얼음을 띄우고 통깨를 뿌린다.\"]},{\"id\":\"k442\",\"title\":\"수삼매운닭찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102109_1416273669146.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/679-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/679-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/679-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/679-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/679-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/679-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"- 주재료 : 토막 낸 닭 170g(닭고기살 무게 90g)\",\"수삼 25g\",\"건표고버섯 8g\",\"건표고버섯 불릴 물 150g\",\"감자 20g\",\"양파 25g\",\"당근 10g\",\"건청양고추 2.5g\",\"건당면 5g\",\"대파 10g\",\"다진 마늘 4g - 양념 : 간장 10g\",\"황설탕 8g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭을 데칠 때 생강편을 넣으면 비린내가 없어진다. - 노두유는 캐러멜소스 대신 사용되는 간장의 일종으로 찜과 구이에 넣으면 색이 진해지고 향이 좋아진다.\",\"instructions\":[\"1. 닭은 찬물에 담가 핏물을 제거하고 끓는 물에 넣고 데쳐 기름을 뺀다.\",\"2. 당면과 표고버섯은 각각 물에 담가 불리고 버섯 불린 물은 따로 받아둔다.\",\"3. 표고버섯, 감자, 양파, 당근은 한입 크기로 썰고 수삼과 대파는 어슷 썬다.\",\"4. 냄비에 닭과 양념, 버섯, 감자, 양파, 당근, 건고추, 버섯 불린 물 3/4컵을 넣고 조린다.\",\"5. 닭이 반쯤 익었을 때 수삼을 넣고 계속 조린다.\",\"6. 닭이 다 익으면 당면, 대파, 다진 마늘을 넣고 살짝 끓여 담아낸다.\"]},{\"id\":\"k443\",\"title\":\"수박즙돼지목심구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102122_1416273682794.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/680-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/680-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/680-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/680-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/680-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/680-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"- 주재료 : 돼지고기 목심 70g\",\"올리브유 2g\",\"후추 0.25g - 소스 : 수박 15g\",\"간장 3g\",\"설탕 2g\",\"물엿 3g\",\"다진 마늘 2g\",\"후추 0.25g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 키친타월을 이용해 돼지고기의 핏물을 뺀다.\",\"2. 돼지고기에 칼집을 내준다.\",\"3. 칼집 낸 돼지고기에 올리브유, 후추를 뿌려 재워둔다.\",\"4. 수박의 씨를 빼고 살만 발라 믹서에 간다.\",\"5. 소스 재료를 모두 섞어 약불에서 살짝 졸여 식힌다.\",\"6. 재워 놓은 고기에 소스를 끼얹어 팬에 굽는다.\"]},{\"id\":\"k444\",\"title\":\"별미병어조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102131_1416273691739.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/681-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/681-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/681-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/681-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/681-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/681-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"- 주재료 : 병어 60g\",\"소금 1g\",\"물 100g\",\"무 40g\",\"양파 25g\",\"풋고추 10g\",\"홍고추 2.5g\",\"대파 5g - 양념장 : 된장 2g\",\"고추장 6g\",\"굵은 고춧가루 1.7g\",\"고운 고춧가루 0.85g\",\"맛술 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"무를 먼저 끓인 뒤 병어를 넣어야 시원한 맛도 잘 우러나고 생선살이 부서지지 않는다. - 물 대신 다시마멸치국물을 넣으면 더욱 깊은 맛을 낼 수 있다. - 매실액 만드는 법 : 매실과 설탕을 동량으로 준비한다. 씻어서 물기를 말린 매실을 병에 한켜 담고 설탕을 켜켜이 뿌려 밀봉하여 10\",\"instructions\":[\"1. 병어에 칼집을 내어 소금을 뿌린다.\",\"2. 무는 두툼하게 썰고 양파는 굵게 채 썰고 고추와 대파는 어슷 썬다.\",\"3. 양념장 재료를 모두 섞어 양념장을 만든다.\",\"4. 양념장의 ¼만 남기고 나머지 양념장을 물 반컵에 풀어 무를 넣어 끓인다.\",\"5. 무에 간이 배면 양파와 병어를 넣고 남은 양념장을 넣어 졸여준다.\",\"6. 고추와 대파를 넣어 마무리한다.\"]},{\"id\":\"k445\",\"title\":\"비름나물겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101935_1416273575289.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/682-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/682-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/682-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/682-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/682-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/682-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 : 비름나물 30g\",\"소금물(물 100g\",\"소금 3g) - 양념장 : 까나리액젓 1.5g\",\"국간장 1.5g\",\"물 15g\",\"고춧가루 1.7g\",\"매실액 6g\",\"통깨 1g\",\"다진 파 2.5g\",\"다진 마늘 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장을 미리 만들어 냉장 보관해두고 부추, 쑥갓, 상치 등을 무쳐 먹어도 맛있다. - 연한 쇠비름은 줄기 째 무쳐먹고 나물이 쇠면 단단한 줄기를 떼고 연한 부분만 먹는다.\",\"instructions\":[\"1. 쇠비름을 씻는다.\",\"2. 씻은 쇠비름을 소금물에 담가 살짝 절인다.\",\"3. 절여논 쇠비름을 헹구어 체에 건진다.\",\"4. 양념 재료를 모두 섞어 양념장을 만든다.\",\"5. 쇠비름에 양념장을 넣어 살짝 무쳐낸다.\",\"6. 그릇에 담아 완성한다.\"]},{\"id\":\"k446\",\"title\":\"깻잎단호박튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101944_1416273584860.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/683-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/683-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/683-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/683-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/683-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/683-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"깻잎 5g\",\"단호박 30g\",\"호두 5g\",\"꿀 3g\",\"찹쌀가루 10g\",\"물 15g\",\"콩기름 4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수삼을 잘게 썰어 넣어도 맛있다. - 크기가 큰 깻잎을 선택하여 깻잎 뒷면에 단호박을 넣고 말면 잘 말아지고 색도 선명하다.\",\"instructions\":[\"1. 단호박을 반 갈라 씨를 빼고 8등분 한다.\",\"2. 김이 오른 찜통에 단호박을 찐다.\",\"3. 찐 단호박을 껍질을 벗겨 으깨고 호두는 잘게 다진다.\",\"4. 으깬 단호박에 다진 호두와 꿀 넣고 섞는다.\",\"5. 깻잎 뒷면에 4 를 한 숟가락 올리고 양끝을 오무려 돌돌 만다.\",\"6. 찹쌀가루에 물 한 큰술을 섞은 튀김옷을 골고루 입혀 바삭하게 튀겨낸다.\"]},{\"id\":\"k447\",\"title\":\"냉머위들깨나물\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101949_1416273589013.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/684-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/684-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/684-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/684-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/684-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/684-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 : 머위대 70g\",\"들기름 2g\",\"쪽파 5g\",\"물 100g - 양념 : 거피들깨가루 6g\",\"국간장 3g\",\"다진 파 2.5g\",\"다진 마늘 1g\",\"소금 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"머위대를 물에 충분히 우려내야 쓴맛이 줄어든다. - 머위잎을 살짝 쪄서 강된장(강된장부추비빔밥 참조)을 발라 밥을 싸먹으면 쌉쌀한 맛이 입맛을 돋운다.\",\"instructions\":[\"1. 머위대를 잘라 데쳐서 껍질을 벗긴다.\",\"2. 데친 머위대를 찬물에 1~2 시간 담가 쓴맛을 제거한다.\",\"3. 양념을 넣어 머위대를 무친다.\",\"4. 팬에 들기름을 두르고 양념한 머위대를 볶는다.\",\"5. 물 반컵을 넣고 국물이 자박하도록 푹 끓여낸다.\",\"6. 완성된 머위나물을 식혀서 냉장고에 차게 보관하였다가 먹는다.\"]},{\"id\":\"k448\",\"title\":\"수박껍질풋고추볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102032_1416273632764.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/685-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/685-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/685-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/685-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/685-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/685-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"수박 속껍질 50g\",\"풋고추 15g\",\"홍고추 5g\",\"포도씨유 4g\",\"소금 1g(절일 때 0.5g\",\"간 맞출 때 0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수박을 먹을 때 미리 과육만 발라 썰어 내면 껍질을 요리에 활용하기 좋다. - 센 불에서 재빨리 볶아내면 아삭하게 익혀지고 기름 사용을 최소화 할 수 있다.\",\"instructions\":[\"1. 수박껍질의 녹색부분을 제거하고 얄팍하게 채 썬다.\",\"2. 채 썬 수박껍질에 소금을 뿌려 살짝 절여 물기를 짠다.\",\"3. 고추는 길이로 2등분하여 씨를 뺀다.\",\"4. 씨를 뺀 고추는 굵게 채 썬다.\",\"5. 팬에 기름을 두르고 수박껍질과 고추를 넣어 살짝 볶는다.\",\"6. 소금으로 간을 맞추고 마무리한다.\"]},{\"id\":\"k449\",\"title\":\"우무오미자냉화채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102047_1416273647602.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/686-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/686-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/686-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/686-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/686-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/686-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오미자 10g\",\"물 200g\",\"올리고당 14g\",\"우무묵 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오미자 슬러쉬에 꿀떡과 단팥을 올려 빙수로 먹어도 맛있다.\",\"instructions\":[\"1. 오미자를 헹궈 따뜻한 물에 담가 12시간 우린다.\",\"2. 우려낸 오미자물을 면보에 거른다.\",\"3. 오미자 국물 1컵에 올리고당을 넣어 감미한다.\",\"4. 우무를 곱게 채 썰거나 모양 틀로 찍어낸다.\",\"5. 오미자 국물을 살짝 얼려 믹서에 갈아 슬러쉬를 만든다.\",\"6. 오미자 슬러쉬에 우무를 올린다.\"]},{\"id\":\"k450\",\"title\":\"포도호두스무디\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102113_1416273673197.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/688-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/688-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/688-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/688-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/688-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/688-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"얼린포도알 80g\",\"오미자액 15g\",\"호상요구르트 30g\",\"깐호두 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"포도 대신 냉장고에 있는 살구, 자두, 복숭아 등 다른 제철과일을 이용해도 좋다.\",\"instructions\":[\"1. 포도를 씻는다.\",\"2. 포도 껍질을 까고, 포도알을 떼어 낸다.\",\"3. 포도알은 뚜껑이 있는 통에 담아 냉동고에 얼린다.\",\"4. 얼린 포도알에 오미자액과 호상요구르트를 넣고 믹서에 갈아 스무디를 만든다.\",\"5. 호두는 칼로 굵게 다진다.\",\"6. 다진 호두는 스무디 위에 뿌린다.\"]},{\"id\":\"k451\",\"title\":\"전복영양밥과 부추양념장\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102114_1416273674091.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/689-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/689-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/689-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/689-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/689-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/689-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"전복영양밥 : 쌀 90g\",\"전복살 40g\",\"양송이 버섯 13g\",\"표고버섯 15g\",\"당근 15g\",\"건다시마 5g\",\"물 400g - 부추양념장 : 다시마국물 5g\",\"부추 5g\",\"간장 5g\",\"실파 2.5g\",\"다진 마늘 2.5g\",\"참기름 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"전복은 솔로 살의 표면을 문질러 씻은 후 한손으로 껍데기부분을 잡고 숟가락을 이용해 얇은 쪽에서부터 전복살을 뜨고 푸르스름한 내장과 단단한 이빨을 제거한다. - 전복살을 썰 때는 사선방향으로 놓고 썰어야 미끄러지지 않고 잘 썰린다. - 다시마국물과 간장의 비율은 1:1로 섞어 사용한다\",\"instructions\":[\"1. 물 2컵에 건다시마를 넣어 다시마국물을 1컵 반 정도를 낸다.\",\"2. 우린 다시마와 전복살은 잘게 다진다.\",\"3. 표고버섯, 양송이버섯, 당근은 0.5~0.7cm 주사위모양으로 썬다.\",\"4. 쌀은 씻어 2와 3을 넣고 다시마국물 1컵 반을 부어 30분 정도 불린 후 밥을 짓는다.\",\"5. 부추와 실파는 다지고 참기름, 다진 마늘, 통깨, 다시마국물, 간장을 넣어 양념장을 만든다.\",\"6. 전복영양밥과에 부추양념장을 곁들인다.\"]},{\"id\":\"k452\",\"title\":\"근대쌈밥과 멸치견과류쌈장\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102115_1416273675090.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/690-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/690-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/690-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/690-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/690-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/690-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"근대쌈밥 : 쌀 70g\",\"현미 10g\",\"보리쌀 10g\",\"근대 50g\",\"물 400g\",\"국멸치 2g\",\"건다시마 2.5g\",\"- 멸치견과류쌈장 : 다시마국물 10g\",\"양파 3g\",\"된장 2.5g\",\"파 2.5g\",\"고추장 2.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"근대 대신 취나물, 양배추잎, 호박잎 등을 사용해도 된다.\",\"instructions\":[\"1. 물 2/3컵에 국멸치와 건다시마를 넣고 끓여 국물을 내면서 이 열로 근대를 삼발이에 놓고 찐다.\",\"2. 국물 우린 다시마를 잘게 썰어 쌀, 현미, 보리쌀과 함께 잡곡밥을 짓는다.\",\"3. 잔멸치는 기름을 두르지 않고 팬에 살짝 볶아 다지고 견과류도 칼로 다진다.\",\"4. 양파와 파를 다진다.\",\"5. 고추장, 된장, 견과류, 양파, 다진 마늘, 매실액, 파, 멸치다시마국물을 섞어 멸치견과류쌈장을 만든다.\",\"6. 근대위에 밥을 약 30g(1숟가락)정도 올리고 멸치견과류쌈장 5g 가량 넣어 근대잎으로 싼다.\"]},{\"id\":\"k453\",\"title\":\"장어조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00428_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00428_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00428_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00428_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00428_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00428_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00428_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"장어 150g\",\"깻잎 10g\",\"청고추17g\",\"홍고추 17g\",\"양파 60g\",\"생강 15g\",\"양념장 : 맛간장 25g\",\"올리고당 15g\",\"청주 15g\",\"참기름 15g\",\"흰후추 1g\",\"통깨 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"깻잎을 곱게 채 썰어 깻잎의 향으로 기존에 먹어왔던 장어 소스의 진한 맛을 중화시켜주었다.\",\"instructions\":[\"1. 장어는 한입 크기로 잘라서 흰 후추와 청주를\\n뿌려 재워준다.\",\"2. 깻잎은 채를 썰어서 냉수에 담가 물기를\\n빼준다.\",\"3. 생강, 마늘은 편으로 썰어주고 양파, 청고추,\\n홍고추는 어슷하게 잘라준다.\",\"4. 참기름을 뺀 양념장 재료에 편마늘과 다진대파를\\n넣어서 양념장을 만들어준다.\",\"5. 만들어진 양념장 1/2에 장어를 넣고 졸여준다.\",\"6. 나머지 양념장에 준비된 채소를 넣어 볶아주다\\n졸인 장어를 넣어 졸여주고 깻잎을 깔고\\n완성한다.\"]},{\"id\":\"k454\",\"title\":\"통삼겹스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00429_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00429_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00429_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00429_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00429_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00429_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00429_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통삼겹 200g\",\"건로즈마리 1g\",\"로즈마리 2g\",\"올리브유 15g\",\"곁들이채소1 : 백일송이 30g\",\"당근 20g\",\"양파 60g\",\"곁들이채소2 : 2가지색 미니파프리카 30g\",\"양파 60g\",\"식초 15g\",\"설탕 1g\",\"매쉬포테이토 : 감자 100g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장소스에 플레인 요구르트를 사용해 나트륨을 줄여주었고,\\n볶은 현미를 이용해 부족한 맛을 고소한 맛으로 내주었다.\",\"instructions\":[\"1. 통삼겹에 건로즈마리와 로즈마리, 올리브유를\\n넣고 마리네이드 해준다.\",\"2. 양파는 먹기 좋게 썰어 식초, 설탕, 로즈마리에\\n살짝 버무려준다.\",\"3. 양파, 2가지색 미니파프리카는 송송 다져서\\n설탕, 식초에 담가 꼭 짜서 수분을 빼준다.\",\"4. 당근은 먹기 좋은 크기로 잘라서 버터에 살짝\\n볶아주다 백일송이 버섯도 함께 볶아준다.\",\"5. 재워 놓은 통삼겹은 플레인요구르트에 다시\\n30분 정도 더 재워준 후 소스에 졸여준다.\",\"6. 감자를 쪄서 버터에 매쉬포테이토를 만들어\\n담아주고, 구운 통삼겹과 준비된 채소와 볶은\\n현미를 올려 완성한다.\"]},{\"id\":\"k455\",\"title\":\"저염된장 삼치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306050759_1678090079442.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306050908_1678090148319.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306050923_1678090163609.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306050941_1678090181947.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306050959_1678090199008.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051031_1678090231590.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051053_1678090253179.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 삼치(140g)\",\"치커리(35g)\",\"전분가루(10g)\",\"•구이소스 : 일본된장(5g)\",\"청주(5g)\",\"•곁들임소스 : 유자청(15g)\",\"다진마늘(5g)\",\"청고추(15g)\",\"홍고추(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•달콤하고 매콤한 소스를 사용하여 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 삼치는 세척 후 전분가루로 옷을 입혀준다.\",\"2. 일본된장과 청주를 섞어 구이소스를 만들어 삼치를 재운다.\",\"3. 청고추와 홍고추는 곱게 다지고 치커리는 적당하게 잘라서 물에 담가준다.\",\"4. 유자청, 다진마늘, 다진 청고추와 홍고추를 섞어 곁들임소스를 만든다.\",\"5. 재워두었던 삼치를 굽는다.\",\"6. 접시에 구운 삼치와 치커리를 올리고 치커리를 올리고 곁들임소스를 뿌려 완성한다.\"]},{\"id\":\"k456\",\"title\":\"미역전복죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00431_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00431_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00431_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00431_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00431_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00431_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00431_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"전복 100g\",\"찹쌀 70g\",\"당근 25g\",\"다시마 사방 10x10cm\",\"건조 자른미역 3g\",\"참기름 15g\",\"검정깨 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"전복 껍질에서 나오는 구수한 맛과 짠맛이 추가로 간을 안해도 염도를 맞출 수가 있었다.\\n검정깨의 고소한 맛은 죽을 먹기 전에 간을 하지 않아도 담백하고 고소한 맛으로 나트륨 줄인 죽을 만들 수가 있다.\",\"instructions\":[\"1. 전복은 내장과 분리해 손질한다.\",\"2. 내장은 칼로 다진다.\",\"3. 당근과 전복살은 송송 잘라준다.\",\"4. 전복 껍질과 다시마를 넣어 물 300g에 국물을\\n만들어준다.\",\"5. 만들어진 국물에 미역을 넣고 끓여준다.\",\"6. 다진 내장과 불린 찹쌀을 참기름에 볶다가\\n끓인 미역국을 넣고 더 끓여 죽을 만든다.\\n다진 당근, 흑임자로 마무리 완성한다.\"]},{\"id\":\"k457\",\"title\":\"불고기미니볼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00432_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00432_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00432_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00432_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00432_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00432_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00432_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다진소고기 40g\",\"다진양파 15g 빵가루 30g\",\"계란 60g\",\"밀가루 15g\",\"식용유 200g\",\"단호박 25g\",\"감자 25g\",\"로즈마리 1g\",\"양념장 : 참기름 5g\",\"맛간장 15g\",\"생강청 15g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"딸기잼과 오미자청을 이용하여 새콤하면서 달콤한 맛을 주었으며,\\n튀김의 고소하면서 새콤달콤한 소스가 짠맛을 보완해 주었다.\",\"instructions\":[\"1. 단호박, 감자는 가늘게 채 썰어 기름에 바싹\\n튀겨준다\",\"2. 불고기에 다진 양파를 섞어 양념장에 버무려\\n준다.\",\"3. 양념된 불고기는 완자로 만들어 밀가루, 계란,\\n빵가루 순으로 묻혀서 기름에 튀겨준다.\",\"4. 소스를 만들어준다\",\"5. 튀겨진 소고기 볼을 기름에 한 번 더 튀겨준다.\",\"6. 접시에 으깬 감자와 불고기볼 그리고 튀김을\\n올리고 소스와 바질을 올려 완성한다\"]},{\"id\":\"k458\",\"title\":\"치자연근물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00433_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00433_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00433_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00433_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00433_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00433_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00433_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연근 200g\",\"당근 40g\",\"미나리 20g\",\"청고추 15g\",\"홍고추 18g\",\"알마늘 12g\",\"치자가루 15g\",\"생강청 30g\",\"식초 15g\",\"볶은소금 5g\",\"설탕 7g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"국물을 만들 때 마늘을 이용해 마늘의 향을 충분히 살려 시원한 맛을 내주었으며 생연근으로 식감을 살려주었다.\",\"instructions\":[\"1. 당근은 모양틀로 잘라서 편으로 썰어준다.\",\"2. 연 근 은 껍 질 을 벗 겨 서 식 초 물 에 살 짝\\n담가준다.\",\"3. 청고추, 홍고추, 미나리는 먹기 좋게 썰어준다.\",\"4. 마늘은 편으로 썰어서 물 400g에 끓여주다\\n불을 끄고 치자가루를 넣어 국물을 만들어준다.\",\"5. 국물에 연근을 담가 색을 들인다.\",\"6. 여기에 생강청, 식초, 설탕, 볶은소금과 준비된\\n채소를 넣어 치자 연근물김치를 완성한다.\"]},{\"id\":\"k459\",\"title\":\"훈제연어롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00434_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00434_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00434_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00434_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00434_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00434_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00434_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"훈제연어(100g)\",\"양파(20g)\",\"피클(20g)\",\"후춧가루(0.02g)\",\"- 소스 : 오렌지(30g)\",\"오렌지 주스(20g)\",\"설탕(10g)\",\"레몬(10g)\",\"물녹말(10g)\",\"스위트칠리(20g)\",\"- 곁들임채소 : 아스파라거스(20g)\",\"어린잎(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"피클과 양파를 사용하여 훈제 연어의 맛을 한층 더 살렸고, 소스에 오렌지를 넣어 새콤달콤한 맛을 첨가하여 나트륨 함량이 낮으면서도 맛있는 롤을 만들었어요.\",\"instructions\":[\"1. 훈제연어를 살포시 포를 뜬다.\",\"2. 양파와 피클은 곱게 다져 준비한다.\",\"3. 포를 떠 놓은 훈제 연어에 살짝 후춧\\n가루를 뿌리고, 양파와 피클을 넣어\\n말아준다.\",\"4. 오렌지는 껍질과 과육을 분리해서 썰어\\n준비한다.\",\"5. 냄비에 오렌지주스와 설탕과 레몬,\\n분리시킨 오렌지를 넣고 끓여준다.\",\"6. 끓고 있는 오렌지소스에 물녹말과 스위\\n트칠리소스를 넣고 한 소큼만 끓인 후\\n말아 놓은 훈제 연어롤을 접시에 담고,\\n어린잎을 한쪽에 놓아주고, 오렌지\\n소스를 함께 올려 완성한다.\"]},{\"id\":\"k460\",\"title\":\"크림닭\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00435_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00435_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00435_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00435_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00435_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00435_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00435_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살(120g)\",\"우유(100g)\",\"소금(0.5g)\",\"후춧가루(0.02g)\",\"밀가루(10g)\",\"달걀(50g)\",\"빵가루(20g)\",\"튀김기름(100g)\",\"양송이버섯(30g)\",\"양파(20g)\",\"버터(10g)\",\"크림소스(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크림소스를 이용하여 만든 크림 닭은 부드럽고 단백하며, 치즈를 활용한 소스는 나트륨 사용을 줄여 줄 수 있었어요.\",\"instructions\":[\"1. 우유에 닭가슴살을 넣어 약20분 정도\\n재워 놓는다.\",\"2. 양송이버섯은 껍질을 벗기고, 양파와\\n캐슈넛과 각각 다져 준비한다.\",\"3. 우유에 재워놓은 닭가슴살은 소금,\\n후춧가루를 뿌려 밀가루와 달걀물,\\n빵가루 순서로 입혀 기름에 튀기듯이\\n익혀 기름을 빼놓는다.\",\"4. 팬에 버터를 넣고, 버터가 녹으면,\\n양송이와 양파를 넣고 볶는다.\",\"5. 볶아지는 채소에 크림소스를 넣어\\n은근히 볶는다.\",\"6. 소스가 볶아지면, 마지막에 다져 놓은\\n캐슈넛과 생크림, 모짜렐라치즈를\\n넣고 한 번 더 익힌 후, 접시에 어린잎과,\\n닭가슴살을 놓고, 크림소스를 곁들여\\n완성한다.\"]},{\"id\":\"k461\",\"title\":\"등심채소롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00436_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00436_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00436_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00436_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00436_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00436_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00436_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심(100g)\",\"소금(0.3g)\",\"후춧가루(0.05g)\",\"파프리카(30g)\",\"시금치(30g)\",\"파인애플(30g)\",\"치즈(30g)\",\"밀가루(20g)\",\"달걀(50g)\",\"빵가루(30g)\",\"튀김기름(200g)\",\"- 소스 : 칠리소스(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일과 채소를 이용하여 아이들이 골고루 먹을 수 있는 음식을 만들었으며, 상큼한 파인애플과 매콤달콤한 칠리소스가 풍부한 맛을 더했어요.\",\"instructions\":[\"1. 등심은 넓게 펴서 소금과 후춧가루를\\n뿌려 준비한다.\",\"2. 파프리카와 파인애플은 속을 제거하고\\n약 7cm 길이로 썰어놓는다.\",\"3. 시금치는 끓는 물에 데쳐 찬물에 헹구어\\n준비한다.\",\"4. 밑간을 해 놓은 등심에 준비한 파프리카와\\n시금치 파인애플을 넣는다.\",\"5. 채소와 파인애플을 넣은 등심에 치즈를\\n넣고 돌돌말아 밀가루, 달걀물, 빵가루\\n순서로 입혀 튀김기름 170~180℃에서\\n약 3분 정도 튀겨 기름을 빼 놓는다.\",\"6. 냄비에 칠리소소와 물, 설탕을 넣고\\n바글바글 끓이다가 물녹말을 넣고\\n한 번 더 끓인 후, 튀겨놓은 등심채소\\n롤에 함께 뿌려 완성한다.\"]},{\"id\":\"k462\",\"title\":\"유부완자탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00437_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00437_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00437_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00437_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00437_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00437_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00437_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"유부(50g)\",\"두부(30g)\",\"새우(50g)\",\"배추(30g)\",\"표고버섯(30g)\",\"양파(30g)\",\"당근(30g)\",\"마늘(10g)\",\"저염소금(0.5g)\",\"후춧가루(0.05g)\",\"미나리(20g)\",\"육수(200g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"유부주머니가 어린이들의 호기심을 자극할 수 있으며, 새우를 넣어 감칠맛을 더해 짠맛을 대체하였어요.\",\"instructions\":[\"1. 유부는 1/4 정도를 잘라 준비한다.\",\"2. 잘라진 유부는 끓는 물에 약 20초 정도\\n데쳐 물기를 짜 놓는다.\",\"3. 새우는 내장과 껍질을 제거 하고 곱게\\n으깨 준비한다.\",\"4. 배추와 미나리는 끓는 물에 데치고,\\n표고버섯은 뜨거운 물에 불려 준비\\n한다.\",\"5. 데친 배추와 표고버섯을 입자있게\\n다지고, 양파와 당근도 입자있게 다져\\n준비한다.\",\"6. 두부는 물기를 짜 놓은 후 새우(③)와\\n다진 야채(⑤), 마늘, 소금, 후춧가루\\n를 넣고 골고루 섞는다. 유부(②)에\\n속을 넣고 미나리로 묶은 후, 끓는\\n육수에 유부주머니를 넣고 간장으로\\n간을 하여 완성한다.\"]},{\"id\":\"k463\",\"title\":\"미니밥버거\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00438_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00438_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00438_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00438_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00438_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00438_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00438_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥패티 : 찹쌀(100g)\",\"현미쌀(50g)\",\"올리브오일(10g)\",\"버터(10g)\",\"- 소고기패티 : 다진소고기(50g)\",\"양파(20g)\",\"마늘(10g)\",\"빵가루(10g)\",\"생크림(10g)\",\"으깬두부(20g)\",\"소금(0.2g)\",\"후춧가루(0.02g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"햄버거를 좋아하는 아이들에게 밥패티와 다양한 재료가 들어간 소고기패티를 넣어 만든 밥버거는 나트륨 함량도 낮고 영양가 있는 인기 만점 버거예요.\",\"instructions\":[\"1. 찹쌀과 현미는 깨끗이 씻어 30분 이상\\n충분히 불려 밥을 지어, 둥글둥글하게\\n패티를 만들어 놓는다.\",\"2. 마늘과 양파는 곱게 다져 볶아 준비\\n한다.\",\"3. 다진고기에 볶은 양파와 마늘, 빵가루,\\n생크림, 으깬두부, 소금, 후춧가루를\\n넣어 골고루 섞는다.\",\"4. 섞어진 소고기를 둥글게 패티를 만들어\\n놓는다.\",\"5. 토마토는 편으로 썰어 준비한다.\",\"6. 팬에 올리브 오일과 버터를 넣고 팬이\\n따끈하게 달궈지면, 밥패티를 먼저\\n굽고, 소고기 패티를 구운 후, 밥패티에\\n마요네즈를 살짝 바르고, 치즈와\\n토마토를 올리고, 구운 소고기패티를\\n올려 다시 밥패티를 덮어 완성한다.\"]},{\"id\":\"k464\",\"title\":\"파프리카볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00439_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00439_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00439_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00439_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00439_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00439_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00439_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당근(20g)\",\"쥬키니호박(20g)\",\"표고버섯(10g)\",\"양송이버섯(10g)\",\"파인애플(20g)\",\"버터(10g)\",\"밥(50g)\",\"닭고기살(30g)\",\"다진마늘(10g)\",\"저염간장(10g)\",\"양파(20g)\",\"올리고당(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토 사용으로 나트륨 배출을 시킬 수 있었어요.\",\"instructions\":[\"1. 당근, 양파, 호박, 버섯은 입자있게\\n다지고, 파인애플은 작은 깍뚝썰기로\\n썰어 준비한다.\",\"2. 닭고기살은 작게 썰어 팬에 저염간장과\\n양파, 다진마늘, 올리고당을 넣어\\n볶으면서 졸인다.\",\"3. 팬에 버터를 녹인 후 준비한 밥을\\n넣고 볶는다.\",\"4. 볶은밥(③)에 썰어놓은 채소(①)를\\n넣고, 다시 볶아준다.\",\"5. 밥과 채소가 볶아지면, 닭고기살(②)을\\n넣고, 토마토 페스트와 토마토를\\n다져넣고 볶는다.\",\"6. 파프리카의 속을 파내고, 그 안에\\n볶아진 밥(⑤)을 넣고, 달걀물을\\n씌우고 모짜렐라치즈를 뿌려 치즈가\\n녹을 때까지 팬에 뚜껑을 덮어\\n약불에서 익힌 후 파슬리가루를\\n올려 완성한다.\"]},{\"id\":\"k465\",\"title\":\"리코타치즈돈가스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00440_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00440_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00440_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00440_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00440_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00440_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00440_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심(120g)\",\"소금(0.3g)\",\"후춧가루(0.03g)\",\"올리브오일(10g)\",\"밀가루(10g)\",\"달걀(50g)\",\"빵가루(20g)\",\"튀김기름(200g)\",\"- 리코타치즈 : 우유(50g)\",\"레몬즙(10g)\",\"모짜렐라치즈(10g)\",\"- 소스 : 양파(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"판매하는 리코타치즈가 아닌, 직접 만들어 사용하는 리코타치즈로 나트륨에 대한 섭취를 낮추었어요.\",\"instructions\":[\"1. 돼지등심을 넓게 피고 소금과 후춧가루\\n올리브오일을 발라 숙성시킨다.\",\"2. 우유를 끓이다가 레몬즙을 넣고 몽글\\n거리면, 소창에 걸러 리코타치즈를\\n만든다.\",\"3. 양파와 토마토, 마늘, 사과는 입자있게\\n다져 케첩을 섞어준다.\",\"4. 숙성시킨 등심에 리코타치즈를\\n올려준다.\",\"5. 리코타치즈를 올린 등심에 다시 모짜렐\\n라치즈를 넣고 등심을 다시 위에 올려,\\n밀가루와 달걀물, 빵가루 순서로 입힌\\n뒤 튀김온도 170~180℃에 약 3분 정도\\n튀겨 기름을 빼 놓는다.\",\"6. 냄비에 준비해 놓은 소스(③)를 넣고\\n볶다가 돈가스 소스를 넣고 다시 한 번 더\\n끓인 후 튀겨놓은 리코타돈가스(⑤)에\\n곁들여 완성한다.\"]},{\"id\":\"k466\",\"title\":\"삼겹살부추찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00544_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00544_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00544_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00544_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00544_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00544_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00544_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼겹살(150g)\",\"생강(20g)\",\"양파(20g)\",\"월계수잎(3g)\",\"통후추(5g)\",\"소주(10g)\",\"된장(10g)\",\"부추(50g)\",\"편마늘(20g)\",\"홍고추(10g)\",\"- 소스 : 저염간장(20g)\",\"물(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"찜기를 이용한 조리법은 수증기로 된장 간이 베이므로 나트륨을 낮출 수 있는 조리법이예요.\",\"instructions\":[\"1. 보쌈용 삼겹살을 깨끗이 씻어 생강채와\\n양파채, 월계수잎, 통후추와 소주를\\n넣고 약 1시간 정도 숙성을 시킨다.\",\"2. 찜통에 물과 된장, 편마늘을 넣고 숙성된\\n삼겹살을 올려 약 50분 정도 찜을 하다가\\n부추를 올려 1분 정도 더 찜을 한다.\",\"3. 부추는 약 6cm 길이로 썰어 준비한다.\",\"4. 홍고추는 반으로 갈라 씨를 제거하고,\\n채를 썰어 놓는다.\",\"5. 냄비에 간장과 물, 설탕, 올리고당,\\n통후추, 생강을 넣고 은근히 끓인다.\",\"6. 소스가 은근히 끓고 있을 때 채로 생강과\\n통후추를 걸러내고, 물녹말을 풀어 한\\n소큼 더 끓인 후, 찜통에서 쪄 나온 부추와\\n삼겹살을 썰어 접시에 담고, 그 위에\\n소스와 홍고추를 올려 완성한다.\"]},{\"id\":\"k467\",\"title\":\"전복죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00545_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00545_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00545_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00545_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00545_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00545_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00545_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(50g)\",\"전복(50g)\",\"새우살(20g)\",\"양송이(20g)\",\"당근(10g)\",\"참기름(10g)\",\"잣(10g)\",\"- 소스 : 저염간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"전복 자체에 간을 이용하고, 참기름의 고소하고 깊은 맛을 이용하여 별도의 소금을 사용하지 않은 음식이예요.\",\"instructions\":[\"1. 깨끗이 씻은 쌀에 물을 2배 정도 넣고\\n약 30분 정도 충분히 불려 준비한다.\",\"2. 전복은 수저를 이용하여 껍질에서\\n떼어내어 내장을 분리해 놓는다.\",\"3. 내장을 제거한 전복은 깨끗이 씻어,\\n썰어 놓는다.\",\"4. 새우살은 꼬리를 제거하고 입자있게\\n썰어 놓는다.\",\"5. 양송이는 껍질을 벗겨 입자있게\\n썰고, 당근도 양송이 크기에 맞게\\n썰어 놓는다.\",\"6. 냄비에 참기름을 두르고, 전복을 은근히\\n볶다가, 다시 불린 쌀을 넣고 볶은 뒤\\n물을 넣고 약 20분 정도 끓인다. 죽이\\n끓으면 새우와 양송이, 당근을 넣고\\n은근히 저어가면서 다시 20분 정도\\n더 끓여, 죽이 어우러지면 잣을 올리고\\n저염간장을 함께 제공한다.\"]},{\"id\":\"k468\",\"title\":\"오징어토마토초무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00546_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00546_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00546_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00546_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00546_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00546_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00546_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어(100g)\",\"미나리(20g)\",\"소금(0.3g)\",\"토마토(50g)\",\"양파(20g)\",\"청고추(10g)\",\"홍고추(10g)\",\"대파(10g)\",\"당근(20g)\",\"통깨(5g)\",\"- 양념장 : 토마토(50g)\",\"고추장(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토를 활용하여 소스를 만들어 짠맛을 감소시킴으로써 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 오징어는 껍질을 벗겨 안 쪽으로 칼집을\\n넣어 무늬를 만들어 놓는다.\",\"2. 끓는 물에 소금을 넣고 미나리를 데쳐\\n찬물에 헹구고, 바로 오징어를 데쳐\\n준비한다.\",\"3. 준비한 토마토 반은 굵게 다지고, 반은\\n썰어서 접시에 돌려 담아놓는다.\",\"4. 다진 토마토와 고추장, 식초, 생강즙,\\n올리고당을 골고루 섞어 양념장을\\n만든다.\",\"5. 당근, 양파, 대파, 청 ․ 홍고추를 썰어\\n놓는다.\",\"6. 만들어 놓은 양념장에 데친 오징어와\\n채소를 넣어 무친 후 토마토를 돌려\\n담은 접시에 담아 통깨를 올려 완성한다.\"]},{\"id\":\"k469\",\"title\":\"들깨칼국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00547_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00547_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00547_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00547_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00547_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00547_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00547_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀가루(100g)\",\"녹말가루(10g)\",\"식용유(10g)\",\"소금(0.2g)\",\"달걀(50g)\",\"애호박(20g)\",\"홍고추(10g)\",\"들깨가루(30g)\",\"- 육수 : 건새우(10g)\",\"멸치(20g)\",\"양파(20g)\",\"다시마(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시원한 해물육수와 고소한 들깨의 조합으로 별도의 소금이 필요없어요\",\"instructions\":[\"1. 밀가루에 녹말가루와 식용유, 소금,\\n달걀, 물을 넣고 반죽을 한다.\",\"2. 반죽된 밀가루를 비닐에 넣고 숙성을\\n시킨다.\",\"3. 냄비에 건새우와 머리 ․ 내장을 제거한\\n멸치, 양파, 다시마, 무, 통마늘을 넣고\\n끓인 육수를 소창에 걸러 놓는다.\",\"4. 호박은 반달로 썰고, 홍고추는 어슷\\n썰어 준비한다.\",\"5. 만들어 놓은 육수에 들깨 가루를 넣어\\n끓인다.\",\"6. 숙성된 밀가루(②)를 얇게 밀어 칼국수로\\n만든 뒤 준비한 육수(⑤)를 한소끔 끓인\\n후 칼국수와 호박을 넣어 끓이다가 다시\\n홍고추를 넣고 한 번 더 끓여 완성한다.\"]},{\"id\":\"k470\",\"title\":\"소고기채소불고기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308031803_1678256283359.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308031844_1678256324276.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308031856_1678256336951.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308031915_1678256355410.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308031929_1678256369102.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308031942_1678256382651.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308032001_1678256401133.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 소불고기(120g)\",\"배(20g)\",\"정종(5g) 양배추(10g)\",\"양파(10g)\",\"깻잎(5g)\",\"표고버섯(10g) 당근(10g)\",\"대파(5g)\",\"청고추(5g)\",\"홍고추(5g)\",\"•곁들임 채소 : 대추(10g)\",\"통깨(1g)\",\"•소스 : 저염간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•배즙과 저염간장 사용으로 나트륨 함량을 줄였어요.\\n•소고기는 배즙과 정종에 재워 고기를 부드럽게 하고 누린내를 제거해요.\\n•향이 진한 깻잎과 표고버섯을 넣어 풍부한 풍미를 더해 조리해요.\",\"instructions\":[\"1. 배는 껍질을 벗겨 배즙을 갈아 준비한다.\",\"2. 소고기에 배즙과 정종을 넣어 버무려 숙성시킨다.\",\"3. 양배추와 양파, 깻잎, 표고버섯은 채 썰고 대파와 당근은 납작하게 5cm 길이로 썰고 청·홍고추는 어슷 썰어 준비한다.\",\"4. 간장과 올리고당, 참기름, 다진마늘, 후춧가루를 넣어 소스를 만든다.\",\"5. 만든 소스를 소불고기에 넣어 2차 숙성을 시킨다.\",\"6. 팬에 고기를 볶고 별도로 채소를 볶은 뒤 씨를 빼고 얇게 썬 대추와 통깨를 얹어 접시에 함께 담아 완성한다.\"]},{\"id\":\"k471\",\"title\":\"숙주라면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00549_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00549_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00549_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00549_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00549_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00549_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00549_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홍합(20g)\",\"숙주(50g)\",\"청경채(20g)\",\"청고추(5g)\",\"홍고추(5g)\",\"고춧가루(10g)\",\"굴소스(10g)\",\"라면(100g)\",\"대파(10g)\",\"달걀(50g)\",\"- 육수 : 멸치(20g)\",\"건새우(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해물 육수에 홍합을 넣어 만들어서 별도의 나트륨을 첨가하지 않아도 맛이 좋아요.\",\"instructions\":[\"1. 멸치, 건새우, 무, 양파, 마늘을 넣고\\n육수를 만들어 소창에 걸러 준비한다.\",\"2. 홍합은 끓는 물에 살짝 데쳐 놓는다.\",\"3. 숙주는 씻어 놓고 청경채는 반으로\\n자르고 청 ․ 홍고추는 어슷썰어 준비\\n한다.\",\"4. 만들어 놓은 육수에 고춧가루와\\n굴소스를 넣어 끓인다.\",\"5. 달걀은 풀어 준비한다.\",\"6. 육수(④)가 끓으면 라면을 넣고, 다시\\n한 번 더 끓으면 홍합을 넣어 끓이다가,\\n불을 줄인 뒤 달걀을 넣어 줄알을 치고,\\n청경채와 숙주, 홍고추와 대파를 넣고\\n살짝 끓은 뒤 그릇에 담아 완성한다.\"]},{\"id\":\"k472\",\"title\":\"곤약냉면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00550_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00550_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00550_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00550_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00550_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00550_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00550_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"실곤약(100g)\",\"무(20g)\",\"식초(10g)\",\"소금(0.2g)\",\"설탕(10g)\",\"홍파프리카(20g)\",\"오이(20g)\",\"배(20g)\",\"달걀(30g)\",\"- 국물 : 동치미국물(200g)\",\"배즙(10g)\",\"홍초(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"동치미 국물에 배즙을 넣어 시원함을 높였어요.\",\"instructions\":[\"1. 곤약은 끓는 물에 넣어 데친다.\",\"2. 데친 곤약은 찬물에 헹구어 채에 받쳐\\n물기를 빼 놓는다.\",\"3. 무는 얇게 썰어 식초, 소금, 설탕에 넣어\\n김치를 만든다.\",\"4. 파프리카는 5cm 길이로 썰고, 배와\\n오이도 같은 길이로 얇게 썬 뒤 오이는\\n살짝 절인다.\",\"5. 달걀은 삶아 껍질을 벗겨, 실로 잘라\\n놓는다.\",\"6. 동치미 국물에 배즙 , 홍초, 설탕 , 겨자,\\n식초를 넣어 섞는다. 그릇에 곤약국수를\\n담고, 무김치(③)와 준비한 채소(④)를\\n올리고, 삶은 달걀(⑤)을 얹고, 국물을\\n살며시 넣어 완성한다.\"]},{\"id\":\"k473\",\"title\":\"과일갈비찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00551_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00551_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00551_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00551_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00551_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00551_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00551_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지갈비(150g)\",\"홍고추(5g)\",\"참기름(5g)\",\"통깨(2g)\",\"배(20g)\",\"사과(20g)\",\"대추(20g)\",\"밤(10g)\",\"오이(20g)\",\"양파(20g)\",\"당근(20g)\",\"무(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과와 배의 새콤달콤한 맛과, 대추와 생강 등의 맛이 어우러져 간장을 적게 사용해도 맛을 유지시켜 주어요.\",\"instructions\":[\"1. 돼지갈비는 물에 담그어 핏물을 충분히\\n제거한다.\",\"2. 홍고추는 어슷썰어 냄비에 볶는다.\",\"3. 핏물을 제거한 돼지갈비를 홍고추와\\n함께 넣어 볶아준다.\",\"4. 배는 강판에 갈고, 파, 마늘, 생강은\\n다진 뒤 간장과 올리고당, 설탕,\\n후춧가루, 소주와 함께 넣고 골고루\\n섞어서 양념장을 만든다.\",\"5. 사과, 대추, 밤, 오이, 양파, 당근, 무는\\n사각 깍둑 썰기로 준비한다.\",\"6. 볶아진 갈비(③)에 양념장(④)과 물을\\n넣고 은근히 갈비를 졸이다가, 국물이\\n자작하게 남으면, 손질한 과일과 채소\\n등(⑤)을 참기름과 함께 넣고, 한 번 더\\n졸여 완성한다.\"]},{\"id\":\"k474\",\"title\":\"토마토소스닭갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00552_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00552_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00552_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00552_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00552_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00552_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00552_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭(120g)\",\"생강즙(10g)\",\"소주(10g)\",\"양파(20g)\",\"당근(20g)\",\"깻잎(5g)\",\"양배추(30g)\",\"고구마(20g)\",\"- 소스 : 토마토(30g)\",\"토마토소스(50g)\",\"마늘(20g)\",\"고춧가루(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭갈비 소스에 토마토를 넣어 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 닭은 먹기 좋은 크기로 잘라 준비한다.\",\"2. 토막 낸 닭 에 생강즙과 소주를 넣어\\n숙성한다.\",\"3. 양파, 당근은 얇게 썰고, 양배추는 깍뚝\\n썰고, 깻잎은 4등분하여 잘라놓는다.\",\"4. 작은 깍둑썰기로 자른 토마토와\\n고구마에 토마토소스, 마늘, 고춧가루,\\n고추장, 매실청을 넣어 골고루 섞는다.\",\"5. 닭을 먼저 냄비에 볶는다.\",\"6. 볶아지는 닭에 만들어 놓은 소스를\\n넣고, 볶다가 준비한 채소를 넣어 한 번\\n더 볶아 완성한다.\"]},{\"id\":\"k475\",\"title\":\"골뱅이과일무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00553_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00553_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00553_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00553_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00553_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00553_5.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"골뱅이(50g)\",\"통깨(2g)\",\"당근(20g)\",\"양파(20g)\",\"양배추(20g)\",\"깻잎(10g)\",\"대파(10g)\",\"홍고추(5g)\",\"청고추(5g)\",\"황도(20g)\",\"배(20g)\",\"사과(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갖가지 채소와 과일맛이 양념과 함께 어우러져 짠 맛을 대체하면서 식욕을 자극한다.\",\"instructions\":[\"1. 골뱅이는 뜨거운 물에 살짝 데친 뒤\\n물기를 빼고 4등분으로 썬다.\",\"2. 양파와 깻잎은 채썰고, 당근은 양파랑\\n같은 길이로 얇게 저미고, 고추와\\n대파는 어슷썰고, 양배추는 1~2cm\\n두께로 썬다.\",\"3. 사과와 배는 채를 썰고 황도와 바나나,\\n파인애플은 작게 깍둑썰기 한다.\",\"4. 고추장에 고춧가루, 다진 마늘, 케첩,\\n설탕, 식초, 매실액, 생강즙, 참기름을\\n골고루 섞어 양념장을 만든다.\",\"5. 양념장에 준비한 골뱅이(①), 채소(②),\\n과일(③)을 넣고 고루 섞은 뒤 통깨를\\n얹어 완성한다.\"]},{\"id\":\"k476\",\"title\":\"두유 마 떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00588_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00588_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00588_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00588_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00588_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00588_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00588_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(120g)\",\"돼지고기(120g)\",\"떡볶이떡(100g)\",\"흑미(20g)\",\"현미(20g)\",\"백미(20g)\",\"조(10g)\",\"애호박(1/4개)\",\"당근(20g)\",\"토마토(150g)\",\"양송이버섯(20g)\",\"양파(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두유의 고소한 맛 때문에 소금을 적게 넣어도 충분히 맛있어요.\",\"instructions\":[\"1. 표고버섯은 뜨거운 물에 약 1시간 정도\\n불려 다지듯이 썬다.\",\"2. 마는 껍질을 벗겨 썰어서 갈아주고,\\n연근은 껍질을 벗겨 팬에 굽는다.\",\"3. 애호박은 반달모양으로 썰어 끓는 물에\\n감자와 함께 데친다.\",\"4. 소고기와 돼지고기는 곱게 다져\\n저염간장, 설탕, 다진마늘 및 간 마를\\n넣고 골고루 치대어 떡갈비를 만들고,\\n팬에 기름을 두르고 앞뒤로 굽는다\",\"5. 깻잎은 저염간장에 살짝 절인다\",\"6. 구워 놓은 떡갈비와 깻잎, 표고버섯,\\n연근, 애호박 및 감자를 접시에 담고 간\\n마와 두유를 섞어 자작하게 끓여 만든\\n소스를 그 밑에 담아 완성한다\"]},{\"id\":\"k477\",\"title\":\"떡갈비와 미니잡곡밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00589_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00589_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00589_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00589_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00589_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00589_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00589_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(120g)\",\"돼지고기(120g)\",\"떡볶이떡(100g)\",\"흑미(20g)\",\"현미(20g)\",\"백미(20g)\",\"조(10g)\",\"애호박(1/4개)\",\"당근(20g)\",\"토마토(150g)\",\"양송이버섯(20g)\",\"양파(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토를 곁들여 나트륨 배출을 돕고, 잡곡을 사용하여 식이섬유의 양을 늘립니다.\",\"instructions\":[\"1. 떡볶이떡은 잘게 다진다.\",\"2. 현미, 흑미, 백미 및 조는 깨끗이 씻어\\n물에 불린다.\",\"3. 소고기와 돼지고기에 소금, 다진 마늘,\\n설탕 및 참기름을 넣고 양념한다\",\"4. 당근과 호박은 잘게 다진다\",\"5. 달걀은 황백으로 나눠 지단을 부친다.\",\"6. 불린 쌀로 밥을 짓고, 밥과 3번과 4번을\\n섞어 미니 떡갈비를 만들어 팬에\\n기름을 두르고 익힌 뒤 황백지단으로\\n장식한다.\"]},{\"id\":\"k478\",\"title\":\"리코타소스 연어샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00590_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00590_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00590_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00590_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00590_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00590_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00590_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(100g)\",\"토마토(100g)\",\"우유(200g)\",\"레몬(1/4개)\",\"파인애플(50g)\",\"아보카도(1/4개)\",\"오이(20g)\",\"오렌지(1/2개)\",\"어린잎(20g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"직접 만든 리코타치즈로 샐러드를 만들어 나트륨 함량을 줄일 수 있어요.\",\"instructions\":[\"1. 연어는 깍둑 썰기한다.\",\"2. 냄비에 우유를 넣고 은근히 끓이다가\\n레몬즙과 소금을 넣고 뭉글거리게\\n한다.\",\"3. 뭉글거리는 우유를 체에 걸러\\n리코타치즈를 만든다\",\"4. 토마토, 아보카도, 오이 및 파인애플은\\n주사위 모양으로 썬다.\",\"5. 어린잎은 찬물에 담궈 싱싱해지면\\n물에서 건져 놓는다\",\"6. 오렌지와 파인애플은 즙을 만들어\\n리코타치즈와 섞어 소스를 만들고,\\n연어와 야채를 담은 뒤 그 위에 소스를\\n올린다.\"]},{\"id\":\"k479\",\"title\":\"망고무스케이크와 마카롱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00591_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00591_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00591_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00591_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00591_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00591_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00591_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀(1개)\",\"아몬드(30g)\",\"레몬(1/4개)\",\"망고퓨레(20g)\",\"버터(20g)\",\"생크림(20g)\",\"우유(50g)\",\"물엿(50g)\",\"소금(0.2g)\",\"설탕(20g)\",\"판젤라틴(1장)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"직접 만든 케이크와 마카롱으로 건강한 후식을 즐길 수 있어요.\",\"instructions\":[\"1. 아몬드는 곱게 갈아 체에 내려\\n준비한다.\",\"2. 달걀흰자로 머랭을 만들어 짤주머니로\\n짜준 후 20분 정도 말리고 오븐에\\n13분간 구워 마카롱을 만든다.\",\"3. 냄비에 설탕, 물엿, 소금을 넣고\\n끓인다.\",\"4. 달걀노른자, 설탕, 우유 및 생크림을\\n끓이다가 망고퓨레를 넣고 섞는다\",\"5. 판젤라틴은 물에 불려 중탕으로 녹여\\n4에 섞고, 차갑게 휘핑한 생크림을\\n넣는다.\",\"6. 5를 틀에 굳힌 후, 접시에 담고\\n마카롱으로 장식한다.\"]},{\"id\":\"k480\",\"title\":\"망고자몽드레싱 해산물전체\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00592_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00592_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00592_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00592_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00592_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00592_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00592_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"관자(2개)\",\"새우(4마리)\",\"방울토마토(2개)\",\"생크림(50g)\",\"파슬리(5g)\",\"당근(30g)\",\"오이(50g)\",\"단호박(1/4개)\",\"브로콜리(30g)\",\"감자(50g)\",\"망고(1/2개)\",\"레몬(1/4개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우와 관자가 소금 역할을 하기 때문에 소금을 적게 사용할 수 있어요.\",\"instructions\":[\"1. 감자는 삶아 껍질을 벗긴다\",\"2. 새우와 관자는 끓는 물에 레몬즙을\\n넣고 삶아 건져 껍질을 벗긴다.\",\"3. 오이, 당근, 단호박은 껍질을 벗겨\\n슬라이스 썬다.\",\"4. 데친 관자는 토치로 한 번 더 익혀 썬다\",\"5. 믹서에 간 망고와 레몬에 설탕, 소금을\\n약간 넣고 소스를 만든다.\",\"6. 토마토는 먹기 좋은 크기로 자르고,\\n접시에 준비한 야채와 해산물을 담고,\\n소스는 먹기 직전에 올린다\"]},{\"id\":\"k481\",\"title\":\"머쉬룸 닭스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00593_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00593_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00593_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00593_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00593_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00593_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00593_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(1마리)\",\"당근(20g)\",\"양파(20g)\",\"단호박(1/4개)\",\"미니\",\"양배추(5개)\",\"새송이버섯(1개)\",\"느타리버섯(20g)\",\"버터(10g)\",\"소금(0.3g)\",\"후춧가루(0.02g)\",\"발사믹소스(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"발사믹소스와 버터를 사용하기 때문에 나트륨이 적은 소스를 만들 수 있어요.\",\"instructions\":[\"1. 닭은 살만 발라낸다.\",\"2. 준비한 닭살에 소금, 후춧가루,\\n올리브오일을 발라 마리네이드 한다\",\"3. 양파와 버섯은 입자있게 다진다.\",\"4. 냄비에 버터를 넣고 녹인다.\",\"5. 녹인 버터에 다져 놓은 야채를 볶다가\\n발사믹소스를 넣고 바글바글 끓여\\n소스를 만든다.\",\"6. 팬에 버터와 기름을 넣고 중불에서\\n마리네이드한 닭살을 익혀 스테이크를\\n만들고, 미니양배추를 팬에 굴려가며\\n익혀 접시에 담은 뒤 소스를 올린다\"]},{\"id\":\"k482\",\"title\":\"미역소스와 타르타르\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00594_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00594_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00594_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00594_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00594_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00594_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00594_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"관자(2개)\",\"새우(3마리)\",\"미역(20g)\",\"새송이버섯(1개)\",\"시금치(30g)\",\"토마토(50g)\",\"마늘(10g)\",\"블랙올리브(3알)\",\"메추리알(5개)\",\"레몬(1/4개)\",\"두유(100g)\",\"생크림(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"미역과 새우에서 나오는 천연 감칠맛을 이용했기 때문에 소금을 사용할 필요가 없어요.\",\"instructions\":[\"1. 미역은 찬물에 충분히 불린다.\",\"2. 새우는 껍질을 벗겨 관자 한 개와 다져\\n완자를 만든다.\",\"3. 나머지 관자 한 개는 썰어 팬에 굽는다\",\"4. 버섯, 토마토, 블랙올리브는 곱게\\n다진다.\",\"5. 시금치와 미역은 끓는 물에 데쳐 잘게\\n썬다.\",\"6. 마늘을 다져 우유와 함께 끓이다가\\n썰어 놓은 미역과 시금치, 새우완자를\\n넣고 한소끔 끓인다.\"]},{\"id\":\"k483\",\"title\":\"발사믹소스를 곁들인 오리스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00595_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00595_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00595_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00595_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00595_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00595_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00595_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오리고기(가슴살\",\"120g)\",\"당근(20g)\",\"토마토(100g)\",\"새송이버섯(1개)\",\"표고버섯(1개)\",\"감자(50g)\",\"아스파라거스(2개)\",\"소금(0.2g)\",\"후추(0.01g)\",\"올리브오일(10g)\",\"발사믹소스(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 들어간 다진 토마토가 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 감자는 껍질을 벗겨 슬라이스로 썰어\\n찬물에 담궈 전분을 빼고 건져 물기를\\n제거한다.\",\"2. 토마토, 양파, 새송이버섯. 표고버섯은\\n입자있게 다지고, 당근은 샤또\\n모양으로 썰어 준비한다.\",\"3. 오리 가슴살은 소금, 후춧가루로\\n밑간을 한다.\",\"4. 팬에 올리브오일을 두르고\\n마리네이드한 오리 가슴살을 넣고 구워\\n기름이 빠지면 접시에 담는다.\",\"5. 오리 가슴살을 구운 팬에\\n아스파라거스, 당근, 감자를 구워\\n접시에 담는다.\",\"6. 냄비 또는 팬에 다진 야채를 넣고\\n볶다가 발사믹소스를 넣고 졸여 소스를\\n만들고, 접시에 담아 놓은 오리\\n스테이크에 올린다.\"]},{\"id\":\"k484\",\"title\":\"방울토마토를 곁들인 너비아니구이와 쌈밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00596_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00596_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00596_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00596_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00596_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00596_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00596_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(120g)\",\"흑미(100g)\",\"아스파라거스(3개)\",\"감자(50g)\",\"당근(20g)\",\"사과(1/2개)\",\"양송이버섯(5개)\",\"방울토마토(5개)\",\"깻잎(3장)\",\"배(1/4개)\",\"브로콜리(30g)\",\"마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쌈밥에 토마토와 흑미를 넣고 만들어서 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 감자는 삶아 껍질을 벗긴다.\",\"2. 아스파라거스는 2등분 하고,\\n방울토마토와 함께 끓는 물에 살짝\\n데친다.\",\"3. 닭고기에 소금, 후추, 배즙을 넣고 숙성\\n시킨다.\",\"4. 저염간장에 다진 마늘, 설탕, 후춧가루,\\n참기름을 넣고 양념장을 만들어 3번에\\n묻혀 굽는다\",\"5. 흑미는 충분히 불려 밥을 짓는다\",\"6. 깻잎은 간장, 식초, 설탕에 절여\\n흑미밥과 너비아니 구이를 넣고 돌돌\\n말아 쌈밥을 만든다\"]},{\"id\":\"k485\",\"title\":\"배차와 주악\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00597_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00597_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00597_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00597_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00597_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/597-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00597_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀가루(100g)\",\"밀가루(100g)\",\"막걸리(100g)\",\"배(1/2개)\",\"통후추(20알)\",\"꿀(100g)\",\"생강(20g)\",\"식용꽃(20g)\",\"계피(10g)\",\"설탕(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배차에서 우러나오는 생강과 계피, 통후추가 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 쌀가루와 밀가루를 섞어 체에 내린다.\",\"2. 냄비에 막걸리를 붓고 끓인다\",\"3. 끓인 막걸리를 체 친 쌀가루와\\n밀가루에 섞어 반죽을 만들고 치대어\\n숙성시킨다.\",\"4. 배는 1/8등분으로 썰어 양쪽모서리를\\n돌려 깎아 통후추를 꽂는다.\",\"5. 1을 넓게 펴서 주먹밥을 얹고 감싼다.\",\"6. 숙성시킨 반죽을 둥그렇게 빚어 팬에\\n굽고, 다 익으면 접시에 담은 뒤 꿀을\\n위에 올린다.\"]},{\"id\":\"k486\",\"title\":\"배추관자카나페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00598_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00598_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00598_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00598_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00598_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00598_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00598_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"관자(2개)\",\"배춧잎(6장)\",\"파프리카(1/2개)\",\"레몬(1/2개)\",\"고추장(20g)\",\"매실액(10g)\",\"설탕(20g)\",\"소금(5g)\",\"파슬리(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"관자를 사용해서 만들기 때문에 소금을 넣지 않아도 맛을 느낄 수 있어요.\",\"instructions\":[\"1. 배춧잎을 물에 담궈 싱싱하게 한다\",\"2. 레몬은 슬라이스로 썬다.\",\"3. 레몬, 고추장, 설탕 및 매실액을 넣고\\n양념장을 만든다.\",\"4. 파프리카는 작은 사각형 모양으로\\n자른다.\",\"5. 관자는 끓는 물에 소금을 넣고 데친다.\",\"6. 관자는 프라이팬에 구운 뒤 잘게 썰어\\n파프리카와 섞어 배춧잎에 올리고, 그\\n위에 파슬리와 만들어 놓은 양념장을\\n먹기 직전에 올린다.\"]},{\"id\":\"k487\",\"title\":\"버섯과 두부 비프웰링턴\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00599_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00599_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00599_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00599_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00599_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00599_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00599_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(안심\",\"120g)\",\"두부(50g)\",\"양송이버섯(3개)\",\"양파(30g)\",\"당근(20g)\",\"단호박(1/2개)\",\"가지(1/2개)\",\"감자(50g)\",\"깻잎(3장)\",\"마늘(20g)\",\"버터(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"버터를 사용해서 만들기 때문에 적은양의 소금만 사용할 수 있어요.\",\"instructions\":[\"1. 밀가루에 버터, 달걀을 넣고 골고루\\n반죽한 뒤 비닐봉투에 넣고\\n숙성시킨다.\",\"2. 안심과 두부는 잘게 썬다\",\"3. 단호박은 씨를 제거하고 삶아 다진다\",\"4. 양파, 당근, 마늘은 곱게 다져 안심,\\n두부와 섞고 소금을 약간 넣는다.\",\"5. 야채를 섞은 안심과 두부는 다진\\n단호박을 섞어 깻잎으로 먼저 감싼다.\",\"6. 숙성된 반죽을 밀대로 밀어 5번을 감싼\\n뒤 오븐에 넣고 25분 정도 굽는다.\"]},{\"id\":\"k488\",\"title\":\"복분자소스를 곁들인 닭테린\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00600_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00600_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00600_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00600_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00600_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00600_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00600_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"200g)\",\"시금치(30g)\",\"브로콜리(30g)\",\"토마토(100g)\",\"고구마(100g)\",\"아스파라거스(3개)\",\"복분자(20g)\",\"새송이버섯(1개)\",\"마늘(20g)\",\"치즈(1장)\",\"전분(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치즈에 함유된 짠맛으로 소금을 적게 넣어도 맛이 좋은 음식을 만들 수 있어요.\",\"instructions\":[\"1. 닭가슴살은 곱게 다진다\",\"2. 시금치와 브로콜리는 끓는 물에 데쳐\\n찬물에 헹구고 토마토와 함께 입자있게\\n다져 다진 닭가슴살과 섞는다.\",\"3. 닭가슴살에 치즈를 섞는다.\",\"4. 고구마는 찜통에 넣고 쪄서 체에\\n내린다.\",\"5. 냄비에 물, 복분자, 고구마를 넣고\\n끓인다.\",\"6. 5번에 전분을 넣고 걸죽하게 소스를\\n완성하고, 아스파라거스와 버섯은\\n팬에 구워 쪄낸 닭테린 옆에 담은 뒤\\n소스를 올린다.\"]},{\"id\":\"k489\",\"title\":\"관자버터구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00601_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00601_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00601_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00601_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00601_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00601_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00601_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"관자(2개)\",\"시금치(30g)\",\"비트(20g)\",\"양파(30g)\",\"오이피클(20g)\",\"고추피클(20g)\",\"마요네즈(20g)\",\"꿀(20g)\",\"버터(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오이피클과 고추피클을 이용하여 소금을 사용하지 않고 요리를 만들 수 있어요.\",\"instructions\":[\"1. 양파, 오이피클, 고추피클은 입자있게\\n다진다.\",\"2. 다진 양파와 피클에 마요네즈를 넣고\\n골고루 섞어 소스를 만든다.\",\"3. 마요네즈소스에 꿀을 넣고 섞는다\",\"4. 관자의 앞뒤에 버터를 바른다.\",\"5. 관자에는 버터를 발라 팬에 구워\\n접시에 담는다.\",\"6. 비트, 양파, 데친 시금치를 넣고 갈아서\\n소스를 만들고 관자에 마요네즈소스와\\n시금치소스를 올린다\"]},{\"id\":\"k490\",\"title\":\"세 가지 미니 에피타이저\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00602_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00602_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00602_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00602_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00602_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00602_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00602_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(훈제연어\",\"120g)\",\"새우(3마리)\",\"애호박(1/2개)\",\"사과(1/4개)\",\"오렌지(1/4개)\",\"레몬(1/4개)\",\"석류주스(200g)\",\"판젤라틴(1장)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과, 오렌지, 레몬을 이용하여 나트륨이 적은 상큼한 에피타이저를 만들 수 있어요.\",\"instructions\":[\"1. 훈제 연어는 슬라이스로 썰어서\\n굽는다.\",\"2. 사과는 채썬다.\",\"3. 판젤라티은 찬물에 담궈 불린 후\\n중탕해서 녹인다.\",\"4. 석류주스를 끓인 뒤 중탕한 젤라틴을\\n넣고 굳혀 접시에 담는다.\",\"5. 애호박은 껍질을 벗겨 끓는 물에\\n소금을 넣고 살짝 데치고, 새우는 살짝\\n데쳐 껍질을 벗겨 포를 뜬 뒤 다시\\n굽는다.\",\"6. 석류주스 젤리가 담긴 접시에 새우와\\n애호박을 담고 소스를 올린 뒤 연어와\\n사과, 호박을 올려 담는다.\"]},{\"id\":\"k491\",\"title\":\"식혜양갱과 수박증편\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00603_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00603_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00603_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00603_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00603_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00603_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00603_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"엿기름(100g)\",\"밥(50g)\",\"미숫가루(50g)\",\"막걸리(50g)\",\"대추(3알)\",\"잣(10g)\",\"백년초(30g)\",\"밀가루(20g)\",\"찹쌀가루(200g)\",\"버터(10g)\",\"설탕(100g)\",\"한천(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"미숫가루가 들어간 버터 잼을 곁들여 나트륨을 줄인 맛있는 증편을 만들 수 있어요.\",\"instructions\":[\"1. 엿기름은 물을 넣고 주물럭거린다\",\"2. 엿기름에 맑은 물이 생기면 채에\\n걸러내어 밥을 넣고 3시간 정도 발효를\\n시켜 밥알이 떠오르면 설탕을 넣고\\n끓인다.\",\"3. 한천은 물을 넣고 불린다\",\"4. 식혜에 불린 한천을 넣고 틀에 담아\\n굳힌다.\",\"5. 미숫가루에 밀가루, 버터, 설탕을 섞고\\n살짝 끓여 잼을 만든다.\",\"6. 찹쌀가루에 뜨거운 막걸리와 백년초를\\n넣고 익반죽 후 찜통에 쪄서\\n수박모양의 증편을 만들고 식혜, 양갱,\\n버터 잼과 함께 담는다.\"]},{\"id\":\"k492\",\"title\":\"호박잎다슬기된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102116_1416273676261.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/691-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/691-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/691-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/691-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/691-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/691-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"호박잎은 비벼서 연하게 만든 후 사용한다. - 다슬기를 달걀물에 묻혀 넣으면 달걀이 얇게 입혀 다슬기가 가라앉지 않는다.\",\"instructions\":[\"1. 물 1컵 반에 국멸치와 건다시마를 넣고 멸치다시마국물 1컵을 낸다.\",\"2. 호박잎은 줄기를 꺾으며 잡아당겨 실 같은 껍질을 벗기고 씻는다.\",\"3. 멸치다시마국물 1컵에 된장을 풀고 씻은 다슬기살을 함께 넣어 중불에서 5분정도 국물을 우려낸다.\",\"4. 국물낸 다슬기는 건져 달걀물과 함께 섞는다.\",\"5. 부추는 1cm 가량의 크기로 썰고 대파는 어슷썰기 한다.\",\"6. 국물이 끓어 오르면 호박잎과 부추, 파, 다진 마늘을 넣고 마지막으로 달걀물을 입힌 다슬기를 살포시 넣는다.\"]},{\"id\":\"k493\",\"title\":\"양배추두부찜과 양파케첩소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102117_1416273677432.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/692-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/692-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/692-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/692-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/692-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/692-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양배추의 단단한 잎줄기는 부드러운 잎과 열을 받는 시차가 다르고 음식을 할 때도 모양이 고르게 나지 않으므로 조리하기 전 칼로 굵은 심을 도려내는 것이 좋다.\",\"instructions\":[\"1. 양배추는 씻어 잎을 넓게 뗀 후 7×12cm 가량의 크기로 자른다.\",\"2. 자른 양배추는 김이 오른 찜통에 5분 정도 찐다.\",\"3. 당근, 양파, 표고버섯은 곱게 다지고 두부는 으깨 면보에 짠다\",\"4. 다진 돼지고기에 파, 다진 마늘, 참기름, 설탕, 소금, 후춧가루를 넣고 양념을 한 후 2의 재료와 섞는다.\",\"5. 찐 양배추에 밀가루를 뿌리고 3의 재료를 놓고 돌돌 감아 찜통에 찐다.\",\"6. 소스는 다진 양파와 마늘을 먼저 볶아 향을 낸 후 토마토케첩, 간장, 매실액을 넣어 만든다.\"]},{\"id\":\"k494\",\"title\":\"수박비빔국수와 수박고추장소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102118_1416273678307.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/693-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/693-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/693-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/693-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/693-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/693-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다슬기살 20g\",\"호박잎 20g\",\"부추 15g\",\"달걀 15g\",\"물 300g\",\"된장 8g\",\"국멸치 5g\",\"건다시마 2.5g\",\"파 5g\",\"다진 마늘 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수박물로 고추장양념의 농도를 조절한다.\",\"instructions\":[\"1. 당근, 적채, 깻잎, 양배추는 씻어 4~5cm 가량으로 채 썬다.\",\"2. 수박의 과육과 흰부분의 껍질은 4~5cm 가량으로 채 썬다.\",\"3. 소면은 끓는 물에 넣고 끓어오르면 소량의 찬물을 붓고 다시 한 번 끓이고 속까지 익으면 재빨리 찬물에 헹구어 채반에 건진다.\",\"4. 달걀은 황백지단을 부쳐 채 썬다.\",\"5. 수박과 양파를 강판에 갈고 고추장, 고춧가루, 참기름, 다진 파, 다진 마늘, 식초, 매실액, 통깨를 넣어 수박고추장양념소스를 만든다.\",\"6. 소면에 수박고추장양념소스를 넣어 비비고 지단을 올린다.\"]},{\"id\":\"k495\",\"title\":\"미숫가루 부추전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102120_1416273680405.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/694-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/694-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/694-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/694-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/694-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/694-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"부침가루 30g\",\"미숫가루 10g\",\"오징어 20g\",\"부추 20g\",\"감자 15g\",\"당근 5g\",\"양파 5g\",\"현미유 4g\",\"소금 0.5g\",\"물 60g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"미숫가루를 많이 넣으면 미숫가루부추전의 질감이 거칠다.\",\"instructions\":[\"1. 오징어는 내장을 제거하고 깨끗하고 씻어낸다.\",\"2. 부추, 감자, 당근, 양파는 2cm 가량으로 곱게 채 썬다.\",\"3. 부침가루와 미숫가루를 3 : 1의 비율로 섞는다.\",\"4.  1, 2, 3에 물을 넣어 반죽하고 소금으로 간을 한다.\",\"5. 팬에 현미유를 두르고 3의 반죽을 둥글게 떠 넣어 노릇노릇하게 지진다.\",\"6. 그릇에 담아 완성한다.\"]},{\"id\":\"k496\",\"title\":\"애호박장떡말이밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102121_1416273681545.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/695-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/695-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/695-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/695-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/695-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/695-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 100g\",\"애호박 25g\",\"양파 10g\",\"풋고추 5g\",\"고추장 15g\",\"우리밀가루 50g\",\"물 50g\",\"현미유 1.5g\",\"흑임자 1g\",\"참기름 1g\",\"소금 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"애호박장떡을 얇게 부쳐야 잘 말린다.\",\"instructions\":[\"1. 양파는 갈고 애호박과 풋고추는 잘게 다진다.\",\"2. 물 1/2컵에 고추장을 풀고 우리밀가루를 넣어 골고루 섞는다.\",\"3. 1의 재료를 2에 넣어 반죽한다.\",\"4. 팬에 현미유를 두르고 3의 재료를 얇게 부친다.\",\"5. 밥에 참기름과 흑임자, 소금을 넣고 양념을 한다.\",\"6. 애호박장떡에 양념한 밥을 얇게 펴놓고 돌돌 말아 2~3cm 가량의 길이로 자른다.\"]},{\"id\":\"k497\",\"title\":\"봄나물주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102124_1416273684105.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/696-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/696-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/696-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/696-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/696-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/696-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 70g\",\"취나물 20g\",\"고사리 20g\",\"빨강파프리카 5g\",\"노랑파프리카 5g\",\"참기름 3g\",\"다진 마늘 1g\",\"소금 0.7g\",\"통깨 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"주먹밥 안에 매실장아찌, 멸치 다진 것, 명란젓 다진 것 등을 넣어도 좋다\",\"instructions\":[\"1. 쌀은 불린 후 밥을 짓는다.\",\"2. 고사리는 끓는 물에 삶고, 잘게 썬 파프리카는 고사리 삶는 물에 살짝 데친다.\",\"3. 고사리 삶는 중간에 취나물을 넣어 함께 데친다.\",\"4. 고사리와 취나물은 잘게 썬다 .\",\"5. 파프리카, 고사리, 취나물에 참기름, 마늘, 소금, 통깨를 넣고 양념을 한다.\",\"6. 밥에 참기름, 통깨, 소금을 넣어 양념한 후 4의 재료를 섞어 주먹밥을 만든다.\"]},{\"id\":\"k498\",\"title\":\"달래두부김치무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102129_1416273689039.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/698-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/698-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/698-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/698-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/698-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/698-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 40g\",\"달래 10g\",\"배추김치 20g\",\"홍피망 2g\",\"다진 파 2.5g\",\"다진 마늘 2.5g\",\"설탕 1g\",\"참기름 1g\",\"통깨 0.5g\",\"고춧가루 0.5g\",\"소금 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배추김치는 줄기부분을 사용하고 간이 있으므로 두부에 소금 간을 하지 않는다 무장아찌를 채 썰어 같이 무쳐도 좋다\",\"instructions\":[\"1. 두부는 5cm× 1.5cm× 1cm 크기로 썬다.\",\"2. 썰어논 두부는 기름을 두르지 않고 팬에 노릇노릇 굽는다 .\",\"3. 달래는 2cm 가량의 크기로 썬다 .\",\"4. 배추김치는 물기를 적당히 짜고 2cm 가량으로 가늘게 채썬다 .\",\"5. 홍피망은 2cm 가량으로 가늘게 채썰고 3, 4와 파, 마늘, 설탕, 참기름, 통깨, 고춧가루, 소금을 넣고 조물조물 무친다.\",\"6. 두부위에 5의 김치달래무침을 곁들인다.\"]},{\"id\":\"k499\",\"title\":\"딸기소스닭가슴살채소무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102130_1416273690444.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/699-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/699-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/699-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/699-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/699-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/699-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 50g\",\"방울토마토 20g\",\"양상추 15g\",\"브로콜리 10g\",\"적채 5g\",\"노랑 파프리카 3g\",\"빨강 파프리카 3g\",\"호상요구르트 50g\",\"딸기 40g\",\"호두 2g\",\"소금 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오리엔탈드레싱 등 여러 가지 드레싱을 입맛에 맞게 이용해도 좋다\",\"instructions\":[\"1. 닭가슴살을 삶는 뜨거운 물에 데친다.\",\"2. 닭가슴살 데친물에 브로콜리도 살짝 데친다.\",\"3. 닭가슴살은 고기결을 따라 잘게 찢는다.\",\"4. 양상추는 손으로 잘게 찢고 적채, 파프리카는 2cm가량으로 채 썰고 방울토마토는 반으로 자른다.\",\"5. 딸기를 강판에 갈아 호상요구르트와 호두, 소금을 넣어 드레싱을 만든다.\",\"6. 2, 3의 재료를 접시에 담아 딸기드레싱과 곁들인다.\"]},{\"id\":\"k500\",\"title\":\"쑥호두달걀말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101930_1416273570778.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/700-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/700-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/700-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/700-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/700-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/700-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 50g\",\"쑥 3g\",\"당근 3g\",\"호두 2g\",\"현미유 1g\",\"소금 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쑥을 많이 넣으면 쓴맛이 강해 어린이들이 싫어할 수 있다\",\"instructions\":[\"1. 쑥을 잘게 썬다.\",\"2. 당근을 잘게 다진다.\",\"3. 호두를 칼로 부순다.\",\"4. 달걀을 그릇에 깨뜨려 넣고 소금을 넣어 섞은 후 1,2,3의 재료를 섞는다 .\",\"5. 달군 팬에 기름을 두르고 달걀물을 부어 반숙이 되면 말아서 두툼하게 만든 뒤 약한 불에서 아래, 위, 양옆으로 뒤집어가며 속까지 익힌다 .\",\"6. 한입 크기로 썰어 그릇에 담는다.\"]},{\"id\":\"k501\",\"title\":\"시래기리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101931_1416273571933.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/701-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/701-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/701-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/701-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/701-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/701-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"무청시래기 불린 것 50g\",\"밥 180g\",\"된장 18g\",\"다진 마늘 2.5g\",\"생강즙 1.25g\",\"포도씨유\",\"12g\",\"생크림 30g\",\"버터 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생크림 대신 우유를 넣어도 맛있다. - 찬밥과 먹다 남은 시래기나물을 활용하면 시간과 연료를 절약할 수 있다.\",\"instructions\":[\"1. 무청을 찬물에 담궈 잡냄새를 제거한다.\",\"2. 무청의 물기를 짠다.\",\"3.  물기를 뺀 무청은 적당한 크기로 송송 썰어준다.\",\"4. 무청에 된장, 다진 마늘, 생강즙을 넣어 조물조물 무친다.\",\"5. 팬에 포도씨유를 두르고 양념한 무청을 넣고 볶는다.\",\"6. 밥을 넣고 함께 볶다가 생크림과 버터를 넣고 맛이 어우러지도록 잠시 더 볶아 완성한다.\"]},{\"id\":\"k502\",\"title\":\"생과일과가자미까나페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101933_1416273573588.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/703-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/703-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/703-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/703-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/703-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/703-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"식빵 40g\",\"딸기 30g\",\"참다래 30g\",\"가자미살 20g\",\"크래커 15g\",\"마요네즈 9g\",\"양파 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크래커가 없을 때 치즈를 이용하고, 식빵대신 모닝빵을 이용해도 좋다 식빵 테두리 자른 빵은 냉동실에 놓고 빵가루로 사용해도 좋다 식빵위에 잼을 바르고 재료를 얹어도 좋다\",\"instructions\":[\"1. 가자미를 찜통에 찐다 .\",\"2. 양파를 곱게 다진다.\",\"3. 가자미살을 발라내고 양파 다진 것과 마요네즈와 섞는다.\",\"4. 딸기와 참다래는 먹기 좋은 크기로 자른다.\",\"5. 식빵은 동그란 틀로 찍는다.\",\"6. 식빵위에 2의 재료를 바르고 크래커를 올린 뒤 2의 재료를 다시 바르고 참다래를, 딸기를 올린다.\"]},{\"id\":\"k503\",\"title\":\"꽃게살국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101934_1416273574399.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/704-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/704-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/704-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/704-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/704-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/704-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"꽃게 70g(꽃게살 30g)\",\"양배추 20g\",\"토마토 20g\",\"된장 6g\",\"파 5g\",\"건다시마 3g\",\"다진 마늘 2.5g\",\"물 200g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"꽃게는 껍질을 솔로 문질러 닦고 등딱지와 아가미를 떼어낸 다음 몸통을 토막낸다. - 된장국의 국물양을 120~150g 으로 줄여서 1인분량으로 제공하면 나트륨섭취를 줄일 수 있다.\",\"instructions\":[\"1. 꽃게는 손질하여 먹기 좋은 크기로 자른다.\",\"2. 물 1컵에 건다시마와 꽃게를 넣고 끓여 육수 ⅔컵을 만든다.\",\"3. 양배추와 토마토는 씻어 1cm×1cm 크기로 썬다.\",\"4. 파는 씻어 어슷썰기 한다.\",\"5. 육수 낸 꽃게는 건져 살을 발라낸다.\",\"6. 육수에 된장을 풀고 양배추와 토마토를 넣고 한소끔 끓인 후 발라놓은 꽃게 살과 파, 다진 마늘을 넣어 완성한다.\"]},{\"id\":\"k504\",\"title\":\"우엉들깨무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044205_1678174925034.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044344_1678175024096.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044402_1678175042667.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044416_1678175056640.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044431_1678175071847.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044446_1678175086045.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044503_1678175103723.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 우엉(25g)\",\"파(2g)\",\"물(300g)\",\"•양념 : 들깻가루(2g)\",\"다진마늘(2g)\",\"들기름(1g)\",\"간장(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•들깨의 고소한 맛을 활용하여 나트륨 함량을 낮췄어요.\\n•같은 용량 대비 소금보다 간장의 나트름 함량이 낮아서 소금 대신 간장을 소량 사용하면 나트륨 함량을 낮출 수 있어요.\",\"instructions\":[\"1. 우엉은 껍질을 벗긴다.\",\"2. 껍질을 벗긴 우엉은 4cm 길이로 가늘게 채 썬다.\",\"3. 냄비에 물과 우엉을 넣어 3~5분간 삶는다.\",\"4. 삶은 우엉을 체에 건진다.\",\"5. 파를 어슷 썬다.\",\"6. 삶은 우엉, 손질한 파, 양념 재료를 넣고 골고루 무쳐 마무리한다.\"]},{\"id\":\"k505\",\"title\":\"새우두부만두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101937_1416273577460.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/706-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/706-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/706-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/706-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/706-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/706-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"칵테일 새우 50g\",\"두부 80g\",\"부추 10g\",\"표고버섯\",\"8g\",\"소금 1g\",\"후추 0.25g\",\"만두피 75g\",\"간장 1.5g\",\"식초 0.75g\",\"물 5g\",\"고춧가루 0.4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우를 다질 때 칼로 다지면 씹히는 맛이 살아 있어 식감이 좋다. - 먹다 남은 배추김치를 다져 넣어도 맛있다.\",\"instructions\":[\"1. 칼등으로 두부를 으깨 면보에 싸서 물기를 짜낸다.\",\"2. 새우, 부추, 표고버섯은 잘게 다진다.\",\"3. 두부에 다진 새우, 부추, 표고버섯, 소금, 후추를 넣어 소를 만든다.\",\"4. 만두피에 소를 10g씩을 올리고 새우 꼬리를 밖으로 나오게 넣고 오므린다.\",\"5. 찜기에 젖은 면보를 깔고 만두를 넣어 7분 간 찐다.\",\"6.  양념장과 함께 곁들여 낸다.\"]},{\"id\":\"k506\",\"title\":\"마마무스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00455_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00455_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00455_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00455_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00455_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00455_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00455_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"무(50g)\",\"마(50g)\",\"우유(50g)\",\"생크림(20g)\",\"시금치(30g)\",\"대파(10g)\",\"양파(20g)\",\"육수(50g)\",\"소금( 0.2g)\",\"버터(10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시금치, 마 등을 고소한 우유와 생크림과 함께 갈아서 소금없이도 고소하고 영양가 있는 스프를 만들었어요\",\"instructions\":[\"1. 양파와 파는 다져 준비한다.\",\"2. 무는 채를 썰어 놓는다.\",\"3. 시금치는 끓는 물에 소금을 넣고 데쳐,\\n우유와 함께 갈아 준비한다.\",\"4. 마는 강판에 갈아 시금치 우유(③)에\\n섞는다.\",\"5. 다져 놓은 양파와 파는 냄비에 버터를\\n넣고 볶는다.\",\"6. 볶아지는 채소(⑤)에 무(②)와 육수를\\n붓고 끓여서 무가 익으면 충분히 식힌\\n뒤, 준비한 우유(④)와 함께 믹서에\\n갈고, 생크림을 올려 완성한다.\"]},{\"id\":\"k507\",\"title\":\"단호박리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00456_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00456_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00456_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00456_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00456_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00456_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00456_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"현미(100g)\",\"단호박(100g)\",\"양송이버섯(20g)\",\"양파(20g)\",\"버터(20g)\",\"우유(30g)\",\"설탕(10g)\",\"단호박가루(20g)\",\"생크림(20g)\",\"요거트(10g)\",\"- 곁들임 : 캐슈넛(20g)\",\"아몬드(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박과 견과류가 함께 어우러져 만든 리조또는 나트륨을 감소시킨다.\",\"instructions\":[\"1. 현미쌀은 깨끗이 씻어 약 30분 이상\\n충분히 불린다.\",\"2. 단호박은 껍질을 벗겨 먹기 좋게 썰어\\n불린 현미 쌀과 함께 밥을 짓는다.\",\"3. 양송이와 양파는 다져, 냄비에 볶다가\\n우유와 설탕, 호박가루를 넣는다.\",\"4. 끓고 있는 냄비에 단호박 현미밥(②)을\\n넣고 끓인다.\",\"5. 밥이 어느 정도 어우러지면, 생크림과\\n요거트를 섞어 한 번 더 젓는다.\",\"6. 만들어진 리조또(⑤) 위에 캐슈넛과\\n아몬드, 어린잎 채소를 올려 함께\\n완성한다.\"]},{\"id\":\"k508\",\"title\":\"토마토떡볶이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00457_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00457_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00457_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00457_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00457_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00457_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00457_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"떡볶이떡(100g)\",\"어묵(20g)\",\"양파(20g)\",\"당근(20g)\",\"표고버섯(20g)\",\"양배추(20g)\",\"대파(20g)\",\"육수(100g)\",\"- 소스 : 고추장(20g)\",\"케첩(20g)\",\"올리고당(20g)\",\"다진마늘(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토와 사과를 이용하여 나트륨을 줄이고, 매운맛도 많이 줄여 누구나 즐겨 먹을 수 있게 만들었어요.\",\"instructions\":[\"1. 떡볶이는 뜨거운 물에 담그어 놓는다.\",\"2. 토마토, 사과는 입자 있게 다진다.\",\"3. 떡볶이떡은 뜨거운 물에 담그어\\n놓는다.\",\"4. 고추장과 케첩, 올리고당, 다진 마늘을\\n골고루 섞는다.\",\"5. 냄비에 버터를 녹인 뒤 토마토와 사과\\n(②), 소스(④)를 넣고 볶아준다.\",\"6. 볶고 있는 소스(⑤)에 떡볶이 떡(①)과\\n썰어놓은 채소와 어묵(③)을 넣고,\\n육수를 부어 끓이다가 대파를 넣고\\n한 번 더 끓여 완성한다.\"]},{\"id\":\"k509\",\"title\":\"소고기채소볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00458_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00458_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00458_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00458_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00458_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00458_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00458_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기등심(150g)\",\"소금(0.3g)\",\"후춧가루(0.3g)\",\"올리브오일(10g)\",\"브로컬리(30g)\",\"양파(20g)\",\"당근(20g)\",\"토마토(30g)\",\"파프리카(30g)\",\"식용유(10g)\",\"- 소스 : 포도주스(50g)\",\"올리고당(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"포도주스와 칠리소스를 이용하여 만든 소스에는 별도의 소금을 첨가하지 않기 때문에 나트륨을 감소시킬 수가 있어요.\",\"instructions\":[\"1. 소고기는 깍뚝썰어 준비한다.\",\"2. 깍뚝썰은 소고기에 소금, 후추, 올리브\\n오일을 넣어 숙성시킨다.\",\"3. 브로컬리는 살짝 데쳐 썰고 ,양파,\\n당근, 토마토, 파프리카도 같은 크기로\\n썰어 준비한다.\",\"4. 포도주스에 올리고당과 칠리소스 넣어\\n은근히 졸여 소스를 만들어 놓는다.\",\"5. 팬에 식용유를 두르고 채소를 먼저\\n볶는다.\",\"6. 채소를 볶은 팬에 다시 숙성된 소고기를\\n익히고, 볶아놓은 채소를 넣고 소스를\\n넣어 살짝 더 졸여 완성한다.\"]},{\"id\":\"k510\",\"title\":\"양송이크림볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00459_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00459_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00459_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00459_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00459_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00459_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00459_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기살(50g)\",\"양송이(60g)\",\"떡볶이떡(20g)\",\"양파(20g)\",\"당근(30g)\",\"소금(0.2g)\",\"버터(10g)\",\"밥(100g)\",\"육수(50g)\",\"우유(50g)\",\"생크림(10g)\",\"치즈(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"우유와 생크림치즈를 사용하여 소금간을 대체하였어요.\",\"instructions\":[\"1. 닭살은 삶아 입자있게 썰고, 양송이도\\n껍질을 벗겨 입자있게 썰어 준비한다.\",\"2. 떡볶이떡과 양파도 입자있게 썰어\\n놓는다.\",\"3. 당근은 소금을 넣고 삶아 꼬마 당근을\\n만들어 장식을 준비한다.\",\"4. 냄비에 버터를 두르고 양파를 먼저\\n볶는다.\",\"5. 볶아지는 냄비에 닭살과 떡볶이떡,\\n양파를 넣어 다시 볶는다.\",\"6. ⑤번에 밥을 넣고 육수와 우유, 생크림을\\n넣어 볶으면서 치즈를 넣고 한 번 더 고실\\n하게 볶아 완성하고 삶은 당근은 꼬마\\n당근을 만들어 장식으로 올려 준다.\"]},{\"id\":\"k511\",\"title\":\"해물우동볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00460_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00460_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00460_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00460_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00460_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00460_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00460_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(20g)\",\"오징어(20g)\",\"조개살(20g)\",\"양배추(20g)\",\"파프리카(20g)\",\"청경채(20g)\",\"당근(20g)\",\"양파(20g)\",\"저염버터(10g)\",\"우동(100g)\",\"굴소스(20g)\",\"칠리소스(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해산물로 간을 하여 추가 간을 해주지 않아도 음식에 맛과 풍미를 주었어요.\",\"instructions\":[\"1. 새우는 내장을 제거하고, 오징어는\\n껍질을 벗겨 안쪽으로 칼집을 넣은 뒤\\n준비한 새우, 오징어, 조개살을 살짝\\n데친다.\",\"2. 양배추와 파프리카를 길쭉하게 썰고\\n당근, 양파는 채를 썰어 준비한다.\",\"3. 굴소스와 칠리소스를 섞어 소스를\\n만들어 놓는다.\",\"4. 우동은 끓는 물에 한 번 데쳐 준비한다.\",\"5. 팬에 버터를 둘러 해물을 먼저 볶다가\\n만들어 놓은 소스를 넣는다.\",\"6. 5번에 채소를 넣어 살짝 볶다가 데친\\n우동을 넣고 한 번 더 볶은 후 접시에\\n담고 그 위에 가쯔오부시를 올려\\n완성한다.\"]},{\"id\":\"k512\",\"title\":\"단호박닭꼬치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00461_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00461_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00461_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00461_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00461_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00461_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00461_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭다리살(120g)\",\"우유(20g)\",\"소금(0.3g)\",\"후춧가루(0.05g)\",\"떡볶이떡(30g)\",\"단호박(50g)\",\"양파(20g)\",\"대파(20g)\",\"꼬치(3개)\",\"- 소스 : 고추장(20g)\",\"다진마늘(20g)\",\"다진양파(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"꼬치 소스에 마늘, 양파, 올리고당 등을 넣어 나트륨 함량은 낮추고 새콤달콤한 맛을 살렸어요.\",\"instructions\":[\"1. 닭다리살은 뼈를 발라 일정 크기로\\n자른 뒤 우유에 재워둔다.\",\"2. 재워둔 닭다리살에 소금과 후춧가루를\\n뿌려놓는다.\",\"3. 단호박은 속을 파서 잘라 삶아\\n준비한다.\",\"4. 떡볶이떡은 뜨거운 물에 살짝 불리고,\\n대파는 단호박 크기로 잘라 준비한다.\",\"5. 고추장과 다진마늘, 다진양파, 케첩,\\n올리고당을 넣고, 골고루 섞어 양념장을\\n만들어 놓는다.\",\"6. 꼬치에 준비한 닭다리살과 단호박, 양파,\\n떡볶이떡, 대파를 꽂아 은근히 초벌로\\n굽고, 다시 만들어 놓은 양념장을 발라\\n구워 완성한다.\"]},{\"id\":\"k513\",\"title\":\"떡갈비콩나물밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00462_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00462_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00462_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00462_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00462_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00462_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00462_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(100g)\",\"콩나물(100g)\",\"표고버섯(20g)\",\"브로컬리(20g)\",\"- 김치떡갈비 : 다진 소고기(50g)\",\"배(10g)\",\"맛술(10g)\",\"설탕(10g)\",\"저염간장(10g)\",\"대파(10g)\",\"마늘(10g)\",\"참기름(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치를 충분히 헹구고 사용하여 나트륨을 많이 줄여 주었어요.\",\"instructions\":[\"1. 콩나물은 꼬리를 떼어 준비한다.\",\"2. 표고버섯을 길이로 썰고 떡은 입자있게\\n다져 놓고 배는 갈아놓는다.\",\"3. 김치 물에 충분히 씻어 물기를 제거하고\\n송송 썰어 준비한다.\",\"4. 냄비에 불린 쌀과 콩나물, 표고버섯을\\n넣고 밥을 짓는다.\",\"5. 다진 소고기에 간장과 갈아놓은 배,\\n맛술, 파, 마늘, 참기름, 통깨로 양념을\\n하여 30분 이상 재워둔 뒤 썰어 놓은\\n김치, 다진 떡을 넣고 골고루 치대어\\n섞는다.\",\"6. 팬에 기름을 넣고 따끈해지면 떡갈비\\n(⑤)를 넣어 익힌 후, 콩나물밥(④)\\n위에 올리고, 브로컬리는 살짝 데쳐\\n장식으로 올려 완성한다.\"]},{\"id\":\"k514\",\"title\":\"크림치즈떡볶이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00463_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00463_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00463_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00463_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00463_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00463_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00463_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"떡볶이떡(100g)\",\"펜네(20g)\",\"양파(20g)\",\"버터(10g)\",\"밀가루(10g)\",\"육수(100g)\",\"생크림(20g)\",\"우유(50g)\",\"모짜렐라치즈(30g)\",\"파슬리가루(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치즈를 사용하여 소금간 없이 맛을 냈어요.\",\"instructions\":[\"1. 펜네는 10분정도 삶아 데치고, 떡볶이\\n떡은 뜨거운 물에 살짝 불려 놓는다.\",\"2. 양파는 채를 썰어 준비한다.\",\"3. 냄비에 버터를 넣고 밀가루를 넣어\\n볶는다.\",\"4. 볶아지는 밀가루에 준비한 육수를\\n넣는다.\",\"5. 육수가 은근히 끓으면 우유와 생크림\\n넣어준다.\",\"6. 끓고 있는 냄비에 떡볶이떡, 삶은 펜네와\\n양파를 넣어 끓인 후 모짜렐라치즈를\\n넣고 치즈가 녹으면 파슬리가루를\\n살짝 뿌려 완성한다.\"]},{\"id\":\"k515\",\"title\":\"목살스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00464_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00464_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00464_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00464_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00464_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00464_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00464_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지목살(120g)\",\"생강(5g)\",\"로즈마리(2g)\",\"소금(0.3g)\",\"후춧가루(0.1g)\",\"칠리소스(20g)\",\"케첩(20g)\",\"포도주스(100g)\",\"양파(20g)\",\"마늘(10g)\",\"버터(10g)\",\"브로컬리(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스를 넣어 졸여 만든 목살 스테이크는 별도의 소금간이 필요 없기 때문에 나트륨을 감소시켜 만들 수 있어요.\",\"instructions\":[\"1. 돼지목살에 생강즙과 로즈마리, 소금,\\n후춧가루를 뿌려 숙성시킨다.\",\"2. 양파와 마늘, 샐러리는 입자있게\\n다진다.\",\"3. 칠리소스와 케첩, 포도주스를 섞는다.\",\"4. 브로컬리는 살짝 데쳐, 작게 썰고,\\n당근과 적채 채를 썰어 준비한다.\",\"5. 냄비에 버터를 넣고, 양파와 마늘을\\n넣어 볶는다.\",\"6. 볶은 냄비(⑤)에 샐러리를 넣고 포도\\n주스(③)와 채소(④)를 넣고 자작하게\\n졸인 후 팬에 버터를 살짝 바르고, 팬이\\n따끈해 지면 숙성한 목살을 넣어 익힌다.\\n목살이 익혀지면, 자작하게 졸인 소스에\\n넣어 다시 한 번 더 졸여 완성한다.\"]},{\"id\":\"k516\",\"title\":\"치킨완자스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00465_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00465_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00465_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00465_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00465_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00465_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00465_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"버터(20g)\",\"밀가루(20g)\",\"육수(100g)\",\"생크림(20g)\",\"브로컬리(30g)\",\"우유(100g)\",\"닭고기살(100g)\",\"대추(20g)\",\"표고버섯(20g)\",\"당근(20g)\",\"마늘(10g)\",\"양파(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다진 채소를 넣은 완자와 크림소스가 더해져 고소하고 맛있는 스프를 만들었어요.\",\"instructions\":[\"1. 닭고기살은 곱게 다져 준비한다.\",\"2. 대추는 씨를 빼고 다진다.\",\"3. 당근과 양파, 표고버섯, 마늘은 다진다.\",\"4. 삶은 브로컬리는 우유와 함께 갈아\\n놓는다.\",\"5. 닭고기살에 대추(②)와 채소(③), 소금,\\n후춧가루, 참기름을 넣어 골고루 섞는다.\",\"6. 섞여진 닭고기살(⑤)을 동글동글 하게\\n완자를 지어 살짝 데쳐내고, 냄비에\\n버터와 밀가루를 넣어 볶다가, 육수를\\n넣고 끓인 뒤 우유와 브로컬리 갈은 것\\n(④)과 생크림을 넣어 한 소큼 끓여 완성\\n한다.\"]},{\"id\":\"k517\",\"title\":\"돼지고기말이튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00466_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00466_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00466_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00466_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00466_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00466_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00466_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심(100g)\",\"소금(0.3g)\",\"후춧가루(0.02g)\",\"깻잎(10g)\",\"당근(20g)\",\"청피망(20g)\",\"양파(20g)\",\"치즈(30g)\",\"밀가루(20g)\",\"달걀(50g)\",\"빵가루(20g)\",\"튀김기름(400g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"마요네즈 소스에 두부를 으깨어 넣기 때문에 나트륨 함량을 낮출 수 있었어요.\",\"instructions\":[\"1. 돼지고기등심은 자근자근 두들겨\\n소금과 후추를 뿌려 숙성시킨다.\",\"2. 깻잎, 당근, 피망, 양파는 채를 썰어\\n준비한다.\",\"3. 숙성된 돼지고기(①)에 썰어놓은 채소\\n(②)와 치즈를 넣어 말아준다.\",\"4. 마요네즈에 두부를 으깨어 넣고\\n생크림과 요구르트, 설탕, 머스터드를\\n넣어 골고루 섞어준다.\",\"5. 어린잎은 찬물에 잠시 담그어 놓았다가\\n채에 건져 물기를 제거한다.\",\"6. 말아놓은 등심에 밀가루, 달걀물,\\n빵가루 순서로 입혀 튀김기름\\n170~180℃의 온도에 약 3분 정도\\n튀겨 기름을 빼 놓고, 튀김소스(④)와\\n어린잎(⑤)을 접시에 담아 완성한다.\"]},{\"id\":\"k518\",\"title\":\"단호박피자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00467_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00467_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00467_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00467_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00467_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00467_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00467_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다진 소고기(20g)\",\"다진 마늘(10g)\",\"소금(0.2g)\",\"후춧가루(0.02g)\",\"맛술(10g)\",\"미니단호박(120g)\",\"생크림(20g)\",\"양송이(20g)\",\"양파(20g)\",\"당근(20g)\",\"청피망(20g)\",\"파프리카(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"호박을 도우로 이용하여 영양가는 높이고 나트륨 함량은 줄일 수 있어요\",\"instructions\":[\"1. 다진 소고기에 다진마늘, 소금,\\n후춧가루, 맛술을 넣고 잘 섞어\\n숙성을 시킨다.\",\"2. 미니 단호박을 반으로 잘라 속을 파낸\\n뒤 약 15분 정도 쪄서 호박 속을 긁는다.\",\"3. 긁어 놓은 호박 속에 생크림을 넣어\\n골고루 섞는다.\",\"4. 양송이와 양파, 당근, 베이컨, 햄은\\n사각지게 썰고, 피망과 파프리카는\\n속을 제거하고 사각지게 썰어 놓는다.\",\"5. 재워놓은 소고기(①)와 베이컨, 햄을\\n올리브기름에 볶다가 썰어 놓은 채소를\\n넣어 함께 볶아 준비한다.\",\"6. 속 파낸 단호박(②)에 준비해둔 호박속\\n(③)과 볶아놓은 햄과 채소(⑤)를 담고,\\n모짜렐라치즈를 올려 오븐에 약 5분\\n정도 구운 뒤 파슬리가루를 살짝 뿌려\\n완성한다.\"]},{\"id\":\"k519\",\"title\":\"L..A갈비구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00468_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00468_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00468_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00468_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00468_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00468_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00468_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"L.A갈비(200g)\",\"배(20g)\",\"양파(20g)\",\"- 양념 : 저염간장(20g)\",\"월계수잎(5g)\",\"통후추(5g)\",\"올리고당(20g)\",\"정종(10g)\",\"설탕(10g)\",\"매실액(10g)\",\"대파 다진것(20g)\",\"다진 마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"월계수잎과 통후추 등을 사용해 깊은 맛을 내주어 소금을 사용하지 않아도 깊은 맛이 나는 갈비를 만들었어요.\",\"instructions\":[\"1. L.A 갈비는 물에 담그어 핏물과 갈비\\n톱밥을 제거시켜 놓는다.\",\"2. 강판에 배와 양파를 곱게 갈아 준비\\n한다.\",\"3. 핏물을 제거한 갈비에 배즙과 양파즙을\\n넣어 숙성시킨다.\",\"4. 냄비에 저염간장과 월계수잎, 통후추,\\n올리고당, 정종, 설탕, 물, 매실액을\\n넣어 은근히 약 30분 정도 끓여 식힌다.\",\"5. 끓여 식힌 간장에 파, 마늘, 참기름,\\n통깨를 넣는다.\",\"6. 숙성시킨 L.A 갈비에 만들어 놓은\\n양념을 넣고 다시 하루 정도 더 숙성\\n후 팬에 구워 완성한다.\"]},{\"id\":\"k520\",\"title\":\"닭고기파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00469_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00469_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00469_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00469_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00469_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00469_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00469_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"마늘(20g)\",\"양파(20g)\",\"양송이버섯(30g)\",\"버터(10g)\",\"스파게티(70g)\",\"올리브오일(5g)\",\"모짜렐라치즈(20g)\",\"- 닭가슴살 : 닭살(100g)\",\"소금(0.2g)\",\"후춧가루(0.02g)\",\"밀가루(20g)\",\"- 소스 : 토마토(40g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 생토마토를 넣어 나트륨 함량을 낮출 수 있었어요.\",\"instructions\":[\"1. 닭살을 깎뚝 썰어 소금, 후춧가루,\\n밀가루 넣어 살살 털어 준비해 놓는다.\",\"2. 마늘과 토마토, 양파는 입자있게 다져\\n놓는다.\",\"3. 양송이는 껍질을 벗겨 다져 준비한다.\",\"4. 냄비에 버터 넣고, 다진 마늘과 양파를\\n볶는다.\",\"5. 볶아지는 냄비에 밀가루 뭍힌 닭살을\\n넣어 살짝 볶는다.\",\"6. ⑤번에 양송이와 다진 토마토, 토마토\\n소스, 올리고당, 굴소스를 넣고 살짝\\n볶다가 육수를 넣어 끓인 후 다시 우유를\\n넣고 은근히 끓이고, 스파게티는 약\\n10분 정도 삶아 건져 접시에 담아, 끓인\\n소스를 붓고, 위에 모짜렐라치즈를 올려\\n오븐에 약 5분 정도 구어 완성한다.\"]},{\"id\":\"k521\",\"title\":\"동글동글도넛\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00619_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00619_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00619_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00619_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00619_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00619_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00619_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(100g)\",\"돼지고기(100g)\",\"토마토(50g)\",\"양파(30g)\",\"찹쌀가루(50g)\",\"달걀(1개)\",\"순두부(20g)\",\"유자청(20g)\",\"소금(0.2g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"순두부와 유자청을 사용하여 소금을 적게 넣어도 맛을 유지할 수 있어요.\",\"instructions\":[\"1. 소고기와 돼지고기는 곱게 다진다.\",\"2. 양파는 곱게 다진다.\",\"3. 다진 고기에 양파, 달걀, 찹쌀가루,\\n소금, 후춧가루를 넣고 잘 치댄다.\",\"4. 토마토는 씨를 제거하고 곱게 다져\\n?에 섞는다.\",\"5. 순두부는 곱게 체에 내린다\",\"6. ?에 유자청을 섞고, 구워놓은\\n스테크에 올린다.\"]},{\"id\":\"k522\",\"title\":\"된장크림소스 잡곡 오므라이스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00620_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00620_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00620_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00620_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00620_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00620_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00620_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀(50g)\",\"보리(20g)\",\"율무(20g)\",\"은행(3알)\",\"팥(20g)\",\"대추(3알)\",\"호박(1/4개)\",\"홍피망(20g)\",\"청피망(20g)\",\"양파(30g)\",\"표고버섯(1개)\",\"부추(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장과 생크림을 섞어 나트륨을 감소시키고, 된장의 부드럽고 고소한 맛을 살렸어요.\",\"instructions\":[\"1. 잡곡은 깨끗이 씻어 충분히 불린 뒤\\n밥을 짓는다.\",\"2. 호박, 청피망, 홍피망, 양파,\\n표고버섯은 입자있게 다지고 부추는\\n송송 썰고 마늘은 다진다.\",\"3. 팬에 기름을 두르고 썰어놓은 야채를\\n살짝 볶다가 잡곡밥을 넣고 볶는다.\",\"4. 된장에 생크림과 로즈마리를 넣고\\n믹서에 간다.\",\"5. ?에 생크림과 로즈마리를 넣어\\n끓인다.\",\"6. 달걀은 풀어 체에 내려 넓게 지단을\\n부쳐 에 넣고 오므라이스로 말아 담고\\n된장 소스를 올린다.\"]},{\"id\":\"k523\",\"title\":\"두릅부추 소고기말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00621_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00621_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00621_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00621_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00621_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00621_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00621_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(홍두깨살\",\"100g)\",\"부추(30g)\",\"양파(30g)\",\"두릅(50g)\",\"대파(20g)\",\"마늘(20g)\",\"저염간장(30g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장을 졸일 때 대파와 양파를 넣어서 나트륨을 감소시키고 맛과 향을 좋게 만들 수 있어요.\",\"instructions\":[\"1. 동량의 물과 저염간장에 대파, 양파,\\n마늘을 넣고 은근히 졸인다.\",\"2. 마늘이 익을 정도로 끓으면 체에\\n거른다.\",\"3. 부추는 길게 썰고, 양파는 채썬다\",\"4. 두릅은 데친 후 찬물에 헹군다.\",\"5. 졸인 간장에 요리술을 넣고 다시\\n졸인다.\",\"6. 고기를 구운 뒤 준비한 야채와 두릅을\\n넣고 돌돌 말아 간장에 졸인다.\"]},{\"id\":\"k524\",\"title\":\"두부 비빔호박쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00622_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00622_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00622_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00622_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00622_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00622_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00622_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(150g)\",\"쌀(100g)\",\"강황쌀(100g)\",\"당근(20g)\",\"애호박(1/2개)\",\"숙주(50g)\",\"고사리(20g)\",\"호박잎(5장)\",\"파인애플(20g)\",\"올리고당(20g)\",\"고추장(20g)\",\"저염간장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장에 과일을 섞어 나트륨을 감소시키고 부드러운 고추장소스를 만들 수 있어요.\",\"instructions\":[\"1. 쌀과 강황쌀은 깨끗이 씻어 30분 정도\\n불린 뒤 밥을 짓는다.\",\"2. 고사리는 불린 뒤 삶고 잘게 썰어\\n저염간장에 볶는다.\",\"3. 두부, 당근은 채썰고, 애호박은\\n반달모양으로 썰어 볶는다.\",\"4. 숙주는 꼬리를 떼고 살짝 데친다.\",\"5. 호박잎은 끓는 물에 데친다.\",\"6. 고추장, 올리고당, 갈은 파인애플을\\n섞어 소스를 만들고, 데친 호박잎에\\n볶은 강황밥과 두부, 야채를 넣고\\n고추장소스를 넣고 둥글게 말아\\n완성한다.\"]},{\"id\":\"k525\",\"title\":\"두부곤약파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00623_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00623_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00623_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00623_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00623_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00623_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00623_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"곤약(50g)\",\"두부(150g)\",\"배(1/4개)\",\"양파(30g)\",\"파프리카(50g)\",\"양배추(20g)\",\"적양배추(20g)\",\"토마토(50g)\",\"저염간장(20g)\",\"설탕(10g)\",\"식초(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부를 얼려서 사용하게 되면 두부의 나트륨을 배출시킬 수 있어요.\",\"instructions\":[\"1. 곤약은 5cm 길이로 썰어 가운데\\n칼집을 넣고 매작과 모양으로 만들어\\n뜨거운 물에 살짝 데친다.\",\"2. 양배추, 적양배추는 채 썰고 배, 양파,\\n파프리카는 굵은 채를 썬다.\",\"3. 두부는 얼려 수분을 뺀다\",\"4. 얼린 두부는 3cm 주사위 모양으로\\n썬다.\",\"5. 토마토는 슬라이스 한다.\",\"6. 저염 간장에 설탕과 식초를 섞어\\n소스를 만들고, 곤약과 두부를 볶다가\\n야채를 넣어 한 번 더 볶은 뒤 소스를\\n뿌린다.,\"]},{\"id\":\"k526\",\"title\":\"두유 라이크 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00624_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00624_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00624_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00624_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00624_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00624_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00624_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"스파게티(100g)\",\"양파(30g)\",\"베이컨(20g)\",\"새송이버섯(1개)\",\"브로콜리(50g)\",\"홍고추(1개)\",\"두유(200g)\",\"견과류(20g)\",\"치즈(1장)\",\"올리브오일(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"베이컨을 데쳐 사용하면 베이컨의 나트륨과 첨가제를 제거할 수 있어요.\",\"instructions\":[\"1. 스파게티면은 10분 삶아 건진다.\",\"2. 팬에 올리브오일을 넣고 삶은\\n스파게티를 볶는다.\",\"3. 베이컨은 끓는 물에 살짝 데친다.\",\"4. 양파, 브로컬리, 홍보추, 베이컨은\\n썰고, 견과류는 다진다.\",\"5. 팬에 올리브오일을 넣고 ④를 볶는다.\",\"6. 야채가 볶아지면 두유를 넣고 끓이다가\\n스파게티, 치즈를 넣고 끓인 뒤 그릇에\\n담고 견과류를 올린다\"]},{\"id\":\"k527\",\"title\":\"라따뚜이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00625_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00625_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00625_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00625_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00625_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00625_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00625_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토(150g)\",\"가지(1/2개)\",\"애호박(1/2개)\",\"홀토마토(50g)\",\"양파(30g)\",\"월계수잎(1장)\",\"파슬리(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"홀토마토를 사용하게 되면 별도의 나트륨을 넣지 않아도 맛있는 음식을 만들 수 있어요.\",\"instructions\":[\"1. 토마토는 슬라이스 한다.\",\"2. 홀토마토와 양파는 곱게 다진다.\",\"3. 가지와 애호박은 둥글게 썬다.\",\"4. 팬에 가지와 애호박을 굽는다\",\"5. 냄비에 다진 토마토를 넣고 볶다가\\n다진 양파, 월계수잎을 넣고 볶아\\n은근히 끓여서 소스를 만든다.\",\"6. 파슬리는 곱게 다져 준비하고 접시에\\n토마토, 가지, 애호박을 돌려담고 그\\n위에 토마토소스를 올린 뒤 다진\\n파슬리를 올린다.\"]},{\"id\":\"k528\",\"title\":\"라이스페이퍼 야채롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00626_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00626_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00626_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00626_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00626_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00626_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00626_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(3마리)\",\"양파(30g)\",\"파프리카(50g)\",\"베이컨(20g)\",\"아스파라거스(2개)\",\"라이스페이퍼(3장)\",\"깻잎(5장)\",\"땅콩(20g)\",\"블루베리(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"땅콩과 블루베리를 섞어 나트륨 양을 줄이고 새콤달콤한 소스 맛을 낼 수 있어요.\",\"instructions\":[\"1. 새우는 껍질을 제거하고 데쳐 편썬다.\",\"2. 양파, 파프리카는 채썬다.\",\"3. 땅콩은 갈아서 블루베리와 섞어 소스를\\n만든다.\",\"4. 라이스페이퍼는 물에 적신 뒤 건진다.\",\"5. 라이스페이퍼에 깻잎을 올린다.\",\"6. ?위에 새우, 파프리카, 양파, 베이컨,\\n아스파라거스를 넣고 돌돌 말아 땅콩소\\n스를 곁들인다.\"]},{\"id\":\"k529\",\"title\":\"브로컬리 단호박스프와 완두콩퓨레\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00627_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00627_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00627_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00627_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00627_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00627_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00627_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"브로콜리(100g)\",\"우유(200g)\",\"단호박(1/2개)\",\"고구마(1개)\",\"완두콩(20g)\",\"식빵(1쪽)\",\"밀가루(20g)\",\"버터(20g)\",\"생크림(30g)\",\"오렌지(1/6개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"버터와 밀가루를 볶으면 별도의 소금을 넣지 않아도 고소하고 담백한 맛을 느낄 수 있어요\",\"instructions\":[\"1. 단호박, 고구마는 껍질을 벗겨 삶는다.\",\"2. 고구마는 삶아 체에 내린다.\",\"3. 완두콩은 삶아 간다.\",\"4. 데친 브로컬리와 우유를 믹서에 넣어\\n간다.\",\"5. 냄비에 버터와 밀가루를 넣고 볶아\\n화이트 루를 만든다.\",\"6. 고구마와 단호박에 우유를 넣어\\n끓이다가 화이트 루, 완두콩, 생크림을\\n넣고 끓인 뒤 오렌지즙 한 방울을\\n떨어뜨리고 식빵을 작게 잘라 올린다.\"]},{\"id\":\"k530\",\"title\":\"삼색샐러드와두부구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00628_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00628_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00628_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00628_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00628_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00628_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00628_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(150g)\",\"홍피망(30g)\",\"황파프리카(30g)\",\"적채(30g)\",\"양파(30g)\",\"깻잎(2장)\",\"흑임자(5g)\",\"밀가루(10g)\",\"매실액(20g)\",\"저염간장(20g)\",\"설탕(20g)\",\"소금(0.1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부에 밀가루를 묻혀 사용하면 나트륨도 줄일 수 있고, 바삭한 두부부침을 할 수 있어요.\",\"instructions\":[\"1. 두부는 3X4cm 크기로 썰어 소금을\\n살짝 뿌려둔다.\",\"2. 소금을 뿌려 놓은 두부는 물기를\\n제거하고 밀가루를 골고루 묻힌다.\",\"3. 팬에 기름을 두르고 두부를 앞뒤로\\n노릇노릇하게 구워 접시에 담는다.\",\"4. 매실액에 간장과 설탕을 넣고 골고루\\n섞어 소스를 만든다.\",\"5. 홍피망, 파프리카, 적채, 양파, 깻잎은\\n곱게 채썬다.\",\"6. 썰어 놓은 야채를 각각 물에 담궜다\\n건져 두부 옆에 담고 소스를 뿌리고\\n흑임자를 올린다.\"]},{\"id\":\"k531\",\"title\":\"새송이등갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00629_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00629_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00629_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00629_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00629_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00629_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00629_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(등갈비\",\"200g)\",\"새송이버섯(1개)\",\"당근(30g)\",\"대파(20g)\",\"양파(30g)\",\"저염간장(30g)\",\"후춧가루(0.01g)\",\"올리고당(20g)\",\"마늘(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"야채육수를 사용하면 맛이 담백하고 깔끔하며, 자연의 맛을 느낄 수 있어 소금을 적게 사용할 수 있어요.\",\"instructions\":[\"1. 등갈비는 찬물에 담궈 핏물을 빼고\\n끓는 물에 데친다.\",\"2. 새송이버섯은 길쭉하게 슬라이스로\\n썰어둔다.\",\"3. 당근, 양파, 대파는 큼직하게 썰어,\\n뜨거운 물에 담군다.\",\"4. 담궈 놓은 야채를 걸러 야채물을\\n만든다.\",\"5. 냄비에 야채물을 넣고 저염간장과\\n올리고당, 다진마늘, 후춧가루를\\n섞는다.\",\"6. 야채간장에 등갈비를 넣고 은근히\\n졸이다가, 썰어놓은 야채와\\n새송이버섯을 넣고 윤기나게 졸인다.\"]},{\"id\":\"k532\",\"title\":\"설렁탕쑥떡볶이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00630_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00630_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00630_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00630_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00630_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00630_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00630_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(뼈갈비\",\"200g)\",\"쑥(20g)\",\"찹쌀가루(200g)\",\"당근(20g)\",\"감자(50g)\",\"숙주(20g)\",\"청양고추(1개)\",\"홍고추(1개)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"뼈를 사용해서 육수를 만들어 칼슘 보충뿐만 아니라 소금을 적게 넣어도 고소한 맛을 느낄 수 있어요.\",\"instructions\":[\"1. 뼈갈비는 찬물에 담궈 핏물을 뺀다.\",\"2. 핏물을 뺀 뼈갈비를 건져 냄비에 넣고\\n끓여 육수를 만든다\",\"3. 쑥은 데치고, 당근, 감자는 한입크기로\\n썰고, 홍고추, 청양고추는 어슷썬다.\",\"4. 데친 쑥은 곱게 다진다.\",\"5. 찹쌀가루에 다진 쑥을 넣고 뜨거운\\n물로 익반죽 한 뒤 비닐에 담아\\n숙성시킨다.\",\"6. 숙성된 찹쌀반죽을 작게 잘라 가운데를\\n비벼 조랭이 쑥 떡을 만들고, 끓인\\n육수에 준비 한 야채와 함께 한소끔\\n끓인다.\"]},{\"id\":\"k533\",\"title\":\"소안심 야채 호박잎쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00631_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00631_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00631_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00631_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00631_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00631_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00631_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"호박잎(5장)\",\"적채(20g)\",\"파프리카(50g)\",\"양파(30g)\",\"오이(30g)\",\"소고기(안심\",\"120g)\",\"다시마(10g)\",\"두부(50g)\",\"고추장(30g)\",\"설탕(10g)\",\"식초(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장에 다시마 물과 설탕 식초를 넣어 나트륨을 감소시킬 수 있어요.\",\"instructions\":[\"1. 호박잎은 끓는 물에 데친다.\",\"2. 다시마는 물에 넣고 불린다.\",\"3. 불린 다시마는 채썬다.\",\"4. 파프리카, 양파, 오이, 두부는 채썬다.\",\"5. 고추장에 준비한 다시마물을 섞고,\\n설탕과 식초를 넣어 소스를 만든다.\",\"6. 소고기는 소금, 후춧가루로 밑간을\\n한뒤 구워 썰고, 호박잎에 소고기와\\n갖은 야채를 올려 돌돌말아 접시에\\n담고 고추장 소스를 올린다.\"]},{\"id\":\"k534\",\"title\":\"양배추 고기말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00632_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00632_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00632_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00632_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00632_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00632_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00632_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양배추(120g)\",\"돼지고기(등심\",\"50g)\",\"두부(50g)\",\"시금치(30g)\",\"달걀(1개)\",\"마늘(10g)\",\"소금(0.2g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"엽산과 비타민C가 풍부한 양배추를 사용해서 나트륨을 감소시킬 수 있어요.\",\"instructions\":[\"1. 돼지고기 등심은 곱게 다진다.\",\"2. 두부는 꼭 짜서 물기를 제거하고,\\n시금치는 데친 후 다진다.\",\"3. 두부와 다진 등심에 시금치, 소금,\\n후춧가루, 다진마늘 및 달걀을 넣고\\n골고루 잘 섞는다.\",\"4. 양배추는 김이 오른 찜통에서 약 5분\\n정도 찐다.\",\"5. 김발에 양배추를 넓게 편다.\",\"6. 양배추 위에 ?을 넣고 돌돌말아 한 번\\n더 찐다.\"]},{\"id\":\"k535\",\"title\":\"양배추 쌈말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00633_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00633_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00633_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00633_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00633_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00633_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00633_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양배추(120g)\",\"돼지고기(100g)\",\"깻잎(5장)\",\"사과(1/2개)\",\"파프리카(50g)\",\"당근(20g)\",\"다시마(10g)\",\"마늘(10g)\",\"저염간장(20g)\",\"후춧가루(0.01g)\",\"가쓰오부시(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마와 가쓰오부시로 소스를 만들어 천연 조미료의 감칠맛을 느낄 수 있어요.\",\"instructions\":[\"1. 물에 다시마를 넣고 끓인다.\",\"2. 끓여 놓은 다시마 육수에 마늘,\\n저염간장, 가쓰오부시를 넣고 살짝\\n끓인 뒤 걸러서 소스를 만든다.\",\"3. 양배추는 찜통에 찐다.\",\"4. 돼지고기는 저염간장과 후춧가루를\\n뿌려 볶고 식힌다\",\"5. 파프리카, 사과, 당근은 굵게 채썬다.\",\"6. 쪄낸 양배추에 깻잎과 썰어놓은 야채를\\n올려 둥그렇게 말아 준비한 소스에\\n살짝 적신다.\"]},{\"id\":\"k536\",\"title\":\"연어샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00634_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00634_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00634_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00634_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00634_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00634_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00634_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어(150g)\",\"레몬(1/4개)\",\"발사믹소스(50g)\",\"어린잎(30g)\",\"후춧가루(0.01g)\",\"올리브오일(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"발사믹소스에 레몬과 올리브오일을 섞어 별도의 소금을 넣지 않을 수 있어요.\",\"instructions\":[\"1. 연어는 깍둑썰기한다.\",\"2. 썰어 놓은 연어는 후춧가루와 레몬으로\\n마리네이드한다.\",\"3. 어린잎은 찬물에 담궈둔다\",\"4. 담궈 놓은 어린잎을 체에 받쳐 물기를\\n뺀다.\",\"5. 레몬과 올리브오일을 섞는다.\",\"6. ?번에 발사믹소스를 넣고 연어 샐러드\\n양념을 만들고, 접시에 연어와 물기를\\n뺀 어린잎을 담는다.\"]},{\"id\":\"k537\",\"title\":\"오렌지 드레싱 타다키 부추샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00635_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00635_1.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00635_2.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00635_3.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00635_4.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00635_5.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00635_6.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오렌지(1/2개)\",\"양파(30g)\",\"소고기(등심\",\"120g)\",\"레몬(1/4개)\",\"부추(30g)\",\"양배추(30g)\",\"견과류(20g)\",\"소금(0.2g)\",\"후춧가루(0.01g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오렌지와 레몬, 양파를 갈아서 드레싱을 만들면 간을 세게 하지 않아도 맛있게 즐길 수 있어요.\",\"instructions\":[\"1. 소고기는 소금과 후춧가루로\\n양념한다.\",\"2. 부추는 5cm 길이로 썰고 양배추는\\n채썬다.\",\"3. 오렌지는 껍질째 썬다.\",\"4. 썰어 놓은 오렌지와 레몬, 양파를 갈아\\n드레싱을 만든다.\",\"5. 견과류는 입자있게 다진다.\",\"6. 부추와 양배추를 준비한 드레싱에\\n버무려 접시에 담고, 양념된 소고기는\\n팬에 구워 먹기 좋게 썰어 담는다.\"]},{\"id\":\"k538\",\"title\":\"마감자전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101939_1416273579568.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/708-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/708-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/708-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/708-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/708-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/708-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"마감자전 : 감자 40g\",\"마 40g\",\"찹쌀가루 15g\",\"양파 5g\",\"현미유 5g 간장양념장 : 간장 3g\",\"파 2g\",\"식초 2g\",\"통깨 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양파를 갈아 넣으면 감자의 색이 덜 변한다.\",\"instructions\":[\"1. 양파와 파는 씻어 곱게 다진다.\",\"2. 감자와 마는 껍질을 벗긴 후 씻는다.\",\"3. 2를 강판에 간다.\",\"4. 1과 3을 섞은 후 찹쌀가루를 넣어 반죽한다.\",\"5. 현미유를 두른 팬에 반죽을 떠서 지름 8cm 크기로 동그랗게 부친다.\",\"6. 간장, 파, 식초, 통깨를 넣고 간장양념장을 만들어 곁들인다.\"]},{\"id\":\"k539\",\"title\":\"배추토란국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101941_1416273581628.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/709-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/709-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/709-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/709-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/709-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/709-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토란 50g\",\"쇠고기 양지 15g\",\"배추 10g\",\"대파 2.5g 다진 마늘 1.25g\",\"고춧가루 1.7g\",\"된장 9g\",\"물 180g\",\"참기름 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"자투리 배추를 살짝 데쳐 냉동 보관했다가 국 끓일 때 넣으면 시간도 절감되고 폐기량을 줄일 수 있다. - 토란의 아린 맛을 제거하려면 소금물에 담구거나 쌀뜨물에 데쳐 낸다.\",\"instructions\":[\"1. 토란은 감자칼로 껍질을 벗겨 3~4 등분한다.\",\"2. 소고기와 배추는 5mm 너비로 썰고 대파는 어슷 썬다.\",\"3. 토란을 연한 소금물(물 1컵 + 소금 1g)에 담근다.\",\"4. 참기름에 소고기와 다진 마늘을 볶다가 향이 우러나면 고춧가루를 넣고 잠시 더 볶는다.\",\"5. 볶은 고기에 물을 붓고 된장을 풀어 넣는다.\",\"6. 국물이 끓으면 배추, 토란, 대파를 넣고 한소끔 끓인다.\"]},{\"id\":\"k540\",\"title\":\"갈치고추장구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101943_1416273583596.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/711-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/711-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/711-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/711-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/711-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/711-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"갈치구이 : 갈치 50g\",\"현미유 4g 고추장양념 : 고추장 5g\",\"양파 5g\",\"파 3g\",\"다진 마늘 2g\",\"간장 2g\",\"매실액 2g\",\"고춧가루 1g\",\"다진 생강 0.5g\",\"통깨 0.1g\",\"후춧가루 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"갈치 표면을 덮고 있는 은백색의 비늘은 긁어낸다.\",\"instructions\":[\"1. 갈치는 비늘을 벗기고 손질한 후 토막내어 3~4회 칼집을 넣는다.\",\"2. 파는 다진다.\",\"3. 고추장, 양파, 파, 다진 마늘, 간장, 매실액, 고춧가루, 다진 생강, 후춧가루를 섞어 양념장을 만든다.\",\"4. 팬에 현미유를 두르고 갈치를 앞뒤로 애벌구이 한다.\",\"5. 애벌구이된 갈치 위에 고추장양념을 발라 구운다.\",\"6. 통깨를 뿌려 마무리한다.\"]},{\"id\":\"k541\",\"title\":\"단호박푸딩\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101945_1416273585547.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/712-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/712-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/712-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/712-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/712-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/712-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 70g\",\"우유 80g\",\"달걀노른자 20g\",\"꿀 2.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"푸딩을 냉장고에 넣어 두었다가 시원하게 먹어도 좋다.\",\"instructions\":[\"1. 단호박을 깨끗이 씻는다.\",\"2. 단호박은 익기 쉽도록 토막 내어 찐다.\",\"3. 찐 단호박은 뜨거울 때 으깬다.\",\"4. 2의 재료에 우유, 달걀노른자, 꿀을 넣어 잘 섞는다.\",\"5. 김이 오른 찜통에 넣고 10~15분간 찐다.\",\"6. 냉장고에 넣어 식힌후 차갑게 먹는다.\"]},{\"id\":\"k542\",\"title\":\"고등어된장구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101946_1416273586905.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/713-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/713-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/713-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/713-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/713-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/713-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고등어 50g\",\"콩기름 2g\",\"양파 껍질 2g\",\"양파 5g\",\"일식된장 미소 3g\",\"마요네즈 2g\",\"식초 0.3g\",\"맛술 3.75g\",\"생강즙 1.25g\",\"다시마 국물 3.75g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양파 속껍질과 양파를 깔고 구우면 고등어가 타지 않고 양파가 비린내를 흡수해 준다. - 고등어에 양념장을 발라 재운 후 구울 때 긁어 내고 구우면 염분 섭취를 낮출 수 있다.\",\"instructions\":[\"1. 고등어의 내장을 제거한다.\",\"2. 내장을 제거한 고등어를 길이로 반을 갈라 각각 2등분 한다.\",\"3. 양념장 재료를 모두 섞어 양념장을 만든다.\",\"4. 고등어에 양념장을 발라 30분 이상 재운다.\",\"5. 고등어의 양념장을 가볍게 긁어낸다.\",\"6.  팬에 기름을 두르고 양파 속껍질과 얇게 썬 양파 위에 고등어를 올려 굽는다.\"]},{\"id\":\"k543\",\"title\":\"낙지브로콜리볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101951_1416273591573.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/715-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/715-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/715-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/715-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/715-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/715-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"낙지 70g\",\"브로콜리 30g\",\"방울토마토 60g\",\"밀가루 5g\",\"양파 25g\",\"마늘 2g\",\"올리브유 3g\",\"소금 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"방울 토마토의 양을 3배로 해서 삶은 파스타면을 넣고 볶으면 맛있는 해물파스타가 된다. - 마늘을 볶을 때 불은 중불 이하로 해야 타지 않고 향이 잘 우러난다.\",\"instructions\":[\"1. 낙지는 밀가루를 넣고 주물러 씻는다.\",\"2. 씻은 낙지를 5cm 길이로 썬다\",\"3. 마늘은 편으로, 양파는 사방 3cm, 브로콜리는 한입 크기로 썬다.\",\"4. 팬에 올리브유를 넣고 마늘을 볶아 향을 낸다.\",\"5. 양파와 방울토마토를 넣고 약한 불에서 토마토가 물러질 때까지 천천히 익힌다.\",\"6. 브로콜리와 낙지를 넣고 볶은 뒤 소금으로 간하고 접시에 담아낸다.\"]},{\"id\":\"k544\",\"title\":\"주꾸미돌나물무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102010_1416273610854.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/717-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/717-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/717-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/717-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/717-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/717-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주꾸미 50g\",\"돌나물 15g\",\"오이 10g\",\"노랑파프리카 5g\",\"빨강파프리카 5g\",\"양파 5g 고추장 9g\",\"식초 6g\",\"매실액 5g\",\"다진 파 5g\",\"다진 마늘 2.5g\",\"통깨 1g\",\"고춧가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"주꾸미머리는 버리지 않고 계속 끓여 익힌 후 먹는다\",\"instructions\":[\"1. 돌나물은 먹기 좋은 크기로 자른다.\",\"2. 오이와 파프리카는 4~5cm 가량의 크기로 채 썬다.\",\"3. 주꾸미는 끓는 물에 데친다.\",\"4. 데친 주꾸미 4~5cm 가량의 크기로 썬다.\",\"5. 고추장, 식초, 매실액, 파, 마늘, 통깨, 고춧가루를 넣고 고추장양념을 만든다.\",\"6. 접시에 1,2,4를 담고 5의 고추장양념을 곁들인다.\"]},{\"id\":\"k545\",\"title\":\"사과소스폭찹\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102042_1416273642633.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/718-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/718-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/718-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/718-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/718-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/718-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기 등심 60g\",\"소금 0.5g\",\"후추 0.25g\",\"올리 브유 1.5g\",\"사과 50g\",\"양파 25g\",\"토마토 50g\",\"물 50g\",\"버터 1g\",\"올리브유 1.5g\",\"레몬즙 2.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"먹다 남은 사과와 토마토를 활용하면 음식물 쓰레기를 줄일 수 있다.\",\"instructions\":[\"1. 돼지고기를 0.5cm 두께로 썰어 칼집을 넣어 소금, 후추로 밑간한다.\",\"2. 사과와 양파는 얇게 채 썬다.\",\"3. 토마토는 4등분하여 물을 넣고 믹서에 간다.\",\"4. 팬에 버터와 올리브유를 두르고 사과와 양파를 볶다가 토마토를 넣고 약불에서 사과가 무를 때 까지 천천히 익힌 뒤 레몬즙을 넣는다.\",\"5. 팬에 올리브유를 두르고 고기를 앞뒤로 노릇하게 굽는다.\",\"6. 고기를 한입 크기로 잘라 사과소스를 얹어 낸다.\"]},{\"id\":\"k546\",\"title\":\"건도토리묵버섯들깨국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102044_1416273644261.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/719-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/719-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/719-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/719-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/719-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/719-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"건도토리묵 30g(불린것 50g)\",\"표고버섯 5g\",\"느타리버섯 5g\",\"들깨가루 5g\",\"국멸치 3g\",\"건다시마 3g\",\"파 2g\",\"다진 마늘 2.5g\",\"국간장 1g\",\"소금 0.5g\",\"물 300g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"도토리묵을 사용해도 되지만 건도토리묵보다 쫄깃한 맛은 덜하다.\",\"instructions\":[\"1. 물 1컵 반에 국멸치와 건다시마를 넣고 멸치다시마국물 1컵 정도를 내고 다시마는 미리 건져 채 썬다.\",\"2. 건도토리묵은 물에 불려 5cm 길이로 썬다.\",\"3. 표고버섯은 5cm 길이로 채 썰고 느타리버섯은 5cm 길이로 가늘게 찢는다.\",\"4. 파는 씻어 어슷썰기 한다.\",\"5. 멸치다시마국물 1컵에 도토리묵, 표고버섯, 느타리버섯을 넣고 한소끔 끓인다.\",\"6. 5에 들깨가루, 파, 다진 마늘, 다시마를 넣고 국간장과 소금으로 간을 한다.\"]},{\"id\":\"k547\",\"title\":\"무대하무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102046_1416273646384.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/720-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/720-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/720-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/720-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/720-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/720-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"무 40g\",\"새우(대하) 30g\",\"파 3g\",\"다진 마늘 3g\",\"고춧가루 2g\",\"간장 2g\",\"설탕 1g\",\"참기름 2g\",\"통깨 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우 머리는 한손으로 잡고 살짝 비틀어서 떼고 이때 내장이 같이 나오기도 하는데 그렇지 않은 경우는 등 쪽으로 이쑤시개를 찔러 넣어 실 같은 검은 내장을 제거 한다.\",\"instructions\":[\"1. 무는 씻어 1cm× 4cm × 0.3cm 크기로 나박썰기 한다.\",\"2. 새우는 등 쪽의 내장을 제거한다.\",\"3. 내장을 제거한 새우는 소금물에 살살 흔들어 씻는다.\",\"4. 김이 오른 찜통에 무와 새우를 넣고 함께 찐다.\",\"5. 찐 새우는 껍질을 벗기고 반으로 가른다.\",\"6. 무에 파, 다진 마늘, 고춧가루, 간장, 설탕, 참기름, 통깨를 넣고 무친 뒤 5의 새우를 넣고 버무린다.\"]},{\"id\":\"k548\",\"title\":\"간편조기찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102048_1416273648524.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/721-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/721-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/721-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/721-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/721-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/721-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"조기 70g\",\"고사리 20g\",\"양파 10g\",\"홍고추 3g\",\"청고추 3g\",\"다진 마늘 2.5g\",\"다진 생강 1g\",\"국간장 2g\",\"참기름 1g\",\"통깨 0.3g\",\"물 100g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"비늘을 긁을 때는 꼬리를 잡고 머리쪽을 향해 긁는다\",\"instructions\":[\"1. 조기의 비늘과 지느러미를 제거하고 앞뒤 3~4회 칼집을 내어 양념이 잘 배도록 손질한다\",\"2. 고사리는 4cm 가량으로 자른다.\",\"3.  자른 고사리는 국간장, 참기름, 마늘을 넣고 무친다\",\"4. 양파, 홍고추, 청고추는 잘게 썬다\",\"5. 양념된 고사리는 냄비에 넣는다\",\"6. 5의 냄비에 물을 붓고 조기, 양파, 홍고추, 청고추, 생강, 마늘, 국간장, 통깨, 참기름을 넣고 찐다\"]},{\"id\":\"k549\",\"title\":\"표고버섯쇠고기찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102049_1416273649461.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/722-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/722-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/722-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/722-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/722-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/722-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"표고버섯 30g\",\"다진 쇠고기 등심 20g\",\"양파 3g\",\"대파 2.5g\",\"다진 마늘 1.25g\",\"간장 3g\",\"설탕 2g\",\"참기름 1g\",\"말린 청양고추 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"찜기에 찌면 촉촉하고 부드러운 맛을 볼 수 있고 오븐에 구우면 쫄깃한 맛을 즐길 수 있다. -기호에 따라 초간장을 곁들여 낸다.\",\"instructions\":[\"1. 표고버섯의 기둥을 떼 낸다.\",\"2. 버섯 기둥과 양파, 대파는 다진다.\",\"3. 말린 고추는 으깨준다.\",\"4. 고기에 2, 3과 나머지 양념을 넣어 잘 치댄다.\",\"5. 표고버섯에 양념한 고기를 채운다.\",\"6. 찜기에 젖은 면보를 깔고 10분간 쪄 낸다.\"]},{\"id\":\"k550\",\"title\":\"참나물돼지고기샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102050_1416273650645.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/723-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/723-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/723-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/723-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/723-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/723-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기사태 60g\",\"참나물 20g\",\"양파 15g\",\"파 5g\",\"통마늘 3g\",\"생강 2g\",\"후춧가루 0.5g 양파 10g\",\"간장 4g\",\"식초 4g\",\"설탕 3g\",\"마늘 3g\",\"고춧가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"돼지고기는 물에 담가 핏물을 제거한 후 사용한다\",\"instructions\":[\"1. 냄비에 물 2컵을 넣고 돼지고기, 양파, 파, 통마늘, 생강, 후춧가루를 넣고 삶는다.\",\"2. 삶은 돼지고기는 2cm × 3cm × 0.3cm 가량의 크기로 썬다.\",\"3. 참나물은 먹기 좋은 크기로 자른다.\",\"4. 양파는 다져준다.\",\"5.  다진양파, 설탕, 간장, 고춧가루, 올리브유, 식초, 마늘, 통깨를 넣어 샐러드드레싱을 만든다.\",\"6. 2의 돼지고기와 3의 참나물을 그릇에 담고 샐러드드레싱을 곁들인다.\"]},{\"id\":\"k551\",\"title\":\"연근배추홍시샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102052_1416273652549.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/724-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/724-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/724-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/724-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/724-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/724-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연근배추샐러드 : 연근 20g\",\"배추 20g\",\"사과 20g\",\"배 20g\",\"땅콩 3g\",\"호두 3g\",\"현미유 5g\",\"물 100g 홍시드레싱 : 홍시 30g\",\"호상요구르트 30g\",\"3배 식초 0.5g\",\"소금 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연근은 최대한 얇게 썰어야 바삭바삭한 칩이 된다. - 연근은 식초물에 담가 갈변을 방지한다.\",\"instructions\":[\"1. 연근은 껍질을 벗겨 0.2 cm 길이로 얇게 썰어 물 반컵에 식초를 넣은 후 10분정도 담갔다가 물기를 제거한다.\",\"2. 배추, 사과, 배는 씻어 4~5cm 길이로 채썬다.\",\"3. 땅콩과 호두는 칼로 굵게 다진다.\",\"4. 연근은 팬에 현미유를 두르고 노릇노릇하게 구어 연근칩을 만든다.\",\"5. 홍시, 호상요구르트, 3배 식초, 소금을 섞어 홍시드레싱을 만든다.\",\"6. 그릇에 배추, 사과, 배, 연근칩, 땅콩, 호두를 넣고 버무린 뒤 홍시드레싱을 곁들인다.\"]},{\"id\":\"k552\",\"title\":\"열무곤약국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00370_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00370_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00370_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00370_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00370_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00370_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00370_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"열무김치 100g\",\"실곤약 150g\",\"오이 25g\",\"레몬 20g\",\"양파 60g\",\"계란 60g\",\"당근 20g\",\"통깨 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"열무김치를 이용해 추가 간을 하지 않고 김치 고유의 맛으로 맛을 냈으며, 오이와 양파를 넣어 씹는 맛과 향미로 짠 맛을 대체하였다.\",\"instructions\":[\"1. 실곤약은 세척해 레몬즙을 뿌려 물기를 빼준다.\",\"2. 오이는 채 썰어준다.\",\"3. 당근, 양파를 채 썰어서 냉수에 담가준다.\",\"4. 열무김치국물과 물200g에 섞어서 국물을\\n만들어준다\",\"5. 달걀은 쪄서 반만 잘라 준비해준다.\",\"6. 그릇에 곤약. 열무, 준비된 채소를 넣고 마지막에\\n국물을 넣어 완성한다\"]},{\"id\":\"k553\",\"title\":\"장어구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00371_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00371_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00371_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00371_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00371_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00371_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00371_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"장어 250g\",\"우유 100g\",\"뿌리채소조림 : 우엉 60g\",\"더덕 60g\",\"생강 20g\",\"맛간장 15g\",\"생강청 15g\",\"올리고당 15g\",\"발사믹식초 30g\",\"곁들이김치 : 명이김치 25g\",\"백김치 25g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스를 만들 때 발사믹식초를 사용하여 특유의 맛을 활용해 졸여 나트륨을 줄였다.\",\"instructions\":[\"1. 장어는 손질해 우유에 담가 이물질을 빼준다.\",\"2. 더덕과 우엉은 가늘게 채 썰어 냉수에 담가\\n준다.\",\"3. 생강은 채 썰어 냉수에 담가준다.\",\"4. 조림장을 만들어 더덕, 우엉, 생강을 각각\\n볶아 섞어준다.\",\"5. 맛간장과 발사믹식초를 졸이다가 장어를\\n볶아준다.\",\"6. 곁들이 김치를 준비하고 졸여진 뿌리채소와\\n장어를 섞어 완성한다.\"]},{\"id\":\"k554\",\"title\":\"안심스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00372_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00372_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00372_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00372_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00372_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00372_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00372_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"안심 160g\",\"아스파라거스 60g\",\"당근 25g\",\"감자 60g\",\"호두 40g\",\"소스 : 망고 150g\",\"블루베리잼 30g\",\"다진마늘 15g\",\"버터 15g\",\"포도주 15g\",\"올리고당 15g\",\"흰후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"호두를 다져서 소스에 발라주어 씹으면 씹을수록 육즙과 만나 고소함을 더해 주었고, 망고와 블루베리잼을 사용해 달콤하면서 풍미를 더해 짠맛을 대체하였다.\",\"instructions\":[\"1. 망고를 먹기 좋은 크기로 자르고 소스재료로\\n소스를 만들어준다.\",\"2. 호두를 곱게 다져준다.\",\"3. 안심에 만들어진 소스를 발라주고 곱게 다진\\n호두가루를 발라준다.\",\"4. 감자, 당근, 아스파라거스는 먹기 좋은 크기로\\n잘라서 버터에 볶아준다.\",\"5. 호두를 발라준 안심을 구워준다.\",\"6. 남은 망고소스를 다시 졸여서 구워진 안심\\n위에 뿌려주고 볶은 채소랑 완성한다.\"]},{\"id\":\"k555\",\"title\":\"로제파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00373_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00373_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00373_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00373_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00373_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00373_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00373_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토홀 50g\",\"토마토 100g\",\"다진양파 30g\",\"다진마늘 15g\",\"푸실리 50g\",\"치즈가루 25g\",\"파슬리가루 1g\",\"함초소금2g\",\"마늘오일 15g\",\"곁들이야채 : 양파 25g\",\"가지 25g\",\"파프리카 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"곁들이 채소를 입자가 있게 잘라주어 씹는 맛을 주었고 채소의 신선함을 함께 주어 나트륨 사용을 줄였다.\",\"instructions\":[\"1. 토마토홀과 토마토는 송송 다져준다.\",\"2. 다진양파, 다진마늘과 다진토마토를 섞어\\n소스를 볶아서 신맛을 날려준다.\",\"3. 푸실리는 삶아 오일에 버무려주고 볶아준다.\",\"4. 양파, 애호박, 가지, 파프리카를 먹기 좋게\\n잘라 팬에 볶아준다.\",\"5. 접시에 볶아진 채소와 파스타면을 서로 다시\\n볶아준다.\",\"6. 접시에 푸슬리를 올려 셋팅하고 토마토소스를\\n뿌려주고 치즈가루를 뿌려 완성한다.\"]},{\"id\":\"k556\",\"title\":\"가지라따뚜이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00374_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00374_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00374_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00374_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00374_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00374_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00374_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지 1/2개(180g)\",\"피망 100g\",\"파프리카 100g\",\"양파 100g\",\"토마토페이스트 200g\",\"애호박 200g\",\"치즈가루 10g\",\"바질잎 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치즈가루와 토마토페이스트를 사용하여 소금간 없이 맛을 냈다.\",\"instructions\":[\"1. 토마토 페이스트는 신맛이 날아가도록 볶아\\n준다.\",\"2. 피망, 파프리카와 양파 , 애호박은 작은\\n사각형으로 잘라준다.\",\"3. 잘라준 채소를 올리브오일에 볶은 뒤 볶아진\\n페이스트에 함께 볶아준다.\",\"4. 가지는 어슷하고 도톰하게 잘라준다.\",\"5. 가지를 팬에 구워준다.\",\"6. 팬에 구운 가지를 올려주고 볶아진 채소를\\n올려주고 다진 치즈를 뿌려서 완성한다.\"]},{\"id\":\"k557\",\"title\":\"쪽갈비구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00375_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00375_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00375_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00375_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00375_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00375_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00375_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쪽갈비 400g\",\"올리브오일 30g\",\"통후추 1g\",\"건 로즈마리 1g\",\"와인 15g\",\"곁들이채소 : 방울토마토 45g\",\"양파 60g\",\"레몬껍질 10g\",\"소스 : 마요네즈 30g\",\"식초 15g\",\"홀그레인 머스터즈 10g\",\"설탕 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기에는 로즈마리의 향으로 잡냄새를 제거해주고 통후추를 사용해 훨씬 더 깊은 맛을 내주어 소금을 사용 안 해도 깊은 맛을 내 주어 나트륨을 줄였다.\",\"instructions\":[\"1. 쪽갈비는 물에 와인을 넣어 80% 이상을 삶아\\n냉수에 헹군다. 데쳐낸 쪽갈비를 올리브오일\\n과 로즈마리와 통후추를 뿌려서 구워준다.\",\"2. 소스를 만들어준다.\",\"3. 레몬껍질은 채 썰어준다.\",\"4. 방울토마토는 먹기 좋게 자르고 양파도 먹기\\n좋게 잘라 팬에 구워준다.\",\"5. 쪽갈비를 레몬껍질과 함께 굽는다.\",\"6. 구워진 채소에 함께 쪽갈비를 굽고 소스와\\n함께 완성한다.\"]},{\"id\":\"k558\",\"title\":\"베이컨밀푀유\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00376_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00376_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00376_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00376_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00376_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00376_05.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"알배추 8장(200g)\",\"깻잎 12장(20g)\",\"베이컨 80g\",\"무 100g\",\"숙주 120g\",\"청경재 80g\",\"백일송이 25g\",\"국물 : 채소국물 8컵(표고버섯\",\"다시마\",\"마늘\",\"대파뿌리\",\"양파)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"베이컨 같은 식재료는 나트륨 함량이 다른 식재료보다 더 높아 한 번 데쳐 조리하였다.\",\"instructions\":[\"1. 베이컨은 뜨거운 물에 살짝 데쳐준다.\",\"2. 배춧잎 위에 깻잎 2장을 양쪽으로 깔고, 그\\n사이에 베이컨을 얹는 방식으로 반복하여\\n겹겹이 올려준 후 먹기 좋게 잘라준다.\",\"3. 냄비 바닥에 끓인 무와 청경채, 숙주나물을\\n깔아준다.\",\"4. 2가지 소스를 만들어준다.\",\"5. 가운데 부분은 백일송이버섯으로 채워주고\\n먹기 직전에 만든 육수를 부어 끓여주고\\n소스와 함께 완성한다.\"]},{\"id\":\"k559\",\"title\":\"실곤약냉파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00377_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00377_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00377_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00377_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00377_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00377_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00377_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"실곤약 150g\",\"칵테일새우 100g\",\"브로콜리 100g\",\"바질 5g\",\"레몬즙 15g\",\"소스 : 잣 바질페이소스 15g\",\"마늘오일 15g\",\"드라이토마토 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"염분 대신 바질의 향과 잣의 고소한 맛을 강조하여 나트륨 섭취량과 칼로리까지 줄일 수 있다.\",\"instructions\":[\"1. 실 곤약은 세척 후에 물기를 빼준다.\",\"2. 새우와 브로콜리는 데쳐 냉수에 헹궈 준비한다.\",\"3. 드라이 토마토는 물에 데쳐 준 후 송송 다져\\n준 후 올리브 오일에 버무려주고 생 바질은\\n데친 후 송송 다져준다.\",\"4. 볼에 실 곤약을 바질 페이스트에 버무려준다.\",\"5. 다져 놓은 채소와 새우, 브로콜리를 섞어\\n버무려준다.\",\"6. 마지막에 파마산 가루를 뿌려 완성한다.\"]},{\"id\":\"k560\",\"title\":\"명란프리타타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00378_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00378_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00378_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00378_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00378_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00378_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00378_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"명란젓 50g\",\"생크림 20g\",\"달걀 4개(240g)\",\"흰추후 1g\",\"시금치 50g\",\"방울토마토 6개(100g)\",\"올리브유 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"명란젓에는 다량의 염분을 함유하고 있기에 추가 간을 하지 않고 맛있는 맛을 냈다.\",\"instructions\":[\"1. 명란은 껍질을 벗겨 송송 다져준다.\",\"2. 달걀을 풀어서 채에 내려주고 후추로 간을\\n해준다.\",\"3. 달걀에 명란과 생크림을 넣어 섞어준다.\",\"4. 시금치는 데쳐서 수분을 제거 후 송송 다져\\n주고 토마토는 작은 사각형으로 잘라준다.\",\"5. 팬에 기름을 두르고 달걀을 부어 반 정도\\n익혀준다.\",\"6. 달걀이 반 정도 익었을 때 토마토와 시금치를\\n넣어 뚜껑을 덮어 익혀 완성한다.\"]},{\"id\":\"k561\",\"title\":\"양송이구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00379_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00379_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00379_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00379_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00379_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00379_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00379_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양송이 100g\",\"로즈마리 1g\",\"소 : 다진 돼기고기 100g\",\"청양고추 30g\",\"후추 1g\",\"다진마늘 5g\",\"달걀 60g\",\"밀가루 5g\",\"소스 : 홀스레디쉬 30g\",\"레몬즙 15g\",\"후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"청양고추와 마늘을 사용해 특유의 맛과 향을 냈고, 양송이버섯 특유의 감칠맛으로 나트륨 사용을 줄일 수가 있다.\",\"instructions\":[\"1. 양송이는 꼭지를 제거하고 밀가루를 살짝\\n묻혀준다.\",\"2. 청양고추를 송송 다진다.\",\"3. 청양고추, 다진 돼지고기, 계란을 함께 버무려\\n준다.\",\"4. 양송이 소에 양념된 돼지고기를 채워준다.\",\"5. 소스를 만들어준다.\",\"6. 팬에 양송이를 구워준 후 로즈마리를 올려주고\\n소스와 함께 낸다.\"]},{\"id\":\"k562\",\"title\":\"함초김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00380_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00380_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00380_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00380_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00380_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00380_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00380_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"함초 25g\",\"알배추 50g\",\"양파 50g\",\"무 100g\",\"간편 어간장 15g\",\"국물 : 오렌지주스 50g\",\"유자청 30g\",\"식초 15g\",\"설탕 15g\",\"야채국물 800g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"함초에서 나오는 염분을 이용하고 간편 어간장의 감칠맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 함초는 먹기 좋게 썰어준다.\",\"2. 알 배추, 무, 양파도 먹기 좋게 썬다.\",\"3. 오렌지주스와 유자청을 넣어 국물을 만든다.\",\"4. 볼에 함초, 알배추, 무를 넣어 섞고 어간장을\\n넣어 살짝 절여준다.\",\"5. 절여진 재료에 국물을 부어준다.\",\"6. 3시간 정도 후부터 먹을 수가 있다.\"]},{\"id\":\"k563\",\"title\":\"연어스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00381_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00381_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00381_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00381_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00381_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00381_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00381_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연어 150g\",\"건조다시마 사방 10cm 1장\",\"잎녹차 5g\",\"브로콜리 15g\",\"호두10g\",\"귀리 20g\",\"쌀 20g\",\"미소된장 5g\",\"흰후추 1g\",\"화이트와인 15g\",\"생크림 50g\",\"수제조미료 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연어에 다시마의 자체 염을 염지하여 맛과 풍미를 높였다.\",\"instructions\":[\"1. 연어는 불려준 다시마에 싸주어 24시간 염지\\n시켜준다.\",\"2. 잎 녹차는 물에 불려준다.\",\"3. 뒤 수분을 빼주고 팬에 올려서 연어를 약불\\n에서 구워내 준다.\",\"4. 브로콜리, 호두도 먹기 좋게 잘라준다.\",\"5. 귀리와 쌀은 1시간정도 불려준다.\",\"6. 닭 육수와 미소된장을 넣어 볶아주다가 불린\\n쌀을 넣어 볶아주어 리조또를 완성하고 접시에\\n리조또를 담고 구운 연어를 올려 완성한다.\"]},{\"id\":\"k564\",\"title\":\"웰빙꼬치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00382_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00382_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00382_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00382_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00382_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00382_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00382_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 150g\",\"자숙새우 100g\",\"소라살 100g\",\"방울토마토 80g\",\"단호박 100g\",\"대파 50g\",\"2가지색 파프리카 100g\",\"양파 100g\",\"흰 후추 2g\",\"레드와인 30g\",\"다진 마늘 15g\",\"올리브오일 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"버터와 발사믹 식초를 이용해 소스를 만들고 설탕으로 소스의 농도와 윤기를 내주면서 발사믹 식초의 상큼한 맛으로 짠맛을 대체하였다.\",\"instructions\":[\"1. 닭가슴살과 단호박은 사방 2.5cm 크기로\\n잘라준다.\",\"2. 양파 2가지, 색파프리카, 대파는 닭 크기와\\n비슷하게 잘라준다.\",\"3. 닭가슴살과 소라살은 통후추, 올리브오일에\\n재워준다.\",\"4. 소스를 만들어준다.\",\"5. 모든 재료를 꼬치에 꽂는다.\",\"6. 꼬치를 팬에 구워주면서 소스를 발라준다.\"]},{\"id\":\"k565\",\"title\":\"매운닭날개구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00383_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00383_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00383_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00383_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00383_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00383_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00383_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭날개 100g\",\"감자 80g\",\"방울토마토 100g\",\"브로콜리 30g\",\"마늘 15g\",\"양파 50g\",\"버터 15g\",\"후추 1g\",\"황설탕 5g\",\"고춧가루 5g\",\"레드와인 30g\",\"멕시코고추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭날개에 간을 내어 닭 고유의 맛과 향신료 특유의 맛이 조화를 이루어 짠맛을 대체하였다.\",\"instructions\":[\"1. 닭날개를 멕시코고추와 고추가루에 설탕,\\n다진마늘, 후추를 넣어 밑간을 해준다.\",\"2. 감자는 먹기 좋게 썰어 뜨거운 물에 70%\\n정도 익혀준다.\",\"3. 감자는 데쳐 낸 후 버터에 볶아준다.\",\"4. 브로콜리는 데치고, 사과와 토마토는 잘게\\n잘라준다.\",\"5. 냄비에 다진마늘과 다진양파를 볶아주다\\n토마토를 넣어 소스를 만들어준다.\",\"6. 닭날개를 팬에 구워주고 감자와 샐러드를\\n곁들여 완성한다.\"]},{\"id\":\"k566\",\"title\":\"웰빙카레죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00384_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00384_01.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00384_02.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00384_03.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00384_04.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00384_05.png\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_00384_06.png\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"카레가루 45g\",\"귀리밥 200g\",\"닭가슴살 150g\",\"애호박 25g\",\"감자 60g\",\"양파 60g\",\"방울토마토 100g\",\"마늘 100g\",\"버터 15g\",\"칵테일새우 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레의 특유 향과 갖가지 채소가 짠맛을 대체하면서 식욕을 자극한다.\",\"instructions\":[\"1. 카레가루를 물에 풀어서 30분 정도 숙성\\n시켜준다.\",\"2. 닭가슴살은 사방 1cm 크기로 잘라주고,\\n칵테일새우도 세척해 준비한다.\",\"3. 알 마 늘 , 감자는 사 방 1 c m 길이로 잘라\\n물 400g에 먼저 익혀준다.\",\"4. 방울토마토, 애호박은 사방 1cm 크기로\\n썰어준다.\",\"5. 끓고 있는 냄비에 풀어 놓은 카레가루를 섞어\\n다시 끓여준다.\",\"6. 양파는 사방 1cm 길이로 잘라주고 끓고 있는\\n카레에 양파, 방울토마토, 애호박을 넣고\\n끓여 완성한다.\"]},{\"id\":\"k567\",\"title\":\"닭가슴살 두부선\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102916_1554686956344.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103000_1554687000960.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103015_1554687015468.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103030_1554687030209.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103046_1554687046659.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103107_1554687067539.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103138_1554687098574.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살) 50g\",\"두부 120g\",\"비트 10g\",\"시금치 10g\",\"베이비채소 1g\",\"마늘 2g\",\"참기름 1.5g\",\"흑임자 3g\",\"플레인요거트 15g\",\"식초 0.5g\",\"설탕 1g\",\"소금 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"플레인요거트를 이용한 흑임자소스로 고소하고 상큼한 맛을 내 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 닭가슴살, 두부, 소금을 믹서에 간다.\",\"2. 1에 간 마늘과 소금, 참기름을 섞는다.\",\"3. 반죽 1/3은 비트물, 1/3은 시금치물을 넣어 색을 입힌다.\",\"4. 틀에 반죽을 층층이 쌓아 모양을 만든 뒤 오븐에 찐다.\",\"5. 흑임자가루, 플레인요거트, 식초, 설탕을 섞어 드레싱을 만든다.\",\"6. 접시에 담고 소스와 베이비채소를 얹는다.\"]},{\"id\":\"k568\",\"title\":\"단호박 마전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103439_1554687279859.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103508_1554687308037.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103524_1554687324066.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103541_1554687341478.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103604_1554687364961.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103620_1554687380157.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103634_1554687394121.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 70g\",\"마 20g\",\"밀가루 5g\",\"찹쌀가루 5g\",\"건대추 1g\",\"소금 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박의 달고 고소한 맛으로 나트륨이 적어도 풍미를 낼 수 있어요.\",\"instructions\":[\"1. 단호박을 잘게 다진다.\",\"2. 마를 0.3cm 두께로 썰어 뜨거운 물에 데친다.\",\"3. 잘게 다진 단호박에 밀가루와 찹쌀가루, 물, 소금을 넣어 반죽한다.\",\"4. 프라이팬에 식용유를 두르고 반죽을 두른다.\",\"5. 두른 반죽 가운데 마를 올려 부친다.\",\"6. 먹기 좋게 담은 후 건대추를 고명으로 올린다.\"]},{\"id\":\"k569\",\"title\":\"완두콩과 당근을 넣은 감자요거트 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030122_1678082482750.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030200_1678082520663.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030222_1678082542361.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030258_1678082578679.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030319_1678082599173.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030344_1678082624608.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030405_1678082645724.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"완두콩 10g\",\"당근 10g\",\"감자 50g\",\"플레인요거트 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•요거트를 드레싱으로 사용하여 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 완두콩을 삶아 건진다.\",\"2. 감자는 삶은 뒤 건져 껍질을 벗긴다.\",\"3. 감자가 뜨거울 때 곱게 으깬다.\",\"4. 당근을 잘게 다진다.\",\"5. 으깬 감자와 완두콩, 당근을 섞는다.\",\"6. 플레인요거트를 섞어 마무리한다.\"]},{\"id\":\"k570\",\"title\":\"무오색쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113150_1584412310801.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113247_1584412367164.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113259_1584412379608.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113312_1584412392448.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113329_1584412409628.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113342_1584412422251.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113356_1584412436129.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌈무 10.5g\",\"쇠고기 4.5g\",\"달걀 2.4g\",\"당근 3.3g\",\"표고버섯 3.2g\",\"오이 7.8g\",\"연겨자 0.28g\",\"진간장 0.05g\",\"식초 0.57g\",\"참기름 0.14g\",\"깐마늘 0.3g\",\"설탕 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새콤달콤 톡 쏘는 연겨자를 이용해 소금의 사용을 최소화했어요.\",\"instructions\":[\"1. 당근, 오이, 표고버섯은 5cm 길이로 가늘게 채썬다.\",\"2. 당근, 오이, 표고버섯은 각각 살짝 볶아내어 식혀둔다.\",\"3. 쇠고기는 간장, 설탕, 마늘, 참기름을 넣어 밑간하여 볶아낸다.\",\"4. 달걀은 얇게 지단을 부쳐 5cm 길이로 썬다.\",\"5. 연겨자, 식초, 마늘, 설탕, 깨를 넣어 소스를 만든다.\",\"6. 모든 재료를 소스에 버무린 다음 무쌈과 함께 낸다.\"]},{\"id\":\"k571\",\"title\":\"흑마늘견과류조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113538_1584412538874.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113611_1584412571158.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113624_1584412584475.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113638_1584412598283.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113658_1584412618614.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113716_1584412636861.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113731_1584412651969.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통마늘 10g\",\"마카다미아 5g\",\"호두 5g\",\"아몬드 5g\",\"캐슈넛 2g\",\"땅콩 2g\",\"대두유 5g\",\"흑마늘진액 5g\",\"간장 2g\",\"물엿 2g\",\"깨 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"흑마늘은 이용해 보기 좋은 색과 향을 입혀 간장 사용량을 줄여요.\",\"instructions\":[\"1. 통마늘과 견과류들은 먹기 좋은 크기로 자른다.\",\"2. 흑마늘 진액과 간장, 물엿, 물을 넣어 흑마늘 소스를 만든다.\",\"3. 대두유를 두르고 마늘을 팬에 노릇하게 구워준다.\",\"4. 구워진 마늘에 각종 견과류를 넣어 볶는다.\",\"5. 소스를 넣어 조린다.\",\"6. 그릇에 담고 깨를 뿌려 마무리한다.\"]},{\"id\":\"k572\",\"title\":\"고구마 찰 빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052349_1612254229383.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052425_1612254265580.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052445_1612254285163.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052504_1612254304996.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052522_1612254322095.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052535_1612254335627.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052549_1612254349513.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 쌀가루 120g\",\"타피오카 전분 80g\",\"비트가루 15g\",\"물 140g\",\"르뱅 발효종 160g\",\"소금 2g\",\"올리브유 25g\",\"(속재료)  고구마 30g\",\"생크림 10g\",\"김치 70g\",\"양파30g\",\"기름5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"타피오카를 넣어 반죽에 단맛을 주었고, 고구마와 양파를 볶아 넣어 단맛을 냈어요.\\n르뱅 발효종은 이스트 10g으로 대체 가능해요.\",\"instructions\":[\"1. (속재료) 고구마는 쪄서 으깬 후 생크림을 넣어 부드러운 무스를 만든다.\\n 양파와 김치는 다지고, 기름 두른 팬에 양파를 볶아 단맛을 낸 다음 김치를 볶아 볶음 김치를 만든다.\",\"2. 반죽재료를 모두 넣고 1단으로 믹싱한 후 올리브유를 넣고 최종단계 직전까지 믹싱한다.\",\"3. 1차 발효 후에 반죽을 각 100g씩 총 3개로 분할하여 둥글리기 한 후 랩을 덮어 중간발효(10분)를 해준다.\",\"4. 반죽에 고구마 무스 ,볶음김치을 넣어 싼 후 고구마 모양으로 만들어 준다.\\n★이음새가 벌어지면 구우면서 반죽이 터져지니 꼼꼼히 붙여주세요.\",\"5. 팬닝 후 2차 발효(30분)를 한다.\",\"6. 윗불 160℃, 아랫불 180℃에서 15분 굽는다.\"]},{\"id\":\"k573\",\"title\":\"브로콜리견과류복음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034924_1678085364484.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035056_1678085456949.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035143_1678085503782.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035203_1678085523804.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035225_1678085545072.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035243_1678085563315.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035303_1678085583790.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 브로콜리 70g\",\"아몬드슬라이스 5g\",\"캐슈넛 10g\",\"•양념 : 무염버터 10g\",\"소금 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•버터의 고소한 향과 불향을 더해 나트륨이 적어도 맛있게 먹을 수 있어요.\",\"instructions\":[\"1. 끓는 물에 한 입 크기로 썬 브로콜리를 데친다.\",\"2. 팬에 아몬드슬라이스, 캐슈넛을 굽는다.\",\"3. 팬에 무염버터를 녹인다.\",\"4. 버터가 녹으면 브로콜리를 넣어 불향이 나도록 볶는다.\",\"5. 구운 견과류를 넣어 볶다가 소금으로 간한다.\",\"6. 그릇에 담아 마무리한다.\"]},{\"id\":\"k574\",\"title\":\"유린기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024736_1678340856988.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024821_1678340901077.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024838_1678340918407.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024851_1678340931321.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024904_1678340944118.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024917_1678340957864.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024936_1678340976008.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 닭다리살(110g)\",\"양상추(25g)\",\"그린치커리(5g)\",\"라디치오(5g)\",\"홍고추(5g)\",\"청양고추(5g)\",\"대파(5g)\",\"무순(3g)\",\"마늘(1g)\",\"생강(1g)\",\"식용유(3g)\",\"•소스 : 식초(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•청양고추와 레몬을 사용해 매콤하고 새콤하면서 나트륨이 적은 소스를 만들었어요.\",\"instructions\":[\"1. 양상추와 그린치커리, 라디치오는 먹기 좋은 크기로 찢고, 고추는 잘게 다진다.\",\"2. 대파와 생강, 마늘은 곱게 다지고, 팬에 식용유를 두른 뒤 볶는다.\",\"3. 소스 재료를 넣어 약한 불에서 5분 정도 끓인다.\",\"4. 소스를 식힌 뒤 잘게 썬 고추를 섞는다.\",\"5. 닭다리살에 옥수수전분을 묻히고, 팬에 식용유를 두른 뒤 노릇하게 굽는다.\",\"6. 그릇에 손질한 채소를 깔고, 구운 닭다리살을 올린 뒤 소스와 무순을 올려 마무리한다.\"]},{\"id\":\"k575\",\"title\":\"단호박 호밀빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042050_1611904850936.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042144_1611904904150.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042157_1611904917199.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042211_1611904931573.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042224_1611904944555.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042241_1611904961135.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042253_1611904973344.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 통밀가루 200g\",\"강력분 200g\",\"전립분 40g\",\"소금 15g\",\"드라이이스트 5g\",\"물 150ml\",\"베이킹파우더 10g\",\"(속재료) 단호박 20g\",\"참깨 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕 대신 잘 익은 단호박을 이용하여 담백한 단맛을 냈고, 참깨의 고소한 맛으로 단맛을 대체했어요.\",\"instructions\":[\"1. (속재료) 단호박은 쪄서 먹기 좋은 크기로 썰어둔다.\",\"2. 통밀가루와 강력분, 전립분, 물, 소금을 섞어 5℃에서 반나절동안 1차 발효를 시킨다.\",\"3. 반죽을 썰어 모양을 잡고, 중간발효를 15분동안 한다.\",\"4. 반죽 가운데에 썰은 단호박과 참깨를 넣고 가볍게 접어서 말아 면포에 올린다.\",\"5. 굽기 전에 쿠프(칼집내기)를 한다.\",\"6. 230℃ 로 예열한 오븐에 넣고 스팀 후 210℃에서 25분 굽는다.\"]},{\"id\":\"k576\",\"title\":\"미숫가루 스콘\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045232_1611906752043.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045311_1611906791433.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045323_1611906803703.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045338_1611906818168.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045351_1611906831195.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045417_1611906857326.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045433_1611906873845.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"버터 40g\",\"박력분 90g\",\"강력분 90g\",\"미숫가루 70g\",\"베이킹파우더 10g\",\"우유 66g\",\"달걀 50g(1개)\",\"건크랜베리 20g\",\"호두 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕을 빼고 건크랜베리를 첨가함으로써 자연스러운 단맛을 느끼도록 했어요.\",\"instructions\":[\"1. 체 친 강력분, 박력분, 미숫가루, 베이킹파우더와 버터를 카드를 이용해 잘게 잘라 섞는다.\\n★ 자르듯이 섞어야 글루텐이 생기는 것을 최소화 해, 바삭한 질감을 얻을 수 있어요.\",\"2. 계란과 우유를 섞어 넣고 카드로 잘라 주듯이 섞는다.\",\"3. 가루가 약간 보일 때쯤 건크랜베리와 호두를 넣어 같이 반죽한다.\",\"4. 뭉쳐진 반죽을 비닐에 싸서 냉장고에서 1시간 이상 휴지시킨다.\",\"5. 휴지시킨 반죽을 밀대로 밀어주고 여러 겹 쌓이도록 3접절이를 5회 정도 해준 후 카드로 일정하게 자른다.\",\"6. 오븐팬에 놓고 겉면 코팅을 위해 계란물을 얇게 발라준 후 180℃로 예열된 오븐에서 20분 정도 굽는다.\"]},{\"id\":\"k577\",\"title\":\"고구마 공갈빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053118_1612254678493.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053150_1612254710865.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053215_1612254735930.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053235_1612254755179.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053253_1612254773238.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053306_1612254786183.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053322_1612254802225.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 300g\",\"이스트 6g\",\"소금 4g\",\"버터 10g\",\"물 170ml\",\"(속재료) 고구마 3~4개\",\"우유20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마와 우유를 섞어 식재료의 본연의 단맛을 이용한 무스를 사용했어요.\",\"instructions\":[\"1. (속재료) 고구마를 삶아서 껍질을 제거하고 우유를 넣어가며 으깨서 부드러운 무스 상태로 만든다.\\n★ 고구마를 물에 삶으면 수분이 많아 우유량을 조절해야 해요.\",\"2. 버터를 제외한 모든 반죽 재료를 넣고 클린업 단계까지 믹싱하다가 버터를 넣어 최종단계까지 믹싱한다.\",\"3. 반죽은 처음 부피의 2배 정도 되도록 1차 발효하여 50g씩 분할하여 둥글리기 한 다음 중간 발효(10-15분)한다.\",\"4. 중간 발효가 끝난 반죽은 납작하게 펴고 만들어 놓은 고구마무스를 넣어 동그란 모양으로 일정하게 만든 후 팬닝한다.\",\"5. 팬닝된 반죽을 호떡처럼 윗면을 살짝 눌러준다.\",\"6. 190℃에서 15분 정도 굽는다.\"]},{\"id\":\"k578\",\"title\":\"검은콩 크림빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053932_1612255172900.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054408_1612255448952.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054429_1612255469984.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054447_1612255487980.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054500_1612255500326.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054517_1612255517207.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054528_1612255528253.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료)강력분 300g\",\"물 250ml\",\"이스트 8g\",\"호밀가루 50g\",\"검은콩가루 24g\",\"올리브유 4g\",\"호두 50g\",\"크랜베리 24g\",\"(속재료) 불린 검은콩 300g\",\"우유 200g\",\"달걀 50g(1개)\",\"소금 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"검은콩을 끓여 자체에서 나오는 본연의 단맛을 이용한 검은콩 크림을 만들었어요.\",\"instructions\":[\"1. (속재료) 물에 불린 검은 콩을 30-40분 정도 삶은 다음 콩과 물을 분리시켜 식힌다. 식은 검은콩에 우유, 계란, 소금을 넣고 믹서에 갈고 끓여 검은콩 크림을 만든다. 이때 검은콩 물로 농도를 맞춘다.\",\"2. 호두, 크랜베리를 제외한 모든 재료를 섞어 한 덩어리가 되면 호두와 크랜베리를 넣어 밖으로 빠져 나오지 않게 잘 넣어가며 반죽한다.\",\"3. 처음 부피의 2배 정도 부풀게 1차 발효를 하고 발효가 끝나면 반죽을 6개로 분할하여 둥글리기하여 중간 발효한다.\",\"4. 중간 발효한 반죽을 공기를 빼주고 양끝을 접어 바게트 모양으로 만들어 주고 팬에 3개씩 팬닝한다.\",\"5. \\\"윗불 180℃, 아랫불 160℃에서 약 20-30분정도 구워 준 뒤 냉각팬에 옮겨 식힌다.\\n★팬에 크기에 따라 2회로 나눠 구워요.\\\"\",\"6. 식은 빵을 반으로 갈라 검은콩크림을 넣는다.\"]},{\"id\":\"k579\",\"title\":\"오이 소르베\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044201_1670485321757.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310014954_1615351794762.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015030_1615351830012.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015044_1615351844635.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015101_1615351861230.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015116_1615351876244.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오이(100g)\",\"셀러리 줄기(15g)\",\"요거트(60g)\",\"과일(20g)\",\"라임즙(5g)\",\"아가베 시럽(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 오이와 셀러리를 사용하여 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 오이는 껍질을 제거한 뒤 큼직하게 썰고, 셀러리는 필러로 겉껍질을 벗겨 큼직하게 썬다.\",\"2. 손질한 오이와 셀러리에 양념을 넣어 믹서에 곱게 간다.\",\"3. 면포에 간 오이와 셀러리를 부은 뒤 즙만 짠다.\",\"4. 오이셀러리 즙을 밀폐 용기에 넣어 냉동실에서 3시간 이상 얼린다.\",\"5. 요거트에 얼린 오이소르베를 얹고 과일을 곁들인다.\"]},{\"id\":\"k580\",\"title\":\"리코타치즈 카프레제\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040853_1615360133030.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310043002_1615361402358.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310043015_1615361415513.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310043032_1615361432098.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310043047_1615361447877.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310043127_1615361487055.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"방울토마토(100g)\",\"우유(370㎖)\",\"레몬즙(20g)\",\"발사믹식초(10g)\",\"레몬즙(1g)\",\"올리브유(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨 함량이 높은 토마토는 나트륨 배출에 도움을 줘요.\\n직접 만든 리코타치즈를 사용하면 짜지 않고 고소한 맛을 낼 수 있어요.\",\"instructions\":[\"1. 냄비에 우유(370㎖)를 넣어 센 불로 올린 뒤 가장자리가 끓어오르면 레몬즙(20g)을 넣어 몽글해질 때까지 젓는다.\",\"2. 물에 적신 면포에 끓인 우유를 넣고 물기를 제거해 리코타치즈를 만든다.\",\"3. 냄비에 발사믹식초(10g), 레몬즙(1g)을 넣어 2분간 끓이다가 올리브유(10g)를 넣어 섞은 뒤 불을 꺼 발사믹 드레싱을 만든다.\",\"4. 방울토마토는 반으로 썰고, 굳힌 리코타치즈는 한입 크기로 만든다.\",\"5. 그릇에 방울토마토와 리코타치즈를 올리고 발사믹 드레싱을 뿌린다.\"]},{\"id\":\"k581\",\"title\":\"연두부 카프레제\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310045858_1615363138551.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310045937_1615363177782.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310045950_1615363190842.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310050005_1615363205237.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310050018_1615363218140.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310050040_1615363240253.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310050054_1615363254074.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"깻잎(2장)\",\"양파(20g)\",\"방울토마토(5개=50g)\",\"연두부(100g)\",\"두부(100g)\",\"다진 마늘(10g)\",\"치즈(40g)\",\"간장(8g)\",\"올리브유(30g)\",\"참기름(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"으깬 두부, 고소한 치즈, 상큼한 토마토의 조합이 끝내줘요.\",\"instructions\":[\"1. 방울토마토는 3등분하고, 깻잎과 양파는 곱게 다진다.\",\"2. 연두부와 두부를 크림 형태가 될 때까지 으깬다.\",\"3. 다진 깻잎과 양파에 깻잎 드레싱 재료를 넣어 고루 섞는다.\",\"4. 중간 불로 달군 팬에 다진 마늘을 볶아 마늘 플레이크를 만든다.\",\"5. 그릇에 연두부 크림과 방울토마토, 치즈를 올린다.\",\"6. 깻잎 드레싱을 뿌리고 마늘 플레이크를 올려 마무리한다.\"]},{\"id\":\"k582\",\"title\":\"연두부 토마토\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeNsKgD-bA\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeNsKgD-gY\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeNsKgD-ib\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeNsKgD-jc\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeNsKgD-ki\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeNsKgD-n6\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연두부(70g)\",\"방울토마토(6~7개=50g)\",\"스트링치즈(40g)\",\"어린잎채소(약간)\",\"발사믹식초(5g)\",\"사과(150g)\",\"사과주스(50g)\",\"플레인 요거트(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과드레싱의 상큼함과 발사믹식초의 시큼함을 더해 싱거운 맛을 보완했어요.\",\"instructions\":[\"1. 믹서에 사과와 사과주스를 넣고 곱게 간 뒤 플레인 요거트를 섞어 사과드레싱을 만든다.\",\"2. 연두부는 9cm 크기로 썬 뒤 중앙 부분을 파낸다.\",\"3. 방울토마토와 스트링치즈는 굵게 다진 뒤 사과드레싱에 버무린다.\",\"4. 버무려진 방울토마토와 스트링치즈로 연두부 속을 채운 뒤 사과드레싱을 올린다.\",\"5. 그릇에 발사믹 식초를 바른 뒤 속 채운 연두부를 올리고 어린잎채소를 곁들인다.\"]},{\"id\":\"k583\",\"title\":\"들깨삼겹살과 참외쌈장\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9W9R\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqqO\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqoi\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqsS\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqvO\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqz_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJer0H\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 삼겹살(200g)\",\"참외(중간 크기 1개)\",\"영양부추(50g)\",\"들깻가루(3Ts)\",\"마늘(5쪽)\",\"통후추(1ts)\",\"저염 된장(3Ts)\",\"다진 양파(2ts)\",\"다진 마늘(1ts)\",\"참깨(1Ts)\",\"참기름(2Ts)\",\"다진 청고추(1ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•나트륨 배출에 도움을 주는 칼륨이 풍부한 참외, 영양부추, 견과류를 사용했어요.\\n•설탕 대신 사과즙을 사용하여 식재료 본연의 단맛을 내고 설탕의 사용을 줄였어요.\\n•들깻가루를 사용해 고소한 맛을 살렸어요.\",\"instructions\":[\"1. 냄비에 물(3컵)과 양념을 넣어 5분간 끓이고, 삼겹살을 넣어 중간 불로 15분간 끓인다.\",\"2. 참외(½개)는 껍질과 씨를 제거한 뒤 곱게 다진다.\",\"3. 다진 참외에 견과류와 저염쌈장 재료를 넣어 고루 섞는다.\",\"4. 영양부추는 한입 크기로 자르고, 참외(½개)는 씨를 제거한다.\",\"5. 그릇에 영양부추를 깔고, 삼겹살을 가지런히 올린다.\",\"6. 씨를 제거한 참외에 참외 저염쌈장을 담아 마무리한다.\"]},{\"id\":\"k584\",\"title\":\"돼지고기 포두부 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9XCr\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerz2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJes0h\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJes2i\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJes5M\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJes81\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJesA7\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(½개)\",\"마늘(6~7쪽)\",\"대파(1대)\",\"다진 돼지고기(400g)\",\"두부면(2팩=200g)\",\"새우(¾컵)\",\"닭육수(5컵)\",\"청양고추(2개)\",\"고추장(0.5Ts)\",\"후춧가루(0.8Ts)\",\"식초(1.5Ts)\",\"올리브유(10Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•조미료 대신 마늘, 대파, 건새우, 닭육수가 감칠맛을 살리고, 청양고추의 칼칼한 맛으로 느끼함을 잡았어요.\",\"instructions\":[\"1. 양파는 3mm 두께로 채 썰고, 마늘은 납작 썰고, 대파와 청양고추는 어슷 썬다.\",\"2. 다진 돼지고기에 고추장과 후춧가루 (0.3Ts)를 넣어 고루 섞은 뒤 10분간 재운다.\",\"3. 중간 불로 달군 팬에 올리브유(3Ts)를 두르고, 다진 돼지고기와 고춧가루를 넣어 돼지고기의 겉면이 하얗게 변할 때까지 볶는다.\",\"4. 올리브유(7Ts)에 납작 썬 마늘, 대파, 양파, 건새우, 후춧가루(0.3Ts)를 넣고 마늘이 노릇해질 때까지 볶는다.\",\"5. 두부면과 닭육수(½컵)를 넣은 뒤 육수가 졸아들 때까지 볶고, 후춧가루(0.2Ts)와 청양고추를 넣어 1분간 볶는다.\",\"6. 그릇에 담고 볶은 돼지고기와 식초에 재운 양파를 곁들여 마무리한다.\"]},{\"id\":\"k585\",\"title\":\"단호박 양파잼 샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9l5l\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rpu\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rrh\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rtd\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rwa\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9r_F\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9s1c\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(3개)\",\"미니 단호박(2개)\",\"삶은 달걀(3개)\",\"우유(½컵)\",\"식빵(4장)\",\"슬라이스 체더치즈(2장)\",\"말린 자두(½컵)\",\"청상추(2장)\",\"아몬드 슬라이스(⅓컵)\",\"화이트와인(⅓컵)\",\"꿀(2Ts)\",\"소금(0.3Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 우유는 나트륨 배출에 도움을 줘요.\\n•단호박과 양파를 구워 단맛을 내고 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 양파는 얇게 채 썰고, 단호박은 껍질과 씨를 제거한 뒤 큼직하게 썰고, 말린 자두는 굵게 다지고, 청상추는 깨끗하게 씻는다.\",\"2. 종이포일 위에 단호박을 올리고, 식용유(1Ts)를 두른 뒤 180℃로 예열한 오븐에서 15분간 구워 꺼내고, 삶은 달걀의 노른자는 체에 거르고, 흰자는 곱게 다진다.\",\"3. 중간 불로 달군 팬에 식용유(2Ts)를 두르고, 화이트와인을 조금씩 넣으며 양파가 갈색이 될 때까지 볶아 양파잼을 만든다.\",\"4. 구운 단호박은 한 김 식힌 뒤 체에 곱게 거르고, 달걀노른자, 흰자, 우유, 꿀, 소금, 후춧가루를 넣어 고루 섞어 단호박샐러드를 만든다.\",\"5. 약한 불로 달군 마른 팬에 아몬드 슬라이스를 넣어 노릇하게 볶는다.\",\"6. 식빵(1장)에 단호박샐러드, 청상추, 슬라이스 체더치즈를 올리고, 다른 식빵(1장)에 양파잼을 넉넉하게 바른 뒤 덮고, 삼각형으로 잘라 마무리한다.\"]},{\"id\":\"k586\",\"title\":\"시금치크림치즈 빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054852_1612255732266.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202055110_1612255870085.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202055131_1612255891255.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202055147_1612255907202.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202055204_1612255924726.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202055220_1612255940312.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202055232_1612255952835.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 통밀가루 50g\",\"강력분 200g\",\"인스턴트 드라이 이스트 3g\",\"사과종 45ml\",\"물 120ml\",\"소금 2g\",\"달걀 50g(1개)\",\"올리브유 15g\",\"시금치 소량\",\"말린 방울토마토 4~5개\",\"(속재료) 시금치 50g\",\"다진 마늘 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"말린 방울토마토의 풍미가 시금치와 어우러져 단맛 없이도 맛있게 즐기게 했어요.\\n사과종은 사과주스로 대체하고 계량제를 5g 더 넣어주세요.\",\"instructions\":[\"1. (속재료) 시금치, 다진 마늘, 볶은 참깨, 올리브유, 소금, 후추를 블랜더로 갈아 시금치 페스토를 만들고 크림치즈와 섞는다.\",\"2. 물, 계란, 소금, 올리브유, 사과종, 드라이 이스트와 체 친 가루류를 넣고 한 덩이가 되도록 반죽한 뒤 시금치를 작게 잘라 넣어 섞는다.\",\"3. 매끈한 반죽이 되면 8등분 하여 둥글리기를 하고 15분간 중간 발효한다.\",\"4. 중간 발효가 끝난 반죽을 납작하게 펴고 안에 시금치 필링을 넣어 잘 봉합한 뒤 팬에 놓고 살짝 눌러준다.\",\"5. \\\"중앙에 말린 방울토마토를 얹어 30분간 2차 발효 한다.\\n★방울토마토를 반으로 잘라 100℃ 오븐에 1시간 구워 사용했어요.\\\"\",\"6. 180℃로 예열한 오븐에 15분간 굽는다.\"]},{\"id\":\"k587\",\"title\":\"무말랭이김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105718_1554688638823.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105748_1554688668379.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105802_1554688682362.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105817_1554688697222.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105829_1554688709434.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105845_1554688725794.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105908_1554688748550.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"무말랭이 10g\",\"식초 30g\",\"설탕 25g\",\"레몬 8g\",\"당근 5g\",\"오이 5g\",\"피클링스파이스 5g\",\"물 100g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금에 절인 김치와 다르게 말린 무말랭이로 식감을 주고 식초와 설탕, 피클링스파이스로 나트륨이 적고 상큼하고 개운한 맛의 김치를 만들 수 있어요.\",\"instructions\":[\"1. 무말랭이를 물에 불린다.\",\"2. 식초, 설탕, 피클링스파이스, 물을 넣고 끓인다.\",\"3. 끓인 물을 식힌다.\",\"4. 레몬, 당근, 오이를 적당한 크기로 자른다.\",\"5. 4를 3에 넣어 하루 이상 숙성시킨다.\",\"6. 보기 좋게 담는다.\"]},{\"id\":\"k588\",\"title\":\"코울슬로샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020951_1678252191936.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021041_1678252241713.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021059_1678252259020.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021116_1678252276743.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021131_1678252291785.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021149_1678252309018.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021206_1678252326603.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 양배추(30g)\",\"양파(10g)\",\"적파프리카(3g)\",\"청피망(3g)\",\"•마요네즈드레싱 : 마요네즈(5g)\",\"설탕(1g)\",\"식초(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•마요네즈와 식초로 새콤하게 무쳐내 싱거운 맛을 보완했어요.\",\"instructions\":[\"1. 양배추와 양파, 적파프리카, 청피망을 깨끗이 씻는다.\",\"2. 양배추와 양파를 잘게 썬다.\",\"3. 적파프리카와 청피망은 씨를 제거하고 잘게 썬다.\",\"4. 마요네즈드레싱 재료를 고루 섞는다.\",\"5. 볼에 썰어둔 채소를 담는다.\",\"6. 마요네즈드레싱을 넣고 버무려 마무리한다.\"]},{\"id\":\"k589\",\"title\":\"마들깨미역국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012227_1583727747787.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309011456_1583727296779.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309011511_1583727311369.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309011526_1583727326418.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309011541_1583727341360.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309011558_1583727358377.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309011616_1583727376885.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"건미역 4g\",\"마 40g\",\"깐들깨가루 17g\",\"건다시마 1g\",\"참기름 2.5g\",\"마늘 2.5g\",\"물 300ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"들깨가루의 고소한 맛으로 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 다시 육수를 만들어 준다.\",\"2. 건미역은 불려 잘게 썰어준다.\",\"3. 마는 껍질을 제거한 후 깍둑 썰기하여 준비한다.\",\"4. 참기름을 두르고 미역과 마늘을 볶다가 육수를 부어 끓인다.\",\"5. 끓어오른 미역국에 마를 넣어 익혀준다.\",\"6. 들깨가루를 넣어 한소끔 끓여낸다.\"]},{\"id\":\"k590\",\"title\":\"바지락맑은국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040515_1678172715096.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040624_1678172784168.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040643_1678172803395.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040657_1678172817753.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040722_1678172842284.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040737_1678172857705.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040756_1678172876846.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 바지락(60g)\",\"팽이버섯(20g)\",\"홍고추(5g)\",\"쑥갓(2g)\",\"•육수 : 다시마(5g)\",\"청양고추(3g)\",\"무(10g)\",\"대파(5g)\",\"물(300g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•향신채소인 홍고추와 쑥갓을 이용해서 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 물에 다시마, 청양고추, 대파, 한 입 크기로 썬 무를 넣고 끓인다.\",\"2. 육수가 끓으면 청양고추와 다시마를 건진다.\",\"3. 해감한 바지락을 넣고 끓인다.\",\"4. 팽이버섯은 밑동을 자른 뒤 적당히 가르고, 홍고추는 어슷 썰고, 쑥갓은 먹기 좋은 크기로 썬다.\",\"5. 국에 팽이버섯을 넣고 끓인다.\",\"6. 홍고추와 쑥갓을 넣고 마무리한다.\"]},{\"id\":\"k591\",\"title\":\"통배추 겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313025524_1678686924073.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308034925_1678258165215.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308034938_1678258178466.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308034951_1678258191967.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308035008_1678258208586.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308035026_1678258226333.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308035048_1678258248316.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 통배추(25g)\",\"쪽파(1g)\",\"마늘(1g)\",\"생강(0.5g)\",\"•양념 : 소금(0.1g)\",\"홍시(1g)\",\"고춧가루(1g)\",\"젓갈(1g)\",\"통깨(1g)\",\"참기름(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•달콤한 홍시를 사용하여 소금 사용량을 줄였어요.\",\"instructions\":[\"1. 배추는 연한 잎으로 골라 한 장씩 떼어 길게 갈라놓는다.\",\"2. 배추에 소금을 뿌려 절인다.\",\"3. 쪽파는 4cm 길이로 썰고, 마늘과 생강은 다진다.\",\"4. 고춧가루에 홍시를 으깨서 나머지 양념을 섞는다.\",\"5. 물기를 제거한 배추에 고춧가루 양념을 넣고 무친다.\",\"6. 쪽파, 통깨, 참기름을 넣고 마무리한다.\"]},{\"id\":\"k592\",\"title\":\"포니언 스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313030603_1678687563726.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309095425_1678323265283.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309100820_1678324100273.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309101704_1678324624935.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309101739_1678324659988.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309101758_1678324678108.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309101817_1678324697234.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 감자(100g)\",\"양파(40g)\",\"우유(30g)\",\"시판 크루통(7g)\",\"파슬리가루(1g)\",\"•양념 : 버터(5g)\",\"소금(0.3g)\",\"후춧가루(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•육수 대신 채소와 우유만으로 담백하게 끓여 나트륨 함량을 줄였어요.\\n•허브, 통후추 등의 향신 재료로 저염수프를 더 맛있게 만들 수 있어요.\",\"instructions\":[\"1. 감자는 슬라이스하고, 양파는 채 썬다.\",\"2. 끓는 물(5컵)에 감자를 넣어 7분간 삶아 건진다.\",\"3. 중간 불로 달군 팬에 버터를 두른 뒤 양파를 넣어 3~5분간 볶아 꺼낸다.\",\"4. 믹서에 삶은 감자와 양파, 우유를 넣어 곱게 간다.\",\"5. 냄비에 믹서에 간 재료들을 넣어 약한 불로 3분간 끓여 농도를 맞춘다.\",\"6. 소금과 후춧가루로 간을 맞춘 뒤 시판 크루통과 파슬리가루를 올린다.\"]},{\"id\":\"k593\",\"title\":\"가지 탕수육\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF8rC\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF8vs\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF8x5\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9Vs\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9WP\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9XR\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9X_\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(70g)\",\"두부(50g)\",\"아삭이고추(30g)\",\"가지(60g)\",\"식용유(100ml)\",\"소금(0.3g)\",\"후춧가루(0.2g)\",\"간장(20g)\",\"올리고당(30g)\",\"식초(10g)\",\"전분(10g)\",\"튀김가루(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"가지는 칼로리가 낮고 수분이 많으며, 칼륨이 풍부하여 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 돼지고기, 두부, 아삭이고추는 잘게 다지고, 가지는 어슷하게 4등분해 가운데 칼집을 넣는다.\",\"2. 다진 돼지고기는 밑간한 뒤 다진 두부, 고추를 넣어 섞는다.\",\"3. 칼집을 넣은 가지에 밑간한 돼지고기를 채운 뒤 튀김가루를 묻힌다.\",\"4. 튀김가루를 묻힌 가지는 180℃로 예열한 식용유(100㎖)에 7~8분간 두 번 튀긴다.\",\"5. 냄비에 가지소스 재료와 물(100㎖)을 넣어 4분간 끓인다.\",\"6. 그릇에 튀긴 가지를 얹고 가지소스를 뿌린다.\"]},{\"id\":\"k594\",\"title\":\"토마토소스 애호박냉파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9bhk\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9o8W\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oHo\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oMi\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oOP\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oQM\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oSV\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 토마토(2개)\",\"참외(1개)\",\"오이(1개)\",\"양파(½개)\",\"마늘(3쪽)\",\"애호박(1개)\",\"바질잎(4장)\",\"블랙올리브 파우더(약간)\",\"레몬즙(1Ts)\",\"올리브유(5Ts)\",\"소금(0.4Ts)\",\"페페론치노(0.3Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 토마토, 참외, 애호박은 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 토마토는 꼭지를 제거하고, 열십자로 칼집을 낸 뒤 끓는 물에 30초간 데쳐 건지고, 껍질을 제거해 한입 크기로 썬다.\",\"2. 참외는 깨끗하게 씻어 2등분해 씨를 제거한 뒤 한입 크기로 썰고, 오이와 양파는 한입 크기로 썰고, 마늘은 꼭지를 제거한 뒤 4등분한다.\",\"3. 애호박은 스파이럴라이저로 썰고, 끓는 물에 30초간 데쳐 건진 뒤 한 김 식히고, 레몬즙(1Ts), 올리브유(2Ts), 소금(0.1Ts)에 버무린다.\",\"4. 믹서에 토마토, 오이, 참외, 양파, 마늘, 바질잎(3장), 페페론치노, 차가운 물(½컵)을 넣어 곱게 갈아 토마토소스를 만든다.\",\"5. 저염 간장, 식초, 꿀, 올리브유(3Ts), 소금(0.3Ts)을 넣어 한 번 더 곱게 간다.\",\"6. 그릇에 애호박면과 토마토소스를 담고, 바질잎(1장)과 블랙올리브 파우더를 뿌려 마무리한다.\"]},{\"id\":\"k595\",\"title\":\"새우채소 김치롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nfC\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sm8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sq2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9srT\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9stx\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9swQ\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9syw\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 김치(¼포기)\",\"오이(1개)\",\"파프리카(노랑\",\"빨강 각 1개)\",\"깻잎(5장)\",\"새우(2마리)\",\"달걀물(2개 분량)\",\"무순(⅓줌)\",\"크래미(2줄)\",\"식용유(0.3ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•김치를 물에 담그고, 크래미 및 새우를 물에 데치면 나트륨 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 김치는 깨끗하게 씻어 찬물에 30분간 담근 뒤 건져내고, 물기를 꼭 짠 뒤 윗동을 약간 자른다.\",\"2. 오이와 파프리카는 5cm 길이로 채 썰고, 깻잎과 무순은 깨끗하게 씻어 물기를 빼고, 크래미는 낱낱이 가른다.\",\"3. 새우는 껍질을 벗기고, 끓는 물에 익을 때까지 데쳤다 건져 길게 2등분한다.\",\"4. 약한 불로 달군 팬에 식용유를 두르고, 달걀물을 부어 지단을 부친다.\",\"5. 김발에 김치를 한 장씩 겹쳐 넓게 펼친다.\",\"6. 김치 위에 지단, 손질한 채소, 새우를 올리고, 돌돌 말아 한입 크기로 썰어 마무리한다.\"]},{\"id\":\"k596\",\"title\":\"떡순이 두부쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106030518_1699250718775.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106030827_1699250907733.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106030852_1699250932232.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106030913_1699250953533.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106030933_1699250973778.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106030954_1699250994075.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106031013_1699251013014.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [가정 간편식 재료] 누들 떡볶이 떡(20개\",\"130g)\",\"소고기 양지(110g)\",\"어묵(1장\",\"40g)\",\"양배추(60g)\",\"떡볶이양념파우더(30g)<br>\",\"• [추가 재료] 쌈두부(100g)\",\"부추(10g)\",\"파프리카(빨간색\",\"노란색 각 30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 가정 간편식의 떡볶이양념파우더를 소량 사용하여 나트륨과 당류 사용량을 줄였어요.<br>\\n\\n• 떡볶이 소스는 뿌리지 않고 찍어 먹도록 하여 나트륨 섭취량을 줄였어요.\",\"instructions\":[\"1. 양배추, 어묵, 파프리카를 길게 썰고 부추는 한번 데친다.\",\"2. 팬에 식용유를 살짝 두르고 어묵을 볶아 꺼내고, 같은 팬에 소고기 양지를 구워 준비한다.\",\"3. 냄비에 물과 누들 떡볶이 떡을 넣어 끓이고 떡이 익으면 건져낸다.\",\"4. 떡볶이양념파우더를 넣고 조려서 떡볶이 소스를 만든다.\",\"5. 쌈두부를 깔고 조리한 소고기 양지, 떡과 손질한 어묵, 파프리카, 양배추를 올린 후 싸서 데친 부추로 묶는다.\",\"6. 떡볶이 소스를 곁들여 마무리한다.\"]},{\"id\":\"k597\",\"title\":\"두부샐러드 메밀김밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040351_1699254231703.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040418_1699254258267.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040433_1699254273087.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040451_1699254291704.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040505_1699254305675.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040520_1699254320600.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040536_1699254336718.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [간편식 재료] 메밀면(생면\",\"166g)\",\"오이(55g)\",\"양파(42g)\",\"당근(25g)\",\"족발(200g)\",\"달걀지단(20g)<br>\",\"• [추가 재료] 양배추(50g)\",\"사과(1/4개=60g)\",\"깻잎(15g)\",\"리코타 치즈(60g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 레몬청 과육을 활용한 소스를 직접 만들어 나트륨 사용량을 줄였어요.\\n<br>• 사과, 레몬청 과육을 사용하여 설탕 대신 과일의 단맛을 활용했어요.\",\"instructions\":[\"1. 당근, 양파, 깻잎은 깨끗이 씻고, 오이, 양배추, 사과는 채 썬다.\",\"2. 리코타 치즈, 연두부, 다진 레몬청 과육을 섞어 소스를 만들고 양배추, 사과와 함께 버무려 두부 리코타 샐러드를 만든다.\",\"3. 메밀면을 4분간 삶아 물기를 제거한 후 참기름, 간장을 넣어 버무린다.\",\"4. 족발은 전자레인지에 1분간 돌리고 채 썰어 준비한다.\",\"5. 김을 깔고 양념한 메밀면 → 깻잎 → 오이 → 당근 → 양파 → 두부 리코타 샐러드 → 족발 순서로 올려 말아 김밥을 만든다.\",\"6. 김밥을 먹기 좋은 크기로 썰고 달걀지단을 올려 마무리한다.\"]},{\"id\":\"k598\",\"title\":\"토마토채소스프와 연어소바찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6ZH\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6bP\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6cT\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6dK\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6e1\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6fe\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6ha\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토(356g)\",\"무(6g)\",\"당근(6g)\",\"마늘(5g)\",\"양파(6g)\",\"연어(100g)\",\"메밀면(70g)\",\"월계수잎(2g)\",\"소금(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨 함량이 높은 토마토는 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 토마토(100g)와 무, 당근, 마늘, 양파는 작게 썰고, 연어는 길게 2장으로 포를 뜬다.\",\"2. 믹서에 토마토(250g)를 넣어 간 뒤 체에 걸러 월계수잎과 함께 3분간 졸인다.\",\"3. 졸인 토마토에 작게 썬 토마토와 무, 당근, 마늘, 양파, 소금을 넣어 1분간 볶다가 물(250㎖)을 넣고 5분간 끓인다.\",\"4. 끓는 물(800㎖)에 메밀면을 넣어 4분간 삶아 찬물에 헹군 뒤 포 뜬 연어에 돌돌만다.\",\"5. 면포 깐 찜기에 김이 오르면 메밀면을 감싼 연어를 넣어 3분간 찐다.\",\"6. 그릇에 토마토채소스프와 연어소바찜을 담아 마무리한다.\"]},{\"id\":\"k599\",\"title\":\"참나물무말이 물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF29h\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF2Bk\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF2CH\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF2D8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF2Dh\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF2FU\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF2F_\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"참나물(30g)\",\"무(20g)\",\"레몬(1개)\",\"설탕(10g)\",\"사과식초(20g)\",\"물(20㎖)\",\"사과식초(15g)\",\"마늘(2쪽)\",\"홍고추(1개)\",\"사과(½개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"식초를 사용하여 맛에 새콤함을 주어 나트륨의 사용을 줄였어요.\",\"instructions\":[\"1. 끓는 물(500㎖)에 참나물 줄기를 1분간 데쳐 건진 뒤 찬물에 헹군다.\",\"2. 무는 둥근 모양을 살려 얇게 썰고, 참나물 잎은 얇게 채 썰고, 레몬은 강판에 갈아 제스트를 만든다.\",\"3. 냄비에 절임물 재료와 물(40㎖)을 넣어 2분간 끓인 뒤 손질한 무를 넣어 30분간 절인다.\",\"4. 믹서에 김칫국물 재료를 넣어 간 뒤 고운체에 거른다.\",\"5. 절인 무에 채 썬 참나물 잎을 올려 돌돌 말고 데친 참나물 줄기로 묶는다.\",\"6. 그릇에 무말이와 김칫국물을 담은 뒤 레몬 제스트를 뿌린다.\"]},{\"id\":\"k600\",\"title\":\"소고기 무국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110212_1554688932975.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110245_1554688965153.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110256_1554688976342.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110314_1554688994479.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110333_1554689013380.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110349_1554689029367.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110416_1554689056305.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기 14g\",\"무 15g\",\"파 3g\",\"느타리버섯 5g\",\"숙주 5g\",\"저염간장 10g\",\"물 150g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"물과 간장을 1:1 비율로 섞고 야채를 넣어 끓인 뒤 식혀 만든 저염간장으로 나트륨을 줄여요.\",\"instructions\":[\"1. 소고기를 먹기 좋은 크기로 썬다.\",\"2. 무를 한입 크기로 썬다.\",\"3. 냄비에 참기름을 두르고 고기의 핏기가 없어질 때 까지 볶는다.\",\"4. 고기가 익으면 무를 넣고 투명해질 때 까지 볶는다.\",\"5. 중불에서 물을 붓고 끓으면 느타리버섯을 넣는다.\",\"6. 숙주나물과 파를 넣고 한소끔 끓이고 저염간장과 고춧가루를 넣는다.\"]},{\"id\":\"k601\",\"title\":\"매운락교무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033105_1678343465526.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033140_1678343500923.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033154_1678343514252.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033209_1678343529259.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033225_1678343545046.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033240_1678343560254.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309033255_1678343575206.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 락교(30g)\",\"쪽파(2g)\",\"마늘(0.1g)\",\"•양념장 : 고춧가루(0.3g)\",\"설탕(0.3g)\",\"참기름(0.1g)\",\"참깨(0.1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•락교를 한 번 헹궈 짠맛을 제거했어요.\\n•고춧가루로 매운맛을 더해 맛을 냈어요.\",\"instructions\":[\"1. 락교는 물에 헹군다.\",\"2. 락교의 물기를 제거한다.\",\"3. 쪽파는 송송 썬다.\",\"4. 마늘은 곱게 다진다.\",\"5. 양념장을 만든다.\",\"6. 락교와 쪽파, 다진마늘에 양념장을 골고루 버무려 마무리한다.\"]},{\"id\":\"k602\",\"title\":\"채소초밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014740_1554871660142.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014837_1554871717060.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014850_1554871730740.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014907_1554871747506.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014921_1554871761267.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014936_1554871776283.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410014952_1554871792524.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 40g\",\"현미 30g\",\"현미찹쌀 5g\",\"애호박 20g\",\"새송이버섯 20g\",\"우엉 20g\",\"적파프리카 15g\",\"황파프리카 15g\",\"주황파프리카 15g\",\"식초 2.5g\",\"설탕 2g\",\"파래김 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"레몬을 넣어 상큼하게 만든 배합초로 다른 양념 없이도 맛있게 먹을 수 있어요.\",\"instructions\":[\"1. 쌀, 현미, 현미찹쌀은 물에 불린 뒤 고슬고슬하게 밥을 짓는다.\",\"2. 분량의 식초, 설탕, 다시마, 레몬, 미향을 넣고 초밥용 배합초를 만들어 밥과 섞는다.\",\"3. 우엉은 0.5cm 두께로 슬라이스 한 뒤 끓는 물에 데쳐 팬에 굽는다.\",\"4. 애호박, 파프리카는 초밥 크기로 썰어 소금물에 절인 뒤 팬에 굽는다.\",\"5. 밥을 초밥모양으로 길쭉하게 만든 뒤 파프리카, 우엉, 버섯, 애호박을 올려 초밥을 만든다.\",\"6. 길게 썬 파래김으로 채소가 고정되도록 밥을 감싼다.\"]},{\"id\":\"k603\",\"title\":\"꽃게바지락찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306045438_1583481278124.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306053922_1583483962652.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306053935_1583483975676.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306053956_1583483996477.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054008_1583484008134.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054020_1583484020856.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054033_1583484033498.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"꽃게 8.2g\",\"바지락 4g\",\"조선무 11.3g\",\"깐양파 5g\",\"애호박 9.2g\",\"두절콩나물 5.3g\",\"국멸치 1.3g\",\"건다시마 0.3g\",\"깐대파 2g\",\"국간장 1.4g\",\"고춧가루 0.6g\",\"된장 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바지락, 꽃게가 가진 유기산과 천연의 단맛을 이용해 염도를 낮췄어요.\",\"instructions\":[\"1. 국멸치, 건다시마로 육수를 낸다.\",\"2. 꽃게는 먹기 좋은 크기로 손질하고, 바지락은 해감하여 준비한다.\",\"3. 무는 나박썰기, 양파는 사각썰기, 애호박은 반달썰기, 파는 어슷썰기 한다.\",\"4. 콩나물은 거두절미 한다.\",\"5. 육수에 무, 꽃게, 바지락을 넣고 한소끔 끓인다.\",\"6. 콩나물, 양파, 애호박 대파를 넣고 끓이다 간을 맞춰 마무리한다.\"]},{\"id\":\"k604\",\"title\":\"새뱅이찌개\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309020630_1583730390527.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309021207_1583730727485.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309021225_1583730745128.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309021239_1583730759159.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309021253_1583730773903.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309021311_1583730791521.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309021328_1583730808428.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"물 300ml\",\"다시마 2g\",\"양파 15g\",\"새뱅이 30g\",\"밀가루 20g\",\"호박 10g\",\"무 10g\",\"청양고추 5g\",\"파10g\",\"마늘 5g\",\"쑥갓 5g\",\"고춧가루 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"채소를 이용하여 육수를 우려내면 소금 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 다시마, 양파와 물을 넣고 육수를 만든다.\",\"2. 새뱅이는 불순문을 제거하여 세척하고, 밀가루에 물을 넣어 손수제비 반죽을 한다.\",\"3. 무와 호박은 나박썰기, 고추와 파는 어슷썰기, 마늘은 다진다.\",\"4. 들기름 두른 냄비에 무, 고추장, 고춧가루를 볶다가 육수를 부워 끓인다.\",\"5. 새뱅이와 호박, 고추 마늘을 넣어 끓인다.\",\"6. 손수제비와 파를 넣고 간을 맞추고 마지막에 쑥갓을 올린다.\"]},{\"id\":\"k605\",\"title\":\"황태미역국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308030341_1678255421758.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308022118_1678252878938.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308024721_1678254441605.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308024737_1678254457626.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308024751_1678254471834.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308030228_1678255348132.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308030246_1678255366614.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 건미역(2g)\",\"황태(4g)\",\"•육수 : 황태머리(5g)\",\"다시마(1g)\",\"표고버섯(1g)\",\"대파(1g)\",\"물(250g)\",\"•양념 : 참기름(1g)\",\"다진마늘(1g)\",\"저염국간장(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨이 풍부한 미역을 식재료로 사용하고, 황태 및 채소를 통해 재료 본연의 맛을 살렸어요.\",\"instructions\":[\"1. 물과 육수 재료를 넣고 끓여 육수를 만든다.\",\"2. 끓인 육수를 체에 거른다.\",\"3. 건미역과 황태를 물에 불린 후, 먹기 좋은 크기로 썬다.\",\"4. 냄비에 참기름을 두르고 미역과 황태를 넣어 볶는다.\",\"5. 냄비에 육수를 넣고 끓인다\",\"6. 다진마늘과 저염국간장으로 간을 맞춰 마무리한다.\"]},{\"id\":\"k606\",\"title\":\"매실입은가지닭볶음탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313021810_1584076690447.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313012024_1584073224952.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313012040_1584073240770.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313012055_1584073255312.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313012150_1584073310501.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313012136_1584073296219.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313012205_1584073325331.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기 100g\",\"가지 30g\",\"매실엑기스 5g\",\"파 5g\",\"마늘2g\",\"대두유 3g\",\"간장 3g\",\"식초 2g\",\"미림 2g\",\"올리고당 2g\",\"참기름 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"간장에 졸이는 대신 소량의 간장소스로 살짝 볶아 맛을 냈어요.\",\"instructions\":[\"1. 닭과 가지는 먹기 좋은 사이즈로 토막 낸다.\",\"2. 다진파, 다진 마늘, 맛술, 참기름, 올리고당에 닭을 재운다.\",\"3. 매실엑기스, 간장, 식초, 다진마늘, 미림, 물을 섞어 소스를 만든다.\",\"4. 가지와 닭은 오븐에 구워준다.\",\"5. 구워진 닭과 가지를 매실소스에 버무린다.\",\"6. 팬에 소스 묻은 닭과 가지를 볶아 낸다.\"]},{\"id\":\"k607\",\"title\":\"홍시잼 식빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129012126_1611894086934.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023050_1611898250263.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023109_1611898269556.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023126_1611898286137.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023138_1611898298138.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023155_1611898315249.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129021437_1611897277148.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 500g\",\"인스턴트 이스트 5g\",\"소금 7g\",\"달걀 50g(1개)\",\"우유 250g\",\"포도씨유 50g\",\"(속재료) 홍시 1000g\",\"레몬즙 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"홍시와 레몬즙으로 만든 홍시 잼을 사용하여 당을 줄였어요.\",\"instructions\":[\"1. (속재료) 홍시는 껍질을 제거하고 체에 거른 다음 냄비에 레몬즙을 넣고 졸여서 잼을 만든다.\",\"2. 강력분, 소금, 인스던트 이스트를 먼저 섞다가 달걀, 포도씨유, 미지근하게 데운 우유를 넣어 가며 반죽한다.\\n★ 액체 온도가 60℃가 넘어가면 이스트가 죽을 수 있어 조심해 주세요.\",\"3. 완성된 반죽을 1~2시간동안 실온에서 1차 발효 시킨 후, 세 덩어리로 나누어 15분 정도 2차 발효한다.\",\"4. 반죽을 60g씩 8개의 덩어리로 만들어 밀대를 사용하여 피자도우처럼 얇게 편다.\",\"5. 얇게 핀 반죽 위에 홍시 잼을 바르고 그 위에 핀 반죽을 올리는 걸 반복한 후 맨 위에 홍시 잼을 바르지 않은 반죽을 올리고 소량의 포도씨유를 바른 큐브식빵 틀에 담는다.\",\"6. \\\"180도로 예열한 오븐에 식빵 틀을 넣고 40분정도 굽는다.\\n★ 윗 면의 색이 많이 나면 종이 호일을 덮고 속까지 익혀요.\\\"\"]},{\"id\":\"k608\",\"title\":\"콩가루 소보로\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112827_1612405707511.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112856_1612405736356.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112909_1612405749902.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112924_1612405764566.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112940_1612405780692.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112955_1612405795307.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204113008_1612405808117.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 320g\",\"날콩가루 80g\",\"따뜻한 우유 140ml\",\"이스트 8g\",\"달걀 2개\",\"코코넛 오일 20g\",\"소금 2g\",\"(비스킷재료) 박력 쌀가루 100g\",\"볶은 콩가루 60g\",\"베이킹파우더 2g\",\"달걀 2개\",\"버터 60g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"반죽과 비스킷에 설탕 대신 콩가루를 사용하여 당류를 줄이고, 크랜베리의 상큼함으로 맛을 더 했어요.\",\"instructions\":[\"1. (속재료) 찐 고구마에 우유, 다진 아몬드, 크랜베리를 넣어 섞는다.\\n★ 고구마를 물에 삶으면 수분이 많아 우유량을 조절해야 해요.\",\"2. (비스킷) 버터를 부드럽게 만들어 준 다음 볶은 콩가루와 소금을 넣고 섞다가 계란을 조금씩 넣어 분리되지 않게 반죽한다. 여기에 체 친 박력 쌀가루와 베이킹파우더를 넣어 섞어준 뒤 냉장고에 30분간 휴지시킨다.\",\"3. 코코넛 오일을 제외한 반죽 재료를 모두 반죽하다가 한 덩어리가 되면 코코넛 오일을 넣어 부드러워질 때까지 반죽한 다음 반죽의 크기가 두배가 될 때까지 발효한다. (약 1시간)\",\"4. 1차 발효 반죽은 30g씩 분할해 둥글리기 하고 중간 발효 (약 15분)한 다음 반죽 속 가스를 빼고 ①의 속재료를 40g씩 넣어 감싼다.\",\"5. 20g씩 비스킷을 분할해 비닐 위에 얇게 민 다음 비닐을 이용해 빵 반죽 위에 덮어준다.\\n★반죽이 비닐에 달라 붙으면 덧가루를 조금 뿌려요.\",\"6. 팬닝 후 2차 발효(약15분)를 하고 윗불 180℃ , 아랫불 160℃ 로 예열된 오븐에서 20분 굽는다.\"]},{\"id\":\"k609\",\"title\":\"곤약 가스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210113042_1612924242867.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210113133_1612924293965.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210113155_1612924315331.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210113211_1612924331487.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210113224_1612924344454.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210012203_1612930923830.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210012221_1612930941301.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"냉동 곤약(200g)\",\"채 썬 양파(50g)\",\"납작 썬 마늘(10g)\",\"채소 육수(100㎖)\",\"아몬드(100g)\",\"땅콩(100g)\",\"통밀가루(45g)\",\"미림(20g)\",\"간장(5g)\",\"간 마늘(10g)\",\"토마토 페이스트(30g)\",\"간장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"한 번 얼렸다 해동한 곤약을 사용하면 식감이 쫀득해요.\\n빵가루 대신 아몬드와 땅콩가루로 고소함을 더했어요.\",\"instructions\":[\"1. 냉동 곤약에 칼집을 낸 뒤 냄비에 조림 양념과 물(40㎖)을 함께 넣고 5분간 조린다.\",\"2. 팬에 채 썬 양파와 납작 썬 마늘을 넣어 3분간 볶다가 토마토 페이스트(30g)를 넣어 3분간 볶는다.\",\"3. 채소 육수(100㎖), 간장(10g), 설탕(3g), 발사믹식초(5g)를 넣어 3분간 끓인 뒤 체에 밭쳐 건더기를 걸러 내 소스를 만든다.\",\"4. 중간 불로 달군 마른 팬에 아몬드와 땅콩을 5분간 볶은 뒤 잘게 다진다.\",\"5. 조린 곤약에 통밀가루(45g)와 물(40㎖)을 섞은 반죽을 입힌 뒤 잘게 다진 견과류를 묻힌다.\",\"6. 중간 불로 달군 팬에 식용유(5㎖)를 두른 뒤 견과류를 묻힌 곤약을 넣어 앞뒤로 3~5분간 굽고, 그릇에 곤약가스를 올리고 ③의 소스를 곁들인다.\"]},{\"id\":\"k610\",\"title\":\"두부크림 관자뇨키\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9W1G\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqXd\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqZl\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqc2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqeh\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqh8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeqjH\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(25g)\",\"관자(200g)\",\"새우(6마리)\",\"모시조개(6개)\",\"청양고추(2개)\",\"두부(200g)\",\"우유(⅔컵)\",\"생크림(⅔컵)\",\"후춧가루(약간)\",\"다진 마늘(0.7Ts)\",\"바질(4장)\",\"그라나파다노 치즈(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•해산물과 소량의 치즈를 넣어 감칠맛을 내며 채소와 향신료로 풍미를 높여 소금의 사용을 줄였어요.\",\"instructions\":[\"1. 양파는 5mm 두께로 채 썰고, 청양고추는 어슷 썬 뒤 씨를 제거하고, 관자는 깨끗하게 헹군 뒤 후춧가루로 밑간한다.\",\"2. 두부에 우유와 생크림을 넣어 고루 섞어 두부크림을 만든다.\",\"3. 중간 불로 달군 팬에 식용유(1.5Ts)를 두른 뒤 관자를 넣어 불투명해질 때까지 구워 꺼낸다.\",\"4. 같은 팬에 식용유(0.5Ts)를 두른 뒤 다진 마늘과 양파를 넣어 볶다가 새우, 모시조개, 청양고추를 넣어 볶는다.\",\"5. 물(100ml)을 넣어 조개가 입을 벌릴 때까지 끓이고, 두부크림을 넣어 끓어오르면 관자를 넣어 3분간 익힌다.\",\"6. 그릇에 담아 바질을 올리고, 그라나파다노 치즈를 뿌려 마무리한다.\"]},{\"id\":\"k611\",\"title\":\"토마토 해물누룽지탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033231_1699252351417.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033352_1699252432376.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033410_1699252450686.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033719_1699252639778.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033738_1699252658623.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033817_1699252697262.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106033835_1699252715068.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"•[간편식 재료] 알배추(40g)\",\"우목심(50g)\",\"깻잎(5g)\",\"청경채(25g)\",\"팽이버섯(20g)\",\"표고버섯(5g)\",\"숙주(30g)<br>\",\"•[추가 재료] 오징어(30g)\",\"새우(40g)\",\"홍합(164g)\",\"베트남 건고추(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 칼륨이 풍부한 토마토를 활용하여 나트륨 배출을 도왔어요.<br>\\n\\n• 고춧가루를 넣어 매콤한 맛으로 심심한 맛을 보완했어요.\",\"instructions\":[\"1. 물에 다시팩을 넣고 20분간 중불에 끓여 육수를 만들고, 오징어는 껍질을 벗겨 솔방울 모양으로 썰고 홍합은 수염을 제거하고 새우는 몸통의 껍질을 벗긴다.\",\"2. 토마토는 껍질을 벗겨 5×5mm 크기로 썰고, 알배추, 표고버섯, 청양고추, 양파, 우목심, 깻잎은 채 썰고 청경채는 어슷 썬다.\",\"3. 팬에 토마토 페이스트를 볶다가 토마토를 넣고 끓이고 고춧가루, 다시마 육수(200ml)를 넣고 살짝 끓여 토마토 소스를 만든다.\",\"4. 팬에 식용유를 두르고 대파, 편 마늘을 볶고, 우목심, 새우, 오징어, 홍합, 알배추, 양파, 표고버섯, 건고추를 넣어 볶다가 후추로 간하고, 간장을 넣는다.\",\"5. 토마토 소스를 함께 넣어 5분간 끓인다.\",\"6. 청경채, 팽이버섯, 숙주를 넣어 살짝 볶고, 깻잎과 누룽지를 올려 마무리한다.\"]},{\"id\":\"k612\",\"title\":\"삼색나물, 토마토양념장\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110832_1554689312799.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110902_1554689342740.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110915_1554689355976.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110932_1554689372627.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110950_1554689390083.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111005_1554689405712.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111022_1554689422912.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토 35g\",\"마늘 2g\",\"양파 20g\",\"꿀 15g\",\"식초 15g\",\"도라지 15g\",\"시금치 30g\",\"고사리 20g\",\"고추장 20g\",\"소금 2g\",\"참기름 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장의 토마토에 함유된 칼륨이 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 토마토를 데쳐 껍질을 벗겨낸 뒤 잘게 썬다.\",\"2. 마늘과 양파를 잘게 다진 뒤 썰어둔 토마토, 고추장, 꿀, 식초와 골고루 섞는다.\",\"3. 도라지는 껍질을 벗긴 뒤 물에 담궈 쓴맛을 제거하고 길이 5cm, 두께 0.5cm로 찢는다.\",\"4. 시금치는 뿌리를 잘라내고 2~4등분으로 나눈다.\",\"5. 고사리는 깨끗하게 씻은 뒤 물에 불린다.\",\"6. 끓는 물에 소금을 넣고 도라지, 시금치, 고사리 순으로 데친 뒤 찬물에 헹궈 물기를 짜고 양념장을 곁들인다.\"]},{\"id\":\"k613\",\"title\":\"삼색 브레드 스틱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044129_1670485289362.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101421_1612487661904.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101437_1612487677081.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101448_1612487688989.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101528_1612487728027.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101544_1612487744370.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101611_1612487771505.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"강력분 300g\",\"소금 3g\",\"드라이이스트 12g\",\"버터 36g\",\"식용유 6g\",\"당근 50g\",\"참나물 50g\",\"연근 30g\",\"견과류 10g\",\"물 100ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕이 들어가지 않아 심심할 수 있는 빵에 채소를 갈아 넣어 향과 맛을 더 했어요.\",\"instructions\":[\"1. 강력분, 소금, 이스트, 물을 넣어 만든 반죽을 3등분 하여 각각 당근, 참나물, 연근을 다져 넣어 섞어준다.\",\"2. 반죽에 글루텐이 형성되면 각각 식용유와 버터를 넣어 섞고, 연근을 넣은 반죽에는 마지막에 견과류를 넣어 섞는다.\\n★다른 반죽보다 향이 없는 연근 반죽에 견과류를 넣어 맛을 냈어요.\",\"3. 반죽이 완료되면 3-40분 정도 1차 발효를 한다.\",\"4. 1차 발효 후 30g씩 무게를 달아 둥글리기하고 중간 발효 후 길게 밀어 편다.\",\"5. 20분 정도 2차 발효를 한다.\",\"6. 아랫불 160, 윗불 180℃ 오븐에서 18분 동안 굽는다.\"]},{\"id\":\"k614\",\"title\":\"양배추말이 김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF690\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6G3\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6Hr\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6J6\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6KK\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6Lb\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양배추(2장)\",\"시금치(20g)\",\"오이(60g)\",\"당근(20g)\",\"고춧가루(1t)\",\"간장(1t)\",\"사과식초(1t)\",\"사과즙(1t)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 많은 양배추, 시금치를 활용하여 나트륨 배출에 도움을 주었어요.\\n설탕 대신 사과즙을 사용하여 당을 줄였어요.\",\"instructions\":[\"1. 끓는 물(800㎖)에 양배추와 시금치를 넣어 데친 뒤 찬물에 헹궈 체에 밭쳐 물기를 제거한다.\",\"2. 데친 시금치와 오이, 당근은 얇게 채 썬다.\",\"3. 데친 양배추를 깔고 위에 채 썬 재료를 올려 돌돌 말아준다.\",\"4. 양념장을 만든다.\",\"5. 양배추말이를 한입 크기로 썰어 그릇에 담은 뒤 양념장을 곁들인다.\"]},{\"id\":\"k615\",\"title\":\"단호박 양고기볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9WFj\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerPn\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerSS\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerUM\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerY2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerbm\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerfK\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 콜리플라워(50g)\",\"고구마(1개)\",\"양파(1개)\",\"양고기(부채살\",\"250g)\",\"마늘(7~8쪽)\",\"단호박(1개)\",\"올리브유(5ts)\",\"바질럽드(3Ts)\",\"바질페스토(3ts)\",\"홀그레인 머스터드(2ts)\",\"다진 마늘(2ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•단호박, 양파, 고구마, 콜리플라워 등을 사용해 식감을 높이고 단맛을 보완했어요.\\n•바질페스토와 홀그레인 머스터드로 맛의 심심함을 보완했어요.\",\"instructions\":[\"1. 콜리플라워는 송이 부분만 떼어내고, 고구마와 양파는 한입 크기로 썬다.\",\"2. 양고기는 한입 크기로 썰어 밑간한 뒤 15분간 재운다.\",\"3. 재워둔 고기에 손질한 채소와 마늘을 넣어 고루 버무리고, 중간 불로 달군 팬에 올려 고구마가 약간 익을 때까지 볶는다.\",\"4. 양념을 넣어 재료와 고루 섞는다.\",\"5. 단호박은 전자레인지에 5분간 돌리고, 익으면 윗부분을 약간 잘라낸 뒤 씨를 제거하고, 양고기와 볶은 재료를 단호박 속에 채운다.\",\"6. 찜기에 넣어 25분간 쪄낸 뒤 8등분하여 마무리한다.\"]},{\"id\":\"k616\",\"title\":\"채소 프리타타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034056_1699252856642.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034141_1699252901583.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034202_1699252922337.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034231_1699252951006.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034255_1699252975019.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034312_1699252992588.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034332_1699253012822.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [가정 간편식 재료] 소고기(180g)\",\"단호박(50g)\",\"팽이버섯(20g)\",\"새송이버섯(25g)\",\"느타리버섯(20g)\",\"쌈추(10g)\",\"적근대(10g)\",\"배추(20g)\",\"숙주(20g)<br>\",\"• [추가 재료] 달걀(3개=180g)\",\"우유(75g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 시판 양념을 제외한 샤브샤브의 재료를 활용하여 조리형태(국물류→구이류)를 바꿈으로써 국물 섭취 감소를 통한 나트륨 섭취를 줄였어요.\\n <br>• 치즈는 나트륨 함량이 높으므로 너무 많이 섭취하지 않도록 주의해요.\",\"instructions\":[\"1. 단호박, 팽이버섯, 새송이버섯, 느타리버섯, 쌈추, 적근대, 배추, 숙주와 소고기를 3cm 크기로 자른다.\",\"2. 팬에 식용유(20g)를 두르고 중간 불에 손질한 채소와 소고기를 차례대로 볶는다.\",\"3. 볼에 달걀을 풀고 소금, 우유를 넣고 섞어 달걀물을 만든다.\",\"4. 타르트 틀에 식용유(6g)를 바르고 볶은 채소, 소고기를 올리고 ③을 넣는다.\",\"5. 140도로 예열한 오븐에 25분 정도 구워 프리타타를 만든다.\",\"6. 프리타타 위에 새싹채소와 리코타 치즈를 올린 후 올리브유를 두르고 마무리한다.\"]},{\"id\":\"k617\",\"title\":\"고등어 라따뚜이 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040805_1699254485787.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231120/20231120090418_1700438658302.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231120/20231120090437_1700438677911.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231120/20231120090457_1700438697919.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231120/20231120090516_1700438716926.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231120/20231120090626_1700438786668.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231120/20231120090654_1700438814964.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [가정 간편식 재료] 고등어(1마리=250g)\",\"시래기(30g)\",\"무(20g)\",\"대파(20g)\",\"청양고추(20g)\",\"양념장(75g)<br>\",\"• [추가 재료] 토마토 홀(200g)\",\"가지(60g)\",\"애호박(90g)\",\"표고버섯(40g)\",\"두부면(50g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 가정 간편식의 양념장을 1/3만 사용해 나트륨과 당류 사용량을 줄였어요.<br>\\n• 칼륨이 풍부한 토마토를 사용해서 나트륨 배출을 도왔어요.<br>\\n• 가다랑어포를 이용한 육수를 활용하여 감칠맛을 증가시켜 나트륨 사용량을 줄였어요.\",\"instructions\":[\"1. 냄비에 물, 무, 대파를 넣고 끓으면 불을 끄고 가다랑어포를 넣고, 30분 후에 체로 걸러 육수를 만든다.\",\"2. 애호박, 가지, 표고버섯은 두께 5mm 크기로 썬다. 시래기는 굵게 다진다.\",\"3. 고등어는 흐르는 물에 씻은 후 키친타월로 물기를 제거하고, 180도로 예열한 팬에 식용유를 두르고 고등어를 껍질부터 앞뒤로 10분 동안 굽는다.\",\"4. 고등어를 구운 팬에 남은 기름을 이용해 시래기를 볶고, 토마토 홀을 넣고 주걱으로 으깬다.\",\"5. 육수(500g)와 양념장, 구운 고등어, 손질한 애호박, 가지, 표고버섯을 넣고 중간 불에서 조린다.\",\"6. 청양고추, 두부면을 넣고 2분 정도 더 조리한 후 불을 끄고 접시에 담고, 바질 잎을 올려 마무리한다.\"]},{\"id\":\"k618\",\"title\":\"과카몰리 갈치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120011251_1732075971990.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111347_1732068827429.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111358_1732068838875.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111410_1732068850104.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111421_1732068861207.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111434_1732068874272.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111445_1732068885173.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료] 갈치(70g(1토막))\",\"아보카도(35g)\",\"토마토(10g)\",\"양파(10g)\",\"마늘(10g)\",\"레몬(10g)\",\"라임(10g)\",\"바질(5g)<br>\",\"[양념] 올리브유(12g)\",\"소금(1g)\",\"후추(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•갈치에 밑간을 따로 하지 않고 과카몰리와 곁들여 고소한 맛을 더해 심심한 맛을 보완했어요.\",\"instructions\":[\"1. 아보카도는 반으로 갈라 씨를 제거하고 과육을 으깬다. 레몬은 반으로 갈라 즙을 짜고, 라임은 얇게 자른다.\",\"2. 토마토, 양파, 마늘은 깍둑썰고, 바질은 곱게 다진다\",\"3. 볼에 손질한 아보카도, 토마토, 양파, 마늘, 바질을 넣고 올리브유, 레몬즙, 소금, 후추를 섞어 과카몰리를 만든다.\",\"4. 깨끗이 씻은 갈치는 칼집을 낸 후 달군 팬에 노릇하게 굽는다.\",\"5. 접시에 갈치구이를 담고 과카몰리를 곁들인다.\",\"6. 접시에 손질한 라임을 담고 마무리한다.\"]},{\"id\":\"k619\",\"title\":\"초코치즈크림케이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110921_1761185361351.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023111328_1761185608640.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023111344_1761185624841.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023111407_1761185647716.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023111421_1761185661934.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023111437_1761185677093.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023111450_1761185690167.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"크림치즈 > 우유 875ml\",\"식초 20ml\",\"알룰로스① 56g\",\"소금 1g\",\"초코크림 > 아몬드가루 85g\",\"무가당 코코아가루① 20g\",\"알룰로스② 70g\",\"두유① 25ml\",\"반 죽 > 바나나 175g\",\"달걀 105g\",\"두유② 25ml\",\"무가당 코코아가루② 45g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크림치즈를 직접 만들어 사용해 나트륨 사용량을 줄였어요.\",\"instructions\":[\"1. 냄비에 우유를 넣고 중불로 끓이다\\n약한 불에서 식초를 넣어 젓는다.\\n면보로 유청을 거른 덩어리를 믹서에\\n넣고 알룰로스①, 소금을 넣고 곱게\\n갈아 크림치즈를 만든다.\",\"2. 볼에 아몬드가루, 무가당\\n코코아가루①을 체 쳐서 넣고\\n알룰로스②, 두유①을 섞어\\n초코크림을 만든다.\",\"3. 믹서에 바나나, 달걀, 두유②,\\n무가당 코코아가루②, 땅콩버터를 넣고\\n갈아 반죽을 만들어 종이컵 높이의\\n50% 정도 채운다.\",\"4. 전자레인지에서 4~5분 동안 구워\\n시트를 만든다. 구운 시트는 가로로\\n3등분한다.\",\"5. 크림치즈와 초코크림을 섞어 시트 위에\\n올린다.\",\"6. 시트를 겹쳐 케이크를 만들고\\n무가당 코코아가루를 뿌려 마무리한다\"]},{\"id\":\"k620\",\"title\":\"배추겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120014935_1732078175251.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112138_1732069298703.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112149_1732069309321.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112200_1732069320605.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112211_1732069331781.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112223_1732069343025.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112233_1732069353478.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료] 알배추(23g)\",\"쪽파(5g)\",\"통깨(2g)\",\"겉절이 양념(15g)<br>\",\"[겉절이 양념(124g분량)] 찐 감자(20g)\",\"고춧가루(25g)\",\"매실청(5g)\",\"까나리액젓(10g)\",\"새우젓(3g)\",\"무(20g)\",\"양파(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 칼륨이 풍부한 감자를 사용하여 나트륨 배출을 도왔어요. \\n<br>• 설탕 대신 양파의 단맛을 활용했어요.\",\"instructions\":[\"1. 알배추는 한입 크기로 자른다.\",\"2. 쪽파는 3cm 길이로 썰고, 찐 감자는 한입 크기로 자른다\",\"3. 마늘, 생강, 무, 양파는 깨끗이 씻어 한입 크기로 자른다.\",\"4. 믹서에 찐 감자, 고춧가루, 매실청, 까나리액젓, 새우젓, 무, 양파, 생강, 마늘을 넣고 갈아 겉절이 양념을 만든다.\",\"5. 손질한 알배추, 쪽파, 겉절이 양념(15g)을 버무린다.\",\"6. 접시에 담고 통깨를 뿌려 마무리한다.\"]},{\"id\":\"k621\",\"title\":\"홍시에이드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112605_1554690365803.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112708_1554690428035.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112725_1554690445485.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112739_1554690459273.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112752_1554690472906.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112807_1554690487505.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112821_1554690501729.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홍시 50g\",\"배 20g\",\"탄산수 50g\",\"사이다 50g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"에이드에 들어가는 배가 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 홍시를 반으로 가르고 껍질을 벗긴다.\",\"2. 씨를 제거한 뒤 3등분으로 썬다.\",\"3. 배는 1/4로 나눠 껍질을 벗긴다.\",\"4. 믹서에 배, 홍시를 넣고 간다.\",\"5. 4를 냉동실에서 살짝 얼린다.\",\"6. 반쯤 얼었을 때 탄산수와 사이다를 섞는다.\"]},{\"id\":\"k622\",\"title\":\"낙지묵은지콩나물국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309010557_1583726757270.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054729_1583484449779.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054741_1583484461050.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054751_1583484471236.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054800_1583484480636.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054910_1583484550343.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200306/20200306054824_1583484504819.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"낙지 50g\",\"묵은지 20g\",\"콩나물 40g\",\"무 40g\",\"대파 5g\",\"마늘 5g\",\"국멸치 3g\",\"대두유 5g\",\"간장 1.5g\",\"쌀뜨물 300ml\",\"고춧가루 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"묵은지를 물에 씻어 짠맛을 줄이고, 고춧가루와 콩나물을 넣어 칼칼하고 시원한 맛을 더했어요.\",\"instructions\":[\"1. 쌀뜨물과 국멸치로 육수를 우리고 멸치를 건져낸다.\",\"2. 무는 나박썰기, 대파는 어슷썰기, 마늘은 다진다.\",\"3. 묵은지는 물에 헹구어 짠맛을 빼주고 기름에 살짝 볶는다.\",\"4. 멸치육수에 묵은지, 낙지, 고춧가루, 무, 마늘을 넣고 끓인다.\",\"5. 콩나물을 넣고 국간장으로 간을 하여 끓인다.\",\"6. 대파를 얹어 마무리한다.\"]},{\"id\":\"k623\",\"title\":\"자색고구마 버터크림 빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112435_1612405475440.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112456_1612405496410.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112511_1612405511599.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112527_1612405527445.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112542_1612405542836.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112606_1612405566873.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210204/20210204112619_1612405579569.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 290g\",\"박력분 70g\",\"이스트 4g\",\"소금 5g\",\"달걀 50g(1개)\",\"무염버터 30g\",\"바나나 180g\",\"밤고구마 130g\",\"물 150g\",\"(속재료) 삶은 밤고구마 380g\",\"바나나 180g\",\"바나나슬라이스\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕 대신 고구마와 바나나에 함유한 천연당을 사용하여 이스트를 발효시켰어요.\",\"instructions\":[\"1. (속재료) 삶은 밤고구마와 바나나를 섞은 앙금을 35g씩 둥글리기 해주고 여유분 바나나는 0.5두께로 슬라이스한다.\",\"2. (버터크림) 삶은 자색고구마와 밤고구마를 으깬 후 물을 넣어 반죽하다가 박력분, 달걀 1개를 풀어 잘 섞어 준 후 버터를 넣고 덩어리가 생기지 않게 섞어 짤주머니에 담는다.\",\"3. 체에 내린 강력분과 박력분에 소금,이스트를 넣어 섞어주고 밤고구마 130g, 바나나 180g, 달걀 1개를 섞어 반죽이 한 덩이가 되면 무염버터 30g을 넣어 치댄다.\",\"4. 반죽이 2배가 되도록 1차 발효 후 50g 분할해 둥글리기 해서 10분 정도 중간 발효한다.\",\"5. 반죽에 앙금과 바나나슬라이스를 넣어 동그랗게 모양을 만들어 2차 발효 시키고 굽기 전에 고구마 버터크림을 올려준다.\\n★이음새가 벌어지면 구우면서 반죽이 터져지니 꼼꼼히 붙여주세요.\",\"6. 윗불 180℃ 아랫불 160℃로 예열된 오븐에서 20분 구워낸다.\"]},{\"id\":\"k624\",\"title\":\"치아바타 피자빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044531_1670485531889.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101843_1612487923297.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205101927_1612487967163.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205102002_1612488002414.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205102027_1612488027050.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205102053_1612488053729.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210205/20210205102120_1612488080905.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 블루베리 발효원종 250g\",\"강력분 250g\",\"소금 3g\",\"물 100ml\",\"(소스) 토마토 150g\",\"양송이 버섯 50g\",\"양파 50g\",\"파프리카 50g\",\"로즈마리 5g\",\"식용유 10g\",\"물 50ml\",\"(토핑) 저염치즈 200g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕을 사용하지 않는 치아바타 빵을 사용하고, 생 토마토로 소스를 만들어 가공품 사용을 줄였어요.\",\"instructions\":[\"1. (소스) 소스에 들어가는 재료는 전부 다진 후 기름 두른 팬에 양파를 먼저 볶다가 남은 재료를 넣고 볶아 준 뒤 물을 넣고 끓여 조린다.\",\"2. 반죽 재료를 넣고 27℃ 최종단계 까지 믹싱한 후 1차 발효는 고온발효로 27℃에서 1시간 발효한다.\",\"3. 150g씩 분할하여 모양을 성형한 후 면포 위에 팬닝한다.\\n★반죽이 많이 질어요. 손에 묻으면 덧밀가루를 뿌려가며 진행하세요.\",\"4. 2차 발효는 온도는 30℃, 수분은 75%에서 60분간 발효한 후 오븐팬에 팬닝한다.\",\"5. 반죽 위에 만들어 놓은 토마토 소스를 바르고 스팀 160℃/230℃에서 13분간 굽는다.\",\"6. 치즈를 올리고 4분간 구워낸다.\"]},{\"id\":\"k625\",\"title\":\"코코넛워터 토마토카레\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105005_1612835405539.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105036_1612835436099.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105046_1612835446864.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105100_1612835460050.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105114_1612835474046.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105127_1612835487427.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105141_1612835501269.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파(75g)\",\"감자(50g)\",\"당근(40g)\",\"닭가슴살(100g)\",\"토마토(150g)\",\"코코넛워터(100㎖)\",\"우유(100㎖)\",\"현미밥(150g)\",\"올리브유(10g)\",\"후춧가루(3g)\",\"카레가루(10g)\",\"물(3T)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"신맛의 요거트를 소스로 활용하면 적은 양의 염분으로도 짠맛을 높일 수 있어요.\",\"instructions\":[\"1. 양파(30g)는 다지고, 나머지 양파와 감자, 당근, 닭가슴살은 한입 크기로 썬다.\",\"2. 닭가슴살은 밑간해 고루 버무려 재운다.\",\"3. 끓는 물에 토마토를 넣어 20초간 데쳐 건진 뒤 껍질을 벗겨 8등분한다.\",\"4. 중간 불로 달군 팬에 올리브유(10g)를 두른 뒤 다진 양파와 올리고당, 다진 마늘, 카레가루를 넣어 2분간 볶다가 손질한 토마토를 넣고 으깨듯 볶는다.\",\"5. 손질한 채소와 밑간한 닭가슴살을 넣고 2분간 볶은 뒤 코코넛워터와 우유를 부어 끓인다.\",\"6. 그릇에 현미밥을 담고 카레를 부은 뒤 요거트소스와 파슬리가루(0.5g)를 올려 마무리한다.\"]},{\"id\":\"k626\",\"title\":\"치즈 단호박\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF7wm\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF7-V\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF815\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF81e\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF82T\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF84M\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF85L\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(1개=800g)\",\"달걀(1개)\",\"맛술(1T)\",\"우유(1T)\",\"모차렐라치즈(30g)\",\"그라나파다노치즈(1Ts)\",\"아몬드 플레이크(2Ts)\",\"꿀(1Ts)\",\"파슬리가루(약간)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박과 치즈를 사용하여 달콤함과 짭짤함의 조화가 어우러져요.\",\"instructions\":[\"1. 단호박은 3mm 정도 윗부분을 도려내 씨를 제거한 뒤 전자레인지에 5분간 돌려 익힌다.\",\"2. 단호박 씨를 제거한 뒤 속(50g)을 파서 덜어놓는다.\",\"3. 달걀은 곱게 풀어 체에 내린 뒤 맛술, 우유, 모차렐라치즈(20g), 덜어 놓은 호박과 함께 믹서에 넣어 간다.\",\"4. 속을 파낸 단호박에 간 재료를 넣은 뒤 뚜껑을 닫고 전자레인지에 8분간 돌려 익힌다.\",\"5. 뚜껑을 열고 모차렐라치즈(10g)를 올려 전자레인지에 3분간 돌려 녹인다.\",\"6. 단호박을 6~7등분해 그릇에 담고 꿀과 그라나파다노치즈, 아몬드 플레이크, 파슬리가루를 뿌린다.\"]},{\"id\":\"k627\",\"title\":\"강황 투움바 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9WOj\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerkN\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJern5\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeroe\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerrR\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJerui\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJervP\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(1개)\",\"양송이버섯(6개)\",\"마늘(5쪽)\",\"토마토(3개)\",\"탈리아텔레(200g)\",\"말린 토마토(2개)\",\"다진 파슬리(0.5Ts)\",\"핑크 페퍼(5알)\",\"바질잎(2장)\",\"바게트(약간)\",\"물(1260ml)\",\"무(150g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 토마토와 양송이버섯은 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 양파는 도톰하게 채 썰고, 양송이버섯은 모양대로 썰고, 마늘은 납작 썰고, 토마토는 6~8등분한다.\",\"2. 채소 육수(6컵)에 탈리아텔레를 넣고 13분간 삶아 건진다.\",\"3. 중간 불로 달군 팬에 올리브유를 두른 뒤 납작 썬 마늘을 노릇하게 익히고, 양파와 양송이버섯을 넣어 3분간 볶는다.\",\"4. 면수(1컵), 강황가루, 고운 고춧가루를 넣어 고루 섞고, 토마토를 넣어 볶다가 식물성 생크림과 두유를 넣어 끓어 오르면 말린 토마토를 넣고 1분간 끓인다.\",\"5. 삶은 탈리아텔레를 넣고, 소스가 면에 잘 배어들게 고루 볶은 뒤 후춧가루를 뿌린다.\",\"6. 그릇에 담고 다진 파슬리와 핑크 페퍼를 뿌리고, 바질잎과 바게트를 곁들여 마무리한다.\"]},{\"id\":\"k628\",\"title\":\"깻잎 쌈두부 라자냐\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034746_1699253266204.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034833_1699253313070.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034850_1699253330499.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034909_1699253349908.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034928_1699253368406.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106034948_1699253388056.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035007_1699253407571.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [간편식 재료] 쌈두부(18g)\",\"소고기 양지(120g)\",\"숙주(80g)\",\"청경채(30g)\",\"배추(60g)\",\"당면(30g)<br>\",\"• [추가 재료] 쌈두부(1팩=100g)\",\"모차렐라 치즈(1컵=100g)\",\"깻잎(10g)\",\"완숙 토마토(80g)\",\"양파(80g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 칼륨이 풍부한 토마토를 사용하여 나트륨 배출을 도왔어요.<br>\\n• 소스를 직접 만들어 나트륨 및 당류 함량을 낮췄어요.<br>\\n• 오레가노, 월계수 잎 등 허브류를 사용하여 풍미를 높이고 나트륨 사용량은 줄였어요.\",\"instructions\":[\"1. 껍질 벗긴 토마토는 주사위 모양으로 썰고, 양파, 배추, 청경채, 숙주는 잘게 썬다.\",\"2. 팬에 소고기 양지를 구운 뒤 꺼내고, 같은 팬에 식용유를 두르고 다진 마늘과 손질한 채소를 넣고 물기가 없어질 때까지 볶는다.\",\"3. ②에 소고기 다짐육을 넣어 볶다가 손질한 완숙 토마토, 월계수 잎, 화이트 와인, 오레가노를 넣어 끓이고 소금, 후추로 간하여 소스를 만든다.\",\"4. 당면은 6cm 길이로 잘라 끓는 물에 7분간 삶아 ③에 넣는다.\",\"5. 쌈두부 → 구운 소고기 양지 → 소스 → 모차렐라 치즈 순으로 켜켜이 올리고 180도로 예열한 오븐에 8분간 익힌다.\",\"6. 깻잎을 돌돌 말아 채 썰어 올려 마무리한다.\"]},{\"id\":\"k629\",\"title\":\"참깨가지말이밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120104724_1732067244359.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105217_1732067537379.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105228_1732067548937.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105239_1732067559993.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105255_1732067575870.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105308_1732067588488.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105319_1732067599615.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분기준<br>\",\"[주재료]닭다리살(25g)\",\"닭안심살(30g)\",\"토마토(35g)\",\"방울토마토(15g)\",\"시금치(5g)\",\"양파(10g)\",\"감자(7g)\",\"스파게티면(건면)(5g)<br>\",\"[양념]고추장(5g)\",\"고춧가루(3g)\",\"다진 마늘(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 케첩 대신 토마토 페이스트를 사용하여 당류 및 나트륨 사용을 줄였어요.\\n<br>• 참깨를 이용한 고소한 소스로 심심한 맛을 보완했어요.\",\"instructions\":[\"1. 가지는 0.3cm 두께로 얇게 썰고 방울토마토, 파프리카, 양파는 잘게 자른다.\",\"2. 손질한 가지는 오븐에 굽는다. (180℃, 10분)\",\"3. 달군 팬에 올리브유(6g)를 두르고 양파를 볶다가 현미밥, 방울토마토, 파프리카를 넣고 볶는다.\",\"4. 채소가 익으면 약한 불로 줄이고 토마토 페이스트, 쿠민가루를 넣어 볶음밥을 만든다.\",\"5. 믹서에 참깨, 올리브유(6g)를 넣어 갈고 요거트, 다진 마늘을 섞어 참깨 소스를 만든다.\",\"6. 구운 가지 위에 볶음밥을 올려 돌돌 말고, 참깨 소스를 얹어 마무리한다.\"]},{\"id\":\"k630\",\"title\":\"코다리 뿌리채소 들깨탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113144_1554690704520.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113251_1554690771565.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113303_1554690783122.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113316_1554690796964.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113331_1554690811815.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113354_1554690834017.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113418_1554690858145.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"코다리 150g\",\"무 60g\",\"연근 20g\",\"호박 20g\",\"우엉 10g\",\"느타리버섯 10g\",\"표고버섯 10g\",\"대파 5g\",\"양파 10g\",\"청양고추 2g\",\"쑥갓 1g\",\"홍고추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연근, 우엉 같은 뿌리채소에 많이 들어있는 칼륨이 나트륨 흡수를 줄여줘요.\",\"instructions\":[\"1. 생강과 마늘을 잘게 다진다.\",\"2. 코다리를 세척 후 다진마늘, 다진생강, 소금, 후추로 밑간한다.\",\"3. 냄비에 다시멸치, 다시마를 넣고 끓여 육수를 우린 뒤 건져낸다.\",\"4. 무, 대파, 양파, 연근, 우엉, 호박, 느타리버섯, 표고버섯, 청양고추를 깨끗이 씻어 먹기좋은 크기로 썬다.\",\"5. 육수에 대파, 청양고추, 쑥갓을 뺀 야채를 넣고 끓이다가 들깨가루와 천일염을 넣어 간 한다.\",\"6. 마지막으로 코다리를 넣고 거품을 걷어가며 끓인 뒤 대파, 청양고추, 쑥갓을 올린다.\"]},{\"id\":\"k631\",\"title\":\"찹쌀 흰살 생선찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103625_1612834585653.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103650_1612834610642.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103703_1612834623306.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103717_1612834637126.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103731_1612834651340.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103747_1612834667352.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209103803_1612834683273.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추(30g)\",\"대파(12g)\",\"가자미(70g)\",\"찹쌀가루(5g)\",\"식초(3g)\",\"맛술(5g)\",\"새우젓(2g)\",\"다진 마늘(2g)\",\"다진 파(2g)\",\"월계수잎(1장)\",\"불린 찹쌀(30g)\",\"고운 고춧가루(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생선을 쪄서 재료 본연의 맛을 살렸어요.\\n새우젓과 고춧가루를 사용하여 나트륨의 사용을 줄였어요.\",\"instructions\":[\"1. 배추는 한입 크기로 썰고, 대파는 6cm 길이로 썰어 길게 2등분하고, 가자미는 먹기 좋은 크기로 자른다.\",\"2. 가자미에 밑간을 고루 버무린 뒤 냉장실에서 20분간 재운다.\",\"3. 찹쌀싸라기 재료를 고루 섞는다.\",\"4. 재워둔 가자미에 찹쌀가루(5g)를 고루 바른 뒤 찹쌀싸라기를 촘촘히 입힌다.\",\"5. 찜기에 배추와 대파를 깔고 가자미를 올린 뒤 12분간 찌고 불을 꺼 5분간 뜸 들인다.\",\"6. 그릇에 담아 마무리한다.\"]},{\"id\":\"k632\",\"title\":\"깻잎퓌레를 곁들인 삼치새우\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105401_1612835641196.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105429_1612835669808.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105442_1612835682969.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105455_1612835695101.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105510_1612835710415.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105523_1612835723657.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209105536_1612835736153.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"깻잎(20장)\",\"청경채(1단)\",\"새우(3마리)\",\"삼치(75g)\",\"생크림(230㎖)\",\"식용 꽃(약간)\",\"삶은 감자(150g)\",\"녹인 무염 버터(15㎖)\",\"우유(15㎖)\",\"레몬즙(3g)\",\"소금(2g)\",\"후춧가루(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"삼치와 새우로 간을 맞추고 나트륨의 사용을 줄였어요.\\n깻잎퓌레의 은은한 향으로 자극적이지 않은 맛을 냈어요.\",\"instructions\":[\"1. 깻잎은 깨끗이 씻고, 청경채는 2등분하고, 새우는 머리를 제거한 뒤 껍질을 벗기고, 삼치는 밑간한다.\",\"2. 냄비에 깻잎과 생크림, 올리브유(3㎖)를 넣어 끓어오르면 믹서에 넣어 곱게 간 뒤 체에 걸러 퓌레를 만든다.\",\"3. 삶은 감자는 으깬 뒤 녹인 무염 버터와 설탕(3g),후춧가루(3g)를 고루 섞고 체에 한 번 걸러 우유를 섞어 매시드 포테이토를 만든다.\",\"4. 손질한 새우에 튀김옷을 입혀 180℃로 달군 식용유(180㎖)에 3분간 튀겨 건지고, 마른 팬에 손질한 청경채를 볶은 뒤 토치로 불맛을 낸다.\",\"5. 중간 불로 달군 팬에 식용유(5㎖)를 두른 뒤 밑간한 삼치를 5분간 앞뒤로 노릇하게 구워 꺼낸다.\",\"6. 그릇에 깻잎퓌레 → 구운 삼치 → 매시드 포테이토 → 청경채 → 튀긴 새우 → 꽃잎 순으로 올린다.\"]},{\"id\":\"k633\",\"title\":\"참나물페스토 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094407_1678322647562.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094519_1678322719488.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094538_1678322738402.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094554_1678322754813.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094612_1678322772805.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094639_1678322799580.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309094659_1678322819968.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 참나물(45g)\",\"방울토마토(2개)\",\"스파게티면(90g)\",\"•참나물 페스토 : 참나물(18g)\",\"잣(4g)\",\"올리브유(4g)\",\"소금(1g)\",\"•양념 : 올리브유(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•향기로운 참나물을 사용해 짠맛을 보완했어요.\",\"instructions\":[\"1. 참나물은 얇게 썰고, 방울토마토는 2등분하고, 잣은 곱게 빻아 잣가루를 만든다.\",\"2. 믹서에 참나물 페스토 재료를 넣고 갈아 페스토를 만든다.\",\"3. 끓는 소금물(물 8컵과 소금 1g 비율)에 스파게티를 넣어 8분간 삶아 건진다.\",\"4. 스파게티에 페스토를 넣어 버무린다.\",\"5. 그릇에 스파게티를 담은 뒤 손질한 참나물을 올리고 올리브유, 잣가루를 뿌린다.\",\"6. 손질한 방울토마토를 곁들여 마무리한다.\"]},{\"id\":\"k634\",\"title\":\"카레삼겹살 파니니\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJetjt\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeuii\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeukY\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeumR\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeupA\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeurS\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeutU\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 방울토마토(4개)\",\"아보카도(1개)\",\"로메인(4장)\",\"양파(¼개)\",\"대파(15cm)\",\"미나리(⅓줌=50g)\",\"마늘(5쪽)\",\"대패삼겹살(100g)\",\"치아바타(2개)\",\"올리브유(0.5Ts)\",\"후춧가루(약간)\",\"간장(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•카레가루를 사용하여 식품 본연의 풍미를 증가시켜 소금 및 설탕 사용량을 줄였어요.\",\"instructions\":[\"1. 방울토마토는 4등분하고, 아보카도는 얇게 모양대로 썰고, 로메인은 깨끗하게 씻어 물기를 제거하고, 양파, 대파, 미나리는 4cm 길이로 썰고, 마늘은 납작 썬다.\",\"2. 중간 불로 달군 팬에 올리브유를 두른 뒤 납작 썬 마늘, 양파, 대파를 넣어 1분간 볶는다.\",\"3. 대패삼겹살과 후춧가루를 넣어 겉면이 노릇해질 때까지 볶고, 미나리, 간장, 꿀을 넣어 1분 정도 볶고, 카레가루, 고운 고춧가루를 넣어 고루 섞으며 볶는다.\",\"4. 허니요거트소스를 만든다.\",\"5. 치아바타는 마른 팬에 안쪽 면을 노릇하게 구워 꺼내고, 빵 안쪽에 허니 요거트소스를 바른다.\",\"6. 로메인, 삼겹살볶음, 허니요거트소스, 아보카도, 방울토마토, 후춧가루 순으로 올려 마무리한다.\"]},{\"id\":\"k635\",\"title\":\"어린잎채소 건두부말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97uZ\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9F8l\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FDg\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FFb\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FLv\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FPS\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FRD\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 어린잎채소(4컵)\",\"견과류(1컵)\",\"건두부(10장)\",\"슈레드 모차렐라치즈(1컵)\",\"라임청(3ts)\",\"후춧가루(약간)\",\"올리브유(2ts)\",\"다진 마늘(0.3ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•건두부를 사용해 고소한 맛을 냈어요.\\n•라임청을 이용하여 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 어린잎채소는 깨끗하게 씻어 물기를 제거하고, 견과류는 굵게 다진다.\",\"2. 건두부는 끓는 물에 데쳐 건져낸 뒤 물기를 제거한다.\",\"3. 건두부 위에 어린잎채소(3컵)를 올리고, 돌돌 말아 한입 크기로 썬다.\",\"4. 남은 어린잎채소에 다진 견과류와 슈레드모차렐라치즈를 고루 섞는다.\",\"5. 라임청의 라임을 얇게 다지고, 나머지 라임청드레싱 재료와 고루 섞는다.\",\"6. 그릇에 건두부말이와 샐러드를 담고, 라임청 드레싱을 뿌려 마무리한다.\"]},{\"id\":\"k636\",\"title\":\"해산물 완자볼을 곁들인 양장피 콩국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035211_1699253531583.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035300_1699253580534.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035318_1699253598029.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035333_1699253613218.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035350_1699253630588.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035411_1699253651119.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035426_1699253666007.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [가정 간편식 재료] 새우(50g)\",\"오징어(60g)\",\"양장피 면(60g)\",\"건목이버섯(10g)\",\"참기름(4g)\",\"양파(110g)\",\"볶음 소스(20g)\",\"크레미(40g)\",\"당근(40g)\",\"피망(45g)\",\"붉은 파프리카(45g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 시판 양념장의 사용량을 줄이고 콩국물을 넣어 고소한 맛을 더해 심심한 맛을 보완했어요.<br>\\n• 크레미를 데쳐 사용하면 나트륨 섭취량을 줄일 수 있어요.\",\"instructions\":[\"1. 오징어, 새우, 당근, 양파를 믹서에 갈아 달걀흰자를 넣어 치댄 후 완자를 만들어 160도로 예열한 식용유에 4분 정도 튀긴다.\",\"2. 붉은 파프리카와 피망은 올리브유에 살짝 볶는다.\",\"3. 양장피 면은 끓는 물에 5분간 데치고, 같은 냄비에 건목이버섯을 데친다.\",\"4. 양장피 면이 서로 달라붙지 않게 참기름에 버무리고 돌돌 말아 접시 위에 올린다.\",\"5. 크레미, 데친 건목이버섯, 달걀지단을 면 위에 올리고, 튀겨낸 완자, 딜, 볶은 파프리카와 피망을 올린다.\",\"6. 콩국물을 붓고 볶음 소스를 곁들여 마무리한다.\"]},{\"id\":\"k637\",\"title\":\"토마토를 곁들인 마늘밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105532_1732067732591.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105638_1732067798894.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105651_1732067811695.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105703_1732067823550.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105715_1732067835438.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105728_1732067848065.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105741_1732067861384.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료]현미(60g)\",\"백미(30g)\",\"마늘(30g)\",\"토마토(60g)<br>\",\"[양념] 올리브유(24g)\",\"후추(1g)\",\"파슬리가루(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 마늘, 후추를 사용하여 풍미를 높이고 심심한 맛을 보완했어요 \\n<br>•칼륨이 풍부한 토마토를 사용해서 나트륨 배출을 도왔어요\",\"instructions\":[\"1. 현미는 1시간, 백미는 30분 동안 불린다.\",\"2. 마늘의 절반은 편으로 썰고, 나머지는 통으로 준비한다.\",\"3. 냄비에 불린 쌀, 마늘을 넣고 물을 맞춰 센 불에서 끓어오르면 중약 불로 줄이고 15분 동안 끓인다.\",\"4. 약한 불로 줄이고 뜸을 들여 마늘밥을 만든다.\",\"5. 칼집을 낸 토마토를 뜨거운 물에 살짝 데쳐 껍질과 씨를 제거하고, 잘게 다진다.\",\"6. 접시에 마늘밥을 담고 손질한 토마토를 올린 후 올리브유, 후추, 파슬리가루를 뿌려 마무리한다.\"]},{\"id\":\"k638\",\"title\":\"낙전새 카레볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112421_1732069461131.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105819_1732067899940.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105831_1732067911750.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105844_1732067924118.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105855_1732067935148.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105906_1732067946746.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120105925_1732067965561.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[주재료]백미 60g\",\"잡곡 15g\",\"콩 15g\",\"전복 15g\",\"낙지 15g\",\"칵테일 새우 15g\",\"양파 15g\",\"대파 15g\",\"마늘 10g\",\"브로콜리 30g\",\"[양념]강황가루 15g\",\"올리브유 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨이 풍부한 콩, 브로콜리, 파슬리가루를 활용하여 나트륨 배출을 도왔어요.\\n•향신료인 강황가루를 넣어 풍미를 높이고 나트륨 사용량을 줄였어요.\",\"instructions\":[\"1. 밥솥에 백미, 잡곡, 콩을 넣어 잡곡밥을 만든다.\",\"2. 양파, 대파, 마늘, 브로콜리를 잘게 다진다.\",\"3. 낙지, 전복을 끓는 물에 데친다.\",\"4. 낙지, 전복을 잘게 자른다.\",\"5. 달군 팬에 올리브유를 두르고 마늘, 대파, 칵테일 새우, 낙지, 전복, 양파, 브로콜리 순으로 볶는다.\",\"6. 재료가 익으면 잡곡밥을 넣고 굴소스, 강황가루, 후추를 넣고 볶은 후 파슬리가루를 뿌려 마무리한다.\"]},{\"id\":\"k639\",\"title\":\"토마토 채소 계란찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113717_1554691037799.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113757_1554691077396.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113814_1554691094356.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113828_1554691108509.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113849_1554691129904.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113914_1554691154761.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408113927_1554691167879.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"방울토마토 20g\",\"양파 5g\",\"브로콜리 10g\",\"그린빈스 10g\",\"계란 80g\",\"파마산치즈 3g\",\"생크림 20g\",\"마늘 0.1g\",\"후추 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"소금 대신 파마산치즈로 간을 해 나트륨을 줄였어요.\",\"instructions\":[\"1. 볼에 계란을 푼다.\",\"2. 마늘을 다져 계란과 섞고 파마산치즈, 후추를 넣어 간을 맞춘다.\",\"3. 양파는 채 썰고 브로콜리는 깍둑썰고 그린빈스는 2cm 길이로 자른다.\",\"4. 3의 재료를 볶은 뒤 계란물과 섞는다.\",\"5. 방울토마토를 반으로 잘라 4에 넣는다.\",\"6. 그릇에 옮겨 담아 찐다.\"]},{\"id\":\"k640\",\"title\":\"배 깍두기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011724_1554869844830.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011756_1554869876952.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011823_1554869903762.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011837_1554869917197.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011902_1554869942228.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011921_1554869961218.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410011941_1554869981226.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배 400g\",\"쪽파 5g\",\"고춧가루 8g\",\"액젓 15g\",\"마늘 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단맛이 있는 배를 사용해 소금을 사용하지 않은 깍두기를 만들 수 있어요.\",\"instructions\":[\"1. 배 껍질을 벗긴다.\",\"2. 껍질 벗긴 배를 깍둑썰기 한다.\",\"3. 쪽파를 송송 썬다.\",\"4. 마늘을 곱게 다진다.\",\"5. 고춧가루, 액젓, 다진마늘, 쪽파를 섞어 양념을 만든다.\",\"6. 깍둑썰기한 배와 양념을 버무린다.\"]},{\"id\":\"k641\",\"title\":\"바지락가자미완탕국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012513_1583727913803.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012617_1583727977972.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012632_1583727992958.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012648_1583728008963.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012711_1583728031179.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012725_1583728045779.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012739_1583728059843.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가자미살 40g\",\"두부 20g\",\"양파 10g\",\"대파 5g\",\"후추 1.1g\",\"전분 3g\",\"바지락 60g\",\"무우 40g\",\"마늘 2g\",\"쑥갓 1g\",\"청홍고추 0.1g\",\"팽이버섯 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"가자미와 바지락의 감칠맛으로 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 가시를 제거한 가자미와 양파, 대파는 다진다.\",\"2. ①에 으깬두부와 후추를 넣어 동그랗게 완자를 만든다.\",\"3. 무는 나박 썰기, 청?홍고추는 어슷썰기한다.\",\"4. 바지락은 해감 후 무와 함께 끓인다.\",\"5. 바지락 육수에 완자를 넣어 한소끔 끊인다.\",\"6. 마지막에 쑥갓, 청홍고추, 팽이버섯을 넣어 마무리한다.\"]},{\"id\":\"k642\",\"title\":\"저염보쌈김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050101_1611561661950.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050216_1611561736325.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050231_1611561751734.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050246_1611561766912.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050300_1611561780838.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050315_1611561795536.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050331_1611561811580.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"\\\"배추 17g\",\"배 3.0g\",\"대추슬라이스 0.2g\",\"깐밤 1.1g\",\"당근 1.0g\",\"(저염양념) 조선무 1.1g\",\"미나리 1.0g\",\"깐양파 1.1g\",\"파프리카 1.1g\",\"황설탕 0.1g\",\"잣 0.2g\",\"깐마늘 1.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파프리카 즙으로 양념을 하여 젓갈의 양을 줄였어요.\",\"instructions\":[\"1. 배추는 손질하여 심심하게 절인다.\",\"2. 국멸치, 건표고버섯으로 육수를 낸다.\",\"3. 파프리카는 갈아서 즙을 짜서 준비한다.\",\"4. 식힌 육수에 파프리카 즙과 무, 미나리, 양파를 채쳐서 넣고 저염 양념을 만든다.\",\"5. 배, 대추, 밤, 당근은 마지막에 채쳐 섞는다.\",\"6. 저염 양념에 ⑤를 섞어서 절인 배추에 켜켜로 바른다.\"]},{\"id\":\"k643\",\"title\":\"새우게살 파프리카롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104030_1612834830514.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104117_1612834877876.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104224_1612834944812.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104241_1612834961243.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104254_1612834974734.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104311_1612834991377.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104325_1612835005323.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"크래비(20g)\",\"냉동 새우살(20g)\",\"파프리카(빨강\",\"주황\",\"노랑 각각 10g)\",\"냉동 아보카도(15g)\",\"절임 올리브(그린\",\"블랙 5g)\",\"다진 파(2g)\",\"다진 마늘(1g)\",\"후춧가루(약간)\",\"간 파르메산치즈(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 아보카도와 다양한 피클을 사용하여 염분을 낮췄어요.\",\"instructions\":[\"1. 크래비는 꼭 짜 물기를 제거하고, 새우살은 끓는 물에 1분간 데쳐 건진다.\",\"2. 파프리카는 약한 불에 구워 껍질을 검게 태운 뒤 찬물에 씻어 탄 부분을 제거한다.\",\"3. 구운 파프리카는 얇게 포를 뜨고, 아보카도와 크래비, 데친 새우살은 굵게 다진다.\",\"4. 손질한 아보카도, 크래비, 새우살에 다진 파, 다진 마늘, 후춧가루, 간 파르메산치즈, 파프리카 피클을 넣어 고루 섞어 소를 만든다.\",\"5. 비닐랩 위에 포 뜬 파프리카를 올린 뒤 가운데에 소를 넣어 돌돌 말아준다.\",\"6. 그릇에 소스를 담고 비닐랩을 제거한 롤을 올린 뒤 홀그레인 머스터드와 절임 올리브를 올린다.\"]},{\"id\":\"k644\",\"title\":\"콩국물소스를 곁들인 게살 냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9c7\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9df\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9el\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9fa\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9fy\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9gT\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9hM\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"게살(50g)\",\"수박(70g)\",\"가지(30g)\",\"적채(20g)\",\"브로콜리(20g)\",\"두부(100g)\",\"우유(100㎖)\",\"꿀(5g)\",\"소금(1g)\",\"후춧가루(2g)\",\"올리브유(5㎖)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수박, 게살, 브로콜리, 가지 등을 사용해 식감을 높였어요.\\n고소한 맛의 콩국물소스를 활용해 나트륨의 사용을 줄였어요.\",\"instructions\":[\"1. 게살은 잘게 찢고, 수박, 가지, 적채, 브로콜리는 5cm 길이로 채 썬다.\",\"2. 끓는 물(5컵)에 손질한 브로콜리를 1분간 데쳐 찬물에 담가 체에 밭친다.\",\"3. 중간 불로 달군 팬에 올리브유(5㎖)를 두른 뒤 가지를 2분간 볶는다.\",\"4. 믹서에 콩국물소스 재료를 넣고 갈아 콩국물소스를 만든다.\",\"5. 그릇에 수박 → 가지 → 브로콜리 → 적채 → 게살 순으로 쌓는다.\",\"6. 콩국물소스를 부어 마무리한다.\"]},{\"id\":\"k645\",\"title\":\"방아잎 닭고기말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9XmD\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeuyR\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeu_i\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJev1j\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJev2n\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJev3r\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJev68\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 아스파라거스(2개)\",\"닭다릿살(400g)\",\"방울토마토(4개)\",\"방아잎(⅓줌=30g)\",\"파르메산 치즈(1Ts)\",\"레몬즙(0.5Ts)\",\"맛간장(2Ts)\",\"잣(1Ts)\",\"마늘(3쪽)\",\"올리브유(⅔컵)\",\"간장(1컵)\",\"물(½컵)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•맛간장을 만들어 간을 맞추고 나트륨의 사용을 줄였어요.\\n\\n•무가당 요거트를 이용하여 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 아스파라거스는 두꺼운 밑동을 잘라내고, 방아잎은 깨끗이 씻어 물기를 제거한다.\",\"2. 믹서에 방아잎 페스토 재료를 넣어 곱게 갈고, 요거트 소스 재료를 모두 섞는다.\",\"3. 닭다릿살을 넓게 편 뒤 방아잎 페스토 (4Ts)를 올리고, 파르메산 치즈를 올린 뒤 스테이크 시즈닝과 파슬리가루를 넣어 돌돌 말고, 풀리지 않도록 실로 묶는다.\",\"4. 중간 불로 달군 팬에 식용유를 두르고, 돌돌 만 닭다릿살을 넣어 5분간 튀기듯 굽는다.\",\"5. 같은 팬에 아스파라거스와 방울토마토를 넣어 2분간 볶는다.\",\"6. 그릇에 구운 닭다릿살과 아스파라거스, 방울토마토를 올리고 요거트 소스를 곁들여 마무리한다.\"]},{\"id\":\"k646\",\"title\":\"새우 카레 빠에야\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr94dA\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96Wp\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96bB\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96dg\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96hC\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96i_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96lp\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(½개)\",\"토마토(2개)\",\"새우(8마리)\",\"쌀(1½컵)\",\"카레가루(1Ts)\",\"황태 머리(1개)\",\"다시마(5×5cm\",\"1장)\",\"다진 마늘(1Ts)\",\"파슬리가루(0.3Ts)\",\"후춧가루(0.3Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•카레가루는 이국적인 향을 내고, 식품 본연의 풍미를 증가시켜 소금의 사용량을 줄일 수 있어요.\\n•황태 머리, 다시마가 들어간 육수로 자극적이지 않은 감칠맛을 냈어요.\",\"instructions\":[\"1. 양파는 얇게 채 썰고, 토마토는 윗부분을 약간 자른 뒤 속을 파내고, 새우는 머리와 껍질을 제거한다.\",\"2. 냄비에 물(3컵)과 육수 재료를 넣어 중간 불에 15분간 끓여 육수를 만든다.\",\"3. 중간 불로 달군 팬에 식용유를 두르고, 양파와 다진 마늘을 넣어 양파가 갈색이 될 때까지 볶는다.\",\"4. 토마토 속을 넣어 3분간 더 볶고, 쌀과 육수(2컵)를 넣어 끓으면 약한 불로 줄인 뒤 뚜껑을 덮어 15분간 더 끓인다.\",\"5. 뚜껑을 열어 새우를 올리고, 뚜껑을 다시 덮어 5분간 더 끓이고, 불을 꺼 5분간 뜸을 들인다.\",\"6. 파슬리가루와 후춧가루를 뿌려 마무리한다.\"]},{\"id\":\"k647\",\"title\":\"오징어 가라아게&칠리소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032043_1678342843593.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032201_1678342921809.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032221_1678342941060.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032235_1678342955393.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032306_1678342986735.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032326_1678343006043.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032352_1678343032997.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 오징어(80g)\",\"대파(20g)\",\"마늘(10g)\",\"달걀노른자(25g)\",\"밀가루(20g)\",\"식용유(3g)\",\"•양념 : 토마토(20g)\",\"고춧가루(15g)\",\"식초(50g)\",\"설탕(15g)\",\"전분(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•케첩 대신 토마토를 사용하여 나트륨을 줄였어요.\",\"instructions\":[\"1. 오징어는 채 썰고, 마늘과 대파는 곱게 다진다.\",\"2. 오징어, 대파, 마늘, 달걀노른자, 밀가루, 물(10g)을 섞어 반죽한 뒤 동그랗게 빚는다.\",\"3. 가라아게를 180℃ 온도의 기름에서 튀긴다.\",\"4. 토마토는 껍질을 제거한 뒤 잘게 다진다.\",\"5. 냄비에 다진 토마토, 식초, 설탕, 물(50g), 고춧가루, 전분을 넣고 끓여 칠리소스를 만든다.\",\"6. 오징어 가라아게에 칠리소스를 곁들여 마무리한다.\"]},{\"id\":\"k648\",\"title\":\"토마토 채소 가지롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035912_1699253952214.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106035945_1699253985386.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040005_1699254005944.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040023_1699254023471.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040041_1699254041285.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040104_1699254064292.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040121_1699254081027.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [가정 간편식 재료] 순두부(1/2봉지=175g)\",\"팽이버섯(150g)\",\"애호박(30g)\",\"양파(40g)\",\"파(30g)\",\"청양고추(8g)\",\"느타리버섯(33g)\",\"마늘(18g)\",\"차돌박이(87g)<br>\",\"• [추가 재료] 토마토(260g)\",\"가지(120g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 가정 간편식 순두부찌개 소스 대신 레몬즙을 활용한 소스를 직접 만들어 나트륨 및 당류 사용량을 줄였어요.\\n<br>• 칼륨이 풍부한 토마토와 가지를 이용하여 나트륨 배출을 도왔어요.\",\"instructions\":[\"1. 껍질을 벗긴 토마토, 마늘, 파, 양파, 애호박, 느타리버섯, 팽이버섯을 다진다.\",\"2. 팬에 올리브유(20g)를 두르고 마늘, 양파를 넣고 볶다가 토마토를 넣고 소금(4g), 후추(3g)로 간하고 졸여 토마토 소스를 만든다.\",\"3. 믹서에 순두부, 올리브유(10g), 소금(4g), 레몬즙을 넣고 갈아 순두부크림 소스를 만든다.\",\"4. 팬에 올리브유(5g)를 두르고 차돌박이를 구운 후, 같은 팬에 올리브유(15g)를 두르고 파, 애호박, 느타리버섯, 팽이버섯을 볶고 소금(7g)으로 간한다.\",\"5. 가지를 얇게 잘라 팬에 가볍게 굽고 ④를 올리고 돌돌 말아준다.\",\"6. 토마토 소스를 아래에 깔고 ⑤를 올리고, 순두부크림 소스를 올려 마무리한다.\"]},{\"id\":\"k649\",\"title\":\"토마토시금치 닭볶음탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120010619_1732075579019.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120110023_1732068023620.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120110036_1732068036693.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120110048_1732068048196.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120110059_1732068059788.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120110110_1732068070601.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120110120_1732068080682.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료]닭다리살(25g)\",\"닭안심살(30g)\",\"토마토(35g)\",\"방울토마토(15g)\",\"시금치(5g)\",\"양파(10g)\",\"감자(7g)\",\"스파게티면(건면)(5g)<br>\",\"[양념]l고추장(5g)\",\"고춧가루(3g)\",\"다진 마늘(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨이 풍부한 토마토, 시금치, 닭고기를 활용하여 나트륨 배출을 도왔어요.\",\"instructions\":[\"1. 닭다리살, 닭안심살은 키친타월로 물기를 제거하고 끓는 물에 데쳐 한입 크기로 썬다.\",\"2. 칼집을 낸 토마토를 뜨거운 물에 살짝 데치고 껍질을 제거하여 깍둑썰고, 방울토마토는 모양을 살려 반으로 자른다.\",\"3. 양파, 감자는 껍질을 제거하고 깍둑썬다. 시금치는 밑동을 제거하고 깨끗이 씻어 한입 크기로 썬다.\",\"4. 볼에 손질한 닭고기, 양파, 감자를 담고, 고추장, 고춧가루, 다진 마늘, 진간장, 알룰로스를 넣어 버무린다.\",\"5. 달군 팬에 넣고 중약 불로 살짝 볶은 후 물을 부어 끓인다. 채소가 익으면 불을 끄고 시금치를 넣어 잔열로 익힌다.\",\"6. 접시에 담고 삶은 스파게티면을 곁들여 마무리한다.\"]},{\"id\":\"k650\",\"title\":\"콜라비 깍두기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044956_1678175396907.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307045042_1678175442009.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307045059_1678175459149.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307045155_1678175515581.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307045212_1678175532364.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307045231_1678175551991.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307045255_1678175575707.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 콜라비(80g)\",\"쪽파(5g)\",\"홍고추(0.5g)\",\"생강(0.1g)\",\"양파(0.1g)\",\"마늘(1g)\",\"•양념장 : 고춧가루(4g)\",\"액젓(1g)\",\"매실청(0.2g)\",\"•양념 : 천일염(0.1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•콜라비의 단맛을 이용하여 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 콜라비는 껍질을 벗긴 뒤 깍둑 썬다.\",\"2. 손질한 콜라비에 천일염을 뿌려 1시간 동안 절인다.\",\"3. 홍고추, 양파, 생강, 마늘을 믹서에 곱게 간다.\",\"4. 갈아 낸 채소에 양념장 재료를 넣어 양념장을 만든다.\",\"5. 절여 놓은 콜라비는 물기를 제거하고, 쪽파는 적당한 길이로 썬다.\",\"6. 콜라비에 쪽파, 양념장을 넣고 버무려 하루 동안 숙성해 마무리한다.\"]},{\"id\":\"k651\",\"title\":\"비타 오이 물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408013158_1554697918452.jpg\",\"stepImages\":[],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오이 30g\",\"무 50g\",\"홍고추 10g\",\"파프리카 20g\",\"당근 20g\",\"미나리 10g\",\"식초 30g\",\"배 30g\",\"고춧가루 10g\",\"설탕 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"재료를 소금에 절이지 않고 얇게 잘라 나트륨 첨가를 줄였어요.\",\"instructions\":[\"조리 순서 정보가 제공되지 않았습니다.\"]},{\"id\":\"k652\",\"title\":\"감자미역국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015125_1583729485543.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015232_1583729552858.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015248_1583729568748.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015303_1583729583755.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015316_1583729596761.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015329_1583729609745.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309015349_1583729629362.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"건미역 1.5g\",\"감자 40g\",\"다진마늘 1g\",\"참기름 1g\",\"국간장 2g\",\"물 300ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감자에서 나오는 전분이 깊은 맛을 내줘서 염분 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 미역을 물에 불리고 건져내 물기를 제거한다.\",\"2. 감자는 껍질을 제거하고 한입 크기로 자른다.\",\"3. 냄비에 참기름을 두르고 미역을 볶다가 물을 부어 끓인다.\",\"4. 국물이 우러나면 감자를 넣고 익을 때까지 끓인다.\",\"5. 국간장을 넣어 간을 맞춘다.\",\"6. 다진마늘을 넣고 한소끔 더 끓여서 완성한다.\"]},{\"id\":\"k653\",\"title\":\"청경채 김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030413_1678341853588.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030544_1678341944472.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030559_1678341959235.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030613_1678341973161.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030626_1678341986519.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030640_1678342000760.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309030658_1678342018664.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 청경채(60g)\",\"배(10g)\",\"•양념장 : 매실액(5g)\",\"고춧가루(5g)\",\"저염간장(3g)\",\"다진마늘(1g)\",\"다진생강(2g)\",\"•양념 : 소금(2g)\",\"찹쌀가루(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•저염간장, 배즙, 매실액과 향신채소로 나트륨을 줄인 겉절이 양념을 만들 수 있어요.\",\"instructions\":[\"1. 청경채는 반으로 자른 후 줄기 부분에 칼집을 넣는다.\",\"2. 청경채에 소금을 뿌려 30~40분 정도 절인다.\",\"3. 배는 껍질을 벗긴 후 강판에 갈아 즙을 만든다.\",\"4. 냄비에 물(30g)과 찹쌀가루를 넣고 끓여 찹쌀풀을 만들고, 충분히 식힌다.\",\"5. 볼에 식힌 찹쌀풀, 배즙, 양념장 재료를 넣고 고루 섞어 양념장을 만든다.\",\"6. 절인 청경채의 물기를 제거하고, 양념장을 버무려 마무리한다.\"]},{\"id\":\"k654\",\"title\":\"두부 새우볼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104612_1612835172747.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104637_1612835197531.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104650_1612835210980.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104716_1612835236211.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104730_1612835250572.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104744_1612835264926.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210209/20210209104803_1612835283375.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(100g)\",\"냉동 새우살(90g)\",\"양파(30g)\",\"새송이버섯(100g)\",\"생강가루(1g)\",\"후춧가루(1g)\",\"소금(1g)\",\"소금(1g)\",\"후춧가루(1g)\",\"파슬리가루(2g)\",\"식용유(25ml)\",\"버터(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해산물인 새우를 이용해 간을 맞추고 나트륨의 사용을 줄였어요.\\n나트륨 배출에 도움을 주는 칼륨이 풍부한 새송이버섯을 사용했어요.\\n새송이버섯의 쫄깃한 식감으로 맛의 심심함을 보완했어요.\",\"instructions\":[\"1. 두부는 물기를 제거한 뒤 칼등으로 으깨고, 새우와 양파는 잘게 다지고, 새송이버섯은 한입 크기로 썬다.\",\"2. 으깬 두부와 잘게 다진 새우, 양파는 밑간해 고루 버무린 뒤 적당량(25g)씩 떼어 동그랗게 빚는다.\",\"3. 중간 불로 달군 팬에 식용유(25㎖)를 둘러 10~15분간 두부새우볼을 골고루 익혀 꺼낸다.\",\"4. 같은 팬에 새송이버섯을 5분간 볶아 꺼낸다.\",\"5. 약한 불로 줄인 뒤 같은 팬에 버터와 밀가루를 넣고 3~5분간 볶아 블론드 루를 만들고 우유를 부은 뒤 10분간 끓인다.\",\"6. 구운 두부새우볼과 버섯, 소금(1g), 후춧가루(1g)를 넣은 뒤 그릇에 담고 파슬리가루(2g)를 뿌린다.\"]},{\"id\":\"k655\",\"title\":\"소고기육전과 전복내장소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9m5\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9oA\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9pP\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9q-\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9tg\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF9uN\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"부챗살(150g)\",\"쪽파(5g)\",\"홍고추(5g)\",\"익힌 전복내장(5g)\",\"다진 건새우(5g)\",\"밀가루(20g)\",\"달걀물(50g)\",\"생강(1g)\",\"저염 간장(5g)\",\"맛술(2g)\",\"식초(2g)\",\"참기름(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 후춧가루로 고기를 밑간해 잡내를 제거하고 간을 맞췄어요.\",\"instructions\":[\"1. 부챗살은 3mm로 썰어 후춧가루를 뿌려 버무리고, 쪽파, 홍고추, 익힌 전복내장은 잘게 다진다.\",\"2. 밀가루에 다진 건새우를 섞은 뒤, 부챗살에 밀가루 → 달걀물 순으로 입힌다.\",\"3. 다진 쪽파, 홍고추, 익힌 전복내장에 초간장 재료를 섞어 전복내장소스를 만든다.\",\"4. 중간 불로 달군 팬에 식용유(10㎖)를 두른 뒤 옷을 입힌 부챗살을 앞뒤로 4분간 굽는다.\",\"5. 그릇에 구운 부챗살을 담고 전복내장소스를 곁들인다.\"]},{\"id\":\"k656\",\"title\":\"라이스페이퍼 수제소시지\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeu8m\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJev88\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJev9d\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJevAy\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJevCF\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJevEs\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJevGz\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 다진 돼지고기(600g)\",\"사각 라이스페이퍼(8장)\",\"새우젓(0.5Ts)\",\"저염 간장(0.5Ts)\",\"버섯가루(1Ts)\",\"스테비아(0.3Ts)\",\"찹쌀가루(2Ts)\",\"후춧가루(0.3Ts)\",\"훈제 파프리카파우더(1.5Ts)\",\"카옌 페퍼(0.5Ts)\",\"커민(0.5Ts)\",\"다진 양파(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•저염 간장, 버섯가루, 향신료를 사용하여 짠맛을 보완했어요.\\n•스테비아를 이용하여 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 다진 돼지고기(300g)에 밑간한 뒤 얼음물(¼컵)을 넣어 찰기가 생길 때까지 치대 소시지 반죽을 만든다.\",\"2. 남은 다진 돼지고기(300g)에 양념과 얼음물(¼컵)을 넣고 고루 섞어 치대 다른 소시지 반죽을 만든다.\",\"3. 두 가지 소시지 반죽은 짤주머니에 각각 담아 냉장실에서 30분간 숙성한다.\",\"4. 라이스페이퍼 양면에 물을 약간 묻히고, 소시지 반죽을 일정하게 짠 뒤 돌돌 말아 소시지를 만든다.\",\"5. 약한 불로 달군 팬에 식용유를 두르고, 소시지를 돌려가며 5분간 골고루 익힌다.\",\"6. 센 불로 올려 1분간 더 익혀 마무리한다.\"]},{\"id\":\"k657\",\"title\":\"치즈토마토 가지구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr94St\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96CX\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96Dy\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96HM\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96K8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96M5\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96Pz\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 새송이버섯(1개)\",\"양파(½개)\",\"토마토(2~3개)\",\"가지(2개)\",\"돼지고기(목살\",\"200g)\",\"슈레드 모차렐라치즈(½컵)\",\"올리브유(1Ts)\",\"다진 마늘(2Ts)\",\"쌈장(0.5Ts)\",\"파프리카가루(약간)\",\"바질잎(3~4장)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 토마토는 나트륨 배출에 도움을 줘요.\\n•파프리카가루를 이용하여 감칠맛을 더해 싱거운 맛을 보완했어요.\",\"instructions\":[\"1. 새송이버섯, 양파, 토마토는 굵게 다지고, 가지는 모양대로 길게 썰고, 돼지고기는 한입 크기로 썬다.\",\"2. 중간 불로 달군 마른 팬에 가지를 올려 앞뒤로 노릇하게 굽는다.\",\"3. 같은 팬에 올리브유를 두르고 다진 마늘을 넣어 노릇하게 볶고, 양파와 새송이버섯을 넣어 양파가 투명해질 때까지 볶는다.\",\"4. 중간 불로 올린 뒤 목살을 넣어 겉면의 색이 변할 때까지 볶고, 토마토를 넣어 으깬다.\",\"5. 쌈장과 파프리카가루를 넣어 고루 섞고, 토마토 국물이 배어 나오면 바질을 손으로 뜯어 넣은 뒤 국물이 자작해질 때까지 끓인다.\",\"6. 그릇에 ⑤의 재료를 담은 뒤 가지를 엇갈려 올리고, 치즈를 얹은 뒤 전자레인지에 넣어 모차렐라치즈가 녹을 때까지 조리해 마무리한다.\"]},{\"id\":\"k658\",\"title\":\"묵은지 밀푀유나베\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr99W1\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Gou\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GqI\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Gr8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GsX\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Gv1\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Gwi\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 묵은지(¼포기)\",\"배추(6장)\",\"깻잎(10장)\",\"소고기(샤브샤브용\",\"150g)\",\"콩나물(1줌=20g)\",\"북어채(1줌=10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•묵은지를 물에 담가 나트륨 함량을 줄였어요.\\n•콩나물과 북어채를 사용하여 재료 본연의 감칠맛을 살렸어요.\",\"instructions\":[\"1. 묵은지는 흐르는 물에 헹군 뒤 찬물에 30분간 담가둔다.\",\"2. 배추, 깻잎, 소고기, 묵은지 순으로 층층이 쌓는다.\",\"3. 쌓은 재료를 3~4cm 크기로 자른다.\",\"4. 냄비에 재료를 둘러 담고, 가운데에 콩나물과 북어채를 담는다.\",\"5. 물(3컵)을 넣는다.\",\"6. 중간 불로 10분간 끓여 마무리한다.\"]},{\"id\":\"k659\",\"title\":\"생선까스&타르타르소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313013838_1678682318628.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034258_1678084978921.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034322_1678085002552.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034359_1678085039765.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034420_1678085060063.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034443_1678085083478.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034508_1678085108967.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 명태포(40g)\",\"튀김가루(20g)\",\"달걀(1/4개)\",\"식용유(5g)\",\"물(30g)\",\"•밑간 : 후춧가루(1g)\",\"레몬즙(3g)\",\"•타르타르 소스 : 삶은 달걀(1/2개)\",\"마요네즈(5g)\",\"홍고추(1g)\",\"청양고추(1g)\",\"양파(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•타르타르소스에 피클 대신 홍고추와 청양고추를 넣어 매콤한 맛을 첨가해 나트륨을 낮췄어요.\\n•소금 대신 레몬즙을 사용하여 나트륨을 낮췄어요.\",\"instructions\":[\"1. 명태포는 키친타월에 올려 물기를 제거한다.\",\"2. 후춧가루와 레몬즙을 뿌려 비린내를 제거한다.\",\"3. 볼에 튀김가루와 달걀, 식용유, 물을 섞어 튀김옷을 만든다\",\"4. 명태포에 튀김옷을 입힌 뒤 170℃ 기름에서 두 번 튀긴다.\",\"5. 삶은 달걀, 홍고추, 청양고추, 양파를 다져 볼에 섞은 뒤 마요네즈와 레몬즙, 후춧가루를 섞어 소스를 만든다\",\"6. 생선까스에 타르타르소스를 곁들여 담는다.\"]},{\"id\":\"k660\",\"title\":\"미옹 카레\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041400_1699254840769.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041514_1699254914380.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041531_1699254931309.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041551_1699254951642.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041608_1699254968541.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041623_1699254983031.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041639_1699254999867.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [간편식 재료] 커리 소스(80g)\",\"홍새우 튀김(150g)\",\"컬리플라워(50g)\",\"감자튀김(100g)<br>\",\"• [추가 재료] 감자(2개=360g)\",\"불린 미역(70g\",\"마른 미역 10g)\",\"양파(110g)\",\"식용유(10g)\",\"물(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 감자와 미역은 칼륨이 풍부하여 체내 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 감자로 만든 옹심이 반죽을 숟가락의 절반 크기로 동그랗게 모양을 만든다.\",\"2. 180도로 예열한 에어프라이어에 홍새우 튀김을 15분 동안 익힌다.\",\"3. 팬에 식용유를 두르고 양파를 채 썰어 넣고 갈색이 나도록 볶는다.\",\"4. 컬리플라워, 감자튀김, 불린 미역을 넣고 3분 동안 더 볶는다.\",\"5. 커리 소스, 물(1/2컵=100g), 옹심이를 넣고 3분 동안 끓인다.\",\"6. 접시에 담고 홍새우 튀김을 올려 마무리한다.\"]},{\"id\":\"k661\",\"title\":\"곤약 감자조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011910_1554697150266.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012018_1554697218725.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012051_1554697251494.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012107_1554697267792.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012130_1554697290917.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012148_1554697308694.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012210_1554697330618.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"곤약 100g\",\"감자 50g\",\"풋고추 5g\",\"홍고추 5g\",\"다시마 10g\",\"간장 15g\",\"설탕 10g\",\"미림 15g\",\"참기름 3g\",\"식초 10g\",\"물 200g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"곤약과 감자를 조림장에 익히지 않고 따로 삶아 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 곤약과 감자는 2cm ? 2cm 크기로 썰고 풋고추와 홍고추는 송송 썰어 씨를 제거한다.\",\"2. 물(200g)에 다시마를 넣고 끓여 육수를 만든 뒤 다시마를 건진다.\",\"3. 육수에 간장, 설탕, 미림을 섞어 조림장을 만든다.\",\"4. 곤약과 감자를 끓는 물에 넣고 80% 정도 익힌 뒤 건져 식힌다.\",\"5. 4에 조림장 50g을 넣고 살짝 졸인다.\",\"6. 불을 끄고 참기름을 섞는다.\"]},{\"id\":\"k662\",\"title\":\"배추된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022612_1583731572075.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022132_1583731292189.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022147_1583731307341.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022201_1583731321063.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022215_1583731335496.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022233_1583731353838.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309022246_1583731366341.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추 20g\",\"두부 30g\",\"양파 20g\",\"대파 10g\",\"다시멸치 5g\",\"청양고추 1g\",\"다진마늘 0.5g\",\"생강즙 0.5g\",\"된장 2g\",\"쌀뜨물 60ml\",\"물 300ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부는 미리 한번 데쳐 내면 염분을 줄일 수 있어요.\",\"instructions\":[\"1. 배추, 양파, 두부는 한입 크기로 썰고 대파와 청양고추는 어슷썰어 준비한다.\",\"2. 전처리 후 남은 양파껍질, 대파뿌리와 다시멸치를 넣고 육수를 우린 후 거른다.\",\"3. 두부는 끓는 물에 10분정도 넣어서 염분기를 빼준다.\",\"4. 냄비에 참기름과 배추를 넣어 볶다가 쌀뜨물과 육수를 넣어 끓인다.\",\"5. 두부와 양파, 대파, 고추를 넣는다.\",\"6. 된장, 간마늘, 생강즙을 넣어 간을 맞춘다.\"]},{\"id\":\"k663\",\"title\":\"한우굴라쉬\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309035140_1583736700730.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309035924_1583737164266.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309035954_1583737194373.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309040008_1583737208826.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309040157_1583737317308.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309040215_1583737335926.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309040232_1583737352462.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기 등심 17.5g\",\"양파 7.5g\",\"감자 15g\",\"파프리카 3.2g\",\"토마토 25g\",\"마늘 1.7g\",\"밀가루 1.7g\",\"토마토페이스트 13.7g\",\"케첩 9g\",\"버터 5g\",\"올리브유 1g\",\"월계수잎 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토의 새콤달콤한 맛이 짠맛을 대체해줘서 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 쇠고기 등심은 큐브 모양으로 썰어 소금, 후추 간을 하고 밀가루를 묻힌다.\",\"2. 감자, 토마토는 한 입 크기로 썰고, 마늘은 편썰기, 파프리카는 채썰기, 양파는 다진다.\",\"3. 팬에 버터와 올리브유를 넣고 양파, 마늘을 볶다가 쇠고기를 넣어 볶는다.\",\"4. 쇠고기가 익으면 감자, 토마토, 파프리카를 넣는다.\",\"5. 토마토 페이스트, 케찹을 넣어 볶다가 물과 월계수잎을 넣어 끓인다.\",\"6. 소금, 후추로 간을 하고 푹 익혀준다.\"]},{\"id\":\"k664\",\"title\":\"요거트강화순무김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050922_1611562162968.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125050947_1611562187845.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051002_1611562202196.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051037_1611562237705.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051051_1611562251555.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051103_1611562263937.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051140_1611562300279.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"순무 40g\",\"쪽파 0.2g\",\"고운 고춧가루 1g\",\"굵은 고춧가루 1g\",\"다진마늘 1g\",\"플레인요거트 2g\",\"소금 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일무라고 불리는 순무에 플레인 요거트의 상큼한 맛을 곁들여 소금의 사용을 줄였어요.\",\"instructions\":[\"1. 순무는 2.5*2.5*0.3 cm 크기로 나박 모양으로 썬다.\",\"2. 고운 고춧가루, 굵은 고춧가루, 다진마늘, 소금, 요거트를 섞어 양념장을 만든다.\",\"3. 쪽파는 0.2cm 크기로 송송 썰어 준비한다.\",\"4. 순무에 양념장을 넣고 버무려 준다.\",\"5. 양념된 순무를 하루 정도 냉장보관하여 숙성시킨다.\",\"6. 숙성된 순무김치에 쪽파를 고명으로 얹어 제공한다.\"]},{\"id\":\"k665\",\"title\":\"크림카레소스를 곁들인 함초두부스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210102914_1612920554422.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210103023_1612920623709.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210103036_1612920636249.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210103050_1612920650832.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210103104_1612920664477.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210103116_1612920676950.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210103128_1612920688440.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파(30g)\",\"당근(20g)\",\"양송이버섯(20g)\",\"불린 함초(15g)\",\"으깬 두부(120g)\",\"닭가슴살(60g)\",\"달걀(40g)\",\"빵가루(5g)\",\"밀가루(10g)\",\"버터(10g)\",\"우유(250g)\",\"강황가루(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"건함초는 뜨거운 물(100㎖)에 40분간 불린 뒤 사용해요.\\n두부와 닭가슴살이 들어간 스테이크 반죽에 소금 대신 함초를 넣어 나트륨의 사용을 줄였어요.\\n시판 소스가 아닌 수제 크림카레소스를 만들어 나트륨의 사용을 줄였어요.\",\"instructions\":[\"1. 양파와 당근, 양송이버섯, 불린 함초는 잘게 다진다.\",\"2. 으깬 두부는 물기를 제거한 뒤 닭가슴살과 믹서에 넣어 곱게 갈고 다진 양파(20g), 당근(10g), 함초(7.5g), 달걀, 빵가루, 함초소금(0.25g)을 넣어 버무린다.\",\"3. 두부 반죽은 동그랗게 만들어 중간 불로 달군 팬에 식용유(10㎖)를 두른 뒤 4분간 앞뒤로 노릇하게 구워 꺼낸다.\",\"4. 약한 불로 달군 냄비에 밀가루, 버터를 넣어 루를 만들고 우유, 강황가루, 다진 양파(10g)와 당근(10g), 양송이버섯, 다진 마늘(5g)을 넣어 섞은 뒤 저염 간장(3g), 함초소금(0.25g)으로 간한다.\",\"5. 믹서에 소스와 다진 함초(7.5g)를 넣어 곱게 간다.\",\"6. 그릇에 함초두부스테이크를 올리고 소스를 뿌린다.\"]},{\"id\":\"k666\",\"title\":\"레몬등갈비구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308013049_1678249849873.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020210_1678251730139.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020237_1678251757897.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020255_1678251775439.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020312_1678251792175.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020329_1678251809244.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020351_1678251831171.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 등갈비(150g)\",\"마늘(10g)\",\"레몬(15g)\",\"•밑간 : 소주(10g)\",\"로즈메리(1g)\",\"다진마늘(1g)\",\"후춧가루(1g)\",\"올리브유(5g)\",\"•디핑소스 : 요거트(10g)\",\"꿀(2g)\",\"레몬즙(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•레몬으로 간을 맞춰 나트륨 함량을 낮췄어요.\\n•디핑 소스는 뿌리지 않고 찍어 먹으면 나트륨 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 등갈비는 찬물(5컵)에 담가 1시간 이상 핏물을 제거한다.\",\"2. 등갈비는 한 쪽씩 썬다.\",\"3. 손질한 등갈비는 밑간한 뒤 마늘, 로즈메리와 함께 버무려 30분 정도 재운다.\",\"4. 재운 등갈비는 190℃로 예열한 오븐에 40분간 굽고, 뒤집어서 같은 온도에 30분간 더 굽는다.\",\"5. 디핑소스를 만든다.\",\"6. 그릇에 등갈비구이를 담은 뒤 레몬을 짜 즙을 뿌리고, 디핑 소스를 곁들여 마무리한다.\"]},{\"id\":\"k667\",\"title\":\"밀푀유 채소 웰링턴\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041905_1699255145380.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041939_1699255179546.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106041955_1699255195491.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106042010_1699255210505.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106042024_1699255224812.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106042043_1699255243788.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106042100_1699255260819.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"2인분 기준<br>\",\"• [가정 간편식 재료] 배추(200g)\",\"소고기(200g)\",\"숙주(80g)\",\"청경채(30g)\",\"표고버섯(20g)\",\"새송이버섯(50g)\",\"백목이버섯(3g)\",\"다시마(10g)\",\"깻잎(5g)<br>\",\"• [추가 재료] 두부(150g)\",\"머스타드(17g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"• 단맛이 나는 천연 식재료인 양파를 활용한 소스를 사용하여 첨가당의 사용량을 줄였어요.\\n<br>• 덕셀 소스에 버터 대신 올리브유, 우유, 들깨가루를 활용하여 풍미와 고소함은 높이고 소금의 사용량은 줄였어요.\",\"instructions\":[\"1. 표고버섯, 양파, 마늘은 다지고, 끓는 물에 배추, 숙주, 청경채를 데친다. 토마토는 껍질을 벗기고, 소고기는 키친타월로 핏물을 제거하고 두부는 물기를 제거한다.\",\"2. 팬에 올리브유(20g)를 두르고 손질한 표고버섯, 양파(15g), 마늘을 볶은 뒤 간장(15g), 들깨가루, 우유를 넣어 덕셀을 만들고 식힌다.\",\"3. 양파(20g)를 볶은 뒤 물을 붓고 다시마, 새송이버섯, 백목이버섯, 토마토를 넣고 중약 불에서 15분 동안 끓여 갈고 간장(15g), 소금(3g)으로 간해 브라운 소스를 만든다.\",\"4. 소고기에 머스타드, 덕셀을 바르고 깻잎, 두부, 숙주, 청경채를 넣어 감싸준 후 소금(5g), 후추를 뿌리고, 팬에 올리브유(20g)를 두르고 소고기를 굽고, 로즈메리를 넣는다.\",\"5. 종이 포일에 올리브유(20g)를 뿌리고, 데친 배추를 올린 후 위에 구운 고기와 덕셀(30g)을 올리고 돌돌 말아 에어프라이어에 200도, 10분간 굽는다.\",\"6. 접시에 웰링턴을 담고 여분의 덕셀, 브라운 소스를 올리고 마무리한다.\"]},{\"id\":\"k668\",\"title\":\"참나물 매콤함박스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120011100_1732075860462.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111041_1732068641663.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111055_1732068655084.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111105_1732068665415.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111117_1732068677701.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111130_1732068690385.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111140_1732068700943.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료] 참나물(5g)\",\"부침두부(15g)\",\"닭가슴살(40g)\",\"청양고추(2g)<br>\",\"[양념] 올리브유(12g)\",\"고추장(10g)\",\"고춧가루(2g)\",\"알룰로스(5g)\",\"후추(1g)\",\"다진 마늘(4g)\",\"깨(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•청양고추를 넣어 매콤한 맛으로 심심한 맛을 보완했어요.\",\"instructions\":[\"1. 닭가슴살, 부침두부, 참나물, 청양고추를 잘게 다진다.\",\"2. 볼에 담아 소금으로 밑간하고 4등분하여 둥글게 다져 함박스테이크를 만든다.\",\"3. 달군 팬에 올리브유를 두르고 함박스테이크를 굽는다.\",\"4. 고추장, 고춧가루, 알룰로스, 후추, 다진 마늘, 물을 넣어 소스를 만든다.\",\"5. 달군 팬에 소스를 넣고 살짝 졸인다.\",\"6. 접시에 함박스테이크를 담고 소스를 올린 후 깨를 뿌려 마무리한다.\"]},{\"id\":\"k669\",\"title\":\"과일 먹은 닭탕수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012615_1554697575394.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012702_1554697622088.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012732_1554697652820.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012753_1554697673568.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012811_1554697691704.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012829_1554697709232.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408012844_1554697724213.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(다리살) 300g\",\"포도 15g\",\"미니사과 30g\",\"파인애플 15g\",\"전분 80g\",\"설탕 20g\",\"레몬 70g\",\"청주 10g\",\"후추 0.2g\",\"소금 2g\",\"물 200g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일을 이용해 천연의 새콤 달콤한 맛을 내 소금 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 닭다리의 살만 발라내 4cm ? 1cm 크기로 썬다.\",\"2. 1에 소금, 후추로 밑간한 뒤 청주를 넣어 재운다.\",\"3. 포도알은 2등분하고 사과, 파인애플은 한 입 크기로 썬다.\",\"4. 2에 녹말을 입혀 기름에 2번 튀긴다.\",\"5. 팬에 물, 설탕, 레몬즙을 넣고 한소끔 끓인다.\",\"6. 소스에 물전분을 넣어 농도를 맞추고 썰어둔 과일을 넣는다.\"]},{\"id\":\"k670\",\"title\":\"콜리플라워미역국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023204_1583731924541.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023251_1583731971026.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023305_1583731985515.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023317_1583731997484.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023335_1583732015547.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023348_1583732028816.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309023403_1583732043020.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콜리플라워 25g\",\"건미역 2g\",\"(육수) 물 500ml\",\"디포리 2g\",\"양파 20g\",\"무 20g\",\"(양념) 저염간장 1g\",\"건표고버섯 3g\",\"건새우 3g\",\"물 300ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"건표고버섯과 건새우를 갈아 만든 천연조미료가 풍미를 높여 소금사용을 줄여줘요.\",\"instructions\":[\"1. 디포리를 살짝 볶아 물, 양파, 무를 넣고 육수를 낸다.\",\"2. 건새우를 볶아서 건표고버섯과 함께 곱게 간다.\",\"3. 콜리플라워는 먹기 좋은 크기로 썰어 볶는다.\",\"4. 냄비에 불려서 손질해 놓은 미역과 참기름을 넣어 볶는다.\",\"5. 육수를 넣고 푹 끓이다가 ②와 저염간장으로 간을 맞춘다.\",\"6. 마지막으로 콜리플라워를 넣어 완성한다.\"]},{\"id\":\"k671\",\"title\":\"구기자모듬장조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011138_1584072698244.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011248_1584072768170.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011304_1584072784898.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011317_1584072797861.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011335_1584072815025.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011347_1584072827654.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313011400_1584072840511.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"한돈(사태) 30g\",\"메추리알 30g\",\"당근 10g\",\"곤약 10g\",\"구기자 5g\",\"양파 10g\",\"파 10g\",\"다시마 5g\",\"마늘 10g\",\"표고버섯 10g\",\"저염간장 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"약선재료인 구기자와 야채들로 저염조림간장을 만들었어요.\",\"instructions\":[\"1. 한돈은 사태로 준비하여 깍둑썰기하여 세척한다.\",\"2. 양파, 파, 다시마, 표고버섯, 마늘은 깨끗이 세척 후 적당한 크기로 자르고, 당근, 곤약은 깍뚝썰기하여 준비한다.\",\"3. 냄비에 물과 저염간장을 2:1 비율로 조림장을 준비한다.\",\"4. 조림장에 구기자 및 양파, 파, 다시마, 표고버섯, 마늘을 넣고 끓인다.\",\"5. 조림장이 끓으면 사태, 메추리알, 당근, 곤약을 넣고 조린다.\",\"6. 접시에 담아서 완성한다.\"]},{\"id\":\"k672\",\"title\":\"오미자저염나박김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051842_1611562722531.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051908_1611562748474.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051924_1611562764362.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051937_1611562777717.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125051952_1611562792378.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125052007_1611562807357.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125052021_1611562821450.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추 10g\",\"콜라비 5g\",\"오이 2g\",\"당근 2g\",\"실파 1g\",\"홍고추 1g\",\"레몬 5g\",\"오미자엑기스 5g\",\"식초 30g\",\"설탕 5g\",\"물 10ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오미자 엑기스와 식초의 새콤달콤함이 소금 없이도 맛을 내줘요.\",\"instructions\":[\"1. 배추, 콜라비, 오이, 당근을 나박모양으로 썬다.\",\"2. 레몬은 은행잎썰기, 홍고추는 어슷썰기, 실파는 1.5cm 길이로 썬다.\",\"3. 식초, 설탕, 오미자청으로 단촛물을 만든다.\",\"4. 단촛물에 야채, 레몬, 고추, 실파를 넣고 숙성시킨다.\",\"5. 숙성 후 색을 보고 오미자청을 더 첨가한다.\",\"6. 숙성된 오미자 나박김치를 그릇에 담아준다.\"]},{\"id\":\"k673\",\"title\":\"메밀면 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210110714_1612922834280.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210110740_1612922860531.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210110754_1612922874953.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210110810_1612922890913.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210110824_1612922904787.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210110839_1612922919610.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양상추(40g)\",\"당근(10g)\",\"방울토마토(30g)\",\"닭가슴살(60g)\",\"메밀면(90g)\",\"어린잎채소(10g)\",\"식초(20g)\",\"간장(15g)\",\"올리브유(15g)\",\"다진 마늘(3g)\",\"올리고당(5g)\",\"유자청(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수제 유자오리엔탈소스를 활용해 나트륨의 사용을 줄였어요.\",\"instructions\":[\"1. 양상추는 한입 크기로 찢고, 당근은 채 썰고, 방울토마토는 4등분한다.\",\"2. 끓는 물(2컵)에 닭가슴살을 넣어 10분간 익힌 뒤 건져 결대로 찢는다.\",\"3. 끓는 물(2컵)에 메밀면을 넣어 5분간 삶아 건진 뒤 찬물에 헹궈 체에 밭쳐 물기를 제거한다.\",\"4. 유자오리엔탈소스를 만든다.\",\"5. 그릇에 준비한 재료와 어린잎채소를 담고 유자오리엔탈소스를 뿌린다.\"]},{\"id\":\"k674\",\"title\":\"치즈 두부 튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111559_1612923359198.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210112118_1612923678175.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210112132_1612923692904.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210112147_1612923707555.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210112159_1612923719770.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210112213_1612923733931.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210112228_1612923748754.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마(50g)\",\"호두(15g)\",\"우유(10㎖)\",\"두부(150g)\",\"빵가루(50g)\",\"모차렐라치즈(15g)\",\"식용유(100ml)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마와 모차렐라치즈를 사용하여 단맛과 짠맛, 고소함을 모두 맛볼 수 있어요.\",\"instructions\":[\"1. 고구마는 끓는 물(2컵)에 4분간 삶아 껍질을 제거한 뒤 곱게 으깬다.\",\"2. 호두는 굵게 부순다.\",\"3. 으깬 고구마에 호두, 우유를 넣어 고루 섞는다.\",\"4. 키친타월을 이용해 두부의 물기를 제거한 뒤 곱게 으깨고 빵가루(15g)를 넣어 섞는다.\",\"5. 두부를 얇게 편 뒤 고구마와 모차렐라치즈를 넣어 동그랗게 빚는다.\",\"6. 두부를 얇게 편 뒤 고구마와 모차렐라치즈를 넣어 동그랗게 빚는다.\"]},{\"id\":\"k675\",\"title\":\"단호박 라타투이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJeuf4\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJevya\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJevz_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJew04\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJew1h\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJew3l\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJew7C\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 가지(1개)\",\"주키니호박(½개)\",\"토마토(1½개)\",\"단호박(1개)\",\"훈제 오리(400g)\",\"마늘(6쪽)\",\"다진 양파(½컵)\",\"다진 토마토(1컵)\",\"다진 파프리카(1컵)\",\"올리브유(2Ts)\",\"소금(0.3Ts)\",\"후춧가루(0.3Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•시판 소스 대신 직접 만든 소스로 설탕과 소금의 사용을 줄였어요.\\n•훈제오리를 끓는 물에 한번 데치면 나트륨 섭취량을 줄일 수 있어요.\",\"instructions\":[\"1. 가지, 주키니호박, 토마토는 0.3mm 두께로 썬다.\",\"2. 단호박은 전자레인지에 5분간 돌리고, 익으면 윗부분을 약간 잘라낸 뒤 씨를 제거한다.\",\"3. 중간 불로 달군 팬에 훈제오리와 마늘을 넣어 고루 볶은 뒤 단호박 속에 채운다.\",\"4. 팬에 올리브유를 두른 뒤 약한 불로 올리고, 라타투이 소스 재료, 소금, 후춧가루를 넣어 10분간 볶아 라타투이 소스를 만든다.\",\"5. 높이가 낮은 냄비에 라타투이 소스를 넓게 깔고, 손질한 채소를 둘러 담는다.\",\"6. 오리로 채운 단호박을 가운데 올린 뒤 6~8등분하여 펼치고, 중간 불로 15분간 쪄 마무리한다.\"]},{\"id\":\"k676\",\"title\":\"느타리버섯볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051519_1678090519731.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051626_1678090586108.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051645_1678090605363.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051703_1678090623293.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051719_1678090639349.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051735_1678090655396.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306051752_1678090672160.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 느타리버섯(25g)\",\"파프리카(빨간색\",\"노란색 각 10g)\",\"청피망(10g)\",\"크래미(10g)\",\"식용유(3g)\",\"•양념 : 소금(1g)\",\"후추(3g)\",\"간장(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•크래미의 간을 이용해 소금의 사용을 줄였어요.\",\"instructions\":[\"1. 느타리버섯은 밑동을 자르고 가닥가닥 찢어 데쳐서 찬물에 헹궈 물기를 제거한다.\",\"2. 파프리카와 청피망은 채 썰고, 크래미는 잘게 찢는다.\",\"3. 팬에 기름을 두르고 손질한 파프리카와 피망을 넣어 볶는다.\",\"4. 느타리버섯을 넣어 볶는다.\",\"5. 게살을 넣어 볶다가 간장으로 색을 낸다.\",\"6. 소금과 후추로 마무리한다.\"]},{\"id\":\"k677\",\"title\":\"오리들깨 겨자소스 초무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120011152_1732075912579.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111209_1732068729050.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111219_1732068739156.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111229_1732068749207.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111240_1732068760323.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111252_1732068772765.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111305_1732068785277.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료]오리고기(90g)\",\"양파(10g)\",\"당근(10g)\",\"오이(10g)<br>\",\"[양념]들깻가루(8g)\",\"겨잣가루(4g)\",\"식초(10g)\",\"레몬즙(5g)\",\"물(15ml)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•들깻가루, 겨잣가루, 식초를 넣어 매콤 새콤한 맛으로 심심한 맛을 보완하고, 깊은 맛을 더했어요.\",\"instructions\":[\"1. 달군 팬에 오리고기를 넣고 센 불에서 볶는다.\",\"2. 들깻가루, 겨잣가루, 식초, 레몬즙, 물을 섞어 양념장을 만든다.\",\"3. 양파, 당근, 오이는 채 썬다.\",\"4. 볶은 오리고기는 한 김 식힌다.\",\"5. 볼에 오리고기, 손질한 채소, 양념장을 넣고 버무린다.\",\"6. 접시에 담아 마무리한다.\"]},{\"id\":\"k678\",\"title\":\"닭고기 바비큐\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053447_1416213287870.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/849-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/849-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/849-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/849-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/849-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/849-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 60g\",\"홍피망 24g\",\"양파 30g\",\"노랑파프리카 24g\",\"양송이버섯 9g [소스소개] 소스:양파다진것 6g\",\"마늘다진것 1.2g\",\"케첩 9g\",\"홍토마토 12g\",\"설탕 3g\",\"물 18g<br /> 이탈리안시즈닝:타임 0.9g\",\"로즈마리 0.9g\",\"바질 1.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 소스에는 소금, 간장보다 염도가 낮은 케첩을 훨씬 많이 넣을 수 있으므로 고기요리에 사용하면 좋다.\",\"instructions\":[\"1. 닭가슴살은 3cm 주사위모양으로 썰고 식용유와 이탈리안 시즈닝으로 양념한다.\",\"2. 홍피망, 노랑파프리카, 양파는 3cm 크기로 썰고 양송이버섯은 반으로 썬다.\",\"3. 소스 재료를 넣고 끓인다.\",\"4. 닭가슴살은 구워서 반만 익히고 꼬치에 채소와 함께 꽂는다.\",\"5. 그릴에서 완전히 굽는다.\",\"6. 소스를 끼얹어 낸다.\"]},{\"id\":\"k679\",\"title\":\"닭고기 편육\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053449_1416213289103.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/851-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/851-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/851-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/851-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/851-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/851-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기가슴살 100g [소스소개] 밑간양념:요구르트 6g\",\"식용유 1g\",\"후춧가루 0.03g<br /> 조림장:간장 3g\",\"설탕 5g\",\"꿀 1g\",\"홍고추마른것 1g\",\"정종 5g\",\"참기름 0.8g\",\"대파 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭고기는 간하지 않고 오븐에서 굽고 저나트륨 간장소스를 만들어 곁들여내거나 먹기 직전에 얹어 제공하는 것이 좋다.\",\"instructions\":[\"1. 오븐을 175℃로 예열한다.\",\"2. 닭고기 밑간 양념으로 30분정도 재운다.\",\"3. 재워 놓은 닭고기를 175℃의 오븐에서 15분 굽는다.\",\"4. 조림장을 모두 넣고 끓인다.\",\"5. 닭고기 구운 것을 넣고 10~15분 간 졸인다.\",\"6. 닭고기를 먹기 좋게 잘라 남은 소스를 얹어 낸다.\"]},{\"id\":\"k680\",\"title\":\"돼지고기 찹쌀부침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053450_1416213290025.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/852-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/852-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/852-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/852-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/852-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/852-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기 등심 50g\",\"젖은 찹쌀가루 50g [소스소개] 밑간양념:간장 1g\",\"물엿 3g\",\"다진마늘 2g\",\"후춧가루 0.1g\",\"무순 1g\",\"레디쉬 0.3g\",\"깻잎 1.5g\",\"대파 3g 저나트륨된장소스:된장 1g\",\"파인애플 15g\",\"물 30g\",\"홍고추 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 돼지고기는 간장, 물엿, 다진마늘, 후춧가루로 밑간 한다.\",\"2. 레디쉬, 깻잎, 대파는 채썬다.\",\"3. 소스 재료들은 모두 믹서에 간다.\",\"4. 돼지고기에 찹쌀가루를 두 번 입힌다.\",\"5. 가열된 팬에 옷입힌 돼지고기를 지진다.\",\"6. 구운 돼지고기에 썰어둔 채소를 얹은 후 고기를 말아 소스와 곁들인다.\"]},{\"id\":\"k681\",\"title\":\"등심 배구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053450_1416213290929.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/853-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/853-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/853-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/853-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/853-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/853-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기등심 38g\",\"배 12g\",\"오이 9g\",\"잣가루 0.5g\",\"식용유 0.5g [소스소개] 고기재움장:포도주 2.5g\",\"후춧가루 0.1g<br /> 저나트륨초간장소스:간장 1.3g\",\"사과주스 3.8g\",\"식초 1.3g\",\"설탕 1.3g\",\"와사미 0.8g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기는 포도주와 후춧가루로만 재워두며 간을 하지 않는다. 저나트륨 초간장소스는 염도를 줄이기 위해 간장 양을 1/5정도 줄여서 사용하고, 사과주스를 넣어 줄어든 간장 양을 대신 넣어 만든 소스로 고기에 뿌려 이용하는 것이 좋다.\",\"instructions\":[\"1. 소고기등심은 손질하여 칼등으로 부드럽게 두드린 뒤 4cm 길이로 썰어서 재움장에 30분 정도 재운다.\",\"2. 오이는 0.2cm 두께로 동그랗게 썰어 소금에 살짝 절였다 짠다.\",\"3. 배는 껍질과 씨를 제거하고 반달모양으로 0.2cm 두께로 썬다.\",\"4. 팬에 식용유를 두르고 오이는 센불에서 살짝 볶고 배는 노릇하게 지진다.\",\"5. 팬에 재워둔 소고기등심을 지지고 초간장소스를 만든다.\",\"6. 노릇하게 지진 배에 소고기등심을 오이, 잣가루를 얹고 가볍게 싸서 저나트륨 초간장에 찍어 먹는다.\"]},{\"id\":\"k682\",\"title\":\"버섯소스를 곁들인 돼지 등심 스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053454_1416213294458.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/855-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/855-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/855-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/855-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/855-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/855-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심 100g\",\"양송이버섯 45g\",\"표고버섯 15g\",\"애느타리버섯 10g\",\"파슬리다진것 3g\",\"버터 5g\",\"후춧가루 0.1g\",\"밀가루 4g\",\"식용유 2g\",\"화이트와인 50g\",\"물 50g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시중에서 판매하는 버터는 보통 가염버터인데 저나트륨 조리시에는 무염버터로 쓰면 나트륨을 줄이는데 도움이 된다.\",\"instructions\":[\"1. 양송이버섯과 표고버섯은 얇게 썰고 애느타리버섯은 잘게 찢어 놓는다.\",\"2. 썰어놓은 돼지고기는 후춧가루와 밀가루로 밑간한다.\",\"3. 가열된 팬에 식용유를 넣고 고기를 굽는다.\",\"4. 고기를 한쪽으로 밀어두고 버섯들을 넣어 볶다가 화이트와인과 물을 넣고 끓인다. 반쯤 졸아지면 고기를 꺼낸다.\",\"5. 팬에 버터를 넣어 소스의 농도를 맞추고 다진 파슬리를 뿌려 소스를 완성한다.\",\"6. 고기에 소스를 얹어 낸다.\"]},{\"id\":\"k683\",\"title\":\"쇠고기 감자찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053456_1416213296253.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/857-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/857-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/857-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/857-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/857-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/857-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"알감자 80g\",\"쇠고기다진것 50g\",\"육수 50g\",\"녹말가루 3g [소스소개] 쇠고기양념:파다진것 1g\",\"마늘 다진것 1g\",\"청고추 다진것 1g\",\"홍고추 다진것 1g\",\"간장 1.2g\",\"설탕 1.2g\",\"깨소금 0.5g\",\"참기름 1g\",\"후춧가루 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"보통 찜은 간장이나 소금으로 2~3% 간을 하는 요리인데 쇠고기감자찜은 간장을 적게 넣고 찜을 해서 맛이 잘 어울리는 요리이다.\",\"instructions\":[\"1. 감자는 껍질을 벗겨 반으로 갈라편편하게 놓일 수 있도록 밑면을 다듬는다.\",\"2. 숟가락으로 감자 윗면을 파낸다.\",\"3. 다진 소고기는 분량의 재료를 넣고 양념한다.\",\"4. 파낸 감자 안에 녹말을 묻히고 양념한 소고기를 채운다.\",\"5. 감자가 잠길 정도로 육수를 붓고 끓인다.\",\"6. 찜이 완성되면 물녹말을 부어 걸쭉하게 만든다.\"]},{\"id\":\"k684\",\"title\":\"양송이버섯과 포도주스를 가미한 등심구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053458_1416213298111.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/859-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/859-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/859-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/859-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/859-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/859-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기등심 50g\",\"양송이버섯 20g\",\"포도주스 50g\",\"토마토 80g\",\"물 15g\",\"바질 2.5g\",\"설탕 1.3g\",\"오레가노 2g\",\"마늘가루 0.5g\",\"소금 0.4g\",\"파슬리다진것 5g\",\"월계수잎 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 요리에서는 여러 사양 향신료를 섞어서 조리하면 강한 향으로 인해 염도가 낮은 것이 잘 인식되지 않게 해준다.\",\"instructions\":[\"1. 유리볼에 고기를 담고 로즈마리, 통후추 으깬 것, 양송이버섯 썬 것, 월계수잎, 포도주스를 넣고 절인다.\",\"2. 작은 유리볼에 토마토소스와 소고기육수, 바질, 오레가노, 설탕, 마늘가루를 넣고 섞는다.\",\"3. 재워둔 고기를 꺼내 가열된 팬에 앞 뒷면을 익힌다.\",\"4. 고기를 구웠던 팬에 1의 남은 국물과 2의 토마토소스를 붓는다.\",\"5. 팬에 붙은 고기 조각들을 긁어내 함께 중불에서 끓여 양송이버섯 소스를 만든다.\",\"6. 스테이크를 썰어 그릇에 담고 양송이버섯 소스를 끼얹는다.\"]},{\"id\":\"k685\",\"title\":\"새우살토마토스튜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309025909_1583733549459.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309025937_1583733577515.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309025949_1583733589893.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309030002_1583733602099.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309030017_1583733617556.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309030030_1583733630522.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309030044_1583733644603.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우살 30g\",\"토마토 20g\",\"양파 15g\",\"당근 10g\",\"애호박 15g\",\"건다시마 3g\",\"버터 3g\",\"케찹 5g\",\"10g\",\"후추 0.1g\",\"소금 0.2g\",\"물 300ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우살을 데쳐 사용해 염분을 줄였어요.\",\"instructions\":[\"1. 다시마로 육수를 낸다.\",\"2. 새우살은 데치고 토마토는 칼집을 내어 데친 후 껍질을 벗긴다.\",\"3. 토마토, 양파, 당근, 호박은 먹기 좋은 크기로 썬다.\",\"4. 새우살과 당근, 호박을 버터에 볶아 준다.\",\"5. 기름을 두른 팬에 토마토와 양파를 넣고 조린다.\",\"6. ⑤에 ④와 육수, 케첩을 넣고 끓인 후 후추를 넣고 소금으로 간을 하여 마무리한다.\"]},{\"id\":\"k686\",\"title\":\"견과류문어떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102240_1584062560564.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102316_1584062596568.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102330_1584062610223.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102343_1584062623212.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102433_1584062673193.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102446_1584062686200.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102458_1584062698308.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돈민찌 80g\",\"우민찌 30g\",\"떡 40g\",\"문어 3g\",\"배 5g\",\"호두 3g\",\"아몬드 3g\",\"다진마늘 5g\",\"다진파 5g\",\"찹쌀가루 5g\",\"참기름 1g\",\"후추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"문어가 가진 짠맛으로 간을 하고 견과류로 고소함을 살렸어요.\",\"instructions\":[\"1. 삶은 문어, 배, 호두, 아몬드는 작게 자르고, 파와 마늘은 다진다.\",\"2. 대추는 돌려 깍기 하여 돌돌 말아 자른다.\",\"3. 돈민찌, 우민찌는 잘 섞어주고 ①재료와 참기름, 후추, 찹쌀가루를 넣어 치대어 준다.\",\"4. 데쳐서 익힌 떡에 밀가루를 얇게 입히고 ③의 반죽을 붙혀 떡갈비를 만든다.\",\"5. 떡갈비를 팬에 올려 속이 익을 때까지 굽는다.\",\"6. 잘라놓은 대추와 잣을 고명으로 올려 완성한다.\"]},{\"id\":\"k687\",\"title\":\"배물김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125052704_1611563224561.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125053313_1611563593939.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125053329_1611563609059.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125053343_1611563623712.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125053359_1611563639089.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125053756_1611563876811.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125053810_1611563890459.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배 30g\",\"미나리 1g\",\"청홍고추 0.2g\",\"감자 4g\",\"설탕 3g\",\"마늘 2g\",\"생강 1g\",\"물 100ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 감자를 사용해 나트륨 배출을 도왔어요.\",\"instructions\":[\"1. 감자를 삶아 물과 함께 갈아 감자풀을 만든다.\",\"2. 배는 나박썬다.\",\"3. 청홍고추는 어슷썬다.\",\"4. 미나리는 고추와 비슷한 크기로 썰어준다.\",\"5. 준비된 재료에 감자 전분물, 설탕, 마늘, 생강을 넣고 섞어 물김치를 만든다.\",\"6. 하루 정도 숙성시킨 다음 먹는다.\"]},{\"id\":\"k688\",\"title\":\"성주참외동치미\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054438_1611564278881.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054038_1611564038248.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054140_1611564100267.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054155_1611564115991.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054215_1611564135168.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054231_1611564151352.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210125/20210125054242_1611564162881.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"참외 20g\",\"양파 10g\",\"배 5g\",\"대파 3g\",\"마늘 3g\",\"홍고추 1g\",\"생강 1g\",\"식초 4g\",\"설탕 3g\",\"누룩소금 0.5g\",\"물 150ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"천일염 대비 염도가 4배 낮은 누룩소금을 사용했어요.\",\"instructions\":[\"1. 참외는 껍질과 속을 제거하고 먹기 좋은 크기로 썬다.\",\"2. 배와 마늘은 편 썰기, 양파와 대파는 채썰기, 홍고추와 생강은 다진다.\",\"3. 물에 식초, 설탕, 누룩소금을 넣어 국물을 만든다.\",\"4. 만들어 놓은 국물에 참외, 배, 양파를 넣어 잘 섞어 준다.\",\"5. 마지막으로 마늘, 홍고추, 생강을 넣어 섞어 준다.\",\"6. 동치미를 그릇에 담아 완성한다.\"]},{\"id\":\"k689\",\"title\":\"애호박 순대\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111134_1612923094669.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111159_1612923119780.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111212_1612923132230.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111224_1612923144147.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111236_1612923156817.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111252_1612923172073.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210210/20210210111328_1612923208649.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(8g)\",\"생새우(45g)\",\"팽이버섯(3g)\",\"당근(3g)\",\"깻잎(1g)\",\"파프리카(3g)\",\"다진 소고기(8g)\",\"감자전분(50g)\",\"달걀흰자(60g)\",\"애호박(1개)\",\"저염 간장(1g)\",\"식초(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양파장아찌를 곁들여 먹도록 해 따로 간을 하지 않아도 맛있는 애호박순대를 먹을 수 있어요.\",\"instructions\":[\"1. 저염 간장, 식초, 물(10㎖)을 섞은 뒤 얇게 채 썬 적양파를 넣어 30분간 숙성해 양파장아찌를 만든다.\",\"2. 두부와 생새우, 팽이버섯, 당근, 깻잎, 파프리카는 믹서에 넣어 곱게 간다.\",\"3. 중간 불로 달군 팬에 다진 소고기를 살짝 볶은 뒤 곱게 간 재료와 감자전분(45g), 달걀흰자와 섞어 소를 만든다.\",\"4. 애호박은 양끝을 자른 뒤 속을 파내고 안쪽에 감자전분(5g)을 고루 묻힌다.\",\"5. 애호박에 소를 채운 뒤 찜기에 넣어 8분간 찐다.\",\"6. 애호박 순대를 1cm 두께로 썰어 그릇에 담고 양파장아찌를 올린다.\"]},{\"id\":\"k690\",\"title\":\"버터치킨카레\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJewLo\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90Kx\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90NY\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90OS\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90Rb\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90UE\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90WL\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(1개)\",\"당근(½개)\",\"토마토(2개)\",\"닭고기(가슴살\",\"다릿살 각 200g)\",\"생크림(200g)\",\"파프리카(빨강\",\"노랑 각 1개)\",\"바게트(약간)\",\"월계수잎(1장)\",\"통후추(5알)\",\"정향(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•향신료로 간을 하여 나트륨 사용을 줄였으며 전통 인도의 맛을 살렸어요.\",\"instructions\":[\"1. 양파, 당근, 토마토, 파프리카는 한입 크기로 썰고, 닭고기는 한입 크기로 썬다.\",\"2. 닭고기는 요거트(1컵), 가람마살라(1Ts), 코리앤더파우더(1Ts), 커민파우더(1Ts), 다진 마늘(1Ts), 파프리카가루(1Ts), 소금(0.5ts)에 버무려 15분간 재운다.\",\"3. 중간 불로 달군 팬에 버터(2Ts)를 녹이고, 다진 마늘(1Ts), 양파, 당근, 토마토를 넣어 5분간 볶는다.\",\"4. 물(⅓컵), 육수 재료, 생크림을 넣어 끓이고, 당근이 익으면 핸드 믹서로 곱게 간 뒤 체로 거른다.\",\"5. 갈아 낸 카레를 냄비에 붓고, 가람마살라 (1Ts), 코리앤더파우더(1Ts), 커민파우더, (1Ts), 다진 마늘(1Ts), 파프리카가루(1Ts), 소금(0.5ts)을 넣어 걸쭉하게 끓인다.\",\"6. 꼬치에 파프리카와 닭을 번갈아 끼운 뒤 중간 불로 달군 팬에 닭이 익을 때까지 굽고, 그릇에 카레를 담은 뒤 닭꼬치와 바게트를 곁들여 마무리한다.\"]},{\"id\":\"k691\",\"title\":\"소고기찜과 검은콩수제비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr906p\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91uT\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91z2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr920u\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr923v\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9260\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr928V\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 팽이버섯(½봉)\",\"느타리버섯(½줌)\",\"알배추(½개)\",\"쪽파(3대)\",\"가지(½개)\",\"당근(¼개)\",\"흰다리새우(7마리)\",\"관자(4개)\",\"삶은 검은콩(½컵)\",\"소고기(불고기용 부채살\",\"200g)\",\"숙주(⅓줌)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 단호박, 느타리버섯, 검은콩, 감자는 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 팽이버섯과 느타리버섯은 밑동을 잘라 낱낱이 가르고, 알배추는 한입 크기로 썰고, 쑥갓과 쪽파는 한입 크기로 썬다.\",\"2. 가지와 당근은 어슷 썰고, 단호박은 씨 제거 후 7~8쪽으로 썰고, 표고버섯은 별모양 칼집을 내고, 새우는 깨끗하게 씻고, 관자는 한입 크기로 썬다.\",\"3. 믹서에 삶은 검은콩과 물(1컵)을 넣어 갈고, 볼에 담은 뒤 검은콩 수제비 반죽 재료와 고루 섞어 치대고, 냉장실에서 30분간 숙성한다.\",\"4. 불고기용 소고기를 펼치고, 팽이버섯과 쪽파를 위에 올려 돌돌 만다.\",\"5. 대나무 찜기에 손질한 채소, 해산물,  숙주 순으로 깔아준다.\",\"6. 그 위에 고기 버섯말이를 올려 중간 불에서 10분간 쪄내고, 달걀노른자와 양념장을 곁들여 마무리한다.\"]},{\"id\":\"k692\",\"title\":\"소고기 김말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120012450_1732076690467.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111518_1732068918225.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111528_1732068928972.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111539_1732068939279.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111551_1732068951152.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111602_1732068962904.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111615_1732068975834.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료] 소고기(치맛살)(100g)\",\"김(6g(3장))\",\"튀김가루(20g)\",\"<br>[양념] 식용유(45g)\",\"다진 쪽파(10g)\",\"다진 마늘(12g)\",\"저염간장(4g)\",\"고춧가루(12g)\",\"깨(20g)\",\"후추(3g)\",\"물(반죽용)(15ml)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•향신 재료인 고춧가루, 깨, 쪽파, 마늘 등을 활용하여 풍미를 높여 나트륨과 당류 사용량을 줄였어요.\\n<br>•고소함과 깊은 맛이 있는 김을 활용하여 심심한 맛을 보완했어요.\",\"instructions\":[\"1. 소고기는 키친타월로 핏물을 제거한다.\",\"2. 다진 쪽파, 다진 마늘, 저염간장, 고춧가루, 깨(18g), 물(4ml)을 섞어 양념장을 만든다.\",\"3. 튀김가루와 물(15ml)을 섞어 반죽을 만든다\",\"4. 손질한 소고기는 후추로 밑간하여 한입 크기로 다지고 김 위에 올려 돌돌 말아 김말이를 만든다.\",\"5. 김말이에 반죽을 묻히고 달군 팬에 식용유를 두르고 김말이를 앞뒤로 굽는다.\",\"6. 접시에 담고 양념장, 깨를 올려 마무리한다.\"]},{\"id\":\"k693\",\"title\":\"땅콩 밀푀유 샌드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071112_1760955072877.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071737_1760955457004.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071752_1760955472906.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071816_1760955496398.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071836_1760955516159.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071851_1760955531301.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020071907_1760955547284.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀푀유 재료 > 박력 밀가루 65g\",\"강력 밀가루 65g\",\"무염버터 120g\",\"물 65ml\",\"소금① 3g\",\"땅콩 분태 5g\",\"크림 스프레드 > 그릭요거트 45g\",\"크림치즈 30g\",\"꿀 4g\",\"땅콩 스프레드 > 구운 땅콩 45g\",\"소금② 1g\",\"계피가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"견과류의 고소한 맛과 계피가루를 활용하여 풍미를 높이고, 나트륨과 당류 사용량을 줄였어요.\",\"instructions\":[\"1. 볼에 체 친 박력 밀가루, 강력 밀가루,\\n잘게 자른 무염버터를 넣고 콩알\\n크기가 될 때까지 잘라가며 섞는다.\",\"2. 차가운 물, 소금①을 넣고 고루 섞은 후\\n비닐에 담아 납작하게 편 상태로\\n냉장고에서 30분 동안 휴지시켜\\n반죽을 만든다.\",\"3. 반죽을 밀대로 밀어 3번 접고\\n냉장고에서 20분 동안 휴지한다.\\n같은 작업을 2번 반복한다.\",\"4. 반죽을 5mm 두께로 밀고, 가장자리를\\n잘라 오븐 팬에 올린다. 포크로 구멍을\\n뚫고, 종이 포일을 올린 뒤 무거운 팬을\\n올려 부풀지 않게 한다. ① 200°C로\\n예열한 오븐에서 10분, ② 190°C에서 20분\\n동안 굽고 식힌 뒤 적당한 크기로 자른다.\",\"5. 그릭요거트, 크림치즈, 꿀을 섞어 크림\\n스프레드를 만든다. 믹서에 구운 땅콩,\\n소금②, 계피가루를 넣고 갈아 땅콩\\n스프레드를 만든다.\",\"6. 밀푀유에 크림 스프레드, 땅콩\\n스프레드를 바르고 땅콩 분태를 뿌려\\n마무리한다.\"]},{\"id\":\"k694\",\"title\":\"케이준 스타일 닭고기 요리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053459_1416213299404.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/861-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/861-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/861-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/861-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/861-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/861-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 100g\",\"식용유 8g\",\"파프리카가루 2g\",\"키엔페퍼 1g\",\"양파가루 1g\",\"마늘가루 1g\",\"후추 1g\",\"흰후춧가루 1g\",\"오레가노마른것 0.5g\",\"타임 마른것 0.5g\",\"바질마른것 1g\",\"로즈마리마른것 0.5g *선택:황설탕 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 식용유를 제외한 모든 향신료를 섞어준다.\",\"2. 닭가슴살에 식용유를 바른다.\",\"3. 1의 향신료를 닭가슴살의 한면에만 잘 발라준다.\",\"4. 가열된 식용유를 두르고 닭가슴살의 향신료 묻는 면이 팬에 닿도록 놓는다.\",\"5. 앞 뒷면이 노릇하게 되도록 구워준다.\",\"6. 그릇에 담아 마무리 한다.\"]},{\"id\":\"k695\",\"title\":\"헝가리안 폭찹\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053501_1416213301131.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/863-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/863-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/863-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/863-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/863-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/863-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심 100g\",\"물 50g\",\"사워크림 30g\",\"실파다진것 4g [소스소개]양념재료:파프리카가루 3g\",\"머스터드 씨드 2.5g\",\"코리앤더 씨드 1g\",\"양파즙 13g\",\"마늘가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 작은 불에 양념 재료를 넣고 섞어 절반은 돼지고기에 밑간한다.\",\"2. 달라붙지 않는 팬을 중간불고 가열한다.\",\"3. 양념한 돼지고기의 앞·뒷면을 익혀 고기의 중간이 핑크빛이 날 때까지 익히고 그릇에 옮겨담아 뚜껑을 덮어둔다.\",\"4. 강한불에 팬을 놓고 물 1컵을 부어 팬 바닥에 남아 있는 성분들을 녹여 2분정도 끓인다.\",\"5. 물이 1/4컵으로 줄어들면 불을 낮추고 사워크림을 넣고 거품기로 저으면서 끓지 않게 2~3분 간 조리한다.\",\"6. 접시에 돼지고기 폭찹을 담고 스푼으로 소스를 위에 얹고 실파를 뿌려준다.\"]},{\"id\":\"k696\",\"title\":\"구운 닭고기 샐러드와 저나트륨 과일 드레싱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053502_1416213302505.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/865-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/865-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/865-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/865-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/865-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/865-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 60g\",\"양상추 18g\",\"방울토마토 18g\",\"브로컬리 20g [소스소개] 저나트륨과일드레싱:파인애플통조림 40g\",\"키위 20g\",\"사과 10g\",\"양파 4g\",\"올리브오일 6g\",\"레몬즙 3.2g\",\"설탕 3.2g\",\"소금 0.4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭가슴살에는 밑간을 하지 않는다.\",\"instructions\":[\"1. 닭가슴살을 170℃의 오븐에서 20분간 구운 후 잘게 찢는다.\",\"2. 양상추는 한 잎 크기로 뜯어 차가운 물에 담갔다가 물기를 뺀다.\",\"3. 방울토마토는 꼭지를 뗀 후 반으로 가른다.\",\"4. 브로콜리는 송이송이 떼어 끓는 물에 데친다.\",\"5. 저나트륨 과일드레싱 재료를 믹서에 넣고 곱게 간다.\",\"6. 준비된 재료를 한데 섞고 저나트륨 과일드레싱을 곁들인다.\"]},{\"id\":\"k697\",\"title\":\"돼지고기 수육 부추부침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053504_1416213304243.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/867-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/867-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/867-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/867-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/867-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/867-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기 삼겹살 40g\",\"대파 5g\",\"마늘 5g\",\"생강 1.5g\",\"통후추 0.5g\",\"영양부추 10g\",\"양파 2.5g\",\"무 15g\",\"소금 0.1g\",\"식초 1.5g\",\"설탕 1g [소스소개] 매운소스:고추기름 1g\",\"간장 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 두부 된장소스는 된장의 양을 1/5정도 줄이고 대신 두부를 으깨서 소스 분량을 늘린 것이다.\",\"instructions\":[\"1. 돼지고기는 덩어리로 준비해 충분히 무르도록 대파, 마늘, 생강, 통후추를 넣어 삶는다.\",\"2. 부추와 양파는 3cm 길이로 썰어 매운 소스 양념에 가볍게 무친다.\",\"3. 무는 채썰어 소금, 설탕, 식초에 절였다가 꼭 짠다.\",\"4. 삶은 돼지고기를 건져 얇게 저민다.\",\"5. 저민 돼지고기와 양념한 부추, 무를 곁들여 접시에 담는다.\",\"6. 두부를 곱게 다져 분량의 소스 재료와 섞어 저나트륨 두부 된장소스를 만들어 수육과 함께 낸다.\"]},{\"id\":\"k698\",\"title\":\"쇠고기 채소볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053505_1416213305070.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/868-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/868-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/868-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/868-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/868-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/868-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기 40g\",\"생표고버섯 16g\",\"양송이버섯 9g\",\"애느타리버섯 12g\",\"흰목이버섯 0.4g\",\"목이버섯 0.4g\",\"샐러리 4g\",\"홍피망 8g\",\"정종 2g\",\"간장 2g\",\"육수 10g\",\"후춧가루 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 소고기는 굵게 채썬다.\",\"2. 채썬 소고기에 전분과 달걀을 넣고 밑간을 한다.\",\"3. 버섯과 채소는 씻은 후 0.3cm 두께로 채 썬다.\",\"4. 후라이팬에 소고기를 넣고 볶는다.\",\"5. 채소와 버섯을 넣고 한번 더 볶는다.\",\"6. 육수에 간장, 정종, 후춧가루를 넣고 끓이다가 마지막에 참기름을 넣어 낸다.\"]},{\"id\":\"k699\",\"title\":\"낙지볶음면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053505_1416213305819.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/869-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/869-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/869-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/869-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/869-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/869-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"낙지 20g\",\"쭈꾸미 20g\",\"생면 80g\",\"배추 20g\",\"양파 13g\",\"느타리버섯 13g\",\"표고버섯 13g [소스소개] 볶음소스:청피망 8g\",\"홍피망 5g\",\"청양고추 15g\",\"대파 13g\",\"굴소스 1g\",\"고춧가루 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"낙지나 쭈꾸미는 간이 없이도 먹을 수 있으므로 그대로 채소와 간을 하지 않고 볶은 후 소스를 만들어 먹기 직전에 넣는다.\",\"instructions\":[\"1. 낙지와 쭈꾸미는 각각 소금물에 씻어 손질한다.\",\"2. 낙지는 5cm 길이로 자른다.\",\"3. 채소들은 각각 10cm 길이로 얇게 채 썬다.\",\"4. 소스를 만든다.\",\"5. 생면은 끓는 물에 데친다.\",\"6. 가열된 팬에 식용유를 넣고 채소를 볶다가 면과 소스를 넣고 충분히 볶는다.\"]},{\"id\":\"k700\",\"title\":\"지중해 소스를 곁들인 도미스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053508_1416213308021.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/871-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/871-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/871-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/871-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/871-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/871-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"도미 100g\",\"후춧가루 0.1g\",\"밀가루 4g\",\"식용유 12g\",\"화이트와인 50g\",\"물 50g\",\"파슬리다진것 1g[소스소개] 지중해소스:토마토 20g\",\"올리브 10g\",\"케이퍼 3g\",\"양파다진것 5g\",\"마늘다진것 2g\",\"토마토 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 도미에 후춧가루와 밀가루를 묻혀 놓는다.\",\"2. 토마토는 껍질을 벗겨 썰고 올리브는 0.8cm 주사위모양으로 썬다.\",\"3. 팬에 식용유를 넣고 도미를 넣어 익히다가 화이트와인을 넣는다.\",\"4. 소스 재료들과 물을 넣어 끓이면서 반으로 졸인다.\",\"5. 도미는 건져내고 팬에 남은 소스에 다진 파슬리가루를 뿌린다.\",\"6. 접시에 도미와 소스를 함께 곁들여 낸다.\"]},{\"id\":\"k701\",\"title\":\"해산물 샤브샤브\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053508_1416213308848.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/872-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/872-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/872-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/872-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/872-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/872-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우 13g\",\"모시조개 15g\",\"굴 25g\",\"패주 5g\",\"오징어 10g\",\"당귀잎 2.5g\",\"배추잎 2.5g\",\"샐러리잎 2.5g\",\"백만송이버섯 2.5g\",\"쑥갓 1.3g\",\"팽이버섯 1.3g\",\"곤약 2.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 새우는 내장을 제거하고 오징어는 껍질을 벗겨 안쪽에 대각선으로 칼집을 넣어 5x6cm로 썬다.\",\"2. 굴은 소금물에 흔들어 씻고 패주는 3등분 하고 모시조개는 소금물에 담가 해감시킨다.\",\"3. 곤약은 2x4cm로 썰어 가운데 칼집을 넣어 꼬아주고 버섯들은 찢어 준비한다.\",\"4. 쑥갓, 셀러리, 당귀잎은 잎만 뜯어 준비하고 배추잎은 저며 썬다.\",\"5. 통깨를 갈고 그 밖에 재료들은 모두 섞어 가는 체에 내려 땅콩 소스를 만든다.\",\"6. 냄비에 다시마 국물을 붓고 소금으로 약하게 간을 한 다음 해산물과 채소를 번갈아 가면서 익혀 소스에 찍어 먹는다.\"]},{\"id\":\"k702\",\"title\":\"고등어구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053510_1416213310332.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/873-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/873-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/873-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/873-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/873-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/873-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고등어 70g\",\"밀가루 4g[소스소개]저나트륨발사믹소스:간장 1g\",\"올리브오일 13g\",\"발사믹식초 6g\",\"꿀 4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고등어는 소금을 뿌리지 않은 생태로 갈색이 나도록 바싹 굽는다.\",\"instructions\":[\"1. 손질된 고등어는 5cm 길이로 토막낸 뒤 껍질에 칼집을 넣는다.\",\"2. 칼집 낸 고등어에 밀가루를 묻힌다.\",\"3. 오븐을 200℃로 예열한다.\",\"4. 간장, 올리브오일, 발사믹식초, 꿀을 섞어 소스를 완성한다.\",\"5. 고등어를 팬에 넣어 오븐에 굽는다.\",\"6. 저나트륨발사믹소스와 구운 고등어를 함께 제공한다.\"]},{\"id\":\"k703\",\"title\":\"골뱅이무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053511_1416213311553.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/874-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/874-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/874-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/874-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/874-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/874-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"골뱅이 25g\",\"양파 13g\",\"대파 0.8g\",\"오이 25g\",\"미나리 13g\",\"깻잎 3g [소스소개]저나트륨초고추장소스:고추가루 1g\",\"생강즙 1g\",\"사과주스 10g\",\"설탕 10g\",\"고추장 2g\",\"식초 3g\",\"깨소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 양파와 대파는 채 썰고 오이는 반달썰기한다.\",\"2. 미나리와 깻잎은 다지듯 썬다.\",\"3. 골뱅이는 물기를 제거하고 한 입 크기로 썬다.\",\"4. 대파 채는 얼음물에 담가 둔다.\",\"5. 저나트륨 초고추장소스를 만든다.\",\"6. 내기 직전에 무친 후 완성한다.\"]},{\"id\":\"k704\",\"title\":\"굴 두부 국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053512_1416213312256.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/875-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/875-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/875-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/875-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/875-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/875-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"굴 20g\",\"두부 20g\",\"마늘다진것 1g\",\"실파 2g\",\"김 0.3g\",\"새우젓 0.5g\",\"소금 0.2g\",\"참기름 1g\",\"다시마 육수 100g\",\"홍고추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"국의 국물은 100~150g으로 하고 간은 0.7% 간으로 한다.\",\"instructions\":[\"1. 굴은 소금으로 깨끗이 씻어 물기를 뺀다.\",\"2. 두부는 2x2x1cm 크기로 썰고, 실파는 2cm 길이로 자른다.\",\"3. 김은 구워서 잘게 찢거나 가위로 자른다.\",\"4. 고추는 채썰어 씨를 제거한다.\",\"5. 다시마 육수를 끓이다가 두부와 굴을 넣고 뭉근히 끓인 뒤 새우젓과 다진 마늘을 넣고 한소끔 끓인다.\",\"6. 실파와 홍고추를 넣고 마지막에 김과 참기름을 넣는다.\"]},{\"id\":\"k705\",\"title\":\"과일퓨레수제함박스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102744_1584062864601.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102854_1584062934752.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313102910_1584062950180.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103314_1584063194662.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103350_1584063230679.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103417_1584063257771.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103434_1584063274927.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기(우둔) 12g\",\"돼지고기(전지) 23g\",\"도라지 1.3g\",\"사과 2.2g\",\"배 2.2g\",\"깐연근 1.7g\",\"토마토 9g\",\"깐양파 9.5g\",\"양송이버섯 1.3g\",\"당근 11.4g\",\"청피망 2.3g\",\"달걀 7g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 많은 연근, 토마토, 배, 파인애플을 이용해 퓨레를 만들었어요.\",\"instructions\":[\"1. 도라지, 사과, 배, 연근은 갈아서 뭉근하게 조려 퓨레를 만든다.\",\"2. 연근, 토마토, 양파, 양송이버섯, 당근, 청피망 등 모든 채소는 곱게 다진다.\",\"3. 고기에 퓨레, 달걀, 후추, 생강, 빵가루를 넣어 찰지게 반죽하고 납작하게 빚어서 오븐에 굽는다.\",\"4. 소스제조를 위해 밀가루, 버터를 볶아 루를 만든다.\",\"5. ④에 ②에서 다져놓은 야채를 넣어 끓이고, 소금간과 레몬즙을 뿌려준다.\",\"6. 구운 수제함박스테이크에 새싹채소-파인애플-방울토마토 순으로 장식하고 소스와 함께 제공한다.\"]},{\"id\":\"k706\",\"title\":\"달콤과일깍두기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128052409_1611822249198.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021440_1678252480988.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021457_1678252497862.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021515_1678252515896.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021529_1678252529699.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021551_1678252551009.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308021610_1678252570691.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 무(20g)\",\"배(10g)\",\"참외(10g)\",\"마늘(1g)\",\"새우젓(0.5g)\",\"생강(0.5g)\",\"실파(1g)\",\"•양념 : 고춧가루(1g)\",\"통깨(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•과일 깍두기는 소금에 절이지 않아 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 배와 참외는 1~1.5cm 크기로 깍둑 썬다.\",\"2. 무는 1~1.5cm 크기로 깍둑 썬다.\",\"3. 실파는 1cm 길이로 썬다.\",\"4. 새우젓, 마늘, 생강은 곱게 다진다.\",\"5. 고춧가루, 새우젓, 마늘, 생강, 통깨를 버무려 양념장을 만든다.\",\"6. 배, 참외, 무, 실파에 양념장을 넣어 버무린다.\"]},{\"id\":\"k707\",\"title\":\"비트 단호박 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042347_1615188227457.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042418_1615188258180.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042432_1615188272490.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042455_1615188295967.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042521_1615188321909.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042538_1615188338503.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308042551_1615188351249.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삶은 스파게티(80g)\",\"감자(10g)\",\"파르메산 치즈가루(약간)\",\"어린잎채소(약간)\",\"비트(40g)\",\"올리브유(30g)\",\"스리라차소스(5g)\",\"마늘(10g)\",\"미니 단호박(70g)\",\"생크림(100g)\",\"설탕(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"비트소스의 매콤함과 단호박소스의 달콤함으로 맛을 주었어요.\",\"instructions\":[\"1. 믹서에 비트소스 재료를 넣어 곱게 갈아 삶은 스파게티에 넣어 버무린다.\",\"2. 미니 단호박은 잘게 자른 뒤 끓는 물에 3분간 익혀 건진다.\",\"3. 익힌 미니 단호박은 믹서에 곱게 간 뒤 생크림으로 농도를 맞추고 설탕으로 간하여 단호박소스를 만든다.\",\"4. 감자는 얇게 모양대로 썬다.\",\"5. 중간 불로 달군 팬에 얇게 썬 감자를 2분간 볶아 바삭하게 만들어 잘게 부순다.\",\"6. 그릇에 단호박소스를 붓고, 비트소스를 버무린 스파게티를 담은 뒤 어린잎채소, 파르메산 치즈가루, 잘게 부순 감자를 올려 마무리한다.\"]},{\"id\":\"k708\",\"title\":\"해조비빔국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJe-oV\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91Ik\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91K0\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91LL\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91N4\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91Ra\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 오이(⅓개)\",\"양파(⅓개)\",\"파프리카(빨강\",\"노랑 각 ½개)\",\"도토리묵(250g)\",\"해조국수(1팩=180g)\",\"스테비아(0.3Ts)\",\"식초(1Ts)\",\"간장(0.5Ts)\",\"스리라차소스(1Ts)\",\"매실청(0.5Ts)\",\"다진 마늘(1.5Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•스리라차소스로 간을 맞추고 나트륨의 사용을 줄였어요.\\n•스테비아를 이용하여 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 오이, 양파, 파프리카는 같은 길이로 채 썰고, 도토리묵은 2~3cm 두께로 채 썬다.\",\"2. 양파는 찬물에 5분간 담가 매운맛을 제거하고, 해조국수는 찬물에 헹궈 건진다.\",\"3. 양념장을 만든다.\",\"4. 그릇에 해조국수를 가운데 담고, 손질한 채소와 묵을 올린다.\",\"5. 양념장을 곁들여 마무리한다.\"]},{\"id\":\"k709\",\"title\":\"닭봉 로제스튜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr94Gc\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr960Z\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9629\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr963i\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr965W\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr966b\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr969P\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(3개)\",\"마늘(5쪽)\",\"감자(1개)\",\"파프리카(빨강\",\"노랑 각 ⅓개)\",\"당근(½개)\",\"브로콜리(½개)\",\"닭봉(20개)\",\"통조림 홀토마토(2캔=822g)\",\"생크림(1컵)\",\"파르메산 치즈가루(1컵) 월계수잎(1장)\",\"소금(0.5Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 토마토, 감자는 나트륨 배출에 도움을 줘요.\\n•양파를 이용하여 단맛을 내고 첨가당 사용을 줄였어요.\\n•무염버터를 사용하면 나트륨 섭취량을 줄일 수 있어요.\",\"instructions\":[\"1. 양파와 마늘은 다지고, 감자, 파프리카, 당근은 한입 크기로 썰고, 브로콜리는 송이만 떼어낸다.\",\"2. 닭봉은 밑간해 15분간 재운다.\",\"3. 중간 불로 달군 팬에 올리브유를 두르고, 다진 양파와 마늘을 넣어 양파가 갈색이 될 때까지 볶고, 화이트와인을 넣어 자작해질 때까지 볶고, 월계수잎과 홀토마토를 넣어 으깬 뒤 5분간 끓인다.\",\"4. 강황, 코리앤더가루, 커민, 레드크러쉬드 페퍼, 바질가루, 오레가노 가루를 넣어 섞고, 한 김 식힌 뒤 믹서에 곱게 갈아 토마토소스를 만든다.\",\"5. 밑간한 닭봉은 중간 불로 달군 팬에 버터를 둘러 앞뒤로 노릇하게 익혀 꺼낸다.\",\"6. 같은 팬에 손질한 채소를 넣어 볶다가 구운 닭봉, 토마토소스를 넣어 10분간 끓이고, 생크림과 파르메산 치즈가루를 넣어 자작해질 때까지 졸여 마무리한다.\"]},{\"id\":\"k710\",\"title\":\"수제새우소시지\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97YW\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9BlB\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9BnG\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Bp0\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Brx\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Bu2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9CC4\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양파(½개)\",\"칵테일새우(14마리)\",\"라이스페이퍼(8장)\",\"깻잎(3장)\",\"감자전분(2Ts)\",\"후춧가루(약간)\",\"레몬즙(1ts)\",\"다진 마늘(2Ts)\",\"올리브유(2ts)\",\"다진 마늘(1Ts)\",\"올리고당(1Ts)\",\"파슬리가루(1ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•밀가루 대신 염분이 낮고 칼륨이 풍부한 감자 전분을 사용했어요\\n•소금 대신 향신료와 레몬즙을 넣어 풍미를 살렸어요.\\n•설탕이나 꿀 대신 소량의 올리고당을 넣어 단맛은 내면서 칼로리를 낮췄어요.\",\"instructions\":[\"1. 양파와 깻잎은 곱게 다지고, 칵테일새우는 깨끗하게 씻은 뒤 곱게 다진다.\",\"2. 다진 양파, 깻잎, 새우에 양념을 넣어 고루 섞은 뒤 치대 새우반죽을 만든다.\",\"3. 뜨거운 물(4컵)에 라이스페이퍼를 살짝 담갔다 꺼내 식용유를 바른 도마 위에 올린다.\",\"4. 지퍼백에 새우반죽을 넣은 뒤 가위로 끝부분을 잘라 라이스페이퍼 위에 반죽을 짜 올리고, 돌돌 말아 새우소시지를 만든다.\",\"5. 중간 불로 달군 팬에 식용유를 둘러 새우소시지를 올린 뒤 겉면이 하얗게 변할 때까지 노릇하게 굽는다.\",\"6. 그릇에 담고 마늘소스를 윗면에 발라 마무리한다.\"]},{\"id\":\"k711\",\"title\":\"감태샐러드말이와 버섯말이깐풍\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120012701_1732076821671.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111711_1732069031353.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111721_1732069041815.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111732_1732069052816.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111743_1732069063719.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111754_1732069074388.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111805_1732069085265.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료] 감태 (2g(2장))\",\"라이스페이퍼(60g)\",\"양상추(80g)\",\"적채(20g)\",\"건표고버섯(5g)\",\"느타리버섯(10g)\",\"만가닥버섯(10g)\",\"청고추(5g)\",\"홍고추(5g)\",\"대파(5g)\",\"마늘(5g)<br>\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨이 풍부한 감태를 사용해서 나트륨 배출을 도왔어요. \\n<br>•감칠맛이 풍부한 버섯을 사용해 나트륨과 당류 사용량을 줄였어요.\",\"instructions\":[\"1. 양상추, 적채는 채 썰어 찬물에 담근다. 마요네즈, 홀그레인 머스터드, 파인애플청을 섞어 샐러드 드레싱을 만든다.\",\"2. 데친 느타리버섯, 만가닥버섯과 불린 건표고버섯의 물기를 제거하고 깍둑 썰기하여 예열한 팬에 볶고 진간장,참기름(3g)으로 간한다.\",\"3. 라이스페이퍼에 올리고 한입 크기로 싼다. 예열한 팬에 식용유(10g)를 두르고 굽는다.\",\"4. 물기를 제거한 양상추, 적채를 라이스페이퍼에 올리고 싼 뒤, 감태 위에 올려 돌돌 말고 한입 크기로 썬다.\",\"5. 예열한 팬에 식용유(10g)를 두르고 다진 청고추, 홍고추, 대파, 마늘을 볶아 향을 내고 굴 소스, 올리고당, 식초, 참기름(3g)을 넣어 깐풍 소스를 만든다.\",\"6. 접시에 담고 샐러드 드레싱과 깐풍 소스를 곁들여 마무리한다.\"]},{\"id\":\"k712\",\"title\":\"금태찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053513_1416213313394.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/876-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/876-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/876-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/876-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/876-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/876-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"금태 50g\",\"소금 0.1g\",\"흰후춧가루 0.1g\",\"청주 3g\",\"생강즙 3g\",\"녹말가루 1g\",\"콩나물 16g\",\"미나리 12g\",\"느타리버섯 16g\",\"홍고추 0.8g\",\"당근 10g\",\"대파 4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"보통 매운 찜요리 종류는 염도가 2~3% 되므로 생선을 그대로 찌거나 약한 간의 찜소스를 뿌려 조리하면 비린맛도 적고 담백한 생선 요리가 된다.\",\"instructions\":[\"1. 금태는 아가미와 내장을 제거 한 후 몸통에 어슷하게 칼집을 넣어 소금, 흰후추, 청주, 생강즙으로 밑간을 해둔다.\",\"2. 밑간 한 금태의 수분을 닦고 녹말가루를 고루 묻힌다.\",\"3. 콩나물은 머리와 꼬리를 떼고 미나리는 7cm 길이로 썰고 느타리버섯은 굵게 찢고 홍고추, 대파, 당근, 무는 채썬다.\",\"4. 다시마 국물에 간장, 맛술, 식초를 섞어 찜소스를 만든다.\",\"5. 찜그릇에 무, 당근 채썬 것을 놓고 녹말 입힌 도미와 찜소스를 얹어 찐다.\",\"6. 중간 중간 소스를 뿌려 주고 느타리버섯, 미나리, 홍고추, 콩나물, 채썬 대파를 얹어 찐다.\"]},{\"id\":\"k713\",\"title\":\"김자반\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053514_1416213314112.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/877-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/877-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/877-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/877-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/877-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/877-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"김 10g\",\"마늘 8g\",\"생강 5g\",\"통깨 1.3g [소스소개]양념간장:물 30g\",\"간장 2g\",\"설탕 2g\",\"물엿 1g\",\"식초 1g\",\"홍고추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 김은 티를 골라낸다.\",\"2. 홍고추, 마늘, 생강은 곱게 채썬다.\",\"3. 간장소스의 양념들은 모두 합하여 20분 가량 낮은 불에서 끓여서 식힌다.\",\"4. 김은 먹기 좋은 크기로 12~18등분으로 자른다.\",\"5. 양념간장에 마늘, 생강, 홍고추채를 섞는다.\",\"6. 김을 차곡차곡 쌓은 뒤 양념간장을 위에 부어준다.\"]},{\"id\":\"k714\",\"title\":\"꽁치 양념구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053514_1416213314814.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/878-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/878-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/878-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/878-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/878-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/878-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"꽁치 60g\",\"후춧가루 0.1g\",\"밀가루 4g\",\"녹말가루 8g\",\"식용유 2g [소스소개]저나트륨고추장소스:토마토케첩 2g\",\"고추장 2g\",\"마늘 2g\",\"생강즙 2.4g\",\"청고추다진것 4g\",\"홍고추다진것 2g\",\"물엿 20g\",\"간장 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생선류는 염을 가하지 않은 상태로 그대로 바싹 구운 후 양념장을 살짝 뿌려서 먹는다.\",\"instructions\":[\"1. 꽁치는 머리와 내장을 제거해 손질하고 칼집을 낸다.\",\"2. 손질한 꽁치에 후춧가루와 청주를 뿌려 밑간해 둔다.\",\"3. 밑간해 둔 꽁치의 수분을 제거하고 밀가루를 묻힌다.\",\"4. 밀가루 묻힌 꽁치를 팬에서 노릇하게 굽는다.\",\"5. 팬에 저나트륨 고추장소스 재료를 넣고 살짝 졸인다.\",\"6. 구워진 꽁치에 소스를 뿌려낸다.\"]},{\"id\":\"k715\",\"title\":\"꽃게강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053515_1416213315658.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/879-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/879-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/879-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/879-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/879-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/879-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"꽃게 120g\",\"후춧가루 0.3g\",\"청고추 1g\",\"홍고추 1g\",\"토마토케첩 4g\",\"마늘 1.3g\",\"생강 0.5g\",\"생강즙 4g\",\"찹쌀가루 8g\",\"식용유 10g [소스소개] 매운고추소스:매운 고춧가루 1.3g\",\"맛술 8g\",\"간장 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 꽃게를 잘 손질한다.\",\"2. 손질한 꽃게에 생강즙과 후춧가루로 간을 한다.\",\"3. 청·홍고추는 사방 0.7cm로 썰고 생강은 다진다.\",\"4. 매운 고추소스의 재료들을 모두 섞고 냄비에 넣어 끓이다가 준비해둔 채소들을 넣고 한소큼 끓여준다.\",\"5. 꽃게에 찹쌀가루를 묻혀 튀긴다.\",\"6. 4의 소스에 넣고 섞는다.\"]},{\"id\":\"k716\",\"title\":\"낙지강회\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053517_1416213317156.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/880-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/880-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/880-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/880-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/880-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/880-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"낙지 50g\",\"실파 30g\",\"미역마른것 3g\",\"쌈다시마 0.5g\",\"당근 10g [소스소개] 고추장 1g\",\"식초 2g\",\"설탕 2g\",\"사과주스 5g\",\"고춧가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 고추장소스는 일반 고추장소스보다 고추장 양은 1/5로 줄이고 대신 사과주스와 고춧가루를 넣어 맛과 양을 보완한 소스이다.\",\"instructions\":[\"1. 낙지는 내장을 손질하고 밀가루로 비벼 씻는다.\",\"2. 씻어낸 낙지는 끓는 소금물에 살짝 데쳐서 다리를 하나씩 떼어 낸다.\",\"3. 실파는 데치고 불린 미역과 다시마도 데쳐서 알맞게 자른다.\",\"4. 당근은 채썰어 준비해 둔다.\",\"5. 데친 낙지를 절반씩 실파와 미역, 다시마로 감는다.\",\"6. 저나트륨 고추장소스를 만들어 곁들인다.\"]},{\"id\":\"k717\",\"title\":\"낙지 잣소스 냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053518_1416213318219.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/881-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/881-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/881-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/881-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/881-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/881-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"낙지 50g\",\"오이 20g\",\"밤 15g\",\"미나리 15g\",\"배 30g\",\"홍피망 12g [소스소개] 잣소스:잣20g\",\"배즙 37.5\",\"흰후춧가루 0.1g레몬즙 5g\",\"소금 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"잣을 갈면 기름기가 많고 잣의 고소한 향으로 부드러운 소스의 베이스가 된다. 들깨가루를 첨가해도 더욱 저나트륨과 어울리는 소스가 된다.\",\"instructions\":[\"1. 낙지는 밀가루를 넣어 주물러 미끈거리는 것을 씻어내고 흐르는 물에 헹군다.\",\"2. 끓는 물에 데쳐 한 입 크기로 썬다.\",\"3. 오이는 가운데 씨를 잘라낸 뒤 눈썹 모양으로 썰고 홍피망과 미나리는 5cm 길이로 썬다.\",\"4. 배는 굵게 채 썰고 밤은 얇게 썬다.\",\"5. 잣은 곱게 다져 분마기에 넣고 배즙을 조금씩 넣어가며 뽀얗게 즙을 내고 레몬즙과 흰후춧가루, 소금을 넣어준다.\",\"6. 준비된 재료를 잣소스에 버무린다.\"]},{\"id\":\"k718\",\"title\":\"두부 해산물 꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053519_1416213319253.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/882-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/882-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/882-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/882-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/882-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/882-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 100g\",\"소라살 16g\",\"패주 16g\",\"소금 0.2 [소스소개]마늘올리브유소스:마늘 0.2g\",\"올리브유 7g\",\"바질다진것 0.6g\",\"방울토마토 8g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"구운 요리들은 구운 향으로 염을 첨가하지 않고도 먹기에 적당한 조리법이다.\",\"instructions\":[\"1. 두부는 4x1.5x1cm 크기로 썬 후 소금을 뿌려 물기를 제거한다.\",\"2. 소라살은 내장을 뺀 뒤 반으로 가르고 패주는 주위의 지저분한 막을 벗겨 깨끗이 손질한 뒤 2~3등분 한다.\",\"3. 바질 잎은 다진다.\",\"4. 볼에 다진 마늘을 담고 소금 간을 한 뒤 올리브유를 조금씩 넣으면서 한 방향으로 젓다가 다진 바질을 넣어 마늘 올리브유 소스를 만든다.\",\"5. 두부와 해산물을 차례로 꼬치에 끼워 붓으로 소스를 고루 바른다.\",\"6. 예열된 250℃ 오븐이나 그릴에서 노릇하게 구워낸다.\"]},{\"id\":\"k719\",\"title\":\"마 두부 오징어전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053520_1416213320408.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/883-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/883-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/883-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/883-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/883-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/883-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 60g\",\"마 60g\",\"표고버섯마른것 3.5g\",\"오징어 6g\",\"소금 0.2g\",\"후춧가루 0.1g\",\"녹말 0.8g\",\"식용유 4.8g\",\"홍고추 0.5g[소스소개] 양념장:간장 1.5g\",\"조미술 1.5g\",\"설탕 0.5g\",\"식초 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 두부는 소창에 싸서 으깬다.\",\"2. 마는 껍질을 벗기고 강판에 간다.\",\"3. 홍고추는 다지고 표고버섯은 물에 불린 후 잘게 다진다. 오징어도 손질하여 잘게 다진다.\",\"4. 두부와 마, 다진 재료들을 모두 섞어 소금, 후춧가루로 간한다.\",\"5. 반죽을 한 스푼씩 떠 식용유를 넣은 팬에 노릇하게 구워낸다.\",\"6. 재료를 섞어 양념장을 만들어 함께 낸다\"]},{\"id\":\"k720\",\"title\":\"멸치 찹쌀양념 튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053521_1416213321149.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/884-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/884-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/884-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/884-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/884-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/884-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"멸치중간것 10g\",\"찹쌀가루 5g\",\"식용유 2g\",\"땅콩 13g [소스소개]고추장소스:고추장 2g\",\"간장 0.5g\",\"양파즙 10g\",\"마늘즙 1g\",\"생강즙 0.5g\",\"맛술 5g\",\"설탕 3g\",\"물엿 3g\",\"식용유 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 멸치는 티를 골라내어 선별해 두고 실파는 썬다.\",\"2. 팬에 식용유를 두르고 소스의 양념들을 넣어 최대한 낮은 불에서 서서히 졸여 농도를 낸다.\",\"3. 찹쌀가루 중 1/3분량만 묽게 풀을 쑤어 식힌다.\",\"4. 멸치에 풀을 가볍게 익히고 남은 찹쌀가루를 묻힌다.\",\"5. 튀김기름의 온도를 170~180℃에 맞추어 4의 멸치를 재빨리 튀겨낸다.\",\"6. 식은 후에 (2)의 소스에 버무리거나 끼얹어 낸다.\"]},{\"id\":\"k721\",\"title\":\"미역 물오징어 연두부 초회\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053521_1416213321929.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/885-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/885-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/885-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/885-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/885-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/885-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연두부큰것 25g\",\"불린미역 25g\",\"물오징어 25g\",\"꽈리고추 4.2g [소스소개] 저나트륨양념장:고추장 2.5g\",\"간장 0.8g\",\"물엿 1g\",\"레몬즙 0.8g\",\"식초 0.8g\",\"마늘다진것 0.2g\",\"생강즙 1g\",\"파다진것 0.2g\",\"참기름 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"\",\"instructions\":[\"1. 연두부는 작은 숟가락으로 떠 놓는다.\",\"2. 불린 미역은 4cm 길이로 썬다.\",\"3. 오징어는 껍질을 벗기고 칼집을 넣어 데친다.\",\"4. 데친 오징어는 솔방울 모양으로 자른다.\",\"5. 꽈리고추는 데친다.\",\"6. 재료를 보기좋게 담고 양념장을 곁들여 낸다.\"]},{\"id\":\"k722\",\"title\":\"부추조개살 콩비지조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053522_1416213322648.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/886-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/886-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/886-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/886-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/886-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/886-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콩비지 20g\",\"조갯살 20g\",\"부추 5g\",\"당근 5g [소스소개]조림장:간장 1g\",\"청주 1g\",\"조미술 1g\",\"설탕 1g\",\"생강즙 1g\",\"마늘다진것 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 조갯살은 연한 소금물로 헹구어 물기를 뺀다.\",\"2. 부추는 2~3cm 길이로 썰고 당근은 짧게 채 썬다.\",\"3. 냄비에 분량의 조림장 재료를 전부 넣고 한소큼 끓어 오르면 조갯살을 넣어 살짝 데쳐 건져둔다.\",\"4. 3의 냄비에 물 3컵을 더 넣고 당근을 넣어 조림장 분량이 2/3정도가 될 때까지 졸인다.\",\"5. 다른 팬에 기름을 두르지 않고 콩비지를 넣어 보슬보슬해질 때 까지 볶는다.\",\"6. 5에 4를 전부 붓고 채썬 부추와 데친 조갯살도 넣어 간이 고루 들도록 저어가며 볶는다.\"]},{\"id\":\"k723\",\"title\":\"연어냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053524_1416213324459.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/888-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/888-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/888-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/888-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/888-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/888-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"훈재연어 40g\",\"흰후춧가루 0.01g\",\"녹말가루 2.4g\",\"오이 3.8g\",\"래디쉬 15g\",\"샐러리 7.5g\",\"배 7.5g [소스소개] 저나트륨파인애플소스:파인애플 3g\",\"파인애플 통조림 국물 4.5g\",\"올리브오일 3.6g\",\"레몬즙 1.5g\",\"사과 4.5g\",\"소금 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 파인애플 소스의 경우 소금 양이 1/5 이상 줄어 있지만 파인애플 주스가 설탕, 올리브 오일과 어우러져 싱겁게 느끼지 않고 먹을 수 있는 소스이다.\",\"instructions\":[\"1. 연어는 주사위모양으로 썬다.\",\"2. 흰후춧가루를 살짝 뿌린 후 녹말가루를 묻힌다.\",\"3. 녹말을 묻힌 연어는 김 오른 찜통에 찌고 식혀둔다.\",\"4. 오이, 래디쉬, 셀러리, 배는 곱게 채썰어 냉수에 담갔다가 건진다.\",\"5. 캔 파인애플을 잘게 썰어 분량의 재료들과 함께 믹서기에 곱게 간다.\",\"6. 접시에 준비된 채소와 찐 연어를 담고 소스를 곁들인다.\"]},{\"id\":\"k724\",\"title\":\"오징어말이 케첩조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053525_1416213325208.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/889-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/889-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/889-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/889-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/889-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/889-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어 80g\",\"당근 17g\",\"시금치 17g\",\"달걀 19g\",\"표고버섯마른것 7g\",\"식용유 1.4g\",\"밀가루 1.1g [소스소개] 토마토케첩소스:마늘다진것 1.1g\",\"양파다진것 1.1g\",\"토마토케첩 2g\",\"물 60g\",\"후춧가루0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장이나 간장에 조리는 것보다 케첩은 염도가 낮으므로 케첩을 넣어 상큼하게 조리면 저나트륨 조리시 보완이 된다.\",\"instructions\":[\"1. 오징어는 껍질을 벗긴 후 안쪽에 대각선으로 칼집을 넣어 데친다.\",\"2. 당근, 시금치, 불린 표고버섯은 0.5cm 두께로 썬다.\",\"3. 시금치는 끓는 물에 데쳐 찬물에 헹군 뒤 물기를 제거한다.\",\"4. 달걀은 잘 풀어 도톰하게 달걀말이를 만 후 당근처럼 썬다.\",\"5. 오징어의 물기를 제거하고 밀가루를 살짝 뿌린후 2, 3의 재료를 모두 넣어 김밥 말듯이 돌돌말아 꼬치로 두군데를 고정시킨다.\",\"6. 토마토케첩소스의 재료를 섞어 팬에서 졸이다가 4의 오징어를 넣고 소스를 끼얹어가며 졸여 1.5cm의 두께로 썬다.\"]},{\"id\":\"k725\",\"title\":\"오징어보쌈과 저나트륨 된장소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053526_1416213326629.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/890-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/890-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/890-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/890-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/890-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/890-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"갑오징어 50g\",\"당근 9g\",\"오이 9g\",\"상추 7g [소스소개] 저나트륨된장소스:된장 1.6g\",\"양파 1.3g\",\"물 6.6g\",\"식초 0.4g\",\"설탕 0.2g\",\"청고추 0.2g\",\"홍고추 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"된장은 보통 양의 1/5로 줄이고, 분량을 늘리기 위해 양파, 풋고추, 홍고추를 잘게 다져서 넣는다.\",\"instructions\":[\"1. 오징어는 반으로 갈라 껍질을 제거하고 몸통 안쪽에 대각선으로 칼집을 넣는다.\",\"2. 칼집 낸 오징어를 끓는 물에 데친다.\",\"3. 데친 오징어는 한 입 크기로 썬다.\",\"4. 오이는 돌려 깎아 3cm 길이로 채썰고 당근도 4cm 길이로 얇게 채썬다.\",\"5. 드레싱에 들어갈 양파, 청·홍고추는 잘게 다져 분량의 재료와 섞어 저나트륨 된장소스를 만든다.\",\"6. 상추에 준비된 오징어와 오이, 당근, 저나트륨 된장소스를 기호에 맞게 곁들여 먹는다.\"]},{\"id\":\"k726\",\"title\":\"칠리새우\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053527_1416213327815.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/891-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/891-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/891-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/891-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/891-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/891-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"백새우 40g\",\"케첩 4g\",\"대파 6g\",\"녹말가루 3g\",\"밀가루 6g\",\"달걀 10g\",\"완두콩 4g\",\"식용유 5g\",\"참기름 0.5g [소스소개] 저나트륨칠리소스:두반장 1g\",\"고추기름 3g\",\"설탕 6g\",\"마늘 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 칠리소스는 고추기름 등을 넣어 매운맛을 내 저나트륨의 맛을 보완할수 있다.\",\"instructions\":[\"1. 새우는 손질하여 물기를 제거한다.\",\"2. 달걀, 녹말가루, 밀가루로 튀김옷을 만들어 새우에 묻힌다.\",\"3. 튀김옷을 입힌 새우를 170℃ 식용유에 두 번 튀겨낸다.\",\"4. 대파, 마늘, 생강은 다진다.\",\"5. 팬에 고추기름을 두르고 2를 넣고 볶다가 청주, 두반장, 케첩을 첨가하여 볶은 후 물을 넣고 설탕, 식초로 간을 맞춘다.\",\"6. 살짝 졸인 뒤 튀긴 새우와 완두콩을 넣고 물녹말로 농도를 맞추고 마지막으로 참기름을 넣는다.\"]},{\"id\":\"k727\",\"title\":\"연근샐러드, 흑임자소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190418/20190418111813_1555553893882.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409091835_1554769115905.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409091846_1554769126603.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409091922_1554769162313.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409091943_1554769183645.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409091958_1554769198466.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409092009_1554769209491.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"흑임자 30g\",\"연근 80g\",\"레몬 20g\",\"마요네즈 15g\",\"플레인요거트 15g\",\"식초 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스의 흑임자가 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 연근은 세척 후 껍질을 벗긴다.\",\"2. 연근을 슬라이스 한다.\",\"3. 물에 식초를 넣고 끓으면 연근을 데친다.\",\"4. 레몬즙을 짠다.\",\"5. 흑임자, 마요네즈, 플레인요거트를 믹서 하여 흑임자 소스를 만든다.\",\"6. 연근에 흑임자소스를 곁들여 담는다.\"]},{\"id\":\"k728\",\"title\":\"단호박함박스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103624_1584063384791.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103654_1584063414640.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103707_1584063427359.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103719_1584063439598.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103732_1584063452995.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103746_1584063466050.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313103801_1584063481612.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기 30g\",\"소고기 20g\",\"단호박 20g\",\"양파 10g\",\"마늘 1g\",\"당근 7g\",\"계란20g\",\"빵가루 5g\",\"우유 50ml\",\"콩기름 2g\",\"소금 0.4g\",\"후추 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"나트륨 함량이 높은 시판 소스를 대신해 수제 단호박 소스를 곁들였어요.\",\"instructions\":[\"1. 단호박은 쪄서 속을 파내고, 우유와 올리고당을 넣고 끓여 소스를 만든다.\",\"2. 소고기, 돼지고기, 양파, 마늘, 당근은 모두 잘게 다진다.\",\"3. ②에 빵가루, 달걀, 소금, 후추를 넣고 치댄다.\",\"4. 치댄 반죽을 둥글고 납작하게 만들어 준다.\",\"5. 팬에 기름을 두르고 노릇하게 굽는다.\",\"6. 함박스테이크에 단호박 크림소스를 부어 제공한다.\"]},{\"id\":\"k729\",\"title\":\"배깍두기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128052841_1611822521024.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053055_1611822655036.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053110_1611822670864.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053128_1611822688565.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053141_1611822701973.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053156_1611822716616.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053212_1611822732341.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배 80g\",\"부추 5g\",\"고춧가루 5g\",\"매실청 3g\",\"설탕 2g\",\"참깨 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배를 소금에 절이지 않고 고춧가루와 매실청으로 버무렸어요.\",\"instructions\":[\"1. 배는 껍질을 벗긴다.\",\"2. 껍질 벗긴 배를 깍뚝썰기 한다.\",\"3. 부추는 먹기 좋은 길이로 썬다.\",\"4. 배와 부추에 고춧가루를 버무려 색이 베이도록 한다.\",\"5. 매실청과 설탕을 넣어 새콤달콤하게 버무린다.\",\"6. 참깨를 뿌려 완성한다.\"]},{\"id\":\"k730\",\"title\":\"닭고기 찰깨빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308050056_1615190456312.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308051305_1615191185710.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308051326_1615191206193.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308051339_1615191219134.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308051355_1615191235281.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308051408_1615191248084.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308051423_1615191263725.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"방울토마토(60g)\",\"양파(70g)\",\"파프리카(120g)\",\"할라피뇨(10g)\",\"훈제 닭가슴살(40g)\",\"찰깨빵(45g)\",\"모차렐라치즈(30g)\",\"파슬리가루(약간)\",\"설탕(1g)\",\"소금(0.5g)\",\"레몬즙(15㎖)\",\"후춧가루(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"담백한 닭고기와 알싸하고 새콤한 살사소스로 맛을 내 나트륨의 사용을 줄였어요.\",\"instructions\":[\"1. 방울토마토, 양파, 파프리카, 할라피뇨, 훈제 닭가슴살은 작게 깍둑썬다.\",\"2. 손질한 재료에 양념을 고루 섞는다.\",\"3. 찰깨빵의 윗부분 1cm를 도려낸다.\",\"4. 빵 안에 버무린 재료를 채운 뒤 모차렐라치즈를 올린다.\",\"5. 180℃로 예열한 오븐에 속을 채운 빵을 넣고 5분간 구워 꺼낸다.\",\"6. 그릇에 구운 빵을 올린 뒤 파슬리가루를 뿌린다.\"]},{\"id\":\"k731\",\"title\":\"레몬연어 파피요트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxK4VJe-xN\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91Yj\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91cc\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91gB\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91jK\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91m5\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr91p3\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 브로콜리(¼개)\",\"애호박(½개)\",\"레몬(½개)\",\"양파(½개)\",\"노랑 파프리카(¼개)\",\"방울토마토(5개)\",\"마늘(8쪽)\",\"연어 필레(270g)\",\"로즈메리(3줄기)\",\"올리브유(1Ts)\",\"레몬즙(3.5Ts)\",\"올리브유(7Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•레몬즙으로 간을 맞춰 나트륨의 사용을 줄였어요.\\n•과일과 채소 본연의 맛을 살리고 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 브로콜리는 송이만 떼어내고, 애호박과 레몬은 4mm 두께로 둥글게 썰고, 양파와 노랑 파프리카는 한입 크기로 썰고, 방울토마토는 4등분하고, 마늘은 꼭지를 제거한다.\",\"2. 볼에 레몬즙을 넣고 올리브유를 조금씩 부어가며 거품기로 골고루 섞는다.\",\"3. 올리브유를 섞은 레몬즙에 소금, 후춧가루, 다진 양파를 넣고 고루 섞어 레몬소스를 만든 뒤 연어에 버무려 15분간 재운다.\",\"4. 종이포일에 애호박, 연어, 레몬, 로즈메리 순으로 깔고, 손질한 채소를 올린다.\",\"5. 올리브유(1Ts)를 뿌리고 종이포일 양끝을 돌돌 만 뒤 작은 구멍을 2~3개 낸다.\",\"6. 찜기에 김이 오르면 연어를 넣고, 뚜껑을 덮어 센 불로 25분간 익혀 마무리한다.\"]},{\"id\":\"k732\",\"title\":\"떡꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054654_1678265214010.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054806_1678265286395.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054822_1678265302582.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054839_1678265319326.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054854_1678265334882.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054910_1678265350129.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230310/20230310091616_1678407376975.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 떡볶이떡(40g)\",\"파(3.5g)\",\"양파(7g)\",\"식용유(3g)\",\"•양념장 : 케첩(8g)\",\"스리라차(3g)\",\"올리고당(2g)\",\"다진마늘(2g)\",\"간장(1g)\",\"참기름(1g)\",\"통깨(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•고추장 대신 케첩과 스리라차를 활용하여 달콤 매콤한 맛은 살리고 나트륨 섭취는 줄였어요.\",\"instructions\":[\"1. 떡볶이 떡은 끓는 물에 데쳐 건진다.\",\"2. 꼬치에 데친 떡을 꽂는다.\",\"3. 파와 양파는 다진다.\",\"4. 양념장 재료에 다진 양파와 파를 섞어 양념장을 만든다.\",\"5. 팬에 식용유를 두른 뒤 양념장을 볶는다.\",\"6. 양념장을 떡꼬치에 묻힌 뒤 통깨를 뿌려 마무리한다.\"]},{\"id\":\"k733\",\"title\":\"부추 배무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120014705_1732078025168.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111834_1732069114962.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111849_1732069129396.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111901_1732069141085.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111914_1732069154801.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111926_1732069166569.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120111937_1732069177803.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료]부추(30g)\",\"양파(10g)\",\"배(15g)<br>\",\"[양념]다진 마늘(8g)\",\"고춧가루(8g)\",\"멸치액젓(6g)\",\"저염간장(3g)\",\"레몬즙(10g)\",\"통깨(4g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•배를 사용하여 설탕 대신 과일의 단맛을 활용했어요.<br>\\n•부추를 사용하여 풍미를 높이고 나트륨 사용량을 줄였어요.\",\"instructions\":[\"1. 부추는 다듬어 5~6cm 크기로 썰고, 양파는 뿌리와 껍질을 제거해 얇게 채 썬다.\",\"2. 배는 껍질을 제거해 여덟 등분하고 씨를 제거하여 편 썰기를 한다.\",\"3. 다진 마늘, 고춧가루, 멸치액젓, 저염간장, 레몬즙, 통깨(2g)를 섞어 양념장을 만든다\",\"4. 부추, 양파, 배의 물기를 제거한다.\",\"5. 볼에 담고 양념장을 넣어 버무린다.\",\"6. 접시에 담고 통깨(2g)를 뿌려 마무리한다.\"]},{\"id\":\"k734\",\"title\":\"아보카도 두부 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053530_1416213330214.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/895-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/895-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/895-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/895-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/895-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/895-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연두부 50g\",\"아보카도작은것 35g\",\"게살냉동 50g\",\"양파 25g\",\"민트 0.25g[소스소개] 고추냉이 드레싱:고추냉이 갠것 6g\",\"간장 1g\",\"소금 0.2g\",\"레몬즙 10g\",\"올리브유엑스트라버전 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 소스는 염분이 적게 들어가므로 고추냉이와 같은 강한 향의 향신료와 같이 사용하면 맛이 보완이 된다\",\"instructions\":[\"1. 아보카도는 검은 빛이 돌면서 윤기가 흐르는 것을 골라 세로로 칼날을 넣어 칼날이 씨에 닿으면 한바퀴 돌린다.\",\"2. 양손으로 아보카도 양 끝을 잡고 비틀면서 반으로 나누고 칼날 안쪽 모서리로 씨를 찔러서 빼낸다.\",\"3. 아보카도 과육을 5cm 두께로 썬다.\",\"4. 냉동 게살은 하룻밤 전에 냉장고로 옮겨 놓거나, 실온에서 해동시킨 후 잘게 찢는다. 양파는 얇게 채썰고 민트도 잘게 썬다.\",\"5. 고추냉이 드레싱 재료를 섞는다.\",\"6. 두부는 원형틀로 찍어두고 양파와 게살, 아보카도를 곁들이고 민트를 올린 뒤 드레싱을 뿌린다.\"]},{\"id\":\"k735\",\"title\":\"과일 젤리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053532_1416213332265.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/897-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/897-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/897-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/897-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/897-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/897-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"젤라틴 5g\",\"자몽주수 100g\",\"귤통조림 20g\",\"파인애플통조림 5g\",\"체리 15g\",\"설탕 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 젤라틴을 물에 불려 놓는다.\",\"2. 자몽주스에 설탕을 넣고 가열한다.\",\"3. 불린 젤라틴을 넣어 약한 불에서 젤라틴을 녹인다.\",\"4. 틀에 귤과 파인애플, 체리를 넣는다.\",\"5. 틀에 젤라틴을 녹인 자몽주스를 넣는다.\",\"6. 냉장고에서 식혀 완성한다.\"]},{\"id\":\"k736\",\"title\":\"복숭아샤벳\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053534_1416213334638.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/900-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/900-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/900-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/900-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/900-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/900-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"복숭아 150g\",\"식혜 100g\",\"설탕시럽 20g\",\"민트 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 복숭아는 반으로 갈라 씨를 발라내고 두께 0.5cm가량만 남기고 속을 파낸다.\",\"2. 복숭아와 식혜, 설탕시럽을 넣고 믹서기에 굵게 간다.\",\"3. 2를 냉동실에서 4~5시간 정도 얼리면서 1시간마다 숟가락으로 긁어 샤벳을 만든다.\",\"4. 속을 파낸 복숭아도 냉동실에서 얼려 샤벳 그릇으로 사용한다.\",\"5. 3의 복숭아 식혜 샤벳을 떠서 얼린 복숭아 그릇에 담는다.\",\"6. 민트로 장식하여 완성한다.\"]},{\"id\":\"k737\",\"title\":\"과일 주스 조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053536_1416213336433.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/903-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/903-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/903-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/903-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/903-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/903-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"천도복숭아 30g\",\"자두 20g\",\"체리 40g\",\"산딸기 20g\",\"블루베리 10g\",\"사과 30g\",\"포도 10g\",\"포도주스 50g\",\"설탕 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 천도복숭아는 반으로 잘라 씨를 제거하고 각각 2등분하고 자두는 반으로 갈라 씨를 제거한다.\",\"2. 사과는 8등분하여 씨를 제거한다.\",\"3. 포도는 알알이 떼어내고 체리는 꼭지를 떼어내고 블루베리와 산딸기는 분량대로 준비한다.\",\"4. 냄비에 포도주스와 설탕, 준비한 과일을 넣고 약한불에서 끓인다.\",\"5. 천도복숭아가 부드러워지고 포도주스에 농도가 생기면 불을 끈다.\",\"6. 접시에 졸인 과일과 주스를 함께 담는다.\"]},{\"id\":\"k738\",\"title\":\"감자를 곁들인 야채스튜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053542_1416213342038.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/907-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/907-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/907-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/907-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/907-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/907-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파 15\",\"청피망 15g\",\"가지 10g\",\"애호박 18g\",\"양송이버섯 8g\",\"마늘다진것 2g\",\"토마토콩카세 10g\",\"감자 50g\",\"올리브오일 1g\",\"닭육수 15g\",\"토마토페이스트 8g\",\"생크림 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감자는 뜨거울 때 잘 으깨지므로 식기전에 작업한다. 토마토 콩카세는 껍질을 벗겨 씨를 제거하여 자른 것을 의미한다.\",\"instructions\":[\"1. 마늘은 다지고, 양파, 청피망, 가지, 애호박, 양송이는 1cm 주사위모양으로 썬다.\",\"2. 토마토는 끓는 물에 데쳐 껍질을 벗긴 뒤 씨를 제거하고 야채들과 같은 크기로 자른다.\",\"3. 감자는 껍질을 벗겨 큼직하게 썰어 삶은 뒤 완전히 익으면 오븐서 수분을 제거하고 으깨 우유, 생크림, 소금, 후추를 넣는다.\",\"4. 팬에 기름을 두르고 양파를 투명해질 때까지 볶은 뒤 마늘, 토마토 페이스트를 넣고 볶다가 청피망, 가지, 호박, 양송이, 토마토를 넣어 볶는다.\",\"5. 야채가 부드러워지면 닭육수를 넣어 한번 더 끓이고 소금, 후추로 간 한다.\",\"6. 접시에 완성된 으깬 감자를 깔고 그 위에 야채 스튜를 올려낸다.\"]},{\"id\":\"k739\",\"title\":\"김치 고구마밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053546_1416213346049.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/909-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/909-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/909-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/909-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/909-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/909-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 15g\",\"쌀 40g\",\"물 40g\",\"김치 8g\",\"사과작은것 95g\",\"참기름 1g\",\"마늘다진것 1g[소스1]간장 1g\",\"국간장 1g\",\"고춧가루 1g\",\"다진마늘 1g\",\"통깨 1g\",\"실파송송썬것 1.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"야채와 같이 밥을하는 경우에 물의 양을 정확히 하여 재료에서 나오는 수분으로 인해 질지 않도록 하며 쌀과 물이 동량이 되도록 하는 것이 좋다.\",\"instructions\":[\"1. 고구마는 1cm의 주사위모양으로 썰어 놓는다.\",\"2. 물에 씻은 김치를 송송 썰어서 참기름을 두른 팬에 볶다가 마늘과 소금을 넣어 볶은 뒤 깨소긂으로 마무리한다.\",\"3. 냄비에 불린 쌀과 고구마, 볶은 김치를 넣고 고슬고슬하게 밥을 짓는다.\",\"4. 사과의 꼭지 부분을 자른 뒤 속을 파내고 밥을 채운다.\",\"5.  160℃로 예열된 오븐에 밥을 채운 사과를 넣고 사과가 익을 정도로 구워준다.\",\"6. 양념장 재료를 섞어 양념장을 만들고 밥과 곁들여 낸다.\"]},{\"id\":\"k740\",\"title\":\"돈불고기 파인애플볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033235_1554791555920.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033321_1554791601579.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033335_1554791615555.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033352_1554791632000.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033405_1554791645133.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033419_1554791659435.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033438_1554791678280.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(불고기용) 120g\",\"파인애플 35g\",\"양배추 15g\",\"양파 10g\",\"당근 7g\",\"대파 5g\",\"설탕 5g\",\"부추 1g\",\"마늘 2g\",\"참기름 3g\",\"간장 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파인애플을 넣어 간장을 적게 사용해도 풍미를 낼 수 있어요.\",\"instructions\":[\"1. 돼지고기를 흐르는 물에 담궈 핏물을 제거한다.\",\"2. 파인애플 일부는 먹기 좋은 크기로 썰고 나머지는 믹서에 간다.\",\"3. 간 파인애플과 양념을 섞어 양념장을 만든다.\",\"4. 핏물을 제거한 돼지고기에 양념장을 섞어 재운다.\",\"5. 프라이팬에 기름을 두르고 양념한 돼지고기와 한 입 크기로 썬 채소를 볶는다.\",\"6. 썰어둔 파인애플을 넣는다.\"]},{\"id\":\"k741\",\"title\":\"비름나물 된장무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032656_1678343216209.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032736_1678343256363.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032751_1678343271103.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032806_1678343286733.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032820_1678343300854.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032834_1678343314937.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309032849_1678343329507.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 비름나물(70g)\",\"양파(10g)\",\"마늘(3g)\",\"생강(1g)\",\"•다시마 육수 : 물(200g)\",\"다시마(5g)\",\"•양념장 :  된장(2g)\",\"고추장(1g)\",\"마요네즈(2g)\",\"고춧가루(1g)\",\"•양념 : 참깨(1g)\",\"참기름(4g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•다시마육수에 비름나물을 데쳐 감칠맛을 살려 소금 사용을 줄였어요.\",\"instructions\":[\"1. 비름나물을 적당한 길이로 잘라 다시마육수에 데친 뒤 찬물에 헹궈 물기를 뺀다.\",\"2. 양파는 2mm 두께로 채 썰고 생강과 마늘은 곱게 다진다.\",\"3. 된장을 곱게 다진 뒤 구멍이 큰 체에 걸러 식감을 살리고 고추장, 마요네즈, 고춧가루와 섞는다.\",\"4. 양념장에 다진 생강, 마늘을 섞는다.\",\"5. 비름나물에 양파, 양념장을 넣고 골고루 무친다.\",\"6. 참기름을 둘러 가볍게 섞은 뒤 깨를 뿌려 마무리한다.\"]},{\"id\":\"k742\",\"title\":\"소고기 들깨 알토란탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052034_1554798034902.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052128_1554798088554.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052151_1554798111041.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052212_1554798132026.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052232_1554798152349.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052251_1554798171236.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052308_1554798188714.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(양지) 3g\",\"무 20g\",\"알토란 30g\",\"대파 15g\",\"느타리버섯 10g\",\"고사리 10g\",\"콩나물 10g\",\"고춧가루 10g\",\"깻잎순 3g\",\"들깨가루 15g\",\"소금 3g\",\"간장 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"들깻가루를 이용해 소금을 사용하지 않고 깊은 맛을 낼 수 있어요.\",\"instructions\":[\"1. 양지를 찬물에 담가 핏물을 제거한다.\",\"2. 양지와 무를 냄비에 끓인 뒤 양지를 건진다.\",\"3. 알토란은 쌀뜨물에 1시간 정도 담근 뒤 소금물에 삶아 아린 맛을 제거한다.\",\"4. 각종 채소를 손질하고 건져낸 양지를 찢는다.\",\"5. 육수에 손질한 야채와 양지를 넣고 끓인다.\",\"6. 고춧가루와 들깨가루를 넣고 끓인다.\"]},{\"id\":\"k743\",\"title\":\"과일삼겹살조림&파채무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313111944_1584065984038.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112016_1584066016373.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112029_1584066029870.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112044_1584066044005.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112103_1584066063252.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112116_1584066076425.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112131_1584066091305.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(삼겹살) 70.8g\",\"새싹채소 2.8g\",\"깐대파 3.5g\",\"파인애플 1.5g\",\"배 1.5g\",\"사과 1.5g\",\"깐양파 2g\",\"진간장 1.2g\",\"깐마늘 1.2g\",\"깐생강 0.3g\",\"고춧가루 0.17g\",\"레몬 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일을 이용하여 간장과 설탕의 사용을 줄였어요.\",\"instructions\":[\"1. 삼겹살은 덩어리로 준비하여 삶아낸다.\",\"2. 배, 사과, 파인애플, 양파, 깐마늘, 깐생강은 갈아서 체에 거르고 간장과 함께 끓인다.\",\"3. ②에 삶아낸 삼겹살을 넣어 윤기 나게 조린다.\",\"4. 대파는 가늘게 채 썰고, 새싹채소는 깨끗하게 씻는다.\",\"5. 레몬즙, 식초, 설탕, 국간장, 고춧가루를 넣어 만든 소스를 야채에 버무린다.\",\"6. 한입 크기로 썬 삼겹살과 ⑤를 곁들여 낸다.\"]},{\"id\":\"k744\",\"title\":\"곤약백김치말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053429_1611822869995.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053501_1611822901019.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053516_1611822916619.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053529_1611822929572.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053543_1611822943743.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053559_1611822959641.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128053611_1611822971560.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"판곤약 60g\",\"부추 2g\",\"파프리카(빨강\",\"노랑\",\"청색) 각 7g\",\"대왕오징어채 30g\",\"백김치 30g\",\"양조식초 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕, 소금을 사용하지 않고 백김치와 파프리카의 단맛을 이용했어요\",\"instructions\":[\"1. 곤약은 얇게 편으로 썰어 데친 뒤, 백김치 국물에 절인다.\",\"2. 끓는 물에 식초를 넣고 오징어를 질기지 않게 살짝 삶는다.\",\"3. 파프리카는 채썰어 준다.\",\"4. 백김치는 물기를 제거한다.\",\"5. 곤약을 깔고 오징어, 파프리카를 얹어 백김치로 말아준다.\",\"6. 데쳐낸 부추로 풀어지지 않게 매듭을 짓는다.\"]},{\"id\":\"k745\",\"title\":\"꽈리고추 닭강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr90FP\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr92CQ\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr92F6\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr92Lu\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr92z4\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr92_V\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr92-s\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 꽈리고추(2줌=100g)\",\"양파(½개)\",\"건고추(3개)\",\"마늘(10쪽)\",\"대파(1대)\",\"닭다릿살(400g)\",\"백후춧가루(0.3Ts)\",\"식용유(8Ts)\",\"참깨(0.3Ts)\",\"전분(2Ts)\",\"달걀흰자(1개)\",\"굴소스(1.5Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•굴소스도 나트륨 함량이 높으므로 과량 사용하지 않도록 주의하세요.\\n•건고추, 마늘, 대파로 만든 기름의 은은한 향으로 자극적이지 않은 맛을 냈어요.\\n•양파를 이용하여 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 꽈리고추, 양파, 건고추는 3cm 길이로 썰고, 마늘은 2등분하고, 대파는 송송 썬다.\",\"2. 닭다릿살은 4×4cm 크기로 썰고, 백후춧가루에 버무린 뒤 튀김옷 재료를 입힌다.\",\"3. 약한 불로 달군 팬에 식용유를 두른 뒤 손질한 건고추, 마늘, 대파를 넣고 볶아 기름을 낸다.\",\"4. 튀김옷을 입힌 닭다릿살을 넣어 노릇해 질 때까지 튀기듯 볶고, 양파를 넣어 투명해질 때까지 볶는다.\",\"5. 센 불로 올린 뒤 양념장을 넣어 재빠르게 볶고, 꽈리고추를 넣어 10초간 볶아 꺼낸다.\",\"6. 참깨를 뿌려 마무리한다.\"]},{\"id\":\"k746\",\"title\":\"참치두부 주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Ba2\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9RXM\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Ra2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9RbK\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Rdz\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9RgP\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Rk-\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 두부(1모=300g)\",\"파프리카(빨강\",\"노랑 각 ¼개)\",\"깻잎(4장)\",\"잡곡밥(70g)\",\"통조림 참치(50g)\",\"스테비아(0.5Ts)\",\"간장(0.5Ts)\",\"참기름(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•통조림 참치 등 가공식품 사용 시에는 물에 데치거나 뜨거운 물을 부으면 나트륨 섭취를 줄일 수 있어요.\\n•스테비아를 이용하여 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 큰 볼에 두부를 담은 뒤 물이 담긴 무거운 그릇을 3분간 올려 수분을 제거한다.\",\"2. 두부 속을 사각형 모양으로 파내고, 파낸 두부 속은 물기를 꼭 짜 으깬다.\",\"3. 파프리카와 깻잎은 잘게 썬다.\",\"4. 통조림 참치는 체에 밭친 뒤, 뜨거운 물을 부어 기름과 염분을 제거한다.\",\"5. 볼에 으깬 두부, 손질한 채소, 잡곡밥, 참치를 넣은 뒤 양념해 고루 섞는다.\",\"6. 주먹밥을 동그랗게 만들고, 속을 판 두부 속에 넣어 마무리한다.\"]},{\"id\":\"k747\",\"title\":\"열무톳김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120014837_1732078117022.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112013_1732069213935.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112025_1732069225773.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112036_1732069236444.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112048_1732069248071.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112059_1732069259420.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20241120/20241120112110_1732069270505.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"1인분 기준<br>\",\"[주재료] 열무(30g)\",\"톳(10g)\",\"마늘(3g)\",\"생강(1g)<br>\",\"[양념] 어간장(5g)\",\"고춧가루(2g)\",\"통깨(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•나트륨 사용량을 줄이기 위해 열무를 절이지 않고 사용했어요.<br>\\n•어간장을 사용하여 감칠맛을 증가시켜 나트륨 사용량을 줄였어요.\",\"instructions\":[\"1. 톳은 깨끗한 물에 여러 번 씻은 후 끓는 물에 살짝 데치고 물기를 제거한다\",\"2. 열무는 3cm 크기로 썬다.\",\"3. 손질한 열무는 끓은 물에 살짝 데치고 물기를 제거한다.\",\"4. 마늘, 생강은 잘게 다진다.\",\"5. 볼에 손질한 열무, 톳, 마늘, 생강을 넣고 고춧가루, 어간장으로 간하여 버무린다.\",\"6. 접시에 담고 통깨를 뿌려 마무리한다.\"]},{\"id\":\"k748\",\"title\":\"콩가루 쑥 다쿠아즈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016014506_1760589906399.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016015925_1760590765848.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016015945_1760590785193.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016020007_1760590807526.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016020029_1760590829101.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016020048_1760590848347.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016020109_1760590869369.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 달걀흰자 180g\",\"설탕① 50g\",\"아몬드가루 160g\",\"박력 밀가루 15g\",\"슈가파우더 40g\",\"콩가루 40g\",\"쑥크림 > 생크림 150g\",\"설탕② 20g\",\"쑥가루 24g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"향신 재료인 쑥을 활용해 풍미를 높이고, 나트륨과 당류는 줄였어요.\",\"instructions\":[\"1. 달걀흰자에 설탕①을 조금씩 넣으며,\\n단단한 머랭을 만든다. 아몬드가루,\\n박력 밀가루를 체 쳐서 머랭에 넣고\\n자르듯이 섞어 반죽을 만든다.\",\"2. 오븐 팬에 테프론 시트를 깔고,\\n다쿠아즈 틀을 올린 후 반죽을\\n팬닝한다. 다쿠아즈 틀을 제거하고,\\n슈가파우더를 두 번에 나누어서 뿌린다.\",\"3. 180°C로 예열한 오븐에서 15분 동안\\n구운 후 꺼내 식혀 다쿠아즈를 만든다.\",\"4. 생크림에 설탕②를 넣고 휘핑하여\\n생크림이 약간 단단해지면 쑥가루를\\n섞어 쑥크림을 만든다.\",\"5. 다쿠아즈에 쑥크림을 바르고, 다른\\n다쿠아즈로 덮어 샌드한다.\",\"6. 콩가루를 골고루 뿌리고 냉장실에서\\n10분 동안 식혀 마무리한다.\"]},{\"id\":\"k749\",\"title\":\"대구 크림스튜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053550_1416213350093.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/912-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/912-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/912-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/912-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/912-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/912-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파다진것 10g\",\"청피망다진것 10g\",\"마늘다진것 2g\",\"청고추다진것 2g\",\"대구살 35g\",\"토마토콩카세 30g\",\"땅콩버터 1g\",\"생크림 13g\",\"파프리카가루 1g\",\"새우 20g\",\"올리브오일 1g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우는 지나치게 가열하면 질겨지므로 가장 나중에 넣어 익힌다.\",\"instructions\":[\"1. 양파, 청피망, 마늘, 고추는 다지고, 대구살은 굵직하게 썬다.\",\"2. 토마토는 데친 뒤 껍질을 벗기고 씨를 제거해 과육만 썬다.\",\"3. 기름을 두른 팬에 양파, 고추를 넣고 볶다가 마늘을 넣고 볶는다.\",\"4. 생크림과 땅콩버터를 넣은 후 토마토, 파프리카, 새우 순서대로 넣어 끓인다.\",\"5. 썰어둔 대구살을 넣는다.\",\"6. 소금, 후추로 간을 한다.\"]},{\"id\":\"k750\",\"title\":\"대추죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053551_1416213351482.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/913-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/913-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/913-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/913-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/913-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/913-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"좁쌀 15g\",\"대추 10g\",\"깐밤 5g\",\"찹쌀가루 10g\",\"물 70g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"좁쌀 대신 찹쌀가루를 사용해도 된다.찹쌀물은 찹쌀과 물을 1:1 비율로 섞어 준비한다.\",\"instructions\":[\"1. 좁쌀을 씻어 불린다.\",\"2. 대추와 깐 밤을 냄비에 넣고 물 4컵을 넣고 대추가 무르도록 삶는다.\",\"3. 삶은 대추를 손으로 주물러 대추 속살이 나오도록 한 뒤 밤과 함께 체에 거른다.\",\"4. 좁쌀은 5배의 물을 부어 저어가면서 익힌다.\",\"5. 3을 4에 넣어 잘 섞은 뒤 찹쌀물을 넣어 농도가 나도록 끓인다.\",\"6. 소금으로 간을 맞추고 준비한 그릇에 담아낸다.\"]},{\"id\":\"k751\",\"title\":\"돼지고기 토마토 두부볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053552_1416213352435.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/914-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/914-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/914-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/914-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/914-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/914-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기목살 30g\",\"두부 30g\",\"토마토 50g\",\"생강다진것 5g\",\"파다진것 5g\",\"땅콩기름 5g\",\"간장 5g\",\"닭육수 10g\",\"물전분 10g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"전분을 육수에 넣어 풀어주면 음식의 향이 더 좋아진다. 고기, 두부나 토마토의 모양이 으깨지지 않도록 유의하며, 전체적으로 부드러운 질감을 갖고 있어야 한다.\",\"instructions\":[\"1. 돼지고기는 깨끗이 손질한 뒤 잘게다진다.\",\"2. 두부는 1cm 정사각형 모양으로 썬다\",\"3. 토마토는 껍질과 씨를 제거한 뒤 두부와 같은 크기로 썬다.\",\"4. 기름을 두른 팬에 파와 생강을 넣고 볶아 향이 나면 1을 넣고 볶은 뒤 따로 담아둔다.\",\"5. 기름을 두른 팬에 토마토, 두부, 고기를 넣고 볶다가 육수를 자작하게 부은 뒤 간장, 소금으로 간을 한다.\",\"6. 소스가 졸아들면 두부를 넣고 물 전분을 넣어 소스 농도를 맞춘다.\"]},{\"id\":\"k752\",\"title\":\"멜론스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053554_1416213354184.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/915-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/915-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/915-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/915-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/915-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/915-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"멜론 110g\",\"오렌지 30g\",\"레몬 5g\",\"탄산수 30g\",\"레몬껍질 2g\",\"전분 3g\",\"설탕 5g[장식재료선택] 멜론\",\"자두\",\"생크림\",\"민트\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오렌지와 레몬껍질 부분에 향을 내는 오일주머니가 있어 진한 향을 이용하기 위해서는 껍질을 깨끗이 씻어 사용하는 것이 좋다. 오렌지와 레몬껍질은 제스터나 야채 껍질 벗기는 기구를 이용하여 잘라낼 수 있다.\",\"instructions\":[\"1. 메론은 적당한 크기로 잘라 믹서에 간다.\",\"2. 오렌지와 레몬은 과육만 잘라내 믹서에 각각 갈아 주스형태로 만든다.\",\"3. 2에 탄산수, 오렌지껍질, 레몬껍질을 넣어 향이 우러나도록 끓인다.\",\"4. 3에 전분을 넣어 농도를 맞춘 뒤 덩어리지지 않게 체에 걸러 차갑게 식힌다.\",\"5. 1에 4를 넣고 잘 섞은 뒤 설탕으로 맛을 낸다.\",\"6. 생크림을 휘핑해 올리고 자두, 메론, 민트로 장식한다.\"]},{\"id\":\"k753\",\"title\":\"미니버거\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053555_1416213355495.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/916-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/916-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/916-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/916-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/916-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/916-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파다진것 3g\",\"브로컬리다진것 3g\",\"당근다진것 3g\",\"바질다진것 1g\",\"달걀 6g\",\"쇠고기다진것 25g\",\"돼지고기갈은것 10g\",\"빵가루 5g\",\"마요네즈 1g\",\"토마토케첩 1g\",\"미니\",\"버거빵 12g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양파를 기름을 두르지 않은 팬에 볶아 사용하면 물기와 매운맛을 제거해 주므로 햄버거에 넣는 양파는 볶아서 사용하기도 한다.\",\"instructions\":[\"1. 바질과 양파, 브로콜리, 당근은 곱게 다진다.\",\"2. 소고기와 돼지고기는 곱게 간다.\",\"3. 2를 1:1 비율로 섞고 1과 달걀, 케첩, 후추, 빵가루와 섞어 패티를 만든다.\",\"4. 미니버거빵의 안쪽 면에 버터를 바른 후 팬에서 살짝 구워준다.\",\"5. 3을 팬에서 갈색이 나도록 익혀준다.\",\"6. 4에 마요네즈를 바르고 양상추, 패티, 케첩, 토마토, 양상추 순으로 올리고 마요네즈를 바른 빵으로 덮는다.\"]},{\"id\":\"k754\",\"title\":\"바질 고구마 옥수수빵(플렌타)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053556_1416213356807.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/917-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/917-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/917-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/917-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/917-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/917-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"시금치 10g\",\"바질 3g\",\"고구마 30g\",\"옥수수가루플렌타가루 15g\",\"파마산치즈 10g\",\"모짜렐라 치즈 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마는 항상화 비타민 전구체, 베타카로틴 성분과 섬유질이 많아 영양 간식용으로 좋다.\",\"instructions\":[\"1. 시금치와 바질을 팬에서 볶다가 소금, 후추로 간한 뒤 모짜렐라 치즈를 넣어 식히고 고구마는 삶아 껍질을 벗긴 뒤 1cm 주사위 모양으로 자른다.\",\"2. 소스팬에 물 2컵반을 넣고 끓이다가 찬물 1컵에 소금을 넣고 섞은 옥수수 가루를 천천히 넣어준다.\",\"3. 다시 끓어오를 때까지 천천히 젓다가 낮은 온도에서 아주 되직해질 때까지 익힌 뒤 파마산 치즈를 넣고 섞는다.\",\"4. 버터를 바른 사기그릇에 3을 절반가량 넣고 그위에 1과 2를 올리고, 남은 반죽을 올려 그릇을 채워 냉장고에서 식힌다.\",\"5. 4가 완전히 굳으면 176℃의 오븐에서 윗면에 갈색이 나도록 40분정도 굽는다.\",\"6. 5를 적당한 크기로 잘라 접시에 담고 기호에 따라 토마토케첩을 곁들여 낸다.\"]},{\"id\":\"k755\",\"title\":\"밥스틱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053557_1416213357993.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/918-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/918-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/918-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/918-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/918-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/918-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당근다진것 10g\",\"양파다진것 15g\",\"홍피망다진것 10g\",\"청피망다진것 10g\",\"햄다진것 10g\",\"밥 10g\",\"카레가루 2g\",\"춘권피 30g\",\"치즈 5g\",\"튀김기름 3g\",\"소금적당량\",\"후춧가루 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밥은 고슬고슬하게 지어 사용하는 것이 좋다.\",\"instructions\":[\"1. 당근, 양파, 청피망, 홍피망, 햄은 곱게 다진다.\",\"2. 달군 팬에 1을 넣고 볶는다.\",\"3. 2에 밥을 넣고 볶으면서 카레가루와 소금, 후춧가루로 간을 맞춘다.\",\"4. 치즈는 적당한 크기로 잘라준다.\",\"5. 춘권피에 3과 4를 넣고 스틱 모양으로 만든다.\",\"6. 팬에 기름을 넉넉히 두르고 5를 튀겨준다\"]},{\"id\":\"k756\",\"title\":\"버섯 리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053339_1416213219624.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/788-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/788-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/788-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/788-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/788-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/788-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 70g\",\"양송이버섯 15g\",\"마늘다진것 2g\",\"닭육수 180g\",\"파슬리다진것 2g\",\"타임다진것 0.5\",\"올리브오일 1.5g\",\"파마산치즈 3g\",\"버터 1g\",\"소금적당량\",\"후추적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"리조또는 볶음밥보다 기름이 적게 들어가고 우유 등을 넣을 수도 있기 때문에 다양한 방법으로 영양성분을 보강할 수 있다.\",\"instructions\":[\"1. 기름을 두른 팬에 다진 마늘을 넣고 볶는다.\",\"2. 2mm 두께로 썬 양송이버섯을 넣고 볶아준 뒤 접시에 담는다.\",\"3. 버섯을 볶은 팬에 쌀을 넣고 볶는다.\",\"4. 볶은 쌀에 닭육수를 넣고 수분이 흡수 될 때까지 잘 저어가며 조리한다.\",\"5. 쌀이 어느 정도 익으면 볶아놓은 버섯을 넣고 쌀이 완전히 익을 때까지 조리한다.\",\"6. 파마산치즈, 소금, 후추, 타임 다진것, 다진 파슬리를 넣어 마무리한다.\"]},{\"id\":\"k757\",\"title\":\"버섯 참치 무른밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053600_1416213360850.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/920-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/920-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/920-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/920-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/920-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/920-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"불린 쌀 30g\",\"물 92g\",\"참치살 10g\",\"표고버섯 5g\",\"무 5g\",\"양파 5g\",\"참기름 2g\",\"통깨 1g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"물의 양 조절에 주의하여 너무 죽처럼 되지 않도록 주의 한다.\",\"instructions\":[\"1. 불린 쌀은 믹서나 절구를 이용하여 간다.\",\"2. 참치 살, 표고버섯, 무, 양파는 곱게 다진다.\",\"3. 팬에 참기름을 두르고 1과 다진 표고버섯, 무, 양파를 볶는다.\",\"4. 3에 물을 넣어 무른 밥을 짓는다.\",\"5. 4의 밥이 끓어오르면 다진 참치 살을 넣고 저어가며 끓인다.\",\"6. 참치 살이 다 익으면 통깨를 뿌린다.\"]},{\"id\":\"k758\",\"title\":\"송이 미역국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053603_1416213363580.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/922-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/922-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/922-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/922-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/922-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/922-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"불린 쌀 30g\",\"양송이버섯 10g\",\"당근 10g\",\"양파 3g\",\"마른미역 5g\",\"참기름 2g\",\"물 90g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"죽은 항상 소금 간을 마지막에 해야 묽어지지 않는다.\",\"instructions\":[\"1. 쌀은 깨끗하게 씻어 불린다.\",\"2. 1을 분쇄기로 살짝 간다.\",\"3. 양송이버섯과 채소를 잘게 다진다.\",\"4. 마른 미역은 30분 정도 불렸다가 잘게 다진다.\",\"5. 냄비에 참기름을 두르고 2를 볶다가 3, 4를 넣고 한번 더 볶는다.\",\"6. 5에 물을 넣은 뒤 쌀알이 퍼지도록 끓인다.\"]},{\"id\":\"k759\",\"title\":\"시금치 배 미음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053604_1416213364610.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/923-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/923-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/923-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/923-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/923-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/923-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"불린쌀 30g\",\"물 90g\",\"배 25g\",\"시금치 20g\",\"꿀 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"물의 양은 쌀의 5배 정도로 하여 묽은 미음으로 만들어도 좋다.\",\"instructions\":[\"1. 쌀은 깨끗하게 씻어 불린다.\",\"2. 2를 믹서나 절구로 곱게 갈아 냄비에 물과 함께 넣고 끓인다.\",\"3. 배는 껍질과 씨를 제거하고 강판에 간다.\",\"4. 시금치는 끓는 물에 데친 후 물기를 꼭 짜서 곱게 다진다.\",\"5. 2가 끓어오르면 3,4를 넣고 끓인다.\",\"6. 입맛에 맞게 꿀로 간한다.\"]},{\"id\":\"k760\",\"title\":\"어린이 스시\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053608_1416213368763.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/925-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/925-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/925-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/925-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/925-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/925-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 120g\",\"달걀 삶은것 20g\",\"슬라이스햄 5g\",\"슬라이스치즈 5g\",\"양파 3g\",\"샐러리 3g\",\"캔참치 3g\",\"칵테일새우 5g\",\"날치알 3g\",\"마요네즈 5g[초대리] 식초 5g\",\"설탕 3g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일을 모양틀로 찍어 올려놓아도 된다.\",\"instructions\":[\"1. 초대리 재료를 분량대로 섞어 설탕, 소금이 녹을 정도로만 가열해 초대리를 만들어 고슬고슬하게 지은 따듯한 밥에 넣고 섞어 식힌다.\",\"2. 달걀은 삶아 흰자와 노른자로 따로 체에 내려 가루를 만들어 놓는다.\",\"3. 햄, 치즈는 원하는 모양틀로 찍는다.\",\"4. 기름을 제거한 참치에 다진 양파와 셀러리, 마요네즈를 섞는다.\",\"5. 칵테일 새우는 데쳐서 식힌다.\",\"6. 모양틀에 밥을 찍어내고 그 위에 준비한 재료들을 올려 완성한다.\"]},{\"id\":\"k761\",\"title\":\"에멘탈 치즈 퐁듀\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053610_1416213370153.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/926-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/926-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/926-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/926-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/926-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/926-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"에멘탈 치즈 20g\",\"마늘 2g\",\"넉맥약간\",\"닭육수 30g\",\"물전분 2g\",\"바케트빵 6g\",\"방울토마토 30g\",\"키위 20g\",\"소금적당량\",\"후추 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치즈가 닭육수와 잘 섞여 분리되지 않도록 한쪽 방향으로 잘 저어 주어야 한다.\",\"instructions\":[\"1. 바닥이 두꺼운 팬의 표면에 마늘을 문질러 마늘 즙을 골고루 묻힌다.\",\"2. 1을 가열한 뒤 버터를 녹인다.\",\"3. 팬에 닭육수와 물전분을 넣고 약한 불에서 덩어리가 생기지 않도록 저어가며 끓인다.\",\"4. 자른 에멘탈치즈를 넣고 나무 주걱을 이용하여 한 방향으로 젓는다.\",\"5. 치즈가 다 녹으면 기호에 맞게 넉맥, 소금, 후추를 넣는다.\",\"6. 바케트, 방울토마토, 키위 등을 적당한 크기로 잘라 꼬치에 꼿아 곁들인다.\"]},{\"id\":\"k762\",\"title\":\"두부구이, 버섯소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033713_1554791833052.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033742_1554791862874.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033758_1554791878109.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033813_1554791893702.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033832_1554791912004.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033847_1554791927240.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033904_1554791944845.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 100g\",\"느타리버섯 10g\",\"발사믹크림 5g\",\"올리브유 5g\",\"올리고당 5g\",\"쪽파 1g\",\"간장 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"두부의 고소한 맛과 발사믹크림을 이용한 버섯소스의 새콤한 맛으로 싱겁지 않아요.\",\"instructions\":[\"1. 두부를 1.5cm 두께로 잘라 물기를 뺀다.\",\"2. 프라이팬에 올리브유를 두르고 두부를 굽는다.\",\"3. 느타리버섯을 먹기 좋은 크기로 찢는다.\",\"4. 느타리버섯을 올리브유에 살짝 볶는다.\",\"5. 4에 발사믹크림, 올리고당을 넣어 졸인다.\",\"6. 두부구이 위에 소스를 올린다.\"]},{\"id\":\"k763\",\"title\":\"고구마 김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040208_1554793328976.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040259_1554793379581.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040320_1554793400853.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040349_1554793429348.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040418_1554793458444.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040444_1554793484270.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040507_1554793507506.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 35g\",\"미나리 3g\",\"홍고추 1g\",\"고춧가루 0.8g\",\"올리고당 0.5g\",\"마늘 1g\",\"젓갈 0.5g\",\"참깨 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"젓갈을 양념에 넣지 않고 고구마를 절이는데 쓰면 사용량을 줄일 수 있어요.\",\"instructions\":[\"1. 고구마를 먹기 좋은 크기로 썬다.\",\"2. 고구마를 젓갈에 절인다.\",\"3. 미나리, 홍고추를 먹기 좋은 크기로 썬다.\",\"4. 양념 재료를 모두 섞는다.\",\"5. 절인 고구마와 썰어둔 미나리, 홍고추, 양념을 섞어 무친다.\",\"6. 참깨를 뿌려 마무리한다.\"]},{\"id\":\"k764\",\"title\":\"담양식떡갈비&야채쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112428_1584066268285.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313104524_1584063924063.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313104557_1584063957402.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313104616_1584063976952.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313104631_1584063991222.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313104654_1584064014577.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313104711_1584064031363.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"우육(분쇄육) 60g\",\"돈육(분쇄육) 30g\",\"두부 30g\",\"양파 5g\",\"대파 5g\",\"상추 30g\",\"깻잎 10g\",\"해바라기씨 2g\",\"간장 0.5g\",\"설탕 5g\",\"쌈장 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쌈장에 두부와 해바라기씨를 섞어 염분을 낮췄어요.\",\"instructions\":[\"1. 분쇄 우육과 돈육은 해동 후 핏물을 제거한다.\",\"2. 두부는 끓는 물에 데쳐낸 후 으깬다.\",\"3. 우육, 돈육, 다진양파, 다진대파, 으깬 두부(15g)에 간장과 설탕으로 간을 한 후 여러번 치댄다.\",\"4. 점성이 생긴 고기를 동그랗게 성형한 후 팬에 구워낸다.\",\"5. 쌈장에 으깬 두부(15g)와 해바라기 씨를 넣어 섞는다.\",\"6. 떡갈비와 양념장, 야채쌈을 함께 제공한다.\"]},{\"id\":\"k765\",\"title\":\"단감피클\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054056_1611823256080.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054123_1611823283009.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054135_1611823295849.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054148_1611823308432.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054201_1611823321317.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054216_1611823336523.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054228_1611823348472.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단감 60g\",\"식초 15g\",\"설탕 25g\",\"물 15ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"나트륨이 높은 김치를 새콤달콤한 피클로 대체해 염분을 줄여요.\",\"instructions\":[\"1. 단감의 껍질과 씨를 제거한다.\",\"2. 단감을 깍둑썰기 한다.\",\"3. 식초와 설탕과 물을 섞어 단촛물을 만든다.\",\"4. 단촛물을 끓인다.\",\"5. 단촛물을 식혀 단감에 부워 절인다.\",\"6. 30분 정도 숙성시켜 완성한다.\"]},{\"id\":\"k766\",\"title\":\"들깨 삼계면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052649_1615192009692.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052327_1615191807585.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052341_1615191821496.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052354_1615191834939.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052407_1615191847952.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052420_1615191860456.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052435_1615191875734.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼계탕용 닭(250g)\",\"우유(500㎖)\",\"삼계탕 티백(70g)\",\"메밀면(100g)\",\"깻잎(5장)\",\"바질(5장)\",\"삼계탕 육수(100㎖)\",\"사과식초(30g)\",\"홍고추(2개)\",\"사과(½개)\",\"삼계탕 육수(30㎖)\",\"들깻가루(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"들깻가루의 고소함과 식초의 새콤함으로 짠맛을 보완했어요.\",\"instructions\":[\"1. 닭은 우유에 담가 20분간 재운다.\",\"2. 냄비에 물(1.5L)과 닭, 삼계탕 티백, 소금을 넣어 30분간 삶아 건진 뒤 살을 발라 한입 크기로 찢는다.\",\"3. 끓는 삼계탕 육수(800㎖)에 메밀면을 4분간 삶아 건져 얼음에 비벼 식힌 뒤 돌돌 말아준다.\",\"4. 끓는 물(500㎖)에 깻잎을 넣어 1분간 살짝 데쳐 건진 뒤 펼쳐 찢은 닭고기, 들깨소스, 바질을 얹어 돌돌 말아준다.\",\"5. 믹서에 국물 재료를 넣어 간 뒤 체에 거른다.\",\"6. 그릇에 메밀면과 깻잎말이를 담은 뒤 국물을 부어 마무리한다.\"]},{\"id\":\"k767\",\"title\":\"골뱅이무침과 삼겹살수육\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr946U\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr95Hs\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr95KY\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr95l_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr95nl\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr95qW\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr95w0\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 삼겹살(900g)\",\"파채(100g)\",\"월계수잎(3~5장)\",\"맛술(3Ts)\",\"설탕(1Ts)\",\"고춧가루(1.5Ts)\",\"간장(1Ts)\",\"고추장(3Ts)\",\"다진 마늘(1Ts)\",\"레몬즙(1Ts)\",\"골뱅이 국물(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•양파, 대파 등 다양한 채소를 사용하여 재료 본연의 감칠맛을 살렸어요.\\n•신맛의 레몬즙을 양념장에 넣어 적은 양으로도 단맛과 감칠맛을 높일 수 있어요.\\n•골뱅이를 끓는 물에 데쳐 나트륨 함량을 줄였어요.\",\"instructions\":[\"1. 양파는 도톰하게 모양대로 썰고, 대파는 2등분하고, 마늘은 꼭지를 제거하고, 알배추는 깨끗하게 씻는다.\",\"2. 통조림 골뱅이는 체에 밭쳐 국물을 거르고, 끓는 물에 30초간 데쳐 건진 뒤 찬물에 헹군다.\",\"3. 냄비에 양파, 대파를 깔고, 통마늘, 삼겹살, 월계수잎, 맛술을 넣어 센 불로 끓인다.\",\"4. 채즙이 나오면 약한 불로 줄여 45분간 고기를 삶는다.\",\"5. 파채에 데친 골뱅이와 양념장을 넣어 골고루 버무린다.\",\"6. 삶은 수육은 한 김 식힌 뒤 한입 크기로 썰고, 알배추, 골뱅이무침을 곁들여 마무리한다.\"]},{\"id\":\"k768\",\"title\":\"살레마이슈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016020447_1760591087339.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016021124_1760591484417.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016021141_1760591501005.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016021158_1760591518111.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016021218_1760591538236.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016021331_1760591611335.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016021353_1760591633127.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 바나나 60g\",\"양파 24g\",\"양송이버섯 24g\",\"감자 24g\",\"검은콩두유 24g\",\"달걀 48g\",\"후추 3g\",\"다진 마늘 12g\",\"아몬드가루 36g\",\"베이킹파우더 3g\",\"강황가루 6g\",\"토 핑 > 방울토마토 36g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1 칼륨이 풍부한 토마토, 양파를 활용하여 나트륨 배출을 도왔어요.\\n2 채소는 제철 식재료로 변경하여 활용해도 좋아요.\",\"instructions\":[\"1. 바나나는 으깨고 양파, 양송이버섯,\\n감자, 바질은 작게 자른다.\\n방울토마토는 1/4 크기로 자른다.\",\"2. 볼에 손질한 바나나, 양파, 양송이버섯,\\n감자, 바질을 넣고 검은콩두유, 달걀,\\n후추, 다진 마늘을 넣고 섞는다.\",\"3. 볼에 아몬드가루, 베이킹파우더,\\n강황가루를 체 쳐서 넣고 섞어 반죽을\\n완성한다.\",\"4. 머핀 틀에 반죽을 2/3 정도 넣고,\\n손질한 방울토마토 3~4토막을 올린다.\",\"5. 170°C로 예열한 오븐에서 20분 동안\\n구운 후 꺼낸다.\",\"6. 바질로 장식하여 마무리한다.\"]},{\"id\":\"k769\",\"title\":\"완두콩 스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053611_1416213371666.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/927-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/927-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/927-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/927-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/927-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/927-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파다진것 10g\",\"샐러리다진것 5g\",\"베이컨 13g\",\"완두콩 80g\",\"육수 120g\",\"생크림 2g\",\"소금 적당량\",\"후추 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"육수는 주로 닭뼈와 다양한 야채를 함께 넣고 끓인 닭 육수를 이용한다.\",\"instructions\":[\"1. 양파와 셀러리는 다지고, 베이컨은 적당한 크기로 자른다.\",\"2. 팬에 베이컨을 넣고 볶다가 양파, 셀러리를 넣고 색이 나지 않게 볶는다.\",\"3. 야채가 볶아지면 완두콩을 넣고 충분히 볶아준다.\",\"4. 완두콩이 반 정도 익으면 육수를 넣고 푹 끓여준다.\",\"5. 완두콩이 다 익으면 믹서에 간 뒤 체에 걸러낸다.\",\"6. 5를 냄비에 옮기고 기호에 맞게 소금, 후춧가루, 생크림을 넣는다.\"]},{\"id\":\"k770\",\"title\":\"유부 만두찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053613_1416213373259.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/928-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/928-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/928-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/928-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/928-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/928-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"유부 10g\",\"미나리 10g\",\"두부 20g\",\"닭가슴살 15g\",\"양파채썬것 15g\",\"당근채썬것 10g\",\"건표고버섯 5g\",\"시금치 10g\",\"소금적당량\",\"흰 후춧가루 적당량\",\"깨소금 1g\",\"참기름 1g [초간장] 멸치 육수 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"유부는 기름기를 제거하기 위해 끓는 물에 데쳐서 사용하는 것이 좋다.\",\"instructions\":[\"1. 유부는 윗면을 살짝 잘라 내고 입을 벌려 주머니를 만든 뒤 끓는 물에 데쳐 냉수에 헹구고 미나리는 잎을 떼고 데쳐 냉수에 헹군다.\",\"2. 두부는 면보에 물기를 짠 뒤 곱게 으깨고 닭고기는 껍질을 제거하여 곱게 다진다.\",\"3. 양파와 당근, 불린 표고버섯은 곱게 채썰고 시금치는 끓는 물에 데쳐 물기를 짜고 2cm 길이로 썬다.\",\"4. 볼에 2, 3을 담고 소금, 흰 후춧가루, 깨소금과 참기름을 넣고 양념하여 만두소를 만든다.\",\"5. 준비한 유부주머니에 만두소를 넣고 미나리로 묶어 김 오른 찜통에 10분 정도 찐다.\",\"6. 초간장을 곁들여 낸다.\"]},{\"id\":\"k771\",\"title\":\"펜네 파스타 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053614_1416213374492.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/929-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/929-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/929-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/929-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/929-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/929-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"펜넬파스타 40g\",\"청피망 10g\",\"홍피망 10g\",\"양파 10g\",\"완두콩 5g\",\"블랙올리브 2g\",\"아스파라거스 2g\",\"토마토콩카세 15g\",\"파마산치즈 4g\",\"소금적당량 [바질 페스토] 잣 2g\",\"올리브오일 2g\",\"바질 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파스타는 국수와 달리 전분량이 많지 않기 때문에 찬물에 헹구지 말고 물기를 빼서 그대로 식혀 사용한다.\",\"instructions\":[\"1. 펜네 파스타를 끓는 소금물에 기름을 약간 넣고 10분정도 삶아 체에 밭쳐 물기를 뺀다.\",\"2. 청피망, 홍피망, 양파는 펜네 파스타 길이로 썰고, 완두콩은 끓는 물에 데쳐서 찬물에 헹군 뒤 물기를 뺀다.\",\"3. 아스파라거스도 펜네 파스타 길이로 썰어 끓는 소금물에 데쳐 찬물에 식힌 뒤 물기를 뺀다.\",\"4. 블랙올리브를 링 형태로 썬다.\",\"5. 볼에 1과 바질 페스토, 소금을 넣고 섞는다.\",\"6. 5와 나머지 야채들을 같이 섞어 접시에 담는다.\"]},{\"id\":\"k772\",\"title\":\"해산물 옥수수 오븐구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053615_1416213375835.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/930-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/930-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/930-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/930-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/930-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/930-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 30g\",\"새우 5g\",\"바지락 3g\",\"도미살 5g\",\"슬라이스 햄 3g\",\"실파 2g\",\"토마토 10g\",\"애호박 25g\",\"캔 옥수수 20g\",\"슬라이스 치즈 8g\",\"홍고추 1g\",\"바질 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"달걀을 스크램블할 때에는 낮은 온도에서 서서히 익혀야 부드러운 질감을 얻을 수 있다.\",\"instructions\":[\"1. 새우는 껍질과 내장을 제거하고 바지락은 살짝 데쳐 입이 열리면 살을 발라낸다.\",\"2. 해산물은 0.5cm 크기로 썰고 실파는 송송 썬다.\",\"3. 토마토는 껍질을 벗겨 햄과 비슷한 크기로 썰고 바질은 굵게 채썬다.\",\"4. 팬에 올리브오일은 두르고 햄, 옥수수를 넣어 볶다가 풀어둔 달걀을 넣고 스크램블을 만든다.\",\"5. 4가 반 정도 익었을 때 해산물, 토마토, 바질을 넣고 홍고추로 장식하고 다 익으면 오븐용 용기에 담는다.\",\"6. 5에 치즈를 0.5cm 넓이로 잘라 격자로 올리고 오븐에서 굽는다.\"]},{\"id\":\"k773\",\"title\":\"향향 볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053616_1416213376974.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/931-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/931-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/931-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/931-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/931-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/931-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 10g\",\"오이 10g\",\"목이버섯 5g\",\"닭고기 15g\",\"닭 육수 10g\",\"밥 50g\",\"파 9g\",\"식물성기름 1g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"목이버섯 대신 다른 버섯을 이용해도 된다.\",\"instructions\":[\"1. 닭고기를 깍둑썰기한다.\",\"2. 감자, 오이는 깍둑썰기 하고 목이버섯은 물에 불린다.\",\"3. 기름을 두른 팬에 1을 넣고 볶다가 닭 육수를 넣는다.\",\"4. 닭고기가 익으면 감자, 목이버섯을 넣고 끓인 뒤 건진다.\",\"5. 깨끗한 팬에 기름을 두르고 밥과 송송 썬 파를 넣고 볶는다.\",\"6. 5에 오이와 익힌 닭고기, 목이버섯, 소금을 넣어 볶는다.\"]},{\"id\":\"k774\",\"title\":\"흑임자 두부국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053618_1416213378582.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/932-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/932-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/932-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/932-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/932-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/932-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"불린 쌀 30g\",\"으깬 두부 35g\",\"검은 깨 5g\",\"물 90g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"검은깨 간 것을 체에 걸러내면 더 고운 죽을 만들 수 있다.\",\"instructions\":[\"1. 쌀을 씻어 불린 뒤 믹서나 절구에 넣고 곱게 간다.\",\"2. 두부를 곱게 으깬다.\",\"3. 검은깨를 물에 넣어 돌맹이가 없도록 거른다.\",\"4. 3의 물기를 빼고 볶은 뒤 동량의 물을 넣고 곱게 간다.\",\"5. 냄비에 쌀과 두부, 적당량의 물을 넣고 센불에서 끓인다.\",\"6. 불을 줄여 쌀이 퍼지면 2의 검은깨를 넣고 더 끓여 소금으로 간한다.\"]},{\"id\":\"k775\",\"title\":\"과일 요구르트 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053621_1416213381018.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/934-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/934-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/934-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/934-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/934-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/934-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"멜론 30g\",\"사과 30g\",\"바나나 20g\",\"오렌지 30g\",\"플레인 요구르트 30g\",\"레몬주스 5g\",\"오렌지주스 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다양한 계절과를 활용하자\",\"instructions\":[\"1. 메론의 껍질을 벗기고 2cm 정도의 주사위모양으로 썬다.\",\"2. 사과는 껍질을 벗기고 메론과 같은 크기로 썬다.\",\"3. 바나나도 껍질을 벗기고 같은 크기로 썬다.\",\"4. 오렌지는 칼로 껍질을 도려내고 속살만 자른다.\",\"5. 플레인 요구르트와 레몬주스, 오렌지주스를 섞어 드레싱을 만든다.\",\"6. 볼에 과일을 한데 섞고 드래싱으로 버무려 완성한다.\"]},{\"id\":\"k776\",\"title\":\"단호박 스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053621_1416213381846.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/935-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/935-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/935-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/935-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/935-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/935-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"버터 2g\",\"마늘 1g\",\"양파 10g\",\"샐러리 5g\",\"생강 1g\",\"닭육수 100g\",\"단호박 50g\",\"고구마 15g\",\"우유 10g\",\"라임주스 1g\",\"생크림 5g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라임주스는 기호에 따라 생략해도 된다.\",\"instructions\":[\"1. 냄비에 버터를 녹인 후 마늘, 양파, 셀러리, 생강을 넣고 볶는다.\",\"2. 양파와 셀러리가 부드러워지면 닭육수를 넣는다.\",\"3. 2에 단호박, 고구마를 넣고 단호박이 부드러워질 때까지 약한불로 끓인다.\",\"4. 단호박이 다 익으면 믹서에 부드러운 상태가 되도록 간다.\",\"5. 4를 다시 냄비에 넣고 중간불로 끓인다.\",\"6. 5에 우유, 라임주스, 소금, 후추, 크림을 넣어 마무리한다.\"]},{\"id\":\"k777\",\"title\":\"새우 완자탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053623_1416213383797.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/937-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/937-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/937-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/937-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/937-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/937-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우 살 40g\",\"달걀흰자 5g\",\"전분 4g\",\"당면불린것 10g\",\"팽이버섯 10g\",\"부추 5g\",\"홍고추 3g\",\"다시마육수 70g\",\"국간장 1g\",\"마늘다진것 2g\",\"소금적당량\",\"흰 후춧가루 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우 대신 흰살생선으로 만들어도 가능하다.\",\"instructions\":[\"1. 곱게 다진 새우살에 소금, 흰 후춧가루로 밑간한다.\",\"2. 1에 달걀흰자, 전분을 넣어 치댄후 지름 2cm 정도의 완자를 만든다.\",\"3. 불린 당면, 팽이버섯, 부추는 5cm 길이로 자르고 홍고추는 2cm 길이로 채썬다.\",\"4. 냄비에 다시마 육수를 넣어 끓으면 2의 완자를 넣고 불을 줄인다.\",\"5. 완자가 떠오르면 불린 당면, 팽이버섯, 부추, 홍고추 순으로 넣는다.\",\"6. 다진마늘, 국간장, 소금으로 간한다.\"]},{\"id\":\"k778\",\"title\":\"생강향의 고구마 크로켓\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053625_1416213385372.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/938-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/938-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/938-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/938-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/938-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/938-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 60g\",\"생강 2g\",\"생크림 3g\",\"버터 2g\",\"꿀 2g\",\"밀가루 3g\",\"달걀물 5g\",\"빵가루 3g\",\"튀김기름 8g\",\"소금적당량\",\"후추적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오븐이 없으면 뜨거운 팬에서 고구마의 수분을 제거하도록 한다.\",\"instructions\":[\"1. 고구마를 삶아 껍질을 제거하고 오븐에 넣어 수분을 제거한다.\",\"2. 생강을 편으로 썰어 생크림과 섞어 생강향이 우러나도록 살짝 끓인 후 체에 거른다.\",\"3. 볼에 1을 넣고 으깬다.\",\"4. 3에 2를 넣고 골고루 섞어준다.\",\"5. 버터, 꿀, 소금, 후추를 넣어 맛을 내고 원하는 모양으로 빚는다.\",\"6. 5에 밀가루, 달걀물, 빵가루 순으로 묻혀 180℃ 기름에 튀긴다.\"]},{\"id\":\"k779\",\"title\":\"알파벳 스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053626_1416213386512.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/939-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/939-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/939-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/939-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/939-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/939-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파 1cm 정사각형 14g\",\"샐러리 1cm 정사각형 7g\",\"당근 1cm 정사각형 7g\",\"마늘다진것 1g\",\"식용유 1g\",\"닭육수 150g\",\"후추적당량\",\"소금적당량\",\"월계수잎\",\"알파벳파스타 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"알파벳 파스타를 넣고 지나치게 오래 가열하면 파스타 모양이 파괴될 수 있으므로 주의한다.\",\"instructions\":[\"1. 냄비에 기름을 두르고 중간불로 열을 가열한다.\",\"2. 1에 양파, 셀러리, 당근을 넣고 색이 나지 않도록 부드러워 질 때까지 볶는다.\",\"3. 야채가 익을 때 쯤 마늘을 넣고 볶는다.\",\"4. 3에 닭육수, 후추, 월계수잎을 넣고 끓인다.\",\"5. 중간불로 줄이고 35분 정도 은근하게 끓인다.\",\"6. 여기에 알파벳 파스타를 넣고 약 10분간 저어주며 끓인다.\"]},{\"id\":\"k780\",\"title\":\"야채 과일 돌구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053627_1416213387667.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/940-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/940-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/940-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/940-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/940-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/940-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 30g\",\"고구마 30g\",\"오렌지 30g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"조직이 단단한 과일과 야채를 사용하는 것이 적당하다. 된장소스:된장, 설탕, 참께, 참기름, 땅콩버터를 섞어 만든다. 참깨소스:식초, 땅콩버터, 깨소금, 설탕을 섞어 만든다.\",\"instructions\":[\"1. 냄비 전체에 작은 돌을 깔고 돌이 뜨거워질 때까지 불에 올려놓는다.\",\"2. 단호박, 고구마, 오렌지를 0.5cm 두께로 자른다.\",\"3. 2의 표면에 소금을 살짝 뿌린다.\",\"4. 뜨거워진 돌 위에 3을 올린다.\",\"5. 뚜껑을 닫고 약한 불에서 속이 익을 때 까지 굽는다.\",\"6. 소금, 된장소스, 참깨소스 등 취향에 맞는 소스를 골라 찍어 먹는다.\"]},{\"id\":\"k781\",\"title\":\"야채볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053629_1416213389072.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/941-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/941-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/941-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/941-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/941-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/941-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 20g\",\"양송이버섯 15g\",\"당근 15g\",\"건목이버섯 5g\",\"산마 10g\",\"참기름 1g\",\"물전분 6g\",\"육수 6g\",\"식용유 2g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 당근과 감자를 2cm 주사위모양으로 자르고 버섯은 4등분한다.\",\"2. 산마를 끓는 물에 데친다.\",\"3. 기름을 두른 팬을 가열한 후 당근, 감자, 데친 마를 넣고 볶은 뒤 육수를 넣는다\",\"4. 육수가 끓으면 양송이버섯과 목이버섯을 넣고 소금으로 간한다.\",\"5. 물 전분을 넣어 농도를 맞춘다.\",\"6. 참기름을 넣어 향을 낸다.\"]},{\"id\":\"k782\",\"title\":\"야채빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053630_1416213390212.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/942-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/942-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/942-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/942-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/942-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/942-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀가루 30g\",\"베이킹파우더 1g\",\"버터 2g\",\"달걀 12g\",\"설탕 5g\",\"당근 10g\",\"양파 10g\",\"캔옥수수 10g\",\"완두콩 10g\",\"우유 10g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 밀가루와 베이킹파우더를 섞어 체에 내린다.\",\"2. 녹인 버터에 달걀, 소금, 설탕을 넣고 1을 넣어 골고루 섞는다.\",\"3. 당근, 양파는 0.5cm 주사위모양으로 썰어 데친다.\",\"4. 옥수수, 완두콩을 물에 헹군다.\",\"5. 2에 당근, 양파, 옥수수, 완두콩, 우유를 넣고 섞는다.\",\"6. 모양 틀에 넣어 김이 오른 찜통에서 10분간 찐다.\"]},{\"id\":\"k783\",\"title\":\"영양 달걀찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053631_1416213391320.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/943-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/943-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/943-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/943-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/943-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/943-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"죽순 5g\",\"밤 5g\",\"찐 어묵 5g\",\"건표고버섯 3g\",\"은행 5g\",\"새우 5g\",\"잣 1g\",\"달걀 20g\",\"쑥갓 1g\",\"멸치 육수 50g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"찜통이 없는 경우 냄비에 중탕을 하도록 한다.\",\"instructions\":[\"1. 죽순은 빗살을 살려 썰고 밤은 껍질을 벗겨 4등분한다.\",\"2. 찐 어묵은 얇게 썰고 표고버섯은 미지근한 물에 불려 어슷하게 4등분 한다.\",\"3. 볼에 달걀 풀고 달걀 부피의 2.5배의 멸치 육수를 넣고 소금으로 간을 한 뒤 거품기로 잘 풀어 체에 내린다.\",\"4. 끓는 물에 은행, 죽순, 밤, 새우 순으로 데친다.\",\"5. 데쳐 낸 은행은 껍질을 벗기고 새우는 머리와 껍질을 제거한다.\",\"6. 찜 용기에 준비한 속 재료들을 담고 준비한 달걀 물을 부어 찜통에서 약 12분간 찐다.\"]},{\"id\":\"k784\",\"title\":\"유부 달걀찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053632_1416213392616.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/944-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/944-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/944-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/944-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/944-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/944-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"유부 8g\",\"달걀 30g\",\"당근 7g\",\"멸치 육수 50g\",\"간장 3g\",\"설탕 2g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"달걀 노른자의 형태가 유지되도록 주의한다.\",\"instructions\":[\"1. 유부는 윗면을 잘라 내고 입을 벌려서 주머니를 만든다.\",\"2. 1을 끓는 물에 데친 뒤 냉수에 헹군다.\",\"3. 달걀을 그릇에 풀고 다진 당근과 소금을 넣고 섞는다.\",\"4. 2에 3을 넣어 꼬지로 주름을 잡아 끝부분을 마무리한다.\",\"5. 냄비에 멸치 육수와 간장, 설탕, 소금을 넣는다.\",\"6. 5에 4를 넣어 10분정도 끓인다.\"]},{\"id\":\"k785\",\"title\":\"찰 어묵찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053634_1416213394771.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/945-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/945-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/945-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/945-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/945-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/945-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찰어묵 50g\",\"새우살 20g\",\"전분 5g 양념 마늘다진것 2g\",\"참기름 1g\",\"깨소금 1g\",\"청주 1g\",\"소금적당량\",\"후추 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"여러종류의 어묵이 있으므로 이를 활용하여 다양한 메뉴를 만들어 보자\",\"instructions\":[\"1. 찰어묵을 2cm 두께로 썬 후 가운데 칼집을 넣는다.\",\"2. 새우살을 입자있게 다진다.\",\"3. 2에 양념재료를 넣고 잘 버무린다\",\"4. 찰어묵의 칼집 사이에 전분을 묻힌다.\",\"5. 칼집 사이에 3를 끼워 넣는다.\",\"6. 김이 오른 찜통에 10분간 찐다.\"]},{\"id\":\"k786\",\"title\":\"유부 우엉 잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035029_1554792629494.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035109_1554792669874.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035124_1554792684076.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035138_1554792698990.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035323_1554792803242.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035344_1554792824527.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035412_1554792852277.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"우엉 20g\",\"유부 6g\",\"양파 10g\",\"당근 10g\",\"올리브유 5g\",\"올리고당 6g\",\"간장 5g\",\"설탕 0.5g\",\"참깨 0.5g\",\"참기름 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"섬유소가 풍부한 우엉이 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 우엉을 깨끗이 씻어 채 썬다.\",\"2. 양파와 당근을 채 썬다.\",\"3. 간장과 양념들을 넣고 채 썬 우엉을 졸인다.\",\"4. 3이 80% 정도 졸았을 대 채 썬 양파와 당근을 넣는다.\",\"5. 거의 다 졸여지면 채 썬 유부를 넣는다.\",\"6. 참깨를 뿌려 마무리한다.\"]},{\"id\":\"k787\",\"title\":\"치즈두부샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050413_1554797053629.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050451_1554797091852.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050514_1554797114758.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050544_1554797144440.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050607_1554797167204.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050630_1554797190258.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050652_1554797212730.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"까망베르치즈 8g\",\"두부 25g\",\"새싹채소 5g\",\"아몬드슬라이스 1g\",\"유자청 6g\",\"식초 1g\",\"레몬즙 2g\",\"올리브유 3g\",\"저염간장 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스에 소량의 저염간장을 첨가하고 치즈 자체의 짠맛으로 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 유자청을 잘게 다진 뒤 저염간장, 식초, 올리브유, 레몬즙을 섞어 드레싱을 만든다.\",\"2. 두부는 2cm 크기로 깍둑썰기 한다.\",\"3. 까망베르치즈도 깍둑썰기 한다.\",\"4. 새싹채소는 세척 후 건져 물기를 제거한다.\",\"5. 그릇에 새싹채소를 담고 두부, 치즈를 얹는다.\",\"6. 드레싱과 아몬드를 뿌린다.\"]},{\"id\":\"k788\",\"title\":\"된장숙성저수분수육\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313105128_1584064288421.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313105606_1584064566814.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313105622_1584064582123.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313110500_1584065100167.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313111201_1584065521105.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313111213_1584065533975.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313111230_1584065550759.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"앞다리살 돈육(보쌈용) 100g\",\"양파 40g\",\"대파 20g\",\"저염된장 4g\",\"통후추 1g\",\"월계수잎 1g\",\"생강가루 2g\",\"다진마늘 4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"채소 자체의 수분으로 익혀 재료 본연의 맛을 살리고 염분 사용을 줄였어요.\",\"instructions\":[\"1. 돼지고기 앞다리 살에 칼집을 낸다.\",\"2. 돼지고기에 된장, 생강가루, 다진마늘, 통후추, 월계수잎을 입혀 숙성시킨다.\",\"3. 파와 대파는 큼지막하게 썰어 준비한다.\",\"4. 냄비 혹은 오븐용기의 밑 부분에 양파와 대파를 놓아준다.\",\"5. ④에 숙성시킨 돼지고기를 올려 약 50분 정도 가열하여 완전히 익혀준다.\",\"6. 0.5cm 두께로 썰어서 제공한다.\"]},{\"id\":\"k789\",\"title\":\"스마일오이피클\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054408_1611823448289.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054439_1611823479386.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054452_1611823492918.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054508_1611823508719.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054522_1611823522219.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054535_1611823535170.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054549_1611823549441.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오이 80g\",\"배 50g\",\"홍피망 5g\",\"청피망 5g\",\"노랑파프리카 5g\",\"식초 3g\",\"설탕 6g\",\"물 100ml\",\"피클링스파이스 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"피클의 새콤달콤한 맛과 신선한 야채로 저염 피클을 만들 수 있어요.\",\"instructions\":[\"1. 오이를 3등분하여 속을 파낸다.\",\"2. 피망 및 파프리카는 U모양으로 휘어지게 썰어준다.\",\"3. 배를 채 썰어 준다.\",\"4. 오이 중앙에 파프리카와 배를 채워 넣는다.\",\"5. 물, 식초, 설탕, 피클링 스파이스를 넣어 피클물을 만든다.\",\"6. ④에 피클물을 넣고 30분 정도 숙성시킨다.\"]},{\"id\":\"k790\",\"title\":\"참나물 소보로덮밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052952_1615192192726.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308053301_1615192381240.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308053318_1615192398267.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308053334_1615192414868.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308053349_1615192429833.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308053402_1615192442489.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308053420_1615192460093.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"건취나물(10g)\",\"건표고버섯(20g)\",\"불린 쌀(80g)\",\"불린 곤약쌀(60g)\",\"다진 돼지고기(20g)\",\"달걀(1개)\",\"참나물(10g)\",\"간장(7g)\",\"참기름(3g)\",\"소금(1g)\",\"식용유(3㎖)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"참나물은 베타카로틴과 칼륨이 많은 식재료예요.\",\"instructions\":[\"1. 건취나물과 건표고버섯은 뜨거운 물(200㎖)에 담가 30분간 불린다.\",\"2. 밥솥에 불린 쌀과 곤약쌀, 불린 건취나물, 물(100㎖)을 넣어 취사 버튼을 눌러 밥을 짓는다.\",\"3. 불린 표고버섯은 잘게 다져 중간 불로 달군 팬에 넣고 다진 돼지고기, 간장(5g), 참기름(2g)을 넣어 3분간 볶아 꺼낸다.\",\"4. 중간 불로 달군 다른 팬에 식용유(3㎖)를 두른 뒤 달걀을 넣어 스크램블드에그를 만든다.\",\"5. 끓는 물(300㎖)에 참나물을 넣고 1분간 데쳐 찬물에 헹군 뒤 소금(1g), 간장(2g), 참기름(1g)을 넣어 버무린다.\",\"6. 그릇에 취나물 곤약밥을 담은 뒤 볶은 버섯과 고기, 스크램블드에그, 양념한 참나물을 얹는다.\"]},{\"id\":\"k791\",\"title\":\"버섯초계탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9544\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr96_L\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr971Y\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr975h\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97AN\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97DC\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97Fo\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 닭(1마리)\",\"양파(1개)\",\"대파(1대)\",\"미나리(½줌)\",\"새송이버섯(3개)\",\"팽이버섯(1봉)\",\"마늘(6쪽)\",\"양송이버섯(4개)\",\"달걀(1개)\",\"전분(0.7Ts)\",\"간장(0.5Ts)\",\"소금(0.3ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•양파, 대파, 미나리가 들어간 육수로 자극적이지 않은 맛을 냈어요.\",\"instructions\":[\"1. 닭은 깨끗하게 씻어 준비하고, 양파와 대파는 4등분한다.\",\"2. 새송이버섯은 모양대로 두툼하게 썰고, 팽이버섯은 밑동을 자른 뒤 낱낱이 가르고, 미나리는 한입 크기로 썬다.\",\"3. 냄비에 닭을 넣고 잠길 만큼 물을 붓고, 양파, 대파, 미나리(½분량), 마늘을 넣어 센 불로 올린 뒤 닭이 익을 때까지 끓인다.\",\"4. 닭, 양파, 미나리를 건져내 한 김 식히고, 닭은 살을 발라낸다.\",\"5. 닭고기, 양파, 남은 미나리, 달걀, 전분을 고루 섞어 닭볼을 만든다.\",\"6. 육수에 닭볼, 새송이버섯, 팽이버섯, 양송이버섯, 남은 미나리를 넣고, 양념으로 간한 뒤 한소끔 끓여 마무리한다.\"]},{\"id\":\"k792\",\"title\":\"사과채소타코\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9afz\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GZ0\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GaG\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GdV\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Gge\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GjT\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GkX\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양상추(2장)\",\"사과(½개)\",\"토르티야(4장)\",\"슈레드 모차렐라치즈(약간)\",\"양파(⅛개)\",\"파프리카(⅛개)\",\"토마토(½개)\",\"할라피뇨 피클(4개)\",\"스리라차 소스(1Ts)\",\"스테비아(0.5Ts)\",\"아보카도(½개)\",\"살사소스(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 아보카도, 토마토는 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 양상추는 채 썰고, 사과는 모양대로 얇게 썰고, 양파, 파프리카, 토마토, 할라피뇨 피클은 잘게 다진다.\",\"2. 다진 양파, 파프리카, 토마토, 할라피뇨 피클에 나머지 살사소스 재료를 넣어 고루 섞는다.\",\"3. 아보카도는 씨와 껍질을 제거하고, 골고루 으깬 뒤 나머지 과카몰레 재료와 고루 섞는다.\",\"4. 갈릭요거트소스를 만든다.\",\"5. 약한 불로 달군 마른 팬에 토르티야를 올려 1~2분간 구워 꺼내고, 맥주잔에 감아 모양을 잡는다.\",\"6. 토르티야에 채 썬 양상추, 사과, 슈레드 모차렐라치즈를 올리고 살사소스, 과카몰레, 갈릭요거트소스를 곁들여 마무리한다.\"]},{\"id\":\"k793\",\"title\":\"코코넛 수플레 치즈케이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020062651_1760952411936.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020063430_1760952870284.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020063446_1760952886477.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020063502_1760952902541.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020063548_1760952948975.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020063612_1760952972450.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020063633_1760952993602.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 크림치즈 90g\",\"무염버터 15g\",\"코코넛우유 50ml\",\"달걀노른자 70g\",\"박력 밀가루 5g\",\"옥수수전분 10g\",\"머 랭 > 달걀흰자 130g\",\"레몬즙 1g\",\"알룰로스 가루 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"코코넛우유, 무염버터를 사용하여 심심한 맛을 보완하고 나트륨과 당류 사용량을 줄였어요.\",\"instructions\":[\"1. 볼에 크림치즈, 무염버터,\\n코코넛우유를 넣고 중탕하며 부드럽게\\n될 때까지 섞는다. 중탕물에서 내려\\n달걀노른자를 섞는다.\",\"2. ①에 박력 밀가루, 옥수수전분을\\n체 쳐서 넣고 섞은 후 고운체로\\n한 번 더 거른다.\",\"3. 달걀흰자에 레몬즙을 넣고 휘핑한다.\\n알룰로스 가루를 1/3씩 넣으며 섞어\\n약간 단단한 머랭을 만든다.\",\"4. ②에 머랭을 1/3씩 넣고 섞어 반죽을\\n만든다. 케이크 틀에 유산지를 깔고\\n반죽을 넣는다.\",\"5. 큰 팬에 뜨거운 물을 붓고 케이크\\n틀을 올려 중탕하여 150°C로 예열한\\n오븐에서 30분 동안 굽는다.\",\"6. 케이크 틀에서 꺼내 유산지를 제거하고\\n마무리한다.\"]},{\"id\":\"k794\",\"title\":\"세 가지 맛 공기과자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105712_1761184632944.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110533_1761185133824.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110553_1761185153709.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110609_1761185169430.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110636_1761185196719.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110653_1761185213184.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023110708_1761185228178.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 검은콩 20g\",\"단호박 70g\",\"비트 70g\",\"달걀흰자 120g\",\"설탕 10g\",\"달걀노른자 20g\",\"박력 밀가루 24g\",\"허브가루 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"검은콩, 단호박, 비트 등 천연재료의 단맛을 활용하여 당류 사용량을 줄였어요.\",\"instructions\":[\"1. 냄비에 검은콩을 넣고 20분 동안 삶아\\n체에 거르고 으깨어 검은콩 퓨레를\\n만든다.\",\"2. 달걀흰자에 설탕을 넣으며 단단한\\n머랭을 만든다. 달걀노른자,\\n박력 밀가루를 머랭에 넣고 자르듯이\\n섞어 머랭 반죽을 만든다.\",\"3. 퓨레에 머랭 반죽을 나누어 섞어 3가지\\n반죽을 만든다.\",\"4. 종이컵에 각각의 반죽을 2/3 정도\\n넣고, 전자레인지에 50~55초 동안\\n굽는다.\",\"5. 10분 동안 식혀 종이컵에서 분리한다\",\"6. 모양을 내어 자른 후 허브가루를\\n뿌리고 접시에 담아 마무리한다.\"]},{\"id\":\"k795\",\"title\":\"케첩 완자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053636_1416213396022.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/946-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/946-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/946-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/946-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/946-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/946-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지목살다진것 50g\",\"청경채 20g\",\"케첩 10g\",\"파다진것 5g\",\"생강다진것 5g\",\"전분 5g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"완자의 모양이 부서지지 않도록 하려면 완자가 담겼는 모양이 부서지지 않도록 완자가 담겨져 있는 그릇에 미지근한 물을 넣어둔다.\",\"instructions\":[\"1. 그릇에 다진고기, 파, 생강, 소금, 물 전분을 넣어 골고루 버무린 뒤 케첩을 넣는다.\",\"2. 1을 한 방향으로 치댄 뒤 고기에 양념이 베도록 둔다.\",\"3. 청경채는 1cm 정사각형 모양으로 썬다.\",\"4. 2에 끈기가 생기도록 다시 치대준 뒤 지름 1.5cm의 완자 모양으로 빚는다.\",\"5. 팬에 물을 넣고 끓으면 완자를 넣어 익힌다.\",\"6. 청경채를 넣고 살짝 끓인 뒤 소금으로 간을 하고 소스가 약간 남도록 더 끓인다.\"]},{\"id\":\"k796\",\"title\":\"홍시 생밤 무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053637_1416213397131.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/947-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/947-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/947-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/947-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/947-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/947-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홍시 40g\",\"바나나 40g\",\"생밤 10g\",\"대추 5g\",\"호두 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"아이의 약한 이에 무리를 주지 않도록 생밤의 크기는 너무 크지 않도록 주의한다.\",\"instructions\":[\"1. 홍시는 껍질을 제거하여 으깬다.\",\"2. 바나나는 체에 내린다.\",\"3. 1과 2를 잘 섞어준다.\",\"4. 생밤은 납작납작하게 썬다.\",\"5. 대추는 돌려 깎아 씨를 제거하고 채 썬다.\",\"6. 3과 4, 5를 잘 무쳐 그릇에 담는다.\"]},{\"id\":\"k797\",\"title\":\"고구마 경단\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053638_1416213398255.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/948-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/948-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/948-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/948-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/948-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/948-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 50g\",\"카스텔라 20g\",\"우유 5g\",\"버터 2g\",\"꿀 3g\",\"건포도 20g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마는 밤고구마를 선택하는 것이 반죽의 농도를 조절하기 좋다.\",\"instructions\":[\"1. 고구마를 찜통에 찐다.\",\"2. 고구마의 껍질을 벗기고 체에 곱게 내린다.\",\"3. 카스텔라는 윗면의 갈색 부분을 잘라내고 믹서에 곱게 갈아 가루로 만든다.\",\"4. 2에 우유와 버터, 꿀, 소금을 넣고 섞어 반죽한다.\",\"5. 3의 반죽 속에 건포도를 1~2개 넣고 경단을 만든다.\",\"6. 경단에 카스텔라 가루를 묻힌다.\"]},{\"id\":\"k798\",\"title\":\"두부 깻잎 과자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053639_1416213399348.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/949-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/949-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/949-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/949-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/949-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/949-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 30g\",\"깻잎 10g\",\"밀가루박력분 10g\",\"베이킹파우더 2g\",\"설탕 10g\",\"달걀 20g\",\"검은깨 3g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 두부는 면보를 이용해 물기를 꼭 짠 후 곱게 으깬다.\",\"2. 밀가루와 베이킹파우더를 섞어 체에 내린다.\",\"3. 으깬 두부를 볼에 담고 설탕, 달걀, 검은깨를 넣고 거품기로 잘 저어준다.\",\"4. 3에 채 썬 깻잎을 넣은 뒤 2의 밀가루를 넣어 반죽한다.\",\"5. 도마에 밀가루를 살짝 뿌리고 4를 밀대로 2mm 두께로 민 뒤 너비 1cm, 길이 4cm의 직사각형으로 자른다.\",\"6. 자른 반죽을 오븐팬에 올려 180℃로 예열된 오븐에 10분간 굽는다.\"]},{\"id\":\"k799\",\"title\":\"두부양갱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053640_1416213400394.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/950-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/950-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/950-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/950-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/950-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/950-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"치자 2g\",\"백련초가루 1g\",\"두부 30g\",\"한천 2g\",\"설탕 10g\",\"물 40g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"한천은 사용하기 전에 미지근한 물에 불려서 사용하는 것이 좋다.\",\"instructions\":[\"1. 치자를 따뜻한 물에 담궈 색을 우려내고, 백련초가루는 물에 푼다.\",\"2. 두부는 면보에 물기를 짠 뒤 칼로 으깬다.\",\"3. 두 개의 냄비에 한천을 필요량 만큼 넣고 1을 각각 넣고 30분 정도 불린다.\",\"4. 3에 으깬 두부를 반씩 나누어 넣고 설탕을 넣은 뒤 골고루 섞는다.\",\"5. 4를 모양 틀에 넣고 냉장고에서 굳힌다.\",\"6. 양갱이 굳으면 틀 째 미지근한 물에 담궈 뒤집어 뺸다.\"]},{\"id\":\"k800\",\"title\":\"멸치 누룽지과자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053641_1416213401737.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/951-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/951-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/951-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/951-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/951-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/951-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 70g\",\"잔멸치 20g\",\"통깨 5g\",\"설탕 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 잔멸치는 잡티를 제거하고 기름을 두르지 않은 팬에서 살짝 볶는다.\",\"2. 고슬고슬하게 지은 밥에 1과 통깨, 설탕을 넣고 골고루 섞는다.\",\"3. 사각 틀에 2를 넣고 랩을 씌워 밀대로 평평하게 민다.\",\"4. 3을 바람이 잘 통하는 곳에서 건조 시킨다.\",\"5. 175℃로 예열된 오븐에 4를 넣고 밥이 바삭해질 때 까지 굽는다.\",\"6. 먹기 좋은 크기로 부숴 접시에 담고 설탕을 뿌린다.\"]},{\"id\":\"k801\",\"title\":\"복숭아 화채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053642_1416213402814.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/952-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/952-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/952-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/952-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/952-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/952-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오미자 5g\",\"천도복숭아 30g\",\"배 10g\",\"설탕 10g\",\"물 45g\",\"잣 1g 설탕시럼 설탕과 물을 동량으로 하여 중불에서 서서히 녹인다. 기호에 맞게 만든다.\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오미자는 분이 나고 잘 마른것을 구매한다.\",\"instructions\":[\"1. 오미자에 7배의 물에 8시간 담궈 맛과 색이 우러나도록 한다.\",\"2. 천도복숭아는 사방 0.5cm의 주사위모양으로 썰어 설탕을 뿌려 30분 정도 절인다.\",\"3. 배를 모양 틀로 찍어 0.3cm 두께로 썰어 설탕에 절인다.\",\"4. 오미자 국물을 면보에 거르고 시럽으로 단맛을 맞춘다.\",\"5. 4에 복숭아와 배를 넣는다.\",\"6. 5에 잣과 얼음을 띄운다.\"]},{\"id\":\"k802\",\"title\":\"사과 포도주스 조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053643_1416213403845.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/953-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/953-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/953-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/953-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/953-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/953-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과 60g\",\"포도주스 60g\",\"계피가루 2g\",\"아이스크림 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과는 물이 많고 조직이 단단한 것을 사용한다.\",\"instructions\":[\"1. 사과씨를 통째로 제거한다.\",\"2. 1을 2cm 두께로 썬다.\",\"3. 냄비에 사과와 포도주스를 넣고 중불에서 서서히 졸인다.\",\"4. 졸여진 사과를 냉장고에 넣어 시원하게 한다.\",\"5. 접시에 사과를 담고 계피가루를 뿌린다.\",\"6. 5에 아이스크림을 떠서 위에 얹는다.\"]},{\"id\":\"k803\",\"title\":\"홍시 쉐이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053645_1416213405140.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/954-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/954-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/954-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/954-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/954-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/954-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"냉동홍시 70g\",\"오미자 5g\",\"물 35g\",\"레몬즙 4g\",\"꿀 5g\",\"민트 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오미자는 실온에서 우리는 것이 좋으며 유리나 사기그릇에서 우려낸다.\",\"instructions\":[\"1. 냉동 홍시의 껍질을 벗기고 씨를 뺀다.\",\"2. 1을 잘게 자른다.\",\"3. 오미자를 7배의 물에 8시간 이상 우려 맛과 색이 우러나오도록 한다.\",\"4. 믹서에 홍시, 오미자물, 꿀, 레몬즙을 넣어 함께 갈아준다.\",\"5. 4를 컵에 담는다.\",\"6. 민트로 장식한다.\"]},{\"id\":\"k804\",\"title\":\"김치떡\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053647_1416213407139.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/956-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/956-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/956-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/956-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/956-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/956-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"메밀가루 20g\",\"찹쌀가루 20g\",\"밀가루 20g\",\"물 20g\",\"소금적당량 [소재료] 김치 20g\",\"오징어 30g [양념] 설탕 5g\",\"깨소금 1g\",\"파다진것 4g\",\"마늘다진것 3g\",\"참기름 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치를 익힐 때 다양한 야채를 넣어 섭취하도록 한다.\",\"instructions\":[\"1. 메밀가루, 밀가루, 찹쌀가루에 소금을 넣어 체에 내린 뒤 끓는 물을 넣어 익반죽한다.\",\"2. 김치는 송송 썰고 오징어는 껍질을 벗겨 굵게 다진다.\",\"3. 가열된 팬에 기름을 두르고 김치를 볶은 다음 오징어를 넣고 볶아 식힌다.\",\"4. 반죽을 떼어 10cm 둥근 모양으로 빚은 다음 가운데에 3을 넣고 반달모양으로 접어 모양을 만든다.\",\"5. 김이 오른 찜통에 면보를 깔고 14분간 찐 다음 5분 정도 뜸을 들인다.\",\"6. 한 김 식힌 뒤 접시에 담아낸다.\"]},{\"id\":\"k805\",\"title\":\"누룽지 피자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053649_1416213409310.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/958-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/958-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/958-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/958-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/958-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/958-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"잡곡밥흑미 검은콩 50g\",\"피자치즈 20g\",\"양파 10g\",\"청 피망 8g\",\"홍 피망 8g\",\"양송이 10g\",\"햄 5g\",\"캔옥수수 10g\",\"실파 5g[피자소스] 마늘다진것 2g\",\"양파다진것 5g\",\"쇠고기다진것 5g\",\"토마토케첩 8g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"물의 양도 밥알이 서로 떨어질 정도로만 넣어준다.\",\"instructions\":[\"1. 잡곡밥에 소량의 물을 넣고 밥알을 풀어준다.\",\"2. 기름을 두르지 않은 팬에 1을 0.4cm두께로 노릇하게 양면을 굽는다.\",\"3. 양파와 청, 홍피망, 햄은 적당한 크기로 썰고 캔 옥수수는 물기를 뺀다.\",\"4. 냄비에 식용유를 두르고 다진 마늘과 다진 양파, 다진 소고기를 넣고 볶은 뒤 토마토 케첩과 물을 약간 넣어 졸이면서 설탕, 간장, 후춧가루로 간한다.\",\"5. 누룽지에 4를 골고루 펴 바르고 그 위에 토핑 재료, 피자치즈, 송송 썬 실파를 뿌린다.\",\"6. 5번을 예열된 오븐에 굽는다.\"]},{\"id\":\"k806\",\"title\":\"단호박 새우찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053650_1416213410481.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/959-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/959-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/959-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/959-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/959-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/959-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박작은것 125g\",\"잔새우살다진것 20g\",\"두부 20g\",\"건표고버섯 10g\",\"청피망다진것 10g\",\"홍피망다진것 10g\",\"실파 5g\",\"밀가루 8g\",\"마늘 3g\",\"깨소금 1g\",\"참기름 1g\",\"소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박 속에 쌀과 견과류를 함께 넣어 만들어도 좋다.\",\"instructions\":[\"1. 단호박은 표면을 깨끗하게 씻어 물기를 제거하고 꼭지 부분의 윗면을 자르고 수저로 속을 파낸 후 소금을 뿌려 놓는다.\",\"2. 새우살은 다지고 두부는 면보로 싸서 물기를 제거하고 곱게 으깨고 불린 건표고버섯과 청, 홍피망은 곱게 다지고 실파는 송송 썬다.\",\"3. 2의 재료를 한 데 섞고 소금, 다진 마늘, 깨소금, 참기름, 흰 후춧가루를 넣고 양념하여 소를 만든다.\",\"4. 1의 내부에 수분을 제거한다.\",\"5. 4의 안쪽에 밀가루를 살짝 뿌리고 밀가루가 골고루 잘 묻도록 한다.\",\"6. 준비된 소를 채운 후 잘라둔 꼭지 부분의 뚜껑을 덮어 김 오른 찜통에 20분가량 찐 뒤 4~6등분 하여 낸다.\"]},{\"id\":\"k807\",\"title\":\"두부 샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053651_1416213411605.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/960-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/960-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/960-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/960-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/960-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/960-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 80g\",\"키위 20g\",\"오렌지 20g\",\"토마토 20g\",\"바나나 20g\",\"사과 20g\",\"꿀 10g\",\"소금적당량\",\"식용유 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부는 가능하면 단단한 것을 구입한다.\",\"instructions\":[\"1. 두부는 3cm 주사위모양으로 썰고 소금을 뿌려 간을 한다.\",\"2. 과일은 5mm 주사위모양으로 썬 뒤 꿀을 넣고 버무린다.\",\"3. 기름을 두른 팬에 1을 넣고 5면을 노릇하게 지진 뒤 종이타월로 기름기를 제거한다.\",\"4. 3의 지지지 않은 한 쪽 면을 숟가락을 이용해 뚫리지 않게 조심스럼게 파낸다.\",\"5. 속을 파낸 두부에 2를 채워 넣는다.\",\"6. 민트로 장식한다\"]},{\"id\":\"k808\",\"title\":\"라이스페이퍼 새우롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053652_1416213412573.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/961-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/961-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/961-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/961-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/961-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/961-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우 20g\",\"홍피망 5g\",\"팽이버섯 5g\",\"숙주 15g\",\"무순 3g\",\"상추 5g\",\"차이브 5g\",\"쌀국수가는것 15g\",\"라이스페이퍼 20g[새콤 달콤 소스] 양파 5g\",\"마늘 1g\",\"홍고추 1g\",\"청고추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"모든 재료를 준비 하여 아이들에게 롤을 말도록 하는 것도 재미를 주는 방법이다.\",\"instructions\":[\"1. 새우는 끓는 물에 대친 뒤 찬물에 담궈 식히고 껍질을 벗긴다.\",\"2. 홍피망은 얇게 채 썰고 팽이버섯은 밑동을 잘라 준비하고 숙주는 거두절미하여 끓는 물에 데친 뒤 찬물에 식혀서 물기를 빼고 상추는 채 썬다.\",\"3. 쌀국수를 물에 불렸다가 끓는 물에 데친 뒤 찬물에 식혀 물기를 제거한다.\",\"4. 따뜻한 물에 라이스페이퍼를 담궜다가 꺼내 면보 위에 놓고 물기를 살짝 제거하고 1, 2, 3을 올리고 조심스럽게 말아준다.\",\"5. 마늘은 다지고 양파, 홍고추, 청고추는 0.3mm로 잘게 썬다.\",\"6. 팬에 고추기름을 두르고 다진 마늘을 볶다가 양파를 넣고 청, 홍고추를 넣어 살짝 볶은 뒤 물, 식초, 설탕을 넣고 물전분으로 농도를 맞춘다.\"]},{\"id\":\"k809\",\"title\":\"레몬, 파슬리 빵가루를 입힌 도미\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053653_1416213413557.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/962-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/962-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/962-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/962-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/962-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/962-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"도미 40g\",\"마늘다진것 2g\",\"빵가루 10g\",\"버터 1g\",\"레몬주스 3g\",\"레몬제스트 2g\",\"파슬리다진것 2g\",\"소금적당량\",\"후추적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"제스트:레몬, 오렌지 등의 껍질을 가늘게 잘라 다진 것을 말한다.\",\"instructions\":[\"1. 도미에는 소금과 후추로 밑간을 하고 마늘, 파슬리는 다진다.\",\"2. 버터를 두른 팬에 다진 마늘을 넣고 마늘 향을 낸 버터물을 만든다.\",\"3. 2에 빵가루를 섞어 믹싱볼로 옮겨 담는다.\",\"4. 3에 다진 파슬리, 레몬주스, 레몬제스트, 소금, 후추를 넣고 고무주걱으로 잘 섞는다.\",\"5. 도미를 양념하고 도미위에 4을 얹는다.\",\"6. 5를 오븐에 굽는다.\"]},{\"id\":\"k810\",\"title\":\"롤피자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053655_1416213415836.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/964-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/964-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/964-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/964-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/964-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/964-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밀가루중력분 80g\",\"이스트 2g\",\"따뜻한물 20g\",\"소금 1g\",\"올리브오일 1g\",\"청피망 10g\",\"홍피망 10g\",\"베이컨 5g\",\"양파 10g\",\"양송이 5g\",\"토마토소스 5g\",\"모짜렐라 치즈 12g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"피자 반죽을 발효시키기 어려울 때에는 또띠아나 바게트 빵을 이용해도 좋다.\",\"instructions\":[\"1. 볼에 밀가루를 담고 가운데에 웅덩이를 만들어 따뜻한 물과 이스트를 넣어 녹인 후 소금을 넣고 밀가루를 조금씩 섞으며 반죽을 한다.\",\"2. 반죽이 하나로 뭉쳐지면 랩으로 싸서 따뜻한 곳에서 30분 정도 발효시킨다.\",\"3. 발효된 반죽을 밀대를 이용하여 넓게 편다.\",\"4. 청, 홍피망은 꼭지부분을 썰어내고 링 모양으로 썰어 심지를 제거하고 베이컨, 양파, 양송이는 슬라이스 한다.\",\"5. 3을 오븐용 팬에 옮긴 뒤 토마토소스를 바르고 준비된 재료들과 피자치즈를 올린다.\",\"6. 반죽을 말아서 윗부분에 칼집을 넣은 뒤 175℃로 예열된 오븐에 굽는다.\"]},{\"id\":\"k811\",\"title\":\"닭곰탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031431_1678083271333.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031512_1678083312934.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031545_1678083345384.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031606_1678083366956.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031629_1678083389828.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031646_1678083406084.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031705_1678083425528.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 닭 정육(90g)\",\"대파(10g)\",\"무(70g)\",\"양파(20g)\",\"홍고추(5g)\",\"마늘(3g)\",\"청양고추(5g)\",\"•육수재료 : 닭뼈(200g)\",\"다시마(3g)\",\"대파(5g)\",\"마늘(2g)\",\"물(600g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•닭뼈와 채소로 진하게 육수를 만들어 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 닭정육과 닭뼈를 깨끗이 씻어 물, 마늘, 대파, 다시마를 넣고 육수를 끓인다.\",\"2. 닭 정육이 익으면 건져 잘게 찢는다.\",\"3. 무는 나박썰기하고 대파와 홍고추, 청양고추는 어슷썰기 하고 양파와 마늘은 다진다.\",\"4. 육수가 우러나면 체에 육수를 걸러낸다.\",\"5. 냄비에 마늘을 볶다가 닭고기를 넣고 함께 볶은 뒤 육수와 손질한 채소를 넣어 푹 끓인다.\",\"6. 후추로 간을 해 마무리한다.\"]},{\"id\":\"k812\",\"title\":\"미나리버섯고기말이&산채소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010600_1584072360556.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010624_1584072384126.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010641_1584072401819.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010841_1584072521978.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010854_1584072534740.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010908_1584072548412.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010923_1584072563077.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돈등심 80g\",\"새송이버섯 24g\",\"미나리 18g\",\"후추 0.3g\",\"찹쌀가루 15g\",\"참나물 5g\",\"취나물 5g\",\"올리브오일 10g\",\"땅콩 2g\",\"파마산치즈 1g\",\"마늘 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"산채소스에 소금 대신 파마산치즈로 간을 했어요.\",\"instructions\":[\"1. 돈등심은 널찍하게 성형한다.\",\"2. 새송이 버섯은 길게 채썰고, 미나리도 비슷한 사이즈로 썰어 준다.\",\"3. 고기에 미나리, 새송이를 감싸 말아 찹쌀가루를 묻혀 굽는다.\",\"4. 참나물, 취나물, 올리브오일, 땅콩, 마늘, 후추를 믹서에 갈아 소스를 만든다.\",\"5. 소스에 파마산 치즈를 섞어준다.\",\"6. 구워진 고기에 소스를 곁들여 낸다.\"]},{\"id\":\"k813\",\"title\":\"오이파프리카새콤무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054738_1611823658692.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054807_1611823687977.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054820_1611823700226.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054835_1611823715831.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054847_1611823727434.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054900_1611823740996.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054913_1611823753087.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오이 10g\",\"파프리카(빨강/노랑) 각 5g\",\"식초 2g\",\"설탕 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"절이는 과정이 없는 생채류로 염분 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 오이는 굵은 소금으로 문질러 깨끗이 씻는다.\",\"2. 오이를 적당한 두께로 썰고 4등분 한다.\",\"3. 파프리카는 깨끗이 씻은 후 씨를 제거한다.\",\"4. 파프리카를 적당한 크기로 썬다.\",\"5. 식초, 설탕, 물을 섞어 단촛물을 만든다.\",\"6. 단촛물에 오이, 파프리카를 버무린다.\"]},{\"id\":\"k814\",\"title\":\"양상추샐러드 & 과일드레싱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093629_1678322189909.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093710_1678322230252.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093729_1678322249387.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093744_1678322264726.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093804_1678322284599.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093823_1678322303857.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093844_1678322324340.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 양상추(60g)\",\"당근(10g)\",\"적양배추(10g)\",\"치커리(5g)\",\"•소스 : 사과(20g)\",\"파인애플(15g)\",\"레몬즙(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•나트륨 함량이 높은 시판 드레싱 대신 수제 드레싱을 곁들였어요.\",\"instructions\":[\"1. 양상추는 깨끗이 씻어 먹기 좋은 크기로 썬다.\",\"2. 당근과 적양배추는 곱게 채 썰고, 치커리는 잘게 썬다.\",\"3. 사과는 껍질과 심을 제거한 뒤 한입 크기로 썬다.\",\"4. 파인애플은 껍질과 심을 제거한 뒤 한입 크기로 썬다.\",\"5. 손질한 과일과 레몬즙을 믹서에 넣어 곱게 갈아 드레싱을 만든다.\",\"6. 양상추와 당근, 적양배추를 접시에 깔고 드레싱을 곁들여 마무리한다.\"]},{\"id\":\"k815\",\"title\":\"시금치들깨무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102439_1611883479294.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102234_1611883354676.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102250_1611883370481.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102302_1611883382002.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102315_1611883395132.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102327_1611883407007.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102338_1611883418881.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"시금치 70g\",\"파 5g\",\"마늘 5g\",\"들깨가루 15g\",\"통깨 5g\",\"들기름 5g\",\"소금(데치는용) 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시금치나물 양념에 들깨가루, 들기름을 넣어 소금의 사용을 줄였어요.\",\"instructions\":[\"1. 파, 마늘은 다진다.\",\"2. 냄비에 물과 소금을 넣고 끓인다.\",\"3. 세척한 시금치를 데친다.\",\"4. 데친 시금치는 찬물에 헹구어 물기를 짠 다음 먹기 좋게 썬다.\",\"5. 시금치에 들깨가루, 파, 마늘, 통깨, 들기름을 넣고 무친다.\",\"6. 접시에 담아서 완성한다.\"]},{\"id\":\"k816\",\"title\":\"채소롤초밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97hb\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9E2s\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9E4x\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Et_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9EwQ\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Ez8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9F0W\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 가지(1개)\",\"오이(1개)\",\"밥(400g)\",\"소금(0.4ts)\",\"다시마가루(2Ts)\",\"매실식초(2ts)\",\"참기름(2Ts)\",\"참깨(2Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•소금 대신 다시마가루를 사용하여 나트륨 섭취를 줄이고 감칠맛을 더했어요.\",\"instructions\":[\"1. 가지와 오이는 세로로 얇게 썬다.\",\"2. 얇게 썬 오이는 소금(0.2ts)에 10분간 절인 뒤 물기를 꼭 짠다.\",\"3. 얇게 썬 가지는 약한 불로 달군 마른 팬에 올려 앞뒤로 노릇하게 구워 꺼낸다.\",\"4. 밥에 남은 양념을 넣어 고루 섞는다.\",\"5. 소금에 절인 오이와 구운 가지 위에 밥을 한입 크기로 뭉쳐 올린다.\",\"6. 돌돌 말아 그릇에 담아 마무리한다.\"]},{\"id\":\"k817\",\"title\":\"초코바나나 두부크림빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251021/20251021023032_1761024632600.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020070345_1760954625476.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020070510_1760954710138.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020070529_1760954729835.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020070547_1760954747984.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020070606_1760954766532.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020070625_1760954785625.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 박력 쌀가루 56g\",\"강력 밀가루 140g\",\"무가당 코코아가루① 8g\",\"드라이 이스트 16g\",\"소금 4g\",\"설탕 8g\",\"물 115ml\",\"바닐라 에센스 30g\",\"달걀 16g\",\"무염버터 22g\",\"두부크림 > 바나나 98g\",\"두부 33g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부는 크림 식감을 위해 찌개용을 사용하면 더 좋아요.\",\"instructions\":[\"1. 볼에 박력 쌀가루, 강력 밀가루, 무가당\\n코코아가루①, 드라이 이스트, 소금,\\n설탕, 물, 바닐라 에센스, 달걀을 넣고\\n섞다가 무염버터를 넣으며\\n한 덩어리가 될 때까지 반죽한 후\\n상온에서 30분 동안 1차 발효한다.\",\"2. 믹서에 바나나, 물기를 제거한 두부,\\n무가당 코코아가루②, 알룰로스를 넣고\\n큰 덩어리가 없어질 정도로 살짝 갈아\\n두부크림을 만든다.\",\"3. 반죽을 40g씩 분할하여 둥굴리기한 후\\n상온에서 15분 동안 중간 발효한다.\",\"4. 반죽을 성형하여\\n오븐 팬에 올리고 30°C에서\\n20분 동안 2차 발효한다.\",\"5. 달걀물을 바르고 175°C로 예열한\\n오븐에 12분 동안 구운 후 꺼내\\n완전히 식힌다.\",\"6. 두부크림을 짤주머니에 담아 40g씩\\n빵 속에 채우고 무염버터를 발라\\n마무리한다.\"]},{\"id\":\"k818\",\"title\":\"미니 떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053656_1416213416929.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/965-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/965-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/965-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/965-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/965-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/965-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기샄코기 80g\",\"새송이버섯 40g\",\"밀가루 4g\",\"잣가루 1g<br /> [떡갈비 양념] 간장 5g\",\"배즙 5g\",\"양파즙 5g\",\"꿀 4g\",\"다진 파 5g\",\"다진 마늘 3g\",\"깨소금 1g\",\"참기름 1g\",\"후춧가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"잣가루는 반드시 종이나 종이타월을 깔고 다져 보슬보슬하게 사용하여야 한다.\",\"instructions\":[\"1. 소고기는 곱게 다진다.\",\"2. 다진 소고기에 떡갈비 양념을 넣고 골고루 치대 양념한다.\",\"3. 새송이버섯은 폭 1.5cm, 길이 6cm로 썰어 밀가루를 묻힌다.\",\"4. 3에 2를 버섯 위, 아래로 1cm를 남기고 감싸듯이 부쳐 떡갈비를 만든다.\",\"5. 팬에 앞뒤로 타지 않도록 굽는다.\",\"6. 잣가루를 뿌린다.\"]},{\"id\":\"k819\",\"title\":\"배추 달걀볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053658_1416213418057.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/966-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/966-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/966-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/966-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/966-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/966-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추 50g\",\"달걀 30g\",\"돼지고기 20g\",\"파 3g\",\"생강다진것 2g\",\"간장 2g\",\"목이버섯 10g\",\"닭육수 10g\",\"물전분 10g\",\"식용유 3g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 배추는 잎을 떼서 크게 썬 다음 3cm 길이로 결대로 찢는다.\",\"2. 기름을 넣어 가열 된 팬에 배추를 넣고 살짝 볶아 낸 후 수분을 제거한다.\",\"3. 달걀을 풀어 팬에 익힌다.\",\"4. 채 썬 돼지고기를 팬에 볶고 파, 다진 생강, 간장을 넣고 다시 볶는다.\",\"5. 4에 목이버섯, 배추, 달걀을 넣고 잘 섞는다.\",\"6. 5에 육수, 소금, 물전분을 넣는다.\"]},{\"id\":\"k820\",\"title\":\"사과와 양파를 곁들인 돼지등심 요리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053658_1416213418883.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/967-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/967-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/967-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/967-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/967-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/967-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심 100g\",\"오레가노마른것 1g\",\"바질마른것 1g\",\"올리브오일 1g\",\"양파 15g\",\"사과 20g\",\"소금적당량\",\"통후추부순것 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"돼지고기는 종이타월을 이용하여 핏물을 제거한 후 사용하면 냄새가 적고 맛이 좋다.\",\"instructions\":[\"1. 돼지등심은 4cm 정도 두께로 썬다.\",\"2. 볼에 건오레가노, 건바질, 소금, 통후추 간 것을 섞어 허브 믹스를 만들어 1에 골고루 묻힌다.\",\"3. 팬을 가열하여 올리브오일을 두르고 등심의 양면이 갈색이 되게 구운 뒤 알루미늄 호일에 싸서 오븐에서 완전히 익힌다.\",\"4. 양파는 슬라이스하고, 사과는 껍질과 씨를 제거한 후 얇게 슬라이스 한다.\",\"5.  또 다른 팬에 기름을 두르고 고기가 완전히 익을 동안 양파와 사과를 옅은 갈색이 나도록 볶아준다.\",\"6. 고기가 다 익었으면 꺼내서 적당한 두께로 썰고 볶은 양파와 사과를 곁들인다.\"]},{\"id\":\"k821\",\"title\":\"새우 속을 채운 리치와 감자튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053700_1416213420967.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/969-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/969-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/969-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/969-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/969-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/969-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우 60g\",\"달걀흰자 10g\",\"실파 5g\",\"물밤다진것 15g\",\"소금적당량\",\"후추적당량\",\"리치캔 35g\",\"감자 30g\",\"전분 3g\",\"튀김기름 10g [소스] 올ㄹ브오일 1g\",\"다진 양파 3g\",\"다진생강 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"물밤과 리치는 통조림을 사용할 수 있다.\",\"instructions\":[\"1. 새우는 잘게 다지고 흰자, 소금, 후추와 함께 섞어서 간이 배도록 한다.\",\"2. 다진 물밤과 실파를 1과 섞어준 뒤 종이타월을 이용해서 물기를 제거한 리치의 속의 채운다.\",\"3. 속이 채워진 리치에 전분을 묻혀 기름에 튀긴다.\",\"4. 가열된 팬에 올리브오일을 두르고 양파, 마늘, 생강 다진 것을 살짝 볶는다.\",\"5. 4에 물, 고추기름, 설탕, 소금, 후춧가루를 넣고 간을 한 뒤 물전분으로 농도를 맞춘다.\",\"6. 감자는 껍질을 벗겨 채칼로 얇게 슬라이스 한 뒤 물에 담궈 전분을 빼고 튀겨 접시에 깔고 3, 4를 담는다.\"]},{\"id\":\"k822\",\"title\":\"생선살 완자 찹쌀 찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053702_1416213422390.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/970-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/970-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/970-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/970-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/970-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/970-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀 30g\",\"치자 5g\",\"시금치 10g\",\"당근 10g\",\"흰살생선 100g [흰 살생선 양념] 달걀흰자 15g\",\"생강즙 2g\",\"소금적당량\",\"흰후춧가루 적당량\",\"전분 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치자가 없으면 사용하지 않거나 혹은 야채를 갈아서 함께 넣어 색을 이용할 수 있다.\",\"instructions\":[\"1. 찹쌀을 깨끗이 씻어 40분 가량 치차 물에 불린 뒤 물기를 빼고 소금을 약간 넣어 버무리고 마른 면보로 옮겨 수분을 빼면서 반 정도 으깬다.\",\"2. 시금치는 소금물에 데쳐 냉수에 헹군 뒤 물기를 짜서 다지고 당근도 잘게 다진다.\",\"3. 흰 살 생선은 면보로 물기를 꼭 짠 다음 곱게 다지고 끈기가 생기도록 치대면서 생강즙, 소금, 후춧가루를 넣는다.\",\"4. 3에 달걀 흰자, 전분을 첨가하여 계속 치대 끈기가 생기도록 한 뒤 다져놓은 시금치와 당근을 넣어 섞는다.\",\"5. 4를 조금씩 떼어 생선 완자를 만든 뒤 1을 묻힌다.\",\"6. 찜통에 젖은 면보를 깔고 생선 완자가 서로 붙지 않도록 놓고 20분 정도 찐다.\"]},{\"id\":\"k823\",\"title\":\"서양식 씨리얼(뮤즐리)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053704_1416213424592.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/972-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/972-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/972-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/972-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/972-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/972-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오트밀 15g\",\"꿀 5g\",\"플레인 요거트 18g\",\"아몬드 5g\",\"사과 8g\",\"건포도 4g\",\"우유 30g\",\"계피가루적당량\",\"바나나 10g\",\"키위 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"꿀대신 기능성 당류인 올리고당을 이용하면 칼로리를 줄이고 장내 유산균을 증가시킬 수 있다.\",\"instructions\":[\"1. 아몬드는 기름 두르지 않은 팬에 옅은 갈색이 나도록 볶는다.\",\"2. 사과는 껍질을 제거하고 주사위모양으로 썬다.\",\"3. 바나나와 키위는 껍질을 제거하고 사과와 같은 크기로 썬다.\",\"4. 볼에 꿀, 플레인 요거트, 우유를 넣고 잘 섞는다.\",\"5. 깨끗한 볼에 오트밀을 담고 4를 넣어 잘 섞어준다.\",\"6. 5에 준비된 과일과 아몬드, 건포도를 올리고 기호에 따라 계피가루를 뿌린다.\"]},{\"id\":\"k824\",\"title\":\"수퍼 브리또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053705_1416213425545.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/973-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/973-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/973-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/973-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/973-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/973-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파 10g\",\"할라피뇨 3g\",\"쇠고기갈은것 10g\",\"토마토콩카세 10g\",\"양상추 10g\",\"올리브오일 1g\",\"또띠아8인치 30g\",\"아보카도 6g\",\"사워크림 3g\",\"소금적당량\",\"후춧가루 적당량[강낭콩 퓨레]강낭콩 40g\",\"베이컨 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"할라피뇨는 병조림된 것을 구매하거나 청양고추로 대체한다.\",\"instructions\":[\"1. 양파, 할라피뇨는 잘게 다지고 토마토는 끓는 물에 데쳐 껍질과 씨를 제거하고 잘게 썰어 볶다가 간 소고기를 넣고 소금, 후추로 간한다.\",\"2. 베이컨, 마늘, 양파는 잘게 썰고 강낭콩은 체에 받쳐 물기를 제거한다.\",\"3. 팬에 베이컨을 볶아 기름을 제거하고 2의 마늘, 양파를 볶다가 강낭콩을 넣고 건바질 조금, 소금, 후추로 간을 한 뒤 믹서에 갈아 퓨레로 만든다.\",\"4. 배, 오렌지를 1cm 주사위모양으로 썰고 레몬주스, 파프리카 가루와 섞어 살사를 만든다.\",\"5. 기름 없는 팬에 또띠아를 살짝 구운 뒤 강낭콩 퓨레를 얇게 바르고 볶은 소기기, 채 썬 양상추, 아보카도, 베이컨, 토마토, 사워크림을 넣고 만다.\",\"6. 5에 배, 오렌지 살사를 곁들인다.\"]},{\"id\":\"k825\",\"title\":\"아보카도 달걀 샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053706_1416213426888.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/974-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/974-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/974-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/974-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/974-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/974-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 20g\",\"마요네즈 1g\",\"디존 머스타드 1g\",\"레몬주스 2g\",\"식빵 35g\",\"아보카도 6g\",\"워터크레스 1g\",\"소금 약간\",\"후추 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"아보카도는 껍질을 벗겨 반을 자른 후 가운데 씨에 칼집을 넣어 90도 방향으로 돌리면 씨를 제거할 수 있다.\",\"instructions\":[\"1. 달걀을 완숙으로 삶아 찬물에 담궈 식혀 껍질을 벗긴 뒤 볼에 넣어 포크로 거칠게 으깬다.\",\"2. 으깬 달걀에 머스타드, 레몬주스, 소금, 후춧가루, 마요네즈를 섞는다.\",\"3. 아보카도는 껍질을 제거하고 얇게 슬라이스 한다.\",\"4. 식빵은 노릇하게 양면을 굽는다.\",\"5. 4에 아보카도를 얹고 그 위에 달걀 샐러드를 얹어 식빵으로 덮는다.\",\"6. 샌드위치의 가장자리 부분은 잘라내고 원하는 적당한 크기로 자른다.\"]},{\"id\":\"k826\",\"title\":\"알록달록 시금치 당근 수제비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053708_1416213428059.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/975-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/975-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/975-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/975-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/975-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/975-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"시금치 10g\",\"당근 15g\",\"밀가루 50g\",\"물 10g\",\"감자 10g\",\"애호박 15g\",\"실파 5g\",\"멸치육수 200g\",\"다진 마늘 2g\",\"간장 2g\",\"소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"부드러운 반죽을 원하는 경우에는 수제비 반죽을 더 묽게 해서 주걱에 놓고 잘라서 만든다.\",\"instructions\":[\"1. 시금치와 당근은 각각 믹서에 물을 넣고 간다.\",\"2. 밀가루는 반으로 나눠 시금치 즙과 당근 즙을 넣고 소금을 넣어 각각 반죽 한다.\",\"3. 2의 반죽을 직경 1.5cm 정도의 동그란 경단모양으로 빚는다.\",\"4. 감자와 애호박은 1.5cm 주사위모양으로 자르고 실파는 2cm 길이로 썬다.\",\"5. 멸치 육수에 감자, 수제비 경단, 애호박, 다진마늘, 실파 순서로 넣고 끓인다.\",\"6. 5에 간장과 소금으로 간한다.\"]},{\"id\":\"k827\",\"title\":\"인도식만두구이(사모사)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053710_1416213430154.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/977-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/977-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/977-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/977-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/977-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/977-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파다진것 15g\",\"마늘다진것 2g\",\"생강다진것 1g\",\"청고추다진것 1g\",\"새우다진것 25g\",\"버터 1g\",\"레몬주수 1g\",\"생선육수 3g\",\"카레가루 2g\",\"토마토페이스트 3g\",\"달걀물 5g\",\"춘권피 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"전통적인 방법은 감자를 삶아 으깨어 피로 사용한다.\",\"instructions\":[\"1. 양파, 마늘, 생강, 고추, 새우를 다진다.\",\"2. 버터를 두른 팬에 양파, 생강, 마늘, 고추, 카레가루 순으로 볶는다.\",\"3. 2에 토마토페이스트, 레몬즙, 새우를 넣고 볶는다.\",\"4. 3에 육수를 약간 붓고 약한 불로 끓이면서 수분을 증발시킨 뒤 볼에 담아 식힌다.\",\"5. 춘권피에 4를 적당히 넣고 끝부분에 달걀물을 발라 붙여 완성한다.\",\"6. 겉면에 올리브 오일을 약간 발라 오븐 팬에 놓고 170℃ 오븐에서 바삭하게 굽는다.\"]},{\"id\":\"k828\",\"title\":\"중국식 바비큐 폭립\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053712_1416213432496.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/979-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/979-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/979-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/979-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/979-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/979-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지갈비(바비큐용) 120g [소스] 양파작게자른것 20g\",\"마늘다진것 4g\",\"식용유 1g\",\"레드와인식초 2g\",\"황설탕 2g\",\"꿀 5g\",\"데미글라스 10g\",\"토마토케첩 2g\",\"머스타드 2g\",\"우스터소스 2g\",\"케이엔페퍼약간\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"돼지갈비는 찬물에 담가 여러번 핏물을 우려내어 사용한다.\",\"instructions\":[\"1. 소스재료를 볼에 넣고 잘 섞는다.\",\"2. 소스를 돼지갈비에 골고루 바른 뒤 6시간 이상 재운다.\",\"3. 재운 돼지갈비를 호일로 감싼다.\",\"4. 3을 170℃의 오븐에서 30분간 굽는다.\",\"5. 구운 돼지갈비의 호일을 벗긴다.\",\"6. 5의 갈비가 부드러워 질 때까지 약 30분간 소스를 골고루 발라가며 굽는다.\"]},{\"id\":\"k829\",\"title\":\"제주도 빙떡, 귤간장소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055351_1554454431397.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055507_1554454507606.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055525_1554454525900.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055539_1554454539480.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055555_1554454555679.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055610_1554454570754.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055623_1554454583606.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"메밀가루 50g\",\"무 30g\",\"후추 2g\",\"다시마 2g\",\"다진 마늘 5g\",\"다진 파 5g\",\"저염간장 5g\",\"통깨 2g\",\"귤 즙 10g\",\"참기름 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"메밀 자체의 고소한 맛과 무의 시원하고 달면서 매운맛으로 맛이 심심하지 않아요.\",\"instructions\":[\"1. 메밀가루에 물을 섞어 메밀 반죽을 만든다.\",\"2. 무를 채 썰어 다시마 육수에 삶는다.\",\"3. 다진 파, 마늘을 볶은 뒤 무와 통깨, 참기름과 섞어 버무린다.\",\"4. 전병을 부친 뒤 무를 넣어 만다.\",\"5. 귤 즙을 조린 뒤 저염간장을 넣고 섞는다.\",\"6. 접시에 담는다.\"]},{\"id\":\"k830\",\"title\":\"퓨전떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042347_1554794627002.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042454_1554794694442.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042513_1554794713780.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042540_1554794740636.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042555_1554794755373.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042613_1554794773000.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042627_1554794787570.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기 40g\",\"돼지고기 6g\",\"양파 15g\",\"배 10g\",\"마늘 5g\",\"생강 2g\",\"저염간장 3g\",\"찹쌀가루 5g\",\"참기름 2g\",\"참깨 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 저염간장을 사용해 나트륨을 줄였어요.\",\"instructions\":[\"1. 고기는 곱게 다지고 야채는 껍질을 제거한다.\",\"2. 배는 갈아 즙을 만들고 양파는 다진 뒤 기름을 두르지 않은 팬에 살짝 볶는다.\",\"3. 마늘과 생강을 곱게 다져 배즙과 섞은 뒤 다진 고기에 넣어 치댄다.\",\"4. 떡갈비 반죽에 저염간장, 참기름을 이용해 밑간을 하고 찹쌀가루를 넣어 찰기를 준다.\",\"5. 둥근 모양으로 빚은 뒤 중간을 살짝 눌러 기름을 두른 팬에 굽는다.\",\"6. 170℃ 오븐에 3분 정도 구워 속까지 익힌다.\"]},{\"id\":\"k831\",\"title\":\"마늘칩 감자샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050910_1554797350561.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050945_1554797385380.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050956_1554797396990.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051009_1554797409611.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051023_1554797423839.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051039_1554797439434.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051055_1554797455737.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 50g\",\"마늘 5g\",\"양파 5g\",\"마요네즈 10g\",\"플레인요거트 5g\",\"머스터드 1g\",\"설탕 2g\",\"파슬리 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"머스터드, 마요네즈, 플레인요거트를 이용한 드레싱으로 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 감자는 깨끗이 씻어 껍질째 한입 크기로 깍둑썰기 한 뒤 삶는다.\",\"2. 마늘은 얇게 편으로 썬다.\",\"3. 양파는 굵게 다진다.\",\"4. 팬에 식용유를 두르고 다진양파를 볶은 뒤 마늘은 바삭하게 굽는다.\",\"5. 마요네즈, 머스터드, 플레인요거트, 설탕을 섞어 드레싱을 만든다.\",\"6. 감자와 볶은 양파, 드레싱을 골고루 버무리고 마늘칩과 파슬리를 뿌린다.\"]},{\"id\":\"k832\",\"title\":\"시래기닭조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307043730_1678174650348.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307043826_1678174706548.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307043855_1678174735830.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307043910_1678174750474.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307043925_1678174765315.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307043946_1678174786376.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307044000_1678174800866.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 닭고기(120g)\",\"무(30g)\",\"당근(20g)\",\"양파(10g)\",\"홍고추(1g)\",\"청고추(1g)\",\"무청시래기(삶은 것\",\"80g)\",\"•양념 : 다진마늘(2g)\",\"후추(1g)\",\"저염간장(5g)\",\"설탕(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•고추를 활용해 매콤한 맛을 첨가하여 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 닭고기는 부위별로 토막 내어 끓는 물에 살짝 데친다.\",\"2. 데친 닭고기에 양념 재료를 섞어 30분 이상 재운다.\",\"3. 무, 당근, 양파는 사각 썰고, 고추는 송송 썬다.\",\"4. 무청시래기는 끓는 물에 한 번 더 살짝 데치고, 6cm 길이로 썬다.\",\"5. 냄비에 물(30g)과 닭고기, 시래기를 넣고, 청홍고추를 제외한 손질한 채소를 넣어 조린다.\",\"6. 홍고추와 청고추를 올려 마무리한다.\"]},{\"id\":\"k833\",\"title\":\"두부튀김&무소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023659_1584077819229.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023732_1584077852105.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023743_1584077863990.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023756_1584077876100.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023812_1584077892602.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023824_1584077904445.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023912_1584077952278.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 70g\",\"계란 20g\",\"깻잎 2.5g\",\"옥수수전분 10g\",\"식용유 10g\",\"혼다랑어가쓰오부시 1g\",\"무 10g\",\"레몬쥬스 2g\",\"2배 양조식초 1.5g\",\"저염간장 3g\",\"미향 6g\",\"설탕 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"가쓰오부시 국물을 이용하여 간장 사용을 줄였어요.\",\"instructions\":[\"1. 두부는 2cm의 정사각형으로 썰어 전분과 계란물을 무쳐 기름에 튀긴다.\",\"2. 무는 믹서기나 강판에 갈아준다.\",\"3. 끓는 물에 가쓰오부시를 살짝 넣었다 빼내어 국물을 우려낸다.\",\"4. 무와 가쓰오부시 국물에 설탕, 미향, 레몬즙, 식초, 저염간장을 넣고 섞어준다.\",\"5. 깻잎은 곱게 채를 쳐준다.\",\"6. 접시에 두부와 깻잎을 담고, 소스를 곁들여 낸다.\"]},{\"id\":\"k834\",\"title\":\"오징어튀김&딸기쨈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313052539_1584087939467.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313053452_1584088492597.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313053503_1584088503310.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313053514_1584088514732.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313053526_1584088526973.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313053537_1584088537565.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313053550_1584088550945.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어 35g\",\"밀가루 70g\",\"물 50g\",\"계란 32.5g 후추 0.1g\",\"식용유 500g\",\"딸기쨈 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"초간장 대신 딸기잼으로 소스를 대체했어요.\",\"instructions\":[\"1. 오징어를 먹기 좋은 크기로 썬다.\",\"2. 오징어를 살짝 데친 후 물기를 제거한다.\",\"3. 밀가루에 물, 계란, 후추를 넣어 튀김반죽을 만든다.\",\"4. 오징어에 튀김 반죽을 묻혀 식용유에 튀긴다.\",\"5. 키친타올에 올려 기름을 제거한다.\",\"6. 딸기잼과 같이 곁들여 낸다.\"]},{\"id\":\"k835\",\"title\":\"감귤콩샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055101_1611823861687.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055129_1611823889463.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055142_1611823902804.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055156_1611823916060.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055214_1611823934480.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055227_1611823947471.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055240_1611823960715.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감귤 20g\",\"완두콩 8g\",\"수수 4g\",\"율무 10g\",\"병아리콩 20g\",\"유자청 10g\",\"치커리 6g\",\"올리브오일 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"콩의 고소한 맛과 감귤의 단맛, 신맛으로 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 감귤은 껍질을 제거하고 알을 분리하여 반을 갈라 준다.\",\"2. 치커리는 한입크기로 썰어 준비한다.\",\"3. 완두콩, 수수, 율무, 병아리콩은 하루 전에 물에 불린 후 삶아준다.\",\"4. 삶은 콩은 체에 받쳐 물기를 제거한다.\",\"5. 손질한 재료를 모두 섞는다.\",\"6. 올리브오일과 유자청을 넣어 버무린다.\"]},{\"id\":\"k836\",\"title\":\"바질향이 향긋한 고구마 찰 바케트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042524_1611905124726.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042834_1611905314166.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042845_1611905325969.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042900_1611905340177.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042912_1611905352692.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042926_1611905366067.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042940_1611905380986.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 675g\",\"소금 6g\",\"생이스트 10g\",\"물 375ml(바게트반죽용)\",\"파인소프트 T 300g\",\"파인소프트 C 50g\",\"강력분 50g\",\"소금 8g\",\"분유 8g\",\"아몬드 분말 74g\",\"드라이 이스트(골드) 10g\",\"무염버터 54g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕을 따로 사용하지 않고 고구마 천연의 단맛을 살렸어요.\",\"instructions\":[\"1. 반죽을 모두 섞어 30분 발효 후 punch 후 40분 발효한다.\\n★punch는 가스를 빼는 과정을 얘기해요.\",\"2. 150g으로 분할 후 중간발효 20분을 한다.\",\"3. 찰 반죽 80g 분할 후 밀대로 얇게 펴서 크림치즈와 바질페스토를 섞은 속재료를 짜고 삶아 낸 고구마 다이스를 촘촘한 간격으로 올린 후 말아준다.\",\"4. 중간발효를 마친 바게트 반죽은 최대한 기공을 살려 조심히 펴 준다. 펴준 반죽 위에 찰 반죽을 놓고 가볍게 환목모양으로 말아준다.\",\"5. 반죽에 물을 뿌린 후 덧 가루를 묻혀 1시간 동안 2차 발효한다.\",\"6. 빵이 터지지 않게 꾸쁘는 사선으로 세 번 내고 , 195℃의 컨벡션 오븐에 16분 스팀 8초 설정을 하여 굽는다.\"]},{\"id\":\"k837\",\"title\":\"두유 크림 현미리소토\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308054626_1615193186794.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308060349_1615194229274.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308060412_1615194252072.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308060425_1615194265256.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308060440_1615194280139.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308060456_1615194296344.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308060511_1615194311102.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"손질된 고등어(60g)\",\"양파(10g)\",\"마늘(6g)\",\"양송이버섯(1개)\",\"청양고추(2g)\",\"깻잎(1g)\",\"불린 현미(150g)\",\"검은콩 두유(200㎖)\",\"달걀노른자(1개)\",\"다시마(2g)\",\"간장(5g)\",\"레몬즙(8g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"레몬, 깻잎 등 다양한 향신료를 사용하여 짠맛을 보완했어요.\",\"instructions\":[\"1. 냄비에 물(500㎖)과 다시마(2g)를 넣어 3분간 끓이고 다시마는 건져 육수를 만든다.\",\"2. 고등어는 에어프라이어에 넣어 180℃에서 10~15분간 굽는다.\",\"3. 양파와 마늘, 양송이버섯, 청양고추는 잘게 다지고, 깻잎은 얇게 채 썬다.\",\"4. 중간 불로 달군 팬에 식용유를 두른 뒤 다진 양파와 마늘, 양송이버섯, 간장을 넣어 2분간 볶은 뒤 불린 현미를 넣어 2분간 볶는다.\",\"5. 다시마 육수(250㎖)를 2~3번에 나눠 넣어 현미를 익히다가 검은콩 두유를 넣어 졸이고 레몬즙과 다진 청양고추를 넣어 고루 섞는다.\",\"6. 그릇에 현미 리소토를 담고 고등어구이 → 채 썬 깻잎 → 달걀노른자 순으로 올린다.\"]},{\"id\":\"k838\",\"title\":\"당근새우 카나페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98Eq\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FYp\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Faa\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Fc1\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Fer\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Fh8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FkA\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 칵테일새우(2마리)\",\"사과(½개)\",\"양파(⅓개)\",\"당근(¼개)\",\"바게트(2조각)\",\"다진 파슬리(0.5Ts)\",\"블루베리(6알)\",\"애플민트잎(6장)\",\"당근(⅓개)\",\"양파(⅓개)\",\"레몬(⅓개)\",\"후춧가루(3t)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•단맛을 가지고 있는 사과를 활용해 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 물(3컵)에 육수 재료와 칵테일새우를 넣어 새우가 익을 때까지 데친 뒤 건진다.\",\"2. 사과와 양파는 잘게 다지고, 당근은 길게 썬다.\",\"3. 다진 사과와 양파, 채 썬 당근, 후춧가루, 레몬즙, 식초, 올리브유를 넣어 고루 섞는다.\",\"4. 바게트 위에 버무린 재료를 올린다.\",\"5. 데친 새우를 올리고, 다진 파슬리와 후춧가루를 뿌린 뒤 블루베리를 올린다.\",\"6. 애플민트를 올려 마무리한다.\"]},{\"id\":\"k839\",\"title\":\"아보카도 수란샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9BMv\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9RN0\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9ROb\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9RQ2\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9RQl\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9RSG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 상추(3장)\",\"레몬(½개)\",\"아보카도(1개)\",\"토마토(1개)\",\"달걀(1개)\",\"파프리카(빨강\",\"노랑 각 ½개)\",\"소금(0.2ts)\",\"식초(0.5ts)\",\"소금(0.3ts)\",\"후춧가루(약간)\",\"바질가루(0.5t)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•상추, 토마토, 파프리카 등을 사용해 식감을 높였어요.\\n•향신료로 간을 맞추고 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 상추는 깨끗하게 씻어 한입 크기로 뜯고, 레몬은 모양대로 얇게 썰고, 아보카도는 씨와 껍질을 제거한 뒤 한입 크기로 썬다.\",\"2. 파프리카는 씨를 제거한 뒤 한입 크기로 썰고, 토마토는 한입 크기로 썬다.\",\"3. 끓는 소금물(물4컵+소금0.2ts)에 식초를 넣은 뒤 달걀을 넣고 수란을 만든다.\",\"4. 드레싱을 만든다.\",\"5. 그릇에 손질한 채소를 담고 수란과 얇게 썬 레몬을 올려 마무리한다.\"]},{\"id\":\"k840\",\"title\":\"참깨 오렌지 쇠고기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053713_1416213433793.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/980-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/980-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/980-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/980-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/980-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/980-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기사태 100g\",\"전분 2g\",\"간장 2g\",\"오렌지주스 10g\",\"굴소스 2g\",\"꿀 3g\",\"참깨 1g\",\"식용유 1g\",\"생강 1g\",\"오렌지 20g\",\"파인애플 28g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생파인애플을 육류에 익히지 않고 넣게 되면 육질이 지나치게 부드러워져 원치 않는 질감이 될 수 있어 익혀서 이용한다.\",\"instructions\":[\"1. 소고기는 길이 6cm, 넓이 2cm, 두께 0.5cm 정도의 직사각형 모양으로 썬 뒤 전분과 간장을 섞어 재운다.\",\"2. 생강은 다지고 오렌지는 껍질을 벗겨 속만 잘라내고 파인애플은 껍질과 속심을 제거하고 0.5cm 크기의 주사위모양으로 자른다.\",\"3. 오렌지주스, 굴소스, 꿀, 전분을 섞어 소스를 만든다.\",\"4. 기름을 두르지 않은 팬에 깨를 볶은 뒤 식히고 팬에 기름을 두르고 재운 소고기를 앞뒤로 골고루 익힌다.\",\"5. 4에 소스를 넣고 저어주면서 끓여 농도가 나기 시작하면 오렌지와 파인애플을 넣고 살짝 익힌다.\",\"6. 접시에 5를 담고 제공하기 직전에 깨를 뿌린다.\"]},{\"id\":\"k841\",\"title\":\"치킨 버거 스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053715_1416213435185.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/981-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/981-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/981-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/981-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/981-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/981-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 80g\",\"빵가루 5g\",\"차이브 2g\",\"바질 1g\",\"파슬리 1g\",\"소금적당량\",\"후추적당량[양송이 속양파다진것 10g\",\"버터적당량\",\"양송이 30g\",\"빵가루 5g\",\"생크림 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"스테이크로만 사용할 수도 있고 햄버거 패티로 이용할 수도 있다.\",\"instructions\":[\"1. 양파는 곱게 다지고 양송이는 0.5cm로 슬라이스 한다.\",\"2. 팬에 버터를 넣고 녹으면 양파를 볶다가 양송이를 넣어 볶는다.\",\"3. 생크림, 소금, 후추로 간을 하고 양송이에서 물이 빠져나오면 빵가루를 넣어 되직하게 농도를 맞춘 뒤 그릇에 옮겨 식힌다.\",\"4. 차이브, 오레가노, 바질, 파슬리를 잘게 다진다.\",\"5. 간 닭고기와 3, 4를 볼에 넣고 섞어 치대 찰지게 만든 뒤 지름 10cm 정도의 원형 모양이나 럭비공 모양으로 만든다.\",\"6. 팬에 기름을 두른 뒤 치킨 스테이크를 익혀주거나 팬에서 색만 내고 오븐에서 익힌다.\"]},{\"id\":\"k842\",\"title\":\"토마토소스 달걀볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053716_1416213436761.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/982-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/982-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/982-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/982-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/982-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/982-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 35g\",\"파 4g\",\"토마토소스 10g\",\"설탕 8g\",\"소금 적당량\",\"식물성기름 2g\",\"참기름 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토소스는 일반적으로 케첩을 이용하고 팬에 넣을 때 화력이나 기름의 온도가 너무 높으면 색이 변하므로 유의한다.\",\"instructions\":[\"1. 볼에 달걀을 푼다.\",\"2. 달군 팬에 1을 볶아 스크램블을 만든다.\",\"3. 파를 송송 썬다.\",\"4. 기름을 두른 팬에 3을 먼저 볶아 향을 낸 뒤 토마토소스를 넣고 볶는다.\",\"5. 4에 설탕, 소금, 2를 넣고 섞는다.\",\"6. 참기름을 뿌려 마무리한다.\"]},{\"id\":\"k843\",\"title\":\"낫토 시래기 라이스전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053720_1416213440499.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/985-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/985-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/985-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/985-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/985-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/985-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 40g\",\"양파다진것 10g\",\"당근다진것 5g\",\"낫토 15g\",\"시래기불린것 10g\",\"카레가루 3g\",\"파다진것 2g\",\"밀가루 5g\",\"달걀 10g\",\"식용유 적당량\",\"소금 적당량\",\"후춧가루 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"낫토 대신 청국장을 써도 무방하며 냄새를 싫어하면 냄새를 제거한 제품을 구매하여 사용한다.\",\"instructions\":[\"1. 양파와 당근은 잘게 다진다.\",\"2. 시래기는 불려 물기를 꼭 짜낸다.\",\"3. 2번의 시래기를 곱게 다진다.\",\"4. 뜨거운 밥에 1, 3을 넣는다.\",\"5. 4에 낫토, 카레가루, 다진 파를 넣고 골고루 섞는다.\",\"6. 5에 소금, 후춧가루로 간한다.\"]},{\"id\":\"k844\",\"title\":\"나스와 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053721_1416213441420.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/986-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/986-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/986-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/986-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/986-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/986-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 20g\",\"완두콩 5g\",\"오이 10g\",\"토마토 20g\",\"레드어니언 10g\",\"로메인 10g\",\"홍고추 2g\",\"블랙올리브 2g\",\"바질 1g\",\"캔참치 20g<strong>[드래싱]</strong> 올리브오일 2g\",\"레드와인식초 2g\",\"디존 머스타드 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"디존머스터드 대신 허니 머스터드로 대체해서 사용해도 좋다.\",\"instructions\":[\"1. 달걀은 완숙으로 삶아 껍질을 벗긴 뒤 세로로 4등분하고 완두콩은 끓는 물에 삶아 찬물에 헹군 뒤 물기를 제거한다.\",\"2. 오이는 1cm 주사위모양으로 썰고 양파는 링으로 슬라이스 하고 로메인은 먹기 좋게 뜯어 찬물에 담군다.\",\"3. 토마토는 달걀과 같은 모양으로 자르고 홍고추는 어슷하게 썰고 참치는 덩어리가 있게 기름기를 뺀다.\",\"4. 바질은 슬라이스하고 마늘은 다진다.\",\"5. 볼에 올리브오일과 레드와인식초, 머스타드, 설탕, 다진마늘을 섞어 드레싱을 만든다.\",\"6. 다른 볼에 준비해둔 야채들과 달걀, 참치를 넣고 드래싱을 끼얹어 버무린다.\"]},{\"id\":\"k845\",\"title\":\"다시마전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053722_1416213442466.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/987-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/987-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/987-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/987-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/987-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/987-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다시마 30g\",\"영양부추 3g\",\"청고추다진것 3g\",\"홍고추다진것 3g\",\"새우살다진것 10g\",\"밀가루 10g\",\"물 8g\",\"소금적당량[멸치액적소스]멸치액젓 2g\",\"물 3g\",\"설탕 2g\",\"깨소금 2g\",\"고춧가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마의 두께가 너무 얇으면 전을 부치기 힘들므로 적당한 것을 고른다.\",\"instructions\":[\"1. 냄비에 다시마가 잠길 정도의 물을 붓고 중불에서 삶아 10여분 두었다가 건져 찬물에 휑군 뒤 18cm 크기로 자른다.\",\"2. 청, 홍고추는 씨를 빼 잘게 다지고 부추와 새우 살도 다진다.\",\"3. 밀가루에 물과 소금을 넣고 반죽을 한 뒤 다진 채소들을 넣고 골고루 섞는다.\",\"4. 3에 다시마를 넣어 반죽 물을 입히고 팬에 기름을 둘러 노릇하게 지진다.\",\"5. 다시마전이 한 김 식은 후 돌돌 말아 자를 수 있도록 꼬치로 고정시킨다.\",\"6. 5를 4cm 정도 길이로 자르고 멸치액젓소스를 곁들인다.\"]},{\"id\":\"k846\",\"title\":\"모듬옥수수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053723_1416213443714.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/988-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/988-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/988-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/988-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/988-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/988-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"옥수수 35g\",\"잣 3g\",\"청피망 25g\",\"당근 25g\",\"닭고기 35g\",\"식용유 1g\",\"물전분 6g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"철판에 넣어 뜨겁게 제공해도 좋다.\",\"instructions\":[\"1. 청피망, 당근, 닭고기를 옥수수알 크기로 썬다.\",\"2. 팬에 닭고기를 볶는다.\",\"3. 2에 당근을 넣고 볶는다.\",\"4. 3에 잣, 청피망, 옥수수를 넣고 볶는다.\",\"5. 4에 간을 한다.\",\"6. 물전분으로 농도를 맞춘다.\"]},{\"id\":\"k847\",\"title\":\"버섯 들깨탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053724_1416213444900.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/989-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/989-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/989-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/989-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/989-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/989-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"느타리버섯 15g\",\"생표고버섯 15g\",\"팽이버섯 15g\",\"새송이벗서 15g\",\"우엉 15g\",\"조랭이떡 15g\",\"들깨 8g\",\"물 50g\",\"들기름 2g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 끓는 물에 데친 느타리 버섯을 손으로 찢고 생 표고버섯은 데쳐서 물기를 짠 뒤 채썬다.\",\"2. 팽이버섯은 밑동을 제거한 뒤 반으로 자르고 새송이버섯은 팽이버섯 크기로 자른다.\",\"3. 조랭이떡은 물에 휑구고 우엉은 껍질을 벗겨 길이로 3등분 하여 어슷하게 썬 뒤 냉수에 여러번 휑구고 물기를 뺀다.\",\"4. 들깨는 분무기를 이용하여 물을 조금씩 넣으면서 곱게 갈아 체에 밭쳐 들깨 물을 준비하고 찌꺼기는 버린다.\",\"5. 냄비에 들기름을 두르고 우엉을 볶은 뒤 들깨 물을 부어 끓이다가 조랭이 떡을 넣고 끓인다.\",\"6. 5의 떡이 둥둥 떠오르면 버섯을 넣고 한소끔 끓인 뒤 소금으로 간을 한다.\"]},{\"id\":\"k848\",\"title\":\"산마드래싱과 실곤약 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053726_1416213446198.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/990-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/990-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/990-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/990-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/990-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/990-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"그린비타민 8g\",\"치커리 8g\",\"배 15g\",\"포도주스 10g\",\"훈제오리가슴살 30g\",\"실곤약 20g [산마드래싱] 산마 10g\",\"우유 10g\",\"레몬주스 3g\",\"오렌지주스 3g\",\"호두 3g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"훈제 오리가슴살 대신 닭가슴살을 사용해도 된다.\",\"instructions\":[\"1. 비타민과 치커리는 한입 크기로 적당히 뜯어 찬물에 담궈 두었다가 먹기 전에 물기를 제거한다.\",\"2. 믹서에 산마와 우유, 레몬주스, 오렌지주스, 호두, 소금을 넣고 곱게 갈아 드래싱을 만든다.\",\"3. 배는 껍질을 제거하고 4등분 한 뒤 씨를 제거하고 4~5mm 정도의 두께로 슬라이스한다.\",\"4. 팬에 포도주스를 붓고 슬라이스한 배를 넣어 배가 포도색이 되도록 졸인다.\",\"5. 훈제오리가슴살을 얇게 슬라이스 한다.\",\"6. 접시에 5와 4, 실곤약, 야채들을 보기 좋게 담고 드래싱을 끼얹는다.\"]},{\"id\":\"k849\",\"title\":\"산호두부\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053727_1416213447278.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/991-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/991-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/991-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/991-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/991-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/991-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 35g\",\"돼지고기다진것 15g\",\"당근다진것 10g\",\"고추기름 2g\",\"완두콩 10g\",\"파 5g\",\"생강 3g\",\"물전분 10g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 두부를 1cm 주사위모양으로 자른다.\",\"2. 1을 뜨거운 물에 넣었다가 꺼내 물기를 제거한다.\",\"3. 당근과 돼지고기를 잘게 다진다.\",\"4. 팬에 고추기름을 두른 뒤 3을 넣고 볶는다.\",\"5. 파, 다진생강, 물, 완두콩, 소금, 두부를 넣고 간이 들도록 졸인다.\",\"6. 물 전분을 넣어 소스의 농도를 맞춘다.\"]},{\"id\":\"k850\",\"title\":\"섭산삼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053728_1416213448480.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/992-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/992-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/992-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/992-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/992-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/992-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"더덕 40g\",\"젖은 찹쌀가루 30g\",\"가루녹차 2g\",\"백년초 가루 2g\",\"설탕 1g\",\"꿀 5g\",\"소금 적당량\",\"튀김기름 8g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"더덕이 너무 큰 것을 고르면 섬유소가 많고 거치므로 적당한 크기를 고른다.\",\"instructions\":[\"1. 더덕은 껍질을 벗기고 0.3cm 두께로 편 썰어 소금물에 담궈 쓴 맛을 뺀 뒤 면보에 옮겨 밀대로 밀거나 두들겨 얇게 편다.\",\"2. 찹쌀가루는 소금을 넣고 혼합하여 체에 내린다.\",\"3. 2를 3등분 하여 가루녹차와 백년초가루를 각각 섞는다.\",\"4. 3에 더덕을 각각 넣고 앞, 뒤로 꼭꼭 눌러 찹쌀가루를 묻힌다.\",\"5. 170℃의 기름에 2번 튀긴 뒤 기름을 빼고 뜨거울 때 설탕을 약간 뿌린다.\",\"6. 꿀을 곁들여 찍어 먹는다.\"]},{\"id\":\"k851\",\"title\":\"시금치 돼지고기 볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053729_1416213449527.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/993-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/993-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/993-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/993-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/993-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/993-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기살코기 40g\",\"물전분 10g\",\"소금 적당량\",\"시금치 25g\",\"부추 10g\",\"간장 5g\",\"파 5g\",\"생강 3g\",\"식용유 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"취향에 따라 팔각을 넣기도 한다.\",\"instructions\":[\"1. 돼지고기는 채 썬 뒤 소금, 물전분을 넣고 양념한다.\",\"2. 양념한 고기를 기름 두른 팬에 볶으면서 달라붙지 않도록 저어준다.\",\"3. 시금치와 부추를 4~5cm 가량으로 썬다.\",\"4. 가열된 팬에 기름을 두르고 파, 생강, 팔각을 넣어 향을 낸다.\",\"5. 4에 2와 간장을 넣고 볶는다.\",\"6. 물 전분을 넣어 농도를 맞춘 뒤 마직막으로 부추, 시금치를 넣는다.\"]},{\"id\":\"k852\",\"title\":\"발사믹과 로즈마리로 향을 낸 오븐구이 야채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053730_1416213450573.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/994-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/994-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/994-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/994-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/994-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/994-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 40g\",\"당근 40g\",\"비트 40g\",\"고구마 40g\",\"꿀 8g\",\"발사믹식초 30g\",\"로즈마리 2g\",\"소금적당량\",\"후추 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과나 파인애플과 같은 과일도 가능하다\",\"instructions\":[\"1. 단호박, 비트, 고구마, 당근은 껍질을 벗긴다.\",\"2. 1을 자연스럽게 2~2.5cm 두께로 썬다.\",\"3. 볼에 2와 발사믹 식초, 꿀, 로즈마리 잎을 넣고 버무린다.\",\"4. 소금, 후추로 간을 한다.\",\"5. 150℃의 예열된 오븐에서 익을 때까지 굽는다.\",\"6. 중간에 뒤집어 주어 고루 익히도록 한다.\"]},{\"id\":\"k853\",\"title\":\"종이에 싸서 구운 도미(파필로테)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053731_1416213451353.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/995-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/995-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/995-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/995-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/995-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/995-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"도미살 65g\",\"소금 적당량\",\"후추 적당량\",\"샐러리 채친것 3g\",\"당근 채친것 3g\",\"대파채친것 3g\",\"양파채친것 6g\",\"피망채친것 5g\",\"브러컬리 5g\",\"레몬제스트 1g\",\"팽이버섯 3g\",\"버터 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오븐에 넣을 때 내열 접시나 오븐용 팬에 올려서 넣는다.\",\"instructions\":[\"1. 도미살에 소금, 후추로 밑간한다.\",\"2. 셀러리, 당근, 대파, 양파, 피망은 채 썰고 브로컬리는 작은 송이로 자르고 레몬 껍질은 얇게 제스트하고 팽이버섯은 밑동을 자른다.\",\"3. 유산지는 반을 접었다가 편 뒤 안쪽에 부드러운 버터를 바른다.\",\"4. 4의 버터를 바른 한 쪽 면에 셀러리, 당근, 대파, 팽이버섯, 양파, 피망, 레몬 제스트를 준비된 분량의 반 정도 놓고 밑간한 도미살을 올린다.\",\"5. 다시 남은 야채들을 도미위에 올리고 유산지의 한 면으로 야채를 덮어주고, 모서리의 뚫린 곳을 접어 봉해준다.\",\"6. 160℃로 예열된 오븐에서 익혀준다.\"]},{\"id\":\"k854\",\"title\":\"무염 겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042946_1554794986601.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409043237_1554795157968.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409043250_1554795170276.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409043305_1554795185948.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409043320_1554795200264.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409043337_1554795217596.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409043351_1554795231237.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"알배추 50g\",\"적양파 15g\",\"대파 5g\",\"풋고추 3g\",\"마늘 5g\",\"무청 3g\",\"고춧가루 5g\",\"매실액 2g\",\"식초 5g\",\"사과 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 많은 무청과 고추, 양파를 사용해 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 알배추는 세척 후 먹기 좋은 크기로 잘라 물에 담군다.\",\"2. 대파와 풋고추는 어슷썰고 양파는 굵게 채 썬다.\",\"3. 마늘은 곱게 다지고 사과는 믹서에 간다.\",\"4. 사과즙, 다진마늘, 고춧가루, 매실액, 식초를 섞어 겉절이 양념을 만든다.\",\"5. 물에 담궈뒀던 알배추를 건져 물기를 뺀 뒤 넓은 볼에 담는다.\",\"6. 알배추와 양파, 대파, 풋고추, 무청을 겉절이 양념에 골고루 버무린다.\"]},{\"id\":\"k855\",\"title\":\"닭가슴살호두크로켓\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023223_1584077543747.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023251_1584077571164.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023303_1584077583683.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023318_1584077598621.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023410_1584077650685.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023444_1584077684540.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023508_1584077708825.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 80g\",\"두부 20g\",\"양파 12.5g\",\"대파 5g\",\"호두 5g\",\"땅콩 2.5g\",\"마늘 2g\",\"생강 0.5g\",\"후추 0.3g\",\"설탕 3.8g\",\"식초 2.5g\",\"계란 65g(1.5개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"두부와 두유로 마요네즈를 만들어 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 양파, 대파, 호두, 닭가슴살은 잘게 다진다.\",\"2. ①에 물기를 제거한 두부와 생강, 마늘, 후추를 섞어 반죽한다.\",\"3. 반죽을 쌀가루, 계란물, 빵가루 순으로 묻히고 튀겨 크로켓을 만든다.\",\"4. 믹서에 두부, 두유를 넣고 갈아 두부 마요네즈를 만든다.\",\"5. 순무와 양파는 다지고, 계란은 삶아 다져 준비한다.\",\"6. 두부 마요네즈에 ⑤의 재료와 설탕, 레몬, 식초, 땅콩버터, 후추, 홀그레인, 파슬리가루를 넣어 타르소스를 만든다.\"]},{\"id\":\"k856\",\"title\":\"누룽지상추샐러드&유자드레싱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055656_1611824216006.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055718_1611824238396.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055729_1611824249881.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055745_1611824265798.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055758_1611824278574.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055812_1611824292423.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055826_1611824306126.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"누룽지 5g\",\"로메인상추 7.5g\",\"파프리카(빨간색/노란색) 12.5g\",\"유자청 7.5g\",\"식용유 500g\",\"올리브유 3.5g\",\"레몬즙 1g\",\"식초 1g\",\"후추 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일의 상큼한 맛과 튀긴 누룽지의 고소한 맛으로 싱거운 맛을 보완했어요.\",\"instructions\":[\"1. 로메인 상추를 한 입 크기로 썬다.\",\"2. 파프리카는 사방 0.3cm 크기로 썬다.\",\"3. 누룽지를 튀긴 후 으깬다.\",\"4. 유자청, 레몬즙, 올리브유, 식초, 후추를 섞어 드레싱을 만든다.\",\"5. 로메인 상추 위에 파프리카와 튀긴 누룽지를 고명으로 올린다.\",\"6. 드레싱을 얹어 낸다.\"]},{\"id\":\"k857\",\"title\":\"견과류 미숫가루 빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052423_1611908663012.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052455_1611908695113.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052508_1611908708170.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052703_1611908823337.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052717_1611908837618.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052731_1611908851161.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052744_1611908864616.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분60g\",\"박력분 30g\",\"미숫가루 150g\",\"이스트 4g\",\"소금 5g\",\"달걀 50g(1개)\",\"버터 30g\",\"아몬드20g\",\"해바라기씨 30g\",\"호박씨 10g\",\"건포도 20g\",\"(아몬드우유) 아몬드 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"견과류를 구울 때 생기는 견과류의 단맛과 고소함을 이용한 빵이에요.\",\"instructions\":[\"1. (아몬드우유) 믹서기에 아몬드와 우유를 갈아 아몬드 우유를 만든다.\",\"2. 밀가루, 미숫가루, 이스트, 소금, 달걀, 아몬드 우유를 넣어 손으로 반죽하다가 아몬드, 해바라기씨, 호박씨 넣고 반죽한다.\",\"3. ②이 한 덩어리가 되면 무염버터를 넣어 반죽을 하고 마지막으로 건포도를 넣어 섞는다.\",\"4. \\\"크기가 2.5배가 될 때까지 1차 발효하고 반죽을 접어 공기를 빼고 3등분으로 나눠 둥글리기 후 10분 정도 중간 발효한다.\\n★반죽이 달라붙으면 덧가루를 뿌리면서 작업하면 수월해요.\\\"\",\"5. 발효가 끝나면 다시 둥글리기를 해주고 반죽의 매끄러운 면이 위로 가도록 팬닝 후 40~50분 2차 발효 시킨다.\",\"6. \\\"180℃ 오븐에서 20~25분 동안 구워서 완성시킨 뒤 위에 버터를 바르고 아몬드 슬라이스와 미숫가루로 토핑한다.\\n★ 버터는 살짝 녹여 사용하세요.\\\"\"]},{\"id\":\"k858\",\"title\":\"돼지 함초 덮밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310093936_1615336776669.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094015_1615336815863.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094031_1615336831781.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094045_1615336845532.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094108_1615336868082.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094122_1615336882486.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094134_1615336894810.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파(10g)\",\"쪽파(3g)\",\"레몬(3g)\",\"무순(20개)\",\"멸치(7~8마리)\",\"건함초(3g)\",\"다시마(5g)\",\"밥(210g)\",\"꽈리고추(5개)\",\"돼지고기(등심\",\"120g)\",\"수란(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치, 함초, 다시마를 갈아 천연 조미료로 간을 맞춰 나트륨의 사용을 줄였어요.\",\"instructions\":[\"1. 양파는 채 썰고, 쪽파는 송송 썰고, 레몬은 슬라이스하고, 마늘은 으깨고, 생강은 납작 썰고, 건고추는 굵게 부순다.\",\"2. 중간 불로 달군 마른 팬에 멸치를 넣어 3분간 볶아 수분을 날린 뒤 건함초, 다시마와 함께 믹서에 넣어 곱게 간다.\",\"3. 중간 불로 달군 팬에 식용유(20㎖)와 손질한 향신료를 넣고 3분간 볶아 향유를 만든다.\",\"4. 향유에 참기름과 후춧가루, 곱게 간 멸치가루를 넣어 섞은 뒤 밥에 넣어 고루 섞는다.\",\"5. 중간 불로 달군 팬에 남겨둔 향유(10g)를 두르고 꽈리고추와 돼지고기를 넣어 9분간 구운 뒤 돼지고기는 얇게 한입 크기로 썬다.\",\"6. 그릇에 비빔밥, 구운 돼지고기와 꽈리고추, 손질한 양파, 쪽파, 레몬, 김가루, 고추냉이, 무순, 수란을 올린다.\"]},{\"id\":\"k859\",\"title\":\"닭가슴살 채소쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98WE\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Fo7\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Frc\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9FyK\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Fzl\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9F-c\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9G1V\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 양상추(3장)\",\"양파(¼개)\",\"토마토(중간 크기 1개)\",\"청양고추(2개)\",\"할라피뇨 피클(10개)\",\"닭가슴살(270g)\",\"단호박(1개)\",\"라이스페이퍼(7장)\",\"플레인 요거트(1컵)\",\"마늘(3~4쪽)\",\"대파(½대)\",\"후춧가루(0.5ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•단호박을 사용하여 재료 본연의 단맛을 살리고 양상추와 양파를 사용해 식감을 높였어요.\\n•칼륨 함량이 높은 단호박, 토마토는 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 양상추는 채 썰고, 양파와 토마토는 작게 한입 크기로 썰고, 청양고추와 할라피뇨 피클은 잘게 다진다.\",\"2. 냄비에 물(10컵), 닭가슴살, 닭가슴살 삶는 재료와 후춧가루(0.3ts)를 넣어 7분 정도 삶은 뒤 건져 얇게 찢는다.\",\"3. 호박은 4조각으로 잘라 씨를 제거하고, 찜기에 물(1컵)을 넣어 쪄내고, 껍질을 벗긴 뒤 물(1컵)을 부어가며 으깬다.\",\"4. 약한 불로 달군 팬에 으깬 단호박, 닭가슴살, 다진 청양고추, 카레가루, 후춧가루(0.2ts)를 넣어 수분이 날아갈 때까지 볶는다.\",\"5. 팬에 식용유(2컵)를 부은 뒤 중간 불로 예열하고, 라이스페이퍼를 넣어 튀긴 뒤 바로 건져낸다.\",\"6. 튀긴 라이스페이퍼에 단호박 볶음과 손질한 채소, 플레인 요거트를 올려 마무리한다.\"]},{\"id\":\"k860\",\"title\":\"콩감태유자 스콘\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023093851_1761179931161.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023094638_1761180398422.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023094653_1761180413702.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023094708_1761180428151.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023094725_1761180445480.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023094745_1761180465045.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023094807_1761180487176.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 삶은 병아리콩① 175g\",\"두유 210g\",\"코코넛오일 70g\",\"유자필 56g\",\"쌀가루 280g\",\"아몬드가루 105g\",\"감태가루 3.5g\",\"앙 금 > 유자앙금 105g\",\"삶은 병아리콩② 50g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"병아리콩과 감태가루를 사용하여 풍미를 높이고 나트륨과 당류 사용량을 줄였어요.\",\"instructions\":[\"1. 믹서에 삶은 병아리콩①, 두유,\\n코코넛오일을 넣고 곱게 간다.\",\"2. 볼에 담고 유자필을 넣어 섞는다.\",\"3. 쌀가루, 아몬드가루, 감태가루를 체 쳐서\\n넣고 섞어 반죽을 만든다.\",\"4. 반죽은 10~12cm 크기의\\n원형으로 성형하고,\\n유자앙금과 삶은 병아리콩②를 섞어\\n반죽 위에 올린다\",\"5. 4~5등분으로 자르고 오븐 팬에\\n올린다.\",\"6. 175°C로 예열한 오븐에 170°C에서\\n20분 동안 구워 마무리한다.\"]},{\"id\":\"k861\",\"title\":\"호두 사과 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053733_1416213453570.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/997-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/997-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/997-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/997-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/997-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/997-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과 60g\",\"샐러리 5g\",\"마요네즈 4g\",\"레몬주스 1g\",\"식초 1g\",\"호두 5g\",\"건포도 4g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과는 레몬즙이 들어있는 물에 넣어 색의 변화를 막고 레몬향을 느끼도록 한다.\",\"instructions\":[\"1. 사과는 4등분하고 씨를 제거한다.\",\"2. 1을 다시 4등분 한다.\",\"3. 셀러리는 껍질을 제거하고 슬라이스 한다.\",\"4. 마요네즈, 레몬주스, 식초, 소금을 섞어 드래싱을 만든다.\",\"5. 볼에 사과, 셀러리, 호두, 건포도를 넣는다.\",\"6. 5에 만들어 놓은 드래싱을 넣어 고루 섞는다.\"]},{\"id\":\"k862\",\"title\":\"고구마란\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053734_1416213454820.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/998-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/998-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/998-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/998-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/998-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/998-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 70g\",\"꿀 10g\",\"계피가루 2g\",\"대추 5g\",\"호박씨 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"선을 그을 수 있는 도구를 이용하여 대각선 방향으로 금을 그으면 예쁜모양을 만들 수 있다.\",\"instructions\":[\"1. 고구마는 껍질을 벗긴 후 큼직하게 썰어 찜통에 찐다.\",\"2. 다 쪄진 고구마를 체에 곱게 내린다.\",\"3. 2에 꿀과 계피가루를 넣어 섞는다.\",\"4. 대추는 씨를 제거한 뒤 0.5mm  마름모꼴로 자른다.\",\"5. 고구마를 조금씩 떼어 둥글게 빚는다.\",\"6. 호박씨와 썰어둔 대추로 꼭지를 만든다.\"]},{\"id\":\"k863\",\"title\":\"과일 파이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053735_1416213455900.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/999-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/999-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/999-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/999-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/999-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/999-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오렌지 25g\",\"사과 25g\",\"설탕 15g\",\"물전분 4g\",\"버터 1g\",\"식빵 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"만두피로 대용하는 것도 가능하다.\",\"instructions\":[\"1. 오렌지는 껍질을 벗긴 뒤 잘게 썰고 사과는 껍질 째 깨끗하게 씻어서 잘게 썬다.\",\"2. 냄비에 오렌지와 사과를 각각 넣고 설탕을 넣어 중간 불에서 타지 않도록 졸인다.\",\"3. 졸이는 도중에 과일에서 나온 물로 질척해지면 물전분을 넣어 농도를 맞춘 뒤 차게 식힌다.\",\"4. 식빵은 가장자리를 잘라낸 다음 밀대로 납작하게 밀어 버터를 바른다.\",\"5. 졸인 과일을 얹고 돌돌 만 다음 양끝을 포크로 눌러 붙인다.\",\"6. 식빵의 표면에 버터를 얇게 바르고 170℃로 예열된 오븐에 넣어 노릇하게 굽는다.\"]},{\"id\":\"k864\",\"title\":\"수삼당근정과\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053736_1416213456837.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1000-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1000-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1000-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1000-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1000-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1000-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당근 50g\",\"수삼 30g\",\"꿀 20g\",\"물 10g\",\"계피가루 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연령이 높아지면서 수삼이나 당근을 굵게 갈거나 얇게 잘라서 정과를 한다.\",\"instructions\":[\"1. 당근과 수삼을 깨끗하게 씻는다.\",\"2. 1을 믹서에 넣고 곱게 간다.\",\"3. 냄비에 2를 붓고 꿀을 넣어 졸인다.\",\"4. 계피가루를 섞는다.\",\"5. 빵이나 크래커를 준비한다.\",\"6. 5의 위에 수삼 당근 정과를 올린다.\"]},{\"id\":\"k865\",\"title\":\"식혜 팥빙수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053737_1416213457776.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1001-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1001-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1001-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1001-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1001-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1001-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"팥 10g\",\"찹쌀가루 15g\",\"쑥가루 5g\",\"물 10g\",\"식혜 110g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수정과를 얼려서 포크나 스푼으로 긁어서 사용하기도 한다.\",\"instructions\":[\"1. 팥을 깨끗하게 씻어 물을 부어 끓인 뒤 물을 버리고 다시 찬물을 부어 삶는다.\",\"2. 부드럽게 삶아진 팥의 물기를 제거한 후 으깬다.\",\"3. 찹쌀가루를 둘로 나누어 하나는 쑥가루를 넣고 하나는 맨 찹쌀가루에 뜨거운 물로 익반죽 하여 경단을 만든 뒤 끓는 물에 익힌다.\",\"4. 익힌 경단을 바로 차가운 얼음물에 담궈 식힌다.\",\"5. 식혜에 으깬 팥을 넣고 소금 간을 한 뒤 그릇에 담아 냉동실에 얼리면서 1시간 마다 공기가 들어가도록 포크로 저어준다.\",\"6. 샤베트가 부드럽게 얼면 준비한 그릇에 경단과 함께 담는다.\"]},{\"id\":\"k866\",\"title\":\"야채칩\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053738_1416213458618.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1002-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1002-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1002-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1002-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1002-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1002-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연근 20g\",\"고구마 20g\",\"감자 20g\",\"단호박 20g\",\"당근 20g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"주로 뿌리 채소를 이용하여 오븐에서 말리거나 구워낸다.\",\"instructions\":[\"1. 준비된 야채들을 깨끗이 씻는다.\",\"2. 연근, 고구마, 감자, 단호박, 당근은 0.2cm 두께로 썬다.\",\"3. 연근, 고구마, 감자는 물에 담궈 둔다.\",\"4. 오븐 팬에 썰어 놓은 재료를 넣고 소량의 소금을 뿌린다.\",\"5. 130~150℃로 예열한 오븐에 4를 굽는다.\",\"6. 구워진 야채칩을 식혀 담는다.\"]},{\"id\":\"k867\",\"title\":\"잡곡강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053739_1416213459635.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1003-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1003-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1003-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1003-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1003-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1003-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"검은콩튀밥 10g\",\"쌀튀밥 10g\",\"메닐튀밥 10g\",\"물엿 6g\",\"설탕 6g\",\"물 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"물엿과 설탕 녹인 것에 마시멜로우를 넣으면 더 부드러운 강정을 만들 수 있다.\",\"instructions\":[\"1. 검은콩, 쌀, 메밀의 튀밥을 준비한다.\",\"2. 물엿에 설탕, 물을 넣고 약한불에서 투명하게 녹인다.\",\"3. 오목한 팬에 2를 넣는다.\",\"4. 3의 팬에 1을 넣고 시럽에서 실이 생길 때 까지 불 위에서 젓는다.\",\"5. 강정이 굳기 전에 타원형 모양으로 빚거나 밀대로 밀어 편다.\",\"6. 밀어 편 강정을 마름모 모양으로 자른다.\"]},{\"id\":\"k868\",\"title\":\"잣 호두 강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053740_1416213460828.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1004-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1004-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1004-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1004-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1004-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1004-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"잣 3g\",\"호두 3g\",\"대추 3g\",\"통깨 5g [시럽] 물엿 3g\",\"설탕 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"물엿의 비율이 높아지면 덜 단단해 진다.\",\"instructions\":[\"1. 잣은 고깔을 떼어낸 뒤 젖은 행주로 문질러 먼지를 닦는다.\",\"2. 호두는 미지근한 물에 불려 껍질을 제거한다.\",\"3. 대추는 얇게 돌려 깎아 곱게 다진다.\",\"4. 물엿과 설탕을 냄비에 담고 물을 조금 넣은 뒤 약한불에서 투명한 시럽으로 만든다.\",\"5. 잣, 호두, 통깨에 다진 대추와 시럽을 넣고 덩어리지게 섞는다.\",\"6. 살짝 뜨거울 때 손으로 동그랗게 뭉쳐준다.\"]},{\"id\":\"k869\",\"title\":\"현미 크레이프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053741_1416213461876.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1005-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1005-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1005-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1005-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1005-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1005-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"현미가루 10g\",\"밀가루 20g\",\"우유 30g\",\"참기름적당량\",\"소금적당량 [팥소]팥 15g\",\"설탕 10g [당근조림] 당근 20g\",\"설탕 10g\",\"물 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"현미가루를 만들어 냉동실에 밀봉하여 사용하는 것이 좋다.\",\"instructions\":[\"1. 팥을 깨끗하게 씻어 끓인 뒤 물을 따라 버리고 다시 물을 부어 팥이 무르게 삶는다.\",\"2. 당근을 1cm 주사위 모양으로 자른다.\",\"3. 1, 2에 각각 설탕을 넣고 졸인다.\",\"4. 볼에 현미가루, 밀가루, 우유를 넣고 덩어리가 생기지 않도록 잘 갠 뒤 30분간 둔다.\",\"5. 가열된 팬에 참기름을 두르고 약한 불에서 4를 한 국자 정도 떠서 둥글게 부친 뒤 식힌다.\",\"6. 크레이프를 펴고 각각 팥소와 당근조림을 각각 얹은 후 둥글게 만다.\"]},{\"id\":\"k870\",\"title\":\"감자 주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053743_1416213463031.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1006-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1006-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1006-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1006-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1006-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1006-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 80g\",\"밥 80g\",\"당근다진것 20g\",\"시금치 20g\",\"잔멸치 5g\",\"삶은 달걀 노른자 5g\",\"검은깨 1g\",\"흰깨 2g[밥양념] 참기름 2g\",\"소금적당량\",\"흰 후춧가루 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"모양 틀을 구매하여 사용하면 더 많은 모양을 이용할 수 있다.\",\"instructions\":[\"1. 감자를 깨끗하게 씻어 찜통에 찐 뒤 껍질을 벗기고 체에 내린다.\",\"2. 기름 두른 팬에 다진 당근을 볶으면서 소금 간을 하고 시금치는 손질하여 데친 뒤 냉수에 헹궈 물기를 짜고 잘게 다진다.\",\"3. 잔멸치는 팬에 살짝 볶아서 굵직하게 다진다.\",\"4. 볼에 1, 2, 3, 4를 넣고 소금과 흰 후춧가루, 참기름을 넣고 섞는다.\",\"5. 삶은 달걀노른자를 체에 내린다.\",\"6. 4를 원형 또는 삼각형으로 만들어 달걀 노른자와 검은깨, 흰깨에 골고루 굴려 묻힌다.\"]},{\"id\":\"k871\",\"title\":\"고기완두조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053744_1416213464068.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1007-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1007-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1007-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1007-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1007-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1007-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기살코기 40g\",\"완두콩 30g\",\"물 5g\",\"육수 10g\",\"설탕 7g\",\"소금적당량\",\"전분 5g\",\"식용유 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"완두에는 전분이 들어있어 잘 늘러붙기 때문에 잘 저어가며 조리한다.\",\"instructions\":[\"1. 돼지고기는 손질한 뒤 완두콩 크기로 썬다.\",\"2. 완두콩을 믹서에 곱게 간다.\",\"3. 기름을 두른 팬에 1을 넣고 달라붙지 않게 볶는다.\",\"4. 2에 3과 설탕을 넣고 끓인다.\",\"5. 4에 소금으로 간을 한다.\",\"6. 물전분으로 소스의 농도를 맞춘다.\"]},{\"id\":\"k872\",\"title\":\"니고랭\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053747_1416213467375.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1010-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1010-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1010-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1010-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1010-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1010-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀물 10g\",\"식용유 1g\",\"홍고추 3g\",\"마늘다진것 1g\",\"닭가슴살 12g\",\"새우 12g\",\"양파 12g\",\"청경채 20g\",\"스파게티면 40g\",\"방울토마토 15g\",\"버터 적당량[소야소스] 간장 3g\",\"발사믹식초 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"미리 준비하는 경우 면을 삶아 기름을 넣어 섞어두면 덜 붙는다.\",\"instructions\":[\"1. 팬에 기름을 두르고 홍고추와 마늘을 향이 날 때까지 볶는다.\",\"2. 1에 달걀물을 넣고 달걀이 부드럽게 부풀어 오르도록 기다렸다가 반 정도 익었을 때 가볍게 젓는다.\",\"3. 2에 닭고기, 새우, 양파를 넣고 볶는다.\",\"4. 3에 준비된 스파게티면을 넣고 한 번 볶은 뒤 소야소스를 넣고 면에 간이 충분히 베이도록 볶는다.\",\"5. 면이 볶아지면 청경채, 방울토마토를 넣고 살짝 볶는다.\",\"6. 5에 차갑게 한 버터를 넣어 소스에 윤기와 농도가 나도록 한다.\"]},{\"id\":\"k873\",\"title\":\"돼지갈비 볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053749_1416213469472.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1012-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1012-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1012-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1012-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1012-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1012-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지갈비 60g\",\"굵은소금적당량\",\"마늘다진것 3g\",\"생강다진것 2g\",\"대파 10g\",\"토마토 25g[양념장] 간장 5g\",\"물 10g\",\"식초 2g\",\"설탕 3g\",\"통깨 적당량\",\"참기름 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념장을 넣어 익힐 때 다양한 야채를 첨가해도 좋다.\",\"instructions\":[\"1. 돼지갈비는 4cm 길이로 준비하여 기름기를 제거하고 찬물에 담가 핏물을 뺀다.\",\"2. 1에 굵은 소금을 넣고 주물러 갈비를 연하게 한 뒤 소금을 씻어낸다.\",\"3. 돼지갈비에 칼집을 넣은 뒤 대파, 마늘, 생강을 넣고 끓인 물에 데쳐서 헹군다.\",\"4. 냄비에 기름을 두르고 데쳐낸 갈비를 볶다가 양념장을 붓고 뚜껑을 덮어 서서히 익히면서 볶는다.\",\"5. 갈비에 간이 베이면 센불에서 저어주면서 윤기 나게 볶는다.\",\"6. 접시에 얇게 썬 토마토를 깔고 볶아낸 돼지갈비를 담은 뒤 통깨를 뿌린다.\"]},{\"id\":\"k874\",\"title\":\"미니 그라탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053750_1416213470534.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1013-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1013-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1013-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1013-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1013-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1013-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과 50g\",\"참마 25g\",\"레몬주스 10g\",\"건포도 5g\",\"슬라이스아몬드 5g\",\"설탕 6g[소스] 참마 25g\",\"두유 40g\",\"물엿 5g\",\"밀가루 3g\",\"올리브오일 1g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"마 대신 감자를 이용할 수 있고 소스도 크림소스로 대체할 수 있다.\",\"instructions\":[\"1. 껍질을 벗기지 않은 사과와 반을 잘라 껍질을 벗긴 참마를 0.7cm 주사위모양으로 썬다.\",\"2. 사과에 레몬주스, 소금을 넣고 부드러워질 때 까지 익힌 뒤 참마를 넣고 살짝 끓인다.\",\"3. 나머지 참마는 껍질을 벗긴 뒤 토막내 두유, 물엿, 밀가루, 올리브오일과 같이 믹서에 간다.\",\"4. 3이 퓨레 상태가 되면 약 불에서 걸쭉하게 졸인다.\",\"5. 2에 건포도를 섞은 뒤 틀에 담고 4를 펴서 얹고 그 위에 슬라이스 아몬드와 설탕을 뿌린다.\",\"6. 200℃로 예열한 오븐에서 표면이 노릇해 질 때 까지 약 10분 간 굽는다.\"]},{\"id\":\"k875\",\"title\":\"밀라노 스타일 포크 커틀렛\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053751_1416213471597.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1014-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1014-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1014-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1014-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1014-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1014-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지등심 60g\",\"밀가루 4g\",\"달걀 12g\",\"빵가루 4.5g\",\"바질 0.5g\",\"건타임 0.5g\",\"버터 0.5g\",\"식용유 1g\",\"레몬 5g\",\"파마산치즈 2g\",\"소금 적당량\",\"후추 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"돼지고기는 우유에 10분정도 담갔다가 사용하게 되면 누린내 제거에 좋고 맛도 부드러워진다.\",\"instructions\":[\"1. 돼지고기(등심)을 고기망치로 두드려 1cm 정도 두께로 편다.\",\"2. 돼지등심에 소금, 후추로 간을 한다.\",\"3. 파마산치즈, 빵가루, 건바질, 타임을 섞어 허브 빵가루를 만든다.\",\"4. 고기에 밀가루, 달걀물, 허브 빵가루 순으로 묻힌다.\",\"5. 가열한 팬에 기름을 두르고 커틀렛을 익힌다.\",\"6. 커틀렛이 익으면 기름을 빼고 그릇에 담는다.\"]},{\"id\":\"k876\",\"title\":\"바지락 볶음면\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053752_1416213472408.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1015-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1015-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1015-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1015-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1015-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1015-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바지락살 20g\",\"칵테일새우 20g\",\"청고추 5g\",\"홍고추 5g\",\"대파 10g\",\"마늘다진것 3g\",\"생강다진것 2g\",\"칼국수면 80g\",\"식용유 적당량\",\"물전분 4g[간장소스]멸치육수 50g\",\"간장 5g\",\"설탕 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바지락을 소금물에 미리 담그어 놓으면 모래를 뱉어 씹히는 질감이 좋다.\",\"instructions\":[\"1. 바지락살과 새우는 소금물에 흔들어 씻어 체에 받쳐 물기를 제거한다.\",\"2. 대파, 청, 홍고추는 송송 썰고, 마늘, 생강은 다진다.\",\"3. 끓는 물에 칼국수 면을 삶아 냉수에 헹군 뒤 참기름으로 버무린다.\",\"4. 멸치 육수에 분량의 재료를 넣고 간장 소스를 만든다.\",\"5. 팬에 식용유를 두르고 다진 마늘, 생강, 고추를 넣어 볶다가 센 불에서 바지락살과 새우, 청주를 넣어 볶은 뒤 간장소스를 넣고 끓인다.\",\"6. 5가 반정도 졸면 칼국수 면을 넣어 볶으면서 물전분으로 농도를 맞춘 뒤 송송 썬 파와 참기름을 넣고 마무리한다.\"]},{\"id\":\"k877\",\"title\":\"삼색 꽃 화전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044713_1554796033713.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044806_1554796086957.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044823_1554796103141.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044839_1554796119933.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044901_1554796141995.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044916_1554796156256.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044937_1554796177499.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀가루 60g\",\"시금치 30g\",\"치자 5g\",\"식용꽃 5g\",\"타임 5g\",\"설탕 15g\",\"꿀 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"화전 반죽에 시금치와 치자를 이용해 맛과 색을 냈어요.\",\"instructions\":[\"1. 시금치는 데친 뒤 믹서에 곱게 갈고 치자는 따뜻한 물에 불린다.\",\"2. 곱게 간 시금치에 데쳤던 물을 넣고 가열한 뒤 찹쌀가루 절반에 조금씩 부어 익반죽 한다.\",\"3. 남은 절반의 찹쌀가루에 가열한 치자물을 조금씩 부어 익반죽 한다.\",\"4. 30분 간 휴지시킨 뒤 팬에 기름을 두르고 적당한 크기로 빚은 화전을 지진다.\",\"5. 한쪽 면을 익힐 때 위에 꽃을 올린 뒤 뒤집어 살짝만 지진다.\",\"6. 꿀과 설탕, 물을 1:2:3 비율로 섞어 끓여 시럽을 만들어 화전 위에 끼얹고 타임으로 장식한다.\"]},{\"id\":\"k878\",\"title\":\"알록달록연근튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045226_1584085946623.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045628_1584086188105.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045639_1584086199911.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045651_1584086211037.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045708_1584086228342.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045720_1584086240520.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045731_1584086251610.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"깐연근 22.18g\",\"비트 2.12g\",\"시금치 2.12g\",\"카레가루 1.52g\",\"건새우 0.3g\",\"전분 2.25g\",\"튀김가루 4.25g\",\"소금 0.05g\",\"식물성기름 500ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"건새우를 갈아넣어 고소한 맛을 더하고 소금을 최소화 했어요.\",\"instructions\":[\"1. 연근은 얇게 썰어 찬물에 담가 전분기를 제거한다.\",\"2. 건새우는 곱게 갈아준다.\",\"3. 시금치, 비트는 각각 믹서기에 갈아 즙을 준비한다.\",\"4. 튀김가루에 새우가루와 물을 넣어 반죽을 한다.\",\"5. 반죽에 시금치, 카레, 비트를 각각 넣어 3가지 색의 반죽을 만든다.\",\"6. 연근에 전분가루를 묻히고 튀김옷을 입혀 바삭하게 튀겨낸다.\"]},{\"id\":\"k879\",\"title\":\"잎채소튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054031_1584088831750.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054053_1584088853759.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054108_1584088868485.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054119_1584088879283.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054130_1584088890895.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054144_1584088904300.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054202_1584088922129.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"깻잎 5g\",\"상추 6g\",\"배추 7g\",\"계란 10g\",\"튀김가루 10g\",\"콩기름 5g\",\"얼음\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"아이들이 선호하는 튀김 조리법으로 채소 본연의 맛을 느낄 수 있도록 했어요.\",\"instructions\":[\"1. 볼에 튀김가루, 계란 물을 섞어 반죽을 만든 후 얼음을 넣어 차갑게 한다.\",\"2. 깻잎, 상추, 배추는 깨끗하게 씻어 준비한다.\",\"3. 재료를 먹기 좋은 크기로 썬다.\",\"4. 냄비에 콩기름을 부은 후 적당한 온도가 될 때까지 가열한다.\",\"5. 야채에 반죽을 입힌다.\",\"6. 노릇하게 튀긴다.\"]},{\"id\":\"k880\",\"title\":\"포항초사과샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103512_1611884112461.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101431_1611882871711.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101445_1611882885083.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101457_1611882897735.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101511_1611882911331.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101526_1611882926047.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101538_1611882938493.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"포항초 20g\",\"사과 5g\",\"당근 2g\",\"양파 2g\",\"파프리카 1g\",\"레몬즙(또는 식초) 0.2g\",\"저염간장 0.4g\",\"설탕 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해풍의 영향으로 적당한 염분이 함유된 포양초에 사과를 곁들여 맛을 냈어요.\",\"instructions\":[\"1. 포항초는 세척하고 3cm 크기로 자른다.\",\"2. 당근은 얇게 채 썰어주고, 사과는 껍질 채로 채 썰어 설탕물에 담가 둔다.\",\"3. 양파와 파프리카는 작은 큐브 모양으로 썬다.\",\"4. 저염간장, 레몬즙, 설탕, 양파, 파프리카를 넣어 오리엔탈 드레싱을 만든다.\",\"5. 포항초에 당근과 사과를 넣어 섞어준다.\",\"6. 샐러드에 오리엔탈 드레싱을 곁들여 제공한다.\"]},{\"id\":\"k881\",\"title\":\"생선 파피요트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094914_1615337354153.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094939_1615337379572.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094956_1615337396610.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310095120_1615337480563.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310095134_1615337494612.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310095147_1615337507323.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파(⅓개)\",\"파프리카(⅓개)\",\"레몬(1개)\",\"방울토마토(4개)\",\"손질된 흰살생선(½마리)\",\"대하(2마리)\",\"바지락(4개)\",\"월계수잎(3장)\",\"타임(4~5줄기)\",\"소금(2g)\",\"후춧가루(1g)\",\"화이트와인(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해산물을 활용해 따로 간을 하지 않아도 맛있는 요리를 만들 수 있어요.\",\"instructions\":[\"1. 양파, 파프리카는 채 썰고, 레몬은 얇게 썰고, 방울토마토는 2등분한다.\",\"2. 손질된 흰살생선에 밑간한다.\",\"3. 종이 포일에 채 썬 양파를 깐 뒤 밑간한 생선 → 손질한 파프리카 → 레몬 → 방울토마토 순으로 올린다.\",\"4. 대하, 바지락, 월계수잎, 타임을 올린 뒤 화이트와인과 올리브유를 뿌린다.\",\"5. 종이 포일로 감싸고 200℃로 예열한 오븐에 15~25분간 굽는다.\"]},{\"id\":\"k882\",\"title\":\"시금치 후무스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98fz\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9G7H\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9G8B\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GBN\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GDs\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GFn\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 대파(15cm)\",\"시금치(1줌=60g)\",\"불린 병아리콩(½컵)\",\"우유(1컵)\",\"올리브유(0.5Ts)\",\"천일염(0.5Ts)\",\"라임즙(0.3Ts)\",\"백후춧가루(약간)\",\"넛맥가루(약간)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 시금치는 나트륨 배출에 도움을 줘요.\\n•라임즙을 넣어 맛의 심심함을 보완했어요.\",\"instructions\":[\"1. 대파는 송송 썰고, 시금치는 깨끗하게 씻어 물기를 제거한다.\",\"2. 약한 불로 달군 팬에 올리브유를 두른 뒤 불린 병아리콩을 넣고 3분간 볶는다.\",\"3. 물(5컵)을 부어 중간 불로 삶고, 물이 졸아들면 우유를 넣은 뒤 양이 절반이 될 때까지 졸인다.\",\"4. 끓는 소금물(물5컵+천일염0.5Ts)에 시금치를 넣어 5분간 데치고, 찬물에 담가 헹군 뒤 물기를 꼭 짠다.\",\"5. 믹서에 병아리콩조림, 데친 시금치, 라임즙, 백후춧가루, 넛맥가루를 넣어 곱게 갈아 마무리한다.\"]},{\"id\":\"k883\",\"title\":\"클로－바\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023095232_1761180752387.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023101257_1761181977350.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023101314_1761181994808.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023101328_1761182008548.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023101345_1761182025922.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023101401_1761182041264.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023101419_1761182059113.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 귀리 100g\",\"아몬드슬라이스 25g\",\"피칸 25g\",\"땅콩버터 25g\",\"클로렐라가루 7.5g\",\"알룰로스 50g\",\"코코넛우유 45ml\",\"아몬드우유 80ml\",\"대추채 12.5g\",\"카카오닙스 25g\",\"건크랜베리 12.5g\",\"초콜릿 > 카카오매스 40g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"견과류의 고소함과 깊은 맛을 활용하여 심심한 맛을 보완하고 나트륨과 당류 사용량을 줄였어요.\",\"instructions\":[\"1. 프라이팬에 물에 불린 귀리,\\n아몬드슬라이스, 피칸을 넣고 살짝\\n볶는다.\",\"2. 볼에 땅콩버터, 클로렐라가루,\\n알룰로스를 넣고 섞다가 코코넛우유,\\n아몬드우유를 넣어 고루 섞는다.\",\"3. 볶은 귀리, 아몬드슬라이스, 피칸과\\n대추채, 카카오닙스, 건크랜베리를 넣고\\n섞어 크런치 토핑을 만든다.\",\"4. 볼에 카카오매스, 다크초콜릿을\\n넣고 전자레인지에서 20~25초 동안\\n녹인다.\",\"5. 팬에 유산지를 깔고 크런치 토핑을\\n넣고 평평하게 편 후 녹인 초콜릿을\\n코팅하듯 바른다.\",\"6. 냉동실에 20분 동안 넣어 굳히고\\n먹기 좋은 크기로 썰어 마무리한다.\"]},{\"id\":\"k884\",\"title\":\"매생이조랭이떡국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102002_1416273602643.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/743-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/743-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/743-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/743-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/743-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/743-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"조랭이떡 140g\",\"매생이 15g\",\"굴 30g\",\"파 5g\",\"다진 마늘 2g\",\"국멸치 3g\",\"국간장 1g\",\"소금 0.2g\",\"물 300g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"매생이를 씻을 때 흘러내려 가지 않도록 고운체나 소쿠리에 받쳐 씻는다. 굴은 맹물에 씻으면 영양분이 없어지므로 찬 소금물에 헹구듯 가볍게 씻으면서 껍질이나 돌을 제거한다.\",\"instructions\":[\"1. 냄비에 물 1컵 반과 국멸치를 넣고 끓여 멸치국물 1컵을 낸다.\",\"2. 매생이는 물로 서너 번 헹궈 고운체에 받쳐 물기를 제거한다.\",\"3. 굴에 소금을 넣고 으깨지지 않도록 살살 주무른 후 물로 서너 번 헹궈 체에 받친다.\",\"4. 파는 얇게 어슷썰고, 마늘은 다진다.\",\"5. 멸치국물에 조랭이떡, 매생이, 굴을 넣고 끓인다.\",\"6.  파와 다진 마늘을 넣고 한소끔 끓이고, 국간장과 소금으로 간하여 마무리한다.\"]},{\"id\":\"k885\",\"title\":\"문어핫바\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102003_1416273603782.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/744-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/744-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/744-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/744-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/744-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/744-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"문어 50g\",\"톳 5g\",\"감자 20g\",\"당근 5g\",\"양파 5g\",\"우리밀가루 20g\",\"다진 마늘 2g\",\"후춧가루 0.1g\",\"토마토케첩 5g\",\"허니머스터드소스 5g\",\"현미유 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"문어반죽이 잘 뭉쳐지지 않으면 밀가루와 물로 농도를 조절한다. 핫바의 모양을 여러 가지로 만들어 응용할 수 있다.\",\"instructions\":[\"1. 손질한 문어를 데친다.\",\"2. 양파와 감자를 적당한 크기로 자르고 톳과 당근은 잘게 다진다.\",\"3. 데친 문어와 양파, 감자를 믹서기에 넣고 간다.\",\"4. 2와 3에 우리밀가루, 다진 마늘, 후춧가루를 넣고 반죽을 치대 직사각형 모양을 만든다.\",\"5. 팬에 현미유를 두르고 4의 문어를 넣고 지진 후 꼬치에 끼운다.\",\"6. 토마토케첩과 허니머스터드소스를 곁들인다.\"]},{\"id\":\"k886\",\"title\":\"매실장아찌와 과매기구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/745-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/745-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/745-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/745-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/745-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/745-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"과메기 60g\",\"매실장아찌 15g\",\"양파 5g\",\"다진 생강 1g\",\"마늘 1g 고추장 10g\",\"양파 5g\",\"다진 마늘 3g\",\"다진 파 3g\",\"간장 2g\",\"매실액 2g\",\"고춧가루 1g\",\"물 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과메기는 기름이 많아 팬에 기름을 두르지 않고 조리한다. 과메기는 생으로도 먹으므로 양념장을 입히는 정도로 팬에서 살짝만 구워낸다.\",\"instructions\":[\"1. 과메기는 꼬리를 잘라낸다.\",\"2. 다진 생강과 마늘즙을 내어 손질한 과메기 위에 뿌린다.\",\"3. 고추장, 다진 마늘, 다진 파, 매실액, 고춧가루, 후춧가루, 물을 섞어 양념장을 만든다.\",\"4. 매실장아찌는 채썬다.\",\"5. 팬에 과메기를 놓고 고추장양념을 발라가며 살짝 굽는다.\",\"6. 매실장아찌를 구운 과메기위에 올려 마무리한다.\"]},{\"id\":\"k887\",\"title\":\"자색고구마호떡\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102008_1416273608450.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/747-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/747-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/747-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/747-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/747-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/747-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀 30g\",\"자색고구마 20g\",\"소금 0.2g\",\"현미유 3g\",\"물 17g 황설탕 7g\",\"검정깨 2g\",\"땅콩 2g\",\"호두 2g\",\"찹쌀가루 0.5g\",\"계피가루 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"찹쌀가루와 고구마에 수분이 적을 경우 반죽에 물을 넣어 농도를 조절한다\",\"instructions\":[\"1. 찹쌀을 3~5시간 불린 후 물기를 제거하고 믹서기에 간다.\",\"2. 고구마는 껍질을 벗기고 작게 썰어 찜통에 넣고 찐 후 으깬다.\",\"3. 검정깨는 믹서기에 갈고, 호두와 땅콩은 굵게 다지고 황설탕과 찹쌀가루를 함께 섞어 호떡소를 만든다.\",\"4. 으깬 고구마에 찹쌀가루를 넣고 반죽을 한다.\",\"5. 4의 반죽을 동그랗게 빚어 3의 호떡소를 넣고 둥글납작하게 만든다.\",\"6. 팬에 현미유를 두르고 호떡을 눌러가며 앞뒤로 굽는다.\"]},{\"id\":\"k888\",\"title\":\"김치밥그라탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102011_1416273611901.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/748-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/748-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/748-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/748-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/748-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/748-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 180\",\"배추김치(줄기부분) 30\",\"양파 20\",\"생 표고버섯 40\",\"방울토마토 200\",\"올리브유 12\",\"간장 4\",\"피자치즈(모짜렐라) 30\",\"다진 실파 5\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"김치는 흰 줄기부분만 사용하면 씹히는 맛이 있어 볶음밥에 더 잘 어울린다. 실파 대신 다진 파슬리나 바질 등의 허브를 뿌려내도 잘 어울린다.\",\"instructions\":[\"1. 김치, 양파, 버섯은 다진다.\",\"2. 방울토마토는 4등분한다.\",\"3. 팬에 올리브유를 두르고 김치, 양파, 버섯, 토마토를 볶는다.\",\"4. 밥을 넣어 볶은 뒤 간장으로 간한다.\",\"5. 3, 4를 그릇에 담고 피자치즈를 올려 전자렌지에 치즈가 녹을 정도로 익힌다.\",\"6. 실파를 뿌려 마무리한다.\"]},{\"id\":\"k889\",\"title\":\"누룽지굴죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102012_1416273612744.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/749-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/749-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/749-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/749-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/749-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/749-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"굴 50\",\"누룽지 50\",\"다시마국물(건다시마 2\",\"물 450)\",\"부추 10\",\"간장 3\",\"참기름 2\",\"파래김 0.5\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다시마국물 만들기: 찬물에 다시마를 넣어 부드러워 지면 10분간 끓여서 국물만 받아 사용한다.\",\"instructions\":[\"1. 굴은 소금물에 흔들어 씻어 굵게 다진다.\",\"2. 부추는 씻어 송송 썬다.\",\"3. 누룽지에 다시마국물을 넣고 2분간 불린 뒤 끓인다.\",\"4. 누룽지가 거의 퍼졌을 때 굴을 넣고 살짝 끓인다.\",\"5. 죽이 퍼지면 부추를 넣고 잠시 끓인다.\",\"6. 그릇에 담고 구운 파래김을 부스러뜨려 얹어낸다.\"]},{\"id\":\"k890\",\"title\":\"콩비지완자탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102014_1416273614929.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/750-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/750-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/750-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/750-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/750-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/750-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"완자: 콩비지 50\",\"다진 돼지고기(기름기 없는 부위) 25\",\"깍두기 5\",\"새우젓 2.5\",\"계란 5\",\"감자전분 10\",\"후추 0.02\",\"다진 파 4\",\"다진 마늘 2 국물: 멸치다시마국물(물 300\",\"건멸치 2.5\",\"건다시마 2)\",\"청경채 20\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"멸치다시마국물 만드는 법: 찬물에 다시마를 넣고 부드러워지면 멸치를 넣고 30분간 끓여 건더기를 건져내고 국물만 받아 사용한다. 먹다 남은 깍두기를 다져 넣으면 음식물 쓰레기를 줄일 수 있다.\",\"instructions\":[\"1. 콩비지를 체에 받혀 물기를 제거한다.\",\"2. 깍두기와 새우젓을 잘게 다진다.\",\"3. 1에 다진 돼지고기, 깍두기, 새우젓, 계란, 전분, 후추, 파, 마늘을 넣고 치댄다.\",\"4. 치댄 반죽을 한입 크기로 동그랗게 완자를 빚는다.\",\"5. 냄비에 멸치다시마 국물을 넣고 끓으면 완자를 넣어 거품을 걷어가며 끓인다.\",\"6. 완자가 익어서 떠오르면 청경채, 대파, 마늘을 넣고 살짝 끓여 국간장으로 간하여 불에서 내린다.\"]},{\"id\":\"k891\",\"title\":\"돼지갈비구이와 백김치와인조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102015_1416273615804.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/751-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/751-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/751-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/751-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/751-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/751-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 돼지등갈비 200(갈비살 70)\",\"물 500\",\"된장 2\",\"대파 10\",\"생강 3\",\"올리브유 4\",\"후추 0.02\",\"소금 0.38 김치조림: 백김치 60\",\"적포도주 40\",\"맛술 15\",\"꿀 3\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시어진 백김치와 마시고 남은 와인을 활용하면 음식물 쓰레기를 줄일 수 있다. 김치를 조리고 남은 소스에 구운 갈비를 넣어 살짝 조려서 소스 맛이 고기에 배게 하여 먹어도 맛있다.\",\"instructions\":[\"1. 냄비에 물을 넣고 된장을 풀어 대파, 생강을 넣고 끓인다.\",\"2. 물이 끓으면 돼지갈비를 넣고 5분간 삶는다.\",\"3. 백김치는 5cm 길이로 자른다.\",\"4. 적포도주를 냄비에 넣고 불에 올려 알코올을 날려준 뒤 김치, 맛술, 꿀을 넣고 맛이 배도록 졸인다.\",\"5. 삶아 낸 등갈비에 소금을 뿌리고 올리브유를 발라 팬에 구워낸다.\",\"6. 구운 갈비에 백김치 와인조림을 곁들여 낸다.\"]},{\"id\":\"k892\",\"title\":\"오징어오곡밥순대\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102016_1416273616990.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/752-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/752-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/752-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/752-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/752-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/752-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 오징어 30\",\"오곡밥 30\",\"데친 취나물 10\",\"간장 3\",\"다진 마늘 2.5\",\"후추 0.01\",\"참기름 1 소스: 데쳐서 다진 취나물 5\",\"청양고추 2\",\"간장 1.5\",\"참기름 1\",\"설탕 1\",\"다진 마늘 1\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"먹다 남은 취나물이 있으면 따로 간 하지 않고 잘게 다져서 순대 속재료로 넣으면 된다. 취나물 대신 시래기 나물 등 다른 나물을 넣어도 맛있다. 오징어 속을 채울 때 어느 정도 여유를 두고 채워야 쪘을 때 속 재료가 터져 나오지 않는다.\",\"instructions\":[\"1. 오징어는 다리를 떼 내서 내장과 눈을 제거하고, 데친 취나물은 물기를 짜내고 다진다.\",\"2. 오곡밥에 다진 취나물, 간장, 마늘, 후추, 참기름을 넣어 고루 섞는다.\",\"3. 오징어 몸통에 양념한 밥을 넣어 이쑤시개로 끝을 고정시킨다.\",\"4. 김이 오른 찜통에 오징어를 넣고 3분간 쪄낸다.\",\"5. 소스 재료를 섞어 취나물된장소스를 만든다.\",\"6. 쪄낸 오징어순대를 썰어 접시에 담고 소스를 곁들여 낸다.\"]},{\"id\":\"k893\",\"title\":\"코다리 양념구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102018_1416273618224.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/753-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/753-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/753-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/753-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/753-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/753-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 코다리 50\",\"누룽지가루 7.5\",\"콩기름 4\",\"다진 홍고추 2\",\"다진 실파 2 양념장: 간장 3\",\"설탕 1.5\",\"맛술 1.25\",\"고운 고추가루 1\",\"간 양파 5\",\"다진 마늘 1\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"4단계까지 준비해서 냉동해 두고 필요할 때 해동하여 양념장만 발라 구우면 바쁠 때요긴한 밑반찬이 된다. 부스러기 누룽지를 가루를 내어 튀김옷에 섞어 넣으면 고소한 맛이 한층 더해진다.\",\"instructions\":[\"1. 코다리는 배를 갈라 길이로 2등분하여 뼈를 제거한다.\",\"2. 손질한 코다리를 반으로 잘라 안쪽에 누룽지 가루를 묻힌다.\",\"3. 분량의 재료를 섞어 양념장을 만든다.\",\"4. 팬에 기름을 두르고 코다리를 굽는다.\",\"5. 코다리에 양념장을 발라 다시 한번 살짝 굽는다.\",\"6. 다진 홍고추와 실파를 뿌려 마무리한다.\"]},{\"id\":\"k894\",\"title\":\"대구버섯구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102019_1416273619379.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/754-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/754-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/754-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/754-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/754-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/754-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 대구살 60\",\"소금 0.3\",\"흰후추 0.02\",\"찹쌀가루 12\",\"새송이버섯 40\",\"마늘 2\",\"올리브유 6\",\"베이비채소 5 소스: 마요네즈 4\",\"와사비 갠 것1\",\"레몬즙 2\",\"후추 0.02\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"여러 가지 버섯을 섞어 사용하면 다양한 색감과 향을 즐길 수 있다.\",\"instructions\":[\"1. 대구살에 소금, 흰후추를 뿌려 밑간 한 뒤 찹쌀가루를 가볍게 묻힌다. (a)\",\"2. 버섯과 마늘을 얇게 썬다. (b)\",\"3. 팬에 기름을 두르고 마늘을 볶아 향을 낸 뒤 마늘은 따로 건져두고 버섯을 굽는다. (c)\",\"4. 팬에 기름을 두르고 1을 앞뒤로 노릇하게 굽는다. (d)\",\"5. 분량의 재료를 섞어 소스를 만든다.\",\"6. 접시에 대구, 버섯, 마늘을 켜켜이 담아 소스를 뿌리고 베이비채소를 곁들여 낸다.\"]},{\"id\":\"k895\",\"title\":\"잔멸치땅콩볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102020_1416273620679.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/755-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/755-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/755-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/755-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/755-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/755-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"땅콩 10\",\"잔멸치 10\",\"맛술 2.5\",\"올리브유 2\",\"건홍고추 1\",\"참기름 1\",\"콩기름 1\",\"다진 마늘 1\",\"굴소스 0.3\",\"두반장 1\",\"물엿 6\",\"통깨 0.5\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치는 약불에서 천천히 볶아야 딱딱하지 않고 부드럽게 볶아진다. 땅콩을 물에 불리면 물기를 머금어 질감이 훨씬 부드러워 진다.\",\"instructions\":[\"1. 멸치를 마른팬에 넣고 볶는다.\",\"2. 살짝 볶아낸 멸치에 올리브유와 맛술을 넣고 부드러워질 때까지 볶는다.\",\"3. 땅콩을 찬물에 20분 담갔다 체에 건져 물기를 뺀다.\",\"4. 건고추는 송송 썬다.\",\"5. 팬에 올리브유, 참기름, 콩기름을 섞어 두르고 다진 마늘을 넣어 향을 낸 후 땅콩과 고추를 넣어 볶는다.\",\"6. 볶은 멸치와 굴소스, 두반장, 물엿을 넣고 고루 섞은 다음 통깨를 뿌려낸다.\"]},{\"id\":\"k896\",\"title\":\"밥 샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053753_1416213473486.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1016-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1016-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1016-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1016-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1016-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1016-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"맛살 50g\",\"마요네즈 3g\",\"오이 25g\",\"밥 120g\",\"치즈슬라이스 20g\",\"검은깨 2g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오이를 고추장양념이나 간장양념으로 변형시켜도 좋다.\",\"instructions\":[\"1. 맛살을 잘게 다져 마요네즈와 소금을 넣고 버무린다.\",\"2. 오이는 다져서 소금을 뿌려 놓았다가 면보에 짜서 수분을 제거한 뒤 마요네즈에 버무린다.\",\"3. 밥에 소금을 넣어 버무린다.\",\"4. 네모난 플라스틱 통에 랩을 깐다.\",\"5. 4에 밥, 치즈, 밥, 오이나 맛살, 밥 순서로 얹어 꼭꼭 누른다.\",\"6. 랩을 통째로 꺼내 칼로 조심스럽게 썰어 검은깨로 장식한다.\"]},{\"id\":\"k897\",\"title\":\"버섯을 넣은 가지 라자냐\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053754_1416213474657.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1017-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1017-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1017-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1017-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1017-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1017-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기다진것 12g\",\"느타리벗서 15g\",\"표고버섯 10g\",\"새송이버섯 15g\",\"가지 15g\",\"밀가루 6g\",\"버터 0.5g\",\"우유 25g\",\"파마산치즈 3g\",\"모짜렐라 치즈 7g\",\"토마토소스 20g\",\"바질 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라자냐에 돼지고기 대신 닭고기를 사용해도 좋다.\",\"instructions\":[\"1. 가지에 세로로 칼집을 넣어 소금을 뿌린다.\",\"2. 표고버섯, 느타리버섯은 채 썰고 새송이버섯은 세로로 자른다.\",\"3. 돼지고기를 곱게 다진 뒤 볶는다.\",\"4. 팬에 버터를 넣어 녹으면 밀가루를 넣고 볶아서 루를 만든 뒤 우유를 넣어 화이트소스를 만든다.\",\"5. 오븐용기에 화이트소스를 깔고 그 위에 가지를 올린 뒤 가지 사이에 버섯, 토마토소스, 화이트소스, 버섯을 넣는다.\",\"6. 남은 화이트소스와 치즈, 빵가루 순으로 얹고 180℃로 예열된 오븐에서 윗면이 노릇한 색이 나도록 굽는다.\"]},{\"id\":\"k898\",\"title\":\"생선찜 채소말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053756_1416213476798.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1019-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1019-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1019-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1019-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1019-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1019-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"흰살 생선 70g\",\"죽순 20g\",\"청피망 15g\",\"홍피망 15g\",\"건표고버섯 10g\",\"전분 5g\",\"치즈슬라이스 10g\",\"참기름 적당량\",\"소금 적당량\",\"흰후춧가루 적당량[소스] 잣 3g\",\"물 4g\",\"설탕 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생선을 말 때는 껍질부분이 안으로 들어가게 말아야 보기에도 좋고 잘 풀러지지 않는다.\",\"instructions\":[\"1. 흰 살 생선을 얇게 포를 떠서 소금과 흰 후춧가루로 밑간을 한 뒤 생선살의 물기를 제거한다.\",\"2. 죽순은 5cm 길이로 채 썬 뒤 끓는 물에 데쳐 소금과 참기름으로 무치고 청, 홍피망은 같은 길이로 채썰어 팬에 볶으면서 소금 간 한다.\",\"3. 건 표고버섯을 불려서 얇게 포를 떠 채 썬 뒤 소금과 참기름으로 무쳐서 볶고 슬라이스 치즈도 같은 길이로 채 썬다.\",\"4. 1의 생선살을 2장씩 겹쳐 놓고 전분을 위에 뿌려 준비한 속 재료를 올려 돌돌 말아준 뒤 겉면에서 전분을 묻혀 찜통에서 8분간 찐다.\",\"5. 믹서에 잣과 물, 설탕, 소금, 레몬즙, 간장을 넣고 뽀얗게 즙이 나도록 소스를 만든다.\",\"6. 완성된 찜에 소스를 곁들여 낸다.\"]},{\"id\":\"k899\",\"title\":\"쇠고기말이 쌈밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053757_1416213477943.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1020-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1020-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1020-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1020-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1020-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1020-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기살코기 40g\",\"당근 10g\",\"오이피클 10g\",\"양파 15g\",\"깻잎 10g\",\"밥 50g\",\"전분 6g\",\"식용유 적당량[밥밑간]깨소금 2g\",\"참기름 2g\",\"소금 적당량[쇠고기밑간] 간장 2g\",\"청주 2g\",\"참기름 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쇠고기를 너무 익히게 되면 질겨지므로 조심해야한다.\",\"instructions\":[\"1. 소고기는 살코기로 손바닥 크기로 얇게 저며 양념에 재운다.\",\"2. 당근과 양파는 채 썰어 팬에 볶으면서 소금으로 간한다.\",\"3. 오이피클은 물기를 제거하여 채 썰고 깻잎은 깨끗이 씻어 물기를 뺀다.\",\"4. 밥을 고슬고슬하게 지어 밑간을 하고 준비한 당근과 양파, 오이피클을 넣고 잘 섞어 한 입 크기로 뭉쳐 놓는다.\",\"5. 밑간한 소고기를 넓게 펴고 전분을 뿌린 뒤 깻잎을 깔고 준비한 밥을 올려 싼다.\",\"6. 팬에 식용유를 두르고 말아놓은 쌈밥을 굴려가며 소고기가 익을 때 까지 익힌다.\"]},{\"id\":\"k900\",\"title\":\"스테이크 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053759_1416213479021.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1021-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1021-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1021-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1021-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1021-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1021-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기등심 80g\",\"로메인 30g\",\"워터크레스 2g\",\"래디쉬 5g\",\"방울토마토 10g\",\"레드어니언 8g\",\"발사믹식초 4g\",\"올리브오일 1g\",\"소금적당량\",\"통후추 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"발사믹 식초가 없는 경우 사과식초나 양조식초로 대용해도 가능하다.\",\"instructions\":[\"1. 소고기등심에 소금, 후추로 간하고 팬에서 기호에 따라 굽는다. (스테이크 굽기 정도는 기호에 따라 조절한다.)\",\"2. 양파는 얇게 링으로 썰고 로메인은 적당한 크기로 찢고 래디쉬도 얇게 썰어 찬 물에 담궈둔다.\",\"3. 발사믹 식초에 올리브오일, 소금, 후추를 넣고 소스를 만든다. (기호에 따라 양파 다진 것 등을 첨가할 수 있다.)\",\"4. 2를 건져내 물기를 제거하고 소금, 후추로 간을 한다.\",\"5. 스테이크를 슬라이스 하여 접시에 앞 쪽에 담는다.\",\"6. 준비된 야채에 드래싱을 넣고 섞은 뒤 스테이크 옆에 담는다.\"]},{\"id\":\"k901\",\"title\":\"씨앗죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053801_1416213481209.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1023-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1023-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1023-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1023-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1023-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1023-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 30g\",\"참깨 3g\",\"통아몬드 4g\",\"땅콩 4g\",\"호박씨 4g\",\"물 90g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"죽을 끓일 때 견과류 간 것을 나중에 넣어야 죽이 묽어지지 않는다.\",\"instructions\":[\"1. 쌀을 깨끗이 씻어 5시간 정도 불린다.\",\"2. 불린 쌀을 절구에 넣어 쌀알이 반 정도 부서지도록 간다.\",\"3. 참깨, 아몬드, 땅콩, 호박씨를 믹서기에 간다.\",\"4. 냄비에 쌀과 물을 넣고 끓인다.\",\"5. 쌀알이 익으면 3의 씨앗가루를 넣고 끓인다.\",\"6. 소금간을 하고 준비한 그릇에 담아낸다.\"]},{\"id\":\"k902\",\"title\":\"오븐에 구운 또띠아 칩과 아보카도 딥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053802_1416213482302.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1024-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1024-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1024-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1024-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1024-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1024-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"또띠아 25g\",\"양파다진것 5g\",\"할라피뇨다진것 2g\",\"마늘다진것 3g\",\"아보카도 12g\",\"라임주스 3g\",\"토마토 30g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라임 쥬스 대신에 레몬즙이나 오렌지 쥬스를 이용할 수 있다.\",\"instructions\":[\"1. 또띠아는 6등분 한다.\",\"2. 양파, 할라피뇨, 마늘을 잘게 다진다.\",\"3. 아보카도는 껍질을 제거하고 토마토는 씨를 제거하여 각각 1cm 주사위모양으로 자른다.\",\"4. 170℃로 예열한 오븐에 또띠아를 넣어 바삭하게 굽는다.\",\"5. 볼에 2를 넣고 잘 섞어 페이스트를 만들다가 아보카도를 함께 넣고 으깬 후 토마토를 넣고 라임주스, 소금으로 맛을 낸다.\",\"6. 구워 낸 또띠아 칩을 찍어 먹을 수 있도록 아보카도딥을 작은 그릇에 담아낸다.\"]},{\"id\":\"k903\",\"title\":\"참치 쇠고기 양상추 쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053804_1416213484318.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1026-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1026-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1026-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1026-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1026-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1026-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기 25g\",\"밥 60g\",\"상추 5g\",\"캔참치 5g[밑간] 후추약간\",\"달걀흰자 10g\",\"간장 3g\",\"설탕 2g\",\"전분 2g[참치양념] 마요네즈 3g\",\"양파다진것 3g\",\"샐러리다진것 2g\",\"소금적당량\",\"설탕 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"매운맛을 좋아하는 경우 마요네즈에 약간의 고추장을 첨가해도 좋다.\",\"instructions\":[\"1. 소고기는 소금, 후추로 밑간을 하고 실파는 송송 썬다.\",\"2. 참치는 기름을 제거하고 양파, 셀러리, 마요네즈, 소금, 후추, 설탕을 넣고 양념한다.\",\"3. 상추는 작게 다듬어 얼음물에 담근다.\",\"4. 팬에 기름을 두르고 다진 마늘을 넣고 볶다가 밑간한 소고기를 넣고 볶는다.\",\"5. 4에 기호에 맞게 참기름과 실파를 넣는다.\",\"6. 물기를 제거한 상추에 밥 한 숟가락을 놓고 볶은 소고기, 참치, 마요네즈, 소스 순으로 얹는다.\"]},{\"id\":\"k904\",\"title\":\"치킨 쇠고기 땅콩소스 꼬치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053805_1416213485286.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1027-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1027-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1027-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1027-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1027-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1027-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 30g\",\"쇠고기 등심 30g\",\"간장 3g\",\"카레가루 2g\",\"땅콩버터 3g\",\"참기름 0.5g\",\"올리브오일 2g\",\"설탕 1.5g\",\"생강다진것 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해산물을 이용할 수도 있다. 이럴 경우 소스에 레몬주스를 약간 첨가해 준다.\",\"instructions\":[\"1. 닭가슴살과 소고기안심을 먹기 좋은 크기로 자른다.\",\"2. 간장, 카레가루, 땅콩버서, 참기름, 올리브오일, 설탕, 다진 생강을 섞어 소스를 만든다.\",\"3. 꼬치에 1을 번갈아 끼운다.\",\"4. 고기를 끼운 꼬치에 2의 소스를 바른다.\",\"5. 오븐을 176℃로 예열한다.\",\"6. 예열된 오븐에 소스를 바른 꼬치를 구워준다.\"]},{\"id\":\"k905\",\"title\":\"커리향이 들어간 치킨샐러드 샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053806_1416213486379.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1028-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1028-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1028-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1028-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1028-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1028-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살 20g\",\"올리브오일 0.5g\",\"마요네즈 2g\",\"식빵 40g\",\"아몬드 3g\",\"건포도 2g\",\"카레가루 0.5g\",\"레몬주스 2g\",\"바질약간\",\"소금적당량\",\"후추적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"치킨 샐러드에 수분이 생기지 않게 조심해야 샌드위치가 눅눅해 지지 안는다.\",\"instructions\":[\"1. 닭가슴살에 소금, 후추로 간을 한다.\",\"2. 팬에 기름을 두르고 닭가슴살을 굽는다.\",\"3. 구워 낸 닭가슴살을 다져서 볼에 담는다.\",\"4. 올리브오일, 카레가루, 레몬주스, 건포도, 아몬드, 마요네즈를 3에 넣고 섞는다.\",\"5. 식빵을 팬에 바삭하게 굽는다.\",\"6. 식빵에 치킨 샐러드를 얹은 뒤 남은 식빵으로 덮고, 사방을 잘라낸다.\"]},{\"id\":\"k906\",\"title\":\"클럽 샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053808_1416213488663.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1030-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1030-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1030-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1030-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1030-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1030-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"식빵 40g\",\"마요네즈 2g\",\"삶은달걀 15g\",\"양상추 8g\",\"닭가슴살 13g\",\"토마토 20g\",\"치즈슬라이스 4g\",\"슬라이스햄 4g\",\"베이컨 4g\",\"소금적당량\",\"후추적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"닭가슴살 대신 참치 통조림을 이용할 수 있다.\",\"instructions\":[\"1. 식빵은 앞뒤로 바삭하게 굽는다.\",\"2. 양상추는 뜯어서 찬물에 담가 두고 토마토는 얇게 슬라이스 하고 달걀도 삶아 egg slicer로 자른다.\",\"3. 닭가슴살에 소금, 후추로 간을 한 뒤 팬에서 익히고 햄과 베이컨도 살짝 굽는다.\",\"4. 식빵 한 면에 마요네즈를 바른 뒤 양상추, 베이컨, 토마토를 얹고 다시 식빵 양면에 마요네즈를 바르고 토마토 위에 얹는다.\",\"5. 그 위에 양상추, 치즈, 햄, 달걀, 닭고기를 올린 다음 나머지 빵 한 면에 마요네즈를 바른다.\",\"6. 빵 칼로 샌드위치의 사방의 테두리를 잘라내고 대각선으로 먹기 좋게 썬다.\"]},{\"id\":\"k907\",\"title\":\"토마토 야채 오븐구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053809_1416213489835.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1031-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1031-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1031-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1031-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1031-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1031-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 20g\",\"고구마 20g\",\"오릴브오일 2g\",\"홍피망 15g\",\"당근 12g\",\"후추적당량\",\"소금적당량\",\"레드어니언 12g\",\"토마토 25g\",\"돼지호박 12g\",\"파마산치즈 2g\",\"빵가루 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"집에 남아있는 야채의 종류에 따라 여러 가지 야채를 더 첨가해도 좋다.\",\"instructions\":[\"1. 양파는 링으로 자르고 나머지 야채는 0.5cm 주사위모양으로 잘라 볼에 담는다.\",\"2. 볼에 담긴 야채에 소금을 뿌려 골고루 간이 베이도록 섞는다.\",\"3. 오븐용기에 야채를 가지런히 깔고 올리브 오일을 뿌리뒤 소금과 후추로 간을 한다.\",\"4. 그릇에 파마산 치즈와 빵가루를 넣고 잘 섞는다.\",\"5. 3의 야채 위에 4를 뿌려 덮는다.\",\"6. 180℃로 예열된 오븐에 굽는다.\"]},{\"id\":\"k908\",\"title\":\"시금치비트무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102021_1416273621709.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/756-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/756-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/756-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/756-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/756-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/756-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 시금치(포항초) 30\",\"적양파 10\",\"비트 10 드레싱: 발사믹식초 5\",\"올리고당 3\",\"올리브유 1\",\"소금 0.38\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"발사믹식초는 적포도주를 발효시켜 만든 식초로 샐러드 드레싱에 많이 이용된다. 비트는 색이 쉽게 우러나 자칫 음식이 지저분해 보일 수 있으므로 찬물에 충분히 담갔다가 사용한다.\",\"instructions\":[\"1. 포항초는 깨끗이 씻어 잎을 떼어준다.\",\"2. 적양파는 얇게 슬라이스한다.\",\"3. 비트는 채 썰어 찬물에 담근다.\",\"4. 분량의 재료를 섞어 양념장을 만든다\",\"5. 포항초, 적양파, 비트의 물기를 제거한다.\",\"6. 물기를 제거한 포항초, 적양파, 비트를 소스에 버무려 낸다.\"]},{\"id\":\"k909\",\"title\":\"해초탕수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102023_1416273623333.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/757-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/757-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/757-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/757-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/757-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/757-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"불린 미역(혹은 물미역) 7\",\"파래(생것) 10\",\"김 1.3\",\"양파 7\",\"유자청 15\",\"물 20\",\"다진 파 4\",\"다진 마늘 1\",\"감자전분 10\",\"계란 7\",\"콩기름 4\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"눅눅해진 김이나 미역을 이용하면 음식물 쓰레기를 줄일 수 있다.\",\"instructions\":[\"1. 미역과 파래는 깨끗이 씻어 물기를 짜서 잘게 다지고, 김은 살짝 구워 부스러뜨린다.\",\"2. 양파와 유자청 건더기는 잘게 다진다.\",\"3. 1과 2를 합해 감자전분과 달걀을 넣어 반죽한다.\",\"4. 반죽을 동그랗게 뭉쳐 기름에 튀긴다.\",\"5. 유자청 국물에 물을 섞어 팬에 넣고 걸쭉하게 끓여 소스를 만든다.\",\"6. 해초튀김에 소스를 곁들여 낸다.\"]},{\"id\":\"k910\",\"title\":\"호두떡볶이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102026_1416273626065.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/759-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/759-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/759-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/759-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/759-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/759-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"호두 15\",\"올리브유 4\",\"떡볶이 떡 80\",\"올리고당 20\",\"간장 1.5\",\"검정깨(볶은 것) 0.5\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"떡을 볶을 때는 약불로 볶아야 간장이 타지 않는다. 올리고당 대신 꿀을 넣어도 맛있다.\",\"instructions\":[\"1. 호두는 굵게 다진다.\",\"2. 다진 호두는 마른 팬에 살짝 볶는다.\",\"3. 팬에 기름을 두르고 떡이 말랑해질 때까지 볶는다.\",\"4. 떡이 익으면 올리고당과 간장을 넣어 살짝 볶는다.\",\"5. 호두를 넣어 맛이 어우러지도록 조금 더 볶는다.\",\"6. 검은깨를 뿌려내 완성한다.\"]},{\"id\":\"k911\",\"title\":\"죽순콩나물밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102026_1416273626970.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/760-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/760-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/760-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/760-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/760-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/760-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 쌀 90\",\"콩나물 30\",\"삶은 죽순 40\",\"녹차 우린 물 90 양념장: 간장 4\",\"고춧가루 0.5\",\"설탕 1\",\"깨소금 0.5\",\"다진파 2.5\",\"다진마늘 1.25\",\"청양고추 2.5\",\"홍고추 1.25\",\"맛술 3.75\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생 죽순은 쌀뜨물에 10분 간 삶아 길이로 반을 갈아 속에 낀 석회를 제거하고 한다. 생 죽순이 없을 때는 죽순 통조림을 끓는 물에 살짝 데쳐 사용한다. 콩나물을 솥의 맨 밑에 깔면 밥 물 맞추기가 쉽다. 죽순과 콩나물에서 수분이 나오므로 밥물은 평소의 2/3양으로 맞춘다.\",\"instructions\":[\"1. 콩나물은 깨끗이 씻어 꼬리를 뗀다.\",\"2. 죽순은 빗살무늬를 살려 한입 크기로 얄팍하게 썬다.\",\"3. 양념장 재료를 모두 섞어 양념장을 만든다.\",\"4. 솥에 씻은 쌀을 넣고 콩나물과 죽순을 올리고 녹차 우린 물을 부어 밥을 짓는다.\",\"5. 밥이 다 되면 뜸을 들여준다.\",\"6. 밥을 푸고 양념장을 넣어 비벼 먹는다.\"]},{\"id\":\"k912\",\"title\":\"멍게비빔밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102027_1416273627985.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/761-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/761-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/761-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/761-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/761-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/761-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"비빔밥: 쌀밥 210\",\"멍게살 50\",\"부추 10\",\"무순 5\",\"김 0.5\",\"참기름 4\",\"통깨 1.5 양념장: 고추장 5\",\"설탕 1\",\"레몬즙 3\",\"간 양파 3\",\"매실액 3\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멍게살을 다져서 냉동실에 넣어 살짝 얼렸다가 넣어도 맛있다. &#8226; 멍게 향이 강할 때는 쑥갓을 넣어 비비면 강한 향이 줄어든다.\",\"instructions\":[\"1. 멍게는 꼭지를 따고 껍질을 벗겨 한입 크기로 썬다.\",\"2. 부추는 2cm 길이로 썬다.\",\"3. 김도 부추와 같은 길이로 가늘게 채 썬다.\",\"4. 양념장 재료를 모두 섞어 양념장을 만든다.\",\"5. 손질한 멍게에 참기름을 넣어 가볍게 버무린다.\",\"6. 그릇에 밥을 담고 부추, 무순, 멍게, 김, 통깨를 올리고 양념장을 넣어 비벼 먹는다.\"]},{\"id\":\"k913\",\"title\":\"키조개샤브샤브\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102029_1416273629141.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/762-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/762-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/762-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/762-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/762-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/762-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 키조개관자 60\",\"당근 10\",\"참나물 10\",\"애호박 10\",\"표고버섯 20\",\"느타리버섯 30\",\"팽이버섯 30\",\"다시마 국물 200(물 300\",\"다시마 1\",\"대파 5) 소스: 간장 4.5\",\"사과식초 2.5\",\"올리고당 3.5\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스 재료를 끓일 때 양파와 마늘을 넣으면 달큰한 맛과 마늘향이 가미된 소스가 된다.\",\"instructions\":[\"1. 냄비에 물, 건다시마, 대파를 넣고 약불에서 30분간 맛이 우러나게 끓인다.\",\"2. 체에 걸러 다시마 국물을 만든다.\",\"3. 키조개 관자를 얇게 자른다.\",\"4. 당근은 껍질을 벗기고 채소와 버섯은 깨끗이 씻어 한입 크기로 자른다.\",\"5. 소스 재료를 냄비에 넣고 약불에서 5분간 끓여 양념장을 만든다.\",\"6. 샤브샤브 냄비에 1을 넣고 끓으면 키조개 관자, 채소, 버섯을 넣고 살짝 익혀 소스에 찍어 먹는다.\"]},{\"id\":\"k914\",\"title\":\"가자미쑥국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102030_1416273630141.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/763-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/763-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/763-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/763-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/763-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/763-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가자미 50\",\"모시조개 15\",\"쑥 20\",\"물 200\",\"된장 9\",\"대파 4\",\"들깨가루 6\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"가자미 대신 도다리를 넣으면 맛이 한결 담백하다.\",\"instructions\":[\"1. 가자미는 비늘, 내장, 지느러미를 제거하고 3등분 한다.\",\"2. 물에 된장을 풀어 끓인다.\",\"3. 가자미와 모시조개를 넣고 20분 더 끓인다.\",\"4. 쑥을 넣고 5분간 팔팔 끓인다.\",\"5. 대파와 들깨가루를 넣어 살짝 끓여낸다.\",\"6. 그릇에 가자미, 쑥을 우선 담고 국믈을 곁에 부어주며 담아낸다.\"]},{\"id\":\"k915\",\"title\":\"달래바싹불고기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102031_1416273631031.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/764-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/764-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/764-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/764-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/764-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/764-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 쇠고기등심 60\",\"달래 5\",\"올리브유 5 양념장: 간장 4\",\"설탕 3\",\"다진 양파 15\",\"다진 마늘 2\",\"후추 0.01\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"불고기를 익힐 때 중불에서 익혀야 속까지 골고루 익는다.  바싹불고기를 샌드위치 속으로 넣어 먹어도 맛있다.\",\"instructions\":[\"1. 달래를 3cm 길이로 썬다.\",\"2. 양념장 재료를 모두 섞어 양념장을 만든다.\",\"3. 소고기에 달래와 양념장을 넣고 간이 배도록 잘 주무른다.\",\"4. 기름 두른 팬에 양념한 고기를 한 덩이씩 떼서 모양을 잡아준다.\",\"5. 뭉친 고기는 앞뒤로 고루 익혀낸다.\",\"6. 그릇에 담아 마무리 한다.\"]},{\"id\":\"k916\",\"title\":\"오리고기곰피쌈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102033_1416273633876.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/765-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/765-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/765-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/765-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/765-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/765-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 오리고기 50g\",\"곰피 20g\",\"무순 10g\",\"올리브유 4 소스: 오미자 액기스 1g\",\"고추장 6g\",\"설탕 2g\",\"식초 2.5g\",\"물 2.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금에 절여서 시판되는 곰피는 찬물에 충분히 담가 소금기를 제거하고 사용한다.\",\"instructions\":[\"1. 곰피를 데쳐 찬물에 헹군다.\",\"2. 헹군 곰피는 10cm길이로 자른다.\",\"3. 오미자액기스, 고추장, 설탕, 식초, 물을 섞어 오미자 초고추장 소스를 만든다.\",\"4. 팬에 오리고기를 굽는다.\",\"5. 곰피에 오리구이와 무순을 올리고 오미자 초고추장을 발라 돌돌 말아준다.\",\"6. 그릇에 담아 완성한다.\"]},{\"id\":\"k917\",\"title\":\"바지락수제비볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102034_1416273634751.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/766-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/766-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/766-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/766-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/766-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/766-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 밀가루 50\",\"물 25\",\"바지락 100(바지락살 50)\",\"양파 20\",\"마늘 5\",\"청양고추 5\",\"실파 5\",\"콩기름 4\",\"맛술 5\",\"참기름 2 양념장: 물 25\",\"굴소스 1.5\",\"간장 1\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수제비 반죽을 만들어 랩에 싸서 30분 정도 숙성시켰다 사용하면 더욱 쫀득하다. 먹다 남은 수제비 반죽으로 만들면 음식물 쓰레기도 줄이고 시간도 절약된다.\",\"instructions\":[\"1. 밀가루에 물을 넣고 수제비 반죽을 만든다.\",\"2. 반죽을 끓는 물에 떼어 넣어 익혀 체에 받쳐둔다.\",\"3. 양파는 굵게 채 썰고 마늘은 편으로 청양고추는 어슷 썰고 실파는 송송 썬다.\",\"4. 분량의 재료를 섞어 양념장을 만든다.\",\"5. 팬에 기름을 두르고 마늘을 볶다 바지락과 맛술을 넣어 볶는다.\",\"6. 양파, 청양고추를 넣어 볶은 뒤 양념장, 수제비, 참기름을 넣어 살짝 볶는다.\"]},{\"id\":\"k918\",\"title\":\"민들레무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102036_1416273636697.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/767-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/767-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/767-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/767-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/767-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/767-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 민들레 15\",\"양파 10 양념: 고춧가루 1.25\",\"깨소금 1\",\"소금 0.25\",\"다진 파 1.25\",\"다진 마늘 0.5\",\"매실액 4.5\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기구이에 곁들여 먹으면 민들레의 쌉싸레한 맛과 잘 어울린다. 민들레가 숨이 죽지 않도록 상에 내기 직전에 무친다.\",\"instructions\":[\"1. 민들레는 흐르는 물에 씻는다.\",\"2. 깨끗이 씻은 민들레는 한입 크기로 뜯고 물기를 살짝 제거해준다.\",\"3. 양파는 얇게 채썬다.\",\"4. 양념장 재료를 모두 섞어 양념장을 만든다.\",\"5. 양파와 민들레를 볼에 담고 양념을 넣어 가볍게 무쳐낸다.\",\"6. 그릇에 담아 마무리 한다.\"]},{\"id\":\"k919\",\"title\":\"취나물들깨무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102037_1416273637730.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/768-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/768-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/768-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/768-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/768-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/768-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"참취 70g\",\"간장 1.5g\",\"소금 0.5g\",\"다진 파 2.25g\",\"다진 마늘 1g\",\"들기름 3g\",\"거피들깨가루 6g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"어린 취나물은 줄기째 쓰고 늙은 취나물은 줄기를 제거하고 잎만 사용한다.\",\"instructions\":[\"1. 취나물을 끓는 물에 살짝 데친다.\",\"2. 데친 취나물은 찬물에 헹군다.\",\"3. 취나물을 가볍게 짜서 물기를 제거하고 5cm 길이로 자른다.\",\"4. 나머지 재료를 모두 섞어 양념장을 준비한다.\",\"5. 볼에 취나물을 담고 양념장을 넣어 조물조물 무쳐낸다.\",\"6. 무쳐낸 나물을 그릇에 담아 마무리한다.\"]},{\"id\":\"k920\",\"title\":\"토마토소박이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102038_1416273638917.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/769-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/769-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/769-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/769-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/769-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/769-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 토마토 70\",\"영양부추 5\",\"적양파 8 양념: 까나리액젓 2.5\",\"고춧가루 0.6\",\"소금 0.5\",\"통깨 1\",\"설탕 2\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"염도가 낮으므로 하루 이내에 먹는 것이 좋다. 토마토는 너무 무르지 않고 약간 단단한 것이 좋다.\",\"instructions\":[\"1. 재료를 깨끗이 씻어낸다.\",\"2. 토마토는 끝이 떨어지지 않게 6등분 한다.\",\"3. 영양부추는 1cm 길이로 썬다.\",\"4. 적양파는 곱게 채 썬다.\",\"5. 영양부추와 적양파에 양념을 넣고 버무려 소를 만든다.\",\"6. 토마토에 소를 넣어 30분 정도 냉장고에 두었다가 먹는다.\"]},{\"id\":\"k921\",\"title\":\"풋마늘오징어김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102039_1416273639916.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/770-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/770-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/770-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/770-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/770-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/770-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료: 풋마늘 20\",\"물 200\",\"건오징어 5 양념: 밀가루 1.25\",\"물 20\",\"소금 0.25\",\"고춧가루 0.6\",\"새우젓 0.75\",\"멸치액젓 0.2g\",\"설탕 1\",\"통깨 0.5\",\"생강즙 0.25\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시어진 풋마늘 김치에 밀가루를 넣어 전을 부치면 다른 재료를 첨가하지 않아도 맛있는 부침이 된다.\",\"instructions\":[\"1. 풋마늘을 깨끗이 씻어 5cm 길이로 썬다.\",\"2. 물에 풋마늘을 30분 정도 담가 매운맛을 뺀다.\",\"3. 오징어를 1cm x 5cm 크기로 썬다.\",\"4. 밀가루와 물을 섞어 약불에서 풀을 쑤어 차게 식힌다.\",\"5. 풀에 나머지 양념장 재료를 모두 넣어 섞는다.\",\"6. 풋마늘과 오징어에 양념장을 넣고 버무려 즉석에서 먹거나 살짝 익혀 먹는다.\"]},{\"id\":\"k922\",\"title\":\"절편꽃말이떡\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102040_1416273640697.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/771-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/771-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/771-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/771-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/771-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/771-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"절편 35\",\"거피녹두 12.5\",\"물 200\",\"다진 호두 2\",\"진달래꽃 2.5\",\"설탕 2\",\"소금 0.2\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"절편에 참기름을 조금 발라 밀면 달라붙지 않고 잘 밀어진다.\",\"instructions\":[\"1. 거피녹두를 깨끗이 씻는다.\",\"2. 씻은 녹두에 물을 넣고 푹 삶아낸다.\",\"3. 삶아 낸 녹두를 체에 밭쳐 물기를 제거하고 으깬다.\",\"4. 마른 팬에 녹두 소를 넣어 살짝 볶아 수분을 날린 다음 설탕, 소금으로 간한다.\",\"5. 절편을 5cm 길이로 잘라 밀대로 얇게 민다.\",\"6. 절편에 녹두소와 호두를 넣고 돌돌 말아 진달래를 붙인다.\"]},{\"id\":\"k923\",\"title\":\"가지볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053359_1416213239319.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/807-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/807-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/807-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/807-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/807-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/807-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지 70g\",\"생강 0.5g\",\"고추장 2g\",\"물엿 2g\",\"통깨 0.5g\",\"들기름 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 가지를 깨끗하게 씻어 1x1x4cm로 썬다.\",\"2. 생강을 곱게 다진다.\",\"3. 고추장, 물엿, 통깨와 섞어 양념장을 만든다.\",\"4. 팬에 들기름을 넣고 센불에서 가지를 볶는다.\",\"5. 가지가 다 볶아지면 양념장을 넣어 양념장이 섞일 정도로만 볶는다.\",\"6. 접시에 담는다.\"]},{\"id\":\"k924\",\"title\":\"고등어 강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053815_1416213495241.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1036-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1036-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1036-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1036-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1036-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1036-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고등어 35g\",\"전분 5g\",\"땅콩 1g\",\"튀김기름 5g [고등어 밑 양념]생강즙 1g\",\"청주 2g\",\"소금적당량\",\"후춧가루 적당량[조림장]간장 1g\",\"고추장 3g\",\"토마토케첩 3g\",\"설탕 1g\",\"물엿 3g\",\"물 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"꽁치, 삼치 등의 다양한 등푸른 생선을 사용할 수 있다.\",\"instructions\":[\"1. 고등어는 머리를 자른 뒤 내장을 빼고 잘 씻어 물기를 제거한다.\",\"2. 1의 살만 포를 떠서 한입 크기로 자른 뒤 청주, 생강즙, 소금, 후춧가루를 뿌려 밑간 한다.\",\"3. 전분을 앞, 뒤로 묻혀 170℃ 튀김 기름에 2번 바삭하게 튀긴다.\",\"4. 땅콩은 껍질을 벗긴 뒤 비닐봉지에 담아 밀대로 찧어 굵게 다진다.\",\"5. 냄비에 간장, 고추장, 설탕, 물엿을 넣고 끓여 조림장을 만든다.\",\"6. 조림장이 반으로 졸아들면 튀긴 고등어와 땅콩을 넣고 살살 뒤집어가며 윤기나게 버무린다.\"]},{\"id\":\"k925\",\"title\":\"꽃게볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053816_1416213496599.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1037-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1037-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1037-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1037-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1037-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1037-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"꽃게 70g\",\"청주 2g\",\"전분 3g\",\"실파 5g\",\"참기름 2g\",\"건고추 3g\",\"마늘다진것 3g\",\"생강다진것 2g\",\"소금적당량\",\"후춧가루적당량 [양념장]간장 2g\",\"청주 2g\",\"설탕 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 솔을 이용해 게를 깨끗이 씻어 물기를 뺀 뒤 등딱지를 떼고 먹기 좋은 크기로 토막내 소금, 후춧가루, 청주로 밑간 한다.\",\"2. 전분을 묻힌 뒤 찜통에 찐다.\",\"3. 마늘, 생강은 얇게 편썰고 실파는 3cm 길이로 썰고 건 고추는 어슷하게 썬다.\",\"4. 팬에 기름을 두르고 마늘, 생강, 건고추를 넣고 볶는다.\",\"5. 매콤한 향이 나면 양념장을 넣고 살짝 볶으면서 찐 게를 넣어 맛이 베이도록 뒤적이며 볶는다.\",\"6. 마지막에 실파를 넣고 참기름으로 향을 낸다.\"]},{\"id\":\"k926\",\"title\":\"다시마칩\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053817_1416213497711.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1038-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1038-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1038-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1038-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1038-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1038-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"다시마 25g\",\"꿀 7g\",\"참께 4g\",\"오트밀 4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오븐에서 굽는 것이 적당하지 않으면 기름에 튀기는 것도 가능하다.\",\"instructions\":[\"1. 다시마를 젖은 행주로 깨끗하게 닦는다.\",\"2. 다시마를 4x5cm 크기로 자른다.\",\"3. 자른 다시마를 파이팬에 올린다.\",\"4. 예열된 오븐에서 다시마를 굽는다.\",\"5. 구운 다시마에 꿀을 묻힌다.\",\"6. 참깨나 오트밀을 묻힌다.\"]},{\"id\":\"k927\",\"title\":\"브로콜리 쇠고기 볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053818_1416213498790.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1039-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1039-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1039-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1039-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1039-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1039-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"브로콜리 70g\",\"쇠고기안심 30g\",\"물전분 6g\",\"당근 10g\",\"마늘다진것 3g\",\"간장 3g\",\"생강 3g\",\"설탕 3g\",\"식물성기름 2g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"기름에 데치는 방법은 차가운 기름부터 넣어 온도를 올리는 것으로 조직감이 부드러워 진다.\",\"instructions\":[\"1. 브로콜리는 소금물에 담궜다가 씻는다.\",\"2. 브로콜리를 작은 송이로 자른 뒤 기름, 소금을 넣은 물에 데쳐 찬물에 헹군다.\",\"3. 생강과 당근, 마늘, 소고기를 얇게 슬라이스 한다.\",\"4. 소고기를 밑간 한 뒤 10분 정도 재웠다가 기름을 두르고 살짝 익힌다.\",\"5. 마늘, 생강, 당근, 익혀둔 소고기를 팬에 넣고 브로콜리를 넣어 볶는다.\",\"6. 물 전분을 이용해 소스의 농도를 맞춘다.\"]},{\"id\":\"k928\",\"title\":\"새우살을 채운 두부 스프(미네스트로네)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053819_1416213499570.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1040-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1040-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1040-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1040-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1040-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1040-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우 35g\",\"두부 50g\",\"당근 10g\",\"돼지호박 10g\",\"참기름 1g\",\"생강 1g\",\"양파 10g\",\"마늘다진것 1g\",\"닭육수 70g\",\"굴소스 3g\",\"간장 2g\",\"소금적당량[새우 마리네이션]달걀흰자 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새우살 대신 닭가슴살을 다져서 이용해도 좋다.\",\"instructions\":[\"1. 새우살을 다져서 양념한다.\",\"2. 두부는 4x3cm로 썰어 한 쪽 면은 속을 파내고 간이 된 새우살을 채운 뒤 전분을 묻혀 지진다.\",\"3. 당근, 양파, 돼지호박은 1.5x1.5x0.2cm 크기로 썬다.\",\"4. 팬에 참기름을 두르고 3을 타지 않도록 잘 볶은 뒤 생강, 다진 마늘을 넣고 볶다가 닭육수를 넣어 끓인다.\",\"5. 육수에 간장과 굴소스로 간을 맞춘다.\",\"6. 그릇에 지져낸 새우살을 채운 두부를 넣고 끓인 미네스트로네를 담는다.\"]},{\"id\":\"k929\",\"title\":\"시저 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053821_1416213501772.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1042-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1042-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1042-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1042-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1042-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1042-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"상추/로메인 60g\",\"마늘다진것 3g\",\"앤쵸비 3g\",\"소금 적당량\",\"후추 적당량\",\"달걀노른자 5g\",\"레몬주스 3g\",\"올리브오일 1g\",\"파마산 치즈 5g\",\"도미살 30g\",\"밀가루 8g\",\"달걀물 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크루통은 식빵을 1cm 의 정육각형으로 잘라 올리브오일을 뿌려 오븐에서 노릇하게 구워낸다.\",\"instructions\":[\"1. 상추 잎을 떼내어 잘 씻은 다음 물기를 제거하고 적당한 크기로 잘라 냉장고에서 보관한다.\",\"2. 크루통을 만들고 서빙하기 전까지 따로 보관한다.\",\"3. 마늘, 앤초비, 소금, 후추를 넣고 페이스트를 만든 뒤 달걀 노른자, 레몬주스를 넣고 섞는다.\",\"4. 3에 올리브오일을 넣어 진한 농도가 나도록 한 뒤 파마산치즈를 넣고 상추를 넣어 잘 섞는다.\",\"5. 도미살을 손가락 길이로 썰어 소금, 후추로 간을 하고 밀가루, 달걀물, 빵가루 순으로 묻혀 170℃ 정도의 기름에서 튀긴다.\",\"6. 차가운 접시에 4, 5를 담고 크루통을 뿌린다.\"]},{\"id\":\"k930\",\"title\":\"연두부 무순 냉국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053823_1416213503163.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1043-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1043-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1043-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1043-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1043-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1043-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연두부 75g\",\"무순 10g\",\"대파 5g\",\"청고추 3g\",\"홍고추 3g\",\"쑥갓 2g\",\"통깨 1g\",\"소금적당량[냉국 국물재료] 다시마육수 90g\",\"간장 4g\",\"맛술 2g\",\"식초 2g\",\"설탕 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"연두부는 아이스크림 국자로 동그랗고 예쁘게 모양을 내는 것이 보기에 좋다.\",\"instructions\":[\"1. 무순의 잡티를 제거한 뒤 물에 흔들어 씻어 물기를 뺀다.\",\"2. 연두부는 적당한 크기로 나눈다.\",\"3. 다시마 육수에 분량의 재료를 섞어 냉국 국물을 만든 뒤 냉장고에 넣어 차갑게 만든다.\",\"4. 청, 홍고추, 대파는 2cm 길이로 곱게 채 썬다.\",\"5. 냉국 그릇에 2의 연두부를 담고 무순, 채썬 대파, 청, 홍고추를 가지런히 올린다.\",\"6. 5의 연두부에 차게 준비한 냉국 국물을 붓고 쑥갓을 얹은 뒤 통깨를 뿌린다.\"]},{\"id\":\"k931\",\"title\":\"차가운 당근 수프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053825_1416213505303.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1045-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1045-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1045-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1045-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1045-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1045-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당근 80g\",\"버터 2g\",\"양파다진것 10g\",\"생강다진것 1g\",\"마늘다진것 2g\",\"야채육수 50g\",\"오렌지주스 20g\",\"생크림 5g\",\"당근주스 30g\",\"소금적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"야채육수는 양파, 당근, 샐러리, 무 등의 야채와 월계수잎, 타임등을 넣어 끓여낸다.\",\"instructions\":[\"1. 버터를 녹인 냄비에 양파, 생강, 마늘 다진 것을 넣고 양파가 반투명해 질 때까지 볶는다.\",\"2. 1에 얇게 썬 당근을 넣고 볶는다.\",\"3. 2에 야채육수, 오렌지주스를 넣고 당근이 익을 때까지 끓인다.\",\"4. 믹서에 3을 넣고 갈아준 뒤 차갑게 한다.\",\"5. 제공하기 직전에 크림을 넣어 섞은 뒤 당근주스를 넣는다.\",\"6. 소금, 후추로 마지막 간을 하고 차가운 볼에 담는다.\"]},{\"id\":\"k932\",\"title\":\"태국식 불고기 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053826_1416213506192.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1046-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1046-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1046-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1046-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1046-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기 30g\",\"애호박 20g\",\"토마토 25g\",\"가지 15g\",\"양파 8g\",\"새송이버섯 15g\",\"그린 샐러드적당량[불고기 드래싱] 풋고추 3g\",\"홍고추 3g\",\"마늘 1g\",\"고춧가루 1g\",\"레몬주스 3g\",\"타바스코 1g[카레오일]올리브오일 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 소고기는 불고기용으로 손질하여 소금, 후추로 밑간한다.\",\"2. 애호박, 토마토, 가지, 양파, 새송이버섯을 채 썬 뒤 볶는다.\",\"3. 밑간해 둔 소고기를 굽는다.\",\"4. 접시에 밥을 깔고 그 위에 그린샐러드를 올린 뒤 익혀놓은 고기와 볶아놓은 야채들을 올린다.\",\"5. 마지막으로 드래싱을 뿌린다.\"]},{\"id\":\"k933\",\"title\":\"팽이버섯 야채볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053827_1416213507603.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1047-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1047-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1047-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1047-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1047-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1047-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"팽이버섯 70g\",\"청경채 50g\",\"참기름 2g\",\"식용유 2g\",\"물전분 6g\",\"소금 적당량\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 팽이버섯은 밑동을 제거하고 4cm 길이로 자른다.\",\"2. 청경채는 겉잎을 떼어낸 뒤 반으로 가른 뒤 팽이버섯과 같은 길이로 자른다.\",\"3. 썰어 놓은 팽이버섯과 청경채를 끓는 물에 데친다.\",\"4. 기름을 두른 팬에 팽이버섯과 청경채를 볶는다.\",\"5. 물 전분을 넣어 농도를 맞춘다.\",\"6. 참기름을 뿌려 완성한다.\"]},{\"id\":\"k934\",\"title\":\"딸기연두부쉐이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102045_1416273645494.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/772-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/772-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/772-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/772-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/772-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/772-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"딸기 100g\",\"연두부 50g\",\"바나나 50g\",\"올리고당 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"적당히 씹히는 맛을 느끼려면 재료를 완전히 갈지 않고 건더기를 약간 남긴다.\",\"instructions\":[\"1. 딸기를 깨끗이 씻는다.\",\"2. 딸기의 꼭지를 뗀다.\",\"3. 딸기, 바나나를 잘게 썰어 믹서에 넣는다.\",\"4. 연두부를 믹서에 넣고 함께 간다.\",\"5. 올리고당을 넣는다.\",\"6. 컵에 담아 완성한다.\"]},{\"id\":\"k935\",\"title\":\"구운 주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20160503/20160503104705_1462240025010.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/775-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/775-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/775-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/775-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/775-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/775-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"현미(100g)\",\"톳(30g)\",\"생김(5g)\",\"달걀(50g)\",\"밥 밑간 참기름(4g)\",\"참깨(2g)\",\"톳 무침양념 설탕(2g)\",\"식초(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"현미밥과 톳을 넣어 만든 주먹밥에 달걀물을 입혀 구워낸 별미\",\"instructions\":[\"1. 현미로 밥을 지은 뒤 밥 밑간을 넣고 섞는다.\",\"2. 톳에 톳 무침양념을 넣고 버무린다.\",\"3. 밥에 톳을 넣고 버무린다.\",\"4. 밥을 먹기 좋은 크기로 둥글게 뭉친 뒤 부순 생김을 골고루 묻힌다.\",\"5. 주먹밥을 달걀물을 입힌다.\",\"6. 팬에 구워 마무리한다.\"]},{\"id\":\"k936\",\"title\":\"롤 삼계탕\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20160708/20160708060607_1467968767734.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/777-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/777-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/777-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/777-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/777-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/777-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●주재료: 마 30g(1/3개)\",\"대추20g(10개)\",\"은행35g(25개)\",\"단호박 40g(1/8개)\",\"아스파라거스 15g(1/3개)\",\"영콘 20g(1개)\",\"마늘 10g(2개)\",\"쌀 200g(1컴)\",\"●육수 : 닭 550g(1마리)\",\"파 15g(1큰술)\",\"마늘 15(3개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"국물에 별도로 소금 간을 하지 않고 단맛이 있는 단호박을 사용하여 짠맛이 부각되도록 한다.\",\"instructions\":[\"1. 닭은 살을 발라낸다.\",\"2. 남은 뼈는 파, 마늘을 넣고 육수를 만든다.\",\"3. 마와 단호박은 1x1x5cm로 썬다.\",\"4. 마늘, 아스파라거스, 영콘은 굽는다.\",\"5. 닭에 마, 대추, 쌀, 단호박, 은행을 넣고 랩으로 감싸 만다.\",\"6. 곁들일 단호박과 찜통에 찐다.\"]},{\"id\":\"k937\",\"title\":\"효종갱(曉鍾羹)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20160913/20160913012533_1473740733647.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/779-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/779-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/779-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/779-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/779-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/779-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"재료: 배추(20g)\",\"무(10g)\",\"느타리버섯(20g) 육수: 쇠고기(양지 50g\",\"갈비 50g)\",\"양파(40g)\",\"마늘(10g)\",\"물(300g) 양념: 저염간장(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저염간장으로 간을 해 염도를 낮춘 대신 쇠고기와 전복으로 깊은 맛을 더했다.\",\"instructions\":[\"1. 소고기는 핏물을 제거한 뒤 양파, 마늘을 넣고 물(300g)을 부어 1시간 이상 끓인 뒤 면포에 걸러 육수를 만든다.\",\"2. 삶은 소고기는 건져내 결 반대 방향으로 썬다.\",\"3. 배추, 무, 느타리버섯, 표고버섯은 먹기 좋은 크기로 썬다.\",\"4. 전복은 깨끗이 손질한다.\",\"5. 육수를 끓인 뒤 끓어오르면 무를 넣어 반투명해지면 배추, 버섯, 전복을 넣는다.\",\"6. 전복이 익으면 소고기를 넣고 저염간장으로 간을 해 마무리한다.\"]},{\"id\":\"k938\",\"title\":\"갯벌의 여왕 모시조개의 달콤한 유혹\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20161205/20161205092004_1480940404421.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/781-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/781-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/781-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/781-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/781-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/781-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바지락(모시조개( 200g(30개)\",\"양파 15g(2*4cm)\",\"마늘 10g(2쪽)\",\"마른 홍고추 1g(1/5개)\",\"올리브유 15g(1큰술)\",\"호이트와인 15ml(1큰술)\",\"쳥양고추 3g(1/3개)\",\"저염치즈 10g(2작은술)\",\"후추 약간\",\"바질 약간\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"조개 자체의 맛에 마늘, 고추, 양파, 저염치즈가 어우러져 소금 없이도 맛있는 조개찜 요리가 가능해요. 동일한 조리법으로 홍합이나 중합을 사용하여도 자연식품을 이용한 저나트륨 조개찜 요리를 만들 수 있어요.\",\"instructions\":[\"1. 양파는 잘게 썰고 청양고추는 어슷썰기를 한다.\",\"2. 마늘은 편으로 썰고 마른 홍고추도 둥글게 썰어 준비한다.\",\"3. 조개는 흐르는 물에 여러 번 씻어 해감을 시킨 후 물기를 제거한다.\",\"4. 달궈진 팬에 올리브오일을 두르고 마늘, 마른홍고추, 양파를 넣어 볶아 향을 낸 후, 센불로 불을 키우고 모시조개를 넣는다.\",\"5. 조개가 입을 벌리면 바질과 화이트와인을 넣어 잡내를 없앤다.\",\"6. 한소끔 끓여낸 후 붕간 불로 줄이고 저염치즈, 청양고추, 후추를 넣어 칼칼한 맛을 낸다.\"]},{\"id\":\"k939\",\"title\":\"고구마 타락죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053334_1416213214596.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/782-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/782-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/782-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/782-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/782-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/782-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 20g\",\"양송이버섯 15g\",\"양파 10g\",\"느타리버섯 7g\",\"현미(불린것) 30g\",\"저지방우유 130g\",\"식용유 20g\",\"물 100g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마나 현미는 소금을 첨가하지 않고도 먹을 수 있으므로 저나트륨에 사용이 가능하다.\",\"instructions\":[\"1. 고구마는 껍질을 벗겨 1cm 크기로 깍둑썰기 한 뒤 삶는다.\",\"2. 양송이버섯과 양파는 굵게 다지고 느타리버섯은 데친다.\",\"3. 냄비에 식용유를 넣어 양파, 고구마, 양송이버섯 순으로 볶는다.\",\"4. 현미 1/2공기와 물 1/2컵을 넣어 믹서에 굵게 간다.\",\"5. 3에 4와 나머지 우유를 넣어 끓인다.\",\"6. 5를 그릇에 담고 고구마, 데친 느타리버섯을 가운데 담는다.\"]},{\"id\":\"k940\",\"title\":\"두부 채소 볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053336_1416213216938.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/784-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/784-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/784-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/784-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/784-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/784-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 150g\",\"두부 70g\",\"표고버섯(마른것) 10g\",\"당근 5g\",\"감자 5g\",\"청피망 5g\",\"홍피망 5g\",\"오이 10g\",\"애호박 10g\",\"소금 0.2g [소스소개] 간장 2g\",\"청고추 0.5g\",\"홍고추 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 두부는 으깨서 소창을 이용하여 물기를 짠다.\",\"2. 후라이팬에 납작하게 펴서 노릇하게 굽는다.\",\"3. 구워진 두부를 대충 부서뜨린 후 간장을 넣어서 볶는다.\",\"4. 당근, 감자, 피망, 애호박, 불린 표고버섯, 오이는 작은 정육면체로 썰어 각각 소금간 해서 볶는다.\",\"5. 팬에 감자, 표고버섯, 두부, 밥을 넣고 볶다가 나머지 채소를 넣어 볶는다.\",\"6. 양념장을 만들어 함께 낸다.\"]},{\"id\":\"k941\",\"title\":\"건강 마늘 꿀환\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053829_1416213509742.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1049-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1049-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1049-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1049-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1049-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1049-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"마늘 50g\",\"잣 2g\",\"꿀 10g\",\"검은깨 5g\",\"카스텔라가루 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 마늘은 꼭지를 떼고 찜통에 무르도록 찐다.\",\"2. 쪄 낸 마늘을 손절구에 곱게 으깬다\",\"3. 잣은 고깔을 떼고 겉면을 깨끗하게 닦은 뒤 가루를 만든다.\",\"4. 2에 꿀, 검은깨, 잣가루를 넣고 잘 혼합한다.\",\"5. 4에 카스텔라 가루를 넣어 농도를 맞춘다.\",\"6. 반죽을 조금씩 떼어 동그랗게 굴려 꿀환을 만든다.\"]},{\"id\":\"k942\",\"title\":\"과일 샐러드 또띠아\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053831_1416213511544.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1051-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1051-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1051-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1051-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1051-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1051-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"자몽 30g\",\"오렌지 30g\",\"키위 30g\",\"사과 30g\",\"플레인 요구르트 30g\",\"꿀 5g\",\"또띠아 45g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수분이 적은 과일을 이용하고 오렌지의 경우 표피를 제거하고 사용하는 것이 좋다.\",\"instructions\":[\"1. 자몽은 껍질을 벗겨내고 과육만 0.5cm 주사위모양으로 자른다.\",\"2. 오렌지는 껍질을 벗겨내고 과육만 자몽과 같은 크기로 자른다.\",\"3. 키위도 껍질을 벗겨내고 자몽과 같은 크기로 자른다.\",\"4. 썰어 둔 과일에 플레인 요거트, 꿀을 넣고 버무린다.\",\"5. 또띠아를 반으로 자른다.\",\"6. 버무린 과일을 넣고 말아준다.\"]},{\"id\":\"k943\",\"title\":\"수박 화채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053835_1416213515140.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1054-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1054-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1054-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1054-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1054-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1054-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀가루 12g\",\"물 8g\",\"수박 180g\",\"팥 5g\",\"설탕 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"수박은 모양틀을 이용하여 예쁜 모양을 만들어 보자.\",\"instructions\":[\"1. 찹쌀가루에 뜨거운 물을 넣어 익반죽을 한다.\",\"2. 찹쌀 반죽을 동그랗게 빚는다.\",\"3. 찹쌀 경단을 끓는 물에 삶은 뒤 차갑게 식힌다.\",\"4. 수박은 씨를 제거한 뒤 곱게 갈아 차갑게 식힌다.\",\"5. 그릇에 3과 4를 넣는다.\",\"6. 기호에 따라 팥을 삶아 설탕에 졸여 넣는다.\"]},{\"id\":\"k944\",\"title\":\"우유 생강차\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20150524/20150524053243_1432456363204.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1055-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1055-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1055-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1055-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1055-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1055-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"우유 180g\",\"생강 10g\",\"꿀 6g\",\"깨소금 3g\",\"계피가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생강향이 너무 많이 나면 쓰게 느껴지므로 적당량으로 제한한다.\",\"instructions\":[\"1. 생강을 깨끗이 씻는다.\",\"2. 생강을 강판에 곱게 간다.\",\"3. 냄비에 우유와 간 생강을 넣고 끓인다.\",\"4. 가장자리가 보글보글 끓어 오르면 불에서 내린다.\",\"5. 믹서에 4를 붓고 깨소금, 꿀을 넣어 간다.\",\"6. 컵에 5를 붓고 계피가루를 살짝 뿌린다.\"]},{\"id\":\"k945\",\"title\":\"레몬 들깨 소스를 품은 떡꼬치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20160811/20160811080227_1470913347569.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1056-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1056-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1056-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1056-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1056-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1056-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●떡꼬치: 쌀떡 90g\",\"ghen 10g(1알)\",\"잣 5g(5알)\",\"식용유 30g(2큰술)\",\"꼬치용 꼬치 6개\",\"●레몬 들깨 소스: 들깨가루 45g(3큰술)\",\"두유 45g(3큰술)\",\"꿀 15g(1큰술)\",\"물 15ml(1큰술)\",\"참기름 7g(1작은술)\",\"레몬즙 7g(1작은술)\",\"검은깨 5g(1작은술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"튀긴 떡에 먹는 소스는 고추장소스가 대부분이지만, 들깨와 견과류를 활용하면 칼륨 섭취도 늘리고 맛도 고소해 누구나 좋아하는 맛으로 즐길 수 있어요.\",\"instructions\":[\"1. 들깨가루, 검은깨, 두유, 레몬즙, 꿀, 물, 참기름을 섞어 레몬 들깨 소스를 만든다.\",\"2. 떡 군데군데 꼬챙이로 찌르거나 칼집을 넣는다.\",\"3. 팬에 기름을 두르고 160℃ 정도에서 기름이 튀지 않도록 주의하며 떡을 튀긴다.\",\"4. 꼭지를 땐 잣과 호두를 굵게 다진다.\",\"5. 떡은 꼬치에 꽂아 접시에 담는다.\",\"6. 레몬 들깨소스를 바르고 잣, 호두를 고명으로 뿌린다.\"]},{\"id\":\"k946\",\"title\":\"누룽지 요거트 파르페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20160811/20160811080819_1470913699718.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1057-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1057-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1057-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1057-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1057-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1057-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"●누룽지: 밥 210g(1공기)\",\"●요거트파르페: 오렌지 40g(1/5개)\",\"사과 30g(1/5개)\",\"요거트 200g(1컵)\",\"블루베리 30g(2큰술)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단단한 누룽지를 부드러운 요거트와 함께 섭취하면 식감은 살리고, 사과와 오렌지의 칼륨은 몸 속의 나트륨 배출을 도와줍니다. 모든 연령대에서 부족하기 쉬운 칼슘과 비타민을 보충할 수 있어 간식으로 활용하면 효과적입니다.\",\"instructions\":[\"1. 프라이팬에 밥을 얇게 펴 약한 불에서 뚜껑을 덮어 굽는다.\",\"2. 노릇하게 누룽지가 되면 식혀서 굵게 부순다.\",\"3. 오렌지는 깨끗이 씻어 껍질을 벗긴 뒤 먹기 좋은 크기로 자른다.\",\"4. 사과를 깨끗이 씻어 물기를 제거하고 굵게 자른다.\",\"5. 컵에 요거트-오렌지-요거트-누룽지-요거트-사과-요거트-누룽지 순으로 담는다.\",\"6. 마지막에 누룽지와 블루베리로 장식한다.\"]},{\"id\":\"k947\",\"title\":\"자색고구마 호떡\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20170106/20170106011651_1483676211608.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1058-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1058-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1058-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1058-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1058-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/1058-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"반죽: 찹쌀(30g)\",\"자색고구마 20g\",\"소금(0.2g)\",\"현미휴(3g)\",\"물(17g)\",\"황설탕(7g) 호떡소: 검정깨\",\"땅콩\",\"호두(각 2g)\",\"찹쌀가루(0.5g)\",\"계피가루(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 찹쌀을 3-5시간 불려둔 뒤 물기를 제거하고 믹서기에 간다.\",\"2. 고구마는 껍질을 벗기고 작게 썰어 찜통에 찐 뒤 말랑말랑해지면 잘 으깨어 반죽하기 편할 정도로 만든다.\",\"3. 검정깨는 믹서기에 곱게 갈고 호두와 땅콩은 잘게 다진 뒤 황설탕과 섞어 호떡소를 만든다.\",\"4. 으깬 고구마에 찹쌀가루를 넣은 뒤 호떡 반죽을 만든다.\",\"5. 완성된 반죽을 적당량 떼어내 동그랗게 빚어 준비해둔 호떡소를 적당량 넣고 봉합한 뒤 납작하게 누른다.\",\"6. 팬에 현미유를 두르고 호떡을 살짝 눌러가면서 앞뒤로 노릇노릇하게 굽는다.\"]},{\"id\":\"k948\",\"title\":\"청국장지짐 케일쌈밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01059_1.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01059_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01059_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01059_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01059_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01059_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01059_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(20g)\",\"청국장(30g)\",\"밥(100g)\",\"케일(50g)\",\"멸치(10g)\",\"무(40g)\",\"양파(80g)\",\"사과(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"야채와 사과로 만든 육수와 청국장에 다져 넣은 양파의 단맛으로 설탕 없이 맛있는 음식을 만들 수 있어요.\",\"instructions\":[\"1. 멸치와 무, 양파 절반, 사과를\\n끓여 육수를 만든다.\",\"2. 남은 양파와 돼지고기는 곱게\\n다진다.\",\"3. 청국장에 육수, 다진 양파,\\n돼지고기를 넣고 볶는다.\",\"4. 케일은 끓는 물에 살짝 데친 뒤\\n식히고 물기를 없앤다.\",\"5. 밥에 청국장 지짐을 비빈 뒤\\n케일로 돌돌 말아 반을 자른다.\",\"6. 그릇에 담고 어슷썬 홍고추로\\n장식한다.\"]},{\"id\":\"k949\",\"title\":\"마늘 불고기 덮밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01060_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01060_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01060_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01060_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01060_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01060_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01060_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(불고기용\",\"250g)\",\"쌀(150g)\",\"새송이버섯(50g)\",\"당근(30g)\",\"양파(30g)\",\"대파(20g)\",\"마늘\",\"배(30g)\",\"진간장(30g)\",\"후춧가루(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념에 들어간 마늘과, 마늘 칩의 단맛과 향이 설탕 사용을 줄여줘요.\",\"instructions\":[\"1. 쌀은 깨끗이 씻고 불려 밥을\\n짓는다.\",\"2. 소고기는 핏기를 제거하고 버섯,\\n당근, 양파, 대파는 한 입 크기로\\n썰어서 준비한다.\",\"3. 절반의 마늘과 진간장, 양파, 배,\\n후춧가루를 넣고 믹서에 갈아\\n양념을 만든다.\",\"4. 핏기를 제거한 소고기에 3번의\\n양념을 넣고 섞는다.\",\"5. 나머지 마늘은 얇게 편썰어\\n기름에 튀겨 마늘 칩을 만든다.\",\"6. 숙성 시킨 불고기를 팬에 볶고,\\n그릇에 담은 밥 위에 올리고 마늘\\n칩으로 장식한다.\"]},{\"id\":\"k950\",\"title\":\"잡곡강정밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01061_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01061_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01061_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01061_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01061_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01061_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01061_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"잡곡(50g)\",\"찹쌀(50g)\",\"호두(20g)\",\"은행(20g)\",\"밤(20g)\",\"대추고(60g)\",\"꿀(5g)\",\"간장(15g)\",\"소금(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"대추고를 이용하면 대추의 단맛 뿐만 아니라 풍미를 더하고 점성이 생기게 할 수 있어요.\",\"instructions\":[\"1. 잡곡과 찹쌀은 물에 씻어 불린 뒤\\n소금을 넣고 밥을 짓는다.\",\"2. 호두는 껍질을 제거하고 굵게\\n부숴 마른 팬에 볶는다.\",\"3. 은행은 기름에 볶아 껍질을\\n제거하고 4등분 한다\",\"4. 생밤은 껍질을 벗기고 작은\\n주사위 모양으로 자른 뒤 기름에\\n굽는다.\",\"5. 물 40g에 간장, 대추고, 꿀을 넣고\\n끓인 뒤 2,3,4번을 넣고 잘 섞는다.\",\"6. 잡곡밥을 넓게 펼친 뒤 5번을\\n넣고 돌돌 만다.\"]},{\"id\":\"k951\",\"title\":\"함박스테이크 볼 밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01062_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01062_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01062_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01062_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01062_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01062_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01062_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(60g)\",\"돼지고기(60g)\",\"가래떡(20g)\",\"양파(20g)\",\"새송이버섯(20g)\",\"파프리카(15g)\",\"사과(20g)\",\"배(30g)\",\"고추장(5g)\",\"파(10g)\",\"마늘(5g)\",\"간장(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"과일과 단맛이 나는 채소를 사용하면 설탕 없이 단맛을 낼 수 있어요\",\"instructions\":[\"1. 소고기, 돼지고기, 가래떡, 양파,\\n새송이버섯, 파는 잘게 다진다\",\"2. 사과와 배는 믹서에 간 뒤 간장,\\n청주, 다진 마늘, 후춧가루를 넣고\\n양념장을 만든다.\",\"3. 다진 고기와 양념장을 섞은 뒤\\n다진 재료를 넣고 잘 치대어 먹기\\n좋은 크기로 만든다.\",\"4. 팬에 기름을 두르고\\n함박스테이크를 굽는다.\",\"5. 파프리카는 다지고, 사과, 배는\\n갈아서 고추장, 간장, 다진 마늘을\\n섞은 뒤 끓여 소스를 만든다.\",\"6. 밥에 참기름을 넣고\\n함박스테이크를 담은 뒤 소스를\\n올려 완성한다.\"]},{\"id\":\"k952\",\"title\":\"곤드레 밥버거\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01063_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01063_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01063_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01063_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01063_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01063_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01063_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(80g)\",\"찹쌀(40g)\",\"흑미(40g)\",\"곤드레나물(50g)\",\"파프리카(30g)\",\"양상추(30g)\",\"감자(20g)\",\"양파(50g)\",\"깻잎(5장)\",\"바나나(1/2개)\",\"김(10g)\",\"호두(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소스의 바나나는 설탕을 대신하고, 된장은 풍미를 더해 맛있게 만들 수 있어요.\",\"instructions\":[\"1. 곤드레나물에 들기름, 간장으로\\n양념하고 쌀, 찹쌀, 흑미와 밥을\\n지은 뒤 참기름, 소금 간 한다.\",\"2. 식초와 식초2배의 물을 넣고\\n끓이다가 사과를 한 입 크기로\\n썰어 끓인다.\",\"3. 감자를 삶아 으깨고, 다진 양파,\\n호두, 밀가루를 넣고 섞은 뒤 겉에\\n빵가루를 묻혀 팬에 굽는다.\",\"4. 파프리카는 잘게 채 썬다.\",\"5. 마요네즈, 깻잎, 바나나, 된장을\\n믹서에 갈아 소스를 만들고\\n피클을 다져 넣는다.\",\"6. 종이호일을 깔고 중간중간\\n소스를 뿌리면서 김-양상추-\\n패티-파프리카-양상추-밥\\n순으로 얹어 버거를 만든다.\"]},{\"id\":\"k953\",\"title\":\"대추닭살리조또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01064_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01064_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01064_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01064_3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01064_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01064_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01064_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"30g)\",\"쌀(50g)\",\"양파(10g)\",\"표고버섯(10g)\",\"대추(2알)\",\"당근(5g)\",\"피망(5g)\",\"치즈(10g)\",\"우유(50g)\",\"마늘(3g)\",\"소금(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"첨가당 대신 대추로 단맛을 낼 수 있어요.\",\"instructions\":[\"1. 쌀을 씻어 밥을 짓는다.\",\"2. 양파, 표고버섯, 당근, 피망은\\n입자있게 다지고 대추는 씨를\\n제거한 뒤 다진다.\",\"3. 닭가슴살은 먹기 좋은 크기로\\n썬다.\",\"4. 팬에 기름을 두르고 다진 마늘을\\n볶은 뒤 닭가슴살을 볶는다\",\"5. 닭가슴살이 다 익으면 손질한\\n채소를 넣고 볶다가 밥, 우유,\\n치즈, 대추를 넣고 끓인다.\",\"6. 우유가 반으로 졸아들면 불을\\n줄이고 소금, 후추로 간한다.\"]},{\"id\":\"k954\",\"title\":\"먹골배 카레주먹밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01065_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01065_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01065_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01065_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01065_4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01065_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01065_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(150g)\",\"카레가루(70g)\",\"묵은지(15g)\",\"양파(15g)\",\"애호박(5g)\",\"가지(5g)\",\"참치(50g)\",\"마요네즈(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"카레가루로 밥을 하여 따로 간을 하지 않아도 맛있는 주먹밥을 만들 수 있어요.\",\"instructions\":[\"1. 카레가루를 미지근한 물에 개어\\n쌀을 넣고 밥을 한다.\",\"2. 묵은지는 헹궈서 다지고 양파도\\n다진다.\",\"3. 참치의 기름을 빼고 묵은지,\\n양파를 넣고 마요네즈에\\n버무린다.\",\"4. 3번을 넣고 카레밥으로 주먹밥을 만든다.\",\"5. 주먹밥을 배 모양으로 만든다.\",\"6. 애호박과 가지 껍질로 배 꼭지와\\n잎을 만들어 장식한다.\"]},{\"id\":\"k955\",\"title\":\"신호등 통통이(어린이 곤약삼색주먹밥)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01066_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01066_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01066_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01066_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01066_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01066_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01066_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(10g)\",\"곤약미(30g)\",\"쌀(30g)\",\"시금치(20g)\",\"당근(20g)\",\"멸치(5g)\",\"대파(0.5g)\",\"달걀(1개)\",\"간장(1g)\",\"참기름(5g)\",\"소금(1g)\",\"후춧가루(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밥에 참기름을 넣으면 고소한 맛이 식재료 본연의 맛과 어우러져 담백한 요리를 만들 수 있어요.\",\"instructions\":[\"1. 쌀과 곤약은 깨끗이 씻어 밥을\\n짓는다.\",\"2. 시금치는 데쳐 잘게 다지고\\n당근은 잘게 다져 팬에 볶고,\\n달걀은 삶아 노른자만 체에\\n거른다.\",\"3. 소고기는 간장, 참기름, 대파,\\n마늘, 물엿, 후춧가루를 버무려\\n볶는다.\",\"4. 멸치는 올리고당으로 볶고 밥은\\n소금과 참기름으로 밑간한다.\",\"5. 밥과 멸치, 밥과 소고기를 각각\\n버무려 동그랗게 빚는다.\",\"6. 동그랗게 빚은 밥은 시금치, 당근,\\n달걀노른자에 각각 굴린다.\"]},{\"id\":\"k956\",\"title\":\"양배추롤&참치두부쌈장\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01067_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01067_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01067_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01067_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01067_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01067_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01067_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥(150g)\",\"양배추(60g)\",\"참치(캔\",\"30g)\",\"두부(30g)\",\"양파(8g)\",\"파(5g)\",\"마늘(5g)\",\"된장(5g)\",\"고추장(2g)\",\"매실청(3g)\",\"참기름(1.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"참치와 두부의 고소한 맛과 양파의 단맛으로 설탕을 넣지 않아도 맛있는 쌈장을 만들 수 있어요.\",\"instructions\":[\"1. 양배추는 손질하여 찜통에 10분간\\n찐 후 식힌다.\",\"2. 참치는 체에 받쳐 기름을 빼고, 두부는 물기를 제거한 뒤 으깬다\",\"3. 양파와 파, 마늘은 잘게 다진다\",\"4. 팬에 된장, 고추장, 매실청, 다진 \\n양파, 파, 마늘, 물을 넣고 섞어\\n끓이다가 참치, 두부를 넣고 볶은\\n뒤 참기름, 깨를 넣는다.\",\"5. 찐 양배추에 밥을 얹어 돌돌 만다.\",\"6. 양배추롤을 적당한 크기로 썰고\\n참치두부쌈장을 올린다.\"]},{\"id\":\"k957\",\"title\":\"라비올리 크림소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053337_1416213217688.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/785-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/785-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/785-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/785-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/785-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/785-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파 17.5g\",\"마늘 2.1g\",\"새우살 70g\",\"게살 17.5g\",\"식용유 4.2g\",\"크림 17.5g\",\"파마산치즈 4.9g\",\"버터 2.1g[라비올리 반죽] 중력분 35g\",\"강력분 100g\",\"달걀 38.5g\",\"물 40g\",\"시금치 3.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라비올리 반죽에 소금을 넣지 않고 저나트륨용 라비올리를 만들어 사용한다.\",\"instructions\":[\"1. 양파, 마늘, 새우살, 게살을 다진다. 팬에 마늘과 양파를 볶다가 새우살과 게살을 넣고 볶아 식힌다.\",\"2. 시금치는 데친 뒤 믹서에 갈아 즙을 내고, 비트도 갈아 체에 걸러 즙을 낸 뒤 밀가루, 달걀과 섞어 라비올리 반죽을 색깔별로 만든다.\",\"3. 라비올리 반죽을 0.1mm 두께로 밀어 편다.\",\"4. 반죽을 5X5cm크기로 자른 후 볶아둔 새우살 등의 속을 가운데 놓고 삼각형으로 반을 접어 모서리를 봉한다.\",\"5. 끓는 물에 라비올리를 삶는다.\",\"6. 팬에 식용유를 넣고 다진 양파를 볶다가 크림을 넣고 졸인 뒤 라비올리, 파마산치즈, 비트를 넣는다.\"]},{\"id\":\"k958\",\"title\":\"라비올리 토마토소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053338_1416213218390.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/786-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/786-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/786-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/786-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/786-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/786-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"중력분 25g\",\"강력분 25g\",\"달걀 12g\",\"물 12g\",\"양파 25g\",\"당근 12g\",\"토마토 120g  토마토소스:셀러리 8g\",\"바질 8g\",\"오레가노 2.5g\",\"로즈마리 2.5g\",\"물필요량\",\"설탕 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토 가공 식품들은 염분이 높으므로 생 토마토를 이용한 토마토 소스를 만들어 사용하면 저나트륨 소스로 잘 이용할 수 있다.\",\"instructions\":[\"1. 반죽 재료를 섞어 라비올리 반죽을 만든 뒤 냉장고에 휴지 시킨다.\",\"2. 우유가 끓이다 레몬즙을 넣고 응어리가 생기면 면보에 걸러 응고시킨다.\",\"3. 우유가 차갑게 식으면 차이브와 파마산 치즈를 섞어 리코타치즈를 만든다.\",\"4. 냉장 휴지시킨 라비올리 반죽을 1mm두께로 민 뒤 4x4cm 크기로 잘라 리코타치즈로 속을 채워 끎는 물에 삶는다.\",\"5. 양파,당근,토마토은 슬라이스하고 셀러리와 마늘은 잘게 다져 냄비에 바질, 오레가노, 로즈마리, 물, 설탕과 함께 끓여 토마토소스를 만든다.\",\"6. 라비올리와 토마토소스를 곁들여낸다.\"]},{\"id\":\"k959\",\"title\":\"미역 조랭이 떡국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053339_1416213219015.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/787-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/787-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/787-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/787-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/787-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/787-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"미역마른것 5g\",\"우엉 20g\",\"조랭이 떡 100g\",\"들깨 18g\",\"들기름 4g\",\"마늘 4g\",\"물 300g\",\"국간장 4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"조랭이 떡국은 일품요리로 서빙하고 국물은 0.7% 염도로 맞춘다.\",\"instructions\":[\"1. 마른 미역은 물에 담가 불린 후 먹기 좋은 크기로 썬다.\",\"2. 우엉은 연필깍기 하여 냉수에 여러 번 주물러 씻어 쓴맛을 뺀다.\",\"3. 들깨는 믹서기에 물을 넣어 곱게 갈아 준비한다.\",\"4. 냄비에 들기름을 넣고 우엉을 넣어 부드럽게 볶다가 미역을 넣어 함께 볶는다.\",\"5. 4에 들깨물을 넣어 미역이 부드러우질 때까지 끓인다.\",\"6. 들깨 미역국이 부드러워지면 조랭이 떡을 넣고 다진 마늘을 넣어 떡국을 끓여낸다.\"]},{\"id\":\"k960\",\"title\":\"서리태 잣국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053340_1416213220358.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/789-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/789-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/789-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/789-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/789-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/789-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"잣 20g\",\"서리태 20g\",\"오이 10g\",\"밀가루 70g\",\"소금 0.2g\",\"체리토마토 10g\",\"흑임자 0.5g\",\"물 300g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 서리태를 씻어 물에 충분히 불리고 오이는 곱게 채썬다\",\"2. 냄비에 서리태를 넣고 자작하게 물을 부어 한소끔 끓고 나면 불을 끄고 삶아진 서리태를 차가운 물에 헹구면서 껍질을 벗긴다.\",\"3. 믹서에 서리태와 잣을 넣고 물을 넣어 곱게 간다.\",\"4. 밀가루에 소금을 소량 넣어 반죽 한다.\",\"5. 반죽을 가늘고 얇게 국수로 만들어 끓는 물에 넣고 삶는다.\",\"6. 그릇에 국수를 담고 잣, 콩물을 부은 후 채썬 오이와 반 가른 체리토마토를 얹고 흑임자를 뿌려 완성한다.\"]},{\"id\":\"k961\",\"title\":\"쌈밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053342_1416213222185.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/791-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/791-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/791-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/791-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/791-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/791-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 140g\",\"쇠고기다진것 15g\",\"후춧가루 0.01g\",\"참기름 2g\",\"근대 20g\",\"쌈다시마 15g\",\"양배추 20g\",\"케일20g\",\"앤다이브 20g\",\"깻잎 10g\",\"미나리 1g\",\"오징어 10g [소스 소개] 저나트륨 양념간장:간장 6g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"재움장의 간장은 숨만 죽이는 정도로 절여지도록 하기 위한 것이다.\",\"instructions\":[\"1. 고슬고슬하게 지은밥에 참기름을 섞고 다진 소고기는 후춧가루, 참기름에 무친 뒤 볶아서 밥과 섞어 주먹밥을 만든다.\",\"2. 근대는 데친 뒤 소금, 다진 마늘, 참기름으로 무친다.\",\"3. 쌈다시마는 물에 헹군 뒤 끓는 물에 파랗게 데쳐 6cm폭으로 자른다.\",\"4. 케일, 앤다이브는 씻어서 물기를 빼고 깻잎은 저나트륨 양념간장에 재운다.\",\"5. 미나리와 오징어는 손질하여 살짝 데치고 오징어는 얇게 저며 썬다.\",\"6. 1의 주먹밥을 준비한 각각의 재료로 말아 싼 다음 쌈장, 저나트륨 초고추장을 올려 마무리 한다.\"]},{\"id\":\"k962\",\"title\":\"영양밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053343_1416213223105.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/792-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/792-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/792-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/792-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/792-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/792-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀 30g\",\"현미찹쌀 30g\",\"표고버섯 30g\",\"당근 30g\",\"대추 7.5g\",\"은행 3g\",\"밤 12g\",\"다시마 육수 20g [소스소개]저나트륨 간장양념장:간장 1g\",\"사과쥬스 4g\",\"겨자 0.5g\",\"참기름 3g\",\"깨소금 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"일품요리로 영양밥을 제공할 때는 저나트륨 간장양념장을 곁들여도 좋다.\",\"instructions\":[\"1. 쌀과 현미찹쌀을 씻어 불린다.\",\"2. 표고버섯, 당근은 은행크기로 썬다\",\"3. 대추도 돌려깍아 은행크기로 썬다.\",\"4. 1에 표고버섯, 당근, 대추와 은행, 밤을 고루 섞어 솥에 담는다.\",\"5. 다시마 육수를 평상시 밥물보다 적게 넣고 밥을 짓는다.\",\"6. 밥이 뜸이 들면 간장양념과 함께 제공한다.\"]},{\"id\":\"k963\",\"title\":\"팥죽\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053344_1416213224293.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/793-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/793-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/793-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/793-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/793-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/793-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"팥 40g\",\"찹쌀가루 30g\",\"찹쌀 10g\",\"물 300g\",\"설탕기호에따라\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"죽, 스프류는 염도가 낮아도 점도의 질감이 있어서 싱겁게 느껴지지 않으므로 나트륨 섭취율을 줄일 수 있다.\",\"instructions\":[\"1. 찹쌀을 씻어 불린다.\",\"2. 팥을 씻어서 건진 후 잠길 만큼 물을 붓고 끓인다.\",\"3. 검붉은 물이 우러나오면 제거하고 팥 분량의 3배 정도 물을 넣어서 완전히 뭉그러질 때까지 끓인다.\",\"4. 찹쌀가루는 끓는 물로 익반죽하여 1.5cm 가량의 찹쌀경단을 빚는다.\",\"5. 삶은 팥을 손으로 주무른 다음 체에 거르고 앙금을 가라앉도록 하여 웃물을 먼저 끓으면 불린 찹쌀을 넣고 퍼질 때 까지 끓인다.\",\"6. 앙금과 찹쌀경단을 차례로 넣고 끓인 뒤 경단이 떠오르면 2~3분 더 끓여 완성한다.(설탕이나 꿀은 기호에 따라 사용한다.)\"]},{\"id\":\"k964\",\"title\":\"호박만두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053345_1416213225823.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/794-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/794-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/794-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/794-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/794-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/794-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"애호박 50g\",\"표고버섯 10g\",\"청고추 5g\",\"소금 0.1g\",\"시금치 10g\",\"참기름 2g\",\"통깨 0.4g\",\"식용유 2g\",\"후춧가루 0.2g\",\"밀가루 40g\",\"물 20g [소스소개] 초간장:간장 2g\",\"식초 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시중에 파는 만두피는 나트륨 함량이 높으므로 만두피를 직접 만들어 사용하는것이 좋다.\",\"instructions\":[\"1. 호박은 채썰어 굵게 다진 뒤 소금을 뿌렸다가 물기를 제거하고 센불에 충분히 볶아 식힌다.\",\"2. 표고버섯은 불려서 꼭지를 떼고 두꺼운 것은 포를 뜬 뒤 채썰어 들기름을 넣고 무쳐 센불에 볶고 청고추는 다진 뒤 살짝 볶는다.\",\"3. 볶은 호박과 고추, 버섯이 완전히 식으면 섞어서 통깨, 후춧가루, 참기름에 무친다.\",\"4. 분량의 밀가루와 물을 섞어 반죽을 만든 뒤 0.2cm 두께로 밀어 지름 7~8cm 정도의 동그란 틀을 이용해 찍어 만두피를 만든다.\",\"5. 만두피에 만두소를 넣어 만두를 만든다.\",\"6. 김이 오른 찜통에 젖은 소창을 깔고 만두를 넣어 찌거나 끓는 물에 소금을 약간 넣고 터지지 않게 삶는다.\"]},{\"id\":\"k965\",\"title\":\"감자 팬케익\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053346_1416213226963.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/795-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/795-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/795-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/795-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/795-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/795-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 100g\",\"양파다진것 15g\",\"체리 20g\",\"사과 20g\",\"청포도 35g\",\"식초 1g\",\"물 200g\",\"달걀흰자 80g\",\"밀가루 16g\",\"베이킹 파우더 1g\",\"마늘가루 1g\",\"후춧가루 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"마늘향을 좋아하는 경우에 생마늘을 다져서 사용해도 좋다.\",\"instructions\":[\"1. 감자는 껍질을 벗긴 후 곱게 채썰어 식초를 살짝 탄 물에 담가 갈변을 방지한다.\",\"2. 달걀흰자에 밀가루, 베이킹 파우더를 넣어 덩어리 지지 않게 푼다.\",\"3. 마늘가루, 후춧가루를 넣어 잘 섞어 반죽을 만든다.\",\"4. 썰어 둔 감자를 체에 받쳐 물기를 뺀 후 키친타올을 이용해 완전히 물기를 제거한 후 만들어 둔 반죽에 넣어 섞는다.\",\"5. 팬에 식용유를 넣고 반죽을 부어 지름 6cm 정도로 둥글게 편 뒤 양면을 노릇하게 굽는다.\",\"6. 체리, 사과, 청포도 등의 제철 과일을 설탕물에 졸여 팬케익에 곁들인다.\"]},{\"id\":\"k966\",\"title\":\"단호박 두부 포타주\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053347_1416213227837.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/796-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/796-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/796-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/796-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/796-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/796-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 40g\",\"두부작은것 40g\",\"두유 40g\",\"다시마국물 150g\",\"소금 0.5g\",\"후춧가루 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"포타주는 100~150g 정도만 주고, 염도는 0.5% 정도로 낮추어 주는 것이 좋다.\",\"instructions\":[\"1. 단호박은 속을 숟가락으로 깨끗하게 긁어낸다.\",\"2. 껍질을 군데군데 깎은 후 작은 토막으로 잘라 물에 넣어 삶는다.\",\"3. 식힌 단호박과 두부를 믹서에 넣고 간다.\",\"4. 단호박 크기가 작아지면 멈추었다가 두유를 넣고 한번 더 간다.\",\"5. 냄비에 넣고 다시마 국물을 조금씩 부어가며 잘 풀어주면서 약한 불에서 뭉근하게 끓인다.\",\"6. 소금, 후춧가루로 간한다.\"]},{\"id\":\"k967\",\"title\":\"쇠고기와 검은콩 요리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053349_1416213229507.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/798-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/798-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/798-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/798-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/798-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/798-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쇠고기갈은것 50g\",\"서리태 30g\",\"셀러리 3g\",\"양파 7.5g\",\"청피망 4.5g\",\"토마토 61.5g\",\"베이컨 4.5g\",\"현미 30g\",\"닭육수 30g\",\"물 40.5g\",\"마늘다진것 0.8g\",\"월계수잎마른것 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 서리태를 2시간 정도 물에 불려둔다.\",\"2. 셀러리, 양파, 청피망, 토마토를 굵게 다지고 베이컨은 얇게 채썬다.\",\"3. 팬에 식용유를 두르고 다진 마늘을 넣어 볶아 향을 낸 뒤 다진 소고기를 넣어 볶는다.\",\"4. 팬에 식용유를 두르고 베이컨, 양파, 셀러리, 토마토, 청피망 순으로 넣어 볶는다.\",\"5. 냄비에 현미, 볶은 소고기, 닭육수를 넣어 현미가 반쯤 익도록 끓인다.\",\"6. 불린 서리태, 볶은 채소, 월계수잎, 타임, 카엔페퍼를 넣고 현미와 서리태가 완전히 익도록  낮은불에서 은근히 끓인다.\"]},{\"id\":\"k968\",\"title\":\"채소 커리를 곁들인 팬케익\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053350_1416213230319.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/799-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/799-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/799-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/799-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/799-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/799-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"인스턴트 카레가루는 나트륨 함량이 높으므로 카레가루는 원재료 향신료를 섞어서 저나트륨 카레가루를 사용한다. 에피타이저용으로 만들 수 있는데, 팬에 팬케익반죽을 한 스푼 부어 익힌 후, 그 위에 사워크림이나 블랙올리브오일, 혹은 캐비어를 몇알 올려서 먹을 수 있다.\",\"instructions\":[\"1. 브로콜리는 작은 송이로 나누고 실파와 그린빈은 0.8cm의 정육면체로 썬 뒤 브로콜리와 그린빈은 끓는 물에 데친다.\",\"2. 당근, 양배추, 홍파프리카, 양파, 청고추는 0.8cm의 정육면체로 썰고 파슬리를 곱게 다진다.\",\"3. 볼에 밀가루, 우유, 달걀, 버터, 다진 파슬리를 넣고 잘 섞는다.\",\"4. 팬에 식용유를 두르고 브로콜리와 그린빈을 뺀 나머지 재료를 볶다가 커리파우더를 넣고 섞는다.\",\"5. 닭육수를 넣어 재료가 익을 때까지 끓인 뒤 물이 자작하게 줄어들면 브로콜리와 그린빈을 넣어 섞는다.\",\"6. 팬에 식용유를 살짝 두르고 국자로 반죽을 떠 넣어 지름 10cm 정도의 얇은 팬케익을 부친다\"]},{\"id\":\"k969\",\"title\":\"양송이버섯 달걀 크레페\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053351_1416213231334.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/800-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/800-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/800-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/800-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/800-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/800-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양송이버섯 12.8g\",\"달걀 11g\",\"에벤탈치즈 20g\",\"메밀가루 20g\",\"달걀 22g\",\"밀가루 20g\",\"우유 80g\",\"설탕 10g\",\"양파 8g\",\"파슬리다진것 0.4g\",\"감자 20g\",\"로즈마리다진것 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 메밀가루, 달걀, 우유, 밀가루, 설탕을 믹서에 갈아 놓는다.\",\"2. 양송이버섯과 양파는 얇게 썬다. 감자는 1cm 정육면체로 잘라서 삶아 놓는다.\",\"3. 팬에 식용유를 두르고 다진 마늘과 로즈마리, 파슬리, 감자를 볶는다.\",\"4. 또 다른 팬에서는 양파를 볶다가 양송이버섯을 넣고 볶아둔다.\",\"5. 팬에 1의 반죽을 얇게 부친 뒤 뒤집어 볶은 양송이버섯과 3의 감자, 달걀을 올린다.\",\"6. 에멘탈 치즈를 고루 뿌리고 반을 접어 완성한다.\"]},{\"id\":\"k970\",\"title\":\"파인애플떡갈비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01068_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01068_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01068_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01068_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01068_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01068_5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01068_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(갈빗살\",\"60g)\",\"파인애플(45g)\",\"양파(8g)\",\"표고버섯(7g)\",\"전분(10g)\",\"파(5g)\",\"마늘(2g)\",\"진간장(3g)\",\"설탕(1g)\",\"참기름(1.5g)\",\"후춧가루(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"떡갈비에 파인애플을 넣으면 육질도 부드럽게 하고 천연 감미료로 사용할 수 있어요.\",\"instructions\":[\"1. 파인애플은 7cm로 자르고\\n남은 자투리와 파, 마늘, 양파,\\n표고버섯은 곱게 다진다.\",\"2. 갈빗살은 곱게 다져 간장,\\n설탕, 파, 마늘, 참기름, 추후로\\n양념한다.\",\"3. 다진 파인애플, 양파, 표고버섯은\\n볶아 수분을 제거한다.\",\"4. 전분 일부와 갈빗살, 다진\\n파인애플, 양파, 표고버섯을 섞고\\n치댄다.\",\"5. 잘라둔 파인애플에 남은 전분을\\n묻힌 뒤 고기반죽으로 감싼다.\",\"6. 팬 또는 오븐(180℃, 15분)에\\n노릇하게 굽는다.\"]},{\"id\":\"k971\",\"title\":\"건강가지말이+참깨마요소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01069_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01069_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01069_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01069_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01069_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01069_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01069_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지(200g)\",\"단호박(30g)\",\"삼색파프리카(30g)\",\"당근(30g)\",\"사과(30g)\",\"배(30g)\",\"무순(10g)\",\"청양고추(20g)\",\"마요네즈(30g)\",\"참깨(40g)\",\"꿀(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"가지말이 안에 단호박을 바르고, 참깨마요소스의 꿀이 설탕을 대신해줘요.\",\"instructions\":[\"1. 가지는 길이대로 얇게\\n슬라이스한 뒤 살짝 굽는다.\",\"2. 파프리카, 당근, 사과는 얇게\\n채썬다.\",\"3. 단호박은 속을 파내고 쪄서\\n으깬다.\",\"4. 참깨에 마요네즈, 꿀, 간 배를\\n넣고 섞어 참깨마요소스를\\n만든다.\",\"5. 구운 가지에 단호박을 얇게 \\n바르고 야채들을 넣고 돌돌 만다.\",\"6. 참깨마요소스를 올린다.\"]},{\"id\":\"k972\",\"title\":\"순창 고추장 두부강정\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01070_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01070_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01070_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01070_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01070_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01070_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01070_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(불고기용\",\"60g)\",\"두부(400g)\",\"새송이버섯(40g)\",\"당근(30g)\",\"양파(10g)\",\"마늘(15g)\",\"생강가루(5g)\",\"고추장(50g)\",\"튀김가루(200g)\",\"전분(20g)\",\"맥주(200ml)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"올리고당과 케첩이 들어가면 강정 소스의 농도를 살리면서 맛있는 단맛을 내요.\",\"instructions\":[\"1. 당근, 새송이버섯, 소고기, 양파는\\n가늘게 채 썰어 간장, 꿀, 생강가루,\\n다진 마늘로 양념한 뒤 볶는다.\",\"2. 두부는 반으로 잘라 속에 칼집을 \\n낸 뒤 소금을 뿌려 수분을\\n제거한다.\",\"3. 두부에 전분을 골고루 묻힌다.\",\"4. 볶은 야채와 고기를 두부 사이에\\n넣는다.\",\"5. 튀김가루, 전분, 차가운 맥주를\\n섞어 튀김 반죽을 만든 뒤 두부에\\n입혀 170℃기름에 튀긴다.\",\"6. 고추장, 케첩, 올리고당을 섞고\\n냄비에 졸여 소스를 만들고 튀긴\\n두부를 지진다.\"]},{\"id\":\"k973\",\"title\":\"곤약 백김치 말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01071_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01071_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01071_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01071_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01071_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01071_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01071_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오징어(30g)\",\"곤약(100g)\",\"백김치(50g)\",\"삼색파프리카(20g)\",\"부추(10g)\",\"청주(15g)\",\"통후추(5알)\",\"월계수잎(1장)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"파프리카를 넣으면 설탕을 넣지 않아도 단맛을 낼 수 있어요.\",\"instructions\":[\"1. 곤약은 얇게 편으로 썰어 데친 뒤\\n백김치 국물에 절인다.\",\"2. 물에 월계수잎, 통후추, 청주를\\n넣고 오징어를 질기지 않게 살짝\\n삶는다.\",\"3. 파프리카는 채썰고 백김치는\\n물기를 제거한다.\",\"4. 곤약을 깔고 백김치, 오징어,\\n파프리카를 얹어 말아준다.\",\"5. 부추로 풀어지지 않게 단단히\\n매듭을 짓는다.\",\"6. 아랫부분을 정리하고 접시에\\n담는다.\"]},{\"id\":\"k974\",\"title\":\"묵은지비프롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01072_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01072_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01072_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01072_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01072_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01072_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01072_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(불고기용\",\"100g)\",\"묵은지(100g)\",\"팽이버섯(20g)\",\"아스파라거스(10g)\",\"삼색파프리카(20g)\",\"참나물(10g)\",\"달걀(1개)\",\"전분(20g)\",\"올리브오일(50g)\",\"매실액(30g)\",\"레몬즙(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기양념에 설탕 대신 매실액을 사용하면 설탕 사용도 줄이고 음식의 풍미도 높일 수 있어요.\",\"instructions\":[\"1. 소고기는 올리브오일, 매실액,\\n레몬즙, 소금, 후춧가루로\\n밑간한다.\",\"2. 묵은지는 흐르는 물에 헹궈\\n양념을 제거한다.\",\"3. 팽이버섯은 굵은 가닥으로\\n분리하고 아스파라거스는\\n밑기둥을 제거한다.\",\"4. 빨강, 노랑, 주황 파프리카는\\n막대모양으로 썬다.\",\"5. 묵은지 위에 달걀 흰자를 바르고\\n소고기를 펼치고 전분을 묻힌 뒤\\n야채를 넣고 돌돌 만다.\",\"6. 200℃로 예열한 오븐에 넣고\\n15분간 굽는다.\"]},{\"id\":\"k975\",\"title\":\"바나나를 감싼 일본식 달걀말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01073_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01073_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01073_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01073_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01073_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01073_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01073_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀(3개)\",\"바나나(1개)\",\"전분(5g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바나나를 넣으면 부드러우면서 달콤한 맛을 낼 수 있어요.\",\"instructions\":[\"1. 달걀을 흰자와 노른자로\\n분리한다.\",\"2. 흰자와 노른자를 각각 풀어\\n전분과 소금을 넣는다.\",\"3. 팬에 식용유를 두르고 노른자를\\n부어 반정도 익힌다.\",\"4. 바나나를 넣고 말아준다.\",\"5. 흰자를 부어 4번을 감싸 \\n말아준다.\",\"6. 먹기 좋은 크기로 자른다.\"]},{\"id\":\"k976\",\"title\":\"그린커리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01074_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01074_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01074_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01074_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01074_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01074_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01074_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"50g)\",\"그린커리\",\"페이스트(50g)\",\"코코넛밀크(40g)\",\"당근(30g)\",\"가지(50g)\",\"양송이버섯(20g)\",\"레몬그라스(10g)\",\"마늘(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"그린커리의 매운맛과 코코넛밀크의 부드럽고 달짝지근한 맛으로 설탕을 넣지 않고\\n만들 수 있어요.\",\"instructions\":[\"1. 마늘은 입자있게 다진다.\",\"2. 닭가슴살, 당근, 가지, 양송이\\n버섯은 먹기 좋은 크기로 자른다.\",\"3. 팬에 기름을 두르고 마늘을\\n볶다가 가지, 당근, 양송이버섯\\n순으로 넣고 볶는다.\",\"4. 그린커리 페이스트를 넣고\\n볶는다.\",\"5. 4번에 레몬그라스, 물 한 컵과\\n코코넛밀크 2/3를 넣고 끓인다.\",\"6. 코코넛밀크로 농도를 조절하여\\n완성한다.\"]},{\"id\":\"k977\",\"title\":\"현미 고구마 아란치니\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01075_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01075_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01075_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01075_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01075_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01075_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01075_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마(100g)\",\"현미밥(210g)\",\"새송이버섯(25g)\",\"당근(25g)\",\"양파(25g)\",\"달걀(1개)\",\"파슬리(3g)\",\"빵가루(200g)\",\"밀가루(100g)\",\"소금(2g)\",\"후춧가루(1g)\",\"식용유(500g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마를 이용해 단맛을 내고, 당 함량이 적은 현미를 사용해 덜 달면서 건강한 한끼 식사용 아란치니를 만들 수 있어요.\",\"instructions\":[\"1. 고구마는 삶아서 식힌 후 으깬다.\",\"2. 새송이버섯, 양파, 당근은 다진\\n후 후춧가루와 소금을 넣고 팬에\\n볶는다.\",\"3. 야채가 익으면 현미밥을 넣어\\n볶은 후 식힌다.\",\"4. 볶은 현미밥은 속에 고구마를\\n채우고 동그란 모양을 만든다.\",\"5. 밀가루, 달걀물, 빵가루 순으로 \\n묻힌다.\",\"6. 170~180℃ 기름에 튀긴다.\"]},{\"id\":\"k978\",\"title\":\"유자 치킨 꿔바로우\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01076_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01076_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01076_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01076_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01076_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01076_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01076_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"150g)\",\"생강(5g)\",\"녹말(50g)\",\"찹쌀가루(50g)\",\"유자청(10g)\",\"전분(5g)\",\"꿀(10g)\",\"소금(1g)\",\"후춧가루(1g)\",\"식초(45g)\",\"식용유(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"유자청이 설탕을 대신하고 유자의 상큼한 향으로 부족한 단맛을 보완할 수 있어요.\",\"instructions\":[\"1. 닭가슴살을 슬라이스하여 소금,\\n후춧가루로 밑간을 하고 다진\\n생강을 발라 잡냄새를 제거한다.\",\"2. 밑간한 닭가슴살에 찹쌀가루를\\n묻힌다.\",\"3. 녹말, 식용유, 물을 섞어 반죽을\\n만든다.\",\"4. 2번에 반죽을 골고루 묻혀 170℃\\n기름에서 튀긴다.\",\"5. 식초와 유자청을 넣고 끓인 후\\n간장으로 간을 맞추고 전분을\\n풀어 농도를 맞춘다.\",\"6. 튀긴 꿔바로우를 소스에 넣고\\n버무린다.\"]},{\"id\":\"k979\",\"title\":\"펌킨크로켓\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01077_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01077_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01077_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01077_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01077_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01077_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01077_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(80g)\",\"양파(20g)\",\"당근(10g)\",\"참나물(10g)\",\"달걀(1개)\",\"모짜렐라치즈(10g)\",\"빵가루(500g)\",\"식용유(500g)\",\"소금(1g)\",\"후춧가루(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박의 단맛과 볶은 양파의 단맛이 설탕을 대신해요.\",\"instructions\":[\"1. 참나물은 데친 뒤 잘게 다진다.\",\"2. 양파와 당근은 잘게 다진 뒤\\n볶는다.\",\"3. 단호박을 찐 뒤 으깨고 다진\\n참나물, 볶은 양파, 당근을 넣고\\n소금, 후춧가루로 밑간한다.\",\"4. 빵가루를 조금 넣고 섞어 되직한\\n반죽을 만든다.\",\"5. 반죽에 모짜렐라치즈를 넣고\\n한입 크기로 빚은 뒤 달걀, 빵가루\\n순으로 옷을 입힌다.\",\"6.  170℃ 기름에 튀긴다.\"]},{\"id\":\"k980\",\"title\":\"이태리튀밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01078_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01078_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01078_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01078_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01078_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01078_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01078_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀(100g)\",\"방울토마토(2개)\",\"바질(3g)\",\"옥수수(20g)\",\"달걀(1개)\",\"빵가루(30g)\",\"파마산치즈가루(20g)\",\"생모짜렐라치즈(20g)\",\"버터(4g)\",\"올리브오일(3g)\",\"소금(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"옥수수, 토마토를 사용하면 은은한 천연의 단맛을 낼 수 있어요\",\"instructions\":[\"1. 냄비에 물 한 컵을 넣고 끓으면\\n소금을 조금 넣고 쌀을 넣어\\n끓인다.\",\"2. 쌀이 물을 흡수하면 버터를 넣고\\n골고루 섞은 뒤 파마산치즈가루를\\n넣고 섞어 접시에 펼쳐 식힌다.\",\"3. 방울토마토는 굵게 다진 뒤\\n물기를 제거하고 바질은 얇게 채\\n썬다.\",\"4. 모짜렐라치즈는 손으로 작게\\n뜯어 반은 바질, 토마토와 섞어\\n소금과 올리브오일로 간을 하고,\\n나머지는 옥수수와 섞는다.\",\"5. 식은 밥에 4번의 소를 각각 넣고\\n동그랗게 빚는다.\",\"6. 달걀물, 빵가루 순으로 묻혀\\n170℃ 기름에서 튀긴다.\"]},{\"id\":\"k981\",\"title\":\"현미 입은 미트볼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01079_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01079_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01079_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01079_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01079_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01079_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01079_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(100g)\",\"돼지고기(100g)\",\"대추(4알)\",\"배(1개)\",\"현미튀밥(30g)\",\"밀가루(20g)\",\"양파(60g)\",\"마늘(30g)\",\"쪽파(30g)\",\"생강(5g)\",\"간장(30g)\",\"소금(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고기의 대추와 소스의 배, 대추, 양파가 설탕을 대신해요.\",\"instructions\":[\"1. 양파 40g, 마늘 20g, 대추 2알, 배,\\n생강, 간장, 물 70g을 넣고 졸여\\n소스를 만든다.\",\"2. 소고기, 돼지고기는 다진 뒤 소금,\\n후추, 참기름, 깨, 간장 15g을\\n넣어 밑간한다.\",\"3. 양파, 마늘, 대추를 다진 뒤\\n밀가루, 식용유와 함께 2번에\\n넣고 치댄다.\",\"4. 3번의 반죽을 동그란 모양으로\\n빚는다.\",\"5. 팬에 기름을 두르고 미트볼을\\n굽는다.\",\"6. 팬에 소스를 부어가며 졸인 뒤\\n쪽파, 현미튀밥을 올린다.\"]},{\"id\":\"k982\",\"title\":\"시금치 볶음 쌀국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01080_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01080_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01080_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01080_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01080_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01080_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01080_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(100g)\",\"쌀국수(150g)\",\"시금치(40g)\",\"달걀(1개)\",\"메추리알(20g)\",\"마늘(20g)\",\"굴소스(20g)\",\"식초(30g)\",\"땅콩(3g)\",\"전분(10g)\",\"청주(5g)\",\"고추기름(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"굴소스와 식초로 감칠맛을 더해 단맛이 없어도 담백하고 맛있는 요리를 할 수 있어요.\",\"instructions\":[\"1. 미지근한 물에 쌀국수 면을\\n부드러워질 때까지 불린다.\",\"2. 새우는 소금, 청주, 달걀 흰자,\\n전분물로 반죽한 뒤 튀긴다.\",\"3.  팬에 메추리알을 부친다.\",\"4. 팬에 올리브오일과 고추기름을\\n두르고 마늘을 살짝 볶은 뒤\\n튀긴새우와 쌀국수 면을 넣는다.\",\"5. 굴소스와 식초로 간을 하고\\n재료가 다 익어갈 때 시금치를\\n넣고 불을 끈다.\",\"6. 땅콩가루와 메추리알을 올려\\n마무리한다.\"]},{\"id\":\"k983\",\"title\":\"새우채소꼬치구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01081_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01081_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01081_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01081_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01081_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01081_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01081_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"새우(60g)\",\"단호박(60g)\",\"양배추(40g)\",\"방울토마토(35g)\",\"대파(20g)\",\"후추(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박을 익혀서 사용하면 소스를 따로 쓰지 않아도 단맛을 충분히 낼 수 있어요.\",\"instructions\":[\"1. 새우는 꼬리와 껍질을 제거한 뒤 \\n후추로 밑간한다.\",\"2. 단호박은 찜기에 찐다\",\"3. 대파와 양배추는 4cm 길이로\\n썬다.\",\"4. 찐단호박을 4cm 길이로 썬다.\",\"5. 프라이팬에 새우, 단호박, 대파, \\n양배추, 방울토마토를 굽는다..\",\"6. 꼬지에 보기 좋게 끼운다.\"]},{\"id\":\"k984\",\"title\":\"영유아를 위한 고소한 닭꼬치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01082_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01082_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01082_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01082_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01082_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01082_5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01082_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭고기(가슴살\",\"25g)\",\"우유(10g)\",\"아몬드슬라이스(10g)\",\"참깨(2g)\",\"흑임자(1g)\",\"소금(0.1g)\",\"후춧가루(0.1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"견과류를 사용하면 고소한 풍미를 더하여 당을 첨가하지 않아도 맛있게 먹을 수 있어요.\",\"instructions\":[\"1. 닭가슴살은 10cm 길이로 얇게\\n자른다.\",\"2. 닭가슴살에 소금, 후춧가루로\\n밑간을 한다.\",\"3. 아몬드슬라이스를 잘게 다지고\\n흑임자, 참깨와 섞는다.\",\"4. 닭가슴살에 3번을 묻힌다.\",\"5. 팬에 식용유를 두르고 4번을 \\n노릇하게 굽는다.\",\"6. 꼬지에 꽂는다.\"]},{\"id\":\"k985\",\"title\":\"얌얌 맛있게타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01083_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01083_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01083_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01083_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01083_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01083_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01083_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바게트(1/4개)\",\"새송이버섯(15g)\",\"표고버섯(10g)\",\"방울토마토(2개)\",\"바질(10g)\",\"생모짜렐라치즈(15g)\",\"마늘(2.5g)\",\"올리브오일(10g)\",\"소금(0.2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바질, 치즈, 표고버섯, 새송이버섯과 같은 다양한 식재료를 사용하면 첨가당 없이도 다양한 풍미로 맛있게 먹을 수 있어요\",\"instructions\":[\"1. 바게트는 1cm 두께로 잘라 한쪽\\n면에 다진 마늘과 올리브오일을\\n발라 팬에 굽고 식힌다.\",\"2. 방울토마토는 씨를 제거하고\\n다진 뒤 물기를 빼주고 바질은\\n얇게 슬라이스 한다.\",\"3. 생모짜렐라치즈를 잘게 찢고\\n방울토마토, 바질과 함께 소금,\\n올리브오일에 섞는다.\",\"4. 새송이버섯, 표고버섯, 마늘은\\n잘게 다진다.\",\"5. 팬에 올리브오일을 두르고 다진 \\n마늘을 볶다가 표고버섯과\\n새송이버섯을 넣어 볶는다.\",\"6. 바게트에 각각 소를 얹는다.\"]},{\"id\":\"k986\",\"title\":\"오! 푸룻한 뿌리채소\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01084_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01084_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01084_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01084_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01084_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01084_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01084_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"우엉(25g)\",\"연근(50g)\",\"오렌지(100g)\",\"요거트(50g)\",\"크랜베리(10g)\",\"땅콩(5g)\",\"호두(3g)\",\"레디쉬(5g)\",\"식초(3g)\",\"머스터드(3g)\",\"얼음(200g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"요거트에 머스터드를 섞으면 상큼하고 톡쏘는 맛으로 첨가당 없이 맛있는 소스를 만들 수 있어요.\",\"instructions\":[\"1. 연근, 우엉은 껍질을 벗겨 0.2cm\\n두게로 슬라이스한 뒤 식촛물에\\n담군다.\",\"2. 레디쉬는 얇게 슬라이스하여\\n얼음물에 담그고 오렌지는\\n껍질을 벗겨 과육만 분리한다.\",\"3. 우엉과 연근을 끓는 물에 데친\\n뒤 얼음물에 담궈 열기를 식히고\\n물기를 뺀다.\",\"4. 요거트와 머스터드를 섞어\\n소스를 만들고 땅콩, 호두는 잘게\\n부순다.\",\"5. 연근, 우엉, 레디쉬, 오렌지, 땅콩, \\n호두를 만들어둔 소스와 함께\\n버무린다.\",\"6. 그릇에 담고 크랜베리를 올린다.\"]},{\"id\":\"k987\",\"title\":\"채소 팬케익\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053352_1416213232021.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/801-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/801-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/801-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/801-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/801-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/801-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당근갈은것 40g\",\"돼지호박갈은것 20g\",\"셀러리다진것 10g\",\"양파다진것 10g\",\"중력분 32g\",\"후춧가루 0.21g\",\"저나트륨 베이킹 파우더 0.5g\",\"머스터드 파우더 0.5g\",\"식용유 2g\",\"달걀 55g\",\"저지방우유 100g\",\"메이플시럽 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 당근, 돼지호박은 큼직하게 썬다.\",\"2. 셀러리와 양파는 곱게 다진다.\",\"3. 믹서에 당근, 돼지호박, 저지방우유, 달걀, 중력분, 머스터드 파우더, 저나트륨 베이킹 파우더, 후춧가루를 넣고 간다.\",\"4. 3을 그릇에 붓고 셀러리와 양파를 섞는다.\",\"5. 팬에 식용유를 넣고 팬케이크를 부친다.\",\"6. 메이플시럽을 곁들여 낸다.\"]},{\"id\":\"k988\",\"title\":\"누룽지과자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053352_1416213232895.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/802-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/802-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/802-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/802-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/802-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/802-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 20g\",\"달걀흰자 20g\",\"밀가루 8g\",\"식용유 2g\",\"땅콩 10g\",\"건포도 10g\",\"호두 12g\",\"딸기잼 40g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 찬밥에 달걀흰자, 밀가루를 넣고 되직하게 반죽한다.\",\"2. 1cm두께로 민 뒤 둥근 모양 또는 하트 모양으로 만든다.\",\"3. 땅콩, 호두는 잘게 다진다.\",\"4. 팬에 식용유를 넣고 빚어 놓은 밥을 앞, 뒤로 노릇하게 굽는다.\",\"5. 구워진 밥 과자 윗면에 딸기잼을 바른다.\",\"6. 건포도, 호두, 땅콩을 고루 얹어준다.\"]},{\"id\":\"k989\",\"title\":\"단호박 경단\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053353_1416213233629.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/803-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/803-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/803-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/803-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/803-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/803-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 18g\",\"찹쌀가루 18g\",\"카스텔라 18g\",\"소금 0.2g\",\"건포도 2g\",\"호박씨 0.8g\",\"잣 2g\",\"물 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 카스텔라는 굵게 떼어 믹서기에 곱게간다.\",\"2. 단호박은 깨끗이 씻어 찜통에 넣고 쪄낸 뒤 껍질을 제거하고 뜨거울 때 체에 내린다.\",\"3. 찹쌀가루에 소금을 넣고 뜨거운 물을 조금씩 부으면서 익반죽 하다가 2의 으깬 단호박을 넣고 되직해질 때까지 반죽한다.\",\"4. 3의 반죽을 떼어내 손바닥으로 동그랗게 굴려서 가운데 잣을 하나씩 넣고 동그랗게 빚는다.\",\"5. 끓는 물에 4의 경단을 넣고 삶아 둥둥 떠오르면  잠시 두었다 건져 차가운 물에 헹군다.\",\"6. 경단에 카스텔라 가루를 1/3가량 뭍하고 건포도와 호박씨로 장식한다.\"]},{\"id\":\"k990\",\"title\":\"모듬탕수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053354_1416213234285.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/804-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/804-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/804-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/804-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/804-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/804-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"표고버섯마른것 20g\",\"연근 20g\",\"주황파프리카 20g\",\"노랑파프리카 20g\",\"브로컬리 20g\",\"식용유 10g [소스소개] 탕수소스:감자녹말가루 7g\",\"레드와인 5g\",\"간장 2g\",\"식초 1g\",\"설탕 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"녹말이 들어간 점도가 있는 소스류는 염분이 적어도 싱겁게 느끼지 않도록 하므로 이를 적절히 사용하는 것이 저나트륨 요리에 좋다\",\"instructions\":[\"1. 표고버섯은 불려서 기둥을 떼고 끓는 물에 삶은 다음 물기를 제거한다.\",\"2. 손질한 표고버섯은 간장, 다진마늘, 참기름으로 양념한다.\",\"3. 연근은 껍질을 벗기고 깍둑 썰기하여 식초 물에 담근다.\",\"4. 파프리카는 마름모 형태로 썰고 브로콜리는 한 입 크기의 송이로 자른다.\",\"5. 준비한 재료에 녹말가루를 충분히 묻혀서 170℃ 정도의 식용유에서 튀겨낸다.\",\"6. 레드와인, 간장, 식초, 설탕을 넣고 20분가량 끓여 졸인다음 녹말과 물을 섞은 물녹말로 농도를 맞추어 4에 끼얹어 낸다\"]},{\"id\":\"k991\",\"title\":\"새싹 비빔밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053356_1416213236259.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/805-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/805-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/805-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/805-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/805-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/805-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밥 100g\",\"각종 새싹 20g\",\"무순 2g\",\"샐러리 5g\",\"쑥갓 5g\",\"래디쉬 15g [소스소개] 저나트륨 볶음고추장(5인분):고추장 7.5g\",\"물 15g\",\"사과 50g\",\"설탕 2.5g\",\"참기름 2g\",\"쇠고기다진것 20g  고기양념(5인분):파다진것 2.5g\",\"마늘다진것 1.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 새싹과 무순은 씻어 물기를 제거한다.\",\"2. 셀러리는 껍질을 벗겨 3cm로 어슷썬다.\",\"3. 쑥갓은 3cm로 썰고, 래디쉬는 채썬다.\",\"4. 다진 소고기는 고기양념을 한다.\",\"5. 팬에 식용유를 소량 넣고 양념한 소고기를 볶다가 분량의 소스 재료를 넣고 볶아 저나트륨 볶음고추장을 만든다.\",\"6. 그릇에 밥을 담고 준비된 새싹과 채소를 돌려담고 저나트륨 볶음고추장을 곁들인다.\"]},{\"id\":\"k992\",\"title\":\"감자냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053400_1416213240973.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/808-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/808-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/808-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/808-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/808-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/808-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자 40g\",\"래디쉬 5g\",\"오이 10g [소스소개 단촛물:물60g\",\"식초 1.5g\",\"설탕 1.5g\",\"파인애플주스 1.5g\",\"소금 0.3g 겨자초장:겨자가루 1.5g\",\"물미지근한것 1g\",\"설탕 2g\",\"식초 3g\",\"소금 0.03g\",\"파인애플주스 1.6g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감자는 생으로 물에 담갔다가 먹거나 살짝 끓는 물에 데친 후 사용한다.\",\"instructions\":[\"1. 감자는 껍질을 벗긴다.\",\"2. 감자는 0.3x0.2x7cm로 채썬다.\",\"3. 오이는 씻어 0.3x0.2x7cm로 채썬다.\",\"4. 래디쉬는 씻어 0.3x0.2x2cm로 채썬다.\",\"5. 단촛물을 감자, 오이, 래디쉬를 각각 담궜다가 물기를 뺀다.\",\"6. 채소를 차게 두었다가 겨자초장을 곁들인다.\"]},{\"id\":\"k993\",\"title\":\"고추잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053402_1416213242394.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/809-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/809-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/809-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/809-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/809-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/809-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기 30g\",\"청피망 30g\",\"죽순통조림 6g\",\"홍고추 1.4g\",\"표고버섯 7g\",\"소금 0.4g\",\"참기름 1g\",\"식용유 5g[소스소개] 고기 밑간 양념:후춧가루 0.1g\",\"정종 1g\",\"달걀 4g\",\"녹말가루 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"돼지고기나 채소에는 밑간을 하지않고 마지막에 간을 한다. 꽃빵과 함께 제공하면 좋다.\",\"instructions\":[\"1. 고추는 반으로 갈라 속을 제거한다.\",\"2. 손질한 고추는 3cm 길이로 채썬다.\",\"3. 죽순, 표고버섯, 대파, 생강을 채썬다.\",\"4. 돼지고기는 얇게 저민 후 0.3x5cm 길이로 곱게 채썰어 밑간 한다.\",\"5. 밑간 한 돼지고기를 달걀흰자, 녹말가루에 묻혀 놓는다.\",\"6. 팬에 식용유를 넣고 생강을 볶아 향을 내고 채소, 고기를 넣어 볶다가 간을 한 다음 참기름을 두르고 굽는다.\"]},{\"id\":\"k994\",\"title\":\"나박김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053404_1416213244017.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/810-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/810-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/810-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/810-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/810-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/810-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추잎 50g\",\"무30g\",\"당근 10g\",\"실파 5g\",\"수삼 10g\",\"마늘 3g\",\"생강 5g\",\"고춧가루 2.5g\",\"미나리 10g\",\"홍고추 2g\",\"물 70g\",\"소금 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 배추, 무는 2x2cm로 나박썬다.\",\"2. 썰어논 배추, 무는 소금에 살짝 절여둔다.\",\"3. 당근은 모양을 내어 썰고 실파, 미나리도 2cm로 썰어둔다.\",\"4. 마늘과 생강, 홍고추는 채썰고 수삼은 어슷하게 썬다.\",\"5. 물을 끓여 식힌 후 소창에 고춧가루를 싸서 김치국물을 만든다.\",\"6. 무와 배추가 절여지며 준비한 재료들에 김치국물을 부어 완성한다.\"]},{\"id\":\"k995\",\"title\":\"냉잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053405_1416213245344.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/811-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/811-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/811-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/811-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/811-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/811-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당면 20g\",\"표고버섯 5g\",\"양배추 5g\",\"오이 5g\",\"당근 3g\",\"깻잎 5g\",\"상추 5g\",\"청피망 3g\",\"홍피망 3g\",\"팽이버섯 3g\",\"노랑파프리카 3g\",\"간장 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"당면, 채소들은 모두 간을 하지않고 양념장을 먹기 직전에 뿌려 무쳐서 낸다.\",\"instructions\":[\"1. 당면은 물에 불렸다가 끓는 물에 충분히 삶아 부드러워지면 차가운 물에 헹구어 물기를 뺀다.\",\"2. 표고버섯은 불려 꼭 짜 채썬다.\",\"3. 표교버섯은 간장, 들기름에 무쳐 팬에 볶는다.\",\"4. 양배추, 오이, 당근, 깻잎, 상추, 피망, 파프리카는 곱게 채썬다.\",\"5. 배를 강판에 갈아 간장, 소금, 식초, 겨자, 설탕을 넣어 잡채 양념을 만든다.\",\"6. 큰 접시에 준비된 채소를 예쁘게 돌려 담고 가운데 당면을 놓은 후 양념을 부어준다.\"]},{\"id\":\"k996\",\"title\":\"단호박 두부찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053407_1416213247545.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/812-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/812-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/812-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/812-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/812-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/812-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 14g\",\"두부 14g\",\"마늘 1.4g\",\"풋고추 10.5g [소스소개] 저나트륨조림소스:간장 2.4g\",\"청주 1.1g\",\"다시물 12.3g\",\"맛술 0.4g\",\"설탕 0.4g\",\"소금 0.1g\",\"식용유 0.7\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 단호박은 깨끗이 씻어 반을 갈라 씨를 제거하고 찜통에서 쪄낸다.\",\"2. 식힌 단호박은 껍질을 제거하고 한 입 크기로 썬다.\",\"3. 두부는 1.5cm 정육면체로 썰어 데친다.\",\"4. 마늘은 편으로 썰고 청고추는 송송 썰어 팬에 볶는다.\",\"5. 간장에 분량의 재료를 한데 섞어 살짝 끓여 식힌다.\",\"6. 준비된 재료를 담고 소스를 뿌린다.\"]},{\"id\":\"k997\",\"title\":\"단호박전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053408_1416213248950.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/813-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/813-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/813-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/813-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/813-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/813-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박 50g\",\"밀가루 50g\",\"소금 0.2g\",\"식용유 10g\",\"물 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박 자체가 맛이 있어 소금을 넣지 않고 전을 부쳐도 담백하다.\",\"instructions\":[\"1. 단호박은 껍질을 벗겨 속살은 그대로 두고 씨만 털어 낸다.\",\"2. 속살은 숟가락으로 긁어내어 다진다.\",\"3. 나머지 부분은 채썰어 2~3번 다진 후 소금을 조금 넣고 살짝 절인다.\",\"4. 호박에 물기가 생기면 밀가루를 넣어 되직하게 반죽한다.\",\"5. 팬이 가열되면 식용유를 넣고 한 숟가락씩 떠넣어 얇게 펴서 부친다.\",\"6. 앞뒤로 노릇하게 부치고 접시에 담아 완성한다.\"]},{\"id\":\"k998\",\"title\":\"도라지 검은깨 튀김\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053411_1416213251151.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/814-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/814-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/814-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/814-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/814-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/814-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"도라지 25g\",\"검은깨 1.25g\",\"찹쌀가루 8.75g\",\"튀김가루 10g\",\"식용유 3g[소스소개] 저나트륨 간장소스:간장 1g\",\"식초 2g\",\"설탕 2g\",\"물 3g\",\"고추냉이 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 통 도라지는 껍질을 벗기고 0.3cm 두께로 썬다.\",\"2. 손질한 도라지는 옅은 소름물에 잠시 담가 쓴맛을 없애고 차가운 물에 헹궈 물기를 닦는다. (3% 소금물)\",\"3. 그릇에 찹쌀가루와 튀김가루를 넣어 걸쭉한 농도가 되도록 물을 부어 튀김옷의 농도를 맞춘다.\",\"4. 농도를 맞춘 튀김옷 반죽에 검은깨를 섞는다.\",\"5. 손질한 도라지에 튀김옷을 입혀 170℃의 식용유에 튀긴다.\",\"6. 저나트륨 간장소스를 곁들인다.\"]},{\"id\":\"k999\",\"title\":\"발사믹으로 양념한 채소요리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053412_1416213252650.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/815-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/815-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/815-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/815-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/815-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/815-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"브로컬리 20g\",\"컬리플라워 20g\",\"돼지호박 10g\",\"당근 10g\",\"양파 10g\",\"가지 10g [소스소개] 저나트륨 발사믹소스:올리브오일 30g\",\"포도식초 5g\",\"오레가노마른것 0.5g\",\"타임마른것 0.5g\",\"로즈마리마다진것 0.5g\",\"저나트륨소금 0.2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 소금의 맛은 보통 소금과 비슷하지만 Na(나트륨) 대신 K(칼륨)을 써서 만든 소금으로 나트륨의 함량을 줄이는 요리에 사용하기 적합하다.\",\"instructions\":[\"1. 브로콜리와 컬리플라워는 한 입 크기로 손질한다.\",\"2. 당근, 돼지호박, 양파는 5cm 길이로 가늘게 채썬다.\",\"3. 가지는 길게 썬다.\",\"4. 브로콜리, 컬리플라워, 당근을 끓는 물에 데친 후 냉수에 헹궈낸다.\",\"5. 발사믹소스를 만든다.\",\"6. 준비한 채소들을 발사믹소스에 절인다.\"]},{\"id\":\"k1000\",\"title\":\"버섯 굴소스 볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053414_1416213254308.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/816-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/816-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/816-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/816-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/816-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/816-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"표고버섯 5g\",\"양송이버섯 10g\",\"느타리버섯 10g\",\"팽이버섯 5g\",\"새송이버섯 10g\",\"식용유 2g [소스소개]굴소스:굴소스 0.3g\",\"간장 0.3g\",\"마늘다진것 1g\",\"물 5g\",\"참기름 0.6g\",\"부추 또는 실파 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"굴소스는 간장보다 염도가 높으므로 간장 양의 1/2~1/3 정도를 나누어 넣도록 한다.\",\"instructions\":[\"1. 버섯들은 잘 씻어 건진다.\",\"2. 팬에 식용유를 두르고 버섯을 넣어 175℃ 오븐에서 5분 가열한다.\",\"3. 소스 양념을 모두 섞어 끓인다.\",\"4. 오븐에 구운 버섯에 3의 소스를 뿌린다.\",\"5. 부추를 버섯크기와 비슷하게 썬다.\",\"6. 썬 부추나 실파로 장식한다.\"]},{\"id\":\"k1001\",\"title\":\"비트와 호두 요리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053416_1416213256221.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/817-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/817-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/817-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/817-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/817-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/817-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"비트 80g\",\"사워크림 15g\",\"식용유 1g\",\"파슬리 다진것 약간[소스소개]비트양념:식초 15g\",\"설탕 7g\",\"후추 0.1g\",\"식용유 1g 호두캐러멜:호두 12g\",\"황설탕 24g\",\"물 15g\",\"게피 0.5g\",\"넛맥 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 비트는 물에 삶아 80%를 익힌다.\",\"2. 껍질을 벗기고 모양내어 썬다.\",\"3. 비트는 분량에 맞게 양념한다.\",\"4. 양념한비트는 175℃ 오븐에서 굽는다.\",\"5. 호두캐러멜을 만든다. (펜에 설탕과 물을 녹이고 계피, 넉맷을 넣은 뒤 호두를 넣는다.)\",\"6. 그릇에 비트와 호두캐러멜을 담고 사워크림과 다진 파슬리로 장식한다.\"]},{\"id\":\"k1002\",\"title\":\"상추 겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053417_1416213257888.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/818-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/818-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/818-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/818-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/818-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/818-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"상추 15g\",\"간장 2g\",\"물 2g\",\"매실농축액 5g\",\"고춧가루 1g\",\"통깨 0.4g\",\"식초 0.4g\",\"영양부추 10g\",\"양파 5g\",\"홍고추 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 상추를 깨끗하게 씻어 물기를 뺀 후 먹기 좋게 자른다.\",\"2. 영양부추는 3cm 길이로 썰고, 양파는 3cm 길이로 얇게 채썬다.\",\"3. 홍고추도 3cm 길이로 얄게 채썬다.\",\"4. 모든 채소들을 차가운 물에 담갔다가 물기를 빼서 준비해둔다.\",\"5. 간장에 물, 매실농축액, 고춧가루, 통깨, 식초를 넣어 겉절이 양념을 만든다.\",\"6. 상추에 양념을 넣고 젓가락으로 섞어준다.\"]},{\"id\":\"k1003\",\"title\":\"연근고구마샌드위치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01085_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01085_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01085_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01085_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01085_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01085_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01085_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연근(200g)\",\"고구마(200g)\",\"견과류(30g)\",\"튀김가루(100g)\",\"백년초가루(30g)\",\"달걀(1개)\",\"식용유(500g)\",\"소금(5g)\",\"식초(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"샌드위치 속에 들어간 고구마, 견과류가 달콤하고 고소한 맛을 내요.\",\"instructions\":[\"1. 연근 껍질을 제거하고 0.5cm\\n두께로 끓는 물에 소금, 식초를\\n넣어 살짝 데친다.\",\"2. 고구마는 껍질을 제거하고 삶아\\n으깬다.\",\"3. 견과류는 잘게 다져 삶은\\n고구마에 섞어 동그랑땡\\n모양으로 만든다.\",\"4. 튀김가루, 달걀, 소금을 넣고 튀김\\n반죽을 만든다.(백년초가루로\\n2가지 색의 반죽을 만든다)\",\"5. 연근 사이에 으깬 고구마를\\n넣는다.\",\"6. 연근 샌드위치를 만들어 170℃\\n기름에 튀긴다.\"]},{\"id\":\"k1004\",\"title\":\"파프리카깍두기(어린이용)\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01086_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01086_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01086_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01086_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01086_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01086_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01086_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"무(80g)\",\"파프리카(20g)\",\"사과(5g)\",\"현미(5g)\",\"실파(0.5g)\",\"멸치(5g)\",\"마늘(3g)\",\"멸치액젓(5g)\",\"올리고당(2g)\",\"천일염(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"적색 파프리카를 사용하면 단맛과 색감을 살릴 수 있어요.\",\"instructions\":[\"1. 무를 깍둑썰기하여 소금에 30분 \\n간 절인다.\",\"2. 실파를 잘게 다진다.\",\"3. 파프리카, 사과, 멸치액젓,\\n올리고당을 믹서에 넣고 간다.\",\"4. 멸치로 다시물을 만들고\\n현미밥과 다시물을 1:1로 넣어\\n끓인 후 현미풀을 만든다.\",\"5. 3번에 실파, 현미풀, 다진 마늘을\\n넣고 양념을 만든다.\",\"6. 절인 무를 체에 받쳐 소금물을\\n제거하고 양념을 넣어 버무린다.\"]},{\"id\":\"k1005\",\"title\":\"과일 김치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01087_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01087_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01087_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01087_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01087_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01087_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01087_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과(30g)\",\"배(10g)\",\"복숭아(15g)\",\"토마토(25g)\",\"치커리(3g)\",\"고춧가루(2g)\",\"마늘(3g)\",\"깨(2g)\",\"참기름(2g)\",\"소금(0.5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"매운 무 대신 제철 과일을 사용하고 설탕 대신 배를 갈아 넣어 건강한 단맛을 낼 수 있어요.\",\"instructions\":[\"1. 토마토는 십자로 칼집을 내고\\n끓는 물에 살짝 데쳐 껍질을\\n벗긴다.\",\"2. 사과, 복숭아는 깍둑썰고 소금에 \\n10분 정도 절인다.\",\"3. 배를 강판에 갈고, 마늘은 다진다.\",\"4. 갈아둔 배에 고춧가루, 다진 마늘,\\n깨, 참기름을 섞어 양념을 만든다.\",\"5.  절여둔 과일을 양념과 섞는다.\",\"6. 치커리를 넣고 섞는다.\"]},{\"id\":\"k1006\",\"title\":\"오이 짱아지 무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01088_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01088_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01088_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01088_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01088_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01088_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01088_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오이(1/2개)\",\"고춧가루(10g)\",\"매실액(15g)\",\"양파(10g)\",\"파(5g)\",\"마늘(5g)\",\"참기름(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕 대신 매실액을 사용하면 덜 달면서 풍미를 더해줄 수 있어요\",\"instructions\":[\"1. 오이를 끓는 소금물에 넣고\\n돌맹이로 누른다.\",\"2. 오이 색이 노랗게 변하면 썰어서 \\n물기를 완전히 제거한다.\",\"3. 파, 마늘을 다진다.\",\"4. 양파, 고춧가루, 매실액을 믹서에\\n넣고 간다.\",\"5. 4번에 참깨, 다진 파, 마늘, \\n참기름을 섞어 양념을 만든다.\",\"6. 오이에 양념을 넣고 잘 버무린다.\"]},{\"id\":\"k1007\",\"title\":\"비트 배추피클\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01089_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01089_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01089_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01089_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01089_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01089_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01089_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"비트(10g)\",\"배추(20g)\",\"무(50g)\",\"사과(50g)\",\"당근(10g)\",\"식초(25g)\",\"설탕(10g)\",\"월계수잎(2장)\",\"통후추(2g)\",\"물(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과를 갈아 넣어 설탕사용을 줄이고 통후추의 매콤한 맛이 단맛이 적어도 피클을 맛있게 해줘요.\",\"instructions\":[\"1. 무와 배추를 1x4x1cm 크기로 \\n자른다.\",\"2. 비트는 2x4x0.3cm로 자른다.\",\"3. 당근은 모양내어 자른다.\",\"4. 껍질 벗긴 사과와 물을 1:1 비율로\\n넣고 갈아 체에 내려 건더기를\\n제거한다.\",\"5. 4번에 식초를 2:1 비율로 넣고\\n월계수잎, 통후추를 넣고\\n끓여준다.\",\"6. 손질한 무, 배추, 비트, 당근을\\n넣고 식혀준다.\"]},{\"id\":\"k1008\",\"title\":\"오징어와사비마요무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01090_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01090_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01090_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01090_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01090_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01090_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01090_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"진미채(10g)\",\"유자청(3g)\",\"마요네즈(15g)\",\"와사비(3g)\",\"레몬즙(2g)\",\"깨(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"유자청으로 단맛을 내고 와사비의 매콤한 맛과 마요네즈의 고소한 맛으로 설탕 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 진미채는 미지근한 물에 불린 뒤\\n물기를 뺀다.\",\"2. 물기 뺀 진미채를 따끈해질 \\n때까지 마른 팬에 살짝 볶는다.\",\"3. 유자청은 잘게 다진다.\",\"4. 유자청에 마요네즈, 와사비,\\n레몬즙을 섞어 양념을 만든다.\",\"5. 진미채에 양념을 소량씩 \\n넣으면서 버무린다.\",\"6. 깨를 뿌려 마무리한다.\"]},{\"id\":\"k1009\",\"title\":\"삼색 버터롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01091_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01091_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01091_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01091_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01091_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01091_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01091_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홍시(25g)\",\"호두(25g)\",\"곶감(25g)\",\"대추(25g)\",\"블루베리(25g)\",\"크랜베리(25g)\",\"강력분(275g)\",\"꿀(20g)\",\"버터(40g)\",\"달걀(1/2개)\",\"이스트(11g)\",\"소금(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"버터롤 안에 홍시, 곶감, 블루베리 등 다양한 과일, 견과류를 넣으면 버터롤 반죽에 설탕을 사용하지 않아도 맛있게 만들 수 있어요.\",\"instructions\":[\"1. 강력분, 꿀, 달걀, 이스트, 소금,\\n탈지분유, 제빵개량제, 물을\\n믹서에 넣고 섞는다.\",\"2. 가루가 모두 녹아 섞이면 버터를\\n넣고 완전히 섞은 뒤 세 덩어리로\\n나눈다.\",\"3. 60분 간 1차 발효 후 40g씩\\n분할하여 둥글리기하고 15분 간\\n중간 발효 한다.\",\"4. 반죽을 손으로 굴려 뭉툭한 원뿔\\n모양을 만들고 밀대로 밀어 긴\\n삼각형 모양을 만든다.\",\"5. 각 반죽에 홍시/호두, 곶감/대추,\\n블루베리/크랜베리를 넣고\\n버터롤을 모양을 만든다.\",\"6. 40분 간 2차 발효 후 210℃\\n오븐에서 10분 간 굽는다.\"]},{\"id\":\"k1010\",\"title\":\"고구마빵&과일잼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01092_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01092_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01092_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01092_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01092_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01092_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01092_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마(75g)\",\"제철과일(25g)\",\"달걀(1/2개)\",\"우유(7g)\",\"크랜베리(7g)\",\"아몬드(5g)\",\"호두(5g)\",\"올리고당(3g)\",\"레몬즙(7g)\",\"올리브오일(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"잼을 바르지 않고 따로 제공하면 당 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 고구마는 껍질을 벗기고 적당한\\n크기로 썰어 삶은 뒤 50g은\\n으깨고 25g은 작게 자른다.\",\"2. 으깬 고구마에 달걀노른자,\\n우유를 넣고 섞는다.\",\"3. 달걀흰자는 머랭을 만들어\\n2번과 섞은 뒤 크랜베리, 잘라둔\\n고구마와 살살 섞는다.\",\"4. 유리용기 안쪽에 올리브오일을\\n바르고 잘게 부순 아몬드와 호두를\\n뿌린 뒤 3번을 담고 전자레인지로\\n7분 간 가열한다.\",\"5. 제철과일을 중불에서 10분 간 끓인\\n뒤 올리고당을 넣고 한소끔 끓이고,\\n레몬즙을 넣고 다시 한소끔 끓여\\n저당 과일잼을 만든다.\",\"6. 4번을 접시에 뒤집어 담고 저당\\n과일잼을 곁들인다.\"]},{\"id\":\"k1011\",\"title\":\"감말랭이 찰빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01093_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01093_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01093_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01093_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01093_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01093_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01093_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감말랭이(10g)\",\"쌀가루(7g)\",\"보릿가루(7g)\",\"밀가루(6g)\",\"고구마(13g)\",\"냉동딸기(13g)\",\"흑임자(4g)\",\"소금(0.5g)\",\"식용유(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"감말랭이와 냉동딸기가 설탕 대신 단맛을 보충하고, 흑임자로 고소한 맛을 더할 수 있어요.\",\"instructions\":[\"1. 고구마는 삶은 뒤 껍질을\\n제거한다.\",\"2. 쌀가루, 보릿가루, 밀가루는 체에\\n내린다.\",\"3. 체에 내린 가루에 삶은 고구마,\\n감말랭이, 냉동딸기, 흑임자를\\n넣고 믹서에 간다.\",\"4. 믹서에 간 반죽을 10cm 길이의 \\n스틱모양으로 성형한다.\",\"5. 170℃ 기름에 반죽을 튀긴다.\",\"6. 기름을 제거하고 그릇에 담는다.\"]},{\"id\":\"k1012\",\"title\":\"바나나 속 달걀빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01094_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01094_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01094_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01094_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01094_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01094_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01094_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀(2개)\",\"바나나(30g)\",\"밀가루(20g)\",\"우유(5g)\",\"베이킹파우더(0.3g)\",\"버터(0.5g)\",\"소금(0.1g)\",\"물(8g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소량의 소금을 넣으면 단맛이 더 많이 나요\",\"instructions\":[\"1. 달걀노른자, 밀가루,\\n베이킹파우더, 우유, 소금을 섞어\\n반죽을 만든다.\",\"2. 바나나 절반은 0.5cm 두께로\\n자르고 나머지는 잘게 다진다.\",\"3. 타르트팬에 버터를 바른 뒤\\n반죽을 얇게 깔고 그 위에\\n바나나를 담고 소금을 조금\\n뿌린다.\",\"4. 3번에 달걀흰자로 만든 머랭을\\n올린다.\",\"5. 머랭 가운데 바나나 1조각을\\n올리고 노른자 물을 바른다.\",\"6. 달군 팬에 물을 넣고 타르트팬\\n채로 넣은 뒤 약불에서 15분 간\\n익힌다.\"]},{\"id\":\"k1013\",\"title\":\"두부빼빼로\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01095_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01095_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01095_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01095_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01095_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01095_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01095_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(25g)\",\"포도(10g)\",\"호두(1g)\",\"검은깨(1g)\",\"식빵(7.5g)\",\"밀가루(5g)\",\"계피가루(1g)\",\"소금(0.1g)\",\"꿀(2g)\",\"식용유(5g)\",\"물(8g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"포도로 단맛을 더하고 검은깨와 호두로 고소한 맛을 낼 수 있어요.\",\"instructions\":[\"1. 두부를 칼등으로 곱게 으깬 후\\n면포에 싸서 물기를 짠다.\",\"2. 식빵은 믹서에 갈아 빵가루를\\n만들고, 포도는 믹서에 간 뒤 걸러\\n포도즙을 만든다.\",\"3. 냄비에 포도즙, 꿀, 물, 소금을\\n넣고 끓으면 불을 끄고 식용유를\\n넣고 섞는다.\",\"4. 밀가루에 계피가루, 으깬 두부,\\n검은깨, 다진 호두를 넣고\\n반죽한다.\",\"5. 짤주머니에 반죽을 넣고 15cm\\n길이로 팬에 짠다.\",\"6. 반죽표면에 3번을 바르고 180℃\\n오븐에 15분 간 굽는다.\"]},{\"id\":\"k1014\",\"title\":\"땅콩호박 타르트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01096_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01096_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01096_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01096_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01096_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01096_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01096_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"땅콩호박(1/2개)\",\"아몬드가루(13g)\",\"버터(15g)\",\"박력분(35g)\",\"요거트(10g)\",\"달걀(1/2개)\",\"사과(1/2개)\",\"전분(5g)\",\"소금(0.5g)\",\"호두(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"사과즙과 요거트를 이용하면 새콤달콤한 맛으로 설탕 없이 맛있게 만들 수 있어요.\",\"instructions\":[\"1. 차가운 버터에 박력분,\\n아몬드가루, 소금을 넣어\\n으깨가면서 섞는다.\",\"2. 달걀과 물을 넣고 섞어 반죽을\\n만들어 휴지시킨다.\",\"3. 휴지시킨 반죽을 밀대로 밀어\\n커터로 모양을 찍은 뒤 180℃\\n오븐에 굽는다.\",\"4. 땅콩호박을 삶아 체에 걸러 으깬\\n뒤 사과즙, 달걀을 넣고 중탕하여\\n섞는다.\",\"5. 4번에 전분을 조금씩 넣으면서\\n농도를 맞춘 뒤 요거트를 넣는다.\",\"6. 5번을 짤주머니에 담은 뒤 3번\\n위에 굵게 짜주고 다진 호두를\\n뿌린다.\"]},{\"id\":\"k1015\",\"title\":\"고구마 바나나 무스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01097_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01097_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01097_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01097_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01097_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01097_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01097_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마(50g)\",\"바나나(17g)\",\"달걀(1개)\",\"크림치즈(10g)\",\"우유(20g)\",\"생크림(25g)\",\"딸기잼(15g)\",\"젤라틴(8g)\",\"바닐라빈(1g)\",\"올리고당(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마와 바나나로 무스를 만들어 설탕이 없어도 달콤한 무스를 만들 수 있어요.\",\"instructions\":[\"1. 삶아 으깬 고구마와 으깬\\n바나나를 섞는다.\",\"2. 볼에 달걀노른자, 올리고당,\\n우유, 바닐라빈을 넣고 중탕시켜\\n걸쭉하게 만든 뒤 1번과 섞는다.\",\"3. 2번에 휘핑한 생크림을 넣고 섞은\\n뒤 젤라틴을 넣는다.\",\"4. 딸기잼에 우유를 넣고 끓여\\n젤리를 만든다.\",\"5. 무스 틀에 3번과 딸기잼 젤리를\\n차곡차곡 넣어 굳힌다.\",\"6. 굳힌 무스위에 크림치즈를\\n올린다.\"]},{\"id\":\"k1016\",\"title\":\"단호박치즈스틱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01098_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01098_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01098_2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01098_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01098_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01098_5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01098_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(200g)\",\"새우살(120g)\",\"삼색파프리카(80g)\",\"양파(40g)\",\"옥수수(20g)\",\"모짜렐라치즈(20g)\",\"춘권피(10장)\",\"생크림(15g)\",\"식용유(40g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박으로 설탕을 대신할 수 있어요.\",\"instructions\":[\"1. 단호박은 찜통에 찐 뒤 껍질을\\n제거하고 으깨 생크림을 넣고\\n섞는다.\",\"2. 새우살, 파프리카, 양파는 잘게\\n다진 뒤 팬에 식용유를 두르고\\n볶는다.\",\"3. 볼에 1번과 2번, 옥수수, 소금을\\n넣고 잘 섞는다.\",\"4. 춘권피에 3번을 넓게 펴준 뒤  \\n모짜렐라 치즈를 올린다.\",\"5. 춘권피를 잘 말아 모양을 만든다.\",\"6. 180℃ 기름에 튀긴다.\"]},{\"id\":\"k1017\",\"title\":\"크랜베리 샤브레 쿠키\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01099_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01099_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01099_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01099_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01099_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01099_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01099_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"크랜베리(8g)\",\"슈가파우더(10g)\",\"박력분(30g)\",\"아몬드가루(10g)\",\"백년초가루(2g)\",\"우유(3g)\",\"버터(25g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"크랜베리의 단맛으로 설탕 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 실온에 둔 버터를 휘핑기로\\n풀어준 뒤 슈가파우더를 넣고\\n섞는다.\",\"2. 박력분, 아몬드가루, \\n백년초가루를 넣고 섞는다.\",\"3. 크랜베리를 넣고 섞는다.\",\"4. 우유를 넣고 섞는다.\",\"5. 동그란 원기둥 모양으로 만들어\\n냉동실에서 1시간 정도 굳힌다.\",\"6. 굳은 반죽을 1cm 두께로 잘라\\n180℃ 오븐에서 15분 간 굽는다.\"]},{\"id\":\"k1018\",\"title\":\"생과일 타르트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01100_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01100_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01100_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01100_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01100_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01100_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01100_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"박력분(50g)\",\"버터(27g)\",\"달걀(1/4개)\",\"아몬드가루(9g)\",\"꿀(2g)\",\"생크림(37g)\",\"블랙초콜릿(83g)\",\"키위(10g)\",\"블루베리(10g)\",\"체리(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"타르트 충전물로 설탕 대신 생크림과 블랙초콜릿을 녹여 사용할 수 있어요.\",\"instructions\":[\"1. 믹서로 버터를 풀어준 뒤 달걀,\\n꿀을 넣고 섞는다.\",\"2. 박력분과 아몬드가루는 체에\\n내려 주걱으로 섞은 뒤 밀봉하여\\n냉장고에서 30분 간 휴지시킨다.\",\"3. 0.2~0.3cm 두께로 밀어 편 뒤\\n틀에 담아 포크로 구멍을 내고\\n170℃ 오븐에서 25분 간 굽는다.\",\"4. 생크림을 끓인 후 블랙초콜릿을\\n넣고 섞는다.\",\"5. 구운 타르트에 4번을 반 정도\\n채운 뒤 냉동실에서 10분 간\\n굳힌다.\",\"6. 과일을 적당한 크기로 잘라\\n타르트에 올린다.\"]},{\"id\":\"k1019\",\"title\":\"당 떨어진 마들렌\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01101_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01101_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01101_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01101_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01101_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01101_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01101_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"대추고(5g)\",\"대추(2알)\",\"당근퓨레(5g)\",\"녹차가루(5g)\",\"팥앙금(5g)\",\"박력분(150g)\",\"꿀(15g)\",\"버터(150g)\",\"달걀(2개)\",\"베이킹파우더(3g)\",\"소금(0.8g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"반죽에 설탕 대신 꿀과 대추, 당근퓨레, 팥앙금으로 단맛을 낼 수 있어요.\",\"instructions\":[\"1. 박력분, 베이킹파우더, 소금을\\n체친 뒤 달걀을 2~3회 나누어\\n넣는다.\",\"2. 1번을 3등분 하여 대추고,\\n채썬대추/당근퓨레/녹차가루,\\n팥앙금을 각각 섞는다.\",\"3. 각각에 녹인 버터(50g)를 넣고\\n부드럽게 섞은 뒤 비닐을 덮어\\n실온에서 30분 간 휴지시킨다.\",\"4. 마들렌 팬을 깨끗이 닦고 버터를\\n바른 뒤 밀가루를 뿌린다.\",\"5. 짤주머니에 원형 깍지를 끼우고 \\n반죽을 채운 뒤 팬에 80~90%\\n정도 짜 넣는다.\",\"6. 175℃ 오븐에서 20분 간 굽는다.\"]},{\"id\":\"k1020\",\"title\":\"삼색 머핀\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01102_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01102_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01102_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01102_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01102_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01102_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01102_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당근(10g)\",\"시금치(10g)\",\"사과(10g)\",\"호두(5g)\",\"크랜베리(5g)\",\"박력분(150g)\",\"꿀(15g)\",\"버터(90g)\",\"달걀(2개)\",\"소금(1.5g)\",\"베이킹소다(0.6g)\",\"베이킹파우더(2.4g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"반죽에 설탕 대신 꿀과 과일퓨레, 견과류 등을 넣으면 색감도 살리고 단맛도 낼 수 있어요.\",\"instructions\":[\"1. 당근, 시금치, 사과는 물에 익힌\\n후 각각 갈아 퓨레를 만든다.\",\"2. 볼에 버터를 부드럽게 풀고 소금,\\n꿀을 섞어 녹이고 달걀을 2~3회\\n나눠 넣으며 크림을 만든다.\",\"3. 2번에 박력분, 베이킹소다,\\n베이킹파우더를 체쳐 넣고\\n가볍게 섞는다.\",\"4. 반죽을 3등분 한 뒤 당근퓨레/\\n사과퓨레/시금치퓨레를 각각\\n섞고 크랜베리, 호두로 장식한다.\",\"5. 잘 섞은 반죽을 머핀틀에 70%\\n채워 넣는다.\",\"6.  175℃ 오븐에서 30분 간 굽는다.\"]},{\"id\":\"k1021\",\"title\":\"수삼 냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053419_1416213259232.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/819-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/819-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/819-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/819-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/819-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/819-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"수삼 10g\",\"배 20g\",\"오이 20g\",\"샐러리 20g >[소스소개] 저나트륨내채소스:대추 1g\",\"유자청 10g\",\"소금 0.5g\",\"식초 2g\",\"꿀 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 소스에 무치는 요리이므로 향이 강한 과일청인 유자청을 넣어 염도가 낮은 것을 못느끼도록 만든 소스이다.\",\"instructions\":[\"1. 수삼은 흙을 깨끗이 씻은 후 잔뿌리를 다듬어내고 길이로 얇게 썬다.\",\"2. 배, 오이, 셀러리도 각각 1.5cm x 7cm 크기로 얇게 썬다.\",\"3. 대추와 유자는 잘게 다진다.\",\"4. 수삼, 오이, 배, 셀러리는 차가운 물에 담가 조직감을 살린다.\",\"5. 대추, 유자청, 소금, 식초, 꿀물을 합하여 저나트륨 냉채소스를 만든다.\",\"6. 4의 채소를 건져서 물기를 제거하고 소스에 살짝 버무려 낸다.\"]},{\"id\":\"k1022\",\"title\":\"아시아식 채소 두부 볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053420_1416213260840.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/820-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/820-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/820-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/820-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/820-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/820-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"해선장 2g\",\"간장 1.3g\",\"녹말 5g\",\"참기름 2.5g\",\"식용유 5g\",\"마늘다진것 2.5g\",\"두부1.2cm 90g\",\"그린빈 10g\",\"청경채 20g\",\"영콘 15g\",\"밤 20g\",\"땅콩다진것 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 작은 불에 물과 해선장소스, 간장, 전분, 참기름, 녹말가루를 넣고 녹말가루가 잘 풀릴 때까지 섞는다.\",\"2. 큰 소스팬을 중간불에 올린다. 식용유를 두르고 마늘을 15~20초간 타지않게 볶는다.\",\"3. 두부를 넣고 옅은 골든 브라운 색이 날 때까지 3~4분간 익힌다.\",\"4. 데친 그린빈, 청경채, 영콘, 밤을 넣고 섞어준다.\",\"5. 볶은 두부에 소스를 끼얹는다.\",\"6. 땅콩가루를 뿌려 완성한다.\"]},{\"id\":\"k1023\",\"title\":\"양배추 깻잎 피클\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053421_1416213261401.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/821-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/821-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/821-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/821-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/821-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/821-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양배추 16g\",\"깻잎 6g\",\"설탕 2g\",\"청고추 1g\",\"홍고추 1g [소스소개]피클소스:물 35g\",\"식초 2g. 소금 1g\",\"통후추 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 물, 식초, 설탕, 소금, 통후추를 살짝 끓인 후 식혀 준비한다.\",\"2. 양배추와 깻잎을 한장씩 켜켜이 쌓는다.\",\"3. 깻잎 크기에 맞추어 썬다.\",\"4. 청, 홍고추는 어슷썰어 씨를 털어낸다.\",\"5. 그릇에 양배추, 깻잎, 청·홍고추를 무거운 것으로 눌러놓아 뜨지 않게 한 다음 준비한 피클국물을 붓는다.\",\"6. 뚜껑을 닫아 밀봉하여 냉장고에 보관한다.\"]},{\"id\":\"k1024\",\"title\":\"얼갈이 무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053422_1416213262832.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/822-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/822-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/822-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/822-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/822-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/822-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"얼갈이 배추 60g\",\"홍고추 0.6g [소스소개저나트륨 무침양념:두부 30g\",\"된장 3.5g\",\"마늘 1.5g\",\"깨 2g\",\"참기름 1g\",\"사과 20g\",\"홍고추 5g\",\"물 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 무침양념은 된장을 줄이는 대신 두부를 으깨서 넣어 무침 양념양을 늘려 사용하는 것이 특징이다.\",\"instructions\":[\"1. 얼갈이 배추를 씻는다.\",\"2. 씻은 배추는 끓는 물에 데친다.\",\"3. 홍고추는 씨를 빼고 어슷하게 채썬다.\",\"4. 데친 얼갈이 배추를 차가운 물에 씻어 꼭 짠다.\",\"5. 저나트륨 무침양념 재료들을 믹서에 넣고 간다.\",\"6. 4에 채썬 고추와 무침 양념을 넣고 버무린다.\"]},{\"id\":\"k1025\",\"title\":\"오이초절임\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030743_1678082863061.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030839_1678082919597.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030856_1678082936693.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030914_1678082954768.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030930_1678082970944.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030949_1678082989601.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031004_1678083004847.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 오이(60g)\",\"통마늘(3g)\",\"생강(5g)\",\"말린 홍고추(3g)\",\"•오이초절임소스 : 양조식초(60g)\",\"설탕(60g)\",\"두반장(3g)\",\"고추기름(40g)\",\"물(60g)\",\"•양념 : 소금(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•두반장과 고추기름을 사용해 오이초절임소스를 만들면 새콤달콤한 맛을 낼 수 있어요.\",\"instructions\":[\"1. 오이는 길이로 4등분하여 삼각썰기 한 후 0.8cm 두께의 막대모양으로 썬다.\",\"2. 소금에 살짝 절여 꼭 짜서 준비한다.\",\"3. 통마늘은 길이로 3등분하고 생강은 편으로 썬다.\",\"4. 마른 홍고추는 가위를 사용하여 어슷하게 자른다.\",\"5. 손질한 모든 재료를 볼에 담고 푹 잠길 정도로 오이초절임소스를 붓는다.\",\"6. 냉장 보관해 마무리한다.\"]},{\"id\":\"k1026\",\"title\":\"잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053427_1416213267031.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/825-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/825-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/825-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/825-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/825-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/825-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당면 20g\",\"등심얇게썬것 20g\",\"당근 5g\",\"표고버섯마른것 10g\",\"느타리버섯 10g\",\"양파 10g\",\"호부추 5g\",\"도라지 10g\",\"달걀 5g\",\"간장 2g\",\"설탕 5g\",\"마늘 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 잡채에서는 당면, 고기, 각종 채소들을 모두 간을 하지않고 볶고 마지막에 저나트륨 간장소스를 만들어, 먹기 직전에 무쳐서 낸다.\",\"instructions\":[\"1. 당면은 물에 불렸다가 끓는 물에 충분히 삶아 부드러워지면 차가운 물에 헹구어 물기를 뺀다.\",\"2. 표고버섯은 불려 꼭 짜 채썬 후 간장, 들기름에 무쳐 팬에 볶는다.\",\"3. 양배추, 오이, 당근, 깻잎, 상추, 피망, 파프리카는 곱게 채썬다.\",\"4. 배를 강판에 간다.\",\"5. 배와 간장, 소금, 식초, 겨자, 설탕을 넣어 잡채 양념을 만든다.\",\"6. 큰 접시에 준비된 채소를 예쁘게 돌려 담고 가운데 당면을 놓은 후 양념을 부어준다.\"]},{\"id\":\"k1027\",\"title\":\"참기름 드레싱의 즉석 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053428_1416213268062.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/826-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/826-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/826-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/826-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/826-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/826-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"상추 10g\",\"오이 10g\",\"당근 5g\",\"비타민 5g\",\"방울토마토 10g\",\"쑥갓 2g\",\"견과류 : 아몬드\",\"호두 2g [소스소개] 참기름드래싱:간장2g\",\"마늘 2g\",\"레몬즙 2g\",\"식초 15g\",\"참기름 4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 샐러드 재료들을 잘 씻는다.\",\"2. 체에 받쳐 물기를 제거한다.\",\"3. 채소들을 한입 크기로 썰어둔다.\",\"4. 드레싱 재료를 섞어 참기름 드레싱을 만든다.\",\"5. 유리병에 모든 재료를 넣고, 참기름 드레싱을 넣고 섞은 후 접시에 담아 낸다.\",\"6. 샐러드 위에 견과류를 뿌려 마무리 한다.\"]},{\"id\":\"k1028\",\"title\":\"고추 장떡\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053428_1416213268811.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/827-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/827-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/827-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/827-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/827-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/827-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"청고추 10g\",\"깻잎 10g\",\"애호박 20g\",\"홍고추 5g\",\"밀가루 50g\",\"고추자 3g\",\"식용유 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 애호박은 다진다.\",\"2. 깻잎은 송송 썰어 굵게 다진다.\",\"3. 풋고추와 홍고추는 반을 갈라 얇게 썬다.\",\"4. 밀가루에 물을 넣어 되게 반죽한 후 고추장을 풀어준다.\",\"5. 반죽에 채소를 넣어 섞은 후 기름 두른 팬에 장떡을 두껍지 않게 부친다.\",\"6. 썰어놓은 청고추와 홍고추로 장떡을 장식한다.\"]},{\"id\":\"k1029\",\"title\":\"호박 프리타타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053429_1416213269545.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/828-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/828-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/828-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/828-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/828-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/828-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"달걀 110g\",\"돼지호박 50g\",\"실파 20g\",\"마늘다진것 1g\",\"후춧가루 0.1g\",\"모짜렐라치즈 30g\",\"파마산치즈 7g\",\"캔 토마토 20g\",\"타임 2g\",\"바질 2g\",\"로즈마리 2g\",\"오레가노 다진것 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 오븐을 175℃로 예열시킨다.\",\"2. 작은 불에 달걀을 넣고 젓는다.\",\"3. 오븐용 후라이팬에 식용유를 두르고 마늘을 볶다가 작게 깍둑썰기한 애호박을 넣고 부드러워질 때까지 볶는다.\",\"4. 어슷썬 실파를 넣고 젓다가 토마토, 로즈마리, 바질, 오레가노, 후춧가루를 넣고 채소들이 잘 섞일 때 까지 저어준 뒤 달걀을 넣고 젓는다.\",\"5. 모짜렐라 치즈를 뿌리고 170℃ 오븐에서 12분간 구워 산적꼬지로 중간을 찔러넣었을 때 아무것도 묻어나오지 않을 때 까지 익힌다.\",\"6. 익힌 프리타타를 브로일러에 넣어 골든 브라운 색이 날 때까지 3~4분 간 더 익히고 파마산치즈를 뿌린다.\"]},{\"id\":\"k1030\",\"title\":\"고구마 빠스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053430_1416213270309.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/829-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/829-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/829-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/829-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/829-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/829-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마 60g\",\"설탕 20g\",\"물 2g\",\"검은깨 2g\",\"식용유 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 고구마를 깨끗이 씻어 껍질을 벗긴다.\",\"2. 고구마를 길게 4등분 하여 4cm로 토막낸다.\",\"3. 깊은 팬에 식용유를 넣고 160℃로 만든다.\",\"4. 3에 고구마를 넣고 저어가며 4분 정도 노릇하게 튀긴다.\",\"5. 팬에 식용유를 약간 넣고 뜨거워지면 설탕을 넣어 중불에 녹여 갈색나는 시럽을 만든다.\",\"6. 튀긴 고구마를 시럽에 버무리고 검은깨를 뿌린다.\"]},{\"id\":\"k1031\",\"title\":\"검은콩 스프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053431_1416213271961.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/830-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/830-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/830-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/830-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/830-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/830-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콩 30g\",\"닭육수 70g\",\"토마토 30g\",\"큐민파우더 1g\",\"파슬리말린것 1g\",\"카엔패퍼 2g\",\"사워크림 2g\",\"두유 70g\",\"식용유 4g\",\"양파다진것 7g\",\"샐러리 3g\",\"마늘 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 양파, 셀러리, 마늘, 토마토를 굵게 다진다.\",\"2. 팬에 양파를 볶다가 셀러리와 마늘을 볶는다.\",\"3. 콩과 두유를 넣은 뒤 토마토, 육수, 큐민, 파슬리, 카엔패퍼를 넣는다.\",\"4. 볶은 재료들을 모두 믹서로 간다.\",\"5. 믹서에 간 재료들을 체에 거른다.\",\"6. 체에 거른 것을 끓여주고 사워크림으로 장식한다\"]},{\"id\":\"k1032\",\"title\":\"곤약 콩조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053432_1416213272821.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/831-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/831-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/831-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/831-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/831-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/831-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"저나트륨 조림소스는 보통 조림소스보다 간장 양을 1/3정도 줄여서 사용하므로 색을 위해 설탕은 흑설탕을 사용하는 것이 좋다.\",\"instructions\":[\"1. 곤약은 4cm 길이로 얇게 썬 후 가운데 칼집을 넣어 꼰다.\",\"2. 곤약은 데쳐서 준비한다.\",\"3. 콩은 불리고 마늘은 편으로 썬다.\",\"4. 마늘쫑은 3cm 길이로 자르고, 파프리카는 1.5 x 4cm로 썬다.\",\"5. 냄비에 저나트륨 조림소스 재료를 넣고 곤약을 넣어 약한 불에서 졸인다.\",\"6. 나머지 재료를 넣어 연하게 졸여낸다\"]},{\"id\":\"k1033\",\"title\":\"도토리묵 콩국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053433_1416213273867.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/832-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/832-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/832-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/832-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/832-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/832-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"곤약 10g\",\"서리태 20g\",\"마늘 2g\",\"마늘쫑 5g\",\"파프리카 5g[소스소개] 저나트륨 조림소스:간장 3.4g\",\"설탕 2.2g\",\"물 20g\",\"청주 1.5g\",\"소금 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 대두는 6시간 이상 물에 불린다.\",\"2. 불린통은 20~25분 정도 삶은 후 껍질을 제거한다.\",\"3. 껍질을 제거한 삶은 콩에 참깨와 물을 넣고 곱게 갈아 체에 받쳐 준비한다.\",\"4. 도토리묵은 7cm 길이로 굵게 채썬다.\",\"5. 오이는 어슷썬다.\",\"6. 그릇에 묵을 담고 준비된 콩국을 붓고 오이채를 곁들인다.\"]},{\"id\":\"k1034\",\"title\":\"두부 달걀전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053435_1416213275631.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/834-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/834-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/834-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/834-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/834-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/834-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 60g\",\"카레가루 0.4g\",\"후춧가루 0.1g\",\"밀가루 1.6g\",\"식용유 4g\",\"청고추 0.5g\",\"홍고추 0.5g [소스소개]저나트륨초간장소스:간장 1g\",\"식초 1.5g\",\"설탕 0.3g\",\"통깨 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 두부를 네모지게 썬다.\",\"2. 썬 두부를 소창으로 물기를 제거한 뒤 소금과 후춧가루로 밑간 한다.\",\"3. 달걀에 카레가루를 넣은 뒤 잘 풀어준다.\",\"4. 두부의 물기를 제거하고 밀가루를 묻힌 뒤 3의 달걀을 입힌다.\",\"5. 식용유를 넣은 팬에 청, 홍고추 송송 썬것을 얹어 노릇하게 지진다.\",\"6. 저나트륨 초간장소스를 곁들여 낸다.\"]},{\"id\":\"k1035\",\"title\":\"두부선과 저나트륨 겨자 간장소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053436_1416213276349.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/835-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/835-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/835-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/835-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/835-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/835-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 80g\",\"표고버섯마른것 10g\",\"쇠고기 20g\",\"애호박 20g [소스소개] 쇠고기양념:설탕 1.4g\",\"참기름 1g<br />저나트륨겨자간장소스 :간장 2g\",\"물 2g\",\"식초 2g\",\"설탕 0.5g\",\"연겨자 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쇠고기, 표고버섯, 애호박은 간을 하지않고 볶는다.\",\"instructions\":[\"1. 두부는 4x4x2cm로 썰어 윗면에 대각선으로 칼집을 넣는다.\",\"2. 호박은 3cm길이로 곱게 채썰고 표고버섯과 소고기도 곱게 채썰어 양념한다.\",\"3. 팬에 채썬 호박을 볶아내고 양념해 둔 표고버섯과 소고기도 볶는다.\",\"4. 칼집을 넣은 두부에 볶아둔 재료들을 칼집 사이에 끼워 속을 넣는다.\",\"5. 준비된 두부를 찜통에 쪄낸다.\",\"6. 저나트륨 겨자 간장소스를 곁들인다.\"]},{\"id\":\"k1036\",\"title\":\"두부 튀김 조림\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053437_1416213277067.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/836-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/836-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/836-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/836-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/836-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/836-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 70g\",\"녹말가루 10g\",\"식용유 10g\",\"청피망 5g\",\"홍피망 5g\",\"노랑파프리카 5g\",\"간장 2g\",\"물엿 5g\",\"고추장 1g\",\"참기름 2g\",\"통깨 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"튀김요리도 풍미가 강해 염을 많이 사용하지 않고 먹을 때 좋은 조리방법이다.\",\"instructions\":[\"1. 두부를 정육면체로 썬 후 소금을 뿌려 물기를 제거한 뒤 녹말가루를 묻힌다.\",\"2. 두부를 175℃ 식용유에 바삭하게 두 번 튀긴다.\",\"3. 피망과 파프리카는 0.5cm의 사각모양으로 썬다.\",\"4. 불에 간장, 물엿, 고추장, 물을 분량대로 섞어둔다.\",\"5. 식용유를 넣은 팬에 피망과 파프리카를 볶다가 섞어둔 조림장을 넣고 끓인다.\",\"6. 5의 조림장이 걸쭉해지면 튀긴 두부를 넣고 조심스레 섞은 후 참기름과 통깨로 마무리 한다.\"]},{\"id\":\"k1037\",\"title\":\"바나나 스틱\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01103_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01103_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01103_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01103_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01103_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01103_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01103_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바나나(100g)\",\"중력분(85g)\",\"옥수수가루(35g)\",\"아몬드가루(20g)\",\"베이킹파우더(3g)\",\"버터(30g)\",\"소금(1g)\",\"달걀(1개)\",\"크랜베리(30g)\",\"땅콩(30g)\",\"흑임자(30g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바나나, 옥수수가루, 아몬드 가루가 설탕을 대신해 단맛을 보충할 수 있어요.\",\"instructions\":[\"1. 크랜베리는 작게 자르고\\n바나나는 구운 후 으깬다.\",\"2. 중력분, 옥수수, 아몬드가루,\\n베이킹파우더를 체 친 후 소금을\\n섞고 바나나와 달걀을 섞는다.\",\"3. 버터를 부드럽게 만들어 반죽에\\n넣고 섞는다.\",\"4. 반죽을 10g으로 분할하고\\n10cm정도의 막대 모양으로 만들고\\n일부는 크랜베리를 속에 넣어준다.\",\"5. 손잡이 부분을 제외한 부분을 \\n흑임자, 잘게부순 땅콩에 굴린다.\",\"6. 170℃ 오븐에서 25분 간 굽는다.\"]},{\"id\":\"k1038\",\"title\":\"달코미 고구마 타르트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01104_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01104_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01104_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01104_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01104_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01104_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01104_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"딸기(150g)\",\"고구마(180g)\",\"요거트(85g)\",\"만두피(35g)\",\"우유(3g)\",\"식용유(700g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"첨가당 없이 딸기, 고구마를 가지고 단맛을 충분히 낼 수 있어요.\",\"instructions\":[\"1. 고구마 껍질을 벗기고 얇게 썬 뒤\\n삶아 잘게 으깬다.\",\"2. 요거트와 우유를 으깬 고구마에\\n섞어 고구마무스를 만든다.\",\"3. 만두피를 국자를 이용해\\n그릇모양으로 만들어 튀긴다.\",\"4. 튀긴 만두피의 기름을 제거한다.\",\"5. 만두피 그릇에 고구마무스를\\n채운다.\",\"6. 딸기를 입자있게 잘라 졸인 뒤\\n고구마무스 위에 올린다.\"]},{\"id\":\"k1039\",\"title\":\"콩가루 고구마 타르트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01105_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01105_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01105_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01105_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01105_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01105_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01105_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콩가루(15g)\",\"고구마(175g)\",\"박력분(65g)\",\"버터(80g)\",\"우유(25g)\",\"달걀(1/2개)\",\"생크림(30g)\",\"꿀(15g)\",\"소금(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마와 콩가루를 사용해 설탕을 대신하고 고소한 맛을 낼 수 있어요.\",\"instructions\":[\"1. 박력분, 콩가루를 체에 내리고\\n버터(50g)를~ 잘게 잘라 섞은 뒤\\n소금 녹인 물을 조금씩 섞는다.\",\"2. 반죽을 한 덩어리로 뭉쳐 냉장고에 1시간 정도 휴지키신 뒤 밀대로 0.3cm 두께로 밀고 표면에 구멍을 낸다.\",\"3. 2번을 타르트 틀에 넣어 밀착시키고 냉장고에 20분 간 휴지시킨 뒤 누름돌을 올리고 150℃ 오븐에 8분 간 굽는다.\",\"4. 버터(30g)를 풀어 꿀을 넣고 크림화 한 뒤 달걀을 섞고 휘핑한 생크림을 섞고 삶아 으깬 고구마와 콩가루를 섞는다.\",\"5. 고구마를 주사위 모양으로 잘라 오븐에 굽는다.\",\"6. 타르트에 콩가루 고구마 크림을 올리고 그 위에 구운 고구마와 꿀을 올린다.\"]},{\"id\":\"k1040\",\"title\":\"코마레티\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01106_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01106_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01106_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01106_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01106_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01106_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01106_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"아몬드슬라이스(50g)\",\"코코넛슬라이스(50g)\",\"설탕(15g)\",\"달걀(1개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"코코넛슬라이스를 이용하면 단맛과 풍미를 낼 수 있어요.\",\"instructions\":[\"1. 아몬드슬라이스를 비닐봉지에 넣고 적당한 크기로 조각낸다.\",\"2. 달걀흰자와 설탕을 넣고 설탕이 섞일 정도만 풀어준다.\",\"3. 2번에 조각낸 아몬드슬라이스와 코코넛슬라이스를 넣고 섞는다.\",\"4. 20g씩 원형으로 팬에 올린다.\",\"5. 160℃ 오븐에서 굽는다.\",\"6. 20분 정도부터 색이 나면 오븐에서 꺼내 식힌다.\"]},{\"id\":\"k1041\",\"title\":\"수(Sugaer)다(Down) 고구마 케이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01107_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01107_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01107_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01107_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01107_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01107_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01107_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밤고구마(65g)\",\"요거트(18g)\",\"키위(7g)\",\"파인애플(7g)\",\"카스테라(2g)\",\"블루베리(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕이 들어간 생크림 대신 요거트를 사용하면 부드러운 맛과 새콤한 맛을 더해 당 섭취를 줄일 수 있어요\",\"instructions\":[\"1. 고구마는 깨끗하게 씻은 뒤 껍질을 벗기고 찐다.\",\"2. 찐 고구마를 으깨고 요거트와 섞는다.\",\"3. 카스테라를 체에 갈아 가루를 만든다.\",\"4. 키위, 파인애플을 적당한 크기로 자른다.\",\"5. 무스틀에 2번을 넣어 평평하게 펴주고 키위, 블루베리, 파인애플을 넣고 요거트를 올린 뒤 다시 고구마를 넣어 펴준다.\",\"6. 카스테라 가루를 뿌리고 키위, 블루베리, 파인애플을 올린다.\"]},{\"id\":\"k1042\",\"title\":\"단구마 무스 샌드 케이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01108_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01108_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01108_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01108_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01108_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01108_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01108_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마(30g)\",\"단호박(30g)\",\"생크림(60g)\",\"달걀(2개)\",\"박력분(30g)\",\"우유(15g)\",\"설탕(10g)\",\"버터(3g)\",\"레몬즙(1g)\",\"크랜베리(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"레몬즙을 넣으면 설탕은 적게 넣고 더 달고 단단한 머랭을 만들 수 있어요.\",\"instructions\":[\"1. 달걀 노른자를 휘핑하고 박력분을 넣은 뒤 우유와 녹인 버터를 넣고 섞는다.\",\"2. 달걀 흰자는 레몬즙과 설탕을 3번에 나누어 넣으면서 머랭을 만든다.\",\"3. 머랭과 크랜베리를 노른자 반죽에 넣고 부드럽게 섞는다.\",\"4. 180℃ 오븐에서 15분 정도 구워 시트를 만든 뒤 컵모양으로 자른다.\",\"5. 고구마와 단호박은 삶은 뒤 껍질을 벗기고 각각 체에 내려 생크림을 섞는다.\",\"6. 시트, 단호박무스, 고구마무스 순서로 여러겹 쌓아 올린다.\"]},{\"id\":\"k1043\",\"title\":\"당근&그릭요거트 케이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01109_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01109_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01109_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01109_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01109_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01109_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01109_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"당근퓨레(5g)\",\"박력분(150g)\",\"달걀(3개)\",\"버터(37g)\",\"꿀(5g)\",\"소금(2g)\",\"설탕(180g)\",\"베이킹파우더(1.5g)\",\"바닐라향(1g)\",\"그릭요거트(150g)\",\"제철과일(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"생크림 대신에 당근퓨레를 섞은 그릭요거트를 사용하면 설탕양을 줄이면서 새콤달콤한 맛을 낼 수 있어요.\",\"instructions\":[\"1. 달걀 노른자를 풀어준 뒤 설탕(90g), 소금, 바닐라향을 3번에 나눠 넣으며 섞는다.\",\"2. 달걀 흰자는 60% 머랭을 만든 뒤 설탕(90g)을 조금씩 넣으면서 단단한 머랭을 만든다.\",\"3. 1번에 머랭 1/3을 넣고 섞은 뒤 박력분, 베이킹파우더를 체에 내려 섞는다.\",\"4. 3번에 꿀과 버터를 녹여 섞은 뒤 나머지 머랭을 넣고 원형틀에 절반 정도 반죽을 채운다.\",\"5. 170℃ 오븐에서 30분 간 구워 시트를 만든다.\",\"6. 시트와 당근퓨레를 섞은 그릭요거트를 번갈아 쌓고 맨 위에 제철과일을 올린다.\"]},{\"id\":\"k1044\",\"title\":\"완두콩 롤\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01110_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01110_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01110_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01110_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01110_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01110_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01110_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"완두콩(50g)\",\"식빵(50g)\",\"찹쌀가루(20g)\",\"우유(25g)\",\"올리고당(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"속재료로 설탕이 많은 생크림이나 슈크림 대신 완두콩크림과 찹쌀떡을 사용하면 건강한 단맛을 낼 수 있어요.\",\"instructions\":[\"1. 완두콩은 삶은 뒤 믹서에 간다.\",\"2. 간 완두콩에 올리고당, 우유를 넣고 졸인다.\",\"3. 찹쌀가루는 익반죽하여전자레인지에 3분 가열 후 숟가락으로 젓고 2분 간 더 돌려떡을 만든다.\",\"4. 식빵은 밀대로 밀어 납작하게 한 뒤 가장자리를 자른다.\",\"5. 식빵위에 찹쌀떡을 넓게 펴 바르고 그 위에 졸인 완두콩을 올린다.\",\"6. 5번을 돌돌 말아 고정시킨 뒤 먹기 좋은 크기로 자른다.\"]},{\"id\":\"k1045\",\"title\":\"단호박두부팬케이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01111_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01111_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01111_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01111_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01111_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01111_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01111_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(25g)\",\"두부(10g)\",\"밀가루(75g)\",\"타가토스(10g)\",\"우유(15g)\",\"식용유(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"팬케이크 믹스 대신 단호박과 두부, 밀가루로 직접 반죽을 만들면 첨가당을 줄일 수 있어요.\",\"instructions\":[\"1. 단호박은 찜통에 찐 뒤 껍질을 벗기고 으깬다.\",\"2. 으깬 단호박, 두부, 우유를 믹서에 넣고 간다.\",\"3. 밀가루, 타가토스를 체에 곱게 내린다.\",\"4. 2번, 3번을 섞어 팬케이크 반죽을 만든다.\",\"5. 팬에 식용유를 두르고 약불에서 팬케이크를 굽는다.\",\"6. 접시에 담는다.\"]},{\"id\":\"k1046\",\"title\":\"약밥 닮은 호떡\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01112_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01112_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01112_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01112_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01112_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01112_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01112_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"호떡반죽(200g)\",\"밤(30g)\",\"고구마(30g)\",\"곶감(50g)\",\"호두(10g)\",\"호박씨(10g)\",\"잣(5g)\",\"대추(1알)\",\"계피가루(8g)\",\"식용유(15g)\",\"물(80g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"다양한 견과류의 고소한 맛이 설탕 사용을 줄여줘요.\",\"instructions\":[\"1. 호떡반죽에 물을 넣고 반죽한 뒤 발효시킨다.\",\"2. 밤, 고구마, 대추, 곶감, 호두를 다진다.\",\"3. 2번에 잣, 호박씨, 계피가루, 홍시를 섞는다.\",\"4. 발효시킨 반죽에 3번을 채우고 동그랗게 빚는다.\",\"5. 팬에 식용유를 두른다.\",\"6. 가열된 팬에 반죽을 올린 뒤 납작하게 눌러 굽는다.\"]},{\"id\":\"k1047\",\"title\":\"두부티라미수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01113_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01113_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01113_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01113_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01113_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01113_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01113_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부(80g)\",\"고구마(120g)\",\"마스카포네치즈(12g)\",\"크랜베리(2g)\",\"두유(5g)\",\"호두(15g)\",\"아몬드(8g)\",\"박력분(2g)\",\"아몬드가루(3g)\",\"버터(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"두부와 마스카포네치즈의 고소한 맛 때문에 달지 않아도 맛있는 티라미수를 만들 수 있어요.\",\"instructions\":[\"1. 고구마는 껍질을 벗기고 삶아 으깬 뒤 체에 내린다.\",\"2. 두부, 크랜베리, 마스카포네치즈, 두유를 믹서에 넣고 갈아 두부크림을 만든다.\",\"3. 두부크림에 다진 호두, 아몬드를 섞는다.\",\"4. 실온의 말랑한 버터에 박력분과 아몬드가루를 넣고 보슬보슬하게 섞어 소보루 반죽을 만든다.\",\"5. 4번을 170℃ 오븐에서 15분 간 굽는다.\",\"6. 투명한 컵에 으깬 고구마와 두부크림을 켜켜이 쌓고 마지막에 소보루를 올린다.\"]},{\"id\":\"k1048\",\"title\":\"두부있슈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01114_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01114_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01114_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01114_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01114_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01114_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01114_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"연두부(60g)\",\"요거트(100g)\",\"중력분(22g)\",\"버터(22g)\",\"달걀(1개)\",\"소금(0.2g)\",\"딸기(60g)\",\"호두(20g)\",\"물(27g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"슈 충전물로 설탕이 많이 들어간 크림 대신 연두부를 사용하면 고소하고 부드러운 식감을 낼 수 있어요.\",\"instructions\":[\"1. 물, 소금, 버터를 끓이면서 버터가 녹으면 잘 저어 중력분을 섞어 호화시킨다.\",\"2. 불을 끄고 달걀을 조금씩 넣어가며 섞어 반죽에 끈기가 생기게 한다.\",\"3. 짤주머니에 원형 깍지를 끼우고 철판에 도톰하게 짠 뒤 분무기로 반죽 표면에 물을 뿌린다.\",\"4. 190℃ 오븐에서 20분 간 굽는다.\",\"5. 딸기는 다진 후 냄비에 졸인다.\",\"6. 식힌 슈를 가로로 자르고 요거트, 연두부, 딸기, 호두로 속을 채운다.\"]},{\"id\":\"k1049\",\"title\":\"바나나 생강 크림이 들어간 미숫가루 쿠키슈\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01115_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01115_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01115_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01115_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01115_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01115_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01115_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바나나(2개)\",\"생강가루(2g)\",\"휘핑크림(100g)\",\"코코넛밀크(25g)\",\"미숫가루(10g)\",\"박력분(45g)\",\"버터(35g)\",\"코코넛설탕(12g)\",\"달걀(1개)\",\"소금(0.5g)\",\"물(40g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"코코넛밀크와 코코넛설탕의 풍미로 덜 달아도 맛있는 쿠키슈를 만들 수 있어요.\",\"instructions\":[\"1. 실온의 버터(15g)와 코코넛설탕을 섞은 뒤 박력분(15g), 미숫가루를 체쳐 쿠키반죽을 만들어 냉장고에서 휴지시킨다.\",\"2. 휴지시킨 쿠키반죽을 넓게 밀어 편 뒤 원형 커터로 자른다.\",\"3. 바나나, 코코넛밀크, 생강가루를 믹서에서 곱게 갈아 퓌레를 만들고 휘핑한 생크림과 섞는다.\",\"4. 버터(20g), 물, 소금을 끓인 후 체친 박력분(30g)을 넣고 반죽에 얇은 막이 생길 때 까지 볶아 호화시킨다.\",\"5. 4를 식힌 뒤 달걀을 섞고 팬에 둥글게 짜준 뒤 분무기로 물을 뿌린다.\",\"6. 5에 잘라둔 쿠키반죽을 올리고 190℃ 오븐에서 25분 정도 굽고 3번으로 속을 채운다.\"]},{\"id\":\"k1050\",\"title\":\"단호박몽블랑\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01116_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01116_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01116_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01116_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01116_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01116_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01116_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(150g)\",\"아몬드가루(45g)\",\"박력분(15g)\",\"스테비아(2g)\",\"달걀(2.5개)\",\"올리고당(40g)\",\"가루녹차(1.5g)\",\"생크림(210g)\",\"판젤라틴(2g)\",\"마스카르포네치즈(35g)\",\"설탕(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박으로 천연의 단맛을 낼 수 있어요.\",\"instructions\":[\"1. 달걀흰자와 올리고당(50g)을 섞어 머랭을 만들고 아몬드가루, 스테비아, 박력분, 가루녹차를 섞는다.\",\"2. 짤주머니에 반죽을 담아 원형틀에 짜 넣고 170℃ 오븐에서 15분 간 굽는다.\",\"3. 마스카르포네치즈(20g)와 설탕을 섞어 부드럽게 만든 뒤 생크림(120g)을 섞고 젤라틴으로 농도를 맞춘다.\",\"4. 단호박을 삶은 후 볶아 수분을 날리고 올리고당, 계피가루, 마스카르포네치즈를 넣고 섞는다.\",\"5. 4번에 생크림(90g)을 넣고 잘 섞은 뒤 젤라틴으로 농도를 맞춘다.\",\"6. 가루녹차 다쿠아즈를 깔고 그 위에 짤주머니로 치즈크림, 단호박크림 순으로 올린다.\"]},{\"id\":\"k1051\",\"title\":\"렌틸콩 크레이프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01117_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01117_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01117_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01117_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01117_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01117_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01117_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"렌틸콩(레드\",\"20g)\",\"중력분(15g)\",\"달걀(1/2개)\",\"우유(50g)\",\"생크림(30g)\",\"설탕(3g)\",\"버터(2g)\",\"크림치즈(10g)\",\"귤(60g)\",\"키위(60g)\",\"블루베리(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"렌틸콩을 사용하면 고소하면서 맛있는 크레이프를 만들 수 있어요.\",\"instructions\":[\"1. 렌틸콩을 삶아 믹서에 갈고 체 친 중력분과 섞은 뒤 달걀을 섞는다.\",\"2. 1번에 우유, 생크림을 섞은 뒤 녹인 버터를 빠르게 섞어 크레이프 반죽을 만들어 팬에 굽는다.\",\"3. 크림치즈에 생크림(10g)을 조금씩 넣으면서 섞는다.\",\"4. 냄비에 3번과 우유를 끓이다가 설탕, 달걀노른자를 조금씩 섞어 끓인 뒤 얼음물에 받쳐 식힌다.\",\"5. 귤, 키위, 블루베리를 먹기 좋은 크기로 자른다.\",\"6. 크레이프 안쪽에 크림치즈 크림을 바르고 과일을 담은 뒤 4번의 소스를 올린다.\"]},{\"id\":\"k1052\",\"title\":\"콩 판나코타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01118_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01118_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01118_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01118_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01118_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01118_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01118_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"렌틸콩(레드\",\"20g)\",\"완두콩(30g)\",\"생크림(40g)\",\"설탕(8g)\",\"판젤라틴(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"완두콩과 렌틸콩의 고소한 맛으로 단맛이 적어도 맛있는 요리를 만들 수 있어요.\",\"instructions\":[\"1. 완두콩과 렌틸콩은 각각 삶은 뒤 믹서에 간다.\",\"2. 완두콩과 렌틸콩에 각각 생크림(20g)과 설탕(4g)을 넣고 냄비에 끓인다.\",\"3. 젤라틴 1g을 물에 넣어 불린다.\",\"4. 2번에 각각 불린 젤라틴을\\n혼합하여 녹인다.\",\"5. 용기에 4번의 렌틸콩을 붓고\\n얼린다.\",\"6. 5번이 어느정도 굳으면 4번의\\n완두콩을 붓고 얼린다.\"]},{\"id\":\"k1053\",\"title\":\"고구마치즈크로켓\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01119_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01119_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01119_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01119_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01119_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01119_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01119_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"호박고구마(200g)\",\"새우살(80g)\",\"삼색파프리카(80g)\",\"양파(40g)\",\"모짜렐라치즈(40g)\",\"밀가루(20g)\",\"달걀(1개)\",\"빵가루(20g)\",\"생크림(15g)\",\"버터(10g)\",\"꿀(5g)\",\"식용유(40g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마와 양파로 크로켓을 만들어 설탕 없이 단맛을 낼 수 있어요\",\"instructions\":[\"1. 고구마는 찜통에 찐 후 껍질을 제거하고 으깨 생크림, 꿀을 넣고 섞는다.\",\"2. 새우살, 파프리카, 양파는 잘게 다진 뒤 팬에 버터를 두르고 볶는다.\",\"3. 볼에 1번과 2번을 넣고 서로 잘 섞이도록 치댄다.\",\"4. 3번을 한입 크기로 떼어낸 후 가운데 모짜렐라 치즈를 넣고 공모양으로 만든다.\",\"5. 크로켓에 밀가루, 달걀물, 빵가루 순으로 묻힌다.\",\"6. 180℃의 기름에 크로켓을 튀긴다.\"]},{\"id\":\"k1054\",\"title\":\"빵 대신 어묵 사라다\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01120_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01120_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01120_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01120_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01120_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01120_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01120_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"어묵(150g)\",\"양파(100g)\",\"당근(10g)\",\"양배추(20g)\",\"푸룬(15g)\",\"아몬드(10g)\",\"요거트(30g)\",\"마요네즈(35g)\",\"달걀(1/2개)\",\"빵가루(50g)\",\"밀가루(50g)\",\"식용유(8g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양파를 볶아 양파당을 만들면 설탕 대신 사용할 수 있어요.\",\"instructions\":[\"1. 양배추, 당근, 양파는 채 썬다.\",\"2. 채 썬 양파(50g)를 볶다가 물(40g)을 넣은 뒤 믹서로 간다.\",\"3. 2번에 요거트, 마요네즈, 아몬드, 푸룬을 넣고 믹서로 간다.\",\"4. 채 썬 양배추, 당근에 3번을 넣고 버무린다.\",\"5. 어묵은 반을 자르고 밀가루, 달걀, 빵가루 순으로 묻혀 팬에 굽는다.\",\"6. 어묵 사이에 4번을 넣는다.\"]},{\"id\":\"k1055\",\"title\":\"청국장 시래기전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053439_1416213279588.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/839-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/839-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/839-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/839-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/839-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/839-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"대두 10g\",\"시레기 60g\",\"청고추 2g\",\"홍고추 2g\",\"새우살 13g\",\"밀가루 6g\",\"도토리가루 2g\",\"달걀 6.5g\",\"식용유 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시중에 파는 청국장은 염도가 높으므로 집에서 소금을 첨가하지 않은 청국장을 만들어 사용한다.\",\"instructions\":[\"1. 시레기는 1cm 길이로 자른다.\",\"2. 저나트륨 청국장은 굵게 다진다.\",\"3. 청, 홍고추와 새우 살도 굵게 다진다.\",\"4. 불에 준비된 청국장, 시래기, 청, 홍고추를 도토리가루와 밀가루, 물, 달걀을 넣어 되직하게 반죽한다.\",\"5. 팬에 식용유를 두르고 반죽을 부친다.\",\"6. 반죽 위에 새우 살을 얹어 전을 부친다.\"]},{\"id\":\"k1056\",\"title\":\"카레소스를 얹은 두부 스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053440_1416213280344.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/840-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/840-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/840-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/840-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/840-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/840-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 67g\",\"애호박 17g\",\"양송이 33g\",\"가지 17g\",\"파프리카 17g\",\"사과 50g\",\"감자 33g\",\"카레가루 10g\",\"식용유 2g\",\"녹말가루 5g\",\"물 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"인스턴트 카레가루는 나트륨 함량이 너무 높아 저나트륨에는 사용할 수 없으며 이메뉴에 들어가는 카레가루는 인스턴트가 아닌 것을 사용한다.\",\"instructions\":[\"1. 두부를 두께 2cm로 썰어 원형틀로 찍어 준비한다.\",\"2. 준비한 채소는 작은 정육면체로 썰어 팬에 살짝 볶는다.\",\"3. 물과 카레가루를 섞어 끓이다가 감자를 넣어 끓이고 감자가 거의 익을 때쯤에 나머지 채소를 넣어 끓인다.\",\"4. 물과 녹말가루를 섞어 3의 카레소스의 농도를 맞춘다.\",\"5. 가열된 팬에 두부를 노릇노릇하게 지진다.\",\"6. 준비한 소스를 두부 스테이크에 뿌려낸다.\"]},{\"id\":\"k1057\",\"title\":\"녹차 파나코타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053442_1416213282795.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/843-1.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/843-2.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/843-3.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/843-4.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/843-5.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/843-6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"녹차가루 6g\",\"판젤라틴 5.3g\",\"설탕 32g\",\"물 15g\",\"생크림 30g\",\"우유 55.7g\",\"바닐라에센스 0.1g\",\"통조림단팥장식용\",\"민트장식용\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"\",\"instructions\":[\"1. 볼에 물을 담고 판 젤라틴을 넣어 3분 가량 불린 뒤 건진다.\",\"2. 냄비에 녹차가루와 소량의 물을 넣고 진하게 섞는다.\",\"3. 2에 우유와 크림, 설탕, 바닐라 에센스를 넣고 약한 불에서 설탕이 녹을 정도로 끓인다.\",\"4. 3에 불린 젤라틴을 넣고 젤라틴이 녹을 때까지 가열한다.\",\"5. 용기에 녹차 파나코타를 부은 후 실온에서 식힌다.\",\"6. 냉장고에서 한번 더 식혀 완성한다.\"]},{\"id\":\"k1058\",\"title\":\"자색고구마찹쌀푸딩\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01121_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01121_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01121_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01121_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01121_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01121_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01121_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"자색고구마(40g)\",\"우유(120g)\",\"찹쌀가루(4g)\",\"소금(0.1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금을 조금 넣어주면 단맛이 더 살아나요.\",\"instructions\":[\"1. 자색고구마는 솔로 문질러 깨끗하게 씻는다.\",\"2. 껍질을 벗기고 찐다.\",\"3. 찐 자색고구마와 우유, 소금을 믹서에 곱게 간다.\",\"4. 3번을 고운 체에 걸러 덩어리를 없앤다.\",\"5. 볼에 4번을 넣고 찹쌀가루를 넣어 잘 풀리도록 젓는다.\",\"6. 5번을 끓이다가 엉기기 시작하면 그릇에 담아 차게 식힌다.\"]},{\"id\":\"k1059\",\"title\":\"꽃설기\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01122_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01122_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01122_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01122_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01122_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01122_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01122_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"멥쌀가루(112g)\",\"대추(5알)\",\"백년초가루(3.5g)\",\"단호박가루(3.5g)\",\"시금치가루(3.5g)\",\"설탕(3g)\",\"백앙금(25g)\",\"우유(2g)\",\"호박씨(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"말린 대추의 속살을 가루에 섞으면 설탕 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 다양한 색상의 가루를 각각 멥쌀가루와 섞은 뒤 물 15g을 넣고 섞는다.\",\"2. 1번을 한번 더 체에 내리고 설탕 3g을 넣고 섞는다.\",\"3. 2번에 불린 대추 속살을 섞는다.\",\"4. 찜기에 김이 오르면 면보를 깔고 모양틀을 넣은 뒤 3번을 넣는다.\",\"5. 윗면을 고르게 정리하고 20분 간 찐다.\",\"6. 호박씨, 대추로 장식한다.\"]},{\"id\":\"k1060\",\"title\":\"크랜베리 소보로 떡\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01123_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01123_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01123_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01123_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01123_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01123_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01123_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"쌀가루(25g)\",\"찹쌀가루(13g)\",\"크랜베리(8g)\",\"건포도(8g)\",\"견과류(8g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"건과일과 견과류를 사용하면 천연의 단맛과 고소함을 낼 수 있어요.\",\"instructions\":[\"1. 쌀가루, 찹쌀가루에 크랜베리, 건포도, 견과류를 섞어 믹서에 간다.\",\"2. 가루에 물기가 스미도록 물을 넣고 골고루 섞는다.\",\"3. 2번을 체에 내린다.\",\"4. 체에 걸러진 큰 가루는 따로 담아 떡위에 올릴 소로 사용한다.\",\"5. 원형틀에 3번의 가루를 담고 위에 4번의 소를 올린다.\",\"6. 김이 오른 찜기에서 25분 간 찐다.\"]},{\"id\":\"k1061\",\"title\":\"오미자 샹그리아\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01124_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01124_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01124_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01124_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01124_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01124_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01124_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"오미자(30g)\",\"사과(80g)\",\"오렌지(100g)\",\"딸기(80g)\",\"포도(80g)\",\"배(80g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"오미자의 다양한 맛과 과일의 단맛으로 설탕없이 맛있는 음료를 만들 수 있어요.\",\"instructions\":[\"1. 오미자를 세척한 뒤 물에 담궈 맛을 낸다.\",\"2. 사과, 오렌지, 딸기, 포도, 배를 세척한다.\",\"3. 세척한 과일을 작고 얇게 슬라이스한다.\",\"4. 1번에 3번을 넣어 숙성시킨다.\",\"5. 따뜻하게 먹을 때는 계피를 넣어 끓인다.\",\"6. 컵에 담는다.\"]},{\"id\":\"k1062\",\"title\":\"톡톡! 오미자 펀치\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01125_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01125_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01125_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01125_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01125_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01125_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01125_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"말린오미자(5g)\",\"배(50g)\",\"꿀(5g)\",\"잣(3알)\",\"생수(150g)\",\"각얼음(3개)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕이 많이 들어간 오미자 청을 사용하지 않고 배즙과 꿀을 사용하면 건강한 단맛을 낼 수 있어요.\",\"instructions\":[\"1. 말린오미자는 깨끗이 씻은 뒤 생수 150g을 부어 하루정도 우려낸다.\",\"2. 우려낸 오미자를 체에 거른다.\",\"3. 배를 강판에 곱게 간 뒤 면포에 싸서 배즙을 짠다.\",\"4. 우린 오미자와 배즙을 섞은 후 꿀을 넣고 골고루 섞는다.\",\"5. 믹서기에 얼음을 갈아 한 스푼 얹는다.\",\"6. 잣을 띄워 장식한다.\"]},{\"id\":\"k1063\",\"title\":\"사과비트에이드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01126_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01126_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01126_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01126_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01126_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01126_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01126_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과(60g)\",\"비트(2g)\",\"레몬즙(0.5g)\",\"탄산수(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"레몬즙의 신맛이 단맛을 극대화 시켜 첨가당 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 사과(55g)와 비트는 깨끗하게 손질한 뒤 적당한 크기로 썬다.\",\"2. 나머지 사과는 0.5cm 주사위 모양으로 자르고 물에 담근다.\",\"3. 믹서에 1번을 넣고 간다.\",\"4. 냄비에 물기를 제거한 2번과 레몬즙을 넣고 졸인다.\",\"5. 냄비에 3번을 넣고 졸인다.\",\"6. 유리컵에 4,5번을 넣고 탄산수를 부어 완성한다.\"]},{\"id\":\"k1064\",\"title\":\"밤 라떼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01127_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01127_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01127_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01127_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01127_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01127_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01127_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"밤(200g)\",\"우유(180g)\",\"두유(20g)\",\"아몬드(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"밤의 단맛과 우유, 두유의 고소한 맛 때문에 설탕 없이 맛있게 먹을 수 있어요.\",\"instructions\":[\"1. 밤을 냄비에 푹 삶는다.\",\"2. 삶은 밤은 반을 쪼갠 뒤 속을 파낸다.\",\"3. 믹서에 밤, 우유, 두유를 넣고 간다.\",\"4. 3번을 체에 걸러 덩어리를 제거한다.\",\"5. 아몬드를 잘게 다진다.\",\"6. 4번을 컵에 담고 다진 아몬드를 뿌린다.\"]},{\"id\":\"k1065\",\"title\":\"자두 라떼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01128_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01128_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01128_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01128_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01128_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01128_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01128_6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"자두(200g)\",\"우유(250g)\",\"꿀(10g)\",\"물(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"제철과일을 사용하면 건강한 단맛의 맛있는 주스를 만들 수 있어요.\",\"instructions\":[\"1. 자두를 깨끗이 씻어 얼린다.\",\"2. 얼린 자두와 꿀, 물을 믹서에 넣고 간다.\",\"3. 믹서에 간 자두의 일부를 얼음틀에 넣고 얼린다.\",\"4. 믹서에 간 자두를 컵에 담는다.\",\"5. 3번을 컵에 담는다.\",\"6. 우유를 붓는다.\"]},{\"id\":\"k1066\",\"title\":\"와인배숙\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01129_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01129_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01129_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01129_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01129_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01129_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01129_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배(1/2개)\",\"사과(1/2개)\",\"레드와인(200g)\",\"계피(5g)\",\"통후추(6알)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"계피와 통후추를 이용하면 풍미를 살려 덜 달아도 맛있는 음료를 만들 수 있어요.\",\"instructions\":[\"1. 배와 사과는 스쿠퍼로 동그랗게 모양을 만든다.\",\"2. 냄비에 와인을 넣고 계피, 통후추와 함께 약불에서 끓인다.\",\"3. 와인이 끓기 시작하면 배와 사과를 넣고 양이 반이 될 때까지 졸인다.\",\"4. 차갑게 식힌다.\",\"5. 4번을 용기에 담는다.\",\"6. 졸여진 배와 사과를 과일꼬지에 꽂아 곁들인다.\"]},{\"id\":\"k1067\",\"title\":\"유자애(愛) 빠지다\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01130_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01130_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01130_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01130_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01130_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01130_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01130_6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"유자(200g)\",\"밤(25g)\",\"대추(15g)\",\"배(50g)\",\"석류(20g)\",\"꿀(10g)\",\"소금(0.5g)\",\"물(300g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕 대신 꿀을 사용하고 배, 대추, 밤을 채 썰어 넣어 재료 본연의 단맛을 이용할 수 있어요.\",\"instructions\":[\"1. 유자는 십자로 갈집을 낸 뒤 끓는 소금물에 데쳐 껍질을 깨끗이 한다.\",\"2. 유자는 속을 꺼내 씨를 제거하고 유자속과 속껍질을 얇게 채 썬다.\",\"3. 밤, 대추, 배는 채 썰고 2번과 섞어 소를 만든다.\",\"4. 속을 빼낸 유자에 소를 2/3쯤 채워 입구를 실로 묶는다.\",\"5. 유자묶음을 용기에 채워 넣은 후 꿀물을 붓고 잘 밀봉하여 냉장고에 보관한다.\",\"6. 3~4주 정도 숙성한 뒤 석류를 곁들여 먹는다.\"]},{\"id\":\"k1068\",\"title\":\"쌀콩죽 요거트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01131_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01131_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01131_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01131_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01131_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01131_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01131_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"우유(65g)\",\"배(60g)\",\"고구마(35g)\",\"요거트(3g)\",\"쌀가루(5g)\",\"메주콩(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배와 고구마의 단맛으로 설탕을 대신하고 쌀콩죽으로 고소한 맛을 더할 수 있어요.\",\"instructions\":[\"1. 우유에 요거트를 넣어 발효시킨다.\",\"2. 메주콩을 3시간 정도 불린 뒤 불린 콩의 3배의 물을 넣고 삶아\\n믹서에 간다.\",\"3. 쌀가루와 2번을 섞은 뒤 냄비에 끓여 쌀콩죽을 만든다.\",\"4. 배는 껍질을 제거하고 밥솥에 푹 삶아 믹서에 간다.\",\"5. 고구마는 삶아 껍질을 제거한다.\",\"6. 제조한 요거트(1번)에 쌀콩죽, 배즙, 고구마를 넣고 믹서에 곱게 간다.\"]},{\"id\":\"k1069\",\"title\":\"상큼하자두\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01132_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01132_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01132_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01132_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01132_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01132_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01132_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"자두(100g)\",\"오렌지(170g)\",\"탄산수(100g)\",\"민트잎(5g)\",\"얼음(145g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"탄산수의 톡쏘는 식감으로 덜 달아도 맛있는 음료를 만들 수 있어요.\",\"instructions\":[\"1. 자두(30g)를 잘게 다진다.\",\"2. 나머지 자두는 강판에 간다.\",\"3. 오렌지는 즙을 낸다.\",\"4. 오렌지 즙에 1,2번을 넣고 섞는다.\",\"5. 컵에 4번을 넣고 얼음을 넣은 다음 탄산수를 붓는다.\",\"6. 민트잎을 올린다.\"]},{\"id\":\"k1070\",\"title\":\"비트두유\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01133_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01133_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01133_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01133_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01133_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01133_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01133_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"비트(15g)\",\"무첨가두유(200g)\",\"타가토스(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"타가토스와 비트가 단맛을 주고 두유의 비린맛을 줄여줄 수 있어요.\",\"instructions\":[\"1. 비트를 흐르는 물에 깨끗이 씻는다.\",\"2. 비트를 작게 깍뚝썰기한다\",\"3. 두유에 타가토스를 넣고 완전히 녹도록 섞는다.\",\"4. 잘라둔 비트와 3번을 믹서에 넣고 곱게 간다.\",\"5. 딸기우유 정도의 색이 날 때 까지 간다.\",\"6. 체에 걸러 건더기가 없이한다.\"]},{\"id\":\"k1071\",\"title\":\"렌틸콩 두유\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01134_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01134_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01134_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01134_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01134_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01134_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01134_6.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"렌틸콩(레드\",\"70g)\",\"우유(150g)\",\"레몬(1/2개)\",\"딸기(130g)\",\"꿀(15g)\",\"판젤라틴(1.5g)\",\"설탕(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"딸기의 단맛을 설탕 대신 사용할 수 있어요.\",\"instructions\":[\"1. 렌틸콩을 삶아 믹서에 간다.\",\"2. 딸기(100g)를 믹서에 갈고 1번, 우유, 꿀, 레몬즙을 넣고 섞는다.\",\"3. 젤라틴을 물에 담궈 불린다.\",\"4. 딸기를 믹서에 갈아 퓨레를 만들고 설탕을 넣고 끓인다.\",\"5. 4번을 식힌 뒤 젤라틴을 넣고 틀에 넣어 냉동실에서 굳힌다.\",\"6. 2번을 컵에 담고 위에 딸기젤리를 올린다.\"]},{\"id\":\"k1072\",\"title\":\"군고구마 라떼\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01135_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01135_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01135_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01135_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01135_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01135_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01135_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마(100g)\",\"우유(200g)\",\"고구마칩(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고구마를 구워서 조리하면 단맛이 더 높아져요.\",\"instructions\":[\"1. 고구마를 쿠킹호일에 싸 직화냄비에 넣고 약한 불에서\\n30분 간 굽는다.\",\"2. 우유를 냄비에 끓여 데운다.\",\"3. 구운 고구마의 껍질을 제거한다.\",\"4. 우유와 고구마를 믹서에 넣고 간다.\",\"5. 4번을 체에 걸러 부드럽게 한다.\",\"6. 컵에 담고 고구마칩을 올린다.\"]},{\"id\":\"k1073\",\"title\":\"바지락 미역국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405050142_1554451302804.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405054207_1554453727016.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405054250_1554453770311.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405054314_1554453794529.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405054332_1554453812694.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405054349_1554453829417.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405054403_1554453843326.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바지락 10g\",\"미역 5g\",\"저염간장 5g\",\"마늘 5g\",\"참기름 2g\",\"홍고추 2g\",\"무 10g\",\"건새우 10g\",\"대파 5g\",\"함초가루 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"시원하고 맑은 미역국으로 바지락과 미역 자체의 염분으로 간을 맞출 수 있어요.\",\"instructions\":[\"1. 바지락은 해감하고 미역은 20분 동안 불린다.\",\"2. 물에 파, 마늘, 홍고추, 건새우, 무를 넣고 끓여 육수를 만든다.\",\"3. 냄비에 참기름과 미역, 바지락을 넣고 볶은 뒤 저염간장을 넣고 볶는다.\",\"4. 볶은 냄비에 육수를 넣고 끓인다.\",\"5. 함초가루로 간을 맞춘다.\",\"6. 국그릇에 담는다.\"]},{\"id\":\"k1074\",\"title\":\"단호박견과류샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102734_1678325254074.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309102959_1678325399286.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309103012_1678325412697.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309103026_1678325426161.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309103040_1678325440572.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309103100_1678325460560.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309103122_1678325482131.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 단호박(25g)\",\"고구마(25g)\",\"아몬드(5g)\",\"호두(5g)\",\"건블루베리(5g)\",\"당근(10g)\",\"우유(15g)\",\"•양념 : 올리고당(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•별도의 간을 하지 않아도 단호박, 견과류, 채소만으로도 달콤하고 고소한 샐러드를 만들 수 있어요.\",\"instructions\":[\"1. 단호박과 고구마는 껍질을 벗긴다\",\"2. 냄비에 우유를 붓고 단호박과 고구마를 넣어 삶는다.\",\"3. 끓인 우유를 식힌 뒤 단호박과 고구마와 함께 믹서에 넣어 간다.\",\"4. 견과류와 건블루베리, 당근을 잘게 썬다.\",\"5. 믹서에 간 우유에 손질한 견과류와 건블루베리, 당근을 넣어 섞는다.\",\"6. 올리고당으로 농도와 간을 맞춰 마무리한다.\"]},{\"id\":\"k1075\",\"title\":\"함박스테이크&토마토카레소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092358_1554683038189.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092441_1554683081182.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092515_1554683115376.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092543_1554683143299.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092608_1554683168007.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092631_1554683191540.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408092650_1554683210156.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기(다짐육) 50g\",\"양송이버섯 5g\",\"양파 40g\",\"빵가루 25g\",\"다진 마늘 5g\",\"카레가루 15g\",\"토마토 25g\",\"당근 15g\",\"감자 15g\",\"계란노른자 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"함박 스테이크의 양송이버섯과 카레소스로 따로 간을 하지 않아도 맛이 나요.\",\"instructions\":[\"1. 양파, 양송이버섯, 당근, 감자, 토마토를 잘게 다진다.\",\"2. 다진 소고기와 다진 양파, 다진 양송이버섯, 다진 마늘, 빵가루, 계란노른자를 넣고 치댄다.\",\"3. 반죽을 70g씩 나눠 스테이크 모양을 만들어 굽는다.\",\"4. 다진 당근, 감자, 양파, 토마토, 마늘과 카레가루를 물에 넣고 끓인다.\",\"5. 카레 소스가 농도가 날 때 까지 끓인다.\",\"6. 스테이크와 카레소스를 곁들여 담는다.\"]},{\"id\":\"k1076\",\"title\":\"모둠채소 수제피클\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112534_1678328734115.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112625_1678328785475.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112643_1678328803213.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112655_1678328815936.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112709_1678328829122.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112721_1678328841962.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309112740_1678328860571.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 오이(20g)\",\"파프리카(20g)\",\"적양배추(20g)\",\"•피클물 : 설탕(15g)\",\"식초(15g)\",\"피클링스파이스(5g)\",\"물(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•소금을 넣지 않아도 피클링스파이스를 활용하여 새콤달콤한 저염 피클을 만들 수 있어요.\",\"instructions\":[\"1. 오이와 파프리카, 적양배추는 한 입 크기로 썬다.\",\"2. 냄비에 물과 피클물 재료를 넣어 끓인다.\",\"3. 다른 냄비에 물을 끓여, 피클을 담을 용기를 넣어 소독한다.\",\"4. 소독한 용기를 잘 말린 뒤 손질한 채소를 담는다.\",\"5. 피클물이 끓으면 식힌 뒤 용기에 붓는다.\",\"6. 피클을 30분간 숙성해 마무리한다.\"]},{\"id\":\"k1077\",\"title\":\"바지락 맑은국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408093830_1554683910807.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408093856_1554683936227.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408093913_1554683953383.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408093929_1554683969238.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408093943_1554683983317.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408093955_1554683995553.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094010_1554684010944.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"바지락 30g\",\"팽이버섯 10g\",\"홍고추 3g\",\"쑥갓 1g\",\"청양고추 3g\",\"무 8g\",\"대파 5g\",\"다시마 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 많은 바지락으로 국을 만들어 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 물에 무와 다시마, 대파, 청양고추를 넣고 끓인다.\",\"2. 끓으면 청양고추와 다시마를 건진다.\",\"3. 해감한 바지락을 넣고 끓인다.\",\"4. 팽이버섯 밑둥을 자른다.\",\"5. 3에 팽이버섯을 넣고 끓인다.\",\"6. 고명으로 어슷 썬 홍고추, 쑥갓을 올린다.\"]},{\"id\":\"k1078\",\"title\":\"일본식 계란말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094414_1554684254971.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094453_1554684293710.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094511_1554684311206.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094540_1554684340109.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094556_1554684356928.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094611_1554684371874.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408094630_1554684390645.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"계란 150g\",\"가츠오부시 10g\",\"다시마 10g\",\"설탕 5g\",\"미림 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"가츠오부시 육수로 소금을 대신해 맛을 낼 수 있어요.\",\"instructions\":[\"1. 물에 다시마를 넣고 끓인다.\",\"2. 물이 끓어 오르면 다시마를 건진다.\",\"3. 불을 끈 뒤 가츠오부시를 넣고 체에 걸러 육수를 완성한다.\",\"4. 계란을 풀어 채에 내린 뒤 육수와 미림, 설탕을 넣는다.\",\"5. 팬에 기름을 둘러 계란물을 한겹 한겹 만다.\",\"6. 완성된 계란말이는 모양을 잡고 한입크기로 자른다.\"]},{\"id\":\"k1079\",\"title\":\"소고기 가라아게, 칠리소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095001_1554684601056.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095037_1554684637290.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095056_1554684656422.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095114_1554684674696.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095134_1554684694510.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095155_1554684715015.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408095214_1554684734976.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"소고기 70g\",\"대파 20g\",\"토마토 20g\",\"마늘 10g\",\"계란노른자 25g\",\"밀가루 20g\",\"고춧가루 15g\",\"식초 50g\",\"설탕 15g\",\"전분 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"칠리소스에 케첩을 사용하지 않고 토마토를 사용해 나트륨을 줄여요.\",\"instructions\":[\"1. 소고기는 채썰고 마늘, 대파는 다진 뒤 섞는다.\",\"2. 1에 계란노른자와 밀가루, 물을 섞어 반죽하고 조그만 공 모양으로 만들어 튀긴다.\",\"3. 토마토는 껍질을 제거한 뒤 다지고, 마늘도 다진다.\",\"4. 식초, 설탕, 물을 끓이다가 다진 토마토, 마늘, 고춧가루를 넣어 끓인다.\",\"5. 전분으로 소스의 농도를 맞춘다.\",\"6. 소고기 가라야게에 칠리소스를 곁들인다.\"]},{\"id\":\"k1080\",\"title\":\"삼치튀김, 타르타르소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111442_1554689682742.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111522_1554689722310.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111537_1554689737618.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111556_1554689756551.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111613_1554689773428.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111633_1554689793169.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408111648_1554689808507.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"삼치 50g\",\"튀김가루 30g\",\"계란 60g\",\"마요네즈 15g\",\"홍고추 2g\",\"청양고추 2g\",\"후추 3g\",\"양파 5g\",\"레몬즙 20g\",\"식용유 5g\",\"물 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"타르타르소스에 피클 대신 홍고추와 청양고추를 넣어 매콤한 맛을 첨가해 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 삼치의 살과 가시를 분리한다.\",\"2. 키친타올로 삼치살의 핏기와 물기를 제거한 뒤 후추와 레몬즙을 뿌려 비린내를 제거한다.\",\"3. 볼에 튀김가루, 계란, 물, 식용유를 섞어 튀김옷을 만든다.\",\"4. 삼치에 튀김옷을 입힌 뒤 170℃ 기름에서 두 번 튀긴다.\",\"5. 삶은 계란, 홍고추, 청양고추, 양파를 다져 볼에 섞은 뒤 마요네즈와 레몬즙을 섞어 소스를 만든다.\",\"6. 삼치 튀김에 타르타르소스를 곁들여 담는다.\"]},{\"id\":\"k1081\",\"title\":\"두부해물완자\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112127_1554690087850.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112147_1554690107415.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112204_1554690124165.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112216_1554690136572.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112231_1554690151278.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112250_1554690170739.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408112334_1554690214523.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"두부 50g\",\"오징어 14g\",\"칵테일 새우 14g\",\"감자전분 15g\",\"부침가루 10g\",\"계란 20g\",\"꿀 5g\",\"새우가루 5g\",\"마늘 2g\",\"파 2g\",\"양파 10g\",\"저염간장 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"새우가루를 소금대신 사용하면 감칠맛도 나고 나트륨 섭취도 줄일 수 있어요.\",\"instructions\":[\"1. 두부를 으깨고 오징어와 새우는 잘게 다진다.\",\"2. 볼에 1의 재료와 감자전분을 넣고 섞어 완자모양으로 만든다.\",\"3. 감자전분과 부침가루를 섞어 완자에 묻힌다.\",\"4. 가루를 묻힌 완자에 계란물을 입혀 기름 두른 팬에 굴려가며 익힌다.\",\"5. 마늘과 파를 다진 뒤 새우가루, 꿀, 저염간장을 섞어 소스를 만든다.\",\"6. 양파를 채 썰어 냄비에 소스와 함께 끓인 뒤 전분물을 넣어 농도를 맞추고 완자를 넣는다.\"]},{\"id\":\"k1082\",\"title\":\"톳나물 두부무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010349_1554696229438.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010451_1554696291920.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010506_1554696306290.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010520_1554696320783.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010535_1554696335232.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010549_1554696349028.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408010607_1554696367867.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"톳나물 15g\",\"두부 40g\",\"천일염 0.1g\",\"참깨 0.1g\",\"참기름 0.1g\",\"마늘 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해초에 두부를 넣어 나트륨을 낮췄어요.\",\"instructions\":[\"1. 톳나물을 깨끗이 세척한다.\",\"2. 끓는 물에 톳나물을 살짝 데친다.\",\"3. 데친 톳나물의 물기를 제거하고 한 입 크기로 썬다.\",\"4. 두부를 찜기에 넣고 찐 뒤 으깬다.\",\"5. 마늘을 잘게 다진다.\",\"6. 톳나물과 두부를 볼에 담고 나머지 재료들을 섞는다.\"]},{\"id\":\"k1083\",\"title\":\"퀴노아 팥수프\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045407_1554796447701.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045448_1554796488680.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045503_1554796503873.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045515_1554796515750.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045541_1554796541326.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045555_1554796555369.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045609_1554796569345.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"퀴노아 3g\",\"팥 10g\",\"무가당 휘핑크림 25g\",\"무염 버터 10g\",\"우유 15g\",\"닭뼈 20g\",\"밀가루 10g\",\"양파 10g\",\"세발나물 10g\",\"설탕 3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"세발나물로 가루를 만들어 소금을 대신해 나트륨 섭취를 줄일 수 있어요.\",\"instructions\":[\"1. 세발나물을 살짝 데쳐 말린 뒤 가루를 내고 닭뼈를 이용해 육수를 만든다.\",\"2. 퀴노아를 볶아 쓴맛을 제거하고 삶은 팥과 믹서에 곱게 간다.\",\"3. 팬에 버터 일부를 녹인 뒤 밀가루를 넣어 루를 만든다.\",\"4. 양파를 갈아 버터 녹인 냄비에 볶은 뒤 닭육수와 2를 넣어 끓인다.\",\"5. 세발나물가루로 간을 맞추고 향을 낸 뒤 루를 넣어 농도를 맞춘다.\",\"6. 우유와 휘핑을 넣어 고소함을 더하고 설탕을 소량 넣어 간을 한다.\"]},{\"id\":\"k1084\",\"title\":\"참치 두부 함박스테이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045907_1554796747438.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045932_1554796772425.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045946_1554796786343.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409045957_1554796797783.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050028_1554796828701.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050046_1554796846910.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050128_1554796888217.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"캔참치 20g\",\"두부 20g\",\"양파 25g\",\"토마토 15g\",\"청피망 20g\",\"당근 10g\",\"밀가루 7g\",\"케찹 15g\",\"표고버섯가루 1g\",\"후추 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금대신 표고버섯가루를 사용하여 나트륨을 줄이고 감칠맛과 향을 낼 수 있어요.\",\"instructions\":[\"1. 양파, 피망은 반은 다지고 반은 작은 주사위모양으로 썰고 당근은 다진다.\",\"2. 두부는 칼등으로 으깬 뒤 물기를 제거한다.\",\"3. 2에 캔참치, 다진채소, 표고버섯가루, 밀가루, 후추를 넣어 반죽한 뒤 치대 모양을 만든다.\",\"4. 팬에 식용유를 두르고 3을 노릇하게 굽고 1을 볶는다.\",\"5. 토마토는 주사위모양으로 썰어 케찹과 함께 볶아 소스를 만든다.\",\"6. 접시에 스테이크와 볶은 채소를 담고 토마토소스를 곁들인다.\"]},{\"id\":\"k1085\",\"title\":\"김치양배추볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051446_1554797686842.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051543_1554797743554.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051556_1554797756643.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051610_1554797770314.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051622_1554797782894.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051641_1554797801594.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409051654_1554797814772.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배추김치 18g\",\"양배추 15g\",\"양파 10g\",\"대파 1g\",\"간장 0.2g\",\"보리새우 0.1g\",\"마늘 0.5g\",\"흑임자 0.1g\",\"들기름 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금대신 보리새우를 갈아 이용해 간을 맞췄어요.\",\"instructions\":[\"1. 배추김치는 양념을 헹궈내 짠맛을 제거한 뒤 채 썬다.\",\"2. 양배추, 양파는 곱게 채 썰고 대파는 어슷썬다.\",\"3. 보리새우와 마늘은 곱게 간다.\",\"4. 팬에 들기름을 두르고 김치를 볶다가 양배추와 양파를 넣고 볶는다.\",\"5. 양배추의 숨이 죽으면 간장과 3을 넣어 간을 한다.\",\"6. 흑임자를 뿌린다.\"]},{\"id\":\"k1086\",\"title\":\"돈수육, 해물냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052530_1554798330170.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052605_1554798365688.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052618_1554798378878.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052633_1554798393303.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052654_1554798414893.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052710_1554798430448.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409052727_1554798447774.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(삼겹살) 100g\",\"오징어 15g\",\"새우 15g\",\"주꾸미 25g\",\"적파프리카 5g\",\"황파프리카 5g\",\"주황파프리카 5g\",\"양파 5g\",\"당근 5g\",\"오이 5g\",\"대파 10g\",\"마늘 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"해물냉채와 곁들여 쌈장이나 새우젓, 소금 없이도 맛있는 수육을 먹을 수 있어요.\",\"instructions\":[\"1. 냄비에 물, 대파, 생강, 마늘, 통후추, 맛술, 된장을 넣고 끓인다.\",\"2. 1이 끓으면 삼겹살 덩어리를 넣고 35~40분 간 삶는다.\",\"3. 새우, 오징어, 주꾸미는 모양을 내 데치고 파프리카와 오이, 당근, 양파는 가늘게 채 썬다.\",\"4. 겨자가루를 개어 숙성시켜 설탕, 식초로 냉채 소스를 만든 뒤 3을 넣고 무친다.\",\"5. 2의 삽겹살을 모양대로 썬다.\",\"6. 수육과 해물냉채를 담는다.\"]},{\"id\":\"k1087\",\"title\":\"알록달록화전, 멸치두부전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190419/20190419034505_1555656305675.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409053059_1554798659398.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409053114_1554798674409.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409053129_1554798689527.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409053142_1554798702109.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409053155_1554798715524.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409053208_1554798728673.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"찹쌀가루 15g\",\"알비트 5g\",\"시금치 5g\",\"두부 10g\",\"잔멸치 5g\",\"식용꽃 10g\",\"쑥갓 10g\",\"부침가루 10g\",\"꿀 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치를 이용해 소금 없이도 간을 맞춘 전을 만들 수 있어요.\",\"instructions\":[\"1. 두부는 살짝 구워 물기를 제거하고 멸치는 설탕과 함께 볶는다.\",\"2. 알비트, 시금치에 약간의 물을 넣고 각각 믹서에 간다.\",\"3. 찹쌀가루를 알비트, 시금치 간 물에 반죽한다.\",\"4. 두부를 으깨 볶은 멸치와 함께 부침가루에 넣고 반죽한다.\",\"5. 식용꽃과 쑥갓을 씻어 물기를 제거한다.\",\"6. 팬에 3과 4를 각각 부치고 식용꽃과 쑥갓으로 장식하고 꿀을 곁들인다.\"]},{\"id\":\"k1088\",\"title\":\"단호박떡볶이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111752_1584411472208.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111815_1584411495760.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111826_1584411506883.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111843_1584411523208.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111856_1584411536172.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111908_1584411548717.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111919_1584411559736.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"떡볶이떡 26g\",\"단호박 14.5 g\",\"브로콜리 1.6g\",\"우유 4ml\",\"생크림 2.6g\",\"검정깨 0.01g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"고추장, 간장 대신 단호박, 유제품으로만 맛을 냈어요.\",\"instructions\":[\"1. 떡볶이 떡은 물에 넣어 한 개씩 떼어 놓는다.\",\"2. 단호박은 반으로 잘라 쪄서 속만 파낸다.\",\"3. 브로콜리는 데쳐서 작게 썰어 준비해 둔다.\",\"4. 삶은 단호박, 생크림, 우유를 넣고 간다.\",\"5. ④에 물을 넣고 끓이다가 떡과 브로콜리를 넣어 익힌다.\",\"6. 검정깨를 뿌려 마무리한다.\"]},{\"id\":\"k1089\",\"title\":\"배·라임 모히또\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01136_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01136_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01136_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01136_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01136_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01136_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01136_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"배(1개)\",\"라임(1개)\",\"탄산수(500g)\",\"애플민트(5g)\",\"스테비아(5g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"라임의 신맛이 배의 단맛을 높여주고 애플민트의 상큼한 향으로 맛있는 모히또를 만들 수 있어요.\",\"instructions\":[\"1. 라임을 반으로 잘라 즙을 짠다.\",\"2. 라임즙과 배를 믹서에 넣고 간다.\",\"3. 2번에 애플민트와 올리고당,탄산수를 넣고 믹서로 간다.\",\"4. 냉동실에 3번을 넣고 얼린다.\",\"5. 얼린 모히또를 믹서에 갈아 슬러시처럼 만든다.\",\"6. 잔에 담고 애플민트로 장식한다.\"]},{\"id\":\"k1090\",\"title\":\"포도청 보리 수단\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01137_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01137_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01137_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01137_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01137_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01137_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01137_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"포도(150g)\",\"보리(10g)\",\"전분(30g)\",\"녹차(티백\",\"1개)\",\"설탕(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"포도로 설탕을 대신하고 보리수단을 넣어 쫄깃한 식감을 살릴 수 있어요.\",\"instructions\":[\"1. 포도는 껍질과 씨를 제거한 뒤  설탕을 넣고 포도청을 만든다.\",\"2. 찬물에 녹차를 우려낸다.\",\"3. 보리를 깨끗이 씻은 뒤 푹 삶는다.\",\"4. 삶은 보리에 전분을 묻혀 끓는 물에 삶아 건지는 것을 반복한다.\",\"5. 포도청에 우려낸 녹차를 10:1 비율로 넣는다.\",\"6. 보리수단을 넣는다.\"]},{\"id\":\"k1091\",\"title\":\"감자주스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/cook/10_01138_2.png\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01138_1.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01138_2.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01138_3.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01138_4.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01138_5.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/cook/20_01138_6.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"감자(400g)\",\"우유(200g)\",\"설탕(10g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"담백한 감자를 우유와 함께 갈아 부드럽고 고소한 주스를 만들 수 있어요.\",\"instructions\":[\"1. 감자를 깨끗이 씻는다.\",\"2. 냄비에 설탕을 넣고 감자를 삶는다.\",\"3. 삶은 감자의 껍질을 벗긴다.\",\"4. 껍질 벗긴 감자를 우유와 믹서에넣고 간다.\",\"5. 4번을 체에 걸러 부드럽게 만든다.\",\"6. 컵에 담는다.\"]},{\"id\":\"k1092\",\"title\":\"만가닥버섯볶음\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101043_1554685843526.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101109_1554685869686.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101126_1554685886814.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101144_1554685904857.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101159_1554685919241.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101222_1554685942044.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101237_1554685957122.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"만가닥버섯 25g\",\"게살(크래미) 10g\",\"적파프리카 10g\",\"황파프리카 10g\",\"청피망 10g\",\"후추 3g\",\"소금 1g\",\"간장 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"게살(크래미)로 소금을 대신해요.\",\"instructions\":[\"1. 만가닥버섯을 한 송이씩 자른다.\",\"2. 청피망, 황, 적파프리카는 채썰고 게살은 길이로 찢는다.\",\"3. 팬에 기름을 두르고 채썬 파프리카와 피망을 볶는다.\",\"4. 3에 손질한 만가닥버섯을 넣고 볶는다.\",\"5. 찢어둔 게살을 넣고 볶다가 소금, 후추로 간을 한다.\",\"6. 간장으로 색을 내고 담는다.\"]},{\"id\":\"k1093\",\"title\":\"양파홍초절임\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114231_1554691351521.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114257_1554691377320.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114309_1554691389381.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114321_1554691401789.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114335_1554691415716.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114347_1554691427610.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408114405_1554691445748.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파 80g\",\"홍초 15g\",\"간장 0.1g\",\"설탕 1.5g\",\"홍고추 1g\",\"청양고추 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"홍초를 사용해 설탕과 간장의 사용을 줄일 수 있어요.\",\"instructions\":[\"1. 양파는 깨끗이 씻어 한 입 크기로 자른다.\",\"2. 홍고추와 청양고추는 깨끗이 씻어 어슷하게 썬다.\",\"3. 저염간장과 설탕, 홍초를 넣고 끓여 초절임장을 만든다.\",\"4. 초절임장을 뚜껑이 있는 용기에 옮겨 담는다.\",\"5. 초절임장에 양파와 홍고추, 청양고추를 넣는다.\",\"6. 양파홍초절임을 하루정도 숙성시킨다.\"]},{\"id\":\"k1094\",\"title\":\"고구마순나물\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054715_1554799635774.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054753_1554799673808.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054808_1554799688544.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054824_1554799704223.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054837_1554799717099.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054850_1554799730211.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409054906_1554799746045.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마순 25g\",\"양파 10g\",\"된장 10g\",\"두부 5g\",\"마늘 10g\",\"흑임자 5g\",\"설탕 5g\",\"식초 5g\",\"참기름 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"양념에 두부를 넣어 나트륨을 줄이고 고소한 맛을 더했어요\",\"instructions\":[\"1. 두부를 데친 뒤 식혀 으깬다.\",\"2. 으깬 두부에 식초, 설탕, 된장을 섞어 양념을 만든다.\",\"3. 손질한 고구마순을 4cm 길이로 썬다.\",\"4. 고구마순을 데친다.\",\"5. 양파를 곱게 채 썬다.\",\"6. 고구마순에 채 썬 양파와 양념, 흑임자을 넣고 무친다.\"]},{\"id\":\"k1095\",\"title\":\"저염 겉절이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035647_1678085807473.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035841_1678085921861.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035903_1678085943027.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035921_1678085961708.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306035943_1678085983952.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306040006_1678086006310.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수재료 : 배추(50g)\",\"무(20g)\",\"쪽파(10g)\",\"양파(5g)\",\"다진마늘(5g)\",\"다진생강(5g)\",\"참깨(1g)\",\"•양념 : 저염소금(5g)\",\"고춧가루(10g)\",\"설탕(5g)\",\"젓갈(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•배추를 소금에 절이는 시간이 적은 겉절이는 일반 김치에 비해 나트륨 함량이 적습니다.\\n•저염소금을 사용하여 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 배추에 세로로 칼집을 낸 뒤 저염소금을 뿌리고, 10분 뒤 씻는다.\",\"2. 무는 깨끗이 손질하여 씻은 뒤 얇게 채 썰고, 쪽파는 4cm 길이로 썰고, 양파는 채 썬다.\",\"3. 볼에 참깨를 제외한 무, 쪽파, 양파, 다진 마늘, 다진 생강과 저염소금을 제외한 양념재료를 넣고 버무려 양념을 만든다.\",\"4. 저염소금에 절여 씻은 배추를 김치 양념에 골고루 버무린다.\",\"5. 참깨를 뿌려 마무리한다.\"]},{\"id\":\"k1096\",\"title\":\"아욱 된장무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410114015_1554864015237.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410114041_1554864041168.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410114108_1554864068329.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410114120_1554864080942.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410114134_1554864094776.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410114147_1554864107483.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410125824_1554868704099.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"아욱 200g\",\"된장 15g\",\"마늘 10g\",\"저염간장 5g\",\"참기름 2g\",\"참깨 1g\",\"소금 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼슘과 식이섬유가 풍부한 아욱과 소금을 대신한 된장으로 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 아욱 줄기 끝부분을 꺽어 손질한다.\",\"2. 손질한 아욱을 소금을 약간 넣은 물에 넣어 치대듯이 주무른다.\",\"3. 끓는 물에 아욱을 삶은 뒤 찬물에 헹궈 물기를 짠다.\",\"4. 아욱을 먹기 좋은 크기로 썬다.\",\"5. 마늘을 곱게 다진다.\",\"6. 아욱에 된장, 다진마늘, 참기름, 저염간장, 깨를 넣고 버무린다.\"]},{\"id\":\"k1097\",\"title\":\"검은콩부추전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054355_1584089035031.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054418_1584089058761.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054430_1584089070161.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054442_1584089082349.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054456_1584089096521.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054511_1584089111728.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054522_1584089122628.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"검정콩(서리태) 2.7g\",\"밀가루 5.3g\",\"부침가루 5.3g\",\"홍고추 0.25g\",\"풋고추 0.25g\",\"당근 1.2g\",\"부추 5.9g\",\"깐양파 3.7g\",\"애호박 5.3g\",\"달걀 1.0g\",\"콩기름 2.0g\",\"국간장 0.4g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"콩 삶은 물과 나트륨 함량이 낮은 국간장으로 간을 맞췄어요.\",\"instructions\":[\"1. 부추는 깨끗이 씻어 4~5cm 길이로 썬다.\",\"2. 애호박, 당근, 양파는 가늘게 채썬다.\",\"3. 홍고추, 풋고추는 어슷하게 썬다.\",\"4. 검정콩은 삶아서 거칠게 갈고, 콩을 삶은 물은 보관한다.\",\"5. 모든 재료를 섞고 콩 삶은 물로 반죽 농도를 맞춘다.\",\"6. 1인 분량씩 노릇하게 부친다.\"]},{\"id\":\"k1098\",\"title\":\"고사리파전&단감전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054649_1584089209268.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054718_1584089238352.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054731_1584089251220.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054743_1584089263191.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054753_1584089273423.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054804_1584089284386.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054817_1584089297037.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고사리 30g\",\"쪽파 7g\",\"홍고추 6g\",\"계란 20g(0.3개)\",\"밀가루 20g\",\"단감 13g\",\"물 30ml\",\"찹쌀가루 15g\",\"감자전분 50g\",\"대추 0.1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"고사리의 쫄깃한 식감과 특유의 향을 살려 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 고사리와 쪽파는 길이를 반으로 자르고, 홍고추는 길이는 살려 길게 썬다.\",\"2. 기름을 두른 팬에 ①을 얹고 밀가루, 계란 푼 반죽을 부워 지져낸다.\",\"3. 단감을 0.4cm 원형으로 썰고 꽃 모양 틀로 찍어낸다.\",\"4. 찹쌀가루에 감자전분물을 넣어 반죽한다.\",\"5. 기름 두른 팬에 반죽을 동그랗게 만든 후 감과 대추 꽃을 얹어 부친다.\",\"6. 단감전과 먹기 좋은 크기로 썬 고사리 파전을 그릇에 담아 완성시킨다.\"]},{\"id\":\"k1099\",\"title\":\"바지락매생이전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055015_1584089415237.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055036_1584089436625.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055048_1584089448253.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055058_1584089458476.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055109_1584089469724.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055122_1584089482903.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313055142_1584089502033.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"매생이 30g\",\"바지락살 10g\",\"부침가루 5g\",\"튀김가루 5g\",\"홍고추 1g\",\"대두유 12g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바지락과 매생이는 칼륨이 풍부하여 나트륨 배출에 도움을 줘요.\",\"instructions\":[\"1. 매생이와 바지락은 소금기를 없애기 위해 물에 여러 번 헹군다.\",\"2. 튀김가루, 부침가루에 물을 넣고 반죽을 만든다.\",\"3. 매생이를 잘게 다져 반죽에 섞어준다.\",\"4. 팬에 매생이 반죽을 얹고 바지락살을 넣고 노릇하게 구워준다.\",\"5. 구워진 전에 홍고추 고명을 얹어 준다.\",\"6. 그릇에 담아 마무리 한다.\"]},{\"id\":\"k1100\",\"title\":\"알콩달콩전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104751_1584409671661.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104815_1584409695753.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104828_1584409708204.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104840_1584409720292.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104853_1584409733658.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104908_1584409748507.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317104928_1584409768208.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"병아리콩 10g\",\"검정콩 10g\",\"완두콩 10g\",\"두부 25g\",\"빨간 파프리카 5g\",\"찹쌀가루 10g\",\"밀가루 5g\",\"소금 0.3g\",\"물 2ml\",\"식용유 10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 대두류를 사용하여 체내 나트륨 흡수를 줄일 수 있어요.\",\"instructions\":[\"1. 파프리카는 콩 크기의 큐브모양으로 썬다.\",\"2. 준비된 콩들은 물에 불린 후, 각각 끓는 물에 삶은 다음 물기를 제거한다.\",\"3. 두부와 삶은 병아리콩을 으깨준다.\",\"4. ③에 밀가루, 찹쌀가루, 소금, 물을 넣어 반죽한다.\",\"5. 반죽에 콩과 파프리카를 섞는다.\",\"6. 팬에 식용유를 두르고, 반죽의 콩들이 잘 보이도록 먹기 좋은 크기로 부친다.\"]},{\"id\":\"k1101\",\"title\":\"계란만두&토마토소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105129_1584409889495.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105153_1584409913191.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105204_1584409924311.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105216_1584409936854.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105230_1584409950034.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105241_1584409961721.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317105256_1584409976377.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지 7g\",\"당면 5g\",\"계란 75g(1.5개)\",\"부추 5g\",\"양파 10g\",\"식용유 3g\",\"토마토홀 30g\",\"월계수잎 1g\",\"파슬리 1g\",\"마늘 3g\",\"함초소금 0.5g\",\"후추 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"케찹 대신 칼륨 함량이 높은 토마토로 소스를 만들었어요.\",\"instructions\":[\"1. 당면은 물에 불리고, 물에 불린 당면과 가지, 부추, 양파를 다진다.\",\"2. 계란은 잘 풀어 둔다.\",\"3. 계란과 전처리한 야채, 후추를 넣고 골고루 섞는다.\",\"4. 기름 두른 팬에 반죽을 지름이 10cm되는 타원형 모양으로 올리고, 반쯤 익으면 접어 납작 만두 모양을 만든다.\",\"5. 토마토홀, 월계수잎, 함초소금을 끓여 소스를 만든다.\",\"6. 완성된 계란만두에 소스를 끼얹고 파슬리로 장식한다.\"]},{\"id\":\"k1102\",\"title\":\"통도라지양념구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111149_1584411109361.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111215_1584411135789.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111232_1584411152216.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111243_1584411163658.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111257_1584411177229.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111307_1584411187876.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111322_1584411202069.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"통도라지 80g\",\"배 5g\",\"다진마늘 3g\",\"골파 15g\",\"통깨 3g\",\"고추장 10g\",\"간장 7.5g\",\"참기름 15g\",\"소금(쓴맛 제거용) 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"배를 갈아 넣어 고추장 양념의 짠맛을 줄였어요.\",\"instructions\":[\"1. 통도라지는 세척 후 껍질을 제거한다.\",\"2. 통도라지를 소금물에 담궈 쓴맛을 우려낸 후 물기를 없앤다.\",\"3. 통도라지를 반으로 갈라서 방망이로 두들겨 얇고 넓적하게 만든다.\",\"4. 갈은 배, 다진 마늘, 고추장, 간장, 참기름을 이용하여 양념장을 만든다.\",\"5. 팬에 도라지를 구워 익히다가, 양념장을 발라 약한불에서 다시 굽는다.\",\"6. 골파와 통깨를 뿌려 완성한다.\"]},{\"id\":\"k1103\",\"title\":\"삼색계란찜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111454_1584411294716.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111525_1584411325937.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111538_1584411338021.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111550_1584411350079.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111602_1584411362448.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111615_1584411375172.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317111626_1584411386586.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"계란 60g\",\"시금치 20g\",\"비트 10g\",\"우유 20g\",\"애플민트 1g\",\"다시마 3g\",\"소금 0.5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"다시마 우린물로 감칠맛을 더해 소금을 줄였어요.\",\"instructions\":[\"1. 다시마를 물에 씻어 낸 후 찬물에 우려낸다.\",\"2. 시금치와 비트는 다시마 우린물을 넣고 각각 갈아 준다.\",\"3. 계란과 우유를 섞어 계란물을 만든다.\",\"4. 계란물을 3등분 하여 나눠 담아 놓는다.\",\"5. 나눠 놓은 계란물에 시금치, 비트를 각각 섞는다.\",\"6. 3가지 계란물을 순서대로 쪄 내고, 애플민트로 장식한다.\"]},{\"id\":\"k1104\",\"title\":\"고구마순들깨나물\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101743_1611883063736.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101805_1611883085051.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101816_1611883096204.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101831_1611883111514.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101844_1611883124694.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101859_1611883139609.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129101911_1611883151302.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"고구마순 60g\",\"들깨가루 20g\",\"다시마 2g\",\"소금 1g\",\"참기름 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 많은 고구마순은 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 고구마순을 끓는 물에 삶아 씻어둔다.\",\"2. 물과 다시마를 약불에 10분정도 우려 다시물을 낸다.\",\"3. 고구마순을 팬으로 옮기고 다시물을 넣어 삶는다.\",\"4. 다시물이 반쯤 줄어들면 소금과 들깻가루를 넣는다.\",\"5. 물기가 없게 볶아준 후 참기름을 넣는다.\",\"6. 접시에 담아서 완성한다.\"]},{\"id\":\"k1105\",\"title\":\"시금치토마토무침\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103147_1611883907986.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103211_1611883931852.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103226_1611883946764.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103239_1611883959934.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103253_1611883973196.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103307_1611883987662.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103319_1611883999668.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"시금치 80g\",\"방울토마토 30g\",\"참기름 2g\",\"참깨 1g\",\"마늘 1g\",\"함초가루 1g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금대신에 함초가루를 사용해 나트륨을 줄였어요.\",\"instructions\":[\"1. 시금치를 끓는 물에 살짝 데친다.\",\"2. 데친 시금치는 찬물에 헹구어 내고 물기를 짠다.\",\"3. 방울토마토는 끓는 물에 살짝 데쳐 껍질을 제거한다.\",\"4. 껍질을 제거한 방울토마토는 반으로 자른다.\",\"5. 데친 시금치에 토마토, 함초가루, 참기름, 참깨, 마늘을 넣어 무친다.\",\"6. 접시에 담아 완성시킨다.\"]},{\"id\":\"k1106\",\"title\":\"바나나미숫가루쉐이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103756_1611884276239.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129104005_1611884405255.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129104017_1611884417757.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129104031_1611884431417.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129104045_1611884445493.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129104059_1611884459335.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129104112_1611884472560.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"미숫가루 15g\",\"바나나 50g\",\"우유 100ml\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바나나는 칼륨 함량이 풍부하여 나트륨 배출을 도와요.\",\"instructions\":[\"1. 바나나 껍질을 벗긴다.\",\"2. 바나나를 알맞은 크기로 잘라 준비해 둔다.\",\"3. 우유와 미숫가루를 알맞은 양으로 계량한다.\",\"4. ③과 바나나를 믹서기에 넣는다.\",\"5. 건더기가 생기지 않을 정도로 간다.\",\"6. 컵에 담아 완성시킨다.\"]},{\"id\":\"k1107\",\"title\":\"배쨈 식빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129015238_1611895958550.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129022820_1611898100646.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129022836_1611898116347.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129015412_1611896052294.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129022908_1611898148998.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129022922_1611898162487.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129022932_1611898172987.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 500g\",\"인스턴트 이스트 5g\",\"소금 7g\",\"달걀 50g(1개)\",\"우유 250g\",\"포도씨유 50g\",\"(속재료) 배 1개\",\"전분물 24g\",\"(토핑재료) 배 1개\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕을 첨가하지 않고 배와 전분만을 사용하여 배 시럽을 만들어 당을 줄였어요.\",\"instructions\":[\"1. (속재료) 배는 껍질을 제거하고 믹서기에 갈아 준 후 체에 걸러 배즙을 만든다. 배즙을 냄비에 넣고 전분과 함께 중불로 20분간 끓여서 배 시럽을 만든다.\",\"2. (토핑) 배는 1개는 작게 잘라 건조시켜 배 크런치 10g을 만든다.\",\"3. 강력분, 소금, 이스던트 이스트를 잘 섞다가 달걀과 미지근하게 데운 우유, 포도씨유를 조금씩 넣어가며 반죽한다.\",\"4. 완성된 반죽을 1-2시간동안 실온에서 1차 발효 시킨 후, 세 덩어리로 나누어 15분 정도 2차 발효 해준다.\",\"5. 2차 발효를 마친 반죽 세덩어리를 포도씨유가 발린 식빵틀에 나란히 담아서 180도로 예열한 오븐에 30분 정도 굽는다.\\n★꼬지로 찔렀을 때 반죽이 묻어나지 않으면 다 익은 거예요.\\\"\",\"6. 구워진 식빵에 배시럽을 바르고 그 위에 건조시켜 만든 배 크런치를 뿌린다.\"]},{\"id\":\"k1108\",\"title\":\"사과 견과류 식빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023426_1611898466994.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023745_1611898665291.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023806_1611898686599.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023826_1611898706650.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023839_1611898719978.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023906_1611898746472.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129023924_1611898764341.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 250g\",\"소금 5g\",\"드라이이스트 6g\",\"버터 25g\",\"달걀 22g\",\"우유 175g\",\"(속재료) 사과 500g (2개)\",\"견과류 15g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕을 넣지 않고 사과 속의 당을 이용하여 맛을 냈어요.\",\"instructions\":[\"1. (속재료) 사과 1개와 견과류는 다이스하고 사과 1개는 강판에 간 후 냄비에 졸인다.\\n★ 사과를 졸이면 단 맛이 농축되고, 갈변도 막을 수 있어요.\",\"2. 강력분과 소금, 이스트, 우유, 물을 넣고 반죽하여 어느 정도 글루텐이 형성되면 버터를 넣어 반죽한다.\",\"3. 반죽을 60분 정도 1차 발효하고 분할해 둥글리기 하여 중간 발효한다.\",\"4. 중간발효가 끝난 반죽은 길게 밀어 편 후 졸인 사과와 견과류를 넣어 롤로 말아 30분간 2차 발효한다.\",\"5. 2차 발효한 반죽 위에 계란물을 발라 아랫불160℃, 윗 불180℃의 오븐에 넣고 30분간 굽는다.\",\"6. 5분정도 남았을 때 꺼내 계란물을 한 번 더 발라 아랫불 170℃, 윗불 180℃로 구워 윗면에 색을 내준다.\\n★ 굽는 중간에 틀을 돌려주면 골고루 구워져요.\"]},{\"id\":\"k1109\",\"title\":\"카카오 깜빠뉴\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032316_1611901396829.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032438_1611901478077.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032459_1611901499716.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032512_1611901512815.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032533_1611901533336.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032546_1611901546659.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129032610_1611901570436.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 500g\",\"소금 8g\",\"코코아 30g\",\"버터 38g\",\"생이스트 8g\",\"드라이이스트(레드) 4g\",\"파트 페레멘테 95g\",\"우유 114ml\",\"물 236g\",\"(속재료) 카카오 닙스 94g\",\"호두 94g\",\"건포도 150g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"바게트 반죽을 만들어 하루 동안 저온 발효시킨 파트 페레멘테를 활용해 건강빵을 만들었어요.\",\"instructions\":[\"1. 버터를 제외한 모든 재료를 넣어 반죽하다가 버터를 넣어 최종까지 믹스한다. 믹스된 반죽에 속재료를 넣어 골고루 섞는다.\",\"2. 1차 발효 30분 후 punch 후 35분 발효 시킨다.\\n★punch는 가스를 빼는 과정을 얘기해요.\",\"3. 200g 분할 후 중간발효 20분을 한다.\",\"4. 중간 발효된 반죽은 둥글게 성형한다.\",\"5. 스프레이를 뿌린 후 덧가루를 묻혀 50분 동안 2차 발효 한다.\",\"6. X모양 칼집을 주고 195℃ 12분 스팀 5초로 설정하여 굽는다.\\n★칼집은 날이 얇은 면도칼 등을 이용하면 좋아요.\"]},{\"id\":\"k1110\",\"title\":\"곶감 베이글\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043447_1611905687183.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043558_1611905758915.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043610_1611905770468.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043632_1611905792414.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043643_1611905803906.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043658_1611905818241.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129043710_1611905830062.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 통밀가루 200g\",\"강력밀가루 150g\",\"인스턴트 드라이 이스트 8g\",\"사과종 30ml\",\"물 220ml\",\"소금 6g\",\"카놀라유 20g\",\"레몬 제스트 1개\",\"곶감 88g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"레몬의 상큼한 향과 곶감이 당이 적게 들어가도 맛있게 해줘요. \\n사과종은 사과주스로 대체하고 계량제를 5g 더 넣어주세요.\",\"instructions\":[\"1. 레몬의 겉껍질로 제스트를 만들고, 곶감은 작은 다이스로 썬다.\",\"2. 물에 만들어 놓은 레몬 제스트와 소금, 이스트, 사과종, 카놀라유를 넣고 섞어준 뒤 통밀가루와, 강력분을 넣고 반죽해 겉표면이 매끄럽고 탄력성을 가질 때 까지 치댄다.\",\"3. 반죽에 비닐을 덮어 40~50℃에서 2배가 부풀 때까지 1차발효하고, 발효가 끝난 반죽은 기포를 빼준 뒤 75g씩 분할해 둥글리기하고 비닐을 씌워 다시 15분간 중간 발효한다.\",\"4. 반죽은 가스를 살짝 빼주고 타원형으로 밀고, 곶감을 올려 삼절 접기한 다음 이음새를 꼬집고 양쪽을 붙여 원형모양으로 성형하여 30분간 2차 발효한다.\",\"5. 발효된 반죽은 끓는 물에 앞, 뒤로 10초간 데쳐내고 팬닝한다.\",\"6. 200도로 예열된 오븐에서 17분간 굽는다.\"]},{\"id\":\"k1111\",\"title\":\"단호박크림을 곁들인 브로콜리 베이글\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044142_1611906102544.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044206_1611906126693.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044220_1611906140319.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044233_1611906153631.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044255_1611906175818.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044311_1611906191452.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129044709_1611906429428.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력분 225g\",\"물 40ml\",\"블루베리 발효원종 550g\",\"소금 3g\",\"올리브유 15g\",\"브로콜리 100g\",\"(속재료) 단호박 600g\",\"생크림 250g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"천연발효종을 이용하여 이스트를 넣지 않고 발효 시켰으며 단호박 크림으로 단맛을 추가했어요.\\n블루베리 발효원종은 계량제 10g으로 대체 가능해요.\",\"instructions\":[\"1. (속재료) 익힌 단호박과 생크림을 믹싱하여 단호박 크림을 만든다.\\n★ 단호박은 쪄서 사용하는게 좋아요.\",\"2. 브로콜리를 제외한 반죽 재료를 넣고 최종단계까지 믹싱한 후 삶아서 다진 브로콜리를 넣고 섞어준다. 1차 발효를 고온발효로 27℃에서 1시간 발효한다.\",\"3. 130g씩 분할하여 둥글리기 후 중간 발효를 20분간 한다.\",\"4. 반죽을 30cm ~35cm 정도 늘린 후 링 모양으로 정형하여 팬닝한 후 35℃, 85%의 습도 환경에서 60분간 2차 발효 해주고 끓는 물에 양쪽 면을 데친다.\",\"5. 210℃에서 15분간 구워주고 식힘망에서 식힌다.\",\"6. \\\"식은 빵을 갈라 단호박 크림을 샌드한다.\\n★빵이 식은 후 크림을 올려야 녹지 않아요.\\\"\"]},{\"id\":\"k1112\",\"title\":\"어묵 잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100338_1615338218715.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100406_1615338246235.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100419_1615338259474.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100431_1615338271552.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100444_1615338284090.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100457_1615338297653.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100510_1615338310739.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"돼지고기(70g)\",\"어묵(100g)\",\"아삭이고추(30g)\",\"빨강 파프리카(25g)\",\"노랑 파프리카(25g)\",\"콩나물(150g)\",\"소금(0.3g)\",\"후춧가루(0.3g)\",\"굴소스(5g)\",\"참기름(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"소금 대신 굴소스를 활용해 간을 맞췄어요.\",\"instructions\":[\"1. 돼지고기, 어묵, 아삭이고추, 파프리카는 채 썬다.\",\"2. 콩나물은 찬물에 헹궈 체에 밭친다.\",\"3. 채 썬 돼지고기에 밑간을 한다.\",\"4. 중간 불로 달군 팬에 밑간한 돼지고기를 넣어 3분간 볶는다.\",\"5. 채 썬 재료와 어묵을 넣어 5분간 볶는다.\",\"6. 굴소스를 넣어 1~2분간 볶고 참기름을 두른 뒤 고루 섞는다.\"]},{\"id\":\"k1113\",\"title\":\"토마토 비빔국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310102052_1615339252330.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100941_1615338581489.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310100953_1615338593092.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101012_1615338612946.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101028_1615338628933.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101040_1615338640648.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"양파(20g)\",\"바질(10g)\",\"삶은 달걀(1개)\",\"쌀국수(100g)\",\"토마토(200g)\",\"고추장(½Ts)\",\"고춧가루(½Ts)\",\"꿀(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토로 비빔소스를 만들어 고추장 사용을 줄였어요.\\n양파와 바질을 곁들여 샐러드처럼 산뜻하게 즐길 수 있어요\",\"instructions\":[\"1. 양파, 바질은 채 썰고, 삶은 달걀은 반으로 자른다.\",\"2. 채 썬 양파는 찬물에 담가 체에 밭쳐 물기를 제거한다.\",\"3. 믹서에 비빔소스 재료를 넣고 갈아 비빔소스를 만든다.\",\"4. 끓는 물(8컵)에 쌀국수를 넣어 2분 삶아 찬물에 헹궈 체에 밭친다.\",\"5. 그릇에 쌀국수 → 비빔소스 → 양파, 바질 → 달걀 순으로 얹고 마무리한다.\"]},{\"id\":\"k1114\",\"title\":\"멸치 전복 저염국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101237_1615338757971.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101318_1615338798896.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101336_1615338816950.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101351_1615338831986.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101406_1615338846258.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101428_1615338868980.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310101444_1615338884696.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"전복(2개)\",\"애호박(20g)\",\"표고버섯(15g)\",\"당근(20g)\",\"달걀지단(흰자\",\"노른자 각각 1장)\",\"삶은 쌀소면(80g)\",\"식용유(5㎖)\",\"멸치(5g)\",\"황태포(2g)\",\"다시마(3g)\",\"대파(100g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"멸치 양념장을 활용해 소금 사용을 줄였어요.\\n멸치와 황태포를 약한 불에 볶아서 이용하면 감칠맛이 향상되요.\",\"instructions\":[\"1. 약한 불에 멸치와 황태포를 5분간 볶은 뒤 나머지 육수 재료와 물(1L)을 넣어 끓어오르면 30분간 끓이고 체에 밭쳐 거른다.\",\"2. 건진 멸치는 잘게 다지고, 전복은 껍질과 내장을 제거한 뒤 칼집을 넣고, 애호박, 표고버섯, 당근, 달걀지단은 채 썬다.\",\"3. 잘게 다진 멸치에 멸치 양념장 재료를 넣어 멸치 양념장을 만든다.\",\"4. 냄비에 육수를 붓고 약한 불에 손질한 전복을 넣어 5분간 익힌다.\",\"5. 중간 불로 달군 팬에 식용유(5㎖)를 두른 뒤 손질한 채소를 볶는다.\",\"6. 그릇에 삶은 소면 → 볶은 재료 → 익힌 전복 순으로 담고 육수를 붓는다.\"]},{\"id\":\"k1115\",\"title\":\"유부초절임\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101724_1554686244336.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101748_1554686268393.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101801_1554686281666.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101816_1554686296305.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101830_1554686310626.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101846_1554686326634.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408101951_1554686391295.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"사과 20g\",\"유부 5g\",\"양배추 15g\",\"당근 10g\",\"설탕 3g\",\"식초 15g\",\"오이 15g\",\"다시마 5g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"유부를 물에 데쳐 기름기와 나트륨을 줄일 수 있어요.\",\"instructions\":[\"1. 유부와 다시마를 데친다.\",\"2. 데친 유부의 물기를 짜내고 채썬다.\",\"3. 데친 다시마를 채썬다.\",\"4. 양배추와 당근, 사과, 오이를 채썬다.\",\"5. 설탕과 식초, 후추를 섞어 소스를 만든다.\",\"6. 채썬 재료와 소스를 섞어 버무린다.\"]},{\"id\":\"k1116\",\"title\":\"토마토 미소 된장국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409055823_1554800303065.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409055859_1554800339984.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409055912_1554800352822.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409055926_1554800366946.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409055941_1554800381617.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409055954_1554800394793.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409060009_1554800409126.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"토마토 50g\",\"두부 30g\",\"양파 15g\",\"표고버섯 15g\",\"멸치 5g\",\"고추 8g\",\"대파 3g\",\"다시마 2g\",\"미소된장 30g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"토마토, 다시마, 양파의 칼륨은 나트륨 배출을 도와줘요.\",\"instructions\":[\"1. 멸치, 다시마를 끓여 육수를 만든다.\",\"2. 두부, 양파, 표고버섯, 고추, 대파를 먹기 좋은 크기로 썬다.\",\"3. 냄비에 물을 끓여 토마토를 5분 정도 익힌다.\",\"4. 토마토 껍질을 제거하고 적당한 크기로 썰어 씨를 제거한다.\",\"5. 육수에 미소 된장을 풀고 양파, 표고버섯을 넣는다.\",\"6. 토마토와 대파를 넣는다.\"]},{\"id\":\"k1117\",\"title\":\"미역 미소국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031437_1678342477922.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031527_1678342527128.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031641_1678342601262.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031658_1678342618597.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031713_1678342633781.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031735_1678342655265.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309031832_1678342712960.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 건미역(2g)\",\"가다랑어포(0.3g)\",\"•양념 : 미소된장(3g)\",\"미향(0.3g)\",\"물(350g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•가다랑어포로 우려낸 육수는 소금을 넣지 않아도 간이 맞아요.\",\"instructions\":[\"1. 건미역을 물에 불린다.\",\"2. 불린 미역을 잘게 썬다.\",\"3. 냄비에 물(350g)과 가다랑어포를 넣어 우려내 육수를 만든다.\",\"4. 육수에 미소된장을 곱게 푼다.\",\"5. 국에 미역을 넣어 한소끔 끓인다.\",\"6. 미향을 넣어 마무리한다.\"]},{\"id\":\"k1118\",\"title\":\"포두부채소잡채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054041_1678264841984.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054124_1678264884238.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054138_1678264898644.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054257_1678264977263.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054326_1678265006103.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054344_1678265024296.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308054405_1678265045098.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"•필수 재료 : 포두부(100g)\",\"참느타리버섯(45g)\",\"양파(45g)\",\"게맛살(15g)\",\"청피망(15g)\",\"홍피망(15g)\",\"파(10g)\",\"생강(3g)\",\"식용유(3g)\",\"•양념 : 다진마늘(10g)\",\"설탕(15g)\",\"노두유(3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•포두부는 물에 데쳐 사용하여 나트륨 함량을 낮췄어요.\",\"instructions\":[\"1. 포두부, 양파, 피망, 파, 생강은 가늘게 채 썬다.\",\"2. 참느타리버섯, 게맛살은 가늘게 찢는다.\",\"3. 냄비에 물을 끓이고 포두부는 미리 데쳐 체에 밭쳐 물기를 뺀다.\",\"4. 팬에 식용유를 두른 뒤 파, 다진 마늘, 생강을 볶는다.\",\"5. 손질한 채소와 참느타리버섯, 게맛살을 넣어 볶는다.\",\"6. 채소가 익으면 데쳐 놓은 포두부를 넣고 볶다가 노두유와 설탕으로 간을 해 마무리한다.\"]},{\"id\":\"k1119\",\"title\":\"속이 든든든한 밥 빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129055906_1611910746844.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053617_1611909377364.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053638_1611909398737.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053658_1611909418365.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053710_1611909430640.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053723_1611909443946.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053743_1611909463453.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 강력 쌀가루 240g\",\"불린밥 100g\",\"물 150ml\",\"이스트 4g\",\"소금 4g\",\"코코넛 오일 12g\",\"(속재료) 단호박 700g\",\"옥수수 100g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"설탕을 사용하지 않고 단호박과 밥의 단맛으로 맛을 냈어요.\",\"instructions\":[\"1. (속재료) 익혀 낸 단호박과 옥수수 알을 섞어준다.\",\"2. 쌀가루, 소금, 불린 밥, 물을 넣고 한 덩어리가 되게 반죽한 다음 코코넛 오일을 넣고 부드러워질 때까지 반죽한다.\",\"3. \\\"반죽의 크기가 두 배가 될 때까지 발효한다. \\n★손으로 반죽을 눌렀을 때 자국이 남아 있으면 발효가 잘 된 거예요.\\\"\",\"4. 반죽을 얇은 직사각형(크기 약 35cm ×28cm, 두께 약 0.5cm )으로 밀어 위에 속재료를 바르고 말아준다.\",\"5. 말린 반죽을 약 4cm 크기로 잘라 머핀틀에 넣어 틀에 꽉 찰때까지 발효한다.\",\"6. 위에 우유를 발라 윗불 180℃, 아랫불 160℃ 예열된 오븐에 20~25분 굽는다.\"]},{\"id\":\"k1120\",\"title\":\"참외지 리코타버무리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044333_1670485413793.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015822_1615352302189.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015835_1615352315522.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015849_1615352329829.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015904_1615352344759.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015919_1615352359018.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310015935_1615352375167.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"참외(110g)\",\"아몬드(5g)\",\"소금(1g)\",\"설탕(2g)\",\"레몬즙(15g)\",\"올리브유(2g)\",\"유자청(5g)\",\"리코타치즈(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"절인 참외의 감칠맛과 리코타치즈 본연의 맛으로 간을 맞추고 나트륨 사용을 줄였어요.\",\"instructions\":[\"1. 참외는 껍질을 벗기고 반 갈라 속을 파내고, 파낸 속은 면포에 감싸 즙을 짠다.\",\"2. 과육은 필러로 얇게 저민 뒤 손으로 즙을 꼭 짠다.\",\"3. 참외즙에 끓는 물(50㎖)과 양념을 넣어 고루 섞는다.\",\"4. 양념을 섞은 참외즙에 얇게 저민 참외 과육을 넣어 냉장실에서 20분간 절인다.\",\"5. 소스를 만든다.\",\"6. 절인 참외 과육을 찬물에 헹궈 물기를 꼭 짠 뒤 그릇에 담고 소스와 아몬드를 곁들인다.\"]},{\"id\":\"k1121\",\"title\":\"과일 피클 젤리\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208043833_1670485113169.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023016_1615354216151.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023027_1615354227397.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023041_1615354241109.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023054_1615354254419.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023107_1615354267760.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023121_1615354281611.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"방울토마토(50g)\",\"바나나(80g)\",\"청포도(50g)\",\"젤라틴(7.5g)\",\"한천가루(0.25g)\",\"피클링 스파이스(5g)\",\"사과식초(10g)\",\"설탕(3g)\",\"올리고당(5g)\",\"소금(1g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"각종 과일을 사용해 식재료 본연의 단맛을 내고 설탕의 사용을 줄였어요.\",\"instructions\":[\"1. 과일은 한입 크기로 썬다.\",\"2. 젤라틴은 찬물에 불린다.\",\"3. 냄비에 물(100㎖), 양념을 넣어 끓인 뒤 피클링 스파이스를 체로 거른다.\",\"4. ③에 불린 젤라틴과 한천가루를 넣어 녹인 뒤 한 김 식힌다.\",\"5. 유리 용기에 손질한 과일을 담고 식힌 ④의 젤라틴 물을 붓는다.\",\"6. 냉장실에서 1시간 30분간 굳혀 마무리한다.\"]},{\"id\":\"k1122\",\"title\":\"바나나 쑥두부푸딩\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208043901_1670485141626.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023424_1615354464242.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023436_1615354476045.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023448_1615354488178.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023503_1615354503575.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023517_1615354517259.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"흰강낭콩(30g)\",\"두부(140g)\",\"우유(40g)\",\"올리고당(50g)\",\"바나나(1개)\",\"쑥 파우더(1g)\",\"아몬드(2g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"쑥의 향긋한 향과 당도가 높은 바나나를 사용하여 건강한 디저트를 만들었어요.\",\"instructions\":[\"1. 흰강낭콩은 물에 담가 8시간 불렸다가 건진 뒤 끓는 물에 20분간 삶는다.\",\"2. 끓는 물에 두부를 살짝 데쳐 건진다.\",\"3. 믹서에 데친 두부, 삶은 흰강낭콩, 우유, 올리고당, 바나나(½분량)를 넣어 곱게 간다.\",\"4. 믹서에 데친 두부, 삶은 흰강낭콩, 우유, 올리고당, 바나나(½분량)를 넣어 곱게 간다.\",\"5. 나머지 바나나는 한입 크기로 썰고 아몬드와 함께 푸딩 위에 올린다.\"]},{\"id\":\"k1123\",\"title\":\"채소말이와 고구마가지구이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023755_1615354675351.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023820_1615354700644.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023839_1615354719621.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023935_1615354775273.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310023949_1615354789393.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310024004_1615354804010.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310024016_1615354816818.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"가지(½개+20g)\",\"양배추(70g)\",\"빨강 파프리카(20g)\",\"당근(20g)\",\"청경채(1단)\",\"달걀지단(3개 분량)\",\"구운 김(1장)\",\"불린 라이스페이퍼(2장)\",\"깻잎(2장)\",\"찐 고구마(200g)\",\"우유(15g)\",\"무염 버터(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨이 풍부한 채소는 나트륨 배출에 도움을 줘요.\\n당도가 높은 고구마를 사용해 달콤한 맛을 내고 채소의 아삭한 식감으로 심심한 맛을 보완했어요.\",\"instructions\":[\"1. 가지(½개)는 반 갈라 속을 파고, 나머지 가지(20g), 양배추(50g), 빨강 파프리카, 당근은 채 썰고, 양배추(20g)와 청경채는 한입 크기로 썰고, 달걀지단은 채 썬다.\",\"2. 찐 고구마는 껍질을 벗겨 우유와 생크림, 무염 버터를 으깨고 고루 섞어 속을 판 가지에 채운 뒤 다진 마늘과 무염 치즈를 올려 180℃로 예열한 오븐에 5분간 굽는다.\",\"3. 중간 불로 달군 팬에 식용유(20㎖)를 두른 뒤 채 썬 가지, 양배추, 파프리카, 당근을 2분간 볶아 꺼낸다.\",\"4. 같은 팬에 식용유(15㎖)를 두른 뒤 한입 크기로 썬 양배추와 청경채, 후춧가루(0.5g)를 넣어 3분간 볶아 꺼낸다.\",\"5. 구운 김에 불린 라이스페이퍼 → 달걀지단 → 깻잎 → 볶은 채 썬 채소 순으로 넣어 돌돌 말아 한입 크기로 썬다.\",\"6. 그릇에 구운 가지 → 볶은 양배추와 청경채 → 김밥 순으로 올리고 꽃잎과 파슬리가루(2g)를 뿌려 마무리한다.\"]},{\"id\":\"k1124\",\"title\":\"들깨 곤약 냉채\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035228_1615359148382.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035258_1615359178390.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035319_1615359199740.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035348_1615359228369.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035400_1615359240987.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035414_1615359254016.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035427_1615359267600.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"닭가슴살(40g)\",\"노랑 파프리카(20g)\",\"양파(15g)\",\"오이(15g)\",\"당근(15g)\",\"곤약면(80g)\",\"어린잎채소(10g)\",\"겨잣가루(10g)\",\"식초(20g)\",\"올리고당(10g)\",\"들깻가루(10g)\",\"소금(0.3g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"곤약을 사용해 식감을 살려 입맛을 돋우었어요.\\n식초, 겨자와 같이 향과 맛이 강한 들깨소스를 이용해 짠맛을 대체했어요.\",\"instructions\":[\"1. 닭가슴살은 끓는 물에 7분간 삶아 건진 뒤 결대로 찢어 준비한다.\",\"2. 노랑 파프리카, 양파, 오이, 당근은 채 썬다.\",\"3. 곤약면은 끓는 물에 살짝 데쳐 건진 뒤 찬물에 씻어 체에 밭쳐 물기를 제거한다.\",\"4. 들깨소스를 만든다.\",\"5. 곤약면에 삶은 닭가슴살, 채 썬 채소, 들깨소스를 넣어 버무린다.\",\"6. 그릇에 담고 어린잎채소를 올린다.\"]},{\"id\":\"k1125\",\"title\":\"요거트 단호박 샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044231_1670485351624.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040336_1615359816756.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040402_1615359842211.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040415_1615359855517.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040434_1615359874168.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040447_1615359887001.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040501_1615359901368.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"단호박(100g)\",\"감자(5g)\",\"표고버섯(5g)\",\"불린 곤드레나물(10g)\",\"불린 쌀(30g)\",\"건포도(5g)\",\"건무화과(5g)\",\"볶은 호두(5g)\",\"볶은 아몬드 슬라이스(5g)\",\"라즈베리(5g)\",\"요거트(20g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"단호박, 건과일, 무가당 요거트를 이용하여 첨가당 사용을 줄였어요.\\n누룽지와 견과류를 사용하여 식감을 살렸어요.\",\"instructions\":[\"1. 단호박은 껍질을 벗겨 찜기에 넣어 5분간 찐 뒤 으깬다.\",\"2. 감자와 표고버섯은 채 썰고, 불린 곤드레나물은 잘게 썬다.\",\"3. 냄비에 불린 쌀, 채 썬 감자와 표고버섯, 불린 곤드레나물, 물(20㎖)을 넣어 센 불로 5분 30초간 끓인다.\",\"4. 오븐 팬에 감자곤드레밥을 얇게 편 뒤 180℃로 예열한 오븐에 구워 누룽지를 만든다.\",\"5. 으깬 단호박에 건과일과 볶은 호두, 볶은 아몬드 슬라이스를 넣어 고루 섞는다.\",\"6. 그릇에 건과일과 견과류를 섞은 단호박을 예쁘게 담고 곤드레 누룽지와 라즈베리, 요거트를 올린다.\"]},{\"id\":\"k1126\",\"title\":\"타이거새우 현미볶음밥\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98sn\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GLe\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GOC\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GRO\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GTo\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GVZ\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9GWG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 브로콜리(¼개)\",\"양파(¼개)\",\"파프리카(빨강\",\"노랑 각 ¼개)\",\"쪽파(2대)\",\"블랙타이거새우(8마리)\",\"현미밥(2공기)\",\"청양고추(2개)\",\"레몬(½개)\",\"다진 마늘(3Ts)\",\"버터(3Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•저염버터를 사용하면 나트륨 섭취량을 줄일 수 있어요.\\n•백미보다 칼륨이 풍부한 현미밥을 사용했어요.\",\"instructions\":[\"1. 브로콜리는 윗동만 분리해 다지고, 양파, 파프리카, 청양고추는 잘게 다지고, 쪽파는 송송 썰고, 레몬은 2등분한다.\",\"2. 블랙타이거새우는 깨끗하게 씻은 뒤 머리를 제거한다.\",\"3. 약한 불로 달군 팬에 식용유를 두르고, 다진 마늘을 넣어 튀기듯 볶은 뒤 양파를 넣어 볶는다.\",\"4. 손질한 블랙타이거새우와 버터를 넣은 뒤 새우의 색이 변할 때까지 볶고, 다진 파프리카, 청양고추, 브로콜리를 넣어 2분간 볶는다.\",\"5. 그릇에 현미밥을 담고, 볶은 블랙타이거 새우와 국물을 골고루 뿌린다.\",\"6. 송송 썬 쪽파와 레몬을 올려 마무리한다.\"]},{\"id\":\"k1127\",\"title\":\"카레크림 두부면 파스타\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9AyL\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9H0f\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9H2L\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9ItS\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9IvO\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9Iyi\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9I_5\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 콜리플라워(200g)\",\"양송이버섯(2개)\",\"양파(½개)\",\"마늘(3쪽)\",\"무가당 두유(2컵)\",\"두부면(1팩=100g)\",\"바질(3장)\",\"올리브유(1Ts)\",\"다진 마늘(1ts)\",\"강황가루(2Ts)\",\"식초(1ts)\",\"파슬리가루(1ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•두유, 양파를 이용하여 단맛을 보완하고 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 콜리플라워는 잘게 썰고, 양송이버섯과 양파는 3mm 두께로 채 썰고, 마늘(2쪽)은 납작 썬다.\",\"2. 믹서에 잘게 썬 콜리플라워, 무가당 두유, 물(1컵), 마늘(1쪽)을 넣어 곱게 갈아 콜리플라워 크림을 만든다.\",\"3. 중간 불로 달군 팬에 올리브유를 두른 뒤 다진 마늘을 볶고, 납작 썬 마늘, 양파, 양송이버섯을 넣어 양파가 숨이 죽을 때까지 볶는다.\",\"4. 콜리플라워 크림을 넣은 뒤 끓어오르면 강황가루와 두부면을 넣어 골고루 섞는다.\",\"5. 바질을 넣어 고루 섞고, 불을 끈 뒤 식초를 넣어 고루 섞는다.\",\"6. 그릇에 카레크림 두부면 파스타를 담고, 파슬리가루를 뿌려 마무리한다.\"]},{\"id\":\"k1128\",\"title\":\"홍합 배춧국\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102339_1554686619522.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102431_1554686671466.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102444_1554686684343.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102455_1554686695924.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102509_1554686709741.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102525_1554686725585.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102541_1554686741824.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"홍합 50g\",\"배추 50g\",\"무 30g\",\"마늘 2g\",\"파 3g\",\"홍고추 1g\",\"소금 0.3g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"홍합의 감칠맛과 야채로 시원한 맛의 채수를 만들어 재료 본연의 맛을 낼 수 있어요.\",\"instructions\":[\"1. 끓는 물에 한 입 크기로 썬 무를 넣는다.\",\"2. 무가 투명해지면 배추를 넣고 끓인다.\",\"3. 홍합을 넣는다.\",\"4. 홍합이 입을 벌리면 마늘을 다져 넣어 조미한다.\",\"5. 소금을 넣는다.\",\"6. 어슷 썬 파와 홍고추를 고명으로 올린다.\"]},{\"id\":\"k1129\",\"title\":\"얼큰 콩나물 수제비\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011347_1554696827859.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011417_1554696857950.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011432_1554696872854.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011453_1554696893859.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011520_1554696920131.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011536_1554696936719.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408011556_1554696956872.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"콩나물 50g\",\"황태머리 40g\",\"고추장 10g\",\"밀가루 100g\",\"고춧가루 5g\",\"소금 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"황태머리를 구워서 이용하면 나트륨이 적어도 맛있는 육수를 만들 수 있어요.\",\"instructions\":[\"1. 밀가루에 소금을 섞어 반죽한 뒤 숙성시킨다.\",\"2. 황태머리를 구운 뒤 찬물에 넣고 끓여 육수를 만들어 거즈에 거른다.\",\"3. 냄비에 2의 육수를 붓고 콩나물 1/2를 넣은 뒤 끓어 오르면 고추장과 고춧가루를 풀어 끓인다.\",\"4. 숙성된 수제비 반죽을 밀어 따로 끓인 물에 삶아 건진다.\",\"5. 3에 4의 수제비를 넣고 한소끔 끓인다.\",\"6. 나머지 콩나물을 넣어 완성한다.\"]},{\"id\":\"k1130\",\"title\":\"단호박 생선탕수, 키위소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113325_1554863605497.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113411_1554863651965.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113433_1554863673905.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113446_1554863686651.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113501_1554863701195.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113518_1554863718684.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20190410/20190410113535_1554863735706.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"동태살 120g\",\"단호박 10g\",\"당근 15g\",\"오이 15g\",\"양파 15g\",\"전분 30g\",\"계란 110g\",\"튀김가루 10g\",\"목이버섯 3g\",\"식초 15g\",\"키위소스 20g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"키위를 이용해 과일의 단맛을 더해 소금 없이도 맛있는 탕수육을 먹을 수 있어요.\",\"instructions\":[\"1. 따뜻한 물에 부린 목이버섯, 동태살, 당근, 오이, 양파를 먹기 좋은 크기로 썬다.\",\"2. 동태살에 소금과 흰후추로 밑간을 하고 녹말과 계란 흰자를 섞어 튀김옷을 만든다.\",\"3. 동태살에 튀김옷을 입혀 기름에 튀긴다.\",\"4. 물, 계란, 튀김가루를 섞어 튀김옷을 만든 뒤 단호박을 튀긴다.\",\"5. 프라이팬에 기름을 두르고 당근, 양파, 목이버섯을 볶는다.\",\"6. 5에 키위소스, 식초를 넣고 전분물을 넣어 농도를 맞춘 뒤 튀긴 재료와 오이를 섞는다.\"]},{\"id\":\"k1131\",\"title\":\"낙지모듬초말이\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112606_1584411966414.JPG\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112625_1584411985737.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112701_1584412021851.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112715_1584412035350.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112726_1584412046615.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112749_1584412069535.JPG\",\"http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317112808_1584412088717.JPG\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"낙지 30g\",\"가지 12g\",\"오이 7g\",\"표고버섯 24g\",\"당근 10g\",\"미나리 12g\",\"홍고추 0.1g\",\"설탕 15g\",\"식초 25g\",\"물 30m\",\"사과 10g\",\"간장10g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"새콤달콤한 초절이 양념으로 짠맛을 대체했어요.\",\"instructions\":[\"1. 낙지는 살짝 데치고 한입 크기로 썬다.\",\"2. 오이와 당근, 표고, 가지는 얇게 동그란 모양으로 썰고 가지와 표고를 살짝 구워준다.\",\"3. 설탕, 식초, 물로 초절이 양념을 만들어 오이, 당근, 구운 가지와 표고를 절인다.\",\"4. ③의 재료에 낙지를 올린 후 데친 미나리로 감싼다.\",\"5. 사과를 잘게 다져서 준비한다.\",\"6. 사과, 간장, 고춧가루, 설탕, 식초, 깨로 소스를 만들어 초말이와 제공한다.\"]},{\"id\":\"k1132\",\"title\":\"삼각김밥 빵\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129053949_1611909589857.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129054204_1611909724402.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129054426_1611909866869.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129055258_1611910378459.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129055315_1611910395064.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129055326_1611910406766.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129055338_1611910418977.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"(반죽재료) 쌀가루 200g\",\"우유 80g\",\"물 15ml\",\"르뱅 발효종 160g\",\"달걀 50g(1개)\",\"소금 3g\",\"올리브유 25g\",\"양파 30g\",\"당근 30g\",\"먹물 가루 30g\",\"(속재료) 토마토 250g\",\"양파 150g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"빵 반죽에는 양파와 당근을 넣어 단 맛을 냈어요.\\n르뱅 발효종은 이스트 10g으로 대체 가능해요.\",\"instructions\":[\"1. (속재료) 양파, 마늘, 토마토, 파프리카, 닭가슴살을 다져 올리브유를 두른 팬에 볶아준 후에 월계수 잎을 넣고 졸이다가 고추, 오레가노, 바질가루, 고춧가루, 소금, 후추를 넣고 간을 맞춘다.\",\"2. 반죽재료를 모두 넣고 1단으로 믹싱한 후 올리브유를 넣고 최종단계 직전까지 믹싱이 되면 다진 양파와 당근을 넣고 최종단계까지 믹싱한다.\",\"3. 1차 발효(30분~40분)후에 반죽을 각 70g씩 총 3개로 분할하여 둥글리기 한 후 랩을 덮어 중간발효(10분)를 한다.\",\"4. 반죽을 손 위에 놓고 납작하게 눌러서 속재료 40g과 모짜렐라치즈 10g을 넣고 봉합 한 뒤에 삼각형 모양으로 만든다.\\n★이음새가 벌어지면 구우면서 반죽이 터져지니 꼼꼼히 붙여주세요.\",\"5. 팬닝 후 2차 발효(30분)를 한다.\",\"6. 윗불 160℃, 아랫불 180℃에서 15분 동안 굽는다.\"]},{\"id\":\"k1133\",\"title\":\"병아리콩 컵케이크\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208043938_1670485178488.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035706_1615359426041.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035718_1615359438588.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035732_1615359452722.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035744_1615359464688.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035758_1615359478802.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310035811_1615359491736.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"불린 병아리콩(100g)\",\"바나나(1½개)\",\"무가당 코코아 파우더(3g)\",\"다크초콜릿(30g)\",\"아몬드가루(50g)\",\"달걀노른자(1개)\",\"우유(130g)\",\"식용유(10ml)\",\"아몬드 슬라이스(1g)\",\"병아리콩 삶은 물(50ml)\",\"무가당 휘핑크림(50g)\",\"올리고당(15g)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"칼륨 함량이 높은 병아리 콩을 사용했어요.\\n바나나의 천연당을 사용하여 설탕의 사용을 줄였어요.\",\"instructions\":[\"1. 불린 병아리콩은 끓는 물(3컵)에 30~40분간 끓여 건지고, 병아리콩 삶은 물(50㎖)은 한 김 식혀 냉장실에 넣는다.\",\"2. 삶은 병아리콩, 바나나(½개), 무가당 코코아 파우더, 다크 초콜릿, 아몬드가루, 달걀노른자, 우유는 믹서에 넣어 곱게 갈아 반죽을 만든다.\",\"3. 중간 불로 달군 팬에 식용유(10㎖)를 두른 뒤 컵 사이즈에 맞게 반죽을 올려 앞뒤로 노릇하게 굽는다.\",\"4. 냉장실에서 병아리콩물을 꺼내 휘핑해 두고, 무가당 휘핑크림에 올리고당을 넣고 휘핑한 뒤 바나나(½개)를 으깨 고루 섞는다.\",\"5. ④의 병아리콩물과 바나나무가당크림을 모두 섞고, 바나나(1개)는 얇게 썬다.\",\"6. 컵에 구운 시트 → 얇게 썬 바나나 → 크림을 반복하여 쌓고 아몬드 슬라이스를 올린다.\"]},{\"id\":\"k1134\",\"title\":\"양파토마토스튜\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9bVw\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nqc\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9ntS\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nx7\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9n-B\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9o13\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9o2J\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 마늘(4쪽)\",\"토마토(2개)\",\"양파(1개)\",\"월계수잎(2장)\",\"육수용 멸치(½컵)\",\"다시마(5×5cm\",\"2장)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 토마토는 나트륨 배출에 도움을 줘요.\\n•멸치 육수로 간을 맞추어 나트륨 사용은 줄이고 감칠맛을 냈어요.\",\"instructions\":[\"1. 물(8컵)에 육수 재료와 마늘(2쪽)을 넣어 끓으면 다시마를 건진 뒤 약한 불 로 30분간 더 끓여 육수를 만든다.\",\"2. 토마토는 꼭지를 제거하고, 열십자로 칼집을 낸 뒤 끓는 물에 30초간 데쳐 찬물에 담근다.\",\"3. 데친 토마토는 껍질을 벗긴 뒤 씨를 제거하고, 1×1cm 크기로 썬다.\",\"4. 양파는 3mm 두께로 채 썰고, 마늘(2쪽)은 1mm 두께로 채 썬다.\",\"5. 중간 불로 달군 마른 냄비에 채 썬 양파와 물(1Ts)을 넣어 진한 갈색이 될 때까지 볶는다.\",\"6. 토마토를 넣어 으깨가며 5분간 볶고, 육수(6컵), 월계수잎, 채 썬 마늘을 넣어 10분간 끓이고 마무리한다.\"]},{\"id\":\"k1135\",\"title\":\"황금팽이 비빔국수\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9cBO\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oXb\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oZg\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9ob_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oen\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9oi3\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 황금팽이버섯(400g)\",\"양파( 개)\",\"상추(2장)\",\"깻잎(2장)\",\"오이(½개)\",\"천도복숭아(½개)\",\"새우살(½컵)\",\"게살(½컵)\",\"고춧가루(3Ts)\",\"물(3Ts)\",\"현미식초(1.5Ts)\",\"저염 간장(1.5Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 천도복숭아는 나트륨 배출에 도움을 주고, 천도복숭아의 단맛으로 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 황금팽이버섯은 밑동을 자른 뒤 낱낱이 가르고, 양파, 상추, 깻잎, 오이는 채 썰고, 천도복숭아는 웨지 모양으로 썬다.\",\"2. 끓는 물에 황금 팽이버섯을 넣어 5분간 삶아 건진 뒤 찬물에 헹궈 물기를 뺀다.\",\"3. 같은 물에 새우살과 게살을 30초간 데쳐 건진 뒤 찬물에 헹궈 물기를 뺀다.\",\"4. 양념장을 만든다.\",\"5. 손질한 재료를 그릇에 담고, 양념장을 곁들여 마무리한다.\"]},{\"id\":\"k1136\",\"title\":\"맛살 미역줄기전\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9ktU\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rX_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rZw\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rbr\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rfn\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rhb\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9rlQ\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 4인분 ] 미역 줄기(1팩=300g)\",\"양파(½개)\",\"맛살(135g)\",\"건새우(1컵)\",\"부침가루(1컵)\",\"튀김가루(½컵)\",\"탄산수(1컵)\",\"아보카도유(1Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•미역 줄기를 물에 담그고, 게맛살을 데쳐 나트륨 함량을 줄였어요.\\n•양파를 이용하여 단맛을 내고 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 미역 줄기는 흐르는 물에 여러 번 헹구고, 찬물에 1시간 정도 담가둔다.\",\"2. 미역 줄기는 한입 크기로 썰고, 양파는 얇게 채 썰고, 맛살은 낱낱이 가른다.\",\"3. 끓는 물에 맛살을 살짝 데쳐 건진 뒤 물기를 제거한다.\",\"4. 반죽 재료를 고루 섞은 뒤 손질한 재료를 넣어 대충 섞는다.\",\"5. 중간 불로 달군 팬에 아보카도유를 두른 뒤 반죽을 적당한 크기로 떼어 올리고, 건새우를 얹는다.\",\"6. 반죽이 불투명해지면 뒤집고, 앞뒤로 노릇하게 구워 마무리한다.\"]},{\"id\":\"k1137\",\"title\":\"해산물샐러드와 미나리소스\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nAC\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9s9A\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sB_\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sET\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sGV\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sKn\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sOq\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 새송이버섯(1개)\",\"방울토마토(200g)\",\"오징어(1마리)\",\"칵테일새우(200g)\",\"후춧가루(약간)\",\"다진 마늘(1Ts)\",\"올리브유(1Ts)\",\"레몬즙(1Ts)\",\"후춧가루(약간)\",\"미나리(50g)\",\"깻잎(2장)\",\"마늘(2쪽)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•칼륨 함량이 높은 토마토는 나트륨 배출에 도움을 줘요.\\n•미나리를 사용하여 재료 본연의 맛을 내고 향긋함을 살렸어요.\",\"instructions\":[\"1. 새송이버섯은 모양대로 도톰하게 썰고, 방울토마토는 꼭지를 제거한 뒤 열십자 모양을 내고, 오징어 몸통 부분에 사선으로 칼집을 낸 뒤 후춧가루를 뿌린다.\",\"2. 칵테일새우는 양념에 버무린 뒤 20분간 재운다.\",\"3. 중간 불로 달군 마른 팬에 새송이버섯, 방울토마토를 넣어 노릇하게 구워 꺼낸다.\",\"4. 같은 팬에 새우, 오징어를 넣어 겉면의 색이 변할 때까지 구워 꺼낸다.\",\"5. 믹서에 페스토 재료를 넣어 곱게 간다.\",\"6. 그릇에 미나리 페스토를 담고, 손질한 재료를 올려 마무리한다.\"]},{\"id\":\"k1138\",\"title\":\"매운요거트 토마토샐러드\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nNW\",\"stepImages\":[\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sTx\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sVf\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sYb\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sa8\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9seb\",\"https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9sgw\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"[ 2인분 ] 토마토(2개)\",\"양파(¼개)\",\"감자(¼개)\",\"노랑 파프리카(¼개)\",\"브로콜리(¼개)\",\"새우(4마리) 고추기름(1Ts)\",\"후춧가루(0.3Ts)\",\"다진 마늘(0.3Ts)\",\"플레인 요거트(½컵)\",\"고추장(0.3Ts)\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"•플레인 요거트를 이용하여 첨가당 사용을 줄였어요.\",\"instructions\":[\"1. 토마토는 윗부분을 약간 자른 뒤 속을 파낸다.\",\"2. 양파, 감자, 노랑 파프리카, 브로콜리, 새우는 1×1cm 크기로 썬다.\",\"3. 중간 불로 달군 팬에 고추기름을 두르고, 손질한 채소를 넣어 양파가 투명해질 때까지 볶는다.\",\"4. 새우와 후춧가루를 넣은 뒤 고루 섞으며 볶는다.\",\"5. 고추장 요거트 드레싱을 만든다.\",\"6. 토마토 속에 ④의 볶은 재료를 담고, 고추장 요거트 드레싱을 곁들여 마무리한다.\"]},{\"id\":\"k1139\",\"title\":\"초코타르트\",\"origin\":\"KR\",\"source\":\"MFDS COOKRCP01 sample\",\"imageUrl\":\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023104957_1761184197030.jpg\",\"stepImages\":[\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105335_1761184415603.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105348_1761184428506.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105403_1761184443817.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105418_1761184458869.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105432_1761184472352.jpg\",\"http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105446_1761184486939.jpg\"],\"ageRanges\":[\"12-17\",\"18-23\",\"24-30\"],\"ingredients\":[\"주재료 > 아몬드가루 90g\",\"무가당 코코아가루① 12g\",\"귀리 30g\",\"코코넛오일 20g\",\"알룰로스① 20g\",\"소금 1g\",\"초코필링 > 무가당 코코아가루② 12g\",\"땅콩버터 12g\",\"알룰로스② 55g\",\"아몬드우유 60ml\",\"그릭요거트 토핑 > 그릭요거트 42g\",\"알룰로스③ 2g\"],\"allergens\":[],\"cookTime\":15,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"무가당 코코아가루를 사용하여 당류 사용량을 줄였어요.\",\"instructions\":[\"1. 볼에 아몬드가루, 무가당\\n코코아가루①을 체 쳐서 넣고 귀리,\\n코코넛오일, 알룰로스①, 소금을 넣고\\n섞어 반죽을 만든다.\",\"2. 반죽은 냉장고에서 30분 동안\\n휴지한다.\",\"3. 볼에 무가당 코코아가루②를 체 쳐서\\n넣고 땅콩버터, 알룰로스②를 넣는다.\\n완전히 섞이면 아몬드우유를 넣고\\n섞어 초코필링을 만든다.\",\"4. 냉동실에서 30분 동안 굳힌\\n그릭요거트에 알룰로스③을 섞어\\n숟가락으로 모양을 잡아 그릭요거트\\n토핑을 만든다.\",\"5. 머핀 틀에 코코넛오일을 바르고\\n반죽을 넣어 타르트지 모양을 잡는다.\\n170°C로 예열한 오븐에 20분 동안\\n구운 후 완전히 식힌다.\",\"6. 초코필링을 채우고 그릭요거트\\n토핑을 올려 마무리한다.\"]},{\"id\":\"g1\",\"title\":\"Adana kebab\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/04axct1763793018.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Romano Pepper\",\"Lamb Mince\",\"Red Pepper Paste\",\"Pul Biber\",\"Sunflower Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nFinely chop the peppers in a food processor, then tip them in a sieve and press into the sieve so that the peppers release all of their juices. Tip into\",\"instructions\":[\"step 1\",\"Finely chop the peppers in a food processor, then tip them in a sieve and press into the sieve so that the peppers release all of their juices. Tip into a bowl along with the mince, red pepper paste, pul biber, 1½ tsp flaky sea salt, and 2 tbsp of the oil. Mix together, kneading well for at least 2-3 mins. If you need to, wet your hands with cold water to prevent the mixture from sticking. The mixture should be sticky when ready. Cover and chill for at least 2 hrs, or up to 12 hrs.\",\"step 2\",\"When ready to cook, heat the grill to high or an oven to 220C/200C fan/gas 6. Divide the mixture into 12 equal portions, around 85g each. If you’d like to skewer them, divide into 8 equal portions and roll into balls. Using wet hands, thread the balls onto the end of the skewers, massaging the mixture down the skewers in between the palms of your hands, until evenly distributed. Ensure that the mixture is fully wrapped tightly around the skewers without any exposed metal. Alternatively, lay them on a large baking tray lined with parchment paper if cooking in the oven, or foil if cooking under the grill. Shape into 20cm-long köfte. Wet your fingers with a little cold water and make indents all along the köfte for the traditional shape.\",\"step 3\",\"Gently brush each köfte with the remaining 1 tbsp oil and cook under the grill, on the top shelf for 10-12 mins, turning regularly, or cook in the oven for 16-18 mins, until crispy on the outside and juicy in the middle\"]},{\"id\":\"g2\",\"title\":\"Air Fryer Egg Rolls\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/grhn401765687086.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Ground Pork\",\"Garlic\",\"Ginger\",\"Carrots\",\"Scallions\",\"Cabbage\",\"Soy Sauce\",\"Rice Vinegar\",\"Egg Roll Wrappers\",\"Oil\",\"Duck Sauce\",\"Plum Sauce\",\"Soy Sauce\"],\"allergens\":[\"egg\",\"soy\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Alternative Pan Fry Method: If you don’t have access to an air fryer, you can make these egg rolls using a traditional pan fry method. Add enough oil to a mediu\",\"instructions\":[\"Alternative Pan Fry Method: If you don’t have access to an air fryer, you can make these egg rolls using a traditional pan fry method. Add enough oil to a medium skillet with high walls so the oil is about 1/2 inch up the side of the skillet. Heat oil on medium high heat until it reaches 350°F. Add egg rolls and fry for 3 to 4 minutes, flip, and fry for another 3 to 4 minutes until golden brown. Remove and let them drain and cool on a few paper towels.\",\"Cook the filling:\",\"In a large skillet over medium heat, add the olive oil along with the ground pork or chicken. Break apart the meat with a spatula or wooden spoon as it cooks. Cook until the meat is cooked through, 6 to 8 minutes.\",\"Add garlic, ginger, carrot, scallions, and cabbage. Continue to cook until cabbage wilts down and is soft, another 3 to 4 minutes, stirring regularly. Season the filling with soy sauce and rice wine vinegar, and take off the heat to cool. (This filling can be made in advance.)\",\"Assemble the egg rolls:\",\"Place a single egg roll wrapper on a dry surface with one point of the square facing you (like a diamond). Place about 1/4 cup of the egg roll filling mixture in the middle of the wrapper.\",\"Dip your fingers in water and run around the edges of the wrapper. Then fold the edges of the wrapper over the center and start rolling the egg roll away from you to form a tight cylinder. Place on a plate and repeat until you are out of filling. You should get at least a dozen egg rolls.\",\"Air fry the egg rolls:\",\"Place the egg rolls in the basket of your air fryer. Spray or brush them lightly with oil. Add as many as you can without stacking the egg rolls, making sure they don’t touch. Air needs to circulate around them. Brush the egg rolls lightly with oil.\",\"Place the basket in the air fryer and turn the air fryer to 350°F. Cook for 6 to 7 minutes, then flip the egg rolls, spray or brush with oil a second time on the bottom side, and cook for another 4 to 5 minutes.\"]},{\"id\":\"g3\",\"title\":\"Air fryer patatas bravas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/3m8yae1763257951.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Olive Oil\",\"Onion\",\"Garlic\",\"Paprika\",\"Tomato Puree\",\"Tinned Tomatos\",\"Basil Leaves\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nSoak the potatoes in just-boiled water for 30 mins, then drain and leave to air-dry for 5 mins. Heat the air fryer to 200C. Tip the potatoes into a bowl\",\"instructions\":[\"step 1\",\"Soak the potatoes in just-boiled water for 30 mins, then drain and leave to air-dry for 5 mins. Heat the air fryer to 200C. Tip the potatoes into a bowl and drizzle over 1 tbsp of the oil and add 1/2 tsp each of salt and freshly ground black pepper. Mix to coat the potatoes all over, then tip into the air fryer basket and cook for 20-30 mins until crisp and golden.\",\"step 2\",\"Meanwhile, heat the remaining oil in a small pan over a medium-low heat and fry the onion for 8-10 mins until softened but not golden. Stir in the garlic and cook for a minute before adding the paprika and cooking for 30 seconds more. Stir in the tomato purée, cook for 1 min, then tip in the chopped tomatoes. Cook for 5-10 mins over a medium heat until thickened slightly.\",\"step 3\",\"Once the potatoes are cooked, tip out onto a platter and pour over the tomato sauce. Sprinkle with the basil leaves, then serve.\"]},{\"id\":\"g4\",\"title\":\"Ajo blanco\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/5jdtie1763289302.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"White bread\",\"Almonds\",\"Extra Virgin Olive Oil\",\"Garlic Clove\",\"Red Wine Vinegar\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip the bread into a bowl and pour over 350ml water. Leave to soak for 10 mins.\\r\\n\\r\\nstep 2\\r\\nBlend the ingredients together with 350ml water and 1 tsp sal\",\"instructions\":[\"step 1\",\"Tip the bread into a bowl and pour over 350ml water. Leave to soak for 10 mins.\",\"step 2\",\"Blend the ingredients together with 350ml water and 1 tsp salt.\",\"step 3\",\"Let the soup cool in the fridge for 1 hr or so, then serve with a drizzle of oil and some black pepper.\"]},{\"id\":\"g5\",\"title\":\"Alfajores\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/a4kgf21763075288.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"All purpose flour\",\"Cornstarch\",\"Butter\",\"Sugar\",\"Egg Yolks\",\"Lemon Zest\",\"Dulce de leche\",\"Desiccated Coconut\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Make the Dough: Cream butter and sugar. Add egg yolks and lemon zest. Gradually mix in flour and cornstarch to form a dough. Chill for 1 hour.\\r\\nBake the Cookies\",\"instructions\":[\"Make the Dough: Cream butter and sugar. Add egg yolks and lemon zest. Gradually mix in flour and cornstarch to form a dough. Chill for 1 hour.\",\"Bake the Cookies: Roll out the dough, cut into circles, and bake at 180°C (350°F) for 12-15 minutes. Let cool.\",\"Assemble: Spread dulce de leche on one cookie, then sandwich with another. Roll the edges in coconut flakes.\",\"Pro Tips:\",\"Chill the dough before rolling it out to make it easier to handle and to prevent the cookies from spreading too much while baking.\",\"Dip the alfajores in melted chocolate and let them set on a wire rack for an extra decadent treat.\"]},{\"id\":\"g6\",\"title\":\"Algerian Bouzgene Berber Bread with Roasted Pepper Sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/se5vhk1764114880.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Pepper\",\"Tomato\",\"Olive Oil\",\"Garlic\",\"Jalapeno\",\"Salt\",\"Semolina\",\"Salt\",\"Water\",\"Olive Oil\",\"Olive Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Preheat your oven's broiler. Place red bell peppers and tomatoes on a baking sheet, and roast under the broiler for about 8 minutes, turning occasionally. This \",\"instructions\":[\"Preheat your oven's broiler. Place red bell peppers and tomatoes on a baking sheet, and roast under the broiler for about 8 minutes, turning occasionally. This should blacken the skin and help it peel off more easily. Cool, then scrape the skins off of the tomatoes and peppers, and place them in a large bowl. Remove cores and seeds from the bell peppers.\",\"Heat 1 tablespoon of olive oil in a skillet over medium heat. Add the jalapenos and garlic, and cook until tender, stirring frequently. Remove from heat, and transfer the garlic and jalapeno to the bowl with the tomatoes and red peppers. Using two sharp steak knives (one in each hand), cut up the tomatoes and peppers to a coarse and soupy consistency. Stir, and set sauce aside.\",\"Place the semolina in a large bowl, and stir in salt and 4 tablespoons of olive oil. Gradually add water while mixing and squeezing with your hand until the dough holds together without being sticky or dry, and molds easily with the hand. Divide into 6 pieces and form into balls.\",\"For each round, heat 1 tablespoon of olive oil in a large heavy skillet over medium heat. Roll out dough one round at a time, to no thicker than 1/4 inch. Fry in the hot skillet until dark brown spots appear on the surface, and they are crispy. Remove from the skillet, and wrap in a clean towel while preparing the remaining flat breads.\",\"To eat the bread and sauce, break off pieces of the bread, and scoop them into the sauce. It will slide off, but just keep reaching in!\"]},{\"id\":\"g7\",\"title\":\"Algerian Carrots\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/o2cd4r1764113576.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Carrots\",\"Olive Oil\",\"Salt\",\"Black Pepper\",\"Ground Cinnamon\",\"Ground Cumin\",\"Garlic\",\"Thyme\",\"Bay Leaf\",\"Lemon Juice\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Place a steamer insert into a saucepan, and fill with 1 1/2 cups of water, or just below the bottom of the steamer. Cover, and bring the water to a boil over hi\",\"instructions\":[\"Place a steamer insert into a saucepan, and fill with 1 1/2 cups of water, or just below the bottom of the steamer. Cover, and bring the water to a boil over high heat. Add the sliced carrots, reduce the heat to medium, and cover the pan again. Steam until tender but not mushy, 4 to 6 minutes depending on the thickness of the slices. Reserve 1/2 cup of the cooking liquid.\",\"Heat the olive oil in a skillet over medium heat. Reduce the heat to low and stir in the salt, pepper, cinnamon, cumin, garlic, and thyme. Cook the spices and garlic, stirring frequently, until fragrant, about 10 minutes. Add the 1/2 cup reserved cooking liquid and the bay leaf, cover, and simmer for 20 minutes.\",\"Stir in the carrots, tossing well to coat with the spice mixture, and cook until heated through, about 2 to 3 minutes. Sprinkle with lemon juice and remove the bay leaf before serving.\"]},{\"id\":\"g8\",\"title\":\"Algerian Flafla (Bell Pepper Salad)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tbj1bs1764118062.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Green Pepper\",\"Olive Oil\",\"Red Onions\",\"Garlic\",\"Salt\",\"Pepper\",\"Plum Tomatoes\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Preheat an oven to 450 degrees F (230 degrees C). Place the whole peppers on aluminum foil. Bake until the skin is spotted black and the peppers are soft, 30 to\",\"instructions\":[\"Preheat an oven to 450 degrees F (230 degrees C). Place the whole peppers on aluminum foil. Bake until the skin is spotted black and the peppers are soft, 30 to 45 minutes, turning the peppers once if necessary.\",\"Remove peppers from the oven and set aside to cool for 10 minutes. Peel off the skin and remove the stem and seeds. Chop the roasted peppers into half-inch pieces.\",\"Heat the olive oil in a skillet over medium heat. Stir in the onion and cook, stirring frequently, until the onion has softened and turned translucent, about 5 minutes. Add the garlic, salt, and pepper; stir in the chopped peppers and tomato. Cook over medium heat, stirring occasionally, until the tomato is soft and the mixture is well incorporated, about 5 minutes.\"]},{\"id\":\"g9\",\"title\":\"Algerian Kefta (Meatballs)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8rfd4q1764112993.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ground Beef\",\"Garlic\",\"Onion\",\"Salt\",\"Pepper\",\"Plum Tomatoes\",\"Parsley\",\"Water\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Combine ground beef with 1/2 of the minced garlic and 1 tablespoon chopped onion in a large bowl. Mix with your hands until fully incorporated. Shape meat mixtu\",\"instructions\":[\"Combine ground beef with 1/2 of the minced garlic and 1 tablespoon chopped onion in a large bowl. Mix with your hands until fully incorporated. Shape meat mixture into 1 1/2-inch oblong patties; you should have 12 to 14 meatballs.\",\"Heat a large skillet over medium-high heat. Brown patties in batches in the hot skillet until crispy on both sides and no longer pink in the center, about 10 minutes. Set meatballs aside in a rimmed serving dish.\",\"Reduce heat to medium and stir remaining chopped onion into drippings in the skillet. Season with salt and pepper. Cook, stirring constantly, until onion has softened and turned translucent, about 5 minutes. Stir in remaining garlic and cook for 30 seconds. Stir in Roma tomatoes, dried parsley, and ras el hanout. Pour in water. Cook until tomatoes are soft, about 5 minutes.\",\"Pour tomato sauce over meatballs to serve.\"]},{\"id\":\"g10\",\"title\":\"Anzac biscuits\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/q47rkb1762324620.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Porridge oats\",\"Desiccated Coconut\",\"Plain Flour\",\"Caster Sugar\",\"Butter\",\"Golden Syrup\",\"Bicarbonate Of Soda\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat oven to 180C/fan 160C/gas 4. Put the oats, coconut, flour and sugar in a bowl. Melt the butter in a small pan and stir in the golden syrup. Add the\",\"instructions\":[\"step 1\",\"Heat oven to 180C/fan 160C/gas 4. Put the oats, coconut, flour and sugar in a bowl. Melt the butter in a small pan and stir in the golden syrup. Add the bicarbonate of soda to 2 tbsp boiling water, then stir into the golden syrup and butter mixture.\",\"step 2\",\"Make a well in the middle of the dry ingredients and pour in the butter and golden syrup mixture. Stir gently to incorporate the dry ingredients.\",\"step 3\",\"Put dessertspoonfuls of the mixture on to buttered baking sheets, about 2.5cm/1in apart to allow room for spreading. Bake in batches for 8-10 mins until golden. Transfer to a wire rack to cool.\"]},{\"id\":\"g11\",\"title\":\"Apam balik\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/adxcbq1619787919.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Milk\",\"Oil\",\"Eggs\",\"Flour\",\"Baking Powder\",\"Salt\",\"Unsalted Butter\",\"Sugar\",\"Peanut Butter\"],\"allergens\":[\"egg\",\"milk\",\"peanut\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix milk, oil and egg together. Sift flour, baking powder and salt into the mixture. Stir well until all ingredients are combined evenly.\\r\\n\\r\\nSpread some batter \",\"instructions\":[\"Mix milk, oil and egg together. Sift flour, baking powder and salt into the mixture. Stir well until all ingredients are combined evenly.\",\"Spread some batter onto the pan. Spread a thin layer of batter to the side of the pan. Cover the pan for 30-60 seconds until small air bubbles appear.\",\"Add butter, cream corn, crushed peanuts and sugar onto the pancake. Fold the pancake into half once the bottom surface is browned.\",\"Cut into wedges and best eaten when it is warm.\"]},{\"id\":\"g12\",\"title\":\"Apple & Blackberry Crumble\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xvsurr1511719182.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Caster Sugar\",\"Butter\",\"Braeburn Apples\",\"Butter\",\"Demerara Sugar\",\"Blackberries\",\"Cinnamon\",\"Ice Cream\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 190C/170C fan/gas 5. Tip the flour and sugar into a large bowl. Add the butter, then rub into the flour using your fingertips to make a light bread\",\"instructions\":[\"Heat oven to 190C/170C fan/gas 5. Tip the flour and sugar into a large bowl. Add the butter, then rub into the flour using your fingertips to make a light breadcrumb texture. Do not overwork it or the crumble will become heavy. Sprinkle the mixture evenly over a baking sheet and bake for 15 mins or until lightly coloured.\",\"Meanwhile, for the compote, peel, core and cut the apples into 2cm dice. Put the butter and sugar in a medium saucepan and melt together over a medium heat. Cook for 3 mins until the mixture turns to a light caramel. Stir in the apples and cook for 3 mins. Add the blackberries and cinnamon, and cook for 3 mins more. Cover, remove from the heat, then leave for 2-3 mins to continue cooking in the warmth of the pan.\",\"To serve, spoon the warm fruit into an ovenproof gratin dish, top with the crumble mix, then reheat in the oven for 5-10 mins. Serve with vanilla ice cream.\"]},{\"id\":\"g13\",\"title\":\"Apple cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/c0gmo31766594751.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Eggs\",\"Sugar\",\"Self-raising Flour\",\"Melted Butter\",\"Vanilla Extract\",\"Ground Cinnamon\",\"Apples\",\"Salt\",\"Ground Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 180°C. (350˚F) Grease a cake pan and line it with baking paper.\\r\\nIn a large bowl, break the four eggs with the sugar and beat until they hav\",\"instructions\":[\"Preheat the oven to 180°C. (350˚F) Grease a cake pan and line it with baking paper.\",\"In a large bowl, break the four eggs with the sugar and beat until they have tripled in volume and become fluffy.\",\"Sift the self-rising baking flour and add it to your egg mixture. Fold this over, preserving as much air as possible. Add the melted (and slightly cooled) butter and mix until combined.\",\"Add cinnamon, pinch of salt and vanilla extract.\",\"Add the diced apple to the batter and gently fold them into the batter so that the apple pieces are evenly distributed. You can roll the apple pieces through some more cinnamon.\",\"Pour the batter into the prepared cake pan and smooth the top with a spatula.\",\"Place the apple slices on top of the batter and press lightly. Sprinkle optionally with some almond shavings.\",\"Bake the apple cake in the preheated oven for about 45-50 minutes, or until a wooden skewer comes out clean when inserted into the center of the cake.\",\"Remove the cake from the oven and let it cool in the mold for a few minutes. Then carefully remove the cake from the mold and let cool completely on a wire rack.\",\"Sprinkle the cooled apple cake with powdered sugar\"]},{\"id\":\"g14\",\"title\":\"Apple Frangipan Tart\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wxywrq1468235067.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"digestive biscuits\",\"butter\",\"Bramley apples\",\"Salted Butter\",\"caster sugar\",\"free-range eggs, beaten\",\"ground almonds\",\"almond extract\",\"flaked almonds\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 200C/180C Fan/Gas 6.\\r\\nPut the biscuits in a large re-sealable freezer bag and bash with a rolling pin into fine crumbs. Melt the butter in a\",\"instructions\":[\"Preheat the oven to 200C/180C Fan/Gas 6.\",\"Put the biscuits in a large re-sealable freezer bag and bash with a rolling pin into fine crumbs. Melt the butter in a small pan, then add the biscuit crumbs and stir until coated with butter. Tip into the tart tin and, using the back of a spoon, press over the base and sides of the tin to give an even layer. Chill in the fridge while you make the filling.\",\"Cream together the butter and sugar until light and fluffy. You can do this in a food processor if you have one. Process for 2-3 minutes. Mix in the eggs, then add the ground almonds and almond extract and blend until well combined.\",\"Peel the apples, and cut thin slices of apple. Do this at the last minute to prevent the apple going brown. Arrange the slices over the biscuit base. Spread the frangipane filling evenly on top. Level the surface and sprinkle with the flaked almonds.\",\"Bake for 20-25 minutes until golden-brown and set.\",\"Remove from the oven and leave to cool for 15 minutes. Remove the sides of the tin. An easy way to do this is to stand the tin on a can of beans and push down gently on the edges of the tin.\",\"Transfer the tart, with the tin base attached, to a serving plate. Serve warm with cream, crème fraiche or ice cream.\"]},{\"id\":\"g15\",\"title\":\"Apricot & Turkish delight mess\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/p277uc1764109195.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mascarpone\",\"Greek Yogurt\",\"Icing Sugar\",\"Orange Blossom Water\",\"Meringue Nests\",\"Apricot\",\"Turkish Delight\",\"Almonds\",\"Mint\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPlace the mascarpone, yogurt, sugar and orange flower water into a large bowl and whisk until thickened. Fold the remaining ingredients through, then di\",\"instructions\":[\"step 1\",\"Place the mascarpone, yogurt, sugar and orange flower water into a large bowl and whisk until thickened. Fold the remaining ingredients through, then divide the mix between 2 dessert glasses or bowls and decorate with extra mint, if you like.\"]},{\"id\":\"g16\",\"title\":\"Arepa Pabellón\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/13fg4j1764441982.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Corn Arepa Filled With Mozarella Cheese\",\"Fried Ripe Bananas\",\"Black Beans\",\"Pico De Gallo Sauce\",\"Shredded Meat\",\"Tomato\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Prepare the meat in a skillet and add salt and pepper to taste, heat the beans over medium heat in a pan, fry or grill the ripe plantains as indicated on its pa\",\"instructions\":[\"Prepare the meat in a skillet and add salt and pepper to taste, heat the beans over medium heat in a pan, fry or grill the ripe plantains as indicated on its package and cut the tomato into small cubes. Reserve these ingredients until filling.\",\"Preheat the grill or pan and grill the arepa, putting it once on each side until they are golden brown.\",\"With the help of a knife, open it by the edge through the middle, creating a space to fill it with the ripe plantain, the beans, meat and chopped tomato.\",\"Serve with a little pico de gallo or guacamole dip sauce.\"]},{\"id\":\"g17\",\"title\":\"Arepa pelua\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/jgl9qq1764437635.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Onion\",\"Red Pepper\",\"Garlic\",\"Cumin\",\"Oregano\",\"Paprika\",\"Beef Stock\",\"Water\",\"Salt\",\"Cheese\",\"Extra Virgin Olive Oil\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cook the meat: Place the flank steak in a pot with broth or water and salt. Cook over low heat for about 2 hours, until tender and easy to shred.\\r\\nShred the mea\",\"instructions\":[\"Cook the meat: Place the flank steak in a pot with broth or water and salt. Cook over low heat for about 2 hours, until tender and easy to shred.\",\"Shred the meat: Once cooked, drain and shred the meat using two forks.\",\"Prepare the vegetables: Sauté chopped onion, bell pepper, and garlic in a little oil. Add cumin, oregano, paprika, and salt. Stir in the meat and cook for a few minutes until the flavors are well combined.\",\"Make the dough: In a bowl, mix the cornmeal with warm water and salt until a soft dough forms. Let it rest for 5 minutes.\",\"Form the arepas: Divide the dough into 6 portions, shape into balls, and flatten into thick discs.\",\"Cook: Cook the arepas on a griddle or skillet over medium heat for 2–3 minutes on each side until golden. You can then bake them for a few minutes if you prefer them crispier.\",\"Fill: Slice the arepas open on one side, fill with the hot shredded beef, and top with grated cheese.\"]},{\"id\":\"g18\",\"title\":\"Arroz al horno (baked rice)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qt4i0n1763256454.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Extra Virgin Olive Oil\",\"Pork belly slices\",\"Black Pudding\",\"Bacon lardon\",\"Onion\",\"Red Pepper\",\"Plum Tomatoes\",\"Garlic Clove\",\"Paprika\",\"Chilli Flakes\",\"Dried white beans\",\"Chicken Stock\",\"Thyme\",\"Paella Rice\",\"Lemon Juice\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/180C/gas 6. Heat half the oil in a deep frying or sauté pan (or shallow casserole dish) measuring around 30cm in diameter. Over a high\",\"instructions\":[\"step 1\",\"Heat oven to 200C/180C/gas 6. Heat half the oil in a deep frying or sauté pan (or shallow casserole dish) measuring around 30cm in diameter. Over a high heat, colour the pork belly slices on each side in several batches, then transfer to a bowl. Add the remaining oil to the pan and lower the heat to medium, then add the black pudding and bacon and fry all over for several mins. Remove with a slotted spoon. Fry the onion and peppers for around 10 mins until soft and pale gold, then add the tomato and cook until soft. Add the garlic, smoked paprika and chilli flakes and cook for another 2 mins, then put the pork, black pudding and bacon back in the pan. Add the beans, stock and whichever herb you're using, and bring everything to the boil.\",\"step 2\",\"Sprinkle the rice around the pork belly, pushing it underneath the stock. Let the stock come to the boil again, season well, then transfer to the oven (leave it uncovered). Cook for 20 mins without stirring, then check to see how the rice is doing. The rice should be tender and the stock absorbed. If it’s not ready, put back in the oven for another 5 mins, then check again. Taste for seasoning.\",\"step 3\",\"Squeeze lemon juice over the top and drizzle over some extra virgin olive oil just before serving, if you like.\"]},{\"id\":\"g19\",\"title\":\"Arroz con gambas y calamar\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/jc6oub1763196663.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Raw King Prawns\",\"Olive Oil\",\"Onion\",\"Bay Leaf\",\"Saffron\",\"Paella Rice\",\"Tomato Puree\",\"White Wine\",\"Seafood stock\",\"Squid\"],\"allergens\":[\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPeel and devein most of the prawns (a fishmonger should be able to do this for you), keeping a few whole for decoration, if you like. Heat the olive oil\",\"instructions\":[\"step 1\",\"Peel and devein most of the prawns (a fishmonger should be able to do this for you), keeping a few whole for decoration, if you like. Heat the olive oil in a large frying pan or shallow flameproof casserole over a medium-low heat and fry the onion for 5 mins until softened. Add the bay leaf, saffron, rice and tomato purée, and cook for 1-2 mins more, stirring.\",\"step 2\",\"Pour in the wine and bubble for 1-2 mins, then pour in the seafood stock and 150ml water. Cook for 5 mins, then add the squid, season well and stir to combine. Bring to the boil, then cover and reduce the heat to a gentle simmer. Cook for 12 mins more, adding a little more water if the mixture starts to look dry.\",\"step 3\",\"Uncover the pan and stir through the peeled prawns, then arrange any whole prawns on top of the rice mixture. Cover again and simmer for a further 5-6 mins until the prawns are pink and cooked through. Leave to stand for a couple of minutes before serving from the pan.\"]},{\"id\":\"g20\",\"title\":\"Asado\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kgfh3q1763075438.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mixed Beef Cuts\",\"Chorizo\",\"Morcilla\",\"Salt\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Prepare the Fire: Start a wood fire in your grill and let it burn down to coals.\\r\\nSeason the Meat: Generously salt the beef cuts.\\r\\nGrill the Meat: Place the bee\",\"instructions\":[\"Prepare the Fire: Start a wood fire in your grill and let it burn down to coals.\",\"Season the Meat: Generously salt the beef cuts.\",\"Grill the Meat: Place the beef on the grill, starting with the thickest cuts farthest from the coals. Add chorizo and morcilla after the beef has been cooking for a while.\",\"Cook to Perfection: Cook the meat, turning occasionally, until it reaches your desired doneness. Typically, ribs may take up to 2 hours; thinner cuts will cook faster.\",\"Rest and Serve: Let the meat rest for about 10 minutes before slicing. Serve with chimichurri sauce and grilled vegetables.\",\"Pro Tips:\",\"Use a mix of wood and charcoal for a consistent heat source. Wood adds flavor, while charcoal maintains temperature.\",\"Season the meat just before grilling to ensure it retains its moisture and flavor.\",\"Serving Suggestions:\",\"Serve with a side of chimichurri sauce, a fresh tomato salad, and crusty bread. Pair with a robust Malbec wine to complement the rich flavors of the meat.\"]},{\"id\":\"g21\",\"title\":\"Aubergine & hummus grills\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/zub3s91764110535.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Vegetable Oil\",\"Bread\",\"Hummus\",\"Walnuts\",\"Parsley\",\"Cherry Tomatoes\",\"Lemon\",\"Extra Virgin Olive Oil\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nLay the aubergine out in one layer on a large baking sheet. Brush sparingly with vegetable oil, then season generously. Grill for 15 mins, turning twice\",\"instructions\":[\"step 1\",\"Lay the aubergine out in one layer on a large baking sheet. Brush sparingly with vegetable oil, then season generously. Grill for 15 mins, turning twice and brushing with oil until the slices are softened and cooked through. Meanwhile, whizz the bread into crumbs. Add 2 tsp oil and whizz briefly again, to coat.\",\"step 2\",\"Spread a couple of tsps of hummus on top of each slice of aubergine. Tip the breadcrumbs onto a large plate, then press the hummus side of the aubergines into the crumbs to coat. Grill again, crumb-side up, for about 3 mins until golden.\",\"step 3\",\"Toss the walnuts, parsley and cherry tomatoes in a bowl, season, then add the lemon juice and olive oil and toss again. Serve the grills with the salad, a dollop more hummus and some pitta bread.\"]},{\"id\":\"g22\",\"title\":\"Aubergine couscous salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/02s6gc1763799560.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Olive Oil\",\"Couscous\",\"Vegetable Stock\",\"Cherry Tomatoes\",\"Mint\",\"Goats Cheese\",\"Lemon\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat grill to high. Put the aubergine on a baking sheet, brush with oil and season. Grill for about 15 mins, turning and brushing with more oil halfway,\",\"instructions\":[\"step 1\",\"Heat grill to high. Put the aubergine on a baking sheet, brush with oil and season. Grill for about 15 mins, turning and brushing with more oil halfway, until browned and softened.\",\"step 2\",\"Meanwhile, tip the couscous into a large bowl, pour over the stock, then cover and leave for 10 mins. Mix the tomatoes, mint, goat’s cheese and remaining oil together. Fluff the couscous up with a fork, then stir in the aubergines, tomato mixture and lemon juice.\"]},{\"id\":\"g23\",\"title\":\"Aussie Burgers\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/44bzep1761848278.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lean Minced Steak\",\"Cooked Beetroot\",\"Naan Bread\",\"Rocket\",\"Soured cream and chive dip\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nMake the burgers: Tip the meat into a bowl and sprinkle over 1 tsp salt and a good grinding of black pepper.Work with wet hands to mix in the seasoning.\",\"instructions\":[\"step 1\",\"Make the burgers: Tip the meat into a bowl and sprinkle over 1 tsp salt and a good grinding of black pepper.Work with wet hands to mix in the seasoning. Divide into four with your hands and shape into burgers. (It can be frozen at this stage.)\",\"step 2\",\"Sort out your ingredients: Slice the beetroot and split the naan breads.\",\"step 3\",\"Toast the naans: Heat a griddle pan or barbecue. Griddle the naans on both sides until lightly toasted and set aside. Add the burgers to the grill or barbecue and cook for 2-3 minutes, then turn and cook the other side for a further 2-3 minutes.\",\"step 4\",\"Assemble the dish: Set half a toasted naan on each serving plate and put a pile of rocket on each. Top with a burger, then a few slices of beetroot and a dollop of soured cream. Sprinkle with salt and freshly ground black pepper and serve immediately with a big green salad and chips. A glass of red wine wouldn’t go amiss, either.\"]},{\"id\":\"g24\",\"title\":\"Authentic Norwegian Kransekake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yk78uc1763075719.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Almonds\",\"Egg White\",\"Powdered Sugar\",\"Powdered Sugar\",\"Egg White\",\"Lemon Juice\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Grind almonds in an almond grinder or food processor.\\r\\n▢\\r\\nMix almonds and powdered sugar together in a large mixing bowl. Add three of the egg whites and knead \",\"instructions\":[\"Grind almonds in an almond grinder or food processor.\",\"▢\",\"Mix almonds and powdered sugar together in a large mixing bowl. Add three of the egg whites and knead the dough together with your hands until it comes together in a ball. Wrap in cling film and leave in the fridge for at least an hour, preferably until the next day.\",\"▢\",\"Grease the kransekake forms thoroughly and coat with semolina, flour, or bread crumbs.\",\"▢\",\"Preheat oven to 210°C (410°F) top and bottom heat. Divide the dough into six sections.\",\"▢\",\"Slowly add the remaining egg white to the dough and knead it until you can roll it into long sausages about as thick as your index finger. Fill the forms with the dough sausages, pinching the ends together to make rings.\",\"▢\"]},{\"id\":\"g25\",\"title\":\"Avocado dip with new potatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/flrajf1762341295.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Avocado\",\"Natural Yoghurt\",\"Lime\",\"Lemon\",\"Baby New Potatoes\",\"Olive Oil\",\"Hot Chilli Powder\",\"Cumin Seeds\",\"Tortillas\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nWhizz half the avocado flesh with the yogurt, lime and lemon juice and seasoning. Dice the remaining avocado, then gently stir into the whizzed mix with\",\"instructions\":[\"step 1\",\"Whizz half the avocado flesh with the yogurt, lime and lemon juice and seasoning. Dice the remaining avocado, then gently stir into the whizzed mix with most of the lime zest. Cover, then chill until ready to serve.\",\"step 2\",\"Boil potatoes for 6 mins, then drain well and toss with olive oil, chilli powder and cumin seeds. Now set aside until half an hour before your guests arrive.\",\"step 3\",\"Heat oven to 200C/180C fan/gas 6, then roast potatoes for about 30 mins, shaking the tray halfway, until golden and tender. Transfer the dip to one or two bowls, scatter with the remaining lime zest and serve with the hot potatoes, and tortilla chips for dipping.\"]},{\"id\":\"g26\",\"title\":\"Ayam Percik\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/020z181619788503.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Challots\",\"Ginger\",\"Garlic Clove\",\"Cayenne Pepper\",\"Turmeric\",\"Cumin\",\"Coriander\",\"Fennel\",\"Tamarind Paste\",\"Coconut Milk\",\"Sugar\",\"Water\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a blender, add the ingredients for the spice paste and blend until smooth.\\r\\nOver medium heat, pour the spice paste in a skillet or pan and fry for 10 minutes\",\"instructions\":[\"In a blender, add the ingredients for the spice paste and blend until smooth.\",\"Over medium heat, pour the spice paste in a skillet or pan and fry for 10 minutes until fragrant. Add water or oil 1 tablespoon at a time if the paste becomes too dry. Don't burn the paste. Lower the fire slightly if needed.\",\"Add the cloves, cardamom, tamarind pulp, coconut milk, water, sugar and salt. Turn the heat up and bring the mixture to boil. Turn the heat to medium low and simmer for 10 minutes. Stir occasionally. It will reduce slightly. This is the marinade/sauce, so taste and adjust seasoning if necessary. Don't worry if it's slightly bitter. It will go away when roasting.\",\"When the marinade/sauce has cooled, pour everything over the chicken and marinate overnight to two days.\",\"Preheat the oven to 425 F.\",\"Remove the chicken from the marinade. Spoon the marinade onto a greased (or aluminum lined) baking sheet. Lay the chicken on top of the sauce (make sure the chicken covers the sauce and the sauce isn't exposed or it'll burn) and spread the remaining marinade on the chicken. Roast for 35-45 minutes or until internal temp of the thickest part of chicken is at least 175 F.\",\"Let chicken rest for 5 minutes. Brush the chicken with some of the oil. Serve chicken with the sauce over steamed rice (or coconut rice).\"]},{\"id\":\"g27\",\"title\":\"Baba Ghanoush\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/dlmh401760524897.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg Plants\",\"Garlic\",\"Kosher Salt\",\"Lemon\",\"Tahini\",\"Extra Virgin Olive Oil\",\"Greek Yogurt\",\"Cayenne Pepper\",\"Mint\",\"Parsley\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat an outdoor grill for medium-high heat and lightly oil the grate. Prick the surface of the skin of eggplants several times with the tip of a knife.\\r\\n\\r\\nPl\",\"instructions\":[\"Preheat an outdoor grill for medium-high heat and lightly oil the grate. Prick the surface of the skin of eggplants several times with the tip of a knife.\",\"Place eggplants directly on grill. Turn frequently with tongs while skin chars. Cook until eggplants have collapsed and are very soft, 25 to 30 minutes. Transfer to a bowl and cover tightly with aluminum foil and allow to cool, about 15 minutes.\",\"When eggplants are cool enough to handle, split them in half and scrape flesh into a colander placed over a bowl. Drain 5 or 10 minutes.\",\"Transfer eggplant to mixing bowl. Add crushed garlic and salt; mash until creamy but with a little texture, about 5 minutes. Whisk in lemon juice, tahini, olive oil, and cayenne pepper. Stir in yogurt.\",\"Cover bowl with plastic wrap and refrigerate until completely chilled. Stir in mint and parsley, and taste to adjust seasonings before serving.\"]},{\"id\":\"g28\",\"title\":\"Baingan Bharta\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/urtpqw1487341253.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Onion\",\"Tomatoes\",\"Garlic\",\"Green Chilli\",\"Red Chilli Powder\",\"Oil\",\"Coriander Leaves\",\"salt\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Rinse the baingan (eggplant or aubergine) in water. Pat dry with a kitchen napkin. Apply some oil all over and\\r\\nkeep it for roasting on an open flame. You can a\",\"instructions\":[\"Rinse the baingan (eggplant or aubergine) in water. Pat dry with a kitchen napkin. Apply some oil all over and\",\"keep it for roasting on an open flame. You can also grill the baingan or roast in the oven. But then you won't get\",\"the smoky flavor of the baingan. Keep the eggplant turning after a 2 to 3 minutes on the flame, so that its evenly\",\"cooked. You could also embed some garlic cloves in the baingan and then roast it.\",\"2. Roast the aubergine till its completely cooked and tender. With a knife check the doneness. The knife should slid\",\"easily in aubergines without any resistance. Remove the baingan and immerse in a bowl of water till it cools\",\"down.\",\"3. You can also do the dhungar technique of infusing charcoal smoky flavor in the baingan. This is an optional step.\",\"Use natural charcoal for this method. Heat a small piece of charcoal on flame till it becomes smoking hot and red.\",\"4. Make small cuts on the baingan with a knife. Place the red hot charcoal in the same plate where the roasted\"]},{\"id\":\"g29\",\"title\":\"Baked salmon with fennel & tomatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1548772327.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Fennel\",\"Parsley\",\"Lemon\",\"Cherry Tomatoes\",\"Olive Oil\",\"Salmon\",\"Black Olives\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 180C/fan 160C/gas 4. Trim the fronds from the fennel and set aside. Cut the fennel bulbs in half, then cut each half into 3 wedges. Cook in boiling\",\"instructions\":[\"Heat oven to 180C/fan 160C/gas 4. Trim the fronds from the fennel and set aside. Cut the fennel bulbs in half, then cut each half into 3 wedges. Cook in boiling salted water for 10 mins, then drain well. Chop the fennel fronds roughly, then mix with the parsley and lemon zest.\",\"Spread the drained fennel over a shallow ovenproof dish, then add the tomatoes. Drizzle with olive oil, then bake for 10 mins. Nestle the salmon among the veg, sprinkle with lemon juice, then bake 15 mins more until the fish is just cooked. Scatter over the parsley and serve.\"]},{\"id\":\"g30\",\"title\":\"Bakewell tart\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wyrqqq1468233628.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"plain flour\",\"chilled butter\",\"cold water\",\"raspberry jam\",\"butter\",\"caster sugar\",\"ground almonds\",\"free-range egg, beaten\",\"almond extract\",\"flaked almonds\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To make the pastry, measure the flour into a bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs. Add the water, mixing\",\"instructions\":[\"To make the pastry, measure the flour into a bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs. Add the water, mixing to form a soft dough.\",\"Roll out the dough on a lightly floured work surface and use to line a 20cm/8in flan tin. Leave in the fridge to chill for 30 minutes.\",\"Preheat the oven to 200C/400F/Gas 6 (180C fan).\",\"Line the pastry case with foil and fill with baking beans. Bake blind for about 15 minutes, then remove the beans and foil and cook for a further five minutes to dry out the base.\",\"For the filing, spread the base of the flan generously with raspberry jam.\",\"Melt the butter in a pan, take off the heat and then stir in the sugar. Add ground almonds, egg and almond extract. Pour into the flan tin and sprinkle over the flaked almonds.\",\"Bake for about 35 minutes. If the almonds seem to be browning too quickly, cover the tart loosely with foil to prevent them burning.\"]},{\"id\":\"g31\",\"title\":\"Baklava with spiced nuts, ricotta & chocolate\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ytme8t1764111401.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sugar\",\"Lemon Juice\",\"Walnuts\",\"Pecan Nuts\",\"Almonds\",\"Ground Cinnamon\",\"Ground Cardomom\",\"Ricotta\",\"Lemon\",\"Orange\",\"Vanilla Bean Paste\",\"Unsalted Butter\",\"Filo Pastry\",\"Ground Pistachios\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nFirst, make the syrup. Tip the sugar into a large saucepan with 650ml water. Stir over a low heat until the sugar has dissolved, then turn up the heat a\",\"instructions\":[\"step 1\",\"First, make the syrup. Tip the sugar into a large saucepan with 650ml water. Stir over a low heat until the sugar has dissolved, then turn up the heat and bring to the boil. Reduce the heat to a simmer and cook for 15 mins, then squeeze in a few drops of lemon juice and simmer for a further 5 mins. Remove from the heat and leave to cool. Meanwhile, for assembling the baklava later, melt the butter in a small pan over a low heat for 5 mins, skimming and discarding any froth that rises to the surface.\",\"step 2\",\"For the filling, crush all of the nuts in a pestle and mortar, or blitz in a food processor – you want a mixture of finely ground nuts with a few chunky pieces. Tip into a bowl, stir through the spices and set aside.\",\"step 3\",\"In a separate bowl, mix the ricotta with the lemon and orange zests and vanilla. Heat the oven to 180C/160C fan/gas 4. Brush the bottom of a large baking tray (about 35 x 47cm) with some of the melted butter. Working with one sheet of filo at a time (covering the rest with a damp tea towel to prevent it drying out), lay the sheet out on a board so one of the short ends is facing you. Sprinkle 30g of the nut mixture evenly over the whole sheet, then spoon 1 tbsp of the ricotta mixture across the end closest to you. Fold this end over to enclose the filling, then lay a long, thin skewer next to the folded edge and roll the pastry around it to create a long roll. When it’s fully rolled up, it should be roughly the thickness of a chipolata sausage. While holding one end of the rolling pin or skewer, gently scrunch the filo roll like an accordion and carefully push it off the skewer and onto the prepared tray. Repeat with the rest of the filo and fillings – you should get about 12 rolls. Cut each roll into four to make 48 large baklava, or eight to make 96 mini.\",\"step 4\",\"Brush with the remaining melted butter. Bake for 20-25 mins until evenly golden, turning the tray around halfway through. While still hot, immediately pour over 5-6 ladlefuls of the syrup. You should hear the syrup sizzle as it hits the hot baklava. Set aside to cool and absorb.\",\"step 5\",\"Melt the dark chocolate in a heatproof bowl set over a pan of simmering water, ensuring the bowl doesn’t touch the water, or in the microwave in short bursts. Drizzle this over the cooled baklava and sprinkle with the ground pistachios.\"]},{\"id\":\"g32\",\"title\":\"Banana Pancakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sywswr1511383814.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Banana\",\"Eggs\",\"Baking Powder\",\"Vanilla Extract\",\"Oil\",\"Pecan Nuts\",\"Raspberries\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a bowl, mash the banana with a fork until it resembles a thick purée. Stir in the eggs, baking powder and vanilla.\\r\\nHeat a large non-stick frying pan or panc\",\"instructions\":[\"In a bowl, mash the banana with a fork until it resembles a thick purée. Stir in the eggs, baking powder and vanilla.\",\"Heat a large non-stick frying pan or pancake pan over a medium heat and brush with half the oil. Using half the batter, spoon two pancakes into the pan, cook for 1-2 mins each side, then tip onto a plate. Repeat the process with the remaining oil and batter. Top the pancakes with the pecans and raspberries.\"]},{\"id\":\"g33\",\"title\":\"Bang bang prawn salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4xcfai1763765676.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Noodles\",\"Peanut Butter\",\"Coconut Milk\",\"sweet chilli sauce\",\"Spring Onions\",\"Cucumber\",\"Bean Sprouts\",\"Prawns\"],\"allergens\":[\"milk\",\"peanut\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nCook the noodles following pack instructions, then rinse under cold water and drain thoroughly. In a small saucepan melt together the peanut butter, coc\",\"instructions\":[\"step 1\",\"Cook the noodles following pack instructions, then rinse under cold water and drain thoroughly. In a small saucepan melt together the peanut butter, coconut milk, sweet chilli sauce and half the spring onions, adding 1-2 tbsp of water to loosen the mixture to a drizzling consistency.\",\"step 2\",\"Mix the noodles, cucumber and beansprouts in a serving dish. Top with the prawns, drizzle over the peanut sauce and scatter over the remaining spring onions.\"]},{\"id\":\"g34\",\"title\":\"Barbecue pork buns\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tzsy461763769901.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sugar\",\"White Bread Mix\",\"Sunflower Oil\",\"Bacon\",\"Ginger\",\"Garlic\",\"Soy Sauce\",\"Clear Honey\",\"Tomato Puree\",\"Egg\"],\"allergens\":[\"egg\",\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oven to 200C/fan 180C/gas. Mix the sugar into the bread mix in a large bowl, then add water as instructed on the pack. Bring the dough together\",\"instructions\":[\"step 1\",\"Heat the oven to 200C/fan 180C/gas. Mix the sugar into the bread mix in a large bowl, then add water as instructed on the pack. Bring the dough together with a wooden spoon, then knead on a lightly floured surface for 5 mins until smooth. Put into a large bowl, cover with oiled cling film then leave in a warm place until doubled in size.\",\"step 2\",\"Meanwhile, heat the oil in a pan, then fry the bacon until crisp, about 5 mins. Add the ginger and garlic and fry for 1 min until soft, then tip in the soy, honey and tomato purée and stir well. Can be made up to 3 days ahead.\",\"step 3\",\"Turn out the dough and knead briefly, then pull into 12 even-sized balls. Flatten with your hands, then put a teaspoon-size blob of the filling in the middle. Draw the dough up and pinch it closed like a purse, then turn the bun over and sit it on a large baking sheet. Cover with oiled cling film and leave to rise for about 30 mins until the dough feels pillowy. Brush with egg and bake for 20 mins until golden. Serve warm with dipping sauce. Can be frozen after second rise for up to 1 month or baked up to a day ahead and re-warmed.\"]},{\"id\":\"g35\",\"title\":\"Barramundi with Moroccan spices\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4o4wh11761848573.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"barramundi\",\"Ground Cumin\",\"Coriander\",\"Paprika\",\"Chili Powder\",\"Garlic Clove\",\"Lemon\",\"Olive Oil\",\"Coriander\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip all the dressing ingredients into a food processor with a pinch of salt and blitz to a dressing. Slash the fish three times on each side, coat with \",\"instructions\":[\"step 1\",\"Tip all the dressing ingredients into a food processor with a pinch of salt and blitz to a dressing. Slash the fish three times on each side, coat with half of the dressing, then set aside to marinate for about 30 mins.\",\"step 2\",\"Heat oven to 220C/fan 200C/gas 7. Place the fish on a roasting tray, then cook in the oven for 20 mins until the flesh is firm and the eyes have turned white. Serve the fish with the rest of the dressing and steamed couscous or rice.\",\"step 3\",\"KNOW HOW: HOW TO COOK IT: Cooking barramundi on the bone, as we have done here, has its advantages – it will stay more moist during cooking, and some would say that the flavour is enhanced, too. If you want to take out the bones they are easy to locate and less likely to be lodged in the fillet if the fish is cooked whole. Fillets can be simply pan-fried or grilled. If you like trout, you will really enjoy the flavour of barramundi, which lends itself to similar ingredients and cooking methods – citrus flavours are particularly good, as are garlic and wild mushrooms. Simply roasting the fish with some fresh herbs, olive oil and seasoning is delicious, and in the summer months you could barbecue it, too. One thing that you mustn’t miss are the cheeks or ‘pearls’ of the fish, these are simply lovely, moist and really sweet – well worth leaving the head on for!\"]},{\"id\":\"g36\",\"title\":\"Battenberg Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ywwrsp1511720277.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Caster Sugar\",\"Self-raising Flour\",\"Almonds\",\"Baking Powder\",\"Eggs\",\"Vanilla Extract\",\"Almond Extract\",\"Butter\",\"Caster Sugar\",\"Self-raising Flour\",\"Almonds\",\"Baking Powder\",\"Eggs\",\"Vanilla Extract\",\"Almond Extract\",\"Pink Food Colouring\",\"Apricot\",\"Marzipan\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 180C/160C fan/gas 4 and line the base and sides of a 20cm square tin with baking parchment (the easiest way is to cross 2 x 20cm-long strips over t\",\"instructions\":[\"Heat oven to 180C/160C fan/gas 4 and line the base and sides of a 20cm square tin with baking parchment (the easiest way is to cross 2 x 20cm-long strips over the base). To make the almond sponge, put the butter, sugar, flour, ground almonds, baking powder, eggs, vanilla and almond extract in a large bowl. Beat with an electric whisk until the mix comes together smoothly. Scrape into the tin, spreading to the corners, and bake for 25-30 mins – when you poke in a skewer, it should come out clean. Cool in the tin for 10 mins, then transfer to a wire rack to finish cooling while you make the second sponge.\",\"For the pink sponge, line the tin as above. Mix all the ingredients together as above, but don’t add the almond extract. Fold in some pink food colouring. Then scrape it all into the tin and bake as before. Cool.\",\"To assemble, heat the jam in a small pan until runny, then sieve. Barely trim two opposite edges from the almond sponge, then well trim a third edge. Roughly measure the height of the sponge, then cutting from the well-trimmed edge, use a ruler to help you cut 4 slices each the same width as the sponge height. Discard or nibble leftover sponge. Repeat with pink cake.\",\"Take 2 x almond slices and 2 x pink slices and trim so they are all the same length. Roll out one marzipan block on a surface lightly dusted with icing sugar to just over 20cm wide, then keep rolling lengthways until the marzipan is roughly 0.5cm thick. Brush with apricot jam, then lay a pink and an almond slice side by side at one end of the marzipan, brushing jam in between to stick sponges, and leaving 4cm clear marzipan at the end. Brush more jam on top of the sponges, then sandwich remaining 2 slices on top, alternating colours to give a checkerboard effect. Trim the marzipan to the length of the cakes.\",\"Carefully lift up the marzipan and smooth over the cake with your hands, but leave a small marzipan fold along the bottom edge before you stick it to the first side. Trim opposite side to match size of fold, then crimp edges using fingers and thumb (or, more simply, press with prongs of fork). If you like, mark the 10 slices using the prongs of a fork.\",\"Assemble second Battenberg and keep in an airtight box or well wrapped in cling film for up to 3 days. Can be frozen for up to a month.\"]},{\"id\":\"g37\",\"title\":\"BBQ Pork Sloppy Joes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/atd5sh1583188467.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Red Onions\",\"Garlic\",\"Lime\",\"Bread\",\"Pork\",\"Barbeque Sauce\",\"Hotsauce\",\"Tomato Ketchup\",\"Sugar\",\"Vegetable Oil\",\"Salt\",\"Pepper\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"1\\r\\n\\r\\nPreheat oven to 450 degrees. Wash and dry all produce. Cut sweet potatoes into ½-inch-thick wedges. Toss on a baking sheet with a drizzle of oil, salt, and\",\"instructions\":[\"1\",\"Preheat oven to 450 degrees. Wash and dry all produce. Cut sweet potatoes into ½-inch-thick wedges. Toss on a baking sheet with a drizzle of oil, salt, and pepper. Roast until browned and tender, 20-25 minutes.\",\"2\",\"Meanwhile, halve and peel onion. Slice as thinly as possible until you have ¼ cup (½ cup for 4 servings); finely chop remaining onion. Peel and finely chop garlic. Halve lime; squeeze juice into a small bowl. Halve buns. Add 1 TBSP butter (2 TBSP for 4) to a separate small microwave-safe bowl; microwave until melted, 30 seconds. Brush onto cut sides of buns.\",\"3\",\"To bowl with lime juice, add sliced onion, ¼ tsp sugar (½ tsp for 4 servings), and a pinch of salt. Stir to combine; set aside to quick-pickle.\",\"4\",\"Heat a drizzle of oil in a large pan over medium-high heat. Add chopped onion and season with salt and pepper. Cook, stirring, until softened, 4-5 minutes. Add garlic and cook until fragrant, 30 seconds more. Add pork and season with salt and pepper. Cook, breaking up meat into pieces, until browned and cooked through, 4-6 minutes.\",\"5\",\"While pork cooks, in a third small bowl, combine BBQ sauce, pickling liquid from onion, 3 TBSP ketchup (6 TBSP for 4 servings), ½ tsp sugar (1 tsp for 4), and ¼ cup water (⅓ cup for 4). Once pork is cooked through, add BBQ sauce mixture to pan. Cook, stirring, until sauce is thickened, 2-3 minutes. Taste and season with salt and pepper.\"]},{\"id\":\"g38\",\"title\":\"Bean & Sausage Hotpot\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vxuyrx1511302687.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sausages\",\"Tomato Sauce\",\"Butter Beans\",\"Black Treacle\",\"English Mustard\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"In a large casserole, fry the sausages until brown all over – about 10 mins.\\r\\n\\r\\nAdd the tomato sauce, stirring well, then stir in the beans, treacle or sugar an\",\"instructions\":[\"In a large casserole, fry the sausages until brown all over – about 10 mins.\",\"Add the tomato sauce, stirring well, then stir in the beans, treacle or sugar and mustard. Bring to the simmer, cover and cook for 30 mins. Great served with crusty bread or rice.\"]},{\"id\":\"g39\",\"title\":\"BeaverTails\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ryppsv1511815505.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Yeast\",\"Sugar\",\"Milk\",\"Butter\",\"Eggs\",\"Salt\",\"Flour\",\"Oil\",\"Lemon\",\"Sugar\",\"Cinnamon\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In the bowl of a stand mixer, add warm water, a big pinch of sugar and yeast. Allow to sit until frothy.\\r\\nInto the same bowl, add 1/2 cup sugar, warm milk, melt\",\"instructions\":[\"In the bowl of a stand mixer, add warm water, a big pinch of sugar and yeast. Allow to sit until frothy.\",\"Into the same bowl, add 1/2 cup sugar, warm milk, melted butter, eggs and salt, and whisk until combined.\",\"Place a dough hook on the mixer, add the flour with the machine on, until a smooth but slightly sticky dough forms.\",\"Place dough in a bowl, cover with plastic wrap, and allow to proof for 1 1/2 hours.\",\"Cut dough into 12 pieces, and roll out into long oval-like shapes about 1/4 inch thick that resemble a beaver’s tail.\",\"In a large, deep pot, heat oil to 350 degrees. Gently place beavertail dough into hot oil and cook for 30 to 45 seconds on each side until golden brown.\",\"Drain on paper towels, and garnish as desired. Toss in cinnamon sugar, in white sugar with a squeeze of lemon, or with a generous slathering of Nutella and a handful of toasted almonds. Enjoy!\"]},{\"id\":\"g40\",\"title\":\"Beef and Broccoli Stir-Fry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/m0p0j81765568742.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Soy Sauce\",\"Dry sherry\",\"Cornstarch\",\"Black Pepper\",\"Sirloin steak\",\"Oyster Sauce\",\"Dry sherry\",\"Soy Sauce\",\"Chicken Stock\",\"Broccoli\",\"High Heat Cooking Oil\",\"Garlic\",\"Cornstarch\",\"Water\"],\"allergens\":[\"soy\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Marinate the beef:\\r\\nStir together the beef marinade ingredients (1 teaspoon soy sauce, 1 teaspoon Chinese rice wine, 1/2 teaspoon cornstarch, 1/8 teaspoon black\",\"instructions\":[\"Marinate the beef:\",\"Stir together the beef marinade ingredients (1 teaspoon soy sauce, 1 teaspoon Chinese rice wine, 1/2 teaspoon cornstarch, 1/8 teaspoon black pepper) in a medium bowl.\",\"Add the beef slices and stir until coated. Let stand for 10 minutes.\",\"Prepare the sauce:\",\"Stir together the sauce ingredients (2 tablespoons oyster sauce, 1 teaspoon Chinese rice wine, 1 teaspoon soy sauce, 1/4 cup chicken broth) in a small bowl. Set aside.\",\"Blanch or steam the broccoli:\",\"Bring a pot of water to a boil. Add the broccoli and cook until crisp-tender, about 2 minutes. Drain thoroughly.\",\"Stir-fry the beef:\",\"Heat a large frying pan or wok over high heat until a bead of water sizzles and instantly evaporates upon contact. Add the cooking oil and swirl to coat.\",\"Add the beef and immediately spread it out all over the surface of the wok or pan in a single layer (preferably not touching).\"]},{\"id\":\"g41\",\"title\":\"Beef and Mustard Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sytuqu1511553755.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Plain Flour\",\"Rapeseed Oil\",\"Red Wine\",\"Beef Stock\",\"Onion\",\"Carrots\",\"Thyme\",\"Mustard\",\"Egg Yolks\",\"Puff Pastry\",\"Green Beans\",\"Butter\",\"Salt\",\"Pepper\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 150C/300F/Gas 2.\\r\\nToss the beef and flour together in a bowl with some salt and black pepper.\\r\\nHeat a large casserole until hot, add half of\",\"instructions\":[\"Preheat the oven to 150C/300F/Gas 2.\",\"Toss the beef and flour together in a bowl with some salt and black pepper.\",\"Heat a large casserole until hot, add half of the rapeseed oil and enough of the beef to just cover the bottom of the casserole.\",\"Fry until browned on each side, then remove and set aside. Repeat with the remaining oil and beef.\",\"Return the beef to the pan, add the wine and cook until the volume of liquid has reduced by half, then add the stock, onion, carrots, thyme and mustard, and season well with salt and pepper.\",\"Cover with a lid and place in the oven for two hours.\",\"Remove from the oven, check the seasoning and set aside to cool. Remove the thyme.\",\"When the beef is cool and you're ready to assemble the pie, preheat the oven to 200C/400F/Gas 6.\",\"Transfer the beef to a pie dish, brush the rim with the beaten egg yolks and lay the pastry over the top. Brush the top of the pastry with more beaten egg.\",\"Trim the pastry so there is just enough excess to crimp the edges, then place in the oven and bake for 30 minutes, or until the pastry is golden-brown and cooked through.\"]},{\"id\":\"g42\",\"title\":\"Beef and Oyster pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wrssvt1511556563.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Olive Oil\",\"Shallots\",\"Garlic\",\"Bacon\",\"Thyme\",\"Bay Leaf\",\"Stout\",\"Beef Stock\",\"Corn Flour\",\"Oysters\",\"Plain Flour\",\"Salt\",\"Butter\",\"Eggs\"],\"allergens\":[\"egg\",\"milk\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Season the beef cubes with salt and black pepper. Heat a tablespoon of oil in the frying pan and fry the meat over a high heat. Do this in three batches so that\",\"instructions\":[\"Season the beef cubes with salt and black pepper. Heat a tablespoon of oil in the frying pan and fry the meat over a high heat. Do this in three batches so that you don’t overcrowd the pan, transferring the meat to a large flameproof casserole dish once it is browned all over. Add extra oil if the pan seems dry.\",\"In the same pan, add another tablespoon of oil and cook the shallots for 4-5 minutes, then add the garlic and fry for 30 seconds. Add the bacon and fry until slightly browned. Transfer the onion and bacon mixture to the casserole dish and add the herbs.\",\"Preheat the oven to 180C/350F/Gas 4.\",\"Pour the stout into the frying pan and bring to the boil, stirring to lift any stuck-on browned bits from the bottom of the pan. Pour the stout over the beef in the casserole dish and add the stock. Cover the casserole and place it in the oven for 1½-2 hours, or until the beef is tender and the sauce is reduced.\",\"Skim off any surface fat, taste and add salt and pepper if necessary, then stir in the cornflour paste. Put the casserole dish on the hob – don’t forget that it will be hot – and simmer for 1-2 minutes, stirring, until thickened. Leave to cool.\",\"Increase the oven to 200C/400F/Gas 6. To make the pastry, put the flour and salt in a very large bowl. Grate the butter and stir it into the flour in three batches. Gradually add 325ml/11fl oz cold water – you may not need it all – and stir with a round-bladed knife until the mixture just comes together. Knead the pastry lightly into a ball on a lightly floured surface and set aside 250g/9oz for the pie lid.\",\"Roll the rest of the pastry out until about 2cm/¾in larger than the dish you’re using. Line the dish with the pastry then pile in the filling, tucking the oysters in as well. Brush the edge of the pastry with beaten egg.\",\"Roll the remaining pastry until slightly larger than your dish and gently lift over the filling, pressing the edges firmly to seal, then trim with a sharp knife. Brush with beaten egg to glaze. Put the dish on a baking tray and bake for 25-30 minutes, or until the pastry is golden-brown and the filling is bubbling.\"]},{\"id\":\"g43\",\"title\":\"Beef Asado\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pkopc31683207947.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Beef Stock Concentrate\",\"Tomato Puree\",\"Water\",\"Soy Sauce\",\"White Wine Vinegar\",\"Pepper\",\"Bay Leaf\",\"Lemon\",\"Tomato Sauce\",\"Butter\",\"Olive Oil\",\"Onion\",\"Garlic\"],\"allergens\":[\"milk\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"0.\\tCombine beef, crushed peppercorn, soy sauce, vinegar, dried bay leaves, lemon, and tomato sauce. Mix well. Marinate beef for at least 30 minutes.\\r\\n1.\\tPut the\",\"instructions\":[\"0.\\tCombine beef, crushed peppercorn, soy sauce, vinegar, dried bay leaves, lemon, and tomato sauce. Mix well. Marinate beef for at least 30 minutes.\",\"1.\\tPut the marinated beef in a cooking pot along with remaining marinade. Add water. Let boil.\",\"2.\\tAdd Knorr Beef Cube. Stir. Cover the pot and cook for 40 minutes in low heat.\",\"3.\\tTurn the beef over. Add tomato paste. Continue cooking until beef tenderizes. Set aside.\",\"4.\\tHeat oil in a pan. Fry the potato until it browns. Turn over and continue frying the opposite side. Remove from the pan and place on a clean plate. Do the same with the carrots.\",\"5.\\tSave 3 tablespoons of cooking oil from the pan where the potato was fried. Saute onion and garlic until onion softens.\",\"6.\\tPour-in the sauce from the beef stew. Let boil. Add the beef. Cook for 2 minutes.\",\"7.\\tAdd butter and let it melt. Continue cooking until the sauce reduces to half.\"]},{\"id\":\"g44\",\"title\":\"Beef Banh Mi Bowls with Sriracha Mayo, Carrot & Pickled Cucumber\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/z0ageb1583189517.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice\",\"Onion\",\"Lime\",\"Garlic Clove\",\"Cucumber\",\"Carrots\",\"Ground Beef\",\"Soy Sauce\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add'l ingredients: mayonnaise, siracha\\r\\n\\r\\n1\\r\\n\\r\\nPlace rice in a fine-mesh sieve and rinse until water runs clear. Add to a small pot with 1 cup water (2 cups for\",\"instructions\":[\"Add'l ingredients: mayonnaise, siracha\",\"1\",\"Place rice in a fine-mesh sieve and rinse until water runs clear. Add to a small pot with 1 cup water (2 cups for 4 servings) and a pinch of salt. Bring to a boil, then cover and reduce heat to low. Cook until rice is tender, 15 minutes. Keep covered off heat for at least 10 minutes or until ready to serve.\",\"2\",\"Meanwhile, wash and dry all produce. Peel and finely chop garlic. Zest and quarter lime (for 4 servings, zest 1 lime and quarter both). Trim and halve cucumber lengthwise; thinly slice crosswise into half-moons. Halve, peel, and medium dice onion. Trim, peel, and grate carrot.\",\"3\",\"In a medium bowl, combine cucumber, juice from half the lime, ¼ tsp sugar (½ tsp for 4 servings), and a pinch of salt. In a small bowl, combine mayonnaise, a pinch of garlic, a squeeze of lime juice, and as much sriracha as you’d like. Season with salt and pepper.\",\"4\",\"Heat a drizzle of oil in a large pan over medium-high heat. Add onion and cook, stirring, until softened, 4-5 minutes. Add beef, remaining garlic, and 2 tsp sugar (4 tsp for 4 servings). Cook, breaking up meat into pieces, until beef is browned and cooked through, 4-5 minutes. Stir in soy sauce. Turn off heat; taste and season with salt and pepper.\",\"5\"]},{\"id\":\"g45\",\"title\":\"Beef Bourguignon\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vtqxtu1511784197.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Goose Fat\",\"Beef Shin\",\"Bacon\",\"Challots\",\"Chestnut Mushroom\",\"Garlic Clove\",\"Bouquet Garni\",\"Tomato Puree\",\"Red Wine\",\"Celeriac\",\"Olive Oil\",\"Thyme\",\"Rosemary\",\"Bay Leaf\",\"Cardamom\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat a large casserole pan and add 1 tbsp goose fat. Season the beef and fry until golden brown, about 3-5 mins, then turn over and fry the other side until the\",\"instructions\":[\"Heat a large casserole pan and add 1 tbsp goose fat. Season the beef and fry until golden brown, about 3-5 mins, then turn over and fry the other side until the meat is browned all over, adding more fat if necessary. Do this in 2-3 batches, transferring the meat to a colander set over a bowl when browned.\",\"In the same pan, fry the bacon, shallots or pearl onions, mushrooms, garlic and bouquet garni until lightly browned. Mix in the tomato purée and cook for a few mins, stirring into the mixture. This enriches the bourguignon and makes a great base for the stew. Then return the beef and any drained juices to the pan and stir through.\",\"Pour over the wine and about 100ml water so the meat bobs up from the liquid, but isn’t completely covered. Bring to the boil and use a spoon to scrape the caramelised cooking juices from the bottom of the pan – this will give the stew more flavour.\",\"Heat oven to 150C/fan 130C/gas 2. Make a cartouche: tear off a square of foil slightly larger than the casserole, arrange it in the pan so it covers the top of the stew and trim away any excess foil. Then cook for 3 hrs. If the sauce looks watery, remove the beef and veg with a slotted spoon, and set aside. Cook the sauce over a high heat for a few mins until the sauce has thickened a little, then return the beef and vegetables to the pan.\",\"To make the celeriac mash, peel the celeriac and cut into cubes. Heat the olive oil in a large frying pan. Tip in the celeriac and fry for 5 mins until it turns golden. Season well with salt and pepper. Stir in the rosemary, thyme, bay and cardamom pods, then pour over 200ml water, enough to nearly cover the celeriac. Turn the heat to low, partially cover the pan and leave to simmer for 25-30 mins.\",\"After 25-30 mins, the celeriac should be soft and most of the water will have evaporated. Drain away any remaining water, then remove the herb sprigs, bay and cardamom pods. Lightly crush with a potato masher, then finish with a glug of olive oil and season to taste. Spoon the beef bourguignon into serving bowls and place a large spoonful of the celeriac mash on top. Garnish with one of the bay leaves, if you like.\"]},{\"id\":\"g46\",\"title\":\"Beef Brisket Pot Roast\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ursuup1487348423.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Brisket\",\"Salt\",\"Onion\",\"Garlic\",\"Thyme\",\"Rosemary\",\"Bay Leaves\",\"beef stock\",\"Carrots\",\"Mustard\",\"Potatoes\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1 Prepare the brisket for cooking: On one side of the brisket there should be a layer of fat, which you want. If there are any large chunks of fat, cut them off\",\"instructions\":[\"1 Prepare the brisket for cooking: On one side of the brisket there should be a layer of fat, which you want. If there are any large chunks of fat, cut them off and discard them. Large pieces of fat will not be able to render out completely.\",\"Using a sharp knife, score the fat in parallel lines, about 3/4-inch apart. Slice through the fat, not the beef. Repeat in the opposite direction to make a cross-hatch pattern.\",\"Salt the brisket well and let it sit at room temperature for 30 minutes.\",\"2 Sear the brisket: You'll need an oven-proof, thick-bottomed pot with a cover, or Dutch oven, that is just wide enough to hold the brisket roast with a little room for the onions.\",\"Pat the brisket dry and place it, fatty side down, into the pot and place it on medium high heat. Cook for 5-8 minutes, lightly sizzling, until the fat side is nicely browned. (If the roast seems to be cooking too fast, turn the heat down to medium. You want a steady sizzle, not a raging sear.)\",\"Turn the brisket over and cook for a few minutes more to brown the other side.\",\"3 Sauté the onions and garlic: When the brisket has browned, remove it from the pot and set aside. There should be a couple tablespoons of fat rendered in the pot, if not, add some olive oil.\",\"Add the chopped onions and increase the heat to high. Sprinkle a little salt on the onions. Sauté, stirring often, until the onions are lightly browned, 5-8 minutes. Stir in the garlic and cook 1-2 more minutes.\",\"4 Return brisket to pot, add herbs, stock, bring to simmer, cover, cook in oven: Preheat the oven to 300°F. Use kitchen twine to tie together the bay leaves, rosemary and thyme.\",\"Move the onions and garlic to the sides of the pot and nestle the brisket inside. Add the beef stock and the tied-up herbs. Bring the stock to a boil on the stovetop.\"]},{\"id\":\"g47\",\"title\":\"Beef Caldereta\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/41cxjh1683207682.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Beef Stock\",\"Soy Sauce\",\"Water\",\"Green Pepper\",\"Red Pepper\",\"Potatoes\",\"Carrots\",\"Tomato Puree\",\"Peanut Butter\",\"Chilli Powder\",\"Onion\",\"Garlic\",\"Olive Oil\"],\"allergens\":[\"milk\",\"soy\",\"peanut\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"0.\\tHeat oil in a cooking pot. Saute onion and garlic until onion softens\\r\\n1.\\tAdd beef. Saute until the outer part turns light brown.\\r\\n2.\\tAdd soy sauce. Pour tom\",\"instructions\":[\"0.\\tHeat oil in a cooking pot. Saute onion and garlic until onion softens\",\"1.\\tAdd beef. Saute until the outer part turns light brown.\",\"2.\\tAdd soy sauce. Pour tomato sauce and water. Let boil.\",\"3.\\tAdd Knorr Beef Cube. Cover the pressure cooker. Cook for 30 minutes.\",\"4.\\tPan-fry carrot and potato until it browns. Set aside.\",\"5.\\tAdd chili pepper, liver spread and peanut butter. Stir.\",\"6.\\tAdd bell peppers, fried potato and carrot. Cover the pot. Continue cooking for 5 to 7 minutes.\",\"7.\\tSeason with salt and ground black pepper. Serve.\"]},{\"id\":\"g48\",\"title\":\"Beef Dumpling Stew\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uyqrrv1511553350.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Butter\",\"Beef\",\"Plain Flour\",\"Garlic\",\"Onions\",\"Celery\",\"Carrots\",\"Leek\",\"Swede\",\"Red Wine\",\"Beef Stock\",\"Bay Leaf\",\"Thyme\",\"Parsley\",\"Plain Flour\",\"Baking Powder\",\"Suet\",\"Water\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 180C/350F/Gas 4.\\r\\n\\r\\nFor the beef stew, heat the oil and butter in an ovenproof casserole and fry the beef until browned on all sides.\\r\\n\\r\\nSpr\",\"instructions\":[\"Preheat the oven to 180C/350F/Gas 4.\",\"For the beef stew, heat the oil and butter in an ovenproof casserole and fry the beef until browned on all sides.\",\"Sprinkle over the flour and cook for a further 2-3 minutes.\",\"Add the garlic and all the vegetables and fry for 1-2 minutes.\",\"Stir in the wine, stock and herbs, then add the Worcestershire sauce and balsamic vinegar, to taste. Season with salt and freshly ground black pepper.\",\"Cover with a lid, transfer to the oven and cook for about two hours, or until the meat is tender.\",\"For the dumplings, sift the flour, baking powder and salt into a bowl.\",\"Add the suet and enough water to form a thick dough.\",\"With floured hands, roll spoonfuls of the dough into small balls.\",\"After two hours, remove the lid from the stew and place the balls on top of the stew. Cover, return to the oven and cook for a further 20 minutes, or until the dumplings have swollen and are tender. (If you prefer your dumplings with a golden top, leave the lid off when returning to the oven.)\"]},{\"id\":\"g49\",\"title\":\"Beef Empanadas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/dxpc7j1764370714.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lard\",\"Water\",\"Salt\",\"All purpose flour\",\"Tomato\",\"Garlic\",\"Red Onions\",\"Spring Onions\",\"Sirloin steak\",\"Dried Oregano\",\"Paprika\",\"Red Pepper Flakes\",\"Parsley\",\"Salt\",\"Pepper\",\"Egg\",\"Egg Wash\",\"Chimichurri sauce\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the dough place lard, warm water and salt in a large kneading bowl and stir. Add flour and oregano and either knead five miutes by hand or with the kneading\",\"instructions\":[\"For the dough place lard, warm water and salt in a large kneading bowl and stir. Add flour and oregano and either knead five miutes by hand or with the kneading function of your machine. Let rest covered for at least half an hour or overnight in the fridge.\",\"2\",\"For the filling place tomatoes for about 30 seconds in boiling water, then cool with cold water and peel of skin and cut into cubes. Press garlic through garlic press, cut onions into cubes. Simmer garlic and onions in some olive oil until translucent. Take out onions and garlic and brown the meat at high heat from all sides. Season with all herbs and add the onions, garlic and tomatoes. Let simmer for a few minutes, add salt, pepper and additional spices to taste. You can prepare the meat the night before, chill in fridge if doing so. Boil eggs and also cut into cubes and mix with prepared meat.\",\"3\",\"Cut dough into half and roll out one half thinnly on floured surface. Cut out circles about 12-15cm in diameter. Mine have a diameter of 12.5 cm. Place about 2-4 teaspoons of filling on one circle, put a bit of water all around the edges and fold over the other half so that you get half moons. Be sure to seal the edges with a fork. Repeat until you have no dough and filling left.\",\"4\",\"Meanwhile preheat oven to 200 degrees Celsius. Brush empanadas with egg wash and bake about 8 empanadas on a baking sheet lined with parchment paper for about 25min or until golden. Serve warm with chimichurri sauce.\"]},{\"id\":\"g50\",\"title\":\"Beef Lo Mein\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529444830.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Salt\",\"Pepper\",\"Sesame Seed Oil\",\"Egg\",\"Starch\",\"Oil\",\"Noodles\",\"Onion\",\"Minced Garlic\",\"Ginger\",\"Bean Sprouts\",\"Mushrooms\",\"Water\",\"Oyster Sauce\",\"Sugar\",\"Soy Sauce\"],\"allergens\":[\"egg\",\"soy\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1 - MARINATING THE BEEF\\r\\nIn a bowl, add the beef, salt, 1 pinch white pepper, 1 Teaspoon sesame seed oil, 1/2 egg, corn starch,1 Tablespoon of oil and mix \",\"instructions\":[\"STEP 1 - MARINATING THE BEEF\",\"In a bowl, add the beef, salt, 1 pinch white pepper, 1 Teaspoon sesame seed oil, 1/2 egg, corn starch,1 Tablespoon of oil and mix together.\",\"STEP 2 - BOILING THE THE NOODLES\",\"In a 6 qt pot add your noodles to boiling water until the noodles are submerged and boil on high heat for 10 seconds. After your noodles is done boiling strain and cool with cold water.\",\"STEP 3 - STIR FRY\",\"Add 2 Tablespoons of oil, beef and cook on high heat untill beef is medium cooked.\",\"Set the cooked beef aside\",\"In a wok add 2 Tablespoon of oil, onions, minced garlic, minced ginger, bean sprouts, mushrooms, peapods and 1.5 cups of water or until the vegetables are submerged in water.\",\"Add the noodles to wok\",\"To make the sauce, add oyster sauce, 1 pinch white pepper, 1 teaspoon sesame seed oil, sugar, and 1 Teaspoon of soy sauce.\"]},{\"id\":\"g51\",\"title\":\"Beef Mandi\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1nalo51765188375.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Basmati Rice\",\"Beef Stock\",\"Onion\",\"Garlic\",\"Green Chilli\",\"Tomato\",\"Salt\",\"Oil\",\"Turmeric Powder\",\"Cardamom\",\"Cloves\",\"Bay Leaf\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1. Wash the beef and cut into large pieces. Season lightly with salt and turmeric.\\r\\n2. Heat ghee/oil in a large pot. Add sliced onions and sauté until light gol\",\"instructions\":[\"1. Wash the beef and cut into large pieces. Season lightly with salt and turmeric.\",\"2. Heat ghee/oil in a large pot. Add sliced onions and sauté until light golden.\",\"3. Add garlic, green chilies, and tomato; cook until softened.\",\"4. Add the mandi spice mix: coriander, cumin, black pepper, cinnamon, cardamom, cloves, and bay leaves.\",\"5. Add beef pieces and stir on medium heat until the meat is well coated with spices.\",\"6. Pour in water or beef stock. Cover and simmer until beef is tender (about 1.5–2 hours depending on cut).\",\"7. Remove beef carefully and set aside. Strain and measure the broth.\",\"8. Add washed, soaked basmati rice to the broth (usually 1 cup rice = 1.5–2 cups liquid). Adjust seasoning and bring to a boil.\",\"9. Lower heat, cover, and cook the rice until fluffy.\",\"10. Place the beef pieces over the rice and steam on low heat for 10 minutes so flavors combine.\"]},{\"id\":\"g52\",\"title\":\"Beef Mechado\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/cgl60b1683206581.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Garlic\",\"Onion\",\"Beef\",\"Tomato Puree\",\"Water\",\"Olive Oil\",\"Lemon\",\"Potatoes\",\"Soy Sauce\",\"Black Pepper\",\"Bay Leaves\",\"Salt\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"0.\\tMake the beef tenderloin marinade by combining soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt, and ground black pepper in a large bow\",\"instructions\":[\"0.\\tMake the beef tenderloin marinade by combining soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt, and ground black pepper in a large bowl. Mix well.\",\"1.\\tAdd the cubed beef tenderloin to the bowl with the beef tenderloin marinade. Gently toss to coat the beef. Let it stay for 1 hour.\",\"2.\\tUsing a metal or bamboo skewer, assemble the beef kebob by skewering the vegetables and marinated beef tenderloin.\",\"3.\\tHeat-up the grill and start grilling the beef kebobs for 3 minutes per side. This will give you a medium beef that is juicy and tender on the inside. Add more time if you want your beef well done, but it will be less tender.\",\"4.\\tTransfer to a serving plate. Serve with Saffron rice.\",\"5.\\tShare and enjoy!\"]},{\"id\":\"g53\",\"title\":\"Beef pho\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Stock\",\"Onion\",\"Ginger\",\"Cinnamon Stick\",\"Star Anise\",\"Coriander Seeds\",\"Cloves\",\"Sirloin steak\",\"Palm Sugar\",\"Fish Sauce\",\"Soy Sauce\",\"Rice Noodles\",\"Spring Onions\",\"Birds-eye Chillies\",\"Basil\",\"Coriander\",\"Lime\"],\"allergens\":[\"soy\",\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTip the beef stock along with 500ml of water into a large saucepan. Sit the onion and ginger in a frying pan over a high heat and char on all sides, aro\",\"instructions\":[\"step 1\",\"Tip the beef stock along with 500ml of water into a large saucepan. Sit the onion and ginger in a frying pan over a high heat and char on all sides, around 3-5 mins (you can also do this under your grill). Once charred, add to the beef stock. In the same pan, toast the spices for 2-3 mins and once they begin to smell fragrant, add them to the beef stock as well. Bring the stock to the boil, then turn to a simmer and cook for 30mins before straining.\",\"step 2\",\"Meanwhile, cut the fat from the steak and wrap in cling film, then put into the freezer for 15 mins – this will make your steak really easy to slice! Slice it thinly, then cover with cling film again and pop into the fridge.\",\"step 3\",\"Taste the beef stock and use the palm sugar, fish sauce and soy to season. Cook the noodles according to package instructions and split between two bowls, topping each with the sliced beef. Bring the stock to the boil and then pour into the bowls (the heat will cook the beef). Top each with the spring onions, chilli slices and herbs. Serve with the lime wedges to squeeze over.\"]},{\"id\":\"g54\",\"title\":\"Beef Rendang\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/bc8v651619789840.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Vegetable Oil\",\"Cinnamon Stick\",\"Cloves\",\"Star Anise\",\"Cardamom\",\"Coconut Cream\",\"Water\",\"Tamarind Paste\",\"Lime\",\"Sugar\",\"Challots\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Chop the spice paste ingredients and then blend it in a food processor until fine.\\r\\nHeat the oil in a stew pot, add the spice paste, cinnamon, cloves, star anis\",\"instructions\":[\"Chop the spice paste ingredients and then blend it in a food processor until fine.\",\"Heat the oil in a stew pot, add the spice paste, cinnamon, cloves, star anise, and cardamom and stir-fry until aromatic. Add the beef and the pounded lemongrass and stir for 1 minute. Add the coconut milk, tamarind juice, water, and simmer on medium heat, stirring frequently until the meat is almost cooked. Add the kaffir lime leaves, kerisik (toasted coconut), sugar or palm sugar, stirring to blend well with the meat.\",\"Lower the heat to low, cover the lid, and simmer for 1 to 1 1/2 hours or until the meat is really tender and the gravy has dried up. Add more salt and sugar to taste. Serve immediately with steamed rice and save some for overnight.\"]},{\"id\":\"g55\",\"title\":\"Beef stroganoff\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/svprys1511176755.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onions\",\"Garlic\",\"Butter\",\"Mushrooms\",\"Beef Fillet\",\"Plain Flour\",\"Creme Fraiche\",\"English Mustard\",\"Beef Stock\",\"Parsley\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the olive oil in a non-stick frying pan then add the sliced onion and cook on a medium heat until completely softened, so around 15 mins, adding a little s\",\"instructions\":[\"Heat the olive oil in a non-stick frying pan then add the sliced onion and cook on a medium heat until completely softened, so around 15 mins, adding a little splash of water if they start to stick at all. Crush in the garlic and cook for a 2-3 mins further, then add the butter. Once the butter is foaming a little, add the mushrooms and cook for around 5 mins until completely softened. Season everything well, then tip onto a plate.\",\"Tip the flour into a bowl with a big pinch of salt and pepper, then toss the steak in the seasoned flour. Add the steak pieces to the pan, splashing in a little oil if the pan looks particularly dry, and fry for 3-4 mins, until well coloured. Tip the onions and mushrooms back into the pan. Whisk the crème fraîche, mustard and beef stock together, then pour into the pan. Cook over a medium heat for around 5 mins. Scatter with parsley, then serve with pappardelle or rice.\"]},{\"id\":\"g56\",\"title\":\"Beef Sunday Roast\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ssrrrs1503664277.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Broccoli\",\"Potatoes\",\"Carrots\",\"plain flour\",\"Eggs\",\"milk\",\"sunflower oil\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cook the Broccoli and Carrots in a pan of boiling water until tender.\\r\\n\\r\\nRoast the Beef and Potatoes in the oven for 45mins, the potatoes may need to be checked\",\"instructions\":[\"Cook the Broccoli and Carrots in a pan of boiling water until tender.\",\"Roast the Beef and Potatoes in the oven for 45mins, the potatoes may need to be checked regularly to not overcook.\",\"To make the Yorkshire puddings:\",\"Heat oven to 230C/fan 210C/gas 8. Drizzle a little sunflower oil evenly into 2 x 4-hole Yorkshire pudding tins or a 12-hole non-stick muffin tin and place in the oven to heat through\",\"To make the batter, tip 140g plain flour into a bowl and beat in four eggs until smooth. Gradually add 200ml milk and carry on beating until the mix is completely lump-free. Season with salt and pepper. Pour the batter into a jug, then remove the hot tins from the oven. Carefully and evenly pour the batter into the holes. Place the tins back in the oven and leave undisturbed for 20-25 mins until the puddings have puffed up and browned. Serve immediately.\",\"Plate up and add the Gravy as desired.\"]},{\"id\":\"g57\",\"title\":\"Beef Wellington\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vvpprx1487325699.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"mushrooms\",\"English Mustard\",\"Olive Oil\",\"Beef Fillet\",\"Parma ham\",\"Puff Pastry\",\"Flour\",\"Egg Yolks\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Put the mushrooms into a food processor with some seasoning and pulse to a rough paste. Scrape the paste into a pan and cook over a high heat for about 10 mins,\",\"instructions\":[\"Put the mushrooms into a food processor with some seasoning and pulse to a rough paste. Scrape the paste into a pan and cook over a high heat for about 10 mins, tossing frequently, to cook out the moisture from the mushrooms. Spread out on a plate to cool.\",\"Heat in a frying pan and add a little olive oil. Season the beef and sear in the hot pan for 30 secs only on each side. (You don't want to cook it at this stage, just colour it). Remove the beef from the pan and leave to cool, then brush all over with the mustard.\",\"Lay a sheet of cling film on a work surface and arrange the Parma ham slices on it, in slightly overlapping rows. With a palette knife, spread the mushroom paste over the ham, then place the seared beef fillet in the middle. Keeping a tight hold of the cling film from the edge, neatly roll the Parma ham and mushrooms around the beef to form a tight barrel shape. Twist the ends of the cling film to secure. Chill for 15-20 mins to allow the beef to set and keep its shape.\",\"Roll out the puff pastry on a floured surface to a large rectangle, the thickness of a £1 coin. Remove the cling film from the beef, then lay in the centre. Brush the surrounding pastry with egg yolk. Fold the ends over, the wrap the pastry around the beef, cutting off any excess. Turn over, so the seam is underneath, and place on a baking sheet. Brush over all the pastry with egg and chill for about 15 mins to let the pastry rest.\",\"Heat the oven to 200C, 400F, gas 6.\",\"Lightly score the pastry at 1cm intervals and glaze again with beaten egg yolk. Bake for 20 minutes, then lower the oven setting to 180C, 350F, gas 4 and cook for another 15 mins. Allow to rest for 10-15 mins before slicing and serving with the side dishes of your choice. The beef should still be pink in the centre when you serve it.\"]},{\"id\":\"g58\",\"title\":\"Beetroot & red cabbage sauerkraut\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ra2k8a1764365055.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beetroot\",\"Red Cabbage\",\"Onion\",\"Caraway Seed\",\"Sea Salt\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip all the ingredients into a large bowl, add 1-1½ tsp freshly ground black pepper, then scrunch it all together with your hands for 5 mins. You might \",\"instructions\":[\"step 1\",\"Tip all the ingredients into a large bowl, add 1-1½ tsp freshly ground black pepper, then scrunch it all together with your hands for 5 mins. You might want to wear gloves to avoid staining your skin with the beetroot juices.\",\"step 2\",\"Press the veg down in the bowl with your hands, then cover the surface and up the side of the bowl with a large sheet of compostable cling film or something reusable like a beeswax wrap. Now place another similar-sized bowl on top. Press down hard and add anything heavy (packs of rice or cans work well) to weigh it down so the juices rise to cover the surface. Cover again.\",\"step 3\",\"Leave to ferment at room temperature for at least five days, but for maximum flavour, leave for one-five weeks (until the bubbling subsides).\",\"step 4\",\"Check the sauerkraut. After a few days, you will see bubbles that have built up as it ferments. Give it a stir, then cover and weigh it down again as before. The cabbage will become increasingly sour the longer it’s fermented, so taste it now and again. When you like the flavour, transfer it to sterilised jars and keep chilled. Will keep chilled for up to six months.\"]},{\"id\":\"g59\",\"title\":\"Beetroot latkes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qwicc91764368097.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rapeseed Oil\",\"Greek Yogurt\",\"Mint\",\"Rocket\",\"Cherry Tomatoes\",\"Beetroot\",\"Egg\",\"Plain Flour\",\"Garlic\",\"Caraway Seed\",\"Ground Cumin\",\"Lemon\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oven to 180C/160C fan/gas 4. Make the latkes by combining all of the ingredients.\\r\\n\\r\\nstep 2\\r\\nHeat the oil in a large non-stick pan. Spoon in th\",\"instructions\":[\"step 1\",\"Heat the oven to 180C/160C fan/gas 4. Make the latkes by combining all of the ingredients.\",\"step 2\",\"Heat the oil in a large non-stick pan. Spoon in the mixture to make six round latkes. Fry for 4-5 mins on each side, then transfer to a baking sheet and bake for 10 mins.\",\"step 3\",\"Combine the yogurt and mint in a small bowl. Toss the salad leaves and tomatoes together, then serve the latkes with the mint yogurt and salad.\"]},{\"id\":\"g60\",\"title\":\"Beetroot pancakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xlqqhw1764369924.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beetroot\",\"Milk\",\"Self-raising Flour\",\"Baking Powder\",\"Maple Syrup\",\"Vanilla Extract\",\"Egg\",\"Butter\",\"Frozen Mixed Berries\",\"Blackcurrant Jam\",\"Greek Yogurt\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the beetroot in a jug with the milk and blend with a stick blender until smooth. Pour into a bowl with the rest of the pancake ingredients and whisk\",\"instructions\":[\"step 1\",\"Put the beetroot in a jug with the milk and blend with a stick blender until smooth. Pour into a bowl with the rest of the pancake ingredients and whisk until smooth and vibrant purple.\",\"step 2\",\"Put a small knob of butter in a large non-stick frying pan and heat over a medium-low heat until melted and foamy. Now create 3 or 4 pancakes each made from 2 tbsp of the batter. Cook for 2-3 mins then flip over and cook for a further minute until cooked through. Repeat with any remaining batter. Heat oven to lowest setting and keep the pancakes warm in there until needed.\",\"step 3\",\"Serve with your favourite pancake toppings or make a simple compote by simmering frozen berries in with 1 tbsp blackcurrant jam until bubbling and syrupy (about 5-10 mins). In a small bowl stir together the remaining jam and the yogurt. Stack the cooked pancakes with the yogurt and pour the warm berry compote over the top.\"]},{\"id\":\"g61\",\"title\":\"Beetroot Soup (Borscht)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/zadvgb1699012544.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beetroot\",\"Olive Oil\",\"Chicken Stock Cube\",\"Water\",\"Potatoes\",\"Cannellini Beans\",\"Dill\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Chop the beetroot, add water and stock cube and cook for 15mins. Add the other ingredients and boil until soft. Finally add the beans and cook for 5mins. Serve \",\"instructions\":[\"Chop the beetroot, add water and stock cube and cook for 15mins.\",\"Add the other ingredients and boil until soft.\",\"Finally add the beans and cook for 5mins.\",\"Serve in the soup pot.\"]},{\"id\":\"g62\",\"title\":\"Big Mac\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/urzj1d1587670726.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Minced Beef\",\"Olive Oil\",\"Sesame Seed Burger Buns\",\"Onion\",\"Iceberg Lettuce\",\"Cheese\",\"Dill Pickles\",\"Mayonnaise\",\"White Wine Vinegar\",\"Pepper\",\"Mustard\",\"Onion Salt\",\"Garlic Powder\",\"Paprika\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the Big Mac sauce, combine all the ingredients in a bowl, season with salt and chill until ready to use.\\r\\n2. To make the patties, season the mince with salt\",\"instructions\":[\"For the Big Mac sauce, combine all the ingredients in a bowl, season with salt and chill until ready to use.\",\"2. To make the patties, season the mince with salt and pepper and form into 4 balls using about 1/3 cup mince each. Place each onto a square of baking paper and flatten to form into four x 15cm circles. Heat oil in a large frypan over high heat. In 2 batches, cook beef patties for 1-2 minutes each side until lightly charred and cooked through. Remove from heat and keep warm. Repeat with remaining two patties.\",\"3. Carefully slice each burger bun into three acrossways, then lightly toast.\",\"4. To assemble the burgers, spread a little Big Mac sauce over the bottom base. Top with some chopped onion, shredded lettuce, slice of cheese, beef patty and some pickle slices. Top with the middle bun layer, and spread with more Big Mac sauce, onion, lettuce, pickles, beef patty and then finish with more sauce. Top with burger lid to serve.\",\"5. After waiting half an hour for your food to settle, go for a jog.\"]},{\"id\":\"g63\",\"title\":\"Bigos (Hunters Stew)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/md8w601593348504.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Bacon\",\"Kielbasa\",\"Pork\",\"Flour\",\"Garlic\",\"Onion\",\"Mushrooms\",\"Cabbage\",\"Sauerkraut\",\"Red Wine\",\"Bay Leaf\",\"Basil\",\"Marjoram\",\"Paprika\",\"Caraway Seed\",\"Hotsauce\",\"Beef Stock\",\"Tomato Puree\",\"Diced Tomatoes\",\"Worcestershire Sauce\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 350 degrees F (175 degrees C).\\r\\n\\r\\nHeat a large pot over medium heat. Add the bacon and kielbasa; cook and stir until the bacon has rendered \",\"instructions\":[\"Preheat the oven to 350 degrees F (175 degrees C).\",\"Heat a large pot over medium heat. Add the bacon and kielbasa; cook and stir until the bacon has rendered its fat and sausage is lightly browned. Use a slotted spoon to remove the meat and transfer to a large casserole or Dutch oven.\",\"Coat the cubes of pork lightly with flour and fry them in the bacon drippings over medium-high heat until golden brown. Use a slotted spoon to transfer the pork to the casserole. Add the garlic, onion, carrots, fresh mushrooms, cabbage and sauerkraut. Reduce heat to medium; cook and stir until the carrots are soft, about 10 minutes. Do not let the vegetables brown.\",\"Deglaze the pan by pouring in the red wine and stirring to loosen all of the bits of food and flour that are stuck to the bottom. Season with the bay leaf, basil, marjoram, paprika, salt, pepper, caraway seeds and cayenne pepper; cook for 1 minute.\",\"Mix in the dried mushrooms, hot pepper sauce, Worcestershire sauce, beef stock, tomato paste and tomatoes. Heat through just until boiling. Pour the vegetables and all of the liquid into the casserole dish with the meat. Cover with a lid.\",\"Bake in the preheated oven for 2 1/2 to 3 hours, until meat is very tender.\"]},{\"id\":\"g64\",\"title\":\"Bigos (Polish hunter's stew)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/fl4brj1764361323.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"White Cabbage\",\"Beef Stock\",\"Mushrooms\",\"Lard\",\"German Sausages\",\"Bacon\",\"Onion\",\"Beef\",\"Prunes\",\"Bay Leaf\",\"Cloves\",\"Peppercorns\",\"Juniper Berries\",\"Allspice Berries\",\"Red Wine\",\"Tomato Puree\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the cabbage in a heavy casserole dish, add the stock and cook over a low heat for about 50 mins, until tender.\\r\\n\\r\\nstep 2\\r\\nCut the soaked mushrooms i\",\"instructions\":[\"step 1\",\"Put the cabbage in a heavy casserole dish, add the stock and cook over a low heat for about 50 mins, until tender.\",\"step 2\",\"Cut the soaked mushrooms into strips and save the soaking water. Heat the lard and fry the sausages and bacon, then scoop out, leaving the fat in the pan. Fry the onion in the same pan for 5-8 mins until lightly browned.\",\"step 3\",\"Add the mushrooms and their liquid along with all the cooked meat, onions and prunes, then cover and cook for 20 mins. Add the spices, red wine and tomato purée and bring to a simmer, then cover and cook for 1 hr. Season well and leave to cool. Will keep covered and chilled for up to two days. Bigos improves in flavour over a couple of days. Leave to cool first. Reheat until piping hot before serving.\"]},{\"id\":\"g65\",\"title\":\"Bistek\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4pqimk1683207418.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Soy Sauce\",\"Lemon\",\"Garlic\",\"Onion\",\"Olive Oil\",\"Water\",\"Salt\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"0.\\tMarinate beef in soy sauce, lemon (or calamansi), and ground black pepper for at least 1 hour. Note: marinate overnight for best result\\r\\n1.\\tHeat the cooking \",\"instructions\":[\"0.\\tMarinate beef in soy sauce, lemon (or calamansi), and ground black pepper for at least 1 hour. Note: marinate overnight for best result\",\"1.\\tHeat the cooking oil in a pan then pan-fry half of the onions until the texture becomes soft. Set aside\",\"2.\\tDrain the marinade from the beef. Set it aside. Pan-fry the beef on the same pan where the onions were fried for 1 minute per side. Remove from the pan. Set aside\",\"3.\\tAdd more oil if needed. Saute garlic and remaining raw onions until onion softens.\",\"4.\\tPour the remaining marinade and water. Bring to a boil.\",\"5.\\tAdd beef. Cover the pan and simmer until the meat is tender. Note: Add water as needed.\",\"6.\\tSeason with ground black pepper and salt as needed. Top with pan-fried onions.\",\"7.\\tTransfer to a serving plate. Serve hot. Share and Enjoy!\"]},{\"id\":\"g66\",\"title\":\"Bitterballen (Dutch meatballs)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lhqev81565090111.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Flour\",\"Beef Stock\",\"Onion\",\"Parsley\",\"Beef\",\"Salt\",\"Pepper\",\"Nutmeg\",\"Flour\",\"Eggs\",\"Breadcrumbs\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Melt the butter in a skillet or pan. When melted, add the flour little by little and stir into a thick paste. Slowly stir in the stock, making sure the roux abs\",\"instructions\":[\"Melt the butter in a skillet or pan. When melted, add the flour little by little and stir into a thick paste. Slowly stir in the stock, making sure the roux absorbs the liquid. Simmer for a couple of minutes on a low heat while you stir in the onion, parsley and the shredded meat. The mixture should thicken and turn into a heavy, thick sauce.\",\"Pour the mixture into a shallow container, cover and refrigerate for several hours, or until the sauce has solidified.\",\"Take a heaping tablespoon of the cold, thick sauce and quickly roll it into a small ball. Roll lightly through the flour, then the egg and finally the breadcrumbs. Make sure that the egg covers the whole surface of the bitterbal. When done, refrigerate the snacks while the oil in your fryer heats up to 190C (375F). Fry four bitterballen at a time, until golden.\",\"Serve on a plate with a nice grainy or spicy mustard.\"]},{\"id\":\"g67\",\"title\":\"Blackberry Fool\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rpvptu1511641092.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Hazlenuts\",\"Butter\",\"Caster Sugar\",\"Lemon\",\"Plain Flour\",\"Baking Powder\",\"Blackberries\",\"Sugar\",\"Caster Sugar\",\"Lemon Juice\",\"Double Cream\",\"Yogurt\",\"Mint\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"For the biscuits, preheat the oven to 200C/180C (fan)/Gas 6 and line two large baking trays with baking parchment. Scatter the nuts over a baking tray and roast\",\"instructions\":[\"For the biscuits, preheat the oven to 200C/180C (fan)/Gas 6 and line two large baking trays with baking parchment. Scatter the nuts over a baking tray and roast in the oven for 6-8 minutes, or until golden-brown. Watch them carefully so that they don’t have a chance to burn. Remove from the oven, tip onto a board and leave to cool.\",\"Put the butter and sugar in a large bowl and beat with a wooden spoon until light and creamy. Roughly chop the cooled nuts and add to the creamed butter and sugar, along with the lemon zest, flour and baking powder. Stir well until the mixture comes together and forms a ball – you may need to use your hands.\",\"Divide the biscuit dough into 24 even pieces and roll into small balls. Place the balls the prepared baking trays, spaced well apart to allow for spreading.\",\"Press the biscuits to flatten to around 1cm/½in thick. Bake the biscuits, one tray at a time, for 12 minutes or until very pale golden-brown. Leave to cool on the trays. They will be very soft when you take them out of the oven, but will crisp as they cool.\",\"Store in an airtight tin and eat within five days.\",\"For the fool, rinse the blackberries in a colander to wash away any dust or dirt. Put the blackberries in a non-stick saucepan and sprinkle over the caster sugar.\",\"Stir in the lemon juice and heat gently for two minutes, or until the blackberries begin to soften and release their juices. Remove and reserve 12 blackberries for decoration and continue cooking the rest.\",\"Simmer the blackberries very gently for 15 minutes, stirring regularly until very soft and squidgy. Remove from the heat and press the berries and juice through a sieve over a bowl, using the bottom of a ladle to help you extract as much of the purée as possible. Leave the purée to cool and discard the seeds. You should end up with around 325ml/11fl oz of purée.\",\"Put the cream and yoghurt in a large bowl and whip with an electric whisk until soft peaks form when the whisk is removed from the bowl – the acidity of the fruit will thicken the cream further, so don’t take it too far.\",\"When the purée is completely cold, adjust the sweetness to taste by adding more sugar if needed. Pour it into the bowl with the whipped cream and yoghurt and stir just once or twice until very lightly combined.\"]},{\"id\":\"g68\",\"title\":\"Blini Pancakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0206h11699013358.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Buckwheat\",\"Flour\",\"Salt\",\"Yeast\",\"Milk\",\"Butter\",\"Egg\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a large bowl, whisk together 1/2 cup buckwheat flour, 2/3 cup all-purpose flour, 1/2 teaspoon salt, and 1 teaspoon yeast.\\r\\n\\r\\nMake a well in the center and po\",\"instructions\":[\"In a large bowl, whisk together 1/2 cup buckwheat flour, 2/3 cup all-purpose flour, 1/2 teaspoon salt, and 1 teaspoon yeast.\",\"Make a well in the center and pour in 1 cup warm milk, whisking until the batter is smooth.\",\"Cover the bowl and let the batter rise until doubled, about 1 hour.\",\"Enrich and Rest the Batter\",\"Stir 2 tablespoons melted butter and 1 egg yolk into the batter.\",\"In a separate bowl, whisk 1 egg white until stiff, but not dry.\",\"Fold the whisked egg white into the batter.\",\"Cover the bowl and let the batter stand 20 minutes.\",\"Pan-Fry the Blini\",\"Heat butter in a large nonstick skillet over medium heat.\"]},{\"id\":\"g69\",\"title\":\"Blueberry & lemon friands\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/e756bf1761848342.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Unsalted Butter\",\"Icing Sugar\",\"Flour\",\"Almonds\",\"Egg White\",\"Unwaxed Lemon\",\"Blackberries\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPreheat the oven to fan 180C/conventional 200C/gas 6. Generously butter six non-stick friand or muffin tins. Melt the butter and set aside to cool.\\r\\n\\r\\ns\",\"instructions\":[\"step 1\",\"Preheat the oven to fan 180C/conventional 200C/gas 6. Generously butter six non-stick friand or muffin tins. Melt the butter and set aside to cool.\",\"step 2\",\"Sift the icing sugar and flour into a bowl. Add the almonds and mix everything between your fingers.\",\"step 3\",\"Whisk the egg whites in another bowl until they form a light, floppy foam. Make a well in the centre of the dry ingredients, tip in the egg whites and lemon rind, then lightly stir in the butter to form a soft batter.\",\"step 4\",\"Divide the batter among the tins, a large serving spoon is perfect for this job. Sprinkle a handful of blueberries over each cake and bake for 15-20 minutes until just firm to the touch and golden brown.\",\"step 5\",\"Cool in the tins for 5 minutes, then turn out and cool on a wire rack. To serve, dust lightly with icing sugar.\"]},{\"id\":\"g70\",\"title\":\"Borsch\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/804v1j1764367088.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Shin\",\"Onion\",\"Bay Leaf\",\"Potatoes\",\"Sunflower Oil\",\"Onion\",\"Carrots\",\"Beetroot\",\"Red Pepper\",\"Tinned Tomatos\",\"Prunes\",\"White Cabbage\",\"Kidney Beans\",\"Creme Fraiche\",\"Dill\",\"Crusty Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make the stock, put the meat, whole onion, bay leaf and 2 litres of lightly salted cold water in a large saucepan. Cook over a very low heat for 1 hr\",\"instructions\":[\"step 1\",\"To make the stock, put the meat, whole onion, bay leaf and 2 litres of lightly salted cold water in a large saucepan. Cook over a very low heat for 1 hr 30 mins or until the beef shin is soft and falls apart easily – this can take up to 3 hrs. Skim off the scum with a spoon from time to time. Break up any larger pieces of beef into the broth, remove the whole onion and discard.\",\"step 2\",\"Add the potatoes to the borscht, season well with salt and pepper and cook for 10-15 mins until tender. Meanwhile, heat the sunflower oil in a large, deep frying pan. Add the diced onion and carrot, and cook over a medium heat, stirring, until the carrot is soft and is about to start caramelising.\",\"step 3\",\"Add the beetroot and cook for around 5 mins, stirring occasionally. Add the red pepper, if using, and cook for another 2 mins, then add the tomatoes and prunes, stir, then increase the heat and boil to reduce slightly, before adding everything to the borscht.\",\"step 4\",\"Add the shredded cabbage and the kidney beans, and cook for 7-10 mins or until tender. Serve with a dollop of sour cream or crème fraîche, lots of chopped dill and some crusty bread.\"]},{\"id\":\"g71\",\"title\":\"Boulangère Potatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qywups1511796761.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onions\",\"Thyme\",\"Olive Oil\",\"Potatoes\",\"Vegetable Stock\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 200C/fan 180C/gas 6. Fry the onions and thyme sprigs in the oil until softened and lightly coloured (about 5 mins).\\r\\nSpread a layer of potatoes ove\",\"instructions\":[\"Heat oven to 200C/fan 180C/gas 6. Fry the onions and thyme sprigs in the oil until softened and lightly coloured (about 5 mins).\",\"Spread a layer of potatoes over the base of a 1.5-litre oiled gratin dish. Sprinkle over a few onions (see picture, above) and continue layering, finishing with a layer of potatoes. Pour over the stock and bake for 50-60 mins until the potatoes are cooked and the top is golden and crisp.\"]},{\"id\":\"g72\",\"title\":\"Boxty Breakfast\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/naqyel1608588563.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Spring Onions\",\"Plain Flour\",\"Egg White\",\"Milk\",\"Bicarbonate Of Soda\",\"Butter\",\"Vegetable Oil\",\"Cherry Tomatoes\",\"Bacon\",\"Egg\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\nBefore you start, put your oven on its lowest setting, ready to keep things warm. Peel the potatoes, grate 2 of them, then set aside. Cut the other 2 in\",\"instructions\":[\"STEP 1\",\"Before you start, put your oven on its lowest setting, ready to keep things warm. Peel the potatoes, grate 2 of them, then set aside. Cut the other 2 into large chunks, then boil for 10-15 mins or until tender. Meanwhile, squeeze as much of the liquid from the grated potatoes as you can using a clean tea towel. Mash the boiled potatoes, then mix with the grated potato, spring onions and flour.\",\"STEP 2\",\"Whisk the egg white in a large bowl until it holds soft peaks. Fold in the buttermilk, then add the bicarbonate of soda. Fold into the potato mix.\",\"STEP 3\",\"Heat a large non-stick frying pan over a medium heat, then add 1 tbsp butter and some of the oil. Drop 3-4 spoonfuls of the potato mixture into the pan, then gently cook for 3-5 mins on each side until golden and crusty. Keep warm on a plate in the oven while you cook the next batch, adding more butter and oil to the pan before you do so. You will get 16 crumpet-size boxty from the mix. Can be made the day ahead, drained on kitchen paper, then reheated in a low oven for 20 mins.\",\"STEP 4\",\"Heat the grill to medium and put the tomatoes in a heavy-based pan. Add a good knob of butter and a little oil, then fry for about 5 mins until softened. Grill the bacon, then pile onto a plate and keep warm. Stack up the boxty, bacon and egg, and serve the tomatoes on the side.\"]},{\"id\":\"g73\",\"title\":\"Braised Beef Chilli\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uuqvwu1504629254.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Onions\",\"Garlic\",\"Olive oil\",\"Chorizo\",\"Cumin\",\"Allspice\",\"Cloves\",\"Cinnamon stick\",\"Bay Leaves\",\"Oregano\",\"Ancho Chillies\",\"Balsamic Vinegar\",\"Plum Tomatoes\",\"Tomato Ketchup\",\"Dark Brown Sugar\",\"Borlotti Beans\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 120C/225F/gas mark 1.\\r\\n\\r\\nTake the meat out of the fridge to de-chill. Pulse the onions and garlic in a food processor until finely chopped. \",\"instructions\":[\"Preheat the oven to 120C/225F/gas mark 1.\",\"Take the meat out of the fridge to de-chill. Pulse the onions and garlic in a food processor until finely chopped. Heat 2 tbsp olive oil in a large casserole and sear the meat on all sides until golden.\",\"Set to one side and add another small slug of oil to brown the chorizo. Remove and add the onion and garlic, spices, herbs and chillies then cook until soft in the chorizo oil. Season with salt and pepper and add the vinegar, tomatoes, ketchup and sugar.\",\"Put all the meat back into the pot with 400ml water (or red wine if you prefer), bring up to a simmer and cook, covered, in the low oven.\",\"After 2 hours, check the meat and add the beans. Cook for a further hour and just before serving, pull the meat apart with a pair of forks.\"]},{\"id\":\"g74\",\"title\":\"Braised stuffed cabbage\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/z267f71764364072.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cabbage Leaves\",\"Olive Oil\",\"Onion\",\"Rosemary\",\"Celery\",\"Basmati Rice\",\"Cooked Chestnut\",\"Cranberry\",\"Vegetable Stock\",\"Balsamic Vinegar\",\"Clear Honey\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat oven to 180C/fan 160C/gas 4. Remove the tough central stalk from the cabbage leaves. Bring a large pan of salted water to the boil, add the cabbage\",\"instructions\":[\"step 1\",\"Heat oven to 180C/fan 160C/gas 4. Remove the tough central stalk from the cabbage leaves. Bring a large pan of salted water to the boil, add the cabbage, then cook for just 1-2 mins until the leaves are starting to wilt. Drain and refresh under cold running water. Drain well, then pat dry with a tea towel.\",\"step 2\",\"Heat the oil in a pan, add the onion, then fry for 5 mins until slightly browned. Add the rosemary and celery, then cook for 8 mins more. Stir in the rice, then cook for a min or so until the grains are glistening. Remove from the heat, stir in the chestnuts and cranberries, then season.\",\"step 3\",\"Spoon a little stuffing onto a cabbage leaf, roll up and fold in the sides to enclose the filling. Put in a single layer in a large, oiled, shallow ovenproof dish with the join underneath. Fill the remaining leaves in the same way. Mix the stock, vinegar and honey, then pour over the cabbage. Cover the dish tightly with foil, bake for 1 hr, uncover, then cook for a further 15 mins.\"]},{\"id\":\"g75\",\"title\":\"Bread and Butter Pudding\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xqwwpy1483908697.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"butter\",\"bread\",\"sultanas\",\"cinnamon\",\"milk\",\"double cream\",\"eggs\",\"sugar\",\"nutmeg\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Grease a 1 litre/2 pint pie dish with butter.\\r\\nCut the crusts off the bread. Spread each slice with on one side with butter, then cut into triangles.\\r\\nArrange a\",\"instructions\":[\"Grease a 1 litre/2 pint pie dish with butter.\",\"Cut the crusts off the bread. Spread each slice with on one side with butter, then cut into triangles.\",\"Arrange a layer of bread, buttered-side up, in the bottom of the dish, then add a layer of sultanas. Sprinkle with a little cinnamon, then repeat the layers of bread and sultanas, sprinkling with cinnamon, until you have used up all of the bread. Finish with a layer of bread, then set aside.\",\"Gently warm the milk and cream in a pan over a low heat to scalding point. Don't let it boil.\",\"Crack the eggs into a bowl, add three quarters of the sugar and lightly whisk until pale.\",\"Add the warm milk and cream mixture and stir well, then strain the custard into a bowl.\",\"Pour the custard over the prepared bread layers and sprinkle with nutmeg and the remaining sugar and leave to stand for 30 minutes.\",\"Preheat the oven to 180C/355F/Gas 4.\",\"Place the dish into the oven and bake for 30-40 minutes, or until the custard has set and the top is golden-brown.\"]},{\"id\":\"g76\",\"title\":\"Bread omelette\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hqaejl1695738653.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Bread\",\"Egg\",\"Salt\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Make and enjoy\",\"instructions\":[\"Make and enjoy.\"]},{\"id\":\"g77\",\"title\":\"Breakfast Potatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1550441882.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Olive Oil\",\"Bacon\",\"Garlic Clove\",\"Maple Syrup\",\"Parsley\",\"Salt\",\"Pepper\",\"Allspice\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Before you do anything, freeze your bacon slices that way when you're ready to prep, it'll be so much easier to chop!\\r\\nWash the potatoes and cut medium dice int\",\"instructions\":[\"Before you do anything, freeze your bacon slices that way when you're ready to prep, it'll be so much easier to chop!\",\"Wash the potatoes and cut medium dice into square pieces. To prevent any browning, place the already cut potatoes in a bowl filled with water.\",\"In the meantime, heat 1-2 tablespoons of oil in a large skillet over medium-high heat. Tilt the skillet so the oil spreads evenly.\",\"Once the oil is hot, drain the potatoes and add to the skillet. Season with salt, pepper, and Old Bay as needed.\",\"Cook for 10 minutes, stirring the potatoes often, until brown. If needed, add a tablespoon more of oil.\",\"Chop up the bacon and add to the potatoes. The bacon will start to render and the fat will begin to further cook the potatoes. Toss it up a bit! The bacon will take 5-6 minutes to crisp.\",\"Once the bacon is cooked, reduce the heat to medium-low, add the minced garlic and toss. Season once more. Add dried or fresh parsley. Control heat as needed.\",\"Let the garlic cook until fragrant, about one minute.\",\"Just before serving, drizzle over the maple syrup and toss. Let that cook another minute, giving the potatoes a caramelized effect.\",\"Serve in a warm bowl with a sunny side up egg!\"]},{\"id\":\"g78\",\"title\":\"Brie wrapped in prosciutto & brioche\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qqpwsy1511796276.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Caster Sugar\",\"Yeast\",\"Milk\",\"Eggs\",\"Eggs\",\"Butter\",\"Brie\",\"Prosciutto\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix the flour, 1 tsp salt, caster sugar, yeast, milk and eggs together in a mixer using the dough attachment for 5 mins until the dough is smooth. Add the butte\",\"instructions\":[\"Mix the flour, 1 tsp salt, caster sugar, yeast, milk and eggs together in a mixer using the dough attachment for 5 mins until the dough is smooth. Add the butter and mix for a further 4 mins on medium speed. Scrape the dough bowl and mix again for 1 min. Place the dough in a container, cover with cling film and leave in the fridge for at least 6 hrs before using.\",\"Wrap the Brie in the prosciutto and set aside. Turn out the dough onto a lightly floured surface. Roll into a 25cm circle. Place the wrapped Brie in the middle of the circle and fold the edges in neatly. Put the parcel onto a baking tray lined with baking parchment and brush with beaten egg. Chill in the fridge for 30 mins, then brush again with beaten egg and chill for a further 30 mins. Leave to rise for 1 hr at room temperature. Heat oven to 200C/180C fan/gas 6, then bake for 22 mins. Serve warm.\"]},{\"id\":\"g79\",\"title\":\"Broccoli & Stilton soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tvvxpv1511191952.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rapeseed Oil\",\"Onion\",\"Celery\",\"Leek\",\"Potatoes\",\"Butter\",\"Vegetable Stock\",\"Broccoli\",\"Stilton Cheese\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Heat the rapeseed oil in a large saucepan and then add the onions. Cook on a medium heat until soft. Add a splash of water if the onions start to catch.\\r\\n\\r\\nAdd \",\"instructions\":[\"Heat the rapeseed oil in a large saucepan and then add the onions. Cook on a medium heat until soft. Add a splash of water if the onions start to catch.\",\"Add the celery, leek, potato and a knob of butter. Stir until melted, then cover with a lid. Allow to sweat for 5 minutes. Remove the lid.\",\"Pour in the stock and add any chunky bits of broccoli stalk. Cook for 10 – 15 minutes until all the vegetables are soft.\",\"Add the rest of the broccoli and cook for a further 5 minutes. Carefully transfer to a blender and blitz until smooth. Stir in the stilton, allowing a few lumps to remain. Season with black pepper and serve.\"]},{\"id\":\"g80\",\"title\":\"Brown Stew Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sypxpx1515365095.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Tomato\",\"Onions\",\"Garlic Clove\",\"Red Pepper\",\"Carrots\",\"Lime\",\"Thyme\",\"Allspice\",\"Soy Sauce\",\"Cornstarch\",\"Coconut Milk\",\"Vegetable Oil\"],\"allergens\":[\"milk\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Squeeze lime over chicken and rub well. Drain off excess lime juice.\\r\\nCombine tomato, scallion, onion, garlic, pepper, thyme, pimento and soy sauce in a large b\",\"instructions\":[\"Squeeze lime over chicken and rub well. Drain off excess lime juice.\",\"Combine tomato, scallion, onion, garlic, pepper, thyme, pimento and soy sauce in a large bowl with the chicken pieces. Cover and marinate at least one hour.\",\"Heat oil in a dutch pot or large saucepan. Shake off the seasonings as you remove each piece of chicken from the marinade. Reserve the marinade for sauce.\",\"Lightly brown the chicken a few pieces at a time in very hot oil. Place browned chicken pieces on a plate to rest while you brown the remaining pieces.\",\"Drain off excess oil and return the chicken to the pan. Pour the marinade over the chicken and add the carrots. Stir and cook over medium heat for 10 minutes.\",\"Mix flour and coconut milk and add to stew, stirring constantly. Turn heat down to minimum and cook another 20 minutes or until tender.\"]},{\"id\":\"g81\",\"title\":\"Brun Lapskaus (Norwegian Beef Vegetable Stew)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6vi2cv1763075785.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Beef\",\"Onion\",\"Beef Stock\",\"Swede\",\"Celery\",\"Carrots\",\"Parsley\",\"Potatoes\",\"Leek\",\"Parsley\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"▢\\r\\nHeat olive oil in a large pot. Cut beef into 1 inch (2.5 cm) cubes and brown in oil.\\r\\n▢\\r\\nDice the onion and add to browning beef. Add the stock and bring to \",\"instructions\":[\"▢\",\"Heat olive oil in a large pot. Cut beef into 1 inch (2.5 cm) cubes and brown in oil.\",\"▢\",\"Dice the onion and add to browning beef. Add the stock and bring to a boil, then lower the heat, cover, and let simmer for about 30 minutes.\",\"▢\",\"Peel and cut the rutabaga and celery root into 1 inch (2.5 cm) cubes. Add to the pot, cover, and continue simmering for another 30 minutes.\",\"▢\",\"Peel and chop the rest of the vegetables into 1 inch (2.5 cm) cubes and add to the pot. Slice the leek into rings. Cover and continue simmering for about 20 minutes. Stir as little as possible.\",\"▢\",\"Top with fresh parsley.\"]},{\"id\":\"g82\",\"title\":\"Bryndzové Halušky\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/g33c901763365484.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Plain Flour\",\"Egg\",\"Salt\",\"Bryndza cheese\",\"Bacon\",\"Chives\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1. Prepare the Dough\\r\\nGrate the potatoes finely using a hand grater or food processor. Place the grated potatoes in a bowl and mix them with flour, egg, and sal\",\"instructions\":[\"1. Prepare the Dough\",\"Grate the potatoes finely using a hand grater or food processor. Place the grated potatoes in a bowl and mix them with flour, egg, and salt until a sticky dough forms. The consistency should be thick but pliable.\",\"2. Cook the Dumplings\",\"Bring a large pot of salted water to a boil. Using a halušky maker (similar to a spaetzle maker), press the dough directly into the boiling water. If you don’t have one, use a tilted cutting board and a knife to scrape small pieces of dough into the water.\",\"Let the dumplings cook until they float to the surface, usually within 2-3 minutes. Scoop them out with a slotted spoon and set aside in a large bowl.\",\"3. Prepare the Toppings\",\"Chop the bacon into small pieces and fry in a skillet over medium heat until crispy. If using a bryndza substitute, mix crumbled feta with a dollop of sour cream to mimic the tangy flavour of traditional Slovak sheep cheese.\",\"4. Assemble the Dish\",\"Toss the cooked dumplings with the bryndza cheese (or substitute) until they’re well-coated and creamy. Top with the crispy bacon and its drippings. Garnish with chopped chives or parsley for an extra touch of colour and flavour.\"]},{\"id\":\"g83\",\"title\":\"Budino Di Ricotta\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1549542877.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ricotta\",\"Eggs\",\"Flour\",\"Sugar\",\"Cinnamon\",\"Lemons\",\"Dark Rum\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mash the ricotta and beat well with the egg yolks, stir in the flour, sugar, cinnamon, grated lemon rind and the rum and mix well. You can do this in a food pro\",\"instructions\":[\"Mash the ricotta and beat well with the egg yolks, stir in the flour, sugar, cinnamon, grated lemon rind and the rum and mix well. You can do this in a food processor. Beat the egg whites until stiff, fold in and pour into a buttered and floured 25cm cake tin. Bake in the oven at 180ºC/160ºC fan/gas 4 for about 40 minutes, or until it is firm.\",\"Serve hot or cold dusted with icing sugar.\"]},{\"id\":\"g84\",\"title\":\"Burek\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tkxquw1628771028.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Filo Pastry\",\"Minced Beef\",\"Onion\",\"Oil\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Fry the finely chopped onions and minced meat in oil. Add the salt and pepper. Grease a round baking tray and put a layer of pastry in it. Cover with a thin lay\",\"instructions\":[\"Fry the finely chopped onions and minced meat in oil.\",\"Add the salt and pepper.\",\"Grease a round baking tray and put a layer of pastry in it.\",\"Cover with a thin layer of filling and cover this with another layer of filo pastry which must be well coated in oil.\",\"Put another layer of filling and cover with pastry.\",\"When you have five or six layers, cover with filo pastry, bake at 200ºC/392ºF for half an hour and cut in quarters and serve.\"]},{\"id\":\"g85\",\"title\":\"Cabbage Soup (Shchi)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/60oc3k1699009846.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Unsalted Butter\",\"Onion\",\"Cabbage\",\"Carrots\",\"Celery\",\"Bay Leaf\",\"Vegetable Stock\",\"Potatoes\",\"Tomatoes\",\"Sour Cream\",\"Dill\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Add the butter to a large Dutch oven or other heavy-duty pot over medium heat. When the butter has melted, add the onion and sauté until translucent.\\r\\nAdd the c\",\"instructions\":[\"Add the butter to a large Dutch oven or other heavy-duty pot over medium heat. When the butter has melted, add the onion and sauté until translucent.\",\"Add the cabbage, carrot, and celery. Sauté until the vegetables begin to soften, stirring frequently, about 3 minutes.\",\"Add the bay leaf and vegetable stock and bring to a boil over high heat. Reduce the heat to low and simmer, covered, until the vegetables are crisp-tender, about 15 minutes.\",\"Add the potatoes and bring it back to a boil over high heat. Reduce the heat to low and simmer, covered, until the potatoes are tender, about 10 minutes.\",\"Add the tomatoes (or undrained canned tomatoes) and bring the soup back to a boil over high heat. Reduce the heat to low and simmer, uncovered, for 5 minutes. Season to taste with salt and pepper.\",\"emove and discard the bay leaf from the pot.\",\"Serve topped with fresh sour cream and fresh dill.\"]},{\"id\":\"g86\",\"title\":\"Cacik\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/16zbeu1763789342.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Natural Yoghurt\",\"Lemon Juice\",\"Extra Virgin Olive Oil\",\"Dried Mint\",\"Cucumber\",\"Garlic\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut a sieve over a large bowl, line it with a thick sheet of non-dyed kitchen paper or a clean muslin cloth, and spoon in the yogurt. Cover with another\",\"instructions\":[\"step 1\",\"Put a sieve over a large bowl, line it with a thick sheet of non-dyed kitchen paper or a clean muslin cloth, and spoon in the yogurt. Cover with another sheet of kitchen paper and leave to strain in the fridge for a minimum of 12 hrs.\",\"step 2\",\"Add the lemon juice, most of the olive oil and the dried mint to a bowl and stir well for the dried mint to soften and soak up the juices. Mix in the strained yogurt, then pour away the strained yogurt liquid and leave that bowl to one side.\",\"step 3\",\"Halve the cucumber(s) lengthways and remove the seeds by running a teaspoon from the top to the bottom of the flesh, halve the cucumbers widthways to make them shorter and easier to handle, then coarsely grate each one into the bowl the yogurt was straining over. Using clean hands (or a clean muslin cloth), squeeze as much of the liquid out of the cucumber as possible.\",\"step 4\",\"Add the strained, grated cucumber, garlic and ¾ tsp flaky salt to the rest of the ingredients and mix well. Garnish with a drizzle of extra virgin olive oil and a sprinkling of dried mint.\"]},{\"id\":\"g87\",\"title\":\"Cajun spiced fish tacos\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uvuyxu1503067369.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"cajun\",\"cayenne pepper\",\"white fish\",\"vegetable oil\",\"flour tortilla\",\"avocado\",\"little gem lettuce\",\"Spring Onions\",\"salsa\",\"sour cream\",\"lemon\",\"garlic\"],\"allergens\":[\"milk\",\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cooking in a cajun spice and cayenne pepper marinade makes this fish super succulent and flavoursome. Top with a zesty dressing and serve in a tortilla for a qu\",\"instructions\":[\"Cooking in a cajun spice and cayenne pepper marinade makes this fish super succulent and flavoursome. Top with a zesty dressing and serve in a tortilla for a quick, fuss-free main that's delightfully summery.\",\"On a large plate, mix the cajun spice and cayenne pepper with a little seasoning and use to coat the fish all over.\",\"Heat a little oil in a frying pan, add in the fish and cook over a medium heat until golden. Reduce the heat and continue frying until the fish is cooked through, about 10 minutes. Cook in batches if you don’t have enough room in the pan.\",\"Meanwhile, prepare the dressing by combining all the ingredients with a little seasoning.\",\"Soften the tortillas by heating in the microwave for 5-10 seconds. Pile high with the avocado, lettuce and spring onion, add a spoonful of salsa, top with large flakes of fish and drizzle over the dressing.\"]},{\"id\":\"g88\",\"title\":\"Callaloo and SaltFish\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/73o3vq1765317873.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Salt Cod\",\"Bacon\",\"Callaloo\",\"Onion\",\"Spring Onions\",\"Garlic\",\"Scotch Bonnet\",\"Plum Tomatoes\",\"Thyme\",\"Black Pepper\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Soak salted fish in water overnight. Next, heat salted fish in water on stove until water boils. You should see a foam on top. Remove from heat and drain. Set a\",\"instructions\":[\"Soak salted fish in water overnight. Next, heat salted fish in water on stove until water boils. You should see a foam on top. Remove from heat and drain. Set aside and shred salted fish once it cools.\",\"Cook bacon in skillet over medium heat until crispy. Remove bacon from heat and drain the majority of the bacon grease, leaving about 1 tablespoon in the skillet.\",\"Add yellow onion, green onion, scotch bonnet pepper, and garlic to the skillet and stir. Cook for about 2 minutes or until onions soften. Add salted fish to skillet and stir. Cook for about a minute.\",\"Next, add callaloo, roma tomatoes, thyme, and black pepper. Stir to combine and cook until heated through, about 2 minutes.\",\"Enjoy\"]},{\"id\":\"g89\",\"title\":\"Callaloo Jamaican Style\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ussyxw1515364536.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Kale\",\"Bacon\",\"Garlic\",\"Onion\",\"Paprika\",\"Thyme\",\"Tomato\",\"Red Pepper\",\"Banana\",\"Vegetable Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Cut leaves and soft stems from the kale branches, them soak in a bowl of cold water for about 5-10 minutes or until finish with prep.\\r\\nProceed to slicing the on\",\"instructions\":[\"Cut leaves and soft stems from the kale branches, them soak in a bowl of cold water for about 5-10 minutes or until finish with prep.\",\"Proceed to slicing the onions, mincing the garlic and dicing the tomatoes. Set aside\",\"Remove kale from water cut in chunks.\",\"Place bacon on saucepan and cook until crispy. Then add onions, garlic, thyme, stir for about a minute or more\",\"Add tomatoes; scotch bonnet pepper, smoked paprika. Sauté for about 2-3 more minutes.\",\"Finally add vegetable, salt, mix well, and steamed for about 6-8 minutes or until leaves are tender. Add a tiny bit of water as needed. Adjust seasonings and turn off the heat.\",\"Using a sharp knife cut both ends off the plantain. This will make it easy to grab the skin of the plantains. Slit a shallow line down the long seam of the plantain; peel only as deep as the peel. Remove plantain peel by pulling it back.\",\"Slice the plantain into medium size lengthwise slices and set aside.\",\"Coat a large frying pan with cooking oil spray. Spray the tops of the plantains with a generous layer of oil spray and sprinkle with salt, freshly ground pepper.\",\"Let the plantains \\\"fry\\\" on medium heat, shaking the frying pan to redistribute them every few minutes.\"]},{\"id\":\"g90\",\"title\":\"Canadian Butter Tarts\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wpputp1511812960.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Shortcrust Pastry\",\"Eggs\",\"Muscovado Sugar\",\"Raisins\",\"Vanilla Extract\",\"Butter\",\"Single Cream\",\"Walnuts\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to fan 170C/ conventional 190C/gas 5. Roll out the pastry on a lightly floured surface so it’s slightly thinner than straight from the pack. Th\",\"instructions\":[\"Preheat the oven to fan 170C/ conventional 190C/gas 5. Roll out the pastry on a lightly floured surface so it’s slightly thinner than straight from the pack. Then cut out 18-20 rounds with a 7.5cm fluted cutter, re-rolling the trimmings. Use the rounds to line two deep 12-hole tart tins (not muffin tins). If you only have a regular-sized, 12-hole tart tin you will be able to make a few more slightly shallower tarts.\",\"Beat the eggs in a large bowl and combine with the rest of the ingredients except the walnuts. Tip this mixture into a pan and stir continuously for 3-4 minutes until the butter melts, and the mixture bubbles and starts to thicken. It should be thick enough to coat the back of a wooden spoon. Don’t overcook, and be sure to stir all the time as the mixture can easily burn. Remove from the heat and stir in the nuts.\",\"Spoon the filling into the unbaked tart shells so it’s level with the pastry. Bake for 15-18 minutes until set and pale golden. Leave in the tin to cool for a few minutes before lifting out on to a wire rack. Serve warm or cold.\"]},{\"id\":\"g91\",\"title\":\"Carbonada Criolla\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8b2msz1763074897.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Onion\",\"Carrots\",\"Potatoes\",\"Pumpkin\",\"Dried Apricots\",\"Beef Stock\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Brown the Beef: In a large pot, brown the beef cubes. Remove and set aside.\\r\\nSauté Vegetables: In the same pot, cook the onion until translucent. Add carrots, p\",\"instructions\":[\"Brown the Beef: In a large pot, brown the beef cubes. Remove and set aside.\",\"Sauté Vegetables: In the same pot, cook the onion until translucent. Add carrots, potatoes, and pumpkin, cooking for a few minutes.\",\"Simmer: Return the beef to the pot. Add broth and dried apricots. Season with salt and pepper. Simmer for 1-2 hours, until the beef is tender.\",\"Serve: Enjoy hot, with a crusty piece of bread.\",\"Pro Tips:\",\"Brown the beef in batches to ensure it gets a good sear, which adds depth to the stew's flavor.\",\"Adding the fruits towards the end of cooking preserves their texture and adds a subtle sweetness to the dish.\"]},{\"id\":\"g92\",\"title\":\"Caribbean Tamarind balls\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/z1hz7z1765316430.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tamarind Pulp\",\"Sugar\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Add tamarind pulp and 1 cup granulated sugar to a bowl and mash together with a spoon or fork. Take small amounts of the tamarind and sugar mix and shape them i\",\"instructions\":[\"Add tamarind pulp and 1 cup granulated sugar to a bowl and mash together with a spoon or fork. Take small amounts of the tamarind and sugar mix and shape them into small balls by rolling them in your hands. Make them the size of a marble or slightly bigger, as you like.\",\"Add the remaining sugar to a flat surface, like a plate or a sheet pan. Roll the tamarind balls in granulated sugar until they're well-coated.\",\"You can eat the tamarind balls immediately, or you can let them set for a few hours or overnight. Allowing them to set will give them a firmer texture and more crystallized sugar coating. Enjoy.\"]},{\"id\":\"g93\",\"title\":\"Carrot Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vrspxv1511722107.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Plain Flour\",\"Bicarbonate Of Soda\",\"Sugar\",\"Eggs\",\"Salt\",\"Cinnamon\",\"Carrots\",\"Walnuts\",\"Cream Cheese\",\"Caster Sugar\",\"Butter\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the carrot cake, preheat the oven to 160C/325F/Gas 3. Grease and line a 26cm/10in springform cake tin.\\r\\nMix all of the ingredients for the carrot cake, exce\",\"instructions\":[\"For the carrot cake, preheat the oven to 160C/325F/Gas 3. Grease and line a 26cm/10in springform cake tin.\",\"Mix all of the ingredients for the carrot cake, except the carrots and walnuts, together in a bowl until well combined. Stir in the carrots and walnuts.\",\"Spoon the mixture into the cake tin and bake for 1 hour 15 minutes, or until a skewer inserted into the middle comes out clean. Remove the cake from the oven and set aside to cool for 10 minutes, then carefully remove the cake from the tin and set aside to cool completely on a cooling rack.\",\"Meanwhile, for the icing, beat the cream cheese, caster sugar and butter together in a bowl until fluffy. Spread the icing over the top of the cake with a palette knife.\"]},{\"id\":\"g94\",\"title\":\"Cashew Ghoriba Biscuits\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/t3r3ka1560461972.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cashew Nuts\",\"Icing Sugar\",\"Egg Yolks\",\"Orange Blossom Water\",\"Icing Sugar\",\"Almonds\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven at 180 C / Gas 4. Line a baking tray with greaseproof paper.\\r\\nIn a bowl, mix the cashews and icing sugar. Add the egg yolks and orange blossom \",\"instructions\":[\"Preheat the oven at 180 C / Gas 4. Line a baking tray with greaseproof paper.\",\"In a bowl, mix the cashews and icing sugar. Add the egg yolks and orange blossom water and mix to a smooth homogeneous paste.\",\"Take lumps of the cashew paste and shape into small balls. Roll the balls in icing sugar and transfer to the baking tray. Push an almond in the centre of each ghribia.\",\"Bake until the biscuits are lightly golden, about 20 minutes. Keep an eye on them, they burn quickly.\"]},{\"id\":\"g95\",\"title\":\"Cassava pizza\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lrfdwz1764438393.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Casabe\",\"Tomato Sauce\",\"Chorizo\",\"Turkey Ham\",\"Sweetcorn\",\"Green Olives\",\"Paprika\",\"Mozzarella\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 200ºC.\\r\\nCut the bacon or chorizo into medium pieces and the paprika into strips.\\r\\nSpread a little tomato sauce and mozzarella cheese on each\",\"instructions\":[\"Preheat the oven to 200ºC.\",\"Cut the bacon or chorizo into medium pieces and the paprika into strips.\",\"Spread a little tomato sauce and mozzarella cheese on each portion of cassava.\",\"Add the bacon or chorizo, corn, turkey ham, some olives and paprika.\",\"Bake for 7 to 10 minutes.\",\"Remove from the oven and enjoy.\"]},{\"id\":\"g96\",\"title\":\"Cevapi Sausages\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vc08jn1628769553.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Minced Beef\",\"Minced Pork\",\"Onion\",\"Garlic\",\"Parsley\",\"Paprika\",\"Baking Powder\",\"Breadcrumbs\",\"Water\",\"Vegetable Stock Cube\",\"Salt\",\"Pepper\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Place the ground meat in a bowl. Chop the onion very finely and grate the garlic cloves. Add to the bowl. Add the chopped parsley, all sorts of paprika, baking \",\"instructions\":[\"Place the ground meat in a bowl. Chop the onion very finely and grate the garlic cloves. Add to the bowl. Add the chopped parsley, all sorts of paprika, baking soda, dried breadcrumbs, water, Vegeta, salt, and pepper.\",\"Mix well with the hand mixer fitted with the dough hooks. Cover the bowl with cling film/ plastic foil and leave to rest for 1 or 2 hours in the refrigerator.\",\"Take portions of the meat mixture, about 50-55 g/ 1.7-1.9 oz/ ¼ cup portions, and form the cevapi. The rolls should be about as thick as your thumb and about 7-10 cm/ 3-4 inches long. I had 18 sausages. The recipe can be easily doubled.\",\"Grill the cevapcici on the hot grill pan or on the barbecue for about 12-14 minutes, turning them several times in between, or until brown and cooked through. I checked by cutting one in the middle and then grilling the following batches for the same period of time.\",\"Serve hot as suggested above. The cevapcici can be reheated in the oven at 180 degrees Celsius/ 350 degrees Fahrenheit for about 10 minutes or until heated through. Check one, if it is not hot enough, give the sausages a few more minutes.\"]},{\"id\":\"g97\",\"title\":\"Chakchouka\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/gpz67p1560458984.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tomatoes\",\"Olive Oil\",\"Onion\",\"Red Pepper\",\"Green Pepper\",\"Garlic\",\"Cumin\",\"Paprika\",\"Salt\",\"Chili Powder\",\"Eggs\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a large cast iron skillet or sauté pan with a lid, heat oil over medium high heat. Add the onion and sauté for 2-3 minutes, until softened. Add the peppers a\",\"instructions\":[\"In a large cast iron skillet or sauté pan with a lid, heat oil over medium high heat.\",\"Add the onion and sauté for 2-3 minutes, until softened.\",\"Add the peppers and garlic, and sauté for an additional 3-5 minutes.\",\"Add the tomatoes, cumin, paprika, salt, and chili powder.\",\"Mix well and bring the mixture to a simmer.\",\"Reduce the heat to medium low and continue to simmer, uncovered, 10-15 minutes until the mixture has thickened to your desired consistency.\",\"(Taste the sauce at this point and adjust for salt and spice, as desired.) Using the back of a spoon, make four craters in the mixture, large enough to hold an egg.\",\"Crack one egg into each of the craters.\",\"Cover the skillet and simmer for 5-7 minutes, until the eggs have set.\",\"Serve immediately with crusty bread or pita.\"]},{\"id\":\"g98\",\"title\":\"Challah\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/fm01ky1764366365.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Strong white bread flour\",\"Caster Sugar\",\"Yeast\",\"Egg\",\"Sunflower Oil\",\"Poppy Seeds\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nCombine the yeast, a pinch of the sugar and a couple tablespoons of lukewarm water in a small bowl. Stir to dissolve the yeast, then leave for 10 mins u\",\"instructions\":[\"step 1\",\"Combine the yeast, a pinch of the sugar and a couple tablespoons of lukewarm water in a small bowl. Stir to dissolve the yeast, then leave for 10 mins until foamy.\",\"step 2\",\"Meanwhile, combine the flour, the remaining sugar and 2 tsp fine salt in a large bowl. Make a well in the centre, then add half the beaten egg, the yeast mixture and the oil. Pour in 200ml lukewarm water (it should feel slightly warm to the touch) and stir with a spoon, then mix using one hand, keeping the other clean while you bring the dough together. If there are a lot of very dry bits, gradually add a little water to just bring it together – you don't want it to get too wet and sticky. The dough should be moist, but not soggy.\",\"step 3\",\"Once the dough has come together, turn it out onto a lightly floured surface. Knead using both hands for 10 mins until smooth and a bit springy. If it gets very sticky, add a very small amount of flour – as little as possible. A dough scraper is useful if the dough is sticking to the work surface. Stretch the sides of the dough down and pull together to form a ball. Lightly oil a bowl, then lightly roll the dough ball around the bowl so it's coated in the oil. Cover with a clean tea towel and leave in a warm place for 1 hr, or until dough has doubled in size.\",\"step 4\",\"Line a baking sheet with baking parchment. Turn the dough out onto a clean work surface and divide into three equal pieces, weighing for accuracy, if you like. Roll each piece into a long sausage shape about 25cm long, tapering them slightly at both ends. Lay the pieces out in front of you, parallel to one another with a couple centimetres between each. Bring the sausages together at the top end, then plait them down the length, tucking in the ends when you reach the bottom. Carefully transfer the loaf to the prepared baking sheet and loosely cover with a clean tea towel. Leave to rise until puffy and billowy, about 40 mins.\",\"step 5\",\"Meanwhile, heat the oven to 200C/180C fan/gas 6. Gently brush the rest of the beaten egg all over the challah, getting it into all the crevices, and sprinkle with the poppy or sesame seeds, if using. Bake on a middle shelf of the oven for 25-30 mins, until the loaf is golden brown underneath and sounds hollow when tapped. Check after about 15 mins – if the top of the loaf has started to get too dark, cover it with foil. Leave to cool on a wire rack, then serve.\"]},{\"id\":\"g99\",\"title\":\"Cheese Borek\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/oal8x31764119345.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Parsley\",\"Garlic\",\"Red Pepper\",\"Gouda Cheese\",\"Emmentaler Cheese\",\"Phyllo Dough\",\"Unsalted Butter\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a medium bowl, whisk together egg, parsley, garlic and crushed red pepper. Mix in Gouda and Emmentaler.\\r\\n\\r\\nOne sheet at a time, place phyllo dough on a flat \",\"instructions\":[\"In a medium bowl, whisk together egg, parsley, garlic and crushed red pepper. Mix in Gouda and Emmentaler.\",\"One sheet at a time, place phyllo dough on a flat surface and brush with about 1 tablespoon butter. Cut lengthwise into 4 strips. Place a rounded teaspoon of the egg mixture at one end of each strip. Fold corner of strip over the filling, forming a triangular fold. Continue folding the length of the strip in triangular folds to form a small stuffed triangle. Repeat with remaining phyllo dough.\",\"Preheat oven to 350 degrees F (175 degrees C). Lightly butter a large baking sheet.\",\"Arrange stuffed phyllo triangles in a single layer on the prepared baking sheet. Bake in the preheated oven 30 minutes, or until lightly browned. Serve warm\"]},{\"id\":\"g100\",\"title\":\"Chelsea Buns\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vqpwrv1511723001.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"White Flour\",\"Salt\",\"Yeast\",\"Milk\",\"Butter\",\"Eggs\",\"Vegetable Oil\",\"Butter\",\"Brown Sugar\",\"Cinnamon\",\"Dried Fruit\",\"Milk\",\"Caster Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Sift the flour and salt into a large bowl. Make a well in the middle and add the yeast.\\r\\nMeanwhile, warm the milk and butter in a saucepan until the butter melt\",\"instructions\":[\"Sift the flour and salt into a large bowl. Make a well in the middle and add the yeast.\",\"Meanwhile, warm the milk and butter in a saucepan until the butter melts and the mixture is lukewarm.\",\"Add the milk mixture and egg to the flour mixture and stir until the contents of the bowl come together as a soft dough. (You may need to add a little extra flour.)\",\"Tip the dough onto a generously floured work surface. Knead for five minutes, adding more flour if necessary, until the dough is smooth and elastic and no longer feels sticky.\",\"Lightly oil a bowl with a little of the vegetable oil. Place the dough into the bowl and turn until it is covered in the oil. Cover the bowl with cling film and set aside in a warm place for one hour, or until the dough has doubled in size.\",\"Lightly grease a baking tray.\",\"For the filling, knock the dough back to its original size and turn out onto a lightly floured work surface. Roll the dough out into a rectangle 0.5cm/¼in thick. Brush all over with the melted butter, then sprinkle over the brown sugar, cinnamon and dried fruit.\",\"Roll the dough up into a tight cylinder , cut ten 4cm/1½in slice and place them onto a lightly greased baking sheet, leaving a little space between each slice. Cover with a tea towel and set aside to rise for 30 minutes.\",\"Preheat oven to 190C/375F/Gas 5.\",\"Bake the buns in the oven for 20-25 minutes, or until risen and golden-brown.\"]},{\"id\":\"g101\",\"title\":\"Chick-Fil-A Sandwich\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sbx7n71587673021.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breast\",\"Pickle Juice\",\"Egg\",\"Milk\",\"Flour\",\"Icing Sugar\",\"Paprika\",\"Salt\",\"Black Pepper\",\"Garlic Powder\",\"Celery Salt\",\"Cayenne Pepper\",\"Olive Oil\",\"Sesame Seed Burger Buns\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Wrap the chicken loosely between plastic wrap and pound gently with the flat side of a meat tenderizer until about 1/2 inch thick all around.\\r\\nCut into two piec\",\"instructions\":[\"Wrap the chicken loosely between plastic wrap and pound gently with the flat side of a meat tenderizer until about 1/2 inch thick all around.\",\"Cut into two pieces, as even as possible.\",\"Marinate in the pickle juice for 30 minutes to one hour (add a teaspoon of Tabasco sauce now for a spicy sandwich).\",\"Beat the egg with the milk in a bowl.\",\"Combine the flour, sugar, and spices in another bowl.\",\"Dip the chicken pieces each into the egg on both sides, then coat in flour on both sides.\",\"Heat the oil in a skillet (1/2 inch deep) to about 345-350.\",\"Fry each cutlet for 2 minutes on each side, or until golden and cooked through.\",\"Blot on paper and serve on toasted buns with pickle slices.\"]},{\"id\":\"g102\",\"title\":\"Chicken & chorizo rice pot\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/fk80jp1763280767.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Oil\",\"Chicken\",\"Onion\",\"Red Pepper\",\"Garlic\",\"Chorizo\",\"Tomato Puree\",\"Thyme\",\"White Wine\",\"Chicken Stock\",\"Rice\",\"Parsley\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oil in a large flameproof casserole dish and brown the chicken pieces on all sides – you may have to do this in batches. Remove from the dish a\",\"instructions\":[\"step 1\",\"Heat the oil in a large flameproof casserole dish and brown the chicken pieces on all sides – you may have to do this in batches. Remove from the dish and put to one side.\",\"step 2\",\"Lower the heat, add the onion and pepper, and gently cook for 10 mins until softened. Add the garlic and chorizo, and cook for a further 2 mins until the chorizo has released some of its oils into the dish. Stir in the tomato purée and cook for 1 min more.\",\"step 3\",\"Return the chicken pieces to the dish along with the thyme, white wine and stock. Bring the liquid to a boil, cover the dish with a tight-fitting lid and lower the heat. Cook for 30 mins.\",\"step 4\",\"Tip in the rice and stir everything together. Cover, set over a low heat and cook for a further 15 mins, or until the rice is cooked and has absorbed most of the cooking liquid. Remove from the heat and leave the dish to sit for 10 mins to absorb any remaining liquid. Season to taste and scatter with parsley to serve.\"]},{\"id\":\"g103\",\"title\":\"Chicken & mushroom Hotpot\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uuuspp1511297945.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Onion\",\"Mushrooms\",\"Plain Flour\",\"Chicken Stock Cube\",\"Nutmeg\",\"Mustard Powder\",\"Chicken\",\"Sweetcorn\",\"Potatoes\",\"Butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 200C/180C fan/gas 6. Put the butter in a medium-size saucepan and place over a medium heat. Add the onion and leave to cook for 5 mins, stirring oc\",\"instructions\":[\"Heat oven to 200C/180C fan/gas 6. Put the butter in a medium-size saucepan and place over a medium heat. Add the onion and leave to cook for 5 mins, stirring occasionally. Add the mushrooms to the saucepan with the onions.\",\"Once the onion and mushrooms are almost cooked, stir in the flour – this will make a thick paste called a roux. If you are using a stock cube, crumble the cube into the roux now and stir well. Put the roux over a low heat and stir continuously for 2 mins – this will cook the flour and stop the sauce from having a floury taste.\",\"Take the roux off the heat. Slowly add the fresh stock, if using, or pour in 500ml water if you’ve used a stock cube, stirring all the time. Once all the liquid has been added, season with pepper, a pinch of nutmeg and mustard powder. Put the saucepan back onto a medium heat and slowly bring it to the boil, stirring all the time. Once the sauce has thickened, place on a very low heat. Add the cooked chicken and vegetables to the sauce and stir well. Grease a medium-size ovenproof pie dish with a little butter and pour in the chicken and mushroom filling.\",\"Carefully lay the potatoes on top of the hot-pot filling, overlapping them slightly, almost like a pie top.\",\"Brush the potatoes with a little melted butter and cook in the oven for about 35 mins. The hot-pot is ready once the potatoes are cooked and golden brown.\"]},{\"id\":\"g104\",\"title\":\"Chicken Alfredo Primavera\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/syqypv1486981727.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Olive Oil\",\"Chicken\",\"Salt\",\"Squash\",\"Broccoli\",\"mushrooms\",\"Pepper\",\"onion\",\"garlic\",\"red pepper flakes\",\"white wine\",\"milk\",\"heavy cream\",\"Parmesan cheese\",\"bowtie pasta\",\"Salt\",\"Pepper\",\"Parsley\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat 1 tablespoon of butter and 2 tablespoons of olive oil in a large skillet over medium-high heat. Season both sides of each chicken breast with seasoned salt\",\"instructions\":[\"Heat 1 tablespoon of butter and 2 tablespoons of olive oil in a large skillet over medium-high heat.\",\"Season both sides of each chicken breast with seasoned salt and a pinch of pepper.\",\"Add the chicken to the skillet and cook for 5-7 minutes on each side, or until cooked through.\",\"While the chicken is cooking, bring a large pot of water to a boil.\",\"Season the boiling water with a few generous pinches of kosher salt.\",\"Add the pasta and give it a stir.\",\"Cook, stirring occasionally, until al dente, about 12 minutes.\",\"Reserve 1/2 cup of  pasta water before draining the pasta.\",\"Remove the chicken from the pan and transfer it to a cutting board; allow it to rest.\",\"Turn the heat down to medium and dd the remaining 1 tablespoon of butter and olive oil to the same pan you used to cook the chicken.\"]},{\"id\":\"g105\",\"title\":\"Chicken Basquaise\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wruvqv1511880994.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Butter\",\"Olive Oil\",\"Red Onions\",\"Red Pepper\",\"Chorizo\",\"Sun-Dried Tomatoes\",\"Garlic\",\"Basmati Rice\",\"Tomato Puree\",\"Paprika\",\"Bay Leaves\",\"Thyme\",\"Chicken Stock\",\"Dry White Wine\",\"Lemons\",\"Black Olives\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 180°C/Gas mark 4. Have the chicken joints ready to cook. Heat the butter and 3 tbsp olive oil in a flameproof casserole or large frying pan.\",\"instructions\":[\"Preheat the oven to 180°C/Gas mark 4. Have the chicken joints ready to cook. Heat the butter and 3 tbsp olive oil in a flameproof casserole or large frying pan. Brown the chicken pieces in batches on both sides, seasoning them with salt and pepper as you go. Don't crowd the pan - fry the chicken in small batches, removing the pieces to kitchen paper as they are done.\",\"Add a little more olive oil to the casserole and fry the onions over a medium heat for 10 minutes, stirring frequently, until softened but not browned. Add the rest of the oil, then the peppers and cook for another 5 minutes.\",\"Add the chorizo, sun-dried tomatoes and garlic and cook for 2-3 minutes. Add the rice, stirring to ensure it is well coated in the oil. Stir in the tomato paste, paprika, bay leaves and chopped thyme. Pour in the stock and wine. When the liquid starts to bubble, turn the heat down to a gentle simmer. Press the rice down into the liquid if it isn't already submerged and place the chicken on top. Add the lemon wedges and olives around the chicken.\",\"Cover and cook in the oven for 50 minutes. The rice should be cooked but still have some bite, and the chicken should have juices that run clear when pierced in the thickest part with a knife. If not, cook for another 5 minutes and check again.\"]},{\"id\":\"g106\",\"title\":\"Chicken Congee\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529446352.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Salt\",\"Pepper\",\"Ginger Cordial\",\"Ginger\",\"Spring Onions\",\"Rice\",\"Water\",\"Coriander\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1 - MARINATING THE CHICKEN\\r\\nIn a bowl, add chicken, salt, white pepper, ginger juice and then mix it together well.\\r\\nSet the chicken aside.\\r\\nSTEP 2 - RINSE\",\"instructions\":[\"STEP 1 - MARINATING THE CHICKEN\",\"In a bowl, add chicken, salt, white pepper, ginger juice and then mix it together well.\",\"Set the chicken aside.\",\"STEP 2 - RINSE THE WHITE RICE\",\"Rinse the rice in a metal bowl or pot a couple times and then drain the water.\",\"STEP 2 - BOILING THE WHITE RICE\",\"Next add 8 cups of water and then set the stove on high heat until it is boiling. Once rice porridge starts to boil, set the stove on low heat and then stir it once every 8-10 minutes for around 20-25 minutes.\",\"After 25 minutes, this is optional but you can add a little bit more water to make rice porridge to make it less thick or to your preference.\",\"Next add the marinated chicken to the rice porridge and leave the stove on low heat for another 10 minutes.\",\"After an additional 10 minutes add the green onions, sliced ginger, 1 pinch of salt, 1 pinch of white pepper and stir for 10 seconds.\"]},{\"id\":\"g107\",\"title\":\"Chicken Couscous\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qxytrx1511304021.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Chicken Breast\",\"Ginger\",\"Harissa Spice\",\"Dried Apricots\",\"Chickpeas\",\"Couscous\",\"Chicken Stock\",\"Coriander\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the olive oil in a large frying pan and cook the onion for 1-2 mins just until softened. Add the chicken and fry for 7-10 mins until cooked through and the\",\"instructions\":[\"Heat the olive oil in a large frying pan and cook the onion for 1-2 mins just until softened. Add the chicken and fry for 7-10 mins until cooked through and the onions have turned golden. Grate over the ginger, stir through the harissa to coat everything and cook for 1 min more.\",\"Tip in the apricots, chickpeas and couscous, then pour over the stock and stir once. Cover with a lid or tightly cover the pan with foil and leave for about 5 mins until the couscous has soaked up all the stock and is soft. Fluff up the couscous with a fork and scatter over the coriander to serve. Serve with extra harissa, if you like.\"]},{\"id\":\"g108\",\"title\":\"Chicken Enchilada Casserole\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qtuwxu1468233098.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Enchilada sauce\",\"shredded Monterey Jack cheese\",\"corn tortillas\",\"chicken breasts\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cut each chicken breast in about 3 pieces, so that it cooks faster and put it in a small pot. Pour Enchilada sauce over it and cook covered on low to medium hea\",\"instructions\":[\"Cut each chicken breast in about 3 pieces, so that it cooks faster and put it in a small pot. Pour Enchilada sauce over it and cook covered on low to medium heat until chicken is cooked through, about 20 minutes. No water is needed, the chicken will cook in the Enchilada sauce. Make sure you stir occasionally so that it doesn't stick to the bottom.\",\"Remove chicken from the pot and shred with two forks.\",\"Preheat oven to 375 F degrees.\",\"Start layering the casserole. Start with about ¼ cup of the leftover Enchilada sauce over the bottom of a baking dish. I used a longer baking dish, so that I can put 2 corn tortillas across. Place 2 tortillas on the bottom, top with ⅓ of the chicken and ⅓ of the remaining sauce. Sprinkle with ⅓ of the cheese and repeat starting with 2 more tortillas, then chicken, sauce, cheese. Repeat with last layer with the remaining ingredients, tortillas, chicken, sauce and cheese.\",\"Bake for 20 to 30 minutes uncovered, until bubbly and cheese has melted and started to brown on top.\",\"Serve warm.\"]},{\"id\":\"g109\",\"title\":\"Chicken Fajita Mac and Cheese\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qrqywr1503066605.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"macaroni\",\"chicken stock\",\"heavy cream\",\"fajita seasoning\",\"salt\",\"chicken breast\",\"olive oil\",\"onion\",\"red pepper\",\"garlic\",\"cheddar cheese\",\"parsley\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Fry your onion, peppers and garlic in olive oil until nicely translucent. Make a well in your veg and add your chicken. Add your seasoning and salt. Allow to co\",\"instructions\":[\"Fry your onion, peppers and garlic in olive oil until nicely translucent. Make a well in your veg and add your chicken. Add your seasoning and salt. Allow to colour slightly.\",\"Add your cream, stock and macaroni.\",\"Cook on low for 20 minutes. Add your cheeses, stir to combine.\",\"Top with roasted peppers and parsley.\"]},{\"id\":\"g110\",\"title\":\"Chicken Fried Rice\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wuyd2h1765655837.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Salt\",\"Canola Oil\",\"Egg\",\"Onion\",\"Garlic\",\"Ground Ginger\",\"Carrots\",\"Peas\",\"Jasmine Rice\",\"Scallions\",\"Chinese five spice powder\",\"Soy Sauce\",\"Sesame Seed Oil\"],\"allergens\":[\"egg\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Fried rice is best made with leftover rice that's at least a day old. Otherwise it becomes gummy in the skillet.\\r\\nIf you don’t have any leftover rice from the n\",\"instructions\":[\"Fried rice is best made with leftover rice that's at least a day old. Otherwise it becomes gummy in the skillet.\",\"If you don’t have any leftover rice from the night before, cook a batch of rice and spread it on a large baking sheet or several large plates. Let the rice dry out for about 1 to 2 hours before using it for fried rice.\",\"Rice sticks to the pan very easily, so make sure to use a wok or pan that doesn’t have a sticky surface. I usually cook stir-fries in my seasoned carbon steel wok, but cast iron or nonstick pans work well, too. You might need to add a little more oil if things aren’t releasing easily.\",\"Prepare the chicken:\",\"Chop the chicken into small 1/4-inch to 1/2-inch cubes. Sprinkle 1/2 teaspoon of salt over the chicken and mix to combine. Set the chicken aside for about 10 minutes (I usually use this time to chop all the vegetables).\",\"Scramble the egg:\",\"Heat a wok or large sauté pan over medium-high heat. Swirl in a tablespoon of oil and add the whisked eggs. Use a spatula to quickly scramble the eggs, breaking the curds into smaller pieces as they come together. Transfer the eggs to a plate.\",\"Cook the chicken:\",\"Add another tablespoon of oil in the wok or pan. Add the chicken and cook for 4 to 5 minutes, stirring occasionally. Turn off the heat and transfer the cooked chicken to a plate.\",\"Using your spatula, scrape off any chicken bits that are still stuck to the wok so they don't burn during the next step. You can also use paper towels to wipe down your wok or pan.\"]},{\"id\":\"g111\",\"title\":\"Chicken Ham and Leek Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xrrtss1511555269.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Stock\",\"Chicken Breast\",\"Butter\",\"Leek\",\"Garlic\",\"Plain Flour\",\"Milk\",\"White Wine\",\"Double Cream\",\"Ham\",\"Sea Salt\",\"Pepper\",\"Plain Flour\",\"Butter\",\"Free-range Egg, Beaten\",\"Cold Water\",\"Free-range Egg, Beaten\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the chicken stock in a lidded saucepan. Add the chicken breast and bring to a low simmer. Cover with a lid and cook for 10 minutes. Remove the chicken brea\",\"instructions\":[\"Heat the chicken stock in a lidded saucepan. Add the chicken breast and bring to a low simmer. Cover with a lid and cook for 10 minutes. Remove the chicken breasts from the water with tongs and place on a plate. Pour the cooking liquor into a large jug.\",\"Melt 25g/1oz of the butter in a large heavy-based saucepan over a low heat. Stir in the leeks and fry gently for two minutes, stirring occasionally until just softened. Add the garlic and cook for a further minute. Add the remaining butter and stir in the flour as soon as the butter has melted. Cook for 30 seconds, stirring constantly.\",\"Slowly pour the milk into the pan, just a little at a time, stirring well between each adding. Gradually add 250ml/10fl oz of the reserved stock and the wine, if using, stirring until the sauce is smooth and thickened slightly. Bring to a gentle simmer and cook for 3 minutes.\",\"Season the mixture, to taste, with salt and freshly ground black pepper. Remove from the heat and stir in the cream. Pour into a large bowl and cover the surface of the sauce with cling ilm to prevent a skin forming. Set aside to cool.\",\"Preheat the oven to 200C/400F/Gas 6. Put a baking tray in the oven to heat.\",\"For the pastry, put the flour and butter in a food processor and blend on the pulse setting until the mixture resembles fine breadcrumbs. With the motor running, add the beaten egg and water and blend until the mixture forms a ball. Portion off 250g/10oz of pastry for the lid.\",\"Roll the remaining pastry out on a lightly floured surface, turning the pastry frequently until around 5mm/¼in thick and 4cm/1½in larger than the pie dish. Lift the pastry over the rolling pin and place it gently into the pie dish. Press the pastry firmly up the sides, making sure there are no air bubbles. Leave the excess pastry overhanging the sides.\",\"Cut the chicken breasts into 3cm/1¼in pieces. Stir the chicken, ham and leeks into the cooled sauce. Pour the chicken filling into the pie dish. Brush the rim of the dish with beaten egg. Roll out the reserved pastry for the lid.\",\"Cover the pie with the pastry lid and press the edges together firmly to seal. Trim any excess pastry.\",\"Make a small hole in the centre of the pie with the tip of a knife. Glaze the top of the pie with beaten egg. Bake on the preheated tray in the centre of the oven for 35-40 minutes or until the pie is golden-brown all over and the filling is piping hot.\"]},{\"id\":\"g112\",\"title\":\"Chicken Handi\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wyxwsp1486979827.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Onion\",\"Tomatoes\",\"Garlic\",\"Ginger paste\",\"Vegetable oil\",\"Cumin seeds\",\"Coriander seeds\",\"Turmeric powder\",\"Chilli powder\",\"Green chilli\",\"Yogurt\",\"Cream\",\"fenugreek\",\"Garam masala\",\"Salt\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Take a large pot or wok, big enough to cook all the chicken, and heat the oil in it. Once the oil is hot, add sliced onion and fry them until deep golden brown.\",\"instructions\":[\"Take a large pot or wok, big enough to cook all the chicken, and heat the oil in it. Once the oil is hot, add sliced onion and fry them until deep golden brown. Then take them out on a plate and set aside.\",\"To the same pot, add the chopped garlic and sauté for a minute. Then add the chopped tomatoes and cook until tomatoes turn soft. This would take about 5 minutes.\",\"Then return the fried onion to the pot and stir. Add ginger paste and sauté well.\",\"Now add the cumin seeds, half of the coriander seeds and chopped green chillies. Give them a quick stir.\",\"Next goes in the spices – turmeric powder and red chilli powder. Sauté the spices well for couple of minutes.\",\"Add the chicken pieces to the wok, season it with salt to taste and cook the chicken covered on medium-low heat until the chicken is almost cooked through. This would take about 15 minutes. Slowly sautéing the chicken will enhance the flavor, so do not expedite this step by putting it on high heat.\",\"When the oil separates from the spices, add the beaten yogurt keeping the heat on lowest so that the yogurt doesn’t split. Sprinkle the remaining coriander seeds and add half of the dried fenugreek leaves. Mix well.\",\"Finally add the cream and give a final mix to combine everything well.\",\"Sprinkle the remaining kasuri methi and garam masala and serve the chicken handi hot with naan or rotis. Enjoy!\"]},{\"id\":\"g113\",\"title\":\"Chicken Karaage\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tyywsw1505930373.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Ginger\",\"Garlic\",\"Soy sauce\",\"Sake\",\"Granulated sugar\",\"Potato starch\",\"Vegetable oil\",\"Lemon\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add the ginger, garlic, soy sauce, sake and sugar to a bowl and whisk to combine. Add the chicken, then stir to coat evenly. Cover and refrigerate for at least \",\"instructions\":[\"Add the ginger, garlic, soy sauce, sake and sugar to a bowl and whisk to combine. Add the chicken, then stir to coat evenly. Cover and refrigerate for at least 1 hour.\",\"Add 1 inch of vegetable oil to a heavy bottomed pot and heat until the oil reaches 360 degrees F. Line a wire rack with 2 sheets of paper towels and get your tongs out. Put the potato starch in a bowl\",\"Add a handful of chicken to the potato starch and toss to coat each piece evenly.\",\"Fry the karaage in batches until the exterior is a medium brown and the chicken is cooked through. Transfer the fried chicken to the paper towel lined rack. If you want the karaage to stay crispy longer, you can fry the chicken a second time, until it's a darker color after it's cooled off once. Serve with lemon wedges.\"]},{\"id\":\"g114\",\"title\":\"Chicken Mandi\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/er4d081765186828.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Basmati Rice\",\"Water\",\"Onion\",\"Garlic\",\"Green Chilli\",\"Salt\",\"Oil\",\"Turmeric Powder\",\"Coriander\",\"Cardamom\",\"Cloves\",\"Cinnamon\",\"Pepper\",\"Bay Leaf\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1. Clean and cut the chicken; marinate briefly with salt, turmeric and a little oil.\\r\\n2. Rinse and soak basmati rice 20–30 minutes.\\r\\n3. In a large pot, heat ghe\",\"instructions\":[\"1. Clean and cut the chicken; marinate briefly with salt, turmeric and a little oil.\",\"2. Rinse and soak basmati rice 20–30 minutes.\",\"3. In a large pot, heat ghee/oil. Fry chopped onion until golden. Add minced garlic and green chillies and fry 1–2 min.\",\"4. Add whole spices (cardamom, cloves, cinnamon, bay leaves) and ground spices (coriander, cumin). Stir until fragrant.\",\"5. Add chicken pieces, brown lightly and add enough water/chicken stock to cover. Simmer until chicken is nearly cooked.\",\"6. Remove chicken; measure remaining liquid and add soaked rice. Bring to a boil, then reduce heat, cover and cook rice until almost done.\",\"7. Return the chicken to the rice pot on top, cover tightly and steam on low for 10–15 min so flavors meld.\",\"8. (Optional) For authentic smoky aroma: heat a small charcoal until red hot, place it on a small foil cup in the centre of the pot, add a tsp of butter/oil on the coal then cover immediately to trap smoke for 5–10 minutes. Remove coal.\",\"9. Garnish with fried onions, chopped coriander and serve with chutney or raita.\"]},{\"id\":\"g115\",\"title\":\"Chicken Marengo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qpxvuq1511798906.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Mushrooms\",\"Chicken Legs\",\"Passata\",\"Chicken Stock Cube\",\"Black Olives\",\"Parsley\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oil in a large flameproof casserole dish and stir-fry the mushrooms until they start to soften. Add the chicken legs and cook briefly on each side to c\",\"instructions\":[\"Heat the oil in a large flameproof casserole dish and stir-fry the mushrooms until they start to soften. Add the chicken legs and cook briefly on each side to colour them a little.\",\"Pour in the passata, crumble in the stock cube and stir in the olives. Season with black pepper – you shouldn’t need salt. Cover and simmer for 40 mins until the chicken is tender. Sprinkle with parsley and serve with pasta and a salad, or mash and green veg, if you like.\"]},{\"id\":\"g116\",\"title\":\"Chicken Parmentier\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uwvxpv1511557015.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Butter\",\"Double Cream\",\"Egg Yolks\",\"Butter\",\"Shallots\",\"Carrots\",\"Celery\",\"Garlic Clove\",\"White Wine\",\"Tomato Puree\",\"Tinned Tomatos\",\"Chicken Stock\",\"Chicken\",\"Black Olives\",\"Parsley\",\"Gruyere cheese\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the topping, boil the potatoes in salted water until tender. Drain and push through a potato ricer, or mash thoroughly. Stir in the butter, cream and egg yo\",\"instructions\":[\"For the topping, boil the potatoes in salted water until tender. Drain and push through a potato ricer, or mash thoroughly. Stir in the butter, cream and egg yolks. Season and set aside.\",\"For the filling, melt the butter in a large pan. Add the shallots, carrots and celery and gently fry until soft, then add the garlic. Pour in the wine and cook for 1 minute. Stir in the tomato purée, chopped tomatoes and stock and cook for 10–15 minutes, until thickened. Add the shredded chicken, olives and parsley. Season to taste with salt and pepper.\",\"Preheat the oven to 180C/160C Fan/Gas 4.\",\"Put the filling in a 20x30cm/8x12in ovenproof dish and top with the mashed potato. Grate over the Gruyère. Bake for 30–35 minutes, until piping hot and the potato is golden-brown.\"]},{\"id\":\"g117\",\"title\":\"Chicken Quinoa Greek Salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/k29viq1585565980.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Quinoa\",\"Butter\",\"Red Chilli\",\"Garlic\",\"Chicken Breast\",\"Olive Oil\",\"Black Olives\",\"Red Onions\",\"Feta\",\"Mint\",\"Lemon\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cook the quinoa following the pack instructions, then rinse in cold water and drain thoroughly.\\r\\n\\r\\nMeanwhile, mix the butter, chilli and garlic into a paste. To\",\"instructions\":[\"Cook the quinoa following the pack instructions, then rinse in cold water and drain thoroughly.\",\"Meanwhile, mix the butter, chilli and garlic into a paste. Toss the chicken fillets in 2 tsp of the olive oil with some seasoning. Lay in a hot griddle pan and cook for 3-4 mins each side or until cooked through. Transfer to a plate, dot with the spicy butter and set aside to melt.\",\"Next, tip the tomatoes, olives, onion, feta and mint into a bowl. Toss in the cooked quinoa. Stir through the remaining olive oil, lemon juice and zest, and season well. Serve with the chicken fillets on top, drizzled with any buttery chicken juices.\"]},{\"id\":\"g118\",\"title\":\"Chicken Shawarma with homemade garlic herb yoghurt sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hcg6l91763596970.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breast\",\"Garlic\",\"Ground Coriander\",\"Ground Cumin\",\"Ground Cardomom\",\"Cayenne Pepper\",\"Smoked Paprika\",\"Salt\",\"Lemon Juice\",\"Olive Oil\",\"Greek Yogurt\",\"Garlic\",\"Cumin\",\"Lemon Juice\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nStart by cutting your chicken up into reasonably small slices. Grab your ziplock bag and dump the freshly sliced chicken inside.\\r\\n2\\r\\nAdd garlic, coriander, c\",\"instructions\":[\"1\",\"Start by cutting your chicken up into reasonably small slices. Grab your ziplock bag and dump the freshly sliced chicken inside.\",\"2\",\"Add garlic, coriander, cumin, cardomom, cayenne pepper, paprika, salt, pepper, lemon juice and olive oil to the bag. Close the bag and mix thoroughly. Place in fridge for 10-12 hours (shorter is fine but longer is better).\",\"3\",\"Once ready to cook, heat your fry pan to medium-high and add a tiny bit of olive oil. Fry one side of all of your flatbreads until slightly toasty. Remove from pan, add enough oil to coat the fry pan. Put crumble fries into air fryer on 180 for 15 minutes shaking occasionally.\",\"4\",\"The pan should be pretty hot by now, add the chicken in 2 batches (unless you have a big fry pan) to avoid overcrowding. The chicken should get a nice sear and darker colour which is perfect. Cook for a further 5-8 minutes or until cooked through. Repeat with next chicken batch.\",\"5\",\"While chicken is cooking, place your Greek yoghurt into a bowl. Combine garlic, finely chopped mint and parsley, squeeze or so of lemon and cumin. Combine and add salt to taste. In a small bowl, combine 1tsp garlic powder, paprika, cumin, onion powder, oregano, dried parsley, cayenne pepper (optional) mix and leave aside for fries.\"]},{\"id\":\"g119\",\"title\":\"Chicken wings with cumin, lemon & garlic\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4hzyvq1763792564.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Wings\",\"Garlic\",\"Lemon\",\"Cumin Seeds\",\"Olive Oil\",\"Honey\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nUsing a pair of sharp kitchen scissors, cut each wing at the knuckle into two pieces. Mix the garlic, lemon zest and juice, cumin and oil with plenty of\",\"instructions\":[\"step 1\",\"Using a pair of sharp kitchen scissors, cut each wing at the knuckle into two pieces. Mix the garlic, lemon zest and juice, cumin and oil with plenty of seasoning, then tip into a dish with the chicken wings and toss to coat. Cover and put in the fridge to marinate for at least 1 hr, or overnight if you have time.\",\"step 2\",\"Heat oven to 200C/180C fan/gas 6, or heat an outdoor barbecue. Bake the chicken wings on an oven tray for 45-50 mins until crisp, or barbecue for 20 mins, drizzling over the honey for the final 10 mins of each method. Serve on a platter with plenty of paper napkins. Fill small bowls with olives, pistachios or almonds, dates and pickled chillies and flatbreads to serve alongside, along with the dishes below.\"]},{\"id\":\"g120\",\"title\":\"Chicken with saffron, raisins & pine nuts\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4mhr3u1763481087.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Olive Oil\",\"Garlic\",\"Saffron\",\"Dry sherry\",\"Chicken Stock\",\"Thyme\",\"Raisins\",\"Pine Nuts\",\"Parsley\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat a large frying pan on a high heat and season the chicken. Add the olive oil to the pan, then the chicken. Brown for about 5 mins on each side, remo\",\"instructions\":[\"step 1\",\"Heat a large frying pan on a high heat and season the chicken. Add the olive oil to the pan, then the chicken. Brown for about 5 mins on each side, remove onto a plate, then set aside.\",\"step 2\",\"Lower the heat to medium. In the remaining fat, fry the onions for 3 mins, then add the garlic and saffron. Cook for 3-4 mins more. Add the sherry, then simmer for 3-5 mins until syrupy.\",\"step 3\",\"Put the chicken leg pieces back into the pan, tip in the stock, thyme and raisins, cover, then gently cook on a low heat for 20 mins. Add the breast meat and any juices left on the plate. Simmer for 10 mins more until cooked through and the sauce in the pan has reduced.\",\"step 4\",\"While the chicken is cooking, heat oven to 200C/180C fan/gas 6. Scatter the pine nuts over a baking sheet, then roast for 10 mins until golden and toasted. Once the chicken has cooked through, season to taste, scatter with pine nuts and parsley, then serve with rice.\"]},{\"id\":\"g121\",\"title\":\"Chickpea Fajitas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tvtxpq1511464705.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chickpeas\",\"Olive Oil\",\"Paprika\",\"Tomatoes\",\"Red Onions\",\"Red Wine Vinegar\",\"Avocado\",\"Lime\",\"Lime\",\"Sour Cream\",\"Harissa Spice\",\"Corn Tortillas\",\"Coriander\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Drain the chickpeas, pat dry and tip onto the prepared baking tray. Add the oil and paprika, \",\"instructions\":[\"Heat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Drain the chickpeas, pat dry and tip onto the prepared baking tray. Add the oil and paprika, toss to coat, then roast for 20-25 mins until browned and crisp, shaking halfway through cooking.\",\"Meanwhile, put the tomatoes and onion in a small bowl with the vinegar and set aside to pickle. Put the avocado in another bowl and mash with a fork, leaving some larger chunks. Stir in the lime juice and season well. Mix the soured cream with the harissa and set aside until ready to serve.\",\"Heat a griddle pan until nearly smoking. Add the tortillas , one at a time, charring each side until hot with griddle lines.\",\"Put everything on the table and build the fajitas : spread a little of the harissa cream over the tortilla, top with roasted chickpeas, guacamole, pickled salsa and coriander, if you like. Serve with the lime wedges for squeezing over.\"]},{\"id\":\"g122\",\"title\":\"Chickpea, chorizo & spinach stew\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xvnx8j1763287209.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Extra Virgin Olive Oil\",\"Onion\",\"Carrots\",\"Celery\",\"Thyme\",\"Bay Leaves\",\"Garlic\",\"Chorizo\",\"Cinnamon\",\"Paprika\",\"Chickpeas\",\"Sherry vinegar\",\"Spinach\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oil in a large pan, then gently fry the onion for 3-4 mins until it begins to soften. Stir in the carrot, celery, thyme and bay leaves. Season,\",\"instructions\":[\"step 1\",\"Heat the oil in a large pan, then gently fry the onion for 3-4 mins until it begins to soften. Stir in the carrot, celery, thyme and bay leaves. Season, then cook for 2-3 mins, stirring occasionally. Add the garlic, chorizo, cinnamon and smoked paprika. Gently fry until the vegetables soften and the chorizo starts to release its oils and crisp up.\",\"step 2\",\"Stir in the chickpeas, vinegar and 150ml water, then bring to a simmer for 1-2 mins until the chickpeas have heated up. Add the spinach, then stir through the chickpeas until it wilts a little. Remove from the heat, season to taste, then serve warm with crusty bread.\"]},{\"id\":\"g123\",\"title\":\"Chilli ginger lamb chops\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8xuvhj1763794991.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Garlic\",\"Ginger\",\"Lemon Juice\",\"Olive Oil\",\"Chili Powder\",\"Cumin\",\"Lamb Loin Chops\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut the garlic in a bowl with the ginger, lemon juice, oil, spices and seasoning. Blitz with a hand blender until smooth, then use to coat the lamb chop\",\"instructions\":[\"step 1\",\"Put the garlic in a bowl with the ginger, lemon juice, oil, spices and seasoning. Blitz with a hand blender until smooth, then use to coat the lamb chops on both sides. Leave to marinate in the fridge for a couple of hours or overnight.\",\"step 2\",\"Heat a barbecue until hot. Barbecue the chops over the coals for 3 mins on each side until cooked but still pink and juicy in the centre.\"]},{\"id\":\"g124\",\"title\":\"Chilli prawn linguine\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/usywpp1511189717.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Linguine Pasta\",\"Sugar Snap Peas\",\"Olive Oil\",\"Garlic Clove\",\"Red Chilli\",\"King Prawns\",\"Cherry Tomatoes\",\"Basil Leaves\",\"Lettuce\",\"Bread\",\"Fromage Frais\",\"Lime\",\"Caster Sugar\"],\"allergens\":[\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Mix the dressing ingredients in a small bowl and season with salt and pepper. Set aside.\\r\\n\\r\\nCook the pasta according to the packet instructions. Add the sugar s\",\"instructions\":[\"Mix the dressing ingredients in a small bowl and season with salt and pepper. Set aside.\",\"Cook the pasta according to the packet instructions. Add the sugar snap peas for the last minute or so of cooking time.\",\"Meanwhile, heat the oil in a wok or large frying pan, toss in the garlic and chilli and cook over a fairly gentle heat for about 30 seconds without letting the garlic brown. Tip in the prawns and cook over a high heat, stirring frequently, for about 3 minutes until they turn pink.\",\"Add the tomatoes and cook, stirring occasionally, for 3 minutes until they just start to soften. Drain the pasta and sugar snaps well, then toss into the prawn mixture. Tear in the basil leaves, stir, and season with salt and pepper.\",\"Serve with salad leaves drizzled with the lime dressing, and warm crusty bread.\"]},{\"id\":\"g125\",\"title\":\"Chinese Orange Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/s73ytv1765567838.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Orange\",\"Orange Juice\",\"Soy Sauce\",\"Water\",\"Rice Vinegar\",\"Cornstarch\",\"Sesame Seed Oil\",\"Sugar\",\"Chicken Thighs\",\"Egg\",\"Salt\",\"Black Pepper\",\"Cornstarch\",\"All purpose flour\",\"Vegetable Oil\",\"Garlic\",\"Shallots\",\"Scallions\",\"Sesame Seed\",\"Rice\"],\"allergens\":[\"egg\",\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Make the orange sauce:\\r\\nWhisk together sauce ingredients in a medium bowl. Set aside.\\r\\n\\r\\n\\r\\nPrep the chicken:\\r\\nCut chicken into about 1-inch cubes. Whisk eggs wi\",\"instructions\":[\"Make the orange sauce:\",\"Whisk together sauce ingredients in a medium bowl. Set aside.\",\"Prep the chicken:\",\"Cut chicken into about 1-inch cubes. Whisk eggs with salt and black pepper in a bowl and add chicken. Stir together.\",\"In a separate bowl, whisk together flour and cornstarch. Remove chicken from eggs with a slotted spoon or tongs, letting excess egg drain off, then transfer to cornstarch mixture and coat well.\",\"Fry the chicken:\",\"Add oil to a large 10- to 12-inch skillet. Heat over medium-high heat until it reaches 350°F. If you don’t have a thermometer, you can also test the temperature by sprinkling in some flour. If the oil is hot enough, it should fizzle immediately.\",\"Once oil is hot, fry the chicken in two batches. The oil might not completely cover the chicken—that’s okay. Cook for 3 to 4 minutes. Flip the chicken pieces and cook until the chicken is cooked through, about 3 to 4 more minutes. Total cook time is about 6 to 8 minutes.\",\"Remove fried chicken cubes and transfer to a plate lined with paper towels, so the chicken can drain. Repeat until all the chicken is cooked.\",\"Simmer the chicken in the sauce:\"]},{\"id\":\"g126\",\"title\":\"Chinese Tomato Egg Stir Fry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rwvw8q1765660071.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plum Tomatoes\",\"Vegetable Oil\",\"Eggs\",\"Sesame Seed Oil\",\"Chicken Bouillon Powder\",\"Sugar\",\"Pepper\",\"Salt\",\"Spring Onions\",\"Jasmine Rice\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"You can use chicken broth in place of the chicken bouillon powder. Add 1/4 cup of broth followed by 2 teaspoons of cornstarch dissolved in 1 tablespoPrepare the\",\"instructions\":[\"You can use chicken broth in place of the chicken bouillon powder. Add 1/4 cup of broth followed by 2 teaspoons of cornstarch dissolved in 1 tablespoPrepare the tomatoes:\",\"Slice the tomatoes in half. Remove the tough stem from each half that connects to the vine. Cut each half into equal thirds (you’ll get 6 slices from each tomato).\",\"Make the soft scrambled eggs:\",\"In a cold, 8 to 10-inch nonstick skillet, add the vegetable oil and beaten eggs. Turn the heat to medium. Once a thin layer of eggs is just beginning to cook on the bottom, push the eggs in one direction to create layers of scrambled eggs.\",\"Cook, gently stirring the whole time, until the scramble eggs are mostly set but still slightly wet and shiny, 2 to 5 minutes. Remove the eggs to a plate and, if needed, wipe out the pan.\",\"Stir-fry the tomatoes and seasonings:\",\"Add the sesame oil to the pan followed by the tomatoes and stir-fry over medium heat until the tomatoes are softened but not mushy, about 3 minutes. Add the chicken bouillon powder, sugar, and white pepper. Toss until combined and the sugar and bouillon have dissolved, about 1 minute.\",\"Add eggs, stir-fry, and garnish:\",\"Add the eggs back to the pan with the tomatoes. Stir-fry for about 2 minutes to heat through and combine. Taste, adding salt only if needed. Sprinkle with the green onions and serve with steamed rice.on of water, plus salt to taste.\"]},{\"id\":\"g127\",\"title\":\"Chinon Apple Tarts\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qtqwwu1511792650.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Puff Pastry\",\"Dark Brown Soft Sugar\",\"Braeburn Apples\",\"Red Wine Jelly\",\"Creme Fraiche\",\"Icing Sugar\",\"Cardamom\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"To make the red wine jelly, put the red wine, jam sugar, star anise, clove, cinnamon stick, allspice, split vanilla pod and seeds in a medium saucepan. Stir tog\",\"instructions\":[\"To make the red wine jelly, put the red wine, jam sugar, star anise, clove, cinnamon stick, allspice, split vanilla pod and seeds in a medium saucepan. Stir together, then heat gently to dissolve the sugar. Turn up the heat and boil for 20 mins until reduced and syrupy. Strain into a small, sterilised jam jar and leave to cool completely. Will keep in the fridge for up to 1 month.\",\"Take the pastry out of the fridge and leave at room temperature for 10 mins, then unroll. Heat the grill to high and heat the oven to 180C/160C fan/gas 4. Cut out 2 x 13cm circles of pastry, using a plate as a guide, and place on a non-stick baking sheet. Sprinkle each circle with 1 tbsp sugar and grill for 5 mins to caramelise, watching carefully so that the sugar doesn’t burn. Remove from the grill. Can be done a few hours ahead, and left, covered, out of the fridge.\",\"Peel, quarter and core the apples, cut into 2mm-thin slices and arrange on top of the pastry. Sprinkle over the remaining sugar and pop in the oven for 20-25 mins until the pastry is cooked through and golden, and the apples are softened. Remove and allow to cool slightly. Warm 3 tbsp of the red wine jelly in a small pan over a low heat with 1 tsp water to make it a little more runny, then brush over the top of the tarts.\",\"Tip the crème fraîche into a bowl, sift over the icing sugar and cardamom, and mix together. Carefully lift the warm tarts onto serving plates and serve with the cardamom crème fraîche.\"]},{\"id\":\"g128\",\"title\":\"Chivito sandwich\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Milk\",\"Butter\",\"Molasses\",\"Water\",\"Egg\",\"Bread Flour\",\"Salt\",\"Yeast\",\"Egg Wash\",\"Sesame Seed\",\"Onion\",\"Sirloin steak\",\"Garlic\",\"Bacon\",\"Ham\",\"Mozzarella\",\"Tomato\",\"Lettuce\",\"Mustard\",\"Chimichurri sauce\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the brioche buns heat the milk with the butter and molasses until the butter has melted. Add the cold water and egg to this mix.\\r\\n\\r\\n2\\r\\nIn a large bowl place\",\"instructions\":[\"For the brioche buns heat the milk with the butter and molasses until the butter has melted. Add the cold water and egg to this mix.\",\"2\",\"In a large bowl place flour, salt and yeast and mix. Then add the milk and water mix and stir with a wooden spoon until combined. You don't have to knead the dough, it is perfectly fine to do this by hand with a wooden spoon, this doesn't need to be very thorough. Cover with a damp towel and stick in the fridge overnight.\",\"3\",\"The next morning knead dough on a generously floured surface for a little and cut into eight equal pieces. Shape these into balls and place on a baking sheet lined with parchment paper. Cover again with damp towel and let rise for about an hour or until double in size.\",\"4\",\"Heat oven to 220 degrees Celsius. Brush the buns with either milk, heavy cream or egg wash and sprinkle with sesame seeds, if desired. Bake for about 15-20min or until golden. Let cool.\",\"5\",\"For the toppings chop the onions and sauté in a bit of butter, let caramelize, this may take ten to 15 minutes, stir occasionally. Rub the steaks with a bit of garlic and then grill or fry the steaks, the bacon, and eggs with salt and pepper, toast the buns after having cut in half. Spread mustard on one bun half, layer each chivito with steak, a slice of ham, a slice of cheese, one bacon stripe, a tomato slice, and some lettuce. Place fried egg on top and sprinkle generously with chimichurri and some onions right before serving.\"]},{\"id\":\"g129\",\"title\":\"Chivito uruguayo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/n7qnkb1630444129.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Brisket\",\"Bread\",\"Lettuce\",\"Tomato\",\"Ham\",\"Mozzarella\",\"Bacon\",\"Egg\",\"Onion\",\"Pepper\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Crush the meat so that it is finite and we put it on a griddle to brown. Put the eggs, bacon and ham to fry.\\r\\nCut the bread in half, put the beef brisket, the f\",\"instructions\":[\"Crush the meat so that it is finite and we put it on a griddle to brown. Put the eggs, bacon and ham to fry.\",\"Cut the bread in half, put the beef brisket, the fried eggs, the bacon, the ham, the mozzarella, the tomato and the lettuce. Cover with the other half of the bread and serve.\"]},{\"id\":\"g130\",\"title\":\"Choc Chip Pecan Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rqvwxt1511384809.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Butter\",\"Cream Cheese\",\"Icing Sugar\",\"Butter\",\"Maple Syrup\",\"Light Brown Soft Sugar\",\"Dark Brown Soft Sugar\",\"Eggs\",\"Vanilla Extract\",\"Pecan Nuts\",\"Dark Chocolate Chips\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"First, make the pastry. Tip the ingredients into a food processor with 1 /4 tsp salt. Blend until the mixture resembles breadcrumbs. Drizzle 2-3 tsp cold water \",\"instructions\":[\"First, make the pastry. Tip the ingredients into a food processor with 1 /4 tsp salt. Blend until the mixture resembles breadcrumbs. Drizzle 2-3 tsp cold water into the funnel while the blade is running – the mixture should start to clump together. Tip onto a work surface and bring together, kneading briefly into a ball. Pat into a disc, wrap in cling film, and chill for at least 20 mins. Heat oven to 200C/180C fan/gas 6.\",\"Remove the pastry from the fridge and leave at room temperature for 5 mins to soften. Flour the work surface, then unwrap the pastry and roll to a circle the thickness of a £1 coin. Use the pastry to line a deep, 23cm round fluted tin – mine was about 3cm deep. Press the pastry into the corners and up the sides, making sure there are no gaps. Leave 1cm pastry overhanging (save some of the pastry scraps for later). Line with baking parchment (scrunch it up first to make it more pliable) and fill with baking beans. Blind-bake for 15-20 mins until the sides are set, then remove the parchment and beans and return to the oven for 5 mins until golden brown. Trim the pastry so it’s flush with the top of the tin – a small serrated knife is best for this. If there are any cracks, patch them up with the pastry scraps.\",\"Meanwhile, weigh the butter, syrup and sugars into a pan, and add 1 /4 tsp salt. Heat until the butter has melted and the sugar dissolved, stirring until smooth. Remove from the heat and cool for 10 mins. Reduce oven to 160C/140C fan/gas 3.\",\"Beat the eggs in a bowl. Add the syrup mixture, vanilla and pecans, and mix until well combined. Pour half the mixture into the tart case, scatter over half the chocolate chips, then cover with the remaining filling and chocolate chips. Bake on the middle shelf for 50-55 mins until set. Remove from the oven and leave to cool, then chill for at least 2 hrs before serving.\"]},{\"id\":\"g131\",\"title\":\"Chocolate alfajores\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/k9o0xr1764373018.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Sugar\",\"Egg\",\"Honey\",\"All purpose flour\",\"Cornstarch\",\"Unsweetened Cocoa\",\"Baking Powder\",\"Baking Powder\",\"Dulce de leche\",\"Milk Chocolate\",\"Butter\",\"Orange\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the cookies cream the butter with the sugar for a few minutes. Then add the egg and honey and mix well. Add flour, cornstarch, cocoa, baking soda and baking\",\"instructions\":[\"For the cookies cream the butter with the sugar for a few minutes. Then add the egg and honey and mix well. Add flour, cornstarch, cocoa, baking soda and baking powder and mix until you get a dough. Wrap in plastic wrap and chill for at least half an hour or overnight.\",\"2\",\"Line two baking sheets with parchment paper, preheat oven to 200 degrees Celsius.\",\"3\",\"Divide dough into two parts, put one part back in the fridge before using. Roll out second part to about 2 millimeters and cut out round cookies with 5-6 centimeters in diameter. This can be done with a cookie cutter or glass. You should get 30 cookies in total or even more, I get about 40. Bake one baking sheet at the time for about 8-10min. Let cookies cool.\",\"4\",\"For the filling look for two cookies of the same size and place about one teaspoon of dulce de leche onto the bottom one before sandwiching together.\",\"5\",\"Chop semi-sweet chocolate and melt with butter and orange zest on low heat. Dunk each sandwich cookie into the chocolate and let cool off on parchment paper before serving.\"]},{\"id\":\"g132\",\"title\":\"Chocolate Avocado Mousse\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uttuxy1511382180.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Banana\",\"Cacao\",\"Avocado\",\"Honey\",\"Lemon Juice\",\"Vanilla\",\"Water\",\"Sea Salt\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1. Blend all the mousse ingredients together in your food processor until smooth. Add the cacao powder first and, as you blend, have all the ingredients to hand\",\"instructions\":[\"1. Blend all the mousse ingredients together in your food processor until smooth. Add the cacao powder first and, as you blend, have all the ingredients to hand in order to adjust the ratios slightly as the size of avocados and bananas varies so much. The perfect ratio in order to avoid the dish tasting too much of either is to use equal amounts of both.\",\"2. Taste and add a few drops of stevia if you feel you need more sweetness.\",\"3. Fill little cups or shot glasses with the mousse, sprinkle with the cacao powder or nibs and serve.\",\"Tip If you don’t have a frozen banana to hand you can just use a normal one and then chill the mousse before serving for a cooling dessert.\"]},{\"id\":\"g133\",\"title\":\"Chocolate Caramel Crispy\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1550442508.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mars Bar\",\"Butter\",\"Rice Krispies\",\"Milk Chocolate\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Grease and line a 20 x 20cm/8\\\" x 8\\\" baking tin with parchment paper.\\r\\nPut the mars bars and butter in a heat proof bowl and place over a pan of barely simmering\",\"instructions\":[\"Grease and line a 20 x 20cm/8\\\" x 8\\\" baking tin with parchment paper.\",\"Put the mars bars and butter in a heat proof bowl and place over a pan of barely simmering water. Mixing with a whisk, melt until the mixture is smooth.\",\"Pour over the rice krispies in a mixing bowl and mix until all the ingredients are evenly combined. Press evenly into the prepare baking tin and set aside.\",\"Melt the milk chocolate in the microwave or over a pan of barely simmering water.\",\"Spread the melted chocolate over the rice krispie mixture and leave to set in a cool place. Once set slice into squares and serve!\"]},{\"id\":\"g134\",\"title\":\"Chocolate churros with chocolate & salted caramel sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/erzs951763296201.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sunflower Oil\",\"Ice Cream\",\"Muscovado Sugar\",\"Butter\",\"Double Cream\",\"Dark Chocolate\",\"Golden Caster Sugar\",\"Cinnamon\",\"Plain Flour\",\"Cocoa Powder\",\"Baking Powder\",\"Vanilla Extract\",\"Melted Butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTo make the sauce, tip the sugar and butter into a saucepan and bring to a simmer until the sugar has melted, then stir in the cream and simmer until yo\",\"instructions\":[\"step 1\",\"To make the sauce, tip the sugar and butter into a saucepan and bring to a simmer until the sugar has melted, then stir in the cream and simmer until you have a smooth sauce, about 2-3 mins. Remove from the heat, stir through a pinch of sea salt and the chocolate, and continue to stir for 2-3 mins, or until it has completely melted. Keep warm or leave to cool for reheating later. For the coating, mix the sugar with the cinnamon and a small pinch of fine sea salt and set aside.\",\"step 2\",\"For the churros, tip the flour, cocoa, baking powder and a large pinch of salt into a bowl. Add the vanilla extract and melted butter, then carefully pour in 250-300ml boiling water and whisk to make a smooth, very thick batter. Leave to cool for a few minutes, then scrape the mixture into a piping bag fitted with a medium star nozzle.\",\"step 3\",\"Tip sunflower oil into a deep-fat fryer following the manufacturer’s instructions, or a heavy-based pan, ensuring it is no more than a third full. Heat to 170C, or until a cube of bread dropped in browns in 30 seconds. Pipe 12-15cm lengths of dough into the oil, snipping off the end of each one with a pair of scissors as you go. Pipe four or five at a time and cook for around 4 mins, or until golden and crisp, turning them with tongs or a slotted spoon as they cook. Remove from the oil and place on a wire rack. Repeat with the rest of the dough. Leave to cool if reheating later, otherwise roll the churros in the cinnamon sugar and serve immediately with the warm chocolate sauce and ice cream. To reheat the churros, put on a tray and bake for 5-8 mins, then roll in the sugar coating. Meanwhile, warm the sauce in a pan and serve alongside for dipping.\"]},{\"id\":\"g135\",\"title\":\"Chocolate Coconut Squares\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8oupz51761848432.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Caster Sugar\",\"Egg\",\"Self-raising Flour\",\"Baking Powder\",\"Cocoa Powder\",\"Milk\",\"Plain Chocolate\",\"Butter\",\"Icing Sugar\",\"Desiccated Coconut\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 180C/fan 160C/gas 4. Butter and line the base of a 20cm square baking tin. Beat together the butter and sugar until pale and creamy, then b\",\"instructions\":[\"step 1\",\"Heat oven to 180C/fan 160C/gas 4. Butter and line the base of a 20cm square baking tin. Beat together the butter and sugar until pale and creamy, then beat in the eggs. Add 1 tbsp of the flour if the mix starts to curdle.\",\"step 2\",\"Sieve in the flour, baking powder and cocoa and fold in with a metal spoon. Stir in the milk. Scrape mix into the tin and level the top. Bake for 18-20 mins or until the cake springs back when pressed. Allow to cool in the tin.\",\"step 3\",\"To make the icing, put the chocolate, butter and 4 tbsp water in a pan and gently heat until melted. Allow to cool slightly, then beat in the icing sugar.\",\"step 4\",\"Remove cake from tin and peel away paper. Cut into 16 squares. Dip the squares into the icing, then roll in the coconut. Allow to set on cooling rack.\"]},{\"id\":\"g136\",\"title\":\"Chocolate empanadas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/u9ezi21764375474.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Condensed Milk\",\"All purpose flour\",\"Unsweetened Cocoa\",\"Salt\",\"Butter\",\"Egg\",\"Milk\",\"Butter\",\"Sugar\",\"Cinnamon\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the filling place the can in a large pot and cover completely with water. Boil for two and a half hours, occassionally adding water. Let cool before opening\",\"instructions\":[\"For the filling place the can in a large pot and cover completely with water. Boil for two and a half hours, occassionally adding water. Let cool before opening. For further tips, please check here.\",\"2\",\"For the dough combine the flour, cocoa powder, and salt in a large bowl. Add the cold butter in small pieces and rub into crumbs with your fingers Add the egg and work into a dough. You may have to add milk, a tablespoon at a time if it still is to dry. Wrap and chill for at least half an hour or overnight.\",\"3\",\"Line a baking sheeet with parchment paper and preheat the oven to 180 degrees Celsius.\",\"4\",\"Roll out the dough on a lightly floured surface, it should be thin. Cut out circles of 12cm either with a cookie cutter or with a smaller plate/dish. Put two to three teaspoons of the dulce de leche in the middle of each circle. Brush the edges with milk, I do this with my pinkie. Fold each circle in half so that you have a half moon and press down the edges with a fork. You can also turn the edges about half a centimeter inwards every centimeter or so to create a pattern.\",\"5\",\"Place the prepared empanadas on the baking sheet and brush with egg wash. Bake for about 20-25min.\",\"6\"]},{\"id\":\"g137\",\"title\":\"Chocolate Gateau\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tqtywx1468317395.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain chocolate\",\"Butter\",\"Milk\",\"Eggs\",\"Granulated Sugar\",\"Flour\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 180°C/350°F/Gas Mark 4. Grease and line the base of an 8 in round spring form cake tin with baking parchment\\r\\nBreak the chocolate into a hea\",\"instructions\":[\"Preheat the oven to 180°C/350°F/Gas Mark 4. Grease and line the base of an 8 in round spring form cake tin with baking parchment\",\"Break the chocolate into a heatproof bowl and place over a saucepan of gently simmering water and stir until it melts. (or melt in the microwave for 2-3 mins stirring occasionally)\",\"Place the butter and sugar in a mixing bowl and cream together with a wooden spoon until light and fluffy. Gradually beat in the eggs, adding a little flour if the mixture begins to curdle. Fold in the remaining flour with the cooled, melted chocolate and milk. Mix until smooth.\",\"Spread the mixture into the cake tin and bake for 50-55 mins or until firm in the centre and a skewer comes out cleanly. Cool for 10 minutes, then turn out and cool completely.\"]},{\"id\":\"g138\",\"title\":\"Chocolate Raspberry Brownies\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yypvst1511386427.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Dark Chocolate\",\"Milk Chocolate\",\"Salted Butter\",\"Light Brown Soft Sugar\",\"Eggs\",\"Plain Flour\",\"Cocoa\",\"Raspberries\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 180C/160C fan/gas 4. Line a 20 x 30cm baking tray tin with baking parchment. Put the chocolate, butter and sugar in a pan and gently melt, stirring\",\"instructions\":[\"Heat oven to 180C/160C fan/gas 4. Line a 20 x 30cm baking tray tin with baking parchment. Put the chocolate, butter and sugar in a pan and gently melt, stirring occasionally with a wooden spoon. Remove from the heat.\",\"Stir the eggs, one by one, into the melted chocolate mixture. Sieve over the flour and cocoa, and stir in. Stir in half the raspberries, scrape into the tray, then scatter over the remaining raspberries. Bake on the middle shelf for 30 mins or, if you prefer a firmer texture, for 5 mins more. Cool before slicing into squares. Store in an airtight container for up to 3 days.\"]},{\"id\":\"g139\",\"title\":\"Chocolate Souffle\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/twspvx1511784937.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Single Cream\",\"Caster Sugar\",\"Dark Chocolate\",\"Butter\",\"Butter\",\"Caster Sugar\",\"Dark Chocolate\",\"Double Cream\",\"Egg Yolks\",\"Egg White\",\"Double Cream\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 220C/fan 200C/gas 7 and place a baking tray on the top shelf. For the sauce, heat the cream and sugar until boiling. Remove from the heat, stir in \",\"instructions\":[\"Heat oven to 220C/fan 200C/gas 7 and place a baking tray on the top shelf. For the sauce, heat the cream and sugar until boiling. Remove from the heat, stir in the chocolate and butter until melted, then keep warm.\",\"Brush 6 x 150ml ramekins with melted butter, sprinkle with the 2 tbsp caster sugar, then tip out any excess. Melt the chocolate and cream in a bowl over a pan of simmering water, cool, then mix in the egg yolks. Whisk the egg whites until they hold their shape, then add the sugar, 1 tbsp at a time, whisking back to the same consistency. Mix a spoonful into the chocolate, then gently fold in the rest.\",\"Working quickly, fill the ramekins, wipe the rims clean and run your thumb around the edges. Turn oven down to 200C/fan 180C/gas 6, place the ramekins onto the baking tray, then bake for 8-10 mins until risen with a slight wobble. Don’t open the oven door too early as this may make them collapse.\",\"Once the soufflés are ready, dust with icing sugar, scoop a small hole from their tops, then pour in some of the hot chocolate sauce. Replace the lids and serve straight away.\"]},{\"id\":\"g140\",\"title\":\"Chorba Hamra bel Frik (Algerian Lamb, Tomato, and Freekeh Soup)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/p9tebp1764118792.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Freekeh\",\"Lamb\",\"Onion\",\"Black Pepper\",\"Paprika\",\"Ground Cinnamon\",\"Salt\",\"Vegetable Oil\",\"Cilantro\",\"Mint\",\"Celery\",\"Chickpeas\",\"Water\",\"Zucchini\",\"Carrots\",\"Tomato Puree\",\"Tomato\",\"Potatoes\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Place freekeh in a small bowl and cover with cold water. Set aside.\\r\\n\\r\\nCombine lamb, onion, black pepper, paprika, cinnamon, and salt in a pot. Stir in oil, 1/2\",\"instructions\":[\"Place freekeh in a small bowl and cover with cold water. Set aside.\",\"Combine lamb, onion, black pepper, paprika, cinnamon, and salt in a pot. Stir in oil, 1/2 the cilantro, 1/2 the mint, and celery stalk until combined. Simmer over low heat for 15 minutes. Stir in chickpeas; pour in just enough water to cover, and return to a simmer. Stir in zucchini, carrot, and tomato paste.\",\"Set a steamer over the pot; add tomatoes. Cover and steam tomatoes until soft, about 5 minutes. Crush tomatoes using a wooden spoon, so pulp drips into soup. Remove the steamer and discard leftover tomato peels.\",\"Add potato to soup and just enough water to cover. Simmer until potato is soft, about 10 minutes.\",\"Drain freekeh and add to soup. Simmer until soft, about 15 minutes. Remove celery stalk and discard. Sprinkle soup with remaining 1/2 cilantro and remaining 1/2 mint before serving.\"]},{\"id\":\"g141\",\"title\":\"Choripán\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/5i25sg1763075353.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chorizo\",\"Crusty Bread\",\"Chimichurri sauce\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Grill the Chorizos: Cook the chorizos on a grill or pan until fully cooked, about 10-15 minutes.\\r\\nPrepare the Rolls: Slice the rolls and toast them lightly on t\",\"instructions\":[\"Grill the Chorizos: Cook the chorizos on a grill or pan until fully cooked, about 10-15 minutes.\",\"Prepare the Rolls: Slice the rolls and toast them lightly on the grill or in a pan.\",\"Assemble: Slice each chorizo lengthwise and place in a roll. Top with a generous amount of chimichurri sauce.\",\"Serve: Enjoy immediately while hot.\",\"Pro Tips:\",\"Grill the chorizo slowly on medium heat to prevent the skin from bursting and to ensure it cooks evenly throughout.\",\"Toast the bread on the grill to absorb some of the chorizo's flavors.\"]},{\"id\":\"g142\",\"title\":\"Chorizo & chickpea soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kggfo91763288633.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tinned Tomatos\",\"Chorizo\",\"Savoy Cabbage\",\"Chilli Flakes\",\"Chickpeas\",\"Chicken Stock\",\"Crusty Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut a medium pan on the heat and tip in the tomatoes, followed by a can of water. While the tomatoes are heating, quickly chop the chorizo into chunky p\",\"instructions\":[\"step 1\",\"Put a medium pan on the heat and tip in the tomatoes, followed by a can of water. While the tomatoes are heating, quickly chop the chorizo into chunky pieces (removing any skin) and shred the cabbage.\",\"step 2\",\"Pile the chorizo and cabbage into the pan with the chilli flakes and chickpeas, then crumble in the stock cube. Stir well, cover and leave to bubble over a high heat for 6 mins or until the cabbage is just tender. Ladle into bowls and eat with crusty or garlic bread.\"]},{\"id\":\"g143\",\"title\":\"Chorizo & soft-boiled egg salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/v8eaed1763257313.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Baby New Potatoes\",\"Egg\",\"Green Beans\",\"Chorizo\",\"Garlic Clove\",\"Sherry vinegar\",\"Parsley\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nCook the potatoes in a large pan of boiling salted water for 12 mins, adding the eggs after 6 mins, and the beans for the final 2 mins. Drain everything\",\"instructions\":[\"step 1\",\"Cook the potatoes in a large pan of boiling salted water for 12 mins, adding the eggs after 6 mins, and the beans for the final 2 mins. Drain everything and cool the eggs under cold running water.\",\"step 2\",\"Meanwhile fry chorizo slices for 1-2 mins, until beginning to crisp. Remove from the pan with a slotted spoon and set aside, leaving the oil from the chorizo in the pan. Add the garlic to the pan and cook gently for 1 min.\",\"step 3\",\"Remove the pan from the heat, stir in the vinegar and parsley, then toss with the potatoes, beans, chorizo and seasoning. Shell the eggs, cut into quarters and add to the salad.\"]},{\"id\":\"g144\",\"title\":\"Chorizo & tomato salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6cskio1763338156.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef tomatoes\",\"Red Onions\",\"Thyme\",\"Sherry vinegar\",\"Extra Virgin Olive Oil\",\"Chorizo\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the tomatoes in a bowl with the onion and thyme. Season, then drizzle with the vinegar and oil. Let the flavours mingle while you cook the chorizo.\\r\",\"instructions\":[\"step 1\",\"Put the tomatoes in a bowl with the onion and thyme. Season, then drizzle with the vinegar and oil. Let the flavours mingle while you cook the chorizo.\",\"step 2\",\"In a hot, dry pan, fry the chorizo slices until browned on both sides. Serve the tomatoes with the fried chorizo, drizzled with a little oil from the pan.\"]},{\"id\":\"g145\",\"title\":\"Chorizo, potato & cheese omelette\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0y6uvc1763258983.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Olive Oil\",\"Chorizo\",\"Egg\",\"Parsley\",\"Cheddar Cheese\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nCook the potato in boiling water for 8-10 mins or until tender. Drain and allow to steam-dry. Heat oil in an omelette pan, add chorizo and cook for 2 mi\",\"instructions\":[\"step 1\",\"Cook the potato in boiling water for 8-10 mins or until tender. Drain and allow to steam-dry. Heat oil in an omelette pan, add chorizo and cook for 2 mins. Add the potato and cook for a further 5 mins until the potato starts to crisp. Spoon pan contents out, wipe pan and cook a 2 or 3-egg omelette in the same pan. When almost cooked, scatter with the chorizo and potato, parsley and cheese. Fold the omelette in the pan and cook for 1 min more to melt the cheese.\"]},{\"id\":\"g146\",\"title\":\"Christmas cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ldnrm91576791881.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Muscovado Sugar\",\"Plain Flour\",\"Eggs\",\"Ground Almonds\",\"Sherry\",\"Candied Peel\",\"Glace Cherry\",\"Raisins\",\"Currants\",\"Pecan Nuts\",\"Lemon\",\"Mixed Spice\",\"Rose water\",\"Vanilla Extract\",\"Baking Powder\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 160C/fan 140C/gas 3. Line the base and sides of a 20 cm round, 7.5 cm deep cake tin. Beat the butter and sugar with an electric hand mixer for 1-2 \",\"instructions\":[\"Heat oven to 160C/fan 140C/gas 3. Line the base and sides of a 20 cm round, 7.5 cm deep cake tin. Beat the butter and sugar with an electric hand mixer for 1-2 mins until very creamy and pale in colour, scraping down the sides of the bowl half way through. Stir in a spoonful of the flour, then stir in the beaten egg and the rest of the flour alternately, a quarter at a time, beating well each time with a wooden spoon. Stir in the almonds.\",\"Mix in the sherry (the mix will look curdled), then add the peel, cherries, raisins, cherries, nuts, lemon zest, spice, rosewater and vanilla. Beat together to mix, then stir in the baking powder.\",\"Spoon mixture into the tin and smooth the top, making a slight dip in the centre. Bake for 30 mins, then lower temperature to 150C/fan 130C/gas 2 and bake a further 2-2¼ hrs, until a skewer insterted in the middle comes out clean. Leave to cool in the tin, then take out of the tin and peel off the lining paper. When completely cold, wrap well in cling film and foil to store until ready to decorate. The cake will keep for several months.\"]},{\"id\":\"g147\",\"title\":\"Christmas Pudding Flapjack\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vvusxs1483907034.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"salted butter\",\"dark soft brown sugar\",\"golden syrup\",\"orange\",\"rolled oats\",\"Christmas pudding\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Preheat the oven to 180°C/fan 160°C/gas mark 4 and grease and line a 25cm x 20cm tin. Melt the butter, sugar, syrup and orange zest in a large saucepan over a m\",\"instructions\":[\"Preheat the oven to 180°C/fan 160°C/gas mark 4 and grease and line a 25cm x 20cm tin. Melt the butter, sugar, syrup and orange zest in a large saucepan over a medium heat. The aim is to dissolve all the ingredients so that they are smooth, but to not lose any volume through boiling so be careful not to overheat.\",\"Add the oats and stir well until evenly coated. Stir through the leftover Christmas pudding and tip into the prepared tin. Use a spoon to flatten the top and bake for 40 minutes until the edges start to brown. Whilst still warm in the tin, score into 12 squares. Allow to cool completely before cutting along the scores.\",\"Keeps for 5 days in an air tight tin or freeze for up to 1 month.\"]},{\"id\":\"g148\",\"title\":\"Christmas Pudding Trifle\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/r33cud1576791081.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Orange\",\"Demerara Sugar\",\"Grand Marnier\",\"Christmas Pudding\",\"Custard\",\"Mascarpone\",\"Double Cream\",\"Flaked Almonds\",\"Dark Chocolate\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Peel the oranges using a sharp knife, ensuring all the pith is removed. Slice as thinly as possible and arrange over a dinner plate. Sprinkle with the demerara \",\"instructions\":[\"Peel the oranges using a sharp knife, ensuring all the pith is removed. Slice as thinly as possible and arrange over a dinner plate. Sprinkle with the demerara sugar followed by the Grand Marnier and set aside.\",\"Crumble the Christmas pudding into large pieces and scatter over the bottom of a trifle bowl. Lift the oranges onto the pudding in a layer and pour over any juices.\",\"Beat the mascarpone until smooth, then stir in the custard. Spoon the mixture over the top of the oranges.\",\"Lightly whip the cream and spoon over the custard. Sprinkle with the flaked almonds and grated chocolate. You can make this a day in advance if you like, chill until ready to serve.\"]},{\"id\":\"g149\",\"title\":\"Chtitha Batata (Algerian Potato Stew)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/q8pu1k1764114334.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Garlic\",\"Red Chilli\",\"Ground Cumin\",\"Paprika\",\"Black Pepper\",\"Cayenne Pepper\",\"Salt\",\"Olive Oil\",\"New Potatoes\",\"Tomato Puree\",\"Water\",\"Salt\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Combine garlic, chile pepper, cumin, paprika, black pepper, cayenne, and salt in a mortar; grind with a pestle until it forms a paste. Add olive oil and mix der\",\"instructions\":[\"Combine garlic, chile pepper, cumin, paprika, black pepper, cayenne, and salt in a mortar; grind with a pestle until it forms a paste. Add olive oil and mix dersa well.\",\"Heat a large saucepan over medium heat and stir-fry dersa until fragrant, 2 to 4 minutes. Add potato halves and stir to combine with the dersa. Stir in tomato paste. Pour in enough water to just cover the potatoes and bring to a boil. Reduce heat and simmer until potatoes are tender, about 40 minutes.\",\"Ladle potatoes into a serving bowl. Spoon any remaining sauce over the potatoes.\"]},{\"id\":\"g150\",\"title\":\"Churros\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/nxnny61763250596.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Vanilla Extract\",\"Plain Flour\",\"Baking Powder\",\"Sunflower Oil\",\"Bread\",\"Dark Chocolate\",\"Double Cream\",\"Milk\",\"Golden Syrup\",\"Vanilla Extract\",\"Caster Sugar\",\"Cinnamon\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nBoil the kettle, then measure 300ml boiling water into a jug and add the melted butter and vanilla extract. Sift the flour and baking powder into a big \",\"instructions\":[\"step 1\",\"Boil the kettle, then measure 300ml boiling water into a jug and add the melted butter and vanilla extract. Sift the flour and baking powder into a big mixing bowl with a big pinch of salt. Make a well in the centre, then pour in the contents of the jug and very quickly beat into the flour with a wooden spoon until lump-free. Rest for 10-15 mins while you make the sauce.\",\"step 2\",\"Put all the sauce ingredients into a pan and gently melt together, stirring occasionally until you have a smooth shiny sauce. Keep warm on a low heat.\",\"step 3\",\"Fill a large deep saucepan one-third full of oil. Cooking with hot oil can be dangerous – before you start, read up on how to deep-fry safely to avoid accidents in the kitchen. Heat until a cube of bread browns in 45 seconds to 1 min. Cover a tray with kitchen paper and mix the caster sugar and cinnamon together.\",\"step 4\",\"Fit a star nozzle to a piping bag – 1.5-2cm wide is a good size. Fill with the rested dough, then pipe 2-3 strips directly into the pan, snipping off each dough strip with a pair of kitchen scissors. Fry until golden brown and crisp. Be very careful here – if air bubbles form in the churros they can explode, especially if the oil overheats or you use old flour. Cooking with hot oil can be dangerous – before you start, read up on how to deep-fry safely to avoid accidents in the kitchen. Keep children out of the kitchen and protect yourself by wearing long sleeves and eye protection, and keeping your face away from the pan.\",\"step 5\",\"Once the churros are crisp and golden brown, remove them from the oil with a slotted spoon and drain on the kitchen paper-lined tray. Carry on cooking the rest of the dough in batches, sprinkling the cooked churros with some cinnamon sugar as you go. When you’ve cooked all the churros, toss with any remaining cinnamon sugar and serve with the chocolate sauce, for dipping.\"]},{\"id\":\"g151\",\"title\":\"Cinnamon buns\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/as88dq1762772486.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Unsalted Butter\",\"Milk\",\"Salt\",\"Flour\",\"Strong White Flour\",\"Fast action yeast\",\"Cardamom\",\"Caster Sugar\",\"Egg\",\"Olive Oil\",\"Unsalted Butter\",\"Caster Sugar\",\"Cinnamon\",\"Egg\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a small saucepan heat the butter, milk and salt until the butter is melted. Allow the mixture to cool until it is lukewarm.\\r\\n\\r\\nIn a large bowl, stir together\",\"instructions\":[\"In a small saucepan heat the butter, milk and salt until the butter is melted. Allow the mixture to cool until it is lukewarm.\",\"In a large bowl, stir together the flours, yeast, cardamom and sugar until combined.\",\"Make a well in the centre and crack in the eggs. Pour in the lukewarm milk mixture and stir everything together to form a sticky dough. You may have to use your hands as the dough becomes stiffer.\",\"Oil the work surface with a teaspoon of olive oil. Turn the dough out onto the oiled surface and knead vigorously for 5–8 minutes, using a plastic scraper as needed to prise the dough from the work surface. Don’t be tempted to add flour, as this will make the buns dry and tough. Keep kneading until the dough is considerably less sticky, smoother and more elastic.\",\"Shape into a ball, and put into a large, greased bowl. Cover the bowl with a clean tea towel and set aside in a warm place to prove for an hour, or until doubled in size.\",\"Meanwhile, for the filling and topping, mix the softened butter in a bowl with half the sugar and 1 tablespoon cinnamon. Use a fork to mix the sugar and spice into the butter until it is completely combined.\",\"Mix the remaining sugar and cinnamon in a separate bowl and set aside.\",\"When the dough has risen, turn out onto a floured work surface and gently roll out into a 36x24cm/14x9½in rectangle. Spread the cinnamon-sugar-butter evenly over the dough with a table or palette knife.\",\"With the longest edge closest to you, roll the dough up into a cylinder. Cut into 12 even slices.\",\"Place each slice onto a flattened out paper cupcake case on a baking tray, or into a greased muffin tin. (Baking in a muffin tin will make your cinnamon buns taller and domed.)\"]},{\"id\":\"g152\",\"title\":\"Clam chowder\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rvtvuw1511190488.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Clams\",\"Butter\",\"Bacon\",\"Onion\",\"Thyme\",\"Bay Leaf\",\"Plain Flour\",\"Milk\",\"Double Cream\",\"Potatoes\",\"Parsley\"],\"allergens\":[\"milk\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Rinse the clams in several changes of cold water and drain well. Tip the clams into a large pan with 500ml of water. Cover, bring to the boil and simmer for 2 m\",\"instructions\":[\"Rinse the clams in several changes of cold water and drain well. Tip the clams into a large pan with 500ml of water. Cover, bring to the boil and simmer for 2 mins until the clams have just opened. Tip the contents of the pan into a colander over a bowl to catch the clam stock. When cool enough to handle, remove the clams from their shells – reserving a handful of empty shells for presentation if you want. Strain the clam stock into a jug, leaving any grit in the bottom of the bowl. You should have around 800ml stock.\",\"Heat the butter in the same pan and sizzle the bacon for 3-4 mins until it starts to brown. Stir in the onion, thyme and bay and cook everything gently for 10 mins until the onion is soft and golden. Scatter over the flour and stir in to make a sandy paste, cook for 2 mins more, then gradually stir in the clam stock then the milk and the cream.\",\"Throw in the potatoes, bring everything to a simmer and leave to bubble away gently for 10 mins or until the potatoes are cooked. Use a fork to crush a few of the potato chunks against the side of the pan to help thicken – you still want lots of defined chunks though. Stir through the clam meat and the few clam shells, if you've gone down that route, and simmer for a minute to reheat. Season with plenty of black pepper and a little salt, if needed, then stir through the parsley just before ladling into bowls or hollowed-out crusty rolls.\"]},{\"id\":\"g153\",\"title\":\"Clam, chorizo & white bean stew\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/92wbmf1763252334.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chorizo\",\"Onion\",\"Garlic Clove\",\"Parsley\",\"Vegetable Stock\",\"Tinned Tomatos\",\"Butter Beans\",\"Sherry vinegar\",\"Clams\",\"Crusty Bread\"],\"allergens\":[\"milk\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nFry the chorizo in a large frying pan with a lid, over a medium heat until it is starting to crisp up and release its oil. Add the onion and cook for 5 \",\"instructions\":[\"step 1\",\"Fry the chorizo in a large frying pan with a lid, over a medium heat until it is starting to crisp up and release its oil. Add the onion and cook for 5 mins until starting to soften. Then add the garlic and finely chopped parsley, and fry for 1 min more.\",\"step 2\",\"Pour on the stock and tomatoes. Bring to the boil, reduce the heat, then add the beans and sherry vinegar. Simmer for 10 mins until the liquid is slightly reduced.\",\"step 3\",\"Scatter over the clams, cover with the lid and steam for 2-4 mins, shaking the pan occasionally until the clams are open. Have a little taste before seasoning, as the clams can be quite salty. Then scatter over the chopped parsley. Eat with lots of crusty bread.\"]},{\"id\":\"g154\",\"title\":\"Classic Christmas pudding\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1d85821576790598.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Almonds\",\"Bramley Apples\",\"Candied Peel\",\"Nutmeg\",\"Raisins\",\"Plain Flour\",\"Breadcrumbs\",\"Muscovado Sugar\",\"Eggs\",\"Brandy\",\"Butter\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Get everything for the pudding prepared. Chop the almonds coarsely. Peel, core and chop the cooking apples. Sharpen your knife and chop the candied peel. (You c\",\"instructions\":[\"Get everything for the pudding prepared. Chop the almonds coarsely. Peel, core and chop the cooking apples. Sharpen your knife and chop the candied peel. (You can chop the almonds and apples in a food processor, but the peel must be done by hand.) Grate three quarters of the nutmeg (sounds a lot but it's correct).\",\"Mix the almonds, apples, candied peel, nutmeg, raisins, flour, breadcrumbs, light muscovado sugar, eggs and 2 tbsp brandy or cognac in a large bowl.\",\"Holding the butter in its wrapper, grate a quarter of it into the bowl, then stir everything together. Repeat until all the butter is grated, then stir for 3-4 mins – the mixture is ready when it subsides slightly after each stir. Ask the family to stir too, and get everyone to make a wish.\",\"Generously butter two 1.2 litre bowls and put a circle of baking parchment in the bottom of each. Pack in the pudding mixture. Cover with a double layer of baking parchment, pleating it to allow for expansion, then tie with string (keep the paper in place with a rubber band while tying). Trim off any excess paper.\",\"Now stand each bowl on a large sheet of foil and bring the edges up over the top, then put another sheet of foil over the top and bring it down underneath to make a double package (this makes the puddings watertight). Tie with more string, and make a handle for easy lifting in and out of the pan. Watch our video to see how to tie up a pudding correctly.\",\"Boil or oven steam the puddings for 8 hrs, topping up with water as necessary. Remove from the pans and leave to cool overnight. When cold, discard the messy wrappings and re-wrap in new baking parchment, foil and string. Store in a cool, dry place until Christmas.\",\"To make the brandy butter, cream the butter with the orange zest and icing sugar. Gradually beat in the brandy or cognac and chopped stem ginger. Put in a small bowl, fork the top attractively and put in the fridge to set. The butter will keep for a week in the fridge, or it can be frozen for up to six weeks.\",\"On Christmas Day, boil or oven steam for 1 hr. Unwrap and turn out. To flame, warm 3-4 tbsp brandy in a small pan, pour it over the pudding and set light to it.\"]},{\"id\":\"g155\",\"title\":\"Classic Tourtière\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0sd7ac1764787957.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Canola Oil\",\"Onion\",\"Garlic\",\"Ground Beef\",\"Ground Pork\",\"Dried Leaves Of Summer Savoury\",\"Salt\",\"Pepper\",\"Ground Clove\",\"Ground Nutmeg\",\"Bay Leaf\",\"Beef Stock\",\"Russet Potato\",\"Shortcrust Pastry\",\"Egg\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oil on medium-high heat in a large sauté pan or skillet, then sauté the onion and garlic until softened, about 5 minutes. Add the ground beef, pork, and sp\",\"instructions\":[\"Heat oil on medium-high heat in a large sauté pan or skillet, then sauté the onion and garlic until softened, about 5 minutes. Add the ground beef, pork, and spices and cook until the meat is browned.\",\"Add the beef broth and bring it up to a simmer then reduce heat to medium low. Add the grated potato and stir it in. Cook until liquid is almost absorbed, about 15 min. Remove the bay leaves and add salt to taste. Remove the pan from the heat and let the mixture cool completely — it bakes best if the filling is chilled.\",\"Preheat the oven to 375 °F (190 °C). On a lightly floured surface, roll out one disc of the pie dough to less than the 1/4-inch thickness and line the 9-inch pie plate. Fill this with the cooled tourtière mixture and spread out evenly. Roll out the remaining dough to the same thickness, cut a hole in the centre (for steam to escape) and place on top of the filling. Trim the dough to 1/2-inch beyond the edge of the pie plate and pinch the edges of the crust together. Brush the crust with the egg wash.\",\"Bake tourtière for about 45 minutes or until the pastry is a rich golden brown. Let cool for 15 minutes before slicing to serve.\",\"Serves: 8-10 (makes 2 9-inch pies)\"]},{\"id\":\"g156\",\"title\":\"Coddled pork with cider\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/7vpsfp1608588991.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Pork Chops\",\"Bacon\",\"Potatoes\",\"Carrots\",\"Swede\",\"Cabbage\",\"Bay Leaf\",\"Cider\",\"Chicken Stock\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\nHeat the butter in a casserole dish until sizzling, then fry the pork for 2-3 mins on each side until browned. Remove from the pan.\\r\\n\\r\\nSTEP 2\\r\\nTip the b\",\"instructions\":[\"STEP 1\",\"Heat the butter in a casserole dish until sizzling, then fry the pork for 2-3 mins on each side until browned. Remove from the pan.\",\"STEP 2\",\"Tip the bacon, carrot, potatoes and swede into the pan, then gently fry until slightly coloured. Stir in the cabbage, sit the chops back on top, add the bay leaf, then pour over the cider and stock. Cover the pan, then leave everything to gently simmer for 20 mins until the pork is cooked through and the vegetables are tender.\",\"STEP 3\",\"Serve at the table spooned straight from the dish.\"]},{\"id\":\"g157\",\"title\":\"Coq au vin\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qstyvs1505931190.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Bacon\",\"Shallots\",\"Chicken Legs\",\"Chicken Thighs\",\"Chicken Breasts\",\"Garlic\",\"Brandy\",\"Red Wine\",\"Chicken Stock\",\"tomato puree\",\"thyme\",\"Rosemary\",\"bay leaves\",\"parsley\",\"chestnut mushroom\",\"plain flour\",\"butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat 1 tbsp of the oil in a large, heavy-based saucepan or flameproof dish. Tip in the bacon and fry until crisp. Remove and drain on kitchen paper. Add the sha\",\"instructions\":[\"Heat 1 tbsp of the oil in a large, heavy-based saucepan or flameproof dish. Tip in the bacon and fry until crisp. Remove and drain on kitchen paper. Add the shallots to the pan and fry, stirring or shaking the pan often, for 5-8 mins until well browned all over. Remove and set aside with the bacon.\",\"Pat the chicken pieces dry with kitchen paper. Pour the remaining oil into the pan, then fry half the chicken pieces, turning regularly, for 5-8 mins until well browned. Remove, then repeat with the remaining chicken. Remove and set aside.\",\"Scatter in the garlic and fry briefly, then, with the heat medium-high, pour in the brandy or Cognac, stirring the bottom of the pan to deglaze. The alcohol should sizzle and start to evaporate so there is not much left.\",\"Return the chicken legs and thighs to the pan along with any juices, then pour in a little of the wine, stirring the bottom of the pan again. Stir in the rest of the wine, the stock and tomato purée, drop in the bouquet garni, season with pepper and a pinch of salt, then return the bacon and shallots to the pan. Cover, lower the heat to a gentle simmer, add the chicken breasts and cook for 50 mins-1hr.\",\"Just before ready to serve, heat the oil for the mushrooms in a large non-stick frying pan. Add the mushrooms and fry over a high heat for a few mins until golden. Remove and keep warm.\",\"Lift the chicken, shallots and bacon from the pan and transfer to a warmed serving dish. Remove the bouquet garni. To make the thickener, mix the flour, olive oil and butter in a small bowl using the back of a teaspoon. Bring the wine mixture to a gentle boil, then gradually drop in small pieces of the thickener, whisking each piece in using a wire whisk. Simmer for 1-2 mins. Scatter the mushrooms over the chicken, then pour over the wine sauce. Garnish with chopped parsley.\"]},{\"id\":\"g158\",\"title\":\"Corba\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/58oia61564916529.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lentils\",\"Onion\",\"Carrots\",\"Tomato Puree\",\"Cumin\",\"Paprika\",\"Mint\",\"Thyme\",\"Black Pepper\",\"Red Pepper Flakes\",\"Vegetable Stock\",\"Water\",\"Sea Salt\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Pick through your lentils for any foreign debris, rinse them 2 or 3 times, drain, and set aside.  Fair warning, this will probably turn your lentils into a soli\",\"instructions\":[\"Pick through your lentils for any foreign debris, rinse them 2 or 3 times, drain, and set aside.  Fair warning, this will probably turn your lentils into a solid block that you’ll have to break up later\",\"In a large pot over medium-high heat, sauté the olive oil and the onion with a pinch of salt for about 3 minutes, then add the carrots and cook for another 3 minutes.\",\"Add the tomato paste and stir it around for around 1 minute. Now add the cumin, paprika, mint, thyme, black pepper, and red pepper as quickly as you can and stir for 10 seconds to bloom the spices. Congratulate yourself on how amazing your house now smells.\",\"Immediately add the lentils, water, broth, and salt. Bring the soup to a (gentle) boil.\",\"After it has come to a boil, reduce heat to medium-low, cover the pot halfway, and cook for 15-20 minutes or until the lentils have fallen apart and the carrots are completely cooked.\",\"After the soup has cooked and the lentils are tender, blend the soup either in a blender or simply use a hand blender to reach the consistency you desire. Taste for seasoning and add more salt if necessary.\",\"Serve with crushed-up crackers, torn up bread, or something else to add some extra thickness.  You could also use a traditional thickener (like cornstarch or flour), but I prefer to add crackers for some texture and saltiness.  Makes great leftovers, stays good in the fridge for about a week.\"]},{\"id\":\"g159\",\"title\":\"Corned Beef and Cabbage\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xb97a81583266727.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Brisket\",\"Small Potatoes\",\"Carrots\",\"Cabbage\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\n\\r\\nPlace corned beef in large pot or Dutch oven and cover with water. Add the spice packet that came with the corned beef. Cover pot and bring to a boil, then\",\"instructions\":[\"1\",\"Place corned beef in large pot or Dutch oven and cover with water. Add the spice packet that came with the corned beef. Cover pot and bring to a boil, then reduce to a simmer. Simmer approximately 50 minutes per pound or until tender.\",\"2\",\"Add whole potatoes and peeled and cut carrots, and cook until the vegetables are almost tender. Add cabbage and cook for 15 more minutes. Remove meat and let rest 15 minutes.\",\"3\",\"Place vegetables in a bowl and cover. Add as much broth (cooking liquid reserved in the Dutch oven or large pot) as you want. Slice meat across the grain.\"]},{\"id\":\"g160\",\"title\":\"Corned Beef and Cabbage – Jamaican Style\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kdz63q1764793442.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Cabbage\",\"Green Pepper\",\"Onion\",\"Garlic\",\"Corned Beef\",\"Plum Tomatoes\",\"Thyme\",\"Tomato Ketchup\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat olive oil in a skillet or Dutch pot over medium-high heat. Add onion and green pepper and sauté for about 3-5 minutes.\\r\\nAdd garlic and stir for about 1 min\",\"instructions\":[\"Heat olive oil in a skillet or Dutch pot over medium-high heat. Add onion and green pepper and sauté for about 3-5 minutes.\",\"Add garlic and stir for about 1 minute.\",\"Add shredded cabbage and stir. Cook for about about 3-5 minutes, stirring often until softened.\",\"Add corned beef, Roma tomatoes, and thyme and stir. Add ketchup and scotch bonnet pepper sauce and stir. Reduce heat and cook on medium for about 3-5 minutes, until the corned beef is heated through. Remove from heat.\",\"Serve with white rice, bread, or on its own.\"]},{\"id\":\"g161\",\"title\":\"Corned Beef Hash\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vz94r81760534692.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Unsalted Butter\",\"Onion\",\"Corned Beef\",\"Potatoes\",\"Kosher Salt\",\"Black Pepper\",\"Freshly Chopped Parsley\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Sauté the onions:\\r\\nHeat butter in a large skillet (preferably cast iron) on medium heat. Add the onion and cook a few minutes, until translucent.\\r\\n\\r\\nAdd the pot\",\"instructions\":[\"Sauté the onions:\",\"Heat butter in a large skillet (preferably cast iron) on medium heat. Add the onion and cook a few minutes, until translucent.\",\"Add the potatoes and corned beef:\",\"Mix in the chopped corned beef and potatoes. Spread out evenly over the pan. Increase the heat to high or medium high and press down on the mixture with a metal spatula.\",\"Cook until browned and then flip:\",\"Do not stir the potatoes and corned beef, but let them brown. If you hear them sizzling, this is good.\",\"Use a metal spatula to peek underneath and see if they are browning. If nicely browned, use the spatula to flip sections over in the pan so that they brown on the other side. Press down again with the spatula.\",\"If there is too much sticking, you can add a little more butter to the pan. Continue to cook in this manner until the potatoes and the corned beef are nicely browned.\",\"Stir in the parsley and season:\",\"Remove from heat, stir in chopped parsley. Add plenty of freshly ground black pepper, and add salt to taste.\"]},{\"id\":\"g162\",\"title\":\"Cornes de Gazelle (Gazelle Horns)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0h1b7m1764120235.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Almonds\",\"Sugar\",\"Sugar\",\"Ground Cinnamon\",\"Egg\",\"Orange Blossom Water\",\"All purpose flour\",\"Unsalted Butter\",\"Salt\",\"Egg\",\"Vegetable Oil\",\"Orange Blossom Water\",\"Pistachio\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 300 degrees F (150 degrees C). Line a baking sheet with parchment paper. Spread almonds over the baking sheet.\\r\\n\\r\\nBake in the preheated oven unt\",\"instructions\":[\"Preheat oven to 300 degrees F (150 degrees C). Line a baking sheet with parchment paper. Spread almonds over the baking sheet.\",\"Bake in the preheated oven until almonds are fragrant and roasted, 20 to 25 minutes.\",\"Prepare pastry dough while almonds are roasting. Combine flour, 1/2 cup plus 1 tablespoon butter, and salt in a bowl and rub together until the mixture resembles breadcrumbs. Add egg, oil, and 1 1/2 tablespoons orange blossom water; knead everything into a smooth pastry dough. Add a little water, 1 teaspoon at a time, if dough is too dry. Shape pastry dough into a ball, wrap in plastic wrap, and set aside for 30 minutes.\",\"Remove almonds from oven and cool slightly, about 5 minutes. Place almonds in the bowl of a food processor; process until finely and evenly ground. Add 3/4 cup plus 1 tablespoon sugar, cinnamon, egg, and 1 tablespoon orange blossom water in that order to the food processor, pulsing after each addition until mixture is evenly combined and resembles a paste.\",\"Remove small walnut-sized portions of filling with greased hands. Roll them into small logs with thin ends. Set aside.\",\"Preheat oven to 325 degrees F (165 degrees C). Line a baking sheet with parchment paper.\",\"Roll out half of the pastry dough on a lightly floured surface until very thin. Place one of the almond paste logs on the edge of the pastry, fold pastry over the filling, covering it completely, and seal the edges. Mold with your fingers into a crescent shape. Using a pastry cutter, cut around the crescent, and transfer to the prepared baking sheet. Repeat with remaining dough and filling.\",\"Bake in the preheated oven until gazelle horns are lightly golden and baked through, about 20 minutes. They should not get too dark. Let cool slightly, about 3 minutes.\",\"Heat honey in a small saucepan over low-medium heat. Remove from heat and stir in 1 tablespoon orange blossom water. Dip gazelle horns into the honey and place on a serving plate. Sprinkle with crushed pistachios.\"]},{\"id\":\"g163\",\"title\":\"Cream Cheese Tart\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wurrux1468416624.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Butter\",\"Egg\",\"Salt\",\"Cheese\",\"Milk\",\"Eggs\",\"Parmesan Cheese\",\"Plum tomatoes\",\"White Vinegar\",\"Honey\",\"Basil\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Crust: make a dough from 250g flour (I like mixing different flours like plain and wholegrain spelt flour), 125g butter, 1 egg and a pinch of salt, press it int\",\"instructions\":[\"Crust: make a dough from 250g flour (I like mixing different flours like plain and wholegrain spelt flour), 125g butter, 1 egg and a pinch of salt, press it into a tart form and place it in the fridge.\",\"Filling: stir 300g cream cheese and 100ml milk until smooth, add in 3 eggs, 100g grated parmesan cheese and season with salt, pepper and nutmeg.\",\"Take the crust out of the fridge and prick the bottom with a fork.\",\"Pour in the filling and bake at 175 degrees C for about 25 minutes.\",\"Cover the tart with some aluminium foil after half the time.\",\"In the mean time, slice about 350g mini tomatoes.\",\"In a small pan heat 3tbsp olive oil, 3tbsp white vinegar, 1 tbsp honey, salt and pepper and combine well.\",\"Pour over the tomato slices and mix well.\",\"With a spoon, place the tomato slices on the tart, avoiding too much liquid on it.\",\"Decorate with basil leaves and enjoy.\"]},{\"id\":\"g164\",\"title\":\"Creamy Tomato Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/stpuws1511191310.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onions\",\"Celery\",\"Carrots\",\"Potatoes\",\"Bay Leaf\",\"Tomato Puree\",\"Sugar\",\"White Vinegar\",\"Chopped Tomatoes\",\"Passata\",\"Vegetable Stock Cube\",\"Whole Milk\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Put the oil, onions, celery, carrots, potatoes and bay leaves in a big casserole dish, or two saucepans. Fry gently until the onions are softened – about 10-15 \",\"instructions\":[\"Put the oil, onions, celery, carrots, potatoes and bay leaves in a big casserole dish, or two saucepans. Fry gently until the onions are softened – about 10-15 mins. Fill the kettle and boil it.\",\"Stir in the tomato purée, sugar, vinegar, chopped tomatoes and passata, then crumble in the stock cubes. Add 1 litre boiling water and bring to a simmer. Cover and simmer for 15 mins until the potato is tender, then remove the bay leaves. Purée with a stick blender (or ladle into a blender in batches) until very smooth. Season to taste and add a pinch more sugar if it needs it. The soup can now be cooled and chilled for up to 2 days, or frozen for up to 3 months.\",\"To serve, reheat the soup, stirring in the milk – try not to let it boil. Serve in small bowls with cheesy sausage rolls.\"]},{\"id\":\"g165\",\"title\":\"Crema Catalana\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/x73ll91763247842.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Milk\",\"Double Cream\",\"Cinnamon Stick\",\"Orange Zest\",\"Lemon Zest\",\"Egg Yolks\",\"Caster Sugar\",\"Caster Sugar\",\"Corn Flour\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the milk, cream, cinnamon stick and all the citrus zest in a saucepan set over a medium heat. Cook, stirring often, until the milk is just steaming \",\"instructions\":[\"step 1\",\"Put the milk, cream, cinnamon stick and all the citrus zest in a saucepan set over a medium heat. Cook, stirring often, until the milk is just steaming but not boiling, about 3-5 mins. Remove from the heat, cover with a plate and leave to infuse for at least 30 mins.\",\"step 2\",\"When the cream mixture has infused, whisk the egg yolks, sugar and cornflour together in a separate bowl for 3-5 mins, or until light and pale in colour. Pour the infused milk through a sieve into the egg mixture, whisking continuously. Return the mixture to the saucepan.\",\"step 3\",\"Put the saucepan over a medium-high heat and whisk for around 10-12 mins. The mixture should start thickening to a custard-like consistency – you can tell it’s ready by dipping a wooden spoon in the mixture, then running a finger through the mixture on the back of the spoon. If the line holds, it's ready. Sieve the mixture into a jug to remove any froth.\",\"step 4\",\"Divide the custard between six 150ml ramekins or small terracotta dishes, then leave to cool for 1 hr at room temperature until set with a slight wobble. Chill overnight.\",\"step 5\",\"Just before serving, sprinkle 1 tbsp caster sugar over the top of each ramekin and caramelise using a kitchen blowtorch. Alternatively, slide the ramekins under a hot grill until the sugar turns golden and starts to bubble. Serve straightaway.\"]},{\"id\":\"g166\",\"title\":\"Crispy Eggplant\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/c7lzrl1683208757.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg Plants\",\"Breadcrumbs\",\"Sesame Seed\",\"Eggs\",\"Salt\",\"Pepper\",\"Vegetable Oil\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Slice eggplant into 1 cm (0.4-inch) slices. Place them in a bowl and sprinkle them with salt. allow them to sit for 30 minutes to render some of their liquid an\",\"instructions\":[\"Slice eggplant into 1 cm (0.4-inch) slices. Place them in a bowl and sprinkle them with salt. allow them to sit for 30 minutes to render some of their liquid and bitterness.\",\"2. After 30 minutes wash eggplant slices from salt and pat dry with a kitchen towel.\",\"3. In a large bowl/plate place breadcrumbs and sesame seeds. In another bowl beat 2 eggs with pinch salt and pepper.\",\"4. Heal oil in a large skillet over high heat.\",\"5. Dip eggplant slices in egg, then in crumbs, and place in hot oil. Fry 2 to 3 minutes on each side, or until golden brown. Drain on a paper towel.\"]},{\"id\":\"g167\",\"title\":\"Crispy Sausages and Greens\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/st1ifa1583267248.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Kale\",\"Italian Fennel Sausages\",\"Cabbage\",\"Garlic Clove\",\"Onion\",\"Shiitake Mushrooms\",\"Chicken Stock\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 350°. Remove the stems from one bunch of Tuscan kale and tear the leaves into 1\\\" pieces (mustard greens, collards, spinach, and chard are gr\",\"instructions\":[\"Preheat the oven to 350°. Remove the stems from one bunch of Tuscan kale and tear the leaves into 1\\\" pieces (mustard greens, collards, spinach, and chard are great, too). Coarsely chop half a head of green cabbage. Combine the greens in a large baking dish and add 4 cloves of thinly sliced garlic. Adding some sliced onions and shiitake mushrooms at this point is optional, but highly recommended (I'll sauté the onions and mushrooms in a cast iron baking dish right on the stove before adding to the greens). Coat the greens with some olive oil and pour ½ cup chicken stock or broth over everything. Cover the dish with foil and bake until the greens are wilted, about 15 minutes. Remove foil and season with salt and pepper. Continue to bake until cabbage is tender, about 20-25 minutes more.\",\"Meanwhile, heat a little olive oil in a large skillet over medium-high. Prick four sweet Italian sausages with a fork and cook until browned on all sides and cooked through, 10 to 12 minutes. When the greens are done, slice the sausage and toss into the greens with a splash of your favorite vinegar (I like sherry or red wine).\"]},{\"id\":\"g168\",\"title\":\"Croatian Bean Stew\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tnwy8m1628770384.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cannellini Beans\",\"Vegetable Oil\",\"Tomatoes\",\"Challots\",\"Garlic\",\"Parsley\",\"Chorizo\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the oil in a pan. Add the chopped vegetables and sauté until tender. Take a pot, empty the beans together with the vegetables into it, put the sausages ins\",\"instructions\":[\"Heat the oil in a pan.\",\"Add the chopped vegetables and sauté until tender.\",\"Take a pot, empty the beans together with the vegetables into it, put the sausages inside and cook for further 20 minutes on a low heat.\",\"Or, put it in an oven and bake it at a temperature of 180ºC/350ºF for 30 minutes.\",\"This dish is even better reheated the next day.\"]},{\"id\":\"g169\",\"title\":\"Croatian lamb peka\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pn59o51628769837.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Courgettes\",\"Carrots\",\"Green Pepper\",\"Aubergine\",\"Onion\",\"Lamb Shoulder\",\"Garlic Sauce\",\"Tomato Puree\",\"Olive Oil\",\"Thyme\",\"White Wine\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Preheat oven to 200°C fan / 220°C / 425°F / Gas mark 7\\r\\nIf you have not bought diced lamb, cut your lamb shoulder or leg into large chunks and place to one side\",\"instructions\":[\"Preheat oven to 200°C fan / 220°C / 425°F / Gas mark 7\",\"If you have not bought diced lamb, cut your lamb shoulder or leg into large chunks and place to one side.\",\"Chunks of chopped lamb of a red chopping board\",\"Make oil marinade -\",\"Mix 80ml of olive oil in a bowl with garlic puree, sundried tomato puree ,black pepper and salt.\",\"olive oil, gia sundried tomato puree and gia garlic puree and black pepper mixed together in a silver bowl to make Croatian peka\",\"Add potatoes and vegetables into a large lidded casserole dish.\",\"Chopped up vegetables which consist of chopped up red onion, courgette, potatoes red peppers in a cast iron pan\",\"Place diced lamb on top of the vegetables, pour the marinade and wine over the top.\",\"Chunks of lamb covered in in a sundried tomato oil sauce which is on top of chopped red onion, aubergine, courgette and potatoes in a cast iron pan\"]},{\"id\":\"g170\",\"title\":\"Crock Pot Chicken Baked Tacos\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ypxvwv1505333929.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breasts\",\"Vinaigrette Dressing\",\"Cumin\",\"Smoked Paprika\",\"Garlic\",\"Refried Beans\",\"Hard Taco Shells\",\"Shredded Mexican Cheese\",\"Grape Tomatoes\",\"Jalapeno\",\"Avocado\",\"Green Salsa\",\"Sour Cream\",\"Milk\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Put the uncooked chicken breasts in the crock pot. Pour the full bottle of salad dressing over the chicken. Sprinkle the rest of the ingredients over the top an\",\"instructions\":[\"Put the uncooked chicken breasts in the crock pot. Pour the full bottle of salad dressing over the chicken. Sprinkle the rest of the ingredients over the top and mix them in a bit with a spoon.\",\"Cover your crock pot with the lid and cook on high for 4 hours.\",\"Remove all the chicken breasts from the crock pot and let cool.\",\"Shred the chicken breasts and move to a glass bowl.\",\"Pour most of the liquid over the shredded chicken.\",\"FOR THE TACOS:\",\"Make the guacamole sauce by mixing the avocado and green salsa together. Pour the guacamole mixture through a strainer until smooth and transfer to a squeeze bottle. Cut the tip off the lid of the squeeze bottle to make the opening more wide if needed.\",\"Make the sour cream sauce by mixing the sour cream and milk together until you get a more liquid sour cream sauce. Transfer to a squeeze bottle.\",\"In a 9x 13 glass baking dish, fill all 12+ tacos with a layer of refried beans, cooked chicken and shredded cheese.\",\"Bake at 450 for 10-15 minutes just until the cheese is melted and bubbling.\"]},{\"id\":\"g171\",\"title\":\"Cucumber & fennel salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ei21r61764365935.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cucumber\",\"Sugar\",\"Fennel Bulb\",\"Sour Cream\",\"Lemon\",\"White Wine Vinegar\",\"Dill\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut cucumber in a sieve. Sprinkle with 1 tsp salt and the sugar, then leave for 10 mins. Add fennel.\\r\\n\\r\\nstep 2\\r\\nMix soured cream, lemon juice, vinegar a\",\"instructions\":[\"step 1\",\"Put cucumber in a sieve. Sprinkle with 1 tsp salt and the sugar, then leave for 10 mins. Add fennel.\",\"step 2\",\"Mix soured cream, lemon juice, vinegar and dill, then season with black pepper and add to fennel mix.\"]},{\"id\":\"g172\",\"title\":\"Cumberland Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pvfkz61761595976.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Celery\",\"Onion\",\"Carrots\",\"Bay Leaves\",\"Thyme\",\"Vegetable Oil\",\"Butter\",\"Flour\",\"Tomato Puree\",\"Worcestershire Sauce\",\"Beef Stock Cubes\",\"Feather blade beef\",\"Potatoes\",\"Mature Cheddar\",\"Parmesan Cheese\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 160C/140C fan/gas 3. Soften the celery, onion, carrots, bay and 1 thyme sprig in a casserole with 1 tbsp oil and the butter for 10 mins. St\",\"instructions\":[\"step 1\",\"Heat oven to 160C/140C fan/gas 3. Soften the celery, onion, carrots, bay and 1 thyme sprig in a casserole with 1 tbsp oil and the butter for 10 mins. Stir in the flour, followed by the purée, Worcestershire sauce and stock cubes.\",\"step 2\",\"Gradually stir in 600ml hot water, then tip in the beef and bring to a gentle simmer. Cover and cook in the oven for 2 hrs 30 mins, then uncover and cook for 30 mins -1 hr more until the meat is really tender and sauce thickened.\",\"step 3\",\"Meanwhile, cook potatoes in a pan of boiling water until they’re not done but about ¾ of the way there.\",\"step 4\",\"Transfer meat to a baking dish. Slice spuds into 1cm thick rounds and gently toss with seasoning, the remaining oil and thyme leaves. Layer on the beef, scattering with the cheese as you layer. You can cover and chill the pie now for 1 day, or freeze for up to 3 months.\",\"step 5\",\"Increase oven to 200C/180C fan/gas 6 and bake for 30-40 mins until golden and crispy, and sauce bubbling if the dish went in cold. Serve with peas.\"]},{\"id\":\"g173\",\"title\":\"Dal fry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wuxrtu1483564410.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Toor dal\",\"Water\",\"Salt\",\"Turmeric\",\"Ghee\",\"Chopped tomatoes\",\"Cumin seeds\",\"Mustard Seeds\",\"Bay Leaf\",\"Green Chilli\",\"Ginger\",\"Cilantro\",\"Red Pepper\",\"Salt\",\"Sugar\",\"Garam Masala\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Wash and soak toor dal in approx. 3 cups of water, for at least one hours. Dal will be double in volume after soaking. Drain the water.\\r\\nCook dal with 2-1/2 cup\",\"instructions\":[\"Wash and soak toor dal in approx. 3 cups of water, for at least one hours. Dal will be double in volume after soaking. Drain the water.\",\"Cook dal with 2-1/2 cups water and add salt, turmeric, on medium high heat, until soft in texture (approximately 30 mins) it should be like thick soup.\",\"In a frying pan, heat the ghee. Add cumin seeds, and mustard seeds. After the seeds crack, add bay leaves, green chili, ginger and chili powder. Stir for a few seconds.\",\"Add tomatoes, salt and sugar stir and cook until tomatoes are tender and mushy.\",\"Add cilantro and garam masala cook for about one minute.\",\"Pour the seasoning over dal mix it well and cook for another minute.\",\"Serve with Naan.\"]},{\"id\":\"g174\",\"title\":\"Date squares\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/u4scbo1764446514.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pitted Dates\",\"Water\",\"Vanilla\",\"Oats\",\"All purpose flour\",\"Brown Sugar\",\"Baking Powder\",\"Salt\",\"Unsalted Butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Preheat oven to 350°F (180°C). Grease an 8-inch (20 cm) square baking pan.\\r\\nTo make the date filing: Combine the dates and water in a medium saucepan over high \",\"instructions\":[\"Preheat oven to 350°F (180°C). Grease an 8-inch (20 cm) square baking pan.\",\"To make the date filing: Combine the dates and water in a medium saucepan over high heat and bring to a boil. Reduce heat to low and simmer gently, stirring occasionally until the mixture thickens, around 6 to 8 minutes. Remove from heat, stir in vanilla and let cool. Set aside.\",\"Combine rolled oats, flour, sugar, baking soda and salt in a food processor. Pulse 3 times (careful not to overmix, you don’t want the mixture to be powdery, just combined). Add butter and pulse again until the mixture is crumbly in pea-sized clumps. Transfer to a mixing bowl to thoroughly mix in the butter.\",\"Spread half of the oat mixture on the bottom of the prepared baking pan, pressing down to make a flat, equal bottom later. Add the date mixture over the crust and then spread evenly. Layer with the remaining oat mixture and press down to flatten the top layer.\",\"Bake in the centre of the oven until the top is golden brown, 30 to 35 minutes. Let cool completely in the pan before cutting and serving. Date Squares keep well, covered in the refrigerator for up to a week, and frozen for 2 to 3 months.\"]},{\"id\":\"g175\",\"title\":\"Drunken noodles (pad kee mao)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/2wx8cm1763373419.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flat Rice Noodles\",\"Vegetable Oil\",\"Garlic\",\"Birds-eye Chillies\",\"Sirloin steak\",\"Broccoli\",\"Basil Leaves\",\"Soy Sauce\",\"Oyster Sauce\",\"Fish Sauce\",\"Sugar\"],\"allergens\":[\"soy\",\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPrepare the noodles following pack instructions, then drain and set aside. Combine all the ingredients for the sauce in a small bowl or jug, and set asi\",\"instructions\":[\"step 1\",\"Prepare the noodles following pack instructions, then drain and set aside. Combine all the ingredients for the sauce in a small bowl or jug, and set aside.\",\"step 2\",\"Heat the oil in a large wok or frying pan over a high heat and stir-fry the garlic and chilli for 20 seconds until just starting to turn golden. Add the steak and stir-fry for 1 minute until seared and starting to brown. Add the broccoli and stir-fry for another minute, then tip in the noodles and add the sauce. Stir-fry for another 1-2 mins until well combined and piping hot.\",\"step 3\",\"Stir through the basil and turn off the heat. Serve immediately to avoid overcooking.\"]},{\"id\":\"g176\",\"title\":\"Duck Confit\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wvpvsu1511786158.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sea Salt\",\"Bay Leaf\",\"Garlic\",\"Thyme\",\"Duck Legs\",\"White Wine\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"The day before you want to make the dish, scatter half the salt, half the garlic and half of the herbs over the base of a small shallow dish. Lay the duck legs,\",\"instructions\":[\"The day before you want to make the dish, scatter half the salt, half the garlic and half of the herbs over the base of a small shallow dish. Lay the duck legs, skin-side up, on top, then scatter over the remaining salt, garlic and herbs. Cover the duck and refrigerate overnight. This can be done up to 2 days ahead.\",\"Pour the wine into a saucepan that will snugly fit the duck legs in a single layer. Brush the salt off the duck legs and place them, skin-side down, in the wine. Cover the pan with a lid and place over a medium heat. As soon as the wine starts to bubble, turn the heat down to the lowest setting and cook for 2 hours, checking occasionally that the liquid is just barely simmering. (If you own a heat diffuser, it would be good to use it here.) After 2 hours, the duck legs should be submerged in their own fat and the meat should feel incredibly tender when prodded. Leave to cool.\",\"The duck legs are now cooked and can be eaten immediately – or you can follow the next step if you like them crisp. If you are preparing ahead, pack the duck legs tightly into a plastic container or jar and pour over the fat, but not the liquid at the bottom of the pan. Cover and leave in the fridge for up to a month, or freeze for up to 3 months. The liquid you are left with makes a tasty gravy, which can be chilled or frozen until needed.\",\"To reheat and crisp up the duck legs, heat oven to 220C/fan 200C/gas 7. Remove the legs from the fat and place them, skin-side down, in an ovenproof frying pan. Roast for 30-40 mins, turning halfway through, until brown and crisp. Serve with the reheated gravy, a crisp salad and some crisp golden ptoatoes.\"]},{\"id\":\"g177\",\"title\":\"Dulce de Leche\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/jyjlhj1763075323.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Milk\",\"Sugar\",\"Baking Powder\",\"Vanilla Extract\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Combine Ingredients: In a large, heavy-bottomed pot, mix the milk, sugar, and baking soda. Cook over low heat, stirring constantly to prevent burning.\\r\\nThicken:\",\"instructions\":[\"Combine Ingredients: In a large, heavy-bottomed pot, mix the milk, sugar, and baking soda. Cook over low heat, stirring constantly to prevent burning.\",\"Thicken: Continue to cook, stirring frequently, until the mixture becomes thick and caramel-colored, about 1-2 hours.\",\"Flavor: Stir in the vanilla extract.\",\"Cool: Let the dulce de leche cool, then transfer to a jar. It will thicken further as it cools.\",\"Pro Tips:\",\"Stir continuously and keep the heat low to prevent the milk from burning and sticking to the bottom of the pan.\",\"A drop of vanilla extract added at the end of cooking enhances the flavor.\"]},{\"id\":\"g178\",\"title\":\"Dundee cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wxyvqq1511723401.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Almonds\",\"Butter\",\"Muscovado Sugar\",\"Orange\",\"Apricot Jam\",\"Plain Flour\",\"Baking Powder\",\"Eggs\",\"Ground Almonds\",\"Milk\",\"Dried Fruit\",\"Glace Cherry\",\"Milk\",\"Caster Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Put the almonds into a small bowl and pour over boiling water to just cover. Leave for 5 mins then drain in a sieve and leave to dry.\\r\\nPreheat the oven to 180C/\",\"instructions\":[\"Put the almonds into a small bowl and pour over boiling water to just cover. Leave for 5 mins then drain in a sieve and leave to dry.\",\"Preheat the oven to 180C/160 C fan/Gas Mark 4. Line a deep loose-based 20cm cake tin with baking parchment.\",\"Put the butter in a large bowl and beat well until soft. Add the sugar and beat until light and fluffy. Stir in the orange zest and apricot jam.\",\"Sieve together the flour and baking powder. Add the eggs to the creamed butter and sugar, a little at a time, beating well between each addition. If the mixture starts to curdle, stir in a little flour.\",\"Add the remaining flour and ground almonds and mix well. Mix in the milk and then add the dried fruit and cherries and mix gently together.\",\"Spoon the mixture into the prepared tin and spread level using the back of a spoon. Arrange the whole almonds close together in neat circles on the top of the cake. Bake in the oven for 45 mins.\",\"Lower the oven temperature to 160C/140 C fan/Gas Mark 3 and cook for a further 60–80 minutes. Check the cake after 50 minutes by inserting a wooden or metal skewer into the cake. When it’s done it should have just a few crumbs attached. Check every 10 minutes - it’s important not to overcook this cake so the centre will be a little soft.\",\"When cooked, remove the cake briefly from the oven, put the milk and sugar into a small pan and heat gently until the sugar has dissolved. Brush over the top of the cake and return the cake to the oven for 2-3 mins. Remove and allow the cake to cool in the tin. When quite cold remove from the tin and wrap in foil and keep for at least 2 days before cutting.\"]},{\"id\":\"g179\",\"title\":\"Dutch poffertjes (mini pancakes)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/oaqz9f1766593912.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Buckwheat Flour\",\"Eggs\",\"Butter\",\"Milk\",\"Yeast\",\"vanilla sugar\",\"Butter\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix the dry yeast with some of the luke warm milk en stir until dissolved.\\r\\nPlace buckwheat and the flour together in a bowl and make a small circle in the midd\",\"instructions\":[\"Mix the dry yeast with some of the luke warm milk en stir until dissolved.\",\"Place buckwheat and the flour together in a bowl and make a small circle in the middle. Add the yeast mixture into it. Add the milk and stir until you have a smooth batter.\",\"Add the eggs, salt and vanille sugar and stir through. Leave to stand and rise for about 45 minutes.\",\"Heat the poffertjespan and add a bit of butter into each hole. Fill halfway with batter and first bake one side until you can see the top dry out a little. Turn the poffertjes around with a small fork and bake the other side until cooked and golden brown.\",\"Serve the poffertjes with butter and icing sugar\"]},{\"id\":\"g180\",\"title\":\"Dutch stroopwafel\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8cvkcz1766596315.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Milk\",\"Instant Yeast\",\"All purpose flour\",\"Unsalted Butter\",\"Sugar\",\"Egg\",\"Salt\",\"Dutch Stroop\",\"Brown Sugar\",\"Unsalted Butter\",\"Cinnamon\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Combine milk and yeast in a bowl. Let stand for a moment to allow the yeast to dissolve.\\r\\nIn another bowl, combine flour, butter, sugar, egg, and salt. Pour in \",\"instructions\":[\"Combine milk and yeast in a bowl. Let stand for a moment to allow the yeast to dissolve.\",\"In another bowl, combine flour, butter, sugar, egg, and salt. Pour in the yeast mixture and knead until smooth. Cover the bowl and let the dough rise for one hour.\",\"When the dough is almost ready, make the stroop filling. Combine all the ingredients in a saucepan and stir until the butter is melted and the sugar is dissolved. Let it simmer for a while. The stroop will continue to thicken as it cools.\",\"Shape the dough into balls weighing about 35 grams each. Make a total of 14. Turn your stroopwafel iron on the highest setting.\",\"Place a ball of dough in the iron and close the iron. Don’t flatten the waffle too much; you should still be able to cut through it. Bake for 1-2 minutes until the waffle is nicely golden brown.\",\"When the waffle is done, work quickly. Remove the waffle from the iron and immediately use a round cutter to cut out a nice circle of about 8 to 9 cm (3 to 3.5 inches).\",\"Place the hot waffle on a cutting board and cut horizontally with a sharp knife. The stroopwafel is very hot, so use an oven mitt to hold it in place.\",\"Take half a waffle and spread the (hot!) stroop on it. Place the other half on top, pressing gently if necessary, and place the waffle on a wire rack to cool. Repeat for all the balls.\"]},{\"id\":\"g181\",\"title\":\"Dziriat (Algerian Almond Tarts)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ne5wzp1764115568.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sugar\",\"Water\",\"Lemon Juice\",\"Orange Blossom Water\",\"All purpose flour\",\"Vegetable Oil\",\"Egg\",\"Lemon Juice\",\"Salt\",\"Orange Blossom Water\",\"Almonds\",\"Sugar\",\"Egg\",\"Baking Powder\",\"Vanilla\",\"Lemon\",\"Orange Blossom Water\",\"Cornstarch\",\"Pine Nuts\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Prepare the almonds the day before. Bring 6 cups of water to a boil. Remove from heat, and add the almonds. Let the almonds soak in water for about 5 minutes, t\",\"instructions\":[\"Prepare the almonds the day before. Bring 6 cups of water to a boil. Remove from heat, and add the almonds. Let the almonds soak in water for about 5 minutes, then drain and peel. Spread the almonds on baking sheets, and bake at 200 degrees F(95 degrees C) until completely dry and toasted. This takes several hours, and needs to be prepared ahead. Be careful not to burn the nuts, as this will give a bitter taste to the filling.\",\"Combine 1 cup sugar and 1 cup water in a saucepan, and bring to a boil. Add 1 teaspoon lemon juice, reduce heat to low, and let it simmer until syrupy, about 30 to 40 minutes. Stir in orange blossom water, and remove from heat. Set sugar syrup aside.\",\"Combine flour and salt in a large mixing bowl. Make a hole in the center, and pour oil, egg, 1/2 teaspoon lemon juice, and 1 tablespoon orange blossom water into the center. Mix with fingers until the dough resembles coarse crumbs. Gradually sprinkle with warm water while mixing until the dough becomes soft and pliable. Divide into 4 equal portions. Cover dough with a wet cloth, and set aside.\",\"In a food processor, finely grind the almonds. Measure 3 cups of the finely ground almonds into a mixing bowl, and stir together with 1 cup sugar, baking powder, vanilla powder, lemon zest, and 2 tablespoons orange flower water. Mix in three eggs one at a time, stirring constantly; mix until you get a sticky, paste-like mixture.\",\"Sprinkle cornstarch on the rolling surface to prevent sticking. Roll each portion of dough very thinly, 1 to 2 millimeters (1/16 inch). Cut the rolled dough into circles of about 10 centimeters (4 inches) in diameter each. Lightly wipe the surface of each circle with cornstarch, and fit into a tart mold, cornstarch side down to prevent sticking. Gently press the dough onto the sides and bottom of the mold, and trim extra dough from around the rim. Fill three quarters of each mold with the almond filling.\",\"Bake on the top shelf at 350 degrees F (175 degrees C) for 20 to 25 minutes, or until the surface of the tart is golden and the dough is firm. Remove the tarts from the molds as soon as they come out of the oven. Dip each tart in the sugar syrup while still hot. Stick a pine nut into the middle of each tart for decoration. Place on a wire rack to drain.\"]},{\"id\":\"g182\",\"title\":\"Easy Spanish chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kzxflc1763194887.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Extra Virgin Olive Oil\",\"Onion\",\"Chorizo\",\"Red Pepper\",\"Yellow Pepper\",\"sweet smoked paprika\",\"Garlic\",\"Tinned Tomatos\",\"Green Olives\",\"Butter Beans\",\"Chicken Thighs\",\"Parsley\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oven to 200C/180C fan/gas 6. Heat the olive oil in a large ovenproof frying pan over a medium heat and fry the onion, chorizo and peppers along\",\"instructions\":[\"step 1\",\"Heat the oven to 200C/180C fan/gas 6. Heat the olive oil in a large ovenproof frying pan over a medium heat and fry the onion, chorizo and peppers along with a pinch of salt and pepper for 15 mins until the veg has softened and the chorizo has released its oils. Add the paprika and garlic, and cook for another few minutes until fragrant.\",\"step 2\",\"Tip in the chopped tomatoes, olives and butter beans, stir to combine and season. Nestle in the chicken thighs and season well. Transfer to the oven and bake for 40 mins until the chicken skin is crisp and the meat cooked through and tender. Scatter with the parsley and serve.\",\"Watch after ad (0.04):\",\"3 Budget Egg Ideas\"]},{\"id\":\"g183\",\"title\":\"Eccles Cakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wtqrqw1511639627.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Plain Flour\",\"Lemon\",\"Butter\",\"Currants\",\"Mixed Peel\",\"Muscovado Sugar\",\"Cinnamon\",\"Ginger\",\"Allspice\",\"Lemon\",\"Eggs\",\"Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To make the pastry, dice the butter and put it in the freezer to go really hard. Tip flour into the bowl of a food processor with half the butter and pulse to t\",\"instructions\":[\"To make the pastry, dice the butter and put it in the freezer to go really hard. Tip flour into the bowl of a food processor with half the butter and pulse to the texture of breadcrumbs. Pour in the lemon juice and 100ml iced water, and pulse to a dough. Tip in the rest of the butter and pulse a few times until the dough is heavily flecked with butter. It is important that you don’t overdo this as the flecks of butter are what makes the pastry flaky.\",\"On a floured surface roll the pastry out to a neat rectangle about 20 x 30cm. Fold the two ends of the pastry into the middle (See picture 1), then fold in half (pic 2). Roll the pastry out again and refold the same way 3 more times resting the pastry for at least 15 mins each time between roll and fold, then leave to rest in the fridge for at least 30 mins before using.\",\"To make the filling, melt the butter in a large saucepan. Take it off the heat and stir in all the other ingredients until completely mixed, then set aside.\",\"To make the cakes, roll the pastry out until it’s just a little thicker than a £1 coin and cut out 8 rounds about 12cm across. Re-roll the trimming if needed. Place a good heaped tablespoon of mixture in the middle of each round, brush the edges of the rounds with water, then gather the pastry around the filling and squeeze it together (pic 3). Flip them over so the smooth top is upwards and pat them into a smooth round. Flatten each round with a rolling pin to an oval until the fruit just starts to poke through, then place on a baking tray. Cut 2 little slits in each Eccles cakes, brush generously with egg white and sprinkle with the sugar (pic 4).\",\"Heat the oven to 220C/200C fan/gas 8. Bake the Eccles cakes for 15-20 mins until just past golden brown and sticky. Leave to cool on a rack and enjoy while still warm or cold with a cup of tea. If you prefer, Eccles cakes also go really well served with a wedge of hard, tangy British cheese such as Lancashire or cheddar.\"]},{\"id\":\"g184\",\"title\":\"Egg Drop Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529446137.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Stock\",\"Salt\",\"Sugar\",\"Pepper\",\"Sesame Seed Oil\",\"Peas\",\"Mushrooms\",\"Cornstarch\",\"Water\",\"Spring Onions\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a wok add chicken broth and wait for it to boil.\\r\\nNext add salt, sugar, white pepper, sesame seed oil.\\r\\nWhen the chicken broth is boiling add the vegetables \",\"instructions\":[\"In a wok add chicken broth and wait for it to boil.\",\"Next add salt, sugar, white pepper, sesame seed oil.\",\"When the chicken broth is boiling add the vegetables to the wok.\",\"To thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your soup until it's the right thickness.\",\"Next add 1 egg slightly beaten with a knife or fork and add it to the soup slowly and stir for 8 seconds\",\"Serve the soup in a bowl and add the green onions on top.\"]},{\"id\":\"g185\",\"title\":\"Egg Foo Young\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/47y6ii1765658818.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Unsalted Beef Stock\",\"Soy Sauce\",\"Shaoxing Wine\",\"Oyster Sauce\",\"Pepper\",\"Cornstarch\",\"Water\",\"Cornstarch\",\"Water\",\"Egg\",\"Kosher Salt\",\"Sugar\",\"Spring Onions\",\"Mung Bean Sprouts\",\"Shrimp\",\"Vegetable Oil\",\"Jasmine Rice\"],\"allergens\":[\"egg\",\"soy\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Make the gravy:\\r\\nIn a small saucepan, add the beef stock, soy sauce, Shaoxing wine, oyster sauce, and white pepper powder over medium heat. Whisk together and b\",\"instructions\":[\"Make the gravy:\",\"In a small saucepan, add the beef stock, soy sauce, Shaoxing wine, oyster sauce, and white pepper powder over medium heat. Whisk together and bring to a simmer.\",\"Combine the cornstarch and water in a small bowl and whisk to dissolve. Add to the saucepan and whisk until the gravy thickens and coats the back of the spoon, 2 to 3 minutes. Cover the saucepan with a lid and keep it warm on the lowest possible heat.\",\"Make the egg foo young batter:\",\"In a medium bowl, whisk together the cornstarch and water until dissolved. Add the eggs, salt, and sugar. Whisk until well combined and there are no more egg white clumps.\",\"Add the green onion, bean sprouts, and shrimp. Stir until everything is evenly coated.\",\"Fry the egg foo young:\",\"Add the vegetable oil to a large wok; it should reach about 2 inches up the sides. Heat the oil over medium-high heat to 350°F, or until vigorous bubbles form around an inserted wooden chopstick.\",\"With a ladle, gently and slowly add 1/4 of the omelet batter. Egg foo young should immediately bubble and puff up like magic. Fry until golden brown and crispy on each side, about 2 minutes per side. If there are any light spots, use a ladle to gently baste it with hot oil.\",\"Tip\"]},{\"id\":\"g186\",\"title\":\"Eggplant Adobo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/y7h0lq1683208991.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg Plants\",\"Sugar\",\"Salt\",\"Pepper\",\"Garlic\",\"Olive Oil\",\"Ground Pork\",\"Rice Vinegar\",\"Soy Sauce\",\"Bay Leaf\"],\"allergens\":[\"egg\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1.\\tSlice 1 lb. small Japanese or Italian eggplant (about 3) into quarters lengthwise, then cut crosswise into 2\\\"-wide pieces. Place in a medium bowl. Add 1 Tbsp\",\"instructions\":[\"1.\\tSlice 1 lb. small Japanese or Italian eggplant (about 3) into quarters lengthwise, then cut crosswise into 2\\\"-wide pieces. Place in a medium bowl. Add 1 Tbsp. sugar, 1 tsp. Diamond Crystal or ½ tsp. Morton kosher salt, and ½ tsp. freshly ground black pepper. Toss to evenly coat eggplant and let sit at room temperature at least 20 minutes and up to 2 hours.\",\"2.\\tPeel and thinly slice 8 garlic cloves. Add 3 Tbsp. vegetable oil and half of garlic to a medium Dutch oven or other heavy pot. Cook over medium-high heat, stirring constantly with a wooden spoon, until light golden and crisp, about 5 minutes. Using a slotted spoon, transfer garlic chips to a plate; season lightly with salt.\",\"3. Place 4 oz. ground pork in same pot and break up into small pieces with wooden spoon. Season with ¼ tsp. Diamond Crystal or Morton kosher salt and cook, undisturbed, until deeply browned underneath, about 5 minutes. Using a slotted spoon, transfer to another plate, leaving fat behind in the pot.\",\"4. Place eggplant on a clean kitchen towel and blot away any moisture the salt has drawn out.\",\"5. Working in batches and adding more oil if needed, cook eggplant in the same pot until lightly browned, about 3 minutes per side. Transfer to a plate with pork.\",\"6. Pour 1½ cups of water into the pot and scrape up browned bits from the bottom with a wooden spoon. Add remaining garlic, 3 Tbsp. coconut vinegar or unseasoned rice vinegar, 2 Tbsp. soy sauce, 2 bay leaves, 1 tsp. freshly ground black pepper, and remaining 1 Tbsp. sugar. Bring to a simmer, then return pork and eggplant to pot. Reduce heat to medium-low, partially cover, and simmer until eggplant is tender and silky and sauce is reduced by half, 20–25 minutes. Taste and season with more salt and pepper and add a little more sugar if needed.\",\"7. Top with garlic chips and serve with cooked white rice.\"]},{\"id\":\"g187\",\"title\":\"Egyptian Fatteh\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rlwcc51598734603.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Onion\",\"Chicken Stock Cube\",\"Tomatoes\",\"Garlic Clove\",\"Tomato Puree\",\"Rice\",\"Noodles\",\"Butter\",\"Olive Oil\",\"Pita Bread\",\"Cumin\",\"White Wine Vinegar\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To prepare bread for bottom of dish: Take pita bread and rip into bite size pieces. In a frying pan, add about a 1/4 stick of butter, add bread pieces and fry u\",\"instructions\":[\"To prepare bread for bottom of dish: Take pita bread and rip into bite size pieces. In a frying pan, add about a 1/4 stick of butter, add bread pieces and fry until golden brown and crisp. Put these pieces in a glass baking dish, preferably a square sized dish. Set aside.\",\"Then add to same pan, a little more butter, salt, approximately 2 cloves of crushed fresh garlic, and a teaspoon or so of cumin stir around a bit until you can smell aroma, then add fried bread pieces to this mixture, stir to coat bread and put back into glass baking dish. Set aside.\",\"To prepare meat: put some butter in a pot, stir fry meat until brown, add 1 onion quartered, salt & pepper, 1 cube of chicken bouillon and water to cover meat. Bring to a boil, turn down to simmer, cover and cook until tender, approximately 2 hours. After meat has cooled, take out chunks of meat and put in a bowl, set aside. Reserve soup from the meat separately.\",\"To prepare the rice: Put some butter into a pot, add shareya (fideo noodles) like a handful or so, keep stirring until golden brown, not too dark, but very golden. Then add two cups of rice, stir a little bit until some of the rice turns an opaque white. Add 2-1/4 cups of water and salt to taste. Bring to a boil, cover and turn down to simmer, cook until tender. Test the rice tenderness after about 35 minutes.\",\"Now take some of the soup from meat and add to the top of the bread pieces in baking dish to saturate.Add cooked rice on top of bread pieces. Slowly spoon remainder of soup onto rice, looking at glass dish sides to see level of soup, should reach just to top of rice, don’t worry, this doesn’t have to be exact. Now you’re ready to make the sauce and fry the meat to put on top.\",\"To prepare red sauce: In a pan, add a little oil or butter, crushed tomato, a half teaspoon of tomato paste, salt & pepper, 2 cloves of fresh crushed garlic and cumin. Add also approximately 3 tablespoons of vinegar, stir this until you smell aroma and it is a bit smooth. It should be a bit thick, not watery, but if too thick you can add a bit of water. Spread with a wooden spoon atop the rice to cover.\",\"To fry meat: In a pan add a bit of butter or oil, the meat, just a touch of tomato paste, about a tablespoon of fresh crushed garlic, salt & pepper, a teaspoon of cumin. Cook until meat is golden fried.\",\"Spoon this atop the rice and serve. Enjoy!\"]},{\"id\":\"g188\",\"title\":\"Empanadas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/q99te31763075494.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"All purpose flour\",\"Butter\",\"Water\",\"Salt\",\"Ground Beef\",\"Onion\",\"Egg\",\"Green Olives\",\"Cumin\",\"Paprika\",\"Salt\",\"Pepper\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Make the Dough: Mix flour and salt in a large bowl. Add butter, using your fingers to blend into a crumbly texture. Gradually add water, mixing until a dough fo\",\"instructions\":[\"Make the Dough: Mix flour and salt in a large bowl. Add butter, using your fingers to blend into a crumbly texture. Gradually add water, mixing until a dough forms. Wrap and chill for 30 minutes.\",\"Prepare the Filling: Cook onions in a pan until translucent. Add ground beef, cooking until browned. Stir in spices, then remove from heat. Once cooled, mix in eggs and olives.\",\"Assemble: Roll out the dough and cut into circles. Place a spoonful of filling in each, fold over, and seal the edges.\",\"Cook: Bake at 200°C (400°F) for 20-25 minutes, or until golden.\",\"Pro Tips:\",\"For a flakier crust, incorporate a tablespoon of vinegar into the dough mixture. This helps prevent gluten formation.\",\"Seal the edges of the empanadas with a fork to ensure they do not open during baking or frying.\"]},{\"id\":\"g189\",\"title\":\"English Breakfast\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/utxryw1511721587.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sausages\",\"Bacon\",\"Mushrooms\",\"Tomatoes\",\"Black Pudding\",\"Eggs\",\"Bread\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\\r\\nCook the sausages first. Add the saus\",\"instructions\":[\"Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\",\"Cook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.\",\"Snip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.\",\"For the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.\",\"For the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green 'eye'. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.\",\"For the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.\",\"For 'proper' fried bread it's best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.\",\"For the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.\",\"Once all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce.\"]},{\"id\":\"g190\",\"title\":\"Ensaimada\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1ugsho1763248007.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Yeast\",\"Caster Sugar\",\"Egg\",\"Strong white bread flour\",\"Vegetable Oil\",\"Lard\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPour 230ml lukewarm water into a bowl and add the yeast. Leave to stand for 3 mins, then add the caster sugar, eggs, flour and 1 tsp sea salt flakes. Mi\",\"instructions\":[\"step 1\",\"Pour 230ml lukewarm water into a bowl and add the yeast. Leave to stand for 3 mins, then add the caster sugar, eggs, flour and 1 tsp sea salt flakes. Mix together to form a dough, then knead for 10 mins in stand mixer using a dough hook (or 15 mins by hand) until the dough is elastic enough to be almost see-through when stretched. Cover and set aside to rest for 30 mins, then cut into four equal pieces. Transfer to a baking tray lined with baking parchment. Leave to rest for another 30 mins.\",\"step 2\",\"Oil the work surface and a rolling pin with vegetable oil. Working with one portion of dough at a time, flatten it against the surface using the palm of your hand, then roll it out into a thin rectangle, about 30 x 50cm. Let it rest for 2 mins while you spread a quarter of the lard over the top. (If you want to fill your pastry with sobrasada de Mallorca, mix 50g lard with the sobrasada, and spread this over the dough instead.) Pull one corner of the flattened dough and stretch it out as far as it will go without breaking. Repeat every 10cm or so around the dough rectangle in every direction until it reaches about 50 x 70cm.\",\"step 3\",\"Cut a strip from each of the shorter sides and lay these beside each other along one of the longer sides of the rectangle; this is what we call the heart of the ensaimada. From there, begin rolling the dough until you have a long pastry snake. Repeat with the remaining portions of dough.\",\"step 4\",\"Take the first roll of dough and stretch it until it is over a metre long. Then, roll it up into a spiral, leaving 1cm between each turn of the spiral so the dough can expand. Flatten a little and transfer to a baking sheet lined with baking parchment. Repeat with the remaining dough. Leave to rise in a warm place for at least 12 hrs, or ideally 24 hrs.\",\"step 5\",\"Heat the oven to 200C/180C fan/gas 6. Put the ensaimadas in the top third of the oven and immediately reduce the temperature to 180C/160C fan/gas 4. Bake for 18 mins until dark golden. Leave to cool on a wire rack. To fill your ensaimada with whipped cream, slice and open, then spread over the cream and close. Dust with a generous amount of icing sugar, if you like and cut into pieces to serve.\"]},{\"id\":\"g191\",\"title\":\"Escovitch Fish\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1520084413.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Snapper\",\"Vegetable Oil\",\"Garlic\",\"Ginger\",\"Thyme\",\"Bay Leaf\",\"Red Pepper\",\"Yellow Pepper\",\"Onion\",\"Carrots\",\"Sugar\",\"Allspice\",\"Worcestershire Sauce\",\"Scotch Bonnet\",\"Lime\",\"Malt Vinegar\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Rinse fish; rub with lemon or lime, seasoned with salt and pepper or use your favorite seasoning. I used creole seasoning. Set aside or place in the oven to kee\",\"instructions\":[\"Rinse fish; rub with lemon or lime, seasoned with salt and pepper or use your favorite seasoning. I used creole seasoning. Set aside or place in the oven to keep it warm until sauce is ready.\",\"In large skillet heat oil over medium heat, until hot, add the fish, cook each side- for about 5-7 minutes until cooked through and crispy on both sides. Remove fish and set aside. Drain oil and leave about 2-3 tablespoons of oil\",\"Add, bay leave, garlic and ginger, stir-fry for about a minute making sure the garlic does not burn\",\"Then add onion, bell peppers, thyme, scotch bonnet, sugar, all spice-continue stirring for about 2-3 minutes. Add vinegar, mix an adjust salt and pepper according to preference. Let it simmer for about 2 more minutes.\",\"Discard bay leave, thyme spring and serve over fish with a side of this bammy. You may make the sauce about 2 days in advance.\"]},{\"id\":\"g192\",\"title\":\"Eton Mess\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uuxwvq1483907861.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"strawberries\",\"double cream\",\"meringue nests\",\"ginger cordial\",\"Mint\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Purée half the strawberries in a blender. Chop the remaining strawberries, reserving four for decoration.\\r\\nWhip the double cream until stiff peaks form, then fo\",\"instructions\":[\"Purée half the strawberries in a blender. Chop the remaining strawberries, reserving four for decoration.\",\"Whip the double cream until stiff peaks form, then fold in the strawberry purée and crushed meringue. Fold in the chopped strawberries and ginger cordial, if using.\",\"Spoon equal amounts of the mixture into four cold wine glasses. Serve garnished with the remaining strawberries and a sprig of mint.\"]},{\"id\":\"g193\",\"title\":\"Ezme\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pb6mj11763788331.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tomato\",\"Romano Pepper\",\"Green Chilli\",\"Onion\",\"Garlic\",\"Parsley\",\"Red Pepper Paste\",\"Tomato Puree\",\"Pomegranate Molasses\",\"Pul Biber\",\"Sumac\",\"Dried Mint\",\"Extra Virgin Olive Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut the tomatoes and all of the peppers in a food processor and blitz until finely chopped. Tip out into a sieve, set over a bowl and leave to strain. A\",\"instructions\":[\"step 1\",\"Put the tomatoes and all of the peppers in a food processor and blitz until finely chopped. Tip out into a sieve, set over a bowl and leave to strain. Add the onions, garlic and parsley to the food processor and blitz until finely chopped, then set aside.\",\"step 2\",\"Add red pepper paste, tomato purée, pomegranate molasses, pul biber, sumac, dried mint and most of the extra virgin olive oil to a serving bowl and whisk well so everything comes together as a sauce. Tip in the blitzed onion mixture and the strained pepper mixture along with 1 tsp flaky sea salt . Stir well, then drizzle with the remaining extra virgin olive oil to serve.\"]},{\"id\":\"g194\",\"title\":\"Fainá\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/849jd81763075251.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chickpea Flour\",\"Water\",\"Olive Oil\",\"Salt\",\"Pepper\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Prepare the Batter: Whisk together chickpea flour, water, salt, and pepper. Let sit for at least 4 hours.\\r\\nBake: Preheat the oven to 220°C (430°F). Pour olive o\",\"instructions\":[\"Prepare the Batter: Whisk together chickpea flour, water, salt, and pepper. Let sit for at least 4 hours.\",\"Bake: Preheat the oven to 220°C (430°F). Pour olive oil into a round baking dish and heat in the oven. Pour in the batter and bake for 25-30 minutes, until golden.\",\"Serve: Slice and serve hot, optionally with black pepper on top.\",\"Pro Tips:\",\"Let the batter rest for at least 2 hours, or overnight in the refrigerator, to ensure the chickpea flour fully hydrates and the flavors meld.\",\"For a crispy edge, preheat the baking pan with oil in the oven before adding the batter.\"]},{\"id\":\"g195\",\"title\":\"Falafel\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/u5e9qq1763795441.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sunflower Oil\",\"Onion\",\"Garlic\",\"Chickpeas\",\"Ground Cumin\",\"Ground Coriander\",\"Parsley\",\"Egg\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat 1 tbsp oil in a large pan, then fry the onion and garlic over a low heat for 5 mins until softened. Tip into a large mixing bowl with the chickpeas\",\"instructions\":[\"step 1\",\"Heat 1 tbsp oil in a large pan, then fry the onion and garlic over a low heat for 5 mins until softened. Tip into a large mixing bowl with the chickpeas and spices, then mash together with a fork or potato masher until the chickpeas are totally broken down. Stir in the parsley or dried herbs, with seasoning to taste. Add the egg, then squish the mixture together with your hands.\",\"step 2\",\"Mould the mix into 6 balls, then flatten into patties. Heat the remaining oil in the pan, then fry the falafels on a medium heat for 3 mins on each side, until golden brown and firm. Serve hot or cold with couscous, pitta bread or salad.\"]},{\"id\":\"g196\",\"title\":\"Falafel Pita Sandwich with Tahini Sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ae6clc1760524712.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Falafel\",\"Tahini\",\"Water\",\"Lemon Juice\",\"Garlic\",\"Paprika\",\"Pita Bread\",\"Lettuce\",\"Tomato\",\"Cucumber\",\"Dill Pickles\",\"Red Onions\",\"Harissa Spice\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Preheat the oven to 450 degrees F (230 degrees C). Place falafel on a baking sheet.\\r\\n\\r\\nBake in the preheated oven until heated through, 8 to 10 minutes.\\r\\n\\r\\nWhil\",\"instructions\":[\"Preheat the oven to 450 degrees F (230 degrees C). Place falafel on a baking sheet.\",\"Bake in the preheated oven until heated through, 8 to 10 minutes.\",\"While falafel bake, whisk tahini, water, lemon juice, garlic, and paprika together in a bowl.\",\"Cut about 1 inch from the top of each pita to form a pocket. Add 2 falafel to each pita with equal amounts lettuce, tomato, cucumber, pickle, and red onion. Drizzle each with about 1 tablespoon tahini sauce and some harissa.\"]},{\"id\":\"g197\",\"title\":\"Fårikål (Norwegian National Dish)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ttfxxn1762773067.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb\",\"White Cabbage\",\"Whole black peppercorns\",\"Salt\",\"Water\",\"Flour\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"▢\\r\\nCut the lamb into large pieces.\\r\\n▢\\r\\nSlice the cabbage into large wedges, keeping the core attached.\\r\\n▢\\r\\nAdd a layer of lamb pieces to the bottom of a large p\",\"instructions\":[\"▢\",\"Cut the lamb into large pieces.\",\"▢\",\"Slice the cabbage into large wedges, keeping the core attached.\",\"▢\",\"Add a layer of lamb pieces to the bottom of a large pot, fatty side down. Sprinkle with peppercorns and salt. Add a layer of cabbage wedges on top. Repeat with more layers of lamb, peppercorns, and cabbage, ending with cabbage on top.\",\"▢\",\"Optional: Sprinkle a couple of tablespoons on top of the lamb for a thicker stew.\",\"▢\",\"Add water to the pot and bring to a boil. Cover and reduce heat. Cook on low heat for 2 – 3 hours, until the lamb gently falls away from the bone.\"]},{\"id\":\"g198\",\"title\":\"Fašírky\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/gtpvwp1763363947.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ground Pork\",\"Onion\",\"Garlic\",\"Bread\",\"Milk\",\"Egg\",\"Salt\",\"Black Pepper\",\"Marjoram\",\"Mustard\",\"Parsley\",\"Flour\",\"Egg\",\"Breadcrumbs\",\"Vegetable Oil\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1. Prepare the Bread Mixture\\r\\nSoak the bread slices in milk or water until soft.\\r\\nSqueeze out excess liquid and mash into small crumbs.\\r\\n2. Mix the Ingredients\\r\",\"instructions\":[\"1. Prepare the Bread Mixture\",\"Soak the bread slices in milk or water until soft.\",\"Squeeze out excess liquid and mash into small crumbs.\",\"2. Mix the Ingredients\",\"In a large bowl, combine ground meat, chopped onions, garlic, soaked bread, egg, and seasonings.\",\"Mix well until evenly combined.\",\"3. Shape the Meat Patties\",\"Take portions of the mixture and shape them into palm-sized patties.\",\"Flatten slightly to help with even cooking.\",\"4. Coat the Patties\"]},{\"id\":\"g199\",\"title\":\"Fasoliyyeh Bi Z-Zayt (Syrian Green Beans with Olive Oil)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/21yc5s1760524759.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Green Beans\",\"Olive Oil\",\"Salt\",\"Garlic\",\"Cilantro\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Place the green beans into a large pot, and drizzle with olive oil. Season with salt to taste, and put the lid on the pot. Cook over medium-high heat, stirring \",\"instructions\":[\"Place the green beans into a large pot, and drizzle with olive oil. Season with salt to taste, and put the lid on the pot. Cook over medium-high heat, stirring occasionally, until beans are cooked to your desired doneness. Syrians like it cooked until the green beans are turning brownish in color. The idea is not to saute them, but to let them steam in the moisture released by the ice crystals.\",\"Add cilantro and garlic to the beans, and continue to cook just until the cilantro has started to wilt. Eat as a main course by scooping up with warm pita bread or serve as a side dish.\"]},{\"id\":\"g200\",\"title\":\"Fennel Dauphinoise\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ytttsv1511798734.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Fennel\",\"Garlic\",\"Milk\",\"Double Cream\",\"Butter\",\"Parmesan Cheese\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 180C/160C fan/gas 4. Put potatoes, fennel, and garlic in a medium non-stick pan. Pour in milk and double cream, season well and simmer gently, cove\",\"instructions\":[\"Heat oven to 180C/160C fan/gas 4. Put potatoes, fennel, and garlic in a medium non-stick pan. Pour in milk and double cream, season well and simmer gently, covered, for 10 mins, stirring halfway through, until potatoes are just tender.\",\"Divide the mixture between 2 small (about 150ml) buttered ramekins and scatter with Parmesan. Bake for 40 mins until the potatoes are golden and tender when pierced with a knife. Snip the reserved fennel fronds over before serving.\"]},{\"id\":\"g201\",\"title\":\"Feteer Meshaltet\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9f4z6v1598734293.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Water\",\"Salt\",\"Unsalted Butter\",\"Olive Oil\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Mix the flour and salt then pour one cup of water and start kneading.\\r\\nIf you feel the dough is still not coming together or too dry, gradually add the remainin\",\"instructions\":[\"Mix the flour and salt then pour one cup of water and start kneading.\",\"If you feel the dough is still not coming together or too dry, gradually add the remaining water until you get a dough that is very elastic so that when you pull it and it won’t be torn.\",\"Let the dough rest for just 10 minutes then divide the dough into 6-8 balls depending on the size you want for your feteer.\",\"Warm up the butter/ghee or oil you are using and pour into a deep bowl.\",\"Immerse the dough balls into the warm butter. Let it rest for 15 to 20 minutes.\",\"Preheat oven to 550F.\",\"Stretch the first ball with your hands on a clean countertop. Stretch it as thin as you can, the goal here is to see your countertop through the dough.\",\"Fold the dough over itself to form a square brushing in between folds with the butter mixture.\",\"Set aside and start making the next ball.\",\"Stretch the second one thin as we have done for the first ball.\"]},{\"id\":\"g202\",\"title\":\"Fettuccine Alfredo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0jv5gx1661040802.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Fettuccine\",\"Heavy Cream\",\"Butter\",\"Parmesan\",\"Parsley\",\"Black Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Cook pasta according to package instructions in a large pot of boiling water and salt. Add heavy cream and butter to a large skillet over medium heat until the \",\"instructions\":[\"Cook pasta according to package instructions in a large pot of boiling water and salt.\",\"Add heavy cream and butter to a large skillet over medium heat until the cream bubbles and the butter melts.\",\"Whisk in parmesan and add seasoning (salt and black pepper).\",\"Let the sauce thicken slightly and then add the pasta and toss until coated in sauce.\",\"Garnish with parsley, and it's ready.\"]},{\"id\":\"g203\",\"title\":\"Fettucine alfredo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uquqtu1511178042.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Clotted Cream\",\"Butter\",\"Corn Flour\",\"Parmesan Cheese\",\"Nutmeg\",\"Fettuccine\",\"Parsley\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"In a medium saucepan, stir the clotted cream, butter and cornflour over a low-ish heat and bring to a low simmer. Turn off the heat and keep warm.\\r\\nMeanwhile, p\",\"instructions\":[\"In a medium saucepan, stir the clotted cream, butter and cornflour over a low-ish heat and bring to a low simmer. Turn off the heat and keep warm.\",\"Meanwhile, put the cheese and nutmeg in a small bowl and add a good grinding of black pepper, then stir everything together (don’t add any salt at this stage).\",\"Put the pasta in another pan with 2 tsp salt, pour over some boiling water and cook following pack instructions (usually 3-4 mins). When cooked, scoop some of the cooking water into a heatproof jug or mug and drain the pasta, but not too thoroughly.\",\"Add the pasta to the pan with the clotted cream mixture, then sprinkle over the cheese and gently fold everything together over a low heat using a rubber spatula. When combined, splash in 3 tbsp of the cooking water. At first, the pasta will look wet and sloppy: keep stirring until the water is absorbed and the sauce is glossy. Check the seasoning before transferring to heated bowls. Sprinkle over some chives or parsley, then serve immediately.\"]},{\"id\":\"g204\",\"title\":\"Figgy Duff\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kzi6p51764787198.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"All purpose flour\",\"Brown Sugar\",\"Baking Powder\",\"Ginger\",\"Allspice\",\"Cinnamon\",\"Raisins\",\"Melted Butter\",\"Molasses\",\"Water\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"In a medium bowl, whisk together flour, brown sugar, baking powder, and spices.\\r\\nAdd raisins and stir well, making sure to coat the raisins in the flour mixture\",\"instructions\":[\"In a medium bowl, whisk together flour, brown sugar, baking powder, and spices.\",\"Add raisins and stir well, making sure to coat the raisins in the flour mixture.\",\"Add melted butter, molasses and water and mix with a wooden spoon. Form a ball with the spoon or your hands and put the dough ball in a cotton pudding bag. Tie the bag, leaving at least 1 inch of room to allow the pudding to expand while cooking.\",\"Boil pudding for 1.5 hours. (In NL, this is typically done in the pot along with Jiggs Dinner, but it can be done independently.)\",\"When the duff is firm, remove it from the boiling water and let it cool slightly before removing it from the pudding bag.\",\"Slice pudding like a cake and serve with the warm sauce of your choice: rum butter sauce, warmed molasses or Molasses Coady sauce (1 cup (250 mL) molasses, 1/4 cup (60 mL) butter, 1/4 cup (60 mL) water) is common in Newfoundland.\"]},{\"id\":\"g205\",\"title\":\"Fish fofos\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/a15wsa1614349126.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Haddock\",\"Potatoes\",\"Green Chilli\",\"Coriander\",\"Cumin Seeds\",\"Pepper\",\"Garlic\",\"Ginger\",\"Flour\",\"Eggs\",\"Breadcrumbs\",\"Vegetable Oil\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\n\\r\\nPut the fish into a lidded pan and pour over enough water to cover. Bring to a simmer and gently poach for 10 minutes over a low heat with the lid on.\",\"instructions\":[\"STEP 1\",\"Put the fish into a lidded pan and pour over enough water to cover. Bring to a simmer and gently poach for 10 minutes over a low heat with the lid on. Drain and flake the fish.\",\"STEP 2\",\"Put the fish, potato, green chilli, coriander, cumin, black pepper, garlic and ginger in a large bowl. Season, add the rice flour, mix well and break in 1 egg. Stir the mixture and divide into 15, then form into small logs. Break the remaining eggs into a bowl and whisk lightly. Put the breadcrumbs into another bowl. Dip each fofo in the beaten egg followed by the breadcrumb mixture. Chill for 20 minutes.\",\"STEP 3\",\"Heat 1cm of oil in a large frying pan over a medium heat. Fry the fofos in batches for 2 minutes on each side, turning gently to get an even golden brown colour all over. Drain on kitchen paper and repeat with the remaining fofos.\",\"STEP 4\",\"For the onion salad, mix together the onion, coriander and lemon juice with a pinch of salt. Serve with the fofos and mango chutney.\"]},{\"id\":\"g206\",\"title\":\"Fish pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ysxwuq1487323065.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Floury Potatoes\",\"Olive Oil\",\"Semi-skimmed Milk\",\"White Fish Fillets\",\"Plain flour\",\"Nutmeg\",\"Double Cream\",\"Jerusalem Artichokes\",\"Leek\",\"Prawns\",\"Parsley\",\"Dill\",\"Lemon\",\"Gruyère\",\"Lemon\"],\"allergens\":[\"milk\",\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"01.Put the potatoes in a large pan of cold salted water and bring to the boil. Lower the heat, cover, then simmer gently for 15 minutes until tender. Drain, the\",\"instructions\":[\"01.Put the potatoes in a large pan of cold salted water and bring to the boil. Lower the heat, cover, then simmer gently for 15 minutes until tender. Drain, then return to the pan over a low heat for 30 seconds to drive off any excess water. Mash with 1 tbsp olive oil, then season.\",\"02.Meanwhile put the milk in a large sauté pan, add the fish and bring to the boil. Remove from the heat, cover and stand for 3 minutes. Remove the fish (reserving the milk) and pat dry with kitchen paper, then gently flake into an ovenproof dish, discarding the skin and any bones.\",\"03.Heat the remaining oil in a pan, stir in the flour and cook for 30 seconds. Gradually stir in 200-250ml of the reserved milk (discard the rest). Grate in nutmeg, season, then bubble until thick. Stir in the cream.\",\"04.Preheat the oven to 190°C/fan170°C/gas 5. Grate the artichokes and add to the dish with the leek, prawns and herbs. Stir the lemon zest and juice into the sauce, then pour over. Mix gently with a wooden spoon.\",\"05.Spoon the mash onto the fish mixture, then use a fork to make peaks, which will crisp and brown as it cooks. Sprinkle over the cheese, then bake for 35-40 minutes until golden and bubbling. Serve with wilted greens.\"]},{\"id\":\"g207\",\"title\":\"Fish Soup (Ukha)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/7n8su21699013057.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Carrots\",\"Fish Stock\",\"Water\",\"Potatoes\",\"Bay Leaf\",\"Cod\",\"Salmon\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a medium pot, heat the olive oil over medium-high heat. Add the onions and cook, stirring occasionally until the onions start to caramelize. Add the carrots \",\"instructions\":[\"In a medium pot, heat the olive oil over medium-high heat. Add the onions and cook, stirring occasionally until the onions start to caramelize. Add the carrots and cook until the carrots start to soften, about 4 more minutes.\",\"Add the stock, water, potatoes, bay leaves, and black peppercorns. Season with salt and bring to a boil. Reduce heat, cover and cook for 10 minutes. Add the millet and cook for 15 more minutes until millet and potatoes are cooked.\",\"Gently add the fish cubes. Stir and bring the soup to a simmer. The fish will cook through very fast, so make sure to not overcook them. They are done when the flesh is opaque and flakes easily.\",\"Garnish the soup with chopped fresh dill or parsley before serving.\"]},{\"id\":\"g208\",\"title\":\"Fish Stew with Rouille\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vptqpw1511798500.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Prawns\",\"Olive Oil\",\"Dry White Wine\",\"Fish Stock\",\"Fennel\",\"Onion\",\"Garlic\",\"Potatoes\",\"Orange\",\"Star Anise\",\"Bay Leaf\",\"Harissa Spice\",\"Tomato Puree\",\"Chopped Tomatoes\",\"Mussels\",\"White Fish\",\"Thyme\",\"Bread\"],\"allergens\":[\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Twist the heads from the prawns, then peel away the legs and shells, but leave the tails intact. Devein each prawn. Fry the shells in 1 tbsp oil for 5 mins, unt\",\"instructions\":[\"Twist the heads from the prawns, then peel away the legs and shells, but leave the tails intact. Devein each prawn. Fry the shells in 1 tbsp oil for 5 mins, until dark pink and golden in patches. Add the wine, boil down by two thirds, then pour in the stock. Strain into a jug, discarding the shells.\",\"Heat the rest of the oil in a deep frying pan or casserole. Add the fennel, onion and garlic, season, then cover and gently cook for 10 mins until softened. Meanwhile, peel the potato and cut into 2cm-ish chunks. Put into a pan of cold water, bring to the boil and cook for 5 mins until almost tender. Drain in a colander.\",\"Peel a strip of zest from the orange. Put the zest, star anise, bay and ½ tsp harissa into the pan. Fry gently, uncovered, for 5-10 mins, until the vegetables are soft, sweet and golden.\",\"Stir in the tomato purée, cook for 2 mins, then add the tomatoes and stock. Simmer for 10 mins until the sauce thickens slightly. Season to taste. The sauce can be made ahead, then reheated later in the day. Meantime, scrub the mussels or clams and pull away any stringy beards. Any that are open should be tapped sharply on the worktop – if they don’t close after a few seconds, discard them.\",\"Reheat the sauce if necessary, then stir the potato, chunks of fish and prawns very gently into the stew. Bring back to the boil, then cover and gently simmer for 3 mins. Scatter the mussels or clams over the stew, then cover and cook for 2 mins more or until the shells have opened wide. Discard any that remain closed. The chunks of fish should flake easily and the prawns should be pink through. Scatter with the thyme leaves.\",\"To make the quick rouille, stir the rest of the harissa through the mayonnaise. Serve the stew in bowls, topped with spoonfuls of rouille, which will melt into the sauce and enrich it. Have some good bread ready, as you’ll definitely want to mop up the juices.\"]},{\"id\":\"g209\",\"title\":\"Fiskesuppe (Creamy Norwegian Fish Soup)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/raqjbj1762773035.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Fish fillet\",\"Garlic\",\"Potatoes\",\"Carrots\",\"Leek\",\"Butter\",\"Flour\",\"Fish Stock\",\"Milk\",\"Creme Fraiche\",\"Shrimp\",\"Chives\"],\"allergens\":[\"milk\",\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"▢\\r\\nCut the fish fillets in cubes or strips. Crush or chop the garlic. Rinse the vegetables and cut into thin strips.\\r\\n▢\\r\\nHeat the butter in a pot and add the ga\",\"instructions\":[\"▢\",\"Cut the fish fillets in cubes or strips. Crush or chop the garlic. Rinse the vegetables and cut into thin strips.\",\"▢\",\"Heat the butter in a pot and add the garlic. Once the garlic starts to turn golden add the flour, whisking well.\",\"▢\",\"Add the fish stock and continue to whisk until there are no lumps.\",\"▢\",\"Add the vegetables and milk and bring to a boil. Cook for about 10 minutes.\",\"▢\",\"Add the crème fraîche (or sour cream). Bring the soup back to a simmer and once the soup begins to bubble again turn off the heat. Keep the soup on the burner and add the fish. Let the fish cook in the hot soup for 5 minutes. If using shrimp, add right before serving.\"]},{\"id\":\"g210\",\"title\":\"Flamiche\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wssvvs1511785879.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Leek\",\"Salt\",\"Creme Fraiche\",\"Egg\",\"Egg Yolks\",\"Nutmeg\",\"Plain Flour\",\"Salt\",\"Butter\",\"Lard\",\"Cheddar Cheese\",\"Water\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the pastry, sift the flour and salt into the bowl of a food processor, add the butter and lard, then whizz together briefly until the mixture looks like fin\",\"instructions\":[\"For the pastry, sift the flour and salt into the bowl of a food processor, add the butter and lard, then whizz together briefly until the mixture looks like fine breadcrumbs. Tip the mixture into a bowl, then stir in the cheese and enough of the water for the mixture to come together. Tip out onto a lightly floured surface and knead briefly until smooth. Roll out thinly and line a 23cm x 4cm loose-?bottomed fluted flan tin. Prick the base with a fork. Chill for 20 minutes.\",\"02.Melt the 75g butter in a saucepan over a low heat, then add the leeks and the salt. Cover and cook for ?10 minutes until soft. Uncover the pan, increase the heat and cook ?for 2 minutes, stirring occasionally, until the liquid has evaporated. Spoon onto a plate and leave to cool.\",\"03.Preheat the oven to 200°C/fan180°C/gas 6. Line the pastry case with baking paper and baking beans or rice and blind bake for 15-20 minutes until the edges are biscuit-coloured. Remove the paper and beans/rice and return the case to the oven for 7-10 minutes until the base is crisp and lightly golden. Remove and set aside. Reduce the oven temperature to 190°C/fan170°C/gas 5.\",\"04.Put the crème fraîche into a bowl with the whole egg, egg yolks and nutmeg. Lightly beat together, then season. Stir in the leeks. Spoon ?the mixture into the tart case and bake for 35-40 minutes until set ?and lightly golden. Remove from ?the oven and leave for 10 minutes. Take out of the tin and serve.\"]},{\"id\":\"g211\",\"title\":\"Flan\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0s80wo1764374393.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sugar\",\"Milk\",\"Sugar\",\"vanilla pod\",\"Egg Yolks\",\"Egg\",\"Dulce de leche\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the caramel place 100 grams of sugar in a frying pan without any fat and melt on medium heat. Try not to stir with a spoon, but swirl the pan itself. Let me\",\"instructions\":[\"For the caramel place 100 grams of sugar in a frying pan without any fat and melt on medium heat. Try not to stir with a spoon, but swirl the pan itself. Let melt until you have an amber color and sugar is fully melted. Fill the bottom of four flan containers with it. Caramel will harden immediately, so you need to be fast. My containers yield about 120 milliliters each.\",\"2\",\"Preheat oven to 150 degrees Celsius and look for a casserole or container all your four flan containers fit into.\",\"3\",\"Heat milk with 45 grams of sugar and the cut and scraped out vanilla pod. The milk does not need to boil, just needs to be heated. Take out vanilla pod after a few minutes. Meanwhile stir the egg yolks and eggs gently, try not to incorporate any air in it. Them pour milk-mix into egg-mix and again only stir very gently. Pour into prepared flan containers and place these into your casserole or container. Boil water and pour the water into the large casserole. Be sure not to touch the flan mixture. Place on middle rack in the oven and let bake for about 35-40 minutes. An inserted toothpick should come out clean.\",\"4\",\"Let cool inside the container for an hour before transferring to the fridge. Chill overnight. The next day gently release the rim and then turn upside down on a plate. Serve with some dulce de leche on the side.\"]},{\"id\":\"g212\",\"title\":\"Flapper Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6ht8141764786479.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Graham Cracker Crumbs\",\"Melted Butter\",\"Sugar\",\"Ground Cinnamon\",\"Milk\",\"Sugar\",\"Cornstarch\",\"Egg Yolks\",\"Vanilla Extract\",\"Salt\",\"Egg White\",\"Sugar\",\"Cream Of Tartar\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 350˚F.\\r\\nMix all the crust ingredients (graham cracker crumbs, melted butter, granulated sugar and ground cinnamon) in a medium bowl. Set asi\",\"instructions\":[\"Preheat the oven to 350˚F.\",\"Mix all the crust ingredients (graham cracker crumbs, melted butter, granulated sugar and ground cinnamon) in a medium bowl. Set aside about 2 Tbsp (30 mL) for later and press the mixture into a 9-inch deep-dish pie plate in the bottom and up the sides. Bake crust for 10 minutes, it will only brown slightly.\",\"Combine the vanilla custard filling ingredients (milk, granulated sugar, cornstarch, egg yolks, vanilla extract and salt together) and cook on medium heat, stirring constantly, until it bubbles and thickens to the texture of pudding. Set aside to cool while you make the meringue topping.\",\"In the bowl of a stand mixer fitted with the beater attachment or in a large bowl using an electric mixer beat the meringue ingredients (egg whites, granulated sugar, cream of tartar) together until it holds stiff and glossy peaks.\",\"To assemble the pie, pour the filling into the crust and top with a thick layer of the meringue, making little spikes that will brown on top. Sprinkle the reserved crumb over the top and place it into the preheated oven.\",\"Bake until the meringue browns, around 10 minutes, making sure to watch it carefully.\",\"Chill in the fridge and eat within a few hours of baking. This pie is best eaten the same day as the meringue will soften and liquify.\"]},{\"id\":\"g213\",\"title\":\"French Lentils With Garlic and Thyme\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vwwspt1487394060.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Garlic\",\"Carrots\",\"French Lentils\",\"Thyme\",\"Bay Leaf\",\"Salt\",\"Celery\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Place a large saucepan over medium heat and add oil. When hot, add chopped vegetables and sauté until softened, 5 to 10 minutes.\\r\\nAdd 6 cups water, lentils, thy\",\"instructions\":[\"Place a large saucepan over medium heat and add oil. When hot, add chopped vegetables and sauté until softened, 5 to 10 minutes.\",\"Add 6 cups water, lentils, thyme, bay leaves and salt. Bring to a boil, then reduce to a fast simmer.\",\"Simmer lentils until they are tender and have absorbed most of the water, 20 to 25 minutes. If necessary, drain any excess water after lentils have cooked. Serve immediately, or allow them to cool and reheat later.\",\"For a fuller taste, use some chicken stock and reduce the water by the same amount.\"]},{\"id\":\"g214\",\"title\":\"French Omelette\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yvpuuy1511797244.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Eggs\",\"Butter\",\"Parmesan\",\"Tarragon Leaves\",\"Parsley\",\"Chives\",\"Gruyère\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Get everything ready. Warm a 20cm (measured across the top) non-stick frying pan on a medium heat. Crack the eggs into a bowl and beat them with a fork so they \",\"instructions\":[\"Get everything ready. Warm a 20cm (measured across the top) non-stick frying pan on a medium heat. Crack the eggs into a bowl and beat them with a fork so they break up and mix, but not as completely as you would for scrambled egg. With the heat on medium-hot, drop one knob of butter into the pan. It should bubble and sizzle, but not brown. Season the eggs with the Parmesan and a little salt and pepper, and pour into the pan.\",\"Let the eggs bubble slightly for a couple of seconds, then take a wooden fork or spatula and gently draw the mixture in from the sides of the pan a few times, so it gathers in folds in the centre. Leave for a few seconds, then stir again to lightly combine uncooked egg with cooked. Leave briefly again, and when partly cooked, stir a bit faster, stopping while there’s some barely cooked egg left. With the pan flat on the heat, shake it back and forth a few times to settle the mixture. It should slide easily in the pan and look soft and moist on top. A quick burst of heat will brown the underside.\",\"Grip the handle underneath. Tilt the pan down away from you and let the omelette fall to the edge. Fold the side nearest to you over by a third with your fork, and keep it rolling over, so the omelette tips onto a plate – or fold it in half, if that’s easier. For a neat finish, cover the omelette with a piece of kitchen paper and plump it up a bit with your fingers. Rub the other knob of butter over to glaze. Serve immediately.\"]},{\"id\":\"g215\",\"title\":\"French Onion Chicken with Roasted Carrots & Mashed Potatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/b5ft861583188991.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breasts\",\"Carrots\",\"Potatoes\",\"Onion\",\"Beef Stock\",\"Mozzarella\",\"Sour Cream\",\"Butter\",\"Sugar\",\"Vegetable Oil\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\n\\r\\nPreheat oven to 425 degrees. Wash and dry all produce. Trim, peel, and cut carrots on a diagonal into ¼-inch-thick pieces. Dice potatoes into ½-inch pieces\",\"instructions\":[\"1\",\"Preheat oven to 425 degrees. Wash and dry all produce. Trim, peel, and cut carrots on a diagonal into ¼-inch-thick pieces. Dice potatoes into ½-inch pieces. Halve, peel, and thinly slice onion.\",\"2\",\"Toss carrots on a baking sheet with a drizzle of oil, salt, and pepper. Roast until browned and tender, 15-20 minutes.\",\"3\",\"Meanwhile, place potatoes in a medium pot with enough salted water to cover by 2 inches. Bring to a boil and cook until tender, 12-15 minutes. Drain and return potatoes to pot; cover to keep warm.\",\"4\",\"While potatoes cook, heat a drizzle of oil in a large pan over medium-high heat. Add onion and cook, stirring occasionally, until lightly browned and softened, 8-10 minutes. Sprinkle with 1 tsp sugar (2 tsp for 4 servings). Stir in stock concentrate and 2 TBSP water (¼ cup for 4); season with salt and pepper. Cook until jammy, 2-3 minutes more. Turn off heat; transfer to a small bowl. Wash out pan.\",\"5\",\"Pat chicken dry with paper towels; season all over with salt and pepper. Heat a drizzle of oil in pan used for onion over medium-high heat. Add chicken and cook until browned and cooked through, 5-6 minutes per side. In the last 1-2 minutes of cooking, top with caramelized onion and cheese. Cover pan until cheese melts. (If your pan doesn’t have a lid, cover with a baking sheet!)\"]},{\"id\":\"g216\",\"title\":\"French Onion Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xvrrux1511783685.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Olive Oil\",\"Onion\",\"Sugar\",\"Garlic Clove\",\"Plain Flour\",\"Dry White Wine\",\"Beef Stock\",\"Bread\",\"Gruyère\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Melt the butter with the oil in a large heavy-based pan. Add the onions and fry with the lid on for 10 mins until soft. Sprinkle in the sugar and cook for 20 mi\",\"instructions\":[\"Melt the butter with the oil in a large heavy-based pan. Add the onions and fry with the lid on for 10 mins until soft. Sprinkle in the sugar and cook for 20 mins more, stirring frequently, until caramelised. The onions should be really golden, full of flavour and soft when pinched between your fingers. Take care towards the end to ensure that they don’t burn.\",\"Add the garlic for the final few mins of the onions’ cooking time, then sprinkle in the flour and stir well. Increase the heat and keep stirring as you gradually add the wine, followed by the hot stock. Cover and simmer for 15-20 mins.\",\"To serve, turn on the grill, and toast the bread. Ladle the soup into heatproof bowls. Put a slice or two of toast on top of the bowls of soup, and pile on the cheese. Grill until melted. Alternatively, you can complete the toasts under the grill, then serve them on top.\"]},{\"id\":\"g217\",\"title\":\"Fresh sardines\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/nv5lf31628771380.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sardines\",\"Vegetable Oil\",\"Flour\",\"Salt\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Wash the fish under the cold tap. Roll in the flour and deep fry in oil until crispy. Lay on kitchen towel to get rid of the excess oil and serve hot or cold wi\",\"instructions\":[\"Wash the fish under the cold tap.\",\"Roll in the flour and deep fry in oil until crispy.\",\"Lay on kitchen towel to get rid of the excess oil and serve hot or cold with a slice of lemon.\"]},{\"id\":\"g218\",\"title\":\"Fried calamari\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yhi46r1763330279.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Squid\",\"Plain Flour\",\"Capers\",\"Garlic\",\"Mayonnaise\",\"Vegetable Oil\",\"Lemon\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nCut the squid into rings about ½cm thick. Tip the flour into a freezer bag and season well. Add the capers, then give everything a good shake to mix tog\",\"instructions\":[\"step 1\",\"Cut the squid into rings about ½cm thick. Tip the flour into a freezer bag and season well. Add the capers, then give everything a good shake to mix together. Tip the squid into the bag, then shake again until all the rings are well coated. Mix together the garlic and mayonnaise, then place in a serving bowl.\",\"step 2\",\"Pour some oil into a large pan until it comes about 7cm up the sides, but the pan is no more than a third full. Place over a medium heat and let the oil warm up. To test that the oil is ready, place a small piece of bread in the pan – it should sizzle when it touches the oil.\",\"step 3\",\"Remove a handful of squid from the flour and shake off any excess. Gently drop into the oil, then cook for about 3 mins until crisp. Remove with a slotted spoon and place on kitchen paper. Repeat with the remaining squid. Serve straight away with the mayonnaise and lemon wedges.\"]},{\"id\":\"g219\",\"title\":\"Fruit and Cream Cheese Breakfast Pastries\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1543774956.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cream Cheese\",\"Sugar\",\"Vanilla Extract\",\"Flour\",\"Puff Pastry\",\"Strawberries\",\"Raspberries\",\"Blackberries\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Preheat oven to 400ºF (200ºC), and prepare two cookie sheets with parchment paper. In a bowl, mix cream cheese, sugar, and vanilla until fully combined. Lightly\",\"instructions\":[\"Preheat oven to 400ºF (200ºC), and prepare two cookie sheets with parchment paper. In a bowl, mix cream cheese, sugar, and vanilla until fully combined. Lightly flour the surface and roll out puff pastry on top to flatten. Cut each sheet of puff pastry into 9 equal squares. On the top right and bottom left of the pastry, cut an L shape approximately ½ inch (1 cm) from the edge.\",\"NOTE: This L shape should reach all the way down and across the square, however both L shapes should not meet at the ends. Your pastry should look like a picture frame with two corners still intact.\",\"Take the upper right corner and fold down towards the inner bottom corner. You will now have a diamond shape.\",\"Place 1 to 2 teaspoons of the cream cheese filling in the middle, then place berries on top.\",\"Repeat with the remaining pastry squares and place them onto the parchment covered baking sheet.\",\"Bake for 15-20 minutes or until pastry is golden brown and puffed.\",\"Enjoy!\"]},{\"id\":\"g220\",\"title\":\"Ful Medames\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lvn2d51598732465.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Broad Beans\",\"Parsley\",\"Olive Oil\",\"Lemons\",\"Garlic Clove\",\"Cumin\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"As the cooking time varies depending on the quality and age of the beans, it is good to cook them in advance and to reheat them when you are ready to serve. Coo\",\"instructions\":[\"As the cooking time varies depending on the quality and age of the beans, it is good to cook them in advance and to reheat them when you are ready to serve. Cook the drained beans in a fresh portion of unsalted water in a large saucepan with the lid on until tender, adding water to keep them covered, and salt when the beans have softened. They take 2–2 1/2 hours of gentle simmering. When the beans are soft, let the liquid reduce. It is usual to take out a ladle or two of the beans and to mash them with some of the cooking liquid, then stir this back into the beans. This is to thicken the sauce.\",\"Serve the beans in soup bowls sprinkled with chopped parsley and accompanied by Arab bread.\",\"Pass round the dressing ingredients for everyone to help themselves: a bottle of extra-virgin olive oil, the quartered lemons, salt and pepper, a little saucer with the crushed garlic, one with chili-pepper flakes, and one with ground cumin.\",\"The beans are eaten gently crushed with the fork, so that they absorb the dressing.\",\"Optional Garnishes\",\"Peel hard-boiled eggs—1 per person—to cut up in the bowl with the beans.\",\"Top the beans with a chopped cucumber-and-tomato salad and thinly sliced mild onions or scallions. Otherwise, pass round a good bunch of scallions and quartered tomatoes and cucumbers cut into sticks.\",\"Serve with tahina cream sauce (page 65) or salad (page 67), with pickles and sliced onions soaked in vinegar for 30 minutes.\",\"Another way of serving ful medames is smothered in a garlicky tomato sauce (see page 464).\",\"In Syria and Lebanon, they eat ful medames with yogurt or feta cheese, olives, and small cucumbers.\"]},{\"id\":\"g221\",\"title\":\"Full English Breakfast\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sqrtwu1511721265.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sausages\",\"Bacon\",\"Mushrooms\",\"Tomatoes\",\"Black Pudding\",\"Eggs\",\"Bread\",\"Baked Beans\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\\r\\nCook the sausages first. Add the saus\",\"instructions\":[\"Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\",\"Cook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.\",\"Snip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.\",\"For the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.\",\"For the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green 'eye'. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.\",\"For the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.\",\"For 'proper' fried bread it's best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.\",\"For the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.\",\"Once all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce.\"]},{\"id\":\"g222\",\"title\":\"Fyrstekake – Norwegian Prince Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9zqrod1763075574.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Granulated Sugar\",\"Vanilla Extract\",\"Butter\",\"Egg Yolks\",\"Flour\",\"Baking Powder\",\"Almonds\",\"Brown Sugar\",\"Melted Butter\",\"Egg\",\"Brandy\",\"Almond Extract\",\"Egg\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Crust\\r\\n▢\\r\\nMix together sugar, vanilla and butter until light and fluffy. Mix in the egg yolks. Add in the flour and baking powder and knead with hands until the\",\"instructions\":[\"Crust\",\"▢\",\"Mix together sugar, vanilla and butter until light and fluffy. Mix in the egg yolks. Add in the flour and baking powder and knead with hands until the dough is smooth.\",\"▢\",\"Pack the dough in plastic wrap and chill in refrigerator for at least 30 minutes.\",\"Almond filling\",\"▢\",\"Run the almonds and sugar together in a food processor until the almonds are finely ground (you can decide for yourself how coarse or fine you want them).\",\"▢\",\"Stir in the butter, egg, cognac and/or almond extract (if using).\"]},{\"id\":\"g223\",\"title\":\"Gambas al ajillo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ze8uwg1763196123.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Raw King Prawns\",\"Garlic Clove\",\"Olive Oil\",\"Cayenne Pepper\",\"Parsley\"],\"allergens\":[\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPeel the prawns, leaving the tails intact, and, using a cocktail stick, remove the digestive tracts. Or, if you are using a frying pan rather than a ter\",\"instructions\":[\"step 1\",\"Peel the prawns, leaving the tails intact, and, using a cocktail stick, remove the digestive tracts. Or, if you are using a frying pan rather than a terracotta pot, you can cook the prawns in their shells. Season with a little sea salt.\",\"step 2\",\"Put the garlic, olive oil and chillies in a flameproof terracotta pot or frying pan and set over a high heat. When the garlic starts to turn golden, add the prawns and cook for 1-2 mins on each side until just pink. Sprinkle over the chopped parsley and some freshly cracked black pepper, and serve immediately. If using a terracotta pot, you can take that straight to the table, but be careful with it as the oil and terracotta will remain hot for several minutes.\"]},{\"id\":\"g224\",\"title\":\"Garides Saganaki\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wuvryu1468232995.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Raw king prawns\",\"Olive oil\",\"Chopped onion\",\"Freshly chopped parsley\",\"White wine\",\"Chopped tomatoes\",\"Minced garlic\",\"Cubed Feta cheese\"],\"allergens\":[\"milk\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Place the prawns in a pot and add enough water to cover. Boil for 5 minutes. Drain, reserving the liquid, and set aside.\\r\\nHeat 2 tablespoons of oil in a saucepa\",\"instructions\":[\"Place the prawns in a pot and add enough water to cover. Boil for 5 minutes. Drain, reserving the liquid, and set aside.\",\"Heat 2 tablespoons of oil in a saucepan. Add the onion; cook and stir until soft. Mix in the parsley, wine, tomatoes, garlic and remaining olive oil. Simmer, stirring occasionally, for about 30 minutes, or until the sauce is thickened.\",\"While the sauce is simmering, the prawns should become cool enough to handle. First remove the legs by pinching them, and then pull off the shells, leaving the head and tail on.\",\"When the sauce has thickened, stir in the prawns. Bring to a simmer again if the sauce has cooled with the prawns, and cook for about 5 minutes. Add the feta and remove from the heat. Let stand until the cheese starts to melt. Serve warm with slices of crusty bread.\",\"Though completely untraditional, you can add a few tablespoons of stock or passata to this recipe to make a delicious pasta sauce. Toss with pasta after adding the feta, and serve.\"]},{\"id\":\"g225\",\"title\":\"Garlicky prawns with sherry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/u2lhqb1763331899.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Garlic\",\"Prawns\",\"Dry sherry\",\"Parsley\"],\"allergens\":[\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the olive oil in a large frying pan. Tip in the garlic slices and cook for a few secs. Then stir through the prawns and cook for a couple of mins u\",\"instructions\":[\"step 1\",\"Heat the olive oil in a large frying pan. Tip in the garlic slices and cook for a few secs. Then stir through the prawns and cook for a couple of mins until they start to turn pink.\",\"step 2\",\"Pour over the sherry and cook for a few mins more, just until the prawns are cooked through. Sprinkle with parsley before serving.\"]},{\"id\":\"g226\",\"title\":\"General Tsos Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529444113.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breast\",\"Plain Flour\",\"Egg\",\"Starch\",\"Baking Powder\",\"Salt\",\"Onion Salt\",\"Garlic Powder\",\"Water\",\"Chicken Stock\",\"Duck Sauce\",\"Soy Sauce\",\"Honey\",\"Rice Vinegar\",\"Sesame Seed Oil\",\"Gochujang\",\"Starch\",\"Garlic\",\"Spring Onions\",\"Ginger\"],\"allergens\":[\"egg\",\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"DIRECTIONS:\\r\\nSTEP 1 - SAUCE\\r\\nIn a bowl, add 2 Cups of water, 2 Tablespoon soy sauce, 2 Tablespoon white vinegar, sherry cooking wine, 1/4 Teaspoon white pepper,\",\"instructions\":[\"DIRECTIONS:\",\"STEP 1 - SAUCE\",\"In a bowl, add 2 Cups of water, 2 Tablespoon soy sauce, 2 Tablespoon white vinegar, sherry cooking wine, 1/4 Teaspoon white pepper, minced ginger, minced garlic, hot pepper, ketchup, hoisin sauce, and sugar.\",\"Mix together well and set aside.\",\"STEP 2 - MARINATING THE CHICKEN\",\"In a bowl, add the chicken, 1 pinch of salt, 1 pinch of white pepper, 2 egg whites, and 3 Tablespoon of corn starch\",\"STEP 3 - DEEP FRY THE CHICKEN\",\"Deep fry the chicken at 350 degrees for 3-4 minutes or until it is golden brown and loosen up the chicken so that they don't stick together.\",\"Set the chicken aside.\",\"STEP 4 - STIR FRY\"]},{\"id\":\"g227\",\"title\":\"Gevulde speculaas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rw64di1766595573.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Self-raising Flour\",\"Brown Sugar\",\"Speculaas Spice Mix\",\"Salt\",\"Butter\",\"Milk\",\"Almond Paste\",\"Egg\",\"Milk\",\"Almonds\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix the self-rising flour, sugar, speculaas spice mix and salt. Add the butter and milk and knead into a firm ball of dough. Start with 6 tablespoons of milk, i\",\"instructions\":[\"Mix the self-rising flour, sugar, speculaas spice mix and salt. Add the butter and milk and knead into a firm ball of dough. Start with 6 tablespoons of milk, if the dough is too stiff you can add more milk.\",\"Wrap the dough in plastic wrap and refrigerate overnight. You can process and bake it immediately, but the flavor will be much better if you let it rest.\",\"Mix the almond paste with half of the beaten egg and knead well. This makes it easier to work with and gives it a better and tastier texture.\",\"Take half of the dough and roll it out to 20 x 20 cm. Place in a baking pan lined with parchment paper. Spread the almond paste mixture evenly. Roll out the remaining dough and place on top of the almond paste.\",\"Brush the top with the remaining beaten egg. Garnish with almonds and top with another layer of egg wash.\",\"Bake the filled speculaas for 40 minutes at 180°C/350℉ (conventional oven) or until done.\"]},{\"id\":\"g228\",\"title\":\"Gigantes Plaki\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/b79r6f1585566277.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter Beans\",\"Olive Oil\",\"Onion\",\"Garlic Clove\",\"Tomato Puree\",\"Tomatoes\",\"Sugar\",\"Dried Oregano\",\"Cinnamon\",\"Chopped Parsley\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Soak the beans overnight in plenty of water. Drain, rinse, then place in a pan covered with water. Bring to the boil, reduce the heat, then simmer for approx 50\",\"instructions\":[\"Soak the beans overnight in plenty of water. Drain, rinse, then place in a pan covered with water. Bring to the boil, reduce the heat, then simmer for approx 50 mins until slightly tender but not soft. Drain, then set aside.\",\"Heat oven to 180C/160C fan/gas 4. Heat the olive oil in a large frying pan, tip in the onion and garlic, then cook over a medium heat for 10 mins until softened but not browned. Add the tomato purée, cook for a further min, add remaining ingredients, then simmer for 2-3 mins. Season generously, then stir in the beans. Tip into a large ovenproof dish, then bake for approximately 1 hr, uncovered and without stirring, until the beans are tender. The beans will absorb all the fabulous flavours and the sauce will thicken. Allow to cool, then scatter with parsley and drizzle with a little more olive oil to serve.\"]},{\"id\":\"g229\",\"title\":\"Golabki (cabbage roll)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/q8sp3j1593349686.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cabbage\",\"Butter\",\"Onion\",\"Ground Beef\",\"Ground Pork\",\"Rice\",\"Garlic\",\"Salt\",\"Black Pepper\",\"Tomato Puree\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Bring a large pot of lightly salted water to a boil. Place cabbage head into water, cover pot, and cook until cabbage leaves are slightly softened enough to rem\",\"instructions\":[\"Bring a large pot of lightly salted water to a boil. Place cabbage head into water, cover pot, and cook until cabbage leaves are slightly softened enough to remove from head, 3 minutes. Remove cabbage from pot and let cabbage sit until leaves are cool enough to handle, about 10 minutes.\",\"Remove 18 whole leaves from the cabbage head, cutting out any thick tough center ribs. Set whole leaves aside. Chop the remainder of the cabbage head and spread it in the bottom of a casserole dish.\",\"Melt butter in a large skillet over medium-high heat. Cook and stir onion in hot butter until tender, 5 to 10 minutes. Cool.\",\"Stir onion, beef, pork, rice, garlic, 1 teaspoon salt, and 1/4 teaspoon pepper together in a large bowl.\",\"Preheat oven to 350 degrees F (175 degrees C).\",\"Place about 1/2 cup beef mixture on a cabbage leaf. Roll cabbage around beef mixture, tucking in sides to create an envelope around the meat. Repeat with remaining leaves and meat mixture. Place cabbage rolls in a layer atop the chopped cabbage in the casserole dish; season rolls with salt and black pepper.\",\"Whisk tomato soup, tomato juice, and ketchup together in a bowl. Pour tomato soup mixture over cabbage rolls and cover dish wish aluminum foil.\",\"Bake in the preheated oven until cabbage is tender and meat is cooked through, about 1 hour.\"]},{\"id\":\"g230\",\"title\":\"Grape Nut Ice Cream\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1xscby1764790242.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Heavy Cream\",\"Condensed Milk\",\"Vanilla Extract\",\"Grape Nut Cereal\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"In a large bowl, use an electric mixer to whip the cold heavy cream until stiff peaks form. Gently fold in the sweetened condensed milk and vanilla extract unti\",\"instructions\":[\"In a large bowl, use an electric mixer to whip the cold heavy cream until stiff peaks form. Gently fold in the sweetened condensed milk and vanilla extract until well combined.\",\"Fold in the cereal and stir until evenly distributed throughout the mixture.\",\"Pour the mixture into a freezer-safe container (such as a loaf pan). Lay plastic wrap on top of the ice cream to avoid freezer burn. Cover the container and freeze for at least 6 hours or until solid.\",\"Once frozen, let the ice cream sit at room temperature for a few minutes to soften slightly before scooping and serving.\"]},{\"id\":\"g231\",\"title\":\"Griddled aubergines with sesame dressing\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yoj48r1763817100.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Olive Oil\",\"Greek Yogurt\",\"Tahini Paste\",\"Garlic\",\"Lemon\",\"Coriander\",\"Parsley\",\"Mint\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nBrush each aubergine slice with some oil, then season. Heat a griddle pan or barbecue. When hot, griddle the aubergine slices for 2-3 mins on each side \",\"instructions\":[\"step 1\",\"Brush each aubergine slice with some oil, then season. Heat a griddle pan or barbecue. When hot, griddle the aubergine slices for 2-3 mins on each side until golden brown and tender.\",\"step 2\",\"Mix the yogurt with the tahini, garlic, lemon juice and herbs, then season. Top the aubergines with the dressing and scatter over extra herb leaves.\"]},{\"id\":\"g232\",\"title\":\"Griddled flatbreads\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8825lo1763815264.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Strong Wholemeal Flour\",\"Strong white bread flour\",\"Yeast\",\"Sugar\",\"Olive Oil\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip the flours into a food processor. Add the yeast, sugar and 1tsp salt, then mix well. Pour in 350ml warm water and the oil, then process to a soft do\",\"instructions\":[\"step 1\",\"Tip the flours into a food processor. Add the yeast, sugar and 1tsp salt, then mix well. Pour in 350ml warm water and the oil, then process to a soft dough. Mix for 1 min, then leave until doubled in size, about 1 hour.\",\"step 2\",\"Pulse the dough a couple of times just to knock out the air, then tip onto a floured surface. Cut the dough in half and roll out one half to a rectangle about 20 x 40cm. Trim the edges using a large sharp knife, then cut into eight 10cm squares. Line a large tray or two baking sheets with non-stick paper and arrange the bread rectangles over the tray in one layer. Repeat with the other half of the dough. Leave in a warm place for about 30 mins until the dough is just starting to rise.\",\"step 3\",\"Place bread directly onto the BBQ racks and cook for a couple of mins until they puff up, then flip over and cook on the other side. Tip into a basket and serve with the dips.\"]},{\"id\":\"g233\",\"title\":\"Grilled aubergines with spicy chickpeas & walnut sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ctw3ba1763788978.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Red Chilli\",\"Ginger\",\"Ground Cumin\",\"Chickpeas\",\"Tomato\",\"Lemon\",\"Aubergine\",\"Greek Yogurt\",\"Garlic Clove\",\"Walnuts\",\"Coriander\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat 2 tbsp oil in a pan, add the onion and fry until soft and lightly browned, about 10 mins. Add the chilli, ginger and spices and mix well. Stir in t\",\"instructions\":[\"step 1\",\"Heat 2 tbsp oil in a pan, add the onion and fry until soft and lightly browned, about 10 mins. Add the chilli, ginger and spices and mix well. Stir in the chickpeas, tomatoes and 5 tbsp water, bring to the boil, then simmer for 10 mins. Add a little salt and pepper and the lemon juice.\",\"step 2\",\"Arrange the aubergines over a grill pan. Brush lightly with oil, sprinkle with salt and pepper, then grill until golden. Flip them over, brush again with oil, season and grill again until tender and golden.\",\"step 3\",\"Mix the yogurt with the garlic, most of the walnuts and coriander and a little salt and pepper. Arrange the aubergine slices over a warm platter and spoon over the chickpea mix. Drizzle with the walnut sauce and scatter with the remaining walnuts and coriander.\"]},{\"id\":\"g234\",\"title\":\"Grilled eggplant with coconut milk\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/bopa2i1683209167.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg Plants\",\"Coconut Milk\",\"Lemon Juice\",\"Salt\",\"Red Pepper Flakes\",\"Onions\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\".  Prepare the eggplants for grilling by pricking them all over with a fork.  This is so it won’t burst during the grilling process as the natural water in it h\",\"instructions\":[\".  Prepare the eggplants for grilling by pricking them all over with a fork.  This is so it won’t burst during the grilling process as the natural water in it heats up.\",\"2.  Grill the eggplants, turning them over frequently to ensure even cooking.  Grill until the skins are dark brown, even black and the eggplant is soft when you touch it.\",\"3.  Soak the grilled eggplant in a bowl of water to cool it down.  Peel the skin off the eggplant.  Place the whole eggplants in a shallow dish (my mom actually cuts the eggplant into small, bite-sized pieces).\",\"4.  In a small mixing bowl, mix together the coconut milk or cream, lemon powder, salt and hot pepper.  Mix until the lemon powder and salt dissolve.  Taste, then adjust the amount of lemon powder, salt and hot pepper to your liking.  Pour the mixture over the eggplant.  Sprinkle the green onions over the eggplant and coconut milk.  Stir gently to combine.\"]},{\"id\":\"g235\",\"title\":\"Grilled Mac and Cheese Sandwich\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xutquv1505330523.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Macaroni\",\"Plain Flour\",\"Mustard Powder\",\"Garlic powder\",\"Kosher salt\",\"Black pepper\",\"Cayenne pepper\",\"Butter\",\"Whole Milk\",\"Heavy Cream\",\"Monterey Jack Cheese\",\"Butter\",\"garlic powder\",\"Bread\",\"Cheddar Cheese\",\"Colby Jack Cheese\",\"Butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Make the mac and cheese\\r\\n\\r\\n1. Bring a medium saucepan of generously salted water (you want it to taste like seawater) to a boil. Add the pasta and cook, stirrin\",\"instructions\":[\"Make the mac and cheese\",\"1. Bring a medium saucepan of generously salted water (you want it to taste like seawater) to a boil. Add the pasta and cook, stirring occasionally, until al dente, 8 to 10 minutes, or according to the package directions. The pasta should be tender but still chewy.\",\"2. While the pasta is cooking, in a small bowl, whisk together the flour, mustard powder, garlic powder, salt, black pepper, and cayenne pepper.\",\"3. Drain the pasta in a colander. Place the empty pasta pan (no need to wash it) over low heat and add the butter. When the butter has melted, whisk in the flour mixture and continue to cook, whisking frequently, until the mixture is beginning to brown and has a pleasant, nutty aroma, about 1 minute. Watch carefully so it does not scorch on the bottom of the pan.\",\"4. Slowly whisk the milk and cream into the flour mixture until everything is really well combined. Cook, whisking constantly, until the sauce is heated through and just begins to thicken, about 2 minutes. Remove from the heat. Gradually add the cheese while stirring constantly with a wooden spoon or silicone spatula and keep stirring until the cheese has melted into the sauce. Then stir in the drained cooked pasta.\",\"5. Line a 9-by-13-inch (23-by-33-centimeter) rimmed baking sheet with parchment paper or aluminum foil. Coat the paper or foil with nonstick cooking spray or slick it with butter. Pour the warm mac and cheese onto the prepared baking sheet and spread it evenly with a spatula. Coat another piece of parchment paper with cooking spray or butter and place it, oiled or buttered side down, directly on the surface of the mac and cheese. Refrigerate until cool and firm, about 1 hour.\",\"Make the grilled cheese\",\"6. Heat a large cast-iron or nonstick skillet over medium-low heat.\",\"7. In a small bowl, stir together the 4 tablespoons (55 grams) butter and garlic powder until well blended.\",\"8. Remove the mac and cheese from the refrigerator and peel off the top layer of parchment paper. Carefully cut into 8 equal pieces. Each piece will make 1 grilled mac and cheese sandwich. (You can stash each individual portion in a double layer of resealable plastic bags and refrigerate for up to 3 days or freeze it for up to 1 month.)\"]},{\"id\":\"g236\",\"title\":\"Grilled Portuguese sardines\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lpd4wy1614347943.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sardines\",\"Olive Oil\",\"Garlic\",\"Paprika\",\"Lemon\",\"Rosemary\",\"Red Chilli\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"STEP 1\\r\\n\\r\\nPut all of the ingredients, except the sardines, into a bowl and mix together with some seasoning. Pour into a baking dish, add the sardines and toss \",\"instructions\":[\"STEP 1\",\"Put all of the ingredients, except the sardines, into a bowl and mix together with some seasoning. Pour into a baking dish, add the sardines and toss really well. Cover and chill for a few hours.\",\"STEP 2\",\"Heat a BBQ or griddle pan until hot. Cook the sardines for 4-5 minutes on each side or until really caramelised and charred. Put onto a serving plate, drizzle with oil, sprinkle with a little more paprika and squeeze over the lemon wedges.\"]},{\"id\":\"g237\",\"title\":\"Ham croquetas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6dpa7m1763331105.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Egg\",\"Breadcrumbs\",\"Sunflower Oil\",\"Extra Virgin Olive Oil\",\"Leek\",\"jamón ibérico\",\"Plain Flour\",\"Vegetable Stock\",\"Milk\",\"Nutmeg\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make the filling, heat the olive oil in a pan until it starts to shimmer. Add the leek and sauté until soft but not coloured. Stir in the ham with a \",\"instructions\":[\"step 1\",\"To make the filling, heat the olive oil in a pan until it starts to shimmer. Add the leek and sauté until soft but not coloured. Stir in the ham with a wooden spoon, fry for 1 min, then stir in the flour and fry over a medium heat, stirring occasionally, until the mixture is golden but not burnt – this will take about 5 mins.\",\"step 2\",\"Meanwhile, combine the stock and milk in a small pan and heat until steaming but not boiling. Season with a few scrapes of nutmeg. Gradually add the liquid, a few tbsp at a time, stirring constantly.\",\"step 3\",\"Once you’ve incorporated all the milk stock, continue to cook the filling over a medium heat for about 10 mins or until it thickens and leaves the sides of the pan when you stir it.\",\"step 4\",\"Season with black pepper, taste and adjust the salt if necessary – the ham can be very salty to start with. The filling is now done: it has to be really thick because you don’t want the croquetas to turn into pancakes.\",\"step 5\",\"Smooth the mixture onto a baking tray (30 x 20cm is fine). Once it has stopped steaming, cover with cling film to stop it drying out. Leave to cool before putting it in the fridge for 1 hr.\"]},{\"id\":\"g238\",\"title\":\"Ham hock colcannon\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/n41ny81608588066.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Floury Potatoes\",\"Butter\",\"Garlic Clove\",\"Cabbage\",\"Spring Onions\",\"Double Cream\",\"Mustard\",\"Ham\",\"Eggs\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\nPeel and cut the potatoes into even, medium-sized chunks. Put in a large pan filled with cold salted water, bring to the boil and cook for 10-15 mins un\",\"instructions\":[\"STEP 1\",\"Peel and cut the potatoes into even, medium-sized chunks. Put in a large pan filled with cold salted water, bring to the boil and cook for 10-15 mins until a knife can be inserted into the potatoes easily.\",\"STEP 2\",\"Meanwhile, melt the butter in a large sauté pan over a medium heat. Add the garlic, cabbage, spring onions and some seasoning. Stir occasionally until the cabbage is wilted but still retains a little bite, then set aside.\",\"STEP 3\",\"Drain the potatoes, leave to steam-dry for a couple of mins, then mash with the cream, mustard and seasoning in the same saucepan. Stir in the cabbage and ham hock. Keep warm over a low heat.\",\"STEP 4\",\"Reheat the pan you used to cook the cabbage (no need to wash first), add a splash of oil, crack in the eggs and fry to your liking. To serve, divide the colcannon between bowls and top each with a fried egg.\"]},{\"id\":\"g239\",\"title\":\"Hodge Podge\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xihv0c1764447887.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"New Potatoes\",\"Carrots\",\"Green Beans\",\"Peas\",\"Dill\",\"Chives\",\"Milk\",\"Heavy Cream\",\"Butter\",\"Salt\",\"Black Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"First, cook your vegetables. Bring a large pot of salted water to boil. Par-cook carrots and potatoes for five minutes until carrots and potatoes are fork tende\",\"instructions\":[\"First, cook your vegetables. Bring a large pot of salted water to boil. Par-cook carrots and potatoes for five minutes until carrots and potatoes are fork tender, then blanch the peas and beans for about a minute in the same pot. Strain vegetables and set aside.\",\"In a heavy-bottomed pot or Dutch oven, melt butter over medium heat, add vegetables, and cook to warm through.\",\"Add milk and cream and bring the soup to a boil. Turn the heat down to low and season with salt and pepper.\",\"Add dill and chives and let simmer for at least 10 minutes. Serve warm.\"]},{\"id\":\"g240\",\"title\":\"Home-made Mandazi\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/thazgm1555350962.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Self-raising Flour\",\"Sugar\",\"Eggs\",\"Milk\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"This is one recipe a lot of people have requested and I have tried to make it as simple as possible and I hope it will work for you. Make sure you use the right\",\"instructions\":[\"This is one recipe a lot of people have requested and I have tried to make it as simple as possible and I hope it will work for you. Make sure you use the right flour which is basically one with raising agents. Adjust the amount of sugar to your taste and try using different flavours to have variety whenever you have them.\",\"You can use Coconut milk instead of regular milk, you can also add desiccated coconut to the dry flour or other spices like powdered cloves or cinnamon.\",\"For “healthy looking” mandazis do not roll the dough too thin before frying and use the procedure I have indicated above.\",\"1. Mix the flour,cinnamon and sugar in a suitable bowl.\",\"2. In a separate bowl whisk the egg into the milk\",\"3. Make a well at the centre of the flour and add the milk and egg mixture and slowly mix to form a dough.\",\"4. Knead the dough for 3-4 minutes or until it stops sticking to the sides of the bowl and you have a smooth surface.\",\"5. Cover the dough with a damp cloth  and allow to rest for 15 minutes.\",\"6. Roll the dough on a lightly floured surface into a 1cm thick piece.\",\"7. Using a sharp small knife, cut the dough into the desired size setting aside ready for deep frying.\"]},{\"id\":\"g241\",\"title\":\"Honey Balsamic Chicken with Crispy Broccoli & Potatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kvbotn1581012881.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Broccoli\",\"Garlic\",\"Chicken Breast\",\"Balsamic Vinegar\",\"Honey\",\"Chicken Stock\",\"Butter\",\"Vegetable Oil\",\"Olive Oil\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"2 Servings\\r\\n\\r\\n1. Preheat oven to 425 degrees. Wash and dry all produce. Cut potatoes into 1/2-inch-thick wedges. Toss on one side of a baking sheet with a drizz\",\"instructions\":[\"2 Servings\",\"1. Preheat oven to 425 degrees. Wash and dry all produce. Cut potatoes into 1/2-inch-thick wedges. Toss on one side of a baking sheet with a drizzle of oil, salt, and pepper. (For 4 servings, spread potatoes out across entire sheet.) Roast on top rack for 5 minutes (we'll add the broccoli then).\",\"2. Meanwhile, cut broccoli florets into bite-size pieces, if necessary. Peel and finely chop garlic. In a small microwave-safe bowl, combine 1 TBSP olive oil (2 TBSP for 4 servings) and half the garlic. Microwave until garlic sizzles, 30 seconds.\",\"3. Once potatoes have roasted 5 minutes, remove sheet from oven and add broccoli to empty side; carefully toss with garlic oil, salt, and pepper. (For 4 servings, add broccoli to a second sheet.) Continue roasting until potatoes and broccoli are browned and crispy, 15-20 minutes more.\",\"4. While veggies roast, pat chicken dry with paper towels; season all over with salt and pepper. Heat a drizzle of oil in a large pan over medium-high heat. Add chicken and cook until browned and cooked through, 5-6 minutes per side. (If chicken browns too quickly, reduce heat to medium.) Turn off heat; set chicken aside to rest. Wash out pan.\",\"5. Heat pan used for chicken over medium-high heat. Add a drizzle of oil and remaining garlic; cook until fragrant, 30 seconds. Stir in vinegar, honey, stock concentrate, and 1/4 cup water (1/3 cup for 4 servings). Simmer until thick and glossy, 2-3 minutes. Remove from heat and stir in 1 TBSP butter (2 TBSP for 4). Season with salt and pepper.\",\"6. Return chicken to pan and turn to coat in glaze. Divide chicken, broccoli, and potatoes between plates. Spoon any remaining glaze over chicken and serve.\"]},{\"id\":\"g242\",\"title\":\"Honey Teriyaki Salmon\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xxyupu1468262513.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Salmon\",\"Olive oil\",\"Soy Sauce\",\"Sake\",\"Sesame Seed\"],\"allergens\":[\"soy\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix all the ingredients in the Honey Teriyaki Glaze together. Whisk to blend well. Combine the salmon and the Glaze together.\\r\\n\\r\\nHeat up a skillet on medium-low\",\"instructions\":[\"Mix all the ingredients in the Honey Teriyaki Glaze together. Whisk to blend well. Combine the salmon and the Glaze together.\",\"Heat up a skillet on medium-low heat. Add the oil, Pan-fry the salmon on both sides until it’s completely cooked inside and the glaze thickens.\",\"Garnish with sesame and serve immediately.\"]},{\"id\":\"g243\",\"title\":\"Honey Yogurt Cheesecake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/y2irzl1585563479.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Digestive Biscuits\",\"Almonds\",\"Butter\",\"Greek Yogurt\",\"Mascarpone\",\"Eggs\",\"Lemon\",\"Orange\",\"Honey\",\"Fruit Mix\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 160C/140C fan/gas 3. Crush the biscuits and most of the almonds inside a plastic food bag using a rolling pin. Mix with the butter, then press into\",\"instructions\":[\"Heat oven to 160C/140C fan/gas 3. Crush the biscuits and most of the almonds inside a plastic food bag using a rolling pin. Mix with the butter, then press into the bottom of a deep, oval, 23cm dish (or something similar in size – a roasting tin, baking dish or cake tin will work). Bake for 10 mins until crisp.\",\"Stir or mash together the yogurt and mascarpone, then whisk in the eggs, one at a time. Stir in the lemon and orange zests, then stir in most of the honey, reserving about 3 tbsp. Spread over the biscuit base, cover loosely with foil and cook for 1 hr. Remove the foil and cook for 15 mins more until lightly golden and the top is firm with just the slightest wobble in the middle. Leave to cool. Can be kept in the fridge for up to 2 days.\",\"To serve, scatter with almonds, drizzle over the remaining honey, and hand around fresh fruit to go with it.\"]},{\"id\":\"g244\",\"title\":\"Hot and Sour Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529445893.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mushrooms\",\"Wood Ear Mushrooms\",\"Tofu\",\"Pork\",\"Chicken Stock\",\"Salt\",\"Sugar\",\"Sesame Seed Oil\",\"Pepper\",\"Hotsauce\",\"Vinegar\",\"Soy Sauce\",\"Cornstarch\",\"Water\",\"Spring Onions\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1 - MAKING THE SOUP\\r\\nIn a wok add chicken broth and wait for it to boil.\\r\\nNext add salt, sugar, sesame seed oil, white pepper, hot pepper sauce, vinegar an\",\"instructions\":[\"STEP 1 - MAKING THE SOUP\",\"In a wok add chicken broth and wait for it to boil.\",\"Next add salt, sugar, sesame seed oil, white pepper, hot pepper sauce, vinegar and soy sauce and stir for few seconds.\",\"Add Tofu, mushrooms, black wood ear mushrooms to the wok.\",\"To thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your soup until it's the right thickness.\",\"Next add 1 egg slightly beaten with a knife or fork and add it to the soup and stir for 8 seconds\",\"Serve the soup in a bowl and add the bbq pork and sliced green onions on top.\"]},{\"id\":\"g245\",\"title\":\"Hot Chocolate Fudge\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xrysxr1483568462.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chocolate Chips\",\"Heavy Cream\",\"Condensed Milk\",\"Vanilla Extract\",\"White Chocolate Chips\",\"Miniature Marshmallows\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.\\r\\nIn a microwave-safe bowl, combine the dark chocolate chips, heavy cream\",\"instructions\":[\"Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.\",\"In a microwave-safe bowl, combine the dark chocolate chips, heavy cream and half of the sweetened condensed milk. Microwave the dark chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.\",\"Add the vanilla extract to the dark chocolate mixture and stir well until smooth.\",\"Transfer the dark chocolate mixture into the prepared pan and spread into an even layer.\",\"In a separate bowl, combine the white chocolate chips with the remaining half of the sweetened condensed milk. Microwave the white chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.\",\"Evenly spread the white chocolate mixture on top of dark chocolate layer.\",\"Top the chocolate layers with the Mallow Bits or miniature marshmallows, and gently press them down.\",\"Refrigerate for 4 hours, or until set.\",\"Remove the fudge and wax paper from the pan. Carefully peel all of the wax paper from the fudge.\",\"Cut the fudge into bite-sized pieces and serve.\"]},{\"id\":\"g246\",\"title\":\"Hot cumin lamb wrap with crunchy slaw & spicy mayo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/jyylmo1763790808.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb Leg\",\"Olive Oil\",\"Ground Cumin\",\"Sugar\",\"White Wine Vinegar\",\"Carrots\",\"Spring Onions\",\"White Cabbage\",\"Sweet Peppadew Peppers\",\"Mayonnaise\",\"Pita Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat a griddle pan. Rub the lamb steaks with the oil, cumin and some seasoning. Griddle for about 3-4 mins on each side or until cooked to your liking. \",\"instructions\":[\"step 1\",\"Heat a griddle pan. Rub the lamb steaks with the oil, cumin and some seasoning. Griddle for about 3-4 mins on each side or until cooked to your liking. Place to one side on a plate to rest.\",\"step 2\",\"In a large bowl, stir the sugar into the vinegar until dissolved. Add the carrots, spring onions, cabbage and some seasoning, and toss together.\",\"step 3\",\"Blitz the whole peppers and the mayo in a food processor. Add a heap of the salad to each flatbread. Slice the lamb, trimming off any excess fat and lay on top of the salad, drizzling with the resting juices. Spoon over the mayo and scatter with a few of the sliced peppers. Roll up and eat. If using pitta, split and stuff. Serve any extra salad on the side.\"]},{\"id\":\"g247\",\"title\":\"Hummus\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/gpon5u1763801180.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chickpeas\",\"Tahini Paste\",\"Garlic Clove\",\"Greek Yogurt\",\"Lemon\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nDrain the chickpeas into a sieve set over a bowl or jug to catch the liquid. Tip the chickpeas, tahini, garlic and yogurt into a food processor or blend\",\"instructions\":[\"step 1\",\"Drain the chickpeas into a sieve set over a bowl or jug to catch the liquid. Tip the chickpeas, tahini, garlic and yogurt into a food processor or blender and whizz to smooth.\",\"step 2\",\"Whizz in a tbsp of the chickpea liquid at a time until you have a nice consistency, then scrape into a bowl.\",\"step 3\",\"Stir in a squeeze of lemon juice and season to taste.\"]},{\"id\":\"g248\",\"title\":\"Imam bayildi with BBQ lamb & tzatziki\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ampz9v1763787134.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Olive Oil\",\"Onion\",\"Garlic\",\"Cinnamon\",\"Tomato\",\"Parsley\",\"Lamb Loin Chops\",\"Paprika\",\"Lemon\",\"Greek Yogurt\",\"Cucumber\",\"Mint\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat oven to 190C/170C fan/gas 5. Halve the aubergines lengthways and score the flesh side deeply, brush with a good layer of olive oil and put on a bak\",\"instructions\":[\"step 1\",\"Heat oven to 190C/170C fan/gas 5. Halve the aubergines lengthways and score the flesh side deeply, brush with a good layer of olive oil and put on a baking sheet. Roast for 20 mins or until the flesh is soft enough to scoop out.\",\"step 2\",\"Fry the onion in a little oil until soft, add the garlic and cinnamon and fry for 1 min. Once the aubergines are cool enough to handle, scoop out the centres. Roughly chop the flesh and add it to the onions. Halve the tomatoes, scoop the seeds and juice into a sieve set over a bowl, then chop the flesh. Add the chopped tomatoes to the pan and cook everything for 10 mins until nice and soft. Add a little more oil if you need to. Stir in the parsley, leaving a little for scattering at the end.\",\"step 3\",\"Lay the aubergine halves in a baking dish and divide the tomato mixture between them. Pour over the juice from the tomatoes, drizzle with more olive oil and bake for 30 mins until the aubergines have collapsed.\",\"step 4\",\"Meanwhile, mix the tzatziki ingredients together and put in a small serving bowl.\",\"step 5\",\"Season the lamb with salt, black pepper and a pinch of paprika. Griddle, grill or barbecue for 3 mins on each side or until the fat is nicely browned, then put in a serving dish and squeeze over the lemon halves. Scatter the aubergines with parsley, then serve with the lamb and tzatziki.\"]},{\"id\":\"g249\",\"title\":\"Irish stew\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sxxpst1468569714.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"whole wheat\",\"lamb loin chops\",\"olive oil\",\"shallots\",\"Carrots\",\"turnips\",\"celeriac\",\"charlotte potatoes\",\"white wine\",\"caster sugar\",\"fresh thyme\",\"oregano\",\"chicken stock\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oven to 180C/350F/gas mark 4. Drain and rinse the soaked wheat, put it in a medium pan with lots of water, bring to a boil and simmer for an hour, unti\",\"instructions\":[\"Heat the oven to 180C/350F/gas mark 4. Drain and rinse the soaked wheat, put it in a medium pan with lots of water, bring to a boil and simmer for an hour, until cooked. Drain and set aside.\",\"Season the lamb with a teaspoon of salt and some black pepper. Put one tablespoon of oil in a large, deep sauté pan for which you have a lid; place on a medium-high heat. Add some of the lamb – don't overcrowd the pan – and sear for four minutes on all sides. Transfer to a bowl, and repeat with the remaining lamb, adding oil as needed.\",\"Lower the heat to medium and add a tablespoon of oil to the pan. Add the shallots and fry for four minutes, until caramelised. Tip these into the lamb bowl, and repeat with the remaining vegetables until they are all nice and brown, adding more oil as you need it.\",\"Once all the vegetables are seared and removed from the pan, add the wine along with the sugar, herbs, a teaspoon of salt and a good grind of black pepper. Boil on a high heat for about three minutes.\",\"Tip the lamb, vegetables and whole wheat back into the pot, and add the stock. Cover and boil for five minutes, then transfer to the oven for an hour and a half.\",\"Remove the stew from the oven and check the liquid; if there is a lot, remove the lid and boil for a few minutes.\"]},{\"id\":\"g250\",\"title\":\"Jam jam cookies\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sktequ1764447186.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Butter\",\"Sugar\",\"Molasses\",\"Vanilla\",\"Baking Powder\",\"Water\",\"Baking Powder\",\"Cinnamon\",\"Salt\",\"Flour\",\"Jam\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 350 °F (180 °C) and line a large baking sheet with parchment paper.\\r\\nIn a stand mixer with the paddle attachment, cream the butter, white su\",\"instructions\":[\"Preheat the oven to 350 °F (180 °C) and line a large baking sheet with parchment paper.\",\"In a stand mixer with the paddle attachment, cream the butter, white sugar and egg until combined, then add the molasses and vanilla and mix until smooth.\",\"Once combined, add the baking soda water mixture and mix for another minute to combine.\",\"Combine dry ingredients; mix baking powder, cinnamon, flour and salt in a separate bowl then add to the wet ingredients a little at a time, mixing on low until fully combined and scraping down the sides to ensure everything is incorporated. The dough should be easily shaped.\",\"Portion dough with a small spoon, roll them into balls and place them on the lined cookie sheet, press them into flat discs using a floured glass or your moistened palm.\",\"Place cookies on parchment-lined baking sheets and bake for 10-12 mins. Remove from the oven and let them cool for at least 10 minutes.\",\"Once cooled the cookie sandwiches by spreading at least two teaspoons of your favourite jam between the two cookies. Repeat and enjoy with a cup of tea.\"]},{\"id\":\"g251\",\"title\":\"Jam Roly-Poly\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ysqupp1511640538.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Self-raising Flour\",\"Vanilla\",\"Suet\",\"Milk\",\"Raspberry Jam\",\"Custard\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Put a deep roasting tin onto the bottom shelf of the oven, and make sure that there’s another shelf directly above it. Pull the roasting tin out on its shelf, f\",\"instructions\":[\"Put a deep roasting tin onto the bottom shelf of the oven, and make sure that there’s another shelf directly above it. Pull the roasting tin out on its shelf, fill two-thirds with boiling water from the kettle, then carefully slide it back in. Heat oven to 180C/160C fan/gas 4. Tear off a large sheet of foil and greaseproof paper (about 30 x 40cm). Sit the greaseproof on top of the foil and butter it.\",\"Tip butter, flour and vanilla seeds into a food processor; pulse until the butter has disappeared. Tip into a mixing bowl. Stir through the suet, pour in the milk and work together with a cutlery knife until you get a sticky dough. You may need a drop more milk, depending on your flour.\",\"Tip the dough out onto a floured surface, quickly pat together to smooth, then roll out to a square roughly 25 x 25cm. Spread the jam all over, leaving a gap along one edge, then roll up from the opposite edge. Pinch the jam-free edge into the dough where it meets, and pinch the ends roughly, too. Carefully lift onto the greased paper, join-side down (you might find a flat baking sheet helpful for this), loosely bring up the paper and foil around it, then scrunch together along the edges and ends to seal. The roly-poly will puff quite a bit during cooking so don’t wrap it tightly. Lift the parcel directly onto the rack above the tin and cook for 1 hr.\",\"Let the pudding sit for 5 mins before unwrapping, then carefully open the foil and paper, and thickly slice to serve.\"]},{\"id\":\"g252\",\"title\":\"Jamaican Banana Fritters\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ul2uy31764794321.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Banana\",\"Vanilla Extract\",\"Cinnamon\",\"Nutmeg\",\"Brown Sugar\",\"Salt\",\"All purpose flour\",\"Oil\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Mash bananas with fork in bowl.\\r\\nAdd brown sugar, vanilla, extract, cinnamon, nutmeg and a pinch of salt. Sift in flour and stir with spoon until fully combined\",\"instructions\":[\"Mash bananas with fork in bowl.\",\"Add brown sugar, vanilla, extract, cinnamon, nutmeg and a pinch of salt. Sift in flour and stir with spoon until fully combined.\",\"Add oil to a 10 inch skillet over medium-high heat. Once oil is hot, drop banana fritter batter in oil by the spoonful. Once one side is golden and bubbles appear on the top, flip fritter and cook until the other side is browned as well.\",\"Remove fritters and drain on paper towels. Enjoy\"]},{\"id\":\"g253\",\"title\":\"Jamaican Beef Patties\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wsqqsw1515364068.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Salt\",\"Curry Powder\",\"Butter\",\"Water\",\"Minced Beef\",\"Allspice\",\"Black Pepper\",\"Vegetable Oil\",\"Onions\",\"Red Pepper\",\"Garlic\",\"Thyme\",\"Salt\",\"Tomato Ketchup\",\"Water\",\"Onions\",\"Egg\",\"Water\",\"Water\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Make the Pastry Dough\\r\\n\\r\\nTo a large bowl, add flour, 1 teaspoon salt, and turmeric and mix thoroughly.\\r\\nRub shortening into flour until there are small pieces o\",\"instructions\":[\"Make the Pastry Dough\",\"To a large bowl, add flour, 1 teaspoon salt, and turmeric and mix thoroughly.\",\"Rub shortening into flour until there are small pieces of shortening completely covered with flour.\",\"Pour in 1/2 cup of the ice water and mix with your hands to bring the dough together. Keep adding ice water 2 to 3 tablespoons at a time until the mixture forms a dough.\",\"At this stage, you can cut the dough into 2 large pieces, wrap in plastic and refrigerate for 30 minutes before using it.\",\"Alternatively, cut the dough into 10 to 12 equal pieces, place on a platter or baking sheet, cover securely with plastic wrap and let chill for 30 minutes while you make the filling.\",\"Make the Filling\",\"Add ground beef to a large bowl. Sprinkle in allspice and black pepper. Mix together and set aside.\",\"Heat oil in a skillet until hot.\",\"Add onions and sauté until translucent. Add hot pepper, garlic and thyme and continue to sauté for another minute. Add 1/4 teaspoon salt.\"]},{\"id\":\"g254\",\"title\":\"Jamaican Boiled Dumplings\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tsdbcq1764795636.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Salt\",\"All purpose flour\",\"Salt\",\"Water\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Instructions\\r\\n \\r\\nIn a large pot, bring water and salt to a boil to boil the dumplings.\\r\\nIn a large mixing bowl, combine the all-purpose flour and salt, stirring\",\"instructions\":[\"Instructions\",\"In a large pot, bring water and salt to a boil to boil the dumplings.\",\"In a large mixing bowl, combine the all-purpose flour and salt, stirring to distribute the salt evenly throughout the flour. Gradually add water to the flour mixture, mixing with your hands until a dough forms.\",\"Divide the dough into equal-sized pieces, rolling each into a smooth ball. Flatten each ball slightly with the palm of your hand to form a round, circular dumpling. It should look like a thick disk.\",\"Carefully drop the dumplings into the boiling water, one at a time, ensuring that they don't stick together. You can use a wooden spoon to stir the dumplings in the water.\",\"Boil the dumplings for 15-20 minutes, or until they are cooked through and have risen to the surface of the water. Stir occasionally to prevent sticking.\",\"Use a slotted spoon to remove the cooked dumplings from the pot, allowing any excess water to drain.\",\"Serve with your favorite recipes.\"]},{\"id\":\"g255\",\"title\":\"Jamaican Cornmeal Porridge\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sng9bm1765320170.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Coconut Milk\",\"Fine Yellow Cornmeal\",\"Vanilla Extract\",\"Ground Cinnamon\",\"Ground Nutmeg\",\"Ground Allspice\",\"Sweetened Condensed Milk\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Add 2 ½ cups water, 1 can coconut milk to a 4 QT heavy bottomed pot. Bring to a boil over medium-high heat.\\r\\nMeanwhile, add 1 cup cornmeal and 1 ½ cup water to \",\"instructions\":[\"Add 2 ½ cups water, 1 can coconut milk to a 4 QT heavy bottomed pot. Bring to a boil over medium-high heat.\",\"Meanwhile, add 1 cup cornmeal and 1 ½ cup water to a large mixing cup and whisk until smooth.\",\"Once the pot begins to boil, whisk in cornmeal mixture and continue to whisk for about 1 minute, ensuring there are no lumps. Reduce heat to low and cover with a tight fitting lid.\",\"Cook over low heat for 15-20 minutes, stirring occasionally. When there is about 5 minutes left, stir in vanilla extract, cinnamon, nutmeg, and all-spice. Remove from heat and sweeten with condensed milk.\",\"Serve and enjoy.\"]},{\"id\":\"g256\",\"title\":\"Jamaican Curry Chicken Recipe\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/o5fuq51764789643.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Curry Powder\",\"All-purpose Seasoning\",\"Onion\",\"Spring Onions\",\"Green Pepper\",\"Garlic\",\"Scotch Bonnet\",\"Thyme\",\"Olive Oil\",\"Water\",\"Russet Potato\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Equipment\\r\\n\\r\\nDutch Oven\\r\\n\\r\\nInstructions\\r\\n \\r\\nAdd chicken thighs, all-purpose seasoning, 1 tablespoon of curry powder, onion, green onions, green pepper, garlic c\",\"instructions\":[\"Equipment\",\"Dutch Oven\",\"Instructions\",\"Add chicken thighs, all-purpose seasoning, 1 tablespoon of curry powder, onion, green onions, green pepper, garlic cloves, scotch bonnet pepper (if using), and thyme to a large bowl and combine, making sure all chicken pieces are covered with the seasoning. Cover and refrigerate for at least 1 hour or up to overnight.\",\"One the chicken is done marinating, remove onions, peppers, and garlic cloves from chicken and set aside.\",\"Heat olive oil in a large heavy bottom pot over medium heat. Add remaining curry powder and stir, cooking for about 20-30 seconds. Add onions, green pepper, garlic cloves, thyme, and scotch bonnet pepper (if using) to pot and stir until onions have softened, about 3-5 minutes. If your onions and peppers are looking dry, add about 1 tablespoon of water.\",\"Add chicken and ¼ cup of water to the pot. Cover and reduce heat to medium low. Cook, stirring occasionally, for 30-35 minutes.\",\"When there is about 15 minutes remaining, stir in potato and continue to cook covered.\",\"Once chicken is cooked and potatoes are softened, remove from heat. Salt and pepper to taste.\"]},{\"id\":\"g257\",\"title\":\"Jamaican Curry Goat\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uc9qp11764796575.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Goat Meat\",\"Jamaican Curry Powder\",\"Ground Ginger\",\"All-purpose Seasoning\",\"Allspice\",\"Onion\",\"Garlic\",\"Thyme\",\"Oil\",\"Water\",\"Scotch Bonnet\",\"Russet Potato\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Equipment\\r\\n\\r\\n6QT Pressure cooker\\r\\n\\r\\nInstructions\\r\\n \\r\\nRinse goat meat with vinegar and water.\\r\\nSeason goat meat with 1 ½ tablespoon curry powder, all-purpose sea\",\"instructions\":[\"Equipment\",\"6QT Pressure cooker\",\"Instructions\",\"Rinse goat meat with vinegar and water.\",\"Season goat meat with 1 ½ tablespoon curry powder, all-purpose seasoning, ground ginger, allspice, onion, garlic cloves, and thyme. Marinate for at least 4 hours or up to overnight.\",\"Remove onion and garlic from goat and set aside.\",\"Set an electric pressure cooker, like an Instant Pot, on high sauté and add oil. Add goat meat and brown, about 2-3 minutes per side. Remove goat from insert and add 1 tablespoon oil and remaining curry powder and sauté for about 10 seconds. Then add onions and garlic and sauté until softened. About 4 minutes. If the onions look dry, add a little water and continue to sauté.\",\"Add goat and water to the pressure cooker and cover the pressure cooker. Cook for 40 minutes on high pressure. Allow to naturally release for 10 minutes, then release the remaining pressure.\",\"Once all the pressure has been released, open the pressure cooker. Place on sauté for 10-15 minutes, add potatoes and a whole scotch bonnet pepper. Cook until potatoes have softened. Remove scotch bonnet pepper.\"]},{\"id\":\"g258\",\"title\":\"Jamaican Curry Shrimp Recipe\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/n7h5zs1765318909.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Jumbo Shrimp\",\"Jamaican Curry Powder\",\"All-purpose Seasoning\",\"Olive Oil\",\"Onion\",\"Red Pepper\",\"Green Pepper\",\"Scotch Bonnet\",\"Garlic\",\"Unsweetened Coconut Milk\",\"Tomato Ketchup\",\"Thyme\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Season shrimp with 1 Tablespoon of curry powder and all-purpose seasoning and set aside for about 10 minutes while you prepare the other ingredients like choppi\",\"instructions\":[\"Season shrimp with 1 Tablespoon of curry powder and all-purpose seasoning and set aside for about 10 minutes while you prepare the other ingredients like chopping your onions, peppers, and garlic.\",\"Heat 2 Tablespoons of olive oil in a large skillet over medium heat. Add sliced yellow onion, red bell pepper, green bell pepper, scotch bonnet pepper, if using, and chopped garlic and stir for 5 minutes, until peppers are slightly softened.\",\"Add 1.5 Tablespoons of curry powder to the skillet and stir for an additional minute.\",\"Then add coconut milk, seasoned shrimp, ketchup, and thyme, making sure the shrimp is covered in the sauce.\",\"Allow the sauce to come to a simmer and continue to cook over medium heat, stirring occasionally and flipping the shrimp halfway, until the shrimp is fully cooked on both sides. This should take about 5-6 minutes. Salt and pepper to taste.\"]},{\"id\":\"g259\",\"title\":\"Jamaican Festival (Sweet Dumpling)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/g6xb8m1764875029.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"All purpose flour\",\"Cornmeal\",\"Sugar\",\"Baking Powder\",\"Vanilla Extract\",\"Salt\",\"Milk\",\"Oil\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Heat a heavy bottom pot of oil that has at least 3 inches of oil in it or use a deep fryer if you have one. Turn the heat over medium heat until the temperature\",\"instructions\":[\"Heat a heavy bottom pot of oil that has at least 3 inches of oil in it or use a deep fryer if you have one. Turn the heat over medium heat until the temperature reaches 350 degrees Fahrenheit.\",\"Add the all-purpose flour, cornmeal, granulated sugar, baking powder, and salt to a large bowl and stir to combine.\",\"Add the vanilla extract and milk and stir until the dough comes together. Then use your hands to lightly form the mixture into a ball.\",\"Pinch off pieces of dough and roll them into long oval shapes. Make about 12 dumplings.\",\"Once the oil has reached the temperature of 350 degrees Fahrenheit, fry the dough on all sides, until golden brown. This should take about 4-6 minutes.\",\"Remove dough and drain off any excess grease. Serve and enjoy.\"]},{\"id\":\"g260\",\"title\":\"Jamaican Fried Dumplings\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/dd7t4d1764877271.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"All purpose flour\",\"Baking Powder\",\"Salt\",\"Milk\",\"Oil\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Add flour, baking powder, and salt in a large bowl and stir to combine. Pour in the milk and stir until combined. Then roll the mixture into a ball and lightly \",\"instructions\":[\"Add flour, baking powder, and salt in a large bowl and stir to combine. Pour in the milk and stir until combined. Then roll the mixture into a ball and lightly knead until it comes together.\",\"Break off about 10 pieces of dough and form them into balls. Set them aside.\",\"In a 10-inch skillet, heat enough oil over medium heat to fry the dumplings, until the oil is about 350 degrees.\",\"Once the dumplings are browned on one side, flip them and cook until both sides are browned, about 2-3 minutes each.\",\"Once done, remove the dumplings from the oil and place them on paper towels or a cooling rack to drain off any excess oil.\",\"Serve and enjoy.\"]},{\"id\":\"g261\",\"title\":\"Jamaican Instant Pot Rice and Beans\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/11bvtm1764795135.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Garlic\",\"Spring Onions\",\"Rice\",\"Coconut Milk\",\"Water\",\"Salt\",\"Allspice\",\"Black Pepper\",\"Kidney Beans\",\"Thyme\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Instructions\\r\\n \\r\\nSet Instant Pot to \\\"Sauté.\\\" Once Hot, add olive oil. Then add yellow onion and stir until softened, about 3 minutes. Add garlic and green onion\",\"instructions\":[\"Instructions\",\"Set Instant Pot to \\\"Sauté.\\\" Once Hot, add olive oil. Then add yellow onion and stir until softened, about 3 minutes. Add garlic and green onions and stir for about 30 more seconds.\",\"Press “Cancel” on the Instant Pot. Add rice, coconut milk, water, salt, allspice, and black pepper and stir.\",\"Pour undrained kidney beans on top of the rice mixture. Do not stir. Lay sprigs of thyme on top. Cover the Instant Pot, ensuring the valve is set to “Sealing.”\",\"Press “Manual” or “Pressure Cook” on the Instant Pot and set for High pressure for 6 minutes.\",\"Once the pressure cooking time is done, allow it to natural release for 10 minutes, then quick release any remaining pressure by moving valve to \\\"Venting\\\"\",\"Open lid and remove thyme sprigs. Fluff rice with fork and Enjoy!\",\"Stove Top Instructions\",\"Heat olive oil in a large pot over medium heat. Add yellow onion and stir until softened, about 3 minutes. Add garlic and green onions and stir for about 30 more seconds.\",\"Add rice, undrained kidney beans, coconut milk, water, salt, allspice, and black pepper and stir until combined. Lay thyme on top. Bring mixture to a simmer.\"]},{\"id\":\"g262\",\"title\":\"Jamaican Pepper Shrimp\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/bx07m71764792853.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Shrimp\",\"Scotch Bonnet\",\"All-purpose Seasoning\",\"Ground Annatto\",\"Allspice\",\"Shrimp Stock\",\"Onion\",\"Garlic\",\"White Vinegar\",\"Thyme\",\"Salt\"],\"allergens\":[\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"In a medium bowl, combine shrimp with minced Scotch Bonnet peppers, all-purpose seasoning, ground annatto, and grounf allspice. Toss well to coat evenly and let\",\"instructions\":[\"In a medium bowl, combine shrimp with minced Scotch Bonnet peppers, all-purpose seasoning, ground annatto, and grounf allspice. Toss well to coat evenly and let marinate for 10 minutes.\",\"Heat a large pan over medium heat. Add the shrimp stock and bring to a gentle simmer. Stir in the diced onion and garlic, cooking until softened and fragrant, about 2 minutes.\",\"Add the seasoned shrimp and thyme sprigs, spreading the shrimp in the pan. Cover and cook for about 5–7 minutes, stirring occasionally, until the shrimp turn bright orange and are cooked through.\",\"Add the white vinegar, stir, and cook for another minute. Taste; add salt to taste. Using a slotted spoon, transfer the shrimp to a plate. Serve hot with some cooking liquid drizzled on top.\"]},{\"id\":\"g263\",\"title\":\"Jamaican Rice and Peas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pkyvrn1764878267.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice\",\"Coconut Milk\",\"Kidney Beans\",\"Water\",\"Kosher Salt\",\"Ground Allspice\",\"Black Pepper\",\"Spring Onions\",\"Thyme\",\"Scotch Bonnet\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Equipment\\r\\nDutch oven\\r\\n\\r\\nAdd rice, coconut milk, kidney beans, water, kosher salt, allspice, and black pepper to a large pot and stir until combined. Lay green \",\"instructions\":[\"Equipment\",\"Dutch oven\",\"Add rice, coconut milk, kidney beans, water, kosher salt, allspice, and black pepper to a large pot and stir until combined. Lay green onions, thyme and Scotch bonnet pepper on top. Bring mixture to a boil.\",\"Once boiling, reduce heat to low and cover with a lid. Allow to cook covered for 18 minutes over low heat, then remove from heat. Leave the lid on for an additional 5 minutes.\",\"Open the lid and remove the green onion, Scotch bonnet pepper, and thyme. Fluff the rice and peas with a fork. Serve and enjoy.\"]},{\"id\":\"g264\",\"title\":\"Jamaican Spice Bun Recipe\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/08c5f41764791918.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"All purpose flour\",\"Baking Powder\",\"Ground Cinnamon\",\"Salt\",\"Egg\",\"Brown Sugar\",\"Beer\",\"Milk\",\"Honey\",\"Unsalted Butter\",\"Molasses\",\"Caramelized Sugar Sauce\",\"Vanilla Extract\",\"Dried cranberries\",\"Raisins\",\"Dried Cherries\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Soak the craisins, raisins, and cherries in the 1 cup of beer. Set aside and allow to soak for 30 minutes.\\r\\nPreheat the oven to 325 degrees Fahrenheit. Grease a\",\"instructions\":[\"Soak the craisins, raisins, and cherries in the 1 cup of beer. Set aside and allow to soak for 30 minutes.\",\"Preheat the oven to 325 degrees Fahrenheit. Grease an 8x4 loaf pan. Set aside.\",\"Combine all-purpose flour, baking powder, ground cinnamon, salt, in a large bowl and set aside.\",\"In another bowl, combine brown sugar, egg, milk, honey, melted butter, molasses, browning, vanilla extract, and the beer that’s soaking the fruit. Do not pour the fruit in at this time, just the beer. Mix to combine.\",\"Remove 2 tablespoon of flour from the flour mixture and toss the fruit in it. Set aside.\",\"Make a well in the middle of the bowl of dry ingredients and pour in wet mixture, stirring until fully combined. And the fruits to the mixture and stir until incpororated.\",\"Pour mixture into prepared loaf pan and bake in the preheated oven for 50-60 minutes or until a toothpick comes out clean.\",\"Cool for 5 minutes in the pan and then move to a cooling rack to finish cooling. Serve with slices of cheddar cheese.\"]},{\"id\":\"g265\",\"title\":\"Jamaican Steamed Cabbage\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/paejva1765321314.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cabbage\",\"Carrots\",\"Plum Tomatoes\",\"Onion\",\"Garlic\",\"Spring Onions\",\"Thyme\",\"Scotch Bonnet\",\"Water\",\"Olive Oil\",\"Unsalted Butter\",\"Kosher Salt\",\"Black Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Add all the ingredients to a large pan over medium heat and cover with a lid.\\r\\nCook on medium heat for 10 minutes, stirring occasionally.\\r\\nAfter 10 minutes, red\",\"instructions\":[\"Add all the ingredients to a large pan over medium heat and cover with a lid.\",\"Cook on medium heat for 10 minutes, stirring occasionally.\",\"After 10 minutes, reduce the heat to low and continue to cook for an additional 5 minutes, until the cabbage is soft and tender. Remove from the heat and remove the stalks of thyme before serving.\"]},{\"id\":\"g266\",\"title\":\"Jamaican Sweet Potato Pudding\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xj9sa81764788866.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sweet Potatoes\",\"Coconut Milk\",\"Brown Sugar\",\"All purpose flour\",\"Vanilla Extract\",\"Allspice\",\"Ground Cinnamon\",\"Ground Nutmeg\",\"Ground Ginger\",\"Salt\",\"Raisins\",\"Coconut Milk\",\"Brown Sugar\",\"Ground Cinnamon\",\"Ground Nutmeg\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Preheat oven to 350°F (175°C). Grease and line a 9-inch round pan or loaf pan with parchment paper.\\r\\nPlace your cut sweet potatoes in the bowl of a food process\",\"instructions\":[\"Preheat oven to 350°F (175°C). Grease and line a 9-inch round pan or loaf pan with parchment paper.\",\"Place your cut sweet potatoes in the bowl of a food processor and process until finely grated. In a small bowl, toss raisins in 2 teaspoons flour from the ½ cup. Set aside.\",\"In a large bowl, combine grated sweet potatoes, light brown sugar, all-purpose flour, vanilla extract, allspice, cinnamon, nutmeg, ginger, and salt. Stir in 1½ cups of coconut milk until a batter forms. Fold in the raisins that were tossed in the flour.\",\"Pour the batter into the prepared pan and smooth the top. Bake uncovered for 1 hour 30 minutes, until mostly set but still slightly soft in the center\"]},{\"id\":\"g267\",\"title\":\"Jamon & wild garlic croquetas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/zc9cwz1763196177.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Wild Garlic Leaves\",\"Milk\",\"Olive Oil\",\"Flour\",\"manchego\",\"jamón ibérico\",\"Egg\",\"Breadcrumbs\",\"Vegetable Oil\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nWash the wild garlic leaves well in a colander, then pour over boiling water from the kettle until just wilted. Immediately rinse under cold running wat\",\"instructions\":[\"step 1\",\"Wash the wild garlic leaves well in a colander, then pour over boiling water from the kettle until just wilted. Immediately rinse under cold running water, then squeeze out the excess water and finely chop.\",\"step 2\",\"Warm the milk in a pan over a low heat until just steaming. Heat the oil or butter in a second pan and, once warm or melted, stir in the flour for a couple of minutes until it starts to brown a little. Gradually add the warm milk, a little at a time, until you have a thick, silky sauce. Bubble for a minute or two, stirring to make sure all the flour has cooked out. Season.\",\"step 3\",\"Add the manchego, jamón and wild garlic to the pan, and beat to combine. Tip out onto a lightly oiled baking tray or plate, spread out then cover and chill for at least 1 hr. Will keep chilled for up to 24 hrs.\",\"step 4\",\"Lightly oil your hands and shape the mixture into 18-20 even-sized balls. Arrange on a baking tray and freeze for 30 mins to firm up.\",\"step 5\",\"Beat the egg in a shallow dish with a little seasoning. Tip the panko into a second dish. Dip each of the croquetas in the egg, then turn to coat in the breadcrumbs. At this point, the raw croquetas can be frozen for up to three months. Pour the oil into a large, deep pan ensuring it is no more than a third full and heat to 170C, or until a cube of bread browns lightly in 30 seconds. Fry the croquetas in batches for 2-3 mins until deeply golden. To cook from frozen, fry at 160C for a few minutes longer until they’re piping hot inside. Remove to a sheet of kitchen paper using a slotted spoon and leave to drain. Serve warm with a glass of sherry.\"]},{\"id\":\"g268\",\"title\":\"Japanese gohan rice\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kw92t41604181871.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sushi Rice\",\"Mirin\",\"Pickle Juice\",\"Spring Onions\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"STEP 1\\r\\nRinsing and soaking your rice is key to achieving the perfect texture. Measure the rice into a bowl, cover with cold water, then use your fingers to mas\",\"instructions\":[\"STEP 1\",\"Rinsing and soaking your rice is key to achieving the perfect texture. Measure the rice into a bowl, cover with cold water, then use your fingers to massage the grains of rice – the water will become cloudy. Drain and rinse again with fresh water. Repeat five more times until the water stays clear.\",\"STEP 2\",\"Tip the rinsed rice into a saucepan with 400ml water, or 200ml dashi and 200ml water, bring to the boil, then turn down the heat to a low simmer, cover with a tight-fitting lid with a steam hole and cook for 15 mins. Remove from the heat and leave to sit for another 15 mins, then stir through the mirin. Remove the lid and give it a good stir. Serve with any or all of the optional toppings.\"]},{\"id\":\"g269\",\"title\":\"Japanese Katsudon\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/d8f6qx1604182128.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Onion\",\"Pork\",\"Vegetable Stock\",\"Soy Sauce\",\"Mirin\",\"Sugar\",\"Eggs\",\"Sushi Rice\",\"Chives\"],\"allergens\":[\"egg\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\nHeat the oil in a pan, fry the sliced onion until golden brown, then add the tonkatsu (see recipe here), placing it in the middle of the pan. Mix the da\",\"instructions\":[\"STEP 1\",\"Heat the oil in a pan, fry the sliced onion until golden brown, then add the tonkatsu (see recipe here), placing it in the middle of the pan. Mix the dashi, soy, mirin and sugar together and tip three-quarters of the mixture around the tonkatsu. Sizzle for a couple of mins so the sauce thickens a little and the tonkatsu reheats.\",\"STEP 2\",\"Tip the beaten eggs around the tonkatsu and cook for 2-3 mins until the egg is cooked through but still a little runny. Divide the rice between two bowls, then top each with half the egg and tonkatsu mix, sprinkle over the chives and serve immediately, drizzling with a little more soy if you want an extra umami kick.\"]},{\"id\":\"g270\",\"title\":\"Jerk chicken with rice & peas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tytyxu1515363282.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Lime\",\"Spring Onions\",\"Ginger\",\"Garlic\",\"Onion\",\"Red Chilli\",\"Thyme\",\"Lime\",\"Soy Sauce\",\"Vegetable Oil\",\"Brown Sugar\",\"Allspice\",\"Basmati Rice\",\"Coconut Milk\",\"Spring Onions\",\"Thyme\",\"Garlic\",\"Allspice\",\"Kidney Beans\"],\"allergens\":[\"milk\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To make the jerk marinade, combine all the ingredients in a food processor along with 1 tsp salt, and blend to a purée. If you’re having trouble getting it to b\",\"instructions\":[\"To make the jerk marinade, combine all the ingredients in a food processor along with 1 tsp salt, and blend to a purée. If you’re having trouble getting it to blend, just keep turning off the blender, stirring the mixture, and trying again. Eventually it will start to blend up – don’t be tempted to add water, as you want a thick paste.\",\"Taste the jerk mixture for seasoning – it should taste pretty salty, but not unpleasantly, puckering salty. You can now throw in more chillies if it’s not spicy enough for you. If it tastes too salty and sour, try adding in a bit more brown sugar until the mixture tastes well balanced.\",\"Make a few slashes in the chicken thighs and pour the marinade over the meat, rubbing it into all the crevices. Cover and leave to marinate overnight in the fridge.\",\"If you want to barbecue your chicken, get the coals burning 1 hr or so before you’re ready to cook. Authentic jerked meats are not exactly grilled as we think of grilling, but sort of smoke-grilled. To get a more authentic jerk experience, add some wood chips to your barbecue, and cook your chicken over slow, indirect heat for 30 mins. To cook in the oven, heat to 180C/160C fan/gas 4. Put the chicken pieces in a roasting tin with the lime halves and cook for 45 mins until tender and cooked through.\",\"While the chicken is cooking, prepare the rice & peas. Rinse the rice in plenty of cold water, then tip it into a large saucepan with all the remaining ingredients except the kidney beans. Season with salt, add 300ml cold water and set over a high heat. Once the rice begins to boil, turn it down to a medium heat, cover and cook for 10 mins.\",\"Add the beans to the rice, then cover with a lid. Leave off the heat for 5 mins until all the liquid is absorbed. Squeeze the roasted lime over the chicken and serve with the rice & peas, and some hot sauce if you like it really spicy.\"]},{\"id\":\"g271\",\"title\":\"Jiggs Dinner\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/z1tfnw1764443171.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Yellow Split Peas\",\"Cabbage\",\"Carrots\",\"Turnips\",\"Potatoes\",\"Butter\",\"Black Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"The night before, break salt beef into big chunks and soak in water overnight, at least 8-10 hours. Put split peas into a bowl and cover with water to soak over\",\"instructions\":[\"The night before, break salt beef into big chunks and soak in water overnight, at least 8-10 hours. Put split peas into a bowl and cover with water to soak overnight.\",\"Drain the salt beef and place it into a large stockpot. Cover with fresh water, at least 6-7 litres. Place the split peas into a pease pudding canvas bag or triple layer of cheesecloth and tie, making sure to leave room for peas to expand inside the bag.\",\"Put the bag inside the pot, tying the strings to the outside handle so it doesn't stick to the bottom of the pot with the salt beef. Bring to a boil, then lower the heat and simmer for 2 hours.\",\"Remove the peas pudding bag and empty contents into a bowl, mixing with butter and pepper for taste. Set aside.\",\"Add your cabbage to the pot and boil for 20 more minutes. Then add turnip, carrots and potatoes then boil for 20 more, or until vegetables are tender.\",\"Remove salt beef and vegetables from the pot and put them on a platter.\",\"Use the cooking liquid in two ways; as a pot liquor which some people like to drink or reduce it to make a jus or gravy to pour over the meal.\"]},{\"id\":\"g272\",\"title\":\"kabse\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/utqnjv1763598650.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Rice\",\"Green Pepper\",\"Red Pepper\",\"Mushrooms\",\"Sweetcorn\",\"Carrots\",\"Raisins\",\"Turmeric\",\"Kabse Spice\",\"Salt\",\"Black Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nCaramelize the chicken with olive oil then add a maggi cube and boil it for around 30 minutes.\\r\\n2\\r\\nIn another pot, add all the veggies and caramelize them ti\",\"instructions\":[\"1\",\"Caramelize the chicken with olive oil then add a maggi cube and boil it for around 30 minutes.\",\"2\",\"In another pot, add all the veggies and caramelize them till they are soft.\",\"3\",\"Once everything is done, add the rice, raisins & spices to the veggies and add 2 and a half cups of water for the rice to cook.\",\"4\",\"Once the rice is done put everything in the oven.\"]},{\"id\":\"g273\",\"title\":\"Kafteji\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1bsv1q1560459826.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Olive Oil\",\"Green Pepper\",\"Onions\",\"Ras el hanout\",\"Pumpkin\",\"Eggs\",\"Salt\",\"Pepper\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Peel potatoes and cut into 5cm cubes.\\r\\nPour 1-2 cm of olive oil into a large pan and heat up very hot. Fry potatoes until golden brown for 20 minutes, turning f\",\"instructions\":[\"Peel potatoes and cut into 5cm cubes.\",\"Pour 1-2 cm of olive oil into a large pan and heat up very hot. Fry potatoes until golden brown for 20 minutes, turning from time to time. Place on kitchen paper to drain.\",\"Cut the peppers in half and remove seeds. Rub a little olive oil on them and place the cut side down on a baking tray. Place them under the grill. Grill until the skin is dark and bubbly. While the peppers are still hot, put them into a plastic sandwich bag and seal it. Take them out after 15 minutes and remove skins.\",\"In the meantime, heat more olive oil another pan. Peel the onions and cut into thin rings. Fry for 15 minutes until golden brown, turning them often. Add the Ras el hanout at the end.\",\"Cut the pumpkin into 5cm cubes and fry in the same pan you used for the potatoes for 10-15 minutes until it is soft and slightly browned. Place on kitchen paper.\",\"Pour the remaining olive oil out of the pan and put all the cooked vegetables into the pan and mix. Whisk eggs and pour them over the vegetables. Put the lid on the pan so that the eggs cook. Put the contents of the pan onto a large chopping board, add salt and pepper and chopped and mix everything with a big knife.\"]},{\"id\":\"g274\",\"title\":\"Kapsalon\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sxysrt1468240488.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Fries\",\"Doner Meat\",\"Garlic sauce\",\"Hotsauce\",\"Lettuce\",\"Tomato\",\"Cucumber\",\"Gouda cheese\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Cut the meat into strips. Heat oil in a pan and fry the strips for 6 minutes until it's ready.\\r\\nBake the fries until golden brown in a deep fryrer. When ready t\",\"instructions\":[\"Cut the meat into strips. Heat oil in a pan and fry the strips for 6 minutes until it's ready.\",\"Bake the fries until golden brown in a deep fryrer. When ready transfer to a backing dish. Make sure the fries are spread over the whole dish.\",\"Cover the fries with a new layer of meat and spread evenly.\",\"Add a layer of cheese over the meat. You can also use grated cheese. When done put in the oven for a few minutes until the cheese is melted.\",\"Chop the lettuce, tomato and cucumber in small pieces and mix together. for a basic salad. As extra you can add olives jalapenos and a red union.\",\"Dived the salad over the dish and Serve with garlicsauce and hot sauce\"]},{\"id\":\"g275\",\"title\":\"Karbonader (Lean Beef Patties) with Caramelized Onions\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0bpjb11763075817.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onion\",\"Butter\",\"Ground Beef\",\"Salt\",\"Pepper\",\"Nutmeg\",\"Cornstarch\",\"Water\",\"Butter\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Grate half an onion and set aside. Slice the rest of the onions and fry in butter on low/medium heat until caramelized.\\r\\n▢\\r\\nIn a bowl, mix together ground beef,\",\"instructions\":[\"Grate half an onion and set aside. Slice the rest of the onions and fry in butter on low/medium heat until caramelized.\",\"▢\",\"In a bowl, mix together ground beef, grated onion, salt, pepper, nutmeg, potato/corn starch, and water.\",\"▢\",\"Form into a sausage and cut 6 patties. Using a knife make a light grid pattern in each patty.\",\"▢\",\"Brown both sides of the karbonader in butter on high heat, then turn down to low heat and fry for another 2 – 3 minutes.\",\"▢\",\"Serve the karbonader and onions with potatoes, stewed peas, and brown sauce for dinner, or on a slice of bread for lunch or a snack.\"]},{\"id\":\"g276\",\"title\":\"Katsu Chicken curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vwrpps1503068729.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"chicken breast\",\"plain flour\",\"egg\",\"breadcrumbs\",\"vegetable oil\",\"sunflower oil\",\"onions\",\"garlic\",\"carrot\",\"plain flour\",\"curry powder\",\"chicken stock\",\"honey\",\"soy sauce\",\"bay leaf\",\"garam masala\"],\"allergens\":[\"egg\",\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Prep:15min  ›  Cook:30min  ›  Ready in:45min \\r\\n\\r\\nFor the curry sauce: Heat oil in medium non-stick saucepan, add onion and garlic and cook until softened. Stir \",\"instructions\":[\"Prep:15min  ›  Cook:30min  ›  Ready in:45min\",\"For the curry sauce: Heat oil in medium non-stick saucepan, add onion and garlic and cook until softened. Stir in carrots and cook over low heat for 10 to 12 minutes.\",\"Add flour and curry powder; cook for 1 minute. Gradually stir in stock until combined; add honey, soy sauce and bay leaf. Slowly bring to the boil.\",\"Turn down heat and simmer for 20 minutes or until sauce thickens but is still of pouring consistency. Stir in garam masala. Pour the curry sauce through a sieve; return to saucepan and keep on low heat until ready to serve.\",\"For the chicken: Season both sides of chicken breasts with salt and pepper. Place flour, egg and breadcrumbs in separate bowls and arrange in a row. Coat the chicken breasts in flour, then dip them into the egg, then coat in breadcrumbs, making sure you cover both sides.\",\"Heat oil in large frying pan over medium-high heat. Place chicken into hot oil and cook until golden brown, about 3 or 4 minutes each side. Once cooked, place on kitchen paper to absorb excess oil.\",\"Pour curry sauce over chicken, serve with white rice and enjoy!\"]},{\"id\":\"g277\",\"title\":\"Kedgeree\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/utxqpt1511639216.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Smoked Haddock\",\"Bay Leaves\",\"Milk\",\"Eggs\",\"Parsley\",\"Coriander\",\"Vegetable Oil\",\"Onion\",\"Coriander\",\"Curry Powder\",\"Rice\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the rice, heat the oil in a large, lidded pan, add the onion, then gently fry for 5 mins until softened but not coloured. Add the spices, season with salt, \",\"instructions\":[\"For the rice, heat the oil in a large, lidded pan, add the onion, then gently fry for 5 mins until softened but not coloured. Add the spices, season with salt, then continue to fry until the mix start to go brown and fragrant; about 3 mins.\",\"Add the rice and stir in well. Add 600ml water, stir, then bring to the boil. Reduce to a simmer, then cover for 10 mins. Take off the heat and leave to stand, covered, for 10-15 mins more. The rice will be perfectly cooked if you do not lift the lid before the end of the cooking.\",\"Meanwhile, put the haddock and bay leaves in a frying pan, cover with the milk, then poach for 10 mins until the flesh flakes. Remove from the milk, peel away the skin, then flake the flesh into thumbsize pieces. Place the eggs in a pan, cover with water, bring to the boil, then reduce to a simmer. Leave for 4½-5 mins, plunge into cold water, then peel and cut the eggs into quarters. Gently mix the fish, eggs, parsley, coriander and rice together in the pan. Serve hot, sprinkled with a few extra herbs.\"]},{\"id\":\"g278\",\"title\":\"Keleya Zaara\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8x09hy1560460923.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Lamb\",\"Saffron\",\"Onion\",\"Water\",\"Parsley\",\"Butter\",\"Lemon\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the vegetable oil in a large frying pan over medium-high heat. Add the lamb and cook until browned on all sides, about 5 minutes. Season with saffron, salt\",\"instructions\":[\"Heat the vegetable oil in a large frying pan over medium-high heat. Add the lamb and cook until browned on all sides, about 5 minutes. Season with saffron, salt and pepper to taste; stir in all but 4 tablespoons of the onion, and pour in the water. Bring to the boil, then cover, reduce heat to medium-low, and simmer until the lamb is tender, about 15 minutes.\",\"Uncover the pan, stir in the butter and allow the sauce reduce 5 to 10 minutes to desired consistency. Season to taste with salt and pepper, then pour into a serving dish. Sprinkle with the remaining chopped onions and parsley. Garnish with lemon wedges to serve.\"]},{\"id\":\"g279\",\"title\":\"Kentucky Fried Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/40r49m1763197022.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Oil\",\"Egg White\",\"Flour\",\"Brown Sugar\",\"Salt\",\"paprika\",\"onion salt\",\"chili powder\",\"black pepper\",\"celery salt\",\"sage\",\"garlic powder\",\"allspice\",\"oregano\",\"basil\",\"marjoram\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat fryer to 350°F. Thoroughly mix together all the spice mix ingredients.\\r\\nCombine spice mix with flour, brown sugar and salt.\\r\\nDip chicken pieces in egg w\",\"instructions\":[\"Preheat fryer to 350°F. Thoroughly mix together all the spice mix ingredients.\",\"Combine spice mix with flour, brown sugar and salt.\",\"Dip chicken pieces in egg white to lightly coat them, then transfer to flour mixture. Turn a few times and make sure the flour mix is really stuck to the chicken. Repeat with all the chicken pieces.\",\"Let chicken pieces rest for 5 minutes so crust has a chance to dry a bit.\",\"Fry chicken in batches. Breasts and wings should take 12-14 minutes, and legs and thighs will need a few more minutes. Chicken pieces are done when a meat thermometer inserted into the thickest part reads 165°F.\",\"Let chicken drain on a few paper towels when it comes out of the fryer. Serve hot.\"]},{\"id\":\"g280\",\"title\":\"Kenyan Beef Curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lqampv1762325397.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Sirloin Steak tips\",\"Garlic Clove\",\"Ground Ginger\",\"Oil\",\"Red Onions\",\"Tomato\",\"Paprika\",\"Black Pepper\",\"Curry Powder\",\"Tomato Puree\",\"Salt\",\"Chilli\",\"Cilantro\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Bring the 4 cups of water to a boil in a Dutch oven or soup pot. Add the beef, garlic, and ginger, and stir well. Bring to a gentle simmer, cover, and cook, sti\",\"instructions\":[\"Bring the 4 cups of water to a boil in a Dutch oven or soup pot. Add the beef, garlic, and ginger, and stir well. Bring to a gentle simmer, cover, and cook, stirring occasionally, for 20 minutes. If you get any foamy scum on the top, not to worry, simply spoon it away or stir it back in.\",\"Remove from the heat, and drain, but reserve the excess water for later.\",\"Return the pot or Dutch oven to medium heat with the 2 tablespoons of cooking oil. Once the oil is shimmering, add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.\",\"Add the tomatoes to the onions, and continue cooking, stirring occasionally, until the tomatoes are falling apart, 3 to 5 minutes.\",\"Add the drained beef to the tomato and onion mixture, and stir well. Continue cooking over medium heat for 5 minutes, stirring occasionally.\",\"Add the paprika, pepper, curry powder, tomato paste, and salt to taste, and stir well.\",\"Add back the excess water that was used for cooking the beef, along with enough extra water to cover. Bring to a boil, reduce heat, and simmer, uncovered, stirring occasionally, for about 1 hour, or until the meat is tender and the sauce is thickened. Add additional water if your beef curry begins to dry and stick, or if would like your curry to have more of a soupy consistency.\",\"When the beef curry is ready, remove from the heat, give it a taste, and adjust the seasonings as desired. Garnish with fresh chilis and cilantro.\"]},{\"id\":\"g281\",\"title\":\"Key Lime Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qpqtuu1511386216.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Digestive Biscuits\",\"Butter\",\"Condensed Milk\",\"Egg Yolks\",\"Lime\",\"Double Cream\",\"Icing Sugar\",\"Lime\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oven to 160C/fan 140C/gas 3. Whizz the biscuits to crumbs in a food processor (or put in a strong plastic bag and bash with a rolling pin). Mix with th\",\"instructions\":[\"Heat the oven to 160C/fan 140C/gas 3. Whizz the biscuits to crumbs in a food processor (or put in a strong plastic bag and bash with a rolling pin). Mix with the melted butter and press into the base and up the sides of a 22cm loose-based tart tin. Bake in the oven for 10 minutes. Remove and cool.\",\"Put the egg yolks in a large bowl and whisk for a minute with electric beaters. Add the condensed milk and whisk for 3 minutes then add the zest and juice and whisk again for 3 minutes. Pour the filling into the cooled base then put back in the oven for 15 minutes. Cool then chill for at least 3 hours or overnight if you like.\",\"When you are ready to serve, carefully remove the pie from the tin and put on a serving plate. To decorate, softly whip together the cream and icing sugar. Dollop or pipe the cream onto the top of the pie and finish with extra lime zest.\"]},{\"id\":\"g282\",\"title\":\"Khobz el Dar (Algerian Semolina Bread)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/5u37fy1764116774.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Semolina Flour\",\"Semolina Flour\",\"Sesame Seed\",\"Sugar\",\"Yeast\",\"Salt\",\"Vegetable Oil\",\"Egg\",\"Egg\",\"Milk\",\"All purpose flour\",\"All purpose flour\",\"Water\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix 1/2 cup plus 2 tablespoons semolina, 2 tablespoons sesame seeds, sugar, yeast, and salt together in a large bowl. Whisk in oil, egg, and egg white. Stir in \",\"instructions\":[\"Mix 1/2 cup plus 2 tablespoons semolina, 2 tablespoons sesame seeds, sugar, yeast, and salt together in a large bowl. Whisk in oil, egg, and egg white. Stir in warm milk slowly until a liquid dough forms.\",\"Cover the bowl with a plate or plastic wrap; let stand at room temperature until frothy, about 1 hour.\",\"Stir in 2 3/4 cups flour with a wooden spoon until a sticky dough forms. Cover again and allow to rest for 30 minutes.\",\"Line a baking sheet with parchment paper or a baking mat.\",\"Sprinkle 1 tablespoon flour over the dough and your hands. Mix dough, adding flour as needed, 1 tablespoon at a time, until it pulls away from the sides of the bowl. Shape into a round loaf and place on the prepared baking sheet. Cover loosely with a towel and let rise for 1 hour in a warm place until loaf doubles in volume.\",\"Preheat oven to 400 degrees F (200 degrees C).\",\"Beat egg yolk and water in a bowl with a fork; brush over the entire surface of the loaf. Sprinkle 1 tablespoon sesame seeds on top.\",\"Bake in the preheated oven until loaf is golden brown, about 20 to 25 minutes.\"]},{\"id\":\"g283\",\"title\":\"Kidney Bean Curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sywrsu1511463066.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Onion\",\"Garlic\",\"Ginger\",\"Coriander\",\"Cumin\",\"Paprika\",\"Garam Masala\",\"Chopped Tomatoes\",\"Kidney Beans\",\"Basmati Rice\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the oil in a large frying pan over a low-medium heat. Add the onion and a pinch of salt and cook slowly, stirring occasionally, until softened and just sta\",\"instructions\":[\"Heat the oil in a large frying pan over a low-medium heat. Add the onion and a pinch of salt and cook slowly, stirring occasionally, until softened and just starting to colour. Add the garlic, ginger and coriander stalks and cook for a further 2 mins, until fragrant.\",\"Add the spices to the pan and cook for another 1 min, by which point everything should smell aromatic. Tip in the chopped tomatoes and kidney beans in their water, then bring to the boil.\",\"Turn down the heat and simmer for 15 mins until the curry is nice and thick. Season to taste, then serve with the basmati rice and the coriander leaves.\"]},{\"id\":\"g284\",\"title\":\"Knafeh\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/76nffj1763593933.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Knafeh\",\"Unsalted Butter\",\"Yellow Food Colouring\",\"Mozzarella\",\"Cream Cheese\",\"Milk\",\"Sugar\",\"Corn Flour\",\"Sugar\",\"Water\",\"Rose water\",\"Lemon Juice\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1\\r\\nTake kanfhe in a bowl and roughly cut them. Pour melted butter, yellow food color and mix well with your hands.\\r\\nIn a separate bowl mix milk, cream cheese, s\",\"instructions\":[\"1\",\"Take kanfhe in a bowl and roughly cut them. Pour melted butter, yellow food color and mix well with your hands.\",\"In a separate bowl mix milk, cream cheese, sugar, cornstarch well.\",\"2\",\"Turn on the flame and boil the liquid, when it gets thick turn off the flame let it cool down a little bit.\",\"Add mozzarella in it and mix it well.\",\"Now make a base with half of the kanfhe in a dish, gently press it to level the dough well.\",\"Pour the cheese mixture on the top and level it with a spoon.\",\"3\",\"Cover it with the other half of the kanfhe.\"]},{\"id\":\"g285\",\"title\":\"kofta burgers\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lgmnff1763789847.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb\",\"Onion\",\"Garlic Bulb\",\"Garam Masala\",\"Coriander\",\"Chilli Sauce\",\"Pita Bread\",\"Tomato\",\"Red Cabbage\",\"Red Onions\",\"Yogurt\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip the mince into a large bowl (use a clean washing-up bowl if you don’t have anything big enough) with all the other burger ingredients and a good pin\",\"instructions\":[\"step 1\",\"Tip the mince into a large bowl (use a clean washing-up bowl if you don’t have anything big enough) with all the other burger ingredients and a good pinch of salt. Roll up your sleeves, get your hands into the mix and squelch everything together through your fingers until completely mixed. Pat the mix into 16 small burgers. These may now be frozen for up to 1 month or chilled up to a day ahead.\",\"step 2\",\"To cook, heat grill to its highest setting and lay the burgers in a single layer on a baking tray (you may need to do this in batches, depending on how big your tray is). Grill on the highest shelf for 5-6 mins on each side until browned and cooked through. Pile burgers onto a platter and serve with all the accompaniments, so everyone can construct their own sandwich.\"]},{\"id\":\"g286\",\"title\":\"Koshari\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4er7mj1598733193.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Brown Lentils\",\"Rice\",\"Coriander\",\"Macaroni\",\"Chickpeas\",\"Onion\",\"Salt\",\"Vegetable Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cook the lentils. Bring lentils and 4 cups of water to a boil in a medium pot or saucepan over high heat. Reduce the heat to low and cook until lentils are just\",\"instructions\":[\"Cook the lentils. Bring lentils and 4 cups of water to a boil in a medium pot or saucepan over high heat. Reduce the heat to low and cook until lentils are just tender (15-17 minutes). Drain from water and season with a little salt. (Note: when the lentils are ready, they should not be fully cooked. They should be only par-cooked and still have a bite to them as they need to finish cooking with the rice).\",\"Now, for the rice. Drain the rice from its soaking water. Combine the par-cooked lentils and the rice in the saucepan over medium-high heat with 1 tbsp cooking oil, salt, pepper, and coriander. Cook for 3 minutes, stirring regularly. Add warm water to cover the rice and lentil mixture by about 1 1/2 inches (you’ll probably use about 3 cups of water here). Bring to a boil; the water should reduce a bit. Now cover and cook until all the liquid has been absorbed and both the rice and lentils are well cooked through (about 20 minutes).  Keep covered and undisturbed for 5 minutes or so.\",\"Now make the pasta. While the rice and lentils are cooking, make the pasta according to package instructions by adding the elbow pasta to boiling water with a dash of salt and a little oil. Cook until the pasta is al dente. Drain.\",\"Cover the chickpeas and warm in the microwave briefly before serving.\",\"Make the crispy onion topping.\",\"Sprinkle the onion rings with salt, then toss them in the flour to coat. Shake off excess flour.\",\"In a large skillet, heat the cooking oil over medium-high heat, cook the onion rings, stirring often, until they turn a nice caramelized brown. Onions must be crispy, but not burned (15-20 minutes).\"]},{\"id\":\"g287\",\"title\":\"Krispy Kreme Donut\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4i5cnx1587672171.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Yeast\",\"Water\",\"Water\",\"Sugar\",\"Salt\",\"Eggs\",\"Shortening\",\"Flour\",\"Canola Oil\",\"Milk\",\"Sugar\",\"Vanilla\",\"Boiling Water\",\"Butter\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Dissolve yeast in warm water in 2 1/2-quart bowl. Add milk, sugar, salt, eggs, shortening and 2 cups flour. Beat on low for 30 seconds, scraping bowl constantly\",\"instructions\":[\"Dissolve yeast in warm water in 2 1/2-quart bowl. Add milk, sugar, salt, eggs, shortening and 2 cups flour. Beat on low for 30 seconds, scraping bowl constantly. Beat on medium speed for 2 minutes, scraping bowl occasionally. Stir in remaining flour until smooth. Cover and let rise until double, 50-60 minutes. (Dough is ready when indentation remains when touched.) Turn dough onto floured surface; roll around lightly to coat with flour. Gently roll dough 1/2-inch thick with floured rolling pin. Cut with floured doughnut cutter. Cover and let rise until double, 30-40 minutes.\",\"Heat vegetable oil in deep fryer to 350°. Slide doughnuts into hot oil with wide spatula. Turn doughnuts as they rise to the surface. Fry until golden brown, about 1 minute on each side. Remove carefully from oil (do not prick surface); drain. Dip the doughnuts into creamy glaze set on rack.\",\"Glaze:\",\"Heat butter until melted. Remove from heat. Stir in powdered sugar and vanilla until smooth. Stir in water, 1 tablespoon at a time, until desired consistency.\"]},{\"id\":\"g288\",\"title\":\"Kumpir\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/mlchx21564916997.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Butter\",\"Cheese\",\"Onion\",\"Red Pepper\",\"Red Chilli Flakes\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"If you order kumpir in Turkey, the standard filling is first, lots of butter mashed into the potato, followed by cheese. There’s then a row of other toppings th\",\"instructions\":[\"If you order kumpir in Turkey, the standard filling is first, lots of butter mashed into the potato, followed by cheese. There’s then a row of other toppings that you can just point at to your heart’s content – sweetcorn, olives, salami, coleslaw, Russian salad, allsorts – and you walk away with an over-stuffed potato because you got ever-excited by the choices on offer.\",\"Grate (roughly – you can use as much as you like) 150g of cheese.\",\"Finely chop one onion and one sweet red pepper.\",\"Put these ingredients into a large bowl with a good sprinkling of salt and pepper, chilli flakes (optional).\"]},{\"id\":\"g289\",\"title\":\"Kung Pao Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1525872624.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sake\",\"Soy Sauce\",\"Sesame Seed Oil\",\"Corn Flour\",\"Water\",\"Chicken\",\"Chilli Powder\",\"Rice Vinegar\",\"Brown Sugar\",\"Spring Onions\",\"Garlic Clove\",\"Water Chestnut\",\"Peanuts\"],\"allergens\":[\"soy\",\"peanut\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Combine the sake or rice wine, soy sauce, sesame oil and cornflour dissolved in water. Divide mixture in half.\\r\\nIn a glass dish or bowl, combine half of the sak\",\"instructions\":[\"Combine the sake or rice wine, soy sauce, sesame oil and cornflour dissolved in water. Divide mixture in half.\",\"In a glass dish or bowl, combine half of the sake mixture with the chicken pieces and toss to coat. Cover dish and place in refrigerator for about 30 minutes.\",\"In a medium frying pan, combine remaining sake mixture, chillies, vinegar and sugar. Mix together and add spring onion, garlic, water chestnuts and peanuts. Heat sauce slowly over medium heat until aromatic.\",\"Meanwhile, remove chicken from marinade and sauté in a large frying pan until juices run clear. When sauce is aromatic, add sautéed chicken and let simmer together until sauce thickens.\"]},{\"id\":\"g290\",\"title\":\"Kung Po Prawns\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1525873040.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Prawns\",\"Soy Sauce\",\"Tomato Puree\",\"Corn Flour\",\"Caster Sugar\",\"Sunflower Oil\",\"Peanuts\",\"Chilli\",\"Brown Sugar\",\"Garlic Clove\",\"Water Chestnut\",\"Ginger\"],\"allergens\":[\"soy\",\"peanut\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Mix the cornflour and 1 tbsp soy sauce, toss in the prawns and set aside for 10 mins. Stir the vinegar, remaining soy sauce, tomato purée, sugar and 2 tbsp wate\",\"instructions\":[\"Mix the cornflour and 1 tbsp soy sauce, toss in the prawns and set aside for 10 mins. Stir the vinegar, remaining soy sauce, tomato purée, sugar and 2 tbsp water together to make a sauce.\",\"When you’re ready to cook, heat a large frying pan or wok until very hot, then add 1 tbsp oil. Fry the prawns until they are golden in places and have opened out– then tip them out of the pan.\",\"Heat the remaining oil and add the peanuts, chillies and water chestnuts. Stir-fry for 2 mins or until the peanuts start to colour, then add the ginger and garlic and fry for 1 more min. Tip in the prawns and sauce and simmer for 2 mins until thickened slightly. Serve with rice.\"]},{\"id\":\"g291\",\"title\":\"Kvæfjord Cake “Verdens Beste” (World’s Best Cake)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/gdn1ot1763075684.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg Yolks\",\"Cornstarch\",\"Granulated Sugar\",\"Heavy Cream\",\"Milk\",\"vanilla pod\",\"Butter\",\"Granulated Sugar\",\"Egg Yolks\",\"Flour\",\"Baking Powder\",\"Milk\",\"Egg White\",\"Granulated Sugar\",\"Almonds\",\"Whipping Cream\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Vanilla custard\\r\\n▢\\r\\nSeparate the egg yolks and set aside the whites to use in the meringue.\\r\\n▢\\r\\nWhisk together the egg yolks, cornstarch and sugar in a bowl.\\r\\n▢\",\"instructions\":[\"Vanilla custard\",\"▢\",\"Separate the egg yolks and set aside the whites to use in the meringue.\",\"▢\",\"Whisk together the egg yolks, cornstarch and sugar in a bowl.\",\"▢\",\"Heat the cream and milk in a saucepan. Split open the vanilla pod and add the beans to the saucepan. Once the milk begins to bubble pour about half of it into the bowl with the egg mixture, whisking constantly. Then return the saucepan to the heat and pour the egg mixture back into the saucepan with remaining milk, whisking constantly. Once the mixture thickens lower the heat and continue whisking for about 30 seconds.\",\"▢\",\"Pour the custard into a clean bowl and cover with plastic wrap, placing the plastic directly on the top layer of the custard. Chill in the fridge.\",\"Cake\"]},{\"id\":\"g292\",\"title\":\"Laksa King Prawn Noodles\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rvypwy1503069308.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Red Chilli\",\"Thai red curry paste\",\"vegetable stock cube\",\"coconut milk\",\"fish sauce\",\"rice noodles\",\"lime\",\"king prawns\",\"coriander\"],\"allergens\":[\"milk\",\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oil in a medium saucepan and add the chilli. Cook for 1 min, then add the curry paste, stir and cook for 1 min more. Dissolve the stock cube in a large\",\"instructions\":[\"Heat the oil in a medium saucepan and add the chilli. Cook for 1 min, then add the curry paste, stir and cook for 1 min more. Dissolve the stock cube in a large jug in 700ml boiling water, then pour into the pan and stir to combine. Tip in the coconut milk and bring to the boil.\",\"Add the fish sauce and a little seasoning. Toss in the noodles and cook for a further 3-4 mins until softening. Squeeze in the lime juice, add the prawns and cook through until warm, about 2-3 mins. Scatter over some of the coriander.\",\"Serve in bowls with the remaining coriander and lime wedges on top for squeezing over.\"]},{\"id\":\"g293\",\"title\":\"Lamb & apricot meatballs\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/72fgzj1764109947.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Red Onions\",\"Garlic\",\"Ground Cumin\",\"Ground Coriander\",\"Tinned Tomatos\",\"Sugar\",\"Mint\",\"Lamb Mince\",\"Dried Apricots\",\"Breadcrumbs\",\"Pita Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat 2 tsp oil in a pan and soften the onions for 5 mins. Add the garlic and spices and cook for a few mins more. Spoon half the onion mixture into a bo\",\"instructions\":[\"step 1\",\"Heat 2 tsp oil in a pan and soften the onions for 5 mins. Add the garlic and spices and cook for a few mins more. Spoon half the onion mixture into a bowl and set aside to cool. Add the tomatoes, sugar and seasoning to the remaining onions in the pan and simmer for about 10 mins until reduced.\",\"step 2\",\"Meanwhile, add the mint, lamb, apricots and breadcrumbs to the cooled onions, season and mix well with your hands. Shape into little meatballs.\",\"step 3\",\"Heat the rest of the oil in a non-stick pan and fry the meatballs until golden (in batches if you need to). Stir in the sauce with a splash of water and gently cook everything for a few mins until the meatballs are cooked through. Serve with pitta bread and salad.\"]},{\"id\":\"g294\",\"title\":\"Lamb and Lemon Souvlaki\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rjhf741585564676.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Garlic\",\"Sea Salt\",\"Olive Oil\",\"Lemon\",\"Dill\",\"Lamb Leg\",\"Pita Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Pound the garlic with sea salt in a pestle and mortar (or use a small food processor), until the garlic forms a paste. Whisk together the oil, lemon juice, zest\",\"instructions\":[\"Pound the garlic with sea salt in a pestle and mortar (or use a small food processor), until the garlic forms a paste. Whisk together the oil, lemon juice, zest, dill and garlic. Mix in the lamb and combine well. Cover and marinate for at least 2 hrs or overnight in the fridge. If you’re going to use bamboo skewers, soak them in cold water.\",\"If you’ve prepared the lamb the previous day, take it out of the fridge 30 mins before cooking. Thread the meat onto the soaked or metal skewers. Heat the grill to high or have a hot griddle pan or barbecue ready. Cook the skewers for 2-3 mins on each side, basting with the remaining marinade. Heat the pitta or flatbreads briefly, then stuff with the souvlaki. Add Greek salad (see 'Goes well with', right) and Tzatziki (below), if you like.\"]},{\"id\":\"g295\",\"title\":\"Lamb and Potato pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sxrpws1511555907.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb Shoulder\",\"Flour\",\"Vegetable Oil\",\"Onion\",\"Carrots\",\"Vegetable Stock\",\"Potatoes\",\"Shortcrust Pastry\",\"Eggs\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Dust the meat with flour to lightly coat.\\r\\nHeat enough vegetable oil in a large saucepan to fill the base, and fry the onion and meat until lightly browned. Sea\",\"instructions\":[\"Dust the meat with flour to lightly coat.\",\"Heat enough vegetable oil in a large saucepan to fill the base, and fry the onion and meat until lightly browned. Season with salt and pepper.\",\"Add the carrots, stock and more seasoning to taste.\",\"Bring to the boil, cover and reduce the heat to a simmer. Simmer for at least an hour or until the meat is tender. Take your time cooking the meat, the longer you leave it to cook, the better the flavour will be.\",\"Preheat the oven to 180C/350F/Gas 4.\",\"Add the drained potato cubes to the lamb.\",\"Turn the mixture into a pie dish or casserole and cover with the shortcrust pastry. Make three slits in the top of the pastry to release any steam while cooking.\",\"Brush with beaten egg and bake for about 40 minutes, until the pastry is golden brown.\",\"Serve.\"]},{\"id\":\"g296\",\"title\":\"Lamb Biryani\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xrttsx1487339558.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cashew nuts\",\"Khus khus\",\"Cumin seeds\",\"Onions\",\"Ginger garlic paste\",\"Garlic\",\"Mint\",\"Cilantro\",\"Saffron\",\"Ghee\",\"Basmati rice\",\"Full fat yogurt\",\"Cumin Seeds\",\"Bay leaf\",\"Cinnamon\",\"Cloves\",\"Cardamom\",\"Lamb\",\"Red Chilli powder\",\"Biryani masala\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Grind the cashew, poppy seeds and cumin seeds into a smooth paste, using as little water as possible. Set aside. \\r\\n\\r\\nDeep fry the sliced onions when it is hot. \",\"instructions\":[\"Grind the cashew, poppy seeds and cumin seeds into a smooth paste, using as little water as possible. Set aside.\",\"Deep fry the sliced onions when it is hot. Don’t overcrowd the oil. When the onions turn light brown, remove from oil and drain on paper towel. The fried onion will crisp up as it drains. Also fry the cashewnuts till golden brown. Set aside.\",\"Wash the rice and soak in water for twenty minutes.\",\"Meanwhile, take a big wide pan, add oil in medium heat, add the sliced onions, add the blended paste, to it add the green chillies, ginger garlic paste and garlic and fry for a minute.\",\"Then add the tomatoes and sauté them well till they are cooked and not mushy.\",\"Then to it add the red chilli powder, biryani powder, mint, coriander leaves and sauté them well.\",\"Add the yogurt and mix well. I always move the skillet away from the heat when adding yogurt which prevents it from curdling.\",\"Now after returning the skillet back to the stove, add the washed lamb and salt and ½ cup water and mix well. Cook for 1 hour and cook it covered in medium low heat or put it in a pressure cooker for 6 whistles. If the water is not drained totally, heat it by keeping it open.\",\"Take another big pan, add thrice the cup of rice you use, and boil it. When it is boiling high, add the rice, salt and jeera and mix well. After 7 minutes exact or when the rice is 80% done. Switch off and drain the rice.\",\"Now, the layering starts. To the lamb, pat and level it. Add the drained hot rice on the top of it. Garnish with fried onions, ghee, mint, coriander leaves and saffron dissolved in milk.\"]},{\"id\":\"g297\",\"title\":\"Lamb Pilaf (Plov)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kos9av1699014767.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb\",\"Prunes\",\"Lemon Juice\",\"Butter\",\"Onion\",\"Lamb\",\"Garlic\",\"Vegetable Stock\",\"Rice\",\"Saffron\",\"Parsley\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Place the raisins and prunes into a small bowl and pour over enough water to cover. Add lemon juice and let soak for at least 1 hour. Drain. Roughly chop the pr\",\"instructions\":[\"Place the raisins and prunes into a small bowl and pour over enough water to cover. Add lemon juice and let soak for at least 1 hour. Drain. Roughly chop the prunes.\",\"Meanwhile, heat the butter in a large pan, add the onion, and cook for 5 minutes. Add cubed lamb, ground lamb, and crushed garlic cloves. Fry for 5 minutes, stirring constantly until browned.\",\"Pour 2/3 cup (150 milliliters) of stock into the pan. Bring to a boil, then lower the heat, cover, and simmer for 1 hour, or until the lamb is tender.\",\"Add the remaining stock and bring to a boil. Add rinsed long-grain white rice and a large pinch of saffron. Stir, then cover, and simmer for 15 minutes, or until the rice is tender.\",\"Add the drained raisins, drained chopped prunes, and salt and pepper to taste. Heat through for a few minutes, then turn out onto a warmed serving dish and garnish with sprigs of flat-leaf parsley.\"]},{\"id\":\"g298\",\"title\":\"Lamb Rogan josh\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vvstvq1487342592.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onion\",\"Sunflower Oil\",\"Garlic\",\"Ginger\",\"Madras Paste\",\"Paprika\",\"cinnamon stick\",\"Cardamom\",\"Cloves\",\"Bay Leaf\",\"Tomato Purée\",\"Lamb\",\"Greek yogurt\",\"Coriander\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Put the onions in a food processor and whizz until very finely chopped. Heat the oil in a large heavy-based pan, then fry the onion with the lid on, stirring ev\",\"instructions\":[\"Put the onions in a food processor and whizz until very finely chopped. Heat the oil in a large heavy-based pan, then fry the onion with the lid on, stirring every now and then, until it is really golden and soft. Add the garlic and ginger, then fry for 5 mins more.\",\"Tip the curry paste, all the spices and the bay leaves into the pan, with the tomato purée. Stir well over the heat for about 30 secs, then add the meat and 300ml water. Stir to mix, turn down the heat, then add the yogurt.\",\"Cover the pan, then gently simmer for 40-60 mins until the meat is tender and the sauce nice and thick. Serve scattered with coriander, with plain basmati or pilau rice.\"]},{\"id\":\"g299\",\"title\":\"Lamb Tagine\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yuwtuu1511295751.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Carrots\",\"Lamb Leg\",\"Garlic\",\"Cumin\",\"Ginger\",\"Saffron\",\"Cinnamon\",\"Honey\",\"Apricot\",\"Vegetable Stock Cube\",\"Butternut Squash\",\"Couscous\",\"Parsley\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the olive oil in a heavy-based pan and add the onion and carrot. Cook for 3- 4 mins until softened.\\r\\n\\r\\nAdd the diced lamb and brown all over. Stir in the g\",\"instructions\":[\"Heat the olive oil in a heavy-based pan and add the onion and carrot. Cook for 3- 4 mins until softened.\",\"Add the diced lamb and brown all over. Stir in the garlic and all the spices and cook for a few mins more or until the aromas are released.\",\"Add the honey and apricots, crumble in the stock cube and pour over roughly 500ml boiling water or enough to cover the meat. Give it a good stir and bring to the boil. Turn down to a simmer, put the lid on and cook for 1 hour.\",\"Remove the lid and cook for a further 30 mins, then stir in the squash. Cook for 20 – 30 mins more until the squash is soft and the lamb is tender. Serve alongside rice or couscous and sprinkle with parsley and pine nuts, if using.\"]},{\"id\":\"g300\",\"title\":\"Lamb tomato and sweet spices\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qtwtss1468572261.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"olive oil\",\"ginger\",\"garlic\",\"tomatoes\",\"lemon juice\",\"caster sugar\",\"vine leaves\",\"fennel bulb\",\"lamb mince\",\"onion\",\"potatoes\",\"basmati rice\",\"chopped parsley\",\"coriander\",\"lemon juice\",\"garlic\",\"clove\",\"cinnamon\",\"tomatoes\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Use pickled vine leaves here, preserved in brine. Small delicate leaves are better than the large bristly ones but, if only large leaves are to hand, then trim \",\"instructions\":[\"Use pickled vine leaves here, preserved in brine. Small delicate leaves are better than the large bristly ones but, if only large leaves are to hand, then trim them to roughly 12 by 12 cms so that you don't get too many layers of leaves around the filling. And remove any stalks. Drain the preserved leaves, immerse them in boiling water for 10 minutes and then leave to dry on a tea towel before use.\",\"Basmati rice with butter and pine nuts is an ideal accompaniment. Couscous is great, too. Serves four.\",\"First make the filling. Put all the ingredients, apart from the tomatoes, in a bowl. Cut the tomatoes in half, coarsely grate into the bowl and discard the skins. Add half a teaspoon of salt and some black pepper, and stir. Leave on the side, or in the fridge, for up to a day. Before using, gently squeeze with your hands and drain away any juices that come out.\",\"To make the sauce, heat the oil in a medium pan. Add the ginger and garlic, cook for a minute or two, taking care not to burn them, then add the tomato, lemon juice and sugar. Season, and simmer for 20 minutes.\",\"While the sauce is bubbling away, prepare the vine leaves. Use any torn or broken leaves to line the base of a wide, heavy saucepan. Trim any leaves from the fennel, cut it vertically into 0.5cm-thick slices and spread over the base of the pan to cover completely.\",\"Lay a prepared vine leaf (see intro) on a work surface, veiny side up. Put two teaspoons of filling at the base of the leaf in a 2cm-long by 1cm-wide strip. Fold the sides of the leaf over the filling, then roll it tightly from bottom to top, in a cigar shape. Place in the pan, seam down, and repeat with the remaining leaves, placing them tightly next to each other in lines or circles (in two layers if necessary).\",\"Pour the sauce over the leaves (and, if needed, add water just to cover). Place a plate on top, to weigh the leaves down, then cover with a lid. Bring to a boil, reduce the heat and cook on a bare simmer for 70 minutes. Most of the liquid should evaporate. Remove from the heat, and leave to cool a little - they are best served warm. When serving, bring to the table in the pan - it looks great. Serve a few vine leaves and fennel slices with warm rice. Spoon the braising juices on top and garnish with coriander.\"]},{\"id\":\"g301\",\"title\":\"Lamb Tzatziki Burgers\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/k420tj1585565244.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Bulgur Wheat\",\"Lamb Mince\",\"Cumin\",\"Coriander\",\"Paprika\",\"Garlic\",\"Olive Oil\",\"Bun\",\"Cucumber\",\"Greek Yogurt\",\"Mint\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Tip the bulghar into a pan, cover with water and boil for 10 mins. Drain really well in a sieve, pressing out any excess water.\\r\\n\\r\\nTo make the tzatziki, squeeze\",\"instructions\":[\"Tip the bulghar into a pan, cover with water and boil for 10 mins. Drain really well in a sieve, pressing out any excess water.\",\"To make the tzatziki, squeeze and discard the juice from the cucumber, then mix into the yogurt with the chopped mint and a little salt.\",\"Work the bulghar into the lamb with the spices, garlic (if using) and seasoning, then shape into 4 burgers. Brush with a little oil and fry or barbecue for about 5 mins each side until cooked all the way through. Serve in the buns (toasted if you like) with the tzatziki, tomatoes, onion and a few mint leaves.\"]},{\"id\":\"g302\",\"title\":\"Lamingtons\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/j2n7vg1761848636.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Salted Butter\",\"Golden Caster Sugar\",\"Egg\",\"Self-raising Flour\",\"Milk\",\"Salt\",\"Double Cream\",\"Icing Sugar\",\"Raspberry Jam\",\"Desiccated Coconut\",\"Unsalted Butter\",\"Milk\",\"Cocoa Powder\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oven to 200C/180C fan/gas 6. Butter and line a 20 x 30cm rectangle tin.\\r\\n\\r\\nstep 2\\r\\nBeat the butter and sugar in a free-standing mixer until pal\",\"instructions\":[\"step 1\",\"Heat the oven to 200C/180C fan/gas 6. Butter and line a 20 x 30cm rectangle tin.\",\"step 2\",\"Beat the butter and sugar in a free-standing mixer until pale and fluffy. Add the eggs one at a time and beat well. Beat through the flour, milk and salt until fully combined, then spoon into the tin. Bake in the oven for 25 mins or until golden and firm to the touch. Set aside to cool completely.\",\"step 3\",\"Slice the sponge horizontally to create two halves. Trim the edges to make perfect corners. Cut the sponge into 18 squares. Lightly whip the cream with the icing sugar until it reaches soft peaks. Spread a little of the jam on half of the sponge squares then pipe or spread over a little of the cream. Sandwich each one with a second square of sponge then set aside in the fridge to chill.\",\"step 4\",\"To make the icing, whisk together the melted butter and milk in a bowl. Sieve the cocoa powder and icing sugar together in a seperate bowl. Gradually add the cocoa and sugar to the butter and milk mixture, whisking continuously to ensure there are no lumps. If it gets lumpy, whizz with a hand blender until smooth.\",\"step 5\",\"Divide the coconut between three shallow bowls (this keeps it from getting coated in too much chocolate whilst you’re dipping).\"]},{\"id\":\"g303\",\"title\":\"Lancashire hotpot\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uttrxw1511637813.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Lamb\",\"Lamb Kidney\",\"Onions\",\"Carrots\",\"Plain Flour\",\"Worcestershire Sauce\",\"Chicken Stock\",\"Bay Leaves\",\"Potatoes\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 160C/fan 140C/gas 3. Heat some dripping or butter in a large shallow casserole dish, brown the lamb in batches, lift to a plate, then repeat with t\",\"instructions\":[\"Heat oven to 160C/fan 140C/gas 3. Heat some dripping or butter in a large shallow casserole dish, brown the lamb in batches, lift to a plate, then repeat with the kidneys.\",\"Fry the onions and carrots in the pan with a little more dripping until golden. Sprinkle over the flour, allow to cook for a couple of mins, shake over the Worcestershire sauce, pour in the stock, then bring to the boil. Stir in the meat and bay leaves, then turn off the heat. Arrange the sliced potatoes on top of the meat, then drizzle with a little more dripping. Cover, then place in the oven for about 1½ hrs until the potatoes are cooked.\",\"Remove the lid, brush the potatoes with a little more dripping, then turn the oven up to brown the potatoes, or finish under the grill for 5-8 mins until brown.\"]},{\"id\":\"g304\",\"title\":\"Lasagna Sandwiches\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xr0n4r1576788363.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sour Cream\",\"Chopped Onion\",\"Dried Oregano\",\"Salt\",\"Bread\",\"Bacon\",\"Tomato\",\"Mozzarella\",\"Butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"1. In a small bowl, combine the first four ingredients; spread on four slices of bread. Layer with bacon, tomato and cheese; top with remaining bread.\\r\\n\\r\\n2. In \",\"instructions\":[\"1. In a small bowl, combine the first four ingredients; spread on four slices of bread. Layer with bacon, tomato and cheese; top with remaining bread.\",\"2. In a large skillet or griddle, melt 2 tablespoons butter. Toast sandwiches until lightly browned on both sides and cheese is melted, adding butter if necessary.\",\"Nutrition Facts\",\"1 sandwich: 445 calories, 24g fat (12g saturated fat), 66mg cholesterol, 1094mg sodium, 35g carbohydrate (3g sugars, 2g fiber), 21g protein.\"]},{\"id\":\"g305\",\"title\":\"Lasagne\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wtsvxx1511296896.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Bacon\",\"Onion\",\"Celery\",\"Carrots\",\"Garlic\",\"Minced Beef\",\"Tomato Puree\",\"Chopped Tomatoes\",\"Honey\",\"Lasagne Sheets\",\"Creme Fraiche\",\"Mozzarella Balls\",\"Parmesan Cheese\",\"Basil Leaves\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oil in a large saucepan. Use kitchen scissors to snip the bacon into small pieces, or use a sharp knife to chop it on a chopping board. Add the bacon t\",\"instructions\":[\"Heat the oil in a large saucepan. Use kitchen scissors to snip the bacon into small pieces, or use a sharp knife to chop it on a chopping board. Add the bacon to the pan and cook for just a few mins until starting to turn golden. Add the onion, celery and carrot, and cook over a medium heat for 5 mins, stirring occasionally, until softened.\",\"Add the garlic and cook for 1 min, then tip in the mince and cook, stirring and breaking it up with a wooden spoon, for about 6 mins until browned all over.\",\"Stir in the tomato purée and cook for 1 min, mixing in well with the beef and vegetables. Tip in the chopped tomatoes. Fill each can half full with water to rinse out any tomatoes left in the can, and add to the pan. Add the honey and season to taste. Simmer for 20 mins.\",\"Heat oven to 200C/180C fan/gas 6. To assemble the lasagne, ladle a little of the ragu sauce into the bottom of the roasting tin or casserole dish, spreading the sauce all over the base. Place 2 sheets of lasagne on top of the sauce overlapping to make it fit, then repeat with more sauce and another layer of pasta. Repeat with a further 2 layers of sauce and pasta, finishing with a layer of pasta.\",\"Put the crème fraîche in a bowl and mix with 2 tbsp water to loosen it and make a smooth pourable sauce. Pour this over the top of the pasta, then top with the mozzarella. Sprinkle Parmesan over the top and bake for 25–30 mins until golden and bubbling. Serve scattered with basil, if you like.\"]},{\"id\":\"g306\",\"title\":\"Leblebi Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/x2fw9e1560460636.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Chickpeas\",\"Vegetable Stock\",\"Cumin\",\"Garlic\",\"Salt\",\"Harissa Spice\",\"Pepper\",\"Lime\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the oil in a large pot. Add the onion and cook until translucent.\\r\\nDrain the soaked chickpeas and add them to the pot together with the vegetable stock. Br\",\"instructions\":[\"Heat the oil in a large pot. Add the onion and cook until translucent.\",\"Drain the soaked chickpeas and add them to the pot together with the vegetable stock. Bring to the boil, then reduce the heat and cover. Simmer for 30 minutes.\",\"In the meantime toast the cumin in a small ungreased frying pan, then grind them in a mortar. Add the garlic and salt and pound to a fine paste.\",\"Add the paste and the harissa to the soup and simmer until the chickpeas are tender, about 30 minutes.\",\"Season to taste with salt, pepper and lemon juice and serve hot.\"]},{\"id\":\"g307\",\"title\":\"Lemongrass beef stew with noodles\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ntafxw1763586291.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ginger\",\"Garlic Clove\",\"Lemongrass Stalks\",\"Coriander Leaves\",\"Red Chilli\",\"Vegetable Oil\",\"Beef\",\"Soy Sauce\",\"Five Spice Powder\",\"Brown Sugar\",\"Beef Stock\",\"Rice Noodles\",\"Lime\"],\"allergens\":[\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the ginger, garlic, lemongrass, coriander and 1 chilli in a food processor, then pulse until puréed. Heat the oil in a pan over a low heat. Add the \",\"instructions\":[\"step 1\",\"Put the ginger, garlic, lemongrass, coriander and 1 chilli in a food processor, then pulse until puréed. Heat the oil in a pan over a low heat. Add the purée and cook for 5 mins. Stir in the beef, soy, five-spice, sugar and stock. Put on a lid and bring to the boil, then lower heat and simmer for 1 hr 15 mins. Remove the lid and cook for a further 15 mins until the beef is tender.\",\"step 2\",\"Just before serving, prepare noodles following pack instructions. Drain well, then divide between 2 bowls and spoon over the beef stew. Serve sprinkled with the remaining chilli and coriander leaves, with lime wedges for squeezing over.\"]},{\"id\":\"g308\",\"title\":\"Locro\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/5sgsob1763196284.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Dried white corn\",\"Dried white beans\",\"Pumpkin\",\"Potatoes\",\"Beef\",\"Pork\",\"Chorizo\",\"Onion\",\"Paprika\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Soak: Soak corn and beans overnight in water.\\r\\nCook Meats: In a large pot, brown the beef and pork. Add onions and spices, cooking until translucent.\\r\\nSimmer th\",\"instructions\":[\"Soak: Soak corn and beans overnight in water.\",\"Cook Meats: In a large pot, brown the beef and pork. Add onions and spices, cooking until translucent.\",\"Simmer the Stew: Add soaked corn and beans, pumpkin, potato, and enough water to cover. Simmer for 2-3 hours, until thick.\",\"Serve: Enjoy hot, with bread on the side.\",\"Pro Tips:\",\"Toasting the corn slightly before adding it to the stew enhances its flavor.\",\"Add a spoonful of paprika or a dash of cumin for an extra layer of warmth and complexity\"]},{\"id\":\"g309\",\"title\":\"Ma Po Tofu\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1525874812.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tofu\",\"Minced Beef\",\"Sesame Seed Oil\",\"Doubanjiang\",\"Fermented Black Beans\",\"Pepper\",\"Salt\",\"Sichuan pepper\",\"Soy Sauce\",\"Water\",\"Olive Oil\",\"Scallions\",\"Spring Onions\",\"Garlic\",\"Ginger\",\"Water\",\"Cornstarch\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add a small pinch of salt and sesame oil to minced beef. Mix well and set aside.\\r\\nMix 1 tablespoon of cornstarch with 2 and ½ tablespoons of water in a small bo\",\"instructions\":[\"Add a small pinch of salt and sesame oil to minced beef. Mix well and set aside.\",\"Mix 1 tablespoon of cornstarch with 2 and ½ tablespoons of water in a small bowl to make water starch.\",\"Cut tofu into square cubes (around 2cms). Bring a large amount of water to a boil and then add a pinch of salt. Slide the tofu in and cook for 1 minute. Move out and drain.\",\"Get a wok and heat up around 2 tablespoons of oil, fry the minced meat until crispy. Transfer out beef out and leave the oil in.\",\"Fry doubanjiang for 1 minute over slow fire and then add garlic, scallion white, ginger and fermented black beans to cook for 30 seconds until aroma. Then mix pepper flakes in.\",\"Add water to the seasonings and bring to boil over high fire. Gently slide the tofu cubes. Add light soy sauce and beef.Slow the heat after boiling and then simmer for 6-8 minutes. Then add chopped garlic greens.\",\"Stir the water starch and then pour half of the mixture to the simmering pot. Wait for around 30 seconds and then pour the other half. You can slightly taste the tofu and add pinch of salt if not salty enough. By the way, if you feel it is too spicy, add some sugar can milder the taste. But be carefully as the broth is very hot at this point.\",\"Transfer out when almost all the seasonings stick to tofu cubes. Sprinkle Szechuan peppercorn powder (to taste)and chopped garlic greens if using.\",\"Serve immediately with steamed rice.\"]},{\"id\":\"g310\",\"title\":\"Madeira Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/urtqut1511723591.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Caster Sugar\",\"Eggs\",\"Self-raising Flour\",\"Milk\",\"Lemon\",\"Mixed Peel\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Pre-heat the oven to 180C/350F/Gas 4. Grease an 18cm/7in round cake tin, line the base with greaseproof paper and grease the paper.\\r\\nCream the butter and sugar \",\"instructions\":[\"Pre-heat the oven to 180C/350F/Gas 4. Grease an 18cm/7in round cake tin, line the base with greaseproof paper and grease the paper.\",\"Cream the butter and sugar together in a bowl until pale and fluffy. Beat in the eggs, one at a time, beating the mixture well between each one and adding a tablespoon of the flour with the last egg to prevent the mixture curdling.\",\"Sift the flour and gently fold in, with enough milk to give a mixture that falls slowly from the spoon. Fold in the lemon zest.\",\"Spoon the mixture into the prepared tin and lightly level the top. Bake on the middle shelf of the oven for 30-40 minutes, or until golden-brown on top and a skewer inserted into the centre comes out clean.\",\"Remove from the oven and set aside to cool in the tin for 10 minutes, then turn it out on to a wire rack and leave to cool completely.\",\"To serve, decorate the cake with the candied peel.\"]},{\"id\":\"g311\",\"title\":\"Mamoul (Eid biscuits)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/35kejr1763599712.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Semolina\",\"Sunflower Oil\",\"Unsalted Butter\",\"Milk\",\"Icing Sugar\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1\\r\\nMix butter with sugar until creamy.\\r\\n2\\r\\nAdd oil flour and semolina and mix.\\r\\n3\\r\\nAdd warm milk and don't knead too much\\r\\n4\\r\\nCover and leave aside for an hour \",\"instructions\":[\"1\",\"Mix butter with sugar until creamy.\",\"2\",\"Add oil flour and semolina and mix.\",\"3\",\"Add warm milk and don't knead too much\",\"4\",\"Cover and leave aside for an hour or less until you prepare the filling\",\"5\",\"For the dates filling, fry some sesame in a pan then add butter. Add the dates paste and mixed well with sesame and butter. Then add a little bit of water until it's mushy. Be careful don't make it too mushy.\"]},{\"id\":\"g312\",\"title\":\"Massaman Beef curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tvttqv1504640475.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Peanuts\",\"Coconut cream\",\"Massaman curry paste\",\"Beef\",\"Potatoes\",\"Onion\",\"Lime\",\"Cinnamon stick\",\"Tamarind paste\",\"Brown sugar\",\"Fish Sauce\",\"chilli\",\"Jasmine Rice\"],\"allergens\":[\"milk\",\"peanut\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 200C/180C fan/gas 6, then roast the peanuts on a baking tray for 5 mins until golden brown. When cool enough to handle, roughly chop. Reduce oven t\",\"instructions\":[\"Heat oven to 200C/180C fan/gas 6, then roast the peanuts on a baking tray for 5 mins until golden brown. When cool enough to handle, roughly chop. Reduce oven to 180C/160C fan/gas 4.\",\"Heat 2 tbsp coconut cream in a large casserole dish with a lid. Add the curry paste and fry for 1 min, then stir in the beef and fry until well coated and sealed. Stir in the rest of the coconut with half a can of water, the potatoes, onion, lime leaves, cinnamon, tamarind, sugar, fish sauce and most of the peanuts. Bring to a simmer, then cover and cook for 2 hrs in the oven until the beef is tender.\",\"Sprinkle with sliced chilli and the remaining peanuts, then serve straight from the dish with jasmine rice.\"]},{\"id\":\"g313\",\"title\":\"Matambre a la Pizza\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wf49qs1763075222.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Flank Steak\",\"Tomato Sauce\",\"Mozzarella\",\"Oregano\",\"Green Olives\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Prepare the Steak: Season the steak with salt and pepper. Grill one side until half-cooked.\\r\\nAdd Toppings: Spread tomato sauce over the cooked side, then add ch\",\"instructions\":[\"Prepare the Steak: Season the steak with salt and pepper. Grill one side until half-cooked.\",\"Add Toppings: Spread tomato sauce over the cooked side, then add cheese, oregano, and olives.\",\"Finish Grilling: Grill until the cheese is melted and bubbly.\",\"Serve: Slice and serve hot.\",\"Pro Tips:\",\"Tenderize the matambre by scoring it lightly on both sides. This helps it cook more evenly and absorb the flavors.\",\"Precook the matambre on the grill before adding the toppings to ensure it's fully cooked without burning the cheese.\"]},{\"id\":\"g314\",\"title\":\"Matar Paneer\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xxpqsy1511452222.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sunflower Oil\",\"Paneer\",\"Ginger\",\"Cumin\",\"Turmeric\",\"Coriander\",\"Green Chilli\",\"Tomato\",\"Peas\",\"Garam Masala\",\"Coriander\",\"Naan Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the oil in a frying pan over high heat until it’s shimmering hot. Add the paneer, then turn the heat down a little. Fry until it starts to brown at the edg\",\"instructions\":[\"Heat the oil in a frying pan over high heat until it’s shimmering hot. Add the paneer, then turn the heat down a little. Fry until it starts to brown at the edges, then turn it over and brown on each side – the paneer will brown faster than you think, so don’t walk away. Remove the paneer from the pan and drain on kitchen paper.\",\"Put the ginger, cumin, turmeric, ground coriander and chilli in the pan, and fry everything for 1 min. Add the tomatoes, mashing them with the back of a spoon and simmer everything for 5 mins until the sauce smells fragrant. Add a splash of water if it’s too thick. Season well. Add the peas and simmer for a further 2 mins, then stir in the paneer and sprinkle over the garam masala. Divide between two bowls, top with coriander leaves and serve with naan bread, roti or rice.\"]},{\"id\":\"g315\",\"title\":\"Mazariner – Scandinavian Almond Tartlets\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uh1n5u1763075545.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Powdered Sugar\",\"Butter\",\"Egg\",\"Egg\",\"Powdered Sugar\",\"Butter\",\"Vanilla Extract\",\"Flour\",\"Almond Flour\",\"Almond Extract\",\"Powdered Sugar\",\"Heavy Cream\",\"Almond Extract\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Shells\\r\\n▢\\r\\nCombine the flour and powdered sugar in a food processor. Add the butter and pulse until it's evenly distributed. Add the egg and pulse until the dou\",\"instructions\":[\"Shells\",\"▢\",\"Combine the flour and powdered sugar in a food processor. Add the butter and pulse until it's evenly distributed. Add the egg and pulse until the dough comes together.\",\"▢\",\"Roll out the dough on a floured surface. Cut the dough in circles with a large mug. Press the circles down into a greased muffin pan. Put the pan of shells in the fridge while you prepare the almond filling.\",\"Almond filling\",\"▢\",\"Preheat oven to 355°F (180°C).\",\"▢\",\"Whisk the egg and powdered sugar together until thick and airy. Melt the butter and stir it into the egg mixture. Stir in the vanilla, flour, and almond extract. Stir in the almond flour.\"]},{\"id\":\"g316\",\"title\":\"Mbuzi Choma (Roasted Goat)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/cuio7s1555492979.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Goat Meat\",\"Corn Flour\",\"Tomatoes\",\"Salt\",\"Onion\",\"Green Chilli\",\"Coriander Leaves\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"1. Steps for the Meat: \\r\\n Roast meat over medium heat for 50 minutes and salt it as you turn it.\\r\\n\\r\\n2. Steps for Ugali:\\r\\nBring the water and salt to a boil in a\",\"instructions\":[\"1. Steps for the Meat:\",\"Roast meat over medium heat for 50 minutes and salt it as you turn it.\",\"2. Steps for Ugali:\",\"Bring the water and salt to a boil in a heavy-bottomed saucepan. Stir in the cornmeal slowly, letting it fall through the fingers of your hand.\",\"3. Reduce heat to medium-low and continue stirring regularly, smashing any lumps with a spoon, until the mush pulls away from the sides of the pot and becomes very thick, about 10 minutes.\",\"4.Remove from heat and allow to cool.\",\"5. Place the ugali into a large serving bowl. Wet your hands with water, form a ball and serve.\",\"6. Steps for Kachumbari: Mix the tomatoes, onions, chili and coriander leaves in a bowl.\",\"7. Serve and enjoy!\"]},{\"id\":\"g317\",\"title\":\"McSinghs Scotch pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vssrtx1511557680.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cumin\",\"Rapeseed Oil\",\"Red Onions\",\"Garlic Clove\",\"Green Chilli\",\"Red Pepper\",\"Nutmeg\",\"Coriander\",\"Lamb Mince\",\"Pepper\",\"Coriander\",\"Plain Flour\",\"Salt\",\"Milk\",\"Lard\",\"Egg Yolks\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat a large frying pan and toast the cumin seeds for a few minutes, then set aside. Heat the oil in the same pan and fry the onion, garlic, chilli, pepper and \",\"instructions\":[\"Heat a large frying pan and toast the cumin seeds for a few minutes, then set aside. Heat the oil in the same pan and fry the onion, garlic, chilli, pepper and a good pinch of salt for around eight minutes, until there is no moisture left. Remove from the heat, stir in the toasted cumin seeds, ground mace (or nutmeg) and ground coriander. Leave to cool.\",\"In a large bowl mix together the minced lamb, white pepper, fresh coriander, and the cooled spiced onion mixture until combined. Set aside, covered, in the fridge.\",\"Preheat the oven to 200C/400F/Gas 6 and generously grease a 20cm/8in diameter loose-bottomed or springform round cake tin with lard.\",\"To make the pastry, sift the flour and salt in a large bowl and make a well in the centre.\",\"Put the milk, lard and 90ml/3fl oz of water in a saucepan and heat gently. When the lard has melted, increase the heat and bring to the boil.\",\"Pour the boiling liquid into the flour, and use a wooden spoon to combine until cool enough to handle. Bring together into a ball.\",\"Dust a work surface with flour and, working quickly, knead the dough briefly – it will be soft and moist. Set aside a third of the pastry and roll the rest out on a well-floured surface. Line the pie dish with the pastry, pressing it right up the sides until it pokes just over the top of the tin.\",\"Add the filling into the pastry-lined tin bit by bit. As you reach the top, form a slight peak. Roll out the reserved pastry and top the pie with it. Pinch the edges to seal and trim the excess. Poke a hole in the top of the pie and insert a small tube made from aluminium foil to allow steam to escape.\",\"Brush the top of the pie with a little beaten egg yolk, and bake in the preheated oven for 30 minutes (put a tray on the shelf below to catch any drips). Then reduce the temperature to 160C/325F/Gas 3 and cook for a further 1¼ hours until golden-brown. Leave to cool completely before refrigerating for two hours, or overnight.\",\"Run a knife around the edge of the pie, remove from the tin and serve with chutneys, salads or pickles.\"]},{\"id\":\"g318\",\"title\":\"Mediterranean Pasta Salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wvqpwt1468339226.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"mozzarella balls\",\"baby plum tomatoes\",\"fresh basil\",\"farfalle\",\"extra virgin olive oil\",\"Green Olives\",\"tuna\",\"salt\",\"pepper\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Bring a large saucepan of salted water to the boil\\r\\nAdd the pasta, stir once and cook for about 10 minutes or as directed on the packet.\\r\\nMeanwhile, wash the to\",\"instructions\":[\"Bring a large saucepan of salted water to the boil\",\"Add the pasta, stir once and cook for about 10 minutes or as directed on the packet.\",\"Meanwhile, wash the tomatoes and cut into quarters. Slice the olives. Wash the basil.\",\"Put the tomatoes into a salad bowl and tear the basil leaves over them. Add a tablespoon of olive oil and mix.\",\"When the pasta is ready, drain into a colander and run cold water over it to cool it quickly.\",\"Toss the pasta into the salad bowl with the tomatoes and basil.\",\"Add the sliced olives, drained mozzarella balls, and chunks of tuna. Mix well and let the salad rest for at least half an hour to allow the flavours to mingle.\",\"Sprinkle the pasta with a generous grind of black pepper and drizzle with the remaining olive oil just before serving.\"]},{\"id\":\"g319\",\"title\":\"Mee goreng mamak\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xquakq1619787532.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Peanuts\",\"Chilli\",\"Prawns\",\"Oil\",\"Water\",\"Tamarind Paste\",\"Potatoes\",\"Red Onions\",\"Garlic Clove\",\"Cabbage\",\"Chinese Broccoli\",\"Tofu\",\"Soy Sauce\",\"Noodles\",\"Egg\"],\"allergens\":[\"egg\",\"soy\",\"peanut\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oil in a pan at medium heat. Then, add peanuts, dried chilies, dried shrimps and dhal. Fry the aromatics until fragrant. Remove from pan and leave aside.\\r\\n\",\"instructions\":[\"Heat oil in a pan at medium heat. Then, add peanuts, dried chilies, dried shrimps and dhal. Fry the aromatics until fragrant. Remove from pan and leave aside.\",\"Blend fried ingredients with tamarind paste and water until fine. Then, sauté the blended ingredients in oil heated over low heat. Continue cooking until the oil separates from the paste and turns a darker shade.\",\"Skin and cut potatoes into small chunks and boil them in a pot of water until knife-tender. Once ready, remove them from the pot and leave aside. Discard water.\",\"Slice onion and fried tofu, mince garlic, cut some cabbage and Chinese flowering cabbage (choi sam). Prepare prawn fritters and cut them. Boil noodles to soften them if bought dried. Also mix black soy sauce with water.\",\"To fry one portion of mee goreng mamak, heat oil and add 1/4 of the following ingredients in this order: garlic, onion, paste. Sauté until fragrant. Optionally, add prawns.\",\"Add in 1/4 amount of tofu, boiled potatoes, cabbage, Chinese flowering cabbage and prawn fritters. Sauté for another 30 seconds.\",\"Add noodles to the wok. Add 3 tablespoons of dark soy sauce mixture. Mix evenly for the next 1 minute. Then, move the noodles to the side of the wok. Stir in an egg. Garnish with a slice of lime and slices of green chilies. To cook another plate of noodles, repeat from step 5 onwards.\"]},{\"id\":\"g320\",\"title\":\"Migas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xd9aj21740432378.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Bread\",\"Olive Oil\",\"Garlic\",\"Pork\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Crumble the bread into small pieces. Sprinkle with cold water, cover with a damp cloth and leave for 30 minutes.\\r\\nHeat 2 tsp of olive oil in a deep pan. Add the\",\"instructions\":[\"Crumble the bread into small pieces. Sprinkle with cold water, cover with a damp cloth and leave for 30 minutes.\",\"Heat 2 tsp of olive oil in a deep pan. Add the garlic cloves separated, skins on; just make a small cut with a knife to open them and keep frying for 5 minutes. Set the garlic aside.\",\"In the same oil, where we fried everything, simmer the bread, stirring constantly for 15 minutes and add a grinding of black pepper.\",\"Add the garlic, continue stirring for about 20 minutes. It will be ready when the bread is soft and golden.\"]},{\"id\":\"g321\",\"title\":\"Milanesa\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wdfa171763065079.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Cutlet\",\"Egg\",\"Breadcrumbs\",\"Parsley\",\"Garlic\",\"Salt\",\"Pepper\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Season the Cutlets: Salt and pepper the cutlets.\\r\\nBread the Cutlets: Dip each cutlet in egg, then coat with a mixture of breadcrumbs, parsley, and garlic.\\r\\nFry:\",\"instructions\":[\"Season the Cutlets: Salt and pepper the cutlets.\",\"Bread the Cutlets: Dip each cutlet in egg, then coat with a mixture of breadcrumbs, parsley, and garlic.\",\"Fry: Heat oil in a large pan over medium heat. Fry the cutlets until golden and cooked through, about 3-4 minutes per side.\",\"Serve: Serve hot with lemon wedges or a side salad.\",\"Pro Tips:\",\"For an extra crispy crust, use panko breadcrumbs mixed with finely grated Parmesan cheese.\",\"Gently pound the cutlets to an even thickness for uniform cooking.\"]},{\"id\":\"g322\",\"title\":\"Mince Pies\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qe8pf51576795532.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Plain Flour\",\"Caster Sugar\",\"Mincemeat\",\"Egg\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To make the pastry, rub 225g cold, diced butter into 350g plain flour, then mix in 100g golden caster sugar and a pinch of salt.\\r\\n\\r\\nCombine the pastry into a ba\",\"instructions\":[\"To make the pastry, rub 225g cold, diced butter into 350g plain flour, then mix in 100g golden caster sugar and a pinch of salt.\",\"Combine the pastry into a ball – don’t add liquid – and knead it briefly. The dough will be fairly firm, like shortbread dough. You can use the dough immediately, or chill for later.\",\"Preheat the oven to 200C/gas 6/fan 180C. Line 18 holes of two 12-hole patty tins, by pressing small walnut-sized balls of pastry into each hole.\",\"Spoon 280g mincemeat into the pies.\",\"Take slightly smaller balls of pastry than before and pat them out between your hands to make round lids, big enough to cover the pies.\",\"Top the pies with their lids, pressing the edges gently together to seal – you don’t need to seal them with milk or egg as they will stick on their own. (The pies may now be frozen for up to 1 month).\",\"Beat 1 small egg and brush the tops of the pies. Bake for 20 mins until golden. Leave to cool in the tin for 5 mins, then remove to a wire rack.\",\"To serve, lightly dust with icing sugar.\"]},{\"id\":\"g323\",\"title\":\"Minced Beef Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xwutvy1511555540.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Minced Beef\",\"Onion\",\"Tomato Puree\",\"Plain Flour\",\"Mushrooms\",\"Beef Stock\",\"Worcestershire Sauce\",\"Shortcrust Pastry\",\"Egg Yolks\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 200C/400F/Gas 6.\\r\\nHeat the oil in a deep frying pan and fry the beef mince for 4-5 minutes, breaking it up with a wooden spoon as it browns.\",\"instructions\":[\"Preheat the oven to 200C/400F/Gas 6.\",\"Heat the oil in a deep frying pan and fry the beef mince for 4-5 minutes, breaking it up with a wooden spoon as it browns.\",\"Add the onion and cook for 2-3 minutes, then stir in the tomato purée and cook for 2-3 more minutes. Stir in the flour and cook for a further minute, then add the chopped mushrooms, the stout or beef stock and a couple of dashes of Worcestershire sauce. Bring to the boil, then reduce the heat, cover the pan with a lid and leave to simmer for 20 minutes. Set aside and leave to cool, then turn the meat mixture into a one litre pie dish.\",\"Roll out the pastry on a floured work surface until it is slightly larger than the pie dish. Gently drape the pastry over the dish, pressing firmly onto the edges. Trim, then shape the edges into a fluted shape.\",\"Cut some leaf shapes out of the pastry trimmings and decorate the top of the pie, sticking them to the pastry with the beaten egg yolk.\",\"Make three or four slits in the pastry to allow the steam to escape, then brush the pie with the rest of the beaten egg yolk and bake in the oven for 20-25 minutes, or until golden-brown.\",\"To serve, slice into wedges.\"]},{\"id\":\"g324\",\"title\":\"Mini bundt cakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tzt3it1764363293.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Plain Flour\",\"Caster Sugar\",\"Egg\",\"Baking Powder\",\"Cocoa Powder\",\"Milk\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oven to 180C/160C fan/gas 4. Melt 25g butter and generously brush into the holes of a mini bundt tins. Tip a little flour into each hole and sh\",\"instructions\":[\"step 1\",\"Heat the oven to 180C/160C fan/gas 4. Melt 25g butter and generously brush into the holes of a mini bundt tins. Tip a little flour into each hole and shake to coat, then tip out the excess. Beat the butter, caster sugar and a pinch of salt together using an electric whisk. Add the eggs, one at a time, beating well after each addition. Combine the flour and baking powder in a separate bowl, then sift this into the wet ingredients and stir until smooth. Combine the cocoa powder and milk in a small bowl until smooth.\",\"step 2\",\"Spoon 1 tbsp of the plain batter into each hole of the bundt tin. Mix the remaining plain batter with the cocoa powder mixture, then divide this between the holes. Bake for 15-18 mins, or until a skewer inserted into the cakes comes out clean. Leave to cool in the tin for 5 mins, then turn out onto a wire rack and leave to cool completely. Dust with icing sugar to serve.\",\"step 3\",\"Pour 1 tablespoon of light batter into each mold. Mix the remaining batter with the stirred cocoa mixture and then fill the molds with a tablespoon.\",\"step 4\",\"Bake the mini Bundt cakes in the preheated oven for 15-18 minutes , depending on the size of the molds. After 15 minutes of baking time, use a toothpick to test with a skewer and, if necessary, bake for another 3 minutes. Let the mini Bundt cakes cool down completely in the tin. Then carefully remove from the mold. Dust with some icing sugar and serve. Enjoy your meal!\"]},{\"id\":\"g325\",\"title\":\"Mini chilli beef pies\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6sarfo1762340107.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ready rolled shortcrust pastry\",\"Sunflower Oil\",\"Onion\",\"Hot Chilli Powder\",\"Ground Cumin\",\"Minced Beef\",\"Tomato Puree\",\"Beef Stock\",\"Ground Cinnamon\",\"Kidney Beans\",\"Potatoes\",\"Sour Cream\",\"Chopped Chive\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make chilli, heat oil in a pan and fry onion for 5 mins until soft. Add spices; fry for 1 min. Stir in beef and cook for a few mins. Add tomato purée\",\"instructions\":[\"step 1\",\"To make chilli, heat oil in a pan and fry onion for 5 mins until soft. Add spices; fry for 1 min. Stir in beef and cook for a few mins. Add tomato purée, stock and cinnamon. Give it a stir, bring to the boil, then simmer for 15-20 mins until very little liquid is left. Add beans 5 mins before the end of cooking. Check seasoning and cool.\",\"step 2\",\"Heat oven to 200C/fan 180C/gas 6. Using a 7cm pastry cutter, stamp out 12 circles from the pastry. Use to line a 12-hole mini muffin tray, prick the base of the pastry with a fork, and bake for 10 mins. Remove from oven and cool on a wire tray. Repeat with remaining pastry.\",\"step 3\",\"Meanwhile, cook the potato in boiling water until tender. Drain, mash with soured cream and seasoning, then stir through chives. Spoon 1-2 tsp of chilli mix into the pastry cases and top with a tsp of mash. Ruffle mash with a fork; return to the oven for 15 mins or until golden.\"]},{\"id\":\"g326\",\"title\":\"Molasses Baked Beans\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9tddhg1764443699.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Dried White Navy Beans\",\"Bacon\",\"Onion\",\"Molasses\",\"Brown Sugar\",\"Cider Vinegar\",\"Mustard\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Place the dried beans into a Dutch oven with 6 cups (1.5 L) of water. Soak overnight.\\r\\nDrain and pour beans back into the pot with enough water to cover the bea\",\"instructions\":[\"Place the dried beans into a Dutch oven with 6 cups (1.5 L) of water. Soak overnight.\",\"Drain and pour beans back into the pot with enough water to cover the beans by a couple of inches, cook for 30 minutes until they are tender but still firm. Drain beans, making sure to reserve cooking liquid, set aside.\",\"Preheat the oven to 325 °F (160 °C). While the oven is preheating, cook pork over medium-high heat in the Dutch Oven until fat is rendered and pork is beginning to brown, then add the onion cooking until tender.\",\"Add the beans back to the pot, along with molasses, brown sugar, apple cider vinegar, ground mustard, salt and pepper and 3 cups (750 mL) of reserved bean water.\",\"Bake uncovered for 3 to 5 hours until the beans are tender, and the sauce has thickened, and the edges of the pot get sticky.\",\"(Note: if beans get dry, add another cup of water.)\"]},{\"id\":\"g327\",\"title\":\"Montreal Smoked Meat\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uttupv1511815050.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef Brisket\",\"Salt\",\"Black Pepper\",\"Coriander\",\"Sugar\",\"Bay Leaf\",\"Cloves\",\"Black Pepper\",\"Coriander\",\"Paprika\",\"Garlic\",\"Onion\",\"Dill\",\"English Mustard\",\"Celery Salt\",\"Red Pepper Flakes\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To make the cure, in a small bowl mix together salt, pink salt, black pepper, coriander, sugar, bay leaf, and cloves. Coat entire brisket with the cure and plac\",\"instructions\":[\"To make the cure, in a small bowl mix together salt, pink salt, black pepper, coriander, sugar, bay leaf, and cloves. Coat entire brisket with the cure and place in an extra-large resealable plastic bag. Place in the coldest part of the refrigerator and cure for 4 days, flipping brisket twice a day.\",\"Remove brisket from bag and wash as much cure off as possible under cold running water. Place brisket in a large container and fill with water and let soak for 2 hours, replacing water every 30 minutes. Remove from water and pat dry with paper towels.\",\"To make the rub, mix together black pepper, coriander, paprika, garlic powder, onion powder, dill weed, mustard, celery seed, and crushed red papper in a small bowl. Coat entire brisket with the rub.\",\"Fire up smoker or grill to 225 degrees, adding chunks of smoking wood chunks when at temperature. When wood is ignited and producing smoke, place brisket in, fat side up, and smoke until an instant read thermometer registers 165 degrees when inserted into thickest part of the brisket, about 6 hours.\",\"Transfer brisket to large roasting pan with V-rack. Place roasting pan over two burners on stovetop and fill with 1-inch of water. Bring water to a boil over high heat, reduce heat to medium, cover roasting pan with aluminum foil, and steam brisket until an instant read thermometer registers 180 degrees when inserted into thickest part of the meat, 1 to 2 hours, adding more hot water as needed.\",\"Transfer brisket to cutting board and let cool slightly. Slice and serve, preferably on rye with mustard.\"]},{\"id\":\"g328\",\"title\":\"Moroccan Carrot Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/jcr46d1614763831.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Carrots\",\"Onion\",\"Garlic Clove\",\"Cumin\",\"Coriander\",\"Olive Oil\",\"Garam Masala\",\"Lemon Juice\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Step 1\\r\\nPreheat oven to 180° C.\\r\\nStep 2\\r\\nCombine carrots, onion, garlic, cumin seeds, coriander seeds, salt and olive oil in a bowl and mix well. Transfer on a \",\"instructions\":[\"Step 1\",\"Preheat oven to 180° C.\",\"Step 2\",\"Combine carrots, onion, garlic, cumin seeds, coriander seeds, salt and olive oil in a bowl and mix well. Transfer on a baking tray.\",\"Step 3\",\"Put the baking tray in preheated oven and roast for 10-12 minutes or till carrots soften. Remove from heat and cool.\",\"Step 4\",\"Grind the baked carrot mixture along with some water to make a smooth paste and strain in a bowl.\",\"Step 5\",\"Heat the carrot mixture in a non-stick pan. Add two cups of water and bring to a boil. Add garam masala powder and mix. Add salt and mix well.\"]},{\"id\":\"g329\",\"title\":\"Moussaka\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ctg8jd1585563097.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Aubergine\",\"Greek Yogurt\",\"Egg\",\"Parmesan\",\"Tomato\",\"Tomato Puree\",\"Potatoes\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the grill to high. Brown the beef in a deep ovenproof frying pan over a high heat for 5 mins. Meanwhile, prick the aubergine with a fork, then microwave on\",\"instructions\":[\"Heat the grill to high. Brown the beef in a deep ovenproof frying pan over a high heat for 5 mins. Meanwhile, prick the aubergine with a fork, then microwave on High for 3-5 mins until soft. Mix the yogurt, egg and parmesan together, then add a little seasoning.\",\"Stir the tomatoes, purée and potatoes in with the beef with some seasoning and heat through. Smooth the surface of the beef mixture with the back of a spoon, then slice the cooked aubergine and arrange on top. Pour the yogurt mixture over the aubergines, smooth out evenly, then grill until the topping has set and turned golden.\"]},{\"id\":\"g330\",\"title\":\"Mulukhiyah\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/x372ug1598733932.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mulukhiyah\",\"Onion\",\"Beef\",\"Salt\",\"Water\",\"Garlic Clove\",\"Olive Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Saute the onions in the 3-4 tablespoons olive oil\\r\\nAdd the beef cubes or the chicken cutlets, sear for 3-4 min on each side\\r\\nAdd 1 liter of water or just enough\",\"instructions\":[\"Saute the onions in the 3-4 tablespoons olive oil\",\"Add the beef cubes or the chicken cutlets, sear for 3-4 min on each side\",\"Add 1 liter of water or just enough to cover the meat\",\"Cook over medium heat until the meat is done (I usually do this in the pressure cooker and press them for 5 min)\",\"Add the frozen mulukhyia and stir until it thaws completely and then comes to a boil\",\"In another pan add the 1/4 to 1/2 cup of olive oil and the cloves of garlic and cook over medium low heat until you can smell the garlic (don’t brown it, it will become bitter)\",\"Add the oil and garlic to the mulukhyia and lower the heat and simmer for 5-10 minutes\",\"Add salt to taste\",\"Serve with a generous amount of lemon juice.\",\"You can serve it with some short grain rice or some pita bread\"]},{\"id\":\"g331\",\"title\":\"Mushroom & Chestnut Rotolo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ssyqwr1511451678.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mushrooms\",\"Chestnuts\",\"Challots\",\"Garlic\",\"Rosemary\",\"Wild Mushrooms\",\"Soy Sauce\",\"White Wine\",\"Lasagne Sheets\",\"Breadcrumbs\",\"Sage\",\"Truffle Oil\"],\"allergens\":[\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Soak the dried mushrooms in 350ml boiling water and set aside until needed. Blitz ¾ of the chestnuts with 150ml water until creamy. Roughly chop the remaining c\",\"instructions\":[\"Soak the dried mushrooms in 350ml boiling water and set aside until needed. Blitz ¾ of the chestnuts with 150ml water until creamy. Roughly chop the remaining chestnuts.\",\"Heat 2 tbsp olive oil in a large non-stick frying pan. Fry the shallots with a pinch of salt until softened, then add the garlic, chopped chestnuts and rosemary, and fry for 2 mins more. Add the wild mushrooms, 2 tbsp oil and some seasoning. Cook for 3 mins until they begin to soften. Drain and roughly chop the dried mushrooms (reserve the soaking liquid), then add those too, along with the soy sauce, and fry for 2 mins more.\",\"Whisk the wine, reserved mushroom liquid and chestnut cream together to create a sauce. Season, then add half to the mushroom mixture in the pan and cook for 1 min until the sauce becomes glossy. Remove and discard the rosemary sprigs, then set the mixture aside.\",\"Heat oven to 180C/160C fan/gas 4. Bring a large pan of salted water to the boil and get a large bowl of ice water ready. Drop the lasagne sheets into the boiling water for 2 mins or until pliable and a little cooked, then immediately plunge them into the cold water. Using your fingers, carefully separate the sheets and transfer to a clean tea towel. Spread a good spoonful of the sauce on the bottom two thirds of each sheet, then, rolling away from yourself, roll up the shorter ends. Cut each roll in half, then position the rolls of pasta cut-side up in a pie dish that you are happy to serve from at the table. If you have any mushroom sauce remaining after you’ve rolled up all the sheets, simply push it into some of the exposed rolls of pasta.\",\"Pour the rest of the sauce over the top of the pasta, then bake for 10 mins or until the pasta no longer has any resistance when tested with a skewer.\",\"Meanwhile, put the breadcrumbs, the last 2 tbsp olive oil, sage leaves and some seasoning in a bowl, and toss everything together. Scatter the rotolo with the crumbs and sage, then bake for another 10 mins, until the top is golden and the sage leaves are crispy. Leave to cool for 10 mins to allow the pasta to absorb the sauce, then drizzle with a little truffle oil, if you like, before taking your dish to the table.\"]},{\"id\":\"g332\",\"title\":\"Mushroom soup with buckwheat\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1ngcbf1628770793.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mushrooms\",\"Buckwheat\",\"Vegetable Oil\",\"Onion\",\"Garlic\",\"Bay Leaf\",\"Vegetable Stock Cube\",\"Sour Cream\",\"White Wine Vinegar\",\"Parsley\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Chop the onion and garlic, slice the mushrooms and wash the buckwheat. Heat the oil and lightly sauté the onion. Add the mushrooms and the garlic and continue t\",\"instructions\":[\"Chop the onion and garlic, slice the mushrooms and wash the buckwheat.\",\"Heat the oil and lightly sauté the onion.\",\"Add the mushrooms and the garlic and continue to sauté.\",\"Add the salt, vegetable seasoning, buckwheat and the bay leaf and cover with water.\",\"Simmer gently and just before it is completely cooked, add pepper, sour cream mixed with flour, the chopped parsley and vinegar to taste.\"]},{\"id\":\"g333\",\"title\":\"Mustard champ\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/o7p9581608589317.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Milk\",\"Butter\",\"Mustard\",\"Spring Onions\",\"Spring Onions\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"STEP 1\\r\\nBoil the potatoes for 15 mins or until tender. Drain, then mash.\\r\\n\\r\\nSTEP 2\\r\\nHeat the milk and half the butter in the corner of the pan, then beat into t\",\"instructions\":[\"STEP 1\",\"Boil the potatoes for 15 mins or until tender. Drain, then mash.\",\"STEP 2\",\"Heat the milk and half the butter in the corner of the pan, then beat into the mash, along with the wholegrain mustard.\",\"STEP 3\",\"Gently fry the spring onions in the remaining butter for 2 mins until just soft but still a perky green. Fold into the mash and serve. Great with gammon or to top a fish pie.\"]},{\"id\":\"g334\",\"title\":\"Mutabbaq\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/i5o2b61763739053.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mincemeat\",\"Garlic\",\"Ginger\",\"Egg\",\"Tomato\",\"Spring Onions\",\"Filo Pastry\",\"Melted Butter\",\"Salt\",\"Paprika\",\"Cumin\",\"Allspice\",\"Turmeric\",\"Black Pepper\",\"Sugar\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nHeat the frying pan and add in some oil. Fry the mashed garlic and ginger first and then add in the minced meat and all seasoning. When the meat is cooked, s\",\"instructions\":[\"1\",\"Heat the frying pan and add in some oil. Fry the mashed garlic and ginger first and then add in the minced meat and all seasoning. When the meat is cooked, set aside to cool down.\",\"2\",\"Get another big bowl. Add in egg, chopped tomato, chopped spring onion and minced meat.\",\"3\",\"Get one 2 sheets of filo pastry or 1 sheet spring roll wrap. Brush it with some butter and then put some filling in the middle. Fold the pastry and brush more butter on the seal part.\",\"4\",\"Heat a frying pan and add in some oil to cook the parcel until its both sides and 4 edges all turn into golden brown. (Or brush melted butter all over the parcel and bake it in 180°C oven for 10-15 minutes)\",\"5\",\"Enjoy\"]},{\"id\":\"g335\",\"title\":\"Nanaimo Bars\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vwuprt1511813703.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Custard\",\"Caster Sugar\",\"Cocoa\",\"Egg\",\"Digestive Biscuits\",\"Desiccated Coconut\",\"Almonds\",\"Butter\",\"Double Cream\",\"Custard Powder\",\"Icing Sugar\",\"Dark Chocolate\",\"Butter\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Start by making the biscuit base. In a bowl, over a pan of simmering water, melt the butter with the sugar and cocoa powder, stirring occasionally until smooth.\",\"instructions\":[\"Start by making the biscuit base. In a bowl, over a pan of simmering water, melt the butter with the sugar and cocoa powder, stirring occasionally until smooth. Whisk in the egg for 2 to 3 mins until the mixture has thickened. Remove from heat and mix in the biscuit crumbs, coconut and almonds if using, then press into the base of a lined 20cm square tin. Chill for 10 mins.\",\"For the middle layer, make the custard icing; whisk together the butter, cream and custard powder until light and fluffy, then gradually add the icing sugar until fully incorporated. Spread over the bottom layer and chill in the fridge for at least 10 mins until the custard is no longer soft.\",\"Melt the chocolate and butter together in the microwave, then spread over the chilled bars and put back in the fridge. Leave until the chocolate has fully set (about 2 hrs). Take the mixture out of the tin and slice into squares to serve.\"]},{\"id\":\"g336\",\"title\":\"Napa Cabbage with Dried Shrimp\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9nh4dl1766435484.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Dried Shrimp\",\"Boiling Water\",\"Napa Cabbage\",\"Peanut Oil\",\"Scallions\",\"Ginger\",\"Soy Sauce\",\"Water\",\"Cornstarch\",\"Kosher Salt\",\"Pepper\"],\"allergens\":[\"soy\",\"peanut\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Dried shrimp gives this Chinese dish a punch of salty umami flavor. You can find it at an Asian grocery store in the frozen or refrigerated section. Look for sm\",\"instructions\":[\"Dried shrimp gives this Chinese dish a punch of salty umami flavor. You can find it at an Asian grocery store in the frozen or refrigerated section. Look for small-sized dried shrimp, about a 1/4-inch in size. If you use medium or large dried shrimp, hydrate the shrimp with more water (1 cup for medium-sized shrimp, 1 1/4 cup for large) and for longer time (45 to 60 minutes), then chop it up into smaller 1/4-inch chunks. To make this recipe vegetarian, omit the dried shrimp and use four or five dried shiitake mushrooms, rehydrated, and sliced thin.\",\"Rehydrate the dried shrimp:\",\"Place the dried shrimp in a small bowl and pour the boiling water over it. Cover with a small plate and let sit for 30 minutes so the shrimp can rehydrate. The shrimp will be lighter in color and plump up slightly.\",\"Prep the cabbage:\",\"Meanwhile, split the napa cabbage in half lengthwise. Rinse the cabbage and shake it dry. Cut out the core of the cabbage and discard.\",\"Set out two large bowls. Cut the remaining cabbage into 1-inch pieces, putting the thicker white pieces at the bottom of the cabbage into one bowl and the top thinner leafy green pieces into the other bowl.\",\"Drain the shrimp:\",\"Once the shrimp has rehydrated, drain it and discard the liquid.\",\"Cook the shrimp and cabbage:\",\"In a large wok or skillet over high heat add the peanut oil, swirling it around to coat the pan.\"]},{\"id\":\"g337\",\"title\":\"Nasi lemak\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wai9bw1619788844.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Coconut Milk\",\"Water\",\"Ginger Paste\",\"Ginger\",\"Bay Leaf\",\"Rice\",\"Eggs\",\"Cucumber\",\"Peanuts\",\"Anchovy Fillet\",\"Vegetable Oil\",\"Onion\",\"Garlic\",\"Shallots\",\"Chilli Powder\",\"Anchovy Fillet\",\"Sugar\",\"Tamarind Paste\"],\"allergens\":[\"egg\",\"milk\",\"peanut\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a medium saucepan over medium heat, stir together coconut milk, water, ground ginger, ginger root, salt, bay leaf, and rice. Cover, and bring to a boil. Redu\",\"instructions\":[\"In a medium saucepan over medium heat, stir together coconut milk, water, ground ginger, ginger root, salt, bay leaf, and rice. Cover, and bring to a boil. Reduce heat, and simmer for 20 to 30 minutes, or until done.\",\"Step 2\",\"Place eggs in a saucepan, and cover with cold water. Bring water to a boil, and immediately remove from heat. Cover, and let eggs stand in hot water for 10 to 12 minutes. Remove eggs from hot water, cool, peel and slice in half. Slice cucumber.\",\"Step 3\",\"Meanwhile, in a large skillet or wok, heat 1 cup vegetable oil over medium-high heat. Stir in peanuts and cook briefly, until lightly browned. Remove peanuts with a slotted spoon and place on paper towels to soak up excess grease. Return skillet to stove. Stir in the contents of one package anchovies; cook briefly, turning, until crisp. Remove with a slotted spoon and place on paper towels. Discard oil. Wipe out skillet.\",\"Step 4\",\"Heat 2 tablespoons oil in the skillet. Stir in the onion, garlic, and shallots; cook until fragrant, about 1 or 2 minutes. Mix in the chile paste, and cook for 10 minutes, stirring occasionally. If the chile paste is too dry, add a small amount of water. Stir in remaining anchovies; cook for 5 minutes. Stir in salt, sugar, and tamarind juice; simmer until sauce is thick, about 5 minutes.\",\"Step 5\",\"Serve the onion and garlic sauce over the warm rice, and top with peanuts, fried anchovies, cucumbers, and eggs.\"]},{\"id\":\"g338\",\"title\":\"New York cheesecake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/swttys1511385853.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Sour Cream\",\"Sugar\",\"Cream Cheese\",\"Caster Sugar\",\"Plain Flour\",\"Lemon Juice\",\"Eggs\",\"Sour Cream\",\"Sour Cream\",\"Caster Sugar\",\"Lemon Juice\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Position an oven shelf in the middle of the oven. Preheat the oven to fan 160C/conventional 180C/gas 4. Line the base of a 23cm springform cake tin with parchme\",\"instructions\":[\"Position an oven shelf in the middle of the oven. Preheat the oven to fan 160C/conventional 180C/gas 4. Line the base of a 23cm springform cake tin with parchment paper. For the crust, melt the butter in a medium pan. Stir in the biscuit crumbs and sugar so the mixture is evenly moistened. Press the mixture into the bottom of the pan and bake for 10 minutes. Cool on a wire rack while preparing the filling.\",\"For the filling, increase the oven temperature to fan 200C/conventional 240C/gas 9. In a table top mixer fitted with the paddle attachment, beat the soft cheese at medium-low speed until creamy, about 2 minutes. With the mixer on low, gradually add the sugar, then the flour and a pinch of salt, scraping down the sides of the bowl and the paddle twice.\",\"Swap the paddle attachment for the whisk. Continue by adding the vanilla, lemon zest and juice. Whisk in the eggs and yolk, one at a time, scraping the bowl and whisk at least twice. Stir the 284ml carton of soured cream until smooth, then measure 200ml/7fl oz (just over 3⁄4 of the carton). Continue on low speed as you add the measured soured cream (reserve the rest). Whisk to blend, but don't over-beat. The batter should be smooth, light and somewhat airy.\",\"Brush the sides of the springform tin with melted butter and put on a baking sheet. Pour in the filling - if there are any lumps, sink them using a knife - the top should be as smooth as possible. Bake for 10 minutes. Reduce oven temperature to fan 90C/conventional 110C/gas 1⁄4 and bake for 25 minutes more. If you gently shake the tin, the filling should have a slight wobble. Turn off the oven and open the oven door for a cheesecake that's creamy in the centre, or leave it closed if you prefer a drier texture. Let cool in the oven for 2 hours. The cheesecake may get a slight crack on top as it cools.\",\"Combine the reserved soured cream with the 142ml carton, the sugar and lemon juice for the topping. Spread over the cheesecake right to the edges. Cover loosely with foil and refrigerate for at least 8 hours or overnight.\",\"Run a round-bladed knife around the sides of the tin to loosen any stuck edges. Unlock the side, slide the cheesecake off the bottom of the tin onto a plate, then slide the parchment paper out from underneath.\"]},{\"id\":\"g339\",\"title\":\"No-Churn Rum Raisin Ice Cream\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/s9qyzd1764790772.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Dark Rum\",\"Raisins\",\"Vanilla Extract\",\"Condensed Milk\",\"Brown Sugar\",\"Ground Cinnamon\",\"Allspice\",\"Heavy Cream\",\"Salt\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Heat the rum in a small saucepan over medium heat until warm (do not boil). Remove from heat and stir in the raisins and vanilla extract. Let the mixture sit fo\",\"instructions\":[\"Heat the rum in a small saucepan over medium heat until warm (do not boil). Remove from heat and stir in the raisins and vanilla extract. Let the mixture sit for at least 30 minutes. After soaking, drain off the extra rum, but keep ¼ cup of the rum and reserve it to mix into your ice cream base.\",\"In a large bowl, whisk together the sweetened condensed milk, dark brown sugar, cinnamon, allspice, salt, and reserved rum (¼ cup). Stir until the brown sugar is fully dissolved.\",\"In a separate bowl, whip the cold heavy cream with an electric mixer until stiff peaks form.\",\"Gently fold the whipped cream into the condensed milk mixture until fully combined, being careful not to deflate the cream. Fold in the drained rum-soaked raisins to distribute them evenly.\",\"Pour the mixture into a loaf pan or freezer-safe container. Smooth the top and cover with plastic wrap or an airtight lid. Freeze for at least 6 hours, or until firm.\",\"Let the ice cream sit at room temperature for 5–10 minutes before scooping for the best texture.\"]},{\"id\":\"g340\",\"title\":\"Noodle bowl salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/zry07j1763779321.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Noodles\",\"Sugar Snap Peas\",\"Sesame Seed Oil\",\"Spring Onions\",\"Coriander\",\"Hot Smoked Flaked Salmon\",\"Pretzels\",\"Soy Sauce\",\"Clear Honey\",\"Lemon Juice\",\"Ground Nut Oil\",\"Garlic\",\"Ginger\"],\"allergens\":[\"soy\",\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nDrop the noodles into a large bowl, then pour over enough boiling water to cover. Tip in the sliced sugar snaps and leave for 4 minutes. Drain in a cola\",\"instructions\":[\"step 1\",\"Drop the noodles into a large bowl, then pour over enough boiling water to cover. Tip in the sliced sugar snaps and leave for 4 minutes. Drain in a colander, put under cold running water to cool off, then drain again. Tip into a bowl and toss in the sesame oil.\",\"step 2\",\"Mix the dressing ingredients. Pile spring onions, coriander and salmon onto the noodles, pour over the dressing and toss everything together. Serve with a pretzel or bread roll.\"]},{\"id\":\"g341\",\"title\":\"Nordic smørrebrød with asparagus and horseradish cream\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8a8fu01762772651.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Creme Fraiche\",\"Horseradish\",\"Lemon Juice\",\"Salt\",\"Pepper\",\"Vegetable Oil\",\"Shallots\",\"Salt\",\"White Asparagus\",\"Asparagus\",\"Rye Bread\",\"Butter\",\"västerbottensost cheese\",\"Dill\",\"Salt\",\"Black Pepper\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"To make the horseradish cream, mix the crème fraîche, grated horseradish, lemon juice, salt and white pepper in a bowl. Refrigerate until serving.\\r\\n\\r\\nTo make th\",\"instructions\":[\"To make the horseradish cream, mix the crème fraîche, grated horseradish, lemon juice, salt and white pepper in a bowl. Refrigerate until serving.\",\"To make the crispy shallots, heat some vegetable oil in a frying pan over a medium heat. Add the sliced shallots and fry until golden brown and crispy.\",\"Remove with a slotted spoon and drain on a plate lined with kitchen paper. Season with a pinch of salt.\",\"To make the open sandwich, bring a large saucepan of salted water to the boil, then blanch half of the asparagus (four white and four green) until tender-crisp, about 2–3 minutes.\",\"Add ice to a bowl of cold water. Use a slotted spoon to remove the asparagus from the boiling water and immediately transfer to the iced water to stop cooking. Thinly slice the remaining asparagus lengthwise to serve raw.\",\"Pre-heat the grill until hot. Spread the rye bread with butter and grill until golden and crisp.\",\"To serve, place the grilled bread slices on serving plates. Arrange both the blanched and raw asparagus on the bread. Drizzle with horseradish cream, then sprinkle grated cheese over the top. Garnish with the crispy shallots and some fresh dill to finish.\"]},{\"id\":\"g342\",\"title\":\"Norwegian Krumkake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/z9g8011763075640.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Sugar\",\"Butter\",\"Cardamom\",\"Nutmeg\",\"Salt\",\"Flour\",\"Water\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"▢\\r\\nWhisk the egg and sugar until the mixture thickens.\\r\\n▢\\r\\nMelt the butter and let it cool slightly, then add the butter to the egg mixture.\\r\\n▢\\r\\nMix in spices a\",\"instructions\":[\"▢\",\"Whisk the egg and sugar until the mixture thickens.\",\"▢\",\"Melt the butter and let it cool slightly, then add the butter to the egg mixture.\",\"▢\",\"Mix in spices and then slowly add the flour while stirring to avoid lumps.\",\"▢\",\"Let the batter rest for at least 30 minutes. This improves the texture of the krumkaker.\",\"▢\",\"Spoon about one heaping tablespoon of batter onto iron and bake. If the batter is too thick, add some water to it.\"]},{\"id\":\"g343\",\"title\":\"Norwegian Potato Lefse\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hxcuj01762772827.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Salt\",\"Sugar\",\"Melted Butter\",\"Heavy Cream\",\"All purpose flour\",\"Flour\",\"Butter\",\"Granulated Sugar\",\"Heavy Cream\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Boil the potatoes. Peel the potatoes while still warm and run them through a potato ricer twice.\\r\\n▢\\r\\nLet the potatoes cool in an uncovered bowl in the fridge.\\r\\n\",\"instructions\":[\"Boil the potatoes. Peel the potatoes while still warm and run them through a potato ricer twice.\",\"▢\",\"Let the potatoes cool in an uncovered bowl in the fridge.\",\"▢\",\"Stir the salt, sugar, melted butter, and cream into the riced potatoes.\",\"▢\",\"Slowly add the flour and knead by hand until you get a good consistency. Don't add more flour than necessary! Roll the dough into a long sausage and divide into about 7 or 8 pieces if using an 18 inch griddle. If using a smaller griddle or frying pan, divide the dough into 10 – 12 pieces.\",\"▢\",\"Roll each piece into a ball and then press into a flat circle, using the edges of your hands to form the dough into a nice circle shape without any cracks. This is important, otherwise you won't get round lefser.\",\"▢\"]},{\"id\":\"g344\",\"title\":\"Nutty Chicken Curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yxsurp1511304301.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Chilli\",\"Ginger\",\"Garlic\",\"Coriander\",\"Sunflower Oil\",\"Chicken Breasts\",\"Peanut Butter\",\"Chicken Stock\",\"Greek Yogurt\"],\"allergens\":[\"milk\",\"peanut\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Finely slice a quarter of the chilli, then put the rest in a food processor with the ginger, garlic, coriander stalks and one-third of the leaves. Whizz to a ro\",\"instructions\":[\"Finely slice a quarter of the chilli, then put the rest in a food processor with the ginger, garlic, coriander stalks and one-third of the leaves. Whizz to a rough paste with a splash of water if needed.\",\"Heat the oil in a frying pan, then quickly brown the chicken chunks for 1 min. Stir in the paste for another min, then add the peanut butter, stock and yogurt. When the sauce is gently bubbling, cook for 10 mins until the chicken is just cooked through and sauce thickened. Stir in most of the remaining coriander, then scatter the rest on top with the chilli, if using. Eat with rice or mashed sweet potato.\"]},{\"id\":\"g345\",\"title\":\"Oatmeal pancakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/c400ok1764439058.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Milk\",\"Sugar\",\"Baking Powder\",\"Salt\",\"Vanilla Extract\",\"Ground Oats\",\"Butter\",\"Sugar Syrup\",\"Strawberries\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Place all the ingredients in the glass and beat.\\r\\nLet the mixture stand for 10 minutes.\\r\\nGrease a hot frying pan with a little butter and pour a little of the m\",\"instructions\":[\"Place all the ingredients in the glass and beat.\",\"Let the mixture stand for 10 minutes.\",\"Grease a hot frying pan with a little butter and pour a little of the mixture.\",\"When it starts to bubble on the surface, turn over with a spatula. Cook over medium-low heat so that they do not burn.\",\"Finally, add the caramel and strawberries.\"]},{\"id\":\"g346\",\"title\":\"Osso Buco alla Milanese\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wwuqvt1487345467.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Veal\",\"Flour\",\"Olive Oil\",\"Butter\",\"Onion\",\"Carrots\",\"Celery\",\"Fennel\",\"Garlic\",\"Orange Zest\",\"Marjoram\",\"Bay Leaf\",\"Dry White Wine\",\"Chicken Stock\",\"Tomatoes\",\"Parsley\",\"Garlic\",\"Lemon Zest\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oven to 300 degrees.\\r\\nDredging the shanks: pour the flour into a shallow dish (a pie plate works nicely). Season the veal shanks on all sides with salt\",\"instructions\":[\"Heat the oven to 300 degrees.\",\"Dredging the shanks: pour the flour into a shallow dish (a pie plate works nicely). Season the veal shanks on all sides with salt and pepper. One at a time, roll the shanks around in the flour coat, and shake and pat the shank to remove any excuses flour. Discard the remaining flour.\",\"Browning the shanks: put the oil and 1 tablespoon of the butter in a wide Dutch oven or heavy braising pot (6 to 7 quart) and heat over medium-high heat. When the butter has melted and the oil is shimmering, lower the shanks into the pot, flat side down; if the shanks won’t fit without touching one another, do this in batches. Brown the shanks, turning once with tongs, until both flat sides are well caramelized, about 5 minutes per side. If the butter-oil mixture starts to burn, lower the heat just a bit. Transfer the shanks to a large platter or tray and set aside.\",\"The aromatics: pour off and discard the fat from the pot. Wipe out any burnt bits with a damp paper towel, being careful not to remove any delicious little caramelized bits. Ad the remaining 2 tablespoons butter to the pot and melt it over medium heat. When the butter has stopped foaming, add the onion, carrot, celery, and fennel. Season with salt and pepper, stir, and cook the vegetables until they begin to soften but do not brown, about 6 minutes. Stir in the garlic, orange zest, marjoram, and bay leaf, and stew for another minute or two.\",\"The braising liquid: add the wine, increase the heat to high, and bring to a boil. Boil, stirring occasionally, to reduce the wine by about half, 5 minutes. Add the stock and tomatoes, with their juice, and boil again to reduce the liquid to about 1 cup total, about 10 minutes.\",\"The braise: Place the shanks in the pot so that they are sitting with the exposed bone facing up, and pour over any juices that accumulated as they sat. Cover with parchment paper, pressing down so the parchment nearly touches the veal and the edges hang over the sides of the pot by about an inch. Cover tightly with the lid, and slide into the lower part of the oven to braise at a gentle simmer. Check the pot after the first 15 minutes, and if the liquid is simmering too aggressively, lower the oven heat by 10 or 15 degrees. Continue braising, turning the shanks and spooning some pan juices over the top after the first 40 minutes, until the meat is completely tender and pulling away from the bone, about 2 hours.\",\"The gremolata: While the shanks are braising, stir together the garlic, parsley, and lemon zest in a small bowl. Cover with plastic wrap and set aside in a cool place (or the refrigerator, if your kitchen is very warm.)\",\"The finish: When the veal is fork-tender and falling away from the bone, remove the lid and sprinkle over half of the gremolata. Return the veal to the oven, uncovered, for another 15 minutes to caramelize it some.\",\"Using a slotted spatula or spoon, carefully lift the shanks from the braising liquid, doing your best to keep them intact. The shanks will be very tender and threatening to fall into pieces, and the marrow will be wobbly inside the bones, so this can be a bit tricky. But if they do break apart, don’t worry, the flavor won’t suffer at all. Arrange the shanks on a serving platter or other large plate, without stacking, and cover with foil to keep warm.\",\"Finishing the sauce: Set the braising pot on top of the stove and evaluate the sauce: if there is a visible layer of fat floating on the surface, use a large spoon to skim it off and discard it. Taste the sauce for concentration of flavor. If it tastes a bit weak or flat, bring it to a boil over high heat, and boil to reduce the volume and intensify the flavor for 5 to 10 minutes. Taste again for salt and pepper. If the sauce wants more zip, stir in a teaspoon or two of the remaining gremolata.\"]},{\"id\":\"g347\",\"title\":\"Oxtail with broad beans\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1520083578.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Oxtail\",\"Onion\",\"Spring Onions\",\"Garlic\",\"Ginger\",\"Scotch Bonnet\",\"Soy Sauce\",\"Fresh Thyme\",\"Vegetable Oil\",\"Water\",\"Broad Beans\",\"Corn Flour\",\"Water\"],\"allergens\":[\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Toss the oxtail with the onion, spring onion, garlic, ginger, chilli, soy sauce, thyme, salt and pepper. Heat the vegetable oil in a large frying pan over mediu\",\"instructions\":[\"Toss the oxtail with the onion, spring onion, garlic, ginger, chilli, soy sauce, thyme, salt and pepper. Heat the vegetable oil in a large frying pan over medium-high heat. Brown the oxtail in the pan until browned all over, about 10 minutes. Place into a pressure cooker, and pour in 375ml water. Cook at pressure for 25 minutes, then remove from heat, and remove the lid according to manufacturer's directions.\",\"Add the broad beans and pimento berries, and bring to a simmer over medium-high heat. Dissolve the cornflour in 2 tablespoons water, and stir into the simmering oxtail. Cook and stir a few minutes until the sauce has thickened, and the broad beans are tender.\"]},{\"id\":\"g348\",\"title\":\"Pad See Ew\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uuuspp1468263334.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"rice stick noodles\",\"dark soy sauce\",\"oyster sauce\",\"soy sauce\",\"white vinegar\",\"sugar\",\"water\",\"peanut oil\",\"garlic\",\"Chicken\",\"Egg\",\"Chinese broccoli\"],\"allergens\":[\"egg\",\"soy\",\"peanut\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix Sauce in small bowl.\\r\\nMince garlic into wok with oil. Place over high heat, when hot, add chicken and Chinese broccoli stems, cook until chicken is light go\",\"instructions\":[\"Mix Sauce in small bowl.\",\"Mince garlic into wok with oil. Place over high heat, when hot, add chicken and Chinese broccoli stems, cook until chicken is light golden.\",\"Push to the side of the wok, crack egg in and scramble. Don't worry if it sticks to the bottom of the wok - it will char and which adds authentic flavour.\",\"Add noodles, Chinese broccoli leaves and sauce. Gently mix together until the noodles are stained dark and leaves are wilted. Serve immediately!\"]},{\"id\":\"g349\",\"title\":\"Pad Thai\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rg9ze01763479093.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Noodles\",\"Lime\",\"Cayenne Pepper\",\"Muscovado Sugar\",\"Fish Sauce\",\"Vegetable Oil\",\"Tiger Prawns\",\"Spring Onions\",\"Bean Sprouts\",\"Peanuts\",\"Coriander\",\"Lime\",\"sweet chilli sauce\"],\"allergens\":[\"peanut\",\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the noodles in a large heatproof bowl, pour boiling water over them and leave for 4 minutes, then drain and refresh under cold running water.\\r\\n\\r\\nste\",\"instructions\":[\"step 1\",\"Put the noodles in a large heatproof bowl, pour boiling water over them and leave for 4 minutes, then drain and refresh under cold running water.\",\"step 2\",\"Put the lime juice, cayenne, sugar and fish sauce in a bowl and mix well. Have all the other ingredients ready by the cooker.\",\"step 3\",\"Heat the oil and fry the prawns until warmed through. Add the spring onions and noodles and toss around. Tip in the lime juice mixture, then stir in the beansprouts and half the peanuts and coriander. Cook for 1 minute until everything is heated through.\",\"step 4\",\"Pile into a large dish, scatter with the rest of the peanuts and coriander, and serve with lime wedges and sweet chilli sauce.\"]},{\"id\":\"g350\",\"title\":\"Padron peppers\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0ljvc51763248075.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Padron peppers\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the olive oil in a large frying pan over a high heat, or if using an air-fryer, heat to 205C for 3 mins. Fry the peppers, stirring frequently, for \",\"instructions\":[\"step 1\",\"Heat the olive oil in a large frying pan over a high heat, or if using an air-fryer, heat to 205C for 3 mins. Fry the peppers, stirring frequently, for 5 mins until blistered and wilted. The peppers should be soft and slightly charred.\",\"step 2\",\"Transfer the peppers to a serving plate and season with some sea salt. Serve with dips or as part of a tapas spread, if you like.\"]},{\"id\":\"g351\",\"title\":\"Paella\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9bl20p1763248192.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Raw tiger prawns\",\"Parsley\",\"Dry sherry\",\"Mussels\",\"Saffron\",\"Chorizo\",\"Onion\",\"Garlic\",\"Squid\",\"Tomato\",\"Paella Rice\",\"Broad Beans\",\"Lemon Zest\"],\"allergens\":[\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat 1 tbsp of the oil in a wide, shallow pan. Add the prawn heads and parsley stalks and sizzle until the heads turn pink, then mash with a potato mash\",\"instructions\":[\"step 1\",\"Heat 1 tbsp of the oil in a wide, shallow pan. Add the prawn heads and parsley stalks and sizzle until the heads turn pink, then mash with a potato masher. Pour over the sherry or wine and 300ml water, season with salt and simmer for 10 mins to make a stock, mashing the prawn heads as they cook.\",\"step 2\",\"Scatter the mussels into the pan, cover the pan loosely with a lid or tea towel, then put over a high heat for 3-4 mins until the mussels just open. Stir to release the mussel juices, then pour the contents of the pan into a colander set over a large bowl containing the saffron. Let the saffron steep in the stock – you will need 700ml in total, so top up with water if needed and give everything a good stir. Pick the mussels out from the colander, then set aside.\",\"step 3\",\"Wipe out the pan and add the rest of the olive oil. Sizzle the chorizo until it releases its oil, then add the onion and garlic and cook until softened. Add the squid and turn over until it turns white. Add the tomatoes and cook down for a minute, then pour over most of the stock, give everything a good stir and bring to the boil. Scatter the rice over the stock, stir well once, then boil vigorously for 5 mins. Reduce the heat to the lowest setting and slowly simmer for 10 mins without stirring until the rice has absorbed most of the liquid.\",\"step 4\",\"Tuck the prawn tails into the rice and simmer for 5 mins, turning them over until cooked through. Stir through the mussels and broad beans or peas. Taste the rice – if it is still a little raw but the pan is dry, add a splash more stock and continue to cook; if it’s too soupy, then increase the heat to cook off the last of the stock.\",\"step 5\",\"Once the rice is just cooked, turn off the heat and cover with a tea towel for a few minutes. Scatter over the parsley leaves and lemon zest, then season with smoked salt if you like. Stir everything once, then serve straight from the pan, with lemon wedges on the side.\"]},{\"id\":\"g352\",\"title\":\"Pan-fried hake, white bean & chorizo broth\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4yjart1763248459.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Dried white beans\",\"Garlic\",\"Bay Leaves\",\"Thyme\",\"Olive Oil\",\"Bread\",\"Chorizo\",\"Onion\",\"Paprika\",\"Chicken Stock\",\"Parsley\",\"Hake\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nDrain the beans, then tip into a large pan with 2 litres of water. Simmer with the whole garlic cloves, bay leaves and thyme for 30 mins or until cooked\",\"instructions\":[\"step 1\",\"Drain the beans, then tip into a large pan with 2 litres of water. Simmer with the whole garlic cloves, bay leaves and thyme for 30 mins or until cooked and tender. Remove from the heat and set aside.\",\"step 2\",\"Meanwhile, heat 2 tbsp oil in a frying pan. Fry the bread with the remaining garlic clove. When golden and crisp, scoop out and drain on kitchen paper. Add the chorizo to the pan, fry until crisp, tip out and keep warm with the bread.\",\"step 3\",\"Add another 2 tbsp oil and the onion to the pan, and cook for 5 mins until softened. Stir in the paprika. Drain the beans and add to the onions with the chicken stock and 2 tsp salt. Cook for 5-10 mins. Stir through the parsley and keep warm.\",\"step 4\",\"Season the hake and heat the remaining 2 tbsp oil in the frying pan. Put the hake, skin-side down, in the pan and cook for 3-5 mins over a mediumhigh heat to crisp up the skin. Flip the fish over and cook for a further 3-5 mins until cooked through. Spoon the white bean mix into bowls, place the hake on top and finish with the fried bread, chorizo and a little more thyme.\"]},{\"id\":\"g353\",\"title\":\"Panang chicken curry (kaeng panang gai)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0dhtwr1763371444.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Coconut Milk\",\"Panang Curry Paste\",\"Chicken Breast\",\"Green Beans\",\"Fish Sauce\",\"Brown Sugar\",\"makrut lime leaves\",\"Basil Leaves\",\"Jasmine Rice\",\"Red Chilli\",\"Dried Red Chillies\",\"Shrimp Paste\",\"Garlic\",\"Galangal\",\"Lemongrass\",\"Lime\",\"Ground Nutmeg\",\"Ground Coriander\",\"Ground Cumin\",\"Peanuts\"],\"allergens\":[\"milk\",\"peanut\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nFirst, make the curry paste. Use a pestle and mortar to pound together the dried and fresh chillies, shrimp paste, garlic, galangal, lemongrass, lime ze\",\"instructions\":[\"step 1\",\"First, make the curry paste. Use a pestle and mortar to pound together the dried and fresh chillies, shrimp paste, garlic, galangal, lemongrass, lime zest, white pepper, coriander, cumin, nutmeg and peanuts, plus 1 tsp salt. You should have a rough paste. Alternatively, add all the ingredients to a food processor along with 2-3 tbsp of coconut milk and pulse until you have a paste. Store in a lidded jar in the fridge. Will keep for up to two weeks.\",\"step 2\",\"Add 2-3 tbsp of the thick part of the coconut milk into a saucepan over a medium-high heat. When the coconut milk starts bubbling, add 1-2 tbsp of the curry paste and stir well for about 1 min, until fragrant.\",\"step 3\",\"Stir in the chicken and let it cook for about 3-4 mins until beginning to brown all over. Follow with the French beans and stir well.\",\"step 4\",\"Season with the fish sauce and sugar, then add the rest of coconut milk. Mix well, add half the makrut lime leaves and simmer for 3-5 mins until the chicken is cooked through. Taste and add more sugar or fish sauce if necessary – it should be salty and nutty, and the sweetness should come through. Add the Thai basil leaves, give it a quick mix and take off the heat. Serve with steamed jasmine rice, garnished with the sliced chilli and the rest of the makrut lime leaves.\"]},{\"id\":\"g354\",\"title\":\"Pancakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rwuyqx1511383174.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Eggs\",\"Milk\",\"Sunflower Oil\",\"Sugar\",\"Raspberries\",\"Blueberries\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Put the flour, eggs, milk, 1 tbsp oil and a pinch of salt into a bowl or large jug, then whisk to a smooth batter. Set aside for 30 mins to rest if you have tim\",\"instructions\":[\"Put the flour, eggs, milk, 1 tbsp oil and a pinch of salt into a bowl or large jug, then whisk to a smooth batter. Set aside for 30 mins to rest if you have time, or start cooking straight away.\",\"Set a medium frying pan or crêpe pan over a medium heat and carefully wipe it with some oiled kitchen paper. When hot, cook your pancakes for 1 min on each side until golden, keeping them warm in a low oven as you go.\",\"Serve with lemon wedges and sugar, or your favourite filling. Once cold, you can layer the pancakes between baking parchment, then wrap in cling film and freeze for up to 2 months.\"]},{\"id\":\"g355\",\"title\":\"Parkin Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qxuqtt1511724269.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Egg\",\"Milk\",\"Golden Syrup\",\"Black Treacle\",\"Brown Sugar\",\"Oatmeal\",\"Self-raising Flour\",\"Ground Ginger\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 160C/140C fan/gas 3. Grease a deep 22cm/9in square cake tin and line with baking parchment. Beat the egg and milk together with a fork.\\r\\n\\r\\nGently m\",\"instructions\":[\"Heat oven to 160C/140C fan/gas 3. Grease a deep 22cm/9in square cake tin and line with baking parchment. Beat the egg and milk together with a fork.\",\"Gently melt the syrup, treacle, sugar and butter together in a large pan until the sugar has dissolved. Remove from the heat. Mix together the oatmeal, flour and ginger and stir into the syrup mixture, followed by the egg and milk.\",\"Pour the mixture into the tin and bake for 50 mins - 1 hr until the cake feels firm and a little crusty on top. Cool in the tin then wrap in more parchment and foil and keep for 3-5 days before eating if you can – it’ll become softer and stickier the longer you leave it, up to 2 weeks.\"]},{\"id\":\"g356\",\"title\":\"Passion fruit mousse\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/gkcdpl1764441325.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Unflavoured Gelatin\",\"Passion Fruit Pulp\",\"Sugar\",\"Condensed Milk\",\"Egg White\",\"Mint\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add gelatin and ¼ cup room-temperature water to small bowl; let sit until gelatin softens, about 5 minutes. In medium saucepan over medium-high heat, stir toget\",\"instructions\":[\"Add gelatin and ¼ cup room-temperature water to small bowl; let sit until gelatin softens, about 5 minutes. In medium saucepan over medium-high heat, stir together passion fruit pulp, sugar and gelatin mixture. Cook, stirring occasionally, until mixture is thoroughly combined and smooth (mixture should not come to a boil). Remove from heat; cool completely. Stir in condensed milk.\",\"Meanwhile, in clean mixing bowl, using electric mixer, beat egg whites until stiff (peaks of egg whites will not droop, and egg whites will not move when bowl is tilted).\",\"Stir 1/3 egg whites into cooled passion fruit mixture until combined. Using spatula, gently fold in remaining egg whites until combined. Divide mousse evenly among clear glass serving cups; cover. Refrigerate mousse until well chilled, at least 2 hrs.\",\"Serve chilled. Garnish with mint, if desired.\"]},{\"id\":\"g357\",\"title\":\"Paszteciki (Polish Pasties)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/c9a3l31593261890.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Salt\",\"Egg\",\"Egg\",\"Butter\",\"Butter\",\"Onion\",\"Swede\",\"Beef Brisket\",\"Eggs\",\"Salt\",\"Pepper\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Sift flour and salt into a large mixing bowl.\\r\\nUse a spoon to push the egg yolk through a fine sieve into the flour.\\r\\nAdd the raw egg and mix well.\\r\\nBeat in but\",\"instructions\":[\"Sift flour and salt into a large mixing bowl.\",\"Use a spoon to push the egg yolk through a fine sieve into the flour.\",\"Add the raw egg and mix well.\",\"Beat in butter 1 tablespoon at a time.\",\"Place dough on a floured surface and knead until smooth and elastic, then wrap in waxed paper and refrigerate until firm (at least 30 minutes).\",\"In a heavy skillet, melt 2 tablespoons butter over medium heat; saute the onion and rutabaga until the onion is soft and transparent (5 minutes).\",\"Put the onions, rutabaga, and beef through a meat grinder twice if you have one, if not just chop them up as fine as possible.\",\"Melt the remaining 4 tablespoons butter over medium heat, and add the meat mixture.\",\"Cook over low heat, stirring occasionally, until all of the liquid has evaporated and the mixture is thick enough to hold its shape.\",\"Remove from heat and let cool, then stir in 1 egg, and season with salt and pepper.\"]},{\"id\":\"g358\",\"title\":\"Patatas bravas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/bvg8sn1763298713.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Garlic\",\"Tinned Tomatos\",\"Tomato Puree\",\"Paprika\",\"Chilli Powder\",\"Sugar\",\"Parsley\",\"Potatoes\",\"Olive Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oil in a pan and fry the onion for about 5 mins until softened. Add the garlic, chopped tomatoes, tomato purée, sweet paprika, chilli powder, s\",\"instructions\":[\"step 1\",\"Heat the oil in a pan and fry the onion for about 5 mins until softened. Add the garlic, chopped tomatoes, tomato purée, sweet paprika, chilli powder, sugar and a pinch of salt, then bring to the boil, stirring occasionally. Lower to a simmer and cook for 10 mins until pulpy. Can be kept chilled for up to 24 hrs.\",\"step 2\",\"Heat oven to 200C/180C fan/gas 6. Pat the potatoes dry with kitchen paper, then tip into a roasting tin and toss in the olive oil and some seasoning. Roast for 40-50 mins until crisp and golden. Tip the potatoes into serving dishes and spoon over the tomato sauce. Sprinkle with some fresh parsley to serve.\"]},{\"id\":\"g359\",\"title\":\"Pate Chinois\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yyrrxr1511816289.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Butter\",\"Milk\",\"Minced Beef\",\"Onion\",\"Creamed Corn\",\"Paprika\",\"Parsley\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a large pot of salted water, cook the potatoes until they are very tender. Drain.\\r\\nWith a masher, coarsely crush the potatoes with at least 30 ml (2 tablespo\",\"instructions\":[\"In a large pot of salted water, cook the potatoes until they are very tender. Drain.\",\"With a masher, coarsely crush the potatoes with at least 30 ml (2 tablespoons) of butter. With an electric mixer, purée with the milk. Season with salt and pepper. Set aside.\",\"With the rack in the middle position, preheat the oven to 190 °C (375 °F).\",\"In a large skillet, brown the onion in the remaining butter. Add the meat and cook until golden brown. Season with salt and pepper. Remove from the heat.\",\"Lightly press the meat at the bottom of a 20-cm (8-inch) square baking dish. Cover with the corn and the mashed potatoes. Sprinkle with paprika and parsley.\",\"Bake for about 30 minutes. Finish cooking under the broiler. Let cool for 10 minutes.\"]},{\"id\":\"g360\",\"title\":\"Peach & Blueberry Grunt\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ssxvup1511387476.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Corn Flour\",\"Orange\",\"Orange\",\"Caster Sugar\",\"Peaches\",\"Blueberries\",\"Self-raising Flour\",\"Butter\",\"Muscovado Sugar\",\"Cinnamon\",\"Milk\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 190C/170C fan/gas 5. Butter a wide shallow ovenproof dish. Blend the cornflour with the orange zest and juice, and put in a large pan with the suga\",\"instructions\":[\"Heat oven to 190C/170C fan/gas 5. Butter a wide shallow ovenproof dish. Blend the cornflour with the orange zest and juice, and put in a large pan with the sugar. Halve, stone and slice the peaches and add to the pan. Bring slowly to the boil, stirring gently until the sauce is shiny and thickened, about 3-4 mins. Remove from the heat, stir in the blueberries and tip into the prepared dish.\",\"Tip the flour into a mixing bowl and add the 50g butter. Rub the butter into the flour until it resembles fine breadcrumbs, then stir in half the sugar. Mix the remaining sugar with the cinnamon and set aside.\",\"Add the milk to the dry ingredients and mix to a soft dough. Turn out onto a lightly floured surface and knead briefly. Roll out to an oblong roughly 16 x 24cm. Brush with melted butter and sprinkle evenly with the spicy sugar. Roll up from one long side and cut into 12 slices. Arrange around the top of the dish, leaving the centre uncovered.\",\"Bake for 20-25 mins, until the topping is crisp and golden. Serve warm.\"]},{\"id\":\"g361\",\"title\":\"Peanut Butter Cheesecake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qtuuys1511387068.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Peanut Cookies\",\"Gelatine Leafs\",\"Ricotta\",\"Peanut Butter\",\"Golden Syrup\",\"Milk\",\"Double Cream\",\"Light Brown Soft Sugar\",\"Peanut Brittle\"],\"allergens\":[\"milk\",\"peanut\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Oil and line a 20cm round loose- bottomed cake tin with cling film, making it as smooth as possible. Melt the butter in a pan. Crush the biscuits by bashing the\",\"instructions\":[\"Oil and line a 20cm round loose- bottomed cake tin with cling film, making it as smooth as possible. Melt the butter in a pan. Crush the biscuits by bashing them in a bag with a rolling pin, then stir them into the butter until very well coated. Press the mixture firmly into the base of the tin and chill.\",\"Soak the gelatine in water while you make the filling. Tip the ricotta into a bowl, then beat in the peanut butter and syrup. Ricotta has a slightly grainy texture so blitz until smooth with a stick blender for a smoother texture if you prefer.\",\"Take the soaked gelatine from the water and squeeze dry. Put it into a pan with the milk and heat very gently until the gelatine dissolves. Beat into the peanut mixture, then tip onto the biscuit base. Chill until set.\",\"To freeze, leave in the tin and as soon as it is solid, cover the surface with cling film, then wrap the tin with cling film and foil.\",\"To defrost, thaw in the fridge overnight.\",\"To serve, carefully remove from the tin. Whisk the cream with the sugar until it holds its shape, then spread on top of the cheesecake and scatter with the peanut brittle.\"]},{\"id\":\"g362\",\"title\":\"Peanut Butter Cookies\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1544384070.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Peanut Butter\",\"Sugar\",\"Egg\"],\"allergens\":[\"egg\",\"milk\",\"peanut\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 350ºF (180ºC).\\r\\nIn a large bowl, mix together the peanut butter, sugar, and egg.\\r\\nScoop out a spoonful of dough and roll it into a ball. Place t\",\"instructions\":[\"Preheat oven to 350ºF (180ºC).\",\"In a large bowl, mix together the peanut butter, sugar, and egg.\",\"Scoop out a spoonful of dough and roll it into a ball. Place the cookie balls onto a nonstick baking sheet.\",\"For extra decoration and to make them cook more evenly, flatten the cookie balls by pressing a fork down on top of them, then press it down again at a 90º angle to make a criss-cross pattern.\",\"Bake for 8-10 minutes or until the bottom of the cookies are golden brown.\",\"Remove from baking sheet and cool.\",\"Enjoy!\"]},{\"id\":\"g363\",\"title\":\"Pear Tarte Tatin\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rxvxrr1511797671.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pears\",\"Caster Sugar\",\"Butter\",\"Star Anise\",\"Cardamom\",\"Cinnamon\",\"Brandy\",\"Puff Pastry\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Core the pears, then peel as neatly as possible and halve. If you like, they can be prepared up to a day ahead and kept in the fridge, uncovered, so that they d\",\"instructions\":[\"Core the pears, then peel as neatly as possible and halve. If you like, they can be prepared up to a day ahead and kept in the fridge, uncovered, so that they dry out.\",\"Tip the sugar, butter, star anise, cardamom and cinnamon into an ovenproof frying pan, about 20cm wide, and place over a high heat until bubbling. Shake the pan and stir the buttery sauce until it separates and the sugar caramelises to a toffee colour.\",\"Lay the pears in the pan, then cook in the sauce for 10-12 mins, tossing occasionally, until completely caramelised. Don’t worry about them burning – they won’t – but you want to caramelise them as much as possible. Splash in the brandy and let it flambé, then set the pears aside.\",\"Heat oven to 200C/fan 180C/gas 6. Roll the pastry out to the thickness of a £1 coin. Using a plate slightly larger than the top of the pan, cut out a circle, then press the edges of the circle of pastry to thin them out.\",\"When the pears have cooled slightly, arrange them in the pan, cut side up, in a floral shape, with the pears around the edge pointing inwards. Rest the cinnamon stick on the top in the centre, with the cardamom pods scattered around.\",\"Drape the pastry over the pears, then tuck the edges down the pan sides and under the fruit (see Gordon’s guide). Pierce the pastry a few times, then bake for 15 mins. If a lot of juice bubbles up the side of the pan, pour it off at this stage (see guide). Reduce oven to 180C/fan 160C/gas 4 and bake for 15 mins more until the pastry is golden. Leave the tart to stand for 10 mins, then invert it carefully onto a serving dish.\"]},{\"id\":\"g364\",\"title\":\"Piernik (Polish gingerbread)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kwmdk41764120884.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Unsalted Butter\",\"Clear Honey\",\"Brown Sugar\",\"Self-raising Flour\",\"Ground Ginger\",\"Ground Cinnamon\",\"Ground Clove\",\"Ground Nutmeg\",\"Pepper\",\"Egg\",\"Plum Jam\",\"Double Cream\",\"Dark Chocolate\",\"Clear Honey\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 160C/140C fan/gas 3. Grease and line the base and sides of a deep 20cm cake tin with baking parchment. Put the honey, sugar and butter in a medium \",\"instructions\":[\"Heat oven to 160C/140C fan/gas 3. Grease and line the base and sides of a deep 20cm cake tin with baking parchment. Put the honey, sugar and butter in a medium saucepan and cook over a medium heat until fully melted. Remove from the heat and allow to cool. Put the flour and spices in a large bowl and mix everything together.\",\"step 2\",\"Once the liquid ingredients have cooled, whisk in the eggs. Pour over the dry ingredients, whisking them together to form a smooth batter – be careful not to overmix as this can lead to a dry cake. Pour into the prepared tin and bake for 50-55 mins or until risen and a skewer inserted into the middle of the cake comes out clean. Allow the cake to cool in the pan for 20 mins before turning out onto a wire rack to cool completely.\",\"step 3\",\"Once cooled, use a large serrated knife to slice the cake into 3 layers. Spread the jam across the 2 bottom cake layers, then reassemble the cake and set aside while you make the glaze. Put the cream, chocolate and honey in a medium pan and cook over a low-medium heat until the chocolate is melted and you have a smooth, pourable mixture. Put the cake on a wire rack set over a parchment-lined baking tray and pour over the glaze, making sure to cover the entire cake. Use a fish slice to carefully transfer the cake to a serving plate and allow the glaze to set. To decorate, dust with a little edible gold powder, if you like. Uniced, this cake will keep for up to 5 days. Once iced, enjoy within 3 days – just keep in the fridge, but remove before serving and eat at room temperature.\"]},{\"id\":\"g365\",\"title\":\"Pierogi (Polish Dumplings)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/45xxr21593348847.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Chopped Onion\",\"Sauerkraut\",\"Butter\",\"Chopped Onion\",\"Potatoes\",\"Eggs\",\"Sour Cream\",\"Flour\",\"Salt\",\"Baking Powder\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To prepare the sauerkraut filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Add the draine\",\"instructions\":[\"To prepare the sauerkraut filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Add the drained sauerkraut and cook for an additional 5 minutes. Season to taste with salt and pepper, then remove to a plate to cool.\",\"For the mashed potato filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Stir into the mashed potatoes, and season with salt and white pepper.\",\"To make the dough, beat together the eggs and sour cream until smooth. Sift together the flour, salt, and baking powder; stir into the sour cream mixture until dough comes together. Knead the dough on a lightly floured surface until firm and smooth. Divide the dough in half, then roll out one half to 1/8 inch thickness. Cut into 3 inch rounds using a biscuit cutter.\",\"Place a small spoonful of the mashed potato filling into the center of each round. Moisten the edges with water, fold over, and press together with a fork to seal. Repeat procedure with the remaining dough and the sauerkraut filling.\",\"Bring a large pot of lightly salted water to a boil. Add perogies and cook for 3 to 5 minutes or until pierogi float to the top. Remove with a slotted spoon.\"]},{\"id\":\"g366\",\"title\":\"Pilchard puttanesca\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vvtvtr1511180578.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Spaghetti\",\"Olive Oil\",\"Onion\",\"Garlic\",\"Red Chilli\",\"Tomato Puree\",\"Pilchards\",\"Black Olives\",\"Parmesan\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Cook the pasta following pack instructions. Heat the oil in a non-stick frying pan and cook the onion, garlic and chilli for 3-4 mins to soften. Stir in the tom\",\"instructions\":[\"Cook the pasta following pack instructions. Heat the oil in a non-stick frying pan and cook the onion, garlic and chilli for 3-4 mins to soften. Stir in the tomato purée and cook for 1 min, then add the pilchards with their sauce. Cook, breaking up the fish with a wooden spoon, then add the olives and continue to cook for a few more mins.\",\"Drain the pasta and add to the pan with 2-3 tbsp of the cooking water. Toss everything together well, then divide between plates and serve, scattered with Parmesan.\"]},{\"id\":\"g367\",\"title\":\"Piri-piri chicken and slaw\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hglsbl1614346998.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken\",\"Red Chilli\",\"Garlic\",\"Ginger\",\"Dried Oregano\",\"Coriander\",\"Paprika\",\"Red Wine Vinegar\",\"Oil\",\"Red Onions\",\"Carrots\",\"Beetroot\",\"Cabbage\",\"Mayonnaise\",\"Greek Yogurt\",\"Red Wine Vinegar\",\"Cumin Seeds\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\n\\r\\nWhizz together all of the marinade ingredients in a small food processor. Rub the marinade onto the chicken and leave for 1 hour at room temperature.\\r\",\"instructions\":[\"STEP 1\",\"Whizz together all of the marinade ingredients in a small food processor. Rub the marinade onto the chicken and leave for 1 hour at room temperature.\",\"STEP 2\",\"Heat the oven to 190C/fan 170C/gas 5. Put the chicken in a roasting tray and cook for 1 hour 20 minutes. Rest under loose foil for 20 minutes. While the chicken is resting, mix together the slaw ingredients and season. Serve the chicken with slaw, fries and condiments.\"]},{\"id\":\"g368\",\"title\":\"Pistachio cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xvgpng1764121726.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Pistachio\",\"Plain Flour\",\"Baking Powder\",\"Caster Sugar\",\"Egg\",\"Vanilla Extract\",\"Icing Sugar\",\"Mascarpone\",\"Double Cream\",\"Pistachio Paste\",\"Raspberries\",\"Unwaxed Lime\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oven to 180C/160C fan/gas 4. Butter and line a 23cm springform cake tin. Tip 150g of the pistachios into a food processor and blitz until finely ground\",\"instructions\":[\"Heat the oven to 180C/160C fan/gas 4. Butter and line a 23cm springform cake tin. Tip 150g of the pistachios into a food processor and blitz until finely ground. Tip into a bowl and mix in the flour, baking powder and pinch of salt. Beat the butter and sugar in a separate bowl until fluffy and pale, around 5 mins. Crack in the eggs one at a time, beating well for 1 min after each addition, until they have all been added. Beat in the vanilla, then fold in the flour mixture gently. Carefully spoon into the prepared tin and bake for 35-40 mins until a skewer inserted into the middle comes out clean. Set aside to cool completely on a wire rack in the tin.\",\"step 2\",\"Meanwhile, sift the icing sugar into a bowl, then tip in the mascarpone, double cream and pistachio paste. Beat until well combined, then set aside in the fridge for 20-30 mins to thicken to a spooning consistency.\",\"step 3\",\"Cut the cooled cake in half horizontally using a serrated knife, so you have two layers. Put the bottom layer on a plate or cake stand and spread over a generous spoonful of the pistachio cream. Top with a generous handful of the raspberries so the cake is covered. Top with the other sponge half, then cover the top and sides of the cake with the remaining cream. Scatter over the last of the raspberries, the remaining pistachios and the lime zest to serve. Will keep chilled in an airtight container for two days.\"]},{\"id\":\"g369\",\"title\":\"Pistachio Kunafa Chocolate Cake and Cupcakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yh3sg71763741307.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"White Chocolate\",\"Unsalted Pistachio\",\"Condensed Milk\",\"Milk\",\"Oreo Cream Biscuits\",\"Milk\",\"Baking Powder\",\"Vinegar\",\"Salt\",\"Sevaiiya\",\"Ghee\",\"Dark Chocolate\",\"Malai\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1\\r\\nFor Chocolate Cake:Ready all the ingredients. Powder the oreo biscuits, pinch salt and mix warm milk as needed and make a cake batter. Add in baking powder a\",\"instructions\":[\"1\",\"For Chocolate Cake:Ready all the ingredients. Powder the oreo biscuits, pinch salt and mix warm milk as needed and make a cake batter. Add in baking powder and vinegar and mix.\",\"2\",\"Grease a loose bottomed tin. Pour a 1cm thick layer of the batter.\",\"3\",\"Bake in a preheated oven @160°C for 7-8 minutes or until the knife comes out clean. Cool on wire rack.\",\"4\",\"For Homemade Pistachio Paste:Ready all the pistachio paste ingredients. Slightly melt white chocolate on a double boiler.(else the mixer blade may break) Coarsely powder the pistachio in mixer. Add in condensed milk.\",\"5\",\"Add in slightly warmed and slightly melted white chocolate and milk as required and crush to a smooth paste.(Green food colour can be add. I haven't.)\"]},{\"id\":\"g370\",\"title\":\"Pisto con huevos\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0nswfe1763279040.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Garlic Clove\",\"Mixed peppers\",\"Oregano\",\"Thyme\",\"Bay Leaves\",\"Courgettes\",\"Aubergine\",\"Tomato\",\"Egg\",\"Parsley\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oil in a large flameproof casserole dish or a cast-iron skillet over a low heat. Add the onions and a sprinkle of salt, cover and cook gently f\",\"instructions\":[\"step 1\",\"Heat the oil in a large flameproof casserole dish or a cast-iron skillet over a low heat. Add the onions and a sprinkle of salt, cover and cook gently for 15 mins, stirring occasionally. Add the garlic and cook for another 2 mins.\",\"step 2\",\"Next, throw in the peppers and cook over a medium heat, covered, for about 5 mins, stirring every so often, until the peppers are just tender.\",\"step 3\",\"Mix in the oregano, thyme, bay leaves, some black pepper and a little salt, if needed. Tip in the courgettes and aubergine, combine thoroughly, and cook over a medium heat, covered, for 10 mins. Stir in the tomatoes, cover and cook for 20 mins, stirring occasionally.\",\"step 4\",\"Carefully crack the eggs over the pisto – try not to break the yolks. Cook in the sauce on a medium heat for 5-6 mins until the eggs are cooked through but still a little soft, then scatter with parsley before serving\"]},{\"id\":\"g371\",\"title\":\"Pizza Express Margherita\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/x0lk931587671540.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Sugar\",\"Yeast\",\"Plain Flour\",\"Salt\",\"Olive Oil\",\"Passata\",\"Mozzarella\",\"Oregano\",\"Basil\",\"Black Pepper\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"1 Preheat the oven to 230°C.\\r\\n\\r\\n2 Add the sugar and crumble the fresh yeast into warm water.\\r\\n\\r\\n3 Allow the mixture to stand for 10 – 15 minutes in a warm place\",\"instructions\":[\"1 Preheat the oven to 230°C.\",\"2 Add the sugar and crumble the fresh yeast into warm water.\",\"3 Allow the mixture to stand for 10 – 15 minutes in a warm place (we find a windowsill on a sunny day works best) until froth develops on the surface.\",\"4 Sift the flour and salt into a large mixing bowl, make a well in the middle and pour in the yeast mixture and olive oil.\",\"5 Lightly flour your hands, and slowly mix the ingredients together until they bind.\",\"6 Generously dust your surface with flour.\",\"7 Throw down the dough and begin kneading for 10 minutes until smooth, silky and soft.\",\"8 Place in a lightly oiled, non-stick baking tray (we use a round one, but any shape will do!)\",\"9 Spread the passata on top making sure you go to the edge.\",\"10 Evenly place the mozzarella (or other cheese) on top, season with the oregano and black pepper, then drizzle with a little olive oil.\"]},{\"id\":\"g372\",\"title\":\"Polish chocolate & walnut cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/e8ihjp1764123021.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Coco Sugar\",\"Egg\",\"Caster Sugar\",\"Egg White\",\"Caster Sugar\",\"Walnuts\",\"Plain Flour\",\"Potato Starch\",\"Double Cream\",\"Chocolate Chips\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oven to 170C/150C fan/gas 3½. Line a 30 x 22cm shallow baking tin with baking parchment. Sift the flour and mix it with cocoa, then set aside. Beat the\",\"instructions\":[\"Heat the oven to 170C/150C fan/gas 3½. Line a 30 x 22cm shallow baking tin with baking parchment. Sift the flour and mix it with cocoa, then set aside. Beat the egg whites until stiff, then add the sugar to them in small batches. Add the egg yolks, one by one, whisking constantly. Tip in the flour mixture and gently fold everything together with a spatula. Pour the prepared batter into the lined tin and bake for 35 mins. Cool for 5 mins, remove from the tin and re-line the tin with baking parchment.\",\"step 2\",\"To make the meringue, whisk the whites until stiff, then gradually whisk in the sugar, one tablespoon at a time. When you have a stiff and shiny meringue, fold in the finely chopped walnuts, flour and startch. Spread the mixture into the re-lined tin and cook for 40 mins on the same heat. Remove from the oven and leave to cool.\",\"step 3\",\"For the chocolate glaze, heat the cream over low heat, then remove from the heat, pour the chopped chocolate into it and mix it until it melts and becomes shiny.\",\"step 4\",\"Cut the cooled chocolate sponge cake and meringue into two layers. Put the nut meringue on top of the bottom layer of sponge and sprinkle on some of the reserved walnuts. Add another layer of meringue and then the upper layer of chocolate sponge cake and cover the top with chocolate glaze. Decorate with walnuts. Put the finished cake in the fridge for 1-2 hrs before serving.\"]},{\"id\":\"g373\",\"title\":\"Polish doughnuts (Pączki)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/x6jqog1764359857.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Yeast\",\"Caster Sugar\",\"Flour\",\"Milk\",\"Egg Yolks\",\"Sugar\",\"Caster Sugar\",\"Vanilla Extract\",\"Flour\",\"Double Cream\",\"Butter\",\"Jam\",\"Ground Almonds\",\"Oil\",\"Icing Sugar\",\"Lemon\",\"Almond Essence\",\"Almonds\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make the leaven, mix the yeast with the sugar and flour, and stir in the warm milk. Set aside in a warm place for 30 minutes.\\r\\n\\r\\nstep 2\\r\\nFor the doug\",\"instructions\":[\"step 1\",\"To make the leaven, mix the yeast with the sugar and flour, and stir in the warm milk. Set aside in a warm place for 30 minutes.\",\"step 2\",\"For the dough, put egg yolks into a heatproof bowl and add the sugar and vanilla sugar. Set the bowl over a pan of simmering water and whisk until smooth and thick.\",\"step 3\",\"Sift the flour into the bowl of a stand mixer, add the beaten yolks and the warm cream, mix thoroughly, then add a pinch of salt and the leaven. Bring together to make a dough and knead for 10 minutes (or 15-20 if doing this by hand).\",\"step 4\",\"When the dough stops sticking to your hands, pour in the cooled melted butter and knead for a few more minutes. Cover with a cloth and leave in a warm place to rise for at least 1 hr-1 hr 30 mins.\",\"step 5\",\"Mix the jam with the ground almonds and spoon into a piping bag or jam syringe. Divide the dough into 16 pieces and shape them into doughnuts. Cover and leave to rise for 30 mins.\"]},{\"id\":\"g374\",\"title\":\"Polish patties (kotlety)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vvn5f71764360273.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Bread Rolls\",\"Milk\",\"Onion\",\"Vegetable Oil\",\"Ground Beef\",\"Egg\",\"Garlic Clove\",\"Marjoram\",\"Breadcrumbs\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nSoak the bread roll in the milk so it softens completely. Meanwhile, fry the onion in the oil for around 8 mins or until soft and golden. Add the fried \",\"instructions\":[\"step 1\",\"Soak the bread roll in the milk so it softens completely. Meanwhile, fry the onion in the oil for around 8 mins or until soft and golden. Add the fried onion to the beef mince along with the egg, garlic, marjoram and some seasoning. Squeeze the excess milk from the bread roll and add it to the mince mixture. Mix everything together and season well.\",\"step 2\",\"Divide the meat into 8 patties. Tip the dried breadcrumbs into a shallow bowl and coat the patties in it, all over. Heat some oil in a deep frying pan and fry the patties in batches on both sides until browned and cooked through, about 6-7 mins on each side.\"]},{\"id\":\"g375\",\"title\":\"Pollo en pepitoria\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/li30ck1763281992.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Saffron\",\"Extra Virgin Olive Oil\",\"Garlic Clove\",\"Almonds\",\"Stale bread\",\"Parsley\",\"Chicken Thighs\",\"Onion\",\"Carrots\",\"Celery\",\"Dry sherry\",\"Chicken Stock\",\"Cinnamon Stick\",\"Cloves\",\"Bay Leaves\",\"Egg\",\"Almonds\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the saffron in a small bowl with 75ml of just-boiled water. Stir and set aside. Heat 2 tbsp of the oil in a broad, shallow casserole dish. Cook the \",\"instructions\":[\"step 1\",\"Put the saffron in a small bowl with 75ml of just-boiled water. Stir and set aside. Heat 2 tbsp of the oil in a broad, shallow casserole dish. Cook the garlic until pale gold in colour, then add the blanched almonds and bread, and continue to fry until everything is golden. Tip into a food processor with some salt and pepper and the parsley, and whizz together.\",\"step 2\",\"Heat 2 more tbsp of the oil in the pan and brown the chicken all over, seasoning as you cook. Put in a bowl and set aside.\",\"step 3\",\"Remove all but about 2 tbsp of chicken fat from the pan and cook the onion, carrot and celery until golden. Add the sherry, stirring to dislodge any brown bits that have stuck to the pan. Pour in the stock and the saffron (with its water), and bring to the boil, then turn the heat down to a simmer. Add the spices and bay leaves, and put the chicken back in the pan with any juices. Season and gently cook the chicken for about 40 mins with the lid on.\",\"step 4\",\"Transfer the chicken to a bowl again, leaving the sauce in the pan, and cover with foil to keep warm. Remove the yolks from the eggs and roughly chop the whites. Mash the egg yolks in a small bowl and gradually mix in a couple of tbsp of the sauce. Bring the remaining sauce to the boil to reduce a bit (you want it to just coat the chicken), then turn the heat down. Remove the bay and cinnamon stick. Add the egg yolks and cook for a few mins until the mixture has thickened. Stir in the almond mixture that you made earlier (this will thicken the sauce, too). Put the chicken back in the pan and heat it for about 3 mins, spooning the sauce over it. Season to taste.\",\"step 5\",\"Scatter over the extra parsley, the almonds pieces and the chopped egg whites (if you’re going to use them). You can serve this straight from the dish with some rice, if you like.\"]},{\"id\":\"g376\",\"title\":\"Polskie Nalesniki (Polish Pancakes)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/58bkyo1593350017.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Eggs\",\"Milk\",\"Water\",\"Salt\",\"Sugar\",\"Butter\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add flour, eggs, milk, water, and salt in a large bowl then mix with a hand mixer until you have a smooth, lump-free batter.\\r\\nAt this point, mix in the butter o\",\"instructions\":[\"Add flour, eggs, milk, water, and salt in a large bowl then mix with a hand mixer until you have a smooth, lump-free batter.\",\"At this point, mix in the butter or the vegetable oil. Alternatively, you can use them to grease the pan before frying each pancake.\",\"Heat a non-stick pan over medium heat, then pour in the batter, swirling the pan to help it spread.\",\"When the pancake starts pulling away a bit from the sides, and the top is no longer wet, flip it and cook shortly on the other side as well.\",\"Transfer to a plate. Cook the remaining batter until all used up.\",\"Serve warm, with the filling of your choice.\"]},{\"id\":\"g377\",\"title\":\"Pomegranate salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/fqpqml1764359125.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Lemon Juice\",\"Honey\",\"Thyme\",\"Baby Lettuce Leaves\",\"Cherry Tomatoes\",\"Spring Onions\",\"Red Chilli\",\"Pomegranate\",\"Feta\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nCombine the olive oil, lemon juice, honey and thyme leaves in a large bowl. Season well, then tip in the lettuce, tomatoes, spring onions and chilli, an\",\"instructions\":[\"step 1\",\"Combine the olive oil, lemon juice, honey and thyme leaves in a large bowl. Season well, then tip in the lettuce, tomatoes, spring onions and chilli, and toss to combine.\",\"step 2\",\"Scoop out the pomegranate seeds over a bowl and remove any white membrane. Arrange the dressed salad on a platter, then scatter over the pomegranate seeds and feta.\"]},{\"id\":\"g378\",\"title\":\"Pork & sauerkraut goulash\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/cyuhwp1764362103.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lard\",\"Onion\",\"Cumin Seeds\",\"Pork Shoulder\",\"Garlic\",\"Plain Flour\",\"Paprika\",\"Beef Stock\",\"Bay Leaves\",\"White Sauerkraut\",\"Whipping Cream\",\"Sour Cream\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the lard in a saucepan over a medium heat and fry the finely chopped onion until golden, around 5-8 mins. Tip in the cumin and pork, and fry for 10\",\"instructions\":[\"step 1\",\"Heat the lard in a saucepan over a medium heat and fry the finely chopped onion until golden, around 5-8 mins. Tip in the cumin and pork, and fry for 10 mins all over until browned. Add the garlic, season well and scatter over the flour. Cook for about a minute, then add the paprika and cook for 1 min more.\",\"step 2\",\"Pour in half of the stock, add the bay leaves, and simmer with the lid on over a low heat for 30 mins.\",\"step 3\",\"Add the sauerkraut, remaining stock and a drizzle of the sauerkraut pickling juices. Simmer with the lid for 30 mins, stirring occasionally, until the meat is tender. Stir in the cream and simmer for 5 mins to combine the flavours. Season to taste, the serve garnished with a spoonful of soured cream.\",\"This recipe has been provided by Apetit Online and not been re-tested by us.\"]},{\"id\":\"g379\",\"title\":\"Pork Cassoulet\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wxuvuv1511299147.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Goose Fat\",\"Pork\",\"Onion\",\"Garlic\",\"Carrots\",\"Fennel Seeds\",\"Red Wine Vinegar\",\"Vegetable Stock\",\"Tomato Puree\",\"Rosemary\",\"Parsley\",\"Haricot Beans\",\"Breadcrumbs\",\"Oil\",\"Bread\",\"Broccoli\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 140C/120C fan/gas 1. Put a large ovenproof pan (with a tight-fitting lid) on a high heat. Add your fat and diced meat, cook for a few mins to seal \",\"instructions\":[\"Heat oven to 140C/120C fan/gas 1. Put a large ovenproof pan (with a tight-fitting lid) on a high heat. Add your fat and diced meat, cook for a few mins to seal the edges, giving it a quick stir to cook evenly. Reduce the heat to low, add the sliced onion, whole garlic cloves, carrot and fennel seeds, and cook gently to soften the veg for a few mins.\",\"Pour over the red wine vinegar, scraping any meaty bits off the bottom of the pan. Add the stock, tomato purée, and half the rosemary and parsley. Bring to the boil and simmer for 10 mins, then season, cover with a lid and put into the oven for 2 hrs, removing the lid for the final hour of cooking. Stir occasionally and add the beans with 30 mins to go.\",\"Remove the pan from the oven and heat the grill. Scatter the top with the remaining herbs and breadcrumbs, drizzle a little oil over the top, and return to the oven for 5-10 mins, until the breadcrumbs are golden. Serve with crusty bread and green veg.\"]},{\"id\":\"g380\",\"title\":\"Pork rib bortsch\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/om5hsl1764364721.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pork Back Ribs\",\"Bay Leaves\",\"Dried white beans\",\"Carrots\",\"Onion\",\"Garlic Clove\",\"Red Pepper\",\"Red Chilli\",\"Beetroot\",\"Potatoes\",\"Tomato Puree\",\"White Cabbage\",\"Parsley\",\"Dill\",\"Sour Cream\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nCut the meat into large pieces, put in your largest saucepan and cover with 5 litres water. Bring to the boil over a high heat, skimming away any foam t\",\"instructions\":[\"step 1\",\"Cut the meat into large pieces, put in your largest saucepan and cover with 5 litres water. Bring to the boil over a high heat, skimming away any foam that rises to the surface. Add the bay leaves. Season. Turn the heat down to a simmer and cook for 1 hr, or until the meat is soft and falls off the bone. Add the beans if using dried.\",\"step 2\",\"Turn the heat up. Bring back to the boil, then reduce the heat and simmer for another 20 mins – the beans should still be slightly raw. Add the carrots, onions, garlic and pepper. Stir well, then add the chillies, if using. Cook for 15 mins more.\",\"step 3\",\"Stir in the beetroot and cook for 10 mins before adding the potatoes. After 15 mins, add the tomato purée to taste and beans, if using canned, and bring to the boil. Cook for 5 mins, add the cabbage and cook for 5 mins more. Season, then garnish with the parsley and dill. Turn off the heat and leave to stand for 5 mins. Serve with soured cream on the side.\"]},{\"id\":\"g381\",\"title\":\"Portuguese barbecued pork (Febras assadas)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/cybyue1614349443.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pork\",\"White Wine\",\"Paprika\",\"Lemon\",\"Lemon Juice\",\"Olive Oil\",\"Mayonnaise\",\"Potatoes\",\"Vegetable Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"STEP 1\\r\\n\\r\\nCut the tenderloins into 5 equal-size pieces leaving the tail ends a little longer. Take a clear plastic bag and slip one of the pieces in. Bash it in\",\"instructions\":[\"STEP 1\",\"Cut the tenderloins into 5 equal-size pieces leaving the tail ends a little longer. Take a clear plastic bag and slip one of the pieces in. Bash it into an escalope the size of a side-plate with a rolling pin and repeat with the remaining pieces.\",\"STEP 2\",\"Put the wine, paprika, some salt and pepper and the juice of ½ a lemon in a bowl and add the pork. Leave to marinate for 20-30 minutes, while you get your barbecue to the stage where the coals are glowing but there are no flames.\",\"STEP 3\",\"To make the chips, fill a basin with cool water and cut the potatoes into 3cm-thick chips. Soak them in the water for 5 minutes and then change the water. Leave for 5 more minutes. Drain and then pat dry on a towel or with kitchen paper.\",\"STEP 4\",\"Heat the oil in a deep fryer or a deep heavy-based pan with a lid to 130C and lower the chips into the oil (in batches). Blanch for 8-10 minutes. Remove from the oil and drain well. Place on a tray to cool. Reheat the oil to 180C (make sure it’s hot or your chips will be soggy) and lower the basket of chips into the oil (again, do this in batches). Leave to cook for 2 minutes and then give them a little shake. Cook for another minute or so until they are well coloured and crisp to the touch. Drain well for a few minutes, tip into a bowl and sprinkle with sea salt.\",\"STEP 5\",\"The pork will cook quickly so do it in 2 batches. Take the pieces out of the marinade, rub them with oil, and drop them onto the barbecue (you could also use a chargrill). Cook for 1 minute on each side – they may flare up as you do so. This should really be enough time as they will keep on cooking. Take them off the barbecue and pile onto a plate. Repeat with the remaining batch.\"]},{\"id\":\"g382\",\"title\":\"Portuguese custard tarts\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vmz7gl1614350221.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Icing Sugar\",\"Puff Pastry\",\"Caster Sugar\",\"Lemon Zest\",\"Cinnamon\",\"Eggs\",\"Egg Yolks\",\"Corn Flour\",\"Whole Milk\",\"Vanilla\",\"Cinnamon\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\nRoll the pastry\\r\\nMix the flour and icing sugar, and use this to dust the work surface. Roll the pastry out to make a 45 x 30cm rectangle. Roll up length\",\"instructions\":[\"STEP 1\",\"Roll the pastry\",\"Mix the flour and icing sugar, and use this to dust the work surface. Roll the pastry out to make a 45 x 30cm rectangle. Roll up lengthways to create a long sausage shape.\",\"STEP 2\",\"Cutting pastry into rounds\",\"Cut the pastry into 24 wheels, about 1-2cm thick.\",\"STEP 3\",\"Roll out each pastry portion\",\"Roll each wheel lightly with the rolling pin to fit 2 x 12-hole non-stick fairy cake tins.\",\"STEP 4\"]},{\"id\":\"g383\",\"title\":\"Portuguese fish stew (Caldeirada de peixe)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/do7zps1614349775.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onions\",\"Red Pepper\",\"Coriander\",\"Red Chilli\",\"Garlic\",\"Dry White Wine\",\"Saffron\",\"Bay Leaf\",\"Potatoes\",\"Plum Tomatoes\",\"Cod\",\"Squid\",\"Tiger Prawns\",\"Clams\",\"Mussels\",\"Baguette\"],\"allergens\":[\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"STEP 1\\r\\n\\r\\nHeat a drizzle of oil in a large, deep-sided frying pan, and fry the onion and pepper on a medium heat until softened but not browned. Finely chop the\",\"instructions\":[\"STEP 1\",\"Heat a drizzle of oil in a large, deep-sided frying pan, and fry the onion and pepper on a medium heat until softened but not browned. Finely chop the coriander stalks (keep the leaves for later), and add to the pan with the chilli and chopped garlic. Fry for another few minutes. Add the wine, saffron and bay leaf and let it simmer until reduced by half.\",\"STEP 2\",\"Add the potatoes, tomatoes, and 300ml water and bring to a gentle boil. Break up the tomatoes with a spoon on the side of the pan and simmer for 20-25 minutes until the potatoes are just tender, and the tomatoes have broken down.\",\"STEP 3\",\"Season well, then gently push the fish into the sauce, and arrange the squid, prawns, clams and mussels on the surface. Put the lid on and cook for 6-8 minutes until the mussel and clam shells have opened, the prawns are cooked and the fish is flaky. Toast the bread, rub lightly with the halved garlic clove and drizzle with olive oil. Serve the stew scatted with chopped coriander leaves, and the toasts for dunking.\"]},{\"id\":\"g384\",\"title\":\"Portuguese prego with green piri-piri\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ewcikl1614348364.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Garlic\",\"Beef Fillet\",\"Olive Oil\",\"Vinegar\",\"Parsley\",\"Ciabatta\",\"Rocket\",\"Basil Leaves\",\"Parsley\",\"Jalapeno\",\"Vinegar\",\"Spring Onions\",\"Garlic\",\"Caster Sugar\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\n\\r\\nRub the garlic over the steaks then put in a sandwich bag and tip in the olive oil, sherry vinegar and parsley stalks. Smoosh everything together, the\",\"instructions\":[\"STEP 1\",\"Rub the garlic over the steaks then put in a sandwich bag and tip in the olive oil, sherry vinegar and parsley stalks. Smoosh everything together, then use a rolling pin to bash the steaks a few times. Leave for 1-2 hours.\",\"STEP 2\",\"To make the sauce, put all the ingredients into a blender with 1 tbsp water and whizz until as smooth as possible. This will make more than you’ll need for the recipe but will keep for a week in an airtight jar.\",\"STEP 3\",\"Heat a griddle or frying pan to high. Brush away the garlic and parsley stalks from the steaks and season well. Sear the steaks for 2 minutes on each side then rest on a plate. Put the ciabatta halves onto the plate, toasted-side down, to soak up any juices.\",\"STEP 4\",\"Slice the steaks then stuff into the rolls with the green sauce and rocket.\"]},{\"id\":\"g385\",\"title\":\"Postre Chajá\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wii0591764375062.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Sugar\",\"Salt\",\"All purpose flour\",\"Cornstarch\",\"Egg White\",\"Sugar\",\"Dulce de leche\",\"Heavy Cream\",\"Vanilla Extract\",\"Sugar\",\"Peaches\",\"Peach Juice\",\"Cornstarch\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the sponge cake preheat oven to 180 degrees Celsius and prepare either one or two 20cm/8 inch cake pan(s). Line bottom with parchment paper. Then divide the\",\"instructions\":[\"For the sponge cake preheat oven to 180 degrees Celsius and prepare either one or two 20cm/8 inch cake pan(s). Line bottom with parchment paper. Then divide the eggs into egg white and egg yolks. Use a bigger bowl for the egg yolks. If you have a glass or metal bowl, use that one for the egg whites. Be sure that bowl is free of fat/grease and that your mixer was properly cleaned. First beat the egg whites on medium speed with a pinch of salt until soft peaks form. Set aside. Without cleaning our mixer, beat the egg yolks with the sugar. Beat until the color becomes much paler and you have a creamy consistency. This usually takes several minutes.\",\"2\",\"Gently pour one third of the egg whites on top of the mixed egg yolks and sift the flour and cornstarch on top. Don't skip this step. It is important that the flour mix was sifted. Gently mix all ingredients with a spatula. Try to incorperate the flour mix and egg whites without losing volume. Add the last two thirds of beaten egg whites and gently fold the mixture. Don't overmix. Put batter into the prepared cake pans and immediately bake. Don't let the batter sit for too long as it will quickly lose volume. Bake for 35 minutes if using one springform or 25 minutes if using two. Let cool a little before gently getting them out of the form. Tip: if making the day before, wrap in cling wrap, it is much easier to cut in half once cold.\",\"3\",\"For the meringue beat egg white until soft peaks form, add pinch of salt and continue beating on high while adding the sugar. Beat for at least three more minutes until glossy and shiny. Pipe small stars or other shapes with the meringue on a baking sheet lined with parchment paper. Dry for about 45min at 100 degrees Celsius in the oven. Keep in airtight container until further use.\",\"4\",\"For the filling beat heavy cream, vanilla extract and sugar until stiff peaks form, slice peaches in thin slices. Cut cake in four layers, this is much easier done once the cake layers are cold. Brush cake layer with some of the peach juice left, then pipe thin layer of whipped cream around the edges, place the peach slices in the middle on first layer on cake, on the second layer only spread the dulce de leche. Repeat layer with brushed peach juice, whipped cream and peaches for the third and final layer. Be sure to reserve enough peach slices for the top. Spread thin layer of whipped cream on the sides of the cake and pipe on some roses around the edges if desired. Heat the peach juice and mix the cornstarch with a bit of water until you see no lumps. Once juice is hot, add the cornstarch and stir until glaze thickenes. Pour over peaches of the top layer cake. Crush the meringue and pat around the sides. Serve immediately.\"]},{\"id\":\"g386\",\"title\":\"Potato Gratin with Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qwrtut1468418027.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Onions\",\"Olive Oil\",\"Chicken Stock\",\"Creme Fraiche\",\"Parmesan\",\"Chicken Breasts\",\"Bacon\",\"Spinach\",\"Peas\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"15 minute potato gratin with chicken and bacon greens: a gratin always seems more effort and more indulgent than ordinary boiled or roasts, but it doesn't have \",\"instructions\":[\"15 minute potato gratin with chicken and bacon greens: a gratin always seems more effort and more indulgent than ordinary boiled or roasts, but it doesn't have to take 45mins, it's nice for a change and you can control the calorie content by going with full fat to low fat creme fraiche.\",\"(It's always tastes better full fat though obviously!) to serve 4: use 800g of potatoes, finely slice and boil in a pan for about 5-8 mins till firmish, not soft.\",\"Finely slice 3 onions and place in an oven dish with 2 tblsp of olive oil and 100ml of chicken stock.\",\"Cook till the onions are soft then drain the potatoes and pour onto the onions.\",\"Season and spoon over cream or creme fraiche till all is covered but not swimming.\",\"Grate Parmesan over the top then finish under the grill till nicely golden.\",\"serve with chicken and bacon, peas and spinach.\"]},{\"id\":\"g387\",\"title\":\"Potato Salad (Olivier Salad)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ebvuir1699013665.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Carrots\",\"Salt\",\"White Wine Vinegar\",\"Eggs\",\"Sausages\",\"Dill\",\"Peas\",\"Onions\",\"Mayonnaise\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cut the potatoes and carrots into small uniform cubes.\\r\\nPlace them in a large pot and fill with water.\\r\\nAdd salt and vinegar. Bring it to a boil over medium hig\",\"instructions\":[\"Cut the potatoes and carrots into small uniform cubes.\",\"Place them in a large pot and fill with water.\",\"Add salt and vinegar. Bring it to a boil over medium high heat, and then reduce the heat to medium and continue to cook until the potatoes are cooked through, about 15 minutes. Drain the potatoes and let it cool to room temperature.\",\"Meanwhile, cut the sausage and pickles into small cubes, and chop the green onions.\",\"Cut the hard-boiled eggs into small cubes as well.\",\"If using fresh dill, chop them as well.\",\"In a large bowl, combine potatoes, carrots, sausage, pickles, peas and green onions.\",\"Add mayo and dill and mix until well combined.\",\"Salt and pepper to taste. Cover with a plastic wrap and refrigerate for at least 1 hour before serving.\"]},{\"id\":\"g388\",\"title\":\"Pouding chomeur\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yqqqwu1511816912.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Sugar\",\"Eggs\",\"Vanilla Extract\",\"Flour\",\"Baking Powder\",\"Milk\",\"Maple Syrup\",\"Brown Sugar\",\"Single Cream\",\"Butter\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a large bowl, with an electric mixer, mix the butter and sugar till the mix is light.\\r\\nAdd eggs and vanilla and mix.\\r\\nIn another bowl, mix flour and baking p\",\"instructions\":[\"In a large bowl, with an electric mixer, mix the butter and sugar till the mix is light.\",\"Add eggs and vanilla and mix.\",\"In another bowl, mix flour and baking powder.\",\"Alternate flour mix and milk to the butter mix.\",\"Pour into a 13 inch by 9 inch greased pan.\",\"MAPLE SAUCE.\",\"In a large casserole, bring to boil the syrup, brown sugar, cream and butter and constantly stir.\",\"Reduce heat and and gently cook 2 minutes or till sauce has reduced a little bit.\",\"Pour sauce gently over cake.\",\"Bake at 325°f (160°c) about 35 minutes or till cake is light brown and when toothpick inserted comes out clean.\"]},{\"id\":\"g389\",\"title\":\"Poulet Roti a l'Algerienne (Algerian Roast Chicken)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/nlxald1764112200.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Onion\",\"Olive Oil\",\"Balsamic Vinegar\",\"Dijon Mustard\",\"Garlic\",\"Black Pepper\",\"Cayenne Pepper\",\"Salt\",\"Chicken\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 350 degrees F (175 degrees C).\\r\\n\\r\\nMix water, onion, olive oil, balsamic vinegar, Dijon mustard, garlic, black pepper, cayenne pepper, and salt t\",\"instructions\":[\"Preheat oven to 350 degrees F (175 degrees C).\",\"Mix water, onion, olive oil, balsamic vinegar, Dijon mustard, garlic, black pepper, cayenne pepper, and salt together in a roasting dish. Add chicken; turn until well coated with mixture.\",\"Bake in the preheated oven until an instant-read thermometer inserted into the thickest part of the thigh, near the bone, reads 165 degrees F (74 degrees C), about 1 hour 30 minutes.\"]},{\"id\":\"g390\",\"title\":\"Poutine\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uuyrrx1487327597.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Beef Gravy\",\"Potatoes\",\"Cheese Curds\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oil in a deep fryer or deep heavy skillet to 365°F (185°C).\\r\\nWarm gravy in saucepan or microwave.\\r\\nPlace the fries into the hot oil, and cook until light b\",\"instructions\":[\"Heat oil in a deep fryer or deep heavy skillet to 365°F (185°C).\",\"Warm gravy in saucepan or microwave.\",\"Place the fries into the hot oil, and cook until light brown, about 5 minutes.\",\"Remove to a paper towel lined plate to drain.\",\"Place the fries on a serving platter, and sprinkle the cheese over them.\",\"Ladle gravy over the fries and cheese, and serve immediately.\"]},{\"id\":\"g391\",\"title\":\"Prawn & Fennel Bisque\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rtwwvv1511799504.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tiger Prawns\",\"Olive Oil\",\"Onion\",\"Fennel\",\"Carrots\",\"Dry White Wine\",\"Brandy\",\"Chopped Tomatoes\",\"Fish Stock\",\"Paprika\",\"Double Cream\",\"Prawns\"],\"allergens\":[\"milk\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Shell the prawns, then fry the shells in the oil in a large pan for about 5 mins. Add the onion, fennel and carrots and cook for about 10 mins until the veg sta\",\"instructions\":[\"Shell the prawns, then fry the shells in the oil in a large pan for about 5 mins. Add the onion, fennel and carrots and cook for about 10 mins until the veg start to soften. Pour in the wine and brandy, bubble hard for about 1 min to drive off the alcohol, then add the tomatoes, stock and paprika. Cover and simmer for 30 mins. Meanwhile, chop the prawns.\",\"Blitz the soup as finely as you can with a stick blender or food processor, then press through a sieve into a bowl. Spend a bit of time really working the mixture through the sieve as this will give the soup its velvety texture.\",\"Tip back into a clean pan, add the prawns and cook for 10 mins, then blitz again until smooth. You can make and chill this a day ahead or freeze it for 1 month. Thaw ovenight in the fridge. To serve, gently reheat in a pan with the cream. If garnishing, cook the 8 prawns in a little butter. Spoon into small bowls and top with the prawns and snipped fennel fronds.\"]},{\"id\":\"g392\",\"title\":\"Prawn & noodle salad with crispy shallots\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0iryz91763778419.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Noodles\",\"Prawns\",\"Red Onions\",\"Red Chilli\",\"Cucumber\",\"Coriander\",\"Mint\",\"Roasted Peanut\",\"Lime\",\"Brown Sugar\",\"Fish Sauce\",\"Garlic\",\"Shallots\",\"Vegetable Oil\",\"Flour\"],\"allergens\":[\"peanut\",\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nFor the crispy shallots, heat 5cm of oil until hot in a wok. You will know the oil is hot enough when one piece of shallot sizzles as soon as it’s dropp\",\"instructions\":[\"step 1\",\"For the crispy shallots, heat 5cm of oil until hot in a wok. You will know the oil is hot enough when one piece of shallot sizzles as soon as it’s dropped in. Toss the shallot slices with flour, shake off excess and fry in the oil until golden. They fry quickly, about 1 min. Drain on kitchen paper, sprinkle with salt and set aside.\",\"step 2\",\"To make the dressing, mix the lime juice, sugar, fish sauce and garlic and set aside. In a large mixing bowl, pour boiling water over the noodles. Leave them for 2 mins or until they are just cooked, then rinse under cold water. Drain well, shaking the sieve numerous times to get out the excess water, then place back in the bowl. Add prawns, onion, chilli, cucumber and herbs. Pour the dressing over, mix, then sprinkle with the shallots and peanuts.\"]},{\"id\":\"g393\",\"title\":\"Prawn stir-fry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/96lt871763480970.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Raw tiger prawns\",\"Green Chilli\",\"Garlic\",\"Coriander\",\"Caster Sugar\",\"Lime\",\"Fish Sauce\",\"Ground Nut Oil\",\"Ginger\",\"Spring Onions\",\"Red Pepper\",\"Water Chestnut\",\"Bean Sprouts\",\"Soy Sauce\",\"Rice Noodles\",\"Lime\"],\"allergens\":[\"soy\",\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the prawns in a bowl. Put the chilli, garlic, coriander stalks (snip these up using scissors first) and caster sugar in a spice grinder or small foo\",\"instructions\":[\"step 1\",\"Put the prawns in a bowl. Put the chilli, garlic, coriander stalks (snip these up using scissors first) and caster sugar in a spice grinder or small food processor and whizz together. Add half of the lime juice and the fish sauce, then pour this over the prawns.\",\"step 2\",\"Heat 1 tbsp oil in a wok, add the ginger and spring onions and fry for 1 min. Add the red pepper and fry for 1 min, until the pepper starts to soften. Add the water chestnuts and bean sprouts, and toss together until the bean sprouts start to wilt. Add the soy sauce and a really good grind of black pepper, then tip the lot into a serving dish.\",\"step 3\",\"Heat the remaining oil in the wok and add the prawns, lifting them out of their juices. Toss for 1-2 mins until they turn pink, add the marinade and swirl the wok quickly, then tip the lot onto the veg. Snip over the coriander leaves and sprinkle on the remaining lime. Serves over noodles with extra lime for squeezing over.\"]},{\"id\":\"g394\",\"title\":\"Prawns with Romesco sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/u03xhi1763308917.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Pepper\",\"Garlic Clove\",\"Red Chilli\",\"Tomato\",\"Shelled Hazelnuts\",\"Almonds\",\"Parsley\",\"Bread\",\"Olive Oil\",\"Red Wine Vinegar\",\"Tiger Prawns\"],\"allergens\":[\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPrepare ahead - halve the pepper lengthways and remove the seeds and stalk. Line a grill pan with foil and put the pepper halves, skin side up, on the g\",\"instructions\":[\"step 1\",\"Prepare ahead - halve the pepper lengthways and remove the seeds and stalk. Line a grill pan with foil and put the pepper halves, skin side up, on the grill pan with the whole garlic cloves, chilli and tomato. Grill for 2 minutes, turn the tomato, then grill for a further 2 minutes. Remove the tomato with a large spoon, then peel, quarter and remove the seeds. Then chop the tomato roughly.\",\"step 2\",\"Continue grilling the pepper, chilli and garlic for 4-5 minutes, until the pepper and chilli skins have blackened and the garlic is starting to soften (the garlic skin will start to split when it is ready). When cool enough to handle, peel and halve the chilli, and scrape out and discard the seeds. Peel the pepper and roughly chop both the pepper and chilli.\",\"step 3\",\"Spread nuts over the foil and grill until toasted. Finely chop the nuts and parsley in a food processor. Tip into a small bowl.\",\"step 4\",\"Heat 3 tablespoons of oil in a frying pan, add the pepper, garlic and chilli and fry for 3 minutes. Tear up the bread and add to the pan, turning it in the oil until lightly browned. Pulse in food processor with the tomatoes, salt, vinegar and oil until roughly chopped. Tip into a bowl. Leave to cool and store in fridge for up to 3 days.\",\"step 5\",\"On the day add the nuts and parsley to the sauce and mix. Serve in a small bowl on a plate with the peeled prawns. Supply cocktail sticks for spearing the prawns.\"]},{\"id\":\"g395\",\"title\":\"Provençal Omelette Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qwtrtp1511799242.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Eggs\",\"Olive Oil\",\"Courgettes\",\"Spring Onions\",\"Red Pepper\",\"Garlic Clove\",\"Red Chilli\",\"Cream Cheese\",\"Milk\",\"Chives\",\"Basil\",\"Rocket\",\"Parmesan\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Break the eggs into two bowls, five in each. Whisk lightly and season with salt and pepper. Heat the oil in a pan, add the courgettes and spring onions, then fr\",\"instructions\":[\"Break the eggs into two bowls, five in each. Whisk lightly and season with salt and pepper. Heat the oil in a pan, add the courgettes and spring onions, then fry gently for about 10 mins until softened. Cool, then stir into one bowl of eggs with a little salt and pepper. Add the roasted peppers to the other bowl of eggs with the garlic, chilli, salt and pepper.\",\"Heat a little oil in a 20-23cm frying pan, preferably non-stick. Pour the eggs with courgette into a measuring jug, then pourabout one-third of the mixture into the pan, swirling it to cover the base of the pan. Cook until the egg is set and lightly browned underneath, then cover the pan with a plate and invert the omelette onto it. Slide it back into the pan to cook the other side. Repeat with the remaining mix to make two more omelettes, adding a little oil to the pan each time. Stack the omelettes onto a plate. Make three omelettes in the same way with the red pepper mixture, then stack them on a separate plate.\",\"Now make the filling. Beat the cheese to soften it, then beat in the milk to make a spreadable consistency. Stir in the herbs, salt and pepper. Line a deep, 20-23cm round cake tin with cling film (use a tin the same size as the frying pan). Select the best red pepper omelette and place in the tin, prettiest side down. Spread with a thin layer of cheese filling, then cover with a courgette omelette. Repeat, alternating the layers, until all the omelettes and filling are in the tin, finishing with an omelette. Flip the cling film over the omelette, then chill for up to 24 hrs.\",\"To serve, invert the omelette cake onto a serving plate and peel off the cling film. Pile rocket on the top and scatter over the cheese, a drizzle of olive oil and a little freshly ground black pepper. Serve cut into wedges.\"]},{\"id\":\"g396\",\"title\":\"Pumpkin Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/usuqtp1511385394.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pumpkin\",\"Shortcrust Pastry\",\"Plain Flour\",\"Caster Sugar\",\"Salt\",\"Nutmeg\",\"Cinnamon\",\"Eggs\",\"Butter\",\"Milk\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Place the pumpkin in a large saucepan, cover with water and bring to the boil. Cover with a lid and simmer for 15 mins or until tender. Drain pumpkin; let cool.\",\"instructions\":[\"Place the pumpkin in a large saucepan, cover with water and bring to the boil. Cover with a lid and simmer for 15 mins or until tender. Drain pumpkin; let cool.\",\"Heat oven to 180C/160C fan/gas 4. Roll out the pastry on a lightly floured surface and use it to line a 22cm loose-bottomed tart tin. Chill for 15 mins. Line the pastry with baking parchment and baking beans, then bake for 15 mins. Remove the beans and paper, and cook for a further 10 mins until the base is pale golden and biscuity. Remove from the oven and allow to cool slightly.\",\"Increase oven to 220C/200C fan/gas 7. Push the cooled pumpkin through a sieve into a large bowl. In a separate bowl, combine the sugar, salt, nutmeg and half the cinnamon. Mix in the beaten eggs, melted butter and milk, then add to the pumpkin purée and stir to combine. Pour into the tart shell and cook for 10 mins, then reduce the temperature to 180C/160C fan/gas 4. Continue to bake for 35-40 mins until the filling has just set.\",\"Leave to cool, then remove the pie from the tin. Mix the remaining cinnamon with the icing sugar and dust over the pie. Serve chilled.\"]},{\"id\":\"g397\",\"title\":\"Purple sprouting broccoli tempura with nuoc cham\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xnv4wf1763756529.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Corn Flour\",\"Plain Flour\",\"Sesame Seed\",\"Vegetable Oil\",\"Soda Water\",\"Purple Sprouting Broccoli\",\"Fish Sauce\",\"Lime\",\"Birds-eye Chillies\",\"Sugar\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nFor the nuoc cham, whisk together all of the ingredients with 5 tbsp hot water in a small bowl. Set aside while you make the tempura.\\r\\n\\r\\nstep 2\\r\\nWhisk t\",\"instructions\":[\"step 1\",\"For the nuoc cham, whisk together all of the ingredients with 5 tbsp hot water in a small bowl. Set aside while you make the tempura.\",\"step 2\",\"Whisk the cornflour, plain flour, sesame seeds (if using) and a large pinch of salt together. Fill a large, deep pan no more than a third full with the vegetable oil and heat until it reaches 180C or a cube of bread dropped in browns in 20 seconds.\",\"step 3\",\"Quickly whisk the soda water into the flour mixture, being careful not to overmix, then dunk in the broccoli using tongs. Carefully lower into the hot oil and cook for 2-3 mins until crisp. Drain on kitchen paper, then serve with the nuoc cham on the side for dipping.\"]},{\"id\":\"g398\",\"title\":\"Quick gazpacho\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/h5qmn31763304965.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Passata\",\"Red Pepper\",\"Red Chilli\",\"Garlic\",\"Sherry vinegar\",\"Lime\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nIn a blender (or with a stick blender), whizz together the passata, red pepper, chilli, garlic, sherry vinegar and lime juice until smooth. Season to ta\",\"instructions\":[\"step 1\",\"In a blender (or with a stick blender), whizz together the passata, red pepper, chilli, garlic, sherry vinegar and lime juice until smooth. Season to taste, then serve with ice cubes\"]},{\"id\":\"g399\",\"title\":\"Quick salt & pepper squid\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/cp74zo1762341241.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Squid\",\"Oil\",\"Chinese five spice powder\",\"Sesame Seed Oil\",\"Coriander\",\"sweet chilli sauce\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nAsk the fishmonger to clean the squid; little ones often come ready-cleaned. Using kitchen scissors, cut open the body and open out. Wash well, then pat\",\"instructions\":[\"step 1\",\"Ask the fishmonger to clean the squid; little ones often come ready-cleaned. Using kitchen scissors, cut open the body and open out. Wash well, then pat dry. If you have a large squid, cut the body into four portions, roughly square. Small squid can just be opened up.\",\"step 2\",\"Using the tip of a very sharp knife, score the top in a neat criss-cross. Brush with oil and set aside while you heat the barbecue or griddle until ready to cook.\",\"step 3\",\"Mix together 2 tsp sea salt, Chinese five-spice and 1 tsp freshly ground black pepper. Sprinkle on both sides of the squid just before cooking, according to taste. You may not need it all. Heat the griddle pan to hot and cook about 1 min each side, until it starts to curl. Remove with tongs to a serving plate and drizzle with a little sesame oil. To serve, garnish with coriander leaves and serve with small bowls of sweet chilli sauce to dip into.\"]},{\"id\":\"g400\",\"title\":\"Ramen Noodles with Boiled Egg\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ip5xtp1769779958.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Noodles\",\"Water\",\"Egg\",\"Soy Sauce\",\"Chilli Sauce\",\"Spring Onions\",\"Salt\",\"Pepper\"],\"allergens\":[\"egg\",\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Boil: Bring water to a boil, gently add eggs, and cook for exactly 6½ to 7 minutes.\\r\\nIce Bath: Immediately transfer the eggs to a bowl of ice water for 3–5 minu\",\"instructions\":[\"Boil: Bring water to a boil, gently add eggs, and cook for exactly 6½ to 7 minutes.\",\"Ice Bath: Immediately transfer the eggs to a bowl of ice water for 3–5 minutes to stop cooking.\",\"Marinate (Optional but recommended): Peel the eggs and marinate in a mix of 2 tbsp soy sauce, 2 tbsp mirin, 1 tsp sugar, and 4 tbsp water for at least 4 hours (or overnight).\",\"Serve: Slice in half, letting the yolk flow into the broth\"]},{\"id\":\"g401\",\"title\":\"Rappie Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ruwpww1511817242.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Onions\",\"Chicken Stock\",\"Chicken Breast\",\"Potatoes\",\"Salt\",\"Black Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 400 degrees F (200 degrees C). Grease a 10x14x2-inch baking pan.\\r\\nHeat margarine in a skillet over medium heat; stir in onion. Cook and stir unt\",\"instructions\":[\"Preheat oven to 400 degrees F (200 degrees C). Grease a 10x14x2-inch baking pan.\",\"Heat margarine in a skillet over medium heat; stir in onion. Cook and stir until onion has softened and turned translucent, about 5 minutes. Reduce heat to low and continue to cook and stir until onion is very tender and dark brown, about 40 minutes more.\",\"Bring chicken broth to a boil in a large pot; stir in chicken breasts, reduce heat, and simmer until chicken is no longer pink at the center, about 20 minutes. Remove from heat. Remove chicken breasts to a plate using a slotted spoon; reserve broth.\",\"Juice potatoes with an electric juicer; place dry potato flesh into a bowl and discard juice. Stir salt and pepper into potatoes; stir in enough reserved broth to make the mixture the consistency of oatmeal. Set remaining broth aside.\",\"Spread half of potato mixture evenly into the prepared pan. Lay cooked chicken breast evenly over potatoes; scatter caramelized onion evenly over chicken. Spread remaining potato mixture over onions and chicken to cover.\",\"Bake in the preheated oven until golden brown, about 1 hour. Reheat chicken broth; pour over individual servings as desired.\"]},{\"id\":\"g402\",\"title\":\"Raspberry mousse\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/v5jrnn1764362830.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Gelatine Leafs\",\"Raspberries\",\"Caster Sugar\",\"Lemon\",\"Whipping Cream\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut the gelatine leaves in a bowl, cover with warm water and leave to soak for 5 mins. Drain and squeeze out any excess water.\\r\\n\\r\\nstep 2\\r\\nTip the raspbe\",\"instructions\":[\"step 1\",\"Put the gelatine leaves in a bowl, cover with warm water and leave to soak for 5 mins. Drain and squeeze out any excess water.\",\"step 2\",\"Tip the raspberries into a pan over a medium-low heat along with the sugar and lemon juice. Cook for 5-6 mins until the berries have completely broken down. Push the mixture through a sieve set over a bowl, discarding the seeds. Stir in the gelatine leaves until dissolved (if they don’t dissolve, pour the mixture into a clean saucepan and heat gently until dissolved). Set aside to cool for 15 mins.\",\"step 3\",\"Whip the cream to soft peaks using an electric whisk, then gently fold this into the raspberry mixture. Spoon into the ramekins or moulds and chill overnight, or for at least 6 hrs. Serve with raspberries scattered over the top.\"]},{\"id\":\"g403\",\"title\":\"Raspeballer (Norwegian Potato Dumplings)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hhm7xy1763075871.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pork knuckle\",\"Sausages\",\"Potatoes\",\"Red Potatoes\",\"Flour\",\"All purpose flour\",\"Salt\",\"Bouillon Cubes\",\"Freshly Chopped Parsley\",\"Swede\",\"Carrots\",\"Cream\",\"Butter\",\"Nutmeg\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Raspeballer & (Optional) Salted Meat\\r\\n▢\\r\\nIf you're making pork knuckle, cook it in simmering water for about 3 hours, until the meat falls from the bone. Remove\",\"instructions\":[\"Raspeballer & (Optional) Salted Meat\",\"▢\",\"If you're making pork knuckle, cook it in simmering water for about 3 hours, until the meat falls from the bone. Remove the pork and save the broth to cook the raspeballer.\",\"▢\",\"Boil the boiled potatoes and peel once cooled. Also peel the raw potatoes, and then grate them or run them through a food processor. Use a paper towel to remove some of the moisture from the grated potatoes.\",\"▢\",\"Mash the boiled potatoes in a potato ricer or with a masher. Make sure there are no lumps. Add the grated raw potatoes to the mashed potatoes in a large mixing bowl and stir together. Add the barley flour, all purpose flour, and salt and mix together with your hands until the mixture is fully blended.\",\"▢\",\"You can cook the raspeballer in either vegetable or beef broth, or if you're making pork knuckle, cook them in the broth from the pork knuckle. Bring the broth to a very light simmer – you don't want it to fully boil because then the raspeballer might break apart.\",\"▢\"]},{\"id\":\"g404\",\"title\":\"Ratatouille\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wrpwuu1511786491.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Courgettes\",\"Yellow Pepper\",\"Tomato\",\"Olive Oil\",\"Basil\",\"Onion\",\"Garlic Clove\",\"Red Wine Vinegar\",\"Sugar\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Cut the aubergines in half lengthways. Place them on the board, cut side down, slice in half lengthways again and then across into 1.5cm chunks. Cut off the cou\",\"instructions\":[\"Cut the aubergines in half lengthways. Place them on the board, cut side down, slice in half lengthways again and then across into 1.5cm chunks. Cut off the courgettes ends, then across into 1.5cm slices. Peel the peppers from stalk to bottom. Hold upright, cut around the stalk, then cut into 3 pieces. Cut away any membrane, then chop into bite-size chunks.\",\"Score a small cross on the base of each tomato, then put them into a heatproof bowl. Pour boiling water over the tomatoes, leave for 20 secs, then remove. Pour the water away, replace the tomatoes and cover with cold water. Leave to cool, then peel the skin away. Quarter the tomatoes, scrape away the seeds with a spoon, then roughly chop the flesh.\",\"Set a sauté pan over medium heat and when hot, pour in 2 tbsp olive oil. Brown the aubergines for 5 mins on each side until the pieces are soft. Set them aside and fry the courgettes in another tbsp oil for 5 mins, until golden on both sides. Repeat with the peppers. Don’t overcook the vegetables at this stage, as they have some more cooking left in the next step.\",\"Tear up the basil leaves and set aside. Cook the onion in the pan for 5 mins. Add the garlic and fry for a further min. Stir in the vinegar and sugar, then tip in the tomatoes and half the basil. Return the vegetables to the pan with some salt and pepper and cook for 5 mins. Serve with basil.\"]},{\"id\":\"g405\",\"title\":\"Recheado Masala Fish\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uwxusv1487344500.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mackerel\",\"Red Chilli\",\"Ginger\",\"Garlic\",\"Pepper\",\"Cumin\",\"Turmeric\",\"Cinnamon stick\",\"Cloves\",\"Cardamom\",\"Sugar\",\"Tamarind ball\",\"Vinegar\",\"Oil\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Soak all the spices, ginger, garlic, tamarind pulp and kashmiri chilies except oil in vinegar.\\r\\nAdd sugar and salt.\\r\\nAlso add turmeric powder.\\r\\nCombine all nice\",\"instructions\":[\"Soak all the spices, ginger, garlic, tamarind pulp and kashmiri chilies except oil in vinegar.\",\"Add sugar and salt.\",\"Also add turmeric powder.\",\"Combine all nicely and marinate for 35-40 mins.\",\"Grind the mixture until soft and smooth. Add more vinegar if required but ensure the paste has to be thick so add vinegar accordingly. If the masala paste is thin then it would not stick to the fish.\",\"Rinse the fish slit from the center and give some incision from the top. You could see the fish below for clarity.\",\"Now stuff the paste into the center and into the incision. Coat the entire fish with this paste. Marinate the fish for 30 mins.\",\"Place oil in a shallow pan, once oil is quite hot shallow fry the stuffed mackerels.\",\"Fry until golden brown from both sides\",\"Serve the recheado mackerels hot with salad, lime wedges, rice and curry.\"]},{\"id\":\"g406\",\"title\":\"Red curry chicken kebabs\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/prjve31763486864.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breasts\",\"Thai Red Curry Paste\",\"Coconut Milk\",\"Red Pepper\",\"Courgettes\",\"Red Onions\",\"Lime\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nFire up the barbecue or heat a griddle pan to high. Tip chicken, curry paste and coconut milk into a bowl, then mix well until the chicken is evenly coa\",\"instructions\":[\"step 1\",\"Fire up the barbecue or heat a griddle pan to high. Tip chicken, curry paste and coconut milk into a bowl, then mix well until the chicken is evenly coated. Thread vegetables and chicken onto skewers. Cook the skewers on the barbecue or griddle for 5-8 mins, turning every so often, until the chicken is cooked through and charred. Serve with herby rice, salad and a lime half to squeeze over.\"]},{\"id\":\"g407\",\"title\":\"Red onion pickle\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ppodrp1762325183.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Onions\",\"Sea Salt\",\"Cider Vinegar\",\"Granulated Sugar\",\"Black Pepper\",\"Bay Leaves\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Peel the onions, cut them in half from top to bottom and finely slice into half-moon pieces. Put in a colander placed over a bowl and sprinkle with salt, lightl\",\"instructions\":[\"Peel the onions, cut them in half from top to bottom and finely slice into half-moon pieces. Put in a colander placed over a bowl and sprinkle with salt, lightly turning over the onion pieces with your hands so the surfaces are all covered. Set aside for an hour or so to brine.\",\"Meanwhile put the vinegar, 50ml/2fl oz water and the sugar in a saucepan. Bring to a simmer, stirring to help the sugar dissolve, and cook for a couple of minutes. Set aside.\",\"Pack the onions into the sterilised jars, sprinkling in a little pepper as you go. Cover with the warm vinegar and finish by tucking a couple of bay leaves down the side of the jars. Seal. The onions are best kept in the fridge and used within to 4 weeks.\"]},{\"id\":\"g408\",\"title\":\"Red Peas Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sqpqtp1515365614.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Kidney Beans\",\"Carrots\",\"Spring Onions\",\"Thyme\",\"Onion\",\"Black Pepper\",\"Red Pepper\",\"Garlic Clove\",\"Allspice\",\"Beef\",\"Water\",\"Potatoes\",\"Plain Flour\",\"Water\",\"Coconut Milk\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Wash and rinse the dried kidney beans.. then cover with water in a deep bowl. Remember as they soak they will expand to at least triple the size they were origi\",\"instructions\":[\"Wash and rinse the dried kidney beans.. then cover with water in a deep bowl. Remember as they soak they will expand to at least triple the size they were originally so add a lot of water to the bowl. Soak them overnight or for at least 2 hrs to make the cooking step go quicker. I tossed out the water they were soaked in after it did the job.\",\"Have your butcher cut the salted pigtail into 2 inch pieces as it will be very difficult to cut with an ordinary kitchen knife. Wash, then place a deep pot with water and bring to a boil. Cook for 20 minutes, then drain + rinse and repeat (boil again in water). The goal is to make the pieces of pig tails tender and to remove most of the salt it was cured in.\",\"Time to start the soup. Place everything in the pot (except the flour and potato), then cover with water and place on a high flame to bring to a boil. As it comes to a boil, skim off any scum/froth at the top and discard. Reduce the heat to a gentle boil and allow it to cook for 1 hr and 15 mins.. basically until the beans are tender and start falling apart.\",\"It’s now time to add the potato (and Yams etc if you’re adding it) as well as the coconut milk and continue cooking for 15 minutes.\",\"Now is a good time to start making the basic dough for the spinner dumplings. Mix the flour and water (add a pinch of salt if you want) until you have a soft/smooth dough. allow it to rest for 5 minutes, then pinch of a tablespoon at a time and roll between your hands to form a cigarette shape.\",\"Add them to the pot, stir well and continue cooking for another 15 minutes on a rolling boil.\",\"You’ll notice that I didn’t add any salt to the pot as the remaining salt from the salted pigtails will be enough to properly season this dish. However you can taste and adjust accordingly. Lets recap the timing part of things so you’re not confused. Cook the base of the soup for 1 hr and 15 minute or until tender, then add the potatoes and cook for 15 minutes, then add the dumplings and cook for a further 15 minutes. Keep in mind that this soup will thicken quite a bit as it cools.\",\"While this is not a traditional recipe to any one specific island, versions of this soup (sometimes called stewed peas) can be found throughout the Caribbean, Latin America and Africa. A hearty bowl of this soup will surely give you the sleepies (some may call it ethnic fatigue). You can certainly freeze the leftovers and heat it up another day.\"]},{\"id\":\"g409\",\"title\":\"Ribollita\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xrrwpx1487347049.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Carrots\",\"Celery\",\"Garlic\",\"Cannellini Beans\",\"Canned tomatoes\",\"Water\",\"Rosemary\",\"Thyme\",\"Kale\",\"Wholegrain Bread\",\"Red Onions\",\"Parmesan\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Put 2 tablespoons of the oil in a large pot over medium heat. When it’s hot, add onion, carrot, celery and garlic; sprinkle with salt and pepper and cook, stirr\",\"instructions\":[\"Put 2 tablespoons of the oil in a large pot over medium heat. When it’s hot, add onion, carrot, celery and garlic; sprinkle with salt and pepper and cook, stirring occasionally, until vegetables are soft, 5 to 10 minutes.\",\"Heat the oven to 500 degrees. Drain the beans; if they’re canned, rinse them as well. Add them to the pot along with tomatoes and their juices and stock, rosemary and thyme. Bring to a boil, then reduce heat so the soup bubbles steadily; cover and cook, stirring once or twice to break up the tomatoes, until the flavors meld, 15 to 20 minutes.\",\"Fish out and discard rosemary and thyme stems, if you like, and stir in kale. Taste and adjust seasoning. Lay bread slices on top of the stew so they cover the top and overlap as little as possible. Scatter red onion slices over the top, drizzle with the remaining 3 tablespoons oil and sprinkle with Parmesan.\",\"Put the pot in the oven and bake until the bread, onions and cheese are browned and crisp, 10 to 15 minutes. (If your pot fits under the broiler, you can also brown the top there.) Divide the soup and bread among 4 bowls and serve.\"]},{\"id\":\"g410\",\"title\":\"Rice paper dumplings\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sfahy01763752319.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"White Cabbage\",\"Carrots\",\"Shiitake Mushrooms\",\"Ground Pork\",\"Garlic\",\"Ginger\",\"Soy Sauce\",\"Sesame Seed Oil\",\"Spring Onions\",\"Rice Paper Sheets\",\"Vegetable Oil\",\"Soy Sauce\",\"Rice Vinegar\",\"Sesame Seed\",\"Spring Onions\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip the cabbage into a food processor and blitz until finely chopped. Season with ½ tsp salt, toss well and set aside for 15 mins. Tip into a clean tea \",\"instructions\":[\"step 1\",\"Tip the cabbage into a food processor and blitz until finely chopped. Season with ½ tsp salt, toss well and set aside for 15 mins. Tip into a clean tea towel and squeeze out as much water as you can. Tip into a bowl with the carrot, mushrooms, pork mince, garlic, ginger, soy sauce, sesame oil and spring onions. Season with black pepper. Scrunch everything together using your hands, mixing well until everything is combined.\",\"step 2\",\"Soak the spring roll sheets for a couple of seconds in a shallow dish of warm water, then transfer to an oiled chopping board. Working with one sheet at a time, spoon 1 heaped tbsp of the filling into the middle, then fold the bottom up and over the filling. Fold down the top of the sheet, then the sides to fully encase and make a neat square. If the dumpling feels a little fragile, soak another sheet and wrap it again. Repeat with the remaining sheets and filling, transferring the dumplings to an oiled plate as you go.\",\"step 3\",\"Heat the oil in a large, non-stick frying pan (ensuring it is no more than a third full) over a medium-high heat and fry the dumplings for 3-5 mins until golden brown. Use a slotted spoon or spider to turn them, then cover with a lid and cook for another 3-4 mins until golden. Remove the lid and cook for 1-2 mins.\",\"step 4\",\"Meanwhile, combine all the dipping sauce ingredients in small bowl. Serve the dumplings with the dipping sauce on the side.\"]},{\"id\":\"g411\",\"title\":\"Rigatoni with fennel sausage sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qtqvys1468573168.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"olive oil\",\"Italian fennel sausages\",\"onion\",\"fennel bulb\",\"smoky paprika\",\"garlic\",\"fennel seeds\",\"red wine\",\"chopped tomatoes\",\"caster sugar\",\"pitted black olives\",\"rigatoni\",\"pecorino\",\"anchovy fillet\",\"garlic\",\"olive oil\",\"basil leaves\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat a tablespoon of oil in a large saute pan for which you have a lid. Add the sausage pieces and fry on a medium-high heat for 10 minutes, stirring regularly,\",\"instructions\":[\"Heat a tablespoon of oil in a large saute pan for which you have a lid. Add the sausage pieces and fry on a medium-high heat for 10 minutes, stirring regularly, until golden-brown all over. Transfer the sausages to a plate, then add the onion and fennel to the hot pan and fry for 15 minutes, stirring once in a while, until soft and caramelised; if the pan goes a bit dry, add a teaspoon or so of extra oil. Stir in the paprika, garlic and half the fennel seeds, fry for two minutes more, then pour on the wine and boil for 30 seconds, to reduce by half. Add the tomatoes, sugar, 100ml water, the seared sausage and half a teaspoon of salt, cover and simmer for 30 minutes; remove the lid after 10 minutes, and cook until the sauce is thick and rich. Remove from the heat, stir through the olives and remaining fennel seeds and set aside until you’re ready to serve.\",\"Bring a large pot of salted water to a boil, add the pasta and cook for 12-14 minutes (or according to the instructions on the packet), until al dente. Meanwhile, reheat the sauce. Drain the pasta, return it to the pot, stir in a tablespoon of oil, then divide between the bowls.\",\"Put all the pesto ingredients except the basil in the small bowl of a food processor. Add a tablespoon of water and blitz to a rough paste. Add the basil, then blitz until just combined (the pesto has a much better texture if the basil is not overblended).\",\"Spoon over the ragù and top with a spoonful of pesto. Finish with a sprinkling of chopped fennel fronds, if you have any, and serve at once.\"]},{\"id\":\"g412\",\"title\":\"Roast aubergine with goat's cheese & toasted flatbread\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/iydbwy1763816111.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Extra Virgin Olive Oil\",\"Cherry Tomatoes\",\"Pita Bread\",\"Balsamic Vinegar\",\"Mint\",\"Shallots\",\"Shallots\",\"Red Chilli\",\"Goats Cheese\",\"Rocket\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/180C fan/gas 6. Brush the aubergine slices with 1 tbsp of the oil, then season. Arrange on a baking tray or sheet and roast for 20 min\",\"instructions\":[\"step 1\",\"Heat oven to 200C/180C fan/gas 6. Brush the aubergine slices with 1 tbsp of the oil, then season. Arrange on a baking tray or sheet and roast for 20 mins until browned, popping the tomatoes on the tray for the final 5 mins. Tear the flatbread into pieces and place on a separate baking sheet. Brown in the oven for 8 mins, or until crisp, then remove.\",\"step 2\",\"For the dressing, in a small bowl, mix the vinegar, mint, chopped shallots, chilli, remaining oil and some salt and pepper.\",\"step 3\",\"Scatter the aubergine slices, tomatoes, sliced shallot and crisp flatbread into a serving bowl. Pour over the dressing, sprinkle with the goat’s cheese and scatter over a little rocket.\"]},{\"id\":\"g413\",\"title\":\"Roast fennel and aubergine paella\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1520081754.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Baby Aubergine\",\"Fennel\",\"Red Pepper\",\"Courgettes\",\"Onion\",\"Paella Rice\",\"Paprika\",\"Saffron\",\"White Wine\",\"Vegetable Stock\",\"Frozen Peas\",\"Lemon\",\"Parsley\",\"Salt\",\"Black Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"1 Put the fennel, aubergine, pepper and courgette in a roasting tray. Add a glug of olive oil, season with salt and pepper and toss around to coat the veggies i\",\"instructions\":[\"1 Put the fennel, aubergine, pepper and courgette in a roasting tray. Add a glug of olive oil, season with salt and pepper and toss around to coat the veggies in the oil. Roast in the oven for 20 minutes, turning a couple of times until the veg are pretty much cooked through and turning golden.\",\"2 Meanwhile, heat a paella pan or large frying pan over a low– medium heat and add a glug of olive oil. Sauté the onion for 8–10 minutes until softened. Increase the heat to medium and stir in the rice, paprika and saffron. Cook for around 1 minute to start toasting the rice, then add the white wine. Reduce by about half before stirring in two-thirds of the stock. Reduce to a simmer and cook for 10 minutes without a lid, stirring a couple of times.\",\"3 Stir in the peas, add some seasoning, then gently mix in the roasted veg. Pour over the remaining stock, arrange the lemon wedges on top and cover with a lid or some aluminium foil. Cook for a further 10 minutes.\",\"4 To ensure you get the classic layer of toasted rice at the bottom of the pan, increase the heat to high until you hear a slight crackle. Remove from the heat and sit for 5 minutes before sprinkling over the parsley and serving.\"]},{\"id\":\"g414\",\"title\":\"Roasted chicken with creamy walnut sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ro8mzj1763800655.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Cumin\",\"Paprika\",\"Olive Oil\",\"Pita Bread\",\"Chicken Stock\",\"Walnuts\",\"Onion\",\"Garlic\",\"Single Cream\",\"Lemon\",\"Coriander\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/180C fan/gas 6. In a roasting tin, toss together the chicken, cumin, paprika, 1 tbsp olive oil and seasoning. Cook for 40 mins until t\",\"instructions\":[\"step 1\",\"Heat oven to 200C/180C fan/gas 6. In a roasting tin, toss together the chicken, cumin, paprika, 1 tbsp olive oil and seasoning. Cook for 40 mins until the chicken is crisp and cooked through.\",\"step 2\",\"Meanwhile, tear up 1 pitta bread and place in a small bowl. Pour over a couple of tbsp chicken stock and leave to soak. Dry-fry the walnuts in a frying pan for about 3 mins until golden and toasted. Set aside. Heat the remaining oil in the pan and cook the onion and garlic until softened. Place the softened pitta bread, onion mixture and most of the nuts into a blender. Pour over the rest of the chicken stock and whizz together until a rough paste forms. Return the mixture to the pan. Add the cream and lemon juice, season and keep warm.\",\"step 3\",\"When the chicken is cooked, arrange on a platter. Stir the coriander through the sauce and spoon into a bowl. Roughly chop the remaining walnuts and scatter over the chicken. Toast the pittas, cut into wedges and serve alongside\"]},{\"id\":\"g415\",\"title\":\"Roasted Eggplant With Tahini, Pine Nuts, and Lentils\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ysqrus1487425681.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Carrots\",\"Celery\",\"Onion\",\"Garlic\",\"Brown Lentils\",\"Bay Leaves\",\"Water\",\"Salt\",\"Apple Cider Vinegar\",\"Pepper\",\"Egg Plants\",\"Rosemary\",\"Pine nuts\",\"Parsley\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the Lentils: Adjust oven rack to center position and preheat oven to 450°F to prepare for roasting eggplant. Meanwhile, heat 2 tablespoons olive oil in a me\",\"instructions\":[\"For the Lentils: Adjust oven rack to center position and preheat oven to 450°F to prepare for roasting eggplant. Meanwhile, heat 2 tablespoons olive oil in a medium saucepan over medium heat until shimmering. Add carrots, celery, and onion and cook, stirring, until softened but not browned, about 4 minutes. Add garlic and cook, stirring, until fragrant, about 30 seconds. Add lentils, bay leaves, stock or water, and a pinch of salt. Bring to a simmer, cover with the lid partially ajar, and cook until lentils are tender, about 30 minutes. (Top up with water if lentils are at any point not fully submerged.) Remove lid, stir in vinegar, and reduce until lentils are moist but not soupy. Season to taste with salt and pepper, cover, and keep warm until ready to serve.\",\"2.\",\"For the Eggplant: While lentils cook, cut each eggplant in half. Score flesh with the tip of a paring knife in a cross-hatch pattern at 1-inch intervals. Transfer to a foil-lined rimmed baking sheet, cut side up, and brush each eggplant half with 1 tablespoon oil, letting each brushstroke be fully absorbed before brushing with more. Season with salt and pepper. Place a rosemary sprig on top of each one. Transfer to oven and roast until completely tender and well charred, 25 to 35 minutes. Remove from oven and discard rosemary.\",\"3.\",\"To Serve: Heat 2 tablespoons olive oil and pine nuts in a medium skillet set over medium heat. Cook, tossing nuts frequently, until golden brown and aromatic, about 4 minutes. Transfer to a bowl to halt cooking. Stir half of parsley and rosemary into lentils and transfer to a serving platter. Arrange eggplant halves on top. Spread a few tablespoons of tahini sauce over each eggplant half and sprinkle with pine nuts. Sprinkle with remaining parsley and rosemary, drizzle with additional olive oil, and serve.\"]},{\"id\":\"g416\",\"title\":\"Rock Cakes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tqrrsq1511723764.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Self-raising Flour\",\"Caster Sugar\",\"Baking Powder\",\"Butter\",\"Dried Fruit\",\"Eggs\",\"Milk\",\"Vanilla Extract\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 180C/350F/Gas 4 and line a baking tray with baking parchment.\\r\\nMix the flour, sugar and baking powder in a bowl and rub in the cubed butter unti\",\"instructions\":[\"Preheat oven to 180C/350F/Gas 4 and line a baking tray with baking parchment.\",\"Mix the flour, sugar and baking powder in a bowl and rub in the cubed butter until the mixture looks like breadcrumbs, then mix in the dried fruit.\",\"In a clean bowl, beat the egg and milk together with the vanilla extract.\",\"Add the egg mixture to the dry ingredients and stir with a spoon until the mixture just comes together as a thick, lumpy dough. Add a teaspoon more milk if you really need it to make the mixture stick together.\",\"Place golfball-sized spoons of the mixture onto the prepared baking tray. Leave space between them as they will flatten and spread out to double their size during baking.\",\"Bake for 15-20 minutes, until golden-brown. Remove from the oven, allow to cool for a couple of minutes then turn them out onto a wire rack to cool.\"]},{\"id\":\"g417\",\"title\":\"Rocky Road Fudge\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vtxyxv1483567157.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Miniature Marshmallows\",\"Chocolate Chips\",\"Peanut Butter\",\"Vanilla Extract\",\"Peanuts\"],\"allergens\":[\"milk\",\"peanut\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.\\r\\nPour ½ cup of the miniature marshmallows into the bottom of the lined b\",\"instructions\":[\"Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.\",\"Pour ½ cup of the miniature marshmallows into the bottom of the lined baking dish.\",\"In a microwave-safe bowl, combine the chocolate chips and peanut butter. Microwave the chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.\",\"Add the vanilla extract and stir well, until smooth.\",\"Reserve 2 tablespoons of the chopped almonds or peanuts, and set aside.\",\"Fold 1 ½ cups of the miniature marshmallows and the remaining chopped nuts into the chocolate mixture.\",\"Transfer the chocolate mixture into the prepared pan and spread into an even layer. Immediately top with the reserved chopped nuts and the mallow bits or additional miniature marshmallows, if using.\",\"Refrigerate for 4 hours, or until set.\",\"Remove the fudge and wax paper from the pan. Carefully peel all of wax paper from the fudge.\",\"Cut the fudge into bite-sized pieces and serve.\"]},{\"id\":\"g418\",\"title\":\"Rogaliki (Polish Croissant Cookies)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/7mxnzz1593350801.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Egg Yolks\",\"Cream Cheese\",\"Baking Powder\",\"Flour\",\"Jam\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a medium bowl mix egg yolks, philly cheese and baking powder using a hand held mixer. Carefully start adding the flour. When the mixture will not be mixing w\",\"instructions\":[\"In a medium bowl mix egg yolks, philly cheese and baking powder using a hand held mixer. Carefully start adding the flour. When the mixture will not be mixing well, and will look like wood chips, put away the blending mixer and using your hands knead the dough.\",\"Create a roll and cover in foil and freeze for 15 minutes. At this time preheat the oven to 375.\",\"Take the dough out and separate into two. Roll and cut out 3 inch trangles.\",\"Make as many as you can and on centre of each put a small spoon of jam. Roll them into a croissant shape.\",\"Place the croissants onto a greased cookie sheet, and bake for 10-12 minutes or until golden.\",\"Repeat with the rest of the dough.\",\"When you take them out, put aside and sprinkle with powdered sugar on top.\",\"This makes about 3 batches of 20 cookies each.\",\"Total count about 60 cookies.\"]},{\"id\":\"g419\",\"title\":\"Rømmegrøt – Norwegian Sour Cream Porridge\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hyk47c1762772689.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Full fat sour cream\",\"Flour\",\"Milk\",\"Salt\",\"Sugar\",\"Cinnamon\",\"Butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"▢\\r\\nCook the sour cream in a covered saucepan on medium heat for about 5 minutes.\\r\\n▢\\r\\nTurn down the heat and add half of the flour and stir well with a whisk. On\",\"instructions\":[\"▢\",\"Cook the sour cream in a covered saucepan on medium heat for about 5 minutes.\",\"▢\",\"Turn down the heat and add half of the flour and stir well with a whisk. Once the flour is fully incorporated, let the mixture continue to cook, stirring occasionally, until fat starts to release. Use a spoon to gather as much of the fat as you can in a small bowl, saving for later. (Don't worry if you can't get any fat – in that case you can add butter later.)\",\"▢\",\"Whisk in the rest of the flour and then slowly add the milk, whisking constantly to avoid lumps. Let the porridge continue to cook on low heat for 5 minutes and then add salt.\",\"▢\",\"Serve with sugar, cinnamon, and the fat from the porridge. If you're using lower fat sour cream you can top the rømmegrøt with some butter instead.\"]},{\"id\":\"g420\",\"title\":\"Rosemary braised red cabbage with kabanos\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/s1jxzl1764369317.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Cabbage\",\"Olive Oil\",\"Butter\",\"Red Onions\",\"Red Wine Vinegar\",\"Brown Sugar\",\"Red Chilli\",\"Rosemary\",\"Bramley Apples\",\"Kabanos Sausages\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHalve the cabbage, remove the tough stem and thinly slice. Place in a large pan with all the other ingredients apart from the sausages, then mix in 300m\",\"instructions\":[\"step 1\",\"Halve the cabbage, remove the tough stem and thinly slice. Place in a large pan with all the other ingredients apart from the sausages, then mix in 300ml water and some salt and pepper.\",\"step 2\",\"Bring to a simmer, then reduce the heat, cover with a well-fitting lid and gently cook for 1½ hrs, stirring frequently. If too dry, you can add a little more water.\",\"step 3\",\"Add the kabanos to the cabbage mixture, place a lid on the pan and gently simmer for 20 mins. Remove the lid and cook for a further 10 mins. Serve alongside some simple mash or boiled potatoes.\"]},{\"id\":\"g421\",\"title\":\"Rosol (Polish Chicken Soup)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lx1kkj1593349302.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Legs\",\"Onions\",\"Carrots\",\"Leek\",\"Celery\",\"Cabbage\",\"Cloves\",\"Allspice\",\"Bay Leaf\",\"Parsley\",\"Dill\",\"Pepper\",\"Salt\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add chicken to a large Dutch oven or stock pot \\r\\nCover with water\\r\\nBring to a boil and simmer for 2 to 2 1/2 hours, skimming any impurities off the top to insur\",\"instructions\":[\"Add chicken to a large Dutch oven or stock pot\",\"Cover with water\",\"Bring to a boil and simmer for 2 to 2 1/2 hours, skimming any impurities off the top to insure a clear broth\",\"If your pot is big enough, add the vegetables and spices for the last hour of the cooking time\",\"My Dutch oven wasn’t big enough to hold everything, just the chicken and other bones filled the pot, so I cooked the meat/bones for the full cooking time, then removed them, and cooked the vegetables and spices separately\",\"Strain everything out of the broth\",\"Bone the chicken, pulling the meat into large chunks\",\"Slice the carrots\",\"Return the chicken and carrots to the broth\",\"Cook noodles according to package instructions if you’re using them\"]},{\"id\":\"g422\",\"title\":\"Roti john\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hx335q1619789561.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Minced Beef\",\"Onion\",\"Eggs\",\"Chilli\",\"Baguette\",\"Salt\",\"Pepper\",\"Mayonnaise\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix all the ingredients in a bowl.\\r\\nHeat a pan or griddle with a little vegetable oil.\\r\\nPour the mixture onto the pan and place a piece of open-faced baguette o\",\"instructions\":[\"Mix all the ingredients in a bowl.\",\"Heat a pan or griddle with a little vegetable oil.\",\"Pour the mixture onto the pan and place a piece of open-faced baguette on top.\",\"Press on the bread with a spatula and grill for 2 minutes.\",\"Turn the bread over to make it a little crispy.\",\"Remove from pan and cut the bread into small portions.\",\"Add mayonnaise and/or Sambal before cutting the sandwich (optional).\"]},{\"id\":\"g423\",\"title\":\"Rye bread\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lmc6r51764365554.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rye\",\"Strong white bread flour\",\"Yeast\",\"Salt\",\"Honey\",\"Caraway Seed\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip the flours, yeast and salt into a bowl. In a jug, mix the honey with 250ml warm water, pour the liquid into the bowl and mix to form a dough. Rye fl\",\"instructions\":[\"step 1\",\"Tip the flours, yeast and salt into a bowl. In a jug, mix the honey with 250ml warm water, pour the liquid into the bowl and mix to form a dough. Rye flour can be quite dry and absorbs lots of water, if the dough looks too dry add more warm water until you have a soft dough Tip out onto your work surface and knead for 10 mins until smooth. Rye contains less gluten than white flour so the dough will not feel as springy as a conventional white loaf.\",\"step 2\",\"Place the dough in a well oiled bowl, cover with cling film and leave to rise in a warm place for 1-2 hrs, or until roughly doubled in size. Dust a 2lb/900g loaf tin with flour.\",\"step 3\",\"Tip the dough back onto your work surface and knead briefly to knock out any air bubbles. If using caraway seeds work these in to the dough. Shape into a smooth oval loaf and pop into your tin. Cover the tin with oiled cling film and leave to rise somewhere warm for a further 1 – 1.5 hr, or until doubled in size.\",\"step 4\",\"Heat oven to 220C/200C fan/gas 7. Remove the cling film and dust the surface of the loaf with rye flour. Slash a few incisions on an angle then bake for 30 mins until dark brown and hollow sounding when tapped. Transfer to a wire cooling rack and leave to cool for at least 20 mins before serving\"]},{\"id\":\"g424\",\"title\":\"Salmon Avocado Salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1549542994.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Salmon\",\"Avocado\",\"Cucumber\",\"Spinach\",\"Mint\",\"Lime\",\"Honey\",\"Olive Oil\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Season the salmon, then rub with oil. Mix the dressing ingredients together. Halve, stone, peel and slice the avocados. Halve and quarter the cucumber lengthway\",\"instructions\":[\"Season the salmon, then rub with oil. Mix the dressing ingredients together. Halve, stone, peel and slice the avocados. Halve and quarter the cucumber lengthways, then cut into slices. Divide salad, avocado and cucumber between four plates, then drizzle with half the dressing.\",\"Heat a non-stick pan. Add the salmon and fry for 3-4 mins on each side until crisp but still moist inside. Put a salmon fillet on top of each salad and drizzle over the remaining dressing. Serve warm.\"]},{\"id\":\"g425\",\"title\":\"Salmon Eggs Eggs Benedict\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1550440197.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Eggs\",\"White Wine Vinegar\",\"English Muffins\",\"Butter\",\"Smoked Salmon\",\"Lemon Juice\",\"White Wine Vinegar\",\"Egg\",\"Unsalted Butter\"],\"allergens\":[\"egg\",\"milk\",\"fish\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"First make the Hollandaise sauce. Put the lemon juice and vinegar in a small bowl, add the egg yolks and whisk with a balloon whisk until light and frothy. Plac\",\"instructions\":[\"First make the Hollandaise sauce. Put the lemon juice and vinegar in a small bowl, add the egg yolks and whisk with a balloon whisk until light and frothy. Place the bowl over a pan of simmering water and whisk until mixture thickens. Gradually add the butter, whisking constantly until thick – if it looks like it might be splitting, then whisk off the heat for a few mins. Season and keep warm.\",\"To poach the eggs, bring a large pan of water to the boil and add the vinegar. Lower the heat so that the water is simmering gently. Stir the water so you have a slight whirlpool, then slide in the eggs one by one. Cook each for about 4 mins, then remove with a slotted spoon.\",\"Lightly toast and butter the muffins, then put a couple of slices of salmon on each half. Top each with an egg, spoon over some Hollandaise and garnish with chopped chives.\"]},{\"id\":\"g426\",\"title\":\"Salmon noodle soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ikizdm1763760862.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Stock\",\"Thai Red Curry Paste\",\"Rice Noodles\",\"Shiitake Mushrooms\",\"Sweetcorn\",\"Salmon\",\"Lime\",\"Soy Sauce\",\"Brown Sugar\",\"Coriander\"],\"allergens\":[\"soy\",\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPour the stock into a large pan, bring to the boil, then stir in the curry paste. Add the noodles and cook for 8 mins. Tip in the mushrooms and corn and\",\"instructions\":[\"step 1\",\"Pour the stock into a large pan, bring to the boil, then stir in the curry paste. Add the noodles and cook for 8 mins. Tip in the mushrooms and corn and cook for 2 mins more.\",\"step 2\",\"Add the salmon to the pan and cook for 3 mins or until cooked through. Remove from the heat and stir in the lime juice, soy sauce and a pinch of sugar. Ladle into 4 bowls and sprinkle over the coriander just before you serve.\"]},{\"id\":\"g427\",\"title\":\"Salmon noodle wraps\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/prrirc1763781360.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Noodles\",\"Spring Onions\",\"Petit Pois\",\"Chilli\",\"Coriander\",\"Lime\",\"Salmon\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/fan 180C/gas 6. Put the noodles in a bowl and pour over enough boiling water to just cover them. Leave for 2 mins, until they are bend\",\"instructions\":[\"step 1\",\"Heat oven to 200C/fan 180C/gas 6. Put the noodles in a bowl and pour over enough boiling water to just cover them. Leave for 2 mins, until they are bendable, but not too soft, then drain well. Return to the bowl with the spring onions, petit pois, salt and pepper and a third of the butter. Mix well until the butter has melted.\",\"step 2\",\"Pile the noodles and vegetables onto two large squares of baking parchment, then sit the salmon on top. Slice the remaining butter and arrange over the top of the salmon. Bring the ends of the paper over the fish, fold them together to seal, then tuck the ends of the paper underneath so there are no gaps. Put the parcels on a baking sheet and bake for 15-20 mins. Transfer to dinner plates and serve without delay.\"]},{\"id\":\"g428\",\"title\":\"Salmon Prawn Risotto\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xxrxux1503070723.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"butter\",\"onion\",\"rice\",\"white wine\",\"vegetable stock\",\"lemon\",\"King Prawns\",\"salmon\",\"asparagus\",\"black pepper\",\"Parmesan\"],\"allergens\":[\"milk\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Melt the butter in a thick-based pan and gently cook the onion without colour until it is soft.\\r\\nAdd the rice and stir to coat all the grains in the butter\\r\\nAdd\",\"instructions\":[\"Melt the butter in a thick-based pan and gently cook the onion without colour until it is soft.\",\"Add the rice and stir to coat all the grains in the butter\",\"Add the wine and cook gently stirring until it is absorbed\",\"Gradually add the hot stock, stirring until each addition is absorbed. Keep stirring until the rice is tender\",\"Season with the lemon juice and zest, and pepper to taste. (there will probably be sufficient saltiness from the salmon to not need to add salt) Stir gently to heat through\",\"Serve scattered with the Parmesan and seasonal vegetables.\",\"Grill the salmon and gently place onto the risotto with the prawns and asparagus\"]},{\"id\":\"g429\",\"title\":\"Salt & pepper squid\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yxiilf1763759428.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Corn Flour\",\"Plain Flour\",\"Black Pepper\",\"Szechuan Peppercorns\",\"Sunflower Oil\",\"Squid\",\"Spring Onions\",\"Green Chilli\",\"Red Chilli\",\"Cucumber\",\"Red Onions\",\"Rice Vinegar\",\"Caster Sugar\",\"Fish Sauce\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make the dipping sauce, mix all the ingredients in a small bowl until the sugar has dissolved, then set aside. Mix the cornflour and plain flour with\",\"instructions\":[\"step 1\",\"To make the dipping sauce, mix all the ingredients in a small bowl until the sugar has dissolved, then set aside. Mix the cornflour and plain flour with both peppers and 2 tsp sea salt in a large bowl, then set aside. Line a tray with kitchen paper and make sure you have more salt to sprinkle with.\",\"step 2\",\"Heat about 7cm of oil to 180C in a deep fryer, wok or deep pan. If you don’t have a thermometer, you can test it with a cube of bread – it should brown in 20 secs. Coat the squid well with the flour mix and fry in batches for about 2 mins each or until crisp. Use a slotted spoon to lift out the squid, then drain on the kitchen paper and sprinkle with a little more salt. Serve the squid scattered with the spring onion and chilli, with the dipping sauce on the side.\"]},{\"id\":\"g430\",\"title\":\"Salt cod tortilla\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/njj1681763297231.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Jersey Royal Potatoes\",\"Garlic\",\"Egg\",\"Parsley\",\"Salt Cod\"],\"allergens\":[\"egg\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat half the oil in a frying pan, and sauté the onion over a medium heat until soft and pale gold – this will take about 8 mins. Remove from the pan, s\",\"instructions\":[\"step 1\",\"Heat half the oil in a frying pan, and sauté the onion over a medium heat until soft and pale gold – this will take about 8 mins. Remove from the pan, set aside, and add the potatoes to the pan. Cook until they are tender but not falling apart, carefully turning every so often. Cover the pan some of the time to help the slices cook through. Add the onions back to the pan along with the garlic and cook for another 4 mins. Tip into a bowl with the eggs, parsley and some seasoning and mix together. Leave to sit for half an hour.\",\"step 2\",\"Meanwhile, put the cod in a saucepan and cover with water. Bring up to a simmer. Remove from the heat, cover and leave for 10 mins. Drain, leave to cool and remove the skin and any bones. Break into large flakes and add to the potato and egg mixture.\",\"step 3\",\"Heat the rest of the oil in a non-stick frying pan. Pour in the tortilla mix and cook over a medium-low heat until it is just set and coming away from the sides of the pan. You might need to cover it to help the centre set. Be careful not to overcook it. Put a spatula underneath the tortilla every so often to make sure it isn’t sticking. Slide the tortilla onto a plate, then put the pan on top and flip the tortilla into it, uncooked side-down. Cook over a low heat until golden, or grill until just set. Leave to cool a little before serving.\"]},{\"id\":\"g431\",\"title\":\"Salted Caramel Cheescake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xqrwyr1511133646.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Digestive Biscuits\",\"Pretzels\",\"Butter\",\"Cream Cheese\",\"Vanilla Extract\",\"Icing Sugar\",\"Caramel\",\"Sea Salt\",\"Double Cream\",\"Caramel Sauce\",\"Toffee Popcorn\",\"Pretzels\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1) Blitz the biscuits and the pretzels in a food processor and mix the biscuits with the melted butter. Spread on the bottom of an 8″/20cm Deep Springform Tin a\",\"instructions\":[\"1) Blitz the biscuits and the pretzels in a food processor and mix the biscuits with the melted butter. Spread on the bottom of an 8″/20cm Deep Springform Tin and press down firmly. Leave to set in the fridge whilst you make the rest!\",\"2) Using an electric mixer, I use my KitchenAid with the whisk attachment, whisk together the cream cheese, vanilla, and icing sugar until smooth and then add the caramel and whisk again until smooth and lump free – this could take a couple of minutes, I whisk it at half speed so not too quick or slow!\",\"3) Pour in the double cream & Salt flakes and continue to whisk for a couple of minutes until its very thick and mousse like (I mix it on a medium speed, level 6/10) – Now this could take up to 5 minutes depending on your mixer, but you seriously have to stick at it – it will hold itself completely when finished mixing (like a meringue does!) If you don’t mix it enough it will not set well enough, but don’t get impatient and whisk it really quick because that’ll make it split! Spread over the biscuit base and leave to set in the fridge overnight.\",\"4) Remove the Cheesecake from the tin carefully and decorate the cheesecake – I drizzled over some of the spare caramel, and then some Toffee Popcorn and more Pretzels!\"]},{\"id\":\"g432\",\"title\":\"Saltfish and Ackee\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vytypy1511883765.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Salt Cod\",\"Ackee\",\"Onion\",\"Paprika\",\"Curry Powder\",\"Jerusalem Artichokes\",\"Hotsauce\",\"Red Pepper\",\"Yellow Pepper\",\"Tomatoes\",\"Salt\",\"Pepper\",\"Self-raising Flour\",\"Suet\",\"Salt\",\"Olive Oil\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"For the saltfish, soak the salt cod overnight, changing the water a couple of times.\\r\\nDrain, then put the cod in a large pan of fresh water and bring to the boi\",\"instructions\":[\"For the saltfish, soak the salt cod overnight, changing the water a couple of times.\",\"Drain, then put the cod in a large pan of fresh water and bring to the boil. Drain again, add fresh water and bring to the boil again.\",\"Simmer for about five minutes, or until cooked through, then drain and flake the fish into large pieces. Discard any skin or bones.\",\"For the dumplings, mix the flour and suet with a pinch of salt and 250ml/9fl oz water to make a dough.\",\"Wrap the mixture in clingfilm and leave in the fridge to rest.\",\"Open the can of ackee, drain and rinse, then set aside.\",\"Heat a tablespoon of olive oil in a pan and fry the onion until softened but not brown.\",\"Add the spices, seasoning, pepper sauce and sliced peppers and continue to fry until the peppers are tender.\",\"Add the chopped tomatoes, then the salt cod and mix together. Lastly stir in the ackee very gently and leave to simmer until ready to serve.\",\"When you’re almost ready to eat, heat about 1cm/½in vegetable oil in a frying pan and heat until just smoking.\"]},{\"id\":\"g433\",\"title\":\"Saskatoon Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/5xdrkw1764444472.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"All purpose flour\",\"Salt\",\"Unsalted Butter\",\"Vegetable Shortening\",\"Egg\",\"Vinegar\",\"Water\",\"Saskatoon Berries\",\"Sugar\",\"Sugar\",\"Cornstarch\",\"Unsalted Butter\",\"Egg\",\"Water\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"To make the pastry, place the flour and salt in a large bowl. Mix well. Add the cubes of butter and shortening and mix them in (I like to use my hands to mix th\",\"instructions\":[\"To make the pastry, place the flour and salt in a large bowl. Mix well. Add the cubes of butter and shortening and mix them in (I like to use my hands to mix the fat into the flour, but you can use a pastry blender) just until it looks like coarse oatmeal with some pea-sized bits remaining. Place the egg in a 2-cup measure and beat it with a fork. Beat in the vinegar and just enough ice-cold water to bring it to the 1-cup mark. Stir this into the flour mixture, just until the dough clings together. I like to use my hands for this part as well, but a wooden spoon would also work. Try not to overmix it.\",\"On a lightly floured surface, gather the dough into a ball and divide it into 5 evenly sized portions. Shape each portion into a disc and wrap tightly in plastic. Chill 2 of these discs for 1 hour. Freeze the other 3 in a resealable freezer bag for future use. The pastry keeps well in the freezer for up to 2 months.\",\"Preheat the oven to 350°F. Place the rack in the lower third of the oven. Line a baking sheet with aluminum foil to catch drippings.\",\"On a lightly floured surface, roll out 1 disc of pastry into a 12-inch circle, or thereabouts. Place it in the bottom of a 9-inch pie plate, with the pastry overhanging the edges of the pie plate.\",\"To make the filling, place the saskatoon berries in a large bowl and stir in the 1/2 cup sugar and the cornstarch until well combined. Pour the berry mixture into the bottom of the pie. Dot with the butter. On a lightly floured surface, roll out the pastry in another 12-inch circle for the top crust. Use a ruler to guide you when cutting the pastry into 6 wide, long strips to keep the edges straight. Save the 2 end pieces in case you need to do any patching. I like wide strips, but if you like a thinner look, feel free to cut thin strips of pastry. Weave the pastry strips, going over and under, making sure they connect with the edges of the pie crust. Fold over the edges of the bottom crust, tucking in the lattice ends. This will help to trap the juices and give a rustic look.\",\"If you prefer a cleaner, tidier look, you can trim the overhanging pieces and crimp the edges with a fork. Brush the top of the pie with the egg wash. Sprinkle with the remaining Tbsp sugar. Place the pie on the prepared baking sheet and bake it for about 90 – 100 minutes, until it’s golden brown and bubbling. Remove the pie from the oven and place it on a wire rack to cool.\",\"Serve the pie warm or at room temperature with whipped cream or ice cream. Makes 6 servings. This keeps well if covered with plastic and refrigerated for up to 4 days.\"]},{\"id\":\"g434\",\"title\":\"Sauerkraut pierogi\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ckbx1h1764123606.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sunflower Oil\",\"Shallots\",\"Sauerkraut\",\"Hispi (sweetheart) Cabbage\",\"Egg\",\"Vegetable Oil\",\"Plain Flour\",\"Vegetable Oil\",\"Shallots\",\"Plain Flour\",\"Butter\",\"Sour Cream\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nFirst, make the crispy shallots. Heat the oil in a saucepan to 180C (a cube of bread will turn golden in 15 secs). Toss the shallots in a little flour a\",\"instructions\":[\"step 1\",\"First, make the crispy shallots. Heat the oil in a saucepan to 180C (a cube of bread will turn golden in 15 secs). Toss the shallots in a little flour and deep-fry for 1 min or until light golden and crispy. Drain on kitchen paper. Can be made up to two days before and kept in an airtight container.\",\"step 2\",\"To make the filling, heat the oil in a medium non-stick frying pan and gently fry the shallots for 10 mins until starting to turn golden.\",\"step 3\",\"Add the sauerkraut and cabbage, and cook for 5-10 mins until the cabbage has softened. Taste and add a little salt if under-seasoned, or sugar if stringent. Scrape into a bowl and leave to cool completely.\",\"step 4\",\"To make the dough, mix the eggs and oil with 125ml water, then gradually add in the flour, mixing well with your hands. Knead it on a well-floured surface until the dough stops sticking to your hands. You should end up with firm, elastic dough. Wrap it in cling film and rest in the fridge for at least 30 mins, or overnight.\",\"step 5\",\"Flour your work surface generously. Roll out the dough to a 40cm circle or until the dough is as thick as £1 coin.\"]},{\"id\":\"g435\",\"title\":\"Sauerkraut pierogii\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/gqlxgc1764368767.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sunflower Oil\",\"Shallots\",\"Sauerkraut\",\"Hispi (sweetheart) Cabbage\",\"Egg\",\"Vegetable Oil\",\"Plain Flour\",\"Vegetable Oil\",\"Shallots\",\"Plain Flour\",\"Butter\",\"Sour Cream\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nFirst, make the crispy shallots. Heat the oil in a saucepan to 180C (a cube of bread will turn golden in 15 secs). Toss the shallots in a little flour a\",\"instructions\":[\"step 1\",\"First, make the crispy shallots. Heat the oil in a saucepan to 180C (a cube of bread will turn golden in 15 secs). Toss the shallots in a little flour and deep-fry for 1 min or until light golden and crispy. Drain on kitchen paper. Can be made up to two days before and kept in an airtight container.\",\"step 2\",\"To make the filling, heat the oil in a medium non-stick frying pan and gently fry the shallots for 10 mins until starting to turn golden.\",\"step 3\",\"Add the sauerkraut and cabbage, and cook for 5-10 mins until the cabbage has softened. Taste and add a little salt if under-seasoned, or sugar if stringent. Scrape into a bowl and leave to cool completely.\",\"step 4\",\"To make the dough, mix the eggs and oil with 125ml water, then gradually add in the flour, mixing well with your hands. Knead it on a well-floured surface until the dough stops sticking to your hands. You should end up with firm, elastic dough. Wrap it in cling film and rest in the fridge for at least 30 mins, or overnight.\",\"step 5\",\"Flour your work surface generously. Roll out the dough to a 40cm circle or until the dough is as thick as £1 coin.\"]},{\"id\":\"g436\",\"title\":\"Sea bass with sizzled ginger, chilli & spring onions\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tqd7s21763780609.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sea Bass Fillets\",\"Sunflower Oil\",\"Ginger\",\"Garlic Clove\",\"Red Chilli\",\"Spring Onions\",\"Soy Sauce\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nSeason 6 sea bass fillets with salt and pepper, then slash the skin 3 times.\\r\\n\\r\\nstep 2\\r\\nHeat a heavy-based frying pan and add 1 tbsp sunflower oil.\\r\\n\\r\\ns\",\"instructions\":[\"step 1\",\"Season 6 sea bass fillets with salt and pepper, then slash the skin 3 times.\",\"step 2\",\"Heat a heavy-based frying pan and add 1 tbsp sunflower oil.\",\"step 3\",\"Once hot, fry the sea bass fillets, skin-side down, for 5 mins or until the skin is very crisp and golden. The fish will be almost cooked through.\",\"step 4\",\"Turn over, cook for another 30 seconds - 1 minute, then transfer to a serving plate and keep warm. You’ll need to fry the sea bass fillets in 2 batches.\",\"step 5\",\"Heat 2 tbsp sunflower oil, then fry the large knob of peeled ginger, cut into matchsticks, 3 thinly sliced garlic cloves and 3 thinly shredded red chillies for about 2 mins until golden.\"]},{\"id\":\"g437\",\"title\":\"Seafood fideuà\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wqqvyq1511179730.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mussels\",\"Prawns\",\"Saffron\",\"Vermicelli Pasta\",\"Olive Oil\",\"Onions\",\"Garlic\",\"Paprika\",\"Monkfish\",\"Baby Squid\",\"Fish Stock\",\"Tomatoes\",\"Lemon\",\"Parsley\"],\"allergens\":[\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Boil the kettle. Empty the mussels into a colander and run under cold water. Throw away any with broken shells. Pick through the shells, tapping each one on the\",\"instructions\":[\"Boil the kettle. Empty the mussels into a colander and run under cold water. Throw away any with broken shells. Pick through the shells, tapping each one on the side of the sink – they should be closed or should slowly close when tapped – if they stay open, throw them away. If any of the shells still have barnacles or stringy beards attached, pull them off with a cutlery knife and rinse the shells well. Keep in the colander, covered with a cold, damp cloth, until you’re ready to cook. Peel the prawn shells on the body section only – leave the heads and tails intact. Score down the backs and pull out any gritty entrails. Chill until you’re ready to cook.\",\"Put the saffron in a small cup, cover with 50ml kettle-hot water and set aside for 10 mins. If using vermicelli, put in a bowl and crush to little pieces (about 1cm long) with your hands.\",\"Heat the oil in a large frying pan with at least a 3cm lip, or a 40cm paella pan. Add the onion and stir around the pan for 5 mins until soft. Add the garlic and cook for 1 min more, then tip in the vermicelli and cook for 5 mins, stirring from time to time, until the vermicelli is toasted brown. Stir in the paprika.\",\"Keeping the heat moderate, stir through the monkfish, squid and saffron with its water, seasoning well. Spread the ingredients out in an even layer, then pour over the hot stock and scatter the tomatoes on top. Bring to a simmer, then cover the whole dish with a tight-fitting lid (or foil). Turn the heat to medium and cook for 6 mins.\",\"Uncover and stir to incorporate the dry top layer of pasta. Push the mussels into the pasta so the hinges are buried in the bottom of the dish, and they stand straight up. Arrange the prawns on top, cover tightly and cook for another 6 mins or until the mussels are open, the prawns are pink and the pasta is cooked through. Leave to simmer for another 2-3 mins to cook off most of the remaining liquid (leave a little in the pan to prevent the pasta from sticking together). Allow to sit for 2-3 mins, then squeeze over the lemon juice and arrange the wedges on top. Scatter with parsley before serving.\"]},{\"id\":\"g438\",\"title\":\"Seafood rice\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/5r5rvx1763287943.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Leek\",\"Chorizo\",\"Turmeric\",\"Rice\",\"Fish Stock\",\"Peas\",\"Frozen Seafood mix\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oil in a deep frying pan, then soften the leek for 5 mins without browning. Add the chorizo and fry until it releases its oils. Stir in the tur\",\"instructions\":[\"step 1\",\"Heat the oil in a deep frying pan, then soften the leek for 5 mins without browning. Add the chorizo and fry until it releases its oils. Stir in the turmeric and rice until coated by the oils, then pour in the stock. Bring to the boil, then simmer for 15 mins, stirring occasionally.\",\"step 2\",\"Tip in the peas and cook for 5 mins, then stir in the seafood to heat through for a final 1-2 mins cooking or until rice is cooked. Check for seasoning and serve immediately with lemon wedges.\"]},{\"id\":\"g439\",\"title\":\"Seri muka kuih\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6ut2og1619790195.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice\",\"Coconut Milk\",\"Water\",\"Salt\",\"Corn Flour\",\"Flour\",\"Eggs\",\"Coconut Cream\",\"Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Soak glutinous rice with water for at least 1 ½ hours prior to using. Drain.\\r\\nPrepare a 9-inch round or square cake pan and spray with cooking spray or line wit\",\"instructions\":[\"Soak glutinous rice with water for at least 1 ½ hours prior to using. Drain.\",\"Prepare a 9-inch round or square cake pan and spray with cooking spray or line with plastic wrap.\",\"Mix coconut milk, water, salt and the rice. Pour it into cake pan, topped with the pandan knots.\",\"Steam for 30 minutes.\",\"After 30 minutes, fluff up the rice and remove pandan knots. Then, using a greased spatula, flatten the steamed rice. Make sure there are no holes/air bubbles and gaps in the rice, especially the sides.\",\"Steam for another 10 minutes.\",\"Combine pandan juice, coconut milk, all purpose flour, cornflour, and sugar. Mix well.\",\"Add eggs and whisk well then strain into a medium sized metal bowl or pot.\",\"Place pandan mixture over simmering water (double boiler or bain-marie)\",\"Stir continuously and cook till custard starts to thicken. (15 minutes)\"]},{\"id\":\"g440\",\"title\":\"Sesame Cucumber Salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/93iok31766436070.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cucumber\",\"Salt\",\"Sesame Seed Oil\",\"Rice Vinegar\",\"Basil Leaves\",\"Red Chilli Flakes\",\"Sesame Seed\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Prep the cucumbers:\\r\\nPeel the cucumbers. Cut them into quarters, lengthwise. (If the seeds are bitter, scrape out the seeds and discard.) Cut the cucumbers agai\",\"instructions\":[\"Prep the cucumbers:\",\"Peel the cucumbers. Cut them into quarters, lengthwise. (If the seeds are bitter, scrape out the seeds and discard.) Cut the cucumbers again, crosswise, into 1/2-inch thick pieces.\",\"Toss the salad:\",\"Place cucumbers into a serving bowl. Sprinkle with salt. Toss with sesame oil, seasoned rice vinegar, basil (if using), and chili flakes. Sprinkle with toasted sesame seeds if using.\"]},{\"id\":\"g441\",\"title\":\"Shakshouka\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/crd1jz1763592990.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tomato\",\"Extra Virgin Olive Oil\",\"Egg\",\"Garlic Clove\",\"Black Pepper\",\"Salt\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nFirst, pan fry the black pepper and garlic over a dry medium heat until fragrant.\\r\\n2\\r\\nAdd a good amount of extra virgin olive oil and infuse for a minute.\\r\\n3\",\"instructions\":[\"1\",\"First, pan fry the black pepper and garlic over a dry medium heat until fragrant.\",\"2\",\"Add a good amount of extra virgin olive oil and infuse for a minute.\",\"3\",\"Once the oil heats up, add the tomatoes and salt, and cover with a lid. Simmer for 5 minutes.\",\"4\",\"Remove the lid and mash the tomatoes. Reduce until you reach the desired consistency of choice.\",\"5\",\"Make craters for the eggs and lower the heat. Carefully crack the eggs into the craters, making sure it touches the pan and not the tomato sauce.\"]},{\"id\":\"g442\",\"title\":\"Shakshuka\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/g373701551450225.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Red Onions\",\"Red Chilli\",\"Garlic\",\"Coriander\",\"Cherry Tomatoes\",\"Caster Sugar\",\"Eggs\",\"Feta\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oil in a frying pan that has a lid, then soften the onions, chilli, garlic and coriander stalks for 5 mins until soft. Stir in the tomatoes and sugar, \",\"instructions\":[\"Heat the oil in a frying pan that has a lid, then soften the onions, chilli, garlic and coriander stalks for 5 mins until soft. Stir in the tomatoes and sugar, then bubble for 8-10 mins until thick. Can be frozen for 1 month.\",\"Using the back of a large spoon, make 4 dips in the sauce, then crack an egg into each one. Put a lid on the pan, then cook over a low heat for 6-8 mins, until the eggs are done to your liking. Scatter with the coriander leaves and serve with crusty bread.\"]},{\"id\":\"g443\",\"title\":\"Shakshuka Feta Cheese\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wpkfin1763597958.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Tomato Sauce\",\"Olive Oil\",\"Shallots\",\"Celery\",\"Garlic\",\"Spinach\",\"Feta\",\"Red Pepper\",\"Ground Cumin\",\"Salt\",\"Black Pepper\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nIn a pan heat the oil medium to high heat, with a tablespoon of olive oil\\r\\n2\\r\\nAdd the chopped vegetables as onions, garlic, celery and red pepper. Stir all t\",\"instructions\":[\"1\",\"In a pan heat the oil medium to high heat, with a tablespoon of olive oil\",\"2\",\"Add the chopped vegetables as onions, garlic, celery and red pepper. Stir all together for 5 mins.\",\"3\",\"Add the cumin powder and salt and pepper and the tomato sauce and let it cook for another 7 mins.\",\"4\",\"Add the eggs, cover and leave to coo for 8 mins. Add the fresh spinach and feta cheese at the end.\",\"5\",\"Serve with fresh bread.\"]},{\"id\":\"g444\",\"title\":\"Shawarma\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kcv6hj1598733479.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Coriander\",\"Cumin\",\"Cardamom\",\"Cayenne Pepper\",\"Paprika\",\"Lemon Juice\",\"Olive Oil\",\"Greek Yogurt\",\"Garlic Clove\",\"Cumin\",\"Lemon Juice\",\"Lettuce\",\"Tomato\",\"Pita Bread\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Combine the marinade ingredients in a large ziplock bag (or bowl).\\r\\nAdd the chicken and use your hands to make sure each piece is coated. If using a ziplock bag\",\"instructions\":[\"Combine the marinade ingredients in a large ziplock bag (or bowl).\",\"Add the chicken and use your hands to make sure each piece is coated. If using a ziplock bag, I find it convenient to close the bag then massage the bag to disperse the rub all over each chicken piece.\",\"Marinate overnight or up to 24 hours.\",\"Combine the Yoghurt Sauce ingredients in a bowl and mix. Cover and put in the fridge until required (it will last for 3 days in the fridge).\",\"Heat grill/BBQ (or large heavy based pan on stove) on medium high. You should not need to oil it because the marinade has oil in it and also thigh fillets have fat. But if you are worried then oil your hotplate/grill. (See notes for baking)\",\"Place chicken on the grill and cook the first side for 4 to 5 minutes until nicely charred, then turn and cook the other side for 3 to 4 minutes (the 2nd side takes less time).\",\"Remove chicken from the grill and cover loosely with foil. Set aside to rest for 5 minutes.\",\"TO SERVE\",\"Slice chicken and pile onto platter alongside flatbreads, Salad and the Yoghurt Sauce.\",\"To make a wrap, get a piece of flatbread and smear with Yoghurt Sauce. Top with a bit of lettuce and tomato and Chicken Shawarma. Roll up and enjoy!\"]},{\"id\":\"g445\",\"title\":\"Shawarma bread\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/i8l2fu1763742525.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Salt\",\"Sugar\",\"Baking Powder\",\"Oil\",\"Water\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1\\r\\nSieve flour and add baking powder,salt,sugar,oil nd mix together\\r\\n2\\r\\nAdd water nd knead the dough for like 10mins\\r\\n3\\r\\nCover the mixture and allow it to rise\\r\",\"instructions\":[\"1\",\"Sieve flour and add baking powder,salt,sugar,oil nd mix together\",\"2\",\"Add water nd knead the dough for like 10mins\",\"3\",\"Cover the mixture and allow it to rise\",\"4\",\"After it rised transfer it to a work surface and form a round (you can use a plate or pot's lid)\",\"5\",\"Heat ur pan and put it\"]},{\"id\":\"g446\",\"title\":\"Shawarma chuck roast wrap\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/swo87v1763595282.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chuck Roast\",\"Beef Stock\",\"Lemon Juice\",\"Ground Cumin\",\"Paprika\",\"Salt\",\"Ground Ginger\",\"Turmeric\",\"Cayenne Pepper\",\"Ground Cinnamon\",\"Ground Coriander\",\"Ground Clove\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nIn a dutch oven or slow cooker, add all the spices, beef broth and lemon juice. Stir to combine..\\r\\n2\\r\\nAdd the beef and turn to coat, spoon some sauce over th\",\"instructions\":[\"1\",\"In a dutch oven or slow cooker, add all the spices, beef broth and lemon juice. Stir to combine..\",\"2\",\"Add the beef and turn to coat, spoon some sauce over the top.\",\"3\",\"Cover and cook on low for 8-10 hours.\",\"4\",\"After cooking, remove beef and use two forks to shred. Discard any excess fat.\",\"5\",\"Skim fat off of the top of the liquid remaining.\"]},{\"id\":\"g447\",\"title\":\"Shrimp Chow Fun\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529445434.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Stick Noodles\",\"Prawns\",\"Egg\",\"Pepper\",\"Sesame Seed Oil\",\"Cornstarch\",\"Oil\",\"Minced Garlic\",\"Ginger\",\"Onion\",\"Bean Sprouts\",\"Spring Onions\",\"Cooking wine\",\"Oyster Sauce\",\"Sugar\",\"Vinegar\",\"Soy Sauce\"],\"allergens\":[\"egg\",\"soy\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1 - SOAK THE RICE NOODLES\\r\\nSoak the rice noodles overnight untill they are soft\\r\\nSTEP 2 - BOIL THE RICE NOODLES\\r\\nBoil the noodles for 10-15 minutes and the\",\"instructions\":[\"STEP 1 - SOAK THE RICE NOODLES\",\"Soak the rice noodles overnight untill they are soft\",\"STEP 2 - BOIL THE RICE NOODLES\",\"Boil the noodles for 10-15 minutes and then rinse with cold water to stop the cooking process of the noodles.\",\"STEP 3 -MARINATING THE SHRIMP\",\"In a bowl add the shrimp, egg, 1 pinch of white pepper, 1 Teaspoon of sesame seed oil, 1 Tablespoon corn starch and 1 tablespoon of oil\",\"Mix together well\",\"STEP 4 - STIR FRY\",\"In a wok add 2 Tablespoons of oil, shrimp and stir fry them until it is golden brown\",\"Set the shrimp aside\"]},{\"id\":\"g448\",\"title\":\"Shrimp With Snow Peas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/fpl3mv1766433431.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cornstarch\",\"Dry sherry\",\"Kosher Salt\",\"Shrimp\",\"Peanut Oil\",\"Ground Ginger\",\"Garlic\",\"Snow Peas\",\"Soy Sauce\",\"Chicken Stock\",\"Scallions\",\"Sesame Seed Oil\"],\"allergens\":[\"soy\",\"peanut\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"You can also use sugar snap peas for this recipe. Save prep time by prepping the peas, ginger, and garlic while the shrimp is marinating.\\r\\n\\r\\nMarinate the shrimp\",\"instructions\":[\"You can also use sugar snap peas for this recipe. Save prep time by prepping the peas, ginger, and garlic while the shrimp is marinating.\",\"Marinate the shrimp:\",\"Mix all marinade ingredients in a large bowl, then add the shrimp. Toss to coat. Let sit for 15 to 20 minutes while you prep the peas, ginger, and garlic.\",\"Stir-fry the ginger and garlic:\",\"Heat a wok or large sauté pan over high heat for 1 minute. Add the peanut oil and let it get hot, about 30 seconds. Add the ginger and garlic and toss to combine. Stir-fry for about 30 seconds.\",\"Add the shrimp, snow peas, soy sauce, stock:\",\"Add the shrimp and all the marinade to the pan (scrape out all the marinade with a rubber spatula). Add the snow peas, soy sauce and chicken stock. Stir-fry until the shrimp turns pink, about 2 minutes.\",\"Add the scallions and finish with sesame oil:\",\"Add the scallions and stir-fry 1 more minute. Turn off the heat and add the sesame oil. Toss to combine once more and serve with steamed rice.\"]},{\"id\":\"g449\",\"title\":\"Sichuan Eggplant\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1oz4nb1765687990.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg Plants\",\"Peanut Oil\",\"Chicken Stock\",\"Sugar\",\"Soy Sauce\",\"Chilli Bean Paste\",\"Sichuan Pepper\",\"Ginger\",\"Garlic\",\"Cornstarch\",\"Apple Cider Vinegar\",\"Scallions\",\"Cilantro\"],\"allergens\":[\"egg\",\"soy\",\"peanut\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"This recipe calls for asian eggplants, or Japanese eggplants. They are long and thin compared to a European or globe eggplant, and much more tender and delicate\",\"instructions\":[\"This recipe calls for asian eggplants, or Japanese eggplants. They are long and thin compared to a European or globe eggplant, and much more tender and delicate. If you can't find them you can substitute globe eggplant, but the dish is really best with the asian eggplant.\",\"*A lot of grocery stores have Asian ingredient aisles now. You should be able to find chili-bean paste, a mixture of preserved chilies mixed with mashed soybeans, there or at any Asian market. (Do not confuse with black bean paste or chili-garlic paste.)\",\"**Sichuan peppercorns are available at some stores and online for quite cheap. They aren't spicy like other peppers but rather have a citrusy flavor and induce a tingly, numbing sensation like a carbonated drink.\",\"Prep eggplant, chili sauce, cornstarch slurry, vinegar and scallions:\",\"Begin your mise en place. Quarter the eggplant lengthwise and chop into large batons and set aside.\",\"In a small bowl, mix together the chicken stock, sugar, and soy sauce and set it aside.\",\"In a second bowl, mix together the chili bean paste, garlic, ginger, and sichuan peppercorns and set it aside.\",\"In a third bowl, mix together the cornstarch with a tablespoon of water and set it aside.\",\"Lastly, in a fourth bowl, mix together the scallions and vinegar and set it aside.\",\"Sauté eggplant:\"]},{\"id\":\"g450\",\"title\":\"Sichuan Style Stir-Fried Chinese Long Beans\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/i0610h1765659464.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chinese Long Beans\",\"Peanut Oil\",\"Dried Chillies\",\"Sichuan Pepper\",\"Salt\",\"Sugar\",\"Sesame Seed Oil\",\"Soy Sauce\"],\"allergens\":[\"soy\",\"peanut\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Chinese long beans can be found in both green and purple varieties. Both have similar flavors and textures, and either kind can be used for this recipe.\\r\\nIf you\",\"instructions\":[\"Chinese long beans can be found in both green and purple varieties. Both have similar flavors and textures, and either kind can be used for this recipe.\",\"If you don't have a wok, use a sturdy, large sauté pan that has at least a two-inch lip.\"]},{\"id\":\"g451\",\"title\":\"Silken Tofu with Sesame Soy Sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/j9nray1765657692.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Silken Tofu\",\"Soy Sauce\",\"Chinese Sesame Sauce\",\"Scallions\",\"Sesame Seed\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Prepare the tofu: \\r\\nDrain the tofu and gently remove it from its packaging onto a large plate. Carefully slice the tofu into 1/2-inch slabs widthwise. With the \",\"instructions\":[\"Prepare the tofu:\",\"Drain the tofu and gently remove it from its packaging onto a large plate. Carefully slice the tofu into 1/2-inch slabs widthwise. With the palm of your hands, gently push the sliced tofu sidewise so that they fan out over the plate.\",\"Garnish with toppings and serve:\",\"Drizzle the soy sauce and sesame sauce on top. Then garnish it with scallions and sesame seeds, and serve.\",\"Tightly cover leftovers and refrigerate for up to 2 days. You can enjoy it cold straight out of the fridge or you can reheat it by microwaving in 30-second increments until warmed through\"]},{\"id\":\"g452\",\"title\":\"Singapore Noodles with Shrimp\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/f3cxnc1765656994.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sesame Seed Oil\",\"Soy Sauce\",\"Seasoned Rice Vinegar\",\"Vermicelli Rice Noodles\",\"Egg\",\"Ground Ginger\",\"Garlic\",\"Carrots\",\"Jalapeno\",\"Onion\",\"Salt\",\"Ham\",\"Napa Cabbage\",\"Scallions\",\"Red Pepper\",\"Curry Powder\",\"Shrimp\",\"Cilantro Leaves\"],\"allergens\":[\"egg\",\"soy\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the sweet onion, look for Vidalia, OSO Sweet, or Walla Walla. The super-sweet varieties are more suited to this stir-fry because at the end of cooking, the \",\"instructions\":[\"For the sweet onion, look for Vidalia, OSO Sweet, or Walla Walla. The super-sweet varieties are more suited to this stir-fry because at the end of cooking, the onion still has a slight crunch.\",\"Make the sauce:\",\"In a bowl, combine the sesame oil, soy sauce, and rice vinegar.\",\"Cook the rice noodles:\",\"Bring a large saucepan of water to a boil, add the noodles, and use tongs to turn them so they are submerged. Cook for 2 minutes, or until they are tender but still have some bite (they will cook a little more once you add them to the skillet).\",\"Drain, rinse with cold water, and use scissors to snip the noodles several times to break them up into shorter lengths.\",\"Scramble the eggs:\",\"In a small bowl whisk together the eggs. Heat the skillet or Dutch oven over medium heat. Add 1 tablespoon of the peanut or canola oil. Add the eggs and scramble them for 2 minutes, or until they form large, soft curds. Transfer them from the pan to a plate or bowl.\",\"Cook the vegetables:\",\"Add 1 tablespoon of the remaining oil to the pan. When it is hot, add the ginger, garlic, carrots, jalapeño, onion, and salt. Cook, stirring constantly, for 2 minutes or until the vegetables start to soften.\"]},{\"id\":\"g453\",\"title\":\"Skillet Apple Pork Chops with Roasted Sweet Potatoes & Zucchini\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/h3ijwo1581013377.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Apples\",\"Garlic\",\"Lemon\",\"Pork\",\"Zucchini\",\"Chicken Stock\",\"Vegetable Oil\",\"Sugar\",\"Butter\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Serves 2\\r\\n\\r\\n\\r\\n1. \\r\\n\\r\\nAdjust racks to top and middle positions and preheat oven to 450 degrees. Wash and dry all produce. Dice sweet potatoes into 1/2-inch piece\",\"instructions\":[\"Serves 2\",\"1.\",\"Adjust racks to top and middle positions and preheat oven to 450 degrees. Wash and dry all produce. Dice sweet potatoes into 1/2-inch pieces. Toss on a baking sheet with a drizzle of oil, salt, and pepper. Roast on top rack for 12 minutes (we'll roast the zucchini then).\",\"2.\",\"Meanwhile, halve and core apple; thinly slice into half-moons. Peel and finely chop garlic. Quarter lemon. Trim and halve zucchini lengthwise; cut crosswise into 1/2-inch-thick half-moons. Toss on a second baking sheet with a drizzle of oil and a pinch of salt and pepper. Set aside.\",\"3.\",\"Pat pork dry with paper towels and season all over with salt and pepper. Heat a drizzle of oil in a large pan over medium-high heat. Add pork and cook until browned and cooked through, 4-5 minutes per side. Turn off heat; transfer to a plate.\",\"4.\",\"Once sweet potatoes have roasted 12 minutes, transfer baking sheet with zucchini to middle rack and continue roasting until both veggies are browned and softened, 12-15 minutes more.\",\"5.\"]},{\"id\":\"g454\",\"title\":\"Sledz w Oleju (Polish Herrings)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/7ttta31593350374.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Herring\",\"Onion\",\"Olive Oil\",\"Allspice\",\"Pepper\",\"Bay Leaf\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Soak herring in cold water for at least 1 hour. If very salty, repeat, changing the water each time.\\r\\n\\r\\nDrain thoroughly and slice herring into bite-size pieces\",\"instructions\":[\"Soak herring in cold water for at least 1 hour. If very salty, repeat, changing the water each time.\",\"Drain thoroughly and slice herring into bite-size pieces.\",\"Place in a jar large enough to accommodate the pieces and cover with oil, allspice, peppercorns, and bay leaf. Close the jar.\",\"Refrigerate for 2 to 3 days before eating. This will keep refrigerated up to 2 weeks.\",\"Serve with finely chopped onion or onion slices, lemon, and parsley or dill.\"]},{\"id\":\"g455\",\"title\":\"Slow-roast lamb with cinnamon, fennel & citrus\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/gr4lo51763791826.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb Leg\",\"Lemon\",\"Olive Oil\",\"Clear Honey\",\"Cinnamon\",\"Fennel Seeds\",\"Ground Cumin\",\"Garlic\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut the lamb into a large food bag with all the juice and marinate overnight.\\r\\n\\r\\nstep 2\\r\\nThe next day, take the lamb out of the fridge 1 hr before you w\",\"instructions\":[\"step 1\",\"Put the lamb into a large food bag with all the juice and marinate overnight.\",\"step 2\",\"The next day, take the lamb out of the fridge 1 hr before you want to cook it. Heat oven to 220C/200C fan/gas 7. Take the lamb out of the marinade (reserve remaining marinade) and pat dry. Rub with half the oil and roast for 15-20 mins until browned. Remove lamb and reduce oven to 160C/140C fan/gas 3.\",\"step 3\",\"Mix the zests, remaining oil, honey, spices and garlic with plenty of seasoning. Lay a large sheet of baking parchment on a large sheet of foil. Sit the lamb leg on top, rub all over with the paste and pull up the sides of the foil. Drizzle marinade into base, and scrunch foil to seal.\",\"step 4\",\"Roast for 4 hrs, until very tender. Rest, still wrapped, for 30 mins. Unwrap and serve with juices.\"]},{\"id\":\"g456\",\"title\":\"Slow-roasted ham with lemon, garlic & sage\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/w36ets1764362474.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Garlic\",\"Lemon\",\"Salt\",\"Black Pepper\",\"Vegetable Oil\",\"Pork Shoulder\",\"Dry White Wine\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oven to 200C/180C fan/gas 6. Bash the garlic, sage, lemon zest, salt and pepper together using a pestle and mortar until the mixture becomes a \",\"instructions\":[\"step 1\",\"Heat the oven to 200C/180C fan/gas 6. Bash the garlic, sage, lemon zest, salt and pepper together using a pestle and mortar until the mixture becomes a paste. Stir in the oil, then spread the mixture over the pork shoulder, avoiding the skin on top. Score the skin using a sharp knife, then rub a large pinch of salt into the skin. Tie the pork together using kitchen string.\",\"step 2\",\"Line a large baking tray with a double layer of foil and put the pork on top, skin-side up. Bring the sides of the foil up around the pork to create a parcel, then pour the wine into the tray around the sides. Transfer to the oven and reduce the temperature to 140C/120C fan/gas 1. Roast for 4-5 hrs, or until a meat thermometer inserted into the thickest part of the pork reads 70C.\",\"step 3\",\"Turn the oven up to 240C/220C fan/gas 9. Carefully spoon the pork roasting juices from the pan into a saucepan and cook over a medium heat for 10-15 mins, or until reduced by a third. Season to taste.\",\"step 4\",\"Meanwhile, arrange the foil around the meat so only the skin is exposed, then return to the oven for 10-15 mins until the skin is puffed up and browned all over. Leave to rest for 20 mins before slicing. Serve with the sauce drizzled over.\"]},{\"id\":\"g457\",\"title\":\"Smoked aubergine purée\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8c8m4q1763791156.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Aubergine\",\"Lemon\",\"Garlic\",\"Yogurt\",\"Dill\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat grill to very hot. Slice the aubergines in half lengthways, then grill for 25 mins, turning occasionally, until soft – the skin will remain firm, b\",\"instructions\":[\"step 1\",\"Heat grill to very hot. Slice the aubergines in half lengthways, then grill for 25 mins, turning occasionally, until soft – the skin will remain firm, but the flesh will soften. Lift the aubergines off the grill and leave until cool enough to handle.\",\"step 2\",\"Using a sharp knife, score the grilled flesh and scoop out the flesh with a spoon. Tip into a bowl and mash with a fork until you get a thick pulp. Beat in the lemon juice and garlic. Add the yogurt and dill, and season. Serve while still warm.\"]},{\"id\":\"g458\",\"title\":\"Smoked Haddock Kedgeree\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1550441275.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Onion\",\"Cardamom\",\"Turmeric\",\"Cinnamon Stick\",\"Bay Leaf\",\"Basmati Rice\",\"Chicken Stock\",\"Smoked Haddock\",\"Eggs\",\"Parsley\",\"Lemon\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Melt 50g butter in a large saucepan (about 20cm across), add 1 finely chopped medium onion and cook gently over a medium heat for 5 minutes, until softened but \",\"instructions\":[\"Melt 50g butter in a large saucepan (about 20cm across), add 1 finely chopped medium onion and cook gently over a medium heat for 5 minutes, until softened but not browned.\",\"Stir in 3 split cardamom pods, ¼ tsp turmeric, 1 small cinnamon stick and 2 bay leaves, then cook for 1 minute.\",\"Tip in 450g basmati rice and stir until it is all well coated in the spicy butter.\",\"Pour in 1 litre chicken or fish stock, add ½ teaspoon salt and bring to the boil, stir once to release any rice from the bottom of the pan. Cover with a close-fitting lid, reduce the heat to low and leave to cook very gently for 12 minutes.\",\"Meanwhile, bring some water to the boil in a large shallow pan. Add 750g un-dyed smoked haddock fillet and simmer for 4 minutes, until the fish is just cooked. Lift it out onto a plate and leave until cool enough to handle.\",\"Hard-boil 3 eggs for 8 minutes.\",\"Flake the fish, discarding any skin and bones. Drain the eggs, cool slightly, then peel and chop.\",\"Uncover the rice and remove the bay leaves, cinnamon stick and cardamom pods if you wish to. Gently fork in the fish and the chopped eggs, cover again and return to the heat for 2-3 minutes, or until the fish has heated through.\",\"Gently stir in almost all the 3 tbsp chopped fresh parsley, and season with a little salt and black pepper to taste. Serve scattered with the remaining parsley and garnished with 1 lemon, cut into wedges.\"]},{\"id\":\"g459\",\"title\":\"Smoky chicken skewers\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/3um6il1763794322.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Olive Oil\",\"Fennel Seeds\",\"Ground Cumin\",\"sweet smoked paprika\",\"Garlic\",\"Red Wine Vinegar\",\"Smoky Aïoli\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nYou need 15 skewers: if wooden, soak in water for 10 mins. Cut chicken into 3cm pieces and place in a bowl. Add 1 tbsp olive oil, the spices, garlic and\",\"instructions\":[\"step 1\",\"You need 15 skewers: if wooden, soak in water for 10 mins. Cut chicken into 3cm pieces and place in a bowl. Add 1 tbsp olive oil, the spices, garlic and vinegar, toss well and season. You can do this up to a day before and refrigerate.\",\"step 2\",\"Thread 2-3 pieces on each skewer. Pour remaining oil in a frying pan or rub onto a griddle pan. Get the pan hot and sear the chicken for 3-4 mins on each side – you may have to do this in batches, keeping the cooked skewers warm in a low oven. Serve with smoky aïoli if you like.\"]},{\"id\":\"g460\",\"title\":\"Smoky Lentil Chili with Squash\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uwxqwy1483389553.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Leek\",\"Garlic\",\"Cumin\",\"Coriander\",\"Smoked Paprika\",\"Cinnamon\",\"Chili Powder\",\"Cocoa\",\"Dried Oregano\",\"Diced Tomatoes\",\"Water\",\"Carrots\",\"Brown Lentils\",\"Sea Salt\",\"Squash\",\"Cashews\",\"Apple Cider Vinegar\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Begin by roasting the squash. Slice it into thin crescents and drizzle with a little oil and sprinkle with sea salt. I added a fresh little sage I had in the fr\",\"instructions\":[\"Begin by roasting the squash. Slice it into thin crescents and drizzle with a little oil and sprinkle with sea salt. I added a fresh little sage I had in the fridge, but it’s unnecessary. Roast the squash a 205 C (400 F) for 20-30 minutes, flipping halfway through, until soft and golden. Let cool and chop into cubes.\",\"Meanwhile, rinse the lentils and cover them with water. Bring them to the boil then turn down to a simmer and let cook (uncovered) for 20-30 minutes, or until tender. Drain and set aside.\",\"While the lentils are cooking heat the 1 Tbsp. of oil on low in a medium pot. Add the onions and leeks and sauté for 5 or so minutes, or until they begin to soften. Add the garlic next along with the cumin and coriander, cooking for a few more minutes. Add the remaining spices – paprika, cinnamon, chilli, cocoa, Worcestershire sauce, salt, and oregano. Next add the can of tomatoes, the water or stock, and carrots. Let simmer, covered, for 20 minutes or until the veg is tender and the mixture has thickened up. You’ll need to check on the pot periodically for a stir and a top of of liquid if needed.\",\"Add the lentils and chopped roasted squash. Let cook for 10 more minutes to heat through.\",\"Serve with sliced jalapeno, lime wedges, cilantro, green onions, and cashew sour cream.\",\"SIMPLE CASHEW SOUR CREAM\",\"1 Cup Raw Unsalted Cashews\",\"Pinch Sea Salt\",\"1 tsp. Apple Cider Vinegar\",\"Water\"]},{\"id\":\"g461\",\"title\":\"Snert (Dutch Split Pea Soup)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9ptx0a1565090843.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Peas\",\"Pork\",\"Vegetable Stock Cube\",\"Celery\",\"Carrots\",\"Potatoes\",\"Onion\",\"Leek\",\"Celeriac\",\"Sausages\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Gather the ingredients.\\r\\n\\r\\nIn a large soup pot, bring water, split peas, pork belly or bacon, pork chop, and bouillon cube to a boil. Reduce the heat to a simme\",\"instructions\":[\"Gather the ingredients.\",\"In a large soup pot, bring water, split peas, pork belly or bacon, pork chop, and bouillon cube to a boil. Reduce the heat to a simmer, cover and let cook for 45 minutes, stirring occasionally and skimming off any foam that rises to the top.\",\"Remove the pork chop, debone, and thinly slice the meat. Set aside.\",\"Add the celery, carrots, potato, onion, leek, and celeriac to the soup. Return to the boil, reduce the heat to a simmer and let cook, uncovered, for another 30 minutes, adding a little extra water if the ingredients start to stick to the bottom of the pot.\",\"Add the smoked sausage for the last 15 minutes of cooking time. When the vegetables are tender, remove the bacon and smoked sausage, slice thinly and set aside.\",\"If you prefer a smooth consistency, purée the soup with a stick blender. Season to taste with salt and pepper. Add the meat back to the soup, setting some slices of rookworst aside.\",\"Serve in heated bowls or soup plates, garnished with slices of rookworst and chopped celery leaf.\",\"Enjoy!\"]},{\"id\":\"g462\",\"title\":\"Soy-Glazed Meatloaves with Wasabi Mashed Potatoes & Roasted Carrots\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/o2wb6p1581005243.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Carrots\",\"Scallions\",\"Garlic\",\"Bread\",\"Garlic Powder\",\"Soy Sauce\",\"Ground Beef\",\"Vegetable Oil\",\"Sugar\",\"Butter\"],\"allergens\":[\"milk\",\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1. Preheat oven to 425 degrees. Wash and dry all produce. Dice potatoes into 1/2-inch pieces. Trim, peel, and cut carrots on a diagonal into 1/2-inch-thick piec\",\"instructions\":[\"1. Preheat oven to 425 degrees. Wash and dry all produce. Dice potatoes into 1/2-inch pieces. Trim, peel, and cut carrots on a diagonal into 1/2-inch-thick pieces. Trim and thinly slice scallions, separating whites from greens; finely chop whites. Peel and finely chop garlic.\",\"2. In a medium bowl, soak bread with 2 TBSP water (4 TBSP for 4 servings); break up with your hands until pasty. Stir in beef, sriracha, scallion whites, half the garlic, salt (we used 3/4 tsp kosher salt; 11/2 tsp for 4), and pepper. Form into two 1-inch-tall loaves (four loaves for 4). Place on one side of a baking sheet. Toss carrots on empty side of same sheet with a drizzle of oil, salt, and pepper. (For 4, spread meatloaves out across whole sheet and add carrots to a second sheet.) Bake for 20 minutes (we'll glaze the meatloaves then).\",\"3. Meanwhile, place potatoes in a medium pot with enough salted water to cover by 2 inches. Bring to a boil and cook until very\",\"tender, 12-15 minutes. Reserve 1/2 cup potato cooking liquid, then drain. While potatoes cook, in a small bowl, combine soy sauce, garlic powder, 1/4 cup ketchup (1/2 cup for 4 servings), and 2 tsp sugar (4 tsp for 4).\",\"4. Once meatloaves and carrots have baked 20 minutes, remove from oven. Spoon half the ketchup glaze over meatloaves (save\",\"the rest for serving); return to oven until carrots are browned and tender, meatloaves are cooked through, and glaze is tacky, 4-5 minutes more.\",\"5. Meanwhile, melt 2 TBSP butter (4 TBSP for 4 servings) in pot used for potatoes over medium heat. Add remaining garlic and cook\",\"until fragrant, 30 seconds. Add potatoes and 1/4 tsp wasabi. Mash, adding splashes of reserved potato cooking liquid as necessary until smooth. Season with salt and pepper. (If you like things spicy, stir in more wasabi!)\",\"6. Divide meatloaves, mashed potatoes, and roasted carrots between plates. Sprinkle with scallion greens and serve with remaining ketchup glaze on the side for dipping.\"]},{\"id\":\"g463\",\"title\":\"Spaghetti alla Carbonara\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/llcbn01574260722.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Spaghetti\",\"Egg Yolks\",\"Salt\",\"Bacon\",\"Pecorino\",\"Black Pepper\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\nPut a large saucepan of water on to boil.\\r\\n\\r\\nSTEP 2\\r\\nFinely chop the 100g pancetta, having first removed any rind. Finely grate 50g pecorino cheese and \",\"instructions\":[\"STEP 1\",\"Put a large saucepan of water on to boil.\",\"STEP 2\",\"Finely chop the 100g pancetta, having first removed any rind. Finely grate 50g pecorino cheese and 50g parmesan and mix them together.\",\"STEP 3\",\"Beat the 3 large eggs in a medium bowl and season with a little freshly grated black pepper. Set everything aside.\",\"STEP 4\",\"Add 1 tsp salt to the boiling water, add 350g spaghetti and when the water comes back to the boil, cook at a constant simmer, covered, for 10 minutes or until al dente (just cooked).\",\"STEP 5\",\"Squash 2 peeled plump garlic cloves with the blade of a knife, just to bruise it.\"]},{\"id\":\"g464\",\"title\":\"Spaghetti Bolognese\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sutysw1468247559.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"onions\",\"olive oil\",\"garlic\",\"lean minced beef\",\"mushrooms\",\"dried oregano\",\"tomatoes\",\"hot beef stock\",\"tomato puree\",\"worcestershire sauce\",\"spaghetti\",\"parmesan\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Put the onion and oil in a large pan and fry over a fairly high heat for 3-4 mins. Add the garlic and mince and fry until they both brown. Add the mushrooms and\",\"instructions\":[\"Put the onion and oil in a large pan and fry over a fairly high heat for 3-4 mins. Add the garlic and mince and fry until they both brown. Add the mushrooms and herbs, and cook for another couple of mins.\",\"Stir in the tomatoes, beef stock, tomato ketchup or purée, Worcestershire sauce and seasoning. Bring to the boil, then reduce the heat, cover and simmer, stirring occasionally, for 30 mins.\",\"Meanwhile, cook the spaghetti in a large pan of boiling, salted water, according to packet instructions. Drain well, run hot water through it, put it back in the pan and add a dash of olive oil, if you like, then stir in the meat sauce. Serve in hot bowls and hand round Parmesan cheese, for sprinkling on top.\"]},{\"id\":\"g465\",\"title\":\"Spaghetti with Spanish flavours\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vpcqn01763335688.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chorizo\",\"Spaghetti\",\"Parsley\",\"Red Pepper\",\"Olive Oil\",\"Parmesan Cheese\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut a pan of water on over a high heat to boil. Meanwhile, snip the chorizo into strips with scissors, and chop the parsley and peppers (check for stray\",\"instructions\":[\"step 1\",\"Put a pan of water on over a high heat to boil. Meanwhile, snip the chorizo into strips with scissors, and chop the parsley and peppers (check for stray seeds first).\",\"step 2\",\"When the water is boiling briskly, add the spaghetti with a good measure of salt, stir and return to the boil. Cook for 3 minutes.\",\"step 3\",\"In a large frying pan, heat the oil, add the chorizo and peppers and plenty of black pepper. Cook for a minute or so, until heated through and the juices are stained red from the paprika in the chorizo. Scoop half a mugful of pasta water from the pan, drain the remainder and tip the spaghetti into the frying pan.\",\"step 4\",\"Add the parsley and parmesan, toss well and splash in the pasta water, to moisten. Hand round extra parmesan at the table.\"]},{\"id\":\"g466\",\"title\":\"Spanish beans with chicken & chorizo\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/bpkxtw1763332446.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pinto Beans\",\"Onion\",\"Paprika\",\"Thyme\",\"Bay Leaves\",\"Parsley\",\"Chicken Thighs\",\"Jersey Royal Potatoes\",\"Chorizo\",\"Spinach\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nSoak the beans for at least 4 hrs or overnight in a large bowl with plenty of water to cover. Next day, rinse and drain, then put in a large heavy based\",\"instructions\":[\"step 1\",\"Soak the beans for at least 4 hrs or overnight in a large bowl with plenty of water to cover. Next day, rinse and drain, then put in a large heavy based pan with the onion, paprika, herb bundle and chicken. Pour over enough water or stock to cover, bring to the boil, then reduce the heat, cover and simmer for 45 mins.\",\"step 2\",\"Remove the chicken to a plate, then add the potatoes and chorizo to the pan. Continue cooking for 30 mins until the beans and potatoes are tender.\",\"step 3\",\"Discard the skin and bones from the chicken and tear into large chunks. Return the chicken to the pan with the spinach and simmer for 5 mins.\"]},{\"id\":\"g467\",\"title\":\"Spanish Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pqulvm1763282839.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Onion\",\"Paprika\",\"Lemon\",\"Parsley\",\"Chicken Stock\",\"Olive Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 190C/170C fan/gas 5. Put all the ingredients into a large, wide ovenproof dish. Mix everything together with your hands and season.\\r\\n\\r\\nstep\",\"instructions\":[\"step 1\",\"Heat oven to 190C/170C fan/gas 5. Put all the ingredients into a large, wide ovenproof dish. Mix everything together with your hands and season.\",\"step 2\",\"Bake for 45 mins, stirring the onions after 20 mins, until the chicken is golden and the onions tender. Serve with rice.\"]},{\"id\":\"g468\",\"title\":\"Spanish chicken pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8ovxf41763253962.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Paprika\",\"Olive Oil\",\"Onion\",\"Garlic\",\"Tinned Tomatos\",\"Chicken\",\"Roasted pepper\",\"Green Olives\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/fan 180C/gas 6. Boil the potatoes for 15-20 mins until tender. Drain, return to the pan, then mash with some seasoning and 2 tsp of th\",\"instructions\":[\"step 1\",\"Heat oven to 200C/fan 180C/gas 6. Boil the potatoes for 15-20 mins until tender. Drain, return to the pan, then mash with some seasoning and 2 tsp of the paprika.\",\"step 2\",\"Meanwhile, heat the oil in a large pan, then fry the onions and garlic for a few mins until softened. Stir in the remaining paprika for 1 min, add the tomatoes , then, bring to a simmer. Tip into a large ovenproof dish, then stir in the chicken, peppers, olives and some seasoning.\",\"step 3\",\"Spoon over the mash, then bake for 15 mins until the mash is golden on top and the sauce is bubbling.\"]},{\"id\":\"g469\",\"title\":\"Spanish fig & almond balls\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/si2rty1763282314.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Almonds\",\"Figs\",\"Dried Apricots\",\"Dried cranberries\",\"Brandy\",\"Clear Honey\",\"Cloves\",\"Sesame Seed\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nWhizz the almonds in a food processor until most are finely chopped, then tip into a large bowl. Roughly chop the figs, then whizz to a smooth sticky pa\",\"instructions\":[\"step 1\",\"Whizz the almonds in a food processor until most are finely chopped, then tip into a large bowl. Roughly chop the figs, then whizz to a smooth sticky paste. Scrape onto the almonds then, using your hands, mix together well with the dried fruit, brandy, honey and cloves.\",\"step 2\",\"Divide the mixture into 6 and roll into balls. Tip the sesame seeds onto a tray, then roll the balls in them until covered. Cover the tray loosely with a clean tea towel, then leave the fig balls to dry for a week before packaging. Will keep in a cool place for 2 months.\"]},{\"id\":\"g470\",\"title\":\"Spanish meatballs with clams, chorizo & squid\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/2wt8721763334199.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Shallots\",\"Smoked Paprika\",\"Garlic\",\"Garlic\",\"Dry sherry\",\"Breadcrumbs\",\"Pork\",\"Egg Yolks\",\"Olive Oil\",\"Chorizo\",\"Squid\",\"White Wine\",\"Tomato\",\"Clams\",\"Parsley\",\"Extra Virgin Olive Oil\"],\"allergens\":[\"egg\",\"milk\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nMelt the butter in a heavy-based casserole, then soften the shallots for 5 mins. Add the paprika and crushed garlic and cook for 1 min until the paprika\",\"instructions\":[\"step 1\",\"Melt the butter in a heavy-based casserole, then soften the shallots for 5 mins. Add the paprika and crushed garlic and cook for 1 min until the paprika becomes fragrant. Splash in the sherry, then pour the whole lot into a bowl with the breadcrumbs. Season and cool.\",\"step 2\",\"Add the pork mince and the egg yolk to the bowl, then beat well. Shape into 18 small meatballs. Wipe the pan, put on a medium-high heat, then add the oil. Fry the meatballs for 5 mins, just to colour, then lift onto a plate, but keep the oil in the pan. Sizzle the chorizo with the sliced garlic. Add the squid and fry to give a little colour. Now tip in the white wine and bring to the boil, scraping the bottom. Stir in the pulped tomatoes, bring to the boil, then add the meatballs and the clams. Cover and cook for 5 mins until the clam shells open. Discard any that stay shut. Sprinkle with the chopped parsley, drizzle with the extra virgin oil, then serve with crusty bread.\"]},{\"id\":\"g471\",\"title\":\"Spanish rice & prawn one-pot\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sl6vqv1763335988.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onion\",\"Red Pepper\",\"Green Pepper\",\"Chorizo\",\"Garlic\",\"Olive Oil\",\"Basmati Rice\",\"Tinned Tomatos\",\"Prawns\"],\"allergens\":[\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nBoil the kettle. In a non-stick frying or shallow pan with a lid, fry the onion, peppers, chorizo and garlic in the oil over a high heat for 3 mins. Sti\",\"instructions\":[\"step 1\",\"Boil the kettle. In a non-stick frying or shallow pan with a lid, fry the onion, peppers, chorizo and garlic in the oil over a high heat for 3 mins. Stir in the rice and chopped tomatoes with 500ml boiling water, cover, then cook over a high heat for 12 mins.\",\"step 2\",\"Uncover, then stir – the rice should be almost tender. Stir in the prawns, with a splash more water if the rice is looking dry, then cook for another min until the prawns are just pink and rice tender.\"]},{\"id\":\"g472\",\"title\":\"Spanish seafood rice\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/c6ghxm1763335584.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Red Pepper\",\"Yellow Pepper\",\"Garlic Clove\",\"Paella Rice\",\"Vegetable Stock\",\"Saffron\",\"Frozen Seafood mix\",\"Lemon\",\"Parsley\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oil in a large saucepan and soften the onion for 6-7 mins. Add the pepper and garlic, cook for 2 mins more, then stir in the paella rice and co\",\"instructions\":[\"step 1\",\"Heat the oil in a large saucepan and soften the onion for 6-7 mins. Add the pepper and garlic, cook for 2 mins more, then stir in the paella rice and cook for 1 min, stirring to coat.\",\"step 2\",\"Pour in the stock, add the saffron and bring to the boil. Cook, uncovered, at a gentle bubble, for 20 mins, stirring occasionally until the rice is tender.\",\"step 3\",\"Stir in the seafood and lemon juice and cook for 2 mins or until piping hot and completely cooked through. Serve in warm bowls scattered with the parsley.\"]},{\"id\":\"g473\",\"title\":\"Spanish tomato bread with jamón Serrano\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hsp1fo1763327867.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tomato\",\"Garlic\",\"Olive Oil\",\"Salt\",\"Pepper\",\"Baguette\",\"Serrano Ham\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nMix together the chopped tomatoes, garlic clove, olive oil, salt and pepper. Keep in the fridge until needed.\\r\\n\\r\\nstep 2\\r\\nTo serve, toast 20 slices of ba\",\"instructions\":[\"step 1\",\"Mix together the chopped tomatoes, garlic clove, olive oil, salt and pepper. Keep in the fridge until needed.\",\"step 2\",\"To serve, toast 20 slices of baguette. Spoon a little tomato topping on to each piece of toast. Tear 5-6 slices of jamón Serrano into pieces and put one piece on each slice of bread.\"]},{\"id\":\"g474\",\"title\":\"Spanish Tortilla\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/quuxsx1511476154.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onion\",\"Olive Oil\",\"Butter\",\"Potatoes\",\"Garlic\",\"Eggs\",\"Parsley\",\"Baguette\",\"Vine Tomatoes\",\"Olive Oil\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Put a large non-stick frying pan on a low heat. Cook the onion slowly in the oil and butter until soft but not brown – this should take about 15 mins. Add the p\",\"instructions\":[\"Put a large non-stick frying pan on a low heat. Cook the onion slowly in the oil and butter until soft but not brown – this should take about 15 mins. Add the potatoes, cover the pan and cook for a further 15-20 mins, stirring occasionally to make sure they fry evenly.\",\"When the potatoes are soft and the onion is shiny, crush 2 garlic cloves and stir in, followed by the beaten eggs.\",\"Put the lid back on the pan and leave the tortilla to cook gently. After 20 mins, the edges and base should be golden, the top set but the middle still a little wobbly. To turn it over, slide it onto a plate and put another plate on top, turn the whole thing over and slide it back into the pan to finish cooking. Once cooked, transfer to a plate and serve the tortilla warm or cold, scattered with the chopped parsley.\",\"To accompany, take slices of warmed baguette, stab all over with a fork and rub with the remaining garlic, pile on grated tomatoes and season with sea salt and a drizzle of olive oil.\"]},{\"id\":\"g475\",\"title\":\"Spanish-style slow-cooked lamb shoulder & beans\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9kwatm1763327074.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb Shoulder\",\"Olive Oil\",\"Onion\",\"Carrots\",\"Garlic Bulb\",\"Chicken Stock\",\"Butter Beans\",\"Roasted pepper\",\"Black Olives\",\"Parsley\",\"Garlic\",\"Hot smoked paprika\",\"Olive Oil\",\"Rosemary\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make the spice mix, combine all of the ingredients together with a large pinch of salt. Slash the lamb shoulder all over with a sharp knife and rub i\",\"instructions\":[\"step 1\",\"To make the spice mix, combine all of the ingredients together with a large pinch of salt. Slash the lamb shoulder all over with a sharp knife and rub in. If you have the time, marinate for up to 24 hrs, but this is not essential.\",\"step 2\",\"Heat the oven to 150C/130C fan/gas 2. Heat the oil in a large flameproof casserole dish or roasting tin over a medium-high heat, add the onions, carrots and garlic and sizzle for 5 mins until the onions and carrots are softened. Pour over the stock, then bring to the boil. Nestle the lamb in the pan and cover, then transfer to the oven and roast for 2 hrs.\",\"step 3\",\"Uncover and transfer the lamb to a plate using tongs. Stir the beans, peppers and olives through the stock in the pan, sit the lamb back on top and return to the oven, uncovered, for 1 hr 30 mins until the lamb is cooked through. Transfer the lamb to a board and shred using two forks. Stir the parsley through the braised beans before serving.\"]},{\"id\":\"g476\",\"title\":\"Spiced smoky barbecued chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/a08uqk1761848682.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Garlic\",\"Lemon\",\"Curry Powder\",\"Chilli Flakes\",\"Olive Oil\",\"Chicken Thighs\",\"Rosemary\",\"Rosemary\",\"Thyme\",\"Thyme\",\"Bay Leaves\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nMake the marinade. Smash the garlic with a little salt using a pestle and mortar. Add the lemon zest and juice, the spice mix, chilli, oil and a good gr\",\"instructions\":[\"step 1\",\"Make the marinade. Smash the garlic with a little salt using a pestle and mortar. Add the lemon zest and juice, the spice mix, chilli, oil and a good grinding of black pepper. Mix to a paste. This can be done in a mini food processor.\",\"step 2\",\"Toss the chicken in the marinade and set aside while you light the barbecue. When the barbecue’s hot, lay the bunches of herbs on the grid and put the chicken, skin side up, on top. Close the lid, if your barbecue has one, and cook the chicken on the smouldering herbs for about 10 minutes until the meat starts to colour. Turn the chicken and continue to cook for a further 20-30 minutes, turning as necessary, until it is slightly charred from the burnt herbs and cooked through to the bone.\"]},{\"id\":\"g477\",\"title\":\"Spiced tortilla\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/7b862e1763194846.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sunflower Oil\",\"Onion\",\"Red Chilli\",\"Curry Powder\",\"Cherry Tomatoes\",\"Potatoes\",\"Coriander\",\"Egg\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oil in a large frying pan. Fry the onion and half the chilli for 5 mins until softened. Tip in the spices, fry for 1 min more, then add the che\",\"instructions\":[\"step 1\",\"Heat the oil in a large frying pan. Fry the onion and half the chilli for 5 mins until softened. Tip in the spices, fry for 1 min more, then add the cherry tomatoes, potatoes and coriander stalks to the pan. Season the eggs well, pour over the top of the veg and leave to cook gently for 8-10 mins until almost set.\",\"step 2\",\"Heat the grill and flash the tortilla underneath for 1-2 mins until the top is set. Scatter the coriander leaves and remaining chilli over the top, slice into wedges and serve with a green salad.\"]},{\"id\":\"g478\",\"title\":\"Spicy Arrabiata Penne\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ustsqw1468250014.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"penne rigate\",\"olive oil\",\"garlic\",\"chopped tomatoes\",\"red chilli flakes\",\"italian seasoning\",\"basil\",\"Parmigiano-Reggiano\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Bring a large pot of water to a boil. Add kosher salt to the boiling water, then add the pasta. Cook according to the package instructions, about 9 minutes.\\r\\nIn\",\"instructions\":[\"Bring a large pot of water to a boil. Add kosher salt to the boiling water, then add the pasta. Cook according to the package instructions, about 9 minutes.\",\"In a large skillet over medium-high heat, add the olive oil and heat until the oil starts to shimmer. Add the garlic and cook, stirring, until fragrant, 1 to 2 minutes. Add the chopped tomatoes, red chile flakes, Italian seasoning and salt and pepper to taste. Bring to a boil and cook for 5 minutes. Remove from the heat and add the chopped basil.\",\"Drain the pasta and add it to the sauce. Garnish with Parmigiano-Reggiano flakes and more basil and serve warm.\"]},{\"id\":\"g479\",\"title\":\"Spicy North African Potato Salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/urtwux1486983078.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Small Potatoes\",\"Harissa Spice\",\"olive oil\",\"Lemon\",\"Spring onions\",\"Rocket\",\"Feta\",\"Mint\",\"Pine nuts\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Cook potatoes - place potatoes in a pot of cold water, and bring to the boil. Boil 20 minutes, or until potatoes are tender. You know they are cooked when you c\",\"instructions\":[\"Cook potatoes - place potatoes in a pot of cold water, and bring to the boil. Boil 20 minutes, or until potatoes are tender. You know they are cooked when you can stick a knife in them and the knife goes straight through.\",\"Combine harissa spice, olive oil, salt and pepper and lemon juice in a small bowl and whisk until combined.\",\"Once potatoes are cooked, drain water and roughly chop potatoes in half.\",\"Add harissa mix and spring onions/green onions to potatoes and stir.\",\"In a large salad bowl, lay out arugula/rocket.\",\"Top with potato mix and toss.\",\"Add fetta, mint and sprinkle over pine nuts.\",\"Adjust salt and pepper to taste.\"]},{\"id\":\"g480\",\"title\":\"Spicy Thai prawn noodles\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/568t931763584227.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Noodles\",\"Sesame Seed Oil\",\"Egg\",\"Red Chilli\",\"Ginger\",\"Prawns\",\"Soy Sauce\",\"Coriander\",\"Mint\",\"Lime\",\"Peanuts\"],\"allergens\":[\"egg\",\"soy\",\"peanut\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nCook the noodles following the pack instructions, drain and set aside for later. Heat the oil in a large frying pan and pour in the beaten egg. Swirl ar\",\"instructions\":[\"step 1\",\"Cook the noodles following the pack instructions, drain and set aside for later. Heat the oil in a large frying pan and pour in the beaten egg. Swirl around the pan to make a thin omelette, cook for 1-2 mins, then flip over and cook the other side for 1 min. Tip out and slice into thin strips.\",\"step 2\",\"Add the chilli and ginger to the pan, fry for 1-2 mins then tip in the noodles, prawns and egg. Splash in the soy sauce and stir-fry for 1 min more. Throw in the chopped herbs and pour over the lime juice and zest, then sprinkle over the chopped peanuts and serve.\"]},{\"id\":\"g481\",\"title\":\"Spinach & Ricotta Cannelloni\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wspuvp1511303478.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Garlic\",\"Caster Sugar\",\"Red Wine Vinegar\",\"Chopped Tomatoes\",\"Basil Leaves\",\"Mascarpone\",\"Milk\",\"Parmesan\",\"Mozzarella\",\"Spinach\",\"Parmesan\",\"Ricotta\",\"Nutmeg\",\"Cannellini Beans\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"First make the tomato sauce. Heat the oil in a large pan and fry the garlic for 1 min. Add the sugar, vinegar, tomatoes and some seasoning and simmer for 20 min\",\"instructions\":[\"First make the tomato sauce. Heat the oil in a large pan and fry the garlic for 1 min. Add the sugar, vinegar, tomatoes and some seasoning and simmer for 20 mins, stirring occasionally, until thick. Add the basil and divide the sauce between 2 or more shallow ovenproof dishes (see Tips for freezing, below). Set aside. Make a sauce by beating the mascarpone with the milk until smooth, season, then set aside.\",\"Put the spinach in a large colander and pour over a kettle of boiling water to wilt it (you may need to do this in batches). When cool enough to handle squeeze out the excess water. Roughly chop the spinach and mix in a large bowl with 100g Parmesan and ricotta. Season well with salt, pepper and the nutmeg.\",\"Heat oven to 200C/180C fan/gas 6. Using a piping bag or plastic food bag with the corner snipped off, squeeze the filling into the cannelloni tubes. Lay the tubes, side by side, on top of the tomato sauce and spoon over the mascarpone sauce. Top with Parmesan and mozzarella. You can now freeze the cannelloni, uncooked, or you can cook it first and then freeze. Bake for 30-35 mins until golden and bubbling. Remove from oven and let stand for 5 mins before serving.\"]},{\"id\":\"g482\",\"title\":\"Split Pea Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xxtsvx1511814083.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ham\",\"Peas\",\"Onions\",\"Carrots\",\"Bay Leaves\",\"Celery\",\"Frozen Peas\",\"Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Put the gammon in a very large pan with 2 litres water and bring to the boil. Remove from the heat and drain off the water – this helps to get rid of some of th\",\"instructions\":[\"Put the gammon in a very large pan with 2 litres water and bring to the boil. Remove from the heat and drain off the water – this helps to get rid of some of the saltiness. Recover with 2 litres cold water and bring to the boil again. Put everything but the frozen peas into the pan and bring to the boil. Reduce to a simmer and cook for 1½-2½ hrs, topping up the water as and when you need to, to a similar level it started at. As the ham cooks and softens, you can halve it if you want, so it is all submerged under the liquid. When the ham is tender enough to pull into shreds, it is ready.\",\"Lift out the ham, peel off and discard the skin. While it is still hot (wear a clean pair of rubber gloves), shred the meat. Remove bay from the soup and stir in the frozen peas. Simmer for 1 min, then blend until smooth. Add a splash of water if too thick, and return to the pan to heat through if it has cooled, or if you are making ahead.\",\"When you are ready to serve, mix the hot soup with most of the ham – gently reheat if made ahead. Serve in bowls with the remaining ham scattered on top, and eat with crusty bread and butter.\"]},{\"id\":\"g483\",\"title\":\"Spotted Dick\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xqvyqr1511638875.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Self-raising Flour\",\"Salt\",\"Suet\",\"Currants\",\"Caster Sugar\",\"Lemon\",\"Orange\",\"Milk\",\"Custard\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Put the flour and salt in a bowl. Add the suet, currants, sugar, lemon and orange zest.\\r\\nPour in 150ml milk and mix to a firm but moist dough, adding the extra \",\"instructions\":[\"Put the flour and salt in a bowl. Add the suet, currants, sugar, lemon and orange zest.\",\"Pour in 150ml milk and mix to a firm but moist dough, adding the extra milk if necessary.\",\"Shape into a fat roll about 20cm long. Place on a large rectangle of baking parchment. Wrap loosely to allow for the pudding to rise and tie the ends with string like a Christmas cracker.\",\"Place a steamer over a large pan of boiling water, add the pudding to the steamer, cover and steam for 1 1/2 hours. Top up the pan with water from time to time.\",\"Remove from the steamer and allow to cool slightly before unwrapping. Serve sliced with custard.\"]},{\"id\":\"g484\",\"title\":\"Spring onion and prawn empanadas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1c5oso1614347493.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Spring Onions\",\"Olive Oil\",\"Red Chilli\",\"Garlic\",\"Prawns\",\"Feta\",\"Butter\",\"Plain Flour\",\"Egg\",\"White Wine Vinegar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\n\\r\\nTo make the dough, rub the butter into the flour and then add the egg white and half the yolk (keep the rest), vinegar, a pinch of salt and enough col\",\"instructions\":[\"STEP 1\",\"To make the dough, rub the butter into the flour and then add the egg white and half the yolk (keep the rest), vinegar, a pinch of salt and enough cold water to make a soft dough. Knead on a floured surface until smooth and then wrap and rest for 30 minutes.\",\"STEP 2\",\"Heat the oven to 180c/fan 160c/gas 4. Trim the green ends of the spring onions and then finely slice the rest. Heat a little oil in a pan and fry them gently until soft but not browned. Add the chilli and garlic, stir and then add the prawns and cook until they are opaque. Season well. Scoop out the prawns and bubble the juices until they thicken, then add back the prawns.\",\"STEP 3\",\"Divide the empanada dough into eight balls and roll out to thin circles on a floured surface. Put some filling on one half of the dough, sprinkle the feta on top and fold the other half over. Trim the edge and then fold and crimp the dough together so the empanada is tightly sealed, put it on an oiled baking sheet either on its side or sitting on its un-crimped edge like a cornish pasty. Repeat with the remaining dough and mixture. Mix the leftover egg yolk with a splash of water and brush the top of the empanadas.\",\"STEP 4\",\"Bake for 30 minutes or until golden and slightly crisp around the edges.\"]},{\"id\":\"g485\",\"title\":\"Squash linguine\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wxswxy1511452625.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butternut Squash\",\"Garlic\",\"Olive Oil\",\"Linguine Pasta\",\"Sage\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 200C/180C fan/gas 6. Put the squash and garlic on a baking tray and drizzle with the olive oil. Roast for 35-40 mins until soft. Season.\\r\\nCook the \",\"instructions\":[\"Heat oven to 200C/180C fan/gas 6. Put the squash and garlic on a baking tray and drizzle with the olive oil. Roast for 35-40 mins until soft. Season.\",\"Cook the pasta according to pack instructions. Drain, reserving the water. Use a stick blender to whizz the squash with 400ml cooking water. Heat some oil in a frying pan, fry the sage until crisp, then drain on kitchen paper. Tip the pasta and sauce into the pan and warm through. Scatter with sage.\"]},{\"id\":\"g486\",\"title\":\"Squid, chickpea & chorizo salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wsu0rc1761848482.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Pepper\",\"Can of chickpeas\",\"Parsley\",\"Red Chilli\",\"Garlic Clove\",\"Olive Oil\",\"Squid\",\"Chorizo\",\"Lemon\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nCook the peppers whole under a grill, on a barbecue or griddle, until completely charred. Place the peppers in a bowl, cover with a plate until cool eno\",\"instructions\":[\"step 1\",\"Cook the peppers whole under a grill, on a barbecue or griddle, until completely charred. Place the peppers in a bowl, cover with a plate until cool enough to handle, then peel, deseed and finely slice. In a large bowl mix the peppers and any juices with the chickpeas, parsley, chilli and garlic. Set aside.\",\"step 2\",\"Heat a large frying pan until smoking. Working quickly and carefully, add a splash of oil to the pan, then the squid. Stir-fry for about 30 secs. Scatter the chorizo over the squid, continue to cook for 30 secs more, then tip into the bowl with the peppers. Season everything with salt and pepper, then dress with the remaining oil, lemon juice and lemon zest. Mix together, pile onto a platter and let everyone help themselves.\"]},{\"id\":\"g487\",\"title\":\"Stamppot\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hyarod1565090529.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Bay Leaf\",\"Shallots\",\"Butter\",\"Kale\",\"Sausages\",\"Milk\",\"Nutmeg\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Wash and peel the potatoes and cut into similarly sized pieces for even cooking.\\r\\n\\r\\nIn a large soup pot, boil the potatoes and the bay leaves in salted water fo\",\"instructions\":[\"Wash and peel the potatoes and cut into similarly sized pieces for even cooking.\",\"In a large soup pot, boil the potatoes and the bay leaves in salted water for 20 minutes. Discard the bay leaves.\",\"If you're not using a bag of ready-cut curly kale, wash the bunches thoroughly under cool running water to get rid of all soil—you wouldn't want that gritty texture in your finished dish. Trim any coarse stems and discard any brown leaves. With a sharp knife, cut the curly kale into thin strips.\",\"Peel and chop the shallots.\",\"In a frying pan or skillet, melt 1 tbsp. of butter and saute the shallots for a few minutes before adding the curly kale and 2 tbsp. of water. Season and cook for about 10 minutes, or until tender.\",\"Warm the milk on the stove or in the microwave.\",\"Drain, shake and dry the potatoes with kitchen towels before mashing with a potato masher or ricer. Working quickly, add the warm milk and the remaining butter. Season to taste with nutmeg, salt, and pepper.\",\"Mix the cooked curly kale through the cooked mashed potato mixture.\",\"Top with slices of the smoked sausage and serve hot with your favorite mustard or gravy.\",\"Serve and enjoy!\"]},{\"id\":\"g488\",\"title\":\"Steak & Vietnamese noodle salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/st9shl1763755808.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Brown Rice Noodle\",\"Rapeseed Oil\",\"Fillet Of Steak\",\"Carrots\",\"Chinese Cabbage\",\"Spring Onions\",\"Coriander\",\"Red Chilli\",\"Lime\",\"Brown Sugar\",\"Rice Vinegar\",\"Garlic Clove\",\"Fish Sauce\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nMix all the ingredients for the dressing together in a bowl with 1 tbsp water until the sugar has dissolved.\\r\\n\\r\\nstep 2\\r\\nCook the noodles following pack \",\"instructions\":[\"step 1\",\"Mix all the ingredients for the dressing together in a bowl with 1 tbsp water until the sugar has dissolved.\",\"step 2\",\"Cook the noodles following pack instructions, then plunge into a bowl of cold water to cool completely. Drain the noodles, then add the carrot, cabbage, spring onion and dressing, and toss to combine.\",\"step 3\",\"Heat the oil in a frying pan over a high heat. Season the steak, then cook to your liking; 2-3 mins on each side for medium rare. Leave to rest for 5 mins, then slice. Divide the salad and steak slices between bowls and scatter over some coriander to serve.\"]},{\"id\":\"g489\",\"title\":\"Steak and Kidney Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qysyss1511558054.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Puff Pastry\",\"Egg White\",\"Egg Yolks\",\"Vegetable Oil\",\"Beef\",\"Lamb Kidney\",\"Onions\",\"Plain Flour\",\"Beef Stock\",\"Salt\",\"Pepper\",\"Worcestershire Sauce\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 220C/425F/Gas 7\\r\\nHeat the vegetable oil in a large frying pan, and brown the beef all over. (You may need to do this in batches.) Set aside,\",\"instructions\":[\"Preheat the oven to 220C/425F/Gas 7\",\"Heat the vegetable oil in a large frying pan, and brown the beef all over. (You may need to do this in batches.) Set aside, then brown the kidneys on both sides in the same pan. Add the onions and cook for 3-4 minutes.\",\"Return the beef to the pan, sprinkle flour over and coat the meat and onions\",\"Add the stock to the pan, stir well and bring to the boil.\",\"Turn the heat down and simmer for 1½ hours without a lid. If the liquid evaporates too much, add more stock.\",\"Remove from the heat. Add salt, pepper and Worcestershire sauce and allow to cool completely. Place the cooked meat mixture into a pie dish.\",\"Roll out the pastry to 5mm/¼in thick and 5cm/2in larger than the dish you are using.\",\"Using a rolling pin, lift the pastry and place it over the top of the pie dish. Trim and crimp the edges with your fingers and thumb.\",\"Brush the surface with the beaten egg mixture and bake for 30-40 minutes until golden-brown and puffed.\",\"Serve with creamy mash and steamed vegetables to soak up the gravy.\"]},{\"id\":\"g490\",\"title\":\"Steak Diane\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vussxq1511882648.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Canola Oil\",\"Beef Fillet\",\"Beef Stock\",\"Butter\",\"Garlic\",\"Challots\",\"Mushrooms\",\"Brandy\",\"Heavy Cream\",\"Dijon Mustard\",\"Worcestershire Sauce\",\"Tabasco Sauce\",\"Parsley\",\"Chives\",\"Salt\",\"Pepper\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oil in a 12\\\" skillet over medium-high heat. Season steaks with salt and pepper, and add to skillet; cook, turning once, until browned on both sides and coo\",\"instructions\":[\"Heat oil in a 12\\\" skillet over medium-high heat. Season steaks with salt and pepper, and add to skillet; cook, turning once, until browned on both sides and cooked to desired doneness, about 4 to 5 minutes for medium-rare. Transfer steaks to a plate, and set aside.\",\"Return skillet to high heat, and add stock; cook until reduced until to 1⁄2 cup, about 10 minutes. Pour into a bowl, and set aside. Return skillet to heat, and add butter; add garlic and shallots, and cook, stirring, until soft, about 2 minutes. Add mushrooms, and cook, stirring, until they release any liquid and it evaporates and mushrooms begin to brown, about 2 minutes. Add cognac, and light with a match to flambée; cook until flame dies down. Stir in reserved stock, cream, Dijon, Worcestershire, and hot sauce, and then return steaks to skillet; cook, turning in sauce, until warmed through and sauce is thickened, about 4 minutes. Transfer steak to serving plates and stir parsley and chives into sauce; pour sauce over steaks to serve.\"]},{\"id\":\"g491\",\"title\":\"Sticky Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/cj56fs1762340001.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken drumsticks\",\"Soy Sauce\",\"Honey\",\"Olive Oil\",\"Tomato Puree\",\"Dijon Mustard\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nMake 3 slashes on each of the drumsticks. Mix together the soy, honey, oil, tomato purée and mustard. Pour this mixture over the chicken and coat thorou\",\"instructions\":[\"step 1\",\"Make 3 slashes on each of the drumsticks. Mix together the soy, honey, oil, tomato purée and mustard. Pour this mixture over the chicken and coat thoroughly. Leave to marinate for 30 mins at room temperature or overnight in the fridge. Heat oven to 200C/fan 180C/gas 6.\",\"step 2\",\"Tip the chicken into a shallow roasting tray and cook for 35 mins, turning occasionally, until the chicken is tender and glistening with the marinade.\"]},{\"id\":\"g492\",\"title\":\"Sticky Toffee Pudding\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xqqqtu1511637379.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Muscovado Sugar\",\"Eggs\",\"Self-raising Flour\",\"Baking Powder\",\"Bicarbonate Of Soda\",\"Black Treacle\",\"Milk\",\"Double Cream\",\"Butter\",\"Muscovado Sugar\",\"Black Treacle\",\"Double Cream\",\"Vanilla Extract\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 180C/160C Fan/Gas 4. Butter a wide shallow 1.7-litre/3-pint ovenproof dish.\\r\\nPut the butter, sugar, eggs, flour, baking powder, bicarbonate \",\"instructions\":[\"Preheat the oven to 180C/160C Fan/Gas 4. Butter a wide shallow 1.7-litre/3-pint ovenproof dish.\",\"Put the butter, sugar, eggs, flour, baking powder, bicarbonate of soda and treacle into a mixing bowl. Beat using an electric handheld whisk for about 30 seconds or until combined. Pour in the milk gradually and whisk again until smooth. Pour into the prepared dish. Bake for 35–40 minutes or until well risen and springy in the centre.\",\"To make the sauce, put all the ingredients into a saucepan and stir over a low heat until the sugar has dissolved and the butter has melted. Bring to the boil, stirring for a minute.\",\"To serve, pour half the sauce over the pudding in the baking dish. Serve with the cream or ice cream.\"]},{\"id\":\"g493\",\"title\":\"Sticky Toffee Pudding Ultimate\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xrptpq1483909204.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Medjool dates\",\"water\",\"vanilla extract\",\"self-raising flour\",\"bicarbonate of soda\",\"eggs\",\"butter\",\"demerara sugar\",\"black treacle\",\"milk\",\"ice cream\",\"muscovado sugar\",\"butter\",\"double cream\",\"black treacle\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Stone and chop the dates quite small, put them in a bowl, then pour the boiling water over. Leave for about 30 mins until cool and well-soaked, then mash a bit \",\"instructions\":[\"Stone and chop the dates quite small, put them in a bowl, then pour the boiling water over. Leave for about 30 mins until cool and well-soaked, then mash a bit with a fork. Stir in the vanilla extract. Butter and flour seven mini pudding tins (each about 200ml/7fl oz) and sit them on a baking sheet. Heat oven to 180C/fan 160C/gas 4.\",\"While the dates are soaking, make the puddings. Mix the flour and bicarbonate of soda together and beat the eggs in a separate bowl. Beat the butter and sugar together in a large bowl for a few mins until slightly creamy (the mixture will be grainy from the sugar). Add the eggs a little at a time, beating well between additions. Beat in the black treacle then, using a large metal spoon, gently fold in one-third of the flour, then half the milk, being careful not to overbeat. Repeat until all the flour and milk is used. Stir the soaked dates into the pudding batter. The mix may look a little curdled at this point and will be like a soft, thick batter. Spoon it evenly between the tins and bake for 20-25 mins, until risen and firm.\",\"Meanwhile, put the sugar and butter for the sauce in a medium saucepan with half the cream. Bring to the boil over a medium heat, stirring all the time, until the sugar has completely dissolved. Stir in the black treacle, turn up the heat slightly and let the mixture bubble away for 2-3 mins until it is a rich toffee colour, stirring occasionally to make sure it doesn’t burn. Take the pan off the heat and beat in the rest of the cream.\",\"Remove the puddings from the oven. Leave in the tins for a few mins, then loosen them well from the sides of the tins with a small palette knife before turning them out. You can serve them now with the sauce drizzled over, but they’ll be even stickier if left for a day or two coated in the sauce. To do this, pour about half the sauce into one or two ovenproof serving dishes. Sit the upturned puddings on the sauce, then pour the rest of the sauce over them. Cover with a loose tent of foil so that the sauce doesn’t smudge (no need to chill).\",\"When ready to serve, heat oven to 180C/fan 160C/gas 4. Warm the puddings through, still covered, for 15-20 mins or until the sauce is bubbling. Serve them on their own, or with cream or custard.\"]},{\"id\":\"g494\",\"title\":\"Stir-fried chicken with chillies & basil\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/el64dy1763483009.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Chicken\",\"Garlic\",\"Shallots\",\"Red Chilli\",\"Fish Sauce\",\"Soy Sauce\",\"Sugar\",\"Basil Leaves\"],\"allergens\":[\"soy\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat a wok or large frying pan until it is very hot, then add 1 tbsp of the oil. When it is very hot, add the chicken and stir-fry over a high heat for 8-10 min\",\"instructions\":[\"Heat a wok or large frying pan until it is very hot, then add 1 tbsp of the oil. When it is very hot, add the chicken and stir-fry over a high heat for 8-10 minutes, until browned all over. Using a slotted spoon, take the chicken from the pan and set aside.\",\"step 2\",\"Reheat the wok and add the remaining oil. Toss in the garlic and shallots and stir fry for 3 minutes, until golden brown.\",\"step 3\",\"Return the chicken to the wok and add the chillies, fish sauce, dark soy sauce and sugar. Stir fry over a high heat for a further 8-10 minutes or until the chicken is cooked through. Stir in the basil leaves and serve at once.\"]},{\"id\":\"g495\",\"title\":\"Stovetop Eggplant With Harissa, Chickpeas, and Cumin Yogurt\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yqwtvu1487426027.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Egg Plants\",\"Harissa Spice\",\"Chickpeas\",\"Cherry Tomatoes\",\"Greek yogurt\",\"Ground cumin\",\"Parsley\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oil in a 12-inch skillet over high heat until shimmering. Add the eggplants and lower the heat to medium. Season with salt and pepper as you rotate the\",\"instructions\":[\"Heat the oil in a 12-inch skillet over high heat until shimmering. Add the eggplants and lower the heat to medium. Season with salt and pepper as you rotate the eggplants, browning them on all sides. Continue to cook, turning regularly, until a fork inserted into the eggplant meets no resistance (you may have to stand them up on their fat end to finish cooking the thickest parts), about 20 minutes, lowering the heat and sprinkling water into the pan as necessary if the eggplants threaten to burn or smoke excessively.\",\"2.\",\"Mix the harissa, chickpeas and tomatoes together, then add to the eggplants. Cook until the tomatoes have blistered and broken down, about 5 minutes more. Season with salt and pepper and add water as necessary to thin to a saucy consistency. Meanwhile, combine the yogurt and cumin in a serving bowl. Season with salt and pepper.\",\"3.\",\"Top the eggplant mixture with the parsley, drizzle with more extra virgin olive oil, and serve with the yogurt on the side.\"]},{\"id\":\"g496\",\"title\":\"Strawberries Romanoff\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/oe8rg51699014028.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Strawberries\",\"Sugar\",\"Grand Marnier\",\"Cream\",\"Sour Cream\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"In a medium bowl, combine hulled and quartered strawberries, 4 Tbsp sugar and 4 Tbsp liqueur, stir to combine then cover and refrigerate at least 1 hour and up \",\"instructions\":[\"In a medium bowl, combine hulled and quartered strawberries, 4 Tbsp sugar and 4 Tbsp liqueur, stir to combine then cover and refrigerate at least 1 hour and up to 2 hours, stirring once or twice.\",\"Two photos of cut strawberries in a bowl with one having sugar being added to the bowl Two photos of cut up strawberries for Strawberry Romanoff\",\"Just before serving, in a large mixing bowl, combine 1 cup cold heavy cream and 1/4 cup powdered sugar, and beat with an electric mixer until stiff peaks form. Using a spatula, fold in 1/4 cup sour cream just until well blended.\",\"To serve, stir strawberries then divide between 6 serving glasses or bowls. You can spoon a little syrup over the berries if you like. You can also use this syrup to soak a cake. Spoon cream over strawberries, dividing evenly. You can also use an ice cream scoop with trigger release for a nice rounded puff of cream. Serve right away or chill and enjoy within 2 hours of assembly.\"]},{\"id\":\"g497\",\"title\":\"Strawberry Rhubarb Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/178z5o1585514569.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Salt\",\"Sugar\",\"Butter\",\"Water\",\"Rhubarb\",\"Strawberries\",\"Cornstarch\",\"Sugar\",\"Cinnamon\",\"Lemon Juice\",\"Unsalted Butter\",\"Milk\",\"Sugar\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Pie Crust:  In a food processor, place the flour, salt, and sugar and process until combined. Add the butter and process until the mixture resembles coarse\\r\\n\\r\\nm\",\"instructions\":[\"Pie Crust:  In a food processor, place the flour, salt, and sugar and process until combined. Add the butter and process until the mixture resembles coarse\",\"meal (about 15 seconds). Pour 1/4 cup (60 ml) water in a slow, steady stream, through the feed tube until the dough just holds together when pinched. If necessary, add more water. Do not process more than 30 seconds.\",\"Turn the dough onto your work surface and gather into a ball. Divide the dough in half, flattening each half into a disk, cover with plastic wrap, and refrigerate for about one hour before using. This will chill the butter and relax the gluten in the flour.\",\"After the dough has chilled sufficiently, remove one portion of the dough from the fridge and place it on a lightly floured surface.  Roll the pastry into a 12 inch (30 cm) circle. (To prevent the pastry from sticking to the counter and to ensure uniform thickness, keep lifting up and turning the pastry a quarter turn as you roll (always roll from the center of the pastry outwards).)  Fold the dough in half and gently transfer to a 9 inch (23 cm) pie pan. Brush off any excess flour and trim any overhanging pastry to an edge of 1/2 inch (1.5 cm). Refrigerate the pastry, covered with plastic wrap, while you make the filling.\",\"Remove the second round of pastry and roll it into a 13 inch (30 cm) circle. Using a pastry wheel or pizza cutter, cut the pastry into about 3/4 inch (2 cm) strips. Place the strips of pastry on a parchment paper-lined baking sheet, cover with plastic wrap, and place in the refrigerator for about 10 minutes.\",\"Make the Strawberry Rhubarb Filling: Place the cut strawberries and rhubarb in a large bowl. In a small bowl mix together the cornstarch, sugar, and ground cinnamon.\",\"Remove the chilled pie crust from the fridge. Sprinkle about 2 tablespoons of the sugar mixture over the bottom of the pastry crust. Add the remaining sugar mixture to the strawberries and rhubarb and gently toss to combine. Pour the fruit mixture into the prepared pie shell. Sprinkle the fruit with about 1 teaspoon of lemon juice and dot with 2 tablespoons of butter.\",\"Remove the lattice pastry from the refrigerator and, starting at the center with the longest strips and working outwards, place half the strips, spacing about 1 inch (2.5 cm) apart, on top of the filling. (Use the shortest pastry strips at the outer edges.) Then, gently fold back, about halfway, every other strip of pastry. Take another strip of pastry and place it perpendicular on top of the first strips of pastry. Unfold the bottom strips of pastry and then fold back the strips that weren't folded back the first time. Lay another strip of pastry perpendicular on top of the filling and then continue with the remaining strips. Trim the edges of the pastry strips, leaving a 1 inch (2.5 cm) overhang. Seal the edges of the pastry strips by folding them under the bottom pastry crust and flute the edges of the pastry. Brush the lattice pastry with milk and sprinkle with a little sugar. Cover and place in the refrigerator while you preheat the oven to 400 degrees F (205 degrees C) and place the oven rack in the lower third of the oven. Put a baking sheet, lined with aluminum foil, on the oven rack (to catch any spills.)\",\"Place the pie plate on the hot baking sheet and bake the pie for about 35 minutes and then, if the edges of the pie are browning too much, cover with a foil ring. Continue to bake the pie for about another 10 minutes or until the crust is a golden brown color and the fruit juices begin to bubble.\",\"Remove the pie from the oven and place on a wire rack to cool for several hours. Serve at room temperature with softly whipped cream or vanilla ice cream. Leftovers can be stored in the refrigerator for about 3 days. Reheat before serving. This pie can be frozen.\"]},{\"id\":\"g498\",\"title\":\"Stuffed Bell Peppers with Quinoa and Black Beans\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/b66myb1683207208.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Green Pepper\",\"Olive Oil\",\"Onion\",\"Garlic\",\"Quinoa\",\"Black Beans\",\"Sweetcorn\",\"Diced Tomatoes\",\"Cumin\",\"Chili Powder\",\"Smoked Paprika\",\"Salt\",\"Pepper\",\"Shredded Mexican Cheese\",\"Cilantro\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"1. Preheat your oven to 375°F (190°C). Lightly grease a 9x13-inch baking dish or a similar-sized casserole dish.\\r\\n2. Place the bell pepper halves in the prepare\",\"instructions\":[\"1. Preheat your oven to 375°F (190°C). Lightly grease a 9x13-inch baking dish or a similar-sized casserole dish.\",\"2. Place the bell pepper halves in the prepared baking dish, cut side up. Bake for 15-20 minutes, or until slightly softened.\",\"3. While the bell peppers are baking, prepare the filling. In a large skillet, heat the olive oil over medium heat. Add the chopped onion, and cook for 3-4 minutes, until softened. Add the garlic, and cook for another 1 minute, until fragrant.\",\"4. Stir in the cooked quinoa, black beans, corn, diced tomatoes, ground cumin, chili powder, smoked paprika, salt, and pepper. Cook for 5-7 minutes, until heated through. Remove the skillet from heat, and stir in 1 cup of the shredded cheese, if using.\",\"5. Remove the bell peppers from the oven, and carefully stuff each pepper half with the quinoa and black bean mixture. Top the stuffed peppers with the remaining 1/2 cup of shredded cheese, if using.\",\"6. Return the stuffed peppers to the oven, and bake for another 15-20 minutes, until the cheese is melted and the peppers are tender.\",\"7. Remove from the oven, and allow the stuffed peppers to cool for 5 minutes before serving. Garnish with fresh chopped cilantro.\"]},{\"id\":\"g499\",\"title\":\"Stuffed Lamb Tomatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/u55lbp1585564013.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tomatoes\",\"Sugar\",\"Olive Oil\",\"Onion\",\"Garlic Clove\",\"Lamb\",\"Cinnamon\",\"Tomato Puree\",\"Rice\",\"Chicken Stock\",\"Dill\",\"Chopped Parsley\",\"Mint\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 180C/160C fan/gas 4. Slice the tops off the tomatoes and reserve. Scoop out most of the pulp with a teaspoon, being careful not to break the skin. \",\"instructions\":[\"Heat oven to 180C/160C fan/gas 4. Slice the tops off the tomatoes and reserve. Scoop out most of the pulp with a teaspoon, being careful not to break the skin. Finely chop the pulp, and keep any juices. Sprinkle the insides of the tomatoes with a little sugar to take away the acidity, then place them on a baking tray.\",\"Heat 2 tbsp olive oil in a large frying pan, add the onion and garlic, then gently cook for about 10 mins until soft but not coloured. Add the lamb, cinnamon and tomato purée, turn up the heat, then fry until the meat is browned. Add the tomato pulp and juice, the rice and the stock. Season generously. Bring to the boil, then simmer for 15 mins or until the rice is tender and the liquid has been absorbed. Set aside to cool a little, then stir in the herbs.\",\"Stuff the tomatoes up to the brim, top tomatoes with their lids, drizzle with 2 tbsp more olive oil, sprinkle 3 tbsp water into the tray, then bake for 35 mins. Serve with salad and crusty bread, hot or cold.\"]},{\"id\":\"g500\",\"title\":\"Sugar Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yrstur1511816601.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Brown Sugar\",\"Butter\",\"Eggs\",\"Vanilla Extract\",\"Salt\",\"Plain Flour\",\"Milk\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 350 degrees F (175 degrees C). Grease a 9-inch pie dish.\\r\\nPlace the brown sugar and butter in a mixing bowl, and beat them together with an elec\",\"instructions\":[\"Preheat oven to 350 degrees F (175 degrees C). Grease a 9-inch pie dish.\",\"Place the brown sugar and butter in a mixing bowl, and beat them together with an electric mixer until creamy and very well combined, without lumps. Beat in eggs, one at a time, incorporating the first egg before adding the next one. Add the vanilla extract and salt; beat the flour in, a little at a time, and then the milk, making a creamy batter. Pour the batter into the prepared pie dish.\",\"Bake in the preheated oven for 35 minutes; remove pie, and cover the rim with aluminum foil to prevent burning. Return to oven, and bake until the middle sets and the top forms a crusty layer, about 15 more minutes. Let the pie cool to room temperature, then refrigerate for at least 1 hour before serving.\"]},{\"id\":\"g501\",\"title\":\"Suksessterte (Norwegian almond “success cake”)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/de83k51763075604.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Almonds\",\"Egg\",\"Granulated Sugar\",\"Flour\",\"Baking Powder\",\"Egg Yolks\",\"Heavy Cream\",\"Granulated Sugar\",\"Vanilla Extract\",\"Butter\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Almond base\\r\\n▢\\r\\nPreheat oven to 345°F (175°C) and grease cake form (I use a 27 cm spring form) – you can line the bottom with baking paper if you like.\\r\\n▢\\r\\nGrin\",\"instructions\":[\"Almond base\",\"▢\",\"Preheat oven to 345°F (175°C) and grease cake form (I use a 27 cm spring form) – you can line the bottom with baking paper if you like.\",\"▢\",\"Grind almonds in an almond grinder or food processor. I like to keep them a bit coarse.\",\"▢\",\"Gently whisk the eggs and sugar together until combined (no longer). Stir in the ground almonds, flour, and baking powder.\",\"▢\",\"Pour batter into cake form and bake for about 45 – 50 minutes, monitoring to make sure the top doesn't burn.\",\"Yellow egg cream\"]},{\"id\":\"g502\",\"title\":\"Sukuma Wiki\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/60o82j1762341177.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Oil\",\"Red Onions\",\"Kale\",\"Salt\",\"Double Cream\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the 2 tablespoons of oil in a large skillet or pot over medium heat until shimmering. Add the onions and cook, stirring occasionally, until softened, 5 to \",\"instructions\":[\"Heat the 2 tablespoons of oil in a large skillet or pot over medium heat until shimmering. Add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.\",\"Add the shredded kale to the onions and mix well. Turn the heat to medium-low, cover and cook for 5 minutes.\",\"After 5 minutes, remove the lid, add salt to taste, and stir in the cream. Continue cooking for another 5 minutes, uncovered, stirring occasionally. The cream will thicken slightly, making for a deliciously rich creamed kale and onions. Yumm!\",\"Serve it up with your favorite Kenyan stew, and a side of ugali!\"]},{\"id\":\"g503\",\"title\":\"Šúĺlance s Makom\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/d6o4nu1763362422.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"All purpose flour\",\"Semolina\",\"Salt\",\"Ground Poppy seeds\",\"Powdered Sugar\",\"Butter\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"1. Prepare the Potatoes\\r\\n\\r\\nBoil the potatoes with their skins on until tender.\\r\\nLet them cool completely (preferably overnight), then peel and mash them finely.\",\"instructions\":[\"1. Prepare the Potatoes\",\"Boil the potatoes with their skins on until tender.\",\"Let them cool completely (preferably overnight), then peel and mash them finely.\",\"2. Make the Dough\",\"In a bowl, combine mashed potatoes, flour, semolina, and salt.\",\"Knead the mixture until you get a smooth, non-sticky dough.\",\"3. Shape the Šúĺlance\",\"Divide the dough into portions and roll each into a thin rope (about 1.5 cm in diameter).\",\"Cut into 3 cm-long pieces and roll between your palms to shape small dumplings.\",\"4. Cook the Dumplings\"]},{\"id\":\"g504\",\"title\":\"Summer Pistou\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rqtxvr1511792990.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rapeseed Oil\",\"Leek\",\"Courgettes\",\"Vegetable Stock\",\"Cannellini Beans\",\"Green Beans\",\"Tomatoes\",\"Garlic Clove\",\"Basil\",\"Parmesan\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat the oil in a large pan and fry the leeks and courgette for 5 mins to soften. Pour in the stock, add three-quarters of the haricot beans with the green bean\",\"instructions\":[\"Heat the oil in a large pan and fry the leeks and courgette for 5 mins to soften. Pour in the stock, add three-quarters of the haricot beans with the green beans, half the tomatoes, and simmer for 5-8 mins until the vegetables are tender.\",\"Meanwhile, blitz the remaining beans and tomatoes, the garlic and basil in a food processor (or in a bowl with a stick blender) until smooth, then stir in the Parmesan. Stir the sauce into the soup, cook for 1 min, then ladle half into bowls or pour into a flask for a packed lunch. Chill the remainder. Will keep for a couple of days.\"]},{\"id\":\"g505\",\"title\":\"Summer Pudding\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rsqwus1511640214.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Strawberries\",\"Blackberries\",\"Redcurrants\",\"Raspberries\",\"Caster Sugar\",\"Bread\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Bring out the juices: Wash fruit and gently dry on kitchen paper – keep strawberries separate. Put sugar and 3 tbsp water into a large pan. Gently heat until su\",\"instructions\":[\"Bring out the juices: Wash fruit and gently dry on kitchen paper – keep strawberries separate. Put sugar and 3 tbsp water into a large pan. Gently heat until sugar dissolves – stir a few times. Bring to a boil for 1 min, then tip in the fruit (not strawberries). Cook for 3 mins over a low heat, stirring 2-3 times. The fruit will be softened, mostly intact and surrounded by dark red juice. Put a sieve over a bowl and tip in the fruit and juice.\",\"Line the bowl with cling film and prepare the bread: Line the 1.25-litre basin with cling film as this will help you to turn out the pudding. Overlap two pieces of cling film in the middle of the bowl as it’s easier than trying to get one sheet to stick to all of the curves. Let the edges overhang by about 15cm. Cut the crusts off the bread. Cut 4 pieces of bread in half, a little on an angle, to give 2 lopsided rectangles per piece. Cut 2 slices into 4 triangles each and leave the final piece whole.\",\"Build the pud: Dip the whole piece of bread into the juice for a few secs just to coat. Push this into the bottom of the basin. Now dip the wonky rectangular pieces one at a time and press around the basin’s sides so that they fit together neatly, alternately placing wide and narrow ends up. If you can’t quite fit the last piece of bread in it doesn’t matter, just trim into a triangle, dip in juice and slot in. Now spoon in the softened fruit, adding the strawberries here and there as you go.\",\"Let flavours mingle then serve: Dip the bread triangles in juice and place on top – trim off overhang with scissors. Keep leftover juice for later. Bring cling film up and loosely seal. Put a side plate on top and weight down with cans. Chill for 6 hrs or overnight. To serve, open out cling film then put a serving plate upside-down on top and flip over. serve with leftover juice, any extra berries and cream.\"]},{\"id\":\"g506\",\"title\":\"Sushi\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/g046bb1663960946.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sushi Rice\",\"Rice wine\",\"Caster Sugar\",\"Mayonnaise\",\"Rice wine\",\"Soy Sauce\",\"Cucumber\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"STEP 1\\r\\nTO MAKE SUSHI ROLLS: Pat out some rice. Lay a nori sheet on the mat, shiny-side down. Dip your hands in the vinegared water, then pat handfuls of rice o\",\"instructions\":[\"STEP 1\",\"TO MAKE SUSHI ROLLS: Pat out some rice. Lay a nori sheet on the mat, shiny-side down. Dip your hands in the vinegared water, then pat handfuls of rice on top in a 1cm thick layer, leaving the furthest edge from you clear.\",\"STEP 2\",\"Spread over some Japanese mayonnaise. Use a spoon to spread out a thin layer of mayonnaise down the middle of the rice.\",\"STEP 3\",\"Add the filling. Get your child to top the mayonnaise with a line of their favourite fillings – here we’ve used tuna and cucumber.\",\"STEP 4\",\"Roll it up. Lift the edge of the mat over the rice, applying a little pressure to keep everything in a tight roll.\",\"STEP 5\",\"Stick down the sides like a stamp. When you get to the edge without any rice, brush with a little water and continue to roll into a tight roll.\"]},{\"id\":\"g507\",\"title\":\"Sweet and Sour Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/arzs741766434335.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Thighs\",\"Egg White\",\"Kosher Salt\",\"Cornstarch\",\"Pineapple Chunks\",\"Pineapple Juice\",\"White Vinegar\",\"Tomato Ketchup\",\"Brown Sugar\",\"Oil\",\"Red Pepper\",\"Yellow Pepper\",\"Ginger\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Coat the chicken with egg white:\\r\\nIn a bowl, combine the chicken with the egg white, 1/2 teaspoon kosher salt, and cornstarch. Stir to coat the chicken evenly. \",\"instructions\":[\"Coat the chicken with egg white:\",\"In a bowl, combine the chicken with the egg white, 1/2 teaspoon kosher salt, and cornstarch. Stir to coat the chicken evenly. Let sit for 15 minutes at room temperature or up to overnight in the refrigerator.\",\"Make the sweet and sour sauce:\",\"Whisk together the pineapple juice, vinegar, ketchup, 1/2 teaspoon kosher salt, and brown sugar.\",\"Stir-fry the chicken over high heat:\",\"Heat a large frying pan or wok over high heat until a bead of water instantly sizzles and evaporates. Pour in 1 tablespoon of cooking oil and swirl to coat. It's important that the pan is very hot.\",\"Add the chicken and spread the pieces out in one layer. Let the chicken fry untouched for 1 minute, until the bottoms are browned.\",\"Flip and fry the other side for 1 minute. The chicken should still be pinkish in the middle. Dish out the chicken onto a clean plate, leaving as much oil in the pan as possible.\",\"Stir-fry the bell pepper and ginger:\",\"Reduce the heat to medium and add the remaining 1 teaspoon of cooking oil. Let the oil heat up before adding the bell pepper chunks and ginger. Fry for 1 minute.\"]},{\"id\":\"g508\",\"title\":\"Sweet and Sour Pork\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529442316.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pork\",\"Egg\",\"Water\",\"Salt\",\"Sugar\",\"Soy Sauce\",\"Starch\",\"Tomato Puree\",\"Vinegar\",\"Coriander\"],\"allergens\":[\"egg\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preparation\\r\\n1. Crack the egg into a bowl. Separate the egg white and yolk.\\r\\n\\r\\nSweet and Sour Pork\\r\\n2. Slice the pork tenderloin into strips.\\r\\n\\r\\n3. Prepare the \",\"instructions\":[\"Preparation\",\"1. Crack the egg into a bowl. Separate the egg white and yolk.\",\"Sweet and Sour Pork\",\"2. Slice the pork tenderloin into strips.\",\"3. Prepare the marinade using a pinch of salt, one teaspoon of starch, two teaspoons of light soy sauce, and an egg white.\",\"4. Marinade the pork strips for about 20 minutes.\",\"5. Put the remaining starch in a bowl. Add some water and vinegar to make a starchy sauce.\",\"Sweet and Sour Pork\",\"Cooking Instructions\",\"1. Pour the cooking oil into a wok and heat to 190°C (375°F). Add the marinated pork strips and fry them until they turn brown. Remove the cooked pork from the wok and place on a plate.\"]},{\"id\":\"g509\",\"title\":\"Sweet potato salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/z458v91763817681.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sweet Potatoes\",\"Olive Oil\",\"Shallots\",\"Spring Onions\",\"Chives\",\"Sherry vinegar\",\"Extra Virgin Olive Oil\",\"Honey\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/180C fan/gas 6. Toss the sweet potato chunks with the olive oil and some seasoning, and spread on a baking parchment-lined baking shee\",\"instructions\":[\"step 1\",\"Heat oven to 200C/180C fan/gas 6. Toss the sweet potato chunks with the olive oil and some seasoning, and spread on a baking parchment-lined baking sheet. Roast for 30 - 35 mins until tender and golden. Cool at room temperature.\",\"step 2\",\"When just about cool whisk together all the dressing ingredients with a little more seasoning and gently toss through the potato chunks – use your hands to avoid breaking them up.\"]},{\"id\":\"g510\",\"title\":\"Syrian Bread\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/54xzk31760524666.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"Vegetable Oil\",\"Sugar\",\"Salt\",\"Flour\",\"Yeast\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Place ingredients in the pan of the bread machine in the order recommended by the manufacturer. Select Dough cycle; press Start.\\r\\n\\r\\nWhen the Dough cycle is almo\",\"instructions\":[\"Place ingredients in the pan of the bread machine in the order recommended by the manufacturer. Select Dough cycle; press Start.\",\"When the Dough cycle is almost complete, preheat the oven to 475 degrees F (245 degrees C).\",\"Turn dough out onto a lightly floured surface. Divide into eight equal pieces and form into rounds. Cover the rounds with a damp cloth and let rest.\",\"Roll dough into thin flat circles, about 8 inches in diameter. Cook two at a time on preheated baking sheets or a baking stone until puffed up and golden brown, about 5 minutes. Repeat for remaining loaves.\"]},{\"id\":\"g511\",\"title\":\"Syrian Rice with Meat\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/zg2b9l1760524940.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Ground Beef\",\"Salt\",\"Allspice\",\"Cinnamon\",\"Black Pepper\",\"Chicken Stock\",\"Rice\",\"Butter\",\"Pine Nuts\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat 1/4 cup butter in a large saucepan over medium-high heat. Add ground beef and season with salt, allspice, cinnamon, and black pepper. Cook and stir until b\",\"instructions\":[\"Heat 1/4 cup butter in a large saucepan over medium-high heat. Add ground beef and season with salt, allspice, cinnamon, and black pepper. Cook and stir until beef is browned and crumbly, 7 to 10 minutes.\",\"Stir chicken broth and rice into beef in the saucepan; bring to a boil. Reduce heat to low, cover, and cook until liquid is absorbed, about 20 minutes.\",\"Meanwhile, melt 2 tablespoons butter in a small skillet over medium heat. Cook and stir pine nuts in hot butter until lightly browned, 3 to 5 minutes.\",\"Mix pine nuts into beef-rice mixture before serving.\"]},{\"id\":\"g512\",\"title\":\"Syrian Spaghetti\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/5fu4ew1760524857.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Spaghetti\",\"Tomato Sauce\",\"Tomato Puree\",\"Cinnamon\",\"Vegetable Oil\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13 inch baking dish.\\r\\n\\r\\nBring a large pot of lightly salted water to a boil. Add spaghetti and cook fo\",\"instructions\":[\"Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13 inch baking dish.\",\"Bring a large pot of lightly salted water to a boil. Add spaghetti and cook for 8 to 10 minutes or until al dente; drain and stir in tomato sauce, tomato paste, cinnamon, oil, salt and pepper. Transfer to prepared dish.\",\"Bake in preheated oven for 1 hour, or until top is crunchy.\"]},{\"id\":\"g513\",\"title\":\"Szechuan Beef\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1529443236.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Salt\",\"Sesame Seed Oil\",\"Pepper\",\"Egg White\",\"Starch\",\"Oil\",\"Ginger\",\"Garlic\",\"Onion\",\"Carrots\",\"Green Pepper\",\"Celery\",\"Mushrooms\",\"Cooking wine\",\"Water\",\"Oyster Sauce\",\"Hotsauce\",\"Sugar\",\"Soy Sauce\"],\"allergens\":[\"egg\",\"soy\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1 - MARINATING THE BEEF\\r\\nIn a bowl, add the beef, salt, sesame seed oil, white pepper, egg white, 2 Tablespoon of corn starch and 1 Tablespoon of oil.\\r\\nSTE\",\"instructions\":[\"STEP 1 - MARINATING THE BEEF\",\"In a bowl, add the beef, salt, sesame seed oil, white pepper, egg white, 2 Tablespoon of corn starch and 1 Tablespoon of oil.\",\"STEP 2 - STIR FRY\",\"First Cook the beef by adding 2 Tablespoon of oil until the beef is golden brown.\",\"Set the beef aside\",\"In a wok add 1 Tablespoon of oil, minced ginger, minced garlic and stir-fry for few seconds.\",\"Next add all of the vegetables and then add sherry cooking wine and 1 cup of water.\",\"To make the sauce add oyster sauce, hot pepper sauce, and sugar.\",\"add the cooked beef and 1 spoon of soy sauce\",\"To thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your stir-fry until it's the right thickness.\"]},{\"id\":\"g514\",\"title\":\"Tahini Lentils\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vpxyqt1511464175.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Tahini\",\"Lemon\",\"Olive Oil\",\"Red Onions\",\"Garlic\",\"Yellow Pepper\",\"Green Beans\",\"Courgettes\",\"Kale\",\"Lentils\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"In a jug, mix the tahini with the zest and juice of the lemon and 50ml of cold water to make a runny dressing. Season to taste, then set aside.\\r\\nHeat the oil in\",\"instructions\":[\"In a jug, mix the tahini with the zest and juice of the lemon and 50ml of cold water to make a runny dressing. Season to taste, then set aside.\",\"Heat the oil in a wok or large frying pan over a medium-high heat. Add the red onion, along with a pinch of salt, and fry for 2 mins until starting to soften and colour. Add the garlic, pepper, green beans and courgette and fry for 5 min, stirring frequently.\",\"Tip in the kale, lentils and the tahini dressing. Keep the pan on the heat for a couple of mins, stirring everything together until the kale is wilted and it’s all coated in the creamy dressing.\"]},{\"id\":\"g515\",\"title\":\"Tajine de Poulet aux Carottes et Patates Douces (Chicken and Sweet Potato Tagine)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/d8bfyg1764117503.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onion\",\"Celery\",\"Cilantro\",\"Parsley\",\"Turmeric\",\"Ground Cumin\",\"Paprika\",\"Ground Ginger\",\"Cayenne Pepper\",\"Salt\",\"Black Pepper\",\"Chicken Thighs\",\"Olive Oil\",\"Raisins\",\"Chicken Stock\",\"Sweet Potatoes\",\"Carrots\",\"Prunes\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Combine onions, celery, cilantro, and parsley in a large pot. Stir in turmeric, cumin, paprika, ginger, cayenne pepper, salt, and pepper. Place chicken thighs o\",\"instructions\":[\"Combine onions, celery, cilantro, and parsley in a large pot. Stir in turmeric, cumin, paprika, ginger, cayenne pepper, salt, and pepper. Place chicken thighs on top. Drizzle olive oil over chicken. Cover and simmer over low heat until chicken is tender, about 40 minutes.\",\"Place raisins in a small bowl and cover with hot water; let soak for 10 minutes. Drain.\",\"Preheat oven to 400 degrees F (200 degrees C).\",\"Transfer chicken mixture into an oven-safe tagine or casserole dish. Add sweet potato and carrots. Cover with lid or aluminum foil.\",\"Bake in the preheated oven until sweet potato is soft, about 40 minutes. Add drained raisins and prunes. Continue baking, covered, until raisins and prunes are heated through, about 10 minutes.\"]},{\"id\":\"g516\",\"title\":\"Tall Skoleboller\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xihiu41762773169.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Milk\",\"Instant Yeast\",\"Granulated Sugar\",\"Cardamom\",\"Vanilla Extract\",\"Flour\",\"Butter\",\"Milk\",\"Granulated Sugar\",\"Egg Yolks\",\"Cornstarch\",\"vanilla pod\",\"Powdered Sugar\",\"Water\",\"Shredded Coconut\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"▢\\r\\nHeat the milk until it's lukewarm. Add the yeast and dissolve.\\r\\n▢\\r\\nAdd the sugar, cardamom, vanilla, and about 2/3 of the flour.\\r\\n▢\\r\\nMix the dough together e\",\"instructions\":[\"▢\",\"Heat the milk until it's lukewarm. Add the yeast and dissolve.\",\"▢\",\"Add the sugar, cardamom, vanilla, and about 2/3 of the flour.\",\"▢\",\"Mix the dough together either by hand or in a mixer with a dough hook, slowly adding the rest of the flour. You might need a bit more or less flour to form dough that isn't too sticky to knead. When the dough forms a nice ball, add the softened butter and continue to knead the dough for about ten minutes.\",\"▢\",\"Roll the dough into a cylinder and cut into six equal parts. Roll each piece into a round bun and set them in a greased muffin/cake tin. Cover and let rise until doubled in size (about an hour).\"]},{\"id\":\"g517\",\"title\":\"Tamiya\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/n3xxd91598732796.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Broad Beans\",\"Spring Onions\",\"Garlic Clove\",\"Parsley\",\"Cumin\",\"Baking Powder\",\"Cayenne Pepper\",\"Flour\",\"Vegetable Oil\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"oak the beans in water to cover overnight.Drain. If skinless beans are unavailable, rub to loosen the skins, then discard the skins. Pat the beans dry with a to\",\"instructions\":[\"oak the beans in water to cover overnight.Drain. If skinless beans are unavailable, rub to loosen the skins, then discard the skins. Pat the beans dry with a towel.\",\"Grind the beans in a food mill or meat grinder.If neither appliance is available, process them in a food processor but only until the beans form a paste. (If blended too smoothly, the batter tends to fall apart during cooking.) Add the scallions, garlic, cilantro, cumin, baking powder, cayenne, salt, pepper, and coriander, if using.  Refrigerate for at least 30 minutes.\",\"Shape the bean mixture into 1-inch balls.Flatten slightly and coat with flour.\",\"Heat at least 1½-inches of oil over medium heat to 365 degrees.\",\"Fry the patties in batches, turning once, until golden brown on all sides, about 5 minutes.Remove with a wire mesh skimmer or slotted spoon. Serve as part of a meze or in pita bread with tomato-cucumber salad and tahina sauce.\"]},{\"id\":\"g518\",\"title\":\"Tandoori chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qptpvt1487339892.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"lemons\",\"paprika\",\"red onions\",\"chicken thighs\",\"vegetable oil\",\"Greek yogurt\",\"ginger\",\"garlic clove\",\"garam masala\",\"ground cumin\",\"chilli powder\",\"turmeric\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix the lemon juice with the paprika and red onions in a large shallow dish. Slash each chicken thigh three times, then turn them in the juice and set aside for\",\"instructions\":[\"Mix the lemon juice with the paprika and red onions in a large shallow dish. Slash each chicken thigh three times, then turn them in the juice and set aside for 10 mins.\",\"Mix all of the marinade ingredients together and pour over the chicken. Give everything a good mix, then cover and chill for at least 1 hr. This can be done up to a day in advance.\",\"Heat the grill. Lift the chicken pieces onto a rack over a baking tray. Brush over a little oil and grill for 8 mins on each side or until lightly charred and completely cooked through.\"]},{\"id\":\"g519\",\"title\":\"Tangy cabbage slaw\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/e2g2r21764367568.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Mayonnaise\",\"Lemon\",\"Cider Vinegar\",\"Wholegrain Mustard\",\"Celery Salt\",\"White Cabbage\",\"Red Cabbage\",\"Carrots\",\"Onion\",\"Celery\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nWhisk together mayonnaise, lemon zest and juice, vinegar, mustard and celery salt in a small bowl, then season generously.\\r\\n\\r\\nstep 2\\r\\nAdd cabbage, carro\",\"instructions\":[\"step 1\",\"Whisk together mayonnaise, lemon zest and juice, vinegar, mustard and celery salt in a small bowl, then season generously.\",\"step 2\",\"Add cabbage, carrots, onion and celery. Mix well and refrigerate. Can be made up to 1 day ahead.\"]},{\"id\":\"g520\",\"title\":\"Tangy carrot, cabbage & onion salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/dbazbg1763779999.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Carrots\",\"Red Cabbage\",\"Red Onions\",\"Mint\",\"Coriander Leaves\",\"Roasted Peanut\",\"Lime\",\"Ground Nut Oil\",\"Red Chilli\",\"Brown Sugar\"],\"allergens\":[\"peanut\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nTip the carrots, cabbage and onions into a bowl. Make the dressing by stirring the ingredients together until the sugar has dissolved. Pour over salad, \",\"instructions\":[\"step 1\",\"Tip the carrots, cabbage and onions into a bowl. Make the dressing by stirring the ingredients together until the sugar has dissolved. Pour over salad, tossing the vegetables in the dressing. Add the herbs, toss again, then scatter over the peanuts.\"]},{\"id\":\"g521\",\"title\":\"Tarte Tatin\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ryspuw1511786688.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Puff Pastry\",\"Plain Flour\",\"Braeburn Apples\",\"Caster Sugar\",\"Butter\",\"Creme Fraiche\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Roll the pastry to a 3mm-thick round on a lightly floured surface and cut a 24cm circle, using a plate as a guide. Lightly prick all over with a fork, wrap in c\",\"instructions\":[\"Roll the pastry to a 3mm-thick round on a lightly floured surface and cut a 24cm circle, using a plate as a guide. Lightly prick all over with a fork, wrap in cling film on a baking sheet and freeze while preparing the apples.\",\"Heat oven to 180C/160C fan/gas 4. Peel, quarter and core the apples. Put the sugar in a flameproof 20cm ceramic Tatin dish or a 20cm ovenproof heavy-based frying pan and place over a medium-high heat. Cook the sugar for 5-7 mins to a dark amber caramel syrup that’s starting to smoke, then turn off the heat and stir in the 60g diced chilled butter.\",\"To assemble the Tarte Tatin, arrange the apple quarters very tightly in a circle around the edge of the dish first, rounded-side down, then fill in the middle in a similar fashion. Gently press with your hands to ensure there are no gaps. Brush the fruit with the melted butter.\",\"Bake in the oven for 30 mins, then remove and place the disc of frozen puff pastry on top – it will quickly defrost. Tuck the edges down the inside of the dish and, with a knife, prick a few holes in the pastry to allow steam to escape. Bake for a further 40-45 mins until the pastry is golden brown and crisp.\",\"Allow to cool to room temperature for 1 hr before running a knife around the edge of the dish and inverting it onto a large serving plate that is deep enough to contain the juices. Serve with crème fraîche or vanilla ice cream.\"]},{\"id\":\"g522\",\"title\":\"Teriyaki Chicken Casserole\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wvpsxx1468256321.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"soy sauce\",\"water\",\"brown sugar\",\"ground ginger\",\"minced garlic\",\"cornstarch\",\"chicken breasts\",\"stir-fry vegetables\",\"brown rice\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 350° F. Spray a 9x13-inch baking pan with non-stick spray.\\r\\nCombine soy sauce, ½ cup water, brown sugar, ginger and garlic in a small saucepan a\",\"instructions\":[\"Preheat oven to 350° F. Spray a 9x13-inch baking pan with non-stick spray.\",\"Combine soy sauce, ½ cup water, brown sugar, ginger and garlic in a small saucepan and cover. Bring to a boil over medium heat. Remove lid and cook for one minute once boiling.\",\"Meanwhile, stir together the corn starch and 2 tablespoons of water in a separate dish until smooth. Once sauce is boiling, add mixture to the saucepan and stir to combine. Cook until the sauce starts to thicken then remove from heat.\",\"Place the chicken breasts in the prepared pan. Pour one cup of the sauce over top of chicken. Place chicken in oven and bake 35 minutes or until cooked through. Remove from oven and shred chicken in the dish using two forks.\",\"*Meanwhile, steam or cook the vegetables according to package directions.\",\"Add the cooked vegetables and rice to the casserole dish with the chicken. Add most of the remaining sauce, reserving a bit to drizzle over the top when serving. Gently toss everything together in the casserole dish until combined. Return to oven and cook 15 minutes. Remove from oven and let stand 5 minutes before serving. Drizzle each serving with remaining sauce. Enjoy!\"]},{\"id\":\"g523\",\"title\":\"Thai beef stir-fry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/kyuxew1763479470.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Beef\",\"Red Chilli\",\"Oyster Sauce\",\"Basil Leaves\"],\"allergens\":[\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat a wok or large frying pan until smoking hot. Pour in the oil and swirl around the pan, then tip in the beef strips and chilli. Cook, stirring all t\",\"instructions\":[\"step 1\",\"Heat a wok or large frying pan until smoking hot. Pour in the oil and swirl around the pan, then tip in the beef strips and chilli. Cook, stirring all the time, until the meat is lightly browned, about 3 mins, then pour over the oyster sauce. Cook until heated through and the sauce coats the meat. stir in the basil leaves and serve with plain rice.\"]},{\"id\":\"g524\",\"title\":\"Thai chicken cakes with sweet chilli sauce\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6s3i3p1763488540.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breast\",\"Garlic\",\"Ginger\",\"Onion\",\"Coriander\",\"Green Chilli\",\"Olive Oil\",\"sweet chilli sauce\",\"Lime\",\"Spring Onions\",\"Red Chilli\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nToss the chicken, garlic, ginger, onion, coriander and chilli into a food processor and season well. Blitz until the chicken is finely ground and everyt\",\"instructions\":[\"step 1\",\"Toss the chicken, garlic, ginger, onion, coriander and chilli into a food processor and season well. Blitz until the chicken is finely ground and everything is well mixed. Use your hands to shape six small cakes.\",\"step 2\",\"Heat the oil in a frying pan, then fry the cakes over a medium heat for about 6-8 mins, turning once. Serve hot, with sweet chilli sauce, lime wedges, coriander, shredded spring onion and red chilli.\"]},{\"id\":\"g525\",\"title\":\"Thai coconut & veg broth\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4k8nzy1763583384.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Thai Red Curry Paste\",\"Vegetable Oil\",\"Vegetable Stock\",\"Coconut Milk\",\"Brown Sugar\",\"Egg Noodles\",\"Carrots\",\"Chinese Leaf\",\"Bean Sprouts\",\"Cherry Tomatoes\",\"Lime\",\"Spring Onions\",\"Coriander\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPlace the curry paste in a large saucepan or wok with the oil. Fry for 1 min until fragrant. Tip in the vegetable stock, coconut milk and brown sugar. S\",\"instructions\":[\"step 1\",\"Place the curry paste in a large saucepan or wok with the oil. Fry for 1 min until fragrant. Tip in the vegetable stock, coconut milk and brown sugar. Simmer for 3 mins.\",\"step 2\",\"Add the noodles, carrots and Chinese leaf and simmer for 4-6 mins, until all are tender. Mix in beansprouts and tomatoes. Add lime juice to taste and some extra seasoning, if you like. Spoon into bowls and sprinkle with spring onions and coriander.\"]},{\"id\":\"g526\",\"title\":\"Thai curry noodle soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/118oj61763423896.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Thai Green Curry Paste\",\"Stir-fry Vegetables\",\"Raw King Prawns\",\"Coconut Milk\",\"Vegetable Stock\",\"Udon Noodles\",\"Coriander\",\"Basil\",\"Red Chilli\",\"Spring Onions\"],\"allergens\":[\"milk\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oil in a saucepan over a medium heat and cook the curry paste for 1 min before adding the stir-fry veg and prawns. Cook for 3 mins until the pr\",\"instructions\":[\"step 1\",\"Heat the oil in a saucepan over a medium heat and cook the curry paste for 1 min before adding the stir-fry veg and prawns. Cook for 3 mins until the prawns are mostly pink, then add the coconut milk, veg stock and noodles.\",\"step 2\",\"Bring to the boil, then reduce the heat to a simmer and cook for 5 mins until the noodles are cooked through and the veg is tender but still has a bite. Divide between two bowls and sprinkle over the herbs, chilli and spring onion.\"]},{\"id\":\"g527\",\"title\":\"Thai drumsticks\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ittake1763586925.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"sweet chilli sauce\",\"Orange\",\"Orange\",\"Garlic\",\"Thai Red Curry Paste\",\"Chicken drumsticks\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Mix the chilli sauce with the orange zest and juice, garlic, curry paste and ¼ tsp sa\",\"instructions\":[\"step 1\",\"Heat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Mix the chilli sauce with the orange zest and juice, garlic, curry paste and ¼ tsp salt. Add the chicken and coat really well.\",\"step 2\",\"Arrange the drumsticks on the foil, spaced apart. Coat the chicken with any marinade left in the bowl, then roast for 35-40 mins until tender. Wrap in foil or pack into a food container.\"]},{\"id\":\"g528\",\"title\":\"Thai fried rice with prawns & peas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/hblwvg1763478203.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Red Onions\",\"Garlic Clove\",\"Red Chilli\",\"Raw King Prawns\",\"Brown Rice\",\"Frozen Peas\",\"Soy Sauce\",\"Fish Sauce\",\"Coriander\",\"Egg\",\"Hotsauce\"],\"allergens\":[\"egg\",\"soy\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat 1 tbsp of the oil in a wok, add the onion, garlic and chilli, and cook for 2-3 mins until golden. Add the prawns and cook for 1 min. Tip in the ric\",\"instructions\":[\"step 1\",\"Heat 1 tbsp of the oil in a wok, add the onion, garlic and chilli, and cook for 2-3 mins until golden. Add the prawns and cook for 1 min. Tip in the rice and peas, and keep tossing until very hot. Add the soy and fish sauce, then stir through the chopped coriander. Keep warm while you fry the eggs.\",\"step 2\",\"Heat the remaining oil in a frying pan and fry the eggs with some seasoning. Divide the fried rice mix between 4 bowls and top each with a fried egg. Serve scattered with coriander, with chilli sauce, if you like.\"]},{\"id\":\"g529\",\"title\":\"Thai green chicken soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/7kb44y1763589084.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Sunflower Oil\",\"Onion\",\"Chicken Thighs\",\"Garlic Clove\",\"Thai Green Curry Paste\",\"Coconut Milk\",\"Chicken Stock\",\"Lime Leaves\",\"Fish Sauce\",\"Spring Onions\",\"Green Beans\",\"Bamboo Shoot\",\"Lime\",\"Basil\"],\"allergens\":[\"milk\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oil in your largest pan, add the onion and fry for 3 mins to soften. Add the chicken and garlic, and cook until the chicken changes colour.\\r\\n\\r\\n\",\"instructions\":[\"step 1\",\"Heat the oil in your largest pan, add the onion and fry for 3 mins to soften. Add the chicken and garlic, and cook until the chicken changes colour.\",\"step 2\",\"Add the curry paste, coconut milk, stock, lime leaves and fish sauce, then simmer for 12 mins. Add the chopped onion tops, green beans and bamboo shoots and cook for 4-6 mins, until the beans are just tender.\",\"step 3\",\"Meanwhile, put the lime juice and basil in a narrow jug and blitz with a hand blender to make a smooth green paste. Pour into the soup with the sliced spring onion and heat through. Serve with lime wedges for a light lunch or supper or as a make-ahead starter.\"]},{\"id\":\"g530\",\"title\":\"Thai Green Curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sstssx1487349585.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"green beans\",\"sunflower oil\",\"garlic\",\"Thai green curry paste\",\"coconut milk\",\"Thai fish sauce\",\"Sugar\",\"Chicken\",\"lime\",\"basil\",\"Rice\"],\"allergens\":[\"milk\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Put the potatoes in a pan of boiling water and cook for 5 minutes. Throw in the beans and cook for a further 3 minutes, by which time both should be just tender\",\"instructions\":[\"Put the potatoes in a pan of boiling water and cook for 5 minutes. Throw in the beans and cook for a further 3 minutes, by which time both should be just tender but not too soft. Drain and put to one side.\",\"In a wok or large frying pan, heat the oil until very hot, then drop in the garlic and cook until golden, this should take only a few seconds. Don’t let it go very dark or it will spoil the taste. Spoon in the curry paste and stir it around for a few seconds to begin to cook the spices and release all the flavours. Next, pour in the coconut milk and let it come to a bubble.\",\"Stir in the fish sauce and sugar, then the pieces of chicken. Turn the heat down to a simmer and cook, covered, for about 8 minutes until the chicken is cooked.\",\"Tip in the potatoes and beans and let them warm through in the hot coconut milk, then add a lovely citrussy flavour by stirring in the shredded lime leaves (or lime zest). The basil leaves go in next, but only leave them briefly on the heat or they will quickly lose their brightness. Scatter with the lime garnish and serve immediately with boiled rice.\"]},{\"id\":\"g531\",\"title\":\"Thai pork & peanut curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/snmtd61763426568.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Spring Onions\",\"Coriander\",\"Pork Tenderloin\",\"Thai Red Curry Paste\",\"Peanut Butter\",\"Brown Sugar\",\"Soy Sauce\",\"Coconut Milk\",\"Sweetcorn\",\"Lime\",\"Jasmine Rice\"],\"allergens\":[\"milk\",\"soy\",\"peanut\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oil in a large saucepan or flameproof casserole. Add the spring onions and coriander stalks and cook for 1 min. Add the pork slices and cook fo\",\"instructions\":[\"step 1\",\"Heat the oil in a large saucepan or flameproof casserole. Add the spring onions and coriander stalks and cook for 1 min. Add the pork slices and cook for 5 mins until starting to brown.\",\"step 2\",\"Stir in the curry paste and peanut butter. After 30 secs, add the sugar, soy and coconut milk, plus ½ can of water. Mix well, put a lid on and leave to simmer for 15 mins, stirring occasionally.\",\"step 3\",\"Remove the lid, add the baby corn and increase the heat. Bubble for 3 mins until the corn is cooked and the sauce has thickened a little. Stir in the lime juice and check the seasoning. Can now be frozen for up to 2 months. To cook from frozen: thoroughly defrost, then heat in a pan on the hob until curry is hot all the way through. Serve scattered with the coriander leaves and rice.\"]},{\"id\":\"g532\",\"title\":\"Thai prawn curry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qqlwv91763501559.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Onion\",\"Ginger\",\"Thai Red Curry Paste\",\"Tinned Tomatos\",\"Coconut Cream\",\"Raw Frozen Prawns\",\"Coriander\"],\"allergens\":[\"milk\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oil in a medium saucepan. Tip in the onion and ginger, then cook for a few mins until softened. Stir in the curry paste, then cook for 1 min mo\",\"instructions\":[\"step 1\",\"Heat the oil in a medium saucepan. Tip in the onion and ginger, then cook for a few mins until softened. Stir in the curry paste, then cook for 1 min more. Pour over the chopped tomatoes and coconut cream. Bring to the boil, then leave to simmer for 5 mins, adding a little boiling water if the mixture gets too thick.\",\"step 2\",\"Tip in the prawns, then cook for 5-10 mins more, depending on how large they are. Serve alongside some plain rice and sprinkle with a little chopped coriander, if you like.\"]},{\"id\":\"g533\",\"title\":\"Thai pumpkin soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1brbso1763585098.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pumpkin\",\"Sunflower Oil\",\"Onion\",\"Ginger\",\"Lemongrass\",\"Thai Red Curry Paste\",\"Coconut Milk\",\"Vegetable Stock\",\"Lime juice\",\"Sugar\",\"Red Chilli\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat oven to 200C/180C fan/gas 6. Toss the pumpkin or squash in a roasting tin with half the oil and seasoning, then roast for 30 mins until golden and \",\"instructions\":[\"step 1\",\"Heat oven to 200C/180C fan/gas 6. Toss the pumpkin or squash in a roasting tin with half the oil and seasoning, then roast for 30 mins until golden and tender.\",\"step 2\",\"Meanwhile, put the remaining oil in a pan with the onion, ginger and lemongrass. Gently cook for 8-10 mins until softened. Stir in the curry paste for 1 min, followed by the roasted pumpkin, all but 3 tbsp of the coconut milk and the stock. Bring to a simmer, cook for 5 mins, then fish out the lemongrass. Cool for a few mins, then whizz until smooth with a hand blender, or in a large blender in batches. Return to the pan to heat through, seasoning with salt, pepper, lime juice and sugar, if it needs it. Serve drizzled with the remaining coconut milk and scattered with chilli, if you like.\"]},{\"id\":\"g534\",\"title\":\"Thai rice noodle salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/6g3rso1763486069.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vermicelli Rice Noodles\",\"Bean Sprouts\",\"Lime\",\"Fish Sauce\",\"Muscovado Sugar\",\"Red Onions\",\"Lettuce\",\"Minced Pork\",\"Ginger\",\"Cayenne Pepper\",\"Sunflower Oil\",\"Sesame Seed\",\"Oil\",\"Sirloin steak\",\"Red Chilli\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPlace the noodles and beansprouts in a heatproof bowl and cover with boiling water. Leave for 4 mins, or until the noodles are tender. Drain, then cool \",\"instructions\":[\"step 1\",\"Place the noodles and beansprouts in a heatproof bowl and cover with boiling water. Leave for 4 mins, or until the noodles are tender. Drain, then cool under cold running water and drain again. Return to the bowl.\",\"step 2\",\"Stir together the lime zest and juice, fish or soy sauce and sugar. Stir into the noodles with the red onion and lettuce.\",\"step 3\",\"To make with mince, heat a little oil in a non-stick frying pan and stir-fry 500g minced pork, a small knob of grated ginger and pinch cayenne pepper or chilli powder for 10 mins, until the mince is browned and cooked through. Mix into the noodles, divide between four bowls and serve warm.\",\"step 4\",\"To make with steak, make the rice noodle salad. Heat 1 tsp sunflower oil in a frying pan. Tip 2 tbsp sesame seeds onto a plate. Rub 1 tsp oil into 4 x 175g sirloin steaks and press into sesame seeds. Fry for 5 mins for medium rare, turning halfway. Leave to rest for 5 mins, then thinly slice. Toss 1 deseeded and shredded red chilli, and a handful mint leaves into noodles. Top with steak to serve.\"]},{\"id\":\"g535\",\"title\":\"Thai-style fish broth with greens\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/a2ec961763587756.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Brown Rice Noodle\",\"Chicken Stock\",\"Thai Red Curry Paste\",\"Lime Leaves\",\"Fish Sauce\",\"White Fish\",\"Raw King Prawns\",\"Pak Choi\",\"Coriander Leaves\"],\"allergens\":[\"wheat\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nCook the noodles following pack instructions. Refresh in cold water and drain well.\\r\\n\\r\\nstep 2\\r\\nPut the stock in a large saucepan and stir in the curry p\",\"instructions\":[\"step 1\",\"Cook the noodles following pack instructions. Refresh in cold water and drain well.\",\"step 2\",\"Put the stock in a large saucepan and stir in the curry paste, lime leaves, fish sauce and 250ml cold water. Bring to a simmer and cook for 5 mins.\",\"step 3\",\"Cut the fish into roughly 3cm cubes and add to the pan. Return to a simmer, then cook for 2 mins uncovered.\",\"step 4\",\"Stir in the noodles, prawns and pak choi, and simmer for 2-3 mins or until the fish and prawns are just cooked. Serve in bowls scattered with coriander.\"]},{\"id\":\"g536\",\"title\":\"Thai-style steamed fish\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yx8j1i1763484612.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Trout\",\"Ginger\",\"Garlic Clove\",\"Red Chilli\",\"Lime\",\"Baby Pak Koi\",\"Soy Sauce\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nNestle the fish fillets side by side on a large square of foil and scatter the ginger, garlic, chilli and lime zest over them. Drizzle the lime juice on\",\"instructions\":[\"step 1\",\"Nestle the fish fillets side by side on a large square of foil and scatter the ginger, garlic, chilli and lime zest over them. Drizzle the lime juice on top and then scatter the pieces of pak choi around and on top of the fish. Pour the soy sauce over the pak choi and loosely seal the foil to make a package, making sure you leave space at the top for the steam to circulate as the fish cooks.\",\"step 2\",\"Steam for 15 minutes. (If you haven’t got a steamer, put the parcel on a heatproof plate over a pan of gently simmering water, cover with a lid and steam.)\"]},{\"id\":\"g537\",\"title\":\"Three Fish Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/spswqs1511558697.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Butter\",\"Milk\",\"Gruyere\",\"Butter\",\"Leek\",\"Plain Flour\",\"White Wine\",\"Milk\",\"Parsley\",\"Salmon\",\"Haddock\",\"Smoked Haddock\",\"Eggs\"],\"allergens\":[\"egg\",\"milk\",\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 200C/400F/Gas 6 (180C fan).\\r\\nPut the potatoes into a saucepan of cold salted water. Bring up to the boil and simmer until completely tender.\",\"instructions\":[\"Preheat the oven to 200C/400F/Gas 6 (180C fan).\",\"Put the potatoes into a saucepan of cold salted water. Bring up to the boil and simmer until completely tender. Drain well and then mash with the butter and milk. Add pepper and taste to check the seasoning. Add salt and more pepper if necessary.\",\"For the fish filling, melt the butter in a saucepan, add the leeks and stir over the heat. Cover with a lid and simmer gently for 10 minutes, or until soft. Measure the flour into a small bowl. Add the wine and whisk together until smooth.\",\"Add the milk to the leeks, bring to the boil and then add the wine mixture. Stir briskly until thickened. Season and add the parsley and fish. Stir over the heat for two minutes, then spoon into an ovenproof casserole. Scatter over the eggs. Allow to cool until firm.\",\"Spoon the mashed potatoes over the fish mixture and mark with a fork. Sprinkle with cheese.\",\"Bake for 30-40 minutes, or until lightly golden-brown on top and bubbling around the edges.\"]},{\"id\":\"g538\",\"title\":\"Three-cheese souffles\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sxwquu1511793428.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Butter\",\"Parmesan\",\"Milk\",\"Bay Leaves\",\"Plain Flour\",\"English Mustard\",\"Cayenne Pepper\",\"Gruyère\",\"Eggs\",\"Goats Cheese\",\"Double Cream\",\"Spinach\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 200C/180C fan/ gas 6 and butter 4 small (about 200ml) ramekins. Sprinkle the Parmesan into the ramekins, turning until all sides are covered. Place\",\"instructions\":[\"Heat oven to 200C/180C fan/ gas 6 and butter 4 small (about 200ml) ramekins. Sprinkle the Parmesan into the ramekins, turning until all sides are covered. Place the milk and bay leaves in a large saucepan over a gentle heat and bring to the boil. Turn off the heat and leave to infuse for 15 mins.\",\"Discard the bay leaves, add the butter and flour, and return to a low heat. Very gently simmer, stirring continuously with a balloon whisk, for about 6 mins until you get a smooth, thick white sauce. Make sure that you get right into the corners of the pan to stop the sauce from catching or becoming lumpy.\",\"Once thickened, transfer the sauce to a large bowl and stir in the mustard powder, cayenne pepper, Gruyère and egg yolks until fully combined.\",\"In a spotlessly clean bowl and with a clean whisk, beat the egg whites just until peaks begin to form.\",\"Carefully fold the egg whites into the cheese sauce in three stages making sure you fold, rather than stir, to keep the egg whites light and airy. Fill the prepared ramekins with the soufflé mix.\",\"Top each soufflé with a slice of goat’s cheese, then place on a baking tray. Bake for 20-25 mins or until springy and well risen but cooked through.\",\"Leave to cool, then run a knife around the edge of each dish and remove the soufflés. If preparing in advance, place soufflés upside down (for neat presentation), on a tray. Cover tray in cling film. Chill for a few days or freeze for up to 1 month.\",\"When ready to re-bake, heat oven to 200C/180C fan/gas 6. Place the upside-down soufflés in a shallow baking dish, top with the remaining goat’s cheese slices and pour over the cream (this stops them from drying out when baked for the second time). Cook for 8-10 mins until golden. Serve immediately alongside some simply dressed salad.\"]},{\"id\":\"g539\",\"title\":\"Timbits\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/txsupu1511815755.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Sugar\",\"Baking Powder\",\"Salt\",\"Egg\",\"Milk\",\"Oil\",\"Oil\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Sift together dry ingredients.\\r\\nMix together wet ingredients and incorporate into dry. Stir until smooth.\\r\\nDrop by teaspoonfuls(no bigger) into hot oil (365 deg\",\"instructions\":[\"Sift together dry ingredients.\",\"Mix together wet ingredients and incorporate into dry. Stir until smooth.\",\"Drop by teaspoonfuls(no bigger) into hot oil (365 degrees, no hotter), turning after a few moments until golden brown on all sides.\",\"Remove and drain.\",\"Roll in cinnamon sugar while still warm and serve.\"]},{\"id\":\"g540\",\"title\":\"Toad In The Hole\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ytuvwr1503070420.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"sausages\",\"vegetable oil\",\"plain flour\",\"eggs\",\"horseradish\",\"milk\",\"cherry tomatoes\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat the oven to 200°C/fan180°C/gas 6. fry sausages in a non-stick pan until browned.\\r\\nDrizzle vegetable oil in a 30cm x 25cm x 6cm deep roasting tray and he\",\"instructions\":[\"Preheat the oven to 200°C/fan180°C/gas 6. fry sausages in a non-stick pan until browned.\",\"Drizzle vegetable oil in a 30cm x 25cm x 6cm deep roasting tray and heat in the oven for 5 minutes.\",\"Put the plain flour in a bowl, crack in the medium free-range eggs, then stir in the grated horseradish. Gradually beat in the semi-skimmed milk. Season.\",\"Put the sausages into the hot roasting tray and pour over the batter. Top with cherry tomatoes on the vine and cook for 30 minutes until puffed and golden.\"]},{\"id\":\"g541\",\"title\":\"Tofu, greens & cashew stir-fry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/minfsc1763766806.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Broccoli\",\"Garlic Clove\",\"Red Chilli\",\"Spring Onions\",\"Soya Bean\",\"Pak Choi\",\"Marinated Tofu\",\"Hoisin Sauce\",\"Soy Sauce\",\"Cashew Nuts\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat the oil in a non-stick wok. Add the broccoli, then fry on a high heat for 5 mins or until just tender, adding a little water if it begins to catch.\",\"instructions\":[\"step 1\",\"Heat the oil in a non-stick wok. Add the broccoli, then fry on a high heat for 5 mins or until just tender, adding a little water if it begins to catch. Add the garlic and chilli, fry for 1 min, then toss through the spring onions, soya beans, pak choi and tofu. Stir-fry for 2-3 mins. Add the hoisin, soy and nuts to warm through.\"]},{\"id\":\"g542\",\"title\":\"Tom kha gai\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ol2xxt1763582263.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Stock\",\"Coconut Milk\",\"Galangal Paste\",\"Lemongrass Stalks\",\"Lime Leaves\",\"Chicken Thighs\",\"Oyster Mushrooms\",\"Birds-eye Chillies\",\"Caster Sugar\",\"Fish Sauce\",\"Lime\",\"Coriander Leaves\",\"Rice\"],\"allergens\":[\"milk\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPour the chicken stock and coconut milk into a large saucepan set over a medium heat. Tip in the galangal, lemongrass and lime leaves, and bring to a ge\",\"instructions\":[\"step 1\",\"Pour the chicken stock and coconut milk into a large saucepan set over a medium heat. Tip in the galangal, lemongrass and lime leaves, and bring to a gentle simmer, around 6-8 mins. Keeping at a gentle simmer, add the chicken. Cook for 8-10 mins until tender and cooked through.\",\"step 2\",\"Stir in the mushrooms and chillies, and simmer for a further 3-5 mins until everything is cooked through. Sprinkle in the sugar and 3 tbsp each of the fish sauce and lime juice. Taste and add the remaining if required.\",\"step 3\",\"Remove the galangal, lemongrass and lime leaves before serving using a slotted spoon. Ladle into bowls and serve with coriander leaves sprinkled over and steamed rice on the side. Will keep chilled for up to three days. Leave to cool first.\"]},{\"id\":\"g543\",\"title\":\"Tom yum (hot & sour) soup with prawns\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9c5nlx1763424766.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Stock\",\"Lemongrass\",\"Galangal\",\"Coriander\",\"makrut lime leaves\",\"King Prawns\",\"Fish Sauce\",\"Green Chilli\",\"Lime juice\"],\"allergens\":[\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nBring the stock to a boil in a medium-sized saucepan. Add the lemongrass, galangal, coriander roots and lime leaves, then simmer for 2 mins.\\r\\n\\r\\nstep 2\\r\\n\",\"instructions\":[\"step 1\",\"Bring the stock to a boil in a medium-sized saucepan. Add the lemongrass, galangal, coriander roots and lime leaves, then simmer for 2 mins.\",\"step 2\",\"Add the prawns, fish sauce, chillies and lime juice, then return to the boil. Taste and adjust the seasoning with either more lime juice or fish sauce, then garnish with coriander leaves and serve.\"]},{\"id\":\"g544\",\"title\":\"Tom yum soup with prawns\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/l50vz41763422681.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Onion\",\"Tomato\",\"Red Chilli\",\"Galangal\",\"Lemongrass Stalks\",\"Raw King Prawns\",\"Chicken Stock Cube\",\"Oyster Mushrooms\",\"makrut lime leaves\",\"Fish Sauce\",\"Lime juice\",\"Coconut Milk\",\"Thai Chilli Jam\",\"Coriander\"],\"allergens\":[\"milk\",\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPour 1.3 litres water into a large saucepan over a high heat. Add the onion, tomato, chilli, galangal, lemongrass, prawn heads and chicken stock cube. S\",\"instructions\":[\"step 1\",\"Pour 1.3 litres water into a large saucepan over a high heat. Add the onion, tomato, chilli, galangal, lemongrass, prawn heads and chicken stock cube. Stir and bring to a boil, then reduce the heat to medium and simmer for 20 mins until the liquid has reduced.\",\"step 2\",\"Carefully strain the hot broth into a large heatproof bowl or jug, then discard the prawn heads. Return the strained veg and herb mixture to the saucepan and pour over the broth. Stir through the mushrooms and lime leaves, then cook for 3 mins until the mushrooms are tender.\",\"step 3\",\"Add 1 tbsp sugar, the fish sauce, lime juice, coconut milk and prawns. Bring to the boil and cook until the prawns are cooked through, about 1-2 mins. Remove from the heat. Remove the lemongrass, then stir in the Thai chilli jam, if using. Scatter over the coriander to finish, if you like, and serve.\"]},{\"id\":\"g545\",\"title\":\"Tonkatsu pork\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/lwsnkl1604181187.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pork Chops\",\"Flour\",\"Eggs\",\"Breadcrumbs\",\"Vegetable Oil\",\"Tomato Ketchup\",\"Worcestershire Sauce\",\"Oyster Sauce\",\"Caster Sugar\"],\"allergens\":[\"egg\",\"wheat\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"STEP 1\\r\\nRemove the large piece of fat on the edge of each pork loin, then bash each of the loins between two pieces of baking parchment until around 1cm in thic\",\"instructions\":[\"STEP 1\",\"Remove the large piece of fat on the edge of each pork loin, then bash each of the loins between two pieces of baking parchment until around 1cm in thickness – you can do this using a meat tenderiser or a rolling pin. Once bashed, use your hands to reshape the meat to its original shape and thickness – this step will ensure the meat is as succulent as possible.\",\"STEP 2\",\"Put the flour, eggs and panko breadcrumbs into three separate wide-rimmed bowls. Season the meat, then dip first in the flour, followed by the eggs, then the breadcrumbs.\",\"STEP 3\",\"In a large frying or sauté pan, add enough oil to come 2cm up the side of the pan. Heat the oil to 180C – if you don’t have a thermometer, drop a bit of panko into the oil and if it sinks a little then starts to fry, the oil is ready. Add two pork chops and cook for 1 min 30 secs on each side, then remove and leave to rest on a wire rack for 5 mins. Repeat with the remaining pork chops.\",\"STEP 4\",\"While the pork is resting, make the sauce by whisking the ingredients together, adding a splash of water if it’s particularly thick. Slice the tonkatsu and serve drizzled with the sauce.\"]},{\"id\":\"g546\",\"title\":\"Torrijas with sherry\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/f3ee3y1763309332.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Double Cream\",\"Milk\",\"Golden Caster Sugar\",\"Sweet Sherry\",\"Bread\",\"Olive Oil\",\"Icing Sugar\",\"Creme Fraiche\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nIn a wide, shallow bowl, beat the eggs with the cream, milk, golden caster sugar and sherry. Cut each slice of bread in two and dip them into the egg mi\",\"instructions\":[\"step 1\",\"In a wide, shallow bowl, beat the eggs with the cream, milk, golden caster sugar and sherry. Cut each slice of bread in two and dip them into the egg mix, turning to make sure they get a good coating on either side. Soak bread in egg mixture for 10 mins to absorb the liquid (carefully turn them over from time to time and make sure they don’t get too soggy).\",\"step 2\",\"Heat 1½ tbsp olive oil in a large frying pan and cook the bread for about 3 mins on each side until dark golden and crisp on the edge. Keep the slices warm in a low oven as you cook the rest.\",\"step 3\",\"Divide the torrijas between plates and dust with the icing sugar. Serve with crème fraîche or Greek yogurt on the side.\"]},{\"id\":\"g547\",\"title\":\"Torta de fiambre\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/okl9cm1764371087.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cheddar Cheese\",\"Ham\",\"Egg\",\"Vegetable Oil\",\"Milk\",\"All purpose flour\",\"Baking Powder\",\"Salt\",\"Dried Oregano\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Line the bottom of a springform of 20-2cm (8-9inches) with parchment paper, I usually leave some overhang as the batter is very liquid and may spill a bit. Preh\",\"instructions\":[\"Line the bottom of a springform of 20-2cm (8-9inches) with parchment paper, I usually leave some overhang as the batter is very liquid and may spill a bit. Preheat oven to 220 degrees Celsius.\",\"2\",\"Grate the cheese and take out the ham.\",\"3\",\"Mix all remaining ingredients in a large bowl for about one to two minutes.\",\"4\",\"Pour half the batter into the prepared pan, it is going to be very liquid. Then place ham and cheese on top and pour the remaining batter on top.\",\"5\",\"Bake for about 20-25 minutes or until top is golden. Wait for a few minutes before releasing from the pan and enjoy either hot or cold with some fresh herbs.\"]},{\"id\":\"g548\",\"title\":\"Tortang Talong\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/va668f1683209318.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg Plants\",\"Eggs\",\"Salt\",\"Olive Oil\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"0.\\tGrill the eggplant until the color of skin turns almost black\\r\\n1.\\tLet the eggplant cool for a while then peel off the skin. Set aside.\\r\\n2.\\tCrack the eggs and\",\"instructions\":[\"0.\\tGrill the eggplant until the color of skin turns almost black\",\"1.\\tLet the eggplant cool for a while then peel off the skin. Set aside.\",\"2.\\tCrack the eggs and place in a bowl\",\"3.\\tAdd salt and beat\",\"4.\\tPlace the eggplant on a flat surface and flatten using a fork.\",\"5.\\tDip the flattened eggplant in the beaten egg mixture\",\"6.\\tHeat the pan and pour the cooking oil\",\"7.\\tFry the eggplant (that was dipped in the beaten mixture). Make sure that both sides are cooked. Frying time will take you about 3 to 4 minutes per side on medium heat.\"]},{\"id\":\"g549\",\"title\":\"Tourtiere\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ytpstt1511814614.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Sunflower Oil\",\"Minced Pork\",\"Onion\",\"Garlic Clove\",\"Cinnamon\",\"Allspice\",\"Nutmeg\",\"Vegetable Stock\",\"Shortcrust Pastry\",\"Egg\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 200C/180C fan/gas 6. Boil the potato until tender, drain and mash, then leave to cool. Heat the oil in a non-stick pan, add the mince and onion and\",\"instructions\":[\"Heat oven to 200C/180C fan/gas 6. Boil the potato until tender, drain and mash, then leave to cool. Heat the oil in a non-stick pan, add the mince and onion and quickly fry until browned. Add the garlic, spices, stock, plenty of pepper and a little salt and mix well. Remove from the heat, stir into the potato and leave to cool.\",\"Roll out half the pastry and line the base of a 20-23cm pie plate or flan tin. Fill with the pork mixture and brush the edges of the pastry with water. Roll out the remaining dough and cover the pie. Press the edges of the pastry to seal, trimming off the excess. Prick the top of the pastry case to allow steam to escape and glaze the top with the beaten egg.\",\"Bake for 30 mins until the pastry is crisp and golden. Serve cut into wedges with a crisp green salad. Leftovers are good cold for lunch the next day, served with a selection of pickles.\"]},{\"id\":\"g550\",\"title\":\"Traditional Croatian Goulash\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/n1hcou1628770088.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Beef\",\"Onions\",\"Carrots\",\"Garlic\",\"Bay Leaf\",\"Red Wine\",\"Water\",\"Mustard\",\"Salt\",\"Pepper\",\"Paprika\",\"Vegetable Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Clean the meat from the veins if there are some and cut it into smaller pieces, 3 × 3 cm. Marinate the meat in the mustard and spices and let it sit in the refr\",\"instructions\":[\"Clean the meat from the veins if there are some and cut it into smaller pieces, 3 × 3 cm. Marinate the meat in the mustard and spices and let it sit in the refrigerator for one hour\",\"Heat one tablespoon of pork fat or vegetable oil in a pot and fry the meat on all sides until it gets browned. Once the meat is cooked, transfer it to a plate and add another tablespoon of fat to the pot\",\"Cut the onions very fine, peel the carrots and shred it using a grater. Cook the onions and carrots over low heat for 15 minutes. You can salt the vegetables a little to make them soften faster\",\"Once the vegetables have browned and become slightly mushy, add the meat and bay leaves and garlic. Pour over with wine and simmer for 10-15 minutes to allow the alcohol to evaporate. Now is the right time to add 2/3 the amount of liquid\",\"Cover the pot and cook over low heat for an hour, stirring occasionally. After the first hour, pour over the rest of the water or stock and cook for another 30-45 minutes\",\"Allow the stew to cool slightly and serve it with a sprinkle of chopped parsley and few slices of fresh hot pepper if you like to spice it up a bit\",\"Slice ​​some fresh bread, season the salad and simply enjoying these wonderful flavors\"]},{\"id\":\"g551\",\"title\":\"Treacle Tart\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wprvrw1511641295.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Plain Flour\",\"Butter\",\"Golden Syrup\",\"Breadcrumbs\",\"Lemons\",\"Eggs\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"First make the short crust pastry: measure the flour into a large bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs (\",\"instructions\":[\"First make the short crust pastry: measure the flour into a large bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs (alternatively, this can be done in a food processor). Add about three tablespoons of cold water and mix to a firm dough, wrap in cling film and chill in the fridge for about 20 minutes.\",\"Preheat the oven to 200C/400F/Gas 6 and put a heavy baking tray in the oven to heat up. Grease a deep 18cm/7in loose-bottomed fluted flan tin with butter.\",\"Remove about 150g/5½oz of pastry from the main ball and set aside for the lattice top.\",\"Roll the rest of the pastry out thinly on a lightly floured work surface and line the prepared flan tin with the pastry.\",\"Prick the base with a fork, to stop the base rising up during baking.\",\"Place the reserved pastry for the lattice top on cling film and roll out thinly. Egg wash the pastry and set aside to chill in the fridge (the cling film makes it easier to move about). Do not cut into strips at this stage. Do not egg wash the strips once they are on the tart as it will drip into the treacle mixture.\",\"To make the filling, heat the syrup gently in a large pan but do not boil.\",\"Once melted, add the breadcrumbs, lemon juice and zest to the syrup. (You can add less lemon if you would prefer less citrus taste.) If the mixture looks runny, add a few more breadcrumbs.\",\"Pour the syrup mixture into the lined tin and level the surface.\",\"Remove the reserved pastry from the fridge and cut into long strips, 1cm/½in wide. Make sure they are all longer than the edges of the tart tin.\"]},{\"id\":\"g552\",\"title\":\"Tuna and Egg Briks\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/2dsltq1560461468.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Spring Onions\",\"Spinach\",\"Filo Pastry\",\"Tuna\",\"Eggs\",\"Hotsauce\",\"Tomatoes\",\"Cucumber\",\"Lemon Juice\",\"Apricot Jam\"],\"allergens\":[\"egg\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat 2 tsp of the oil in a large saucepan and cook the spring onions over a low heat for 3 minutes or until beginning to soften. Add the spinach, cover with a t\",\"instructions\":[\"Heat 2 tsp of the oil in a large saucepan and cook the spring onions over a low heat for 3 minutes or until beginning to soften. Add the spinach, cover with a tight-fitting lid and cook for a further 2–3 minutes or until tender and wilted, stirring once or twice. Tip the mixture into a sieve or colander and leave to drain and cool.\",\"Using a saucer as a guide, cut out 24 rounds about 12.5 cm (5 in) in diameter from the filo pastry, cutting 6 rounds from each sheet. Stack the filo rounds in a pile, then cover with cling film to prevent them from drying out.\",\"When the spinach mixture is cool, squeeze out as much excess liquid as possible, then transfer to a bowl. Add the tuna, eggs, hot pepper sauce, and salt and pepper to taste. Mix well.\",\"Preheat the oven to 200°C (400°F, gas mark 6). Take one filo round and very lightly brush with some of the remaining oil. Top with a second round and brush with a little oil, then place a third round on top and brush with oil.\",\"Place a heaped tbsp of the filling in the middle of the round, then fold the pastry over to make a half-moon shape. Fold in the edges, twisting them to seal, and place on a non-stick baking sheet. Repeat with the remaining pastry and filling to make 8 briks in all.\",\"Lightly brush the briks with the remaining oil. Bake for 12–15 minutes or until the pastry is crisp and golden brown.\",\"Meanwhile, combine the tomatoes and cucumber in a bowl and sprinkle with the lemon juice and seasoning to taste. Serve the briks hot with this salad and the chutney.\"]},{\"id\":\"g553\",\"title\":\"Tuna Nicoise\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/yypwwq1511304979.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Olive Oil\",\"Eggs\",\"Red Wine Vinegar\",\"Capers\",\"Sunflower Oil\",\"Red Onions\",\"Spinach\",\"Tuna\"],\"allergens\":[\"egg\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 200C/fan 180C/gas 6. Toss the potatoes with 2 tsp oil and some seasoning. Tip onto a large baking tray, then roast for 20 mins, stirring halfway, u\",\"instructions\":[\"Heat oven to 200C/fan 180C/gas 6. Toss the potatoes with 2 tsp oil and some seasoning. Tip onto a large baking tray, then roast for 20 mins, stirring halfway, until crisp, golden and cooked through.\",\"Meanwhile, put eggs in a small pan of water, bring to the boil, then simmer for 8-10 mins, depending on how you like them cooked. Plunge into a bowl of cold water to cool for a few mins. Peel away the shells, then cut into halves.\",\"In a large salad bowl, whisk together the remaining oil, red wine vinegar, capers and chopped tomatoes. Season, tip in the onion, spinach, tuna and potatoes, then gently toss together. Top with the eggs, then serve straight away.\"]},{\"id\":\"g554\",\"title\":\"Tunisian Lamb Soup\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/t8mn9g1560460231.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb Mince\",\"Garlic\",\"Onion\",\"Spinach\",\"Tomato Puree\",\"Cumin\",\"Chicken Stock\",\"Harissa Spice\",\"Chickpeas\",\"Lemon Juice\",\"Macaroni\",\"Salt\",\"Pepper\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add the lamb to a casserole and cook over high heat. When browned, remove from the heat and set aside.\\r\\nKeep a tablespoon of fat in the casserole and discard th\",\"instructions\":[\"Add the lamb to a casserole and cook over high heat. When browned, remove from the heat and set aside.\",\"Keep a tablespoon of fat in the casserole and discard the rest. Reduce to medium heat then add the garlic, onion and spinach and cook until the onion is translucent and the spinach wilted or about 5 minutes.\",\"Return the lamb to the casserole with the onion-spinach mixture, add the tomato puree, cumin, harissa, chicken, chickpeas, lemon juice, salt and pepper in the pan. Simmer over low heat for about 20 minutes.\",\"Add the pasta and cook for 15 minutes or until pasta is cooked.\"]},{\"id\":\"g555\",\"title\":\"Tunisian Orange Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/y4jpgq1560459207.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Orange\",\"Caster Sugar\",\"Olive Oil\",\"Flour\",\"Baking Powder\",\"Eggs\",\"Vanilla Extract\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Preheat oven to 190 C / Gas 5. Grease a 23cm round springform tin.\\r\\nCut off the hard bits from the top and bottom of the orange. Slice the orange and remove all\",\"instructions\":[\"Preheat oven to 190 C / Gas 5. Grease a 23cm round springform tin.\",\"Cut off the hard bits from the top and bottom of the orange. Slice the orange and remove all seeds. Puree the orange with its peel in a food processor. Add one third of the sugar and the olive oil and continue to mix until well combined.\",\"Sieve together flour and baking powder.\",\"Beat the eggs and the remaining sugar with an electric hand mixer for at least five minutes until very fluffy. Fold in half of the flour mixture, then the orange and the vanilla, then fold in the remaining flour. Mix well but not for too long.\",\"Pour cake mixture into prepared tin and smooth out. Bake in preheated oven for 20 minutes. Reduce the oven temperature to 160 C / Gas 2 and bake again for 30 minutes Bake until the cake is golden brown and a skewer comes out clean. Cool on a wire cake rack.\"]},{\"id\":\"g556\",\"title\":\"Turkey Bánh mì\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1wj8w31763781990.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Baguette\",\"Chicken Liver\",\"Cucumber\",\"Turkey\",\"Mayonnaise\",\"Red Chilli\",\"Mint\",\"Carrots\",\"Red Cabbage\",\"Ground Ginger\",\"Rice Vinegar\",\"Golden Caster Sugar\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make the pickled slaw, tip the carrots and cabbage into a large bowl. In a small bowl, combine the ginger, rice vinegar, sugar and a few pinches of s\",\"instructions\":[\"step 1\",\"To make the pickled slaw, tip the carrots and cabbage into a large bowl. In a small bowl, combine the ginger, rice vinegar, sugar and a few pinches of salt. Pour over the vegetables and toss together. Set aside for at least 15 mins.\",\"step 2\",\"Halve the baguettes lengthways and spread the pâté over the bottom half. Top with the pickled slaw, cucumber and turkey. Mix the mayonnaise with the chopped chilli and dollop over the top. Scatter over the mint leaves and sliced chilli. Sandwich together and dig in.\"]},{\"id\":\"g557\",\"title\":\"Turkey Meatloaf\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ypuxtw1511297463.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Onion\",\"Garlic\",\"Worcestershire Sauce\",\"Tomato Puree\",\"Turkey Mince\",\"Eggs\",\"Breadcrumbs\",\"Barbeque Sauce\",\"Cannellini Beans\",\"Parsley\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat oven to 180C/160C fan/gas 4. Heat the oil in a large frying pan and cook the onion for 8-10 mins until softened. Add the garlic, Worcestershire sauce and 2\",\"instructions\":[\"Heat oven to 180C/160C fan/gas 4. Heat the oil in a large frying pan and cook the onion for 8-10 mins until softened. Add the garlic, Worcestershire sauce and 2 tsp tomato purée, and stir until combined. Set aside to cool.\",\"Put the turkey mince, egg, breadcrumbs and cooled onion mix in a large bowl and season well. Mix everything to combine, then shape into a rectangular loaf and place in a large roasting tin. Spread 2 tbsp barbecue sauce over the meatloaf and bake for 30 mins.\",\"Meanwhile, drain 1 can of beans only, then pour both cans into a large bowl. Add the remaining barbecue sauce and tomato purée. Season and set aside.\",\"When the meatloaf has had its initial cooking time, scatter the beans around the outside and bake for 15 mins more until the meatloaf is cooked through and the beans are piping hot. Scatter over the parsley and serve the meatloaf in slices.\"]},{\"id\":\"g558\",\"title\":\"Turkish lahmacun\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/tqd3ac1763786065.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Strong white bread flour\",\"Fast action yeast\",\"Corn Flour\",\"Tomato\",\"Green Chilli\",\"Spring Onions\",\"Parsley\",\"Ground Beef\",\"Chilli Flakes\",\"Ground Cumin\",\"Allspice\",\"Olive Oil\",\"Lemon\",\"Red Onions\"],\"allergens\":[\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nSift the flour into a large bowl, make a well in the middle and sprinkle in the yeast. Pour 125ml water over the yeast, then flick flour over the liquid\",\"instructions\":[\"step 1\",\"Sift the flour into a large bowl, make a well in the middle and sprinkle in the yeast. Pour 125ml water over the yeast, then flick flour over the liquid to create a layer. Cover and leave to rise in a warm place for 15 mins until cracks appear on the surface of that layer.\",\"step 2\",\"Use your hands to mix in 250ml more water along with 1 tsp salt and knead the dough for about 10 mins until elastic and no longer sticky. Add a little more flour if you need to. Cover and leave to rise again in a warm place for 30 mins until doubled in size.\",\"step 3\",\"Heat the oven to as high as it will go (about 240C/220C fan/gas 9) and sprinkle one or two baking trays thinly with cornmeal.\",\"step 4\",\"Pour boiling water from the kettle over the tomatoes, leave to stand briefly, then drain and slip off the skins. Cut the tomatoes in half, cut out the stalks, scoop out the seeds and discard, then chop the flesh.\",\"step 5\",\"Halve the chillies lengthways, cut out the stalks, seeds and white inner membrane, then rinse. Cut lengthwise into fine strips, then crosswise into fine dice.\"]},{\"id\":\"g559\",\"title\":\"Turkish lamb pilau\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/cr2kyr1763793839.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pine Nuts\",\"Olive Oil\",\"Onion\",\"Cinnamon\",\"Lamb\",\"Basmati Rice\",\"Lamb Stock\",\"Dried Apricots\",\"Mint\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nDry-fry the pine nuts or almonds in a large pan until lightly toasted, then tip onto a plate. Add the oil to the pan, then fry the onion and cinnamon to\",\"instructions\":[\"step 1\",\"Dry-fry the pine nuts or almonds in a large pan until lightly toasted, then tip onto a plate. Add the oil to the pan, then fry the onion and cinnamon together until starting to turn golden. Turn up the heat, stir in the lamb, fry until the meat changes colour, then tip in the rice and cook for 1 min, stirring all the time.\",\"step 2\",\"Pour in 500ml boiling water, crumble in the stock cube, add the apricots, then season to taste. Turn the heat down, cover and simmer for 12 mins until the rice is tender and the stock has been absorbed. Toss in the pine nuts and mint and serve.\"]},{\"id\":\"g560\",\"title\":\"Turkish rice (vermicelli rice)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/xw1ruy1763786501.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice\",\"Vegetable Oil\",\"Vermicelli Pasta\",\"Unsalted Butter\",\"Chicken Stock\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPour the rice into a very large bowl under cold running water and carefully drain the water out of the bowl through a sieve. Repeat a few times until th\",\"instructions\":[\"step 1\",\"Pour the rice into a very large bowl under cold running water and carefully drain the water out of the bowl through a sieve. Repeat a few times until the water in the bowl is clear, then fill the bowl up with cold water and leave rice to soak for 10 mins while you cook the vermicelli.\",\"step 2\",\"Put the oil into a medium pan over medium heat. Add the vermicelli and stir continuously until the strands turn a rich golden brown, 2-3 mins. Remove from the heat, stir through the butter until it melts and allow the vermicelli to cool for 1-2 mins.\",\"step 3\",\"Drain the rice thoroughly through a sieve. Add the rice to the pan and stir well. Pour the hot stock into the pan, sprinkle in ½ tsp salt, stir well then return the pan to the hob over a high heat. Bring to the boil, then reduce the heat to the lowest it will go, put the lid on the pan and simmer for 7-9 mins. Remove the pan from the heat, cover with a couple of sheets of kitchen paper or a light tea towel and the pan lid, and let the rice sit in the pan for 10 mins. Fluff up with a fork before serving.\"]},{\"id\":\"g561\",\"title\":\"Turkish-style lamb\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0p7l6b1763813981.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lamb Leg\",\"Seasoning\",\"Dried Oregano\",\"Mint\",\"Yogurt\",\"Pita Bread\",\"Iceberg Lettuce\",\"Red Onions\",\"Lemon\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat grill to high. Season the lamb, then grill for 2 mins on each side until browned, but still very rare. Meanwhile, mix the seasoning, oregano and ha\",\"instructions\":[\"step 1\",\"Heat grill to high. Season the lamb, then grill for 2 mins on each side until browned, but still very rare. Meanwhile, mix the seasoning, oregano and half of the mint into one of the tubs of yogurt, smother this over the lamb, then return to the grill for another 2-3 mins or until the yogurt is blistered and the meat is cooked to your liking.\",\"step 2\",\"Leave the meat to rest on a board for a few mins while you toast the pittas, shred the lettuce and thinly slice the red onion. Stir the rest of the mint into the second tub of yogurt. Thickly slice the meat and stuff into the pitta bread with the salad and minted yogurt. Squeeze over lemon juice before tucking in, if you like.\"]},{\"id\":\"g562\",\"title\":\"Ugali – Kenyan cornmeal\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/smoa3h1762341142.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Water\",\"White Cornmeal\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Bring the water to a boil in a medium saucepan.\\r\\nReduce the heat to low, and stirring constantly with a whisk, slowly add the cornmeal to the boiling water. The\",\"instructions\":[\"Bring the water to a boil in a medium saucepan.\",\"Reduce the heat to low, and stirring constantly with a whisk, slowly add the cornmeal to the boiling water. The ugali will begin to thicken quite quickly.\",\"Continue cooking on low heat, stirring constantly with a sturdy wooden spoon, until the ugali begins to pull away from the sides of the pan, hold together, and takes on the aroma of roasted corn. Turn it out immediately onto a serving plate. If you would like, using a spoon or spatula, quickly shape it into a thick disk or round.\",\"The ugali will continue to firm as it cools and will be thick enough to cut with a knife (similar to firm polenta).\"]},{\"id\":\"g563\",\"title\":\"Vanilla alfajores\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/3wnyvh1764373818.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Dulce de leche\",\"Coconut Flakes\",\"Butter\",\"Sugar\",\"Egg\",\"Egg Yolks\",\"Cornstarch\",\"All purpose flour\",\"Baking Powder\",\"Vanilla Extract\",\"Dulce de leche\",\"Coconut Flakes\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"For the sandwich cookie cream the soft butter for about a minute, then add the sugar and cream for another two minutes. Incorporate the egg fully before mixing \",\"instructions\":[\"For the sandwich cookie cream the soft butter for about a minute, then add the sugar and cream for another two minutes. Incorporate the egg fully before mixing in the egg yolk. Once everything is nicely combined, add all remaining ingredients and mix one more time. Form dough into a ball and wrap in plastic wrap. Chill for at least half an hour or overnight.\",\"2\",\"Preheat oven to 180 degrees Celsius and line two baking sheets with parchment paper.\",\"3\",\"Divide dough in half, put one back in the fridge and roll out the other thickly on a lightly floured surface. Cut out cookies with either the bottom of a glass or a cookie cutter around 6cm in diameter. Repeat with all the dough.\",\"4\",\"Bake for about 8-10min, the cookies will look very pale. Let cool off before filling half with each a teaspoon of dulce de leche. Place other half of cookies on top and roll the sides of each cookie in the coconut flakes (it helps if the dulce de leche was pressed down to the sides of the cookie). Enjoy.\"]},{\"id\":\"g564\",\"title\":\"Vegan banh mi\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/sonirb1763782831.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Raw Vegetables\",\"Vegan White Wine Vinegar\",\"Golden Caster Sugar\",\"Baguette\",\"Hummus\",\"Tempeh\",\"Coriander\",\"Mint\",\"Hotsauce\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPut the shredded veg in a bowl and add the vinegar, sugar and 1 tsp salt. Toss everything together, then set aside to pickle quickly while you prepare t\",\"instructions\":[\"step 1\",\"Put the shredded veg in a bowl and add the vinegar, sugar and 1 tsp salt. Toss everything together, then set aside to pickle quickly while you prepare the rest of the sandwich.\",\"step 2\",\"Heat oven to 180C/160C fan/gas 4. Cut the baguette into four, then slice each piece horizontally in half. Put the baguette pieces in the oven for 5 mins until lightly toasted and warm. Spread each piece with a layer of hummus, then top four pieces with the tempeh slices and pile the pickled veg on top. To serve, sprinkle over the herbs and squeeze over some hot sauce, then top with the other baguette pieces to make sandwiches.\"]},{\"id\":\"g565\",\"title\":\"Vegan Chocolate Cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qxutws1486978099.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Self-raising Flour\",\"coco sugar\",\"cacao\",\"baking powder\",\"flax eggs\",\"almond milk\",\"vanilla\",\"water\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Simply mix all dry ingredients with wet ingredients and blend altogether. Bake for 45 min on 180 degrees. Decorate with some melted vegan chocolate\",\"instructions\":[\"Simply mix all dry ingredients with wet ingredients and blend altogether.\",\"Bake for 45 min on 180 degrees.\",\"Decorate with some melted vegan chocolate.\"]},{\"id\":\"g566\",\"title\":\"Vegan Lasagna\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/rvxxuy1468312893.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"green red lentils\",\"Carrots\",\"onion\",\"zucchini\",\"coriander\",\"spinach\",\"lasagne sheets\",\"vegan butter\",\"flour\",\"soya milk\",\"mustard\",\"vinegar\"],\"allergens\":[\"milk\",\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1) Preheat oven to 180 degrees celcius. \\r\\n2) Boil vegetables for 5-7 minutes, until soft. Add lentils and bring to a gentle simmer, adding a stock cube if desir\",\"instructions\":[\"1) Preheat oven to 180 degrees celcius.\",\"2) Boil vegetables for 5-7 minutes, until soft. Add lentils and bring to a gentle simmer, adding a stock cube if desired. Continue cooking and stirring until the lentils are soft, which should take about 20 minutes.\",\"3) Blanch spinach leaves for a few minutes in a pan, before removing and setting aside.\",\"4) Top up the pan with water and cook the lasagne sheets. When cooked, drain and set aside.\",\"5) To make the sauce, melt the butter and add the flour, then gradually add the soya milk along with the mustard and the vinegar. Cook and stir until smooth and then assemble the lasagne as desired in a baking dish.\",\"6) Bake in the preheated oven for about 25 minutes.\"]},{\"id\":\"g567\",\"title\":\"Vegetable Shepherds Pie\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/w8umt11583268117.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Small Potatoes\",\"Salted Butter\",\"Mushrooms\",\"Brown Lentils\",\"Garlic\",\"Kosher Salt\",\"Onion\",\"Tomato Puree\",\"Bay Leaves\",\"Olive Oil\",\"Dry White Wine\",\"Vegetable Stock\",\"Cornstarch\",\"Soy Sauce\",\"Rosemary\",\"Parsley\",\"Sage\",\"Chives\"],\"allergens\":[\"milk\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add Ingredients:\\r\\n\\r\\n12 cups chopped mixed vegetables\\r\\n1   cup chopped fresh mushrooms \\r\\n1   cup pearl onions\\r\\n\\r\\nTOPPING:\\r\\n\\r\\nPreheat oven to 450°. Bake potatoes \",\"instructions\":[\"Add Ingredients:\",\"12 cups chopped mixed vegetables\",\"1   cup chopped fresh mushrooms\",\"1   cup pearl onions\",\"TOPPING:\",\"Preheat oven to 450°. Bake potatoes on a foil-lined baking sheet until tender, about 45 minutes. Let cool slightly, then peel. Press potatoes through a ricer, food mill, or colander into a large bowl. Add butter; stir until well blended. Stir in milk. Season to taste with salt.\",\"FILLING:\",\"Soak dried porcini in 3 cups hot water; set aside. Combine lentils, 1 garlic clove, 1 tsp. salt, and 4 cups water in a medium saucepan. Bring to a boil; reduce heat and simmer, stirring occasionally, until lentils are tender but not mushy, 15–20 minutes. Drain lentils and discard garlic.\",\"Heat 3 Tbsp. oil in a large heavy pot over medium heat. Add onions and cook, stirring occasionally, until soft, about 12 minutes. Add chopped garlic and cook for 1 minute. Stir in tomato paste. Cook, stirring constantly, until tomato paste is caramelized, 2–3 minutes.\",\"Add bay leaves and wine; stir, scraping up any browned bits. Stir in porcini, slowly pouring porcini soaking liquid into pan but leaving any sediment behind. Bring to a simmer and cook until liquid is reduced by half, about 10 minutes. Stir in broth and cook, stirring occasionally, until reduced by half, about 45 minutes.\"]},{\"id\":\"g568\",\"title\":\"Vegetarian Casserole\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/vptwyt1511450962.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rapeseed Oil\",\"Onion\",\"Garlic\",\"Paprika\",\"Cumin\",\"Thyme\",\"Carrots\",\"Celery\",\"Red Pepper\",\"Yellow Pepper\",\"Tomato\",\"Vegetable Stock Cube\",\"Courgettes\",\"Thyme\",\"Lentils\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oil in a large, heavy-based pan. Add the onions and cook gently for 5 – 10 mins until softened.\\r\\nAdd the garlic, spices, dried thyme, carrots, celery a\",\"instructions\":[\"Heat the oil in a large, heavy-based pan. Add the onions and cook gently for 5 – 10 mins until softened.\",\"Add the garlic, spices, dried thyme, carrots, celery and peppers and cook for 5 minutes.\",\"Add the tomatoes, stock, courgettes and fresh thyme and cook for 20 - 25 minutes.\",\"Take out the thyme sprigs. Stir in the lentils and bring back to a simmer. Serve with wild and white basmati rice, mash or quinoa.\"]},{\"id\":\"g569\",\"title\":\"Vegetarian Chilli\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wqurxy1511453156.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Roasted Vegetables\",\"Kidney Beans\",\"Chopped Tomatoes\",\"Mixed Grain\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Heat oven to 200C/180C fan/ gas 6. Cook the vegetables in a casserole dish for 15 mins. Tip in the beans and tomatoes, season, and cook for another 10-15 mins u\",\"instructions\":[\"Heat oven to 200C/180C fan/ gas 6.\",\"Cook the vegetables in a casserole dish for 15 mins.\",\"Tip in the beans and tomatoes, season, and cook for another 10-15 mins until piping hot.\",\"Heat the pouch in the microwave on High for 1 min and serve with the chilli.\"]},{\"id\":\"g570\",\"title\":\"Vegetarian Shakshuka\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/eo0yfb1763600916.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Red Onions\",\"Red Pepper\",\"Tomato\",\"Cumin\",\"Garlic Granules\",\"Cayenne Pepper\",\"Paprika\",\"Egg\",\"Parsley\",\"Chilli Flakes\",\"Toast\"],\"allergens\":[\"egg\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nFry onion and pepper together on medium heat until onion is soft\\r\\n2\\r\\nAdd garlic granules, cook for a minute\\r\\n3\\r\\nAdd chopped tomatoes and remaining spices, st\",\"instructions\":[\"1\",\"Fry onion and pepper together on medium heat until onion is soft\",\"2\",\"Add garlic granules, cook for a minute\",\"3\",\"Add chopped tomatoes and remaining spices, stir well\",\"4\",\"Simmer for about 20 minutes\",\"5\",\"Make indents for in the sauce and crack an egg into each one\"]},{\"id\":\"g571\",\"title\":\"Venetian Duck Ragu\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qvrwpt1511181864.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Olive Oil\",\"Duck Legs\",\"Onions\",\"Garlic\",\"Cinnamon\",\"Plain Flour\",\"Red Wine\",\"Chopped Tomatoes\",\"Chicken Stock Cube\",\"Rosemary\",\"Bay Leaves\",\"Sugar\",\"Milk\",\"Paccheri Pasta\",\"Parmesan Cheese\"],\"allergens\":[\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the oil in a large pan. Add the duck legs and brown on all sides for about 10 mins. Remove to a plate and set aside. Add the onions to the pan and cook for\",\"instructions\":[\"Heat the oil in a large pan. Add the duck legs and brown on all sides for about 10 mins. Remove to a plate and set aside. Add the onions to the pan and cook for 5 mins until softened. Add the garlic and cook for a further 1 min, then stir in the cinnamon and flour and cook for a further min. Return the duck to the pan, add the wine, tomatoes, stock, herbs, sugar and seasoning. Bring to a simmer, then lower the heat, cover with a lid and cook for 2 hrs, stirring every now and then.\",\"Carefully lift the duck legs out of the sauce and place on a plate – they will be very tender so try not to lose any of the meat. Pull off and discard the fat, then shred the meat with 2 forks and discard the bones. Add the meat back to the sauce with the milk and simmer, uncovered, for a further 10-15 mins while you cook the pasta.\",\"Cook the pasta following pack instructions, then drain, reserving a cup of the pasta water, and add the pasta to the ragu. Stir to coat all the pasta in the sauce and cook for 1 min more, adding a splash of cooking liquid if it looks dry. Serve with grated Parmesan, if you like.\"]},{\"id\":\"g572\",\"title\":\"Venezuelan Arepas\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/3hcy191764376285.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Cornmeal\",\"Water\",\"Salt\",\"Vegetable Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\"],\"summary\":\"Preheat oven to 410° F.\\r\\nPour the water into a large bowl. Make sure it is room temperature.\\r\\nAdd the salt. Blend well with a mixer, fork or spatula to make sur\",\"instructions\":[\"Preheat oven to 410° F.\",\"Pour the water into a large bowl. Make sure it is room temperature.\",\"Add the salt. Blend well with a mixer, fork or spatula to make sure it dissolves well.\",\"While you continue to beat the mixture, slowly add the corn meal—a little bit at a time.\",\"Once all the flour is added, keep mixing until the corn meal, water and salt are thoroughly blended and dissolved.\",\"Set aside the masa in its bowl. Let it rest for 5 minutes so that the flour is thoroughly hydrated. This type of corn flour does not have any gluten, so it doesn’t need to be kneaded. The masa should be smooth, firm yet malleable.\",\"While waiting for the 5 minutes’ rest, heat your budare (or comal, griddle, cast-iron pan or non-stick pan) over medium heat. Coat with a little bit of the oil.\",\"Fill a small bowl with water to wet your hands to make the arepas.\",\"Take about 2 Tbsp of the masa in your damp hands. The masa should fit easily in your palm so that it is easy to shape into a small ball.\",\"Cross your hands, so that one is on top of the other, with the masa ball between them. Rotate your right hand in a circle, so that you are at the same time both pressing the masa into a flat disc and keeping its round shape.\"]},{\"id\":\"g573\",\"title\":\"Venezuelan Coconut Chicken\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/z2sw3o1764378271.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Chicken Breasts\",\"Onion\",\"Garlic\",\"Bay Leaves\",\"Black Pepper\",\"Turmeric\",\"Cumin\",\"Salt\",\"Sugar\",\"Tomato\",\"Ginger Paste\",\"Olive Oil\",\"Coconut Milk\",\"Water\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Cut the chicken up into bite size pieces. Peel and cut the onions, mince the garlic.\\r\\nAssemble the rest of the ingredients and you are ready to start cooking.\\r\\n\",\"instructions\":[\"Cut the chicken up into bite size pieces. Peel and cut the onions, mince the garlic.\",\"Assemble the rest of the ingredients and you are ready to start cooking.\",\"Make the Dish\",\"Heat up a fry pan over medium heat. Add the oil and when hot, sauté the onion until translucent. Remove from pan and transfer to a blender or food processor.\",\"Add tomatoes, garlic, turmeric, cumin, sugar, ginger paste, coconut milk, water and blend smooth.\",\"In the same pan you cooked the onion, add the chicken and brown all sides. This should take about 3 minutes.\",\"Add the blender ingredients and bay leaves to the pan, bring to a simmer and cook until the chicken is white inside and the liquid is creamy. (15 to 20 minutes)\",\"Remove the bay leaves and serve with white rice.\"]},{\"id\":\"g574\",\"title\":\"Venezuelan Sancocho\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/8859m71764377470.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Hind Shank\",\"Onion\",\"Pepper\",\"Garlic\",\"Garlic\",\"Leek\",\"Beef Stock\",\"Sweet Red Peppers\",\"Scallions\",\"Sweetcorn\",\"Cassaba\",\"Yautia\",\"White Yam\",\"Butternut Squash\",\"Salt\",\"Pepper\",\"Cilantro\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Add hind shank, 1 halved small onion, halved bell pepper, 4 whole garlic cloves, the dark green leaves of the leek, and stock to a large stockpot. Cook for 45-6\",\"instructions\":[\"Add hind shank, 1 halved small onion, halved bell pepper, 4 whole garlic cloves, the dark green leaves of the leek, and stock to a large stockpot. Cook for 45-60 minutes until the meat is fork-tender. NOTE: the meat can take a bit longer to be fork-tender; that is okay, just add more cooking time if necessary.\",\"When the meat is tender, remove the big pieces of vegetables and bones. Discard.\",\"Add diced onion, 2 minced garlic, mini sweet peppers, sliced leeks (light green part), scallions, yucca, and corn; Mix and simmer covered over medium heat for 5- 8 minutes, until the yucca is starting to soften. NOTE: the yuca can take a bit longer to start softening; that is okay, just add more cooking time if necessary.\",\"Add yautia, white yam, and butternut squash. Mix to combine. Simmer covered over medium heat for 5 – 6 minutes, until all the root vegetables are tender. NOTE: Do not cook too much, or they will fall apart.\",\"Taste and add salt to your taste, if necessary. Add cilantro and the remaining 2 minced garlic cloves. Mix and let simmer for 2 more minutes.\",\"Serve hot in large soup bowls, dividing the meat and vegetables evenly. Add a squish of lime juice and/or hot sauce, if desired. Serve along with arepas and or casabe (cassava bread).\"]},{\"id\":\"g575\",\"title\":\"Venezuelan Shredded Beef\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/mq27gf1764436795.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Skirty Steak\",\"Garlic\",\"Onion\",\"Onion\",\"Red Pepper\",\"Tomato\",\"Beef Stock\",\"Worcestershire Sauce\",\"Tomato Puree\",\"Cumin\",\"Tomato Ketchup\",\"Salt\",\"Pepper\",\"Olive Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Season beef with salt, pepper and minced garlic\\r\\nChop 1 onion in 4 big wedges\\r\\nPlace in the beef pressure cooker with the 4 wedges of onion and the stock\\r\\nPress\",\"instructions\":[\"Season beef with salt, pepper and minced garlic\",\"Chop 1 onion in 4 big wedges\",\"Place in the beef pressure cooker with the 4 wedges of onion and the stock\",\"Pressure cook for 20 minutes\",\"Release the pressure and open the lid\",\"Remove the beef and SAVE 2 cups of stock in another container\",\"With 2 forks, shred the beef. Beef should be tender enough to so easily. If not, cook for another 10 minutes\",\"Press the saute button of the Instant pot. Add the olive oil\",\"When the machine beeps, add the sliced onion, pepper and tomatoes. Cook until tender\",\"Add the shredded beef back in the pot and mix\"]},{\"id\":\"g576\",\"title\":\"Venezuelan turnovers\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/zjtfp31764440795.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ground Beef\",\"Pepper\",\"Ground Cumin\",\"Vegetable Oil\",\"Onion\",\"Green Pepper\",\"Red Pepper\",\"Garlic Powder\",\"Capers\",\"Tomato Sauce\",\"Sazon\",\"Yellow Masarepa\",\"Vegetable Oil\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Season meat with Adobo. In skillet, heat oil on medium high. Cook meat until pink is gone. Stir in onion, pepper, garlic, alcaparras, tomato sauce and Sazón. Co\",\"instructions\":[\"Season meat with Adobo. In skillet, heat oil on medium high. Cook meat until pink is gone. Stir in onion, pepper, garlic, alcaparras, tomato sauce and Sazón. Cook, stirring often until most of the liquid has evaporated (about 20 minutes). Cool.\",\"Prepared dough should be moist and should hold together, but it should not stick to your fingers. Start with about ½ cup of dough and roll into a ball between palms of your hands. Working on a sheet of non-stick parchment paper, form the ball into a 5-inch circle about ⅛ inch thick. Place a generous tbsp. of filling on one half of circle and using parchment paper close dough over to form a semi-circle. To seal and trim edges of the empanada, press lip of inverted bowl over semi-circle shaped patty. Repeat for all the Empanadas.\",\"In large skillet on medium high, heat ½ inch of oil until hot but not smoking. Cook empanadas in batches, turning once or twice until lightly browned. Drain on paper towel. Do not over crowd skillet or let oil get too hot.\"]},{\"id\":\"g577\",\"title\":\"Vietnamese caramel trout\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/p02vq41763754350.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Golden Caster Sugar\",\"Fish Sauce\",\"Red Chilli\",\"Ginger\",\"Rainbow Trout\",\"Bok Choi\",\"Lemon\",\"Coriander\",\"Rice\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPut the sugar in a large shallow pan, along with a small splash of water. Heat gently, swirling the pan, until the sugar has dissolved. Increase the hea\",\"instructions\":[\"step 1\",\"Put the sugar in a large shallow pan, along with a small splash of water. Heat gently, swirling the pan, until the sugar has dissolved. Increase the heat and bubble the syrup until it turns a dark amber colour. Add the fish sauce, most of the chilli and ginger, then splash in 1 tbsp water to dilute. Boil again until syrupy, then add the fish fillets, skin-side down, and the bok choi, cut-side down.\",\"step 2\",\"Cover the pan with a lid and simmer for 4-5 mins until the fish is cooked and the bok choi has wilted. Turn off the heat, squeeze over the lemon and scatter with the remaining chilli, ginger and the coriander sprigs. Serve with rice.\"]},{\"id\":\"g578\",\"title\":\"Vietnamese chicken salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/pk8wtn1763758591.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Noodles\",\"Carrots\",\"Cucumber\",\"Chicken Breasts\",\"Radish\",\"Red Onions\",\"Mint\",\"Peanuts\",\"Red Chilli\",\"Lime\",\"Fish Sauce\",\"Soy Sauce\",\"Sesame Seed Oil\"],\"allergens\":[\"soy\",\"peanut\",\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nTo make the dressing, whisk all the ingredients together in a large serving bowl. Cook the noodles following pack instructions, then drain and add to th\",\"instructions\":[\"step 1\",\"To make the dressing, whisk all the ingredients together in a large serving bowl. Cook the noodles following pack instructions, then drain and add to the bowl with the dressing.\",\"step 2\",\"Peel the carrot into long strips using a vegetable peeler. Do the same for the cucumber, until you reach the seeds (discard them). Add the carrot and cucumber to the noodle mixture along with the shredded chicken, radishes, red onion and mint. Toss well to coat in the dressing, scatter over the peanuts and serve.\"]},{\"id\":\"g579\",\"title\":\"Vietnamese Grilled Pork (bun-thit-nuong)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/qqwypw1504642429.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pork\",\"Rice Vermicelli\",\"Egg Rolls\",\"Challots\",\"Garlic\",\"Sugar\",\"Fish Sauce\",\"Soy sauce\",\"Pepper\",\"Olive Oil\",\"Cucumber\",\"Mint\",\"Peanuts\"],\"allergens\":[\"egg\",\"soy\",\"peanut\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Slice the uncooked pork thinly, about ⅛\\\". It helps to slightly freeze it (optional).\\r\\nMince garlic and shallots. Mix in a bowl with sugar, fish sauce, thick soy\",\"instructions\":[\"Slice the uncooked pork thinly, about ⅛\\\". It helps to slightly freeze it (optional).\",\"Mince garlic and shallots. Mix in a bowl with sugar, fish sauce, thick soy sauce, pepper, and oil until sugar dissolves.\",\"Marinate the meat for 1 hour, or overnight for better results.\",\"Bake the pork at 375F for 10-15 minutes or until about 80% cooked. Finish cooking by broiling in the oven until a nice golden brown color develops, flipping the pieces midway.\",\"Assemble your bowl with veggies, noodles, and garnish. Many like to mix the whole bowl up and pour the fish sauce on top, but I like to make individual bites and sauce it slowly.\"]},{\"id\":\"g580\",\"title\":\"Vietnamese lamb shanks with sweet potatoes\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/7xte3u1763757761.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ground Nut Oil\",\"Lamb Shanks\",\"Onion\",\"Ginger\",\"Garlic Clove\",\"Red Chilli\",\"Red Chilli\",\"Brown Sugar\",\"Brown Sugar\",\"Star Anise\",\"Lemongrass Stalks\",\"Lamb Stock\",\"Tomato Puree\",\"Sweet Potatoes\",\"Fish Sauce\",\"Lime\",\"Mint\",\"Basil Leaves\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 160C/140C fan/gas 3. Heat 1 tbsp oil in a heavy-bottomed casserole, season the shanks, then brown them 2 at a time on all sides, adding the\",\"instructions\":[\"step 1\",\"Heat oven to 160C/140C fan/gas 3. Heat 1 tbsp oil in a heavy-bottomed casserole, season the shanks, then brown them 2 at a time on all sides, adding the remaining oil for the second batch. Remove the lamb and add the onions. Fry them quite briskly, about 30 secs, add the ginger, garlic and chopped chilli, then turn the heat down and cook for 1 min. Add 1 tbsp sugar, stir, then add the star anise, lemongrass, stock, purée and seasoning. Bring to the boil.\",\"step 2\",\"Cover and cook in the oven for 1½ hrs, then add the sweet potatoes and cook for 1 hr more. The lamb should be completely tender and almost falling off the bones. Stir in the fish sauce, lime juice and 1 tsp sugar to just lift the flavour, then scatter with the mint, basil and the sliced chilli to serve.\"]},{\"id\":\"g581\",\"title\":\"Vietnamese pork salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/g7jomp1763763994.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Golden Caster Sugar\",\"Lime\",\"Red Chilli\",\"Coriander\",\"Sesame Seed Oil\",\"Fish Sauce\",\"Soy Sauce\",\"Pork Tenderloin\",\"Vegetable Oil\",\"White Cabbage\",\"Cucumber\",\"Celery\",\"Spring Onions\",\"Red Chilli\",\"Lemongrass Stalks\",\"Lime\",\"Coriander\",\"Mint\"],\"allergens\":[\"soy\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nThe day before: make the dressing. Put the sugar and lime juice in a pan with 1 tbsp water and bring to the boil to dissolve the sugar. Add the chilli a\",\"instructions\":[\"step 1\",\"The day before: make the dressing. Put the sugar and lime juice in a pan with 1 tbsp water and bring to the boil to dissolve the sugar. Add the chilli and coriander and stir well, then pulse in a blender until smooth. Tip into a bowl, then stir in the sesame oil, fish sauce, soy sauce and sesame seeds to make a dressing. Cover and chill until needed.\",\"step 2\",\"Two hours before serving: heat a griddle pan. Preheat the oven to 200C/gas 6/fan 180C. Brush the pork with oil and griddle on all sides for a few minutes until seared. Transfer to a baking tray and put in the oven for about 10-12 minutes until cooked through. Cool, thinly slice against the grain of the meat. Tip into a bowl and pour over half the dressing.\",\"step 3\",\"To serve: toss the remaining salad ingredients in a bowl with the remaining dressing. Pile on to a platter, top with the pork slices and spoon over any juices.\"]},{\"id\":\"g582\",\"title\":\"Vietnamese prawn spiralized rolls\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/9r2xrg1763771238.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Lime\",\"Rice Vinegar\",\"Palm Sugar\",\"Fish Sauce\",\"Birds-eye Chillies\",\"Rice Paper Sheets\",\"Mint\",\"Coriander\",\"King Prawns\",\"Carrots\",\"Courgettes\"],\"allergens\":[\"fish\",\"shellfish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nMix all the ingredients for the dipping sauce along with 50ml water in a bowl and set aside to allow the sugar to dissolve and flavour to infuse.\\r\\n\\r\\nste\",\"instructions\":[\"step 1\",\"Mix all the ingredients for the dipping sauce along with 50ml water in a bowl and set aside to allow the sugar to dissolve and flavour to infuse.\",\"step 2\",\"To assemble the rolls, fill a wide bowl with warm water and grab a clean damp tea towel to work on. Dip a rice paper wrapper into the water for a few seconds until it softens then carefully place onto the tea towel.\",\"step 3\",\"Put a few mint and coriander leaves in the centre of the wrapper then top with two prawns and a small handful of the spiralized veg, which may need to be cut up if the spirals are too long.\",\"step 4\",\"Fold the sides of the wrapper into the centre, over the filling, then fold in the edges, so that the filling is completely encased, then tightly roll. Repeat until all of the wrappers and filling have been used. To serve, slice on a diagonal and eat with the dipping sauce.\"]},{\"id\":\"g583\",\"title\":\"Vietnamese veg parcels\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/f698g91763768731.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Rice Flour Pancakes\",\"Rice Noodles\",\"Chicken Breast\",\"Carrots\",\"Cucumber\",\"Red Pepper\",\"Lettuce\",\"Coriander\",\"Mint\",\"Fish Sauce\",\"Rice Vinegar\",\"Lime\",\"Red Chilli\"],\"allergens\":[\"wheat\",\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nSoak the rice fl our pancakes according to pack instructions or in boiling water for 30 secs. Remove and cool on kitchen paper. Soak the rice noodles ac\",\"instructions\":[\"step 1\",\"Soak the rice fl our pancakes according to pack instructions or in boiling water for 30 secs. Remove and cool on kitchen paper. Soak the rice noodles according to pack instructions, then drain and cut them into 2cm strips.\",\"step 2\",\"Lay a rice pancake on a board and arrange some rice noodles, chicken, vegetables and herb leaves about a third of the way up, leaving a 1cm edge at the side. Fold the sides over the vegetables and then roll up lengthways to make a cigar. Store in the fridge, covered with moist kitchen paper for up to 1 day.\",\"step 3\",\"Mix together the ingredients for the dipping sauce and put into a bowl. To serve, arrange the rolls on a plate along with the leaves and herbs. To eat, wrap each roll in a piece of lettuce with a herb sprig and dunk into the sauce.\"]},{\"id\":\"g584\",\"title\":\"Vietnamese-style caramel pork\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4mzt101763761546.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Ground Nut Oil\",\"Pork Shoulder Steaks\",\"Shallots\",\"Ground Ginger\",\"Red Chilli\",\"Brown Sugar\",\"Fish Sauce\",\"Chilli Sauce\",\"Spring Onions\",\"Rice\",\"Pak Choi\"],\"allergens\":[\"fish\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat 1 tbsp of the oil in a wok over a high heat and stir-fry the pork in batches until browned all over. Remove with a slotted spoon and set aside.\\r\\n\\r\\n\",\"instructions\":[\"step 1\",\"Heat 1 tbsp of the oil in a wok over a high heat and stir-fry the pork in batches until browned all over. Remove with a slotted spoon and set aside.\",\"step 2\",\"Turn the heat right down and add the remaining oil, then stir in the shallots, ginger and chilli. Cook over a low heat for a couple of mins until just starting to soften. Add the sugar, fish sauce and 200ml water to the pan and stir everything together. Bring to the boil, stirring, so that the sugar dissolves, then return the pork to the pan. Bubble vigorously for 8-10 mins until the sauce thickens to coat the meat and become glossy. Taste and stir in a little more fish sauce, if needed, along with the chilli sauce. Sprinkle with the spring onions and serve with steamed rice and pak choi.\"]},{\"id\":\"g585\",\"title\":\"Vietnamese-style veggie hotpot\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/4uje7l1763762276.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Vegetable Oil\",\"Ginger\",\"Garlic Clove\",\"Butternut Squash\",\"Soy Sauce\",\"Brown Sugar\",\"Vegetable Stock\",\"Green Beans\",\"Spring Onions\",\"Coriander Leaves\",\"Jasmine Rice\"],\"allergens\":[\"milk\",\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oil in a medium-size, lidded saucepan. Add the ginger and garlic, then stir-fry for about 5 mins. Add the squash, soy sauce, sugar and stock. C\",\"instructions\":[\"step 1\",\"Heat the oil in a medium-size, lidded saucepan. Add the ginger and garlic, then stir-fry for about 5 mins. Add the squash, soy sauce, sugar and stock. Cover, then simmer for 10 mins. Remove the lid, add the green beans, then cook for 3 mins more until the squash and beans are tender. Stir the spring onions through at the last minute, then sprinkle with coriander and serve with rice.\"]},{\"id\":\"g586\",\"title\":\"Walnut Roll Gužvara\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/u9l7k81628771647.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Caster Sugar\",\"Yeast\",\"Salt\",\"Milk\",\"Eggs\",\"Butter\",\"Walnuts\",\"Butter\",\"Brown Sugar\",\"Cinnamon\",\"Milk\",\"Icing Sugar\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Mix all the ingredients for the dough together and knead well. Cover the dough and put to rise until doubled in size which should take about 2 hours. Knock back\",\"instructions\":[\"Mix all the ingredients for the dough together and knead well. Cover the dough and put to rise until doubled in size which should take about 2 hours. Knock back the dough and knead lightly.\",\"Divide the dough into two equal pieces; roll each piece into an oblong about 12 inches by 8 inches. Mix the filling ingredients together and divide between the dough, spreading over each piece. Roll up the oblongs as tightly as possible to give two 12 inch sausages. Place these side by side, touching each other, on a greased baking sheet. Cover and leave to rise for about 40 minutes. Heat oven to 200ºC (425ºF). Bake for 30-35 minutes until well risen and golden brown. Bread should sound hollow when the base is tapped.\",\"Remove from oven and brush the hot bread top with milk. Sift with a generous covering of icing sugar.\"]},{\"id\":\"g587\",\"title\":\"Walnut, date & honey cake\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/towo9c1763814590.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Self-raising Flour\",\"Ground Cinnamon\",\"Butter\",\"Muscovado Sugar\",\"Clear Honey\",\"Egg\",\"Banana\",\"Stoned Dates\",\"Walnuts\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nPreheat the oven to 160C/Gas 3/fan oven 140C. Line the base and long sides of a 900g/2lb loaf tin with greaseproof paper, buttering the tin and paper.\\r\\n\",\"instructions\":[\"step 1\",\"Preheat the oven to 160C/Gas 3/fan oven 140C. Line the base and long sides of a 900g/2lb loaf tin with greaseproof paper, buttering the tin and paper.\",\"step 2\",\"Tip the flour, cinnamon, butter, sugar, 2 tablespoons of the honey and the eggs into a large mixing bowl. Mash the bananas and chop the dates (kitchen scissors are easiest for this) and add to the bowl. Beat the mixture for 2-3 minutes, using a wooden spoon or hand-held mixer, until well blended.\",\"step 3\",\"Spoon into the prepared tin and level the top. Scatter the walnut pieces over. Bake for 1 hour, then lightly press the top – it will feel firm if cooked. If not, bake for a further 10 minutes.\",\"step 4\",\"Cool for 15 minutes, then lift out of the tin using the paper. When cold, drizzle the remaining honey over. Cut into thick slices.\"]},{\"id\":\"g588\",\"title\":\"Warm roast asparagus salad\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/ktsws11761998344.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Asparagus\",\"Red Wine Vinegar\",\"Tomato\",\"Extra Virgin Olive Oil\",\"Streaky Bacon\",\"Clear Honey\",\"Jersey Royal Potatoes\",\"Extra Virgin Olive Oil\",\"Dijon Mustard\",\"Rocket\"],\"allergens\":[],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nPreheat the oven to 200C/Gas 6/fan 180C. Snap off the woody ends of the asparagus and discard. Arrange the asparagus in a single layer in a baking tray \",\"instructions\":[\"step 1\",\"Preheat the oven to 200C/Gas 6/fan 180C. Snap off the woody ends of the asparagus and discard. Arrange the asparagus in a single layer in a baking tray with sides. Cut the tomatoes in half widthways, nestle them in with the asparagus, season with sea salt and pepper and drizzle with olive oil. Roll each bacon rasher into a tight roll (if large, first cut in half crosswise), and arrange in the tray. Drizzle the bacon rolls with the honey and bake for 20 minutes until the tomatoes are soft and the bacon is crisp.\",\"step 2\",\"In the meantime, boil the potatoes until tender. Whisk the vinegar, olive oil, mustard, some sea salt and pepper in a large bowl until blended. Toss the rocket or spinach leaves in half of the dressing, and arrange on a large serving platter.\",\"step 3\",\"Drain the potatoes and cut in half. Gently toss them in the rest of the dressing, and arrange on the platter with the asparagus. Tuck in the tomatoes and bacon.\"]},{\"id\":\"g589\",\"title\":\"White chocolate creme brulee\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/uryqru1511798039.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Double Cream\",\"White Chocolate Chips\",\"Vanilla\",\"Egg Yolks\",\"Caster Sugar\",\"Caster Sugar\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"Heat the cream, chocolate and vanilla pod in a pan until the chocolate has melted. Take off the heat and allow to infuse for 10 mins, scraping the pod seeds int\",\"instructions\":[\"Heat the cream, chocolate and vanilla pod in a pan until the chocolate has melted. Take off the heat and allow to infuse for 10 mins, scraping the pod seeds into the cream. If using the vanilla extract, add straight away. Heat oven to 160C/fan 140C/gas 3.\",\"Beat yolks and sugar until pale. stir in the chocolate cream. Strain into a jug and pour into ramekins. Place in a deep roasting tray and pour boiling water halfway up the sides. Bake for 15-20 mins until just set with a wobbly centre. Chill in the fridge for at least 4 hrs.\",\"To serve, sprinkle some sugar on top of the brûlées and caramelise with a blowtorch or briefly under a hot grill. Leave caramel to harden, then serve.\"]},{\"id\":\"g590\",\"title\":\"Wontons\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/1525876468.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Pork\",\"Garlic Clove\",\"Ginger\",\"Soy Sauce\",\"Sesame Seed Oil\",\"Carrots\",\"Celery\",\"Spring Onions\",\"Wonton Skin\",\"Oil\",\"Water\"],\"allergens\":[\"soy\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Combine pork, garlic, ginger, soy sauce, sesame oil, and vegetables in a bowl.\\r\\nSeparate wonton skins.\\r\\nPlace a heaping teaspoon of filling in the center of the\",\"instructions\":[\"Combine pork, garlic, ginger, soy sauce, sesame oil, and vegetables in a bowl.\",\"Separate wonton skins.\",\"Place a heaping teaspoon of filling in the center of the wonton.\",\"Brush water on 2 borders of the skin, covering 1/4 inch from the edge.\",\"Fold skin over to form a triangle, sealing edges.\",\"Pinch the two long outside points together.\",\"Heat oil to 450 degrees and fry 4 to 5 at a time until golden.\",\"Drain and serve with sauce.\"]},{\"id\":\"g591\",\"title\":\"Yaki Udon\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/wrustq1511475474.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Udon Noodles\",\"Sesame Seed Oil\",\"Onion\",\"Cabbage\",\"Shiitake Mushrooms\",\"Spring Onions\",\"Mirin\",\"Soy Sauce\",\"Caster Sugar\",\"Worcestershire Sauce\"],\"allergens\":[\"soy\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"Boil some water in a large saucepan. Add 250ml cold water and the udon noodles. (As they are so thick, adding cold water helps them to cook a little bit slower \",\"instructions\":[\"Boil some water in a large saucepan. Add 250ml cold water and the udon noodles. (As they are so thick, adding cold water helps them to cook a little bit slower so the middle cooks through). If using frozen or fresh noodles, cook for 2 mins or until al dente; dried will take longer, about 5-6 mins. Drain and leave in the colander.\",\"Heat 1 tbsp of the oil, add the onion and cabbage and sauté for 5 mins until softened. Add the mushrooms and some spring onions, and sauté for 1 more min. Pour in the remaining sesame oil and the noodles. If using cold noodles, let them heat through before adding the ingredients for the sauce – otherwise tip in straight away and keep stir-frying until sticky and piping hot. Sprinkle with the remaining spring onions.\"]},{\"id\":\"g592\",\"title\":\"Yemeni Lahsa (Elite Shakshuka)\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/30s7vf1763741844.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Egg\",\"Onion\",\"Tomato\",\"Olive Oil\",\"Allspice\",\"Black Pepper\",\"Liquid Cheese\"],\"allergens\":[\"egg\",\"milk\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1\\r\\nFirst, On medium heat, heat the olive oil and add the diced onion until it wethers. Next, add the tomatoes and cook for another 4-5 min. Lastly, add the all \",\"instructions\":[\"1\",\"First, On medium heat, heat the olive oil and add the diced onion until it wethers. Next, add the tomatoes and cook for another 4-5 min. Lastly, add the all spice, salt, and cracked pepper.\",\"2\",\"Add the eggs and mix throughly for 2 minutes and cover to cook 5-6 minutes until top is solidified. Lastly, spread the liquid cheese and have it covered for a minute.\",\"3\",\"I served mine Mediterranean style with hash-browns, Egyptian fava beans, Turkish salami and olives, cheese wedges, and greek feta.\"]},{\"id\":\"g593\",\"title\":\"Yorkshire Puddings\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/x5qz5k1761595900.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Flour\",\"Egg\",\"Milk\",\"Sunflower Oil\"],\"allergens\":[\"egg\",\"milk\",\"wheat\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"step 1\\r\\nHeat oven to 230C/fan 210C/gas 8.\\r\\n\\r\\nstep 2\\r\\nDrizzle a little sunflower oil evenly into two 4-hole Yorkshire pudding tins or two 12-hole non-stick muffi\",\"instructions\":[\"step 1\",\"Heat oven to 230C/fan 210C/gas 8.\",\"step 2\",\"Drizzle a little sunflower oil evenly into two 4-hole Yorkshire pudding tins or two 12-hole non-stick muffin tins and place in the oven to heat through.\",\"step 3\",\"To make the batter, tip 140g plain flour into a bowl and beat in 4 eggs until smooth.\",\"step 4\",\"Gradually add 200ml milk and carry on beating until the mix is completely lump-free. Season with salt and pepper.\",\"step 5\",\"Pour the batter into a jug, then remove the hot tins from the oven. Carefully and evenly pour the batter into the holes.\"]},{\"id\":\"g594\",\"title\":\"Zapiekanki\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/72lmpt1764122511.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Baguette\",\"Butter\",\"Vegetable Oil\",\"Onion\",\"Mushrooms\",\"Garlic\",\"Mayonnaise\",\"Cheddar Cheese\",\"Ham\",\"Polish Kabanos\",\"Mozzarella\",\"Dill\",\"Chives\",\"Tomato Ketchup\"],\"allergens\":[\"milk\"],\"cookTime\":20,\"texture\":\"bite-sized\",\"tags\":[\"normal\"],\"summary\":\"step 1\\r\\nHeat the oven to 200C/180C fan/gas 6. Bake the baguettes on a baking tray for 8-10 mins, then leave to cool.\\r\\n\\r\\nstep 2\\r\\nHeat 2 tsp of the butter and 1 t\",\"instructions\":[\"step 1\",\"Heat the oven to 200C/180C fan/gas 6. Bake the baguettes on a baking tray for 8-10 mins, then leave to cool.\",\"step 2\",\"Heat 2 tsp of the butter and 1 tsp of the oil in a pan over a low heat and cook the chopped onion for 5 mins until soft. Stir in the mushrooms, turn the heat to medium and cook for 5-10 mins more until the veg is soft and the mushroom liquid has evaporated. Stir in the garlic and cook for 1-2 mins until soft. Season, then stir in the mayonnaise and remove from the heat.\",\"step 3\",\"Halve the baguettes lengthways, then return to the baking tray, cut-side up and spread over the mushroom mixture, then sprinkle over the cheddar, ham, kabanos and mozzarella. Bake for 8-10 mins, or until the cheese has melted and turned golden.\",\"step 4\",\"Meanwhile, heat the remaining butter and oil in a pan over a medium heat and fry the sliced onions for 5 mins until golden and soft. Remove from the heat and set aside. Once the pizzas are cooked, top with the caramelised onions, dill pickles (if using), the chives and a zig-zag drizzle of ketchup.\"]},{\"id\":\"g595\",\"title\":\"Zemiakové Placky\",\"origin\":\"GLOBAL\",\"source\":\"TheMealDB\",\"imageUrl\":\"https://www.themealdb.com/images/media/meals/0umm891763364625.jpg\",\"ageRanges\":[\"24-30\",\"31-36\"],\"ingredients\":[\"Potatoes\",\"Onion\",\"Garlic\",\"Egg\",\"All purpose flour\",\"Marjoram\",\"Salt\",\"Black Pepper\",\"Oil\"],\"allergens\":[\"egg\",\"wheat\"],\"cookTime\":20,\"texture\":\"soft-chopped\",\"tags\":[\"normal\",\"protein-boost\"],\"summary\":\"1. Prepare the Potatoes\\r\\nStart by peeling and finely grating the potatoes. To ensure extra crispiness, use a clean kitchen towel to squeeze out as much moisture\",\"instructions\":[\"1. Prepare the Potatoes\",\"Start by peeling and finely grating the potatoes. To ensure extra crispiness, use a clean kitchen towel to squeeze out as much moisture as possible.\",\"2. Mix the Ingredients\",\"In a large mixing bowl, combine the grated potatoes, chopped onion, minced garlic, eggs, flour, marjoram, salt, and black pepper. Stir well until the mixture forms a thick, consistent batter.\",\"3. Heat the Oil\",\"In a large frying pan, heat a generous amount of oil over medium heat. The oil should be hot but not smoking.\",\"4. Fry the Pancakes\",\"Spoon portions of the batter into the pan, flattening each into a thin pancake. Fry until golden brown and crispy on one side, then flip and cook the other side until equally golden and crispy.\",\"5. Drain & Serve\",\"Transfer the cooked pancakes onto a plate lined with paper towels to remove excess oil. Serve immediately while hot, with sour cream, garlic dip, or as a side dish.\"]}]"

